// Concurso: TRF3 — 1904 questões
var QUESTOES_TRF3 = [{"id":"TRF3_1","enunciado":"Direitos Fundamentais no Estatuto da Pessoa com Deficiência ,Acessibilidade ,","a":"","b":"","c":"","d":"","e":"","gabarito":"","materia":"Geral","tema":"","origem":"","ano":"","banca":"","orgao":"","concurso":"TRF3"},{"id":"TRF3_2","enunciado":"Lei nº 10.048 de 2000, Lei nº 10.098 de 2000 e Decreto nº 5.296 de 2004: Acessibilidade e Atendimento Prioritário","a":"Ano: 2025 Banca: FGV Órgão: TRF - 3ª REGIÃO Prova: FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto Lei nº 13.146/2015, denominada Lei Brasileira de Inclusão (LBI) ou Estatuto da Pessoa com Deficiência, surge da necessidade de atender ao prescrito na Convenção Internacional sobre os Direitos das Pessoas com Deficiência. Com relação à LBI, assinale a alternativa correta: As pessoas discriminadas não podem merecer tutela jurisdicional coletiva, ainda que a discriminação alcance a honra A e a dignidade de grupos que, historicamente, se sujeitam a atos discriminatórios de todos os tipos, quais sejam, os “grupos raciais, étnicos ou religiosos”. Estabelece a LBI, em seu art. 3º, IV, o que constitui “barreira”, indicando as mais comuns, as mais perceptíveis, como as","b":"barreiras urbanística, as arquitetônicas, as de transporte, mas deixando de lado as chamadas barreiras atitudinais detectadas nas “atitudes ou comportamentos” que impedem ou simplesmente prejudicam a “participação social” em igualdade de condições e oportunidades. Segundo o art. 75, III, da LBI, na propaganda política, debates eleitorais e pronunciamentos oficiais da Justiça Eleitoral","c":"ou de autoridades, é facultado o respeito à acessibilidade das pessoas com deficiência às informações, através da garantia do uso de recursos de subtitulação por meio de legenda oculta, janela com intérprete da Linguagem Brasileira de Sinais (LÍBRAS), e audiodescrição. A Convenção da ONU sobre os Direitos das Pessoas com Deficiência traz uma mudança de paradigma no que diz","d":"respeito ao conceito de pessoa com deficiência, deixando de utilizar o conceito médico até então vigente no Brasil, “para adotar um conceito ambiental, muito mais preocupado com as barreiras existentes na realidade do indivíduo do que apenas e tão somente no aspecto médico”. A LBI estabelece que é dever do Estado, da família, da comunidade escolar e da sociedade, assegurar educação de","e":"qualidade à pessoa com deficiência, colocando-a a salvo de toda forma de violência, negligência e discriminação. A LBI ainda estabelece a obrigatoriedade dos estabelecimentos educacionais, de qualquer nível e modalidade de ensino, cumprirem as incumbências estabelecidas pelo caput do art. 28 dessa lei, sendo que essa obrigatoriedade só se aplica aos estabelecimentos públicos.","gabarito":"","materia":"Geral","tema":"","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3179597","enunciado":"No plano internacional a proteção dos direitos humanos vem sendo ampliada sequencialmente, assim, em futuro breve,","a":"espera-se a efetivação dos direitos humanos pelas empresas transnacionais. Sobre esse tema, assinale a alternativa correta: ONU aprovou o Tratado de Chicago (hard law), em 2023, cuidando de Normas sobre as Responsabilidades das A Empresas Transnacionais e outros Empreendimentos Privados com relação aos Direitos Humanos. As Normas da ONU sobre as Responsabilidades das Empresas Transnacionais e outros Empreendimentos Privado,","b":"aprovadas no Tratado de Chicago de 2023, buscavam determinar as responsabilidades imputáveis às empresas concebidas para serem obrigações voluntárias impostas pelo Direito Internacional às empresas por toda a gama de direitos humanos em sua “esfera de influência”. John Ruggie, professor da Universidade de Harvard, desenvolveu uma pesquisa abrangente na atuação das empresas","c":"transnacionais e outros empreendimentos privados, e tornou pública sua proposta de marco normativo para a imposição, às corporações, de responsabilidades em direitos humanos, o que ficou conhecido como Marco Ruggie, ainda sem força normativa.","d":"O Marco Ruggie foi adotado como Protocolo (hard law) pela Comissão Interamericana de Direitos Humanos, em 2023, assentando-se sobre “responsabilidades diferenciadas, mas complementares” e compreende a obrigação de o Estado proteger os direitos e a responsabilidade das empresas em respeitar os direitos humanos.","e":"Levando-se em consideração a importância das empresas e principalmente das grandes corporações no cenário político econômico mundial, abrigadas pela Lex Mercatoria e protegidas pela Organização Mundial do Comércio, estas não devem receber a imposição de obrigações positivas sobre direitos humanos.","gabarito":"C","materia":"Direitos Humanos","tema":"Direito Internacional dos Direitos Humanos ,Direitos Humanos no Ordenamento Nacional","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3179596","enunciado":"Sobre o sistema de quotas, assinale a alternativa correta:","a":"No Tema 99/STF, foi declarada a inconstitucionalidade do art. 93 da Lei nº 8.213/1991, por ausência de previsão constitucional sobre quotas em empresas privadas. Segundo o previsto na Lei nº 8.213/1991, a dispensa de pessoa com deficiência ou de beneficiário reabilitado da","b":"Previdência Social ao final de contrato por prazo determinado de mais de 90 (noventa) dias e a dispensa imotivada em contrato por prazo indeterminado obrigam a contratação de outro trabalhador com deficiência ou beneficiário reabilitado da Previdência Social no prazo máximo de 60 (sessenta dias).","c":"Conforme a Lei nº 8.213/1991, para a reserva de cargos será considerada a contratação direta de pessoa com deficiência, incluindo o aprendiz com deficiência de que trata a CLT.","d":"A exigência de quotas, fixada no art. 93 da Lei nº 8.213/1991, diz respeito apenas a pessoas com deficiência, não alcançando beneficiários reabilitados.","e":"Segundo o art. 93 da Lei nº 8.213/1991, a empresa com 100 (cem) ou mais empregados está obrigada a preencher de 2% (dois por cento) a 5% (cinco por cento) dos seus cargos com beneficiários reabilitados ou pessoas com deficiência, em proporção progressiva conforme o número de empregados. Direitos Humanos>Sistema Global de Proteção dos Direitos Humanos: Instrumentos Normativos ,","gabarito":"E","materia":"Direito Previdenciário","tema":"Planos de Benefício da Previdência Social - Lei nº 8.213, de 24 de Julho de 1991","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_5","enunciado":"Ano: 2025 Banca: FGV Órgão: TRF - 3ª REGIÃO Prova: FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto Em 1986, foi adotada pela ONU a Declaração sobre o Direito ao Desenvolvimento e, a partir desse documento, o direito ao desenvolvimento se configurou como um direito humano inalienável, passando a ser entendido como um processo global econômico, social, cultural e político. A respeito do Direito ao Desenvolvimento, assinale a alternativa correta:","a":"Os direitos econômicos, sociais e culturais são considerados pontos-chave do Direito Internacional ao desenvolvimento, como assinala o primeiro dos Princípios Limburg.","b":"O principal responsável, ou seja, o sujeito passivo do Direito ao Desenvolvimento é a ONU, que tem o dever de criar as condições favoráveis ao desenvolvimento supranacional e interno dos povos e dos indivíduos.","c":"Com relação à regulação do Direito ao Desenvolvimento no âmbito interamericano, este não se encontra previsto na Carta Americana de Direitos Humanos.","d":"Mesmo sendo signatário da Declaração de 1986, os Estados-parte podem invocar disposições de sua legislação interna","e":"para justificar a falta de cumprimento de obrigações nela estabelecidas. O Brasil não é signatário do Pacto Internacional de Direitos Econômicos, Sociais e Culturais da ONU, de 1966. Direitos Humanos>Direito Internacional dos Direitos Humanos ,","gabarito":"","materia":"Geral","tema":"","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3179594","enunciado":"Ano: 2025 Banca: FGV Órgão: TRF - 3ª REGIÃO Prova: FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto No que diz respeito à justiciabilidade dos Direitos Humanos, assinale a alternativa correta:","a":"Os Tribunais Internacionais da ex-Iugoslávia e o de Ruanda são os antecedentes do Tribunal Penal Internacional criado pelo Estatuto de Londres em 1998.","b":"Com competência para julgar os crimes cometidos ao longo do nazismo, seja pelos líderes do partido, seja pelos oficiais militares, o Tribunal de Nuremberg foi regulamentado pelo Acordo de Roma.","c":"O Tribunal de Nuremberg foi o ponto de partida da justicialização dos Direitos Humanos, inovando ao afirmar a responsabilidade internacional penal do indivíduo.","d":"O Tribunal Penal Internacional aplica o costume internacional para a condenação criminal de indivíduos pela prática de crimes de genocídio, crimes contra a humanidade, crimes de guerra e crimes de agressão.","e":"O exercício da jurisdição internacional pode ser acionado mediante denúncia de um Estado-parte ou de uma ou várias vítimas. Direitos Humanos>Sistema Interamericano de Proteção aos Direitos Humanos: Instituições ,","gabarito":"C","materia":"Sistema Interamericano de Proteção aos Direitos Humanos: Instituições","tema":"","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3179592","enunciado":"Assinale a alternativa correta:","a":"É atribuição das Ouvidorias receber reclamações e denúncias de qualquer interessado contra membros ou órgãos do Poder Judiciário, ou contra seus serviços auxiliares, bem como aplicar as penalidades cabíveis, após o devido processo legal.","b":"São penalidades estabelecidas no Código de Ética da Magistratura Nacional: advertência; censura; remoção compulsória; disponibilidade com vencimentos proporcionais ao tempo de serviço; aposentadoria compulsória com vencimentos proporcionais ao tempo de serviço; demissão.","c":"É considerado tratamento discriminatório injustificado, pelo juiz, a audiência concedida a apenas uma das partes ou seu advogado, ainda que se assegure igual direito à parte contrária, caso solicitado, em respeito ao princípio da imparcialidade.","d":"Estabelece o Código de Ética da Magistratura que o exercício da magistratura deve nortear-se pelos princípios da independência, da imparcialidade, do conhecimento e capacitação, da cortesia, da transparência, do segredo profissional, da prudência, da diligência, da integridade profissional e pessoal, da dignidade, da honra e do decoro. Compete ao Conselho Nacional de Justiça, entre outros, zelar pela autonomia do Poder Judiciário e pelo cumprimento","e":"do Estatuto da Magistratura, podendo expedir atos regulamentares, no âmbito de sua competência, ou recomendar providências; não compete ao mesmo órgão rever, de ofício ou mediante provocação, os processos disciplinares de juízes e membros de tribunais julgados há menos de um ano. Filosofia do Direito>A Filosofia do Direito em Diferentes Momentos Históricos ,","gabarito":"D","materia":"Legislação dos TRFs","tema":"Código de Ética da Magistratura Nacional","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_8","enunciado":"Ano: 2025 Banca: FGV Órgão: TRF - 3ª REGIÃO Prova: FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto Em vista do positivismo jurídico kelseniano, assinale a alternativa correta: Em sua Teoria Geral do Direito, entendendo que o cientista do Direito deveria investigá-lo mediante um método","a":"próprio ao seu estudo, Hans Kelsen concluiu que isso só seria possível se houvesse pureza metódica. Assim, separa o Direito dos fatos naturais, remetendo o estudo destes às ciências causais da natureza e retira do âmbito de apreciação da ciência jurídica a política e os aspectos valorativos do Direito.","b":"Hans Kelsen distingue norma jurídica e proposição jurídica. As normas jurídicas, objeto da ciência jurídica, são ordens da conduta humana produzidas pelo órgão legislativo e a proposição jurídica é produzida pela jurisprudência do Judiciário.","c":"Na confluência do Direito, Estado Moderno e ciência jurídica, podemos perceber que a teoria imperativista da norma jurídica está estreitamente vinculada à concepção legalista-estatal do Direito (isto é, com a concepção que considera o Estado como única fonte do Direito e determina a lei como a única expressão do poder normativo do Estado). Hans Kelsen, em sua Teoria Pura do Direito, procura encontrar um fundamento de validade para o ordenamento","d":"jurídico reconduzível a autoridades metajurídicas, como Deus ou a natureza. Esse fundamento é o critério supremo que permite estabelecer se uma norma pertence a um ordenamento, pois é ele que fundamenta a validade do ordenamento.","e":"O positivismo jurídico sustenta o princípio da coerência do ordenamento jurídico, que consiste em negar que nele possa haver lacunas. Tal princípio estaria garantido por uma norma, implícita em todo ordenamento, segundo a qual duas normas antinômicas não podem ser ambas válidas. Direito Internacional Público>Extradição, Expulsão e Deportação ,Fontes do Direito Internacional Público: Tratados Interna","gabarito":"","materia":"Geral","tema":"","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3179590","enunciado":"Ano: 2025 Banca: FGV Órgão: TRF - 3ª REGIÃO Prova: FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","a":"Assinale a alternativa correta: Será concedida extradição de estrangeiro por crime político ou de opinião.","b":"A Corte Internacional de Justiça não possui competência consultiva.","c":"Na adoção, as autoridades competentes de um Estado Contratante não tomarão providências para conservação das informações de que dispuserem relativamente à origem da criança e, em particular, a respeito da identidade de seus pais, assim como sobre o histórico médico da criança e de sua família.","d":"Nenhum brasileiro será extraditado, salvo o naturalizado, em caso de crime comum, praticado antes da naturalização, ou de comprovado envolvimento em tráfico ilícito de entorpecentes e drogas afins, na forma da lei.","e":"É anulável um tratado que, no momento de sua conclusão, conflite com uma norma imperativa de Direito Internacional geral. Direitos Humanos>Sistema Global de Proteção dos Direitos Humanos: Instrumentos Normativos ,","gabarito":"D","materia":"Assinatura e Ratificação dos Tratados Internacionais: intercâmbio instrumental, \"acordos executivos\", procedimento parlam","tema":"","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_10","enunciado":"Ano: 2025 Banca: FGV Órgão: TRF - 3ª REGIÃO Prova: FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto Quanto a tratados internacionais, assinale a alternativa correta:","a":"Um Estado pode invocar o fato de que seu consentimento em obrigar-se por um tratado foi expresso em violação de uma disposição de seu direito interno sobre competência para concluir tratados, a não ser que essa violação fosse manifesta e dissesse respeito a uma norma de seu direito interno de importância fundamental.","b":"Um Estado não pode invocar o fato de que seu consentimento em obrigar-se por um tratado foi expresso em violação de uma disposição de seu direito interno sobre competência para concluir tratados, a não ser que essa violação fosse manifesta e dissesse respeito a uma norma de seu direito interno de importância fundamental.","c":"Um Estado não pode invocar o fato de que seu consentimento em obrigar-se por um tratado foi expresso em violação de uma disposição de seu direito interno sobre competência para concluir tratados, a não ser que essa violação não","d":"fosse manifesta e não dissesse respeito a uma norma de seu direito interno de importância fundamental. Um erro relativo à redação do texto de um tratado prejudicará inarredavelmente sua validade.","e":"A correção do texto de um tratado já registrado não precisará ser notificada ao Secretariado das Nações Unidas.","gabarito":"","materia":"Geral","tema":"","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3179587","enunciado":"","a":"No que concerne à autoridade judicial brasileira, assinale a alternativa correta: Só à autoridade judiciária brasileira compete conhecer das ações relativas a bens móveis situados no Brasil.","b":"É competente a autoridade judiciária brasileira, quando for o réu domiciliado no estrangeiro, sem que aqui tiver de ser cumprida a obrigação.","c":"A autoridade judiciária brasileira cumprirá, concedido o exequatur e segundo a forma estabelecida pela lei estrangeira, as diligências deprecadas por autoridade estrangeira competente, observando a lei desta, quanto ao objeto das diligências.","d":"É competente a autoridade judiciária brasileira, quando não for o réu domiciliado no Brasil ou aqui não tiver de ser cumprida a obrigação.","e":"É competente a autoridade judiciária brasileira, quando for o réu domiciliado no Brasil ou aqui tiver de ser cumprida a obrigação.","gabarito":"E","materia":"Direito Processual Civil - Novo Código de Processo Civil - CPC 2015","tema":"Jurisdição","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3179586","enunciado":"Assinale a alternativa correta: Será executada no Brasil a sentença proferida no estrangeiro, que não reúna os seguintes requisitos: a) haver sido","a":"proferida por juiz competente; b) terem sido as partes citadas ou haver-se legalmente verificado à revelia; c) ter passado em julgado e estar revestida das formalidades necessárias para a execução no lugar em que foi proferida; d) estar traduzida por intérprete autorizado; e) ter sido homologada pelo STF. Será executada no Brasil a sentença proferida no estrangeiro, que reúna os seguintes requisitos: a) haver sido","b":"proferida por juiz competente; b) terem sido as partes citadas ou haver-se legalmente verificado à revelia; c) ter passado em julgado e estar revestida das formalidades necessárias para a execução no lugar em que foi proferida; d) estar traduzida por intérprete não autorizado; e) ter sido homologada pelo STF. Será executada no Brasil a sentença proferida no estrangeiro, que reúna os seguintes requisitos: a) haver sido","c":"proferida por juiz competente; b) terem sido as partes citadas ou haver-se legalmente verificado à revelia; c) ter passado em julgado e estar revestida das formalidades necessárias para a execução no lugar em que foi proferida; d) estar traduzida por intérprete autorizado; e) ter sido homologada pelo STJ. Será executada no Brasil a sentença proferida no estrangeiro, que reúna os seguintes requisitos: a) haver sido","d":"proferida por juiz competente; b) terem sido, ou não, as partes citadas, ou haver-se legalmente verificado à revelia; c) ter passado em julgado e estar revestida das formalidades necessárias para a execução no lugar em que foi proferida; d) estar traduzida por intérprete autorizado; e) ter sido homologada pelo STF e pelo STJ. Será executada no Brasil a sentença proferida no estrangeiro, que reúna os seguintes requisitos: a) haver sido","e":"proferida por juiz competente; b) terem sido as partes citadas ou haver-se legalmente verificado à revelia; c) ter passado em julgado e estar revestida das formalidades necessárias para a execução no lugar em que foi proferida; d) estar traduzida por intérprete autorizado; e) ter sido homologada pelo STF.","gabarito":"C","materia":"Direito Civil","tema":"Lei de Introdução às Normas do Direito Brasileiro (LINDB)","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3179585","enunciado":"Assinale a alternativa correta:","a":"Realizando-se o casamento no Brasil, será aplicada a lei brasileira quanto aos impedimentos dirimentes e às formalidades da celebração.","b":"Tendo os nubentes domicílios diversos, regerá os casos de invalidade do matrimônio a lei de qualquer domicílio conjugal.","c":"A obrigação resultante do contrato reputa-se constituída no lugar em que residir o proponente ou em outro local, a","d":"depender da vontade das partes. A lei do domicílio do herdeiro ou legatário pode regular a capacidade para suceder.","e":"Os governos estrangeiros, bem como as organizações de qualquer natureza, que eles tenham constituído, dirijam ou hajam investido de funções públicas, poderão adquirir no Brasil bens imóveis ou suscetíveis de desapropriação. Direito Ambiental>Proteção do Meio Ambiente em Normas Infraconstitucionais ,","gabarito":"A","materia":"Direito Civil","tema":"Lei de Introdução às Normas do Direito Brasileiro (LINDB)","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_14","enunciado":"Ano: 2025 Banca: FGV Órgão: TRF - 3ª REGIÃO Prova: FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto De acordo com a Lei nº 9.433/1997, assinale a alternativa correta:","a":"É objetivo da Política Nacional de Recursos Hídricos a prevenção e defesa contra enchentes e inundações de origem natural ou decorrentes do uso inadequado dos recursos naturais.","b":"O sistema de informações sobre recursos hídricos pressupõe a centralização da obtenção de dados e controle de acesso por parte da União para o planejamento e elaboração de seu Plano de Recursos Hídricos.","c":"A efetivação da outorga de direitos de uso de recursos hídricos contempla o princípio da participação na medida em que permite a colaboração da sociedade civil no processo decisório.","d":"O Sistema Nacional de Gerenciamento de Recursos Hídricos é composto por diversos órgãos da administração pública federal, mas a implementação da Política Nacional de Recursos Hídricos compete aos Executivos Estaduais e Municipais.","e":"O regime de outorga de direitos de uso de recursos hídricos tem como objetivo assegurar o controle quantitativo e qualitativo dos usos da água, sendo efetivado apenas por ato da autoridade competente do Poder Executivo Federal ou, por delegação, dos Estados ou do Distrito Federal. Direito Ambiental>Responsabilidade ambiental ,Instrumentos da Política Nacional do Meio Ambiente ,","gabarito":"","materia":"Geral","tema":"","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3179583","enunciado":"Ano: 2025 Banca: FGV Órgão: TRF - 3ª REGIÃO Prova: FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto No que concerne a atividades de mineração, assinale a alternativa correta:","a":"Por força do Decreto-lei nº 227/1967, conclui-se que o monitoramento dos riscos da atividade de mineração não é obrigação da empresa, sendo obrigatória a inspeção dos órgãos públicos ambientais.","b":"A Lei de Segurança de Barragens (Lei nº 12.334/2010) prescreve a necessidade de classificar a atividade por categoria de risco, conforme os aspectos que possam influenciar na possibilidade de ocorrência de acidente ou desastre.","c":"Para a lavra garimpeira de pequeno potencial de impacto ambiental, o STF tem permitido a dispensa ou a simplificação do processo de licenciamento ambiental para atividade de mineração a céu aberto, por norma do legislador estadual.","d":"Aquele que explorar recursos minerais tem a obrigação constitucional de recuperar o meio ambiente degradado, mediante melhor solução técnica disponível pelo próprio detentor da concessão ou da permissão de lavra ou autorização de pesquisa.","e":"A Lei nº 7.805/1989 estabelece que o permissionário da lavra garimpeira deve evitar o extravio das águas e promover a sua drenagem para que não causem danos a terceiros, não prevendo, porém, o dever de tratar aquelas que possam causar danos a terceiros.","gabarito":"B","materia":"Proteção do Meio Ambiente em Normas InfraconstitucionaisRecursos Minerais e legislação correlata","tema":"","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3179582","enunciado":"Assinale a alternativa correta:","a":"As modalidades de pagamento por serviços ambientais poderão ser previamente pactuadas entre pagadores e provedores, mas o órgão gestor da PNPSA deverá estabelecer outras modalidades por atos normativos.","b":"No contexto dos direitos territoriais, os povos e comunidades tradicionais poderão ter o direito de voltar a suas terras tradicionais, ainda que persistam as causas que motivaram seus translados com reassentamento, conforme a Convenção OIT 169.","c":"Ao aplicar as disposições da Convenção OIT 169, os governos poderão consultar os povos interessados, mediante procedimentos apropriados, cada vez que sejam previstas medidas legislativas ou administrativas suscetíveis de afetá- los diretamente, de forma livre, prévia, informada e de boa fé. Nos casos de isenção da obrigação de repartição de benefícios pelas microempresas, empresas de pequeno porte,","d":"microempreendedores individuais, agricultores tradicionais e suas cooperativas, nos termos dos dispositivos da Lei nº 13.123/2015, os detentores do conhecimento tradicional associado à biodiversidade ficam excluídos de programas de repartição de benefícios para manutenção dos sistemas de cultivo. Segundo o STF, é constitucionalmente legítima a indissociabilidade dos direitos territoriais e do direito de existir como","e":"comunidade tradicional. Dada a íntima relação entre a posse das terras coletivas e a reprodução física e cultural das comunidades tradicionais, os direitos territoriais resultam abrangidos pelo direito fundamental à cultura (art. 215 da Constituição da República).","gabarito":"E","materia":"Direito Constitucional","tema":"Educação, Cultura e Desporto ,Ordem Social","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3179581","enunciado":"","a":"respeito da biodiversidade, assinale a alternativa correta: De acordo com a Lei nº 13.123/2015, não é permitida a remessa ao exterior de amostras de patrimônio genético, A sendo vedado também o acesso por pessoa natural estrangeira.","b":"É possível o acesso ao patrimônio genético ou ao conhecimento tradicional associado realizado no exterior por pessoa natural estrangeira, desde que associada a instituição nacional de pesquisa científica e tecnológica.","c":"A Lei nº 13.123/2015 dispõe sobre o acesso ao patrimônio genético de todas as espécies vegetais, animais, microbianas ou espécies de outra natureza, mas não se aplica ao patrimônio genético humano.","d":"É possível o acesso ao patrimônio genético ou ao conhecimento tradicional associado realizado no exterior, mas apenas por pessoa jurídica nacional pública.","e":"Não é permitida a exploração econômica do produto acabado ou material reprodutivo oriundo de acesso ao patrimônio genético ou ao conhecimento tradicional associado produzidos fora do País. Legislação Federal>","gabarito":"C","materia":"Legislação Federal","tema":"Lei nº 13.123 de 2015 - Dispõe sobre o Acesso ao Patrimônio Genético","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_18","enunciado":"Ano: 2025 Banca: FGV Órgão: TRF - 3ª REGIÃO Prova: FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto O princípio da precaução mais amplo independe da incerteza quanto ao risco para a adoção das medidas preventivas e","a":"mitigadoras da situação de risco ambiental. Acerca desta concepção, assinale a alternativa correta: Tem abrigo constitucional e está previsto na lei de política nacional de segurança de barragens, Lei nº 12.334/2010.","b":"Foi previsto na Lei de Política Nacional de Educação Ambiental (Lei nº 14.926/2024, que alterou a Lei nº 9.795/1999).","c":"Encontra-se previsto na Lei da Política Nacional de Biossegurança (Lei nº 11.105/2005).","d":"Está previsto na Lei de Política Nacional de Defesa Civil (Lei nº 12.608/2012).","e":"Está prevista na Lei da Política Nacional de Qualidade do Ar (Lei nº 14.850/2024). Direito Ambiental>Instrumentos da Política Nacional do Meio Ambiente , Instrumentos econômicos. Concessão florestal, servidão ambiental, seguro ambiental e outros. ,","gabarito":"","materia":"Geral","tema":"","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_19","enunciado":"Ano: 2025 Banca: FGV Órgão: TRF - 3ª REGIÃO Prova: FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto Assinale a alternativa correta:","a":"Nos termos da legislação federal, o servidor ocupante de cargo em comissão ou de natureza especial não poderá ser nomeado para o exercício interino de outro cargo em comissão ou função de confiança, sem prejuízo das atribuições do que já ocupa, mesmo que optar pela remuneração de um deles durante o período da interinidade.","b":"Para a legislação federal, recondução é o retorno do servidor estável ao cargo anteriormente ocupado, quando invalidada a sua demissão, com ressarcimento de todas suas vantagens.","c":"Nos termos da legislação federal, o servidor aposentado pode requerer o retorno (reversão) à atividade, no interesse da administração, nos casos em que: tenha se aposentado voluntariamente; se estável quando na atividade; se houver cargo vago e, desde que, a aposentadoria tenha ocorrido nos cinco anos anteriores à solicitação de retorno.","d":"Para a legislação federal, os servidores públicos serão responsabilizados objetivamente, nos âmbitos administrativo e civil, pelos atos lesivos ao patrimônio público praticados em seu interesse ou benefício, exclusivo ou não.","e":"Os entes da federação devem instituir, no âmbito de suas respectivas competências, regime jurídico único, de caráter estatutário, integrado por servidores da administração pública direta, das autarquias e das fundações públicas.","gabarito":"","materia":"Geral","tema":"","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3179577","enunciado":"Assinale a alternativa correta:","a":"No caso da desapropriação para fins de utilidade pública, os bens desapropriados e os direitos decorrentes da respectiva imissão na posse não poderão ser alienados a terceiros, locados, cedidos, arrendados, outorgados em regimes de concessão de direito real de uso, de concessão comum ou de parceria público-privada.","b":"Os concessionários, inclusive aqueles contratados nos termos da Lei nº 11.079/2004 (Lei de Parceria Público-Privada), permissionários, autorizatários e arrendatários poderão promover desapropriação mediante autorização expressa constante de lei ou contrato.","c":"A desapropriação por utilidade pública não poderá abranger áreas contíguas aquelas estritamente necessárias ao desenvolvimento da obra ou empreendimento a que se destinem.","d":"O expropriante tem o prazo de 5 (cinco) anos, a partir da decretação da desapropriação por interesse social, para efetivar a aludida desapropriação e iniciar as providências de aproveitamento do bem expropriado, sendo reduzido o referido prazo para 3 (três) anos, nos casos de reforma agrária. Nos processos de desapropriação para reforma agrária, as partes podem realizar acordo administrativo ou judicial,","e":"sendo que, na hipótese de acordo administrativo o pagamento da indenização será efetuado de modo prévio e em dinheiro, enquanto no acordo judicial o pagamento será feito de forma escalonada em Títulos da Dívida Agrária (TDA), resgatáveis em parcelas anuais, iguais e sucessivas, a partir do segundo ano de sua emissão. Direito Econômico>A Ordem Econômica Constitucional ,Princípios Gerais da Atividade Econômica , Intervenção do Estado na Ordem EconômicaA Intervenção Indireta e a Regulação Estatal ,","gabarito":"B","materia":"Direito Administrativo","tema":"Intervenção do estado na propriedade ,Noções gerais e desapropriação","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_21","enunciado":"O Sistema Brasileiro de Defesa da Concorrência: Finalidade, Territorialidade e Composição Ano: 2025 Banca: FGV Órgão: TRF - 3ª REGIÃO Prova: FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","a":"Assinale a alternativa correta: Agência Nacional de Transportes Terrestres (ANTT), no cumprimento das diretrizes gerais para o transporte terrestre, poderá celebrar contatos de concessão de serviços públicos para a exploração de infraestrutura rodoviária; A para a prestação de serviços de transporte terrestre coletivo de passageiros desvinculados da exploração da infraestrutura rodoviária e, finalmente, para a prestação eventual, sem cobrança de tarifa, de serviços de transporte coletivo de passageiros.","b":"Segundo a legislação federal, a Agência Nacional do Petróleo, Gás Natural e Biocombustíveis (ANP) não pode proibir que empresas estrangeiras sem sede no país celebrem contratos de concessão de serviços púbicos que lhes facultem a produção, industrialização e exploração comercial de gás natural. A Agência Nacional do Petróleo, Gás Natural e Biocombustíveis (ANP), sempre que necessário, deve elaborar os editais","c":"e promover as licitações para a concessão de serviços públicos de produção de petróleo, compreendidas as atividades de refinação, liquefação, regaseificação, carregamento, processamento, tratamento, transporte, estocagem e acondicionamento. Defeso o monitoramento da evolução dos preços de medicamentos, equipamentos, componentes, insumos e serviços","d":"de saúde, à Agência Nacional de Vigilância Sanitária (ANVISA) compete promover a proteção da saúde da população, por intermédio do controle sanitário da produção e da comercialização de produtos e serviços submetidos à vigilância sanitária.","e":"A legislação federal admite a exploração de serviço público de telecomunicações no regime privado, baseada nos princípios constitucionais da atividade econômica, a qual dependerá de prévia autorização da Agência Nacional de Telecomunicações (ANATEL). Legislação Federal>","gabarito":"","materia":"Geral","tema":"","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_22","enunciado":"Ano: 2025 Banca: FGV Órgão: TRF - 3ª REGIÃO Prova: FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto Assinale a alternativa correta:","a":"Depende de concessão de serviço público, mediante licitação, a delegação do transporte de cargas e passageiros, pelos meios rodoviário, ferroviário e aquaviário.","b":"A tarifa do serviço público concedido será fixada por lei de iniciativa do poder executivo que estabelecerá os critérios de reajuste e de revisão tarifárias.","c":"É necessária a realização de licitação prévia para transferência da concessão ou do controle societário de concessionária de serviços.","d":"Em havendo alteração unilateral do contrato que afete o seu inicial equilíbrio econômico-financeiro, o poder concedente deverá restabelecê-lo, concomitantemente à alteração. Incumbe à concessionária a execução do serviço concedido, cabendo-lhe responder por todos os prejuízos causados","e":"ao poder concedente, aos usuários ou a terceiros, permitida a contratação com terceiros para o desenvolvimento de atividades acessórias ou complementares ao serviço concedido, bem como para a implementação de projetos associados, mas vedada a contratação de terceiros para atividades inerentes ao objeto concedido. Legislação Federal>","gabarito":"","materia":"Geral","tema":"","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_23","enunciado":"Ano: 2025 Banca: FGV Órgão: TRF - 3ª REGIÃO Prova: FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto Assinale a alternativa correta: Para os fins da Lei nº 13.019/2014, considera-se organização da sociedade civil a entidade privada sem fins lucrativos que não distribua entre os seus sócios ou associados, conselheiros, diretores, empregados, doadores ou terceiros","a":"eventuais resultados, sobras, excedentes operacionais, brutos ou líquidos, dividendos, isenções de qualquer natureza, participações ou parcelas do seu patrimônio, auferidos mediante o exercício de suas atividades, e que os aplique integralmente na consecução do respectivo objeto social, de forma imediata ou por meio da constituição de fundo patrimonial ou fundo de reserva. No contexto da Lei nº 13.019/2014, acordo de cooperação é o instrumento por meio do qual são formalizadas as","b":"parcerias estabelecidas pela administração pública com organizações da sociedade civil para a consecução de finalidades de interesse público e recíproco propostas pelas organizações da sociedade civil, que envolvam a transferência de recursos financeiros.","c":"No contexto da Lei nº 13.019/2014, comissão de monitoramento e avaliação é o órgão criado pelo poder público para atuar como instância consultiva, na respectiva área de atuação, na formulação, implementação, acompanhamento, monitoramento e avaliação de políticas públicas.","d":"Para a realização de parcerias com organizações da sociedade civil o administrador público realizará prévia licitação, nos termos da Lei nº 14.133/2021.","e":"O Procedimento de Manifestação de Interesse Social é o instrumento por meio do qual as organizações da sociedade civil poderão apresentar propostas ao poder público nos casos de dispensa de licitação estabelecidos pela Lei nº 14.133/2021. Direito Administrativo>Organização da Administração Pública ,Regime jurídico administrativo ,","gabarito":"","materia":"Geral","tema":"","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3179573","enunciado":"Ano: 2025 Banca: FGV Órgão: TRF - 3ª REGIÃO Prova: FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto Assinale a alternativa correta:","a":"Segundo a legislação federal, coaduna-se com a livre iniciativa a regulação de mercado que, de modo amplo, crie requisitos, impeça a adoção de tecnologias, processos ou modelos de negócios, aumente custos de transação, ainda que restrinja a concorrência em certa medida. As empresas públicas e as sociedades de economia mista constituídas por um determinado ente da federação","b":"poderão realizar contrato de programa com outro ente da federação, no âmbito da gestão associada ou interfederativa de quaisquer serviços públicos, sempre que previsto em contrato de consórcio público ou convênio de cooperação. Segundo a legislação federal, o silêncio da autoridade competente importará na aprovação tácita das solicitações de","c":"atos públicos de liberação da atividade econômica, sem exceções, desde que excedido o prazo legal fixado para a decisão administrativa e apresentados pelo particular todos os elementos necessários à instrução e decisão do processo. Empresa pública prestadora de serviço público e dependente é a entidade dotada de personalidade jurídica de direito","d":"público, com criação autorizada por lei e com patrimônio próprio, cujo capital social é integralmente detido pela União, pelos Estados, pelo Distrito Federal ou pelos Municípios, cujos bens são impenhoráveis e que desfruta de imunidade tributária, em semelhança ao que ocorre nas autarquias.","e":"Segundo a legislação federal, interpretam-se em favor da liberdade econômica, da boa-fé e do respeito aos contratos, aos investimentos e à propriedade todas as normas de ordenação pública sobre atividades econômicas privadas. Legislação Federal>","gabarito":"E","materia":"Empresas Públicas e Sociedades de Economia Mista","tema":"","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_25","enunciado":"Ano: 2025 Banca: FGV Órgão: TRF - 3ª REGIÃO Prova: FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto Assinale a alternativa correta: No âmbito da Administração Federal, a natureza especial conferida à agência reguladora é caracterizada pela ausência","a":"de tutela ou de subordinação hierárquica e, assim sendo, pela desnecessidade de autorização ministerial específica para a realização de concursos públicos, ou para o provimento dos cargos relativos ao seu quadro de pessoal autorizados em lei. Previamente à tomada de decisão sobre as minutas e as propostas de alteração de atos normativos de interesse geral","b":"dos agentes econômicos, consumidores ou usuários dos serviços prestados, conforme deliberação pelo conselho diretor ou pela diretoria colegiada, mediante motivação específica, é facultada às agências reguladoras federais a possibilidade de realização de consulta pública. No âmbito das agências reguladoras federais, a adoção e as propostas de alteração de atos normativos de interesse","c":"geral dos agentes econômicos, consumidores ou usuários dos serviços prestados serão precedidas, nos termos da regulamentação específica, da realização de Análise de Impacto Regulatório (AIR), que conterá informações e dados sobre os possíveis efeitos do ato normativo.","d":"Conforme deliberação pelo conselho diretor ou pela diretoria colegiada, mediante motivação específica, é facultado a cada agência reguladora federal editar a chamada agenda regulatória, para explicitar o conjunto dos temas a serem regulamentados pela agência durante sua vigência.","e":"Na elaboração da Análise de Impacto Regulatório (AIR) não devem ser adotadas metodologias que afiram o custo- benefício e os riscos da norma administrativa cogitada.","gabarito":"","materia":"Geral","tema":"","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3179571","enunciado":"Assinale a alternativa correta:","a":"O direito de acesso à informação deve ser executado em conformidade com as seguintes diretrizes, dentre outras: observância da publicidade como preceito geral e do sigilo como exceção; desenvolvimento do controle social da administração pública e utilização de meios de comunicação viabilizados pela tecnologia da informação.","b":"É facultado aos órgãos e entidades públicas promover, independentemente de requerimentos, a divulgação em local de fácil acesso, no âmbito de suas competências, de informações de interesse coletivo ou geral por eles produzidas ou custodiadas.","c":"Qualquer interessado poderá apresentar pedido de acesso a informações, por qualquer meio legítimo, devendo o pedido conter a identificação do requerente, a especificação da informação requerida e os motivos determinantes da solicitação.","d":"O direito de acesso à informação é a faculdade de obter informação custodiada pelo Poder Público, pelos meios e nos modos em que a informação esteja mantida.","e":"O direito de acesso à informação sobre projetos públicos de pesquisa e desenvolvimento científicos ou tecnológicos é amplo e irrestrito. Direito Administrativo>Atos administrativos , Processo Administrativo - Lei nº 9.784 de 1999 e Lei nº 14.210 de 2021 ,Teoria das nulidades","gabarito":"A","materia":"Legislação Federal","tema":"Lei nº 12.527 de 2011 - Lei de Acesso à Informação e Decreto nº 7.724 de 2012","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3179570","enunciado":"Demais aspectos da lei 9.784/99 Ano: 2025 Banca: FGV Órgão: TRF - 3ª REGIÃO Prova: FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto Assinale a alternativa correta:","a":"No âmbito da Administração Federal direta e indireta, os processos administrativos de que resultem sanções poderão ser revistos, a pedido do interessado, no prazo máximo de 5 (cinco) anos da comunicação pessoal ou da publicação da penalidade.","b":"A motivação da decisão administrativa demonstrará a necessidade e a adequação da medida imposta ou da invalidação de ato, contrato, ajuste, processo ou norma administrativa, ônus que não se transmite à decisão jurisdicional que eventualmente a controle, diante da independência e harmonia dos Poderes.","c":"Ressalvados os casos expressamente previstos em lei, é vedado à autoridade administrativa celebrar compromisso com os interessados, em situação contenciosa, inclusive no caso de expedição de licença. A decisão administrativa ou jurisdicional que decretar a invalidação de ato administrativo deverá indicar, de modo","d":"expresso, suas consequências jurídicas e administrativas e deverá ainda, quando for o caso, apontar as condições para que a regularização ocorra de modo proporcional e equânime e sem prejuízo aos interesses gerais, não se podendo impor aos sujeitos atingidos ônus ou perdas que, em função das peculiaridades do caso, sejam anormais ou excessivos.","e":"Padece de nulidade absoluta a decisão administrativa que estabeleça interpretação ou orientação nova sobre norma de conteúdo indeterminado, impondo novo dever ou novo condicionamento de direito, e prevendo regime de transição para que o novo dever ou condicionamento de direito sejam integralmente aplicados.","gabarito":"D","materia":"Extinção dos atos administrativos","tema":"","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3179569","enunciado":"","a":"Assinale a alternativa correta: Lei nº 9.784/1999, com base no art. 22, I, da Constituição Federal, estabelece normas gerais sobre o processo A administrativo no âmbito da Administração brasileira direta e indireta, como também se aplica aos órgãos dos Poderes Legislativo e Judiciário, quando no desempenho de função administrativa.","b":"Nos processos administrativos, as normas jurídicas devem ser interpretadas da forma que melhor garanta o atendimento do fim público a que se dirige, vedada aplicação retroativa de nova interpretação.","c":"Segundo a legislação federal, a competência é irrenunciável e se exerce pelos órgãos administrativos ou titulares a que foi atribuída como própria, sendo proibido a estes delegá-la parcial ou integralmente a outros órgãos ou titulares.","d":"A participação em consulta pública confere, por si, a condição de interessado do processo, mas não confere o direito de obter da Administração resposta fundamentada a todas contribuições apresentadas","e":"Diante do princípio da livre apreciação das provas, encerrada a instrução do processo administrativo, a autoridade pública escolherá as evidências que entenda pertinentes para a motivação explícita de sua decisão.","gabarito":"B","materia":"Direito Administrativo","tema":"Processo Administrativo - Lei nº 9.784 de 1999 e Lei nº 14.210 de 2021","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3179568","enunciado":"Assinale a alternativa correta:","a":"Os usuários de imóveis da União, regularmente inscritos sob o Regime de Ocupação (ato administrativo precário), devem pagar anualmente a Taxa de Ocupação, cuja natureza é tributária. Nesse caso, o imóvel pertence integralmente à União, mas o ocupante tem o direito de utilização do bem. Os usuários de imóveis da União, inscritos sob o Regime de Aforamento, devem pagar anualmente o Foro, cuja","b":"natureza jurídica é receita patrimonial não tributária. O instituto jurídico do aforamento é conhecido como Enfiteuse, e o Foro (devido integralmente à União) deve ser utilizado para a realização de obras no município onde estão localizados os imóveis que ensejaram o recolhimento dessa receita. Cuidando de receitas patrimoniais não tributárias da União, o art. 47 da Lei nº 9.636/1998 prevê que o prazo de decadência decenal é contado do instante em que o respectivo crédito poderia ser constituído, a partir do","c":"conhecimento por iniciativa da União ou por solicitação do interessado das circunstâncias e fatos que caracterizam a hipótese de incidência da receita patrimonial, ficando limitada a 5 (cinco) anos a cobrança de créditos relativos a período anterior ao conhecimento pela União. Porque esse preceito legal rege toda a matéria de decadência e prescrição dessas receitas, são inexigíveis laudêmios cujos fatos geradores, decorrentes de cessões particulares, ocorreram há mais de 5 (cinco) anos do momento em que são levados ao conhecimento da União.","d":"Segundo a redação atual da Lei nº 9.636/1998 e o Tema 1142/STJ, os créditos originados de receitas patrimoniais não tributárias da União serão submetidos ao prazo decadencial de 5 (cinco) anos para sua constituição, mediante lançamento, e prescricional, também de 5 (cinco) anos para sua exigência, contados do lançamento.","e":"O laudêmio é a taxa paga previamente à venda de terreno de terreno de marinha pertencente à União, cuja obrigação propter rem tem natureza de receita patrimonial, a ele sendo aplicável o CTN, por analogia, no tocante aos prazos de decadência e de prescrição, pois a redação atual da Lei nº 9.636/1998 não cuida do assunto.","gabarito":"C","materia":"Direito Tributário","tema":"Extinção do Crédito Tributário ,Decadência ,Prescrição","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3179567","enunciado":"Assinale a alternativa correta: Diante do art. 146, III, “b”, da Constituição Federal, é constitucional o art. 40, §4º, da Lei 6.830/1980 (Lei de Execuções","a":"Fiscais), que regula a prescrição intercorrente no processo de execução fiscal, tendo natureza processual o prazo de 1 (um) ano de suspensão da execução fiscal. Após o decurso desse prazo, inicia-se automaticamente a contagem do prazo prescricional tributário de 5 (cinco) anos.","b":"Por força do art. 146, III, “b”, e do art. 195, §12, ambos da ordem de 1988, é constitucional o art. 13 da Lei nº 8.620/1993, na parte em que estabelece que os sócios de empresas por cotas de responsabilidade limitada respondem solidariamente, com seus bens pessoais, por débitos junto à Seguridade Social. O art. 139, IV, do CPC/2015, confere ao magistrado medidas extraordinárias (atípicas), de forma adicional ou subsidiária, quando as providências ordinárias (típicas, como penhora) se mostrarem ineficazes ou insuficientes para a exigência do crédito executado, sendo também necessário que o devedor se mostre furtivo no cumprimento de suas","c":"obrigações. Para a formação de seu convencimento, o magistrado está autorizado a utilizar indícios sobre a existência de recursos financeiros por parte do devedor que protela o pagamento da dívida, não podendo se amparar, tão somente, no combate à morosidade da prestação jurisdicional. Segundo o STF, dentre essas medidas excepcionais possíveis estão a proibição de participação em concurso e em licitação pública, mas não a apreensão de Carteira Nacional de Habilitação (CNH) e de passaporte, ou a suspensão do direito de dirigir, sob pena de violação ao direito fundamental de liberdade de locomoção.","d":"A contribuição destinada ao Serviço Brasileiro de Apoio às Micro e Pequenas Empresas - Sebrae possui natureza de contribuição no interesse de categoria profissional ou econômica, e não necessita de edição de lei complementar para ser instituída. Segundo o Tema 290/STJ, se o ato translativo foi praticado a partir de 09/06/2005 (data de início da vigência da Lei Complementar nº 118/2005), basta a efetivação da inscrição em dívida ativa para a configuração da figura da fraude","e":"presumida. No caso de a alienação ter ocorrido antes da entrada em vigor da Lei Complementar nº 118/2005 (que alterou o art. 185 do CTN), presume-se fraude à execução se o negócio jurídico tiver sido celebrado após a citação do devedor. Contudo, aplica-se à execução fiscal a Súmula 375/STJ, segundo a qual o reconhecimento da fraude à execução depende de prova da má-fé do vendedor e do terceiro adquirente. Direito Tributário>Obrigação Tributária ,Infrações em Direito Tributário ,Direito Penal Tributário","gabarito":"A","materia":"Direito Tributário","tema":"Execução Fiscal e Processo Tributário","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_31","enunciado":"Ano: 2025 Banca: FGV Órgão: TRF - 3ª REGIÃO Prova: FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto Sobre multas tributárias, considerando o direito tributário legislado e a jurisprudência predominante do STJ, assinale a alternativa correta:","a":"Multa tributária isolada é aquela aplicada em decorrência do descumprimento de obrigação tributária principal, mas","b":"que é documentada em instrumento separado do lançamento do tributo. Multa isolada e multa de ofício podem ser aplicadas conjuntamente.","c":"A alíquota das multas tributárias está limitada, no âmbito federal, ao percentual de 100% (cem por cento) do valor do tributo devido, independente de dolo, fraude, conluio ou reincidência.","d":"Em razão de as multas tributárias não serem tributos, os princípios constitucionais tributários da capacidade contributiva e do não-confisco não têm aplicação.","e":"Não cabe denúncia espontânea quando o tributo, sujeito ao lançamento por homologação, for declarado regularmente, mais pago a destempo. Direito Tributário>Lançamento Tributário ,Modalidades de Lançamento ,Extinção do Crédito Tributário","gabarito":"","materia":"Geral","tema":"","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_32","enunciado":"Ano: 2025 Banca: FGV Órgão: TRF - 3ª REGIÃO Prova: FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","a":"Assinale a alternativa correta. O CTN prescreve que: O lançamento dos tributos é ato privativo da Administração Pública ou do Poder Judiciário.","b":"A homologação do lançamento é ato de Administração Pública e do sujeito passivo do tributo.","c":"O sujeito passivo pode constituir o crédito tributário quando o tributo seja submetido a qualquer modalidade de lançamento, cabendo à Administração Pública a competência para examinar a posteriori.","d":"O lançamento misto ou por declaração é aquele em que a Administração Pública constitui o crédito tributário com informações próprias, do sujeito passivo ou de terceiros.","e":"Quando a legislação dispuser que o tributo está sujeito ao autolançamento ou lançamento por homologação, o prazo decadencial para a Fazenda Pública efetuar o lançamento tem início no primeiro dia do exercício seguinte.","gabarito":"","materia":"Geral","tema":"","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3179564","enunciado":"","a":"Sobre as causas de extinção do crédito tributário, assinale a alternativa correta: Os prazos de decadência e prescrição, em matéria tributária, somente podem ser previstos em lei complementar.","b":"O pagamento extingue o crédito tributário apenas quando expressamente homologado pela Fazenda Pública.","c":"O prazo decadencial de 5 (cinco) anos para constituição de tributos federais conta-se, independente da modalidade de constituição do crédito tributário, do primeiro dia do exercício seguinte ao exercício em que a fazenda pública poderia","d":"efetuar o lançamento. O parcelamento tributário regularmente deferido extingue o crédito tributário.","e":"A transação tributária em relação aos tributos federais, a partir do momento em que é celebrada, extingue o crédito tributário. Direito Tributário>Obrigação Tributária ,Solidariedade e Responsabilidade Tributária ,","gabarito":"A","materia":"Direito Tributário","tema":"Extinção do Crédito Tributário","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_34","enunciado":"Ano: 2025 Banca: FGV Órgão: TRF - 3ª REGIÃO Prova: FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto No que se refere à possibilidade de redirecionamento de execução fiscal por dissolução irregular da pessoa jurídica, ou na presunção de sua ocorrência, assinale a alternativa correta:","a":"Em razão das garantias e privilégios do crédito tributário (art. 183 do CTN), o redirecionamento pode ser autorizado contra o sócio ou o terceiro não sócio que, embora com poderes de gerência ao tempo do fato gerador da obrigação tributária não paga, regularmente se retirou da empresa e não deu causa à sua posterior dissolução irregular. À luz do art. 135, III, do CTN, o Tema 981/STJ admitiu o redirecionamento da somente contra o sócio com poderes de","b":"administração da sociedade, na data em que configurada a sua dissolução irregular ou a presunção de sua ocorrência (Súmula 435/STJ), e que, concomitantemente, tenha exercido poderes de gerência, na data em que ocorrido o fato gerador da obrigação tributária não adimplida.","c":"Com base no art. 135, III, do CTN, o Tema 981/STJ admitiu o redirecionamento da somente em relação ao sócio com poderes de administração da sociedade, na data em que configurada a sua dissolução irregular ou a presunção de sua ocorrência (Súmula 435/STJ). A dissolução irregular da pessoa jurídica não autoriza o redirecionamento da execução fiscal contra sócios e terceiros","d":"(disregard of legal entity), mas dada a responsabilidade pessoal por ato ilícito ou violação do contrato social, é possível esse redirecionar a dívida da empresa quando comprovada fraude no abandono de suas atividades, especificamente em relação àqueles que tinham poderes de gerência na área da empresa que cuidava de obrigações tributárias. Em vista do art. 135, III, do CTN, o Tema 981/STJ reconhece a possibilidade de redirecionamento contra: (i) o sócio com poderes de administração da sociedade, na data em que configurada a sua dissolução irregular ou a presunção de sua","e":"ocorrência (Súmula 435/STJ), e que, concomitantemente, tenha exercido poderes de gerência, na data em que ocorrido o fato gerador da obrigação tributária não adimplida; ou (ii) o sócio com poderes de administração da sociedade, na data em que configurada a sua dissolução irregular ou a presunção de sua ocorrência (Súmula 435/STJ), ainda que não tenha exercido poderes de gerência, na data em que ocorrido o fato gerador do tributo não adimplido. Direito Tributário>Legislação do Direito Tributário ,Função da Lei Complementar em Direito Tributário ,","gabarito":"","materia":"Geral","tema":"","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_35","enunciado":"Ano: 2025 Banca: FGV Órgão: TRF - 3ª REGIÃO Prova: FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto Sobre a Emenda Constitucional nº 132/2023, que institui a reforma tributária do consumo no Brasil, assinale a alternativa correta:","a":"Ao final do período de transição, serão extintos os seguintes tributos: Imposto sobre a Circulação de Mercadorias e Prestação de Serviços (ICMS), Imposto Sobre Bens e Serviços (ISSQN), Programa de Integração Social (PIS), Contribuição para Financiamento da Seguridade Social (COFINS) e Impostos sobre Produtos Industrializados (IPI).","b":"O Imposto sobre Bens e Serviços (IBS) e a Contribuição sobre Bens e Serviços (CBS) são tributos idênticos, variando apenas as alíquotas, que serão fixadas por cada pessoa política competente.","c":"A harmonização das interpretações administrativas atinentes à legislação da Contribuição sobre Bens e Serviços (CBS) será uniformizada pelo Comitê Gestor.","d":"Foram expressamente instituídos os princípios constitucionais tributários da simplicidade, a transparência, da justiça tributária, da cooperação e da defesa do meio ambiente.","e":"A concessão de incentivos e benefícios fiscais regionais deve sempre considerar os critérios de sustentabilidade ambiental e redução de emissões de carbono.","gabarito":"","materia":"Geral","tema":"","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3179561","enunciado":"Sobre as imunidades tributárias, nos termos da Constituição da República, do CTN e da jurisprudência do STF, assinale a alternativa correta:","a":"Estão previstas na Constituição Federal, mutilando a competência tributária em relação à instituição apenas de impostos e taxas.","b":"A lei complementar, ao dispor sobre a limitações ao poder de tributar, por ser lei nacional, pode criar novas hipóteses de imunidades tributárias, desde que não restrinja as já previstas na Constituição Federal.","c":"As entidades beneficentes de assistência social estão imunes em relação às contribuições para seguridade social, mesmo que, na literalidade do art. 195, §7º, da Constituição da República, conste a palavra isenção, razão pela qual somente a lei complementar pode estabelecer requisitos.","d":"A imunidade recíproca não se aplica às empresas públicas e sociedades de economia mista delegatárias de serviços","e":"públicos, porque elas estão submetidas ao regime jurídico de privado. Os cemitérios privados, por serem extensão de templo de qualquer culto, estão imunes aos impostos. Direito Tributário>Limitações Constitucionais ao Poder de Tributar - Princípios Tributários ,","gabarito":"C","materia":"Direito Tributário","tema":"Limitações Constitucionais ao Poder de Tributar - Imunidades","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_37","enunciado":"Ano: 2025 Banca: FGV Órgão: TRF - 3ª REGIÃO Prova: FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","a":"Assinale a alternativa correta. O princípio da estrita legalidade tributária, no Sistema Tributário Nacional, prescreve que: As obrigações acessórias, assim como as obrigações principais, devem ter seus critérios estabelecidos em lei.","b":"Alguns tributos de competência da União, por terem funções extrafiscais, podem ter suas alíquotas fixadas por decretos, mas dentro dos limites estabelecidos em lei.","c":"A sujeição passiva tributária, por ser uma decorrência necessária de quem praticou o fato gerador do tributo, pode ser","d":"previsto em ato normativo infralegal. As multas tributárias, por não serem tributos, podem ser instituídas por decretos.","e":"Os regulamentos dos tributos são atos normativos gerais e abstratas, buscando seus fundamentos diretamente na Constituição da República e não nas leis.","gabarito":"","materia":"Geral","tema":"","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3179559","enunciado":"","a":"Sobre as regras específicas do CTN acerca da interpretação da legislação tributária, assinale a alternativa correta: legislação tributária que dispõe sobre isenção deve ser interpretada de forma extensiva, com o objetivo de alcançar A situações semelhantes não previstas expressamente, conforme o princípio da equidade.","b":"A interpretação literal das normas tributárias no art. 111 do CTN é obrigatória nos casos que tratam de benefícios fiscais, mesmo que não sejam isenções.","c":"A interpretação literal das normas tributárias aplica-se apenas às disposições que tratam de criação de tributos, não abrangendo normas relativas à suspensão, isenção ou exclusão do crédito tributário.","d":"A legislação tributária que trata da responsabilidade por infrações deve ser interpretada de forma mais favorável ao contribuinte em caso de dúvida somente quanto à natureza da penalidade aplicável.","e":"A analogia é permitida para ampliar os casos de isenção tributária, desde que não haja prejuízo à arrecadação e que o benefício se justifique por razões de justiça fiscal.","gabarito":"B","materia":"Direito Tributário","tema":"Legislação do Direito Tributário ,Integração e interpretação da Lei Tributária","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3179558","enunciado":"Assinale a alternativa correta:","a":"O ingresso nas cooperativas é livre a todos que desejarem utilizar os serviços prestados pela sociedade, desde que adiram aos propósitos sociais e preencham as condições estabelecidas no estatuto, sendo vedada a recusa da adesão sob o argumento de impossibilidade técnica de prestação de serviços. É da competência exclusiva da Assembleia Geral Extraordinária deliberar sobre a fusão, incorporação ou desmembramento da sociedade cooperativa. Pela fusão, duas ou mais cooperativas formam nova sociedade. A fusão","b":"determina a extinção das sociedades que se unem para formar a nova sociedade que lhe sucederá nos direitos e obrigações. Pela incorporação, uma sociedade cooperativa absorve o patrimônio, recebe os associados, assume as obrigações e se investe nos direitos de outra ou outras cooperativas. As sociedades cooperativas também poderão desmembrar-se em tantas quantas forem necessárias para atender aos interesses dos seus associados, podendo uma das novas entidades ser constituída como cooperativa central ou federação de cooperativas.","c":"Na sociedade cooperativa, a responsabilidade dos sócios é ilimitada, respondendo o sócio solidária e ilimitadamente pelas obrigações sociais. As cooperativas são sociedades de pessoas, com forma e natureza jurídica próprias, de natureza civil, não sujeitas a","d":"falência, constituídas para prestar serviços aos associados. Dentre as características da sociedade cooperativa, pode- se citar: (i) variabilidade, ou dispensa do capital social; (ii) intransferibilidade das quotas do capital a terceiros estranhos à sociedade, ainda que por herança; e (iii) quorum, para a assembleia geral funcionar e deliberar, fundado no capital social representado. Considera-se Cooperativa de Trabalho a sociedade constituída por trabalhadores para o exercício de suas atividades laborativas ou profissionais com proveito comum, autonomia e autogestão para obterem melhor qualificação, renda,","e":"situação socioeconômica e condições gerais de trabalho. A autonomia deve ser exercida de forma coletiva e coordenada, mediante a fixação, em Assembleia Geral, das regras de funcionamento da cooperativa e da forma de execução dos trabalhos. Considera-se autogestão o processo democrático no qual a Assembleia Geral define as diretrizes para o funcionamento e as operações da cooperativa, e o conselho de administração decide sobre a forma de execução dos trabalhos. Direito Empresarial (Comercial)>Direito da Propriedade Industrial ,Bens tutelados ,","gabarito":"B","materia":"Direito Empresarial (Comercial)","tema":"Direito Societário","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_40","enunciado":"Ano: 2025 Banca: FGV Órgão: TRF - 3ª REGIÃO Prova: FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","a":"Assinale a alternativa correta: ação de nulidade de registro de marca poderá ser proposta pelo INPI ou por qualquer pessoa com legítimo interesse. O juiz poderá, nos autos da ação de nulidade, determinar liminarmente a suspensão dos efeitos do registro A e do uso da marca, atendidos os requisitos processuais próprios. A ação de nulidade do registro será ajuizada no foro da justiça federal e o INPI, quando não for autor, intervirá no feito. Prescreve em 5 (cinco) anos a ação para declarar a nulidade do registro, contados da data da sua concessão. A proteção dos direitos relativos à propriedade industrial, considerado o seu interesse social e o desenvolvimento","b":"tecnológico e econômico do País, efetua-se mediante: (i) concessão de patentes de invenção e de modelo de utilidade; (ii) concessão de registro de desenho industrial; (iii) concessão de registro de marca; (iv) repressão às falsas indicações geográficas; (v) prevenção e repressão às infrações contra a ordem econômica; e (vi) concessão de registro para jogos eletrônicos. É patenteável a invenção que atenda aos requisitos de novidade, atividade inventiva e aplicação industrial, bem como é patenteável como modelo de utilidade o objeto de uso prático, ou parte deste, suscetível de aplicação industrial, que","c":"apresente nova forma ou disposição, envolvendo ato inventivo, que resulte em melhoria funcional no seu uso ou em sua fabricação. Considera-se invenção ou modelo de utilidade, por exemplo: (i) esquemas, planos, princípios ou métodos comerciais, contábeis, financeiros, educativos, publicitários, de sorteio e de fiscalização; (ii) programas de computador em si; e (iii) técnicas e métodos operatórios ou cirúrgicos, bem como métodos terapêuticos ou de diagnóstico, para aplicação no corpo humano ou animal.","d":"Os atos do INPI nos processos administrativos referentes à propriedade industrial só produzem efeitos a partir da sua publicação no respectivo órgão oficial, inclusive as decisões administrativas, quando feita notificação por via postal ou por ciência dada ao interessado no processo. São suscetíveis de registro como marca os sinais distintivos visualmente perceptíveis, não compreendidos nas proibições legais. Nos termos da Lei, considera-se: (i) marca de produto ou serviço: aquela usada para distinguir produto ou serviço de outro idêntico, semelhante ou afim, de origem diversa; (ii) marca de certificação: aquela usada para atestar a conformidade de um produto ou serviço com determinadas normas ou especificações técnicas,","e":"notadamente quanto à qualidade, natureza, material utilizado e metodologia empregada; e (iii) marca coletiva: aquela usada para identificar produtos ou serviços provindos de membros de uma determinada entidade. À marca registrada no Brasil considerada de alto renome será assegurada proteção especial, em todos os ramos de atividade. A marca notoriamente conhecida em seu ramo de atividade goza de proteção especial, independentemente de estar previamente depositada ou registrada no Brasil, e o INPI poderá indeferir o pedido de registro de marca que reproduza ou imite, no todo ou em parte, marca notoriamente conhecida, apenas mediante iniciativa ou pedido da parte interessada.","gabarito":"","materia":"Geral","tema":"","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3179556","enunciado":"Assinale a alternativa correta: Os serviços do Registro Público de Empresas Mercantis e Atividades Afins serão exercidos, em todo o território nacional, de maneira uniforme, harmônica e interdependente, pelo Sistema Nacional de Registro de Empresas","a":"Mercantis (Sinrem), composto pelos seguintes órgãos: (i) o Departamento Nacional de Registro Empresarial e Integração, órgão central do Sinrem; e (ii) as Juntas Comerciais, como órgãos locais, com funções executora e administradora dos serviços de registro. Haverá uma junta comercial em cada unidade federativa, com sede na capital e jurisdição na área da circunscrição territorial respectiva. É vedado as juntas comerciais desconcentrar os seus serviços. Dos atos pertinentes ao registro público de empresas mercantis e atividades afins, o registro compreende no tocante ao arquivamento: (i) dos documentos relativos à constituição, alteração, dissolução e extinção de firmas mercantis individuais, sociedades mercantis e cooperativas; (ii) dos atos relativos a consórcio e grupo de sociedade de que trata","b":"a Lei de Sociedade por Ações; (iii) dos atos concernentes a empresas mercantis estrangeiras autorizadas a funcionar no Brasil; (iv) das declarações de microempresa; (v) de atos ou documentos que, por determinação legal, sejam atribuídos ao Registro Público de Empresas Mercantis e Atividades Afins ou daqueles que possam interessar ao empresário e às empresas mercantis. Podem ser arquivados os atos constitutivos de empresas mercantis que, além das cláusulas exigidas em lei, não designarem o respectivo capital e a declaração de seu objeto, cuja indicação no nome empresarial é facultativa. Todo ato, documento ou instrumento apresentado a arquivamento será objeto de exame do cumprimento das formalidades legais pela junta comercial. Verificada a existência de vício insanável, o requerimento será indeferido;","c":"quando for sanável, o processo será colocado em exigência. As exigências formuladas pela junta comercial deverão ser cumpridas dentro do prazo legal, contados da data da ciência pelo interessado ou da publicação do despacho. O processo em exigência será entregue completo ao interessado e, quando devolvido, independentemente do prazo, será considerado como novo pedido de arquivamento, sujeito ao pagamento dos preços dos serviços correspondentes.","d":"As juntas comerciais subordinam-se, administrativamente, ao governo federal e, tecnicamente, ao Departamento Nacional de Registro Empresarial e Integração. Os documentos, tais como os atos constitutivos, alterações e extinções de empresário individual, deverão ser apresentados a arquivamento na Junta Comercial, mediante requerimento dirigido ao seu Presidente, dentro do prazo","e":"legal contados de sua assinatura. As assinaturas nos requerimentos, instrumentos ou documentos particulares serão lançadas com a indicação do nome do signatário, por extenso, datilografado ou em letra de forma e do número de identidade e órgão expedidor, quando se tratar de testemunha. Quando houver indícios substanciais da falsificação, o Presidente da Junta Comercial deverá suspender os efeitos do ato até a comprovação da veracidade da assinatura.","gabarito":"E","materia":"Direito Empresarial (Comercial)","tema":"Teoria Geral do Direito Empresarial ,Registro e escrituração","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3179555","enunciado":"Assinale a alternativa correta:","a":"O possuidor de título ao portador tem direito à prestação nele indicada, mediante a sua simples apresentação ao devedor, sendo devida a prestação apenas se o título tenha entrado em circulação com a vontade do emitente.","b":"O pagamento de título de crédito, que contenha obrigação de pagar soma determinada, pode ser garantido por aval. O aval deve ser dado no verso ou no anverso do próprio título. Para a validade do aval, dado no anverso do título, é necessário a assinatura do avalista com firma reconhecida, não se admitindo assinatura digital, ainda que certificada.","c":"Considera-se legítimo possuidor o portador do título à ordem com série regular e ininterrupta de endossos, ainda que o último seja em branco. Embora não obrigado a verificar a autenticidade das assinaturas, aquele que paga o título está obrigado a verificar a regularidade da série de endossos. No ato da emissão da fatura, dela poderá ser extraída uma duplicata para circulação como efeito comercial, não sendo admitida qualquer outra espécie de título de crédito para documentar o saque do vendedor pela importância","d":"faturada ao comprador. A duplicata conterá: (i) a denominação \"duplicata\", a data de sua emissão e o número de ordem; (ii) o número da fatura; (iii) a data certa do vencimento ou a declaração de ser a duplicata à vista; (iv) o nome e domicílio do vendedor e do comprador; (v) a importância a pagar, em algarismos e por extenso; (vi) a praça de pagamento; (vii) a cláusula à ordem; e (viii) a declaração do reconhecimento de sua exatidão e da obrigação de pagá-la, a ser assinada pelo comprador, como aceite, cambial. A cédula de crédito rural é promessa de pagamento em dinheiro, sem ou com garantia real cedularmente constituída, sob as seguintes denominações e modalidades: (i) Cédula Rural Pignoratícia; (ii) Cédula Rural Hipotecária; (iii) Cédula","e":"Rural Pignoratícia e Hipotecária; e (iv) Nota de Crédito Rural. Em caso de cobrança em processo contencioso ou não, judicial ou administrativo, o emitente da cédula de crédito rural, da nota promissória rural, ou o aceitante da duplicata rural responderá ainda pela multa de 10% sobre o principal e acessórios em débito, devida a partir do primeiro despacho da autoridade competente na petição de cobrança ou de habilitação de crédito. Direito Financeiro>Atividade Financeira do Estado no Direito Financeiro ,","gabarito":"C","materia":"Direito Empresarial (Comercial)","tema":"Títulos de Crédito","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3179554","enunciado":"Ano: 2025 Banca: FGV Órgão: TRF - 3ª REGIÃO Prova: FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","a":"Assinale a alternativa correta: subvenção econômica destinada à pessoa física no ato da contratação que tenha por objetivo proporcionar a aquisição ou a produção da moradia por meio do Programa Minha Casa, Minha Vida será concedida apenas uma vez para cada beneficiário e poderá ser cumulativa com os descontos habitacionais concedidos nas operações de financiamento efetuadas com recursos do Fundo de Garantia do Tempo de Serviço (FGTS), vedada a sua concessão à pessoa física que: (i) seja titular de contrato de financiamento obtido com recursos do FGTS ou em condições equivalentes às do Sistema Financeiro da Habitação, em qualquer parte do País; (ii) seja proprietária, promitente compradora ou titular de direito de aquisição, de arrendamento, de usufruto ou de uso de imóvel residencial, regular, A com padrão mínimo de edificação e de habitabilidade estabelecido pelas regras da administração municipal, e dotado de abastecimento de água, de solução de esgotamento sanitário e de atendimento regular de energia elétrica, em qualquer parte do País; (iii) tenha recebido, nos últimos 10 anos, benefícios similares oriundos de subvenções econômicas concedidas com recursos do Orçamento-Geral da União, do Fundo de Arrendamento Residencial (FAR), do Fundo de Desenvolvimento Social (FDS) ou provenientes de descontos habitacionais concedidos com recursos do FGTS, excetuados as subvenções e os descontos destinados à aquisição de material de construção e o Crédito Instalação, disponibilizados pelo Instituto Nacional de Colonização e Reforma Agrária (Incra), na forma prevista em regulamentação específica. O Programa Minha Casa, Minha Vida atenderá famílias residentes em áreas urbanas com renda bruta familiar mensal de até R$ 8 mil e famílias residentes em áreas rurais com renda bruta familiar anual de até R$ 96 mil reais, conforme redação da Lei nº 14.620/2023, considerando faixas de renda para famílias residentes em áreas urbanas e faixas de","b":"renda para famílias residentes em áreas rurais. A atualização dos valores de renda bruta familiar deverá ser realizada anualmente, mediante ato do Ministro de Estado das Cidades. Para fins de enquadramento nas faixas de renda, o cálculo do valor de renda bruta familiar considerará os benefícios temporários de natureza indenizatória, assistencial ou previdenciária, como auxílio-doença, auxílio-acidente, seguro-desemprego, benefício de prestação continuada (BPC) e benefício do Programa Bolsa Família, ou outros que vierem a substituí-los. No âmbito do Programa Minha Casa, Minha Vida a União, por meio do Ministério das Cidades e da Caixa Econômica Federal, em conformidade com as dotações e disponibilidades orçamentárias e financeiras, poderá repassar aos entes estaduais, distrital e municipais, a título de transferência facultativa, fundo a fundo ou por meio da celebração de","c":"convênio, contrato de repasse ou instrumentos congêneres, no mínimo 5% (cinco por cento) da soma dos recursos de dotações orçamentárias da União, Fundo Nacional de Habitação de Interesse Social (FNHIS), Fundo de Arrendamento Residencial (FAR) e Fundo de Desenvolvimento Social (FDS), além dos recursos de emendas parlamentares, podendo ser utilizados para: (i) retomada de obras paradas; (ii) obras de retrofit ou requalificação; (iii) obras em Municípios de até 50 mil habitantes.","d":"Para os lotes urbanizados produzidos no âmbito do Programa Minha Casa, Minha Vida, o investimento realizado pelo empreendedor na rede de distribuição de energia elétrica não poderá ser revertido em subsídio ou desconto em tarifa aos proprietários de lote, independente da proporção do impacto do investimento na sua tarifa. A gestão operacional dos recursos do Orçamento-Geral da União será efetuada pela Caixa Econômica Federal, exceto quando destinados a: (i) complementar os descontos concedidos pelo FGTS; (ii) atender as famílias residentes em","e":"áreas rurais, na hipótese de concessão direta a pessoa física; ou (iii) alocar subvenção econômica com a finalidade de complementar o valor necessário a assegurar o equilíbrio econômico-financeiro das operações realizadas pelas instituições ou pelos agentes financeiros, incluídos os custos de alocação, de remuneração e de perda de capital e as despesas de contratação, de administração, de cobrança e de execução judicial e extrajudicial.","gabarito":"A","materia":"Atividade Financeira do Estado e Sistema Financeiro Nacional - SFN","tema":"","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3179553","enunciado":"","a":"Assinale a alternativa correta: As modificações do contrato social de sociedade simples dependem de aprovação da unanimidade dos sócios.","b":"A administração da sociedade simples, nada dispondo o contrato social, compete aos sócios em conjunto.","c":"São irrevogáveis os poderes do sócio de sociedade simples, investido na administração por cláusula expressa do contrato social, salvo justa causa judicialmente determinada.","d":"O sócio de sociedade simples pode, nas épocas determinadas por lei, examinar os livros e documentos, e o estado da caixa e da carteira da sociedade.","e":"A cessão de quota pelo sócio de sociedade simples deve ser precedida de oferta de preferência, em igualdade de condições, aos demais sócios. Legislação Federal>","gabarito":"C","materia":"Direito Empresarial (Comercial)","tema":"Direito Societário ,Sociedade Simples","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_45","enunciado":"Ano: 2025 Banca: FGV Órgão: TRF - 3ª REGIÃO Prova: FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto Assinale a alternativa correta: As operações de financiamento imobiliário em geral, no âmbito do Sistema de Financiamento Imobiliário – SFI, serão livremente pactuadas pelas partes, observadas algumas condições essenciais, como a reposição integral do valor","a":"emprestado e respectivo reajuste. A alienação fiduciária é o negócio jurídico pelo qual o fiduciante, com o escopo de garantia de obrigação própria ou de terceiro, contrata a transferência ao credor, ou fiduciário, da propriedade resolúvel de coisa imóvel. Vencida e não paga, no todo ou em parte, a dívida e constituído em mora o fiduciante, consolidarse-á a propriedade do imóvel em nome do fiduciário. O contrato poderá estabelecer o prazo de carência, após o qual será expedida a intimação. As operações de financiamento imobiliário em geral, no âmbito do Sistema de Financiamento Imobiliário – SFI, poderão ser garantidas, dentre outras, por alienação fiduciária de coisa imóvel. A alienação fiduciária é o negócio jurídico pelo qual o fiduciante, com o escopo de garantia de obrigação própria ou de terceiro, contrata a transferência ao credor, ou fiduciário, da propriedade resolúvel de coisa imóvel. Vencida e não paga, no todo ou em parte, a dívida e","b":"constituído em mora o fiduciante, consolidar-se-á a propriedade do imóvel em nome do fiduciário. O fiduciante, ou seu representante legal ou procurador regularmente constituído, será intimado, a requerimento do fiduciário, pelo oficial do competente Registro de Imóveis, a satisfazer, no prazo legal, a prestação vencida e as que se vencerem até a data do pagamento, os juros convencionais, as penalidades e os demais encargos contratuais, os encargos legais, inclusive tributos, as contribuições condominiais imputáveis ao imóvel, além das despesas de cobrança e de intimação. As operações de financiamento imobiliário em geral, no âmbito do Sistema de Financiamento Imobiliário – SFI, serão livremente pactuadas pelas partes, observadas algumas condições essenciais, como a reposição integral do valor","c":"emprestado e respectivo reajuste. A alienação fiduciária é o negócio jurídico pelo qual o fiduciante, com o escopo de garantia de obrigação própria ou de terceiro, contrata a transferência ao credor, ou fiduciário, da propriedade resolúvel de coisa imóvel. Vencida e não paga a dívida, no todo ou em parte, e constituídos em mora o devedor e, se for o caso, o terceiro fiduciante, será consolidada a propriedade do imóvel em nome do fiduciário. O contrato definirá o prazo de carência após o qual será expedida a intimação. As operações de financiamento imobiliário em geral, no âmbito do Sistema de Financiamento Imobiliário – SFI, poderão ser garantidas, dentre outras, por alienação fiduciária de coisa imóvel. A alienação fiduciária é o negócio jurídico pelo qual o fiduciante, com o escopo de garantia de obrigação própria ou de terceiro, contrata a transferência ao credor, ou fiduciário, da propriedade resolúvel de coisa imóvel. Vencida e não paga a dívida, no todo ou em parte, e","d":"constituídos em mora o devedor e, se for o caso, o terceiro fiduciante, será consolidada a propriedade do imóvel em nome do fiduciário. O devedor e, se for o caso, o terceiro fiduciante serão intimados, a requerimento do fiduciário, pelo oficial do registro de imóveis competente, a satisfazer, no prazo legal, a prestação vencida e aquelas que vencerem até a data do pagamento, os juros convencionais, as penalidades e os demais encargos contratuais, os encargos legais, inclusive os tributos, as contribuições condominiais imputáveis ao imóvel e as despesas de cobrança e de intimação. As operações de financiamento imobiliário em geral, no âmbito do Sistema de Financiamento Imobiliário – SFI, serão livremente pactuadas pelas partes, observadas algumas condições essenciais, como a reposição integral do valor emprestado e respectivo reajuste. A alienação fiduciária é o negócio jurídico pelo qual o fiduciante, com o escopo de","e":"garantia de obrigação própria ou de terceiro, contrata a transferência ao credor, ou fiduciário, da propriedade resolúvel de coisa imóvel. Vencida e não paga a dívida, no todo ou em parte, e constituídos em mora o devedor e, se for o caso, o terceiro fiduciante, será consolidada a propriedade do imóvel em nome do fiduciário. O contrato poderá estabelecer o prazo de carência, após o qual será expedida a intimação e quando não for estabelecido o prazo de carência no contrato, o prazo será estipulado pelo juiz. Direito Financeiro>Competência na Atividade Financeira do Estado e no SFN , Atividade Financeira do Estado no Direito Financeiro ,","gabarito":"","materia":"Geral","tema":"","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_46","enunciado":"Ano: 2025 Banca: FGV Órgão: TRF - 3ª REGIÃO Prova: FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto Assinale a alternativa correta:","a":"O Mandado de Segurança em matéria previdenciária pode ser utilizado quando a análise do pedido administrativo de concessão de auxílio-doença ultrapassar 30 (trinta) dias sem resposta.","b":"O Mandado de Segurança em matéria previdenciária pode ser impetrado em hipótese de redução de pagamento de benefício, desprovida de comunicação ao segurado e de decisão fundamentada.","c":"O Mandado de Segurança em matéria previdenciária não pode versar sobre o direito à aposentadoria por tempo de","d":"contribuição. O Mandado de Segurança em matéria previdenciária não comporta análise do direito à aposentadoria especial.","e":"Em caso de fraude e de cessação de benefício previdenciário, de forma abrupta, não se há de falar em impetração de Mandado de Segurança Direito Processual Civil - Novo Código de Processo Civil - CPC 2015>Recursos ,Cumprimento de Sentença ,","gabarito":"","materia":"Geral","tema":"","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3179549","enunciado":"Ano: 2025 Banca: FGV Órgão: TRF - 3ª REGIÃO Prova: FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto Assinale a alternativa correta:","a":"O requerimento de limitação de litisconsórcio facultativo suspende o prazo para manifestação ou resposta, que recomeçará da intimação da decisão que o solucionar.","b":"Faz-se necessária a instauração de incidente de desconsideração de pessoa jurídica quando a desconsideração da personalidade jurídica for requerida na petição inicial, hipótese em que será citado o sócio ou a pessoa jurídica.","c":"Desafia interposição de recurso de apelação a decisão que decide parte do processo decretando decadência do direito postulado pela parte autora.","d":"Aos Juízes Federais compete processar e julgar as causas em que a União, entidade autárquica, empresa pública federal ou sociedade de economia mista forem interessadas na condição de autoras, rés, assistentes ou oponentes, exceto as de falência, as de acidentes de trabalho e as sujeitas à Justiça Eleitoral e à Justiça do Trabalho.","e":"Não serão devidos honorários no cumprimento de sentença contra a Fazenda Pública que enseje expedição de precatório, desde que não tenha sido impugnada. Direito Processual Civil - Novo Código de Processo Civil - CPC 2015>Tutela Provisória ,","gabarito":"E","materia":"LitisconsórcioIntervenção de Terceiro","tema":"","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_48","enunciado":"Ano: 2025 Banca: FGV Órgão: TRF - 3ª REGIÃO Prova: FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","a":"Assinale a alternativa correta: A tutela da evidência será concedida quando houver súmula de tribunal regional federal a respeito da matéria.","b":"A tutela de urgência será concedida quando houver elementos que evidenciem a probabilidade do direito ou o perigo","c":"de dano ou o risco ao resultado útil do processo. A tutela provisória será requerida ao juiz da causa e, quando antecedente, a qualquer juízo.","d":"A parte não responde pelo prejuízo que a efetivação da tutela de urgência causar à parte adversa, salvo em hipótese","e":"de má-fé. A tutela de urgência pode ser concedida liminarmente ou após justificação prévia.","gabarito":"","materia":"Geral","tema":"","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3179547","enunciado":"Quanto ao cumprimento de sentença, assinale a alternativa correta:","a":"Independe de demonstração de que se realizou a condição ou de que ocorreu o termo, quando o juiz decidir relação","b":"jurídica sujeita a condição ou termo. Não comporta intimação por edital.","c":"Não poderá ser promovido em face do fiador, do coobrigado ou do corresponsável que não tiver participado da fase","d":"de conhecimento. Possibilita nova discussão da lide ou modificação da sentença que a julgou em caso de matéria de ordem pública.","e":"Não incide em caso de benefícios assistenciais.","gabarito":"C","materia":"Direito Processual Civil - Novo Código de Processo Civil - CPC 2015","tema":"Cumprimento de Sentença","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3179546","enunciado":"Quanto à sentença, assinale a alternativa correta:","a":"É possível ao juiz proferir decisão de natureza diversa da pedida, bem como condenar a parte em quantidade superior","b":"ou em objeto diverso do que lhe foi demandado. Deve ser certa, salvo se resolver relação jurídica condicional.","c":"Pode invocar motivos que se prestariam a justificar qualquer outra decisão.","d":"Se, depois da propositura da ação, algum fato constitutivo, modificativo ou extintivo do direito influir no julgamento do mérito, caberá ao juiz tomá-lo em consideração, de ofício ou a requerimento da parte, no momento de proferir a","e":"decisão. Faz coisa julgada a verdade dos fatos, estabelecida como fundamento da sentença. Direito Processual Civil - Novo Código de Processo Civil - CPC 2015>Resposta do Réu e Revelia ,Contestação ,","gabarito":"D","materia":"Direito Processual Civil - Novo Código de Processo Civil - CPC 2015","tema":"Sentença ,Coisa Julgada no Processo Civil","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_51","enunciado":"Ano: 2025 Banca: FGV Órgão: TRF - 3ª REGIÃO Prova: FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto Assinale a alternativa correta:","a":"Na contestação, é lícito ao réu propor reconvenção para manifestar pretensão própria, conexa ou não com a ação","b":"principal ou com o fundamento da defesa. Depois da contestação, é lícito ao réu deduzir novas alegações quando relativas a direito ou fato superveniente.","c":"Se o réu alegar fato impeditivo, modificativo ou extintivo do direito do autor, este será ouvido no prazo de 20 (vinte)","d":"dias, permitindo-lhe o juiz a produção de prova. A produção antecipada da prova previne a competência do juízo para a ação que venha a ser proposta.","e":"A desistência da ação pode ser apresentada a qualquer tempo.","gabarito":"","materia":"Geral","tema":"","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3179544","enunciado":"","a":"Acerca da remessa necessária, assinale a alternativa correta: Ocorre na sentença que julgar procedentes, no todo ou em parte, os embargos à execução fiscal.","b":"Não se aplica quando a condenação ou o proveito econômico obtido na causa for de valor certo e líquido inferior a 500 (quinhentos) salários-mínimos para a União e as respectivas autarquias e fundações de direito público.","c":"Não se aplica quando a condenação ou o proveito econômico obtido na causa for de valor certo e líquido inferior a 200 (duzentos) salários-mínimos para os Municípios que não constituam capitais dos Estados e respectivas autarquias","d":"e fundações de direito público. É aplicável quando a sentença estiver fundada em súmula de tribunal superior.","e":"É aplicável quando a sentença estiver fundada em entendimento coincidente com orientação vinculante firmada no âmbito administrativo do próprio ente público, consolidada em manifestação, parecer ou súmula administrativa.","gabarito":"A","materia":"Direito Processual Civil - Novo Código de Processo Civil - CPC 2015","tema":"Remessa Necessária","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3179543","enunciado":"","a":"Quanto à penhora, assinale a alternativa correta: São impenhoráveis os bens alienáveis e os declarados, por ato voluntário, não sujeitos à execução.","b":"São impenhoráveis os vestuários, bem como os pertences de uso pessoal do executado, mesmo que de elevado valor.","c":"É impenhorável a pequena propriedade rural, assim definida em lei, ainda que não trabalhada pela família.","d":"São impenhoráveis os livros, as máquinas, as ferramentas, os utensílios, os instrumentos ou outros bens móveis","e":"necessários ou úteis ao exercício da profissão do executado. O seguro de vida é penhorável. Direito Processual Civil - Novo Código de Processo Civil - CPC 2015>Resposta do Réu e Revelia ,Reconvenção ,","gabarito":"D","materia":"Direito Processual Civil - Novo Código de Processo Civil - CPC 2015","tema":"Processo de Execução","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3179542","enunciado":"Ano: 2025 Banca: FGV Órgão: TRF - 3ª REGIÃO Prova: FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","a":"Assinale a alternativa correta: A Defensoria Pública gozará de prazo em dobro para todas as suas manifestações processuais.","b":"Havendo litisconsórcio, o desinteresse na realização da audiência pode ser manifestado por parte dos litisconsortes.","c":"O juiz conhecerá de ofício da incompetência relativa, da litispendência, da coisa julgada e da conexão.","d":"A desistência da ação ou a ocorrência de causa extintiva que impeça o exame de seu mérito obsta ao prosseguimento do processo quanto à reconvenção.","e":"Verificando a existência de irregularidades ou de vícios sanáveis, o juiz determinará sua correção em prazo nunca superior a 60 (sessenta) dias. Direito Processual Civil - Novo Código de Processo Civil - CPC 2015>Arguição de Impedimento e Suspeição ,","gabarito":"A","materia":"Sujeitos da Relação ProcessualDefensoria Pública no Processo Civil","tema":"","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_55","enunciado":"Ano: 2025 Banca: FGV Órgão: TRF - 3ª REGIÃO Prova: FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","a":"Assinale a alternativa correta: No sistema do atual CPC, é possível a criação de fato superveniente a fim de caracterizar impedimento do juiz.","b":"Há suspeição do juiz, sendo-lhe vedado exercer suas funções no processo de que conheceu em outro grau de jurisdição, tendo proferido decisão.","c":"Há impedimento do juiz, sendo-lhe vedado exercer suas funções no processo quando for herdeiro presuntivo,","d":"donatário ou empregador de qualquer das partes. O juiz só decidirá por equidade nos casos previstos em jurisprudência.","e":"O juiz dirigirá o processo conforme as disposições do CPC, incumbindo-lhe determinar, a qualquer tempo, o comparecimento pessoal das partes, para inquiri-las sobre os fatos da causa, hipótese em que incidirá a pena de confesso.","gabarito":"","materia":"Geral","tema":"","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3179540","enunciado":"","a":"Assinale a alternativa correta: O mandato não pode ser eficazmente substabelecido, se houver cláusula que o proíba.","b":"O mandato não pode ser objeto de revogação eficaz, se contiver cláusula que a proíba.","c":"O mandato se presume gratuito, salvo se houver previsão de que as despesas incorridas pelo mandatário devam ser ressarcidas.","d":"A cláusula ad judicia inserida em mandato confere ao mandatário, por si só, poderes para transigir, renunciar e celebrar compromisso.","e":"O mandato em termos gerais implica em poderes de administração, o que inclui a aplicação financeira de valores em espécie da titularidade do mandante.","gabarito":"E","materia":"Direito Civil","tema":"Contratos em Espécie ,Depósito, Mandato, Comissão, Agência e Distribuição","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3179539","enunciado":"Assinale a alternativa correta:","a":"Para promover a responsabilidade do construtor por vício, o adquirente do imóvel deve observar o prazo decadencial de cinco anos, além do prazo prescricional de cinco anos.","b":"Ao construtor é imposto um prazo legal de garantia pela solidez e segurança da construção. Ainda pode responder por vícios, no prazo prescricional de dez anos.","c":"Durante cinco anos, o construtor responde por vícios da construção, ficando liberado quanto aos vícios que se manifestem após esse prazo.","d":"O adquirente, sendo consumidor, deve reclamar por vícios aparentes ou não aparentes no prazo de cinco anos,","e":"contados da entrega da obra. Se o contrato for escrito, o construtor responderá por vícios, observada a prescrição trienal.","gabarito":"B","materia":"Direito Civil","tema":"Contratos em Espécie ,Prestação de Serviços e Empreitada","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3179538","enunciado":"Assinale a alternativa correta:","a":"Reduzir os juros vincendos de um empréstimo, na vigência de lei nova que os limitou, é exemplo de retroatividade","b":"máxima. Os limites à retroatividade da lei não se aplicam aos regulamentos administrativos.","c":"O direito sob condição suspensiva é considerado adquirido perante a lei nova; não é assim considerado no que tange","d":"aos efeitos do negócio jurídico. A expectativa de direito não gera efeitos jurídicos.","e":"O direito sujeito a termo inicial não é considerado adquirido.","gabarito":"C","materia":"Direito Civil","tema":"Ato Jurídico, Fato Jurídico e Teoria Geral do Negócio Jurídico ,Parte Geral","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3179536","enunciado":"","a":"Assinale a alternativa correta: responsabilidade do operador de instalação nuclear afere-se por risco integral, sendo irrelevante que o acidente A","b":"nuclear tenha sido provocado por fato de terceiro. O fortuito interno não interfere na responsabilidade do fornecedor, da mesma forma que o fortuito externo.","c":"O transportador de pessoa pode excluir, por cláusula expressa, a responsabilidade pela integridade de animal despachado pelo passageiro.","d":"A responsabilidade por dano causado por animal cabe a seu titular ou possuidor, sendo aferida pelo critério de culpa presumida.","e":"O CDC, por integrar a ordem pública interna, afasta a limitação de responsabilidade do transportador aéreo determinada por Convenção Internacional.","gabarito":"A","materia":"Direito do Consumidor","tema":"Proteção Contratual do Consumidor ,Contratos de Consumo","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3179535","enunciado":"","a":"Assinale a alternativa correta: A morte presumida e a ausência têm efeitos patrimoniais, mas não pessoais.","b":"Durante a fase de sucessão provisória do ausente, seus imóveis são inalienáveis, salvo por ordem judicial, ou desapropriação.","c":"A morte presumida é instituto aplicável apenas na pendência de guerra declarada, ou ainda no caso de ausência por mais de 20 anos.","d":"A sentença que decreta a morte presumida fixará a data da morte, podendo omiti-la se não for possível estabelecer a data exata.","e":"O ausente, ao ser assim declarado por sentença, será interditado para que seu patrimônio possa ser administrado por curador.","gabarito":"B","materia":"Direito Civil","tema":"Direito das Sucessões ,Ausência ,Parte Geral","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3179534","enunciado":"","a":"Assinale a alternativa correta: São incapazes para os atos da vida civil os ébrios, os deficientes mentais e os toxicômanos.","b":"Os deficientes mentais são capazes para os atos da vida civil, podendo receber curador para assisti-los nos atos de","c":"cunho patrimonial. Os deficientes podem praticar atos existenciais, desde que o façam com a anuência de dois apoiadores.","d":"Os toxicômanos, com entendimento reduzido, não podem mais ser interditados segundo a legislação hoje vigente.","e":"Os indígenas são sempre incapazes do ponto de vista individual, mas suas coletividades não o são. Direito Econômico>Noções Fundamentais de Direito Econômico ,A Ordem Econômica Constitucional ,","gabarito":"B","materia":"Direito Civil","tema":"Personalidade, Pessoa Natural e Capacidade ,Parte Geral","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_62","enunciado":"Ano: 2025 Banca: FGV Órgão: TRF - 3ª REGIÃO Prova: FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto Assinale a alternativa correta: O Conselho Administrativo de Defesa Econômica - Cade, por intermédio do Ministério Público Federal, poderá celebrar acordo de leniência, com a extinção da ação punitiva da administração pública ou a redução de 1 (um) a 2/3 (dois","a":"terços) da penalidade aplicável, nos termos previstos em lei, com pessoas físicas e jurídicas que forem autoras de infração à ordem econômica, desde que colaborem efetivamente com as investigações e o processo administrativo e que dessa colaboração resulte: (i) a identificação dos demais envolvidos na infração; e (ii) a obtenção de informações e documentos que comprovem a infração noticiada ou sob investigação. Nos crimes contra a ordem econômica, tipificados na lei que define crimes contra a ordem tributária, econômica e contra as relações de consumo, e nos demais crimes diretamente relacionados à prática de cartel, tais como os","b":"tipificados na Lei de Licitações e Contratos Administrativos, e os tipificados no CP, a celebração de acordo de leniência, nos termos da Lei de Defesa da Concorrência, determina a suspensão do curso do prazo prescricional e impede o oferecimento da denúncia com relação ao agente beneficiário da leniência. Cumprido o acordo de leniência pelo agente, extingue-se a punibilidade dos crimes mediante decisão judicial. Com vistas à promoção da concorrência e à eficácia na implementação da legislação de defesa da concorrência nos","c":"mercados regulados, as agências reguladoras e os órgãos de defesa da concorrência devem atuar em estreita cooperação, privilegiando a troca de experiências. No exercício de suas atribuições, incumbe aos órgãos de defesa da concorrência monitorar e acompanhar as práticas de mercado dos agentes dos setores regulados, de forma a auxiliar as agências reguladoras na observância do cumprimento da legislação de defesa da concorrência. Constitui crime contra a ordem econômica: (i) abusar do poder econômico, dominando o mercado ou eliminando, total ou parcialmente, a concorrência mediante ajuste ou acordo de empresas; (ii) formar acordo, convênio, ajuste ou aliança entre ofertantes, visando à fixação artificial de preços ou quantidades vendidas ou produzidas; (iii) discriminar preços de bens ou de prestação de serviços por ajustes ou acordo de grupo econômico, com o fim de estabelecer","d":"monopólio, ou de eliminar, total ou parcialmente, a concorrência; (iv) açambarcar, sonegar, destruir ou inutilizar bens de produção ou de consumo, com o fim de estabelecer monopólio ou de eliminar, total ou parcialmente, a concorrência; (v) provocar oscilação de preços em detrimento de empresa concorrente ou vendedor de matéria-prima, mediante ajuste ou acordo, ou por outro meio fraudulento; (vi) vender mercadorias abaixo do preço de custo, com o fim de impedir a concorrência; e (vii) elevar, sem justa causa, os preços de bens ou serviços, valendo-se de monopólio natural ou de fato. Pena - reclusão, de 2 (dois) a 5 (cinco) anos, e multa. Quando a agência reguladora, no exercício de suas atribuições, tomar conhecimento de fato que possa configurar infração à ordem econômica, deverá comunicá-lo imediatamente aos órgãos de defesa da concorrência para que","e":"esses adotem as providências cabíveis. Os órgãos de defesa da concorrência são responsáveis pela aplicação da legislação de defesa da concorrência nos setores regulados, incumbindo-lhes a análise de atos de concentração, bem como a instauração e a instrução de processos administrativos para apuração de infrações contra a ordem econômica. Direito Processual Penal>Competência no Processo Penal ,Das Questões e Processos Incidentes ,","gabarito":"","materia":"Geral","tema":"","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3179532","enunciado":"Ano: 2025 Banca: FGV Órgão: TRF - 3ª REGIÃO Prova: FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto Sobre a destinação de bens apreendidos em processos criminais, assinale a alternativa correta:","a":"Demonstrado o interesse público, o juiz poderá autorizar a utilização de bem apreendido, durante a investigação e o processo, por órgãos de segurança pública, os quais terão prioridade em caso de transferência definitiva do bem se houver decretação de perdimento na sentença condenatória transitada em julgado. O juiz deverá determinar a alienação antecipada dos bens apreendidos em processos criminais somente quando","b":"houver dificuldade para sua manutenção pelo Poder Público e o valor obtido em leilão ficará depositado em conta vinculada ao juízo até decisão final do processo, procedendo-se à sua conversão em renda para a União, Estado ou Distrito Federal, no caso de condenação, ou, no caso de sua absolvição, à devolução ao acusado.","c":"Quando a indisponibilidade recair sobre moeda nacional, o juízo deverá determinar o depósito dos valores em conta judicial, e quando se tratar de moeda estrangeira, deverá encaminhar o numerário apreendido ao Banco Central do Brasil.","d":"Em caso de certeza da infração e indícios suficientes de autoria, o ofendido poderá requerer a hipoteca legal sobre os imóveis do indiciado para garantir o ressarcimento do dano, mas haverá preferência ao pagamento das despesas processuais e das penas pecuniárias.","e":"Transitada em julgado a sentença condenatória, o juiz, de ofício ou a requerimento do interessado ou do Ministério Público, determinará a avaliação e a venda dos bens em leilão público cujo perdimento tenha sido decretado, sendo que o valor obtido será destinado aos cofres públicos se não couber ao lesado ou a terceiro de boa-fé.","gabarito":"E","materia":"Sequestro de Bens imóveisCompetência em matéria penal: definição, espécies e critérios","tema":"","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3179531","enunciado":"Assinale a alternativa correta quanto ao acordo de não persecução penal:","a":"Segundo entendimento do STJ, o acordo de não persecução penal possui natureza processual, devendo ser aplicado o princípio da imediatidade à norma que o instituiu e não a retroatividade de norma mais benéfica.","b":"Não cabe acordo de não persecução penal nos crimes fiscais porque uma de suas condições – a reparação do dano, exceto na impossibilidade de fazê-lo – constitui causa extintiva da punibilidade pelo cumprimento da obrigação tributária.","c":"Se o juiz considerar inadequadas, insuficientes ou abusivas as condições impostas no acordo de não persecução penal, deverá encaminhar imediatamente os autos ao Procurador-Geral ou às instâncias de revisão ministerial.","d":"Segundo a jurisprudência do STJ, o acordo de não persecução penal é inaplicável para os crimes de homofobia e transfobia, atribuindo-se a essas condutas o tratamento legal conferido ao crime de racismo.","e":"A audiência de homologação do acordo de não persecução penal poderá ser dispensada se ficar demonstrada a legalidade da proposta realizada e aceitação do investigado e de sua defesa. Direito Processual Penal>Da Prisão e da Liberdade Provisória ,Da Prisão Preventiva ,","gabarito":"D","materia":"Direito Processual Penal","tema":"Ação Penal ,Acordo de Não Persecução Penal","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_65","enunciado":"Ano: 2025 Banca: FGV Órgão: TRF - 3ª REGIÃO Prova: FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto Assinale a alternativa correta:","a":"Em qualquer fase da investigação policial ou do processo penal, caberá a prisão preventiva decretada de ofício pelo juiz, a requerimento do Ministério Público, do querelante ou do assistente, ou por representação da autoridade policial.","b":"O juiz poderá, de ofício ou a pedido das partes, revogar a medida cautelar ou substituí-la quando verificar a falta de motivo para que subsista, bem como voltar a decretá-la, se sobrevierem razões que a justifiquem.","c":"A prisão temporária poderá ser decretada em face de representação da autoridade policial ou requerimento do Ministério Público, em qualquer fase do inquérito ou do processo, tendo duração máxima de 5 dias, prorrogável por igual período, em caso de extrema e comprovada necessidade.","d":"Tratando-se de procedimento destinado à apuração da prática de crime hediondo, o prazo da prisão temporária poderá estender-se para 30 dias, ao final do qual, se não houver prorrogação, a autoridade policial deverá colocar o preso em liberdade assim que expedido o respectivo alvará de soltura pelo juiz que decretou a medida.","e":"A liberdade provisória tem como pressuposto uma prisão cautelar e não poderá ser concedida nos crimes inafiançáveis, tais como racismo e tortura. Direito Processual Penal>Inquérito Policial ,Das Provas ,Encerramento do Inquérito Policial","gabarito":"","materia":"Geral","tema":"","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_66","enunciado":"Ano: 2025 Banca: FGV Órgão: TRF - 3ª REGIÃO Prova: FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","a":"De acordo com a jurisprudência dos Tribunais Superiores, assinale a alternativa correta: serendipidade é admitida no ordenamento jurídico brasileiro, sendo válidas as provas encontradas relativas à A infração penal desconhecida, ainda que não exista conexão ou continência com o crime originário, desde que não haja desvio de finalidade na execução das diligências.","b":"A serendipidade é admitida no ordenamento jurídico brasileiro, desde que não haja desvio de finalidade na execução das diligências, sendo inválida a prova descoberta se não houver conexão ou continência entre o crime originário e aquele encontrado.","c":"Os elementos de informação trazidos pelo colaborador a respeito de crimes que não sejam conexos ao objeto da investigação primária não devem receber o mesmo tratamento conferido ao encontro fortuito de provas que ocorre em interceptação telefônica e na busca e apreensão.","d":"A possibilidade de guarda municipal realizar prisão em flagrante e diligências investigativas é discussão realizada no STF e se refere à falta de treinamento especializado e de previsão no CPP.","e":"Os procedimentos investigatórios criminais instaurados pelo Ministério Público Federal devem ser comunicados ao juiz competente e estão submetidos ao mesmo prazo de 60 dias previsto para a conclusão de inquéritos policiais federais, havendo necessidade de autorização judicial para eventual prorrogação.","gabarito":"","materia":"Geral","tema":"","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3179528","enunciado":"Em relação às provas digitais, assinale a alternativa correta:","a":"Considera-se prova digital qualquer informação produzida, armazenada ou transmitida por meios eletrônicos, incluindo os elementos nascidos em formato digital, mas não aqueles originalmente analógicos que foram digitalizados posteriormente.","b":"A preservação da cadeia de custódia das provas digitais tem a finalidade de garantir sua integridade e sua autenticidade, sendo que uma das etapas consiste em realizar cópias espelho e cálculo da função hash.","c":"A preservação da cadeia de custódia das provas digitais tem a finalidade de garantir sua autenticidade e tornar inacessíveis as informações para terceiros estranhos à investigação, assegurando sua força probatória e relevância.","d":"Todo o material digital coletado deve ser preservado, periciado e, posteriormente, inserido no sistema judicial eletrônico, a fim de garantir a publicidade e o exercício do contraditório e da ampla defesa pelas partes envolvidas.","e":"Nas diligências de investigação das evidências digitais é imprescindível a apreensão dos equipamentos para que, posteriormente, a defesa tenha acesso a todo o conteúdo, o que dispensa a necessidade de cópia de segurança.","gabarito":"B","materia":"Direito Processual Penal","tema":"Das Provas","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3179527","enunciado":"","a":"Assinale a alternativa correta: infiltração de agentes é meio de obtenção de provas que apenas pode ser destinada a investigar os crimes previstos A na Lei nº 12.850/2013 e os conexos, praticados por organização criminosa, devendo ser precedida de circunstanciada, motivada e sigilosa autorização judicial, que estabelecerá seus limites.","b":"A ação controlada consiste em retardar a intervenção policial ou administrativa relativa à ação praticada por organização criminosa ou a ela vinculada, devendo ser comunicada assim que possível ao juiz competente e ao Ministério Público para acompanhamento da medida.","c":"Segundo o STF, na apuração de crimes de lavagem de dinheiro, o Ministério Público e as autoridades policiais podem ter acesso a dados cadastrais de investigados mantidos por empresas de telefonia, sem a necessidade de prévia ordem judicial, tais como qualificação, filiação, endereço, e-mail e números de telefone.","d":"Entrega vigiada é a técnica que consiste em permitir que remessas ilícitas ou suspeitas saiam do território do país, o atravesse ou nele entre, com o conhecimento e sob o controle das autoridades competentes, com a finalidade de investigar infrações e identificar pessoas envolvidas na sua prática.","e":"Da mesma forma que a interceptação de comunicações telefônicas, a captação ambiental de sinais eletromagnéticos, ópticos ou acústicos sempre exige autorização judicial independentemente do local em que realizada.","gabarito":"D","materia":"Direito Processual Penal","tema":"Procedimentos Alternativos de Investigação Criminal ,Investigação Defensiva","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3179526","enunciado":"Assinale a alternativa correta:","a":"Em caso de conexão, a competência do Tribunal do Júri para os crimes dolosos contra a vida prevalece sobre a competência por prerrogativa de função porque se trata de matéria constitucional que se sobrepõe às demais regras previstas no ordenamento jurídico.","b":"A Justiça Eleitoral é competente para julgar os crimes eleitorais de falsidade ideológica e os conexos, exceto aqueles de competência da Justiça Federal e da Justiça Militar.","c":"Compete à Justiça Militar processar e julgar os crimes dolosos contra a vida cometidos por militares das forças armadas contra civis quando em missão para garantia da lei e da ordem, nos termos da Lei nº 13.491/2017.","d":"A competência federal para julgar os crimes de racismo se estabelece quando forem praticados mediante a divulgação de conteúdo em rede social, independentemente de se tratar de perfil aberto ou fechado e do alcance da publicação, diante da possibilidade de ser acessado pela rede mundial de computadores.","e":"A captação de recursos por meio de esquema denominado “pirâmide financeira” sempre caracteriza crime contra o sistema financeiro nacional, de competência da Justiça Federal, nos termos da Lei nº 7.492/1986.","gabarito":"C","materia":"Direito Processual Penal","tema":"Competência no Processo Penal","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3179525","enunciado":"","a":"Considerando o entendimento do STF, assinale a alternativa correta: competência do juiz das garantias abrange todas as infrações penais, exceto as contravenções penais, e cessa com o A oferecimento da denúncia ou queixa.","b":"O juiz que atuar como juiz das garantias na fase de investigação ficará impedido de funcionar no processo em razão do princípio da imparcialidade.","c":"Compete ao juiz das garantias assegurar ao investigado e ao seu defensor o acesso a todos os elementos informativos e provas produzidas na investigação criminal, salvo quanto às diligências em andamento. Os autos que compõem as matérias de competência do juiz das garantias ficarão acautelados na secretaria desse","d":"juízo, à disposição das partes, e não serão apensados aos autos do processo enviados ao juiz da instrução e julgamento, ressalvados os documentos relativos às provas irrepetíveis, medidas de obtenção de provas ou antecipação de provas.","e":"Caberá ao juiz das garantias assegurar o contraditório e a ampla defesa, necessariamente em audiência pública e oral, caso decida prorrogar prisão provisória ou outra medida cautelar, substituí-las ou revogá-las.","gabarito":"C","materia":"Direito Processual Penal","tema":"Sistemas de Investigação ,Investigação Preliminar: Juiz das Garantias","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3179524","enunciado":"Assinale a alternativa correta. Considere as seguintes Convenções Internacionais: Convenção sobre crimes cibernéticos – Budapeste (Decreto nº 11.491/2023); Convenção das Nações Unidas contra o Crime Organizado Transnacional – Palermo (Decreto nº 5.015/2004); Convenção das Nações Unidas contra a Corrupção – Mérida (Decreto nº 5.687/2006); Convenção contra o Tráfico Ilícito de Entorpecentes e Substâncias Psicotrópicas – Viena (Decreto nº 154/1991). Preconizam","a":"expressamente a responsabilidade penal da pessoa jurídica as seguintes Convenções: Budapeste, Palermo, Mérida e Viena.","b":"Apenas Palermo, Mérida e Viena.","c":"Apenas Budapeste, Palermo e Mérida.","d":"Apenas Budapeste Mérida e Viena.","e":"Apenas Palermo e Mérida. Direito Penal>Penas privativas de liberdade ,Noções gerais de dosimetria da pena privativa de liberdade ,","gabarito":"C","materia":"Direito Internacional Público","tema":"Direito Penal Internacional","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_72","enunciado":"Ano: 2025 Banca: FGV Órgão: TRF - 3ª REGIÃO Prova: FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto Assinale a alternativa correta. Tácito, portando arma de fogo, rende entregador dos correios e subtrai furgão cheio de mercadorias. Policiais que avistaram a cena de longe perseguem o veículo, prendendo Tácito, o qual admite o crime. No momento da sentença, verifica o juiz que consta da folha de antecedentes de Tácito: 3 condenações transitadas em julgado por roubos anteriores a estes fatos, 2 condenações transitadas em julgado por crimes cometidos posteriormente a estes, além de mais 2 processos","a":"em curso. Na dosimetria da pena, poderá o juiz: Exasperar a pena base com base nas ações em curso, pela conduta pessoal do agente.","b":"Compensar a multireincidência com a confissão, mantendo a pena estipulada na 1ª fase inalterada na 2ª fase.","c":"Reduzir a pena em 1/3, na 1ª fase, por conta da tentativa, considerando a aproximação da consumação do crime.","d":"Utilizar as condenações por crimes posteriores ao roubo, na 1ª fase, como maus antecedentes, e as condenações","e":"anteriores na 2ª fase, para agravar a pena. Utilizar o critério trifásico para estabelecer a dosimetria da pena restritiva de liberdade e da pena de multa.","gabarito":"","materia":"Geral","tema":"","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3179522","enunciado":"Assinale a alternativa correta. Úlpio, então funcionário do Ministério dos Transportes, solicita dois milhões de reais para elaborar parecer favorável à construção de uma nova rodovia. Recebe o valor em novembro de 2023, diretamente em conta no exterior, não declarada às autoridades brasileiras. Em janeiro de 2024, saca aqueles recursos e adquire para si imóvel no","a":"exterior, colocando-o em nome de Pacúvio, seu motorista. Úlpio poderá responder: Por corrupção passiva, evasão de divisas e lavagem de capitais.","b":"Por corrupção ativa, evasão de divisas e lavagem de capitais.","c":"Apenas por corrupção ativa e lavagem de capitais, tendo em vista que a evasão dos recursos não foi promovida por ele, mas pela construtora.","d":"Apenas por corrupção passiva e lavagem de capitais, tendo em vista que a evasão dos recursos não foi promovida por","e":"ele, mas pela construtora. Apenas pela corrupção passiva e evasão de divisas, sendo a compra do imóvel exaurimento do crime.","gabarito":"A","materia":"Direito Penal","tema":"Crimes contra a administração pública ,Corrupção passiva","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3179521","enunciado":"","a":"Assinale a alternativa correta. Está previsto nas Regras de Tóquio que: O fracasso de uma medida não privativa de liberdade deve conduzir à imposição de uma medida de prisão.","b":"No início da aplicação de uma medida não privativa de liberdade, deve-se explicar ao infrator, verbalmente e por","c":"escrito, seus direitos e obrigações. A escolha das medidas não privativas de liberdade deve levar em conta a vontade da vítima.","d":"Não podem ser adotadas sanções verbais.","e":"As medidas não privativas de liberdade não podem ser encerradas antecipadamente.","gabarito":"B","materia":"Direito Internacional Público","tema":"Direito Penal Internacional","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3179520","enunciado":"","a":"Sobre o Regime Disciplinar Diferenciado, segundo a legislação aplicável, assinale a alternativa correta: Tem duração de 2 anos, prorrogáveis uma única vez, por igual período.","b":"É cabível para membro de associação criminosa, independentemente de cometimento de falta grave.","c":"Todas as entrevistas são monitoradas.","d":"É cumprido sempre em estabelecimento penitenciário federal.","e":"Não é cabível em caso de prisão cautelar.","gabarito":"B","materia":"Direito Penal","tema":"Penas privativas de liberdade ,Regime Disciplinar Diferenciado","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3179519","enunciado":"Assinale a alternativa correta. Querendo se aposentar, em 2008, Catão contrata o despachante Lucrécio, o qual lhe esclarece que faltava tempo de serviço para tal benefício. Dias depois, Lucrécio liga para Catão, propondo que, por um valor extra, solicitaria a Plauto, dirigente sindical, que elaborasse uma declaração falsa de exercício de atividade rural, tendo a concordância de Catão. Após obter o documento, Lucrécio requereu o benefício ao INSS, concedido a Catão naquele mesmo ano. Em 2020, o INSS descobriu a fraude e suspendeu o benefício. Catão tem hoje 71 anos, Plauto tem 55 anos e Lucrécio faleceu. (Sabe-se que a pena privativa de liberdade do estelionato é de 1 a 5 anos; que a causa de aumento do art. 171, § 3º é de 1/3). Considerando a teoria binária do estelionato previdenciário, ao decidir sobre recebimento de denúncia, o","a":"juiz deverá reconhecer que: Os crimes de Plauto e Catão estão prescritos.","b":"Apenas o crime de Catão está prescrito.","c":"Apenas o crime de Plauto está prescrito.","d":"O crime de Plauto e os crimes referentes às parcelas mais antigas de Catão estão prescritos.","e":"Nenhum dos crimes está prescrito. Direito Penal>Lei do Colarinho Branco - Lei nº 7.492 de 1986 - Crimes contra o Sistema Financeiro Nacional ,","gabarito":"C","materia":"Direito Penal","tema":"Causas de extinção da punibilidade ,Prescrição. Conceito e modalidades","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_77","enunciado":"Ano: 2025 Banca: FGV Órgão: TRF - 3ª REGIÃO Prova: FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto Assinale a alternativa correta. Terêncio obteve financiamento para a compra de veículo automotor, mediante fraude,","a":"perante banco privado. Segundo a lei e a jurisprudência do STJ, Terêncio poderá responder por: Irrelevante penal.","b":"Crime de estelionato simples.","c":"Crime de estelionato qualificado.","d":"Crime de apropriação indébita por erro.","e":"Crime contra o sistema financeiro nacional","gabarito":"","materia":"Geral","tema":"","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3179517","enunciado":"Assinale a alternativa correta. Em um posto de abastecimento às margens de rodovia, ao abastecer a viatura, policiais rodoviários conseguiram avistar um motorista que saiu cambaleante da lanchonete, ligou seu veículo e o conduziu pela rodovia, até que os policiais conseguiram alcançá-lo, dando ordem de parada, a 2 km da saída do posto. Ao indagarem seus dados, ele disse se chamar Quinto Petílio, não apresentando nenhum documento, alegando portá-los em seu celular, que se encontrava descarregado. Percebendo estar o banco traseiro mais alto que o normal, com cobertor de mesma cor do estofado, os policiais encontraram ocultos 690 maços de cigarros paraguaios, sem autorização do órgão competente. No posto policial, os policiais conseguiram identificar que o motorista se tratava, na verdade, de Licínio Muciano, o qual detinha condenação anterior por embriaguez ao volante. Em teste de etilômetro, constatou-se volume de álcool por litro de ar expelido significativamente superior ao permitido. Segundo a atual jurisprudência consolidada do STJ, o motorista poderá","a":"responder: Pelos crimes de descaminho, embriaguez ao volante e falsa identidade.","b":"Pelos crimes de contrabando, embriaguez ao volante e falsa identidade.","c":"Pelo crime de embriaguez ao volante, estando a falsa identidade abrangida no direito de autodefesa e o fato relativo","d":"aos cigarros irrelevante penal. Pelos crimes de embriaguez ao volante e falsa identidade, sendo o fato relativo aos cigarros irrelevante penal.","e":"Pelos crimes de descaminho e embriaguez, estando a falsa identidade abrangida no direito de autodefesa. Direito Sanitário>Sistema Único de Saúde - SUS ,","gabarito":"D","materia":"Direito Penal","tema":"Crimes contra a administração pública ,Contrabando ,Descaminho","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_79","enunciado":"Ano: 2025 Banca: FGV Órgão: TRF - 3ª REGIÃO Prova: FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","a":"Assinale a alternativa correta: União Federal e o Instituto Nacional do Seguro Social têm legitimidade para figurar no polo passivo das ações em A que se postulam tratamentos médicos na Justiça Federal.","b":"De acordo com o Enunciado 2, aprovado na I Jornada de Direito da Saúde (2024), realizada pelo Conselho da Justiça Federal, nas ações que pleiteiam o fornecimento de medicamentos incorporados pelo Sistema Único de Saúde não é necessário o prévio requerimento administrativo, exigido tão-somente nas ações de natureza previdenciária.","c":"Estabelece a Lei nº 8.080/1990 que são subsistemas do Sistema Único de Saúde (SUS) o Subsistema de Atenção à Saúde Indígena, o Subsistema de Atendimento e Internação Domiciliar e o Subsistema de Acompanhamento à Mulher nos serviços de saúde.","d":"Constitui atribuição da CONITEC (Comissão Nacional de Incorporação de Tecnologias) elaborar, entre outros, pareceres técnicos Nat-Jus, a fim de auxiliar os magistrados na tomada de decisões (Lei nº 12.401/2011).","e":"Não é admissível a tramitação das ações relativas à saúde nos Juizados Especiais Federais, em razão da complexidade e da necessidade de prova pericial.","gabarito":"","materia":"Geral","tema":"","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3179515","enunciado":"Considerando a legislação vigente sobre a Assistência Social, assinale a alternativa correta:","a":"Os benefícios Bolsa Família, Farmácia Popular, Criança Feliz, Auxílio-Inclusão e Benefício ao Trabalhador Portuário (Lei nº 9.719/1998) têm natureza assistencial e não podem ser acumulados com outros benefícios previdenciários e assistenciais, salvo os da assistência médica ou as pensões especiais de natureza indenizatória. O benefício de prestação continuada é personalíssimo, devido aos brasileiros natos e naturalizados, não sendo devido","b":"aos estrangeiros, com exceção dos portugueses (em razão do Acordo de Seguridade Social firmado entre Brasil e Portugal (Decreto nº 8.805/2006), em respeito ao princípio constitucional que assegura o equilíbrio financeiro e atuarial da seguridade social.","c":"Para fins de cálculo da renda per capita, deve ser computado o valor recebido pela pessoa com deficiência na condição de aprendiz e em razão de estágio supervisionado.","d":"O Sistema Único de Assistência Social (SUAS) é descentralizado, participativo e financiado pelos três entes federativos, voltado especificamente para a operacionalização, prestação, aprimoramento e viabilização dos serviços, programas, projetos e benefícios do sistema.","e":"O valor do auxílio-inclusão percebido por um membro da família será considerado no cálculo da renda familiar per capita, para fins de concessão e manutenção de outro auxílio-inclusão a pessoa do mesmo grupo familiar. Direito Previdenciário>Beneficiários do Regime Geral de Previdência Social - RGPS ,","gabarito":"D","materia":"Serviço Social","tema":"Assistência Social no Serviço Social ,Sistema Único de Assistência Social – SUAS (Gestão da AS)","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_81","enunciado":"Ano: 2025 Banca: FGV Órgão: TRF - 3ª REGIÃO Prova: FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto Sobre a condição de segurado especial, assinale a alternativa correta:","a":"É pescador artesanal ou a este assemelhado que faça da pesca profissão habitual ou principal meio de vida, bem como pessoa quem presta, a diversas empresas, sem vínculo empregatício, serviço de natureza urbana ou rural definidos no Regulamento.","b":"Pode participar de plano de previdência complementar instituído por entidade classista a que seja associado em razão","c":"da condição de trabalhador rural ou de produtor rural em regime de economia familiar. Pode sê-lo o membro de grupo familiar que possuir outra fonte de rendimento em período superior a 120 dias.","d":"Não pode utilizar terceiros em sua atividade.","e":"Pode explorar atividade turística da propriedade rural, inclusive com hospedagem, por não mais de 140 (cento e quarenta) dias ao ano.","gabarito":"","materia":"Geral","tema":"","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3179513","enunciado":"Maria Fernanda é viúva de Antônio Pedro. Soube, por sua vizinha, no ano de 2020, de uma revisão de Direito Previdenciário, importante forma de melhorar a renda mensal inicial de sua pensão por morte. O marido de Maria Fernanda faleceu em 2017. Estava aposentado por tempo de contribuição desde 2000. Há direito a Maria Fernanda de requerer a revisão do benefício previdenciário de seu marido no ano de 2020? Assinale a alternativa correta:","a":"Sim, sendo Maria Fernanda pensionista, há legitimidade para pleitear, por direito próprio, a revisão do benefício derivado – pensão por morte.","b":"Maria Fernanda não tem legitimidade para pleitear a revisão da pensão porque ninguém pode pleitear, em nome próprio, direito alheio.","c":"Maria Fernanda não tem legitimidade ativa para pleitear a revisão da pensão porque o direito foi alcançado pela decadência.","d":"Maria Fernanda não tem legitimidade ativa para pleitear a revisão da pensão por injunção da ocorrência da prescrição.","e":"Maria Fernanda tem legitimidade para pleitear a revisão da pensão porque o prazo decadencial incide a partir da concessão de seu benefício de pensão.","gabarito":"C","materia":"Direito Previdenciário","tema":"Seguridade Social ,Legislação Previdenciária ,Processo Administrativo Previdenciário","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3179512","enunciado":"Sobre a pensão por morte, assinale a alternativa correta:","a":"Será devida ao conjunto dos dependentes do segurado que falecer, aposentado ou não, a contar da data do óbito, quando requerida em até 180 (cento e oitenta) dias após o óbito, para os filhos menores de 16 (dezesseis) anos, ou em","b":"até 90 (noventa) dias após o óbito, para os demais dependentes. Será devida 30 (trinta) dias após a decisão judicial, no caso de morte presumida. Será perdida pelo cônjuge, o companheiro ou a companheira se comprovada, a qualquer tempo, simulação ou fraude","c":"no casamento ou na união estável, ou a formalização desses com o fim exclusivo de constituir benefício previdenciário, apuradas em processo administrativo ou judicial no qual será assegurado o direito ao contraditório e à","d":"ampla defesa. Havendo mais de um pensionista, será rateada entre todos em partes proporcionais.","e":"Será devida a partir do requerimento, quando requerida 60 (sessenta) dias após o óbito.","gabarito":"A","materia":"Direito Previdenciário","tema":"Benefícios em Espécie ,Pensão por Morte","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3179511","enunciado":"Antônio requereu benefício de aposentadoria por tempo de contribuição. Foi decidido em 07 anos, contados do requerimento administrativo. Neste caso, assinale a alternativa correta:","a":"Há prescrição porque o prazo de prescrição não fica suspenso pela formulação de requerimento administrativo e volta a correr pelo saldo remanescente após a ciência da decisão administrativa final.","b":"Não há prescrição na medida em que o prazo fica suspenso pela formulação de requerimento administrativo e volta a","c":"correr pelo saldo remanescente após a ciência da decisão administrativa final. Há decadência de cinco anos, a partir do requerimento administrativo.","d":"Há decadência e prescrição concomitantes.","e":"Há interrupção da prescrição. Direito Previdenciário>Seguridade Social ,Legislação Previdenciária ,","gabarito":"B","materia":"Direito Previdenciário","tema":"Benefícios em Espécie ,Aposentadoria por Tempo de Contribuição","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3179510","enunciado":"Ano: 2025 Banca: FGV Órgão: TRF - 3ª REGIÃO Prova: FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","a":"Assinale a alternativa correta: empresa deverá elaborar e manter atualizado perfil profissiográfico abrangendo as atividades desenvolvidas pelo A","b":"trabalhador e fornecer a este, antes da rescisão do contrato de trabalho, cópia autêntica desse documento. O segurado recluso em cumprimento de pena em regime aberto ou semiaberto não terá direito ao auxílio-doença.","c":"Ao segurado ou segurada da Previdência Social que adotar ou obtiver guarda judicial para fins de adoção de criança é devido salário-maternidade pelo período de 130 (cento e trinta) dias. Perde o direito à pensão por morte o cônjuge, o companheiro ou a companheira se comprovada, em cinco anos,","d":"simulação ou fraude no casamento ou na união estável, ou a formalização desses com o fim exclusivo de constituir benefício previdenciário, apuradas em processo judicial no qual será assegurado o direito ao contraditório e à ampla defesa.","e":"O segurado em gozo de auxílio-doença, insuscetível de recuperação para sua atividade habitual, deverá submeter-se a processo de reabilitação profissional para o exercício de outra atividade. Direito Previdenciário>Carência ,Planos de Benefício da Previdência Social - Lei nº 8.213, de 24 de Julho de 1991 ,","gabarito":"E","materia":"Planos de Benefício da Previdência Social - Lei nº 8.213, de 24 de Julho de 1991","tema":"","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3179509","enunciado":"Ano: 2025 Banca: FGV Órgão: TRF - 3ª REGIÃO Prova: FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto Assinale a alternativa correta: Na hipótese de perda da qualidade de segurado, para fins da concessão dos benefícios de auxílio-doença, de","a":"aposentadoria por invalidez, de salário-maternidade e de auxílio-reclusão, o segurado deverá contar, a partir da data da nova filiação à Previdência Social, com um terço dos períodos previstos nos incisos I, III e IV do caput do art. 25 da Lei nº 8.213/1991.","b":"A doença ou lesão de que o segurado já era portador ao filiar-se ao Regime Geral de Previdência Social nunca lhe conferirá direito à aposentadoria por invalidez.","c":"Período de carência é o número mínimo de contribuições mensais indispensáveis para que o beneficiário faça jus ao benefício, consideradas a partir do transcurso do primeiro dia dos meses de suas competências.","d":"A aposentadoria por tempo de serviço será devida, cumprida a carência exigida pela Lei nº 8.213/1991, ao segurado que completar 30 (trinta) anos de serviço, se do sexo feminino, ou 35 (trinta e cinco) anos, se do sexo masculino.","e":"A aposentadoria especial será devida, uma vez cumprida a carência exigida pela Lei nº 8.213/1991, ao segurado que tiver trabalhado sujeito a condições especiais que prejudiquem a saúde ou a integridade física, durante 20 (vinte), 25 (vinte e cinco) ou 30 (trinta) anos, conforme dispuser a lei. Direito Previdenciário>Regime Geral de Previdência Social - RGPS ,Beneficiários do RGPS ,","gabarito":"C","materia":"Beneficiários do Regime Geral de Previdência Social - RGPSManutenção e Perda da Qualidade de Segurado","tema":"","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3179508","enunciado":"Ano: 2025 Banca: FGV Órgão: TRF - 3ª REGIÃO Prova: FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto Assinale a alternativa correta:","a":"São segurados obrigatórios da Previdência Social as seguintes pessoas físicas, como empregado, o brasileiro civil que trabalha para a União, no exterior, em organismos oficiais brasileiros ou internacionais dos quais o Brasil seja membro efetivo, ainda que lá domiciliado e contratado, salvo se segurado na forma da legislação vigente do país do domicílio.","b":"O servidor civil ocupante de cargo efetivo ou o militar da União, dos Estados, do Distrito Federal ou dos Municípios, bem como o das respectivas autarquias e fundações, são excluídos do Regime Geral de Previdência Social consubstanciado na Lei nº 8.213/1991, desde que não amparados por regime próprio de previdência social.","c":"São beneficiários do Regime Geral de Previdência Social, na condição de dependentes do segurado, o cônjuge, a companheira, o companheiro e o filho não emancipado, de qualquer condição, menor e maior de 21 (vinte e um) anos ou inválido ou que tenha deficiência intelectual ou mental ou deficiência grave.","d":"Será excluído definitivamente da condição de dependente quem tiver sido condenado criminalmente por sentença com trânsito em julgado, como autor, coautor ou partícipe de homicídio doloso ou culposo, ou de tentativa desse crime, cometido contra a pessoa do segurado, ressalvados os absolutamente incapazes e os inimputáveis.","e":"Nos períodos destinados a refeição ou descanso, ou por ocasião da satisfação de outras necessidades fisiológicas, no local do trabalho ou durante este, o empregado não é considerado no exercício do trabalho.","gabarito":"A","materia":"Beneficiários do Regime Geral de Previdência Social - RGPSSegurados Obrigatórios - Empregado","tema":"","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3179507","enunciado":"Assinale a alternativa correta. São Princípios da Previdência Social:","a":"Cálculo dos benefícios considerando-se os salários-de-contribuição corrigidos monetariamente; economicidade; irredutibilidade do valor dos benefícios de forma a preservar-lhes o poder aquisitivo.","b":"Previdência complementar facultativa, custeada por contribuição adicional; caráter democrático e descentralizado da gestão administrativa, com a participação do governo e da comunidade, em especial de trabalhadores em atividade, representantes das empresas, empregadores e aposentados.","c":"Previdência complementar facultativa, custeada, ou não, por contribuição adicional; irredutibilidade do valor dos benefícios de forma a preservar-lhes o poder aquisitivo; universalidade e uniformidade de participação nos planos previdenciários.","d":"Universalidade de participação nos planos previdenciários; uniformidade e equivalência dos benefícios e serviços às populações urbanas e rurais; seletividade e distributividade na prestação dos benefícios.","e":"Uniformidade, universalidade e equivalência dos benefícios e serviços às populações urbanas e rurais; cálculo dos benefícios considerando-se os salários-de-contribuição corrigidos monetariamente pela taxa Selic.","gabarito":"D","materia":"Direito Previdenciário","tema":"Seguridade Social ,Princípios da Seguridade Social","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3179506","enunciado":"Assinale a alternativa correta:","a":"Os pagamentos devidos, em razão de pronunciamento judicial, pelos conselhos de fiscalização profissional (autarquias federais), submetem-se ao regime de precatórios, à luz do art. 100 da Constituição Federal.","b":"A execução de créditos individuais e divisíveis decorrentes de título judicial coletivo, promovida por substituto processual, não caracteriza o fracionamento de precatório vedado pelo § 8º do art. 100 da Constituição Federal.","c":"Sociedades de economia mista que desenvolvem atividade econômica em regime concorrencial se beneficiam do regime de precatórios, previsto no art. 100 da Constituição da República, pois essas empresas são instrumentos de regulação econômica estatal.","d":"A expropriação prevista no art. 243 da Constituição Federal não pode ser afastada, mesmo que o proprietário comprove que não incorreu em culpa (ainda que \"in vigilando\" ou \"in eligendo\"), pois é objetiva a responsabilidade pelo cultivo ilegal de plantas psicotrópicas. Considerando o art. 5º, o art. 109, I, e o art. 173, § 1º, II, todos da Constituição Federal, compete à Justiça Federal","e":"comum processar e julgar mandado de segurança quando a autoridade apontada como coatora for autoridade federal, não se considerando como tal os dirigentes de pessoa jurídica de direito privado, mesmo que investidos de delegação concedida pela União.","gabarito":"B","materia":"Direito Financeiro","tema":"Precatório","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3179505","enunciado":"Assinale a alternativa correta: Analisando a possibilidade de cancelamento automático da inscrição em conselho profissional em decorrência de","a":"inadimplência da anuidade, o STF concluiu pela constitucionalidade do art. 64 da Lei nº 5.194/1966, que admite esse cancelamento automático no caso de não pagamento por dois anos consecutivos, por ser inequívoca a ciência do atraso por parte do profissional ou da pessoa jurídica que deixa de cumprir suas obrigações nesse lapso de tempo. Diante do previsto no art. 5º, XXXV e LV, e art. 93, IX, ambos da Constituição Federal, cuidando do problema da nova","b":"decisão que apenas transcreve a decisão recorrida, sem enfrentar as questões suscitadas nos embargos declaratórios, o STF afirmou que esses preceitos constitucionais exigem que o novo acórdão ou decisão sejam fundamentados, não bastando alegações sucintas que deixem de enfrentar, pormenorizadamente, cada uma das alegações ou provas.","c":"Por força do art. 206, I, da Constituição Federal, sob pena de violação à igualdade e à concorrência nos vestibulares, é inconstitucional a previsão legal que assegure, na hipótese de transferência ex officio de servidor, a matrícula em instituição pública, se inexistir instituição congênere à de origem.","d":"Em vista do art. 41, e do art. 173, § 1º, ambos da Constituição Federal, a Empresa Brasileira de Correios e Telégrafos - ECT tem o dever jurídico de motivar, em ato formal, a demissão de seus empregados.","e":"À luz do art. 205, do art. 206, I e IV, do art. 208, VII, e do art. 212, § 3º, todos da Constituição Federal, é possível a cobrança de taxa de matrícula nas universidades públicas, excetuados os estudantes que comprovem hipossuficiência de recursos. Direito Constitucional>Controle de Constitucionalidade ,Processo Legislativo , Administração Pública – Disposições Gerais e Servidores Públicos","gabarito":"D","materia":"Direito Constitucional","tema":"Direitos Individuais","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_91","enunciado":"Forças Armadas e Segurança Pública Ano: 2025 Banca: FGV Órgão: TRF - 3ª REGIÃO Prova: FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto Assinale a alternativa correta: Em atenção à segurança jurídica e à confiança legítima, os Tribunais de Contas estão sujeitos ao prazo de 5 anos para","a":"o julgamento da legalidade do ato de concessão inicial de aposentadoria, reforma ou pensão, a contar da chegada do processo à respectiva Corte de Contas. Considerando o art. 37, § 5º, da Constituição Federal, é imprescritível a pretensão de ressarcimento ao erário fundada em decisão de Tribunal de Contas.","b":"É constitucional a promulgação, pelo Chefe do Poder Executivo, de parte incontroversa de projeto da lei que não foi vetada, antes da manifestação do Poder Legislativo pela manutenção ou pela rejeição do veto, inexistindo vício de inconstitucionalidade dessa parte inicialmente publicada pela ausência de promulgação da derrubada dos vetos. Foi recepcionada pelo art. 142, § 3º, X, da Constituição de 1988, a delegação normativa contida na expressão “nos","c":"regulamentos da Marinha, do Exército e da Aeronáutica” do art. 10 da Lei 6.880/1980, razão pela qual são válidos os atos normativos infralegais que venham a definir requisitos para ingresso nas Forças Armadas (notadamente idade mínima e máxima). Em razão do previsto no art. 2º da Emenda Constitucional nº 32/2001, as medidas provisórias editadas em data anterior à da publicação dessa emenda ainda continuam em vigor, salvo as revogadas explicitamente ou deliberadas","d":"definitivamente pelo Congresso Nacional. Contudo, o art. 20 da Emenda Constitucional nº 132/2023 determinou que medidas provisórias nessas condições sejam analisadas pelo Congresso Nacional em vinte e quatro meses (contados da publicação dessa nova emenda), sob pena de cessação de eficácia quando vencido esse prazo, exceto as que forem prorrogadas por ato declaratório expresso do mesmo Congresso. Segundo o Tema 686/STF, há reserva de iniciativa do Chefe do Poder Executivo para edição de regras que alterem o","e":"padrão remuneratório dos servidores públicos, ao mesmo tempo em que são aceitas emendas parlamentares que impliquem aumento de despesa nesses projetos de lei, limitadas a 30% (trinta) do gasto previsto inicialmente pelo Chefe do Executivo (art. 61, § 1º, II, “a”, e art. 63, I, ambos da Constituição Federal).","gabarito":"","materia":"Geral","tema":"","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3179503","enunciado":"Assinale a alternativa correta: Segundo o Tema 529/STF, a preexistência de casamento ou de união estável de um dos conviventes, ressalvada a","a":"vedação do artigo 1.723, § 1º, do CC/2002, não impede o reconhecimento de novo vínculo referente ao mesmo período, inclusive para fins previdenciários, em virtude do pluralismo abrigado pelo ordenamento jurídico- constitucional brasileiro (art. 1º, V, da ordem de 1988).","b":"Considerando o Tema 1049/STF, após a vigência da Lei nº 13.021/2014, os práticos em farmácia não podem assumir responsabilidade por drogaria, atividade que passou a ser exclusiva de técnicos em farmácia ou farmacêuticos.","c":"Autarquias federais não podem ser demandadas fora de suas sedes ou em localidades que não possuem agência ou sucursal, pois a elas se aplica a regra prevista no § 2º do art. 109 da Constituição Federal.","d":"Em vista do art. 5º, caput, e art. 37, caput, ambos da Constituição Federal, existe direito dos candidatos em concurso público à prova de segunda chamada nos testes de aptidão física, mesmo sem disposição editalícia, em razão de circunstâncias pessoais, de caráter fisiológico ou de força maior.","e":"Em razão do art. 5º, caput, do 6º, do 37 e do 226, § 7º, todos da Constituição da República, é constitucional a remarcação do teste de aptidão física de candidata que esteja grávida à época de sua realização, independentemente da previsão expressa em edital do concurso público. Direito Constitucional>Administração Pública – Disposições Gerais e Servidores Públicos ,","gabarito":"E","materia":"Direito Constitucional","tema":"Direitos Individuais","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_93","enunciado":"Ano: 2025 Banca: FGV Órgão: TRF - 3ª REGIÃO Prova: FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto Assinale a alternativa correta: Diante do Tema 858/STF, o trânsito em julgado de sentença condenatória proferida em sede de ação desapropriatória","a":"não obsta a propositura de Ação Civil Pública em defesa do patrimônio público, para discutir a dominialidade do bem expropriado, ainda que já se tenha expirado o prazo para a Ação Rescisória. Em sede de Ação de Desapropriação, os honorários sucumbenciais só serão devidos caso haja devido pagamento da indenização aos expropriados Conforme o Tema 916/STF, a contratação por tempo determinado para atendimento de necessidade temporária de","b":"excepcional interesse público realizada em desconformidade com os preceitos do art. 37, IX, da Constituição Federal não gera quaisquer efeitos jurídicos válidos em relação aos servidores contratados (tais como a depósitos no FGTS), com exceção do direito à percepção dos salários referentes ao período trabalhado (sob pena de enriquecimento sem causa do Estado).","c":"O Ministério Público não tem legitimidade para a propositura de ação civil pública em favor de titulares de contas vinculadas ao FGTS, pois se trata de interesse individual de cada um dos trabalhadores correntistas.","d":"Os índios, suas comunidades e organizações não são partes legítimas para ingressar em juízo em defesa de seus direitos e interesses, devendo ser representados ou substituídos pelo Ministério Público ou pela FUNAI. Por força do art. 109, I, da Constituição Federal, compete à Justiça Federal processar e julgar mandados de segurança","e":"nos quais exista controvérsia relativa à expedição de diploma de conclusão de curso superior realizado em instituição pública federal de ensino, ao passo em que writs envolvendo instituições dos demais entes subnacionais, bem como instituições privadas de ensino superior, devem ser processados perante a Justiça Estadual.","gabarito":"","materia":"Geral","tema":"","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3179500","enunciado":"Assinale a alternativa correta: Diante do art. 7º, XXX, e do art. 37, caput, II e IX, ambos do corpo permanente da Constituição Federal, bem como do","a":"art. 10, II, “b” do ADCT, a trabalhadora gestante tem direito ao gozo de licença-maternidade e à estabilidade provisória, independentemente do regime jurídico aplicável, se contratual ou administrativo, ainda que ocupe cargo em comissão, exceto se contratada por tempo determinado (pacta sunt servanda).","b":"Nos moldes do art. 37, X e § 6 º, da Constituição Federal, gera direito subjetivo a indenização o não encaminhamento de projeto de lei de revisão anual dos vencimentos dos servidores públicos, sob pena da violação à irredutibilidade de salários.","c":"Segundo o Tema 1072 do STF, em união homoafetiva, terá direito à licença-maternidade apenas a mãe servidora ou trabalhadora gestante. A companheira não gestante fará jus à licença pelo período equivalente ao da licença- paternidade.","d":"Dado ao sentido e alcance do art. 37, § 5º, da Constituição Federal, é imprescritível a ação de reparação de danos à Fazenda Pública decorrente de ilícito civil. Em vista do Tema 940/STF, ao teor do disposto no art. 37, § 6º, da Constituição Federal, a ação por danos causados por","e":"agente público deve ser ajuizada contra o Estado ou a pessoa jurídica de direito privado prestadora de serviço público, sendo parte ilegítima para a ação o autor do ato, assegurado o direito de regresso contra o responsável nos casos de dolo ou culpa. Direito Constitucional>Tribunais Regionais Federais e Juízes Federais ,","gabarito":"E","materia":"Direito Administrativo","tema":"Responsabilidade civil do estado","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_95","enunciado":"Ano: 2025 Banca: FGV Órgão: TRF - 3ª REGIÃO Prova: FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto Assinale a alternativa correta:","a":"Conforme o Tema 1120/STF, em respeito à separação dos poderes, prevista no art. 2º da Constituição Federal, o Poder Judiciário não pode exercer o controle de constitucionalidade em relação à interpretação do sentido e do alcance de preceitos meramente regimentais das Casas Legislativas, por se tratar de matéria interna corporis.","b":"Tendo em vista o art. 114, I da Constituição Federal, a Justiça Trabalhista é competente para julgar ação ajuizada por servidor celetista contra o Poder Público Federal, mesmo em se tratando de parcela de natureza administrativa, porque se trata de pleito pertinente ao contrato regido pela CLT.","c":"Por força do art. 114, I e II, da Constituição Federal, a Justiça Comum, Federal ou Estadual, é competente para julgar a abusividade de greve de servidores públicos celetistas da administração pública direta, autarquias e fundações públicas.","d":"Segundo o Tema 944/STF, com fundamento no art. 1º, III, art. 3º, IV, art. 4º, II, IV e V, art. 5º, II, XXXV e LIV, e art. 133, todos da Constituição Federal, atos ilícitos praticados por Estados estrangeiros em violação a direitos humanos, dentro do território brasileiro, gozam de imunidade de jurisdição.","e":"Diante da conclusão do Tema 947/STF, organismos internacionais não têm imunidade de jurisdição por não serem equiparados a Estados estrangeiros e, por isso, podem ser demandados perante a Justiça Federal.","gabarito":"","materia":"Geral","tema":"","origem":"FGV - 2025 - TRF - 3ª REGIÃO - Juiz Federal Substituto","ano":"2025","banca":"FGV Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564696","enunciado":"Efetuado o lançamento de ofício do crédito tributário em nome de determinado sujeito passivo, este, inconformado, apresentou defesa (reclamação) no âmbito administrativo, visando o cancelamento da exigência fiscal. Vencido em todas as instâncias administrativas, esse sujeito passivo foi notificado a liquidar o crédito tributário, espontaneamente, sob pena de virem a ser tomadas contra ele todas as medidas legais então cabíveis. O contribuinte manteve-se inerte e não propôs nenhuma medida judicial; e tampouco se prontificou a realizar o pagamento. De acordo com o Código Tributário Nacional (CTN), se a liquidação do crédito tributário não ocorrer, espontaneamente, dentro do prazo concedido na referida notificação,","a":"a Fazenda Pública terá o prazo decadencial de 10 anos, contados da data do reconhecimento definitivo da ocorrência do fato gerador, para ajuizar o executivo fiscal.","b":"o sujeito passivo terá o prazo interruptivo de 10 anos, contados da data da prolação de decisão definitiva na esfera administrativa, para ingressar com a ação, objetivando a conversão de depósito em renda.","c":"o sujeito passivo terá o prazo suspensivo de 5 anos, contados da data da constituição do crédito tributário pelo lançamento, para ajuizar o executivo fiscal, visando a cobrança do crédito tributário.","d":"a Fazenda Pública terá o prazo prescricional de 5 anos, contados da data da constituição definitiva do crédito tributário, para propor ação judicial para cobrança do crédito tributário.","e":"o sujeito passivo terá o prazo decadencial de 5 anos, contados da data da constituição definitiva do crédito tributário, para efetuar o lançamento por homologação definitivo do crédito tributário.","gabarito":"D","materia":"Direito Tributário","tema":"Extinção do Crédito Tributário","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Técnico Judiciário - Área Administrativa","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564695","enunciado":"Admita-se, por hipótese, que, em razão de fortíssimos movimentos tectônicos, tenham surgido duas ilhas no litoral brasileiro, as quais receberam os nomes de Macro e Micro, respectivamente. Essas duas ilhas, de imediato, se tornaram territórios federais e, pelas suas dimensões, logo foram povoadas. A primeira, Macro, foi dividida em Municípios, mas a segunda, Micro, não o foi. Em razão disso, com base nas regras da Constituição Federal de 1988, a União pode lançar e","a":"cobrar dos habitantes de Micro os impostos federais, estaduais e municipais.","b":"ambas as ilhas, os impostos federais, estaduais e municipais.","c":"ambas as ilhas apenas os impostos federais.","d":"Macro os impostos federais, estaduais e municipais.","e":"ambas as ilhas apenas os impostos federais e os impostos municipais.","gabarito":"A","materia":"Direito Tributário","tema":"Competência Tributária ,Partilha e Tipologia (Repartição de Competência)","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Técnico Judiciário - Área Administrativa","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564694","enunciado":"Conforme expressa previsão da legislação que instituiu um imposto específico, este deve ser lançado exclusivamente pela via de lançamento de ofício. Nesse sentido, em consonância com o Código Tributário Nacional (CTN), o prazo decadencial","a":"para a realização do lançamento tributário desse imposto será de 2 anos, iniciando-se na data da ocorrência do fato gerador.","b":"5 anos, iniciando-se no primeiro dia do exercício seguinte àquele em que o lançamento poderia ter sido efetuado.","c":"5 anos, iniciando-se no primeiro dia do exercício seguinte àquele em que o despacho do juiz tiver ordenado a citação","d":"do devedor, em execução fiscal. 10 anos, iniciando-se na data da ocorrência do fato gerador.","e":"5 anos, iniciando-se na data da ocorrência do fato gerador, salvo se comprovada a ocorrência de dolo, fraude ou simulação.","gabarito":"B","materia":"Direito Tributário","tema":"Lançamento Tributário","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Técnico Judiciário - Área Administrativa","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564693","enunciado":"De acordo com a Constituição Federal de 1988, o ouro, quando definido em lei como ativo financeiro ou instrumento cambial, sofrerá, na operação de origem, apenas a incidência do","a":"Imposto sobre Operações de Crédito, Câmbio e Seguro, ou Relativas a Títulos ou Valores Mobiliários (IOF) e do Imposto de Renda (IR), sendo que o montante da arrecadação do IOF será repartido, em partes iguais, entre a União e o Município de sua proveniência.","b":"Imposto sobre Produtos Industrializados (IPI) e do Imposto de Renda (IR), ficando assegurado à União o direito de","c":"retenção de 50% do montante da arrecadação do IPI. Imposto sobre Produtos Industrializados (IP|) e, quando for o caso, do Imposto de Exportação (IE).","d":"Imposto de Renda (IR), sendo que o montante de sua arrecadação será repartido, em partes iguais, entre a União e o Estado e o Município de sua proveniência.","e":"Imposto sobre Operações de Crédito, Câmbio e Seguro, ou Relativas a Títulos ou Valores Mobiliários (IOF), ficando assegurada ao Município de origem do metal a transferência de 70% do montante da arrecadação desse imposto.","gabarito":"E","materia":"Direito Tributário","tema":"Tributos Federais ,IOF","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Técnico Judiciário - Área Administrativa","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564692","enunciado":"Determinada pessoa jurídica de direito público interno, por meio de seus Auditores Fiscais, promoveu o lançamento de ofício de tributo e de multa em nome da empresa AHR Ltda., atribuindo-lhe a prática de irregularidades que teriam culminado com a sonegação de tributo. Dentro do prazo legal, essa empresa apresentou sua defesa administrativa (reclamação), nos termos estabelecidos pelas leis reguladoras do respectivo processo tributário administrativo, efetuando, ainda, simultaneamente, o depósito de parte do montante exigido, pois se encontrava em dificuldade financeira. Considerando os preceitos delineados pelo Código Tributário Nacional (CTN) referentes às circunstâncias que excluem e extinguem o crédito tributário, ou, suspendem a sua exigibilidade, pode-se concluir que o crédito tributário lançado pelos","a":"Auditores Fiscais. foi extinto apenas parcialmente, por meio do depósito parcial efetuado.","b":"não teve sua exigibilidade suspensa, pois, embora a defesa tenha sido apresentada tempestivamente, o depósito","c":"efetuado foi apenas parcial. teve sua exigibilidade suspensa, em razão da apresentação tempestiva da defesa (reclamação) administrativa.","d":"foi excluído em razão da defesa tempestivamente apresentada, mas apenas na proporção do montante do depósito","e":"efetuado. não teve sua exigibilidade suspensa, pois não houve a conversão do depósito parcial em renda.","gabarito":"C","materia":"Direito Tributário","tema":"Suspensão do Crédito Tributário ,Suspensão do Crédito Tributário - Disposições Gerais","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Técnico Judiciário - Área Administrativa","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564691","enunciado":"Caso uma lei federal (hipotética). publicada em 15 de outubro de 2021, tivesse alterado apenas a alíquota do Imposto Territorial Rural (ITR), essa lei, à luz das normas da Constituição Federal de 1988, poderia estabelecer que a nova alíquota","a":"entraria em vigor no mesmo exercício de sua publicação, apenas no caso de se tratar de aumento da referida alíquota.","b":"no mesmo exercício de sua publicação, caso a alíquota tivesse sido reduzida, e em 1º de janeiro de 2022, caso a","c":"alíquota tivesse sido aumentada. em 1º de janeiro de 2022, tanto no caso de aumento como no caso de redução da referida alíquota.","d":"no mesmo exercício de sua publicação, tanto no caso de redução como no caso de aumento da referida alíquota.","e":"em 1º de fevereiro de 2022, tanto no caso de aumento como no caso de redução da referida alíquota.","gabarito":"E","materia":"Direito Tributário","tema":"Tributos Federais ,ITR","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Técnico Judiciário - Área Administrativa","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564690","enunciado":"Dona Maria era mãe de Silas, de Adelina, de Marcos e de Mateus. Por ocasião de sua morte, coube a cada um de seus filhos a quarta parte da herança deixada. Ocorre, todavia, que, na data de seu óbito, Silas se encontrava preso, o que implicava limitação do exercício de suas atividades civis. Adelina encontrava-se sob curatela, em razão de alienação mental precoce, enquanto Mateus ainda era menor de idade, contando apenas com 13 anos. Adelina e Mateus encontravam-se afastados da administração direta de seus negócios. Em razão disso, suscitaram-se dúvidas sobre a capacidade tributária passiva de cada um dos herdeiros, o que motivou a busca de orientação profissional a esse respeito. Com base no que dispõe o Código Tributário Nacional (CTN) acerca da capacidade tributária passiva, o profissional consultado esclareceu a eles, corretamente, que:","a":"Marcos está com sua capacidade tributária suspensa, até que os demais herdeiros venham a recobrar as suas, ou","b":"perdê-las, em razão do falecimento de cada um deles. somente Silas e Marcos são detentores dessa capacidade.","c":"somente Marcos é detentor dessa capacidade.","d":"os quatro herdeiros são detentores dessa capacidade.","e":"somente Adelina, Marcos e Mateus são detentores dessa capacidade.","gabarito":"D","materia":"Direito Tributário","tema":"Obrigação Tributária ,Capacidade, Domicílio e Sujeitos da Obrigação Tributária","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Técnico Judiciário - Área Administrativa","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564689","enunciado":"Segundo a Lei nº 8.213/1991, são beneficiários do Regime Geral de Previdência Social, na condição de dependentes do segurado: O cônjuge, a companheira, o companheiro e o filho","a":"emancipado, sob certas condições, menor de 21 anos ou inválido ou que tenha deficiência intelectual ou mental ou deficiência grave; os pais; e o irmão emancipado, sob certas condições, menor de 21 anos ou inválido ou que tenha deficiência intelectual ou mental ou deficiência grave.","b":"não emancipado, de qualquer condição, menor de 18 anos ou inválido ou que tenha apenas deficiência intelectual ou deficiência grave; os pais; e o irmão emancipado, de qualquer condição, menor de 21 anos ou inválido ou que tenha apenas deficiência intelectual ou deficiência grave.","c":"não emancipado, de qualquer condição, menor de 21 anos ou inválido ou que tenha deficiência intelectual ou mental ou deficiência grave; os pais; e o irmão não emancipado, de qualquer condição, menor de 21 anos ou inválido ou que tenha deficiência intelectual ou mental ou deficiência grave.","d":"emancipado, de qualquer condição, menor de 21 anos ou inválido ou que tenha apenas deficiência mental ou deficiência grave; os pais; e o irmão emancipado, de qualquer condição, menor de 21 anos ou inválido ou que tenha apenas deficiência mental ou deficiência grave.","e":"não emancipado, sob certas condições, menor de 24 anos ou inválido ou que tenha deficiência intelectual ou mental ou deficiência grave; os pais; e o irmão não emancipado, sob certas condições, menor de 24 anos ou inválido ou que tenha deficiência intelectual ou mental ou deficiência grave.","gabarito":"C","materia":"Direito Previdenciário","tema":"Regime Geral de Previdência Social - RGPS ,Beneficiários do RGPS","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Técnico Judiciário - Área Administrativa","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564688","enunciado":"Considerando o art. 202 da Constituição Federal de 1988, o regime de previdência privada é de caráter complementar e organizado de forma","a":"autônoma em relação ao regime geral de previdência social, sendo facultativo, baseado na constituição de reservas que garantam o benefício contratado, e regulado por lei complementar.","b":"autônoma em relação ao regime próprio de previdência social, sendo facultativo, baseado na constituição de despesas que garantam o benefício contratado, e regulado por lei complementar.","c":"autônoma em relação ao regime geral de previdência social, sendo facultativo, baseado na constituição de reservas que garantam o benefício contratado, e regulado por lei ordinária.","d":"dependente ao regime geral de previdência social, sendo facultativo, baseado na constituição de reservas que garantam o benefício contratado, e regulado por lei complementar.","e":"autônoma em relação ao regime geral de previdência social, sendo obrigatório, baseado na constituição de reservas que garantam o benefício contratado, e regulado por lei complementar.","gabarito":"A","materia":"Direito Constitucional","tema":"Previdência Social ,Ordem Social","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Técnico Judiciário - Área Administrativa","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564687","enunciado":"Com base no art. 201 da Constituição Federal de 1988, é VEDADA a adoção de requisitos ou critérios diferenciados para concessão de benefícios, ressalvada, nos termos de lei complementar, dentre outra hipótese, a possibilidade de previsão de idade e tempo de contribuição distintos da regra geral para concessão de aposentadoria exclusivamente em favor dos segurados cujas atividades sejam exercidas com efetiva exposição a agentes químicos, físicos e biológicos prejudiciais à","a":"saúde, com exceção da associação desses agentes, sendo permitida a caracterização por categoria profissional ou ocupação.","b":"ou associação desses agentes, sendo permitida a caracterização por categoria profissional ou ocupação.","c":"ou associação desses agentes, vedada a caracterização apenas por ocupação.","d":"ou associação desses agentes, vedada a caracterização apenas por categoria profissional.","e":"ou associação desses agentes, vedada a caracterização por categoria profissional ou ocupação. Direito Previdenciário>Seguridade Social ,","gabarito":"E","materia":"Direito Constitucional","tema":"Previdência Social ,Ordem Social","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Técnico Judiciário - Área Administrativa","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564685","enunciado":"Segundo a Lei nº 8.212/1991, são segurados obrigatórios da Previdência Social, no Regime Geral, como empregado, aquele que presta serviço de natureza urbana ou rural à empresa, em caráter não eventual, sob sua subordinação e mediante remuneração, inclusive como diretor empregado, e como contribuinte","a":"individual a pessoa física, proprietária ou não, que explora atividade de extração mineral-garimpo, em caráter permanente ou temporário, diretamente ou por intermédio de prepostos, com ou sem o auxílio de empregados, utilizados a qualquer título, ainda que de forma não continua. não eventual, sob sua subordinação e mediante remuneração, inclusive como diretor não empregado, e como","b":"contribuinte individual a pessoa física, apenas proprietária, que explora atividade de extração mineral-garimpo, em caráter permanente ou temporário, diretamente ou por intermédio de prepostos, apenas sem o auxílio de empregados, ainda que de forma não contínua. não eventual, sem sua subordinação e mediante remuneração, exceto como diretor empregado, e como contribuinte","c":"individual a pessoa física, proprietária ou não, que explora atividade de extração mineral-garimpo, apenas em caráter temporário, diretamente ou por intermédio de prepostos, com ou sem o auxílio de empregados, utilizados a qualquer título, ainda que de forma não continua. eventual, sob sua subordinação e mediante remuneração, inclusive como diretor empregado, e como contribuinte","d":"individual a pessoa física, proprietária ou não, que explora atividade de extração mineral-garimpo, em caráter permanente ou temporário, apenas por intermédio de prepostos, com ou sem o auxílio de empregados, utilizados a qualquer título, ainda que de forma não contínua. não eventual, com ou sem subordinação e mediante remuneração, inclusive como membro de conselho de","e":"administração de sociedade anônima, e como contribuinte individual a pessoa física, proprietária ou não, que explora atividade de extração mineral-garimpo, apenas em caráter permanente, diretamente ou por intermédio de prepostos, com ou sem o auxílio de empregados, utilizados a qualquer título, ainda que de forma não contínua.","gabarito":"A","materia":"Direito Previdenciário","tema":"Regime Geral de Previdência Social - RGPS ,Beneficiários do RGPS","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Técnico Judiciário - Área Administrativa","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564684","enunciado":"De acordo com o art. 194 da Constituição Federal de 1988, a seguridade social compreende um conjunto","a":"independente de ações de iniciativa dos Poderes Públicos e da sociedade, destinadas a assegurar os direitos relativos ao meio ambiente, à previdência e à assistência social.","b":"integrado de ações de iniciativa dos Poderes Públicos e da sociedade, destinadas a assegurar os direitos relativos à saúde, à previdência e ao meio ambiente.","c":"independente de ações de iniciativa apenas dos Poderes Públicos, destinadas a assegurar os direitos relativos à saúde, à previdência e à assistência social.","d":"integrado de ações de iniciativa dos Poderes Públicos e da sociedade, destinadas a assegurar os direitos relativos à saúde, à previdência e à assistência social.","e":"integrado de ações de iniciativa apenas da sociedade, destinadas a assegurar os direitos relativos à saúde, à previdência e à assistência social. Direito Previdenciário>Seguridade Social ,","gabarito":"D","materia":"Direito Constitucional","tema":"Previdência Social ,Ordem Social","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Técnico Judiciário - Área Administrativa","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_108","enunciado":"Ano: 2024 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2024 - TRF - 3ª REGIÃO - Técnico Judiciário - Área Administrativa Compete ao Poder Público, nos termos da lei, organizar a Seguridade Social com base na universalidade da cobertura e do atendimento, equidade na forma de participação no custeio; uniformidade e equivalência dos benefícios e serviços às populações urbanas e rurais; seletividade e distributividade na prestação dos benefícios e serviços; redutibilidade do valor dos benefícios; diversidade da base de financiamento, identificando-se,","a":"em rubricas contábeis genéricas, apenas as despesas vinculadas a ações de saúde, previdência e assistência social, preservado o caráter contributivo da previdência social; e caráter democrático e descentralizado da administração, mediante gestão tripartite, com participação dos trabalhadores, dos empregadores e do Governo nos órgãos colegiados. benefícios e serviços; irredutibilidade do valor dos benefícios; diversidade da base de financiamento, identificando-se,","b":"em rubricas contábeis específicas para cada área, apenas as receitas desvinculadas de ações de saúde, previdência e assistência social, preservado o caráter contributivo da previdência social; e caráter democrático e descentralizado da administração, mediante gestão bipartite, com participação dos trabalhadores e dos empregadores nos órgãos colegiados. benefícios e serviços; irredutibilidade do valor dos benefícios; diversidade da base de financiamento, identificando-se,","c":"em rubricas contábeis específicas para cada área, as receitas e as despesas vinculadas a ações de saúde, previdência e assistência social, preservado o caráter contributivo da previdência social; e caráter democrático e descentralizado da administração, mediante gestão quadripartite, com participação dos trabalhadores, dos empregadores, dos aposentados e do Governo nos órgãos colegiados. serviços, apenas; irredutibilidade do valor dos benefícios; unicidade da base de financiamento, identificando-se, em","d":"rubricas contábeis específicas para cada área, as receitas e as despesas vinculadas a ações de saúde, previdência e assistência social, preservado o caráter contributivo da previdência social; e caráter democrático e descentralizado da administração, mediante gestão quadripartite, com participação dos trabalhadores, dos empregadores, dos aposentados e do Governo nos órgãos colegiados. benefícios, apenas; irredutibilidade do valor dos benefícios; diversidade da base de financiamento, identificando-se,","e":"em rubricas contábeis específicas para cada área, as receitas e as despesas vinculadas a ações de saúde, previdência e assistência social, preservado o caráter não contributivo da previdência social, e caráter democrático e centralizado da administração, mediante gestão quadripartite, com participação dos trabalhadores, dos empregadores, dos aposentados e do Governo nos órgãos colegiados.","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Técnico Judiciário - Área Administrativa","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564682","enunciado":"Considere o seguinte caso hipotético: Ricardo foi preso em flagrante pelo crime de roubo praticado no centro da cidade de São Paulo-SP e encaminhado ao Distrito Policial para lavratura do auto de prisão em flagrante pela autoridade policial, que será encaminhado ao juiz competente. A partir desse momento, recebendo o auto de prisão em flagrante, o juiz deverá promover audiência de","a":"custódia no prazo máximo, após a realização da prisão, de até 24 horas.","b":"7 dias.","c":"5 dias.","d":"48 horas.","e":"72 horas.","gabarito":"A","materia":"Direito Processual Penal","tema":"Procedimento Penal","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Técnico Judiciário - Área Administrativa","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564681","enunciado":"Maurilio cometeu um delito de estelionato e ao término do Inquérito Policial, presentes todos os demais requisitos legais, o Ministério Público lhe propõe acordo de não persecução penal, que é aceito e devidamente formalizado. Designada audiência para homologação do acordo, o Magistrado competente recusa homologação à proposta, devolvendo os autos ao","a":"Ministério Público. Nesse caso, contra a decisão do Magistrado caberá recurso em sentido estrito, no prazo de 10 dias.","b":"recurso em sentido estrito, no prazo de 5 dias.","c":"recurso de apelação, no prazo de 5 dias.","d":"recurso de apelação, no prazo de 10 dias.","e":"mandado de segurança. Direito Processual Penal>","gabarito":"B","materia":"Direito Processual Penal","tema":"Recursos Criminais ,Recurso em sentido estrito","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Técnico Judiciário - Área Administrativa","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564680","enunciado":"Ano: 2024 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2024 - TRF - 3ª REGIÃO - Técnico Judiciário - Área Administrativa Em uma situação hipotética, Fulvio está sendo processado por crime de roubo praticado contra uma agência bancária da Caixa Econômica Federal na cidade de São Paulo. O processo tem o seu trâmite regular e ao final Fulvio é condenado pelo referido crime a uma determinada pena pelo Magistrado competente. Após a prolação da sentença, a Caixa Econômica Federal, por meio de seus advogados, peticiona nos autos solicitando a sua habilitação como assistente do Ministério Público. Nesse caso, nos termos preconizados pelo Código de Processo Penal,","a":"o juiz poderá, sem a necessidade de ouvir o Ministério Público, por despacho irrecorrivel, admitir o assistente de acusação, que receberá a causa no estado em que se achar.","b":"o juiz poderá, sem a necessidade de ouvir o Ministério Público, por despacho recorrível, admitir o assistente de acusação, que receberá a causa no estado em que se achar.","c":"após a oitiva do Ministério Público, o juiz poderá, por despacho irrecorrível, admitir o assistente de acusação, que","d":"receberá a causa no estado em que se achar. não é possível a admissão do assistente de acusação após a prolação da sentença em primeiro grau de jurisdição.","e":"após a oitiva do Ministério Público, o juiz poderá, por despacho recorrível, admitir o assistente de acusação, que receberá a causa no estado em que se achar.","gabarito":"C","materia":"Do juiz, do ministério público, do acusado e defensor, dos assistentes e auxiliares da justiça","tema":"","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Técnico Judiciário - Área Administrativa","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564679","enunciado":"Considere os seguintes casos hipotéticos: — Rinaldo está transportando 490 kg de cocaína em seu veículo por uma estrada federal no Estado do Mato Grosso do Sul, cujo destino é a cidade de Salto del Guairá, no Paraguai. Rinaldo foi preso quando se preparava para atravessar a fronteira. — Silvio foi preso em flagrante após cometer um crime de furto, durante a madrugada, em uma agência do Banco do Brasil, sociedade de economia mista federal, subtraindo R$ 50.000,00 em dinheiro. — Marco, após cometer um roubo na cidade de São José dos Campos-SP, iniciou fuga pela Rodovia Federal Presidente Dutra e, quando parado por dois policiais rodoviários federais, realizou cinco disparos de arma de fogo, três dos quais atingiram um dos referidos policiais, levando-o a óbito no local. — Sofia foi presa em flagrante após praticar um roubo de dinheiro que era transportado por uma empresa de transporte de valores, juntamente com indivíduos armados, no interior de um avião estacionado no Aeroporto Internacional de Guarulhos. Na esteira do Código de Processo Penal e da Constituição Federal de 1988, sobre a competência penal da Justiça Federal,","a":"caberá à Justiça Federal processar e julgar APENAS Rinaldo, Marco e Sofia.","b":"Silvio e Marco.","c":"Rinaldo e Sofia.","d":"Rinaldo e Marco.","e":"Silvio, Marco e Sofia.","gabarito":"A","materia":"Direito Processual Penal","tema":"Competência no Processo Penal ,Competência criminal da Justiça Federal","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Técnico Judiciário - Área Administrativa","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564678","enunciado":"Considere os seguintes casos hipotéticos, envolvendo pessoas primárias e sem qualquer antecedente criminal, que estão sendo investigadas em inquéritos policiais instaurados: — Rodrigo, para favorecer interesse próprio, ameaçou uma testemunha que iria depor em uma ação penal, incorrendo, em tese, no crime de coação no curso do processo, previsto no artigo 344, do Código Penal, que estabelece pena de 1 a 4 anos de reclusão, e multa, além da pena correspondente à violência. — Matias falsificou um lote de dez mil notas de R$ 50,00, incorrendo, em tese, no crime de moeda falsa, previsto no artigo 289, do Código Penal, que estabelece pena de 3 a 12 anos de reclusão e multa. — Rita, funcionária pública, facilitou, com infração de dever funcional, a prática de contrabando, incorrendo, em tese, no crime do artigo 318, do Código Penal, que estabelece pena de 3 a 8 anos de reclusão e multa. — Wilson opôs-se à execução de mandado de busca domiciliar, regularmente expedido, mediante violência a funcionário público competente para executá-lo, incorrendo, em tese, no crime de resistência, previsto no artigo 329, do Código Penal, que estabelece pena de 2 meses a 2 anos de detenção, sem prejuízo das penas correspondentes à violência. Nos termos preconizados pelo Código de Processo Penal, após as alterações promovidas pelo Pacote Anticrime, ao término das investigações, não sendo o caso de arquivamento do inquérito policial, presentes os demais requisitos legais, o Ministério","a":"Público poderá propor o acordo de não persecução penal APENAS para Rodrigo, Matias e Rita.","b":"Matias e Rita.","c":"Matias e Wilson.","d":"Rodrigo e Wilson.","e":"Matias, Rita e Wilson.","gabarito":"B","materia":"Direito Processual Penal","tema":"Ação Penal ,Acordo de Não Persecução Penal","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Técnico Judiciário - Área Administrativa","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564677","enunciado":"Maria e José são vizinhos, na cidade de Campo Grande/MS, e desafetos. No bairro onde residem começaram a ocorrer diversos furtos de veículos e de residências. Maria, com o escopo de causar danos ao seu vizinho José, imputou-lhe falsamente a autoria dos referidos furtos em comparsaria com outros indivíduos, não só perante a vizinhança como também em suas redes sociais, Inconformado com a falsa imputação, José ajuizou queixacrime contra Maria, que foi recebida pelo juízo competente, após o cumprimento de todas as formalidades. Designada audiência de instrução, após regular intimação de todas as partes envolvidas na ação penal, o querelante José e seu advogado não compareceram ao ato e nem justificaram a ausência. Maria, então, por meio de seu advogado, poderá apresentar ao Magistrado pedido de","a":"extinção da punibilidade com base na decadência.","b":"na renúncia ao direito de queixa.","c":"no perdão do ofendido.","d":"na perempção.","e":"no perdão judicial.","gabarito":"D","materia":"Direito Processual Penal","tema":"Procedimento Penal","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Técnico Judiciário - Área Administrativa","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564676","enunciado":"Acerca dos recursos, considere: I. A interposição de recursos não impede a eficácia da decisão recorrida, salvo disposição legal ou decisão judicial em sentido diverso. II. O recurso adesivo é admissível na apelação e no agravo de instrumento e não se subordina ao recurso independente. III. O recorrente pode desistir do recurso a qualquer tempo sem anuência do recorrido ou dos litisconsortes. IV. A renúncia ao direito de recorrer depende de aceitação da parte contrária. De acordo com o Código de Processo Civil,","a":"está correto o que se afirma APENAS em I e IV.","b":"I e II.","c":"II e IV.","d":"III e IV.","e":"I e III. Direito Processual Civil - Novo Código de Processo Civil - CPC 2015>Cumprimento de Sentença ,","gabarito":"E","materia":"Direito Processual Civil - Novo Código de Processo Civil - CPC 2015","tema":"Recursos ,Teoria Geral dos Recursos","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Técnico Judiciário - Área Administrativa","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_116","enunciado":"Ano: 2024 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2024 - TRF - 3ª REGIÃO - Técnico Judiciário - Área Administrativa De acordo com o Código de Processo Civil, no caso de condenação em quantia certa, o cumprimento definitivo da sentença será realizado","a":"a requerimento do exequente, intimando-se o executado para pagamento no prazo de 10 dias, sob pena de multa de 15%, a qual não se aplica à Fazenda Pública.","b":"a requerimento do exequente, intimando-se o executado para pagamento no prazo de 15 dias, sob pena de multa de 10%, a qual não se aplica à Fazenda Pública.","c":"de ofício, intimando-se o executado para pagamento no prazo de 10 dias, sob pena de multa de 15%, a qual se aplica inclusive à Fazenda Pública.","d":"de ofício, intimando-se o executado para pagamento no prazo de 15 dias, sob pena de multa de 10%, a qual se aplica inclusive à Fazenda Pública.","e":"a requerimento do exequente, intimando-se o executado para pagamento no prazo de 15 dias, sob pena de multa de 10%, a qual se aplica inclusive à Fazenda Pública.","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Técnico Judiciário - Área Administrativa","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564674","enunciado":"De acordo com o Código de Processo Civil, as provas","a":"caberão sempre ao autor, quanto ao fato constitutivo de seu direito, não podendo o juiz atribuir o ônus de maneira diversa.","b":"podem ser produzidas pelo réu revel, desde que este se faça representar nos autos a tempo de praticar os atos","c":"processuais indispensáveis a essa produção. não podem ser dispensadas pelo juiz, ainda que recaiam sobre fatos notórios ou admitidos como incontroversos.","d":"não podem ser determinadas de ofício.","e":"só podem ser utilizadas em favor da parte que houver requerido sua produção.","gabarito":"B","materia":"Direito Processual Civil - Novo Código de Processo Civil - CPC 2015","tema":"Teoria Geral da Prova","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Técnico Judiciário - Área Administrativa","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564673","enunciado":"","a":"De acordo com o Código de Processo Civil, o Juiz conhecerá de ofício da incompetência relativa, extinguindo o processo com resolução de mérito.","b":"incompetência absoluta, extinguindo o processo sem resolução de mérito.","c":"convenção de arbitragem, extinguindo o processo com resolução de mérito.","d":"litispendência, determinando a reunião dos processos no juízo que houver despachado em primeiro lugar.","e":"incompetência absoluta, determinando a remessa dos autos ao juízo competente. Direito Processual Civil - Novo Código de Processo Civil - CPC 2015>Da Comunicação dos Atos Processuais ,","gabarito":"E","materia":"Direito Processual Civil - Novo Código de Processo Civil - CPC 2015","tema":"Competência no Processo Civil","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Técnico Judiciário - Área Administrativa","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_119","enunciado":"Ano: 2024 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2024 - TRF - 3ª REGIÃO - Técnico Judiciário - Área Administrativa De acordo com o Código de Processo Civil, a citação","a":"será feita por meio eletrônico ou pelo correio para qualquer comarca do país, inclusive quando o citando for incapaz","b":"ou pessoa de direito público. será feita por edital sempre que frustrada a citação pelo correio.","c":"é requisito de validade do processo, salvo no caso de indeferimento da petição inicial ou no de improcedência liminar do pedido.","d":"será realizada ainda que se verifique que o citando é incapaz ou está impossibilitado de recebê-la, independentemente da nomeação de curador.","e":"induz litispendência, torna litigiosa a coisa e constitui em mora o devedor, mas somente se ordenada por juízo competente.","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Técnico Judiciário - Área Administrativa","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564671","enunciado":"De acordo com o Código de Processo Civil, se a petição inicial apresentar defeitos e irregularidades capazes de dificultar o julgamento de mérito, o juiz","a":"determinará que o autor a emende ou a complete, no prazo de 15 dias, indicando com precisão o que deve ser corrigido ou completado, sob pena de indeferimento da petição inicial, com extinção do processo com resolução de mérito.","b":"determinará que o autor a emende ou a complete, no prazo de 5 dias, indicando com precisão o que deve ser corrigido ou completado, sob pena de indeferimento da petição inicial, com extinção do processo com resolução de","c":"mérito. a indeferirá de plano, extinguindo o processo com resolução de mérito.","d":"determinará que o autor a emende ou a complete, no prazo de 15 dias, indicando com precisão o que deve ser corrigido ou completado, sob pena de indeferimento da petição inicial, com extinção do processo sem resolução de","e":"mérito. a indeferirá de plano, extinguindo o processo sem resolução de mérito. Direito Processual Civil - Novo Código de Processo Civil - CPC 2015>","gabarito":"D","materia":"Direito Processual Civil - Novo Código de Processo Civil - CPC 2015","tema":"Improcedência Liminar do Pedido","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Técnico Judiciário - Área Administrativa","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564670","enunciado":"Ano: 2024 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2024 - TRF - 3ª REGIÃO - Técnico Judiciário - Área Administrativa De acordo com o Código de Processo Civil, uma vez opostos embargos à execução que versem apenas sobre questões processuais, o exequente","a":"poderá desistir da execução, independentemente de concordância do embargante, pagando as custas processuais e","b":"os honorários advocatícios. poderá desistir apenas de medidas executivas específicas, mas não da execução toda.","c":"poderá desistir da execução somente com a concordância do embargante, pagando as custas processuais e os honorários advocatícios.","d":"poderá desistir da execução somente com a concordância do embargante, caso em que ficará isento do pagamento","e":"de custas processuais e honorários advocatícios. não poderá desistir da execução nem de medidas executivas específicas.","gabarito":"A","materia":"Processo de Execução de Títulos Extrajudiciais","tema":"","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Técnico Judiciário - Área Administrativa","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564669","enunciado":"","a":"propósito do regime da prescrição referente à responsabilização por improbidade, nos termos da Lei nº 8.429/1992, considere a seguinte situação hipotética: Natalício, servidor federal responsável pela ordenação de despesas, tornou-se investigado em inquérito civil instaurado pelo Ministério Público Federal, em 1º de fevereiro de 2015, em razão de suposto ato de improbidade causador de prejuízo ao erário que teria cometido em 30 de janeiro de 2014. Concluída a investigação, houve a propositura da ação de improbidade em 20 de janeiro de 2016. Em 31 de março de 2018, houve a publicação da sentença condenatória, da qual Natalício apelou. A apelação foi julgada pelo Tribunal Regional Federal em 29 de março de 2022, desprovendo a apelação e mantendo a condenação de Natalício a sanções previstas na Lei nº 8.429/1992 e à reparação dos danos causados ao erário. O acórdão foi publicado em 2 de abril de 2022 e Natalício interpôs recurso especial perante o Superior Tribunal de Justiça, alegando prescrição da pretensão manifestada na ação. Em vista de tal situação, o Superior Tribunal de Justiça deverá reconhecer a prescrição da ação, pois o prazo para ajuizamento da ação, após a instauração de inquérito civil é A","b":"de 180 dias. não deverá reconhecer a prescrição, pois não foram extrapolados os prazos prescricionais previstos na lei.","c":"não deverá reconhecer a prescrição, pois a responsabilidade por atos de improbidade que causem prejuízo ao erário é imprescritível.","d":"deverá reconhecer a prescrição intercorrente em relação às sanções aplicadas, mantendo a condenação de ressarcimento ao erário, que se afigura imprescritível.","e":"deverá reconhecer a prescrição integral da pretensão manifestada na ação, visto que entre a data do ato improbo e a publicação da decisão condenatória decorreu lapso temporal superior a 8 anos.","gabarito":"B","materia":"Direito Administrativo","tema":"Improbidade administrativa - Lei nº 8.429 de 1992 e Lei nº 14.230 de 2021","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Técnico Judiciário - Área Administrativa","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564668","enunciado":"Considere a seguinte descrição: ... são responsáveis pela fiscalização, pelo controle e pela regulação, desempenhando importante papel para promoção da governança das organizações públicas. São autônomas e independentes, e não se vinculam às organizações que são por elas governadas. (Referencial Básico de Governança Organizacional para Organizações Públicas e Outros entes jurisdicionados do TCU. 3a.ed., 2020)","a":"O texto transcrito se refere às instâncias estruturais de governança.","b":"internas de governança.","c":"externas de governança.","d":"internas de apoio à governança.","e":"externas de apoio à governança.","gabarito":"C","materia":"Administração Pública","tema":"Governabilidade, Governança e Accountability ,Governança e governabilidade","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Técnico Judiciário - Área Administrativa","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564667","enunciado":"","a":"Lei de Processo Administrativo (Lei nº 9.784/1999), no que tange aos recursos administrativos, estatui que: A em caso de não conhecimento do recurso, é vedada a revisão de ofício do ato legal, em razão do efeito preclusivo.","b":"os processos administrativos de que resultem sanções poderão ser revistos, a pedido ou de ofício, quando surgirem fatos novos ou circunstâncias relevantes suscetíveis de justificar a inadequação da sanção aplicada, observado o prazo prescricional de 5 anos.","c":"salvo disposição legal específica, é de 10 dias o prazo para interposição de recurso administrativo, contado a partir da ciência ou divulgação oficial da decisão recorrida.","d":"os recursos administrativos serão dirigidos à autoridade superior, que no prazo de 5 dias decidirá sobre a suspensão da decisão recorrida.","e":"têm legitimidade para interpor recurso somente aqueles cujos direitos ou interesses foram diretamente afetados pela decisão recorrida.","gabarito":"C","materia":"Direito Administrativo","tema":"Processo Administrativo - Lei nº 9.784 de 1999 e Lei nº 14.210 de 2021","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Técnico Judiciário - Área Administrativa","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564666","enunciado":"Clara, servidora pública federal, fora demitida de seu cargo, sob acusação de acumulação irregular. Porém, obteve, por meio de ação judicial, decisão anulatória do ato demissional, visto que ficou constatado que os cargos eram acumuláveis, ao contrário do que concluiu a Administração. Transitada em julgado a decisão, verificou-se, na fase de cumprimento da sentença, que o cargo originalmente ocupado por Clara e do qual fora demitida havia sofrido transformação, por força de","a":"lei. Nesse caso, haverá reintegração da autora no cargo resultante da transformação do cargo originalmente ocupado.","b":"a autora será colocada em disponibilidade remunerada com proventos proporcionais ao tempo de serviço até que haja eventual recriação do cargo originalmente ocupado.","c":"a reintegração ficou prejudicada, podendo a autora pleitear perdas e danos em razão da irreversibilidade da demissão.","d":"deverá a autora ser reintegrada no cargo originalmente ocupado, que será recriado por força do efeito preclusivo da força julgada.","e":"invés de reintegração, haverá a aplicação do instituto do aproveitamento, desde que haja compatibilidade de vencimentos e atribuições em relação ao novo cargo.","gabarito":"A","materia":"Direito Administrativo","tema":"Agentes públicos e Lei 8.112 de 1990 ,Provimento e vacância","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Técnico Judiciário - Área Administrativa","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564665","enunciado":"Em razão de grave catástrofe climática ocorrida em um Estado da Federação, o Presidente da República decide criar, por meio de decreto, uma autarquia federal destinada a apoiar os esforços de reconstrução daquela unidade federativa, com prazo de duração de três anos. Nesse caso, a criação da autarquia é","a":"válida, pois cabe ao Presidente da República dispor, mediante decreto, sobre a organização e funcionamento da","b":"Administração federal. inválida, pois não é possível criar autarquia com prazo de duração determinado.","c":"válida, em vista dos poderes excepcionais que a Constituição Federal de 1988 atribui à Presidência da República","d":"durante a vigência de estado de calamidade pública de âmbito nacional. válida, desde que haja ratificação do ato de criação por decreto legislativo do Congresso Nacional.","e":"inválida, pois a criação da autarquia é matéria de reserva legal.","gabarito":"E","materia":"Direito Administrativo","tema":"Organização da Administração Pública ,Autarquias","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Técnico Judiciário - Área Administrativa","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564664","enunciado":"","a":"Nova Lei de Licitações e Contratos (Lei nº 14.133/2021) estabelece, no tocante à alteração dos contratos administrativos, que: Em caso de repactuação de preços prevista no contrato, essa alteração bilateral deverá ser formalizada por meio de A termo aditivo, condição necessária para a produção dos efeitos financeiros respectivos.","b":"Em caso de justificada necessidade e observados os limites legais, a Administração poderá determinar ao contratado prestações não previstas no contrato, desde que formalize o respectivo termo aditivo no prazo máximo de um mês.","c":"É vedada, em contratos de obras ou de serviços de engenharia, a alteração contratual motivada por falha de projeto, devendo haver a realização da nova licitação do objeto, com base em projeto retificado.","d":"Nas alterações unilaterais em contratos de obras, serviços ou compras, o contratado será obrigado a aceitar acréscimos e supressões de até 25% do valor inicial atualizado do contrato; porém, os acréscimos e supressões poderão alcançar o percentual de 50%, desde que haja a concordância do contratado.","e":"Nas hipóteses em que for adotada a contratação integrada ou semi-integrada, é possível alterar os valores contratuais, pela ocorrência de evento superveniente alocado na matriz de riscos como de responsabilidade do contratado.","gabarito":"B","materia":"Direito Administrativo","tema":"Contratos Administrativos – Lei nº 14.133 de 2021","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Técnico Judiciário - Área Administrativa","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564663","enunciado":"Atenção: Para responder à questão, considere a Constituição Federal de 1988. Antônio é membro do Ministério Público Federal há 12 anos. Sandra é advogada de notório saber jurídico e de reputação ilibada, com 14 anos de efetiva atividade profissional. Com base apenas nas informações fornecidas, Antônio e Sandra não poderão vir a compor um Tribunal Regional Federal, pois, apesar de um quinto dos lugares","a":"desses tribunais ser composto de membros do Ministério Público e de advogados, indicados em lista sêxtupla pelos órgãos de representação das respectivas classes, Antônio possui menos de 15 anos de carreira e Sandra possui menos de 15 anos de efetiva atividade profissional. Antônio e Sandra poderão vir a compor um Tribunal Regional Federal, já que um quinto dos lugares desses tribunais","b":"será composto de membros do Ministério Público e de advogados, indicados em lista quíntupla pelos órgãos de representação das respectivas classes e, recebidas as indicações, o Tribunal formará lista tríplice, enviando-a ao Supremo Tribunal Federal, que, nos trinta dias subsequentes, escolherá um de seus integrantes para nomeação. apenas Antônio poderá vir a compor um Tribunal Regional Federal, já que um quinto dos lugares desses tribunais será","c":"composto de membros do Ministério Público, indicados em lista quíntupla pelos órgãos de representação das respectivas classes e, recebidas as indicações, o Tribunal formará lista tríplice, enviando-a ao Supremo Tribunal Federal, que, nos vinte dias subsequentes, escolherá um de seus integrantes para nomeação. Antônio e Sandra poderão vir a compor um Tribunal Regional Federal, já que um quinto dos lugares desses tribunais","d":"será composto de membros do Ministério Público e de advogados, indicados em lista sêxtupla pelos órgãos de representação das respectivas classes e, recebidas as indicações, o Tribunal formará lista tríplice, enviando-a ao Poder Executivo, que, nos vinte dias subsequentes, escolherá um de seus integrantes para nomeação. apenas Sandra poderá vir a compor um Tribunal Regional Federal, já que um quinto dos lugares desses tribunais será","e":"composto de advogados, indicados em lista sêxtupla pelos órgãos de representação das respectivas classes e, recebidas as indicações, o Tribunal formará lista tríplice, enviando-a ao Poder Executivo, que, nos trinta dias subsequentes, escolherá um de seus integrantes para nomeação.","gabarito":"D","materia":"Direito Constitucional","tema":"Tribunais Regionais Federais e Juízes Federais ,Organização do Poder Judiciário","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Técnico Judiciário - Área Administrativa","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564662","enunciado":"Gustavo é Governador do Estado do Mato Grosso do Sul e sua esposa, Débora, pretende se candidatar ao cargo de Prefeita de uma cidade nesse mesmo Estado, nas eleições municipais que ocorrerão neste ano de 2024. Ainda, Gustavo tem um filho, Henrique, que reside há muitos anos em uma cidade no Estado de São Paulo onde mantém o seu domicílio eleitoral, pretendendo, também, candidatar-se a Prefeito dessa cidade. Considerando apenas as informações hipotéticas fornecidas, Débora é inelegível, pois além dos parentes consanguineos ou afins, até o segundo grau ou por adoção, também é inelegível,","a":"no território de jurisdição do titular, o cônjuge do Presidente da República, de Governador de Estado ou Território, do Distrito Federal, de Prefeito ou de quem os haja substituído dentro dos seis meses anteriores ao pleito, enquanto Henrique é elegível, pois o município paulista não se encontra sob a jurisdição do Governador de Mato Grosso do Sul. é elegível, pois apenas são inelegíveis, no território da jurisdição do titular, os parentes consanguíneos ou afins, até o","b":"segundo grau ou por adoção, do Presidente da República, de Governador de Estado ou Território, do Distrito Federal, de Prefeito ou de quem os haja substituído dentro dos seis meses anteriores ao pleito, enquanto Henrique é elegível, desde que Gustavo renuncie ao seu respectivo mandato até seis meses antes das eleições municipais nas quais ele concorrerá ao cargo de prefeito em sua cidade. é elegível, pois apenas são inelegíveis, no território da jurisdição do titular, os parentes consanguíneos ou afins, até o","c":"segundo grau ou por adoção, do Presidente da República, de Governador de Estado ou Território, do Distrito Federal, de Prefeito ou de quem os haja substituído dentro dos seis meses anteriores ao pleito, enquanto Henrique é inelegível, pois é filho de Gustavo, que já é titular do mandato eletivo.","d":"e Henrique são inelegíveis, pois Gustavo já é titular de mandato eletivo, independentemente do território de jurisdição.","e":"e Henrique são elegíveis, pois apenas são inelegíveis, no território da jurisdição do titular, os parentes consanguíneos ou afins, até o segundo grau ou por adoção, do Presidente da República, de Governador de Estado ou Território, do Distrito Federal, de Prefeito ou de quem os haja substituído dentro dos seis meses anteriores ao pleito.","gabarito":"A","materia":"Direito Constitucional","tema":"Direitos Políticos","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Técnico Judiciário - Área Administrativa","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564661","enunciado":"Margareth foi nomeada para cargo de provimento efetivo em virtude de concurso público e, após quatro anos de exercício efetivo desse cargo, foi demitida. Contudo, a sua demissão foi invalidada por sentença judicial. Nesse caso hipotético, Margareth, cumpridas as condições para aquisição da estabilidade, será reintegrada, e o eventual ocupante da vaga, se estável,","a":"reconduzido ao cargo de origem, com direito a indenização, aproveitado em outro cargo ou posto em disponibilidade com remuneração proporcional ao tempo de serviço. E, no caso de ter sido extinto o cargo ou declarada a sua desnecessidade, Margareth não será aproveitada em outro cargo, porém terá direito à indenização. cumpridas as condições para aquisição da estabilidade, será reintegrada, e o eventual ocupante da vaga,","b":"independentemente de ter estabilidade, reconduzido ao cargo de origem, sem direito a indenização, aproveitado em outro cargo ou posto em disponibilidade com remuneração proporcional ao tempo de serviço. E, no caso de ter sido extinto o cargo ou declarada a sua desnecessidade, Margareth ficará em disponibilidade, sem perceber qualquer remuneração, até seu adequado aproveitamento em outro cargo. cumpridas as condições para aquisição da estabilidade, será reintegrada, e o eventual ocupante da vaga, se estável,","c":"reconduzido ao cargo de origem, sem direito a indenização, aproveitado em outro cargo ou posto em disponibilidade com remuneração proporcional ao tempo de serviço. E, no caso de ter sido extinto o cargo ou declarada a sua desnecessidade, Margareth ficará em disponibilidade, com remuneração proporcional ao tempo de serviço, até seu adequado aproveitamento em outro cargo.","d":"por não cumprir o tempo mínimo exigido para aquisição da estabilidade, não poderá ser reintegrada, porém deverá perceber remuneração proporcional ao tempo de serviço até a sua aposentadoria.","e":"por não cumprir o tempo mínimo exigido para aquisição da estabilidade, não poderá ser reintegrada e não terá direito a perceber remuneração proporcional ao tempo de serviço, devendo, contudo, receber indenização do órgão competente.","gabarito":"C","materia":"Direito Constitucional","tema":"Administração Pública – Disposições Gerais e Servidores Públicos ,Servidores Públicos","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Técnico Judiciário - Área Administrativa","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564660","enunciado":"O trabalhador rural possui, dentre outros que visem à melhoria de sua condição social, o direito ao seguro contra acidentes","a":"de trabalho, a cargo do empregador, sem excluir a indenização a que este está obrigado, apenas quando incorrer em culpa.","b":"empregador, sem excluir a indenização a que este está obrigado, quando incorrer em dolo ou culpa.","c":"empregado, sem excluir a indenização a que o empregador está obrigado, quando incorrer em dolo.","d":"empregador, sem excluir a indenização a que este está obrigado, apenas quando incorrer em dolo.","e":"empregado, excluindo-se qualquer indenização por parte do empregador.","gabarito":"B","materia":"Direito Constitucional","tema":"Direitos Sociais","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Técnico Judiciário - Área Administrativa","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564659","enunciado":"Uma convenção internacional sobre direitos humanos que for","a":"aprovada, em cada Casa do Congresso Nacional, em um único turno, por dois quintos dos votos dos respectivos membros, será equivalente à emenda constitucional.","b":"ratificada pelo Brasil, diferentemente de um tratado internacional, apenas será equivalente à emenda constitucional se tiver sido aprovada, em cada Casa do Congresso Nacional, em um único turno, pela maioria dos votos dos respectivos membros.","c":"aprovada, em cada Casa do Congresso Nacional, em dois turnos, por três quintos dos votos dos respectivos membros,","d":"será equivalente à emenda constitucional. ratificada pelo Brasil, diferentemente de um tratado internacional, nunca será equivalente à emenda constitucional.","e":"aprovada, em cada Casa do Congresso Nacional, em dois turnos, por dois quintos dos votos dos respectivos membros, será equivalente à emenda constitucional.","gabarito":"C","materia":"Direito Constitucional","tema":"Direitos Individuais","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Técnico Judiciário - Área Administrativa","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564658","enunciado":"Um grupo de pessoas protetoras dos animais quer se reunir, pacificamente e sem armas, em um local aberto ao público para defender ideias que os beneficiam. Essa reunião pode ocorrer,","a":"desde que a convocação da reunião tenha sido realizada por uma associação criada e aprovada, na forma da lei, por autoridade competente, sendo apenas exigido prévio aviso a essa autoridade.","b":"desde que a convocação da reunião tenha sido realizada por uma associação criada e aprovada, na forma da lei, por autoridade competente, sendo apenas exigida autorização da parte desta.","c":"independentemente de autorização e de prévio aviso à autoridade competente, desde que não frustre outra reunião anteriormente convocada para o mesmo local.","d":"desde que haja autorização da autoridade competente e que não frustre outra reunião anteriormente convocada para o mesmo local.","e":"independentemente de autorização, desde que não frustre outra reunião anteriormente convocada para o mesmo local, sendo apenas exigido prévio aviso à autoridade competente.","gabarito":"E","materia":"Direito Constitucional","tema":"Direitos Individuais ,Direito à Liberdade","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Técnico Judiciário - Área Administrativa","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564657","enunciado":"Atenção: Para responder à questão, considere a Constituição Federal de 1988. Carla, brasileira, estava grávida e resolveu passar as férias na Itália, onde nasceu seu filho, Ademar, que não foi registrado em repartição brasileira competente. Anastacia, espanhola, sem condenação penal, vive no Brasil há 12 anos ininterruptos e, apesar de ainda não conhecer muito a língua portuguesa, quer requerer a nacionalidade brasileira. Nessa situação, considerando apenas os dados fornecidos, Ademar é brasileiro","a":"naturalizado, desde que venha a residir no Brasil e opte, em qualquer tempo, depois de atingida a maioridade, pela nacionalidade brasileira; e Anastacia poderá se naturalizar brasileira nesse momento, pois reside no Brasil há mais de dez anos ininterruptos.","b":"nato, desde que venha a residir no Brasil e opte, em qualquer tempo, depois de atingida a maioridade, pela nacionalidade brasileira; e Anastacia não poderá se naturalizar brasileira nesse momento, pois reside no Brasil há menos de quinze anos ininterruptos.","c":"nato, ainda que não tenha sido registrado em repartição brasileira competente, pois é filho de brasileira e, por essa razão, não é necessário o preenchimento de nenhum outro requisito legal; e Anastacia não poderá se naturalizar brasileira nesse momento, pois reside no Brasil há menos de quinze anos ininterruptos.","d":"naturalizado, desde que venha a residir no Brasil e opte, em qualquer tempo, depois de atingida a maioridade, pela nacionalidade brasileira; e Anastacia não poderá se naturalizar brasileira nesse momento, pois reside no Brasil hã menos de quinze anos ininterruptos.","e":"nato, desde que venha a residir no Brasil e opte, em qualquer tempo, depois de atingida a maioridade, pela nacionalidade brasileira; e Anastacia poderá se naturalizar brasileira nesse momento, pois reside no Brasil há mais de dez anos ininterruptos. Estatuto da Pessoa com Deficiência - Lei nº 13.146 de 2015>Legislação das Pessoas com Deficiência ,","gabarito":"B","materia":"Direito Constitucional","tema":"Direitos da Nacionalidade","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Técnico Judiciário - Área Administrativa","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_135","enunciado":"Ano: 2024 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2024 - TRF - 3ª REGIÃO - Técnico Judiciário - Área Administrativa Em uma situação hipotética, Zeus é médico de um renomado hospital público na cidade de São Paulo. No entanto, Zeus, injustificadamente, recusou-se a prestar assistência médico-hospitalar a Atena, pessoa com deficiência. De acordo com o que preceitua a Lei nº 7.853/1989, a conduta de Zeus","a":"constitui crime punível com reclusão de 2 a 5 anos e multa, não prevendo a lei qualquer agravamento da penalidade, ainda que a conduta tenha sido praticada em atendimento de urgência e emergência.","b":"constitui crime punível com reclusão de 1 a 4 anos e multa, sendo tal pena agravada em 1/2, se o crime tiver sido praticado em atendimento de urgência e emergência.","c":"constitui crime punível com detenção de 1 a 4 anos e multa, sendo tal pena agravada em 1/3, se o crime tiver sido","d":"praticado em atendimento de urgência e emergência. não constitui crime, mas será passível de punição tanto na seara administrativa quanto na cível.","e":"constitui crime punível com reclusão de 2 a 5 anos e multa, sendo tal pena agravada em 1/3, se o crime tiver sido praticado em atendimento de urgência e emergência. Estatuto da Pessoa com Deficiência - Lei nº 13.146 de 2015>Legislação das Pessoas com Deficiência ,","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Técnico Judiciário - Área Administrativa","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_136","enunciado":"Ano: 2024 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2024 - TRF - 3ª REGIÃO - Técnico Judiciário - Área Administrativa De acordo com a Lei nº 10.048/2000, as pessoas com deficiência terão atendimento prioritário. Caso não haja postos, caixas, guichês, linhas ou atendentes específicos para a realização desse atendimento prioritário, as pessoas com deficiência","a":"não terão atendimento imediato, isto é, não terão prioridade de atendimento, devendo ingressar na ordem de atendimento regular, aplicável a todos os cidadãos, havendo, todavia, penalização aos responsáveis.","b":"não terão atendimento imediato, isto é, não terão prioridade de atendimento, devendo ingressar na ordem de","c":"atendimento regular, aplicável a todos os cidadãos, não havendo penalização em decorrência de tal fato. não serão atendidas, no entanto, haverá aplicação de multa e responsabilização pelo fato cometido.","d":"deverão ser atendidas imediatamente, inclusive interrompendo-se eventual atendimento que estiver em andamento.","e":"deverão ser atendidas imediatamente após a conclusão do atendimento que estiver em andamento, antes de quaisquer outras pessoas.","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Técnico Judiciário - Área Administrativa","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564654","enunciado":"Em uma situação hipotética, Romeu, pessoa com deficiência, é servidor público do Tribunal Regional Federal da 3ª Região. Conforme preceitua a Resolução nº 401/2021, do Conselho Nacional de Justiça, a avaliação da deficiência será realizada a cada cinco anos, ou a pedido do(a) interessado(a). Considerando que a deficiência de Romeu é de caráter permanente, a","a":"periodicidade da avaliação anteriormente narrada deverá ser reduzida para dois anos, obrigatoriamente.","b":"poderá ser estendida, a critério de Romeu, não podendo, todavia, ser dispensada.","c":"poderá ser estendida, a critério da equipe multidisciplinar, podendo, inclusive, ser dispensada.","d":"poderá ser reduzida, a critério da equipe multidisciplinar, não podendo, todavia, ser dispensada.","e":"deverá ser estendida para seis anos, obrigatoriamente. Estatuto da Pessoa com Deficiência - Lei nº 13.146 de 2015>","gabarito":"C","materia":"Legislação dos TRFs","tema":"Conselho Nacional de Justiça (CNJ) ,Resoluções do CNJ","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Técnico Judiciário - Área Administrativa","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_138","enunciado":"Ano: 2024 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2024 - TRF - 3ª REGIÃO - Técnico Judiciário - Área Administrativa Nos termos da Lei nº 13.146/2015, considere: I. As frotas de empresas de táxi devem reservar 10% de seus veículos acessíveis à pessoa com deficiência. II. É admitida a cobrança diferenciada de tarifas pelo serviço de táxi prestado à pessoa com deficiência. III. As locadoras de veículos são obrigadas a oferecer 1 veículo adaptado para uso de pessoa com deficiência, a cada conjunto de 20 veículos de sua frota.","a":"Especificamente no que concerne ao direito ao transporte e à mobilidade, está correto o que se afirma em I, II e III.","b":"III, apenas.","c":"I e II, apenas.","d":"I e III, apenas.","e":"II, apenas. Estatuto da Pessoa com Deficiência - Lei nº 13.146 de 2015>Legislação das Pessoas com Deficiência ,","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Técnico Judiciário - Área Administrativa","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_139","enunciado":"Ano: 2024 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2024 - TRF - 3ª REGIÃO - Técnico Judiciário - Área Administrativa Nos termos da Lei nº 10.098/2000, brinquedos e equipamentos de lazer existentes em vias públicas, em parques e nos demais espaços de uso público devem ser adaptados e identificados, tanto quanto tecnicamente possível, para possibilitar sua utilização por pessoas com deficiência, inclusive visual, ou com mobilidade reduzida. Referida Lei exige uma porcentagem mínima de cada brinquedo e equipamento de lazer adaptados e identificados, nos moldes anteriormente","a":"narrados, que deverá ser de, no mínimo, 5%.","b":"10%.","c":"4%.","d":"2%.","e":"3%.","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Técnico Judiciário - Área Administrativa","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564651","enunciado":"Cinco amigos não concordam sobre o dia em que ocorreu o último encontro. — Laís disse que foi em uma quarta-feira, dia 09 de outubro. — Marcos disse que foi em uma sexta-feira. dia 09 de outubro. — Nair disse que foi em uma sexta-feira, dia 10 de novembro. — Olga disse que foi em uma quarta-feira, dia 10 de outubro. — Paulo disse que foi em uma quarta-feira, dia 10 de novembro. Apenas um deles está correto, mas nenhum dos outros está totalmente errado, pois acertou pelo menos o dia da semana,","a":"o dia do mês ou o mês. O nome de quem está correto é Olga.","b":"Marcos.","c":"Lais.","d":"Paulo.","e":"Nair.","gabarito":"A","materia":"Raciocínio Lógico","tema":"Lógica de Argumentação - Diagramas e Operadores Lógicos","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Técnico Judiciário - Área Administrativa","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564650","enunciado":"Considerando a idade de cada um dos 55 funcionários de um escritório como um número inteiro de anos, o mais novo tem","a":"25 anos e o mais velho, 39 anos. Então, pelo menos, 6 funcionários têm a mesma idade.","b":"no máximo, 2 funcionários têm a mesma idade.","c":"pelo menos, 3 funcionários têm 39 anos.","d":"pelo menos, 4 funcionários têm a mesma idade.","e":"a média das idades é 32 anos.","gabarito":"D","materia":"Matemática","tema":"Aritmética e Problemas ,Números Primos e Divisibilidade","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Técnico Judiciário - Área Administrativa","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564649","enunciado":"Uma estrada que liga as cidades A e B será asfaltada por duas equipes de trabalhadores. Cada equipe está responsável por asfaltar metade da estrada, sendo que uma delas começa pela cidade A e a outra começa pela B. Uma das equipes asfalta 300 metros por dia e terminará seu serviço em 16 dias. Já a outra equipe consegue asfaltar 200 metros por dia. Se as","a":"equipes começam a trabalhar ao mesmo tempo, a estrada terá seu asfalto pronto em 56 dias.","b":"64 dias.","c":"24 dias.","d":"18 dias.","e":"40 dias.","gabarito":"C","materia":"Matemática","tema":"Aritmética e Problemas ,Razão e Proporção; e Números Proporcionais","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Técnico Judiciário - Área Administrativa","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564648","enunciado":"André, Bento, Caio e Daniel colecionam relógios e possuem, ao todo, 25 relógios. Daniel é quem tem menos relógios.","a":"Sabendo-se que todos possuem quantidades diferentes de relógios, o maior número de relógios que Daniel pode ter é 5.","b":"6.","c":"3.","d":"7.","e":"4.","gabarito":"E","materia":"Matemática","tema":"Aritmética e Problemas ,MMC e MDC","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Técnico Judiciário - Área Administrativa","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564647","enunciado":"Luís sai de casa às 8h00, caminhando a uma velocidade de 6 km/h. Laura, sua irmã, percebe que Luís esqueceu seu caderno em cima da mesa e sai atrás dele para entregar-lhe o caderno, seguindo o mesmo caminho. Ela parte às 8h05, correndo a","a":"uma velocidade de 12 km/h. Laura alcança Luís às 8h24.","b":"8h10.","c":"8h30.","d":"8h15.","e":"8h18.","gabarito":"B","materia":"Matemática","tema":"Aritmética e Problemas ,Sistema de Unidade de Medidas ,Regra de Três","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Técnico Judiciário - Área Administrativa","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564646","enunciado":"O nascer da Terra Às vezes tento imaginar o mundo sem literatura. Eu sentiria falta dos livros nos aviões. Livrarias e bibliotecas teriam espaço de sobra nas estantes (e as minhas não estariam transbordando). A indústria editorial não existiria como a conhecemos, nem a Amazon, e não haveria nada em minha mesa de cabeceira quando não consigo dormir à noite. Tudo isso seria lamentável, mas mal arranha a superfície do que seria perdido se a literatura nunca tivesse existido, se as histórias só fossem contadas oralmente e nunca tivessem sido escritas. Um mundo assim é quase impossível de imaginar. Nosso sentido de história, da ascensão e queda de impérios e nações, seria completamente diferente. A maior parte das ideias filosóficas e políticas nunca teria existido, ou teria sido esquecida, porquanto a literatura que deu origem a elas não teria sido escrita. Quase","a":"todas as crenças religiosas desapareceriam com as escrituras em que foram expressas. literatura não é apenas para os amantes dos livros. Desde que surgiu, hã 4 mil anos, ela moldou a vida da maioria dos seres humanos que vivem no planeta Terra. (Adaptado de: PUCHNER, Martin. O mundo da escrita. Trad. SOARES, Pedro Maia. São Paulo: Companhia das Letras, 2019) Quase todas as crenças religiosas desapareceriam com as escrituras em que foram expressas. Substitui adequadamente a expressão sublinhada:","b":"A nas quais as quais","c":"das quais","d":"sobre as quais","e":"cujas as quais","gabarito":"A","materia":"Português","tema":"Interpretação de Textos ,Redação - Reescritura de texto","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Técnico Judiciário - Área Administrativa","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564645","enunciado":"Livrarias e bibliotecas teriam espaço de sobra nas estantes.","a":"No trecho acima, a classe gramatical da palavra sublinhada é: Advérbio.","b":"Conjunção.","c":"Adjetivo.","d":"Substantivo.","e":"Verbo.","gabarito":"D","materia":"Português","tema":"Morfologia ,Substantivos","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Técnico Judiciário - Área Administrativa","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564644","enunciado":"","a":"O principal contraste apresentado pelo autor decorre da discordância entre a valorização da literatura e a falta de reconhecimento das artes visuais no mundo atual.","b":"confrontação entre preservação das crenças religiosas através da escrita e seu esquecimento na tradição oral.","c":"divergência entre a disponibilidade de livros físicos e a praticidade da leitura digital nos tempos atuais.","d":"oposição entre a indústria editorial digital e a tradição oral na transmissão de histórias pessoais e coletivas.","e":"diferença entre a escrita como forma de registro documental e a oralidade como meio de transmissão cultural.","gabarito":"E","materia":"Português","tema":"Interpretação de Textos ,Noções Gerais de Compreensão e Interpretação de Texto","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Técnico Judiciário - Área Administrativa","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564643","enunciado":"","a":"O autor, ao discorrer sobre literatura, destaca como aspecto fundamental: A influência da literatura na transformação das crenças religiosas ao longo da história.","b":"A exclusividade da literatura como interesse para os amantes de livros.","c":"A necessidade de mais livrarias e bibliotecas para acomodar a quantidade crescente de livros.","d":"A importância dos livros como fonte de entretenimento durante viagens de avião.","e":"O impacto da literatura na formação da história, das ideias filosóficas e políticas.","gabarito":"E","materia":"Português","tema":"Interpretação de Textos ,Noções Gerais de Compreensão e Interpretação de Texto","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Técnico Judiciário - Área Administrativa","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564642","enunciado":"","a":"relação estabelecida pela oração subordinada porquanto a literatura que deu origem a elas não teria sido escrita (2º parágrafo) em relação à principal é de:","b":"A finalidade. comparação.","c":"causalidade.","d":"temporalidade.","e":"concessão.","gabarito":"C","materia":"Português","tema":"Morfologia ,Conjunções: Relação de causa e consequência","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Técnico Judiciário - Área Administrativa","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564641","enunciado":"Devaneio, logo existo As três pessoas que estavam comigo no elevador se recusavam a devanear. Assim como as pessoas do vagão do metrô. Foram duas rápidas observações que me levaram a respirar aliviado por ter percebido que ainda preservava a autoindulgência tanto do devaneio quanto da inspeção de atitudes alheias. A crítica de “ninguém mais conversa; todo mundo anda e até come com a fuça no celular” nunca me convenceu, pois se a pessoa não está prejudicando ninguém, que faça o que bem entender. No meu conceito, porém, ela está deixando de existir como indivíduo, pois é no devaneio, na contemplação e na troca que se imprime identidade no mundo. Explico melhor. E para isso recorro à inteligência artificial generativa, uma evocação à própria base de dados para geração de conteúdos novos, sejam textos, áudios, músicas, imagens ou vídeos. E o que é essa jornada se não o próprio caminho do processo criativo, por onde estabelecemos nossa assinatura? Os pensamentos não nascem no vácuo. As descobertas tampouco. Insights germinam do correlacionamento de memórias, da conexão das diferentes peças no repertório intelectual que fomos colecionando no decorrer da vida. A iluminação é elaborada em nosso devaneio. Só que cada vez menos somos propensos à permissão de experiências tão somente contemplativas. Até o caminhar precisa ser preenchido por fone de ouvido, consumo de notícias, checagem de mensagens de Whatsapp. Quando dizem que a meditação é um dos pilares de estilo de vida saudável não explicam devidamente sua importância. O próprio René Descartes, inspirador do título deste artigo e do cartesianismo, lançou obra chamada Meditações. Também não é explícito o risco do comodismo de entregar tudo o que tona humana a nossa espécie a um dispositivo. Já é sabido desde o século 18, na Revolução Industrial, que as máquinas são superiores em produção. Só que a mecanização não ativa a inteligência nem a razão, que são as ligas da vida e do real progresso dos seres humanos. Ainda no século 17 os filósofos iluministas ensinaram o valor do devaneio na formação de pessoas com melhores decisões morais.","a":"Predomina no trecho acima a seguinte figura de linguagem: Anacoluto.","b":"Hipérbole.","c":"Metáfora.","d":"Personificação. E Antítese.","e":"(Adaptado de: PIMENTAL, Luiz Cesar. Revista Isto é, 15/03/2024. Disponível em: https://istoe.com.br) o que é essa jornada se não o próprio caminho do processo criativo, por onde estabelecemos nossa assinatura? (2º parágrafo)","gabarito":"C","materia":"Português","tema":"Interpretação de Textos ,Figuras de Linguagem","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Técnico Judiciário - Área Administrativa","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564640","enunciado":"","a":"O uso do advérbio “também” (3º parágrafo) implica dois aspectos no texto: a importância da meditação e o risco do comodismo.","b":"a mecanização do trabalho e a razão do ser humano.","c":"a superioridade das máquinas e a moralidade das decisões.","d":"o devaneio das pessoas e a crítica de René Descartes.","e":"o lado humano da nossa espécie e o uso de dispositivos.","gabarito":"A","materia":"Português","tema":"Morfologia ,Advérbios","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Técnico Judiciário - Área Administrativa","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564639","enunciado":"","a":"O termo “autoindulgência” (1º parágrafo) pode ser substituído, sem prejuízo de sentido ao texto, por autoironia.","b":"autoexigência.","c":"autopreconceito.","d":"autocomplacência.","e":"autoperseverança.","gabarito":"D","materia":"Português","tema":"Interpretação de Textos ,Significação Contextual de Palavras e Expressões. Sinônimos e Antônimos.","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Técnico Judiciário - Área Administrativa","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564638","enunciado":"No texto, a relação entre devaneio e existência é evidenciada pela","a":"sugestão de que o devaneio sobrepuja a essência humana, sendo necessário desafiá-lo por uma compreensão profunda da realidade.","b":"defesa de que devanear é fundamental para a vida humana, pois é por meio dessa atividade que se constrói identidade e se estabelece conexão com o mundo.","c":"discussão da conexão entre devaneio, contemplação e subjetividade, mas sem a apresentação de um ponto de vista claro e conclusivo.","d":"crítica à tendência contemporânea de supervalorizar o devaneio no lugar de constantes estímulos externos, por comprometerem a essência humana.","e":"alegação de que devanear é uma atividade supérflua na vida moderna, uma vez que a existência humana está mais ligada à produção e à eficiência.","gabarito":"B","materia":"Português","tema":"Interpretação de Textos ,Noções Gerais de Compreensão e Interpretação de Texto","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Técnico Judiciário - Área Administrativa","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564637","enunciado":"O elemento sublinhado em Ainda no século 17 os filósofos iluministas ensinaram o valor do devaneio (3º parágrafo) exerce a","a":"mesma função sintática daquele sublinhado em: E para isso recorro à inteligência artificial generativa (2º parágrafo)","b":"pois se a pessoa não está prejudicando ninguém(1º parágrafo)","c":"Só que a mecanização não ativa a inteligência nem a razão (3º parágrafo)","d":"As três pessoas que estavam comigo no elevador se recusavam a devanear (1º parágrafo)","e":"ela está deixando de existir como indivíduo (12 parágrafo)","gabarito":"C","materia":"Português","tema":"Sintaxe ,Análise sintática","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Técnico Judiciário - Área Administrativa","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564510","enunciado":"De acordo com a Lei nº 9.717/1998, os regimes próprios de previdência social dos servidores públicos da União, dos Estados, do Distrito Federal e dos Municípios, dos militares dos Estados e do Distrito Federal deverão ser organizados e baseados em normas gerais de contabilidade e atuária, de modo a garantir o seu equilíbrio financeiro e atuarial, observando critérios para realização","a":"de avaliação atuarial inicial e em cada balanço com parâmetros gerais para a organização e revisão apenas do plano de benefícios, além de observar o financiamento mediante recursos provenientes somente dos Estados, do Distrito Federal e dos Municípios e das contribuições do pessoal civil e militar, ativo, inativo e dos pensionistas, para Os seus respectivos regimes. governança e atuaria, de modo a garantir o seu equilíbrio financeiro e atuarial, observando critérios para realização de","b":"avaliação atuarial inicial e em cada balanço com parâmetros gerais para a organização e revisão do plano de custeio e benefícios, além de observar o financiamento mediante recursos provenientes da União, dos Estados, do Distrito Federal e dos Municípios e das contribuições apenas do pessoal civil e militar ativo e dos pensionistas, para os seus respectivos regimes. governança e atuária, de modo a garantir o seu equilíbrio financeiro e atuarial, observando critérios para realização de","c":"avaliação atuarial final e em alguns balanços com parâmetros gerais para a organização e revisão do plano de custeio e benefícios, além de observar o financiamento mediante recursos provenientes da União, dos Estados, do Distrito Federal e dos Municípios e das contribuições do pessoal civil e militar, ativo, inativo e dos pensionistas, para os seus respectivos regimes. contabilidade e atuária, de modo a garantir o seu equilíbrio financeiro e atuarial, observando critérios para realização","d":"de avaliação atuarial inicial e em cada balanço com parâmetros gerais para a organização e revisão do plano de custeio e benefícios, além de observar o financiamento mediante recursos provenientes da União, dos Estados, do Distrito Federal e dos Municípios e das contribuições do pessoal civil e militar, ativo, inativo e dos pensionistas, para os seus respectivos regimes. contabilidade e atuária, de modo a garantir o seu equilíbrio financeiro e atuarial, observando critérios para realização","e":"de avaliação atuarial inicial e em cada balanço com parâmetros divergentes para a organização e revisão apenas do plano de custeio, além de observar o financiamento mediante recursos provenientes da União, dos Estados, do Distrito Federal e dos Municípios e das contribuições do pessoal civil e militar, ativo, inativo e dos pensionistas, para os seus respectivos regimes. Direito Previdenciário>Seguridade Social , Organização e Custeio da Seguridade Social - Lei n. 8.212, de 24 de julho de 1991 ,","gabarito":"D","materia":"Direito Previdenciário","tema":"Regime Próprio de Previdência Social - RPPS","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_156","enunciado":"Segurados Obrigatórios - Trabalhador Avulso Ano: 2024 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária Segundo a Lei nº 8.212/1991, além das contribuições provenientes do faturamento ou receita e do lucro, a contribuição a cargo da empresa, destinada à Seguridade Social, é de 20% sobre o total das remunerações pagas, devidas ou creditadas a qualquer título, durante o mês aos segurados empregados e trabalhadores avulsos que lhe prestem serviços, destinadas a retribuir o trabalho, qualquer que seja a sua forma,","a":"inclusive as gorjetas, os ganhos habituais sob a forma de utilidades e os adiantamentos decorrentes de reajuste salarial, quer pelos serviços efetivamente prestados, quer pelo tempo à disposição do empregador ou tomador de serviços, nos termos da lei ou do contrato ou, ainda, de convenção ou acordo coletivo de trabalho ou sentença normativa. facultativos que lhe prestem serviços, destinadas a retribuir o trabalho, a depender da sua forma, inclusive as gorjetas,","b":"05 ganhos eventuais sob a forma de utilidades e os adiantamentos decorrentes de reajuste salarial, quer pelos serviços efetivamente prestados, quer pelo tempo à disposição do empregador ou tomador de serviços, nos termos da lei ou do contrato ou, ainda, de convenção ou acordo coletivo de trabalho ou sentença normativa. trabalhadores avulsos que lhe prestem serviços, destinadas a retribuir o capital investido, qualquer que seja a sua","c":"forma, inclusive as gorjetas, mas com exceção dos ganhos habituais sob a forma de utilidades e os adiantamentos decorrentes de reajuste salarial, quer pelos serviços efetivamente prestados, quer pelo tempo à disposição do empregador ou tomador de serviços, nos termos da lei ou do contrato ou, ainda, de convenção ou acordo coletivo de trabalho ou sentença normativa. trabalhadores avulsos que lhe prestem serviços, destinadas a retribuir o capital investido, qualquer que seja a sua","d":"forma, inclusive as gorjetas, os ganhos eventuais sob a forma de utilidades e os adiantamentos decorrentes de reajuste salarial, quer pelos serviços efetivamente prestados, quer pelo tempo à disposição do empregador ou tomador de serviços, nos termos da lei ou do contrato, não se aplicando os termos de convenção ou acordo coletivo de trabalho ou sentença normativa. trabalhadores avulsos que lhe prestem serviço, destinadas a retribuir o trabalho, qualquer que seja a sua forma,","e":"inclusive os ganhos habituais sob a forma de utilidades e os adiantamentos decorrentes de reajuste salarial, exceto as gorjetas, quer pelos serviços efetivamente prestados, quer pelo tempo à disposição do empregador ou tomador de serviços, nos termos da lei ou do contrato ou, ainda, de convenção ou acordo coletivo de trabalho ou sentença normativa.","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_157","enunciado":"Ano: 2024 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária Com base na Lei Complementar nº 109/2001, as entidades de previdência complementar constituirão reservas técnicas, provisões e fundos, de conformidade com os critérios e normas fixados pelo órgão","a":"regulador e fiscalizador, mas não aplicarão os recursos correspondentes conforme diretrizes estabelecidas pelo Conselho Monetário Nacional, sendo vedado o estabelecimento de aplicações compulsórias ou limites mínimos de aplicação.","b":"não constituirão reservas técnicas, provisões e fundos, de conformidade com os critérios e normas fixados pelo órgão regulador e fiscalizador e não aplicarão os recursos correspondentes conforme diretrizes estabelecidas pelo Conselho Monetário Nacional, sendo vedado o estabelecimento de aplicações compulsórias ou limites mínimos de aplicação.","c":"constituirão reservas técnicas, provisões e fundos, de conformidade com os critérios e normas fixados pelo órgão regulador e fiscalizador e aplicarão os recursos correspondentes conforme diretrizes estabelecidas pelo Conselho Monetário Nacional, sendo permitido o estabelecimento de aplicações compulsórias ou limites mínimos de aplicação.","d":"não constituirão reservas técnicas, provisões e fundos, de conformidade com os critérios e normas fixados pelo órgão regulador e fiscalizador, mas aplicarão os recursos correspondentes conforme diretrizes estabelecidas pelo Conselho Monetário Nacional, sendo permitido o estabelecimento de aplicações compulsórias ou limites mínimos de aplicação.","e":"constituirão reservas técnicas, provisões e fundos, de conformidade com os critérios e normas fixados pelo órgão regulador e fiscalizador e aplicarão os recursos correspondentes conforme diretrizes estabelecidas pelo Conselho Monetário Nacional, sendo vedado o estabelecimento de aplicações compulsórias ou limites mínimos de aplicação. Direito Previdenciário>Seguridade Social ,Regime Geral de Previdência Social - RGPS , Organização e Custeio da Seguridade Social - Lei n. 8.212, de 24 de julho de 1991","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_158","enunciado":"Beneficiários do Regime Geral de Previdência Social - RGPS ,Filiação e Inscrição ,Benefícios em Espécie Ano: 2024 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária À previdência social será organizada sob a forma do Regime Geral de Previdência Social, de caráter contributivo e de filiação obrigatória, observados critérios que preservem o equilíbrio financeiro e atuarial, e atenderá, na forma da lei, a cobertura dos eventos de incapacidade temporária ou permanente para o trabalho e idade avançada, proteção à natalidade, especialmente à","a":"gestante; proteção ao trabalhador em situação de desemprego involuntário; salário-família e auxílio-reclusão aos segurados de baixa renda; e pensão por morte do segurado, homem ou mulher, ao cônjuge ou companheiro e dependentes. incapacidade temporária ou permanente para o trabalho e idade avançada; proteção à maternidade, especialmente à","b":"gestante, proteção ao trabalhador em situação de desemprego involuntário, salário-família e auxílio-reclusão para os dependentes dos segurados de baixa renda; e pensão por morte do segurado, homem ou mulher, ao cônjuge ou companheiro e dependentes. incapacidade temporária ou permanente para o trabalho e idade avançada; proteção à maternidade, especialmente à","c":"gestante; proteção ao trabalhador em situação de desemprego involuntário; salário-família e auxílio-reclusão para os dependentes dos segurados de baixa renda, e pensão por morte do segurado, homem ou mulher, apenas ao cônjuge ou companheiro. capacidade temporária ou permanente para o trabalho e idade avançada, proteção à maternidade, especialmente à","d":"gestante; proteção ao trabalhador em situação de desemprego voluntário ou involuntário, salário-família e auxílio- reclusão para 05 dependentes dos segurados de baixa renda; e pensão por morte do segurado, homem ou mulher, ao cônjuge ou companheiro e dependentes. incapacidade temporária ou permanente para o trabalho e idade avançada; proteção à maternidade, especialmente à","e":"gestante, proteção ao trabalhador em situação de desemprego involuntário; salário-família e auxílio-reclusão para os dependentes dos segurados de qualquer renda, e pensão por morte do dependente, homem ou mulher, ao cônjuge ou companheiro e dependentes.","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564506","enunciado":"O benefício de prestação continuada, firmado pela Lei nº 8. 742/1993, é a garantia de um salário-mínimo mensal à pessoa","a":"com deficiência ou ao idoso com 55 anos ou mais que comprovem não possuir meios de prover a própria manutenção nem de tê-la provida por sua família.","b":"sem deficiência ou ao idoso com 55 anos que comprovem não possuir meios de prover a própria manutenção, mas de tê-la provida por sua família.","c":"sem deficiência e ao idoso com 65 anos ou mais que comprovem não possuir meios de prover a própria manutenção ou de tê-la provida por sua família.","d":"com deficiência e ao idoso com 65 anos ou mais que comprovem não possuir meios de prover a própria manutenção nem de tê-la provida por sua família.","e":"com deficiência e ao idoso com 65 anos ou menos que comprovem possuir meios de prover a própria manutenção ou de tê-la provida por sua família. Direito Tributário>Obrigação Tributária ,Fato Gerador ,Capacidade, Domicílio e Sujeitos da Obrigação Tributária","gabarito":"D","materia":"Direito Previdenciário","tema":"Benefícios em Espécie","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_160","enunciado":"Ano: 2024 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária De acordo com o Código Tributário Nacional (CTN), a verificação da ocorrência do fato gerador da obrigação correspondente, a determinação da matéria tributável, o cálculo do montante do tributo devido, a identificação do sujeito","a":"passivo e, sendo o caso, a proposição de aplicação da penalidade cabível, integram o procedimento denominado lançamento tributário.","b":"isenção tributária.","c":"fiscalização.","d":"execução fiscal.","e":"inscrição em divida ativa.","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564504","enunciado":"De acordo com a disciplina estabelecida na Constituição Federal de 1988 e no Código Tributário Nacional (CTN), hã uma relação estreita entre às institutos jurídicos do “tributo” e do “imposto”, de modo que tributo é espécie e imposto é gênero, sendo que imposto é toda prestação pecuniária compulsória, em moeda ou cujo valor","a":"nela se possa exprimir, que não constitua sanção de ato ilícito, instituída em lei e cobrada mediante atividade administrativa plenamente vinculada, como ocorre, por exemplo, com a instituição e cobrança da laxa de coleta de lixo.","b":"gênero e imposto é espécie, sendo que imposto é o tributo que tem como fato gerador o exercício regular do poder de polícia, ou a utilização, efetiva ou potencial, de serviço público específico e divisível, prestado ao contribuinte ou posto à sua disposição, como ocorre, por exemplo, com a cobrança do Imposto de Renda.","c":"espécie e imposto é gênero, sendo que imposto é toda prestação pecuniária compulsória, em moeda ou cujo valor nela se possa exprimir, que não constitua sanção de ato ilícito, instituída em lei e cobrada mediante atividade administrativa plenamente vinculada, como ocorre, por exemplo, com a instituição e cobrança do Imposto de Renda.","d":"gênero e imposto é espécie, sendo que imposto é o tributo cuja obrigação tem por fato gerador uma situação independente de qualquer atividade estatal específica, relativa ao contribuinte, como ocorre, por exemplo, com a instituição e cobrança da taxa de coleta de lixo.","e":"gênero e imposto é espécie, sendo que imposto é o tributo cuja obrigação tem por fato gerador uma situação independente de qualquer atividade estatal específica, relativa ao contribuinte, como ocorre, por exemplo, com a instituição e cobrança do Imposto de Renda. Direito Tributário>Competência Tributária ,Introdução e Características , Partilha e Tipologia (Repartição de Competência)","gabarito":"E","materia":"Direito Tributário","tema":"Conceito de Tributo e Espécies Tributárias ,Conceito legal de tributo ,Imposto","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_162","enunciado":"Tributos Federais ,IE ,IRPF e IRPJ ,Tributos Municipais ,IPTU ,ISSQN Ano: 2024 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária No Sistema Tributário Nacional brasileiro, a Constituição Federal de 1988 (CF) atribui a cada ente federativo competências específicas para criar e legislar sobre impostos. Portanto, a competência tributária para instituir impostos está dividida entre a União, os Estados, o Distrito Federal e os Municípios. Sobre a competência tributária, as limitações constitucionais ao poder de tributar e a imunidade tributária, a CF dispõe: I.É vedado à União, aos Estados, ao Distrito Federal e aos Municípios exigir ou instituir tributo sem lei que o estabeleça. II. O imposto de importação de produtos estrangeiros é de competência da União. III. É vedado à União, aos Estados, ao Distrito Federal e aos Municípios instituir impostos sobre o patrimônio, a renda ou os serviços, uns dos outros. IV. O imposto sobre","a":"a propriedade de veículos automotores é de competência da União. Está coreto o que consta APENAS de I, II e lII.","b":"III e IV.","c":"I e lIII.","d":"II e IV.","e":"I e lI. Direito Tributário>Obrigação Tributária ,Obrigação Principal e Acessória ,","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_163","enunciado":"Ano: 2024 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária De acordo com o artigo 121 do CTN, o sujeito passivo da obrigação principal é a pessoa obrigada ao pagamento de tributo ou penalidade pecuniária, podendo o sujeito passivo ser o contribuinte ou o responsável tributário. De acordo com o referido Código, o responsável tributário é aquele que:","a":"sem revestir a condição de contribuinte, tenha obrigação que decorra de disposição expressa de lei complementar, como ocorre, por exemplo, com a indústria, que é responsável pelo IPI (imposto sobre produtos industrializados) ao promover a saída de produtos industrializados.","b":"tem relação pessoal e direta com a situação que constitua o respectivo fato gerador, como, por exemplo, o produtor rural (proprietário de uma fazenda), que é responsável pelo imposto sobre propriedade territorial rural — ITR.","c":"tem relação pessoal e direta com a situação que constitua o respectivo fato gerador, como, por exemplo, o adquirente de um imóvel, que é pessoalmente responsável pelos tributos relativos ao bem adquirido que não tenham sido quitados.","d":"sem revestir a condição de contribuinte, tenha obrigação que decorra de disposição expressa de lei, como, por exemplo, o adquirente de um imóvel, que é pessoalmente responsável pelos tributos relativos ao bem adquirido que não tenham sido quitados.","e":"tem relação pessoal e direta com a situação que constitua o respectivo fato gerador, como, por exemplo, a pessoa jurídica em relação ao imposto de renda da pessoa jurídica. Direito Tributário>Suspensão do Crédito Tributário ,Extinção do Crédito Tributário ,","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564501","enunciado":"Ano: 2024 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária O Código Tributário Nacional (CTN) traz diversas regras sobre o crédito tributário e as hipóteses de suspensão, extinção e exclusão do crédito tributário, dispondo: I. O depósito do montante integral do crédito tributário é uma hipótese de suspensão do crédito tributário. II. A exclusão do crédito tributário dispensa o cumprimento das obrigações acessórias dependentes da obrigação principal, de modo que uma pessoa jurídica que realize a venda de uma mercadoria, com isenção do imposto, está dispensada da emissão de documento fiscal. III. O pagamento do tributo devido pelo contribuinte é uma das formas de extinção do crédito tributário. IV. O parcelamento do crédito tributário é concedido na forma e condição estabelecidas em lei específica. Está correto o que","a":"consta APENAS de I, II e lIII.","b":"III e IV.","c":"I, III e IV.","d":"II e IV.","e":"I e lI.","gabarito":"C","materia":"Exclusão do Crédito TributárioSuspensão do Crédito Tributário - Disposições Gerais","tema":"","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564499","enunciado":"Xisto e Benício, residentes na área territorial da Subseção Judiciária X, cometeram um crime de roubo na divisa entre as Subseções Judiciárias Y e Z, quando abordaram funcionário público federal em serviço, que reside na Subseção Judiciária A, e subtraíram, mediante grave ameaça, o veículo de propriedade da União, por ele conduzido. Xisto e Benício foram presos em flagrante na posse da res furtiva durante a fuga, quando já estavam na área territorial da Subseção Judiciária B. No caso","a":"hipotético apresentado, a competência para processar e julgar Xisto e Benício será do juízo da Subseção Judiciária A, local do domicílio da vítima.","b":"determinada pela prevenção, e poderá ser do juízo de qualquer das Subseções Judiciárias descritas no enunciado.","c":"determinada pela prevenção e poderá ser tanto do juízo federal da Subseção Judiciária Y quanto da Z.","d":"do juízo federal da Subseção Judiciária B, onde Xisto e Benício foram presos.","e":"do juízo da Subseção Judiciária X, local do domicílio dos réus.","gabarito":"C","materia":"Direito Processual Penal","tema":"Competência no Processo Penal ,Competência territorial","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564498","enunciado":"Rivaldo foi denunciado por determinado crime contra a ordem tributária, previsto na Lei nº 8.137/980. Ao ser citado, Rivaldo, por meio de seu advogado, apresenta exceção de suspeição do órgão do Ministério Público que atua na ação penal. Nesse caso, nos termos preconizados pelo Código de Processo Penal, o juiz, depois de ouvir o membro do Parquet, decidirá,","a":"podendo antes admitir a produção de provas, no prazo de 3 dias, não cabendo recurso contra esta decisão.","b":"5 dias, cabendo recurso inominado contra esta decisão.","c":"10 dias, cabendo agravo de instrumento contra esta decisão.","d":"10 dias, cabendo recurso em sentido estrito contra esta decisão.","e":"3 dias, cabendo correição parcial contra esta decisão.","gabarito":"A","materia":"Direito Processual Penal","tema":"Das Questões e Processos Incidentes","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564497","enunciado":"Considere as seguintes situações hipotéticas de pessoas que estão presas preventivamente: -Marilda, gestante, cometeu crime de roubo juntamente com outros três indivíduos e mediante emprego de arma de fogo. - Ricardo, único responsável pelos cuidados do seu filho Mateus, de 10 anos de idade, cometeu crime de estelionato. - Rodolfo, 75 anos de idade, cometeu crime de concussão. -Giselda, mãe de dois filhos (Renato de 13 anos e Gael de 14 anos) cometeu crime de “lavagem” de bens, previsto na Lei nº 9.613/1998. Nos termos preconizados pelo Código de Processo Penal, presentes 05 demais requisitos legais, o juiz poderá, em tese, substituir a prisão preventiva pela prisão domiciliar","a":"APENAS para: Marilda e Giselda.","b":"Marilda, Rodolfo e Giselda.","c":"Ricardo, Rodolfo e Giselda.","d":"Ricardo e Rodolfo.","e":"Ricardo. Direito Processual Penal>","gabarito":"E","materia":"Direito Processual Penal","tema":"Da Prisão e da Liberdade Provisória ,Da Prisão Preventiva ,Prisão domiciliar","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564496","enunciado":"Ano: 2024 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária Alice conduzia seu veiculo, em determinada rodovia federal, em velocidade superior à permitida, sendo parada em posto da polícia rodoviária federal e multada pelo agente federal que ali trabalhava. Neste momento, passou a ofendê-lo verbalmente em razão da função. Alice foi conduzida à repartição pública competente para lavratura de Termo Circunstanciado objetivando apuração de crime, em tese, de desacato. Os autos foram encaminhados ao Ministério Público Federal, após a colheita de todas as informações necessárias e, por não fazer jus a qualquer benefício, em razão de possuir péssimos antecedentes e ser reincidente, Alice é denunciada pelo Ministério Público Federal pelo crime do artigo 331, do Código Penal (desacato), seguindo-se o rito do procedimento sumarissimo previsto na Lei nº 9.099/1995 (art. 12 da Lei nº 10.259/2001). O Magistrado competente, em decisão fundamentada, rejeita a denúncia apresentada pelo Parquet. Nesse","a":"caso, inconformado, o Ministério Público Federal poderá interpor recurso inominado, no prazo de 5 dias.","b":"apelação, no prazo de 5 dias.","c":"apelação, no prazo de 10 dias.","d":"recurso em sentido estrito, no prazo de 5 dias.","e":"recurso em sentido estrito, no prazo de 10 dias.","gabarito":"C","materia":"Procedimento comum sumaríssimo - Lei nº 9.099 de 1995 - Lei dos Juizados Especiais Criminais - JECRIM","tema":"","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564495","enunciado":"Mauro é comerciante de produtos eletrônicos e reside em uma pequena cidade do Estado do Mato Grosso do Sul. Viajou para O Paraguai, na cidade de Pedro Juan Caballero, onde adquiriu um carregamento de produtos eletrônicos, avaliados em US$ 30.000 (trinta mil dólares americanos), para serem revendidos em sua loja. Mauro retorna ao Brasil com a carga pela via terrestre em um furgão. Logo após passar a fronteira entre os países, sem declarar as mercadorias adquiridas às autoridades aduaneiras e pagar os impostos necessários, ao ingressar em território brasileiro, na cidade de Ponta Porã, o veículo conduzido por Mauro é abordado pela polícia Rodoviária Federal. Mauro é preso em flagrante e cometeu, no caso","a":"hipotético acima, o crime de tráfico de influência.","b":"corrupção ativa.","c":"contrabando.","d":"estelionato.","e":"descaminho.","gabarito":"E","materia":"Direito Penal","tema":"Crimes contra a administração pública ,Descaminho","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564494","enunciado":"","a":"empresa “X, declarada inidônea, é admitida pelos funcionários públicos José, Mônica e Rubens, à licitação promovida pelo órgão federal em que lotados. Nesse caso, nos termos preconizados pelo Código Penal, José, Mônica e Rubens cometeram, em tese, o crime de","b":"A Modificação ou pagamento irregular em contrato administrativo — artigo 337-H, do Código Penal. Frustração do caráter competitivo de licitação — artigo 337-F, do Código Penal.","c":"Contratação inidônea — artigo 337-M, do Código Penal.","d":"Fraude em licitação ou contrato — artigo 337-L, do Código Penal.","e":"Afastamento de licitante — art. 337-K, do Código Penal.","gabarito":"C","materia":"Direito Penal","tema":"Crimes contra a administração pública ,Crimes em Licitações e Contratos Administrativos","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564493","enunciado":"Nos termos preconizados pela Lei nº 12.850/2013, que define organização criminosa e dispõe sobre a investigação criminal, 05 meios de prova, infrações penais correlatas e o procedimento criminal,","a":"a condenação com trânsito em julgado acarretará ao funcionário público a perda do cargo, função, emprego ou mandato eletivo e a interdição para o exercício de função ou cargo público pelo prazo de 4 anos subsequentes ao cumprimento da pena.","b":"a pena privativa de liberdade para aquele que integra pessoalmente organização criminosa é aumentada de 1/6 a 2/3 se há concurso de funcionário público, valendo-se a organização criminosa dessa condição para a prática de infração penal.","c":"a pena privativa de liberdade para aquele que financia pessoalmente organização criminosa é aumentada de 1/6 a 1/2 se o produto ou proveito da infração destinar-se, no todo ou em parte, ao exterior. considera-se organização criminosa a associação de, no mínimo, 3 ou mais pessoas estruturalmente ordenada e","d":"caracterizada pela divisão de tarefas, ainda que informalmente, com o objetivo de obter, direta ou indiretamente, vantagem de qualquer natureza, mediante a prática de infrações penais cujas penas máximas sejam superiores a 4 anos, ou que sejam de caráter transnacional.","e":"a pena privativa de liberdade para aquele que integra pessoalmente organização criminosa aumenta-se até 1/3 se na atuação da organização criminosa houver emprego de arma de fogo.","gabarito":"B","materia":"Direito Processual Penal","tema":"Lei de Organização Criminosa – Lei nº 12.850 de 2013","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564492","enunciado":"Ronaldo, funcionário público, cometeu crime de prevaricação em 12 de abril de 2018. Após o trâmite do Inquérito policial, Ronaldo foi denunciado pelo Ministério Público pelo crime do artigo 319, do Código Penal (prevaricação). A denúncia foi recebida em 19 de maio de 2021. Após a regular instrução do feito, Ronaldo é condenado pelo Magistrado competente ao cumprimento da pena privativa de liberdade de 6 meses de detenção, em regime inicial semiaberto, por sentença publicada no dia 2 de maio de 2023. Na data da sentença, Ronaldo, reincidente em crime doloso, possuía 71 anos de idade. Após o trânsito em julgado da sentença, Ronaldo, por meio de seu advogado, apresenta requerimento de extinção da punibilidade com base na prescrição diante da pena em concreto imposta. Sobre o caso hipotético apresentado, o prazo da prescrição da pretensão punitiva estatal é de:","a":"3 anos, mas o Magistrado não deverá extinguir a punibilidade de Ronaldo, pois o termo inicial da prescrição com base","b":"na pena aplicada não pode ter por termo inicial data anterior à da denúncia. 2 anos, e não restou consumado, devendo o feito prosseguir na fase executória.","c":"4 anos, e não restou consumado, devendo o feito prosseguir na fase executória.","d":"3 anos, cabendo ao Magistrado extinguir a punibilidade de Ronaldo com base na prescrição, que se consumou no lapso temporal transcorrido entre a data do crime e a do recebimento da denúncia.","e":"1 ano e 6 meses, cabendo ao Magistrado extinguir a punibilidade de Ronaldo com base na prescrição, que se consumou no lapso temporal transcorrido entre a data do recebimento da denúncia e da publicação da sentença. Legislação Federal>","gabarito":"E","materia":"Direito Penal","tema":"Causas de extinção da punibilidade ,Prescrição. Conceito e modalidades","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_173","enunciado":"Ano: 2024 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária Determinada empresa celebrou com o Poder Público Federal um contrato de parceria na área aeroportuária, sendo que circunstâncias supervenientes à celebração contratual prejudicaram sua capacidade de adimplir suas obrigações contratuais. Diante de tal situação e nos termos da legislação vigente, a empresa poderá","a":"solicitar que seja o contrato qualificado para fins de relicitação, situação em que a empresa renunciará à participação no novo certame ou no futuro contrato de parceria relicitado.","b":"requerer a transferência do contrato a outro prestador, devendo ser a escolha deste realizada por meio de concorrência.","c":"realizar autodeclaração de caducidade do contrato, o que a isentará da aplicação de sanções administrativas, desde que mantenha condições mínimas de continuidade da prestação contratual.","d":"promover a subconcessão do contrato, indicando à agência reguladora uma empresa de sua escolha para assumir a concessão, nos mesmos termos previstos no contrato original.","e":"promover a transferência de seu controle societário, o que independe de anuência do poder concedente, por se tratar de ato interna corporis.","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564490","enunciado":"No que se refere à acumulação de posições remuneradas (cargos, empregos ou funções), conforme entendimento jurisprudencial dominante, o regime constitucional dos servidores públicos vigente","a":"autoriza que o servidor inativo acumule seus proventos com outras duas posições em atividade, desde que haja compatibilidade de horários em relação a estas.","b":"caracteriza como acumulação a participação de servidores públicos em conselhos de administração e fiscal de","c":"empresas estatais. exige que sejam somadas as respectivas remunerações, para fins de aplicação do teto constitucional.","d":"garante a transferência de vantagens obtidas em um cargo, para o outro cargo, por força da regra do direito adquirido.","e":"permite a acumulação independentemente de limite infraconstitucional de jornada semanal, exigida apenas a compatibilidade de horários.","gabarito":"E","materia":"Direito Constitucional","tema":"Administração Pública – Disposições Gerais e Servidores Públicos ,Servidores Públicos","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564489","enunciado":"Considere o seguinte julgado do Supremo Tribunal Federal: Mandado de Segurança. Tribunal de Contas da União. Tomada de Contas Especial. Desconsideração da Personalidade Jurídica. Possibilidade. Requisitos Legais Observados. Ausência de Direito Liquido e Certo. Denegação da Segurança. 1. Ao TCU é assegurado plexo de poderes e mecanismos cautelares voltados à garantia da eficácia de eventuais provimentos definitivos que imponham sanções a agentes públicos ou particulares responsáveis por irregularidades no trato de recursos públicos. 2. O levantamento do véu da pessoa jurídica, embora grave do ponto de vista da segurança jurídica e da liberdade econômica, não se afeiçoa àquele estrito rol de direitos fundamentais cuja restrição apenas pode ser operacionalizada pelo Poder Judiciário. E equivocado equiparar, para fins de proteção judicial, o conteúdo de comunicações telefônicas de cidadãos à desconsideração, em situações pontuais e fundamentadas, da pessoa jurídica. Não há, nessa hipótese, supressão ou malferimento de qualquer direito fundamental, seja do sócio pessoa física, seja da empresa pessoa jurídica. 3.É legal e constitucionalmente fundada a desconsideração da pessoa jurídica pelo TCU, de modo a alcançar o patrimônio de pessoas físicas ou jurídicas envolvidas na","a":"prática de atos lesivos ao erário público, observados o contraditório e a ampla defesa. 4. Segurança denegada. jurisprudência do Supremo Tribunal Federal que reconhece às Cortes de Contas a possibilidade de impor medidas acautelatórias, ainda que não previstas expressamente na lei, é baseada na chamada teoria","b":"A da dupla imputação. da puissance publique.","c":"da responsabilidade ampliada por alcance.","d":"da encampação dos poderes.","e":"dos poderes implícitos.","gabarito":"E","materia":"Controle Externo","tema":"Jurisprudência do Supremo Tribunal Federal - STF","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564488","enunciado":"","a":"Resolução CNJ nº 325/2020 que dispõe sobre a Estratégia Nacional do Poder Judiciário 2021-2026 e dá outras providências, estabelece: A Estratégia do Judiciário é executada de forma colaborativa e participativa sob a coordenação do Departamento de A Gestão Estratégica (DGE) do CNJ.","b":"Os órgãos do Poder Judiciário realizarão Reuniões de Análise da Estratégia (RAE), pelo menos trimestralmente, para avaliação e acompanhamento dos resultados, buscando possíveis subsídios para o aprimoramento do desempenho institucional.","c":"Metas Nacionais do Poder Judiciário são compromissos, realizados anualmente, dos órgãos do Poder Judiciário para alcance de objetivos comuns ao segmento de justiça ou ao Tribunal Superior, que deverão monitorá-los e comunicá- los ao CNJ.","d":"Os órgãos do Poder Judiciário devem manter unidade de gestão estratégica para assessorar a elaboração, a implementação e o monitoramento do planejamento estratégico.","e":"É obrigatória a instituição de plano estratégico de segmento de justiça, que deve estar alinhado à Estratégia Nacional do Poder Judiciário 2021-2026.","gabarito":"D","materia":"Legislação dos TRFs","tema":"Conselho Nacional de Justiça (CNJ) ,Resoluções do CNJ","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564486","enunciado":"Com relação à Justiça Federal, na hipótese de autorização, por lei, de processamento e julgamento, pela Justiça Estadual, de causa de competência","a":"da Justiça Federal em que forem parte instituição de previdência social e segurado, quando a comarca do domicílio do segurado não for sede de vara federal, o recurso cabível será sempre para o Tribunal Regional Federal na área de jurisdição do juiz de primeiro grau. na hipótese de grave violação de direitos humanos, o Procurador-Geral da República, com a finalidade de assegurar o","b":"cumprimento de obrigações decorrentes de tratados internacionais de direitos humanos dos quais o Brasil seja parte, poderá suscitar, perante qualquer Tribunal Superior, apenas durante a fase de inquérito, incidente de deslocamento de competência para a Justiça Federal.","c":"aos juízes federais compete processar e julgar a execução de carta rogatória, após o exequátur, a homologação de sentença estrangeira, assim como a execução de sentença estrangeira após a homologação, as causas referentes à nacionalidade, inclusive a respectiva opção, e à naturalização.","d":"aos juízes federais compete processar e julgar os crimes políticos e as infrações penais praticadas em detrimento de bens, serviços ou interesse da União ou de suas entidades autárquicas ou empresas públicas, incluídas as contravenções e ressalvada a competência da Justiça Militar e da Justiça Eleitoral.","e":"os Tribunais Regionais Federais compõem-se de, no mínimo, onze juízes, sendo um quinto dentre advogados com mais de dez anos de efetiva atividade profissional e membros do Ministério Público Federal ou Estadual com mais de dez anos de carreira.","gabarito":"A","materia":"Direito Constitucional","tema":"Tribunais Regionais Federais e Juízes Federais ,Organização do Poder Judiciário","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564485","enunciado":"Suponha que o Presidente da República tenha praticado crime de responsabilidade e que um Ministro de Estado tenha praticado crime, da mesma natureza, conexo com esse praticado pelo Presidente da República. Considerando apenas as informações fornecidas, nesse caso hipotético, a competência privativa para processar e julgar o Presidente da República","a":"e o Ministro de Estado é do Supremo Tribunal Federal, ao qual compete, também, processar e julgar privativamente os Ministros de Estado nas infrações penais comuns.","b":"e o Ministro de Estado é do Senado Federal, ao qual compete, também, processar e julgar privativamente os Ministros de Estado nas infrações penais comuns.","c":"e o Ministro de Estado é do Senado Federal, ao qual compete, também, processar e julgar privativamente os membros do Conselho Nacional do Ministério Público nos crimes de responsabilidade.","d":"é do Senado Federal e a competência para processar e julgar privativamente o Ministro de Estado é do Supremo Tribunal Federal.","e":"é do Supremo Tribunal Federal e a competência para processar e julgar privativamente o Ministro de Estado é do Senado Federal.","gabarito":"C","materia":"Direito Constitucional","tema":"Poder Legislativo ,Senado Federal","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564484","enunciado":"Roberval é um diplomata brasileiro que se casou com Anésia. Algum tempo após sua união, Roberval foi trabalhar na Alemanha, a serviço da República Federativa do Brasil, e lã passou a residir com sua esposa, onde, alguns meses depois, nasceu seu filho, Niveo. Embora tenha crescido na Alemanha, Niveo pretende seguir os passos de seu pai e representar o pais de origem de Roberval. Para isso, quando atingir a maioridade, Niveo quer estudar no Brasil e aqui ter um cargo da","a":"carreira diplomática. Considerando apenas os dados fornecidos nessa situação hipotética, isso não é possível, pois Níveo é considerado brasileiro naturalizado e o cargo que pretende é privativo de brasileiro nato.","b":"é possível, pois se trata de cargo que pode ser ocupado por pessoas de qualquer nacionalidade, desde que residentes","c":"no país há mais de dez anos ininterruptos. não é possível, pois Níveo não é brasileiro e o cargo que pretende é privativo de brasileiro nato ou naturalizado.","d":"é possível, desde que Níveo se naturalize brasileiro, pois o cargo que pretende é privativo de brasileiro nato ou","e":"naturalizado. é possível, pois Níveo é brasileiro nato e o cargo que pretende é privativo de brasileiro nato.","gabarito":"E","materia":"Direito Constitucional","tema":"Direitos da Nacionalidade","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564483","enunciado":"","a":"Compete ao Supremo Tribunal Federal processar e julgar, originariamente, a ação em que a metade de todos os membros da magistratura sejam diretamente interessados e o crime político.","b":"as ações contra o Conselho Nacional de Justiça, ao qual compete zelar pela autonomia do Poder Judiciário, não sendo permitido, a esse Conselho, expedir atos regulamentares, ainda que no âmbito de sua competência.","c":"o habeas corpus, sendo paciente Ministro de Estado e a ação direta de inconstitucionalidade de lei ou ato normativo federal ou estadual.","d":"a ação declaratória de constitucionalidade de lei ou ato normativo federal ou estadual e o mandado de segurança contra ato de Ministro de Estado.","e":"a ação direta de inconstitucionalidade de lei ou ação declaratória de constitucionalidade de lei ou ato normativo federal ou estadual proposta pelos legitimados previstos na Constiluição Federal, dentre os quais o Prefeito.","gabarito":"C","materia":"Direito Constitucional","tema":"Supremo Tribunal Federal ,Organização do Poder Judiciário","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564482","enunciado":"Florêncio, advogado, tem, dentre seus clientes, Florisbal, ex-Prefeito do Município “X\" e atual industrial que, estando com todas as condições de elegibilidade atendidas, deseja se candidatar, nas próximas eleições, a Vereador do mesmo Município. Ocorre que, Florisbal procurou Florêncio com a finalidade de propor ação judicial contra Dito, atual Prefeito do Município “X\", visando anular ato lesivo ao meio ambiente, dizendo que tem como comprovar que Dito praticou referido ato. Florêncio, então, esclarece, dentre outros fatos, que Florisbal","a":"poderá propor ação popular ou ação civil pública, não havendo, em ambos os casos, isenção de custas judiciais e do ônus da sucumbência, ainda que esteja de boa-fé.","b":"poderá propor ação popular, ação civil pública ou mandado de segurança, ficando, em todos os casos, isento de custas judiciais e do ônus da sucumbência, independentemente de boa-fé.","c":"poderá propor ação civil pública, pois, como candidato a cargo político, é o único legitimado para a propositura dessa","d":"ação. poderá propor ação popular, ficando, salvo comprovada má-fé, isento de custas judiciais e do ônus da sucumbência.","e":"não poderá propor ação popular, pois a legitimidade para a propositura dessa ação é exclusiva do Ministério Público.","gabarito":"D","materia":"Direito Constitucional","tema":"Direitos Individuais - Remédios Constitucionais e Garantias Processuais ,Ação Popular","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564481","enunciado":"Tícia exerce seu segundo mandato consecutivo como Governadora do Estado “X\" e seu marido, Irineu, brasileiro, 60 anos de idade, vendedor, analfabeto, deseja se candidatar ao cargo de Prefeito em determinado Município do referido Estado nas eleições que acontecerão ainda durante o exercício do mandato de sua esposa como Governadora. Diante dessa situação","a":"hipotética, considerando apenas 05 dados fornecidos, Irineu poderá se candidatar ao cargo que pretende, sendo, para ele, obrigatório o alistamento eleitoral e o voto.","b":"não poderá se candidatar ao cargo que pretende por ser inelegível, sendo, para ele, facultativo o alistamento eleitoral e o voto.","c":"não poderá se candidatar ao cargo que pretende, pois é inelegível, no território de jurisdição do titular, o cônjuge de Governador, podendo, porém, candidatar-se ao cargo de Prefeito de Município de outro Estado.","d":"não poderá se candidatar ao cargo que pretende por ser inelegível, sendo, para ele, obrigatório o alistamento eleitoral","e":"e o voto. poderá se candidatar ao cargo que pretende, sendo, para ele, facultativo o alistamento eleitoral e o voto. Direito Processual Civil - Novo Código de Processo Civil - CPC 2015>Sujeitos da Relação Processual ,","gabarito":"B","materia":"Direito Constitucional","tema":"Direitos Políticos","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_183","enunciado":"Ano: 2024 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária José, ex-funcionário público federal, ajuizou ação de cobrança contra a União pleiteando o pagamento de verbas adicionais que reputava devidas em razão do exercício do cargo público. Ainda na fase de conhecimento, José faleceu e o processo foi suspenso. Em seguida, ele foi substituído no processo por seu único filho e sucessor, menor e incapaz, representado pela mãe. Nesse caso, de acordo com o Código de Processo Civil, a intervenção do Ministério Público é obrigatória","a":"em razão da substituição de José pelo seu filho, neste caso, ressalvadas as hipóteses de prazo próprio para o Ministério Público, este goza da prerrogativa de prazo em dobro para manifestar-se nos autos, inclusive se eles tramitarem em meio eletrônico.","b":"em razão da substituição de José pelo seu filho; neste caso, ressalvadas as hipóteses de prazo próprio para o Ministério Público, este goza da prerrogativa de prazo em dobro para manifestar-se nos autos, exceto se eles tramitarem em meio eletrônico.","c":"desde o início do processo pelo só fato de a União integrar o polo passivo, neste caso, o Ministério Público não goza da prerrogativa de prazo em dobro para manifestar-se nos autos.","d":"desde o início do processo pelo só fato de a União integrar o polo passivo; neste caso, ressalvadas as hipóteses de prazo próprio para o Ministério Público, este goza da prerrogativa de prazo em dobro para manifestar-se nos autos, exceto se eles tramitarem em meio eletrônico.","e":"em razão da substituição de José pelo seu filho, neste caso, o Ministério Público não goza da prerrogativa de prazo em dobro para manifestar-se nos autos. Direito Processual Civil - Novo Código de Processo Civil - CPC 2015>Intervenção de Terceiro ,","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_184","enunciado":"Ano: 2024 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária Em ação de cobrança segundo à procedimento comum movida contra a sociedade XPTO Comércio Ltda., o autor requereu, depois de concluída a instrução, mas antes da sentença, a instauração de incidente de desconsideração da personalidade","a":"jurídica do réu. Nesse caso, de acordo com o Código de Processo Civil, o juiz deverá suspender o processo até a decisão do incidente.","b":"sobrestar a apreciação do incidente para depois da sentença, admitindo o seu ulterior processamento","c":"independentemente do acolhimento ou rejeição do pedido de cobrança. indeferir liminarmente o processamento do incidente, em razão da preclusão.","d":"indeferir liminarmente o processamento do incidente, porque incabível na fase de conhecimento.","e":"sobrestar a apreciação do incidente para depois da sentença, admitindo o seu ulterior processamento apenas se o pedido de cobrança for acolhido ao menos em parte.","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564478","enunciado":"","a":"No tocante à intervenção de terceiros, o Código de Processo Civil estabelece que a denunciação da lide e o chamamento ao processo só podem ser requeridos pelo réu.","b":"e o chamamento ao processo podem ser requeridos por qualquer das partes.","c":"só pode ser promovida pelo réu, ao passo que o chamamento ao processo só pode ser requerido pelo autor.","d":"pode ser promovida por qualquer das partes, ao passo que o chamamento ao processo só pode ser requerido pelo réu.","e":"só pode ser promovida pelo réu, ao passo que o chamamento ao processo pode ser requerido por qualquer das partes.","gabarito":"D","materia":"Direito Processual Civil - Novo Código de Processo Civil - CPC 2015","tema":"Intervenção de Terceiro ,Denunciação da Lide","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564477","enunciado":"","a":"De acordo com o Código de Processo Civil, a tutela de evidência não pode ser deferida liminarmente.","b":"não pode ter por objeto a obrigação de fazer.","c":"pode ser concedida sem prévia oitiva da parte contra quem ela se dirige.","d":"não pode ser concedida em ação que versar sobre direito indisponível.","e":"só pode ser concedida se houver perigo de dano grave e irreparável. Direito Processual Civil - Novo Código de Processo Civil - CPC 2015>Improcedência Liminar do Pedido ,","gabarito":"C","materia":"Direito Processual Civil - Novo Código de Processo Civil - CPC 2015","tema":"Tutela Provisória ,Tutela de Evidência","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_187","enunciado":"Ano: 2024 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","a":"De acordo com o Código de Processo Civil, o juiz julgará liminarmente improcedente o pedido que tiver sido formulado por parte legitima, ou quando constatar a manifesta ausência de interesse de agir.","b":"contrariar entendimento firmado em incidente de assunção de competência, porém somente nas causas que dispensem a fase instrutória.","c":"contrariar enunciado de súmula do Supremo Tribunal Federal ou do Superior Tribunal de Justiça, ainda que a causa exija a fase instrutória.","d":"estiver amparado em fatos cuja demonstração reputar impossível ou consideravelmente improvável, à vista das regras de experiência comum subministradas pela observação do que ordinariamente acontece.","e":"contrariar sentença por ele proferida em casos análogos, desde que a demanda verse exclusivamente sobre matéria de direito.","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564475","enunciado":"","a":"De acordo com o Código Civil, o mandato presume-se oneroso sempre que as partes não estipularem retribuição.","b":"outorgado por instrumento público não pode ser substabelecido por instrumento particular, mas o contrário é","c":"permitido. não poderá ser aceito tacitamente, exceto para evitar ao mandante dano grave.","d":"pode ser verbal, exceto quando o ato deva ser celebrado por escrito.","e":"em termos gerais não confere poderes de administração, que dependem de previsão expressa.","gabarito":"D","materia":"Direito Civil","tema":"Contratos em Espécie ,Depósito, Mandato, Comissão, Agência e Distribuição","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564474","enunciado":"Um banco concedeu à empresa AJM Ltda. um empréstimo de R$ 10.000,00 a juros de 2% ao mês, para utilização como capital de giro. No contrato, formalizado por instrumento particular, a empresa se comprometeu a devolver integralmente o capital emprestado acrescido dos juros. Nesse mesmo instrumento contratual, Beatriz figurou como fiadora da empresa. Contudo, a empresa deixou de honrar a dívida. Nesse caso, de acordo com o Código Civil, a pretensão do banco de cobrar a","a":"dívida prescreve em 5 anos, e a interrupção da prescrição contra a empresa não prejudica Beatriz.","b":"10 anos, e a interrupção da prescrição contra a empresa não prejudica Beatriz.","c":"3 anos, e a interrupção da prescrição contra a empresa prejudica Beatriz.","d":"3 anos, e a interrupção da prescrição contra a empresa não prejudica Beatriz.","e":"5 anos, e a interrupção da prescrição contra a empresa prejudica Beatriz.","gabarito":"E","materia":"Direito Civil","tema":"Prescrição e Decadência ,Parte Geral","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564473","enunciado":"","a":"De acordo com as disposições do Código Civil acerca do contrato de empreitada, o contrato para elaboração de um projeto importa a obrigação de executá-lo, mas não de fiscalizar a sua execução, mesmo que esta seja cometida a terceiro.","b":"importa a obrigação de fiscalizar a sua execução, mas não de executá-lo.","c":"não importa a obrigação de executá-lo nem de fiscalizar a sua execução.","d":"importa a obrigação de executá-lo e de fiscalizar a sua execução por qualquer pessoa que para ela concorra.","e":"importa a obrigação de executá-lo ou de fiscalizar a sua execução, se esta tiver sido cometida a terceiro.","gabarito":"C","materia":"Direito Civil","tema":"Contratos em Espécie ,Prestação de Serviços e Empreitada","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564472","enunciado":"Um banco concedeu empréstimos de mais de R$ 200 milhões à sociedade ABC Indústria Ltda. para financiar a ampliação das suas instalações. Dois terços das quotas dessa sociedade pertenciam às sociedades DEF Indústria Ltda, e GHI Indústria Ltda., ao passo que o terço restante pertencia a João da Silva, que, por sua vez, era titular de todas as quotas dessas outras duas sociedades. Como a mutuária não honrou o empréstimo, o banco ajuizou contra ela uma execução. Posteriormente, o banco requereu a desconsideração da personalidade jurídica de ABC Indústria Ltda., para que os bens dos seus sócios (ou seja, DEF Indústria Ltda, GHI Indústria Ltda. e João da Silva) pudessem ser alcançados pela execução, sob o fundamento exclusivo de todos eles integrarem um mesmo grupo econômico. Nesse caso, de acordo com o Código Civil, a mera existência de grupo econômico.","a":"autoriza a desconsideração da personalidade jurídica, para que sejam alcançados os bens das sociedades DEF Indústria Ltda. e GHI Indústria Ltda., mas não de João da Silva.","b":"não autoriza a desconsideração da personalidade jurídica da sociedade ABC Indústria Ltda. em relação a nenhum dos seus sócios.","c":"autoriza a desconsideração da personalidade jurídica, para que sejam alcançados 05 bens das sociedades DEF Indústria Lida. e GHI Indústria Ltda., bem como de João da Silva, desde que ele também seja administrador de qualquer uma das sociedades.","d":"autoriza a desconsideração da personalidade jurídica, para que sejam alcançados os bens das sociedades DEF Indústria Ltda. e GHI Indústria Ltda., bem como de João da Silva, desde que ele também seja administrador de todas as sociedades.","e":"autoriza a desconsideração da personalidade jurídica, para que sejam alcançados os bens das sociedades DEF Indústria Ltda. e GHI Indústria Ltda., bem como de João da Silva, independentemente de ele ser ou não administrador de quaisquer das sociedades. Estatuto da Pessoa com Deficiência - Lei nº 13.146 de 2015>Legislação das Pessoas com Deficiência ,","gabarito":"B","materia":"Direito Civil","tema":"Pessoa Jurídica ,Parte Geral","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_192","enunciado":"Ano: 2024 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária Imagine a seguinte situação hipotética: A empresa ABC, concessionária de serviço público de transporte coletivo, deixou de reservar assentos, devidamente identificados, às pessoas com deficiência, razão pela qual seus responsáveis foram","a":"penalizados com multa. Nos termos da Lei nº 10.048/2000, a multa para a hipótese mencionada é de R$ 500,00 a R$ 3.000,00, por veículos sem as condições narradas no enunciado, e será elevada ao dobro em caso de reincidência.","b":"R$ 2.500,00, por veículos sem as condições narradas no enunciado, e será elevada ao triplo em caso de reincidência.","c":"R$ 2.500,00, por veículos sem as condições narradas nó enunciado, e será elevada ao dobro em caso de reincidência.","d":"R$ 1.000,00, por veículos sem as condições narradas no enunciado, e será elevada ao triplo em caso de reincidência.","e":"R$ 2.000,00 por veículos sem as condições narradas no enunciado, não podendo ser majorada ainda que houver reincidência. Estatuto da Pessoa com Deficiência - Lei nº 13.146 de 2015>Legislação das Pessoas com Deficiência ,","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_193","enunciado":"Ano: 2024 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária Considere a seguinte situação hipotética: Hermes é o profissional de saúde responsável pelo tratamento de Afrodite, pessoa com deficiência, que está internada no Hospital XYZ. Segundo a Lei nº 13.146/2015, na impossibilidade de permanência do acompanhante ou do atendente pessoal junto a Afrodite,","a":"caberá ao dono do Hospital XYZ, que não precisa necessariamente ser profissional de saúde, justificar essa impossibilidade, desde que o faça por escrito.","b":"será necessária justificativa conjunta do Hospital XYZ e de Hermes sobre tal impossibilidade, podendo adotar, para tanto, a forma oral ou escrita.","c":"não haverá consequência nem será necessário tomar providências, haja vista que, em regra, a pessoa com deficiência, quando internada, não possui direito a acompanhante ou a atendente pessoal.","d":"não constitui competência do Hospital XYZ adotar providências cabíveis para suprir a ausência do acompanhante ou","e":"do atendente pessoal. caberá a Hermes justificar essa impossibilidade, assim o fazendo por escrito.","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564467","enunciado":"Nos termos da Resolução nº 401/2021, do Conselho Nacional de Justiça, a Implementação de medidas que visem à","a":"promoção da acessibilidade e inclusão tem como premissas a adoção do desenho universal e da adaptação razoável, ambos quando justificáveis.","b":"da adaptação razoável, como regra geral, e das barreiras atitudinais, quando justificáveis.","c":"do desenho universal e da adaptação razoável, ambos como regra geral.","d":"do desenho universal, como regra geral, e da adaptação razoável, quando justificável.","e":"da adaptação razoável, como regra geral, e do desenho universal, quando justificável.","gabarito":"D","materia":"Legislação dos TRFs","tema":"Conselho Nacional de Justiça (CNJ) ,Resoluções do CNJ","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564466","enunciado":"De acordo com a Resolução n° 401/2021, do Conselho Nacional de Justiça, considere: I. Possui caráter permanente e multidisciplinar, será presidida por magistrado(a) e composta, necessariamente, por servidores(as) das áreas de acessibilidade e Inclusão, sustentabilidade, gestão estratégica, engenharia ou arquitetura, gestão de pessoas e tecnologia da informação. II. Tem por competência, dentre outras, propor à Presidência do órgão a edição ou alteração de normas e orientações que disponham, parcial ou integralmente, sobre matéria da área de atuação da Comissão. III. Deverá ser composta apenas por integrantes com deficiência, e conter, obrigatoriamente, a representação das múltiplas formas de deficiências existentes. IV. Tem por competência, dentre outras, aprovar apenas relatório mensal e semestral de atuação da Comissão, acerca da promoção da acessibilidade e inclusão no órgão. No que concerne às","a":"características e competências da Comissão de Acessibilidade e Inclusão, está correto o que consta APENAS de I, III e IV.","b":"I e II.","c":"Il e III.","d":"I e IV.","e":"II, III e IV.","gabarito":"B","materia":"Legislação dos TRFs","tema":"Conselho Nacional de Justiça (CNJ) ,Resoluções do CNJ","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564465","enunciado":"Em uma cozinha industrial a produção de marmitas é etiquetada com o dia e mês de fabricação (DDMM) além do tipo de proteína, sendo 1 para carne, 2 para frango, 3 para peixe e 4 para ovo. Sabendo-se que no último mês de dezembro foram produzidas 100 marmitas por dia, sendo 10 com ovo e 30 com cada um dos outros tipos de proteína, o número de","a":"algarismos 4 que foram utilizados para numerar as marmitas naquele mês foi 610.","b":"210.","c":"310.","d":"410.","e":"510.","gabarito":"A","materia":"Raciocínio Lógico","tema":"Problemas Lógicos","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564464","enunciado":"O dia e mês de nascimento de uma pessoa podem ser representados por uma sequência de quatro dígitos: DdMm. Por exemplo, para quem nasce em oito de outubro temos D=0, d=8, M=1 e m=0 Se para uma dada pessoa temos que D+d+M+m","a":"= 19, essa pessoa nasceu em maio ou setembro.","b":"setembro ou dezembro.","c":"julho ou agosto.","d":"junho ou julho.","e":"agosto ou setembro.","gabarito":"E","materia":"Raciocínio Lógico","tema":"Problemas Lógicos","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564463","enunciado":"Uma fábrica de automóveis de luxo produziu 22 carros em 3 semanas. À cada semana foram fabricados mais automóveis do que na semana anterior, e na terceira semana foram fabricados menos automóveis do que haviam sido fabricados, ao todo, nas duas primeiras semanas. Nessas condições, o número máximo de automóveis que podem ter sido fabricados na","a":"segunda semana é: 7.","b":"11.","c":"9.","d":"8.","e":"10.","gabarito":"C","materia":"Raciocínio Lógico","tema":"Raciocínio Matemático","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564462","enunciado":"Em uma eleição para presidente de um clube, havia quatro candidatos, A, B, C e D, e 600 eleitores. Cada eleitor votou em um, e apenas um, dos candidatos. Do total de eleitores, 40% eram mulheres e os demais, homens. O candidato A recebeu 35% dos votos dos eleitores homens e o candidato B recebeu metade dos votos dos eleitores homens. Os candidatos C e D receberam o mesmo número de votos dos eleitores homens. O candidato A recebeu 20% dos votos das eleitoras mulheres. Entre as eleitoras mulheres, o candidato B obteve 8 votos a mais do que o candidato C e 10 votos a mais do que o candidato","a":"D. Nessa eleição, a soma dos votos recebidos pelos candidatos B e D foi 263.","b":"129.","c":"268.","d":"337.","e":"406.","gabarito":"D","materia":"Raciocínio Lógico","tema":"Diagramas de Venn (Conjuntos)","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564461","enunciado":"Artur, Bruno, Carlos e Daniel são eletricista, pintor, professor e guitarrista, não necessariamente nessa ordem. Sabe-se que: 1. Artur é amigo do guitarrista. 2. Carlos é vizinho do eletricista. 3. O pintor é primo de Carlos. 4. O eletricista é mais alto do","a":"que Artur. 5. Carlos e Daniel não tocam nenhum instrumento musical. Com base nas informações fornecidas, Artur é eletricista.","b":"Bruno é guitarrista.","c":"Artur é professor.","d":"Bruno é eletricista.","e":"Carlos é eletricista.","gabarito":"B","materia":"Raciocínio Lógico","tema":"Relacionamentos e Associações","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564460","enunciado":"Valor social da memória Não há evocação, não há memória sem uma inteligência do presente, um homem não sabe o que ele é se não for capaz de sair das determinações atuais. Aturada reflexão pode preceder e acompanhar a evocação. Uma lembrança é um diamante bruto que precisa ser lapidado pelo espírito: sem o trabalho da reflexão e da localização, seria uma imagem fugidia. O sentimento também precisa acompanhá-la, para que ela não seja uma repetição do estado antigo, mas uma reaparição. Se existe uma memória voltada para a ação, com sua prática de hábitos assimilados, e uma outra memória que simplesmente revive o passado, parece ser esta a dos velhos, já libertos das atividades profissionais e familiares. Mas o ancião não sonha quando rememora: desempenha uma função para a qual está maduro, a alta função de unir o começo ao fim, de divisar os limites de uma história inteira. Um mundo social que possui uma riqueza e uma diversidade que não conhecemos pode chegar- nos pela memória dos velhos. Momentos desse mundo perdido podem ser compreendidos por quem não os viveu. À conversa evocativa de um velho é sempre uma experiência profunda: para quem sabe ouvi-la, cria um nexo entre o passado e o presente, é instigante e inspiradora. (Adaptado de: BOSI, Ecléa. Memória a sociedade = Lembranças de velhos. 20.ed. São Paulo: Companhia das Letras, p. 84)","a":"Está correta a seguinte afirmação sobre um elemento de construção do texto: na expressão já libertos das atividades (2º parágrafo), das tem o valor de pelas.","b":"na expressão para a qual está maduro (2º parágrafo), o referente de a qual é uma história.","c":"a forma verbal ser lapidado (1º parágrafo) constitui um caso de voz ativa.","d":"a expressão um diamante bruto (1º parágrafo) é exemplo de linguagem figurada.","e":"opcional o uso da virgula colocada imediatamente após a palavra fim (2º parágrafo).","gabarito":"D","materia":"Português","tema":"Interpretação de Textos ,Figuras de Linguagem","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564459","enunciado":"","a":"Considerando-se o contexto, deve-se entender que a expressão divisar os limites de uma história (2º parágrafo) aponta para a relevância social da memória dos velhos.","b":"para quem sabe ouvi-la (2º parágrafo) personaliza um receptor de atenção descurada.","c":"inteligência do presente (1º parágrafo) refere-se à racionalidade de quem se aliena do que já passou.","d":"diamante bruto (1º parágrafo) é utilizada para acentuar o desprestígio de que sofre a memória dos velhos.","e":"prática de hábitos assimilados (2º parágrafo) acentua a capacidade máxima de criação que tem a memória.","gabarito":"A","materia":"Português","tema":"Interpretação de Textos ,Noções Gerais de Compreensão e Interpretação de Texto","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564458","enunciado":"","a":"O valor da memória dos velhos está, sobretudo, no árduo trabalho das fantasias que descrevem a totalidade de uma vida.","b":"na capacidade que têm os velhos de registrar detalhes avulsos de uma história perdida.","c":"na capacidade que têm de articular experiências já vividas às questões abertas no presente.","d":"na repercussão subjetiva que 0 passado adquire quando fielmente reconstituído.","e":"no estímulo das poderosas imagens passadas que relativizam a importância do presente.","gabarito":"C","materia":"Português","tema":"Interpretação de Textos ,Noções Gerais de Compreensão e Interpretação de Texto","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564457","enunciado":"","a":"Momentos desse mundo perdido podem ser compreendidos por quem não os viveu. frase acima ganha nova, coerente e correta redação em:","b":"A Para viver os momentos de um mundo perdido implica em compreendê-los. E possível compreender um mundo perdido por quem não o pôde ainda assim viver.","c":"Mesmo quem não os tenha vivido poderá compreender momentos desse mundo perdido.","d":"Conquanto os tenha vivido, quem não compreendeu aqueles momentos perdidos pode agora fazê-lo.","e":"O mundo perdido tem momentos onde sua compreensão se dá para quem não os viveu.","gabarito":"C","materia":"Português","tema":"Interpretação de Textos ,Redação - Reescritura de texto","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564456","enunciado":"Leis dos homens e leis da Natureza Enquanto as leis dos homens buscam ordenar o comportamento dos indivíduos e da sociedade como um todo, de modo a tornar a vida comunal mais segura, as leis da Natureza são deduzidas de observações de toda uma variedade de fenômenos. Da mesma forma, enquanto as leis dos homens são baseadas em valores morais que variam de cultura para cultura e conforme o decorrer do tempo, as leis da Natureza buscam uma universalidade, tentando descrever comportamentos concretos - e verificáveis — que ocorrem no espaço e no tempo. Com isso, se para um grupo certos rituais são aceitáveis, enquanto para outro os mesmos rituais são considerados bárbaros, estrelas em todo à cosmos vêm fundindo hidrogênio em hélio seguindo as mesmas regras desde o seu aparecimento, por volta de 200 milhões de anos após o Big Bang. Se em alguns países a pena de morte é um ato imoral, enquanto em outros é instituída com um zelo quase que fanático, moléculas em trilhões de planetas e luas nesta e em outras galáxias combinam-se e recombinam-se em reações químicas que seguem as mesmas leis de conservação, de atração e repulsão entre 05 reagentes. Às variações nas leis dos homens mostram que pouco sabemos sobre nós mesmos, e tampouco conseguimos concordar sobre quais são os valores morais universais, ou mesmo se esses existem. Por outro lado, a precisão das leis da Natureza, sua universalidade, vem inspirando muitos pensadores a usá-las como base para todas as leis, incluindo as leis dos homens. Basta lembrar-se da busca de leis sociais, fundamentadas rigidamente na racionalidade que caracterizou à Iluminismo. Essa busca não começou aí, existindo já bem antes do século XVIII. Consideremos, por exemplo, Platão e suas Formas Ideais: há no pensamento desse filósofo da Antiguidade, um senso de veneração com o poder da matemática, e ainda mais com o poder da mente humana, por ter concebido o que pareciam ser verdades eternas a partir da observação do comportamento da Natureza. (Adaptado de: GLEISER, Marcelo. A Ilha do conhecimento. Rio de Janeiro: Record, 2023, 7.ed., p. 288- 289)","a":"Às normas de concordância verbal estão plenamente respeitadas na frase: Às variações das leis dos homens não se submetem a rígida regularidade das leis naturais.","b":"Sempre haverá filósofos que busquem nas leis naturais o que os inspire no âmbito das leis humanas.","c":"Não cabem às leis dos homens buscar corrigir ou disciplinar as leis da natureza.","d":"Regem-se pelos princípios da natureza toda manifestação de fenômenos que independem da ação humana.","e":"Impõem-se aos que defendem a pena de morte que se amparem em justificativas cabíveis.","gabarito":"B","materia":"Português","tema":"Sintaxe ,Concordância verbal, Concordância nominal","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564455","enunciado":"","a":"É plenamente regular o emprego do elemento sublinhado na frase: Muitos fiéis consideram bárbaros os mesmos ritos de que outros fiéis consideram sagrados.","b":"As leis humanas buscam o equilíbrio comunal à que aspiram as sociedades mais justas.","c":"As leis da natureza constituem um repertório de fenômenos aonde sua regularidade é incontestável.","d":"A veneração com cuja Platão considerava o poder da matemática levou-o às formas ideais.","e":"É admirável o rigoroso zelo a que se obriga aquele cientista no acompanhamento de sua experiência.","gabarito":"E","materia":"Português","tema":"Sintaxe ,Regência","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564454","enunciado":"Quando, no 3º terceiro parágrafo, o autor se refere à busca de leis sociais, fundamentadas rigidamente na racionalidade, ele","a":"está querendo demonstrar a universalidade das leis naturais em oposição à variação mesma das discutíveis leis morais.","b":"o poder da mente humana quando calcado na contestação platônica da existência das formas ideais.","c":"o desapego que os homens ao tempo do Iluminismo mantinham em relação aos valores morais.","d":"o inconformismo radical de Platão quanto ao prestígio exagerado de que gozava a matemática.","e":"a racionalidade das leis morais presente na observação dos comportamentos da natureza.","gabarito":"A","materia":"Português","tema":"Interpretação de Textos ,Noções Gerais de Compreensão e Interpretação de Texto","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564453","enunciado":"","a":"No 2º segundo parágrafo, o autor sugere que os aspectos discutíveis da pena de morte variam por alguma influência de fatores naturais.","b":"afirma que o fanatismo com que alguns se apegam a duros princípios morais deriva de convicções científicas.","c":"faz ver que as leis das reações químicas concorrem para o estabelecimento de certos princípios morais.","d":"mostra que o processo de formação das constelações ratifica a variabilidade de certos ritos humanos.","e":"demonstra a variabilidade das leis humanas quando considera as diferentes valorizações de um mesmo ritual.","gabarito":"E","materia":"Português","tema":"Interpretação de Textos ,Noções Gerais de Compreensão e Interpretação de Texto","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564452","enunciado":"","a":"No 1º parágrafo, argumenta-se em favor da ideia de que as leis humanas potenciam as leis da Natureza quando imbuídas de um propósito de universalidade.","b":"a vigência temporal das leis dos homens é o que essencialmente as distingue das leis naturais.","c":"os códigos das leis humanas buscam organizar e disciplinar toda uma variedade de fenômenos.","d":"o caráter verificável de comportamentos concretos é um componente característico das leis naturais.","e":"nas diferentes culturas variam os valores morais com base na variação mesma dos valores naturais.","gabarito":"D","materia":"Português","tema":"Interpretação de Textos ,Noções Gerais de Compreensão e Interpretação de Texto","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2564451","enunciado":"","a":"Considerando-se o contexto, traduz-se adequadamente o sentido de um segmento do texto em: um senso de veneração com o poder (3º parágrafo) = uma consideração respeitável da potência","b":"é instituída com um zelo quase que fanático (2º parágrafo) = se estabelece com um empenho próximo da obsessão","c":"o que pareciam ser verdades eternas (3º parágrafo) = aquilo que dissimulava aspectos estáveis","d":"de modo a formar a vida comunal mais segura (1º parágrafo) = apesar de regulamentar a vida em comunidade","e":"tampouco conseguimos concordar (3º parágrafo) = a despeito de firmarmos um acordo","gabarito":"B","materia":"Português","tema":"Interpretação de Textos ,Significação Contextual de Palavras e Expressões. Sinônimos e Antônimos.","origem":"FCC - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2024","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2350710","enunciado":"Contadoria Considere as informações relativas aos custos incorridos na fabricação do produto de determinada empresa industrial em um determinado exercício: Depreciação das máquinas R$ 10.000,00. Custo de embalagens prontas (individuais) R$ 5.000,00. Mão de obra indireta R$ 4.000,00. Custos de transformação R$ 40.000,00. Matéria-prima direta R$ 20.000,00. Energia Elétrica/Água R$ 10.000,00. Considere, ainda, que não havia estoques, nem no início nem no final do período. Os gastos com energia elétrica e água são alocados à proporção de 20% para o setor administrativo e 80% para o departamento de produção. O custo do produto","a":"vendido, de acordo como método do custeio por absorção é: R$ 70.000,00.","b":"R$ 69.000,00.","c":"R$ 65.000,00.","d":"R$ 68.000,00.","e":"R$ 67.000,00.","gabarito":"C","materia":"Contabilidade de Custos","tema":"Sistemas de Custeio ,Custeio por Absorção ou Integral","origem":"VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade:","ano":"2024","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2350709","enunciado":"Contadoria Considere as informações relativas aos custos incorridos na fabricação do produto de determinada empresa industrial em um determinado exercício: Depreciação das máquinas R$ 10.000,00. Custo de embalagens prontas (individuais) R$ 5.000,00. Mão de obra indireta R$ 4.000,00. Custos de transformação R$ 40.000,00. Matéria-prima direta R$ 20.000,00. Energia Elétrica/Água R$ 10.000,00. Considere, ainda, que não havia estoques, nem no início nem no final do período. Os gastos com energia elétrica e água são alocados à proporção de 20% para o setor administrativo e 80% para o departamento de produção.","a":"Com base, unicamente, nas informações disponibilizadas, o custo de mão de obra direta incorrido no período foi de R$ 16.000,00.","b":"R$ 18.000,00.","c":"R$ 15.000,00.","d":"R$ 20.000,00.","e":"R$ 25.000,00.","gabarito":"B","materia":"Contabilidade de Custos","tema":"Custo de Produção ,Custo de Transformação ou Conversão","origem":"VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade:","ano":"2024","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2350706","enunciado":"Contadoria O Ministério da Fazenda verificará o cumprimento dos limites e condições relativos à realização de operações de crédito de cada ente da Federação, inclusive das empresas por eles controladas, direta ou indiretamente. O ente interessado formalizará seu pleito fundamentando-o em parecer de seus órgãos técnicos e jurídicos, demonstrando a relação custo- benefício, o interesse econômico e social da operação e o atendimento das seguintes condições:","a":"inclusão no orçamento ou em créditos adicionais dos recursos provenientes da operação, inclusive no caso de","b":"operações por antecipação de receita. autorização específica do Senado Federal, quando se tratar de operação de crédito interno.","c":"observância dos limites e condições fixados pela Câmara dos Deputados.","d":"serão computadas nas despesas de capital as realizadas sob a forma de empréstimo ou financiamento a contribuinte.","e":"existência de prévia e expressa autorização para a contratação, no texto da lei orçamentária ou lei específica. Administração Financeira e Orçamentária>LC nº 101 de 2000 - Lei de Responsabilidade Fiscal ,","gabarito":"E","materia":"Administração Financeira e Orçamentária","tema":"LC nº 101 de 2000 - Lei de Responsabilidade Fiscal","origem":"VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade:","ano":"2024","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_214","enunciado":"Ano: 2024 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade: Contadoria Se a dívida consolidada de um ente da Federação ultrapassar o respectivo limite ao final de um quadrimestre, deverá ser a ele reconduzida até o término dos três subsequentes, reduzindo o excedente em pelo menos 25% (vinte e cinco por cento)","a":"no primeiro. Enquanto perdurar o excesso, o ente que nele houver incorrido não terá observadas as normas deste artigo nos casos de descumprimento dos limites da dívida mobiliária.","b":"poderá realizar operação de crédito interna ou externa.","c":"estará proibido de realizar operação de crédito interna ou externa, ressalvadas as para pagamento de dívidas","d":"mobiliárias. ficará impedido de receber transferências voluntárias da União ou do Estado.","e":"só poderá realizar operação de crédito externa.","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade:","ano":"2024","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_215","enunciado":"Ano: 2024 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade: Contadoria No que se refere à destinação de recursos para, direta ou indiretamente, cobrir necessidades de pessoas físicas ou deficit de","a":"pessoas jurídicas, é correto afirmar que o dispositivo na lei de responsabilidade fiscal não se aplica à administração indireta.","b":"poderão ser utilizados recursos públicos para socorrer instituições do Sistema Financeiro Nacional.","c":"poderá ser autorizada por decreto.","d":"não inclui a concessão de empréstimos e financiamentos.","e":"deverá ser autorizada por lei específica. Administração Financeira e Orçamentária>Despesa Pública ,","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade:","ano":"2024","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_216","enunciado":"Ano: 2024 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade: Contadoria É vedado ao titular de Poder ou órgão, no(s) último(s) _____________do seu mandato, contrair obrigação de despesa que não possa ser cumprida integralmente dentro dele, ou que tenha parcelas a serem pagas no exercício seguinte sem que haja","a":"suficiente disponibilidade de caixa para este efeito. A lacuna no enunciado refere-se ao período de seis meses.","b":"dois quadrimestres.","c":"três meses.","d":"dois bimestres.","e":"um ano. Administração Financeira e Orçamentária>LC nº 101 de 2000 - Lei de Responsabilidade Fiscal ,","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade:","ano":"2024","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_217","enunciado":"Ano: 2024 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade: Contadoria Se a despesa total com pessoal ultrapassar os limites estabelecidos na Lei de Responsabilidade Fiscal, o percentual excedente terá de ser eliminado nos dois quadrimestres seguintes. Assim, é correto afirmar:","a":"não alcançada a redução no prazo estabelecido, e enquanto perdurar o excesso, o Poder ou órgão referido deverá tomar empréstimos.","b":"não alcançada a redução no prazo estabelecido, e enquanto perdurar o excesso, o Poder ou órgão referido não poderá pagar salários.","c":"não alcançada a redução no prazo estabelecido, e enquanto perdurar o excesso, o Poder ou órgão referido poderá","d":"receber transferências voluntárias. pelo menos um terço do excesso deverá ser eliminado no primeiro quadrimestre.","e":"o prazo para regularização pode ser adiado indefinidamente.","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade:","ano":"2024","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2350701","enunciado":"Contadoria","a":"Quanto aos limites com gasto com pessoal estabelecidos na Lei de Responsabilidade Fiscal, é correto afirmar: os valores dos contratos de terceirização de mão de obra não serão contabilizados como Despesas de Pessoal.","b":"a despesa total com pessoal, em cada período de apuração, não poderá exceder o percentual da 50% da receita","c":"corrente líquida, no caso da União. entende-se como despesa total com pessoal: o somatório dos gastos do ente da Federação com os ativos.","d":"neles, não são computadas as despesas com inativos e pensionistas.","e":"a despesa total com pessoal, em cada período de apuração, não poderá exceder o percentual de 70% da receita corrente líquida, no caso dos Municípios.","gabarito":"B","materia":"Administração Financeira e Orçamentária","tema":"LC nº 101 de 2000 - Lei de Responsabilidade Fiscal","origem":"VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade:","ano":"2024","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2350700","enunciado":"Contadoria","a":"As despesas obrigatórias de caráter continuado têm que ser aprovadas por Lei.","b":"fixam obrigação legal de, no máximo, dois exercícios.","c":"podem ser instituídas por Medida Provisória.","d":"se forem prorrogadas não serão consideradas aumento de despesa.","e":"não precisam estar acompanhadas de comprovação de que não afetarão as metas no final. Administração Financeira e Orçamentária>LC nº 101 de 2000 - Lei de Responsabilidade Fiscal ,","gabarito":"C","materia":"Administração Financeira e Orçamentária","tema":"Despesa Pública ,Classificação da Despesa Orçamentária em AFO","origem":"VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade:","ano":"2024","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_220","enunciado":"Ano: 2024 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade: Contadoria De acordo com a Lei de Responsabilidade Fiscal, assinale a alternativa correta quanto à concessão ou ampliação de incentivo ou benefício de natureza tributária da qual decorra renúncia de receita.","a":"O disposto na Lei não se aplica ao cancelamento de débito cujo montante seja inferior ao dos respectivos custos de","b":"cobrança. Deve estar acompanhada de estimativa do impacto orçamentário-financeiro no exercício vigente.","c":"Deve estar acompanhada de medidas de compensação que não incorram em aumento de receita.","d":"Requer demonstração pelo proponente de que a renúncia foi considerada na estimativa de receita no Plano Plurianual.","e":"Se o ato de concessão ou ampliação do incentivo decorrer de medidas de compensação prometidas, o benefício entrará em vigor imediatamente. Administração Financeira e Orçamentária>Ciclo Orçamentário ,","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade:","ano":"2024","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_221","enunciado":"Ano: 2024 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade:","a":"Contadoria Lei Orçamentária Anual:","b":"A é aprovada por decreto do Poder Executivo. estima receitas e fixa as despesas para um exercício financeiro.","c":"estabelece as metas do Plano Plurianual.","d":"é um instrumento de longo prazo.","e":"estabelece as regras para a elaboração da Lei de Diretrizes Orçamentárias.","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade:","ano":"2024","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2350697","enunciado":"","a":"Contadoria Lei de Diretrizes Orçamentárias (LDO)","b":"A traça regras exclusivamente para as despesas do poder Executivo. estabelece as regras para a elaboração da Lei Orçamentária Anual do mesmo ano.","c":"veta o aumento de despesas com pessoal.","d":"indica prioridades de financiamento pelos bancos privados.","e":"determina o nível de equilíbrio geral entre receitas e despesas. Contabilidade Pública>Procedimentos Contábeis Patrimoniais ,","gabarito":"E","materia":"Direito Financeiro","tema":"O Orçamento: Aspectos Gerais ,As leis orçamentárias - PPA, LDO e LOA","origem":"VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade:","ano":"2024","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_223","enunciado":"Ano: 2024 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade: Contadoria","a":"Assinale a alternativa que contém uma variação patrimonial diminutiva. transferências recebidas.","b":"valorização de ativos.","c":"impostos, taxas e contribuições.","d":"pessoal.","e":"exploração e venda de bens.","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade:","ano":"2024","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2350694","enunciado":"Contadoria Na contabilidade do setor público, a demonstração que confronta as receitas e as despesas previstas com as realizadas é","a":"denominada Balanço Orçamentário.","b":"Demonstrativo do Resultado do Exercício.","c":"Balanço Patrimonial.","d":"Demonstrativo das Variações Patrimoniais.","e":"Balanço Financeiro.","gabarito":"A","materia":"Contabilidade Pública","tema":"Demonstrações Contábeis ,Balanço Orçamentário - BO","origem":"VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade:","ano":"2024","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2350693","enunciado":"Contadoria As dívidas resultantes de compromissos gerados em exercícios financeiros anteriores àqueles em que ocorrerão os","a":"pagamentos são denominadas restos a pagar.","b":"despesas extraorçamentárias.","c":"despesas de exercícios anteriores.","d":"dívida ativa.","e":"créditos adicionais. Administração Financeira e Orçamentária>Estágios da Receita e Despesa ,Estágios da Despesa Orçamentária ,","gabarito":"C","materia":"Administração Financeira e Orçamentária","tema":"Despesas de Exercícios Anteriores em AFO","origem":"VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade:","ano":"2024","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_226","enunciado":"Ano: 2024 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade: Contadoria","a":"As etapas da despesa orçamentária são, pela ordem: pagamento, liquidação e empenho.","b":"empenho, liquidação e pagamento.","c":"empenho, pagamento e liquidação.","d":"liquidação, empenho e pagamento.","e":"pagamento, empenho e liquidação.","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade:","ano":"2024","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2350691","enunciado":"Contadoria","a":"Configuram-se Restos a Pagar não processados quando: o pagamento foi feito, mas não foi contabilizado.","b":"falta apenas o pagamento.","c":"o pagamento foi feito fora do prazo.","d":"não foi realizado o empenho da despesa.","e":"a despesa se encontra pendente de liquidação.","gabarito":"E","materia":"Administração Financeira e Orçamentária","tema":"Restos a Pagar","origem":"VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade:","ano":"2024","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2350690","enunciado":"","a":"Contadoria etapa da receita orçamentária correspondente à entrega dos recursos devidos ao Tesouro pelos contribuintes ou devedores, por meio dos agentes arrecadadores ou instituições financeiras autorizadas pelo ente, é denominada","b":"A arrecadação. lançamento.","c":"cobrança.","d":"previsão.","e":"recolhimento.","gabarito":"A","materia":"Administração Financeira e Orçamentária","tema":"Estágios da Receita e Despesa ,Estágios da Receita Orçamentária","origem":"VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade:","ano":"2024","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2350689","enunciado":"Contadoria As despesas empenhadas mas não pagas até o dia 31 de dezembro, distinguindo-se as processadas das não processadas,","a":"são denominadas despesas extraorçamentárias.","b":"créditos adicionais.","c":"dívida ativa.","d":"restos a pagar.","e":"despesas correntes.","gabarito":"D","materia":"Administração Financeira e Orçamentária","tema":"Restos a Pagar","origem":"VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade:","ano":"2024","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2350688","enunciado":"","a":"Contadoria alternativa que traz somente receitas públicas classificadas como correntes é:","b":"A crédito, agropecuária, industrial. crédito, amortização, alienação de bens.","c":"tributária, amortização, industrial.","d":"tributária, agropecuária, industrial.","e":"amortização, agropecuária, crédito.","gabarito":"D","materia":"Administração Financeira e Orçamentária","tema":"Receita Pública ,Classificação da Receita Orçamentária em AFO","origem":"VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade:","ano":"2024","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2350687","enunciado":"Contadoria Se as distorções existentes nas demonstrações são relevantes e generalizadas, havendo evidências, o parecer do auditor","a":"deve ser sem ressalva.","b":"favorável.","c":"adverso.","d":"com ressalva.","e":"com abstenção de opinião.","gabarito":"C","materia":"Auditoria","tema":"Documentos e Relatórios ,Relatório de auditoria (Parecer de auditoria)","origem":"VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade:","ano":"2024","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2350686","enunciado":"Contadoria Ao decidir pela amostragem, o auditor pode fazê-la por dois tipos: estatístico e não estatístico. Considerando o exposto,","a":"assinale a alternativa correta. Se a população for muito heterogênea, a amostragem estatística é a mais recomendável.","b":"Os dois tipos de amostragem têm as mesmas bases científicas.","c":"A amostragem não estatística é determinada pelo conhecimento e experiência do auditor.","d":"A amostragem não estatística só é utilizada em auditorias internas.","e":"A amostragem estatística é recomendável quando a população for pequena. Auditoria>Auditoria Independente (Externa) ,","gabarito":"C","materia":"Auditoria","tema":"Testes, Procedimentos e Técnicas de Auditoria ,Amostragem em Auditoria","origem":"VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade:","ano":"2024","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_233","enunciado":"Ano: 2024 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade:","a":"Contadoria independência da auditoria pode ser afetada por ameaças, como a ameaça de autorrevisão, que ocorre quando o auditor","b":"A obtém benefícios financeiros na entidade auditada. era, anteriormente, diretor da entidade auditada.","c":"tem relacionamento estreito com membros de uma entidade auditada.","d":"questiona a própria competência, levantando dúvidas sobre seu trabalho.","e":"encontra obstáculos devido a ameaças por parte de membros da entidade auditada.","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade:","ano":"2024","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2350684","enunciado":"Contadoria","a":"Os papéis de trabalho correntes são aqueles utilizados em mais de um exercício social.","b":"referentes aos depósitos à vista.","c":"utilizados com valores financeiros.","d":"referentes a contas do ativo imobilizado.","e":"utilizados em apenas um exercício social.","gabarito":"E","materia":"Auditoria","tema":"Documentos e Relatórios ,Documentação de Auditoria (Papéis de Trabalho)","origem":"VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade:","ano":"2024","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2350683","enunciado":"Contadoria","a":"O risco de aceitação incorreta é um risco de amostragem em auditoria que ocorre quando não se identifica distorção relevante, embora exista.","b":"omite-se uma variável de análise relevante.","c":"incorpora-se uma variável de análise irrelevante","d":"o tamanho da amostra extraída é pequeno, tornando viesados os resultados obtidos.","e":"identifica-se distorção relevante, quando não existe. Auditoria>Auditoria Independente (Externa) ,","gabarito":"A","materia":"Auditoria","tema":"Testes, Procedimentos e Técnicas de Auditoria ,Amostragem em Auditoria","origem":"VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade:","ano":"2024","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_236","enunciado":"Ano: 2024 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade: Contadoria","a":"O auditor externo não emite opinião sobre a adequação das demonstrações contábeis.","b":"deve ter registro no CRC.","c":"tem menor grau de independência que o auditor interno.","d":"realiza auditoria tanto contábil como operacional.","e":"tem vínculo empregatício com a empresa auditada.","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade:","ano":"2024","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2350681","enunciado":"Contadoria o De acordo com a Lei n 6.404/76, o pagamento do valor das ações para retirá-las definitivamente de circulação, com","a":"redução ou não do capital social, é denominado reembolso.","b":"conversão.","c":"emissão.","d":"resgate.","e":"amortização.","gabarito":"D","materia":"Contabilidade Geral","tema":"Investimentos ,Transformações Societárias","origem":"VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade:","ano":"2024","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2350680","enunciado":"Contadoria Um veículo no valor de R$ 90.000,00 tem vida útil de 5 anos e taxa de depreciação, pelo método linear, de 20% ao ano. Suponha que o valor residual seja R$ 10.000,00. Com relação à depreciação do veículo, ao final do primeiro ano, deverão ser feitos os seguintes lançamentos:","a":"– Despesa com depreciação (débito): R$ 16.000,00. – Exigível a longo prazo (crédito): R$ 16.000,00.","b":"– Despesa com depreciação (débito): R$ 90.000,00. – Depreciação acumulada (crédito): R$ 16.000,00. – Exigível a longo prazo (crédito): R$ 74000.000,00.","c":"– Despesa com depreciação (débito): R$ 16.000,00. – Depreciação acumulada (crédito): R$ 16.000,00.","d":"– Despesa com depreciação (débito): R$ 16.000,00. – Veículos (crédito): R$ 16.000,00.","e":"– Veículos (débito): R$ 16.000,00. – Depreciação acumulada (crédito): R$ 16.000,00.","gabarito":"C","materia":"Contabilidade Geral","tema":"Balanço Patrimonial ,Amortização, Depreciação e Exaustão","origem":"VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade:","ano":"2024","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2350679","enunciado":"Contadoria Num dado exercício, o lucro líquido de uma empresa foi R$ 2.500.000,00; as despesas com depreciação totalizaram R$ 500.000,00; houve um aumento do saldo da conta fornecedores em R$ 150.000,00 e uma redução do saldo da conta","a":"estoques em R$ 250.000,00. Considerando apenas as informações fornecidas, o caixa gerado pelas operações foi de: R$ 1.770.000,00.","b":"R$ 3.600.000,00.","c":"R$ 2.000.000,00.","d":"R$ 2.900.000,00.","e":"R$ 3.400.000,00.","gabarito":"E","materia":"Contabilidade Geral","tema":"Demonstração dos Fluxos de Caixa -DFC","origem":"VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade:","ano":"2024","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2350678","enunciado":"Contadoria No início do ano, uma empresa apresentava o saldo da conta lucros e prejuízos acumulados, devedor de R$ 20.000,00 (prejuízo), sendo que seu capital social é R$ 250.000,00. O lucro líquido, ao final do ano, foi positivo de R$ 80.000,00. Estabelecidas as reservas legal obrigatória e a de contingência (sendo esta de 20% do lucro líquido), o estatuto da empresa prevê a distribuição de 50% do lucro ajustado na forma de dividendos. Assinale a alternativa que determina corretamente o","a":"montante a ser distribuído em dividendos. R$ 25.000,00.","b":"R$ 36.000,00.","c":"R$ 30.000,00.","d":"R$ 45.000,00.","e":"R$ 22.500,00.","gabarito":"E","materia":"Contabilidade Geral","tema":"Balanço Patrimonial ,Reservas de Capital e Reservas de Lucros","origem":"VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade:","ano":"2024","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2350677","enunciado":"Contadoria No Demonstrativo de Resultado do Exercício de uma empresa, a diferença entre lucro bruto e lucro operacional é resultado","a":"de despesas e receitas operacionais, administrativas e financeiras.","b":"despesas operacionais, administrativas e financeiras, mais imposto de renda.","c":"custo da mercadoria vendida.","d":"deduções sobre vendas: impostos e devoluções.","e":"impostos sobre vendas e imposto de renda.","gabarito":"A","materia":"Contabilidade Geral","tema":"Demonstração do Resultado do Exercício ,Lucro: Bruto, Operacional e Líquido","origem":"VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade:","ano":"2024","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2350676","enunciado":"Contadoria Considere uma empresa que, no início do ano, estava sem estoque. Primeiramente, ela comprou 100 mercadorias para revenda no valor unitário de R$ 20,00; a seguir, comprou mais 50 unidades ao preço de R$ 22,00. Final- mente, comprou outras 50 ao preço unitário de R$ 25,00. Algum tempo depois, vendeu 120 mercadorias. Determine o custo das mercadorias","a":"vendidas, considerando que a avaliação do estoque é feita pelo método PEPS e desconsiderando impostos. R$ 2.620,00.","b":"R$ 2.560,00.","c":"R$ 2.750,00.","d":"R$ 2.440,00.","e":"R$ 2.000,00.","gabarito":"D","materia":"Contabilidade Geral","tema":"Balanço Patrimonial ,Operações com Mercadorias","origem":"VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade:","ano":"2024","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2350675","enunciado":"Contadoria Sobre ativo intangível, é correto afirmar que","a":"um ativo intangível não satisfaz o critério de identificação se for separável, ou seja, puder ser separado da entidade e vendido.","b":"deve ser reconhecido se for provável que os benefícios econômicos futuros esperados atribuíveis ao ativo serão gerados em favor da entidade.","c":"custos com testes para verificar se o ativo está funcionando adequadamente não devem ser considerados no valor do ativo intangível.","d":"custo diretamente atribuível à preparação do ativo para a finalidade proposta não pode ser considerado no valor do","e":"ativo intangível. um ativo intangível deve ser reconhecido mesmo se o custo do ativo não possa ser mensurado com confiabilidade.","gabarito":"B","materia":"Contabilidade Geral","tema":"Balanço Patrimonial ,Ativo Intangível","origem":"VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade:","ano":"2024","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2350674","enunciado":"","a":"Contadoria empresa A adquiriu 50% da empresa B por R$ 100.000,00. O valor dos ativos da empresa B constante em seu Balanço Patrimonial é de R$ 160.000,00, mas há um terreno contabilizado por R$ 40.000,00, cujo valor de mercado é, na verdade, R$ 60.000,00. Considere que a empresa B não tem passivos exigíveis. Qual é o valor do ágio por expectativa de rentabilidade futura (goodwill) nessa operação?","b":"A R$ 10.000,00. 0.","c":"R$ 20.000,00.","d":"R$ 30.000,00.","e":"R$ 10.000,00","gabarito":"E","materia":"Contabilidade Geral","tema":"Investimentos ,Método da Equivalência Patrimonial - MEP ,Participação Societária","origem":"VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade:","ano":"2024","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2350673","enunciado":"Contadoria Uma empresa tem veículos no valor de R$ 600.000,00, e máquinas no valor de R$ 1.200.000,00. A vida útil dos veículos é de 5 anos, e das máquinas, 10 anos, sendo que ambos têm valor residual de 10% do valor total. Qual é a despesa anual de","a":"depreciação da empresa, utilizando o método linear? R$ 240.000,00.","b":"R$ 432.000,00.","c":"R$ 216.000,00.","d":"R$ 324.000,00.","e":"R$ 108.000,00.","gabarito":"C","materia":"Contabilidade Geral","tema":"Balanço Patrimonial ,Patrimônio Líquido ,Noções Gerais de Balanço Patrimonial","origem":"VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade:","ano":"2024","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2350672","enunciado":"Contadoria O ativo circulante de uma empresa era, ao final de um determinado exercício, de R$ 1.000.000,00. Essa empresa adquiriu um terreno no valor de R$ 300.000,00, sendo R$ 100.000,00 tirados do caixa da empresa, R$ 100.000,00 em empréstimos que deverão ser pagos em 12 prestações mensais e R$ 100.000,00 obtidos da receita de venda de outro imóvel. Qual será o","a":"valor do ativo circulante após essas operações? R$ 900.000,00.","b":"R$ 1.000.000,00.","c":"R$ 1.100.000,00.","d":"R$ 1.200.000,00.","e":"R$ 1.300.000,00.","gabarito":"A","materia":"Contabilidade Geral","tema":"Balanço Patrimonial ,Noções Gerais de Balanço Patrimonial","origem":"VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade:","ano":"2024","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2350671","enunciado":"Contadoria São dados para uma empresa em determinado exercício: Ativo Circulante: R$ 600.000,00. Ativo Não Circulante: R$ 700.000,00. Passivo Circulante: R$ 300.000,00. Passivo Não Circulante: R$ 500.000,00.","a":"Em face do exposto, afirma-se corretamente que o patrimônio líquido dessa empresa é: R$ 400.000,00.","b":"R$ 500.000,00.","c":"R$ 300.000,00.","d":"R$ 600.000,00.","e":"R$ 200.000,00.","gabarito":"B","materia":"Contabilidade Geral","tema":"Balanço Patrimonial ,Noções Gerais de Balanço Patrimonial","origem":"VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade:","ano":"2024","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2350670","enunciado":"Contadoria o No tocante ao tema da Gestão Estratégica do Poder Judiciário, a Resolução CNJ n 325/2020 dispõe que a execução da Estratégia Nacional do Poder Judiciário é de responsabilidade de ministros, conselheiros, magistrados de primeiro e segundo graus, servidores e colaboradores do Poder Judiciário.","a":"E, nesse sentido, a Estratégia do Judiciário é executada de forma colaborativa e participativa sob a coordenação do Coordenador Geral de Assuntos Estratégicos do Poder Judiciário.","b":"do Presidente do Supremo Tribunal Federal.","c":"do Corregedor-Geral do Conselho Nacional de Justiça.","d":"da Rede de Governança Colaborativa do Poder Judiciário.","e":"dos Conselhos de Justiça. Direito Constitucional>Disposições Gerais no Poder Judiciário ,Poder Judiciário ,Organização do Poder Judiciário","gabarito":"D","materia":"Legislação dos TRFs","tema":"Conselho Nacional de Justiça (CNJ) ,Resoluções do CNJ","origem":"VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade:","ano":"2024","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_249","enunciado":"Ano: 2024 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade: Contadoria Considerando o disposto na Constituição Federal a respeito do Poder Judiciário e seus órgãos, assinale a alternativa correta.","a":"Os Tribunais Regionais Federais terão em sua composição, além de advogados e membros do Ministério Público Federal, juízes federais, por meio de promoção, com mais de 10 (dez) anos de exercício, por antiguidade e merecimento, alternadamente.","b":"Compete ao Supremo Tribunal Federal processar e julgar, originariamente, a homologação de sentenças estrangeiras e a ação em que todos os membros da magistratura sejam direta ou indiretamente interessados.","c":"Os Ministros do Superior Tribunal de Justiça serão nomeados pelo Presidente da República, entre eles um quinto dentre juízes dos Tribunais Regionais Federais e um quinto dentre desembargadores dos Tribunais de Justiça.","d":"É da competência dos Tribunais Regionais Federais processar e julgar, originariamente, os juízes federais da área de sua jurisdição, exceto os da Justiça Militar e da Justiça do Trabalho, nos crimes comuns e de responsabilidade, e os membros do Ministério Público da União, ressalvada a competência da Justiça Eleitoral.","e":"Com exceção das falências, dos acidentes de trabalho e as sujeitas à Justiça Eleitoral e à Justiça do Trabalho, aos juízes federais compete processar e julgar causas em que a União for autora, ré, assistente ou oponente e as causas entre Estado estrangeiro ou organismo internacional e Município ou pessoa domiciliada ou residente no País.","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade:","ano":"2024","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2350667","enunciado":"Contadoria Simplício, no exercício de suas funções como servidor público, exigiu dolosamente de Tércio, um cidadão, taxa em valor superior ao devido por um serviço público prestado e, ainda, não recolheu aos cofres públicos a importância paga por Tercio, tendo desviado o dinheiro em proveito próprio.","a":"Nessa situação hipotética, considerando o disposto no Código Penal, é correto afirmar que Simplício cometeu o crime de excesso de exação qualificado.","b":"peculato qualificado.","c":"corrupção ativa.","d":"excesso de exação e peculato.","e":"peculato mediante erro de outrem.","gabarito":"A","materia":"Direito Penal","tema":"Crimes contra a administração pública ,Concussão e Excesso de Exação","origem":"VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade:","ano":"2024","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2350665","enunciado":"Contadoria","a":"Dengue prevista dengue é uma doença periódica e cíclica: os casos crescem no verão e há picos epidêmicos a cada 4 ou 5 anos. Trata-se, portanto, de enfermidade de atuação previsível. Supõe-se que o poder público se adiantaria com medidas de prevenção e tratamento. Contudo, há décadas os números de casos e mortes só aumentam no Brasil. Entre 2000 e 2010, foram registrados 4,5 milhões de ocorrências e 1.869 óbitos. Na década seguinte, os números saltaram para 9,5 milhões e 5.385, respectivamente. O primeiro semestre deste ano registra 1,4 milhão de casos, ante 1,5 milhão em 2022. A tendência é piorar. Segundo a OMS, urbanização descontrolada e sistema sanitário precário contribuem para o descontrole da moléstia. No Brasil, cerca de 50% da população não tem acesso a redes de esgoto, em grande parte devido à ineficiência estatal, que só agora começa a mudar com o novo marco do setor. E o desmatamento para a construção de moradias irregulares grassa nos grandes centros. A dimensão de áreas verdes derrubadas para esse fim na cidade de São Paulo atingiu, nos primeiros dois meses de 2023, 85 hectares. Neste ano, o município já conta com 11 444 casos de dengue – 3,7% a mais em relação ao mesmo período de 2022. Dez pessoas morreram, o maior número em oito anos, quando houve pico epidêmico. A OMS ressaltou a importância da vacinação. Mas, devido à burocracia, o Brasil protela a distribuição do imunizante japonês Qdenga – já aprovado para venda pela Anvisa – no sistema público de saúde. O combate à dengue deve ser contínuo, não apenas no verão, e em várias frentes complementares (saúde, infraestrutura e moradia). Com o alerta da OMS, espera-se que o poder público, local e federal, se prepare para receber as consequências do fenômeno climático El Niño. (Editorial. Folha de S.Paulo, 27.07.2023. Adaptado) o Uma senha de seis dígitos, todos numéricos, corresponde ao 10 elemento da seguinte sequência numérica: 2, 11, 47, 191, 767, 3 071, ... Considerando-se que a senha seja mpqxyz, em que m, p, q, x, y, z representam os algarismos dessa senha, o número que representa y é","b":"A 5. 7.","c":"9.","d":"3.","e":"1. Raciocínio Lógico>Equivalência Lógica e Negação de Proposições ,","gabarito":"D","materia":"Raciocínio Lógico","tema":"Sequências Lógicas de Números, Letras, Palavras e Figuras","origem":"VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade:","ano":"2024","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_252","enunciado":"Ano: 2024 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade: Contadoria Considere a seguinte afirmação: “Existe, pelo menos, um candidato que, se ele não dormiu bem à noite, então não foi aprovado no concurso.”","a":"Uma negação lógica para a afirmação apresentada é: Não existe candidato que não dormiu bem à noite e foi aprovado no concurso.","b":"Existe candidato que, se foi aprovado no concurso, então dormiu bem à noite.","c":"Existe mais de um candidato que, se ele não dormiu bem à noite, então não foi aprovado no concurso.","d":"Todos os candidatos dormiram bem à noite e foram aprovados no concurso.","e":"Todos os candidatos não dormiram bem à noite e foram aprovados no concurso. Raciocínio Lógico>Fundamentos de Lógica ,Proposições Simples e Compostas e Operadores Lógicos ,","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade:","ano":"2024","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_253","enunciado":"Ano: 2024 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade: Contadoria","a":"Dengue prevista dengue é uma doença periódica e cíclica: os casos crescem no verão e há picos epidêmicos a cada 4 ou 5 anos. Trata-se, portanto, de enfermidade de atuação previsível. Supõe-se que o poder público se adiantaria com medidas de prevenção e tratamento. Contudo, há décadas os números de casos e mortes só aumentam no Brasil. Entre 2000 e 2010, foram registrados 4,5 milhões de ocorrências e 1.869 óbitos. Na década seguinte, os números saltaram para 9,5 milhões e 5.385, respectivamente. O primeiro semestre deste ano registra 1,4 milhão de casos, ante 1,5 milhão em 2022. A tendência é piorar. Segundo a OMS, urbanização descontrolada e sistema sanitário precário contribuem para o descontrole da moléstia. No Brasil, cerca de 50% da população não tem acesso a redes de esgoto, em grande parte devido à ineficiência estatal, que só agora começa a mudar com o novo marco do setor. E o desmatamento para a construção de moradias irregulares grassa nos grandes centros. A dimensão de áreas verdes derrubadas para esse fim na cidade de São Paulo atingiu, nos primeiros dois meses de 2023, 85 hectares. Neste ano, o município já conta com 11 444 casos de dengue – 3,7% a mais em relação ao mesmo período de 2022. Dez pessoas morreram, o maior número em oito anos, quando houve pico epidêmico. A OMS ressaltou a importância da vacinação. Mas, devido à burocracia, o Brasil protela a distribuição do imunizante japonês Qdenga – já aprovado para venda pela Anvisa – no sistema público de saúde. O combate à dengue deve ser contínuo, não apenas no verão, e em várias frentes complementares (saúde, infraestrutura e moradia). Com o alerta da OMS, espera-se que o poder público, local e federal, se prepare para receber as consequências do fenômeno climático El Niño. (Editorial. Folha de S.Paulo, 27.07.2023. Adaptado) Considere verdadeiras as seguintes afirmações: I. Se o evento é hoje, então descansei ontem. II. O evento não é hoje ou amanhã vou descansar. III. Ou estudo hoje ou não descansarei amanhã. IV. Não descansarei amanhã. Uma conclusão verdadeira que se pode extrair das informações apresentadas é:","b":"A O evento é hoje. Descansei ontem.","c":"Não estudo hoje.","d":"Não descansei hoje.","e":"Estudo hoje.","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade:","ano":"2024","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2350659","enunciado":"Contadoria Minha empregada, Mme. Thérèse, que já ia se conformando em ser chamada de dona Teresa, caiu doente. Mandou-me um bilhete com a letra meio trêmula, falando em reumatismo. Dias depois apareceu, mas magra, mais pálida e menor; explicou-me que tudo fora consequência de uma corrente de ar. Que meu apartamento tem um courant d’air terrível, de tal modo que,__________ , chegando em casa, nem teve coragem de tirar a roupa, caiu na cama. “Dói-me o corpo inteiro, senhor; o corpo inteiro.” O mesmo caso, ajuntou, houve cerca de 15 anos atrás, quando trabalhava em um apartamento que tinha uma corrente de ar exatamente igual _______essa de que hoje sou sublocatário. Fez uma pausa. Fungou. Contou o dinheiro que eu lhe entregava, agradeceu _____dispensa do troco. Foi lá dentro apanhar umas pobres coisas que deixara. Entregou-me a chave, fez qualquer observação sobre o aquecedor ______ gás – e depois, no lugar de sair_____ rua, deixou-se ficar imóvel e calada, de pé, em minha frente. (Rubem Braga, “Dona Teresa”. 200 crônicas escolhidas. Adaptado)","a":"Assinale a alternativa em que o primeiro termo destacado é um pronome com valor possessivo, e o segundo, um adjetivo. O mesmo caso, ajuntou, houve cerca de 15 anos atrás...","b":"Mandou-me um bilhete com a letra meio trêmula, falando em reumatismo.","c":"Entregou-me a chave, fez qualquer observação sobre o aquecedor...","d":"“Dói-me o corpo inteiro, senhor; o corpo inteiro.”","e":"... já ia se conformando em ser chamada de dona Teresa, caiu doente.","gabarito":"D","materia":"Português","tema":"Morfologia ,Adjetivos ,Morfologia - PronomesPronomes possessivos","origem":"VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade:","ano":"2024","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2350658","enunciado":"Contadoria Minha empregada, Mme. Thérèse, que já ia se conformando em ser chamada de dona Teresa, caiu doente. Mandou-me um bilhete com a letra meio trêmula, falando em reumatismo. Dias depois apareceu, mas magra, mais pálida e menor; explicou-me que tudo fora consequência de uma corrente de ar. Que meu apartamento tem um courant d’air terrível, de tal modo que,__________ , chegando em casa, nem teve coragem de tirar a roupa, caiu na cama. “Dói-me o corpo inteiro, senhor; o corpo inteiro.” O mesmo caso, ajuntou, houve cerca de 15 anos atrás, quando trabalhava em um apartamento que tinha uma corrente de ar exatamente igual _______essa de que hoje sou sublocatário. Fez uma pausa. Fungou. Contou o dinheiro que eu lhe entregava, agradeceu _____dispensa do troco. Foi lá dentro apanhar umas pobres coisas que deixara. Entregou-me a chave, fez qualquer observação sobre o aquecedor ______ gás – e depois, no lugar de sair_____ rua, deixou-se ficar imóvel e calada, de pé, em minha frente. (Rubem Braga, “Dona Teresa”. 200 crônicas escolhidas. Adaptado)","a":"Em conformidade com a norma-padrão, as lacunas do texto devem ser preenchidas, respectivamente, com: àquela tarde … à … a … a … à","b":"àquela tarde … a … a … a … à","c":"àquela tarde … à … à … a … a","d":"aquela tarde … à … à … à … a","e":"aquela tarde … a … a … à … à","gabarito":"B","materia":"Português","tema":"Crase ,Crase","origem":"VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade:","ano":"2024","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2350657","enunciado":"Contadoria","a":"Dengue prevista dengue é uma doença periódica e cíclica: os casos crescem no verão e há picos epidêmicos a cada 4 ou 5 anos. Trata-se, portanto, de enfermidade de atuação previsível. Supõe-se que o poder público se adiantaria com medidas de prevenção e tratamento. Contudo, há décadas os números de casos e mortes só aumentam no Brasil. Entre 2000 e 2010, foram registrados 4,5 milhões de ocorrências e 1.869 óbitos. Na década seguinte, os números saltaram para 9,5 milhões e 5.385, respectivamente. O primeiro semestre deste ano registra 1,4 milhão de casos, ante 1,5 milhão em 2022. A tendência é piorar. Segundo a OMS, urbanização descontrolada e sistema sanitário precário contribuem para o descontrole da moléstia. No Brasil, cerca de 50% da população não tem acesso a redes de esgoto, em grande parte devido à ineficiência estatal, que só agora começa a mudar com o novo marco do setor. E o desmatamento para a construção de moradias irregulares grassa nos grandes centros. A dimensão de áreas verdes derrubadas para esse fim na cidade de São Paulo atingiu, nos primeiros dois meses de 2023, 85 hectares. Neste ano, o município já conta com 11 444 casos de dengue – 3,7% a mais em relação ao mesmo período de 2022. Dez pessoas morreram, o maior número em oito anos, quando houve pico epidêmico. A OMS ressaltou a importância da vacinação. Mas, devido à burocracia, o Brasil protela a distribuição do imunizante japonês Qdenga – já aprovado para venda pela Anvisa – no sistema público de saúde. O combate à dengue deve ser contínuo, não apenas no verão, e em várias frentes complementares (saúde, infraestrutura e moradia). Com o alerta da OMS, espera-se que o poder público, local e federal, se prepare para receber as consequências do fenômeno climático El Niño. (Editorial. Folha de S.Paulo, 27.07.2023. Adaptado) No trecho do primeiro parágrafo – A dengue é uma doença periódica e cíclica: os casos crescem no verão e há picos epidêmicos a cada 4 ou 5 anos. Trata-se, portanto, de enfermidade de atuação previsível. –, os dois-pontos e as vírgulas são empregados, correta e respectivamente, para sinalizar","b":"A o resumo das informações precedentes; separar expressão adverbial. a inclusão de um contra-argumento; separar conjunção condicional.","c":"o detalhamento de uma informação; separar conjunção conclusiva.","d":"a inclusão de informação nova; separar oração intercalada.","e":"a retificação de uma informação; separar aposto explicativo.","gabarito":"C","materia":"Português","tema":"Pontuação ,Uso da Vírgula ,Uso dos dois-pontos","origem":"VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade:","ano":"2024","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2350656","enunciado":"","a":"Contadoria reescrita de informações do texto em que se atende à norma-padrão de concordância verbal é:","b":"A Aumenta-se, no verão, os casos de dengue e constata-se picos epidêmicos a cada 4 ou 5 anos. Ocorre a cada 4 ou 5 anos os picos epidêmicos da dengue, por isso é enfermidade de atuação previsível.","c":"Há picos epidêmicos da dengue a cada 4 ou 5 anos. Tratam-se, portanto, de situações de atuação previ- sível.","d":"Segundo a OMS, devem-se à urbanização descontrolada e ao sistema sanitário precário o descontrole da moléstia.","e":"São Paulo é um desses grandes centros que convivem com o desmatamento para a construção de moradias.","gabarito":"E","materia":"Português","tema":"Sintaxe ,Concordância verbal, Concordância nominal","origem":"VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade:","ano":"2024","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2350655","enunciado":"Contadoria Na passagem do primeiro parágrafo do texto – Supõe-se que o poder público se adiantaria com medidas de prevenção e tratamento. Contudo, há décadas os números de casos e mortes só aumentam no Brasil. –, o trecho destacado e o","a":"trecho posterior expressam, correta e respectivamente, sentidos de afirmação e conclusão.","b":"hipótese e adversidade.","c":"contestação e concessão.","d":"afirmação e explicação.","e":"hipótese e comparação.","gabarito":"B","materia":"Português","tema":"Interpretação de Textos ,Coesão e coerência","origem":"VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade:","ano":"2024","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2350654","enunciado":"Contadoria Considere as passagens: o • E o desmatamento para a construção de moradias irregulares grassa nos grandes centros. (4 parágrafo) o • o Brasilprotela a distribuição do imunizante japonês Qdenga... (6 parágrafo) o • O combate à dengue deve ser contínuo... (7 parágrafo)","a":"Os termos destacados significam, correta e respectivamente: propaga-se; posterga; ininterrupto.","b":"amplia-se; retarda; irregular.","c":"difunde-se; prioriza; infrequente.","d":"combate-se; cancela; intermitente.","e":"espalha-se; acelera; interminável.","gabarito":"A","materia":"Português","tema":"Interpretação de Textos ,Significação Contextual de Palavras e Expressões. Sinônimos e Antônimos.","origem":"VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade:","ano":"2024","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2350653","enunciado":"Contadoria O editorial enfatiza que o aumento dos casos de dengue é","a":"sazonal, dispensando atenção sistemática das instâncias governamentais, uma vez que os picos epidêmicos têm sido satisfatoriamente controlados.","b":"insignificante, uma vez que as consequências do El Niño para a população não afetam o sistema de saúde, a infraestrutura e a moradia do país.","c":"esperado, configurando um problema de saúde pública que deve ser combatido por meio de frentes complementares orquestradas pelo poder público.","d":"improvável, o que dispensa o poder público de organizar os mecanismos de prevenção, como a vacinação da população com o imunizante japonês Qdenga.","e":"desesperador, aumentando a insegurança da população que se vê acuada nos picos epidêmicos da doença, mesmo com prevenção e tratamento.","gabarito":"C","materia":"Português","tema":"Interpretação de Textos ,Noções Gerais de Compreensão e Interpretação de Texto","origem":"VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade:","ano":"2024","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2350652","enunciado":"Contadoria (Chargista Ricardo Manhães. https://ndmais.com.br/opiniao/charges, 31.03.2023) Na frase – E se bobear chega a mil facinho! –, a palavra “se” tem o mesmo emprego que a destacada em:","a":"Os moradores do local resolveram ajudar no combate à dengue e se puseram a procurar os focos do mosquito, eliminando-os o mais rápido possível.","b":"O combate à dengue dependerá de todos, se houver empenho para exterminar o mosquito, que facilmente prolifera nos locais onde há água parada.","c":"O agente de saúde visitou as casas e queria saber se as famílias estavam tomando todas as precauções necessárias para combater a dengue.","d":"Muitos focos da dengue foram eliminados em vários bairros da cidade, encontrando-se os mosquitos em locais onde pensavam que eles não estariam.","e":"A população prometeu acabar com a dengue no bairro e, depois de muita ação contra os focos da doença, alcançaram seu objetivo e se abraçaram felizes.","gabarito":"B","materia":"Português","tema":"Funções morfossintáticas da palavra SE","origem":"VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade:","ano":"2024","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2350651","enunciado":"Contadoria","a":"O diálogo entre os mosquitos permite concluir correta- mente que as medidas de combate à dengue deixam-nos apreensivos.","b":"a disseminação da dengue é algo em que eles não creem.","c":"o avanço da dengue é fato inconteste e pode recrudescer.","d":"os casos confirmados negam de fato o avanço da dengue.","e":"a dengue é um problema que eles preferem ignorar por ora. Segurança e Saúde no Trabalho>","gabarito":"C","materia":"Português","tema":"Interpretação de Textos ,Noções Gerais de Compreensão e Interpretação de Texto","origem":"VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade:","ano":"2024","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3149942","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio Especializado: Segurança do Trabalho Para que se obtenham resultados confiáveis nas avaliações ambientais, se faz necessário normatizar critérios e procedimentos. Em relação ao uso de alguns instrumentos de avaliação dos agentes ambientais, é correto afirmar que","a":"no uso dos medidores integradores de uso pessoal, a serem utilizados na avaliação da exposição ocupacional ao ruído intermitente, exige-se o atendimento de alguns parâmetros, como seleção do circuito de ponderação “B”; critério de referência de 85 dB(B), que corresponde à dose de 100% (cem por cento) para uma exposição de 8 (oito) horas. a avaliação do nível de iluminamento, em um determinado plano de trabalho, deve ser precedida pela calibração do","b":"instrumento, realizada pela medição da iluminância, que é a razão entre a intensidade do fluxo luminoso emitido por uma superfície em uma dada direção e a área dessa superfície projetada ortogonalmente sobre um plano perpendicular àquela direção.","c":"o dosímetro, uma vez em conformidade com as normas técnicas vigentes, deve estar ajustado de forma a atender, entre outros, os seguintes parâmetros: circuito de ponderação “A”; circuito de resposta lenta (slow); critério de referência – 85 dB(A); faixa de medição mínima de 80 a 115 dB(A). na utilização do luxímetro, certificar-se de que a calibração feita no instrumento respeita o intervalo de tempo definido","d":"pelo fabricante; estabilizar o medidor dirigindo a fotocélula a uma fonte de luz, sensivelmente mais intensa que aquela no plano de trabalho a ser avaliado, pelo tempo necessário à homogeneização das leituras antes de proceder às medições.","e":"o decibelímetro, por conta de sua elevada precisão na medição da intensidade do som, é usado em levantamentos ambientais para fins judiciais por permitir a alteração dos parâmetros de medição conforme as mudanças no padrão acústico do ambiente de trabalho, dentro da faixa de 80 (oitenta) a 140 (cento e quarenta) decibéis. Segurança e Saúde no Trabalho>Riscos Ocupacionais (Análise e Gerenciamento de Riscos) ,","gabarito":"C","materia":"NR 15 - Norma Regulamentadora n° 15 - Atividades e Operações Insalubres (Acústica","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_264","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio Especializado: Segurança do Trabalho O mapeamento de riscos tem sua origem atrelada à militância sindical italiana na área de segurança e saúde do trabalhador, iniciada na década de 60, que visava possibilitar, durante a sua elaboração, a troca e divulgação de informações afins entre os trabalhadores. A respeito da experiência brasileira em relação ao mapa de riscos, é correto afirmar que em relação ao modelo operário italiano, o modelo que se popularizou no Brasil se caracterizou por considerar um","a":"número maior de classes de riscos, de forma que, além dos riscos mecânicos imanentes à operação das máquinas, fosse concebida a classe dos riscos de acidentes, que incorporava os fatores organizacionais ao mapeamento dos riscos.","b":"o modelo original foi, aos poucos, incorporando traços da organização dos órgãos internos à empresa na gestão das condições de trabalho no Brasil, como a interface entre CIPA e SESMT, que ensejou a necessidade de o mapa produzido pelos trabalhadores sujeitar-se à validação pelo SESMT antes de sua publicação. por tratar-se de metodologia aberta, passível de adaptações, a utilização do mapeamento no trabalho rural","c":"considerou, na classe dos riscos biológicos, os vírus, as bactérias, os protozoários, os fungos, os parasitas, os bacilos, os roedores e os animais peçonhentos como serpentes, aranhas, escorpiões, lacraias, abelhas, vespas e marimbondos.","d":"em consonância com Anexo à Portaria no 25, de 29 de dezembro de 1994, publicada pela Secretaria de Segurança e Saúde no Trabalho, um dos objetivos do mapa de riscos é reunir as informações necessárias para estabelecer o diagnóstico da situação de segurança e saúde no trabalho na empresa.","e":"sofreu forte rejeição no meio empresarial brasileiro por se tratar de ferramenta gerada no meio sindical de trabalhadores, circunstância que dificultou sua utilização no Brasil, somada à dificuldade de padronização das classes de riscos e da métrica aplicada em relação à sua percepção pelos trabalhadores.","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3149940","enunciado":"Especializado: Segurança do Trabalho O objetivo do Programa de Proteção Respiratória, conforme publicação da Fundacentro/MTE, é auxiliar os profissionais responsáveis pela elaboração, implementação e administração de um programa que abrange a seleção, a utilização e a manutenção corretas dos equipamentos de proteção respiratória (EPR). De acordo com esse programa, é correto afirmar que na realização do ensaio de vedação quantitativo pelo método do controle da pressão neutra (CPN), a ocorrência de","a":"qualquer vazamento, no intervalo de tempo do ensaio, provocará um diferencial de pressão entre o ar ambiente e o interior da peça facial, que não deve permitir o ingresso dos contaminantes presentes na atmosfera do ambiente de trabalho. o empregador pode disponibilizar respiradores para uso voluntário, ou seja, quando solicitado espontaneamente","b":"pelos trabalhadores, de maneira a não permitir que utilizem seus próprios respiradores, independentemente de possuírem Certificado de Aprovação – CA, pois essa possibilidade traria sérias dificuldades na gestão do Programa e poderia implicar novos riscos à saúde dos trabalhadores. o oxigênio gasoso comprimido não deve ser usado em respiradores de linha de ar ou em máscaras autônomas de","c":"circuito aberto que tenham sido usadas previamente com ar comprimido, pois o ar comprimido pode conter vapores de óleo em baixas concentrações, introduzidos pelos equipamentos usados para a compressão e contaminar a máscara com essas substâncias e, com isso, gerar risco de fogo ou explosão. há respiradores de circuito aberto que utilizam substâncias que, em contato com o dióxido de carbono do ar exalado,","d":"produzem oxigênio, fazendo com que esse tipo de equipamento apresente peso total inferior ao daqueles de circuito fechado, que têm a vantagem da autonomia, que, dependendo do modelo, varia de 30 (trinta) minutos a 4 (quatro) horas. o texto de um programa de proteção respiratória a ser adotado pela organização deverá incluir, entre outros","e":"aspectos, política da empresa na área de proteção respiratória; regras e responsabilidades dos principais atores envolvidos; avaliação dos riscos respiratórios; uso do respirador e política da barba; resultados dos testes de função pulmonar dos trabalhadores abrangidos pelo programa e responsabilidades das empresas contratadas.","gabarito":"C","materia":"Segurança e Saúde no Trabalho","tema":"Programa de Proteção Respiratória (PPR) ,Sistema de Saúde Brasileira","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3149939","enunciado":"","a":"Especializado: Segurança do Trabalho Norma de Higiene Ocupacional NHO 08 – Coleta de Material Particulado Sólido Suspenso no Ar de Ambientes de Trabalho tem por objetivo estabelecer um procedimento padronizado para coleta de material particulado sólido em filtros de membrana com a finalidade de obter amostras representativas das partículas suspensas no ar dos ambientes de trabalho. De acordo com essa norma técnica, é correto afirmar que a bomba de amostragem portátil deve ser leve e fornecer uma vazão de até 10 L/min (dez litros por minuto), com A bateria recarregável e blindada contra explosão e sistema automático de controle de vazão, com capacidade para mantê-la constante, dentro de um intervalo de ± 1% (um por cento), durante o tempo de coleta.","b":"particulado respirável é a fração de material particulado suspenso no ar constituída por partículas de diâmetro aerodinâmico menor que 100 μm (cem micrômetros), capaz de penetrar além dos bronquíolos terminais e se depositar na região de troca de gases dos pulmões, causando efeito adverso nesse local.","c":"particulado inalável é a fração de material particulado suspenso no ar constituída por partículas de diâmetro aerodinâmico menor que 500 μm (quinhentos micrômetros), capaz de entrar pelas narinas e pela boca, penetrando no trato respiratório durante a inalação.","d":"seu campo de aplicação está na coleta de partículas de origem mineral, metálica, vegetal e animal, de negro de fumo e de partículas na forma de fibras, incluindo partículas que não tenham um limite de exposição estabelecido; que sejam insolúveis ou fracamente solúveis em água ou nos fluidos aquosos dos pulmões.","e":"particulado torácico é a fração de material particulado suspenso no ar constituída por partículas de diâmetro aerodinâmico menor que 25 μm, capaz de passar pela laringe, entrar pelas vias aéreas superiores e penetrar nas vias aéreas dos pulmões.","gabarito":"E","materia":"Segurança e Saúde no Trabalho","tema":"Normas de Higiene ocupacional - NHOs:","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3149938","enunciado":"","a":"Especializado: Segurança do Trabalho Norma de Higiene Ocupacional NHO 06 – Avaliação da Exposição Ocupacional ao Calor tem por objetivo o estabelecimento de critérios e procedimentos para avaliação da exposição ocupacional ao calor que implique sobrecarga térmica ao trabalhador, resultando em risco potencial de dano à sua saúde. De acordo com essa norma técnica, é correto afirmar que considerando-se a exatidão admitida nos valores atribuídos para as taxas metabólicas e as incertezas envolvidas nos A valores fornecidos por sensores de temperatura, a interpretação dos resultados deve considerar os valores médios da série de medidas, de forma a se aproximar da real exposição do trabalhador ao calor.","b":"a aclimatização deve ser específica para o nível de sobrecarga térmica a que o trabalhador será submetido e, consequentemente, para a qual deverá estar adaptado, sendo considerados não aclimatizados os trabalhadores que, mesmo já anteriormente aclimatizados, tenham se afastado da condição de exposição por mais de 7 (sete) dias.","c":"a avaliação do risco de sobrecarga térmica para o trabalhador se dá de forma indireta, por meio do Índice de Bulbo Úmido Termômetro de Globo (IBUTG), que é o índice utilizado para avaliação da exposição ocupacional ao calor que leva em consideração temperatura, velocidade e umidade do ar, taxa metabólica e calor radiante.","d":"para se obter medições representativas da exposição ocupacional, é importante que o período de amostragem seja adequadamente escolhido de forma a considerar os 60 minutos corridos de exposição que correspondam à condição de sobrecarga térmica mais duradoura.","e":"as condições térmicas de curta duração, inferiores ao tempo de estabilização do conjunto de medição, podem ser avaliadas por meio de ponderação, procedimento que consiste em simular, com suporte de modelos matemáticos, o impacto de uma fonte que libera cargas de calor de forma intermitente na exposição ocupacional do trabalhador.","gabarito":"B","materia":"Segurança e Saúde no Trabalho","tema":"Normas de Higiene ocupacional - NHOs:","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3149937","enunciado":"","a":"Especializado: Segurança do Trabalho respeito dos limites de tolerância e de exposição, no campo da Higiene do Trabalho, é correto afirmar que os limites de exposição referem-se às concentrações das substâncias químicas dispersas no ar e representam A condições às quais, acredita-se, a maioria dos trabalhadores possa estar exposta, repetidamente, dia após dia, durante toda uma vida de trabalho, sem sofrer efeitos adversos à saúde.","b":"entre as possibilidades de construção do limite de exposição, o método mais prático e satisfatório para monitorar contaminantes no ar é a concentração média ponderada pelo tempo, que pode ser utilizada independentemente das propriedades toxicológicas do contaminante.","c":"os órgãos de pesquisa vêm aprimorando a metodologia utilizada na proposição de limites de tolerância de tal maneira que, contrariamente à impressão já superada, os valores adotados podem ser considerados como uma linha divisória entre um ambiente de trabalho saudável ou insalubre.","d":"considerando a adoção de estudos epidemiológicos abrangentes no tempo e no espaço, é possível afirmar, usualmente, que substâncias químicas com limites de tolerância numericamente equivalentes tenham efeitos toxicológicos e potência biológica similares.","e":"os limites de exposição que apresentam valor de teto explicitam concentração que não deve ser ultrapassada no ambiente de trabalho por intervalos de tempo superiores a 15 (quinze) minutos em jornadas de 8 (oito) horas e, para substâncias que implicam insalubridade máxima, em momento algum.","gabarito":"A","materia":"Segurança e Saúde no Trabalho","tema":"Normas de Higiene ocupacional - NHOs:","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3149936","enunciado":"Especializado: Segurança do Trabalho Em relação à exposição ocupacional a temperaturas extremas, causa do estresse por frio, a preocupação, no campo da Higiene do Trabalho, é proteger os trabalhadores dos efeitos mais graves da hipotermia. Assim, é correto afirmar que","a":"a temperatura normalizada deve ser utilizada para estimar o efeito calculado do vento e das baixas temperaturas baixas sobre a pele exposta, subsidiando o dimensionamento da roupa e sua capacidade de isolamento térmico.","b":"para os trabalhadores com boa condição orgânica, a incapacidade de pensar de forma racional fica comprometida seriamente quando a temperatura interna do corpo cai abaixo de 37 ºC (trinta e sete graus centígrados) e a exposição não é interrompida.","c":"a taxa de resfriamento do vento e de refrigeração de ar são fatores críticos, sendo definida como a perda de calor do corpo do trabalhador expressa em calorias por metro quadrado, que é função da temperatura do ar e de sua velocidade sobre o corpo exposto.","d":"os tremores devem ser considerados um aviso de perigo para os trabalhadores, e a exposição ao frio deve ser interrompida imediatamente, sempre que eles apresentarem o sintoma de tremor forte.","e":"os sintomas clínicos progressivos de hipotermia, conforme progride a exposição e a temperatura interna do corpo atinge 34 ºC, são os seguintes: consciência diminuída, dificuldade em tomar a pressão sanguínea e pupila dilatada.","gabarito":"D","materia":"Segurança e Saúde no Trabalho","tema":"Normas de Higiene ocupacional - NHOs:","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3149935","enunciado":"Especializado: Segurança do Trabalho Em relação ao estudo da exposição ocupacional aos agentes químicos, conforme estudado na Higiene do Trabalho, é correto afirmar que","a":"grupo homogêneo de exposição corresponde a um grupo de trabalhadores que, em face de uma exposição semelhante, produzem uma quantidade padrão de metabólitos associados ao contaminante, de maneira que o acompanhamento do índice biológico de exposição de um trabalhador reflete a realidade de um coletivo homogêneo.","b":"para as substâncias classificadas como asfixiantes físicos, os limites de exposição ocupacional adotados são sensivelmente maiores que os de outras substâncias, pois o fator limitante é o oxigênio disponível, que tem sua utilização na troca aeróbica comprometida pelo contaminante atmosférico.","c":"os gases e vapores podem ser classificados segundo a sua ação sobre o organismo humano e divididos em 5 grupos: inócuos; irritantes, anestésicos, asfixiantes simples e asfixiantes químicos, sendo que a classificação de uma substância em um desses grupos implica que ela não possua também as principais características dos outros grupos.","d":"a prática de substituir um produto industrial por outros menos tóxicos encontra exemplo quando se trata do benzeno, que pode ser substituído pelo tolueno ou pelo xileno que, embora tenham propriedades similares ao benzeno, não apresentam quaisquer efeitos nocivos à saúde humana, ainda que em exposições mais severas. a pressão atmosférica pode interferir de forma significativa; por exemplo, o nitrogênio presente na atmosfera é","e":"usualmente inerte, mas quando hiperbárico (acima de 2 ou 3 vezes a pressão normal) apresenta toxicidade apreciável, pois, com o aumento da pressão, aumenta a concentração de nitrogênio nos tecidos orgânicos, originando a “embriaguez das profundidades” no caso de mergulhadores e trabalhadores em tubulões pneumáticos.","gabarito":"E","materia":"Segurança e Saúde no Trabalho","tema":"Normas de Higiene ocupacional - NHOs:","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3149934","enunciado":"Especializado: Segurança do Trabalho Em relação ao estudo da exposição ocupacional aos agentes físicos, conforme estudado na higiene do trabalho, é correto afirmar que","a":"a aplicação dos Limites de Exposição Ocupacional deve proteger a moda da população exposta dos efeitos adversos da exposição ao ruído, de forma que a perda auditiva média induzida pelo ruído, nas frequências de 0,5; 1; 2 e 3 KHz, após 40 (quarenta) anos de exposição, não exceda 2 dB (dois decibéis).","b":"o Índice de Bulbo úmido – Termômetro de Globo – IBUTG é um índice primário que quantifica a contribuição ambiental para a sobrecarga térmica por considerar a temperatura do ar, o calor radiante, a velocidade do ar, a umidade relativa do ar e outras fontes de calor, como micro-ondas e radiofrequência.","c":"nos ambientes de trabalho com presença de campos magnéticos estáticos, a exposições ocupacionais de rotina não devem exceder 2 T (dois Teslas) no ambiente geral de trabalho, podendo, entretanto, valores-teto de 8 T (oito Teslas) para trabalhadores com treinamento especial, operando em um ambiente de trabalho controlado. para a vibração de corpo inteiro induzida mecanicamente, em que não se observa o fenômeno do acoplamento entre","d":"o corpo e o objeto vibratório, que se vê no uso de ferramentas portáteis, praticamente inexiste influência da suscetibilidade individual e, portanto, os limites propostos consubstanciam uma fronteira entre condições seguras e potencialmente adversas à saúde.","e":"em atenção à radiação ultravioleta coerente, com comprimentos de onda entre 500 (quinhentos) e 1000 (um mil) nanômetros, que são comuns em ambientes de trabalho e em ambientes abertos, com incidência de luz solar, os limites de exposição propostos visam proteger os trabalhadores de efeitos agudos, como eritemas e fotoqueratites. Segurança e Saúde no Trabalho>Legislação Previdenciária (Previdência Social e Lei nº 8.213/91) ,","gabarito":"C","materia":"Segurança e Saúde no Trabalho","tema":"Normas de Higiene ocupacional - NHOs:","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_272","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio Especializado: Segurança do Trabalho . No âmbito da dimensão previdenciária da área de segurança e saúde do trabalhador, merece destaque o perfil profissiográfico previdenciário – PPP. A esse respeito, atentando para a legislação afim, é correto afirmar que","a":"o PPP busca prover a empresa de meios de prova produzidos em tempo real, de modo a organizar e a individualizar as informações contidas em seus diversos setores ao longo dos anos, possibilitando que a empresa evite o pagamento de adicionais, em virtude de condições de trabalho, indevidamente. o laudo técnico de condições ambientais do trabalho, expedido por médico do trabalho ou engenheiro de segurança","b":"do trabalho, conterá informações sobre a existência de tecnologia de proteção coletiva ou individual e sobre a sua eficácia e será elaborado com observância às normas editadas pela Secretaria Especial de Previdência e Trabalho do Ministério da Economia e aos procedimentos adotados pelo INSS.","c":"a empresa deverá elaborar e manter atualizado o perfil profissiográfico previdenciário, ou o conjunto de documentos que instruíram seu preenchimento, no qual deverão ser contempladas as atividades desenvolvidas ordinária e excepcionalmente durante o período laboral, garantido ao trabalhador o acesso às informações nele contidas. o trabalhador ou o sindicato representativo de sua categoria profissional terá acesso às informações prestadas pela","d":"empresa sobre o seu perfil profissiográfico previdenciário e poderá, inclusive, em conformidade com a Instrução Normativa n° 136/06, solicitar a retificação de informações que estejam em desacordo com a realidade do ambiente de trabalho.","e":"a cooperativa de trabalho e a empresa contratada para prestar serviços mediante cessão ou empreitada de mão de obra atenderão ao disposto na Lei com base nos laudos técnicos de condições ambientais de trabalho emitidos sob sua responsabilidade, quando o serviço for prestado em estabelecimento da contratante. Segurança e Saúde no Trabalho>Legislação Previdenciária (Previdência Social e Lei nº 8.213/91) ,","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_273","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio Especializado: Segurança do Trabalho O Regime Geral de Previdência Social vigente compreende as prestações, devidas inclusive em razão de eventos decorrentes de condições insalubres de trabalho, expressas em benefícios e serviços, como a aposentadoria especial. A esse respeito, é correto afirmar que a comprovação da efetiva exposição do segurado aos agentes nocivos será feita mediante formulário, na forma","a":"estabelecida pelo Instituto Nacional do Seguro Social – INSS, emitido pela empresa ou seu preposto, com base em laudo técnico de condições ambientais do trabalho expedido por médico do trabalho ou engenheiro de segurança do trabalho nos termos da legislação trabalhista. a aposentadoria especial será devida, uma vez cumprida a carência exigida na Lei n° 8.213/91, ao segurado que tiver","b":"trabalhado sujeito a condições especiais que prejudiquem a saúde ou a integridade física, durante 15 (quinze), 20 (vinte) ou 25 (vinte e cinco) anos, conforme dispuser a lei, consistindo em parcelas mensais equivalentes a 91% (noventa e um por cento) do salário de benefício. do Laudo Técnico de Condições Anormais de Trabalho – LTCAT, a ser assinado por engenheiro de segurança ou","c":"médico do trabalho, deverão constar informação sobre a existência de tecnologia de proteção coletiva ou individual que diminua a intensidade do agente agressivo a limites de tolerância e recomendação sobre a sua adoção pelo estabelecimento respectivo. o benefício será financiado com os recursos provenientes da contribuição de 1; 2 e 3% incidentes sobre a folha de","d":"pagamentos da empresa, que serão acrescidas de nove; seis ou três pontos percentuais, conforme a atividade exercida pelo segurado a serviço da empresa, permitindo a concessão de aposentadoria especial após quinze, vinte ou vinte e cinco anos de contribuição, respectivamente. a concessão da aposentadoria especial dependerá de comprovação pelo segurado, perante o Instituto Nacional do","e":"Seguro Social – INSS, do tempo de trabalho permanente e contínuo, sem afastamentos outros que não sejam as férias anuais regulares, em condições especiais que prejudiquem a saúde ou a integridade física, durante o período mínimo fixado. Segurança e Saúde no Trabalho>Acidente de Trabalho (CAT) ,","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3149931","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio","a":"Especializado: Segurança do Trabalho comunicação de acidente de trabalho à Previdência Social é obrigatória e está prevista no Decreto n° 3.048, de 6 de maio de 1999 e na Lei n° 8.213, de 24 de julho de 1991. A seu respeito, é correto afirmar: para fins estatísticos e epidemiológicos, a empresa deverá comunicar à previdência social o acidente de trabalho, ocorrido com o segurado empregado, temporário, doméstico e o trabalhador avulso, até o primeiro dia útil seguinte A ao da ocorrência e, em caso de morte, de imediato, à autoridade competente, sob pena de multa aplicada e cobrada pela auditoria fiscal da previdência social. na falta de comunicação por parte da empresa ou do sindicato representativo da categoria profissional do acidentado,","b":"ou quando se tratar de segurado especial, como os médicos residentes e profissionais autônomos, podem formalizá- la o próprio acidentado, seus dependentes, o médico que o assistiu ou qualquer autoridade pública, não prevalecendo nesses casos o prazo previsto originalmente à empresa. a empresa ou o empregador doméstico poderão requerer a não aplicação do nexo técnico epidemiológico","c":"previdenciário – NTEP, de cuja decisão caberá recurso, com efeito suspensivo, da empresa, do empregador doméstico ou do segurado ao Conselho de Recursos da Previdência Social, mediante exposição de motivos circunstanciada juntada à Comunicação de Acidente de Trabalho ou preenchimento do respectivo formulário no sítio virtual do INSS. considera-se como dia do acidente, no caso de doença profissional ou do trabalho, a data do início da incapacidade","d":"laborativa para o exercício da atividade habitual, ou o dia da segregação compulsória, ou o dia em que for realizado o diagnóstico, ou o dia em que foi feito o lançamento no Programa de Controle Médico de Saúde Ocupacional, valendo para esse efeito o que ocorrer primeiro. a empresa ou o empregador doméstico deverão comunicar o acidente do trabalho à Previdência Social até o primeiro","e":"dia útil seguinte ao da ocorrência e, em caso de morte, de imediato, à autoridade competente, sob pena de multa variável entre o limite mínimo e o limite máximo do salário de contribuição, sucessivamente aumentada nas reincidências, aplicada e cobrada pela Previdência Social.","gabarito":"E","materia":"Legislação Previdenciária (Previdência Social e Lei nº 8.213/91)","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3149930","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio Especializado: Segurança do Trabalho De acordo com a legislação previdenciária vigente acerca do acidente de trabalho, é correto afirmar","a":"será considerado agravamento do acidente aquele sofrido pelo acidentado quando estiver sob a responsabilidade da reabilitação profissional, ensejando reabertura de procedimento administrativo, que indicará o INSS como parte interessada juntamente com o empregador. não são consideradas como doença do trabalho: a) a doença degenerativa; b) a inerente a grupo etário; c) a que não","b":"produza incapacidade laborativa; d) a doença endêmica adquirida por segurado habitante de região em que ela se desenvolva, salvo comprovação de que é resultante de exposição ou contato direto determinado pela natureza do trabalho. entre as entidades mórbidas relacionadas ao trabalho, considera-se como acidente do trabalho a doença profissional","c":"ou mesopatia específica, assim entendida a produzida ou desencadeada pelo exercício do trabalho peculiar a determinada atividade e constante da respectiva relação elaborada pelo Ministério do Trabalho e da Previdência Social.","d":"equiparam-se ao acidente de trabalho o acidente sofrido pelo segurado no local e no horário do trabalho, em consequência de prestação espontânea de qualquer serviço à empresa, ainda que estranho à sua atividade e sem a respectiva ordem de serviço, para evitar prejuízo ou proporcionar proveito ao empregador.","e":"considera-se estabelecido o nexo causal entre o trabalho e o agravo quando se verificar nexo técnico estatístico previdenciário – NTEP entre a atividade da empresa e a entidade mórbida motivadora da incapacidade, elencada na Classificação Internacional de Doenças – CID em conformidade com o disposto na respectiva Lista do Regulamento. Segurança e Saúde no Trabalho>Legislação Previdenciária (Previdência Social e Lei nº 8.213/91) ,","gabarito":"B","materia":"Legislação Previdenciária (Previdência Social e Lei nº 8.213/91)","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_276","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio","a":"Especializado: Segurança do Trabalho respeito dos dispositivos presentes no Decreto n° 3.048, de 6 de maio de 1999, que atentam para a segurança e saúde dos trabalhadores, é correto afirmar que quando indispensáveis ao desenvolvimento do processo de reabilitação profissional, o Instituto Nacional do Seguro Social fornecerá aos segurados, inclusive aposentados, em caráter obrigatório, prótese e órtese, seu reparo ou A substituição, instrumentos de auxílio para locomoção, bem como equipamentos necessários à habilitação e à reabilitação profissional, transporte urbano e alimentação e, na medida das possibilidades do Instituto, aos seus dependentes.","b":"por intermédio dos estabelecimentos de ensino, sindicatos, associações de classe, Fundação Jorge Duprat Figueiredo de Segurança e Medicina do Trabalho, órgãos públicos e outros meios, serão promovidas regularmente instrução e formação com vistas a promover o comportamento seguro no trabalho e a preservação da saúde do trabalhador. o Instituto Nacional do Seguro Social – INSS ajuizará ação regressiva contra os responsáveis nas hipóteses de: I)","c":"negligência quanto às normas-padrão de segurança e higiene do trabalho indicadas para proteção individual e coletiva; II) prática de assédio e outras formas de violência psicológica praticadas no ambiente e relações de trabalho e III) fraude documental nas obrigações junto àquela autarquia. os órgãos de fiscalização das relações de trabalho encaminharão à Procuradoria-Geral Federal os relatórios de análise","d":"de acidentes do trabalho com indícios de negligência quanto às normas-padrão de segurança e higiene do trabalho indicadas para proteção individual e coletiva, constituindo contravenção administrativa, punível com multa, deixar a empresa de cumprir as normas de segurança e saúde do trabalho. a Auditoria Fiscal da Previdência e Assistência Social auditará a regularidade e a conformidade das demonstrações","e":"ambientais, incluindo-se as de monitoramento biológico, e dos controles internos da empresa relativos ao gerenciamento dos riscos ocupacionais, de modo a assegurar a veracidade das informações prestadas pela empresa e constantes do RAIS, bem como o cumprimento das obrigações relativas às condições de trabalho. Segurança e Saúde no Trabalho>Legislação Previdenciária (Previdência Social e Lei nº 8.213/91) ,","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_277","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio Especializado: Segurança do Trabalho Conforme o disposto no Decreto n° 3.048, de 6 de maio de 1999, que aprova o Regulamento da Previdência Social e dá outras providências, é correto afirmar que o INSS auditará a regularidade e a conformidade das demonstrações ambientais, incluindo-se as de monitoramento","a":"biológico, e dos controles internos da empresa relativos ao gerenciamento dos riscos ocupacionais, de modo a assegurar a veracidade das informações prestadas pela empresa e constantes do CNIS, bem como o cumprimento das obrigações relativas ao acidente de trabalho.","b":"a perda da audição, em qualquer grau, somente proporcionará a concessão do auxílio-doença quando, além do reconhecimento do nexo entre o trabalho e o agravo pela Perícia Médica Federal, resultar, comprovadamente, na redução ou perda da capacidade motora ou cognitiva para o trabalho que o segurado habitualmente exercia.","c":"o auxílio-doença será concedido, como indenização, ao segurado empregado, inclusive o doméstico, ao trabalhador avulso e ao segurado especial quando, após a consolidação das lesões decorrentes de acidente de qualquer natureza, resultar sequela definitiva que implique redução da capacidade para o trabalho que habitualmente exercia. se concedido novo benefício decorrente do mesmo motivo que gerou a incapacidade temporária no prazo de noventa","d":"dias, contado da data da cessação do benefício anterior, a empresa ficará desobrigada do pagamento relativo aos quinze primeiros dias de afastamento, prorrogando-se o benefício anterior e descontando-se os dias trabalhados, se for o caso. a aposentadoria por incapacidade permanente, uma vez cumprido o período de carência exigido, quando for o caso,","e":"será devida ao segurado que, em gozo ou não de auxílio por incapacidade temporária, for considerado incapaz para o trabalho e insuscetível de reabilitação para o exercício de atividade que exercia anteriormente, que lhe será paga enquanto permanecer nessa condição. Segurança e Saúde no Trabalho>","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3149927","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio Especializado: Segurança do Trabalho Em conformidade com a Norma Regulamentadora 32 – Segurança e Saúde no Trabalho em Serviços de Saúde, é correto afirmar que","a":"todo recipiente contendo produto químico manipulado deve ser identificado, de forma legível, por etiqueta com o nome do produto, composição química, sua concentração, data de validade, nome do responsável pela manipulação ou fracionamento e medidas de primeiros socorros em caso de acidentes.","b":"os produtos químicos, que impliquem riscos à segurança e saúde do trabalhador, devem ter uma ficha descritiva contendo, entre outros, os seguintes dados: a) as características do produto; b) os riscos à segurança e saúde do trabalhador e ao meio ambiente; c) formas de contenção e tipos de EPI recomendados ao seu manuseio. o local no qual se dá a manipulação de fármacos e outros produtos químicos deve dispor, no mínimo, de: a)","c":"sinalização gráfica para identificação do local; b) equipamentos que garantam a concentração dos produtos químicos no ar abaixo dos limites de tolerância estabelecidos na legislação; c) chuveiro e lava-olhos, os quais deverão ser acionados e higienizados mensalmente. o empregador deve, para a manipulação ou fracionamento de produtos químicos que impliquem riscos à segurança e","d":"saúde do trabalhador, destinar local apropriado, que disponha de equipamentos que garantam a exaustão dos produtos químicos de forma a não potencializar a exposição de trabalhadores, não devendo ser utilizado o equipamento tipo coifa.","e":"no Programa de Gerenciamento de Riscos dos serviços de saúde, deve constar inventário de produtos químicos que apresentem riscos à saúde e segurança do trabalhador, inclusive intermediários e resíduos, com indicação das vias de contaminação ou exposição de pertinentes medidas de proteção. Segurança e Saúde no Trabalho> NR 7 - Norma Regulamentadora n° 7 - Programa de Controle Médico de Saúde Ocupacional - PCMSO (Avaliação Periódica) ,","gabarito":"D","materia":"NR 32 - Norma Regulamentadora n° 32 - Segurança e Saúde no Trabalho em Serviços de Saúde","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_279","enunciado":"Normas Regulamentadoras de Ministério do Trabalho e Emprego Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio Especializado: Segurança do Trabalho Ao tratar dos Riscos Biológicos à segurança e saúde dos trabalhadores em Serviços de Saúde, a regulamentação vigente do Ministério do Trabalho e Emprego estabelece que o Programa de Gerenciamento de Riscos, além do previsto na NR 1, na etapa de identificação de perigos, deve conter","a":"a identificação dos agentes biológicos mais prováveis, em função da localização geográfica e da característica do serviço de saúde e seus setores, considerando: a) fontes de exposição; b) transmissibilidade, taxas de incidência e prevalência relativas ao agente. além dos itens previstos na NR 1, o Programa de Gerenciamento de Riscos deverá contemplar a) a avaliação dos riscos","b":"biológicos; b) a localização das áreas de risco; c) a relação contendo a identificação dos trabalhadores, sua função, o local em que trabalham, o risco a que estão expostos e os EPI que utilizam; d) a vigilância médica dos trabalhadores potencialmente expostos. com relação à possibilidade de exposição acidental aos agentes biológicos, devem constar do PCMSO, entre outros: a)","c":"os procedimentos a serem adotados para diagnóstico, acompanhamento e prevenção da soroconversão e das doenças; b) a identificação dos responsáveis pela aplicação das medidas pertinentes; c) as formas de remoção para atendimento dos trabalhadores. a capacitação dos trabalhadores deve ser adaptada à evolução do conhecimento e à identificação de novos riscos","d":"biológicos e deve incluir, entre outros: a) os dados sobre riscos para a saúde; b) medidas organizacionais de controle que minimizem a exposição aos agentes; c) normas e procedimentos de higiene pessoal e do trabalho; d) utilização de equipamentos de proteção. em caso de exposição acidental ou incidental, medidas de proteção devem ser adotadas imediatamente, mesmo que","e":"não previstas no PGR, sendo que a manipulação em ambiente laboratorial deve seguir as orientações contidas na publicação do Ministério da Saúde – Diretrizes Gerais para o Trabalho com Material Biológico de Risco, correspondentes aos respectivos microrganismos. Segurança e Saúde no Trabalho>NR 26 - Norma Regulamentadora nº 26 - Sinalização de Segurança ,","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_280","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio","a":"Especializado: Segurança do Trabalho Norma Regulamentadora 26 – Sinalização de Segurança estabelece medidas quanto à sinalização e identificação de segurança a serem adotadas nos locais de trabalho. De acordo com essa norma, é correto afirmar que a rotulagem preventiva do produto químico classificado como perigoso à segurança e à saúde dos trabalhadores deve atender as orientações do Comitê de Segurança Química, da Organização Internacional do Trabalho, contendo, entre A outros: a) identificação e composição do produto químico; b) pictograma(s) de perigo; c) frase(s) de perigo; d) frase(s) de precaução.","b":"nas tubulações que conduzem fluidos, as propriedades destes, como concentração, temperatura, densidade, pressão, pureza etc., serão diferenciadas mediante utilização de variações na cor principal, aplicadas conforme legenda definida pela organização.","c":"nos processos industriais passíveis de gerar misturas de duas ou mais substâncias químicas, com propriedades diferentes daquelas dos componentes considerados isoladamente, os ocupantes do ambiente deverão ser alertados sobre o perigo apresentado pela mistura final.","d":"o produto químico utilizado no local de trabalho deve ser classificado quanto aos perigos para a segurança e a saúde dos trabalhadores, de acordo com os critérios estabelecidos pelo Comitê de Harmonização de Comunicação de Riscos em Segurança Química, da Oficina Internacional do Trabalho, da OIT. o produto químico não classificado como perigoso à segurança e à saúde dos trabalhadores, conforme o Sistema","e":"Globalmente Harmonizado de Classificação e Rotulagem de Produtos Químicos – GHS, da Organização das Nações Unidas, deve dispor de rotulagem preventiva simplificada que contenha, no mínimo, a indicação do nome, a informação de que se trata de produto não classificado como perigoso e recomendações de precaução. Segurança e Saúde no Trabalho>","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3149924","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio Especializado: Segurança do Trabalho De acordo com a Norma Regulamentadora 24 – Condições Sanitárias e de Conforto nos Locais de Trabalho, é correto afirmar que nas atividades laborais em que haja exposição e manuseio de material infectante, substâncias tóxicas, irritantes ou","a":"aerodispersoides, bem como naquelas em que haja contato com substâncias que provoquem deposição de poeiras que impregnem a pele e as roupas do trabalhador, devem ser fornecidos armários de compartimentos duplos ou dois armários simples. será exigido, para cada grupo de trabalhadores ou fração, 1 (um) chuveiro para cada 20 (vinte) trabalhadores, nas","b":"atividades laborais em que haja exposição e manuseio de material infectante, substâncias tóxicas, irritantes ou aerodispersoides, que impregnem a pele e roupas do trabalhador ou que exijam esforço físico ou submetidas a condições ambientais de calor intenso. nos estabelecimentos que possuírem cozinha, esta deve dispor de sanitário próprio para uso exclusivo dos","c":"trabalhadores que manipulam gêneros alimentícios, com os recipientes de gás liquefeito de petróleo (GLP) com 3 capacidade igual ou superior a 10 m (dez metros cúbicos) instalados em área externa ventilada, observadas as normas técnicas brasileiras pertinentes.","d":"em relação aos armários, é admitido o uso rotativo de armários simples entre usuários, sendo que, nos casos em que estes sejam utilizados para a guarda de equipamentos de proteção individual – EPI para proteção dos trabalhadores contra agentes ambientais, os usuários devem ser do mesmo setor de serviço.","e":"os vestiários devem ser dimensionados em função do número de trabalhadores que necessitam utilizá-los, até o limite de 500 (quinhentos) trabalhadores, conforme o seguinte cálculo: área mínima do vestiário por trabalhador = 1,5 – (n° de trabalhadores/750), em metros quadrados. Segurança e Saúde no Trabalho>","gabarito":"A","materia":"NR 24 - Norma Regulamentadora nº 24 - Condições Sanitárias e de Conforto nos Locais de Trabalho (Higiene do Trabalho)","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3149923","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio Especializado: Segurança do Trabalho Estabelecer as condições mínimas de higiene e de conforto a serem observadas pelas organizações constitui o objetivo da Norma Regulamentadora 24 – Condições Sanitárias e de Conforto nos Locais de Trabalho. De acordo com essa norma, é correto afirmar que","a":"as instalações sanitárias devem, entre outras características: a) ser mantidas em condição de conservação, limpeza e higiene; b) peças sanitárias íntegras; c) possuir recipientes para descarte de papéis usados que possam ser abertos por pedal, sem o uso das mãos; d) ser ventiladas para o exterior ou com sistema de exaustão forçada. os compartimentos destinados às bacias sanitárias devem, entre outras características: a) ser individuais; b) ter","b":"divisórias com altura que mantenham seu interior indevassável; c) possuir papel higiênico com suporte e recipiente para descarte de papéis higiênicos usados, quando não for permitido descarte na própria bacia sanitária, devendo o recipiente possuir tampa quando for destinado às mulheres. nos alojamentos deverão ser obedecidas as seguintes instruções gerais de uso: a) os sanitários deverão ser","c":"higienizados diariamente; b) é vedada, nos quartos, a instalação e utilização de fogão, fogareiro ou similares a gás, que possuam chama aberta; c) ser garantido o controle de vetores conforme legislação local; d) os pisos dos alojamentos devem ser impermeáveis e laváveis.","d":"no banheiro masculino os mictórios devem ser construídos com material impermeável e mantidos em condições de limpeza e higiene, sendo que, no mictório do tipo calha coletiva, quando inexistir anteparo, cada segmento de, no mínimo, 0,60 m (sessenta centímetros), corresponderá a uma unidade para fins de dimensionamento da calha. o lavatório dos vestiários poderá ser tipo individual, calha ou de tampo coletivo com várias cubas, possuindo torneiras,","e":"sendo que deve ser provido de material ou dispositivo para a limpeza, enxugo ou secagem das mãos, permitindo-se o uso de toalhas coletivas nos locais em que inexista exposição e manuseio de material infectante, substâncias tóxicas, irritantes, aerodispersoides ou que provoquem a deposição de poeiras, que impregnem a pele e roupas do trabalhador. Segurança e Saúde no Trabalho>NR 23 - Norma Regulamentadora nº 23 - Proteção Contra Incêndio ,","gabarito":"B","materia":"NR 24 - Norma Regulamentadora nº 24 - Condições Sanitárias e de Conforto nos Locais de Trabalho (Higiene do Trabalho)","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_283","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio Especializado: Segurança do Trabalho De acordo com a Norma Regulamentadora 23 – Proteção Contra Incêndios, que estabelece medidas de prevenção contra incêndios nos ambientes de trabalho, é correto afirmar que","a":"os exercícios de combate ao fogo e de abandono da edificação devem ser realizados com acompanhamento das chefias de cada setor e, entre outros objetivos, visam que se verifique se a sirene de alarme é ouvida adequadamente em todos os locais de trabalho do estabelecimento.","b":"nos estabelecimentos que contam com brigada de incêndio ou equipe treinada de bombeiros industriais, os exercícios simulados devem ser realizados periodicamente com conhecimento prévio somente de lideranças previamente selecionadas para a condução do exercício sem atropelos ou pânico.","c":"a organização deve providenciar para todos os trabalhadores informações sobre: a) utilização dos equipamentos de combate ao incêndio; b) procedimentos de resposta aos cenários de emergências e para evacuação dos locais de trabalho com segurança; e c) dispositivos de alarme existentes.","d":"os cilindros de extintores de pressão injetada deverão ser pesados semestralmente para avaliar a perda de peso que, se for superior a 5% (cinco por cento) do peso original, implica a necessidade de recarga imediata.","e":"todos os estabelecimentos devem ser providos de unidades móveis de combate a incêndios, excetuando-se as áreas que contam com rede de chuveiros de emergência e possuem acesso imediato à rota de fuga que conduza a local seguro na edificação ou fora dela. Segurança e Saúde no Trabalho>NR 17 - Norma Regulamentadora n° 17 - Ergonomia ,","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_284","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio Especializado: Segurança do Trabalho De acordo com a Norma Regulamentadora 17 – Ergonomia, é correto afirmar que a organização deve realizar Análise Ergonômica do Trabalho – AET da situação de trabalho quando: a) os relatórios do","a":"PCMSO acusarem a ocorrência LER/DORT entre os trabalhadores assistidos; b) houver a necessidade de uma avaliação mais aprofundada da situação; c) as funções com problemas ergonômicos tenham sido citadas no Inventário de Riscos do Programa de Gerenciamento de Riscos. a Análise Ergonômica do Trabalho – AET deve abordar as condições de trabalho e incluir as seguintes etapas: a) análise","b":"da demanda; b) análise do funcionamento da organização e das situações de trabalho; c) estabelecimento de diagnóstico; e) recomendações para as situações de trabalho analisadas; e f) restituição dos resultados e validação das propostas junto ao SESMT, onde houver, e à CIPA. nas atividades que exijam sobrecarga muscular estática ou dinâmica do tronco, do pescoço, dos membros superiores","c":"e dos membros inferiores, devem ser adotadas medidas preventivas como ginástica de fortalecimento ou compensatórias, pausas ou rotação de tarefas com o objetivo de eliminar ou reduzir essas sobrecargas, a partir da avaliação ergonômica preliminar.","d":"ao empregador, cabe garantir que os empregados sejam ouvidos durante o processo da avaliação ergonômica preliminar e na Análise Ergonômica do Trabalho – AET, que deve ter o relatório mantido à disposição na organização pelo prazo de 5 (cinco) anos, conforme orientação presente no Direito do Trabalho. a organização do trabalho, para efeito dessa Norma Regulamentadora, deve levar em consideração: a) as normas de","e":"produção; b) o modo operatório, quando aplicável; c) a exigência de tempo; d) o ritmo de trabalho; e) o conteúdo das tarefas e os instrumentos e meios técnicos disponíveis; e f) os aspectos cognitivos que possam comprometer a segurança e a saúde do trabalhador. Segurança e Saúde no Trabalho>NR 17 - Norma Regulamentadora n° 17 - Ergonomia ,","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_285","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio Especializado: Segurança do Trabalho Estabelecer as diretrizes e os requisitos que permitam a adaptação das condições de trabalho às características psicofisiológicas dos trabalhadores, de modo a proporcionar conforto, segurança, saúde e desempenho eficiente no trabalho constitui objetivo da Norma Regulamentadora 17 – Ergonomia. De acordo com essa Norma, é correto afirmar que","a":"para adaptação do mobiliário às dimensões antropométricas do trabalhador, os pedais e demais comandos para acionamento podem receber prolongadores que lhes sejam firmemente acoplados e, em sua utilização repetitiva, não acarretem riscos de quaisquer naturezas ao operador.","b":"o conjunto do mobiliário do posto de trabalho deve apresentar tamanhos variados de alguns de seus elementos, de maneira que sejam possíveis combinações entre eles que permitam compor conjuntos adequados às características antropométricas dos trabalhadores envolvidos e à natureza do trabalho a ser realizado. para trabalho manual, os planos de trabalho devem proporcionar ao trabalhador condições de boa postura,","c":"visualização e operação e devem ter características dimensionais que possibilitem posicionamento e movimentação dos segmentos corporais de forma a não comprometer a saúde e não ocasionar amplitudes articulares excessivas ou posturas nocivas de trabalho. os assentos utilizados nos postos de trabalho devem atender aos seguintes requisitos mínimos: a) altura ajustável; b)","d":"sistemas de ajustes no apoio dos braços e manuseio acessíveis; c) características de adequada conformação à anatomia humana na base do assento; d) borda frontal arredondada; e e) encosto plano e resistente para proteção da região lombar.","e":"para o trabalho sentado, o mobiliário deve oferecer espaço suficiente para pernas e pés na base do plano de trabalho, para permitir que o trabalhador obeso se aproxime o máximo possível do ponto de operação e possa posicionar completamente a região plantar, podendo para tanto utilizar apoio para os pés. Segurança e Saúde no Trabalho>NR 16 - Norma Regulamentadora n° 16 - Atividades e Operações Perigosas ,","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_286","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio","a":"Especializado: Segurança do Trabalho Norma Regulamentadora 16, ao tratar das atividades e operações perigosas, estabelece que para os fins dessa Norma Regulamentadora, são consideradas atividades ou operações perigosas as executadas com A explosivos em cartuchos ou a granel sujeitos a: a) degradação física ou catalítica; b) ação de agentes exteriores, tais como, calor, umidade, faíscas, fogo, fenômenos sísmicos, choque e atritos. as operações de transporte de inflamáveis líquidos ou gasosos liquefeitos, em quaisquer vasilhames e a granel, são","b":"consideradas em condições de periculosidade, exclusão para o transporte em pequenas quantidades, até o limite de 200 (duzentos) litros para os inflamáveis líquidos e 135 (cento e trinta e cinco) quilos para os inflamáveis gasosos liquefeitos.","c":"para efeito dessa Norma Regulamentadora, considera-se líquido combustível todo aquele que possua ponto de combustão maior que 60 ºC (sessenta graus Celsius) e inferior ou igual a 93 ºC (noventa e três graus Celsius).","d":"o exercício de trabalho em condições de periculosidade assegura ao trabalhador a percepção de adicional de 30% (trinta por cento), incidente sobre o salário base da categoria, sem os acréscimos resultantes de gratificações, prêmios ou participação nos lucros da empresa.","e":"é responsabilidade do empregador, por meio do Serviço Especializado em Segurança e em Medicina do Trabalho, onde houver, ou assessoria técnica a caracterização ou a descaracterização da periculosidade, mediante laudo técnico elaborado por Médico do Trabalho ou Engenheiro de Segurança do Trabalho, nos termos do artigo 195 da CLT. Segurança e Saúde no Trabalho>","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3149918","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio","a":"Especializado: Segurança do Trabalho Norma Regulamentadora 15, ao tratar das atividades e operações insalubres, estabelece que se entende por “Limite de Tolerância”, para os fins dessa Norma, a concentração ou intensidade máxima, relacionada A com a natureza e o tempo de exposição ao agente, que não causará danos à saúde do trabalhador, durante a sua vida laboral em condições normais de desempenho da atividade habitual. a eliminação ou neutralização da insalubridade deverá ocorrer: a) com medida de contenção instalada na fonte do","b":"agente ambiental, que impeça a contaminação do ambiente; b) com a adoção de medidas de ordem geral que conservem o ambiente de trabalho dentro dos limites de tolerância; c) com a utilização de equipamento de proteção individual.","c":"no caso de incidência de mais de um fator de insalubridade, será apenas considerado o de grau mais elevado, para efeito de acréscimo salarial, sendo vedada a percepção cumulativa, excetuando-se a situação na qual há certeza científica de ação sinérgica dos agentes no organismo do trabalhador. cabe à autoridade regional competente em matéria de segurança e saúde do trabalhador, comprovada a","d":"insalubridade por laudo técnico de engenheiro de segurança do trabalho ou médico do trabalho, devidamente habilitado, fixar adicional devido aos empregados expostos à insalubridade quando impraticável sua eliminação ou neutralização.","e":"é facultado às empresas, aos sindicatos das categorias profissionais interessadas e ao próprio trabalhador interessado requererem ao Ministério do Trabalho, através das DRT, a realização de perícia em estabelecimento ou setor deste, com o objetivo de caracterizar e classificar ou determinar atividade insalubre. Segurança e Saúde no Trabalho>Normas Regulamentadoras de Ministério do Trabalho e Emprego ,","gabarito":"D","materia":"NR 15 - Norma Regulamentadora n° 15 - Atividades e Operações Insalubres (Acústica","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_288","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio Especializado: Segurança do Trabalho Em conformidade com a Norma Regulamentadora 12 – Segurança no Trabalho em Máquinas e Equipamentos e seus anexos, é correto afirmar que","a":"os sistemas de segurança devem ser selecionados e instalados de modo a atender, entre outros, aos seguintes requisitos: ter categoria de segurança conforme apreciação de riscos prevista nas normas técnicas oficiais, instalação de modo que dificulte a sua burla e possuir conformidade técnica com o sistema de comando a que são integrados. os dispositivos de partida, acionamento e parada das máquinas devem ser projetados, selecionados e instalados de","b":"modo que, ao se localizarem em suas zonas perigosas, possam ser acionados ou desligados em caso de emergência por outra pessoa que não seja o operador, impeçam acionamento ou desligamento involuntário e não permitam a burla. quando forem utilizados dispositivos de acionamento bimanual, visando a manter as mãos do operador fora da zona","c":"de perigo, esses devem ter relação entre os sinais de entrada e saída, de modo que os sinais de entrada aplicados a cada um dos dois dispositivos de atuação devem juntos se iniciar e manter o sinal de saída somente durante a aplicação de pelo menos um dos sinais.","d":"nas máquinas e equipamentos operados por dois ou mais dispositivos de acionamento bimanual, a atuação assíncrona é requerida somente para cada um dos dispositivos de acionamento bimanual e não entre dispositivos diferentes, que devem manter simultaneidade entre si, com retardo tolerável de até meio segundo.","e":"as máquinas móveis devem possuir medidas preventivas quanto à sua estabilidade, de modo que não basculem e não se desloquem intempestivamente por vibrações, choques, forças externas previsíveis, forças dinâmicas internas ou qualquer outro motivo acidental. Segurança e Saúde no Trabalho>Normas Regulamentadoras de Ministério do Trabalho e Emprego ,","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_289","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio","a":"Especializado: Segurança do Trabalho Norma Regulamentadora 12 – Segurança no Trabalho em Máquinas e Equipamentos e seus anexos definem referências técnicas, princípios fundamentais, medidas de proteção e requisitos mínimos para a prevenção de acidentes e doenças do trabalho nas fases de projeto e de utilização de máquinas e equipamentos. De acordo com essa Norma, é correto afirmar que a distância mínima entre máquinas, em conformidade com suas características e aplicações, deve resguardar a A segurança dos trabalhadores durante sua operação, manutenção, ajuste, limpeza e inspeção, e permitir a movimentação dos segmentos corporais, em face da natureza da tarefa.","b":"devem ser promovidas a segregação, o bloqueio e a sinalização que impeçam a utilização de máquinas e equipamentos, que possuam suas partes móveis desprotegidas, enquanto estiverem aguardando reparos, adequações de segurança, atualização tecnológica, desativação, desmonte e descarte. o empregador deve adotar medidas de proteção para o trabalho em máquinas e equipamentos, capazes de","c":"resguardar a saúde e a integridade física dos trabalhadores, obedecendo à seguinte ordem de prioridade: a) medidas de proteção coletiva; b) medidas administrativas como a capacitação; c) medidas de organização do trabalho, que reduzam a exposição aos riscos e d) medidas de proteção individual.","d":"ao realizar qualquer tipo de alteração nas proteções mecânicas ou dispositivos de segurança de máquinas e equipamentos que opera, o trabalhador deverá dar ciência ao chefe imediato, garantindo que as mudanças promovidas não irão redundar em risco a sua saúde e integridade física ou de terceiros. os quadros ou painéis de comando das máquinas e equipamentos devem atender aos seguintes requisitos mínimos","e":"de segurança: a) possuir porta de acesso mantida permanentemente aberta, exceto nas situações de manutenção, pesquisa de defeitos e outras intervenções, devendo ser observadas as condições previstas nas normas técnicas oficiais ou nas normas internacionais aplicáveis. Segurança e Saúde no Trabalho>","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3149915","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio Especializado: Segurança do Trabalho De acordo com a Norma Regulamentadora 10 – Segurança em Instalações e Serviços em Eletricidade, é correto afirmar que somente serão consideradas desenergizadas as instalações elétricas liberadas para trabalho, mediante os seguintes","a":"procedimentos: a) seccionamento; b) impedimento de reenergização acidental ou voluntária; c) constatação da ausência de corrente; d) instalação de aterramento temporário com equalização dos condutores dos circuitos e e) proteção dos elementos energizados.","b":"os estabelecimentos com carga instalada superior a 50 kW devem constituir e manter o Prontuário de Instalações Elétricas, contendo, entre outros dados, os resultados dos testes de isolação elétrica realizados em ferramentas portáteis, equipamentos de proteção individual e coletiva.","c":"é considerado trabalhador legalmente capacitado aquele que atenda às seguintes condições, simultaneamente: a) tenha concluído curso técnico em eletrotécnica na rede oficial de ensino e b) trabalhe sob a responsabilidade de profissional autorizado e habilitado.","d":"nos trabalhos em instalações elétricas, quando as medidas de proteção coletiva forem tecnicamente inviáveis ou insuficientes para controlar os riscos, devem ser adotados procedimentos operacionais específicos e adequados às atividades desenvolvidas, em atendimento ao disposto no Programa de Gerenciamento de Riscos.","e":"a capacitação só terá validade para a empresa que capacitou o trabalhador e nas condições estabelecidas pelo profissional habilitado e autorizado responsável pela capacitação, sendo considerados autorizados os trabalhadores qualificados ou capacitados e os profissionais habilitados, com anuência formal da empresa. Segurança e Saúde no Trabalho>","gabarito":"E","materia":"NR 10 - Norma Regulamentadora nº 10 - Segurança em Instalações e Serviços em Eletricidade","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3149914","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio Especializado: Segurança do Trabalho Com o propósito de garantir a segurança e a saúde dos trabalhadores que, direta ou indiretamente, interajam em instalações elétricas e serviços com eletricidade, a regulamentação vigente estabelece medidas de controle, medidas de proteção coletiva e medidas de proteção individual. A esse respeito, é correto afirmar que","a":"as empresas estão obrigadas a manter esquemas unifilares e respectivos blocos de potência atualizados das instalações elétricas dos seus estabelecimentos, com as especificações do sistema de aterramento e demais equipamentos e dispositivos de proteção. os estabelecimentos com carga instalada superior a 75 kW devem constituir e manter o Prontuário de Instalações","b":"Elétricas, contendo, além de outras informações, o conjunto de procedimentos e instruções técnicas e administrativas de segurança e saúde, implantadas e relacionadas à Norma Regulamentadora 10 e descrição das medidas de controle existentes.","c":"na impossibilidade de desenergizar ou implantar dispositivo de seccionamento automático, devem ser utilizadas outras medidas de proteção coletiva, tais como: isolação das partes vivas, obstáculos, barreiras, sinalização, bloqueio do religamento automático e treinamento diário intensivo sobre os perigos elétricos no ambiente de trabalho.","d":"é vedado o uso de adornos pessoais condutores de eletricidade nos trabalhos com instalações elétricas ou em suas proximidades, devendo as vestimentas de trabalho serem adequadas às atividades, devendo contar com tratamento superficial que contemple a condutibilidade, inflamabilidade e influências eletromagnéticas.","e":"as empresas que operam em instalações ou equipamentos integrantes do sistema elétrico de potência devem constituir prontuário de instalações elétricas e acrescentar os documentos seguintes: a) descrição dos procedimentos de prevenção e combate a incêndios e b) certificações dos equipamentos de proteção coletiva e individual utilizados. Segurança e Saúde no Trabalho>","gabarito":"B","materia":"NR 10 - Norma Regulamentadora nº 10 - Segurança em Instalações e Serviços em Eletricidade","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3149913","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio Especializado: Segurança do Trabalho Em conformidade com a Norma Regulamentadora 7 – Programa de Controle Médico de Saúde Ocupacional – PCMSO, é correto afirmar que","a":"se espera que o PCMSO descreva os possíveis agravos à saúde relacionados aos riscos ocupacionais identificados e classificados no Programa de Gerenciamento de Riscos e contenha parâmetros para análise quantitativa dos metabólitos associados aos agentes químicos encontrados no meio ambiente de trabalho.","b":"é permitida a interpretação de radiografias digitais, para fins de classificação radiológica da Organização Internacional do Trabalho – OIT, nas seguintes condições: radiografias em monitores comparadas com as radiografias-padrão em negatoscópio, ou o inverso e radiografias digitais impressas em filmes radiológicos. nas funções com indicação de uso de equipamentos individuais de proteção respiratória, os empregados com","c":"histórico de doença respiratória crônica ou sinais e sintomas respiratórios devem ser submetidos a espirometria no exame médico admissional, no exame de mudança de risco e periodicamente, a intervalos não superiores a 6 (seis) meses. no exame demissional, o exame clínico deve ser realizado em até 10 (dez) dias contados do término do contrato,","d":"podendo ser dispensado caso o exame clínico ocupacional mais recente tenha sido realizado há menos de 135 (centro e trinta e cinco) dias, para as organizações graus de risco 1 e 2, e há menos de 90 (noventa) dias, para as organizações graus de risco 3 e 4.","e":"compete ao empregador: a) garantir a elaboração e efetiva implantação do PCMSO; b) custear sem ônus para os trabalhadores que atuam no estabelecimento todos os procedimentos relacionados ao PCMSO; c) indicar médico do trabalho responsável pelo PCMSO. Segurança e Saúde no Trabalho>","gabarito":"D","materia":"NR 7 - Norma Regulamentadora n° 7 - Programa de Controle Médico de Saúde Ocupacional - PCMSO (Avaliação Periódica)","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3149912","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio Especializado: Segurança do Trabalho Para que o Programa de Controle Médico de Saúde Ocupacional – PCMSO seja desenvolvido em conformidade com a legislação vigente, faz-se necessário que ele","a":"traga em seu escopo a vigilância reativa da saúde ocupacional, por meio de exames médicos dirigidos que incluam, além dos exames previstos no corpo da Norma Regulamentadora, a coleta de dados sobre sinais e sintomas de agravos à saúde dos trabalhadores relacionados aos riscos ocupacionais.","b":"possua entre suas diretrizes o fato de subsidiar o encaminhamento de empregados à Previdência Social e a missão de definir a aptidão de cada empregado para exercer suas funções ou tarefas determinadas, colaborando para a área de recursos humanos da organização na lotação de cada novo colaborador.","c":"tenha entres suas diretrizes subsidiar análises epidemiológicas e estatísticas sobre os agravos à saúde e sua relação com os riscos ocupacionais e inclua ações de vigilância passiva da saúde ocupacional, a partir de informações sobre a demanda espontânea de empregados que procurem serviços médicos.","d":"descreva os possíveis agravos à saúde relacionados aos riscos ocupacionais identificados e classificados no Programa de Gerenciamento de Riscos; contenha planejamento de exames médicos clínicos, prospectivos e complementares necessários, conforme os riscos ocupacionais identificados.","e":"tenha autonomia para, por meio de seu coordenador, decidir sobre o afastamento de empregados de situações de trabalho que possam comprometer sua saúde, além de subsidiar a emissão de notificações de agravos relacionados ao trabalho, de acordo com a regulamentação pertinente. Segurança e Saúde no Trabalho>","gabarito":"C","materia":"NR 7 - Norma Regulamentadora n° 7 - Programa de Controle Médico de Saúde Ocupacional - PCMSO (Avaliação Periódica)","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3149911","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio Especializado: Segurança do Trabalho De acordo com a Norma Regulamentadora 6 – Equipamentos de Proteção Individual – EPI, é correto afirmar que","a":"a seleção do EPI deve ser registrada, podendo integrar ou ser referenciada no Programa de Gerenciamento de Riscos – PGR, devendo conter suas características construtivas e potencial de proteção, assim como a justificativa de sua escolha em detrimento da proteção coletiva.","b":"a seleção do EPI deve ser realizada pela organização com a participação do Serviço Especializado em Engenharia de Segurança e em Medicina do Trabalho – SESMT, quando houver, após ouvidos empregados usuários e a Comissão Interna de Prevenção de Acidentes – CIPA ou nomeado.","c":"a adaptação do EPI para uso por pessoa com deficiência feita pelo fabricante ou importador detentor do Certificado de Aprovação (CA) não invalida o certificado já emitido, sendo necessária a declaração do fabricante ou importador que as características de proteção do modelo original foram preservadas.","d":"os óculos e as máscaras semifaciais de tela propiciam proteção adequada aos cortadores de cana, apresentando a vantagem de não embaçarem em condições de calor intenso, que é comum na época da colheita da cana. cabe ao trabalhador, quanto ao EPI: a) utilizar apenas para a finalidade a que se destina; b) comunicar à organização","e":"quando extraviado, danificado ou qualquer alteração que o torne impróprio para uso e c) responsabilizar-se pela higienização e manutenção periódica, quando aplicáveis esses procedimentos, em conformidade com as informações fornecidas pelo fabricante ou importador.","gabarito":"B","materia":"NR 6 - Norma Regulamentadora n° 6 - Equipamentos de Proteção Individual - EPI","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3149910","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio Especializado: Segurança do Trabalho Para que seja atendida a legislação vigente sobre o uso de equipamentos de proteção individual na proteção respiratória, é necessário que","a":"seja prescrito o respirador purificador de ar não motorizado, com peça semifacial filtrante para partículas PFF3, para proteção das vias respiratórias contra poeiras e névoas e com peça semifacial filtrante para partículas PFF1 para proteção das vias respiratórias contra poeiras, névoas, fumos e radionuclídeos. seja usado o respirador purificador de ar motorizado com vedação facial tipo touca com anteparo tipo protetor facial,","b":"capuz ou capacete com filtros para partículas para proteção das vias respiratórias contra material particulado; ou com filtros químicos para proteção contra gases e vapores; ou com filtros combinados para proteção contra material particulado e/ou gases e vapores.","c":"para proteger as vias respiratórias dos trabalhadores contra particulados ácidos ou altamente ionizados, lhes sejam fornecidos respiradores purificadores motorizados com vedação facial tipo peça semifacial ou facial inteira com filtros para partículas com tratamento superficial para neutralização ou retenção do material particulado em suspensão. seja selecionado o respirador tipo purificador de ar para fuga, com bocal e pinça nasal, capuz ou peça facial, para","d":"proteção das vias respiratórias contra gases e vapores, ou contra material particulado, quando utilizado com filtros combinados, em condições de escape de atmosferas perigosas com concentração de oxigênio maior que 12,5% ao nível do mar.","e":"para proteção das vias respiratórias em operações de jateamento e em atmosferas com concentração de oxigênio maior que 12,5% ao nível do mar, seja usado o respirador de adução de ar tipo linha de ar comprimido sem vedação facial de fluxo contínuo tipo capuz ou capacete. Segurança e Saúde no Trabalho>","gabarito":"E","materia":"NR 6 - Norma Regulamentadora n° 6 - Equipamentos de Proteção Individual - EPI","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3149909","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio Especializado: Segurança do Trabalho De acordo com os dispositivos presentes na Norma Regulamentadora 5 – Comissão Interna de Prevenção de Acidentes e de Assédio – CIPA, é correto afirmar que inexistindo obrigação de o estabelecimento constituir CIPA e este não for atendido por SESMT, a organização nomeará","a":"um representante da organização dentre seus empregados para auxiliar na execução das ações de prevenção em segurança e saúde no trabalho, podendo ser adotados mecanismos de participação dos empregados, por meio de negociação coletiva.","b":"o presidente e o vice-presidente da CIPA constituirão, dentre seus membros titulares, a comissão eleitoral, que será a responsável pela organização, acompanhamento e validação do processo eleitoral.","c":"na inexistência de mais suplentes, para suprir vacância definitiva surgida durante os primeiros 3 (três) meses do mandato, a organização deve realizar eleição extraordinária para suprir a vacância, que somente será considerada válida com a participação de, no mínimo, um terço dos trabalhadores.","d":"ocorrendo de a organização contratada para prestação de serviços a terceiros exercer suas atividades em estabelecimento de contratante, que tenha condições insalubres ou perigosas de trabalho, esta deve constituir CIPA própria nesse estabelecimento, considerando o grau de risco da contratante o treinamento deve contemplar, entre outros, no mínimo, os seguintes itens: noções sobre as legislações trabalhista,","e":"sanitária e previdenciária relativas à segurança e saúde no trabalho e noções sobre acidentes e doenças relacionadas ao trabalho decorrentes das condições de trabalho e da exposição aos riscos existentes no estabelecimento e suas medidas de prevenção. Segurança e Saúde no Trabalho>","gabarito":"A","materia":"NR 5 - Norma Regulamentadora nº 5 - Comissão Interna de Prevenção de Acidentes- CIPA","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3149908","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio Especializado: Segurança do Trabalho Entre as atribuições da Comissão Interna de Prevenção de Acidentes e de Assédio – CIPA, conforme definido na regulamentação vigente, consta que","a":"cabe à CIPA, considerando os levantamentos ambientais recentes realizados no estabelecimento, registrar a percepção de riscos dos trabalhadores por meio do mapa de risco e encaminhá-lo ao Serviço Especializado em Segurança e em Medicina do Trabalho – SESMT, onde houver, ou ao empregador, para ciência.","b":"seus membros devem elaborar e acompanhar plano de trabalho que possibilite a ação corretiva em segurança e saúde no trabalho e participar no desenvolvimento e na implementação de programas relacionados à segurança e à saúde no trabalho, sugerindo melhorias e angariando maior participação dos trabalhadores. ela deverá acompanhar a análise de acidentes e doenças relacionadas ao trabalho, nos termos da Norma","c":"Regulamentadora 1, e propor, quando for o caso, medidas para a solução dos problemas identificados e incluir temas referentes à prevenção e ao combate ao assédio sexual e a outras formas de violência no trabalho nas suas atividades e práticas.","d":"a Comissão deverá promover, junto aos trabalhadores do estabelecimento, levantamento qualitativo de perigos e promover avaliação da exposição ocupacional aos perigos identificados, bem como da eficácia das medidas de prevenção implementadas pela organização.","e":"a CIPA deverá propor ao SESMT, quando houver, ou à organização, a análise das condições ou situações de trabalho nas quais considere haver risco grave à segurança e saúde dos trabalhadores e, se for risco iminente, interromper as atividades até a adoção das medidas corretivas e de controle. Segurança e Saúde no Trabalho>","gabarito":"C","materia":"NR 5 - Norma Regulamentadora nº 5 - Comissão Interna de Prevenção de Acidentes- CIPA","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3149906","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio Especializado: Segurança do Trabalho Os parâmetros e os requisitos para constituição e manutenção dos Serviços Especializados em Segurança e Medicina do Trabalho – SESMT estão estabelecidos na Norma Regulamentadora 4. De acordo com essa norma, é correto afirmar que","a":"os integrantes do SESMT têm a atribuição de interromper as atividades e adotar as medidas corretivas e/ou de controle quando constatar condições ou situações de trabalho que estejam associadas a grave e iminente risco para a segurança ou a saúde dos trabalhadores.","b":"cabe ao Serviço Especializado em Segurança e Medicina do Trabalho constituir, em conjunto com a CIPA, grupo de trabalho para proceder à investigação e análise de acidentes de trabalho, em conformidade com o previsto no Programa de Gerenciamento de Riscos previsto na Norma Regulamentadora 1. os profissionais integrantes do SESMT devem possuir formação e registro profissional em conformidade com o","c":"disposto na regulamentação da profissão e nos instrumentos normativos emitidos pelo respectivo conselho profissional, quando existente, sendo que o SESMT deve ser coordenado por um dos profissionais integrantes desse serviço. aos profissionais do SESMT, é vedado o exercício de atividades que não façam parte das atribuições previstas nessa","d":"Norma Regulamentadora e em outras Normas Regulamentadoras aplicáveis no ambiente de trabalho, salvo quando previsão própria inscrita em Convenção Coletiva de Trabalho devidamente registrada na Superintendência Regional do Trabalho e Emprego.","e":"os profissionais do SESMT devem responsabilizar-se pela orientação quanto ao cumprimento das Normas Regulamentadoras aplicáveis às atividades da organização, justificando, perante a auditoria fiscal do trabalho, a escolha dos equipamentos de proteção individual como medida de proteção dos trabalhadores. Segurança e Saúde no Trabalho>Normas Regulamentadoras de Ministério do Trabalho e Emprego ,","gabarito":"C","materia":"NR 4 - Norma Regulamentadora n° 4 - Serviços Especializados em Eng. de Segurança e em Medicina do Trabalho - SESMT","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_299","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio","a":"Especializado: Segurança do Trabalho norma que estabelece as diretrizes para caracterização do grave e iminente risco e os requisitos técnicos objetivos de embargo e interdição é a Norma Regulamentadora 3 – Embargo e Interdição. De acordo com ela, é correto afirmar: a metodologia de avaliação quantitativa prevista nessa norma possui a finalidade específica de caracterização de A situações de grave e iminente risco pelo Auditor Fiscal do Trabalho, não se constituindo em metodologia padronizada para gestão de riscos pelo empregador.","b":"na avaliação dos riscos, a classificação das consequências como leve significa, como princípio geral, que pode prejudicar a integridade física e/ou a saúde, provocando lesão que implique em incapacidade temporária da vítima por prazo igual ou inferior a 15 (quinze) dias.","c":"na caracterização de grave e iminente risco ao trabalhador, o Auditor Fiscal do Trabalho deverá estabelecer a inaceitabilidade do risco por meio da comparação entre o risco atual (situação perigosa) e o risco de referência (situação controlada, com medidas preventivas adequadas), em que o risco residual é desprezível.","d":"considera-se grave e iminente risco toda condição ou situação de trabalho que possa causar acidente ou doença com lesão grave ao trabalhador, na qual as medidas elementares de prevenção estão ausentes e inexiste tolerância para o erro humano.","e":"ao realizar a classificação das probabilidades de ocorrência de acidentes ou doenças relacionadas ao trabalho, o auditor fiscal deverá entender como remota essa probabilidade em que há medidas de prevenção adequadas e com garantia de continuidade dessa situação, na qual uma consequência grave não é esperada. Segurança e Saúde no Trabalho>NR 1 - Norma Regulamentadora nº 1 - Disposições Gerais ,","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_300","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio Especializado: Segurança do Trabalho De acordo com a Norma Regulamentadora 1 – Disposições Gerais e Gerenciamento de Riscos Ocupacionais, é correto afirmar que","a":"cabe ao empregador, entre outros deveres, informar aos trabalhadores os resultados das avaliações ambientais realizadas nos locais de trabalho e permitir que representantes dos trabalhadores acompanhem a fiscalização dos preceitos legais e regulamentares sobre segurança e saúde no trabalho.","b":"o empregador deverá, por meio de sua representação na CIPA, incluir regras de conduta a respeito do assédio moral e de outras formas de violência psicológica nas normas internas da empresa, com ampla divulgação do seu conteúdo aos empregados e às empregadas próprias e terceirizadas.","c":"todo trabalhador, ao ser admitido ou quando mudar de função que implique em alteração de risco ou retornar após afastamento superior a 30 (trinta) dias, deve receber informações sobre os riscos ocupacionais que existam ou possam originar-se nos locais de trabalho e os meios para prevenir e controlar tais riscos.","d":"sempre que várias organizações realizam atividades no mesmo local de trabalho, poderão, sob gestão da responsável pelo estabelecimento, executar ações integradas para aplicar as medidas de prevenção, visando à proteção de todos os trabalhadores expostos aos riscos ocupacionais.","e":"o Inventário de Riscos Ocupacionais deverá descrever os perigos e possíveis agravos à saúde dos trabalhadores, identificar as fontes, descrever os riscos gerados pelos perigos, indicar os grupos de trabalhadores sujeitos a esses riscos, descrever os principais comportamentos de risco e as medidas de prevenção. Segurança e Saúde no Trabalho>NR 1 - Norma Regulamentadora nº 1 - Disposições Gerais ,","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_301","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio","a":"Especializado: Segurança do Trabalho Norma Regulamentadora 1 – Disposições Gerais e Gerenciamento de Riscos Ocupacionais, entre seus dispositivos, define que a organização deve implementar medidas de prevenção, ouvidos os trabalhadores, de acordo com a seguinte ordem de prioridade: I. eliminação dos perigos; II. minimização e controle dos perigos, com a adoção de proteção coletiva; III. A minimização e controle dos riscos associados à exposição aos perigos, com a adoção de medidas de proteção individual.","b":"a Subsecretaria de Inspeção do Trabalho – SIT é o órgão de âmbito nacional competente para, entre outras atribuições, formular e propor as diretrizes, as normas de atuação e supervisionar a fiscalização da área de segurança e saúde do trabalhador e promover o Congresso Nacional de Prevenção de Acidentes do Trabalho – CONPAT.","c":"a Secretaria do Trabalho – STRAB tem a competência para coordenar e fiscalizar o Programa de Alimentação do Trabalhador – PAT e promover o cumprimento dos preceitos legais e regulamentares sobre Segurança e Saúde no Trabalho – SST nos contratos, acordos e convenções coletivas de trabalho firmados em todo o território nacional. cabe ao empregador cumprir e fazer cumprir as disposições legais e regulamentares sobre segurança e saúde no","d":"trabalho, incluindo, nos contratos de prestação de serviços de terceiros, cláusulas contratuais relativas à gestão da segurança e saúde no trabalho pertinente às atividades a serem desenvolvidas no estabelecimento sob sua responsabilidade. o trabalhador, que deve cumprir as disposições legais e regulamentares sobre segurança e saúde no trabalho,","e":"inclusive as ordens de serviço expedidas pelo empregador, poderá interromper suas atividades quando constatar uma situação de trabalho onde, a seu ver, envolva um risco grave e iminente para a sua vida e saúde, informando imediatamente ao seu superior hierárquico. Direito Administrativo>Lei nº 8.112-1990 - Regime jurídico dos servidores públicos federais ,","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_302","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio Especializado: Segurança do Trabalho Sormena é servidora pública federal, mas detectou-se que ela está acumulando ilegalmente o seu cargo público de provimento efetivo com um emprego público que assumiu posteriormente ao cargo. Tendo em vista essa situação hipotética, a Lei n° 8.112/90 estabelece que a autoridade competente deverá","a":"instaurar processo administrativo disciplinar para a devida apuração e, atendidos os princípios do contraditório e da ampla defesa, devidamente comprovada a acumulação ilegal, promover a exoneração de Sormena do cargo e do emprego públicos.","b":"notificar a servidora, diretamente, para apresentar opção no prazo improrrogável de trinta dias, contados da data da ciência e, na hipótese de omissão, adotará procedimento sumário para a sua apuração e regularização imediata.","c":"instaurar processo administrativo disciplinar para a devida apuração e, atendidos os princípios do contraditório e da ampla defesa, devidamente comprovada a acumulação ilegal, decretar a demissão de Sormena do emprego público, podendo ela manter o cargo público.","d":"encaminhar o caso ao Ministério Público, para instauração de inquérito para a devida apuração dos fatos e, comprovada a infração disciplinar, a sua demissão do cargo ou do emprego, podendo Sormena manter o que assumiu em primeiro.","e":"notificar a servidora, por intermédio de sua chefia imediata, para apresentar opção no prazo improrrogável de dez dias, contados da data da ciência e, na hipótese de omissão, adotará procedimento sumário para a sua apuração e regularização imediata.","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3149889","enunciado":"Especializado: Segurança do Trabalho Inteligência artificial: a era do “deus” máquina No teatro grego antigo, quando não havia solução para um impasse, um ator interpretando uma divindade descia ao palco pendurado num guindaste, resolvia o problema e, assim, acabava a peça. Era o Deus ex-machina – o deus surgido da máquina. Com o avanço sem precedentes da inteligência artificial (IA), é justo pensar que, no mundo contemporâneo, a máquina é a própria deidade. Para ela, nada parece impossível. Da confecção de discursos em segundos à criação de obras de arte; da identificação de medicamentos promissores ao diagnóstico preciso de doenças, tudo é resolvido pelo “deus algoritmo”. E, ao observar sua invenção “surgindo do guindaste”, o homem pode se perguntar qual lugar ocupará neste enredo. Segundo especialistas,","a":"porém, o perigo não está na criatura e, sim, no uso que o criador faz dela. inteligência artificial faz parte da rotina, ainda que não se perceba. O GPS que indica o percurso, a atendente virtual, o internet banking são exemplos de seu uso no dia a dia. Só que, até agora, ninguém temia os mecanismos de busca dos navegadores, os sistemas de reconhecimento facial dos condomínios ou a sugestão de filmes apresentadas pelos aplicativos de streaming. Então, as máquinas começaram a gerar imagens perfeitas de pessoas inexistentes, escrever reportagens com acurácia, resolver enigmas matemáticos em frações de segundos, dirigir e voar sozinhas, elaborar defesas jurídicas e até “ler” pensamentos em experimentos científicos. A ponto de, em um editorial da revista Science, um grupo de cientistas pedir a moratória de pesquisas até alguma regulamentação ética da IA. A discussão sobre riscos e avanços da IA ultrapassa o campo da ciência da computação; é também filosófica. Já na Grécia Antiga, filósofos questionavam a essência da inteligência e se ela era um atributo somente humano. Hoje, esse é um dos centros da discussão sobre IA: sistemas programados e alimentados por seres humanos poderão ultrapassar em astúcia seus criadores? Não, garante um dos maiores especialistas no tema, o cientista da computação francês Jean-Gabriel Ganascia, da Universidade de Sorbonne que, já em 1980, obteve mestrado em inteligência artificial em Paris. (Paloma Oliveto, Inteligência artificial: a era do ‘deus’ máquina. https://www.correiobraziliense.com.br/ciencia-e-saude. Adaptado) Nas passagens – ... da identificação de medicamentos promissores ao diagnóstico preciso de doenças... (2° parágrafo) – e – ... sistemas programados e alimentados por seres humanos poderão ultrapassar em astúcia seus criadores? (6° parágrafo) –, os termos destacados significam, correta e respectivamente:","b":"A rigoroso; comunicação. exato; esperteza.","c":"necessário; rapidez.","d":"detalhado; originalidade.","e":"pormenorizado; maldade.","gabarito":"B","materia":"Português","tema":"Interpretação de Textos ,Significação Contextual de Palavras e Expressões. Sinônimos e Antônimos.","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3149888","enunciado":"","a":"Especializado: Segurança do Trabalho expressão destacada contém termo(s) em sentido figurado em:","b":"A ... resolver enigmas matemáticos em frações de segundos... (4° parágrafo) ... e se ela era um atributo somente humano. (5° parágrafo)","c":"... o homem pode se perguntar qual lugar ocupará neste enredo. (2° parágrafo)","d":"... ninguém temia os mecanismos de busca dos navegadores... (3° parágrafo)","e":"... descia ao palco pendurado num guindaste... (1° parágrafo)","gabarito":"C","materia":"Português","tema":"Interpretação de Textos ,Denotação e Conotação","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3149885","enunciado":"Especializado: Segurança do Trabalho","a":"Assinale a alternativa em que a reescrita de informações da tira atende à norma-padrão. Franklin, escreva um poema para mim ler, falando no estilo Paulo Leminski.","b":"Franklin, escreva um poema à meu respeito, no estilo de Paulo Leminski.","c":"Me escreva um poema sobre mim, Franklin, no estilo de Paulo Leminski.","d":"Escreva um poema para eu à Paulo Leminski, falando sobre a minha pessoa.","e":"Escreva-me um poema à Paulo Leminski que fale de mim, Franklin. Português>Pontuação ,Uso da Vírgula ,Sintaxe","gabarito":"E","materia":"Português","tema":"Interpretação de Textos ,Redação - Reescritura de texto","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_306","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio Especializado: Segurança do Trabalho","a":"No primeiro e no terceiro quadros, a vírgula tem empregos diferentes, pois separa, correta e respectivamente, o vocativo e o predicado.","b":"o sujeito e o vocativo.","c":"o vocativo e o aposto.","d":"o sujeito e o predicado.","e":"o aposto e o vocativo.","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q3149883","enunciado":"Especializado: Segurança do Trabalho","a":"O efeito de humor na tira tem relação com a incapacidade de o homem escrever um poema, omitida do robô.","b":"a resposta do robô, que mente ao afirmar desconhecer o que seja um poema.","c":"a burrice artificial do robô, mesmo tendo atendido ao pedido do homem.","d":"o desconhecimento expresso pelo robô sobre o que seja poema.","e":"a indignação do robô diante do pedido de escrita de um poema.","gabarito":"D","materia":"Português","tema":"Interpretação de Textos ,Noções Gerais de Compreensão e Interpretação de Texto","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2649427","enunciado":"","a":"Judiciária incompetência do juízo anula _________, devendo o processo, quando for declarada a nulidade, ser remetido ao juiz competente; a nulidade por ilegitimidade do representante da parte poderá ser _________, mediante ratificação dos atos processuais. Nos termos dos artigos 567 e 568 do CPP, assinale a alternativa que completa, correta e respectivamente, as lacunas do texto.","b":"A todos os atos praticados ... sanada até a denúncia todos os atos praticados ... a todo tempo sanada","c":"todos os atos praticados ... sanada somente até o trânsito em julgado","d":"o curso do prazo prescricional ... sanada somente até o trânsito em julgado","e":"somente os atos decisórios ... a todo tempo sanada","gabarito":"E","materia":"Direito Processual Penal","tema":"Nulidades no Processo Penal","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2649426","enunciado":"Judiciária","a":"Com fundamento em hipótese expressamente prevista no artigo 395 do CPP, magistrado rejeita a denúncia. Reconheceu-se falta de justa causa para o exercício da ação penal.","b":"manifesta hipótese de estado de necessidade.","c":"manifesta causa excludente da culpabilidade do agente.","d":"a absolvição sumária do acusado.","e":"legítima defesa por agressão a vítima mantida refém durante a prática de crime.","gabarito":"A","materia":"Direito Processual Penal","tema":"Procedimento Penal ,Procedimento comum ordinário","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2649424","enunciado":"Judiciária","a":"É requisito expresso e inafastável para a formalização do acordo de não persecução penal pena máxima inferior a 2 anos.","b":"assinatura do acusado na presença do magistrado.","c":"renúncia voluntária a bens e direitos indicados pelo Ministério Público como instrumento, produto ou proveito do","d":"crime. reparação do dano.","e":"crime punido, apenas, com multa ou detenção. Direito Processual Penal>Direito processual penal: fundamentos e aspectos essenciais , Princípios fundamentais do direito processual penal ,","gabarito":"C","materia":"Direito Processual Penal","tema":"Ação Penal ,Acordo de Não Persecução Penal","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_311","enunciado":"Aplicação da Lei Penal Processual Penal Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área:","a":"Judiciária lei processual penal aplicar-se-á desde logo, sem prejuízo da validade dos atos realizados sob a vigência da lei anterior. Também é correto afirmar que","b":"A nova lei processual que suprime recursos não pode ser aplicada no processo que julga fato que lhe é anterior. os princípios gerais do direito são aplicados ao processo penal, mas apenas em benefício do acusado.","c":"quanto ao procedimento, o CPP tem primazia em relação a normas processuais estabelecidas em leis especiais.","d":"a lei processual penal admitirá interpretação extensiva e aplicação analógica.","e":"não se admite aplicação subsidiária do CPC no curso de processo penal.","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2649422","enunciado":"","a":"Judiciária conduta de custear organização paramilitar, grupo ou esquadrão com a finalidade de praticar qualquer dos crimes previstos no Código Penal caracteriza crime","b":"A de associação criminosa. de organização criminosa.","c":"de constituição de milícia privada.","d":"hediondo.","e":"contra a incolumidade pública.","gabarito":"C","materia":"Direito Penal","tema":"Crimes contra a paz pública ,Constituição de Milícia Privada","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2649421","enunciado":"Judiciária O sócio que subtrai, para si, a quem legitimamente a detém, a coisa comum fungível que, todavia, não excede a cota parte a","a":"que ele próprio (sócio-agente) tem direito pratica furto qualificado pelo abuso de confiança.","b":"conduta que não é punível.","c":"apropriação indébita.","d":"furto simples.","e":"furto impróprio.","gabarito":"B","materia":"Direito Penal","tema":"Crimes contra o patrimônio","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2649420","enunciado":"Judiciária","a":"Ação que contempla o uso moderado dos meios necessários para repelir injusta agressão iminente a direito de outrem: excludente de imputabilidade.","b":"excludente de culpabilidade.","c":"exercício regular de direito.","d":"excludente de ilicitude.","e":"estado de necessidade de terceiro.","gabarito":"D","materia":"Direito Penal","tema":"Antijuridicidade ,Legítima defesa","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2649419","enunciado":"Judiciária Ficam sujeitos à lei brasileira, embora cometidos no estrangeiro, ainda que o agente seja absolvido ou condenado no","a":"estrangeiro, sem a necessidade de concorrência de qualquer outra condição, os crimes que, por tratado ou convenção, o Brasil se obrigou a reprimir.","b":"praticados em embarcações brasileiras, mercantes ou de propriedade privada, quando em território estrangeiro.","c":"praticados em aeronaves brasileiras, mercantes ou de propriedade privada, quando em território estrangeiro.","d":"contra a administração pública, por quem está a seu serviço.","e":"praticados por brasileiro.","gabarito":"D","materia":"Direito Penal","tema":"Noções Fundamentais ,Lei penal no espaço","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2649417","enunciado":"Judiciária Figure a hipótese em que Caio está condenado por crime e, contra a sentença, interpôs recurso de apelação, ainda não julgado. Por sua vez, Tício fora condenado pelo mesmo crime, contudo, tendo em vista o trânsito em julgado da sentença condenatória, a pena já está sendo executada. Figure, ainda, que na pendência do recurso de apelação de Caio e durante a","a":"execução da pena de Tício, a conduta deixa de ser tipificada criminalmente. Nessa hipótese, é correto afirmar que Caio e Tício terão a punibilidade extinta.","b":"nenhum dos dois terá a punibilidade extinta.","c":"Caio será absolvido, e Tício terá a punibilidade extinta.","d":"apenas Caio terá a punibilidade extinta.","e":"apenas Tício terá a punibilidade extinta.","gabarito":"A","materia":"Direito Penal","tema":"Causas de extinção da punibilidade ,Abolitio criminis","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2649416","enunciado":"Judiciária o No que diz respeito à comunicação eletrônica dos atos processuais, prevista na Lei n 11.419, de 19 de dezembro de 2006, assinale a alternativa correta.","a":"As intimações feitas por meio eletrônico serão consideradas pessoais para todos os efeitos legais, com exceção das intimações da Fazenda Pública e Ministério Público.","b":"Os prazos processuais terão início no primeiro dia útil seguinte ao da disponibilização da informação no Diário da Justiça eletrônico.","c":"As intimações serão feitas por meio eletrônico em portal próprio aos que se cadastrarem, sendo necessária, em complementação durante o período de 2 (dois) anos, a publicação no órgão oficial.","d":"A publicação eletrônica substitui qualquer outro meio e publicação oficial, para quaisquer efeitos legais, inclusive dos casos em que a lei exige intimação pessoal.","e":"Considerar-se-á realizada a intimação no dia em que o intimando efetivar a consulta eletrônica ao teor da intimação, certificando-se nos autos a sua realização. Direito Processual Civil - Novo Código de Processo Civil - CPC 2015>Processo de Execução ,","gabarito":"E","materia":"Legislação Federal","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_318","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Judiciária Luana contratou a construtora X para reformar sua casa. No contrato, assinado por duas testemunhas, restou especificado, de forma detalhada, o objeto, a entrega em no máximo 120 (cento e vinte) dias e a forma de pagamento, em cinco parcelas de R$ 10.000,00 (dez mil reais). No entanto, cinco dias após o início da obra, a construtora X abandonou o projeto sem concluí-lo. Inconformada, Luana decidiu ingressar com uma ação judicial para compelir a construtora X a concluir a reforma","a":"conforme o contrato firmado. Diante da situação hipotética, assinale a alternativa correta. A construtora X será citada para concluir a reforma no prazo que o juiz lhe designar.","b":"O juiz, ao despachar a inicial, fixará multa por período de atraso no cumprimento da obrigação e a data a partir da","c":"qual será devida. Luana deverá, em autos apartados, requerer a satisfação da obrigação à custa do executado.","d":"Por não se tratar de uma obrigação personalíssima, o juiz não pode ordenar a execução específica da reforma, sendo permitido apenas a concessão de indenização por perdas e danos.","e":"Considerando que qualquer outra construtora poderá concluir a reforma, é lícito ao juiz, de ofício, autorizar que Luana conclua a reforma à custa da construtora X. Direito Processual Civil - Novo Código de Processo Civil - CPC 2015>Audiência de Instrução e Julgamento - AIJ ,","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_319","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Judiciária","a":"As provas orais serão produzidas em audiência, ouvindo-se, nesta ordem, preferencialmente, perito e assistente técnico, testemunhas arroladas pelo autor e pelo réu e autor e réu.","b":"réu, autor, testemunhas arroladas pelo réu e pelo autor, perito e assistente técnico.","c":"perito e assistente técnico, autor e réu, testemunhas arroladas pelo autor e pelo réu.","d":"autor, réu, testemunhas arroladas pelo autor e pelo réu, perito e assistente técnico.","e":"testemunhas arroladas pelo réu e pelo autor, perito e assistente técnico e autor e réu.","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2649413","enunciado":"","a":"Judiciária construtora X está sendo processada em um caso complexo de responsabilidade civil devido a problemas estruturais em um edifício. Nesse edifício, vários apartamentos foram afetados, e cada proprietário tem reclamações individuais em relação aos danos causados. No entanto, todos os proprietários afetados desejam que os problemas estruturais sejam resolvidos e que a empresa responsável seja responsabilizada pelos danos. Nessa situação, seria possível que cada proprietário afetado apresentasse com uma ação individual para buscar indenização por danos em seu próprio apartamento. No entanto, devido à complexidade do caso e à similaridade das reclamações, os proprietários decidem se unir em um litisconsórcio multitudinário. Diante da situação hipotética, é correto afirmar que a limitação do litisconsórcio multitudinário","b":"A suspende o prazo para manifestação ou resposta, que recomeçará da intimação da decisão que o solucionar. é causa de extinção do processo.","c":"poderá ser determinada pelo juiz quando o litisconsórcio multitudinário comprometer a rápida solução do litígio ou","d":"dificultar a defesa ou o cumprimento da sentença. poderá ser determinada pelo juiz apenas na fase de conhecimento.","e":"não poderá ser determinada pelo juiz de ofício, em razão do cerceamento de defesa dos envolvidos no processo. Direito Processual Civil - Novo Código de Processo Civil - CPC 2015>Atos Processuais ,","gabarito":"C","materia":"Direito Processual Civil - Novo Código de Processo Civil - CPC 2015","tema":"Litisconsórcio","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_321","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Judiciária Acerca da ordem cronológica de recebimento para publicação e efetivação dos pronunciamentos judiciais, assinale a","a":"alternativa correta. A ordem cronológica deverá, obrigatoriamente, ser atendida pelo escrivão ou chefe de secretaria.","b":"A parte que se considerar preterida na ordem cronológica poderá reclamar, em autos apartados, ao juiz do processo,","c":"que requisitará informações ao servidor, a serem prestadas no prazo de 2 (dois) dias. Não se submetem à ordem cronológica os processos em que a Fazenda Pública seja parte.","d":"Após elaboração de lista própria, respeitar-se-ão a ordem cronológica de recebimento entre os atos urgentes e as preferências legais.","e":"A lista de processos recebidos poderá ser disponibilizada, de forma provisória, para consulta pública mediante solicitação nos autos.","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2649411","enunciado":"Judiciária","a":"Acerca do Direito do Promitente Comprador, assinale a alternativa correta. Tem por requisito o direito a arrependimento.","b":"Deve ser celebrado por instrumento público e registrado no Cartório de Títulos e Documentos, adquirindo o promitente comprador direito real à aquisição do imóvel.","c":"Trata-se de um direito de preferência que tem por efeito a oponibilidade a terceiros, atribuído por lei ao registro","d":"imobiliário do contrato. Tem por requisito a menção expressa no contrato do direito à adjudicação compulsória do imóvel.","e":"Pode ser celebrado por instrumento público ou particular, sendo necessário, em ambos os casos, o registro no Cartório de Registro de Imóveis.","gabarito":"E","materia":"Direito Civil","tema":"Contratos em Espécie ,Compra e Venda","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2649410","enunciado":"Judiciária","a":"Acerca dos títulos de crédito, assinale a alternativa correta. cláusula constitutiva de mandato, lançada no endosso, confere ao endossatário o exercício dos direitos inerentes ao A título, salvo restrição expressamente estatuída; com a morte do endossante, perde eficácia o endosso-mandato.","b":"O possuidor de título ao portador tem direito à prestação nele indicada, mediante a sua simples apresentação ao devedor, sendo certo que a prestação é devida ainda que o título tenha entrado em circulação contra a vontade do emitente.","c":"Considera-se legítimo possuidor o portador do título à ordem com série regular e ininterrupta de endossos, desde que","d":"nenhum seja em branco. Em regra, o título nominativo não pode ser transformado em à ordem ou ao portador.","e":"Ressalvada cláusula expressa em contrário, constante do endosso, não responde o endossante pelo cumprimento da prestação constante do título, sendo certo que, assumindo responsabilidade pelo pagamento, o endossante se torna devedor subsidiário.","gabarito":"B","materia":"Direito Empresarial (Comercial)","tema":"Títulos de Crédito","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2649409","enunciado":"","a":"Judiciária aplicação da cláusula rebus sic stantibus permite ao devedor pedir a resolução da avença","b":"A nos contratos de execução diferida, continuada ou instantânea. apenas nos contratos de execução diferida.","c":"apenas nos contratos de execução continuada.","d":"apenas nos contratos de execução diferida ou continuada.","e":"apenas nos contratos de execução instantânea.","gabarito":"D","materia":"Direito Civil","tema":"Contratos em Geral","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2649408","enunciado":"Judiciária Acerca das benfeitorias, assinale a alternativa correta.","a":"São voluptuárias as de mero deleite ou recreio, que não aumentam o uso habitual do bem, ainda que o tornem mais agradável ou sejam de elevado valor.","b":"São benfeitorias os bens que, não constituindo partes integrantes, se destinam, de modo duradouro, ao uso, ao","c":"serviço ou ao aformoseamento de outro. São necessárias as que aumentam ou facilitam o uso do bem.","d":"São úteis as que têm por fim conservar o bem ou evitar que se deteriore.","e":"São benfeitorias os melhoramentos ou acréscimos sobrevindos ao bem sem a intervenção do proprietário, possuidor ou detentor.","gabarito":"A","materia":"Direito Civil","tema":"Domicílio e Bens ,Parte Geral","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2649407","enunciado":"Judiciária Lucas, residente no Brasil, embarcou em uma viagem para o exterior sem deixar notícias sobre seu paradeiro. Ele estava desaparecido por mais de um ano e sua esposa, seus pais e sua irmã não tinham informações sobre seu estado. Diante dessa situação, sua irmã, Ana, decidiu solicitar a declaração de ausência de Lucas para que fosse nomeado um curador para administrar seus bens. Diante da situação hipotética, assinale a alternativa correta.","a":"O curador nomeado terá a responsabilidade de gerir os bens de Lucas e, após 3 anos de administração, poderá","b":"requerer a sucessão definitiva. Ana será nomeada curadora, uma vez que foi ela quem requereu a declaração de ausência.","c":"Os bens de Lucas serão imediatamente transferidos para Ana para garantir sua administração adequada.","d":"Decorrido o prazo de seis meses da arrecadação dos bens de Lucas, e não havendo interessados na sucessão provisória, cumpre ao Ministério Público requerê-la ao juízo competente.","e":"Decorrido o prazo legal, os credores de obrigações vencidas e não pagas poderão requerer que se declare a ausência e se abra provisoriamente a sucessão. Direito Administrativo>Responsabilidade civil do estado , Evolução da responsabilidade civil estatal - Teoria da irresponsabilidade, teorias civilistas e teorias publicistas ,","gabarito":"E","materia":"Direito Civil","tema":"Personalidade, Pessoa Natural e Capacidade ,Parte Geral","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_327","enunciado":"Previsão constitucional e elementos da responsabilidade civil objetiva do Estado Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Judiciária","a":"Sobre o tema “responsabilidade civil do Estado”, assinale a alternativa correta. Para a Teoria Objetiva, a indenização só será devida se forem constatados o ato, o dano e a culpa do agente.","b":"A Teoria do Risco Integral também é conhecida como Teoria da Irresponsabilidade Estatal.","c":"O Brasil adota, nas relações de Direito Administrativo, a Teoria Publicista do Risco Administrativo.","d":"A ação regressiva é ajuizada pelo particular que sofreu o dano contra o agente público.","e":"A responsabilidade civil do servidor público, no exercício de suas funções, por danos causados a terceiro, é objetiva. Direito Administrativo>Improbidade administrativa - Lei nº 8.429 de 1992 e Lei nº 14.230 de 2021 ,","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_328","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Judiciária","a":"o o Lei n 8.429/1992, com a redação dada pela Lei n 14.230/2021, dispõe sobre as sanções aplicáveis, em virtude da prática de atos de improbidade administrativa. Diante do exposto, é correto afirmar que constitui ato de improbidade administrativa a ação culposa de permitir ou facilitar a aquisição, permuta ou locação de A bem ou serviço por preço superior ao de mercado.","b":"qualquer pessoa poderá representar à autoridade administrativa competente para que seja instaurada investigação destinada a apurar a prática de ato de improbidade.","c":"na hipótese de indícios de ato de improbidade, a autoridade que vier a conhecer dos fatos representará ao Tribunal de Contas competente, para as providências necessárias.","d":"o inquérito civil para apuração do ato de improbidade será concluído no prazo de 360 (trezentos e sessenta) dias","e":"corridos, improrrogáveis. são aplicados ao sistema da improbidade administrativa os princípios constitucionais do direito penal sancionador.","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2649404","enunciado":"Judiciária O controle administrativo é fundamentado no poder de autotutela da Administração sobre suas próprias decisões. Diante","a":"do exposto, é correto afirmar que o recurso hierárquico precede o pedido de reconsideração.","b":"o poder regulamentar e o poder hierárquico não são poderes administrativos.","c":"o pedido de reconsideração é endereçado à autoridade superior à que praticou o ato recorrido.","d":"a possibilidade de interposição de recurso hierárquico impróprio é condicionada à expressa previsão legal.","e":"o recurso hierárquico próprio é endereçado à mesma autoridade que praticou o ato recorrido. Direito Administrativo>Atos administrativos ,","gabarito":"D","materia":"Direito Administrativo","tema":"Controle da administração pública ,Controle administrativo, judicial e legislativo","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_330","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Judiciária Segundo Hely Lopes Meirelles, ato administrativo é “toda manifestação unilateral de vontade da Administração Pública que, agindo nessa qualidade, tenha por fim imediato adquirir, resguardar, transferir, modificar, extinguir e declarar direitos, ou impor obrigações aos administrados ou a si própria.” Diante do exposto, assinale a alternativa correta.","a":"Não cabe ao Poder Judiciário a verificação do mérito do ato administrativo quanto ao atendimento ou não de pressupostos fáticos ensejadores de sua prática pelo administrador.","b":"A jurisprudência pátria atual é tendente a não admitir revisão judicial sobre o mérito dos atos administrativos discricionários, notadamente em relação à razoabilidade ou à proporcionalidade da decisão administrativa.","c":"O juízo de oportunidade tem a ver com a escolha do conteúdo e a intensidade dos efeitos do ato administrativo, cuja inobservância violaria o princípio da oportunidade.","d":"O juízo de conveniência é relacionado ao momento e ao motivo ensejadores da prática do ato, cuja inobservância violaria o princípio da razoabilidade.","e":"Não cabe ao Poder Judiciário substituir o administrador público, mediante a modificação da decisão administrativa, mas sim a anulação do ato discricionário, em caso de desvio de finalidade.","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2649402","enunciado":"Judiciária","a":"Sobre as fundações criadas e mantidas pelo Poder Público, assinale a alternativa correta. As fundações públicas podem ser pessoas jurídicas de direito público ou de direito privado.","b":"As fundações governamentais de direito privado são espécies do gênero autarquia.","c":"Todas as fundações instituídas pelo Poder Público são espécies de autarquias, também denominadas autarquias","d":"fundacionais, portanto, pessoas jurídicas de direito público. As fundações públicas, também denominadas autarquias fundacionais, pertencem à administração pública direta.","e":"As autarquias fundacionais são pessoas jurídicas de direito privado, enquanto as fundações governamentais são pessoas jurídicas de direito público. Direito Constitucional>","gabarito":"A","materia":"Direito Administrativo","tema":"Organização da Administração Pública ,Fundações Públicas","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2649401","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Judiciária Conforme J. J. Gomes Canotilho: “...o poder constituinte se revela sempre como uma questão de poder, de força ou de autoridade política que está em condições de, numa determinada situação concreta, criar, garantir ou eliminar uma Constituição entendida como lei fundamental da comunidade política.” (In: Direito Constitucional, 7 Ed., p. 65) Diante do exposto, é correto afirmar que o poder constituinte","a":"derivado revisor pode ser caracterizado como um poder de fato e que serve de fundamento para os mecanismos de atuação da mutação constitucional.","b":"originário é um poder condicionado e limitado às regras instituídas pelo poder constituinte originário sendo, assim, um poder jurídico.","c":"supranacional busca a sua fonte de validade na cidadania universal, no pluralismo de ordenamentos jurídicos, na vontade de integração e em um conceito remodelado de soberania.","d":"originário reformador tem a capacidade de modificar a Constituição, por meio de um procedimento específico,","e":"estabelecido pelo poder constituinte originário, sem que haja uma verdadeira revolução. difuso é aquele que instaura uma nova ordem jurídica, rompendo por completo com a ordem jurídica precedente.","gabarito":"C","materia":"Poder Constituinte Originário","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2649400","enunciado":"Judiciária","a":"Sobre a ação civil pública, é correto afirmar que esta deverá ser precedida de inquérito civil público.","b":"não tem, por objetivo, a reparação de danos causados à dignidade de grupos religiosos.","c":"o seu ajuizamento consiste em uma das funções privativas do Ministério Público.","d":"o Ministério Público ou outro legitimado assumirá a titularidade ativa da ação, em caso de desistência infundada ou","e":"abandono da ação por associação legitimada. é facultada ao Ministério Público atuação como fiscal da lei, em processos em que não figura como parte.","gabarito":"D","materia":"Direito Constitucional","tema":"Organização dos Poderes","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2649399","enunciado":"Judiciária São legitimados para propor a ação direta de inconstitucionalidade e a ação declaratória de constitucionalidade, dentre","a":"outros, o Conselho Federal da Ordem dos Advogados do Brasil e as entidades de classe de âmbito nacional.","b":"o Presidente da República e o Defensor Público Geral da União.","c":"os Governadores dos Estados e do Distrito Federal e todos os partidos políticos.","d":"o Procurador-Geral da República e o Advogado Geral da União.","e":"os Presidentes do Senado Federal e da Câmara dos Deputados.","gabarito":"A","materia":"Direito Constitucional","tema":"Controle de Constitucionalidade","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2649398","enunciado":"Judiciária O Conselho Nacional de Justiça","a":"é presidido pelo Presidente do Supremo Tribunal Federal e, nas suas ausências e impedimentos, pelo Presidente do","b":"Superior Tribunal de Justiça. é composto de 13 (treze) membros, com mandato de 4 (quatro) anos, admitida 1 (uma) recondução.","c":"tem, em sua composição, dois cidadãos, de notável saber jurídico e reputação ilibada, indicados um pela Câmara dos Deputados e outro pelo Senado Federal.","d":"tem por atribuição, dentre outras, a de rever, de ofício ou mediante provocação, os processos disciplinares de juízes e","e":"membros de tribunais julgados há menos de cinco anos. possui, como membros, três advogados, indicados pelo Conselho Federal da Ordem dos Advogados do Brasil.","gabarito":"C","materia":"Direito Constitucional","tema":"Disposições Gerais no Poder Judiciário ,Poder Judiciário","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2649397","enunciado":"Judiciária","a":"Nos termos da Constituição da República Federativa do Brasil, é correto afirmar que, aos juízes de direito, é permitido dedicar-se à atividade político-partidária.","b":"vedado exercer advocacia no tribunal do qual se afastou, antes de decorridos três anos do afastamento do cargo por","c":"aposentadoria ou exoneração. vedado, exercer um cargo ou função de magistério, ainda que em disponibilidade.","d":"permitido receber contribuições de entidades privadas, desde que de pequeno valor.","e":"permitido receber custas ou participação em processo, desde que mediante declaração à Receita Federal.","gabarito":"B","materia":"Direito Constitucional","tema":"Disposições Gerais no Poder Judiciário ,Poder Judiciário","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2649396","enunciado":"Judiciária o Devido a um corte de pessoal, Maria foi demitida da empresa na qual trabalhava no dia 1 de agosto de 2022. Dois meses depois de sua demissão, Maria ficou grávida, vindo seu filho a nascer no dia 3 de julho de 2023, estando Maria ainda desempregada. Considerando a situação hipotética, é correto afirmar que Maria","a":"mantém a qualidade de segurada, conforme lhe confere a lei, sendo que o salário-maternidade ao qual faz jus","b":"consistirá no valor equivalente ao seu último salário-de-contribuição. não terá direito ao salário-maternidade porque, em razão de estar desempregada, perdeu a qualidade de segurada.","c":"manterá a qualidade de segurada e terá direito ao salário-maternidade se, desde a sua demissão, estiver contribuindo para a Previdência Social na qualidade de contribuinte individual.","d":"manterá a qualidade e terá direito ao salário-maternidade se, desde a sua demissão, estiver contribuindo para a Previdência Social na qualidade de contribuinte facultativa.","e":"mantém a qualidade de segurada, em razão do período que lhe é assegurado por lei, e terá direito ao salário- maternidade que consistirá em um doze avos da soma dos doze últimos salários-de-contribuição, apurados no período não superior a 15 (quinze) meses.","gabarito":"E","materia":"Direito Previdenciário","tema":"Regime Geral de Previdência Social - RGPS ,Beneficiários do RGPS","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2649395","enunciado":"Judiciária o De acordo com o que dispõe a Lei n 8.213/1991 acerca da aposentadoria por invalidez, quando houver recuperação do segurado após o decurso de 5 (cinco) anos, contados da data de início da aposentadoria dessa modalidade, o benefício","a":"será mantido no seu valor integral, durante 12 (doze) meses contados da data em que for verificada a recuperação da capacidade, com redução de 25% (vinte e cinco por cento), no período seguinte de 6 (seis) meses, com redução de 50% (cinquenta por cento), também por igual período de 6 (seis) meses, ao término do qual cessará definitivamente.","b":"cessará após tantos meses quantos forem os anos de duração da aposentadoria por invalidez, no caso do segurador ser declarado apto para o exercício de trabalho diverso do qual habitualmente exercia.","c":"cessará após tantos meses quantos forem os anos de duração da aposentadoria por invalidez, caso a recuperação do segurado seja parcial.","d":"será mantido no seu valor integral, durante 6 meses contados da data em que for verificada a recuperação da capacidade, com redução de 50% (cinquenta por cento), no período seguinte de 6 (seis) meses, com redução de 75% (setenta e cinco), também por igual período de 6 (seis) meses, ao término do qual cessará definitivamente.","e":"cessará de imediato, se o segurado empregado tiver direito a retornar à função que desempenhava quando se aposentou ou venha a ser declarado apto para o exercício de trabalho diverso do qual habitualmente exercia. Direito Previdenciário>Seguridade Social ,","gabarito":"D","materia":"Direito Previdenciário","tema":"Regimes da Previdência Social","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_339","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Judiciária o Conforme disciplina da Lei n 8.212/1991, assinale a assertiva correta no que se refere à participação da União no custeio da Seguridade Social.","a":"Os recursos da Seguridade Social advindos das contribuições sociais das empresas incidentes sobre o faturamento e o lucro são indisponíveis para pagamento dos encargos previdenciários da União.","b":"A União, juntamente com os Estados e os Municípios, responde pela cobertura de eventuais insuficiências financeiras da Seguridade Social, quando decorrentes do pagamento de benefícios de prestação continuada, na forma da Lei Orçamentária Anual.","c":"O Banco Central do Brasil repassará anualmente recursos referentes às contribuições sociais incidentes sobre os concursos de prognósticos destinados à execução do Orçamento da Seguridade Social.","d":"A contribuição da União é constituída de recursos adicionais do Orçamento Fiscal fixados, obrigatoriamente na Lei Orçamentária Anual.","e":"É vedada a utilização dos recursos da Seguridade Social provenientes das contribuições sociais dos empregados domésticos para o financiamento das despesas com pessoas e administração geral do Instituto Nacional de Seguro Social – INSS.","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2649393","enunciado":"Judiciária o De acordo com as alterações trazidas pela Emenda Constitucional n 103 de 2019, em matéria de previdência social, é correto afirmar que o servidor abrangido pelo regime próprio de previdência social será aposentado, no âmbito da União, aos 62 (sessenta","a":"e dois) anos de idade, se mulher, e aos 65 (sessenta e cinco) anos de idade, se homem, e, no âmbito dos Estados, do Distrito Federal e dos Municípios, na idade mínima estabelecida mediante emenda às respectivas Constituições e Leis Orgânicas, observados o tempo de contribuição e os demais requisitos estabelecidos em lei complementar do respectivo ente federativo.","b":"o regime próprio de previdência social aplica-se ao agente público ocupante, exclusivamente, de cargo em comissão declarado em lei de livre nomeação e exoneração, de outro cargo temporário, inclusive mandato eletivo, ou emprego público. a adoção de requisitos ou critérios diferenciados para concessão de benefícios é permitida, ressalvada, nos termos da","c":"lei ordinária, a possibilidade de previsão de idade e tempo de contribuição distintos da regra geral para concessão de aposentadoria exclusivamente em favor dos segurados com deficiência, previamente submetidos a avaliação biopsicossocial realizada por equipe multiprofissional e interdisciplinar.","d":"o servidor abrangido pelo regime próprio de previdência social será aposentado compulsoriamente, com proventos integrais ao tempo de contribuição, aos 56 (cinquenta e seis) anos de idade, ou aos 70 (setenta) anos de idade, observados os demais requisitos exigidos na forma de lei ordinária. é vedada a percepção de mais de uma aposentadoria à conta de regime próprio de previdência social, incluindo-se as","e":"aposentadorias decorrentes dos cargos acumuláveis na forma da Constituição Federal, caso em que o servidor fará jus ao valor mais vantajoso, aplicando-se as demais vedações, regras e condições para a vedação de acumulação de benefícios previdenciários estabelecidas no Regime Geral de Previdência Social.","gabarito":"A","materia":"Direito Previdenciário","tema":"Regimes da Previdência Social","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2649392","enunciado":"Judiciária o Nos termos que dispõe a Lei n 8.742/1993, o benefício de prestação continuada consiste na garantia de um salário-mínimo mensal à pessoa com deficiência e ao idosos com 65 (sessenta e cinco) anos ou mais, que comprovem não possuir meios de prover a própria manutenção ou de tê-la provida por sua família. A esse respeito, é correto afirmar que observados os demais critérios de elegibilidade definidos pela Lei, terão direito ao benefício de prestação continuada","a":"a pessoa com deficiência ou a pessoa idosa com renda familiar mensal per capita igual ou inferior a 1/4 (um quarto) do salário-mínimo, computando-se, para fins do cálculo, os rendimentos decorrentes de estágio supervisionado e de aprendizagem. o benefício de prestação continuada ou o benefício previdenciário no valor de até 1 (um) salário-mínimo concedido a","b":"idoso acima de 65 (sessenta e cinco) anos de idade ou pessoa com deficiência não será computado no cálculo da renda mensal per capital igual ou inferior a 1/4 (um quanto) do salário-mínimo, para fins de concessão do benefício de prestação continuada a outro idoso ou pessoa com deficiência da mesma família.","c":"o benefício de prestação continuada pode ser cumulado pelo beneficiário com qualquer outro no âmbito da seguridade social ou de outro regime, salvo os da assistência médica e da pensão especial de natureza indenizatória.","d":"para efeito de concessão do benefício é considerada pessoa com deficiência aquela que tem impedimento de curto, médio e longo prazo, de natureza física ou mental, a qual em interação com uma ou mais barreiras, pode obstruir sua participação plena e efetiva na sociedade em igualdade de condições com as demais pessoas.","e":"a condição de acolhimento em instituições de longa permanência prejudica o direito do idoso ou da pessoa com deficiência ao benefício de prestação continuada, por demonstrar incompatibilidade com os meios de prover a própria manutenção ou de tê-la provida por sua família.","gabarito":"B","materia":"Direito Previdenciário","tema":"Seguridade Social ,Princípios da Seguridade Social","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2649391","enunciado":"Judiciária No que diz respeito à vigência da legislação tributária, nos termos do Código Tributário Nacional, é correto afirmar que os","a":"convênios que entre si celebrem a União, os Estados, o Distrito Federal e os Municípios, entram em vigor na data de sua publicação.","b":"90 (noventea) dias após a sua publicação, em atendimento à noventena.","c":"na data neles prevista.","d":"no primeiro dia do exercício seguinte ao se sua publicação, em atendimento ao princípio da anterioridade.","e":"30 (trinta) dias após sua publicação.","gabarito":"C","materia":"Direito Tributário","tema":"Legislação do Direito Tributário ,Vigência e Aplicação da Lei Tributária","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2649390","enunciado":"Judiciária Tendo por base as disposições do Código Tributário Nacional, assinale a assertiva correta no que se refere ao instituto da","a":"moratória. lei que a conceder, em caráter geral, deverá especificar o prazo de duração do favor e as garantias que deva, ser A fornecidas pelos contribuintes beneficiados.","b":"Pode ser concedida pela União, quanto a tributos de competência dos Estados, do Distrito Federal ou dos Município, quando, simultaneamente concedida quanto aos tributos de competência federal e às obrigações de direito privado.","c":"Pode ser concedida em caráter individual, por despacho da autoridade administrativa, desde que autorizada por lei, e gera direito adquirido ao contribuinte por ela beneficiado.","d":"Salvo disposição em contrário, abrange somente créditos a serem constituídos à data da lei ou do despacho que a conceder, ou cujo lançamento tenha de ser iniciado anteriormente àquela data por ato regularmente notificado ao sujeito passivo.","e":"Sempre que se apure que o beneficiado deixou de cumprir os requisitos para a concessão do favor, o crédito será acrescido de juros de mora, com imposição da penalidade cabível, independentemente da existência de dolo ou simulação do beneficiado, ou de terceiro em favor daquele.","gabarito":"B","materia":"Direito Tributário","tema":"Suspensão do Crédito Tributário ,Suspensão do Crédito Tributário - Disposições Gerais","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2649389","enunciado":"Judiciária Com relação a tributo sujeito ao lançamento por homologação, considerando-se a jurisprudência dominante das Cortes Superiores, é correto afirmar que, havendo","a":"início de pagamento pelo sujeito passivo, ainda que não integral, o Fisco terá o prazo decadencial de 5 (cinco) anos, contados do primeiro dia do exercício seguinte àquele em que o lançamento poderia ter sido efetuado, para realizar o lançamento suplementar da diferença que entender devida. declaração por parte do sujeito passivo, desacompanhada de qualquer pagamento, o Fisco terá o prazo decadencial","b":"de 5 (cinco) anos, contados do fato gerador, aos quais serão acrescidos mais 5 (cinco) anos, contados do primeiro dia do exercício seguinte àquele em que o lançamento poderia ter sido efetuado, para realizar o lançamento suplementar da diferença que entender devida.","c":"declaração por parte do sujeito passivo, desacompanhada de qualquer pagamento, o Fisco terá o prazo decadencial de 5 (cinco) anos, contados do fato gerador, para efetuar o lançamento suplementar da diferença de valor que entender devida.","d":"declaração por parte do sujeito passivo, desacompanhada de qualquer pagamento, o Fisco terá o prazo decadencial de 5 (cinco) anos, contados do fato gerador, correndo, a partir de então, o prazo prescricional para que o Fisco promova a cobrança judicial da quantia que entender devida.","e":"início de pagamento pelo sujeito passivo, ainda que não integral, o Fisco terá o prazo decadencial de 5 (cinco) anos, contados do fato gerador, para efetuar o lançamento suplementar da diferença de valor que entender devida.","gabarito":"E","materia":"Direito Tributário","tema":"Lançamento Tributário ,Disposições Gerais sobre o Lançamento Tributário","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2649388","enunciado":"Judiciária Pertence à competência da União, além das contribuições sociais e de interesse de interesse de categorias especiais ou econômicas, a instituição de contribuições de intervenção no domínio. Nesse sentido, é correto afirmar, especificamente,","a":"em relação às contribuições sociais e às contribuições de intervenção no domínio econômico, que ambas não incidem sobre as receitas decorrentes de exportação e poderão ter alíquotas ad valorem ou específicas.","b":"as contribuições sociais não incidem sobre a importação de produtos estrangeiros e as contribuições de intervenção no domínio econômico não incidem sobre a importação de serviços.","c":"a pessoa natural destinatária das operações de importação não poderá ser equiparada à pessoa jurídica para fins da exigência das contribuições sociais e das contribuições de intervenção no domínio econômico.","d":"as alíquotas de ambas as contribuições serão consideradas ad valorem quando a base de cálculo do valor a ser recolhido for a unidade de medida adotada.","e":"as alíquotas de ambas as contribuições serão consideradas específicas quando a base de cálculo for o faturamento ou a receita bruta. Direito Tributário>Execução Fiscal e Processo Tributário ,","gabarito":"A","materia":"Direito Tributário","tema":"Competência Tributária","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_346","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Judiciária Nos termos da Norma Federal que rege o Processo Tributário e seu procedimento, é correto afirmar que","a":"no julgamento em instância especial, considerando-se a eficácia e a execução das decisões, caberá pedido de reconsideração de ato do Ministro da Fazenda que julgar ou decidir as matérias de sua competência.","b":"o sujeito passivo poderá formular consulta sobre dispositivos da legislação tributária aplicáveis a fato determinado que suspenderá o prazo para recolhimento de tributo, retido na fonte ou autolançado, antes e depois de sua apresentação, bem como para apresentação de declaração de rendimentos.","c":"no processo de consulta, a decisão de segunda instância obrigará ao recolhimento de tributo que deixou de ser retido ou autolançado após a decisão reformada e de acordo com a orientação desta, no período compreendido entre as datas de ciência das decisões de primeira e segunda instâncias.","d":"a decisão definitiva contrária ao sujeito passivo será cumprida no prazo de 30 (trinta) dias e, esgotado referido prazo sem que tenha sido pago o crédito tributário, o órgão preparador declarará o sujeito passivo remisso e encaminhará o processo à autoridade competente para promover a cobrança executiva.","e":"em primeira instância, o julgamento do processo de consulta compete ao Coordenador do Sistema de Tributação da Secretaria da Receita Federal e, em segunda, ao Superintendente Regional da Receita Federal.","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2649373","enunciado":"Judiciária Leia o texto para responder às questões de números 08 a 10. Minha empregada, Mme. Thérèse, que já ia se conformando em ser chamada de dona Teresa, caiu doente. Mandou-me um bilhete com a letra meio trêmula, falando em reumatismo. Dias depois apareceu, mas magra, mais pálida e menor; explicou-me que tudo fora consequência de uma corrente de ar. Que meu apartamento tem um courant d’air terrível, de tal modo que, ___________, chegando em casa, nem teve coragem de tirar a roupa, caiu na cama. “Dói-me o corpo inteiro, senhor; o corpo inteiro.” O mesmo caso, ajuntou, houve cerca de 15 anos atrás, quando trabalhava em um apartamento que tinha uma corrente de ar exatamente igual ___________ essa de que hoje sou sublocatário. Fez uma pausa. Fungou. Contou o dinheiro que eu lhe entregava, agradeceu ___________ dispensa do troco. Foi lá dentro apanhar umas pobres coisas que deixara. Entregou-me a chave, fez qualquer observação sobre o aquecedor ___________ gás – e depois, no lugar de sair ___________ rua, deixou-se ficar imóvel e calada, de pé, em minha frente. (Rubem Braga, “Dona Teresa”. 200 crônicas escolhidas. Adaptado)","a":"Em conformidade com a norma-padrão, as lacunas do texto devem ser preenchidas, respectivamente, com: aquela tarde … à … à … à … a","b":"aquela tarde … a … a … à … à","c":"àquela tarde … a … a … a … à","d":"àquela tarde … à … à … a … a","e":"àquela tarde … à … a … a … à","gabarito":"C","materia":"Português","tema":"Crase","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2649372","enunciado":"Judiciária Leia o texto para responder às questões de números 03 a 07.","a":"Dengue prevista dengue é uma doença periódica e cíclica: os casos crescem no verão e há picos epidêmicos a cada 4 ou 5 anos. Trata- se, portanto, de enfermidade de atuação previsível. Supõe-se que o poder público se adiantaria com medidas de prevenção e tratamento. Contudo, há décadas os números de casos e mortes só aumentam no Brasil. Entre 2000 e 2010, foram registrados 4,5 milhões de ocorrências e 1.869 óbitos. Na década seguinte, os números saltaram para 9,5 milhões e 5.385, respectivamente. O primeiro semestre deste ano registra 1,4 milhão de casos, ante 1,5 milhão em 2022. A tendência é piorar. Segundo a OMS, urbanização descontrolada e sistema sanitário precário contribuem para o descontrole da moléstia. No Brasil, cerca de 50% da população não tem acesso a redes de esgoto, em grande parte devido à ineficiência estatal, que só agora começa a mudar com o novo marco do setor. E o desmatamento para a construção de moradias irregulares grassa nos grandes centros. A dimensão de áreas verdes derrubadas para esse fim na cidade de São Paulo atingiu, nos primeiros dois meses de 2023, 85 hectares. Neste ano, o município já conta com 11 444 casos de dengue – 3,7% a mais em relação ao mesmo período de 2022. Dez pessoas morreram, o maior número em oito anos, quando houve pico epidêmico. A OMS ressaltou a importância da vacinação. Mas, devido à burocracia, o Brasil protela a distribuição do imunizante japonês Qdenga – já aprovado para venda pela Anvisa – no sistema público de saúde. O combate à dengue deve ser contínuo, não apenas no verão, e em várias frentes complementares (saúde, infraestrutura e moradia). Com o alerta da OMS, espera-se que o poder público, local e federal, se prepare para receber as consequências do fenômeno climático El Niño. (Editorial. Folha de S.Paulo, 27.07.2023. Adaptado) No trecho do primeiro parágrafo – A dengue é uma doença periódica e cíclica: os casos crescem no verão e há picos epidêmicos a cada 4 ou 5 anos. Trata-se, portanto, de enfermidade de atuação previsível. –, os dois-pontos e as vírgulas são empregados, correta e respectivamente, para sinalizar","b":"A a inclusão de informação nova; separar oração intercalada. a inclusão de um contra-argumento; separar conjunção condicional.","c":"a retificação de uma informação; separar aposto explicativo.","d":"o resumo das informações precedentes; separar expressão adverbial.","e":"o detalhamento de uma informação; separar conjunção conclusiva.","gabarito":"E","materia":"Português","tema":"Pontuação","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2649371","enunciado":"","a":"Judiciária reescrita de informações do texto em que se atende à norma-padrão de concordância verbal é:","b":"A Aumenta-se, no verão, os casos de dengue e constata-se picos epidêmicos a cada 4 ou 5 anos. Há picos epidêmicos da dengue a cada 4 ou 5 anos. Tratam-se, portanto, de situações de atuação previsível.","c":"Segundo a OMS, devem-se à urbanização descontrolada e ao sistema sanitário precário o descontrole da moléstia.","d":"São Paulo é um desses grandes centros que convivem com o desmatamento para a construção de moradias.","e":"Ocorre a cada 4 ou 5 anos os picos epidêmicos da dengue, por isso é enfermidade de atuação previsível.","gabarito":"D","materia":"Português","tema":"Sintaxe ,Concordância verbal, Concordância nominal","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2649369","enunciado":"Judiciária Considere as passagens: o • E o desmatamento para a construção de moradias irregulares grassa nos grandes centros. (4 parágrafo) o • ... o Brasil protela a distribuição do imunizante japonês Qdenga... (6 parágrafo) o • O combate à dengue deve ser contínuo... (7 parágrafo)","a":"Os termos destacados significam, correta e respectivamente: difunde-se; prioriza; infrequente.","b":"espalha-se; acelera; interminável.","c":"combate-se; cancela; intermitente.","d":"amplia-se; retarda; irregular.","e":"propaga-se; posterga; ininterrupto.","gabarito":"E","materia":"Português","tema":"Interpretação de Textos ,Paralelismo sintático e semântico","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2649354","enunciado":"Judiciária O editorial enfatiza que o aumento dos casos de dengue é","a":"esperado, configurando um problema de saúde pública que deve ser combatido por meio de frentes complementares orquestradas pelo poder público.","b":"desesperador, aumentando a insegurança da população que se vê acuada nos picos epidêmicos da doença, mesmo com prevenção e tratamento.","c":"improvável, o que dispensa o poder público de organizar os mecanismos de prevenção, como a vacinação da população com o imunizante japonês Qdenga.","d":"sazonal, dispensando atenção sistemática das instâncias governamentais, uma vez que os picos epidêmicos têm sido satisfatoriamente controlados.","e":"insignificante, uma vez que as consequências do El Niño para a população não afetam o sistema de saúde, a infraestrutura e a moradia do país.","gabarito":"A","materia":"Português","tema":"Interpretação de Textos","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2649349","enunciado":"Judiciária Leia a charge para responder às questões de números 01 e 02. (Chargista Ricardo Manhães. https://ndmais.com.br/opiniao/charges, 31.03.2023) Na frase – E se bobear chega a mil facinho! –, a palavra “se” tem o mesmo emprego que a destacada em:","a":"Os moradores do local resolveram ajudar no combate à dengue e se puseram a procurar os focos do mosquito, eliminando-os o mais rápido possível.","b":"O agente de saúde visitou as casas e queria saber se as famílias estavam tomando todas as precauções necessárias para combater a dengue.","c":"A população prometeu acabar com a dengue no bairro e, depois de muita ação contra os focos da doença, alcançaram seu objetivo e se abraçaram felizes.","d":"Muitos focos da dengue foram eliminados em vários bairros da cidade, encontrando-se os mosquitos em locais onde pensavam que eles não estariam.","e":"O combate à dengue dependerá de todos, se houver empenho para exterminar o mosquito, que facilmente prolifera nos locais onde há água parada. Direito Processual Penal>","gabarito":"E","materia":"Português","tema":"Funções morfossintáticas da palavra SE","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646999","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Judiciária - Especialidade: Oficial de Justiça Avaliador Federal","a":"No que concerne ao rito sumaríssimo, é correto afirmar que a denúncia pode ser oralmente oferecida, com redução a termo.","b":"quanto à interposição de apelação e apresentação de razões, seguem-se as regras e prazos do procedimento comum","c":"ordinário. é vedada a condução coercitiva do autor dos fatos.","d":"a resposta à acusação é peça que se exige seja apresentada por escrito.","e":"a sentença deve conter o relatório, ainda que sucinto.","gabarito":"A","materia":"Procedimento comum sumaríssimo - Lei nº 9.099 de 1995 - Lei dos Juizados Especiais Criminais - JECRIM","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Judiciária -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646998","enunciado":"Especialidade: Oficial de Justiça Avaliador Federal Na falta de perito oficial, o exame será realizado por __________, portadora(s) __________, preferencialmente na área específica, dentre as que tiverem habilitação técnica relacionada com a natureza do exame.","a":"Assinale a alternativa que completa, correta e respectivamente, as lacunas do texto. 2 (duas) pessoas idôneas ... de diploma de curso superior","b":"pessoa idônea ... de diploma de curso superior","c":"pessoa ou empresa idônea ... de experiência comprovada","d":"2 (duas) pessoas idôneas ... de experiência comprovada","e":"pessoa idônea ... de, no mínimo, grau técnico","gabarito":"A","materia":"Direito Processual Penal","tema":"Das Provas","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Judiciária -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646997","enunciado":"Especialidade: Oficial de Justiça Avaliador Federal","a":"Faz coisa julgada no juízo cível ou impede a propositura da ação civil a sentença penal que determinar o arquivamento do inquérito policial.","b":"absolver o acusado, decidindo que o fato imputado não constitui crime.","c":"absolver o acusado por não haver prova da existência do fato.","d":"absolver o acusado por ter sido o ato praticado em estado de necessidade.","e":"julgar extinta a punibilidade.","gabarito":"D","materia":"Direito Processual Penal","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Judiciária -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646996","enunciado":"Especialidade: Oficial de Justiça Avaliador Federal","a":"Obsta o acordo de não persecução penal confissão formal e circunstancial de crime que tenha pena de 1 (um) a 3 (três) anos de detenção.","b":"a existência de qualquer condenação por crime praticado no âmbito de violência doméstica ou familiar, mesmo que","c":"ultrapassado o período depurador da reincidência. a existência de infrações penais pretéritas, ainda que insignificantes.","d":"a ausência de reparação do dano ou restituição da coisa à vítima, mesmo que comprovada a impossibilidade do agente.","e":"ter sido o agente beneficiado nos 5 (cinco) anos anteriores ao cometimento da infração em transação penal ou suspensão condicional do processo. Direito da Criança e do Adolescente - Estatuto da Criança e do Adolescente (ECA) - Lei nº 8.069 de 1990>","gabarito":"E","materia":"Direito Processual Penal","tema":"Ação Penal ,Acordo de Não Persecução Penal","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Judiciária -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646994","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Judiciária - Especialidade: Oficial de Justiça Avaliador Federal o É crime, definido na Lei n 8.069/90, adquirir, possuir ou armazenar, por qualquer meio, fotografia, vídeo ou outra forma de registro que contenha cena de sexo explícito ou pornográfica envolvendo criança ou adolescente. Contudo, o tipo prevê","a":"conduta de menor desvalor, em que a pena é diminuída, quando for pequena a quantidade do material.","b":"a identidade da criança ou do adolescente constante do material é preservada.","c":"o material tratar de simulação da participação de criança ou adolescente por meio de adulteração, montagem ou","d":"modificação. não há intuito de lucro.","e":"o adolescente é maior de 14 anos e consente com a prática.","gabarito":"A","materia":"Conceito de Criança e Adolescente e Prioridades","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Judiciária -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646993","enunciado":"Especialidade: Oficial de Justiça Avaliador Federal Configura-se o crime de advocacia administrativa se o funcionário, valendo-se dessa qualidade, patrocina, direta ou","a":"indiretamente, interesse privado perante a administração pública. Na hipótese de o interesse patrocinado ser legítimo, afasta-se o dolo, punindo-se o agente na modalidade culposa.","b":"a configuração típica não se desnatura.","c":"a pena pode ser reduzida de 1 (um) a 2/3 (dois-terços).","d":"o juiz pode deixar de aplicar a pena, se não houver prejuízo para a administração.","e":"o fato é atípico.","gabarito":"B","materia":"Direito Penal","tema":"Crimes contra a administração pública ,Noções Gerais de Crimes Contra a Administração Pública","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Judiciária -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646992","enunciado":"Especialidade: Oficial de Justiça Avaliador Federal Julius está sendo processado pelo crime de latrocínio circunstanciado pelo resultado morte (CP, art. 157, §3º, II). Em sua defesa, alega que o falecimento da vítima ocorreu sem dolo de sua parte, confessando, contudo, que o resultado morte adveio de sua conduta culposa, pois, durante a ação de subtração, o projétil de arma de fogo que matou a vítima fora por si disparado, imprudentemente. Nesse caso, é correto afirmar:","a":"na ausência de dolo, não se pode aplicar a causa de aumento, pois houve concurso formal de crimes, quais sejam,","b":"furto, ameaça e homicídio culposo. aplica-se aumento de pena pelo resultado, pois também é criminalmente típica a conduta preterdolosa.","c":"aplica-se a figura qualificada pela ocorrência do resultado, ainda que este decorra de culpa.","d":"não havendo previsão culposa para o latrocínio, não se pode aplicar a causa de aumento.","e":"na ausência de dolo, não se pode aplicar a qualificadora, pois houve concurso formal de crimes, quais sejam, roubo simples e homicídio culposo.","gabarito":"C","materia":"Direito Penal","tema":"Crimes contra o patrimônio ,Roubo","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Judiciária -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646991","enunciado":"Especialidade: Oficial de Justiça Avaliador Federal","a":"As regras gerais do Código Penal, nos termos de seu art. 12, aplicam-se, apenas, aos fatos incriminados no Código Penal ou leis especiais que assim expressamente prevejam.","b":"aplicam-se aos fatos incriminados por lei especial, se esta não dispuser de modo diverso.","c":"não se aplicam a fatos incriminados por lei especial se a vigência do Código for posterior à da Lei.","d":"não se aplicam a fatos incriminados por lei especial se a vigência do Código for anterior à da Lei.","e":"tem primazia sobre as regras de lei especial, quando esta dispuser de modo diverso.","gabarito":"B","materia":"Direito Penal","tema":"Teoria Geral do Delito","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Judiciária -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646990","enunciado":"Especialidade: Oficial de Justiça Avaliador Federal Aplica-se a lei penal brasileira a fatos ocorridos no interior de aeronaves brasileiras de natureza pública, onde quer que se","a":"encontrem. Também se aplica a lei penal brasileira a fatos ocorridos no interior de aeronaves brasileiras mercantes, onde quer que se encontrem, desde que a vítima seja brasileira.","b":"aeronaves brasileiras mercantes, onde quer que se encontrem, contra qualquer vítima.","c":"aeronaves brasileiras de propriedade privada, sobrevoando território estrangeiro.","d":"embarcações brasileiras mercantes, ancoradas em porto estrangeiro.","e":"embarcações brasileiras de propriedade privada, que estejam em alto-mar.","gabarito":"E","materia":"Direito Penal","tema":"Noções Fundamentais ,Lei penal no espaço","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Judiciária -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646989","enunciado":"Especialidade: Oficial de Justiça Avaliador Federal Pedro é um segurado do Instituto Nacional do Seguro Social (INSS) que teve seu pedido de concessão de aposentadoria por idade negado administrativamente. Ele alega que cumpriu todos os requisitos necessários para a concessão do benefício e","a":"decidiu ingressar com uma ação no Juizado Especial Federal. De acordo com o caso hipotético, assinale a alternativa correta. Pedro poderá designar, por escrito, representantes para a causa, advogados ou não.","b":"O Juizado Especial Federal não é competente para julgar a ação uma vez que não se incluem na competência do Juizado Especial Federal as causas para a anulação ou cancelamento de ato administrativo federal.","c":"O INSS deverá fornecer ao Juizado a documentação de que disponha para o esclarecimento da causa, apresentando-a até a instalação da audiência de instrução e julgamento.","d":"Pedro somente poderá receber os valores relativos à sua aposentadoria se, julgada procedente a ação, ela for confirmada em sede de reexame necessário.","e":"O Juizado Especial Federal não é competente para julgar a ação uma vez que pode ser parte, como ré, apenas a União e não suas autarquias e fundações.","gabarito":"A","materia":"Direito Processual Civil - Novo Código de Processo Civil - CPC 2015","tema":"Juizado Especial ,Juizado Especial Federal","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Judiciária -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646988","enunciado":"Especialidade: Oficial de Justiça Avaliador Federal","a":"No que diz respeito à suspensão do processo, assinale a alternativa correta. A suspensão do processo será própria quando for determinada pelo juiz.","b":"Se houver acordo entre as partes para o requerimento do sobrestamento do feito, não há necessidade de chancela do","c":"magistrado. O pedido de suspensão processual não poderá ser indeferido pelo juiz.","d":"A suspensão do processo será imprópria quando a paralisação for total, com absoluta impossibilidade de se","e":"praticarem os atos do procedimento. A decisão do magistrado que defere a suspensão do processo tem natureza declaratória, operando efeitos ex nunc.","gabarito":"C","materia":"Direito Processual Civil - Novo Código de Processo Civil - CPC 2015","tema":"Suspensão e Extinção do Processo","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Judiciária -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646987","enunciado":"Especialidade: Oficial de Justiça Avaliador Federal Quando a petição inicial for instruída com prova documental suficiente dos fatos constitutivos do direito do autor, a que o réu não oponha prova capaz de gerar dúvida razoável, independentemente da demonstração de perigo de dano ou de risco","a":"ao resultado útil do processo, será concedida tutela antecipada em caráter antecedente.","b":"cautelar em caráter antecedente.","c":"de urgência.","d":"da evidência.","e":"antecipada em caráter incidental.","gabarito":"D","materia":"Direito Processual Civil - Novo Código de Processo Civil - CPC 2015","tema":"Tutela Provisória ,Tutela de Evidência","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Judiciária -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646986","enunciado":"Especialidade: Oficial de Justiça Avaliador Federal","a":"No que diz respeito à distribuição e registro dos processos, assinale a alternativa correta. A distribuição, que poderá ser eletrônica, será alternada e aleatória, obedecendo-se rigorosa igualdade.","b":"Será cancelada a distribuição do feito se a parte, intimada na pessoa de seu advogado, não realizar o pagamento das","c":"custas e despesas de ingresso em 5 (cinco) dias. Todos os processos estão sujeitos a registro e distribuição.","d":"A distribuição poderá ser fiscalizada pela parte, por seu procurador, por terceiros e pelo Ministério Público.","e":"A lista de distribuição dos processos deverá ser publicada no Diário de Justiça, na rede mundial de computadores, no sítio do respectivo tribunal e na plataforma do Conselho Nacional de Justiça. Direito Processual Civil - Novo Código de Processo Civil - CPC 2015>Competência no Processo Civil ,","gabarito":"A","materia":"Direito Processual Civil - Novo Código de Processo Civil - CPC 2015","tema":"Distribuição e Registro","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Judiciária -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_366","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Judiciária - Especialidade: Oficial de Justiça Avaliador Federal Regina e Roberto moravam na cidade de Campo Limpo, casaram-se e tiveram um filho chamado Pedro. Em janeiro de 2021, decidiram se divorciar e, após o divórcio, Pedro, com cinco anos de idade, representado por sua mãe, propôs ação de alimentos em face de seu pai. A ação foi julgada procedente, condenando Roberto ao pagamento mensal de um salário mínimo. Em 2023, Roberto, em razão de uma proposta de emprego no qual receberia o dobro do salário, mudou-se para a cidade de Campos e Regina e Pedro para a cidade de Pontes, na qual o custo de vida era mais alto. Diante das alterações fáticas, Pedro, representado por sua mãe, decidiu propor uma ação revisional de alimentos. Diante da situação hipotética e considerando o disposto no Código de Processo Civil e o atual entendimento do Superior Tribunal de Justiça, a ação","a":"revisional deverá ser proposta na cidade de Campo Limpo, em razão do princípio da perpetuatio jurisdictionis.","b":"deverá ser proposta na cidade de Campos, por ser o novo domicílio de Roberto.","c":"será julgada improcedente, uma vez que o pedido de revisão de alimentos deveria ser feito na própria ação originária.","d":"deverá ser proposta na cidade de Pontes, por ser o novo domicílio de Pedro.","e":"poderá ser proposta em qualquer das comarcas, ficando a critério de Pedro. Estatuto da Pessoa Idosa - Lei nº 10.741 de 2003>Direitos Fundamentais no Estatuto da Pessoa Idosa ,","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Judiciária -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_367","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Judiciária - Especialidade: Oficial de Justiça Avaliador Federal É assegurada a atenção integral à saúde da pessoa idosa, por intermédio do Sistema Único de Saúde (SUS), garantindo-lhe o acesso universal e igualitário, em conjunto articulado e contínuo das ações e serviços, para a prevenção, promoção, proteção e recuperação da saúde, incluindo a atenção especial às doenças que afetam preferencialmente as pessoas","a":"idosas. Acerca do tema, de acordo com o atual entendimento do Superior Tribunal de Justiça, assinale a alternativa correta. previsão de reajuste de mensalidade de plano de saúde em decorrência da mudança de faixa etária de segurado A idoso configura cláusula abusiva.","b":"A possibilidade de pagamento das custas processuais ao final do processo aplica-se somente às ações referentes a interesses difusos, coletivos e individuais indisponíveis ou homogêneos.","c":"O estatuto do idoso tem aplicação imediata sobre todas as relações jurídicas de trato sucessivo, desde que firmadas após a sua vigência.","d":"A intervenção do ministério público nas ações que envolvam o interesse do idoso é obrigatória; o simples fato de a relação jurídico-processual conter pessoa idosa denota parâmetro suficiente para caracterizar a relevância social a exigir a intervenção do ministério público.","e":"A gratuidade dos transportes coletivos públicos urbanos e semiurbanos engloba linha de ônibus especial, que circula nos principais pontos turísticos da cidade, mesmo quando prestados paralelamente aos serviços regulares.","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Judiciária -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646983","enunciado":"Especialidade: Oficial de Justiça Avaliador Federal Matilde contratou um serviço de assinatura de queijos, pelo qual, mediante o pagamento de doze parcelas de R$ 30,00 (trinta reais) para Berenice, receberia, mensalmente, uma cesta com cinco tipos de queijo. No contrato não estava prevista nenhuma hipótese de resolução, por nenhuma das partes, antes de decorrido 12 (doze) meses de contratação. Ocorre que, no quarto mês do contrato, uma bactéria altamente contagiosa contaminou toda a produção de queijo de Berenice, que, para manter as entregas, teve que importar os queijos, tornando o contrato excessivamente oneroso para ela. Diante da situação hipotética, trata-se de hipótese em que é possível","a":"a resolução por onerosidade excessiva, sendo certo que, neste caso, os efeitos de uma eventual sentença que","b":"decretar a resolução do contrato serão ex nunc, desde a formação do contrato. a exceção do contrato não cumprido requerida por Berenice, por se tratar de um contrato bilateral.","c":"o pedido de resolução do contrato apenas por Matilde, cabendo indenização por perdas e danos.","d":"o distrato, por meio do qual Berenice pode extinguir o contrato mediante a denúncia notificada à Matilde.","e":"a modificação equitativa das condições do contrato ofertada por Matilde, para evitar a resolução.","gabarito":"E","materia":"Direito Civil","tema":"Contratos em Geral","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Judiciária -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646982","enunciado":"Especialidade: Oficial de Justiça Avaliador Federal Uma relação de débito e crédito que vincula objeto e sujeitos determinados, mas que não é dotada de exigibilidade, é uma","a":"obrigação disjuntiva.","b":"de garantia.","c":"civil.","d":"de execução diferida.","e":"imperfeita.","gabarito":"E","materia":"Direito Civil","tema":"Direito das Obrigações","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Judiciária -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646981","enunciado":"Especialidade: Oficial de Justiça Avaliador Federal Miguel recebeu procuração de Joana para representá-la durante o período de seis meses em que ela ficará ausente do país. Durante o período, Miguel, como mandatário de Joana, perdoou dívida dela cujo devedor era sua esposa, Pietra. Diante da","a":"situação hipotética, de acordo com o disposto no Código Civil, o perdão da dívida é um negócio jurídico nulo, em razão do excesso de poder caracterizado pelo conflito de interesses entre Miguel e Joana.","b":"anulável, em razão do conflito de interesses entre Miguel e Joana, se tal fato era do conhecimento de Pietra.","c":"anulável, com prazo decadencial de 2 (dois) anos.","d":"nulo, com prazo prescricional de 2 (dois) anos.","e":"válido, considerando que os poderes de representação de Miguel foram conferidos por mandato.","gabarito":"B","materia":"Direito Civil","tema":"Ato Jurídico, Fato Jurídico e Teoria Geral do Negócio Jurídico ,Parte Geral","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Judiciária -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646980","enunciado":"Especialidade: Oficial de Justiça Avaliador Federal Acerca das associações, instituto previsto no Código Civil, é correto afirmar que","a":"sob pena de nulidade, o estatuto das associações conterá, dentre outros requisitos, os direitos e deveres dos associados.","b":"se o estatuto não dispuser o contrário, a qualidade de associado é transmissível desde que previamente autorizada","c":"por 1/5 (um quinto) dos associados. os associados devem ter iguais direitos, sendo vedado ao estatuto instituir categorias com vantagens especiais.","d":"a exclusão do associado só é admissível havendo justa causa, assim reconhecida em procedimento que assegure direito de defesa e de recurso, mediante aprovação de 2/3 (dois terços) dos associados.","e":"se constituem associações pela união de pessoas que se organizem para fins não econômicos, havendo, entre os associados, direitos e obrigações recíprocos.","gabarito":"A","materia":"Direito Civil","tema":"Pessoa Jurídica ,Parte Geral","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Judiciária -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646979","enunciado":"","a":"Especialidade: Oficial de Justiça Avaliador Federal respeito do tema “bens públicos”, assinale a alternativa correta. A Os bens públicos podem ser objetos de usucapião.","b":"São bens de uso comum do povo aqueles que constituem o patrimônio das pessoas jurídicas de direito público, como","c":"objeto de direito pessoal, ou real, de cada uma dessas entidades. São bens dominicais: rios, mares, estradas, ruas e praças.","d":"Os animais silvestres são bens da União.","e":"Não são bens de uso especial os edifícios ou terrenos destinados a serviço ou estabelecimento da administração federal, estadual, territorial ou municipal, inclusive os de suas autarquias.","gabarito":"D","materia":"Direito Administrativo","tema":"Bens Públicos na Administração Pública","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Judiciária -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646978","enunciado":"Especialidade: Oficial de Justiça Avaliador Federal o De acordo com a Lei n 8.112/1990 – regime jurídico dos servidores públicos civis da União, das autarquias e das fundações públicas federais – assinale a alternativa correta. É facultado ao servidor","a":"manter, sob sua chefia imediata, em cargo ou função de confiança, cônjuge, companheiro ou parente até o segundo grau civil.","b":"aliciar subordinados a se filiarem a associação profissional, exceto se se trata de sindicato da categoria a qual pertence o interessado.","c":"requerer licenças para o trato de assuntos particulares pelo prazo de até três anos consecutivos, sem remuneração,","d":"desde que seja ocupante de cargo efetivo e não esteja em estágio probatório. recusar fé a documentos públicos.","e":"promover manifestação de apreço ou desapreço no recinto da repartição. Direito Administrativo>Regime jurídico administrativo ,","gabarito":"C","materia":"Direito Administrativo","tema":"Agentes públicos e Lei 8.112 de 1990 ,Cargo, emprego, função","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Judiciária -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_374","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Judiciária - Especialidade: Oficial de Justiça Avaliador Federal Leading Case: 14 de novembro de 1956. A viúva de um funcionário público alemão mudou-se de Berlim Oriental para Berlim Ocidental, em virtude de promessa de concessão de determinado benefício previdenciário pela Administração. Após receber a vantagem por certo período, tal benefício foi descontinuado, devido à constatação de que o ato de concessão teria sido assinado por autoridade incompetente. O Superior Tribunal Administrativo de Berlim, no entanto, considerou que determinado princípio do Direito Administrativo incidiria com mais força, de modo a afastar o vício de incompetência do ato de concessão.","a":"Diante do exposto, é correto afirmar que o caso narrado se trata especificamente de teoria da finalidade.","b":"teoria do desvio de finalidade.","c":"princípio da legalidade.","d":"princípio da autotutela.","e":"princípio da proteção à confiança legítima.","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Judiciária -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646976","enunciado":"Especialidade: Oficial de Justiça Avaliador Federal o Nos termos da Lei n 8.987/1995 – Concessão e Permissão de Serviços Públicos –, é correto afirmar que","a":"se trata de concessão de serviço público a delegação, a título precário, mediante licitação, da prestação de serviços públicos, feita pelo poder concedente à pessoa física ou jurídica que demonstre capacidade para seu desempenho, por sua conta e risco.","b":"se trata de permissão de serviço público a delegação de sua prestação, feita pelo poder concedente, mediante licitação, na modalidade concorrência ou diálogo competitivo, a pessoa jurídica ou consórcio de empresas que demonstre capacidade para seu desempenho, por sua conta e risco e por prazo determinado.","c":"a concessão de serviço público, precedida ou não da execução de obra pública, será formalizada mediante contrato, prescindível observar o edital de licitação.","d":"as concessões e permissões sujeitar-se-ão à fiscalização pelo poder concedente responsável pela delegação, sem a cooperação dos usuários.","e":"O poder concedente publicará, previamente ao edital de licitação, ato justificando a conveniência da outorga de concessão ou permissão, caracterizando seu objeto, área e prazo.","gabarito":"E","materia":"Direito Administrativo","tema":"Serviços Públicos ,Delegação dos Serviços Públicos - Concessão e Permissão","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Judiciária -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646975","enunciado":"","a":"Especialidade: Oficial de Justiça Avaliador Federal modalidade de extinção do ato administrativo perfeito, com eficácia ex nunc, praticada pela Administração Pública, diante de ausência de condição necessária à permanência da situação jurídica anterior, é denominada","b":"A Conversão. Cassação.","c":"Anulação.","d":"Revogação.","e":"Convalidação.","gabarito":"B","materia":"Direito Administrativo","tema":"Atos administrativos ,Extinção dos atos administrativos","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Judiciária -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646974","enunciado":"Especialidade: Oficial de Justiça Avaliador Federal Paulo, militar do Exército Brasileiro, é adido militar da embaixada brasileira na China. Casado com Joana, também brasileira, de profissão prendas domésticas, tiveram um filho chamado Antônio, nascido na China.","a":"Conforme previsão constitucional quanto à nacionalidade, Antônio é chinês nato.","b":"brasileiro naturalizado.","c":"chinês naturalizado.","d":"brasileiro nato.","e":"apátrida. Direito Constitucional>Organização Político-Administrativa do Estado ,","gabarito":"D","materia":"Direito Constitucional","tema":"Direitos da Nacionalidade","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Judiciária -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_378","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Judiciária - Especialidade: Oficial de Justiça Avaliador Federal Entende-se, por competência legislativa, o poder conferido pela Constituição aos entes federativos, para elaboração de leis. Diante do exposto, é correto afirmar que compete privativamente à União legislar sobre","a":"normas gerais de organização, efetivos, material bélico, garantias, convocação, mobilização, inatividades e pensões","b":"das polícias militares e dos corpos de bombeiros militares. proteção da infância e da juventude.","c":"florestas, caça, pesca, fauna, conservação da natureza, defesa do solo e dos recursos naturais, proteção do meio","d":"ambiente e controle da poluição. proteção e integração social das pessoas portadoras de deficiência.","e":"previdência social, proteção e defesa da saúde.","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Judiciária -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646972","enunciado":"Especialidade: Oficial de Justiça Avaliador Federal","a":"Sobre as comissões parlamentares de inquérito, é correto afirmar que possuem apenas os poderes de investigação próprios das autoridades policiais.","b":"suas conclusões, se for o caso, deverão ser encaminhadas ao Ministério Público, para que promova a responsabilidade civil ou criminal dos infratores.","c":"podem ser criadas pela Câmara dos Deputados ou pelo Senado Federal, separadamente, mediante requerimento da","d":"maioria simples de seus membros. são destinadas à apuração de fato circunstanciado e por prazo indeterminado.","e":"não podem ser criadas pela Câmara dos Deputados e pelo Senado Federal, conjuntamente, mediante requerimento da maioria absoluta de seus membros. Direito Administrativo>Atos administrativos ,","gabarito":"B","materia":"Direito Constitucional","tema":"Poder Legislativo","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Judiciária -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_380","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Judiciária - Especialidade: Oficial de Justiça Avaliador Federal o Dispõe a Constituição da República, artigo 5 , LXXIII: “qualquer cidadão é parte legítima para propor ação popular que vise a anular ato lesivo ao patrimônio público ou de entidade de que o Estado participe, à moralidade administrativa, ao meio ambiente e ao patrimônio histórico e cultural, ficando o autor, salvo comprovada má-fé, isento de custas judiciais e do ônus o da sucumbência.” A Lei n 4.717/1965 – Lei da Ação Popular, recepcionada pela ordem constitucional de 1988, considera nulos os atos lesivos ao patrimônio público, quando constatada a incompetência, o vício de forma, a ilegalidade do objeto, a inexistência dos motivos ou o desvio de finalidade.","a":"Assinale a alternativa que contempla a conceituação legal correta de um dos casos de nulidade. inexistência dos motivos fica caracterizada quando o ato não se incluir nas atribuições legais do agente que o A","b":"praticou. O vício de forma ocorre quando o resultado do ato importa em violação de lei, regulamento ou outro ato normativo.","c":"A ilegalidade do objeto consiste na omissão ou na observância incompleta ou irregular de formalidades indispensáveis à existência ou seriedade do ato.","d":"A incompetência se verifica quando a matéria de fato ou de direito, em que se fundamenta o ato, é materialmente inexistente ou juridicamente inadequada ao resultado obtido.","e":"O desvio de finalidade se verifica quando o agente pratica o ato visando a fim diverso daquele previsto, explícita ou implicitamente, na regra de competência.","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Judiciária -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646964","enunciado":"Especialidade: Oficial de Justiça Avaliador Federal Nos termos da Constituição da República Federativa do Brasil, constitui uma das funções institucionais do Ministério","a":"Público, dentre outras, a promoção, com exclusivamente, da ação penal privada.","b":"representação judicial de entidades públicas.","c":"defesa judicial dos direitos e interesses das populações indígenas.","d":"consultoria jurídica de entidades públicas.","e":"instauração do inquérito policial e a promoção de ação popular para a proteção do patrimônio público e social, do meio ambiente e de outros interesses difusos e coletivos.","gabarito":"C","materia":"Direito Constitucional","tema":"Funções Essenciais à Justiça ,Ministério Público","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Judiciária -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646961","enunciado":"Especialidade: Oficial de Justiça Avaliador Federal o","a":"De acordo com a Lei n 8.213/91, independe de carência a concessão de auxílio-acidente.","b":"auxílio-doença.","c":"aposentadoria especial.","d":"aposentadoria por invalidez.","e":"auxílio-reclusão. Direito Previdenciário>Regimes da Previdência Social ,","gabarito":"A","materia":"Direito Previdenciário","tema":"Regimes da Previdência Social","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Judiciária -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_383","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Judiciária - Especialidade: Oficial de Justiça Avaliador Federal","a":"o respeito do regime de previdência complementar dos servidores públicos federais, com base na Lei n 12.618/12, é correto afirmar que o custeio da entidade de previdência complementar caberá ao patrocinador, sendo vedada a cobrança de taxa de A administração dos servidores públicos.","b":"os servidores que tenham ingressado no serviço público até a data anterior ao início da vigência do regime de previdência complementar não poderão aderir ao seu regime.","c":"a concessão dos benefícios decorrente de invalidez aos participantes ou assistidos pela entidade fechada de previdência social é condicionada à concessão do benefício pelo regime próprio de previdência social.","d":"fica assegurado ao participante o direito de requerer, a qualquer tempo, o cancelamento de sua inscrição e a restituição integral, em sessenta dias, das contribuições vertidas.","e":"não poderá permanecer filiado aos respectivos planos de benefícios o participante afastado ou licenciado do cargo efetivo temporariamente, sem recebimento de remuneração.","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Judiciária -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646957","enunciado":"Especialidade: Oficial de Justiça Avaliador Federal","a":"o respeito das espécies de benefícios, com base no Decreto n 3.048/99, assinale a alternativa correta. É autorizada a conversão de tempo de serviço de magistério, exercido em qualquer época, em tempo de serviço A comum.","b":"A aposentadoria por idade do trabalhador rural somente será devida se, na oportunidade do requerimento da aposentadoria, o segurado se enquadrar como trabalhador rural.","c":"O salário-maternidade, em caso de aborto não criminoso, comprovado mediante atestado médico, será concedido à segurada no valor correspondente a quatro semanas.","d":"Será devido auxílio por incapacidade temporária, independentemente do cumprimento de período de carência, aos","e":"segurados obrigatório e facultativo quando sofrerem acidente de qualquer natureza. A aposentadoria especial não poderá ser concedida ao trabalhador avulso e ao contribuinte individual.","gabarito":"D","materia":"Direito Previdenciário","tema":"Regimes da Previdência Social","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Judiciária -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646955","enunciado":"Especialidade: Oficial de Justiça Avaliador Federal Considere que Maria era casada com João, que infelizmente veio a falecer em acidente automobilístico. João gozava de duas aposentadorias obtidas no Regime Próprio de Previdência Social, enquanto Maria recebe uma aposentadoria obtida no Regime Geral de Previdência Social. A respeito da possibilidade ou não de cumulação de aposentadorias e pensões, nos o","a":"termos da Emenda Constitucional n 103/2019, é correto afirmar que Maria não poderá receber pensão de João, pois a EC vedou a cumulação dos benefícios.","b":"receberá de forma integral e cumulativa a sua aposentadoria e as duas pensões por morte.","c":"continuará recebendo a sua aposentadoria e deverá optar por uma pensão por morte, decorrente das aposentadorias","d":"de João. somente poderia perceber as pensões por morte caso João fosse militar.","e":"poderá perceber as pensões de forma cumulada caso decorram de cargos acumuláveis em atividade.","gabarito":"E","materia":"Direito Previdenciário","tema":"Regimes da Previdência Social","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Judiciária -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646953","enunciado":"","a":"Especialidade: Oficial de Justiça Avaliador Federal respeito dos aspectos constitucionais da Previdência Social, é correto afirmar que A de acordo com a Constituição Federal, para fins previdenciários, o concubinato se equipara à união estável.","b":"a desaposentação não tem amparo expresso na Constituição Federal e a sua não adoção não representa uma violação ao princípio da vedação ao enriquecimento sem causa.","c":"a Constituição Federal autoriza a extensão de benefício social, não previsto em lei, para atender o princípio","d":"constitucional da isonomia, desde que demonstrada a fonte de seu custeio. o Texto Constitucional determina que haja revisão de benefício previdenciário pelo valor nominal do salário-mínimo.","e":"a Constituição Federal autoriza a adesão ao regime geral de previdência social, na qualidade de segurado facultativo, de pessoa participante de regime próprio de previdência.","gabarito":"B","materia":"Direito Previdenciário","tema":"Regimes da Previdência Social","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Judiciária -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646952","enunciado":"Especialidade: Oficial de Justiça Avaliador Federal Suponha que a legislação comercial estabeleça que são confidenciais, pertencendo exclusivamente à sociedade empresária, livros contábeis por ela escriturados. Neste cenário, assinale a alternativa correta, considerando um auditor fiscal, no curso de fiscalização tributária, solicitando cópia dos referidos livros contábeis, de modo a confrontar as informações neles contidas com as informações declaradas ao Fisco.","a":"Tal solicitação deverá ser considerada ilegal, não devendo ser atendida de nenhum modo pela administração da empresa, sob pena de responder legalmente pelos prejuízos perante os sócios da sociedade.","b":"Perderá imediatamente, para todos os efeitos, o caráter de sigilosa a informação contida na documentação contábil a ser apresentada, podendo ser utilizada livremente pelo auditor fiscal, inclusive em relação a fatos não relacionados à fiscalização.","c":"Tal solicitação apenas poderá ser atendida se precedida de autorização judicial, a ser concedida após processo judicial de exibição de documentos, a ser manejado pela Fazenda Pública por intermédio da competente Procuradoria.","d":"Deverá ser dada aplicação à legislação comercial, em detrimento da legislação tributária, posto que a atividade de lançamento tributário se apresenta como atividade plenamente vinculada, sujeitando-se à estrita legalidade.","e":"A solicitação estará em conformidade com o Código Tributário Nacional, que determina que, para fins tributários, não têm aplicação quaisquer disposições legais excludentes do direito de examinar mercadorias, livros, arquivos, documentos, papéis e efeitos comerciais ou fiscais. Direito Tributário>Conceito de Tributo e Espécies Tributárias ,Imposto ,","gabarito":"E","materia":"Direito Tributário","tema":"Administração Tributária ,Fiscalização na Administração Tributária","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Judiciária -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_388","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Judiciária -","a":"Especialidade: Oficial de Justiça Avaliador Federal Entidade Espiritual da Luz Celestial (EELC), uma organização religiosa dedicada à prática da harmonia espiritual e ao culto à paz interior, tomou uma decisão para expandir suas atividades. Após deliberações, a entidade decidiu alugar um galpão industrial abandonado. Durante os três anos que duraram as intensas obras de renovação, a comunidade da EELC permaneceu animada e envolvida. Considerando-se uma entidade imune, a EELC não realizou, desde o aluguel do imóvel, qualquer pagamento à Prefeitura relativo ao imposto sobre propriedade territorial e predial urbana. Para manter todos informados sobre o progresso e criar uma atmosfera de expectativa, uma placa imponente foi afixada na entrada do galpão, exibindo orgulhosamente os dizeres: “Futuras Instalações do Culto A – O Caminho para a Paz Interior”. A placa serviu como um lembrete constante das metas da entidade e reforçou a crença de que o esforço e a paciência valeriam a pena no final. Finalmente, após três anos, a EELC completou a reforma do galpão. As portas do novo templo foram abertas em uma cerimônia emocionante. Entre os presentes na cerimônia de inauguração estava um auditor fiscal de tributos municipais, que, após o serviço religioso, fez a entrega à administração da entidade de notificação de lançamento e cobrança do IPTU relativo aos anos em que o imóvel permaneceu em reforma. A respeito da situação hipotética apresentada, é correto afirmar, com base na Constituição Federal, que: o não pagamento da dívida pela EELC estava justificado não apenas pela sua condição de entidade imune, mas A também pela sua condição de mera locatária do imóvel, a quem não pode ser estendida a responsabilidade tributária.","b":"as entidades religiosas são imunes em relação a quaisquer tributos no âmbito municipal, estadual ou federal, de forma que o não pagamento do imposto municipal sobre propriedade territorial e predial urbana estava correto.","c":"a imunidade existente em relação ao imposto sobre propriedade territorial e predial urbana de imóveis locados por templos de qualquer culto não abrange imóveis que não estejam sendo utilizados para fins religiosos, como na situação descrita.","d":"a fixação da placa pela entidade religiosa em imóvel de terceiro, sinalizando que no local funcionaria, após a conclusão das obras de engenharia civil, um templo religioso, era suficiente para fazer incidir a imunidade tributária de templos de qualquer culto.","e":"o auditor fiscal violou a liberdade de culto e o sentimento religioso dos frequentadores do templo ao comparecer a um evento público de inauguração para fins de notificação da dívida tributária.","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Judiciária -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646949","enunciado":"Especialidade: Oficial de Justiça Avaliador Federal Conforme estabelece o Código Tributário Nacional, fato gerador e obrigação tributária são conceitos conexos, mas não idênticos.","a":"Neste sentido, é correto afirmar que: o fato gerador faz nascer o crédito tributário, independentemente do lançamento tributário tácito ou expresso.","b":"o aspecto quantitativo do fato gerador corresponde à base de cálculo e à alíquota do tributo a ser cobrado.","c":"as obrigações de natureza tributária, tal qual obrigações civis, admitem situações de solidariedade passiva.","d":"o fato gerador corresponde à regra matriz de incidência tributária, podendo ser principal ou acessório.","e":"o aspecto pessoal da obrigação corresponde à figura do contribuinte, entendido este como aquele que, com ou sem relação pessoal com o fato gerador, responde pelo pagamento. Direito Tributário>Conceito de Tributo e Espécies Tributárias ,Imposto ,Taxa e TarifasContribuição de Melhoria ,","gabarito":"C","materia":"Direito Tributário","tema":"Obrigação Tributária ,Fato Gerador","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Judiciária -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_390","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Judiciária - Especialidade: Oficial de Justiça Avaliador Federal Uma das formas tradicionalmente utilizadas pela doutrina para classificar os tributos previstos na Constituição, consiste em separá-los segundo à sua origem e à sua destinação. Assim, haveria tributos que, em sua origem, estariam vinculados a uma atividade específica do estado e tributos que, no momento da sua cobrança, não teriam correlação direta com uma atividade estatal específica. Haveria também tributos que, em relação ao produto da arrecadação, teriam-no vinculado a fundos ou despesas específicas ou tributos cujo produto seria totalmente desvinculado, podendo ser utilizado livremente, conforme disposto na lei orçamentária. Nesta linha de raciocínio, pode-se dizer que um exemplo de tributo que não possui correlação direta com atividade estatal","a":"específica na sua cobrança, mas que tem o produto da sua arrecadação vinculado, são os(as): contribuições de melhoria.","b":"contribuições sociais.","c":"impostos seletivos.","d":"impostos em geral.","e":"taxas em razão do poder de polícia.","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Judiciária -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646944","enunciado":"Especialidade: Oficial de Justiça Avaliador Federal Entre as fontes do direito tributário, há os chamados convênios de cooperação e os convênios de subordinação. Estes consistem especialmente em convênios previstos na Constituição para regular temas de interesse comum na coordenação dos Estados relativamente à cobrança do imposto estadual sobre a circulação de mercadorias e serviços (ICMS). Em relação","a":"a estes convênios, é correto afirmar que: condicionam a validade de leis estaduais que tratem dos assuntos que a Constituição Federal atribui a eles.","b":"estão formal e materialmente sujeitos à revogação por lei estadual posterior, devendo respeitar leis estaduais precedentes.","c":"podem ser alterados mediante tratamento distinto nas respectivas Constituições Estaduais, no âmbito de cada estado da Federação.","d":"têm a mesma tramitação dos tratados internacionais, mas no âmbito dos estados da Federação, devendo ser","e":"assinados pelo Poder Executivo e ratificados pelo Legislativo estadual. são constitucionalmente equivalentes às leis complementares, não sendo, porém, revogáveis por elas.","gabarito":"A","materia":"Direito Tributário","tema":"Legislação do Direito Tributário ,Normas Complementares","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Judiciária -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646931","enunciado":"Especialidade: Oficial de Justiça Avaliador Federal Leia o texto para responder às questões de números 08 a 10. Minha empregada, Mme. Thérèse, que já ia se conformando em ser chamada de dona Teresa, caiu doente. Mandou-me um bilhete com a letra meio trêmula, falando em reumatismo. Dias depois apareceu, mas magra, mais pálida e menor; explicou-me que tudo fora consequência de uma corrente de ar. Que meu apartamento tem um courant d’air terrível, de tal modo que, _________, chegando em casa, nem teve coragem de tirar a roupa, caiu na cama. “Dói-me o corpo inteiro, senhor; o corpo inteiro.” O mesmo caso, ajuntou, houve cerca de 15 anos atrás, quando trabalhava em um apartamento que tinha uma corrente de ar exatamente igual _________ essa de que hoje sou sublocatário. Fez uma pausa. Fungou. Contou o dinheiro que eu lhe entregava, agradeceu _________ dispensa do troco. Foi lá dentro apanhar umas pobres coisas que deixara. Entregou-me a chave, fez qualquer observação sobre o aquecedor _________ gás – e depois, no lugar de sair _________ rua, deixou-se ficar imóvel e calada, de pé, em minha frente. (Rubem Braga, “Dona Teresa”. 200 crônicas escolhidas. Adaptado)","a":"Assinale a alternativa em que o primeiro termo destacado é um pronome com valor possessivo, e o segundo, um adjetivo. Mandou-me um bilhete com a letra meio trêmula, falando em reumatismo.","b":"Entregou-me a chave, fez qualquer observação sobre o aquecedor...","c":"“Dói-me o corpo inteiro, senhor; o corpo inteiro.”","d":"O mesmo caso, ajuntou, houve cerca de 15 anos atrás...","e":"... já ia se conformando em ser chamada de dona Teresa, caiu doente.","gabarito":"C","materia":"Português","tema":"Morfologia - Pronomes","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Judiciária -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646921","enunciado":"Enfermagem Uma das diretrizes da Política Nacional de Humanização, que visa qualificar a atenção através da valorização da autonomia","a":"do usuário e na aposta das diferentes especialidades compartilhando cuidados na equipe e com o usuário: hierarquização.","b":"clínica ampliada.","c":"universalidade.","d":"terceirização.","e":"verticalidade.","gabarito":"B","materia":"Direito Sanitário","tema":"Sistema Único de Saúde - SUS","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Especialidade:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646920","enunciado":"Enfermagem Está entre um dos fatores de risco modificáveis para o desenvolvimento de doenças cardiovasculares, com associação a alta","a":"morbimortalidade: diabetes.","b":"hipertensão.","c":"tabagismo.","d":"histórico genético.","e":"idade avançada.","gabarito":"C","materia":"Enfermagem","tema":"Dependência ,Tabagismo","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Especialidade:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646919","enunciado":"Enfermagem Sr. Jaime acompanhava seu estado de saúde na UBS próxima de sua residência, recebendo insumos para seu glicosímetro, orientações de alimentação com baixo índice glicêmico e também sobre lesões que não cicatrizaram em seus pés. De que","a":"doença crônica não-transmissível ele estava cuidando? Hanseníase.","b":"Dependência alimentar.","c":"Hiperinsulinemia.","d":"Trombose.","e":"Diabetes.","gabarito":"E","materia":"Enfermagem","tema":"Diabetes Mellitus ,Saúde do Idoso ,Doenças Crônicas Não Transmissíveis","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Especialidade:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646918","enunciado":"Enfermagem Sobre o dispositivo intrauterino de cobre, disponível para inserção no Sistema Único de Saúde, é correto afirmar que se","a":"trata de um método contraceptivo de: eficácia inferior.","b":"emergência quando inserido cinco dias após um ato desprotegido.","c":"hormônio.","d":"barreira.","e":"baixa permanência.","gabarito":"B","materia":"Enfermagem","tema":"Saúde da Mulher ,Planejamento Familiar","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Especialidade:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646917","enunciado":"Enfermagem O exame para coleta de citopatológico de colo do útero deve seguir rigorosamente alguns cuidados. É correto afirmar, a","a":"esse respeito que: deve-se coletar material da ectocérvice com a espátula de Ayre e da endocérvice com a chamada escovinha.","b":"a coleta de material da endocérvice está dispensada para evitar desconforto e sangramento.","c":"a ectocérvice não deve ser manipulada para coleta de material em gestantes.","d":"utiliza-se ácido acético para melhor deslizamento do espéculo e visualização de lesões no colo uterino.","e":"a colposcopia substitui o exame de colpocitologia oncótica, sendo estes exames de igual acurácia diagnóstica.","gabarito":"A","materia":"Enfermagem","tema":"Enfermagem em Oncologia","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Especialidade:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646916","enunciado":"Enfermagem Uma puérpera no terceiro dia pós-parto apresenta mamas túrgidas, com calor local e desconforto, com anotação de enfermagem incluindo a informação de que está no processo de apojadura. Assinale a alternativa que indica cuidados de","a":"enfermagem para este caso. Drenagem de abscesso e acompanhamento médico.","b":"Esvaziamento das mamas com auxílio de bomba ou ordenha manual para evitar evolução para mastite.","c":"Pausa na amamentação para melhora dos sinais e sintomas.","d":"Orientações sobre a fisiologia do processo e sobre a importância da livre demanda.","e":"Massagem vigorosa e encaminhamento para antibioticoterapia.","gabarito":"D","materia":"Enfermagem","tema":"Saúde da Mulher ,Assistência de Enfermagem ao Parto/Aborto","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Especialidade:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646915","enunciado":"Enfermagem Na assistência a uma mulher que acabou de passar por um parto vaginal, para diminuir o risco de hemorragia pós-parto,","a":"deve-se administrar: vitamina K.","b":"ocitocina.","c":"nitrato de prata a 1%.","d":"imunoglobulina.","e":"ácido valproico.","gabarito":"B","materia":"Enfermagem","tema":"Saúde da Mulher ,Assistência de Enfermagem ao Parto/Aborto","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Especialidade:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646914","enunciado":"Enfermagem Dentre os exames solicitados no pré-natal, assinale a alternativa que apresenta a doença que tem sido um grave problema","a":"de saúde pública e exige tratamento com antibioticoterapia, podendo ocorrer recidivas. HTLV.","b":"toxoplasmose.","c":"sífilis.","d":"hepatites.","e":"anemia ferropriva.","gabarito":"C","materia":"Enfermagem","tema":"Doenças Infecciosas e parasitárias","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Especialidade:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646913","enunciado":"","a":"Enfermagem observação de sinais e sintomas de vaginoses é uma atitude que possibilita tratamento e manejo na atenção primária à saúde, por profissional enfermeiro, no âmbito do SUS. A esse respeito, é correto afirmar: A a menopausa precoce é fator que inibe a ocorrência de vaginoses bacterianas.","b":"a candidíase vulvovaginal recorrente é definida como a ocorrência de pelo menos dois episódios de candidíase em um ano.","c":"a presença de corrimento amarelo espesso, sem queixa de prurido deve ser submetida a exame laboratorial de cultura antes de tentativa de tratamento.","d":"a tricomoníase apresenta quadro característico com prurido intenso e presença de grumos esbranquiçados, sem odor.","e":"placas brancas aderidas na parede vaginal, edema vulvar e escoriações por coceiras são achados característicos da candidíase vaginal.","gabarito":"E","materia":"Enfermagem","tema":"Saúde da Mulher","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Especialidade:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646912","enunciado":"Enfermagem","a":"Durante uma consulta de pré-natal, é realizada a manobra de Leopold que, em seu quarto tempo, consiste em: delimitar o fundo uterino.","b":"pesar corretamente a gestante.","c":"verificar presença de edema em membros inferiores.","d":"determinar a insinuação fetal.","e":"identificar de qual lado está o dorso fetal.","gabarito":"D","materia":"Enfermagem","tema":"Saúde da Mulher ,Assistência de Enfermagem ao Pré-Natal","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Especialidade:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646911","enunciado":"Enfermagem No acolhimento da UBS, em uma situação de queixa de dor abdominal, o enfermeiro recebe a sugestão de auxiliar no","a":"exame físico do abdome. Assinale a alternativa que apresenta a sequência correta em que deve ser avaliada esta região. Ausculta, palpação, percussão e inspeção.","b":"Percussão, palpação, inspeção e ausculta.","c":"Inspeção, ausculta, percussão e palpação.","d":"Palpação, inspeção, ausculta e percussão.","e":"Palpação, percussão, inspeção e ausculta.","gabarito":"C","materia":"Enfermagem","tema":"Urgência e emergência ,Primeiros Socorros","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Especialidade:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646910","enunciado":"Enfermagem","a":"Após lesão por picada de cobra não identificada, ao procurar o pronto atendimento, a pessoa deve ser submetida a: monitoramento durante infusões e primeiras horas após o início da soroterapia.","b":"restrição hídrica e balanço hídrico.","c":"garroteamento do membro acometido para evitar que o potencial veneno se espalhe para a corrente sanguínea.","d":"inquérito e investigação através de entrevistas para tentar localizar ou identificar o animal, para escolha do melhor","e":"soro antiofídico. teste de sensibilidade cutânea com soro antiofídico disponível.","gabarito":"A","materia":"Enfermagem","tema":"Urgência e emergência","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Especialidade:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646909","enunciado":"Enfermagem Após exposição a produto químico perigoso, um professor apresentou lesões de queimadura de segundo grau nos membros inferior e superior direito e na genitália. Com base na regra dos nove, assinale a alternativa que apresenta a","a":"porcentagem da superfície corporal lesionada. 40%","b":"28%","c":"9%","d":"10%","e":"3%","gabarito":"B","materia":"Enfermagem","tema":"Assistência de Enfermagem em Feridas e Curativos ,Assistência de Enfermagem a Queimados","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Especialidade:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646908","enunciado":"Enfermagem","a":"Sobre a infecção de trato urinário (ITU), é correto afirmar que: uma estratégia profilática para o surgimento de ITU é a colocação de pomada antimicrobiana no cateter a ser inserido.","b":"deve-se realizar o teste de Allen sempre antes da inserção de uma sonda, para evitar o aumento do risco de ITU.","c":"cateteres vesicais de demora não representam fator de risco para o desenvolvimento de ITU.","d":"cateteres vesicais de demora devem ser trocados a cada 48h para evitar a chance de ITU.","e":"a ITU assintomática é definida como aquela em que há urocultura com colonização de bactérias e em que não há sinais e sintomas.","gabarito":"E","materia":"Enfermagem","tema":"Anatomia na Enfermagem ,Anatomia do Sistema Genito Urinário","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Especialidade:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646907","enunciado":"Enfermagem Os transtornos do pensamento podem trazer uma série de acometimentos que podem comprometer a vida social e","a":"profissional de um indivíduo. É correto afirmar que, quando há ideias fixas, bem construídas e persecutórias, há: psicose, alteração do humor.","b":"alucinações, alterações do juízo.","c":"delírios, alterações da sensopercepção.","d":"delírios, alterações do juízo e crítica.","e":"falta de juízo, alteração da sensopercepção.","gabarito":"D","materia":"Enfermagem","tema":"Saúde Mental","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Especialidade:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646906","enunciado":"Enfermagem","a":"Assinale a alternativa que apresenta um cuidado de enfermagem específico para a administração de drogas vasoativas. Observação de prurido e descamação da pele.","b":"Monitoramento de sinais de síndrome neuroléptica.","c":"Observação de nível de consciência, padrão respiratório e hemodinâmico.","d":"Observação da presença de sinais de reflexo patelar.","e":"Observação das pupilas, se ocorrem alterações.","gabarito":"C","materia":"Enfermagem","tema":"Administração de medicamentos","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Especialidade:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646905","enunciado":"Enfermagem Em um atendimento de urgência obstétrica, observou-se um prolapso de cordão no período expulsivo. Assinale a","a":"alternativa que apresenta os cuidados de enfermagem podem ser imediatamente realizados. Iniciar protocolo de prevenção a hemorragia pós-parto.","b":"Proceder com manobra de versão cefálica externa.","c":"Posicionar parturiente em quatro apoios.","d":"Posicionar e manter a parturiente em decúbito lateral esquerdo.","e":"Iniciar manobra para reposicionar cordão.","gabarito":"C","materia":"Enfermagem","tema":"Saúde da Mulher ,Assistência de Enfermagem ao Parto/Aborto","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Especialidade:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646904","enunciado":"Enfermagem","a":"Em um caso de traumatismo cranioencefálico moderado, a prioridade de cuidado consiste em: assegurar vias aéreas pérvias.","b":"verificar e anotar se há sinal de Guaxinim.","c":"determinar escala de coma de Glasgow.","d":"estabelecer reposição hídrica para manter a volemia.","e":"providenciar remoção da vítima do local.","gabarito":"A","materia":"Enfermagem","tema":"Urgência e emergência ,Primeiros Socorros","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Especialidade:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646903","enunciado":"Enfermagem No atendimento a um jovem adulto que lesionou membro superior esquerdo, após queda de telhado, observa-se dor,","a":"hematoma e o registro escrito de que há contusão. Um dos principais cuidados a serem orientados é: imobilização com gesso por duas semanas ao menos.","b":"realização de exercícios de tonificação no membro.","c":"aplicação de compressa fria.","d":"tração do membro.","e":"manutenção do membro abaixado e garroteado.","gabarito":"C","materia":"Enfermagem","tema":"Urgência e emergência ,Primeiros Socorros ,Cuidados de Enfermagem","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Especialidade:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646902","enunciado":"Enfermagem","a":"Entre as classes de medicamentos mais amplamente utilizadas para controle da hipertensão arterial sistêmica está a dos betabloqueadores.","b":"digitálicos.","c":"antiarrítmicos.","d":"inibidores de recaptação de serotonina.","e":"inibidores da enzima conversora de angiotensina.","gabarito":"E","materia":"Enfermagem","tema":"Farmacologia na Enfermagem","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Especialidade:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646901","enunciado":"Enfermagem Uma paciente teve três episódios de vômitos com sangue em poucos minutos enquanto aguardava por atendimento.","a":"Assinale a alternativa que indica a nomenclatura correta para a ocorrência e a classificação provável de sua pressão arterial. Henurese e hipertensão.","b":"Hematêmese e hipotensão.","c":"Hematúria e hipotensão.","d":"Epistaxe e hipertensão.","e":"Epistaxe e normotensão.","gabarito":"B","materia":"Enfermagem","tema":"Fundamentos e Procedimentos de Enfermagem","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Especialidade:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646900","enunciado":"Enfermagem","a":"São sinais e sintomas de pneumotórax hipertensivo: hipertensão arterial e extremidades frias.","b":"dor precordial e hipotensão arterial.","c":"tumefação sonora à percussão e hipotensão arterial.","d":"hipotensão e ausência de murmúrio vesicular unilateral.","e":"dispneia e crepitações bilateralmente.","gabarito":"D","materia":"Enfermagem","tema":"Anatomia na Enfermagem ,Anatomia do Sistema Respiratório","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Especialidade:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646899","enunciado":"Enfermagem Na sala de emergência, observa-se um jovem com padrão respiratório irregular e 36 irpm e dificuldade de formar frases.","a":"Como deve ser a anotação de enfermagem referente a estes parâmetros observados, específica e respectivamente? Dispneia e ecolalia.","b":"Taquipneia e disfagia.","c":"Taquicardia e afasia.","d":"Taquidispneia e disartria.","e":"Bradipneia e ecolalia.","gabarito":"D","materia":"Enfermagem","tema":"Urgência e emergência","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Especialidade:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646898","enunciado":"Enfermagem Em um atendimento de parada cardiorrespiratória, após detecção do ritmo cardíaco através de um desfibrilador, o choque","a":"não é recomendado. É possível que se trate de: fibrilação ventricular.","b":"atividade elétrica sem pulso.","c":"taquicardia ventricular sem pulso.","d":"multissistolia.","e":"bradicardia.","gabarito":"B","materia":"Enfermagem","tema":"Urgência e emergência ,Primeiros Socorros","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Especialidade:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646897","enunciado":"Enfermagem Uma senhora está com pressão arterial muito elevada e sinais de acometimento ou lesões de órgãos-alvo, esperando por atendimento no pronto-socorro. Você compõe a equipe que está fazendo a triagem e a classificação de risco. Neste caso,","a":"trata-se de uma: emergência hipertensiva.","b":"síndrome hipertensiva crônica.","c":"urgência com severidade, exigindo repouso e elevação de membros inferiores.","d":"urgência hipertensiva.","e":"síndrome metabólica com chances de evolução para urgência hipertensiva.","gabarito":"A","materia":"Enfermagem","tema":"Urgência e emergência ,Primeiros Socorros","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Especialidade:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646896","enunciado":"Enfermagem No indivíduo adulto que está recebendo compressões cardíacas por uma parada cardiorrespiratória, qual deve ser a","a":"frequência das compressões? 90 a 140 por minuto.","b":"70 a 100 por minuto.","c":"100 a 120 por minuto.","d":"70 a 90 por minuto.","e":"150 a 200 por minuto.","gabarito":"C","materia":"Enfermagem","tema":"Urgência e emergência ,Primeiros Socorros","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Especialidade:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646895","enunciado":"Enfermagem Uma indicação de posicionamento foi indicada especialmente para melhora de um paciente com quadro de insuficiência respiratória, consistindo em deitá-lo com o abdome para baixo e os membros superiores acomodados para cima. Trata-se","a":"da: Sims.","b":"decúbito dorsal.","c":"prona.","d":"Trendelenburg.","e":"supina.","gabarito":"C","materia":"Enfermagem","tema":"Urgência e emergência ,Primeiros Socorros","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Especialidade:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646894","enunciado":"Enfermagem","a":"Segundo a Lei do Exercício Profissional de Enfermagem, compete privativamente ao enfermeiro: anotação de enfermagem.","b":"cumprir o Código de Deontologia.","c":"coleta de sangue para exame laboratorial.","d":"realizar cuidados de higiene íntima.","e":"consulta de enfermagem.","gabarito":"E","materia":"Enfermagem","tema":"Legislação de Enfermagem ,Lei do Exercício Profissional de Enfermagem","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Especialidade:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646893","enunciado":"Enfermagem Um gestor está utilizando um instrumento de planejamento gerencial, de maneira integrada, participativa, identificando problemáticas atuais e potenciais e tem quatro etapas para seguir: explicativa, normativa, estratégica, tático-operacional.","a":"Qual modelo ele está utilizando? Diagrama de Ishikawa.","b":"Avaliação 360º.","c":"Índice de governança.","d":"Planejamento estratégico-situacional.","e":"Pirâmide de graus de evidências.","gabarito":"D","materia":"Enfermagem","tema":"Administração em Enfermagem","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Especialidade:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646892","enunciado":"Enfermagem Trata-se de um processo físico ou químico, que destrói microrganismos de materiais e superfícies, exceto um número","a":"elevado de esporos: eletrocauterização.","b":"desinfecção de alto nível.","c":"esterilização.","d":"antissepsia.","e":"degermação enzimática.","gabarito":"B","materia":"Enfermagem","tema":"Infecção Hospitalar","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Especialidade:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646891","enunciado":"Enfermagem Como são classificados os artigos que penetram na barreira da pele e mucosas adjacentes, nos tecidos subepiteliais e","a":"sistema vascular, para fins de processamentos? Críticos.","b":"Não-críticos.","c":"Acríticos.","d":"Sensíveis.","e":"Semicríticos.","gabarito":"A","materia":"Enfermagem","tema":"Enfermagem em Central de Material Esterilizado","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Especialidade:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646890","enunciado":"","a":"Enfermagem chamada cadeia de frio é o processo logístico que envolve o sistema de armazenamento, transporte e manuseio em condições adequadas de temperatura dos imunobiológicos, desde o laboratório produtor até a aplicação. A seu respeito, é correto afirmar que:","b":"A as câmaras refrigeradas devem ser operadas em temperaturas entre 0 °C e 10 °C. para as atividades extramuros se recomenda a utilização de gelo em barras ou escamas.","c":"as bobinas reutilizáveis exigem uma prévia ambientação, em bancada, por exemplo, antes de serem colocadas em caixas de transporte.","d":"as câmaras refrigeradas devem servir também para acondicionamento de bombinas reutilizáveis necessárias para a","e":"conservação dos imunobiológicos em caixas de transporte. os imunobiológicos com vírus vivos atenuados devem ser acondicionados na porta das câmaras refrigeradas.","gabarito":"C","materia":"Enfermagem","tema":"Imunização ,Política Nacional de Imunização","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Especialidade:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646889","enunciado":"Enfermagem Em um exame admissional, um senhor de 42 anos refere ter perdido a sua carteirinha e não ter nenhum outro registro ou","a":"cópia. Para a recomendação de vacinas destinadas ao seu caso, observou-se que um dos imunizantes indicados foi: varicela.","b":"poliomielite.","c":"hepatite C.","d":"rotavírus.","e":"dupla adulto.","gabarito":"E","materia":"Enfermagem","tema":"Imunização","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Especialidade:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646888","enunciado":"Enfermagem No estado de São Paulo, há uma vacina cuja segunda dose somente pode ser administrada até que a criança tenha 7 meses","a":"e 29 dias de idade. Trata-se da: Febre amarela.","b":"Rotavírus humano.","c":"BCG.","d":"VOP.","e":"Hepatite B.","gabarito":"B","materia":"Enfermagem","tema":"Imunização","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Especialidade:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646887","enunciado":"Enfermagem","a":"Assinale a alternativa que apresenta vacinas que fazem parte do Programa Nacional de Imunização atualmente. VIP, BCG e HPG.","b":"VOP, febre amarela e hepatite C.","c":"Penta, Pneumo10 e VEP.","d":"VRH, HPV e hepatite B.","e":"DTQ, SCR e BCG.","gabarito":"D","materia":"Enfermagem","tema":"Imunização","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Especialidade:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646886","enunciado":"Enfermagem","a":"Ao que está contido na braçadeira do esfigmomanômetro também se atribui o nome de: manguito.","b":"aneroide.","c":"coluna.","d":"bisel.","e":"manômetro.","gabarito":"A","materia":"Enfermagem","tema":"Administração de medicamentos","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Especialidade:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646885","enunciado":"Enfermagem “A enfermagem é a ciência e a arte de assistir o ser humano no atendimento de suas necessidades básicas, de torná-lo independente desta assistência através da educação, de recuperar, manter e promover sua saúde, contando, para isso, com a colaboração de outros grupos profissionais”. A autora desta frase, uma notável enfermeira que introduziu os conceitos do","a":"processo de enfermagem, também desenvolveu a chamada Teoria das Necessidades Humanas Básicas. Trata-se de: Ana Néri.","b":"Dorothea Orem.","c":"Florence Nightingale.","d":"Callista Roy.","e":"Wanda Horta.","gabarito":"E","materia":"Enfermagem","tema":"Teorias da Enfermagem","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Especialidade:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646883","enunciado":"Enfermagem","a":"É da alçada do Conselho Federal de Enfermagem, ouvido o referido Conselho Regional, a penalidade citada em: suspensão do exercício profissional.","b":"multa.","c":"cassação do exercício profissional.","d":"censura.","e":"advertência verbal.","gabarito":"C","materia":"Enfermagem","tema":"Legislação de Enfermagem ,COREN","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Especialidade:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646882","enunciado":"Enfermagem","a":"De acordo com o Novo Código de Ética dos Profissionais de Enfermagem, está contido entre os direitos do profissional: negar-se a ser filmado ou fotografado durante o desempenho de suas atividades profissionais.","b":"cometer infração dolosa, quando do desconhecimento da legislação vigente e das normas institucionais do local onde","c":"trabalha. recusar-se a utilizar como metodologia de cuidado e implementação o processo de enfermagem como instrumento.","d":"provocar, cooperar, ser conivente ou omisso diante de forma de violência contra a família, quando no exercício da","e":"profissão. anunciar formação profissional, qualificação e título que não possa comprovar.","gabarito":"A","materia":"Enfermagem","tema":"Legislação de Enfermagem","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Especialidade:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646874","enunciado":"","a":"Enfermagem base menor de um trapézio foi dividida em duas partes de mesma medida pelo ponto M e a base maior desse trapézio foi dividida em três partes de mesma medida pelos pontos P e Q. Esse trapézio foi dividido em cinco triângulos a partir de dois de seus vértices e dos pontos M, P e Q, conforme mostra a figura. Sabe-se que a razão entre a área do triângulo T1 e a área do triângulo T5 é 2/3, que o triângulo T4 é equilátero e que a área 2 do trapézio é 39√ 3 cm . A medida da base menor desse trapézio é","b":"A 13 cm. 12 cm.","c":"10 cm.","d":"8 cm.","e":"9 cm.","gabarito":"D","materia":"Matemática","tema":"Geometria Plana","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Especialidade:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646867","enunciado":"Enfermagem Leia o texto para responder às questões de números 04 a 10. Inteligência artificial: a era do “deus” máquina No teatro grego antigo, quando não havia solução para um impasse, um ator interpretando uma divindade descia ao palco pendurado num guindaste, resolvia o problema e, assim, acabava a peça. Era o Deus ex-machina – o deus surgido da máquina. Com o avanço sem precedentes da inteligência artificial (IA), é justo pensar que, no mundo contemporâneo, a máquina é a própria deidade. Para ela, nada parece impossível. Da confecção de discursos em segundos à criação de obras de arte; da identificação de medicamentos promissores ao diagnóstico preciso de doenças, tudo é resolvido pelo “deus algoritmo”. E, ao observar sua invenção “surgindo do guindaste”, o homem pode se perguntar qual lugar ocupará neste enredo. Segundo especialistas,","a":"porém, o perigo não está na criatura e, sim, no uso que o criador faz dela. inteligência artificial faz parte da rotina, ainda que não se perceba. O GPS que indica o percurso, a atendente virtual, o internet banking são exemplos de seu uso no dia a dia. Só que, até agora, ninguém temia os mecanismos de busca dos navegadores, os sistemas de reconhecimento facial dos condomínios ou a sugestão de filmes apresentadas pelos aplicativos de streaming. Então, as máquinas começaram a gerar imagens perfeitas de pessoas inexistentes, escrever reportagens com acurácia, resolver enigmas matemáticos em frações de segundos, dirigir e voar sozinhas, elaborar defesas jurídicas e até “ler” pensamentos em experimentos científicos. A ponto de, em um editorial da revista Science, um grupo de cientistas pedir a moratória de pesquisas até alguma regulamentação ética da IA. A discussão sobre riscos e avanços da IA ultrapassa o campo da ciência da computação; é também filosófica. Já na Grécia Antiga, filósofos questionavam a essência da inteligência e se ela era um atributo somente humano. Hoje, esse é um dos centros da discussão sobre IA: sistemas programados e alimentados por seres humanos poderão ultrapassar em astúcia seus criadores? Não, garante um dos maiores especialistas no tema, o cientista da computação francês Jean-Gabriel Ganascia, da Universidade de Sorbonne que, já em 1980, obteve mestrado em inteligência artificial em Paris. (Paloma Oliveto, Inteligência artificial: a era do ‘deus’ máquina. https://www.correiobraziliense.com.br/ciencia-e-saude. Adaptado) A expressão destacada contém termo(s) em sentido figurado em: o A ... ninguém temia os mecanismos de busca dos navegadores... (3 parágrafo)","b":"o ... resolver enigmas matemáticos em frações de segundos... (4 parágrafo)","c":"o ... e se ela era um atributo somente humano. (5 parágrafo)","d":"o ... o homem pode se perguntar qual lugar ocupará neste enredo. (2 parágrafo)","e":"o ... descia ao palco pendurado num guindaste... (1 parágrafo)","gabarito":"D","materia":"Português","tema":"Interpretação de Textos","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Especialidade:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646864","enunciado":"Enfermagem Leia a tira para responder às questões de números 01 a 03. (Caco Galhardo, Bicudinho. Folha de S. Paulo, 07.08.2023)","a":"Assinale a alternativa em que a reescrita de informações da tira atende à norma-padrão. Franklin, escreva um poema para mim ler, falando no estilo Paulo Leminski.","b":"Escreva um poema para eu à Paulo Leminski, falando sobre a minha pessoa.","c":"Me escreva um poema sobre mim, Franklin, no estilo de Paulo Leminski.","d":"Franklin, escreva um poema à meu respeito, no estilo de Paulo Leminski.","e":"Escreva-me um poema à Paulo Leminski que fale de mim, Franklin.","gabarito":"E","materia":"Português","tema":"Interpretação de Textos ,Redação - Reescritura de texto","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Especialidade:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646863","enunciado":"Enfermagem Leia a tira para responder às questões de números 01 a 03. (Caco Galhardo, Bicudinho. Folha de S. Paulo, 07.08.2023)","a":"No primeiro e no terceiro quadros, a vírgula tem empregos diferentes, pois separa, correta e respectivamente, o vocativo e o predicado.","b":"o sujeito e o vocativo.","c":"o vocativo e o aposto.","d":"o sujeito e o predicado.","e":"o aposto e o vocativo.","gabarito":"C","materia":"Português","tema":"Pontuação ,Funções morfossintáticas da palavra SE","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Especialidade:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646811","enunciado":"Especializado - Especialidade: Psicologia Um pesquisador elabora um projeto de pesquisa de metodologia mista, de natureza explanatória sequencial.","a":"Uma característica dessa estratégia é: a existência de um banco de dados quantitativo primário que abriga um banco de dados qualitativo secundário.","b":"os dados quantitativos e qualitativos são coletados simultaneamente e a análise subsequente se volta para pontos de","c":"convergência. há interação constante entre análise qualitativa e quantitativa dos dados, visando à explicação mais adequada.","d":"dados quantitativos coletados em um segundo momento se baseiam nos dados qualitativos inicialmente coletados.","e":"dados quantitativos inicialmente coletados direcionam a coleta subsequente de dados qualitativos relativos a resultados não esperados.","gabarito":"E","materia":"Psicologia","tema":"Metodologia de Pesquisa e Estatística Aplicada à Psicologia","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646810","enunciado":"Especializado - Especialidade: Psicologia Um pesquisador deseja investigar se duas variáveis categóricas estão associadas, mas seus dados não seguem uma distribuição normal.","a":"Nesse caso, o pesquisador deve utilizar a técnica de associação de Pearson.","b":"qui-quadrado.","c":"normalização Z.","d":"regressão linear.","e":"teste de sinal.","gabarito":"B","materia":"Psicologia","tema":"Metodologia de Pesquisa e Estatística Aplicada à Psicologia","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646809","enunciado":"Especializado - Especialidade: Psicologia Júlia, 25 anos, tem uma personalidade intensa e impulsiva. Encantadora e cativante em alguns momentos, mostrando-se extrovertida e divertida, em outros se mostra insegura e solitária. É suscetível a episódios de raiva, tristeza ou ansiedade intensos. Por conta dessas características, seus relacionamentos interpessoais são intensos e instáveis.","a":"De acordo com o DSM-V, um diagnóstico compatível com essas características seria o de transtorno de personalidade borderline.","b":"bipolar.","c":"dissociativo reativo.","d":"explosivo intermitente.","e":"de personalidade histriônica.","gabarito":"A","materia":"Psicologia","tema":"Psicopatologia ,Transtornos de Personalidade ,CID-10 e DSM","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646808","enunciado":"Especializado - Especialidade: Psicologia","a":"Prosopagnosia é um distúrbio sensoperceptivo caracterizado por dificuldade de discriminar estímulos sensoriais.","b":"tendência a associar de maneira incomum as informações oriundas de diferentes sentidos.","c":"alteração do olfato e do paladar decorrente de lesão do nervo olfativo.","d":"comprometimento da integridade do esquema corporal.","e":"incapacidade de reconhecer rostos familiares, inclusive o próprio rosto.","gabarito":"E","materia":"Psicologia","tema":"Psicologia do Desenvolvimento","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646807","enunciado":"","a":"Especializado - Especialidade: Psicologia participação do psicólogo nas equipes mínimas de saúde da família nas unidades básicas de saúde","b":"A se dá em regime de trabalho parcial, com vistas a intervenções pontuais junto à população. pode ser recomendada a partir das características e demandas da organização de serviços locais.","c":"está prevista na constituição mínima dessas equipes para apoio aos profissionais envolvidos.","d":"é opcional, em regime de revezamento com um assistente social como Agente Comunitário de Saúde.","e":"consiste na realização de visitas domiciliares para identificação das famílias de risco.","gabarito":"B","materia":"Psicologia","tema":"Psicologia da Saúde ,Saúde Coletiva","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646806","enunciado":"Especializado - Especialidade: Psicologia Nas equipes de saúde da família das unidades básicas de saúde, o desenvolvimento de ações básicas de saúde nas áreas de atenção à criança, à mulher, ao adolescente, ao trabalhador e ao idoso, com ênfase na promoção da saúde e prevenção de","a":"doenças, é atribuição do médico generalista.","b":"psicólogo social.","c":"auxiliar de enfermagem.","d":"agente comunitário de saúde.","e":"enfermeiro. Psicologia>Intervenção Psicossocial ,Políticas Públicas no SUAS ,","gabarito":"D","materia":"Psicologia","tema":"Psicologia da Saúde ,Saúde da Família ,Promoção, Prevenção e Reabilitação em Saúde","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_442","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio Especializado - Especialidade: Psicologia Os grupos de convivência são exemplos de programas comunitários oferecidos pelos CRAS.","a":"Nesses grupos, espera-se que o psicólogo desenvolva atendimentos psicoterápicos grupais que favoreçam a convivência na comunidade.","b":"faça uso de diferentes estratégias psicoeducativas para a formação comunitária.","c":"ofereça acolhimento e promova o fortalecimento de vínculos sociais e comunitários.","d":"assegure a inclusão de pessoas portadoras de transtornos mentais na comunidade.","e":"adote uma postura passiva que permita a projeção das demandas comunitárias. Psicologia>Políticas Públicas no SUS ,Psicologia e Políticas Públicas de Proteção e Promoção à Saúde ,","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_443","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio Especializado - Especialidade: Psicologia","a":"Na assistência domiciliar, o psicólogo participa das equipes multiprofissionais de atuação domiciliar (EMAD).","b":"modalidades AD2 de Melhor em Casa (SAD).","c":"equipes multiprofissionais de apoio (EMAP).","d":"modalidades Tipo 2 da Atenção Domiciliar (METAD).","e":"modalidades AD1 da Atenção Básica (AB). Psicologia>Psicologia da Saúde ,Equipes de Saúde, Multidisciplinaridade e Interdisciplinaridade ,","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_444","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio Especializado - Especialidade: Psicologia","a":"Uma das principais finalidades da atuação do psicólogo como interconsultor é a de atuar como facilitador da comunicação entre o profissional de saúde, o paciente e a família.","b":"neutralizar o atravessamento institucional na atuação da equipe de saúde.","c":"fazer o diagnóstico de possíveis transtornos mentais no hospital geral.","d":"promover sessões de acompanhamento terapêutico da equipe de saúde.","e":"promover o treinamento da equipe de saúde em boas práticas de comunicação.","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646802","enunciado":"Especializado - Especialidade: Psicologia","a":"Na visão da Psicanálise, um grupo deixa de ser terapêutico quando o terapeuta se deixa envolver pelo fundo de indiferenciação comum ao grupo.","b":"impede a sociabilidade por interação e a expressão das identidades.","c":"elimina a clivagem entre os níveis mais e menos discriminados do grupo.","d":"há mobilização de reações paranoides frente ao indeterminado e desconhecido.","e":"imobiliza os níveis sincréticos da personalidade e do grupo.","gabarito":"E","materia":"Psicologia","tema":"Teorias e Técnicas Psicoterápicas","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646801","enunciado":"Especializado - Especialidade: Psicologia Em 1935, John Ridley Stroop desenvolveu um experimento para investigar uma condição de interferência cognitiva. Os participantes foram apresentados a uma série de palavras impressas em cores diferentes, como “vermelho”, “azul”, “verde” e assim por diante. Algumas eram congruentes, ou seja, a cor impressa e o significado da palavra eram correspondentes; outras, eram incongruentes, ou seja, a cor impressa não correspondia ao significado da palavra escrita. Os participantes foram instruídos a nomear a cor da tinta em que as palavras estavam impressas o mais rapidamente possível, desconsiderando a palavra escrita. Seus tempos de resposta foram cronometrados.","a":"Nesse caso, é correto afirmar que a variável independente é a palavra escrita.","b":"a congruência significado-cor da palavra.","c":"a interferência cognitiva.","d":"a cor das palavras.","e":"o tempo de resposta.","gabarito":"B","materia":"Psicologia","tema":"Psicologia do Desenvolvimento","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646800","enunciado":"Especializado - Especialidade: Psicologia Jorge, 25 anos, não tem amigos ou confidentes. Sente-se pouco à vontade ao se relacionar com as pessoas. Embora interaja com outros, se necessário, prefere não o fazer, pois se acha diferente.","a":"Essa descrição é compatível com o diagnóstico de transtorno de personalidade esquizotímica.","b":"esquiva.","c":"evitativa.","d":"esquizotípica.","e":"esquizofrênica.","gabarito":"D","materia":"Psicologia","tema":"Psicopatologia ,Outros Transtornos","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646798","enunciado":"Especializado - Especialidade: Psicologia Fenomenologicamente, pode-se distinguir certas propriedades da consciência do eu, como: atividade, unidade, identidade e oposição ao exterior.","a":"Tais propriedades formam o que se pode chamar de identidade.","b":"esquema corporal.","c":"personalização.","d":"self.","e":"autoimagem.","gabarito":"C","materia":"Psicologia","tema":"Psicologia do Desenvolvimento","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646797","enunciado":"Especializado - Especialidade: Psicologia Nas visões mais atuais sobre a primeira hora de observação lúdica, em geral também o primeiro contato do psicólogo em","a":"uma situação de psicodiagnóstico, expressas por autores de orientação psicanalítica, o observador deve observar com uma atenção mais flutuante, para registrar a mensagem da criança.","b":"procurar identificar se a cena primária é representada sob um prisma sádico ou masoquista.","c":"evitar o uso de material pouco estruturado que fomente condutas regressivas em caso de ansiedade","d":"voltar sua atenção para as brincadeiras que revelem as fantasias masturbatórias da criança.","e":"identificar como são representados os imagos materno e paterno.","gabarito":"A","materia":"Psicologia","tema":"Teorias e Técnicas Psicoterápicas ,Ludoterapia","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646796","enunciado":"Especializado - Especialidade: Psicologia Na ludoterapia psicanalítica com crianças pequenas, é importante","a":"adotar um enquadre flexível que permita a extensão ou a antecipação do final da sessão de acordo com a disposição","b":"da criança. dispor de alguns brinquedos complexos que desafiem as habilidades cognitivas e adaptativas da criança.","c":"assegurar que a criança tenha uma caixa lúdica individualizada e trancada, guardada em um armário para indicar-lhe","d":"que o conteúdo é inviolável. levar a criança a expressar verbalmente seus conflitos a partir da manipulação dos brinquedos durante a sessão.","e":"deixar que a mãe da criança tenha livre acesso à sala terapêutica para impedir níveis intoleráveis de ansiedade da criança.","gabarito":"C","materia":"Psicologia","tema":"Teorias e Técnicas Psicoterápicas ,Ludoterapia","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646795","enunciado":"Especializado - Especialidade: Psicologia","a":"Ao se comparar anamnese e entrevista psicológica, conforme conceituada por José Bleger, pode-se dizer que ambas partem do princípio de que o entrevistado está capacitado para fornecer dados sobre a sua vida.","b":"a comunicação não-verbal do examinando é a fonte de informações primárias no contexto da anamnese.","c":"a simulação é compreendida como fator de perturbação a ser denunciado pelo entrevistador na entrevista psicológica.","d":"na anamnese espera-se que o entrevistador tenha uma atitude menos flexível em relação ao enquadramento do que na entrevista psicológica.","e":"as contradições apresentadas devem ser entendidas como contradições da própria personalidade na entrevista psicológica.","gabarito":"E","materia":"Psicologia","tema":"Avaliação Psicológica ,Psicodiagnóstico e Avaliação Psicológica","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646794","enunciado":"Especializado - Especialidade: Psicologia","a":"Na visão da psicossomática psicanalítica, uma das características dos pacientes somatizadores é o alto grau de autoacusações e sentimento de culpa.","b":"a boa adaptação social ou mesmo sobreadaptação aos padrões culturais.","c":"a redução do comportamento em relação à valorização do pensamento.","d":"o marcante pessimismo decorrente das dificuldades que enfrenta na vida.","e":"a presença de uma vida onírica rica em conteúdos pessoais. Psicologia>Psicopatologia ,Terapia Cognitivo Comportamental ,Teorias e Técnicas Psicoterápicas","gabarito":"B","materia":"Psicologia","tema":"Teorias e Técnicas Psicoterápicas","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_453","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio Especializado - Especialidade: Psicologia Entre os pacientes com maior probabilidade de se beneficiar das terapias cognitivo-comportamentais, destacam-se os que","a":"apresentam uso de drogas ou álcool.","b":"depressão moderada ou intensa.","c":"transtorno de humor bipolar.","d":"transtorno obsessivo-compulsivo leve ou moderado.","e":"ausência de insight.","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646792","enunciado":"Especializado - Especialidade: Psicologia Na perspectiva existencial, patologia é compreendida como","a":"uma desproporção entre os recursos psicológicos disponíveis no indivíduo e as pressões a que é submetido em sua existência.","b":"a aceitação, pelo indivíduo, de que a aquisição de um sentido para sua vida é de sua única e exclusiva","c":"responsabilidade. um sentido de falta, decorrente de relações objetais falhas, que acompanha o indivíduo ao longo de sua existência.","d":"um constructo teórico de natureza positivista que não encontra respaldo nas abordagens humanistas de modo geral.","e":"desequilíbrio existencial que ocorre quando a pessoa enfrenta dificuldades para lidar com os desafios e as questões fundamentais da existência humana.","gabarito":"E","materia":"Psicologia","tema":"Psicopatologia ,Outros Transtornos","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646791","enunciado":"Especializado - Especialidade: Psicologia Na visão de Wilhelm Reich, a ansiedade é a tensão gerada por uma energia reprimida que não consegue ser descarregada.","a":"Sob essa perspectiva, é correto afirmar que a ansiedade sempre decorre de conflitos intrapsíquicos de natureza sexual do indivíduo.","b":"resulta da tentativa do indivíduo de enfrentar diretamente os conflitos emocionais associados.","c":"pode se apresentar de forma emocional, mental e física.","d":"deve ser elaborada por meio da interpretação das fantasias inconscientes subjacentes.","e":"é uma emoção inata de caráter patogênico por natureza.","gabarito":"C","materia":"Psicologia","tema":"Psicopatologia ,Outros Transtornos","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646790","enunciado":"Especializado - Especialidade: Psicologia","a":"O ego auxiliar, pela perspectiva do Psicodrama, é um instrumento terapêutico com múltiplas funções. função associada à revelação de novas perspectivas é a de","b":"A protagonista. ator.","c":"diretor de cena.","d":"investigador social.","e":"agente terapêutico.","gabarito":"D","materia":"Psicologia","tema":"Psicologia do Desenvolvimento","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646789","enunciado":"Especializado - Especialidade: Psicologia Diante de pacientes em unidade de terapia intensiva que enfrentam a possibilidade concreta da morte, cabe ao psicólogo","a":"hospitalar oferecer um espaço para que o paciente possa elaborar suas vivências nesse contexto.","b":"orientar a equipe de saúde quanto às informações que devem ser comunicadas ao paciente.","c":"levar o paciente a olhar para os aspectos positivos da vida, desviando sua atenção do risco de morte.","d":"encerrar as intervenções quando não houver mais a possibilidade de cura.","e":"adotar todas as estratégias possíveis para evitar que o paciente caia em depressão.","gabarito":"A","materia":"Psicologia","tema":"Psicologia da Saúde ,Psicologia Hospitalar","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646788","enunciado":"","a":"Especializado - Especialidade: Psicologia hospitalização de um membro da família via de regra leva ao desequilíbrio do sistema familiar. Diante de uma solicitação da família por atendimento psicológico, o psicólogo hospitalar deve","b":"A mostrar otimismo quanto à evolução do paciente para evitar episódios depressivos no grupo familiar. favorecer a formação de um vínculo de confiança com a família.","c":"abordar, de início, as questões mais conflitivas da família, de modo a reduzir a ansiedade do grupo.","d":"encaminhar a família para um psicólogo clínico externo à instituição.","e":"ater-se ao esclarecimento de dúvidas quanto ao quadro do paciente.","gabarito":"B","materia":"Psicologia","tema":"Psicologia da Saúde ,Psicologia Hospitalar","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646787","enunciado":"Especializado - Especialidade: Psicologia Uma forma de relato das conclusões de um psicodiagnóstico com que os psicólogos se deparam hoje em dia é o de encaminhamento a uma instituição pagadora de convênio de saúde para comprovar a necessidade de atendimento psicológico do paciente.","a":"Nesses casos, recomenda-se que o documento redigido seja coerente com as determinações do Conselho Federal de Psicologia para a elaboração de declarações psicológicas.","b":"determinado pela empresa solicitante, para que esteja dentro de seus padrões para avaliação da necessidade do atendimento.","c":"bastante sucinto, por envolver demanda de atendimento psicológico a ser processada por setores administrativos da empresa solicitante.","d":"o mais detalhado possível, de modo a abranger demandas de atendimento atuais e futuras que possam se","e":"apresentar. pouco extenso, cabendo ao psicólogo ou médico da empresa solicitante zelar pelo sigilo das informações.","gabarito":"E","materia":"Psicologia","tema":"Avaliação Psicológica ,Psicodiagnóstico e Avaliação Psicológica","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646786","enunciado":"Especializado - Especialidade: Psicologia Assinale a alternativa que apresenta, corretamente, uma condição necessária para a constituição de um grupo terapêutico","a":"ou operativo efetivo. Diluição das individualidades.","b":"Eliminação de fantasias inconscientes.","c":"Definição de um enquadre.","d":"Existência de interesses comuns.","e":"Equiparação das vinculações afetivas.","gabarito":"C","materia":"Psicologia","tema":"Teorias e Técnicas Psicoterápicas","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646785","enunciado":"","a":"Especializado - Especialidade: Psicologia forma habitual de diagnósticos e de psicoterapia não satisfaz a exigência para o atendimento do número de pacientes nos hospitais. Por isso, a realização de terapias breves focais tem sido cada vez mais comum nesse tipo de contexto. Na instituição hospitalar, o local mais adequado para esse tipo de intervenção é:","b":"A salas de emergência. área de recepção.","c":"ambulatório.","d":"enfermarias.","e":"centros de terapia intensiva.","gabarito":"C","materia":"Psicologia","tema":"Teorias e Técnicas Psicoterápicas","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646784","enunciado":"Especializado - Especialidade: Psicologia","a":"Ontem Marina conheceu uma nova colega de classe. No momento, ela está tentando se lembrar do nome da jovem. função cognitiva envolvida nessa conduta é a da memória","b":"A episódica. factual.","c":"implícita.","d":"semântica.","e":"imediata.","gabarito":"D","materia":"Psicologia","tema":"Teorias e Técnicas Psicoterápicas","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646783","enunciado":"Especializado - Especialidade: Psicologia","a":"Segundo a abordagem gestáltica, a fronteira de ego envolve dois fenômenos: aqui, agora.","b":"identificação, alienação.","c":"propriocepção, exterocepção.","d":"eu, tu.","e":"mundo interno, mundo externo.","gabarito":"B","materia":"Psicologia","tema":"Psicologia do Desenvolvimento","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646782","enunciado":"Especializado - Especialidade: Psicologia Um clínico usa a Escala de Gesell para avaliar o desenvolvimento de uma criança de 7 meses. Ao colocá-la diante de um espelho, observa que a criança, sentada, inclina o tronco para a frente e toca na sua imagem refletida.","a":"Tal conduta deve ser avaliada como comportamento socioafetivo.","b":"motor delicado.","c":"pessoal-social.","d":"motor grosseiro.","e":"adaptativo.","gabarito":"C","materia":"Psicologia","tema":"Psicologia do Desenvolvimento","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646781","enunciado":"Especializado - Especialidade: Psicologia Para a abordagem centrada na pessoa, de Carl Rogers, o resultado desejado do desenvolvimento psicológico é a “pessoa de pleno funcionamento”.","a":"Uma característica dessa condição é a pessoa estar aberta tanto a experiências positivas quanto negativas.","b":"ter uma noção de si com base nas experiências positivas da infância.","c":"conseguir superar as tendências inatas à indiferenciação.","d":"tender a se comportar de uma maneira estável e previsível.","e":"manter afastado o que é potencialmente ameaçador em uma dada situação.","gabarito":"A","materia":"Psicologia","tema":"Teorias da Personalidade","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646780","enunciado":"","a":"Especializado - Especialidade: Psicologia Psicanálise já existe há mais de um século, período em que passou por algumas modificações. Pode-se dizer que, ao contrário da Psicanálise clássica, a Psicanálise contemporânea prioriza","b":"A o desenvolvimento das instâncias psíquicas. o processo de repressão dos desejos edípicos.","c":"a cura por meio da promoção da catarse.","d":"a remoção dos sintomas apresentados pelo paciente.","e":"a dupla analítica e os vínculos relacionais que a permeiam.","gabarito":"E","materia":"Psicologia","tema":"Teorias da Personalidade","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646779","enunciado":"Especializado - Especialidade: Psicologia","a":"Entre as estruturas psicológicas conceituadas por Carl Jung, identifica-se, como estrutura de identidade, o animus.","b":"o complexo.","c":"o arquétipo.","d":"o inconsciente pessoal.","e":"a sombra.","gabarito":"E","materia":"Psicologia","tema":"Jung ,Teorias da Personalidade","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646778","enunciado":"Especializado - Especialidade: Psicologia","a":"O principal objetivo da atuação do psicólogo nas oficinas abrigadas é realizar avaliações diagnósticas para identificar as competências psicológicas e cognitivas de deficientes intelectuais.","b":"desenvolver um trabalho de coaching para deficientes físicos e mentais em diferentes equipes multiprofissionais.","c":"elaborar projetos terapêuticos visando à superação de conflitos de indivíduos com deficiências físicas ou mentais","d":"específicas. oferecer suporte emocional e psicológico aos participantes durante as atividades realizadas nas oficinas.","e":"reproduzir as principais características dos ambientes de trabalho em condições protegidas para deficientes em geral.","gabarito":"D","materia":"Psicologia","tema":"Psicologia Social","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646777","enunciado":"Especializado - Especialidade: Psicologia As terapias contextuais têm trazido importantes atualizações para a tradição cognitivo-comportamental. Particularmente a","a":"Terapia Dialética Comportamental de início foi criada visando ao atendimento de indivíduos com doenças orgânicas de alto índice de letalidade.","b":"pacientes com transtorno de personalidade borderline.","c":"portadores de transtornos dissociativos.","d":"grupos em situação de emergência e desastre.","e":"crianças com problemas de aprendizagem.","gabarito":"B","materia":"Psicologia","tema":"Teorias e Técnicas Psicoterápicas","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646776","enunciado":"Especializado - Especialidade: Psicologia Lorena é uma criança que acredita que todas as pessoas veem, pensam e sentem as coisas da mesma maneira que ela, o que lhe traz dificuldade para compreender que aqueles com quem convive possam ter pontos de vista diferentes dos seus.","a":"De acordo com Jean Piaget, essa característica de Joana é própria do estágio de desenvolvimento alocêntrico.","b":"operatório concreto.","c":"pré-operatório.","d":"sensório-motor.","e":"pré-objetal.","gabarito":"C","materia":"Psicologia","tema":"Piaget ,Teorias da Personalidade","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646775","enunciado":"Especializado - Especialidade: Psicologia","a":"Na visão do sociólogo Émile Durkeim, um fato social é uma força coercitiva exterior que se impõe à maneira de agir, pensar e sentir das pessoas.","b":"um evento concreto que promove mudanças significativas no funcionamento social.","c":"uma crença ou valor coletivo não necessariamente endossado no nível individual.","d":"uma circunstância social atípica cujas implicações modelam a psique coletiva.","e":"uma tendência individual que se impõe a determinados grupos sociais. Psicologia>Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia ,","gabarito":"A","materia":"Psicologia","tema":"Psicologia Social","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_472","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio Especializado - Especialidade: Psicologia Um psicólogo atende semanalmente um paciente em seu consultório, cobrando um “preço social” abaixo de seus honorários habituais. Como expressão de seu reconhecimento, ao final do ano o pai do paciente oferece uma doação considerável em termos de suas posses.","a":"De acordo com o Código de Ética do Psicólogo, o psicólogo precisa discutir com o paciente se uma doação feita por seu pai poderia ser aceita.","b":"não deve receber doações de qualquer espécie, além dos honorários contratados.","c":"poderia aceitar a doação, explicitando ao paciente o teor de reconhecimento do presente.","d":"sempre deve aceitar presentes e doações por parte de seus pacientes.","e":"deve decidir quanto à adequação de receber a doação ou não, tendo em vista a dinâmica da relação.","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646773","enunciado":"Especializado - Especialidade: Psicologia Joana é uma garota de 15 anos bastante ativa, que se ressente da falta de autonomia por depender financeiramente dos","a":"pais. Se submetida à técnica projetiva de desenho da Casa-Árvore-Pessoa, esse ponto provavelmente se manifestará por tronco fino na Árvore.","b":"braços colados ao corpo na Pessoa.","c":"paredes da Casa transparentes.","d":"ausência de raízes na Árvore.","e":"pernas da Pessoa cortadas pela margem da folha.","gabarito":"E","materia":"Psicologia","tema":"Psicologia do Desenvolvimento","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646772","enunciado":"Especializado - Especialidade: Psicologia Mateus é um garoto de 8 anos de idade diagnosticado com Transtorno de Déficit de Atenção e Hiperatividade (TDAH). a Tendo em vista essa condição, é de se esperar que, ao ser submetido à 4 edição da Escala Wechsler de Inteligência para Crianças (WISC-IV), Mateus apresente maior dificuldade nos subtestes:","a":"Dado: suplementares entre colchetes. Completar Figuras, Cubos, [Arranjo de Figuras].","b":"Compreensão, Semelhanças, [Informação].","c":"Dígitos, Sequência de Números e Letras, [Aritmética].","d":"Raciocínio com Palavras, Raciocínio Matricial, [Conceitos Figurativos].","e":"Armar Objetos, Cancelamento, [Labirinto].","gabarito":"C","materia":"Psicologia","tema":"Psicopatologia ,Outros Transtornos","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646771","enunciado":"Especializado - Especialidade: Psicologia Com o desenvolvimento cada vez maior da inteligência artificial, é de se perguntar se uma boneca mecânica equipada com um Gestalt-sinal poderia promover o desenvolvimento inicial do bebê. Na visão de René Spitz, a resposta a essa pergunta","a":"seria não, pois o bebê não tem como identificar um Gestalt-sinal em um rosto imóvel.","b":"talvez, se a mesma boneca for apresentada ao bebê de maneira constante.","c":"sim, porque uma mamadeira acoplada à boneca poderia suprir a necessidade básica da alimentação.","d":"não, porque só uma relação de trocas pode fornecer o lampejo vital ao equipamento inato do bebê.","e":"sim, porque o bebê nasce predisposto à identificação da Gestalt olhos-boca como rosto humano.","gabarito":"D","materia":"Psicologia","tema":"Psicologia do Desenvolvimento","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646765","enunciado":"Especializado - Especialidade: Psicologia Além de outras vacinas oferecidas em campanhas nacionais, o Ministério da Saúde preconiza que as gestantes recebam, de","a":"acordo com o Calendário Nacional de Vacinação, vacinas contra tétano, sarampo, caxumba e rubéola.","b":"hepatite B, difteria, coqueluche e tétano.","c":"papiloma vírus humano 6, tétano, meningite meningocócica e rubéola.","d":"tétano e rubéola.","e":"hepatite B, sarampo, rubéola e tétano.","gabarito":"B","materia":"Saúde Pública","tema":"Políticas Públicas, Planejamento e Gestão em Saúde Pública","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646689","enunciado":"Especialidade: Oficial de Justiça Avaliador Federal Leia a charge para responder às questões de números 01 e 02. (Chargista Ricardo Manhães. https://ndmais.com.br/opiniao/charges, 31.03.2023)","a":"O diálogo entre os mosquitos permite concluir corretamente que a dengue é um problema que eles preferem ignorar por ora.","b":"os casos confirmados negam de fato o avanço da dengue.","c":"o avanço da dengue é fato inconteste e pode recrudescer.","d":"a disseminação da dengue é algo em que eles não creem.","e":"as medidas de combate à dengue deixam-nos apreensivos.","gabarito":"C","materia":"Português","tema":"Interpretação de Textos","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Judiciária -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646662","enunciado":"Enfermagem Leia a tira para responder às questões de números 01 a 03. (Caco Galhardo, Bicudinho. Folha de S. Paulo, 07.08.2023)","a":"O efeito de humor na tira tem relação com a incapacidade de o homem escrever um poema, omitida do robô.","b":"a resposta do robô, que mente ao afirmar desconhecer o que seja um poema.","c":"a indignação do robô diante do pedido de escrita de um poema.","d":"o desconhecimento expresso pelo robô sobre o que seja poema.","e":"a burrice artificial do robô, mesmo tendo atendido ao pedido do homem.","gabarito":"D","materia":"Português","tema":"Interpretação de Textos","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário / Especialidade:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646585","enunciado":"Especializado - Especialidade: Estatística","a":"Observação: Para as questões que assim necessitarem, há tabelas estatísticas disponibilizadas no final deste caderno. tabela a seguir descreve as receitas anuais, em bilhões de reais, de uma empresa no período de 2018 a 2022. Ano 20182019202020212022 Receita 1,5 1,8 1,7 2,0 2,0 Usando o método dos mínimos quadrados e supondo linear a tendência dos dados informados, a estimativa pontual da receita (em bilhões de reais) para 2023 é de:","b":"A 2,65. 2,16.","c":"3,10.","d":"3,40.","e":"3,74.","gabarito":"B","materia":"Estatística","tema":"Inferência estatística ,Propriedades dos estimadores","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646584","enunciado":"Especializado - Especialidade: Estatística Considere as informações da tabela a seguir. TABELA 5 Produção anual do bem A AnoProdução (toneladas)Médias móveis de 3 anos 2016 20 2017 22 W 2018 18 X 2019 23 Y 2020 17 Z 2021 20 a","a":"Os valores de W e Y da 3 coluna (médias móveis de ordem 1 e 3) são, respectivamente: 20,0 e 19,3.","b":"20,2 e 20,0.","c":"19,3 e 21,0.","d":"20,0 e 20,2.","e":"18,3 e 21,0.","gabarito":"A","materia":"Estatística","tema":"Análise de séries temporais","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646583","enunciado":"Especializado - Especialidade: Estatística Observação: Para as questões que assim necessitarem, há tabelas estatísticas disponibilizadas no final deste caderno. Para responder às questões de números 57 e 58, considere o texto a seguir. Suponha que uma análise de regressão com dados das variáveis x e y indicou correlação linear entre elas, obtendo-se para coeficientes os seguintes valores: 0,78 para o coeficiente de determinação, – 0,28 para o coeficiente de inclinação e 52,10 para o coeficiente linear (ou de interceptação).","a":"Entre as alternativas seguintes, o valor mais próximo do coeficiente de correlação entre as variáveis é: 0,72.","b":"– 0,80.","c":"0,96.","d":"– 0,88.","e":"– 0,88.","gabarito":"D","materia":"Estatística","tema":"Modelos lineares ,Regressão Linear","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646582","enunciado":"Especializado - Especialidade: Estatística Com relação à equação da reta de regressão, podemos usá-la para diversas estimativas. Se o fizermos para x = 60,","a":"obteremos o correspondente y. Dos valores a seguir, o que mais se aproxima de y é: 25.","b":"28.","c":"20.","d":"30.","e":"35. Estatística>Estatística descritiva (análise exploratória de dados) ,Covariância, Correlação ,Modelos lineares","gabarito":"E","materia":"Estatística","tema":"Modelos lineares","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_483","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio Especializado - Especialidade: Estatística Observação: Para as questões que assim necessitarem, há tabelas estatísticas disponibilizadas no final deste caderno. O gráfico a seguir é o diagrama de dispersão obtido com uma amostra de trabalhadores de certa região para estudar a possível correlação entre o tempo médio de escolaridade e a renda média anual. GRÁFICO 2 Tempo médio escolaridade X Renda média anual Admitindo uma correlação linear entre as variáveis e considerando os coeficientes r de correlação e b de inclinação da reta","a":"de regressão associada, é correto afirmar que: r > 0 e b < 0.","b":"r > 0 e b > 0.","c":"r < 0 e b < 0.","d":"r > 0 e b < 0.","e":"r = 0 e b < 0.","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646580","enunciado":"Especializado - Especialidade: Estatística Observação: Para as questões que assim necessitarem, há tabelas estatísticas disponibilizadas no final deste caderno. Para responder às questões de números 54 e 55, considere o texto a seguir. Para comparar os custos de produção de produtos de três modelos de um mesmo bem, um engenheiro de produção selecionou as amostras A1, A2 e A3, cujos resultados estão anotados na tabela a seguir. TABELA 4 Dados colhidos de três amostras independentes A1 A2 A3 Tamanho das amostras: 8 8 8 n Médias amostrais: 2,8 3,1 3,4 Variâncias amostrais: 0,15 0,18 0,12 2 s Considere agora o nível de significância de 5% e as hipóteses: Ho: µ1 = µ2 = µ3 H1: há pelo menos uma média diferente das demais","a":"Nesse caso, o teste de hipótese da estatística F faz concluir que: Ho deve ser aceita.","b":"os dados são insuficientes para uma conclusão sobre médias.","c":"Ho deve ser rejeitada.","d":"nada se pode afirmar sobre a igualdade ou não das médias, pois a razão F está fora de padrão para esse tipo de teste.","e":"o nível de significância adotado permite conclusão apenas sobre a moda amostral.","gabarito":"C","materia":"Estatística","tema":"Inferência estatística ,Testes de hipóteses","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646578","enunciado":"Especializado - Especialidade: Estatística Supondo que as informações iniciais e o problema indicavam que tal estudo devia ser feito por análise de variância, o engenheiro considerou os dados amostrais e calculou a estatística F. Com isso, verificou que a razão entre as variabilidades","a":"“entre” e “dentro” dos grupos é de aproximadamente: 4,8.","b":"3,0.","c":"3,9.","d":"5,2.","e":"6,0.","gabarito":"A","materia":"Estatística","tema":"Inferência estatística ,Testes de hipóteses","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646577","enunciado":"Especializado - Especialidade: Estatística Observação: Para as questões que assim necessitarem, há tabelas estatísticas disponibilizadas no final deste caderno. Um teste de hipóteses a 2% pretendeu verificar a razoabilidade das hipóteses Ho : μ = 49 e H1 : μ > 49 para uma população com desvio padrão igual a 9. Investigada uma amostra de tamanho 36, se os valores fizerem concluir que Ho deve ser","a":"aceita, então sua média amostral deve ser de no máximo: 64.","b":"58.","c":"60.","d":"52.","e":"72.","gabarito":"D","materia":"Estatística","tema":"Inferência estatística ,Propriedades dos estimadores","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646576","enunciado":"","a":"Especializado - Especialidade: Estatística vida média anunciada de determinado produto colocado à venda no mercado é de 30 meses, com distribuição normal e desvio padrão de 5 meses. Dessa forma, ao selecionarmos uma amostra aleatória de 36 desses produtos, então o valor mais próximo da probabilidade que difira por mais de 2 meses da média anunciada é:","b":"A 5%. 1%.","c":"8%.","d":"10%.","e":"15%.","gabarito":"B","materia":"Estatística","tema":"Principais distribuições de probabilidade","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646575","enunciado":"Especializado - Especialidade: Estatística Dois cursinhos dizem diferenciar-se pela proporção de alunos aprovados nos concursos: o curso A diz aprovar 60% e o curso B, 50%. Se selecionados 40 alunos de A e 25 de B, a probabilidade de o percentual de aprovados por A ser 20 pontos","a":"percentuais superior aos dos aprovados por B é de aproximadamente: 15%.","b":"25%.","c":"17%.","d":"28%.","e":"22%.","gabarito":"E","materia":"Estatística","tema":"Principais distribuições de probabilidade","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646574","enunciado":"Especializado - Especialidade: Estatística Em condições normais, uma oficina mecânica anuncia que 90% dos veículos deixados para revisão são devolvidos no mesmo dia. Essa informação pode ser contestada se uma amostra de 100 veículos revelar que 80 deles foram prontamente atendidos e considerando um índice de significância de 2%?","a":"Qual o tipo de erro associado a essa conclusão? Sim. Erro tipo 1.","b":"Não. Erro tipo 1.","c":"Não. Erro tipo 2.","d":"Sim. Erro tipo 2.","e":"Dados insuficientes para qualquer conclusão.","gabarito":"A","materia":"Estatística","tema":"Inferência estatística ,Testes de hipóteses","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646573","enunciado":"","a":"Especializado - Especialidade: Estatística empresa Viajantes quer estimar, com 95% de confiança e erro máximo de 5%, a percentagem de caminhões que trafegam por suas vias com excesso de peso. O tamanho mínimo da amostra necessária para tanto, supondo os referidos pesos normalmente distribuídos e a proporção média provável igual a 50%, é de:","b":"A 341. 392.","c":"379.","d":"334.","e":"385.","gabarito":"E","materia":"Estatística","tema":"Inferência estatística ,Intervalos de confiança","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646572","enunciado":"Especializado - Especialidade: Estatística Segundo o Pnad (Pesquisa Nacional por Amostras de Domicílio) de 2022, o piso nacional dos salários dos professores da educação básica nesse ano era de R$ 3.840,00, valor superior à renda média familiar de 92% dos alunos das escolas públicas. (Folha de S. Paulo, 20.07.2023, pág. A 15). Isso posto, assumindo um desvio padrão de 1,2% e um nível de confiança de 95%, o intervalo de confiança normal para a","a":"proporção de famílias com rendas não inferiores às dos professores é: 6,8% e 9,2%.","b":"10% e 13%.","c":"3% e 13%.","d":"5,6% e 10,4%.","e":"4,2% e 11,5%.","gabarito":"D","materia":"Estatística","tema":"Inferência estatística ,Intervalos de confiança","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646571","enunciado":"Especializado - Especialidade: Estatística O Invest Fund propaga aos quatro ventos que qualquer grupo de 36 ações da sua carteira de investimentos rende, em média, mais de 9% ao ano. Se os rendimentos dos referidos grupos de títulos tiverem distribuição normal e renderem, em","a":"média, 10% ao ano, com desvio padrão de 3%, a probabilidade de ele parecer mentiroso é de aproximadamente: 3,4%.","b":"2,3%.","c":"1,2%.","d":"5,6%.","e":"4,5%.","gabarito":"B","materia":"Estatística","tema":"Principais distribuições de probabilidade","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646569","enunciado":"Especializado - Especialidade: Estatística Duzentos candidatos foram entrevistados para se avaliar a correlação entre “fazer cursinho” e “ser aprovado” em um concurso. Os resultados estão na tabela a seguir. TABELA 3 Relações entre realização de cursinho e desempenho em concursos Aprovado? Cursinho?Sim Não Sim 50 30 Não 50 70 Aplicando o teste qui quadrado com nível de significância de 5% aos dados da tabela 2, conclui-se que:","a":"2 x = 40 e fazer cursinho influencia na aprovação.","b":"2 x = 20 e fazer cursinho influencia na aprovação.","c":"2 x = 8,3 e fazer cursinho influencia na aprovação.","d":"2 x = 4,2 e fazer cursinho não influencia na aprovação.","e":"2 x = 0,8 e fazer cursinho não influencia na aprovação.","gabarito":"C","materia":"Estatística","tema":"Inferência estatística ,Testes de hipóteses","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646568","enunciado":"Especializado - Especialidade: Estatística Na região R, a CDEE – Companhia de Distribuição de Energia Elétrica detectou que seu consumo era normalmente distribuído com média mensal de 160 kwh (quilowatt-hora) por consumidor e desvio padrão de 45 kwh. Como complemento de sua nova política social, ela decidiu reduzir o preço do kwh das residências com consumo de até 70 kwh. Se o número de residências de R que consomem energia elétrica gerada pela CDEE for estimado em 38000, então o número","a":"de residências que terão tarifas menores será de aproximadamente: 980.","b":"1 210.","c":"1 500.","d":"1 080.","e":"870.","gabarito":"E","materia":"Estatística","tema":"Principais distribuições de probabilidade","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646567","enunciado":"Especializado - Especialidade: Estatística Observação: Para as questões que assim necessitarem, há tabelas estatísticas disponibilizadas no final deste caderno. Os vendedores da loja Mínimus Pressus atendem, em RAS C U NHO média, 8 clientes por hora. Apesar de saberem que há alguma probabilidade de que ainda cheguem clientes para serem atendidos, quando faltam 15 minutos para o final de expediente eles dão o dia por “encerrado”.","a":"Nas condições dadas, a probabilidade de que, nos próximos 15 minutos, ainda cheguem à loja 2 ou mais clientes é de:","b":"","c":"","d":"","e":"","gabarito":"A","materia":"Estatística","tema":"Principais distribuições de probabilidade","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646566","enunciado":"Especializado - Especialidade: Estatística Na região R, projetos para exploração de recursos minerais devem ser submetidos a três comissões de avaliação, que os aprovam ou não conforme seus supostos impactos ambientais. Ali, por lei, um projeto só é aprovado se ratificado por pelo menos duas das três comissões. As comissões instaladas não revelam seus critérios de análise e aprovam respectivamente, em média, 3/5, 1/3 e 2/3 dos projetos a elas submetidos.","a":"Em tais condições, a probabilidade de um projeto qualquer ser aprovado é de aproximadamente: 40%.","b":"56%.","c":"30%.","d":"76%.","e":"25%. Estatística>Cálculo de Probabilidades ,Probabilidade condicional, Teorema de Bayes e independência ,","gabarito":"B","materia":"Estatística","tema":"Principais distribuições de probabilidade","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_497","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio Especializado - Especialidade: Estatística Observação: Para as questões que assim necessitarem, há tabelas estatísticas disponibilizadas no final deste caderno. Para responder as questões de números 41 e 42, considere a seguinte situação. O radar de velocidade de uma estrada registra que a metade dos veículos que por ali passam na hora H o fazem com velocidade acima da permitida. Suponha que o caso possa ser bem aproximado por uma distribuição binomial e considere","a":"uma amostra de n = 4 veículos. probabilidade de todos os quatro veículos amostrados estarem acima da velocidade máxima permitida é de aproximadamente:","b":"A 5,5%. 5,0%.","c":"4,5%.","d":"6,3%.","e":"1,8%. Estatística>Estatística descritiva (análise exploratória de dados) ,","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_498","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","a":"Especializado - Especialidade: Estatística média esperada de veículos acima da velocidade permitida e o respectivo desvio padrão são:","b":"A E(x) = 4 e σ = 2. E(x) = 2 e σ = 2.","c":"E(x) = 4 e σ = 4.","d":"E(x) = 2 e σ = 1.","e":"E(x) = 1 e σ = 1. Estatística>Cálculo de Probabilidades ,Probabilidade condicional, Teorema de Bayes e independência ,","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_499","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio Especializado - Especialidade: Estatística Observação: Para as questões que assim necessitarem, há tabelas estatísticas disponibilizadas no final deste caderno. Por seu histórico, o júri J condena 90% dos culpados e absolve 99% dos inocentes. Se o próximo réu submetido a ele vier de","a":"um grupo de 80% de culpados (e 20% de inocentes), então a probabilidade de ele ser absolvido é de aproximadamente: 99%.","b":"90%.","c":"28%.","d":"50%.","e":"20%.","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646562","enunciado":"Especializado - Especialidade: Estatística Se o segredo de um cofre for constituído por três números de dois dígitos, então a chance de um hacker abri-lo “de","a":"primeira” é de: 1 em 1000000.","b":"1 em 100000000.","c":"1 em 10000000.","d":"1 em 10000.","e":"1 em 100000.","gabarito":"A","materia":"Estatística","tema":"Principais distribuições de probabilidade","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646561","enunciado":"Especializado - Especialidade: Estatística O laboratório L usa como reagentes os produtos X e Y, que reserva em frascos de duas unidades. Segundo o último relatório do estoque, o frasco A contém duas unidades de X, o frasco B, uma unidade de X e outra de Y, e o frasco C, duas unidades de Y. Em um estudo que exige duas unidades desses reagentes, um pesquisador escolhe aleatoriamente um","a":"frasco. Se, na primeira retirada, obteve uma unidade de X, então a probabilidade de obter X também na segunda é de: 1/2.","b":"2/3.","c":"2/5.","d":"1/3.","e":"1/5.","gabarito":"B","materia":"Estatística","tema":"Cálculo de Probabilidades ,Probabilidade condicional, Teorema de Bayes e independência","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646559","enunciado":"Especializado - Especialidade: Estatística Muito bem de vida, G. G. decide suas economias em “investimento de risco”. Se comprar títulos cuja probabilidade de","a":"ganhar $ 700,00 é de 60% e a de perder $ 300,00 é de 40%, então deve esperar um retorno de: 20%.","b":"40%.","c":"25%.","d":"35%.","e":"30%.","gabarito":"E","materia":"Estatística","tema":"Cálculo de Probabilidades ,Probabilidade condicional, Teorema de Bayes e independência","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646558","enunciado":"Especializado - Especialidade: Estatística Os pesos dos 49 concursados da Probies são normalmente distribuídos, com média e desvio padrão, respectivamente, iguais a 82 kg e 6,0 kg. Se a empresa programar uma atividade da qual só poderão participar aqueles com peso entre 70 kg","a":"e 85 kg, o número de seus colaboradores aptos para tanto será aproximadamente igual a: 38.","b":"40.","c":"45.","d":"33.","e":"27.","gabarito":"D","materia":"Estatística","tema":"Cálculo de Probabilidades ,Probabilidade condicional, Teorema de Bayes e independência","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646557","enunciado":"Especializado - Especialidade: Estatística Em dezembro, o quadro de ‘colaboradores’ da Probies compõe-se de 49 concursados e 21 contratados. Dos concursados, 28 são homens e, dos contratados, 7 são mulheres. Se, na festa de fim de ano, for sorteado um prêmio, a probabilidade de","a":"o ganhador ser uma mulher é: 40%.","b":"42%.","c":"57%.","d":"14%.","e":"10%.","gabarito":"A","materia":"Estatística","tema":"Cálculo de Probabilidades ,Probabilidade condicional, Teorema de Bayes e independência","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646556","enunciado":"Especializado - Especialidade: Estatística Para realização de uma pesquisa com unidades do modelo M, serão considerados quatro estoques contendo, cada um, respectivamente, 144, 192, 240 e 384 unidades. Se tomada uma amostra estratificada de 40 unidades, dos valores a seguir, apenas um pode representar a soma dos elementos de duas subamostras.","a":"Assinale a alternativa que apresenta corretamente esse valor. 20.","b":"18.","c":"30.","d":"28.","e":"15.","gabarito":"B","materia":"Estatística","tema":"Amostragem","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646554","enunciado":"","a":"Especializado - Especialidade: Estatística tabela 2 a seguir relaciona os estudantes de um curso universitário por turnos. TABELA 2 Turno MatutinoNoturnoTotais Alunos 70 120 190 Alunas 50 60 110 Totais 120 180 300 Assumindo a significância de 5%, considerando os valores dados, o quiquadrado calculado e a hipótese “mesma proporção de alunos e alunas nos turnos”, conclui-se:","b":"A aceitar a hipótese. rejeitar a hipótese.","c":"aceitar a hipótese.","d":"rejeitar a hipótese.","e":"aceitar a hipótese.","gabarito":"C","materia":"Estatística","tema":"Inferência estatística ,Testes de hipóteses","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646553","enunciado":"Especializado - Especialidade: Estatística Desejando conhecer a opinião dos participantes quanto à qualidade dos congressos que promovem, os organizadores decidem consultar uma amostra de 122 pessoas. Por terem em mãos as fichas de inscrição dos últimos 976 participantes, todas numeradas por ordem de inscrição, optaram pela amostragem sistemática. Calculada a razão da progressão aritmética que define os números que serão incluídos na amostra, sortearam o primeiro","a":"entre eles, obtendo x = 2. Se continuarem com esse critério, o último dos números a ser incluído na amostra será: 976.","b":"974.","c":"970.","d":"960.","e":"980. Estatística>Estatística descritiva (análise exploratória de dados) ,","gabarito":"C","materia":"Estatística","tema":"Amostragem","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_508","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio Especializado - Especialidade: Estatística Em uma sala de aula de 45 estudantes, a nota média foi 7,0. Em conversa com a turma sobre tais resultados, o professor comentou que, computadas apenas as notas dos meninos, a média caía para 6,0.","a":"Nesse caso, a média das 25 meninas da turma foi de: 7,8.","b":"7,0.","c":"8,2.","d":"7,5.","e":"8,0.","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646531","enunciado":"Especializado - Especialidade: Estatística As distribuições de probabilidade ou frequências podem RAS C U NHO ser simétricas ou assimétricas. Nas simétricas, média, mediana e moda coincidem. Nas assimétricas, esses valores são diferentes.","a":"No caso de uma distribuição com assimetria à esquerda, a relação de grandeza entre essas variáveis é: média < moda < mediana.","b":"mediana < média < moda.","c":"mediana < moda < média.","d":"moda < mediana < média.","e":"média < mediana < moda. Estatística>Estatística descritiva (análise exploratória de dados) ,","gabarito":"E","materia":"Estatística","tema":"Estatística descritiva (análise exploratória de dados) ,Distribuições de frequência","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_510","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio Especializado - Especialidade: Estatística O gráfico a seguir mostra os valores da frequência acumulada da distribuição de frequências sem perda de informação de certa variável x. GRÁFICO 1 Frequências acumuladas da variável x Variável x","a":"Do gráfico, podemos inferir que a frequência relativa de x = 5 é: 7,3%.","b":"12%.","c":"15,8%.","d":"10%.","e":"15%. Estatística>Estatística descritiva (análise exploratória de dados) ,","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_511","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio Especializado - Especialidade: Estatística Observação: Para as questões que assim necessitarem, há tabelas estatísticas disponibilizadas no final deste caderno. Para as questões de números 27 e 28, considere os dados do quadro a seguir, relativo às idades em anos de 12 usuários de um aplicativo de internet aletoriamente escolhidos. 40 48 60 60 62 62 68 70 70 70 71 84","a":"Ainda com relação ao diagrama de caixa, o seu limite superior é: 92.","b":"85.","c":"74.","d":"90.","e":"80. Estatística>Estatística descritiva (análise exploratória de dados) ,","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_512","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio Especializado - Especialidade: Estatística","a":"Com relação ao diagrama de caixa (ou boxplot) relativo aos dados, é correto afirmar que, entre eles: existem dois outliers.","b":"todos os dados acima da mediana são outliers.","c":"todos os dados abaixo do 1 º quartil são outliers.","d":"o único outlier é a idade 40 anos.","e":"inexistem outliers.","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646519","enunciado":"Especializado - Especialidade: Estatística Observação: Para as questões que assim necessitarem, há tabelas estatísticas disponibilizadas no final deste caderno. Observando suas turmas de estatística, Pardalis inferiu que 60% dos alunos estudam de fato para as provas e que, destes, 80% passam. Quanto aos que não estudam, 80% acabam reprovados. No final do semestre, um aluno reprovado pede","a":"revisão de notas. A probabilidade de ele ter estudado (e talvez merecer uma segunda chance) é de, aproximadamente: 27%","b":"22%","c":"29%","d":"30%","e":"32%","gabarito":"A","materia":"Estatística","tema":"Principais distribuições de probabilidade","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646516","enunciado":"Especializado - Especialidade: Estatística Observação: Para as questões que assim necessitarem, há tabelas estatísticas disponibilizadas no final deste caderno. Para as questões de números 21 a 25, considere a seguinte tabela de distribuição de frequência com perda de informação 3 relativa ao consumo mensal de água, em m , do quarteirão Q da cidade C, obtida de uma amostra aleatória de residências do local. TABELA 1 Consumo mensal de água do quarteirão Q da cidade C 3 Consumo em m Número de residências (fi) 10 |-----20 4 20 |-----30 6 30 |-----40 10 40 |-----50 12 50 |-----60 8","a":"Dos histogramas a seguir, o que melhor representa a distribuição de frequência da tabela 1 é:","b":"","c":"","d":"","e":"","gabarito":"C","materia":"Estatística","tema":"Estatística descritiva (análise exploratória de dados) ,Distribuições de frequência","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_515","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio Especializado - Especialidade: Estatística Observação: Para as questões que assim necessitarem, há tabelas estatísticas disponibilizadas no final deste caderno. Para as questões de números 21 a 25, considere a seguinte tabela de distribuição de frequência com perda de informação 3 relativa ao consumo mensal de água, em m , do quarteirão Q da cidade C, obtida de uma amostra aleatória de residências do local. TABELA 1 Consumo mensal de água do quarteirão Q da cidade C 3 Consumo em m Número de residências (fi) 10 |-----20 4 20 |-----30 6 30 |-----40 10 40 |-----50 12 50 |-----60 8","a":"O nível de consumo, em metros cúbicos, mais próximo ao do valor do terceiro quartil da amostra é 25.","b":"40.","c":"18.","d":"32.","e":"48. Estatística>Estatística descritiva (análise exploratória de dados) ,","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_516","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio Especializado - Especialidade: Estatística 3","a":"O valor de consumo, em m , que representa a moda amostral (considerando-se a moda bruta) é: 50.","b":"45.","c":"35.","d":"65.","e":"70.","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646509","enunciado":"Especializado - Especialidade: Estatística 3","a":"O consumo médio, em m , por residência de Q de C é de aproximadamente: 32.","b":"38.","c":"19.","d":"25.","e":"45.","gabarito":"B","materia":"Estatística","tema":"Estatística descritiva (análise exploratória de dados) ,Distribuições de frequência","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646507","enunciado":"","a":"Especializado - Especialidade: Estatística estimativa de residências que consomem entre o valor do limite inferior da 2 ª classe e o valor do limite superior da 4 ª classe é:","b":"A 84% 80%","c":"65%","d":"70%","e":"74%","gabarito":"D","materia":"Estatística","tema":"Estatística descritiva (análise exploratória de dados) ,Distribuições de frequência","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646454","enunciado":"Especializado - Especialidade: Medicina (Do Trabalho)","a":"Assinale a alternativa que apresenta como os agravos à saúde do trabalhador podem ser prevenidos. Não é possível prevenir agravos à saúde do trabalhador.","b":"Fornecendo equipamentos de proteção individual, apenas.","c":"Através do tratamento médico após o surgimento dos agravos, apenas.","d":"Oferecendo planos de saúde aos trabalhadores, apenas.","e":"Através da identificação e controle dos riscos ocupacionais, adoção de medidas de prevenção e promoção de um ambiente de trabalho seguro e saudável.","gabarito":"E","materia":"Medicina","tema":"Anatomia e Fisiologia Humana em Medicina","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646453","enunciado":"Especializado - Especialidade: Medicina (Do Trabalho) Trabalhador braçal do sexo masculino, com 45 anos de idade, legalmente registrado em uma jornada de trabalho de 8 h diárias, ativado na função laboral de roçador de uma concessionária administradora de rodovia, em seu trabalho apresenta movimentos repetitivos contínuos. Há 15 dias apresenta queixa de lombalgia. Diante desse quadro clínico, assinale a alternativa correta em relação à patologia mais provável apresentada pelo","a":"supracitado trabalhador. Hérnia de disco lombar.","b":"Calculose renal.","c":"Metástases de câncer de próstata.","d":"Osteomalácia.","e":"Dor miofascial.","gabarito":"A","materia":"Medicina","tema":"Anatomia e Fisiologia Humana em Medicina","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646452","enunciado":"Especializado - Especialidade: Medicina (Do Trabalho) Um trabalhador da área da saúde (enfermeiro) teve a sua jornada de trabalho expirada às 18h. Quando subiu em sua Motocicleta, dirigindo-se para sua residência, lembrou-se de realizar as compras do mês em um supermercado que estava inserido no trajeto. Tendo gasto aproximadamente 90 minutos para realizá-las, então dá início ao seu retorno para casa. Sofre um acidente projetando-se para o solo, apresentando diversas fraturas de membros superiores.","a":"Assinale a alternativa correta. Não há elementos para caracterizar como acidente de trabalho.","b":"Caracteriza-se como acidente de trajeto, de acordo com a legislação trabalhista vigente.","c":"Caracteriza-se apenas como acidente de trânsito, de acordo com a legislação vigente.","d":"Caracteriza-se como acidente do trabalho típico, de acordo com a legislação vigente.","e":"Tanto pode ser caracterizado como acidente de trânsito ou do trabalho.","gabarito":"C","materia":"Medicina","tema":"Anatomia e Fisiologia Humana em Medicina","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646451","enunciado":"Especializado - Especialidade: Medicina (Do Trabalho) Sobre o impacto do trabalho remoto sobre gestores e equipe na pandemia e pós-pandemia de SARS-CoV-2, é correto afirmar que:","a":"o trabalho deve ser benéfico e eficiente, para isso não é necessário ter horário flexível e trabalhar em ambiente em que o trabalhador se sinta relaxado, como o de sua residência.","b":"o trabalho remoto gera, em muitas pessoas, a sensação de maior tempo de trabalho e poucos momentos de","c":"relaxamento. o trabalho em home office não auxiliou na eliminação dos problemas decorrentes da pandemia.","d":"ele apresentou apenas benefícios aos trabalhadores, permitindo a flexibilização de horários e a permanência por mais tempo em família.","e":"a mescla do ambiente de trabalho e ambiente familiar não gerou ansiedade nem adaptação do local de trabalho, especialmente com relação à manutenção do vínculo empregatício.","gabarito":"B","materia":"Medicina","tema":"Anatomia e Fisiologia Humana em Medicina","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646450","enunciado":"Especializado - Especialidade: Medicina (Do Trabalho)","a":"Como a antropometria pode contribuir para a saúde e segurança dos trabalhadores? A antropometria não tem relação com a saúde e segurança dos trabalhadores.","b":"A antropometria pode apenas determinar se um trabalhador está apto para determinadas tarefas.","c":"A antropometria ajuda a garantir que os trabalhadores sejam uniformes em tamanho.","d":"A antropometria permite o design de ambientes de trabalho ergonômicos, evitando posturas prejudiciais e lesões","e":"musculoesqueléticas. A antropometria só é relevante para melhorar a estética do local de trabalho.","gabarito":"D","materia":"Medicina","tema":"Anatomia e Fisiologia Humana em Medicina","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646449","enunciado":"Especializado - Especialidade: Medicina (Do Trabalho)","a":"Assinale a alternativa que apresenta a importância da imparcialidade na realização de perícias médicas. A imparcialidade não é necessária, pois o perito médico deve sempre proteger os interesses do trabalhador.","b":"A imparcialidade é importante apenas para evitar a realização de perícias médicas.","c":"A imparcialidade não é relevante, pois o perito médico sempre deve beneficiar o empregador.","d":"A imparcialidade é fundamental para garantir que as decisões sejam baseadas em evidências médicas objetivas e","e":"justas, protegendo tanto o trabalhador quanto o empregador. A imparcialidade é importante apenas quando a perícia envolve casos legais.","gabarito":"D","materia":"Medicina","tema":"Anatomia e Fisiologia Humana em Medicina","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646448","enunciado":"Especializado - Especialidade: Medicina (Do Trabalho)","a":"O principal objetivo da estatística descritiva na Medicina do Trabalho é prever o futuro estado de saúde dos trabalhadores.","b":"calcular a probabilidade de acidentes de trabalho.","c":"analisar a eficácia de programas de saúde no futuro.","d":"determinar as causas subjacentes de doenças ocupacionais.","e":"resumir e apresentar informações sobre características de saúde e exposição dos trabalhadores de maneira compreensível.","gabarito":"E","materia":"Medicina","tema":"Anatomia e Fisiologia Humana em Medicina","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646447","enunciado":"Especializado - Especialidade: Medicina (Do Trabalho) É correto afirmar, considerando atestados médicos, segundo o Código de Ética Médica, que é obrigação de todo profissional","a":"médico: atestar óbito de paciente ao qual vinha prestando assistência.","b":"elaborar ou divulgar atestados médicos que revelem o diagnóstico, prognóstico ou terapêutica, especialmente em","c":"casos de médicos do trabalho. fornecer atestado sem ter praticado o ato profissional que o justifique.","d":"elaborar ou divulgar boletim médico que não revele o diagnóstico, prognóstico ou terapêutica.","e":"utilizar-se de formulários de instituições públicas para atestar fatos verificados em clínica privada.","gabarito":"C","materia":"Medicina","tema":"Anatomia e Fisiologia Humana em Medicina","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646446","enunciado":"Especializado - Especialidade: Medicina (Do Trabalho)","a":"Assinale a alternativa que apresenta a relação entre a gestão ambiental e a saúde dos trabalhadores. A gestão ambiental foca exclusivamente na saúde dos trabalhadores, ignorando o impacto ambiental.","b":"Não há relação direta entre esses dois aspectos.","c":"A gestão ambiental e a saúde dos trabalhadores são áreas separadas, sem influência mútua.","d":"A gestão ambiental pode afetar a saúde dos trabalhadores, já que um ambiente de trabalho saudável contribui para a saúde ocupacional.","e":"A gestão ambiental visa proteger o meio ambiente, enquanto a saúde dos trabalhadores se concentra apenas nos aspectos da saúde ocupacional.","gabarito":"D","materia":"Medicina","tema":"Anatomia e Fisiologia Humana em Medicina","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646445","enunciado":"Especializado - Especialidade: Medicina (Do Trabalho)","a":"Assinale a alternativa que apresenta os efeitos da sobrecarga de trabalho em linhas de produção. Aumento do risco de acidentes de trabalho, fadiga, estresse e baixa produtividade.","b":"Melhoria das condições de saúde dos trabalhadores.","c":"Redução do absenteísmo e da rotatividade.","d":"Aumento da motivação dos trabalhadores.","e":"Maior facilidade de aprendizado das tarefas.","gabarito":"A","materia":"Medicina","tema":"Anatomia e Fisiologia Humana em Medicina","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646444","enunciado":"Especializado - Especialidade: Medicina (Do Trabalho) Um trabalhador com dor crônica necessita ter uma abordagem clínica adequada. Considerando a afirmação, aponte a","a":"alternativa correta. A capacidade para o trabalho do indivíduo com dor crônica é influenciada apenas pela função física dele.","b":"Os objetivos da reabilitação são a analgesia, o relaxamento muscular, a redução dos sinais inflamatórios, a estimulação sensitivo-motora, ganho de amplitude de movimentos e restauração da função.","c":"Na Síndrome Fibromiálgica, o repouso-inatividade- -afastamento inicial é fundamental para reabilitação do paciente, com abordagem de anti-inflamatórios.","d":"A cinesiofobia corresponde ao medo excessivo, irracional e debilitante do movimento e da atividade física. Deve ser","e":"estimulada com fins de evitar novas lesões ou recorrência do quadro clínico. Para a reintegração profissional, não há evidências ou recomendações de necessidade de atuação multiprofissional.","gabarito":"B","materia":"Medicina","tema":"Anatomia e Fisiologia Humana em Medicina","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646443","enunciado":"Especializado - Especialidade: Medicina (Do Trabalho) Assinale a alternativa que apresenta a principal finalidade das Normas Técnicas da Previdência Social para Diagnóstico de","a":"Doenças Relacionadas ao Trabalho. Definir os procedimentos para avaliação de condições ergonômicas.","b":"Padronizar critérios para diagnóstico de doenças relacionadas ao trabalho.","c":"Determinar as regras para registro de acidentes de trabalho.","d":"Estabelecer diretrizes para o tratamento de doenças ocupacionais.","e":"Estabelecer diretrizes para treinamento de primeiros socorros.","gabarito":"B","materia":"Segurança e Saúde no Trabalho","tema":"Medicina do trabalho ,Sistema de Saúde Brasileira","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646442","enunciado":"Especializado - Especialidade: Medicina (Do Trabalho) Considerando esses procedimentos realizados por profissionais da área da saúde, assinale o que apresenta maior risco de","a":"contaminação por SARS-CoV-2. Coleta de amostras biológicas para exames clínicos.","b":"Nebulização.","c":"Intubação orotraqueal.","d":"Aplicação de vacinas.","e":"Higienização em leito.","gabarito":"C","materia":"Medicina","tema":"Anatomia e Fisiologia Humana em Medicina","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646441","enunciado":"Especializado - Especialidade: Medicina (Do Trabalho) Profissional de Saúde, ao colocar luvas para procedimento em centro cirúrgico, desenvolveu urticária com lesões em pápula e angioedema, além de intensa rinoconjuntivite.","a":"Assinale a opção que melhor explica o quadro desenvolvido pelo trabalhador. O quadro certamente foi por algum produto farmacológico utilizado durante o procedimento.","b":"O quadro não foi grave pela existência de talco entre as luvas de látex.","c":"O quadro se deveu a uma dermatite irritativa de contato ao látex da luva.","d":"Ocorreu uma reação de hipersensibilidade do tipo IV, por sensibilização ao látex da luva utilizada.","e":"O quadro é decorrente de reações de hipersensibilidade do tipo I, por alergia à proteína do látex. Segurança e Saúde no Trabalho>Estudos Epidemiológicos e Doenças Endêmicas ,","gabarito":"E","materia":"Medicina","tema":"Anatomia e Fisiologia Humana em Medicina","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_533","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio Especializado - Especialidade: Medicina (Do Trabalho) O SESMT de uma madeireira, com finalidade de identificar os efeitos extra-auditivos da exposição ao ruído, validou um","a":"protocolo clínico que será utilizado em grupos de trabalhadores expostos durante 5 anos. denominação mais adequada para este tipo de estudo é:","b":"A Ensaio Clínico Experimental. Estudo Transversal.","c":"Estudo Caso-Controle.","d":"Estudo de Coorte Retrospectivo.","e":"Estudo Coorte Prospectivo.","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646439","enunciado":"Especializado - Especialidade: Medicina (Do Trabalho) o","a":"Segundo o que rege a Lei n 8.213/1991, segundo seu Artigo 23, considera-se como o dia do acidente do trabalho o(a): data do início da incapacidade laborativa para o exercício da atividade que labora.","b":"data do encaminhamento para médico Assistente ou Emergência Clínica.","c":"data do ASO, no Exame médico, em que o trabalhador foi considerado inapto.","d":"data do preenchimento da Comunicação de Acidente de Trabalho (CAT).","e":"dia da notificação no Sistema de Informação de Agravos de Notificação (SINAN).","gabarito":"A","materia":"Direito Previdenciário","tema":"Benefícios em Espécie ,Acidente do Trabalho","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646438","enunciado":"Especializado - Especialidade: Medicina (Do Trabalho) Em relação à Síndrome do manguito rotador, é correto afirmar que:","a":"o manguito rotador é formado por quatro músculos, sendo supraespinhoso, infraespinhoso, redondo menor, redondo maior","b":"os testes que permitem avaliar componentes específicos do manguito rotador são: Testes de Jobe, Tinnel, Patte, Gerber.","c":"a dor é caracteristicamente maior ao final da jornada e ao levantar-se, na região antero-lateral do ombro e com a face lateral do braço.","d":"esta condição patológica representa um espectro de doença que varia de uma tendinite aguda até uma tensão maciça envolvendo todos os músculos componentes do manguito rotador.","e":"o teste de Jobe avalia o componente infraespinhoso e redondo menor e o Teste de Patte, o componente Supraespinhoso.","gabarito":"D","materia":"Medicina","tema":"Anatomia e Fisiologia Humana em Medicina","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646437","enunciado":"Especializado - Especialidade: Medicina (Do Trabalho) Considerando os Distúrbios Osteomusculares Relacionados ao Trabalho, é correto afirmar que:","a":"a história ocupacional e epidemiológica da Síndrome de De Quervain está relacionada com a tensão, flexão ou desvio","b":"radial do carpo, em exposição ocupacional que exijam movimentos repetitivos. os homens são três vezes mais predispostos, pois executam tarefas altamente repetitivas mais frequentemente.","c":"a rizartrose é um importante diagnóstico diferencial quando estamos avaliando uma possível Síndrome do Supraespinhoso.","d":"a Síndrome do Túnel do Carpo é causada pela compressão do nervo mediano, pode ser desencadeada pela pós- menopausa, amiloidose, hipotireoidismo, predisposição genética, fratura de punho.","e":"a parestesia ou formigamento e perda de sensibilidade mais frequente em trabalhadores em construção civil, que carregam baldes (com alça) contendo massa de cimento, é a doença de Dupuytren. Segurança e Saúde no Trabalho>","gabarito":"D","materia":"Medicina","tema":"Anatomia e Fisiologia Humana em Medicina","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646436","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio Especializado - Especialidade: Medicina (Do Trabalho) No que se refere às Condições Sanitárias e de Conforto nos Locais de Trabalho, é correto afirmar que:","a":"em estabelecimentos com funções comerciais, administrativas ou similares, com até 20 trabalhadores, poderá ser disponibilizada uma instalação sanitária individual separada por gênero.","b":"em locais com exposição de trabalhadores em que haja exposição e manuseio de material infectante, substâncias tóxicas, irritantes ou aerodispersóides que impregnem as roupas e pele dos trabalhadores, deve-se ter disponível, 1 chuveiro e 1 lavatório a cada 15 trabalhadores.","c":"em locais com exposição de trabalhadores em que haja exposição e manuseio de material infectante, substâncias tóxicas, irritantes ou aerodispersóides que impregnem as roupas e pele dos trabalhadores, deve-se ter disponível, 1 lavatório a cada 10 trabalhadores.","d":"em estabelecimentos com funções comerciais, administrativas ou similares, com até 20 trabalhadores, poderá ser disponibilizada apenas uma instalação sanitária individual de uso comum.","e":"em locais com exposição de trabalhadores em que haja exposição e manuseio de material infectante, substâncias tóxicas, irritantes ou aerodispersóides que impregnem as roupas e pele dos trabalhadores, deve-se ter disponível, 1 chuveiro a cada 15 trabalhadores.","gabarito":"C","materia":"NR 24 - Norma Regulamentadora nº 24 - Condições Sanitárias e de Conforto nos Locais de Trabalho (Higiene do Trabalho)","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646435","enunciado":"Especializado - Especialidade: Medicina (Do Trabalho) Na Anamese Ocupacional, considerando atividade laborativa com manuseio e levantamento de carga e a aptidão para tais","a":"atividades, é correta a afirmativa: não há relação estatística de hábitos de vida como tabagismo relacionado à maior incidência de lombalgia.","b":"levantamento de miopia é importante, assim como uso de óculos, a ser considerado como contraindicação em","c":"determinadas situações de carregamentos de cargas. o histórico prévio de lombalgia contraindica o carregamento e manuseio de cargas.","d":"trabalhadores com menos de 18 anos e mais de 45 anos devem ser consideradas com restrição à atividade por maior propensão a distúrbios de natureza ergonômica.","e":"trabalhadores entre 18 e 45 anos, com histórico prévio de lombalgia leve remota, podem ser liberados para carregamento de cargas entre 50 e 60 kg.","gabarito":"B","materia":"Medicina","tema":"Anatomia e Fisiologia Humana em Medicina","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646434","enunciado":"Especializado - Especialidade: Medicina (Do Trabalho) Um trabalhador, em uma empresa de manutenção de poços artificiais, sofre uma queda em um poço abandonado com cobertura, não sinalizado, com cerca de 14 metros de profundidade, morrendo minutos depois por gás tóxico.","a":"Assinale a alternativa que apresenta o gás mais provável responsável pela morte do trabalhador. Óxido Nitroso.","b":"Monóxido de Carbono.","c":"Gás Carbônico.","d":"Metano.","e":"Gás Sulfídrico. Segurança e Saúde no Trabalho>","gabarito":"C","materia":"Medicina","tema":"Anatomia e Fisiologia Humana em Medicina","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646433","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio Especializado - Especialidade: Medicina (Do Trabalho) Segundo o texto atual da NR-7, trabalhadores expostos a poeiras minerais (sílica, asbestos, carvão mineral e outras poeiras","a":"insolúveis ou poucos solúveis), a espirometria deve ser solicitada em exame admissional, periódico anual e demissional.","b":"admissional, periódico semestralmente e demissional.","c":"periódico bienalmente e demissional.","d":"admissional e anualmente, em periódico.","e":"admissional e bienalmente, em periódico. Segurança e Saúde no Trabalho>NR 1 - Norma Regulamentadora nº 1 - Disposições Gerais ,","gabarito":"E","materia":"NR 7 - Norma Regulamentadora n° 7 - Programa de Controle Médico de Saúde Ocupacional - PCMSO (Avaliação Periódica)","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_541","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio Especializado - Especialidade: Medicina (Do Trabalho) Atualmente, com relação ao Programa de Gerenciamento de Riscos (PGR), previsto na NR-1, é correto afirmar que:","a":"é um programa adotado pelas empresas, objetivando gerenciar os riscos sem a necessidade de consultar os","b":"trabalhadores. é utilizado apenas para fins de prevenção e gerenciamento dos riscos ocupacionais.","c":"pode ser utilizado para fins de caracterização de atividades operacionais insalubres ou perigosas.","d":"não substitui o PPRA.","e":"é implementado de acordo com o grau de risco e o CNPJ da organização.","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646431","enunciado":"Especializado - Especialidade: Medicina (Do Trabalho) Com relação à Perda Auditiva Induzida Por Ruído, é correto afirmar que:","a":"é sempre neurossensorial, apresenta como sinais e sintomas mais comuns perda auditiva, zumbidos, dificuldades no","b":"entendimento de fala. é sugestivo de PAIR caso uma ou mais frequências estejam abaixo de 25dBA nas faixas de 3000 a 6000 Hz.","c":"pode ser perda neurossensorial, pode ser bilateral e é irreversível, cessando com a exposição ao agente causador.","d":"a realização de exame audiométrico deve ser realizada com equipamento calibrado periodicamente, por fonoaudiólogo ou médico, em local silencioso e necessariamente com 10 horas de repouso auditivo.","e":"tem definição diagnóstica pela audiometria e nunca se deve considerar a longa exposição a agentes químicos como chumbo, magnésio que podem apresentar interação e acentuar a perda auditiva.","gabarito":"A","materia":"Medicina","tema":"Anatomia e Fisiologia Humana em Medicina","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646430","enunciado":"Especializado - Especialidade: Medicina (Do Trabalho) Trabalhador da área da saúde comparece para exame médico admissional e informa esquema vacinal de duas doses de vacina contra Hepatite B, sendo a última anotada em carteira vacinal há 9 meses. Frente ao quadro relatado, a conduta correta é:","a":"realizar esquema vacinal completo de Vacina contra a Hepatite B e 30 dias depois realizar a sorologia Anti-HBs para verificação de viragem sorológica.","b":"realizar Imunoglobulina Humana anti-Hepatite B e,30 dias depois, realizar a sorologia Anti-HBs para verificação de viragem sorológica.","c":"orientar a importância da notificação em caso de acidente biológico e conduta imediata, sem necessidade de conduta clínica no momento.","d":"completar o esquema vacinal iniciado e, em 30 dias, realizar a sorologia Anti-HBs para verificação de viragem","e":"sorológica. realizar sorologia Anti-HBs para avaliação de viragem sorológica e posterior decisão clínica.","gabarito":"D","materia":"Medicina","tema":"Anatomia e Fisiologia Humana em Medicina","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646429","enunciado":"Especializado - Especialidade: Medicina (Do Trabalho) Quanto ao reconhecimento do potencial cancerígeno de agentes tóxicos, é correto afirmar que:","a":"não há grande número de estudos que apontam o potencial cancerígeno dos agrotóxicos e a ocorrência de outros agravos à saúde humana relacionados a agrotóxicos.","b":"a IARC reconhece todos os tipos de amianto como sendo “provável” e “possível” cancerígenos, possuindo o persistente processo de inflamação dos pulmões, o que gera substâncias oxidantes que resultam nos efeitos genotóxicos no parênquima pulmonar.","c":"o formol é rapidamente absorvido pelo trato respiratório e gastrointestinal, e rapidamente metabolizado e vem sendo associada, pela (IARC) e pela U.S. Department of Health and Human Services, a câncer hepático.","d":"estudos indicam associação positiva entre o uso de carbofurano (metilcarbamato de benzofuranila) e o uso do herbicida Paraquat e tumores no SNC.","e":"o chumbo e o mercúrio são considerados suspeitos de causarem câncer (categorias “provável” e “possível” pela International Agency for Research on Cancer (Agência Internacional para Pesquisa do Câncer – IARC) – grupos 2A e 2B, respectivamente). Direito Previdenciário>Benefícios em Espécie ,","gabarito":"E","materia":"Medicina","tema":"Anatomia e Fisiologia Humana em Medicina","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_545","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio Especializado - Especialidade: Medicina (Do Trabalho)","a":"Segundo o Regulamento da Previdência Social (Decreto no 3048 de 06.05.1999), assinale a alternativa correta. comprovação de efetiva exposição do segurado a agentes prejudiciais à saúde para fins de Laudo de Comprovação A de Aposentadoria Especial, emitido pela empresa ou por seu preposto, com base em Laudo Técnico de Condições Ambientais de Trabalho (LTCAT) emitido por Técnico de segurança por meio eletrônico ou físico.","b":"A Aposentadoria por Incapacidade Permanente (AIP), uma vez cumprido o período de carência exigido, quando for o caso, será devida ao segurado que for considerado incapaz para o trabalho e insuscetível de reabilitação para o exercício de atividade que lhe garanta subsistência.","c":"O Auxílio Por Incapacidade Temporária será devido ao segurado em caso de incapacidade para seu trabalho por mais de 15 dias consecutivos, conforme definido em avaliação Médico-Pericial, sem prazo de carência.","d":"O Auxílio-Acidente será concedido ao trabalhador quando para consolidação das lesões de qualquer natureza para evitar sequelas definitivas decorrentes de acidente típico proveniente do trabalho.","e":"O Perfil Psicográfico Previdenciário deverá ser elaborado pelo empregado e ser mantido pela empresa em documento físico ou digital e deve contemplar as atividades desenvolvidas durante o período laboral, contendo seu histórico laboral, de acordo com modelo fornecido pelo INSS, com os detalhes das atividades realizadas e riscos ocupacionais.","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646427","enunciado":"Especializado - Especialidade: Medicina (Do Trabalho) É dever do médico do trabalho, segundo o Código de Conduta do Médico do Trabalho:","a":"não permitir que seus serviços sejam utilizados no sentido de propiciar direta ou indiretamente o desligamento do empregado.","b":"considerar a gestação como fator de inaptidão ao trabalho, desde que não haja risco para a gestante e para o feto na atividade a ser desempenhada.","c":"ao constatar inaptidão por motivos médicos para determinado posto de trabalho, informar a empresa dos motivos","d":"médicos. marginalizar, nos exames admissionais, portadores de afecções ou deficiências físicas.","e":"não informar empregadores sobre riscos existentes no ambiente de trabalho, bem como as medidas necessárias para seu controle.","gabarito":"A","materia":"Medicina","tema":"Anatomia e Fisiologia Humana em Medicina","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646426","enunciado":"Especializado - Especialidade: Medicina (Do Trabalho) Ao considerar a identificação e caracterização de substâncias químicas no ambiente de trabalho, assinale a alternativa que apresenta a afirmativa correta.","a":"Perigo é a probabilidade de um efeito adverso ser causado a um organismo, sistema ou (sub)população, sob circunstâncias de exposição a este agente.","b":"Risco é a propriedade inerente de um agente ter o potencial de causar efeitos adversos quando um organismo, sistema ou (sub)população é exposta a este agente.","c":"TLV, Risco, Perigo, Limite de Tolerância e Limite de Ação não são conceitos a serem considerados no conjunto da caracterização das substâncias químicas.","d":"TLV (Threshold Limit Values), um dos limites de exposição ocupacional estabelecidos pela ACGIH, refere- -se à concentração de substâncias químicas no ar e representa condições sobre as quais acredita-se que a maioria dos trabalhadores possam estar expostos diariamente sem efeito adverso à saúde.","e":"Para se saber se uma substância química deve ser caracterizada como Risco, observa-se o conjunto de sua toxicicidade, características físico-químicas, Proteção Coletiva e Frequência de Uso.","gabarito":"D","materia":"Medicina","tema":"Anatomia e Fisiologia Humana em Medicina","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646425","enunciado":"Especializado - Especialidade: Medicina (Do Trabalho)","a":"Assinale a alternativa que apresenta a definição do fator previdenciário no sistema previdenciário brasileiro. Ajuste aplicado à idade mínima de aposentadoria para mulheres.","b":"Cálculo utilizado para determinar o valor da aposentadoria por invalidez.","c":"Cálculo que considera a idade, expectativa de vida e tempo de contribuição.","d":"Benefício adicional concedido a trabalhadores com deficiência.","e":"Desconto aplicado ao salário de contribuição de trabalhadores autônomos.","gabarito":"C","materia":"Direito Previdenciário","tema":"Regime Geral de Previdência Social - RGPS","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646424","enunciado":"Especializado - Especialidade: Medicina (Do Trabalho) As etapas da absorção, distribuição, armazenamento, biotransformação e eliminação de substâncias químicas absorvidas pelo organismo formam o conjunto denominado toxicocinética.","a":"Frente a substâncias potencialmente tóxicas, assinale o conceito farmacológico correto. ordenação da cadeia de eventos ou fases que levam ao efeito sistêmico de um xenobiótico é, respectivamente: A contato, exposição, dinâmica, cinética e clínica.","b":"A biotransformação transforma substâncias hidrossolúveis em lipossolúveis. Esse processo aumenta ou diminui a toxicidade.","c":"Biodisponibilidade indica o percentual da substância que atingiu a circulação sistêmica após sua administração,","d":"absorção e inativação por enzimas hepáticas. Na biodisponibilidade, a inativação de uma substância potencialmente tóxica ocorre no pulmão.","e":"A orientação da cadeia de eventos ou fatores que levam ao efeito sistêmico de um xenobiótico é, respectivamente: exposição, cinética, contato, dinâmica e clínica. Segurança e Saúde no Trabalho>Riscos Ocupacionais (Análise e Gerenciamento de Riscos) ,","gabarito":"E","materia":"Medicina","tema":"Anatomia e Fisiologia Humana em Medicina","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_550","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio Especializado - Especialidade: Medicina (Do Trabalho) Quanto à monitoração biológica dos trabalhadores de uma empresa, é correto considerar que se trata de:","a":"conjunto de avaliação de exposição possível dos trabalhadores aos agentes químicos, verificação de ruído, fumos e","b":"poeiras metálicas no ambiente de trabalho. avaliação que estima a exposição possível do trabalhador aos agentes químicos e seus efeitos.","c":"análise de exposição dos trabalhadores a agentes químicos e seus efeitos no organismo, por meio de amostras biológicas.","d":"análise de amostras que podem promover medidas de melhoria e aumento de treinamento de comunicação e de","e":"reuniões de equipe. análise de amostras de sangue, urina, cabelo e alimentos consumidos no local de trabalho. Segurança e Saúde no Trabalho>Doenças do Trabalho e Doenças Profissionais (Dort) ,","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_551","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio Especializado - Especialidade: Medicina (Do Trabalho)","a":"No que se refere ao trabalhador exposto ao monóxido de carbono, assinale a alternativa correta. A intoxicação por Monóxido de carbono causa asfixia simples.","b":"A exposição crônica entre trabalhadores pode levar à aterogênese por permeabilidade vascular anormal, captação","c":"vascular aumentada de lipídios e aumento de adesividade plaquetária. Nos casos graves, pode levar à hipertensão arterial, insuficiência cardíaca e derrame pleural.","d":"A exposição crônica a altos níveis de monóxido de carbono poderá levar à miocardiopatia restritiva.","e":"O monóxido de carbono pode acarretar carboxihemoglobinemia e fibrose maciça dos pulmões.","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646421","enunciado":"Especializado - Especialidade: Medicina (Do Trabalho) Dentre as opções a seguir, que apresentam diferentes conceitos relacionados à epidemiologia, assinale aquele que está","a":"correto. Virulência é a capacidade do agente invadir o organismo hospedeiro e ali permanecer, multiplicando-se.","b":"Efeito Trabalhador Sadio é o que mostra melhores níveis de mortalidade e morbidade dos trabalhadores em","c":"comparação com a população geral. Sensibilidade é a proporção de indivíduos sem a doença, apresentando teste negativo para ela.","d":"Especificidade é a proporção de indivíduos com a doença, mas que apresentam teste negativo para ela.","e":"Acurácia é o valor verdadeiro igual ao valor estimado real.","gabarito":"A","materia":"Medicina","tema":"Epidemiologia","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646420","enunciado":"Especializado - Especialidade: Medicina (Do Trabalho)","a":"Dentre as doenças a seguir, é correto afirmar que aquelaque tem relação mais específica com a exposição ao frio é a Dermatose.","b":"Síncope.","c":"Cãibra.","d":"Eritema Pernio.","e":"Ceratose palmar.","gabarito":"D","materia":"Medicina","tema":"Anatomia e Fisiologia Humana em Medicina","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646419","enunciado":"Especializado - Especialidade: Medicina (Do Trabalho)","a":"O principal objetivo da análise estatística de acidentes de trabalho em uma empresa é identificar causas e padrões para melhorar a segurança.","b":"acompanhar o FAP/NETEP.","c":"prever acidentes futuros.","d":"identificar o uso de Equipamento de Proteção Individual.","e":"avaliar o papel das doenças crônicas nos acidentes.","gabarito":"A","materia":"Segurança e Saúde no Trabalho","tema":"Acidente de Trabalho (CAT) ,Fundamentos da Saúde Ocupacional","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646418","enunciado":"Especializado - Especialidade: Medicina (Do Trabalho)","a":"Assinale a alternativa que apresenta a abordagem principal no tratamento da dermatose ocupacional. Aplicação de pomadas de corticosteroides.","b":"Uso indiscriminado de anti-histamínicos.","c":"Administração de antibióticos sistêmicos.","d":"Aplicação de óleos essenciais.","e":"Evitar completamente qualquer exposição a substâncias irritantes ou alérgicas.","gabarito":"E","materia":"Medicina","tema":"Anatomia e Fisiologia Humana em Medicina","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646417","enunciado":"Especializado - Especialidade: Medicina (Do Trabalho) o De acordo com a Lei n 8.213/91, que dispõe sobre planos de benefícios da Previdência Social, assinale a alternativa correta.","a":"Para cumprir as cotas previstas na Lei no 8.213/91, as empresas devem calcular a porcentagem de vagas para pessoas com deficiência com base no número total de vagas disponíveis.","b":"A penalidade pelo não cumprimento da cota de contratação de pessoas com deficiência ou reabilitadas, estabelecida pela Lei no 8.213/91, é de natureza criminal e financeira.","c":"As cotas previstas na Lei no 8.213/91 de vagas para pessoas com deficiência e reabilitadas devem ser calculadas pelas empresas com base no seu número total de funcionários.","d":"Se uma empresa não cumprir a cota de contratação de pessoas com deficiência e reabilitadas, estabelecida pela Lei no 8.213/91, ela pode ser sujeita a penalidades criminais e financeiras para os proprietários.","e":"Empresas com 100 ou mais empregados são obrigadas a reservarem uma porcentagem de 5% das vagas para pessoas com deficiência. Segurança e Saúde no Trabalho>","gabarito":"C","materia":"Direito Previdenciário","tema":"Regimes da Previdência Social","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646416","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio Especializado - Especialidade: Medicina (Do Trabalho)","a":"Pelo novo texto da NR-9, sua característica legal principal é definida como aquela que monitora os riscos físicos, biológicos, ergonômicos e de acidentes.","b":"mantém o PPRA, que se associa ao PGR na definição e controle de riscos ocupacionais.","c":"foi substituída integralmente pela NR que define o PGR.","d":"identifica a exposição ocupacional aos agentes físicos, químicos e biológicos.","e":"instrui o PPRA e o PGR.","gabarito":"D","materia":"NR 9 - Norma Regulamentadora n° 9 - Programa de Prevenção de Riscos Ambientais - PPRA (Agentes Químicos)","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646415","enunciado":"Especializado - Especialidade: Medicina (Do Trabalho) Jovem, masculino, 30 anos, trabalhador há 2 anos e 3 meses em fábrica de algodão hidrófilo, inicia quadro de dispneia e sibilos com melhora em finais de semana há cerca de 40 dias.","a":"Assinale a alternativa que corresponde à possível diagnóstico e exame complementar indicado Asma sem latência / raio X de Tórax em duas incidências.","b":"Asma ocupacional / Medida seriada de Peak Flow.","c":"Bissinose / Espirometria.","d":"Asma induzida / Espirometria.","e":"Bissinose / Exame de escarro para teste de toxinas produzidas por bactérias que atuam junto ao algodão.","gabarito":"B","materia":"Medicina","tema":"Anatomia e Fisiologia Humana em Medicina","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646408","enunciado":"Especializado - Especialidade: Medicina (Do Trabalho)","a":"O que caracteriza um estudo epidemiológico do tipo ecológico? Coleta de dados por meio de entrevistas com pacientes diagnosticados com a doença.","b":"Análise de informações agregadas em grupos populacionais, em vez de dados individuis.","c":"Coleta de dados em nível individual e acompanhamento longitudinal dos participantes.","d":"Ter como objeto de estudo questões ambientais e seus efeitos sobre os indivíduos.","e":"Investigação de casos isolados de doenças em diferentes regiões geográfica","gabarito":"B","materia":"Direito Sanitário","tema":"Saúde Pública","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646407","enunciado":"Especializado - Especialidade: Medicina (Do Trabalho) Qual princípio fundamental da Reforma Sanitária Brasileira é expresso na frase: “Saúde é direito de todos e dever do","a":"Estado”? Equidade.","b":"Igualdade.","c":"Universalidade.","d":"Descentralização.","e":"Integralidade.","gabarito":"C","materia":"Direito Sanitário","tema":"Saúde Pública","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646394","enunciado":"","a":"Especializado - Especialidade: Engenharia (Mecânica) figura mostra quatro símbolos utilizados na cotagem de um desenho técnico mecânico. É correto afirmar que se trata de indicação de tolerâncias geométricas que indicam, na ordem e da esquerda para a direita,","b":"A batimento, paralelismo, posição de um elemento e retilineidade. direção, inclinação, concentricidade e planeza.","c":"batimento, inclinação, circularidade e horizontalidade.","d":"batimento, paralelismo, circularidade e retilineidade.","e":"inclinação, batimento, posição de um elemento e planeza.","gabarito":"A","materia":"Engenharia Mecânica","tema":"Manutenção Mecânica","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646393","enunciado":"","a":"Especializado - Especialidade: Engenharia (Mecânica) tecnologia BIM alavancou uma série de ferramentas, destacando-se, como exemplo, o Programa Revit MEP, da Autodesk. As opções de ferramentas oferecidas pelo Revit abrangem diversas áreas e profissionais de projeto e construção/fabricação. Nesse contexto, é correto afirmar que o Revit MEP foi baseado na tecnologia BIM e seus recursos atendem necessidades mais amplas, apesar de não possibilitar A integrações entre profissionais de mecânica, elétrica e hidráulica, servindo apenas como excelente ferramenta para projetos individuais e customizados.","b":"foi baseado na tecnologia BIM e seus recursos atendem necessidades mais amplas, indo além dos recursos físicos, como documentação executiva e elementos físicos de construção ou fabricação, como indica a sigla MEP, que se refere, respectivamente, a instalações mecânicas, elétricas e de tubulações.","c":"surgiu como concorrente da tecnologia BIM, criando uma plataforma dedicada apenas às instalações mecânicas, relativamente mal atendidas pela tecnologia BIM.","d":"veio para otimizar a economia nos projetos mecânicos, elétricos e de tubulações, mas depende da tecnologia BIM para executar as funções de CAD 3 D, uma vez que a tecnologia BIM é um software que permitiu ser alocado dentro da Plataforma Revit.","e":"depende da tecnologia CAD como complemento para os projetos arquitetônicos, uma vez que os projetos mecânicos já possuem bibliotecas customizadas, porém, ainda sem a parte CAD para elétrica, que virá em breve.","gabarito":"B","materia":"Engenharia Mecânica","tema":"Planejamento e Informatização na Engenharia ,Processos e Planejamento de Produção","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646392","enunciado":"Especializado - Especialidade: Engenharia (Mecânica) Um avanço verdadeiramente revolucionário, inclusive aplicável a variados projetos de engenharia e arquitetura, diz respeito à tecnologia BIM (Building Information Modeling), com base na qual surgiram outras excelentes ferramentas. Nesse contexto, é correto afirmar que","a":"unindo-se à da tecnologia BIM, a série de programas e ferramentas que surgiram permitiram melhorias no gerenciamento de dados, controle e desenvolvimento em todas as fases de projeto e materialização da obra.","b":"os recursos oferecidos ficam limitados às fases de projeto orçamentário e não de desenvolvimento técnico e otimização do projeto, mas, mesmo assim supera outras tecnologias orçamentárias oferecidas.","c":"a tecnologia BIM já oferecia todos os recursos existentes hoje, mas essas novas ferramentas foram bem recebidas por oferecerem preço baixo e viabilizar BIM para qualquer pequena empresa.","d":"os recursos oferecidos ficam limitados à fase de desenvolvimento do projeto e não durante a construção ou","e":"fabricação. há, atualmente, tendência de substituição total da tecnologia BIM pela tecnologia Revit, da Autodesk.","gabarito":"A","materia":"Engenharia Mecânica","tema":"Planejamento e Informatização na Engenharia ,Processos e Planejamento de Produção","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646391","enunciado":"Especializado - Especialidade: Engenharia (Mecânica) BDI - Budget Difference Income é um conceito relacionado a levantamentos financeiros envolvidos em um projeto. Considerando a afirmação apresentada, é correto dizer afirmar que","a":"aluguel de um imóvel para ser escritório sede e equipamentos utilizados em todas as obras na empresa não fazem parte do BDI.","b":"o BDI inclui custos relativos a atividades auxiliares contratadas, mas não inclui os de veículos de uso cotidiano nas obras.","c":"o BDI contém todos os custos que estão diretamente relacionados com a execução física da obra, como aluguel de","d":"equipamentos e seguros, por exemplo. o BDI, para ser mais simples, representa o valor total mínimo direto previsto para realização do projeto conceitual.","e":"o BDI contém todos os custos que não estão diretamente relacionados com a execução física da obra, como, por exemplo, aluguel de equipamentos, reservas para incertezas e seguros.","gabarito":"E","materia":"Engenharia Mecânica","tema":"Programação, Controle e Fiscalização de Obras ,Orçamento e Composição de Custos","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646390","enunciado":"Especializado - Especialidade: Engenharia (Mecânica)","a":"Duas partes fundamentais de um projeto são a sua EAP e o seu Escopo, sobre os quais é correto afirmar que a EAP independe do escopo, mas depende da orçamentação do projeto.","b":"o Escopo não se refere à entrega final do projeto, exceto se os custos previstos forem insuficientes.","c":"o Escopo, por ser essencialmente uma representação gráfica, um cronograma, deve organizar a EAP.","d":"a EAP representa o detalhamento hierárquico de uma parte fundamental do projeto, que é o seu Escopo.","e":"o Escopo depende da EAP para ser formulado.","gabarito":"D","materia":"Engenharia Mecânica","tema":"Planejamento e Informatização na Engenharia ,Processos e Planejamento de Produção","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646389","enunciado":"Especializado - Especialidade: Engenharia (Mecânica) Na comunicação entre pessoas envolvidas em projetos, diversos termos e siglas são utilizados e convém que sejam reconhecidos e entendidos. Analise os textos reduzidos I, II e III para identificar os termos correspondentes. I. somatória dos custos identificados em cada atividade da EAP; II. empresas ou organizações que possam ser afetadas de algum modo pela execução do projeto; III. organização ou pessoa de grande autoridade que proporciona recursos financeiros necessários para arcar com a execução do projeto.","a":"Considerando o exposto, é correto afirmar que os textos I, II e III referem-se, respectivamente, aos termos Budget, Stakeholders e Sponsor.","b":"Sponsor, Stakeholders e Budget.","c":"Escopo, Patrocinadores e Budget.","d":"Budget, Sponsor e Patrocinador.","e":"Patrocinadores, Stakeholders e Sponsor.","gabarito":"A","materia":"Engenharia Mecânica","tema":"Planejamento e Informatização na Engenharia ,Processos e Planejamento de Produção","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646388","enunciado":"Especializado - Especialidade: Engenharia (Mecânica) 3 Uma viga engastada, de aço, de peso específico igual a 80 kN/m , de comprimento 3 metros e seção transversal constante de 10 x 10 cm, é utilizada como reforço numa estrutura predial. No centro da viga é preso um cabo de aço que sustenta um peso de 10 kN e na sua extremidade livre há outro cabo de aço que sustenta uma massa de 400 kg. Considerando o exposto, é correto afirmar que o momento fletor atuante no engastamento, em N.m, pode ser estimado em: 2","a":"Dado: g = 10 m/s . 19.800.","b":"27.000.","c":"63.000.","d":"30.600.","e":"6.300.","gabarito":"D","materia":"Engenharia Mecânica","tema":"Mecânica dos Sólidos ,Modelagem Estática e Dinâmica","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646387","enunciado":"Especializado - Especialidade: Engenharia (Mecânica) Um condicionador de ar opera com ciclo de compressão de vapor refrigerante. Seu condensador opera com condensação do fluido feita por ventilador e ar a uma temperatura de 29 ºC.","a":"É adequado e possível a temperatura de condensação do fluido refrigerante ser, em ºC, de 29.","b":"38.","c":"27.","d":"25.","e":"20.","gabarito":"B","materia":"Engenharia Mecânica","tema":"Sistemas Termomecânicos ,Ventilização, Climatização e Ar Condicionado","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646386","enunciado":"Especializado - Especialidade: Engenharia (Mecânica) Em sistemas de condicionamento de ar, exaustão, ventilação etc., geralmente as análises e operações envolvem valores bem reduzidos de pressão. As conversões e entendimentos sobre unidades de pressão são bastante importantes. Há uma variedade imensa de instrumentos para medição de pressão. Se um instrumento indicar uma pressão de 27,2 milímetros de coluna de água, é correto afirmar que as conversões para mmHg e Pa valerão, respectivamente: 3 3","a":"Dados: Peso específico da Água = 10 000 N/m e do Mercúrio = 136 000 N/m . 20 e 272000.","b":"0,002 e 272.","c":"0,0027 e 272000.","d":"2 e 272.","e":"3,6 e 367000.","gabarito":"D","materia":"Engenharia Mecânica","tema":"Sistemas Termomecânicos ,Ventilização, Climatização e Ar Condicionado","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646385","enunciado":"Especializado - Especialidade: Engenharia (Mecânica) Os sistemas de ventilação podem garantir a qualidade aceitável ou requerida do ar interno. A quantidade de ar de","a":"renovação a ser insuflado dependerá, principalmente, do sistema de condicionamento de ar utilizado.","b":"apenas da vazão e da temperatura do ar a ser insuflado no ambiente.","c":"da concentração permitida de contaminantes gerados no ambiente em questão.","d":"da umidade e da temperatura de bulbo seco do ar externo de renovação.","e":"da umidade e da temperatura serem mantidas no ambiente.","gabarito":"C","materia":"Engenharia Mecânica","tema":"Sistemas Termomecânicos ,Ventilização, Climatização e Ar Condicionado","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646384","enunciado":"Especializado - Especialidade: Engenharia (Mecânica) Na gestão da qualidade e da manutenção, as análises de controle contam com dados que normalmente são representados por siglas em inglês e são bem conhecidas. Os significados expressos em I, II e III deverão ser relacionados às siglas correspondentes, do inglês: I. média aritmética dos tempos de reparo de um item; II. média aritmética dos tempos entre falhas sucessivas de um item; III. média de tempo entre qualquer tipo de ação, corretiva ou preventiva.","a":"Considerando o exposto, é correto afirmar que as siglas correspondentes a I, II e III são, respectivamente, MTBF, MTTR e MTBM.","b":"MTBM, MTTR e MTBF.","c":"MTTR, MTBM e MTBF.","d":"MTBF, MTBM e MTTR.","e":"MTTR, MTBF e MTBM. Administração Geral>Gestão Estratégica ,Abordagem Neoclássica da Administração ,","gabarito":"E","materia":"Engenharia Mecânica","tema":"Manutenção Mecânica ,Conceitos Básicos de Manutenção Mecânica","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646383","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio Especializado - Especialidade: Engenharia (Mecânica) Os sistemas de gestão de projetos, planejamento e de produção podem contar com diversas ferramentas de análise e integração, que deverão ser identificadas. Considerando a afirmação apresentada, é correto afirmar que o planejamento, relativo às necessidades de materiais, por exemplo, conta com sistemas denominados","a":"ERPs, que são sistemas de gestão que permitem acesso fácil, integrado e confiável aos dados de uma empresa, permitindo melhor fluxo de informações para atender especialmente à dinâmica dos departamentos de produção.","b":"MRPs, que são sistemas de gestão que permitem acesso fácil, integrado e confiável aos dados de uma empresa, permitindo melhor fluxo de informações corporativas, porém, na sua maioria, não conseguem lidar com a dinâmica do sistema produtivo para atender departamentos de produção.","c":"ERPs, criados com forte foco na produção, desconsiderando outras atividades complementares fundamentais, coisa que não ocorre com os MRPs, que integram de modo excelente processos relacionados, mas de diferentes setores.","d":"MRPs, que são sistemas de gestão que permitem acesso fácil, integrado e confiável aos dados de uma empresa, permitindo melhor fluxo de informações, substituindo os antigos ERPs, que tinham foco exagerado na produção.","e":"ERPs, que são sistemas de gestão que permitem acesso fácil, integrado e confiável aos dados de uma empresa, permitindo melhor fluxo de informações corporativas, porém, na sua maioria, não conseguem lidar com a dinâmica do sistema produtivo para atender departamentos de produção.","gabarito":"E","materia":"Decorrências da Teoria Neoclássica: Processo Administrativo - Planejamento","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646382","enunciado":"Especializado - Especialidade: Engenharia (Mecânica) O ciclo PDCA é uma importante ferramenta de planejamento da produção e da qualidade. As autoridades e responsabilidades podem ser definidas para pessoas diferentes, encaixadas em cada uma das letras da sigla PDCA. Considerando a afirmação apresentada, é correto afirmar que as letras C e D podem ser relacionadas, por exemplo, às","a":"pessoas que, respectivamente, verificam e desempenham.","b":"desempenham e verificam.","c":"desempenham e planejam.","d":"padronizam e desempenham.","e":"corrigem e verificam.","gabarito":"A","materia":"Administração Geral","tema":"Gestão da Qualidade ,Ciclo PDCA","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646381","enunciado":"Especializado - Especialidade: Engenharia (Mecânica) Existem particularidades na maioria das aplicações de lubrificação em máquinas e equipamentos. Tanto o pessoal de manutenção como os projetistas devem estar atentos. Um rolamento rígido de esferas de especificação (código) 6216, de diâmetro externo igual a D = 100 mm e diâmetro interno d, a ser obtido para cálculo do diâmetro médio, foi selecionado num projeto. Há uma orientação de catálogo que indica que a lubrificação por banho de óleo só pode ser aplicada se obedecer a um coeficiente n.dm ≤ 100.000 (cem mil) (mm.rpm). Considerando as afirmações apresentadas, é correto afirmar que a lubrificação por banho de óleo poderá ser aplicada se a","a":"rotação máxima desse rolamento for de, aproximadamente, 1 253 rpm.","b":"1 111 rpm.","c":"4 000 rpm.","d":"3 448 rpm.","e":"1 724 rpm.","gabarito":"B","materia":"Engenharia Mecânica","tema":"Sistemas Mecânicos ,Lubrificação e Desgaste","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646380","enunciado":"Especializado - Especialidade: Engenharia (Mecânica) Muitos equipamentos possuem partes muito exigentes em termos de lubrificação. Para uma boa vida útil dos rolamentos, por exemplo, a lubrificação correta é fundamental. Sobre a lubrificação, os rolamentos e suas características, é correto afirmar que","a":"rotação limite dos rolamentos só é afetada pelo tipo de lubrificação, sendo menor quando o rolamento é lubrificado com óleo.","b":"lubrificação por graxa é mais indicada para rolamentos de baixa capacidade de carga dinâmica, pois esses não devem operar em altas rotações.","c":"rotação limite dos rolamentos só é afetada pelo tipo de lubrificação, sendo menor quando o rolamento é lubrificado com graxa.","d":"a rotação limite dos rolamentos depende do diâmetro de seus elementos rolantes (esferas, rolos etc.) e correta lubrificação e condições de catálogo.","e":"lubrificação por banho de óleo é mais indicada para rolamentos de baixa capacidade de carga dinâmica e não depende da rotação.","gabarito":"D","materia":"Engenharia Mecânica","tema":"Sistemas Mecânicos ,Lubrificação e Desgaste","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646379","enunciado":"Especializado - Especialidade: Engenharia (Mecânica) Cuidados com a rede elétrica da empresa e com a economia de energia são muito importantes. Sabe-se que os motores elétricos são grandes consumidores de energia elétrica. Tanto o Rendimento do motor elétrico quanto o Fator de Potência (cosϕ) devem ser bem entendidos para que se consiga aplicar qualquer iniciativa de economizar energia e evitar problemas nas redes elétricas. Se uma máquina exigir do eixo do motor uma potência de 9 kW, com o fator de potência igual a 0,6, a concessionária de","a":"energia elétrica terá que fornecer 15 kW, sendo recomendável a redução do fator de potência, inclusive para redução da corrente na rede elétrica.","b":"54 kW, sendo recomendável a redução do fator de potência, inclusive para redução da corrente na rede elétrica.","c":"15kVA, sendo recomendável o aumento do fator de potência, inclusive para redução da corrente na rede elétrica.","d":"5,4 kVA, sendo recomendável o aumento do fator de potência, inclusive para redução da corrente na rede elétrica.","e":"5,4 kW, sendo recomendável a redução do fator de potência, inclusive para redução da corrente na rede elétrica.","gabarito":"C","materia":"Engenharia Elétrica","tema":"Análise de SEP ,Fluxo de Potência ,Sistema Elétrico Brasileiro","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646378","enunciado":"Especializado - Especialidade: Engenharia (Mecânica) Os motores elétricos são amplamente aplicados para acionamentos mecânicos, como elevadores, escadas rolantes, sistemas de condicionamento de ar, ventilação etc. A respeito das características dos motores CA assíncronos, são normalmente oferecidos no mercado as opções de 2, 4, 6 e 8 polos e uma grande variedade de potências nominais. Fazendo-se algumas comparações entre 2 e 8 polos, é correto afirmar que podem representar suas rotações de catálogo os","a":"valores 1 750 e 1 210 rpm, e que a carcaça do motor de 2 polos é menos robusta que a do motor de 8 polos.","b":"3 600 e 840 rpm, e que a carcaça do motor de 2 polos é mais robusta que a do motor de 8 polos.","c":"3 500 e 820 rpm, e que a carcaça do motor de 2 polos é menos robusta que a do motor de 8 polos.","d":"840 e 3 600 rpm, e que a carcaça do motor de 2 polos é mais robusta que a do motor de 8 polos.","e":"3 600 e 1 000 rpm, e que a carcaça do motor de 2 polos é menos robusta que a do motor de 8 polos.","gabarito":"C","materia":"Engenharia Elétrica","tema":"Máquinas Elétricas ,Sistema Elétrico Brasileiro","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646377","enunciado":"Especializado - Especialidade: Engenharia (Mecânica) Em certas situações, a parada de uma máquina exige soluções inevitavelmente muito rápidas do pessoal de manutenção e, afim de operar sempre com segurança e evitar falhas ainda mais graves no futuro, as decisões devem ser bem cuidadosas. Nesse contexto, sendo necessária, apesar de indesejável, uma solução emergencial que deverá ser corrigida brevemente, é","a":"correto afirmar que seria menos crítico um eixo de aço ABNT 1060 ser substituído por outro, de ferro fundido cinzento.","b":"que um rolamento rígido (ou fixo) de esferas, de código SKF 6210, substituísse um rolamento semelhante, como o rolamento de código SKF 6210 ZZ, pois ambos possuem furo de diâmetro 50 mm, sendo o ZZ lubrificado por graxa.","c":"substituir um parafuso de aço danificado, de rosca M8, com gravação na cabeça de código 10.9 (classe de resistência), por outro semelhante, também de rosca M8, de aço, que não apresenta qualquer gravação na cabeça do parafuso.","d":"substituir uma engrenagem do par, de módulo igual a 5,2 mm e 50 dentes por outra de módulo igual a 6,5 mm e 40","e":"dentes, pois elas apresentam o mesmo diâmetro primitivo. substituir uma correia dentada por uma correia trapezoidal, mais simples, porém mais robusta e barata. Engenharia Mecânica>Manutenção Mecânica ,Tipos (corretiva, preventiva, preditiva e detectiva) ,","gabarito":"B","materia":"Engenharia Mecânica","tema":"Manutenção Mecânica","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_579","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio Especializado - Especialidade: Engenharia (Mecânica) Entre os diversos tipos de manutenção, encontram-se as quatro seguintes: a Corretiva, a Preventiva, a Preditiva e a Produtiva Total (TPM), cada uma com suas características e aplicações principais. Considerando apenas as características de I a III: I. prever o provável momento da falha, antecipando intervenção antes da ocorrência, graças à coleta de sinais sem interrupção do funcionamento; II. disponibilizar ao máximo as máquinas e equipamentos, sem improvisações, e executar rotinas que evitem paradas imprevistas; III. restabelecer o funcionamento normal, analisar e procurar modos de evitar a reincidência. É correto afirmar que, entre os quatro tipos de manutenção apresentados, os itens I, II e III correspondem, respectivamente,","a":"às manutenções Corretiva, Preventiva e TPM.","b":"Preventiva, Preditiva e Corretiva.","c":"Preditiva, TPM, Preventiva.","d":"Corretiva, Preditiva e Preventiva.","e":"Preditiva, Preventiva e Corretiva.","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646375","enunciado":"Especializado - Especialidade: Engenharia (Mecânica) As bombas centrífugas radiais são as mais utilizadas para transporte de líquidos. É correto afirmar, com relação aos seus componentes, aspectos de manutenção, vedações, características de operação etc., que","a":"os selos mecânicos não apresentam o vazamento típico das gaxetas, podem apresentar a vantagem de vida útil mais longa, mas normalmente custam mais caros que as gaxetas.","b":"o anel cadeado, também conhecido como cadeado d’água e anel lanterna, pode substituir o anel de desgaste, porém apenas em bombas de rotor aberto, vedadas por gaxetas.","c":"os selos mecânicos não apresentam o vazamento típico das gaxetas, apresentam a desvantagem de vida útil mais curta e são muito mais baratos.","d":"o anel de desgaste reduz o vazamento interno da bomba, porém reduz seu rendimento mecânico, aumentando sua potência.","e":"os selos mecânicos não apresentam o vazamento típico das gaxetas, porém apresentam menor vida útil e custam mais caros.","gabarito":"A","materia":"Engenharia Mecânica","tema":"Sistemas Fluidomecânicos ,Sistemas Hidráulicos e Pneumáticos","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646374","enunciado":"Especializado - Especialidade: Engenharia (Mecânica) Considere o enunciado a seguir para resolução das questões de números 38 a 40. Numa instalação hidráulica, haverá necessidade de mudar a posição do reservatório superior, trazendo seu nível para a mesma cota que o nível do reservatório inferior, 20 metros abaixo. A constituição geral será mantida, exceto o comprimento dos tubos, que deverá ser reduzido em 40%, mantendo-se a mesma bomba e o mesmo fluido, a água. Pretende-se, assim que possível, fazer modificações que permitam manter a vazão final próxima da vazão anterior, quando a cota estava 20 metros acima, mas pretende-se usar a mesma bomba, que é do tipo centrífuga radial, com vedação por gaxetas. É correto afirmar, analisando-se melhor a tubulação, suas perdas de carga e seus demais componentes, para corrigir as","a":"mudanças devido às alterações ocorridas, que o diâmetro dos tubos poderá ser reduzido, diminuindo as perdas de carga, além de utilizar válvula globo menor para controle de vazão.","b":"reduzido, aumentando as perdas de carga, além de utilizar válvula globo menor para controle de vazão.","c":"reduzido, mantendo constantes as perdas de carga, além de utilizar válvula gaveta menor para controle de vazão.","d":"aumentado, elevando as perdas de carga, além de utilizar válvula gaveta menor para controle de vazão.","e":"mantido, perdurando as perdas de carga, além de utilizar válvula globo menor para controle de vazão.","gabarito":"B","materia":"Engenharia Mecânica","tema":"Sistemas Fluidomecânicos ,Sistemas Hidráulicos e Pneumáticos","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646373","enunciado":"Especializado - Especialidade: Engenharia (Mecânica) Analisando outras consequências, mesmo sem a consideração de valores, é correto afirmar que, quanto às gaxetas, essa","a":"mudança tenderá a apresentar mesmo vazamento e o motor elétrico CA, assíncrono, da bomba, não sofrerá alterações de operação.","b":"reduzir seu vazamento e o motor elétrico CA, assíncrono, da bomba, não sofrerá alterações de operação.","c":"aumentar seu vazamento e o motor elétrico CA, assíncrono, da bomba, poderá ficar subcarregado.","d":"aumentar seu vazamento e o motor elétrico CA, assíncrono, da bomba, ficará subcarregado.","e":"reduzir seu vazamento e o motor elétrico CA, assíncrono, da bomba, poderá sofrer sobrecarga.","gabarito":"E","materia":"Engenharia Mecânica","tema":"Sistemas Fluidomecânicos ,Sistemas Hidráulicos e Pneumáticos","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646372","enunciado":"Especializado - Especialidade: Engenharia (Mecânica)","a":"Analisando-se apenas a pressão no bocal de saída da bomba e a sua vazão, é correto afirmar que a pressão aumentará e a vazão sofrerá redução.","b":"aumentará e a vazão também aumentará.","c":"sofrerá redução e a vazão diminuirá.","d":"sofrerá redução e a vazão aumentará.","e":"permanecerá a mesma, mas a vazão aumentará.","gabarito":"D","materia":"Engenharia Mecânica","tema":"Sistemas Fluidomecânicos ,Sistemas Hidráulicos e Pneumáticos","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646371","enunciado":"Especializado - Especialidade: Engenharia (Mecânica) Um processo de soldagem utiliza gás inerte ou mistura de gases para proteção do arco elétrico e da poça de fusão, utiliza eletrodo sinterizado de tungstênio e permite ou não metal de enchimento.","a":"É correto afirmar que se trata de soldagem denominada MIG.","b":"soldagem por pontos ou por costura.","c":"TIG.","d":"MAG.","e":"soldagem a gás.","gabarito":"C","materia":"Engenharia Mecânica","tema":"Sistemas Mecânicos ,Processos de Fabricação","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646370","enunciado":"Especializado - Especialidade: Engenharia (Mecânica) As máquinas operatrizes com CNC são muito produtivas e preferidas nas usinagens, quando possível. Um ponto de destaque refere-se à rapidez e precisão dos movimentos de avanço. É usual referir-se aos centros de usinagem com CNC dizendo seu número e eixos. Num certo centro de usinagem, um dos movimentos é o de rotação da mesa em torno do eixo X e outro é a rotação em torno do eixo Z da máquina.","a":"É correto afirmar que essas rotações em torno de X e de Z são, geralmente, denominados eixos A e C.","b":"B e C.","c":"C e B.","d":"C e A.","e":"B e A.","gabarito":"A","materia":"Engenharia Mecânica","tema":"Sistemas Mecânicos ,Processos de Fabricação","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646369","enunciado":"Especializado - Especialidade: Engenharia (Mecânica) Analisando as propriedades dos aços ABNT 8 620, ABNT 1 020 e ABNT 1095, sem qualquer tratamento, é correto afirmar","a":"que, entre os três, o(s) aço(s) ABNT 1 020 tem baixa resistência mecânica e baixa dureza, mas que podem ser bastante elevadas por têmpera.","b":"1 020 é um aço de baixo carbono e possui 2,0 % de carbono.","c":"8 620 e 1 020 possuem, respectivamente, 20 % de carbono, por ser aço ligado, e 2,0 % de carbono.","d":"1 095 possui maior dureza e fragilidade entre os três, porém é o que apresenta menor limite de resistência à tração.","e":"1 095 possui a maior dureza, mas, devido ao alto teor de carbono, ainda pode ser temperado e revenido.","gabarito":"E","materia":"Engenharia Mecânica","tema":"Materiais de Construção Mecânica ,Propriedades e Comportamentos dos Materiais","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646368","enunciado":"Especializado - Especialidade: Engenharia (Mecânica)","a":"É correto afirmar que uma peça de aço rico em cementita (Fe3C) possui alta dureza, do mesmo modo que aços de baixa liga sem tratamento.","b":"alta fragilidade, do mesmo modo que um aço que passou pelo tratamento de recozimento.","c":"alta dureza, do mesmo modo que os ferros fundidos brancos.","d":"baixa dureza, do mesmo modo que os ferros fundidos cinzentos.","e":"baixa dureza, do mesmo modo que um aço ABNT 1020.","gabarito":"C","materia":"Engenharia Mecânica","tema":"Materiais de Construção Mecânica ,Propriedades e Comportamentos dos Materiais","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646367","enunciado":"Especializado - Especialidade: Engenharia (Mecânica)","a":"Assinale a alterativa correta a respeito dos tratamentos térmicos e termoquímicos. A cementação não admite têmpera posterior ao processo, sendo considerada tratamento termoquímico.","b":"A nitretação a gás tem a desvantagem de ser mais lenta que a feita em banho de sal.","c":"Na nitretação a gás, a lentidão se deve à deposição de carbono no aço.","d":"A nitretação a gás é rápida, porém não permite atingir a dureza obtida no banho de sal.","e":"A nitretação a gás é bem rápida, mas não permite a dureza obtida na cementação.","gabarito":"B","materia":"Engenharia Mecânica","tema":"Materiais de Construção Mecânica ,Ensaios Mecânicos e Tratamentos Térmicos","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646366","enunciado":"Especializado - Especialidade: Engenharia (Mecânica) Há uma grande variedade de aços inoxidáveis, para diferentes condições de aplicação, que devem ser conhecidas.","a":"É correto afirmar sobre esses aços que não permitem têmpera, que é sua principal desvantagem.","b":"alguns não contêm Cromo e todos são amagnéticos.","c":"possuem resistências mecânicas diferentes, mas iguais resistências à corrosão.","d":"alguns deles não contêm Níquel e alguns são magnéticos.","e":"não admitem estrutura martensítica, pois não são magnéticos.","gabarito":"D","materia":"Engenharia Mecânica","tema":"Materiais de Construção Mecânica ,Propriedades e Comportamentos dos Materiais","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646365","enunciado":"Especializado - Especialidade: Engenharia (Mecânica) Analise as afirmações seguintes e escolha a alternativa que se encaixa ou diz respeito, corretamente, aos conceitos da segunda lei da termodinâmica e não à primeira lei da termodinâmica.","a":"Uma máquina térmica que trocasse calor apenas com uma fonte quente teria rendimento nulo, o que é possível, porém indesejável.","b":"Um sistema que opere ciclicamente, transferindo calor de uma fonte fria para uma fonte quente, somente é possível","c":"se não consumir trabalho e é denominado bomba de calor. Num sistema fechado que realiza um ciclo com o meio, o calor e o trabalho líquidos trocados são iguais.","d":"Uma máquina térmica que trocasse calor apenas com uma fonte quente teria rendimento de 100%, o que é","e":"impossível. Independentemente do sentido das trocas do calor e do trabalho, estes são proporcionais, num ciclo termodinâmico. Engenharia Mecânica>Termodinâmica ,Leis e Propriedades da Termodinâmica ,Sistemas Termomecânicos","gabarito":"D","materia":"Engenharia Mecânica","tema":"Termodinâmica ,Leis e Propriedades da Termodinâmica","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_591","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio Especializado - Especialidade: Engenharia (Mecânica) Vapor superaquecido, de temperatura desconhecida, é a fonte quente de uma máquina de Carnot, reversível obviamente. A fonte fria opera a 20 ºC, recebendo calor rejeitado pela fonte quente. A fonte quente fornece à máquina 8 000 kcal e o rendimento do ciclo da máquina térmica é de 30 %.","a":"É correto afirmar que a temperatura da fonte quente é, em ºC, aproximadamente igual a 300.","b":"145.","c":"205.","d":"418.","e":"293.","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646363","enunciado":"Especializado - Especialidade: Engenharia (Mecânica) Um reservatório metálico de óleo combustível contém óleo quente internamente e na parte externa de sua parede vertical","a":"ar atmosférico. respeito das trocas de calor por condução e por convecção, é correto afirmar que, analisando-se a","b":"A convecção, o fluxo de calor é maior que na condução. condução, o fluxo de calor seria maior se a parede do reservatório tivesse maior espessura.","c":"convecção, o fluxo de calor aumentaria com o óleo e o ar em repouso, sem movimentação.","d":"convecção, o fluxo de calor seria maior com iguais temperaturas do ar externo e do óleo.","e":"condução, a resistência térmica poderia ser reduzida com espessura da parede menor.","gabarito":"E","materia":"Engenharia Mecânica","tema":"Termodinâmica ,Transferência de Calor (Condução, Convecção e Radiação)","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646362","enunciado":"Especializado - Especialidade: Engenharia (Mecânica) Diversos conceitos diferentes norteiam a estática dos fluidos. Considerando-se esses conceitos, é correto afirmar que","a":"a pressão no interior de um fluido só depende da profundidade, independente das suas propriedades, conforme a Lei de Stevin.","b":"a lei de Stevin permite observar que a pressão num líquido em repouso depende da profundidade e do formato do recipiente.","c":"as prensas hidráulicas valem-se do conceito de que a pressão aplicada num ponto do fluido em repouso transmite-se a todos os pontos do fluido, segundo Pascal.","d":"o princípio de Arquimedes permite observar que o empuxo viabiliza a flutuação de muitos corpos sólidos, mas não ocorre em corpos totalmente submersos.","e":"as prensas hidráulicas valem-se da lei de Stevin, que mostra que pressão aplicada num ponto do fluido em repouso transmite-se a todos os pontos da superfície do fluido.","gabarito":"C","materia":"Engenharia Mecânica","tema":"Mecânica dos Fluidos ,Estática dos Fluidos","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646361","enunciado":"Especializado - Especialidade: Engenharia (Mecânica) Considere-se um tubo de Venturi horizontal cujo diâmetro da garganta é igual a 25% do diâmetro da região de maior diâmetro, operando sem perdas de carga. A velocidade do fluido incompressível que escoa na garganta do Venturi será de X vezes a velocidade no maior diâmetro.","a":"Considerando o contexto apresentado, é correto afirmar que X será igual a 16.","b":"4.","c":"8.","d":"0,0625.","e":"0,25.","gabarito":"A","materia":"Engenharia Mecânica","tema":"Mecânica dos Fluidos ,Fundamentos e Análise da Cinemática de Escoamentos","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646360","enunciado":"Especializado - Especialidade: Engenharia (Mecânica) Uma máquina utiliza 10 correias trapezoidais de código 5V em sua transmissão. O fabricante oferece, no mercado, correias de códigos 3V, 5V e 8V de dimensões crescentes diferentes. Ocorreu rompimento de 3 correias. Dessa forma, a solução correta a ser dada pela manutenção será","a":"substituir as 3 correias rompidas por 3 correias mais robustas, como as de código 8V, para compensar o desgaste das correias que não rompidas.","b":"aumentar o tensionamento das correias restantes, para evitar deslizamento da correia sobre a polia e aumentar sua vida útil.","c":"substituir todo o jogo de correias por 10 correias de código 8V, para compensar o desgaste das polias e não ser necessário mudar o tensionamento das correias.","d":"substituir todo o jogo de correias, não sendo, normalmente, necessário alterar o tensionamento original dessas","e":"correias. substituir todo o jogo de correias por 10 correias de código 8V, mais robustas, para compensar o desgaste das polias.","gabarito":"D","materia":"Engenharia Mecânica","tema":"Manutenção Mecânica","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646359","enunciado":"Especializado - Especialidade: Engenharia (Mecânica) Na engenharia mecânica é de fundamental importância dominar os conceitos de Energia, Torque, Potência, Rotação e suas relações, para tomadas de decisão em projetos e manutenções, por exemplo. Para análise de um projeto, considerou-se um eixo sobre o qual são acoplados dois elementos de transmissão mecânica, montados com chavetas. O eixo opera recebendo uma potência total de 10 kW. Sabe-se que num desses elementos o torque transmitido pela chaveta é de 40 kN.mm e que a chaveta desse elemento transmite apenas 30% da potência total para outro eixo da máquina. É correto afirmar que, nesse contexto, a rotação do eixo, em rpm, vale:","a":"Dado: Admitir π = 3; Potência = P; Torque = T; n = rotação; ω = 2 . π . n; P = T . ω; unidades devem ser conhecidas. 12,5.","b":"0,125.","c":"0,75.","d":"75.","e":"750.","gabarito":"E","materia":"Engenharia Mecânica","tema":"Sistemas Mecânicos ,Elementos de Máquinas","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646358","enunciado":"Especializado - Especialidade: Engenharia (Mecânica) Conside o enunciado a seguir para resolução das questões de números 23 e 24. Duas vigas cilíndricas de aço, de diâmetros d1 e d2, de mesmo comprimento e mesmo módulo de elasticidade longitudinal 5 (E = 200 MPa) operam sob tração, articuladas em suas duas extremidades. A barra 1 suporta 1,2 . 10 N e a barra 2 suporta 60 kN. O limite e resistência ao escoamento da viga 1 é de 600 MPa e da viga 2 é de 800 MPa. O coeficiente de segurança de ambos os projetos é igual a 2. Dados: Considerar π = 3; σ = E . ε; ε = ΔL/L; as interpretações fazem parte da questão.","a":"Conforme contexto apresentado, é correto afirmar que a deformação, em mm, elástica sofrida pela viga 1 será de (12/60).L/r.","b":"2 (5).L/r .","c":"2 (0,2).L/r .","d":"2 (5).r /L.","e":"(0,5).L/r.","gabarito":"C","materia":"Engenharia Mecânica","tema":"Mecânica dos Sólidos ,Modelagem Estática e Dinâmica","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646357","enunciado":"Especializado - Especialidade: Engenharia (Mecânica) Nesse contexto, é correto afirmar que a relação entre os diâmetros das barras 2 e 1 (d2/d1) será igual a","a":"1/2 (3/8) .","b":"1,33.","c":"1/2 (8/3) .","d":"0,75.","e":"8/3.","gabarito":"A","materia":"Engenharia Mecânica","tema":"Mecânica dos Sólidos ,Modelagem Estática e Dinâmica","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646356","enunciado":"Especializado - Especialidade: Engenharia (Mecânica) Um fuso de esferas recirculantes é acionado diretamente pelo eixo de um servomotor. O fuso possui diâmetro 50 mm, comprimento 1 600 mm e passo igual a 20 mm, e deverá acionar o movimento do cabeçote de uma máquina. Para movimentar o cabeçote com velocidade constante de 24 m/minuto, é correto afirmar que o a rotação do servomotor","a":"deverá ser, em rpm, de 2,67.","b":"1 200.","c":"160.","d":"20.","e":"1,2.","gabarito":"B","materia":"Engenharia Mecânica","tema":"Sistemas Mecânicos ,Elementos de Máquinas","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646355","enunciado":"Especializado - Especialidade: Engenharia (Mecânica) No projeto de uma máquina operatriz, deseja-se analisar algumas possibilidades e suas viabilidades técnico-econômicas. Uma proposta em estudo é que a mesa da máquina possa se deslocar, com velocidade constante, uma distância de 1 200 mm em 2 segundos. Deseja-se também que a mesa atinja essa velocidade de avanço em 0,2 segundo e que demore esse mesmo intervalo de tempo para parar, ao final dos deslocamentos desejados. Sabe-se que a massa total da mesa a ser deslocada é de 160 kg e que quaisquer outros esforços e atritos deverão ser desconsiderados nesse estudo. O fuso de esferas recirculantes, que realiza esse acionamento, deverá aplicar na mesa uma força de X N e o deslocamento total que ocorrerá, somente nos intervalos de aceleração e de frenagem lineares, será de L mm.","a":"Considerando as afirmações apresentadas, é correto afirmar que os valores de X e L são, respectivamente, 19,2 e 60.","b":"53,3 e 0,06.","c":"53,3 e 60.","d":"480 e 120.","e":"5 4,8 x 10 e 1,20.","gabarito":"D","materia":"Engenharia Mecânica","tema":"Sistemas Mecânicos ,Elementos de Máquinas","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646334","enunciado":"Especializado - Especialidade: Medicina (Clínica Geral) Homem de 52 anos com histórico de hipertensão e hiperlipidemia apresenta vertigem de início agudo. Ao exame físico, ele não apresenta déficits de nervos cranianos, mas apresenta algum nistagmo ao olhar para a direita. O exame à beira do leito, incluindo o desalinhamento ocular (desvio Skew), não apresenta achados anormais. O teste de impulso cefálico mostra uma sacada de volta ao centro ao virar a cabeça para a direita.","a":"Com os dados descritos, mais provavelmente, onde se localiza a vertigem desse paciente? Nervo vestibular esquerdo.","b":"Nervo vestibular direito.","c":"Ponte medial direita.","d":"Território da artéria cerebral média esquerda.","e":"Território da artéria cerebral média direita.","gabarito":"B","materia":"Medicina","tema":"Anatomia e Fisiologia Humana em Medicina","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646333","enunciado":"Especializado - Especialidade: Medicina (Clínica Geral) Mulher de 63 anos é avaliada em uma consulta de acompanhamento. Há seis meses uma angiotomografia foi feita para avaliar uma possível embolia pulmonar. O exame foi negativo para embolia, mas demonstrou um nódulo em vidro fosco (parcialmente sólido) de 8 mm no lobo superior esquerdo. O histórico é notável para tabagismo de 21 maços/ano, mas parou há 6 meses; não há outras comorbidades ou uso de medicamento. Os sinais vitais e exame físico são normais. A tomografia (TC) repetida 6 meses após não mostra alteração no tamanho ou nas características do nódulo.","a":"Nessa paciente, o manejo mais adequado é: indicar ressecção cirúrgica do nódulo.","b":"solicitar TC de tórax em 6 meses","c":"solicitar TC de tórax após 2 anos.","d":"indicar biópsia guiada por TC.","e":"solicitar PET com fluorodesoxiglicose.","gabarito":"C","materia":"Medicina","tema":"Anatomia e Fisiologia Humana em Medicina","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646332","enunciado":"Especializado - Especialidade: Medicina (Clínica Geral) Mulher de 43 anos apresenta quadro de humor deprimido e letargia. Ela tem histórico de ressecção transesfenoidal de um adenoma de hipófise não funcionante 5 anos atrás, em uso atual de tiroxina e hidrocortisona. A paciente também faz uso de lamotrigina por epilepsia. Exames de sangue: prolactina: 270 mU/L (normal: 45 a 375); IGF-1: 8 nmol/L (normal: 16 a 118); T4 livre: 1,1 ng/dL (normal: 0,7 a 1,8); TSH: 0,03 mU/L (normal: 0,35 a 4,5).","a":"Nessa paciente, o exame mais apropriado para avaliar a suspeita de deficiência de GH é níveis de GH.","b":"níveis de IGFBP3 (proteína de ligação do fator de crescimento semelhante à insulina 3).","c":"teste de tolerância à glicose.","d":"teste de tolerância à insulina.","e":"teste de estimulação com glucagon.","gabarito":"E","materia":"Medicina","tema":"Endocrinologia","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646331","enunciado":"Especializado - Especialidade: Medicina (Clínica Geral) Homem de 61 anos relata quadro de prurido nas pernas. O paciente tem um histórico de diabetes de longa data e faz hemodiálise para insuficiência renal relacionada ao diabetes. Ao exame físico, ele apresenta uma erupção cutânea de múltiplas pequenas pápulas com um tampão ceratótico central e escoriações.","a":"Nesse contexto, o diagnóstico mais provável da condição adquirida é: dermatose perfurante.","b":"rubeose.","c":"colestase.","d":"acantose nigricans.","e":"dermopatia diabética.","gabarito":"A","materia":"Medicina","tema":"Endocrinologia","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646330","enunciado":"Especializado - Especialidade: Medicina (Clínica Geral) Mulher de 36 anos sem histórico prévio de doença cardíaca desenvolve dispneia e ortopneia aos esforços cerca de 1 mês após o parto de um bebê saudável nascido a termo. À investigação, o ecocardiograma demonstra um ventrículo esquerdo dilatado com função sistólica globalmente reduzida.","a":"Em relação ao quadro clínico descrito, é correto afirmar que a CMP é mais frequentemente diagnosticada antes do parto.","b":"idade materna mais jovem é um fator de risco para CMP.","c":"a incidência de cardiomiopatia periparto (CMP) é maior nas primeiras gestações.","d":"há predisposição genética compartilhada em alguns casos de CMP e outras formas de cardiomiopatia dilatada.","e":"aproximadamente 10% das pacientes com CMP apresentam recuperação nos primeiros 6 meses após o parto.","gabarito":"D","materia":"Medicina","tema":"Cardiologia e Alterações Vasculares","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646329","enunciado":"Especializado - Especialidade: Medicina (Clínica Geral) Mulher de 65 anos com cirrose relacionada ao álcool é atendida com o marido na unidade de saúde. Ela parou de beber há dois anos. O marido está preocupado por ela não ser como sempre, com episódios de confusão. No momento, ela parece orientada para tempo e lugar.","a":"Em relação ao quadro descrito, é correto afirmar que o teste Stroop pode ser usado para ajudar no diagnóstico de EH mínima.","b":"o exame de imagem é essencial para o diagnóstico de EH.","c":"eletroencefalografia só tem utilidade na encefalopatia hepática (EH) grau IV.","d":"elevação de amônia no sangue é diagnóstica de EH.","e":"não há indicação para rastreamento de EH mínima.","gabarito":"A","materia":"Medicina","tema":"Gastroenterologia ,Hepatologia","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646328","enunciado":"Especializado - Especialidade: Medicina (Clínica Geral) Mulher de 65 anos apresenta quadro de alguns meses com prurido intenso. Ao exame físico: nota-se eritrodermia generalizada, alopecia e linfadenopatia difusa com linfonodos de 1,5 a 3 cm de diâmetro; o baço não é palpável. Exames de 3 3 3 sangue: hemoglobina: 10,8 g/dL; leucócitos: 17.200/mm ; neutrófilos: 8.800/mm ; linfócitos: 4.500/mm ; eosinófilos: 3 3 2.900/mm ; plaquetas: 523 mil/mm ; alguns linfócitos anormais são vistos e a imunofenotipagem mostra uma população de células com o fenótipo CD2-, CD3+, CD4+, CD5+, CD7- e CD25-.","a":"O diagnóstico mais provável é: leucemia prolinfocítica de células T.","b":"síndrome de Sézary.","c":"leucemia/linfoma de células T do adulto.","d":"micose fungoide.","e":"síndrome hipereosinofílica idiopática.","gabarito":"B","materia":"Medicina","tema":"Ginecologia e Obstetrícia","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646327","enunciado":"Especializado - Especialidade: Medicina (Clínica Geral) Mulher de 30 anos é atendida com o relato de duas horas de vômitos e dor abdominal intensa. A última menstruação foi há 3 semanas e ela não usa métodos contraceptivos. Ao exame físico, ela está taquicárdica, mas a temperatura e pressão arterial são normais; o abdome está muito sensível e há uma massa anexial esquerda dolorosa no exame vaginal bimanual.","a":"Nessa paciente, o diagnóstico mais provável é: doença diverticular.","b":"doença inflamatória pélvica.","c":"torção ovariana.","d":"gravidez ectópica.","e":"hidrossalpingite.","gabarito":"C","materia":"Medicina","tema":"Ginecologia e Obstetrícia","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646326","enunciado":"Especializado - Especialidade: Medicina (Clínica Geral) Em relação às possíveis alterações do segmento ST durante o teste de esforço, é correto afirmar que","a":"a localização eletrocardiográfica da depressão do segmento ST prediz com precisão o território anatômico da doença coronariana obstrutiva.","b":"a depressão do segmento ST deve estar presente durante o exercício e na recuperação para ser interpretada como","c":"anormal. a depressão do ponto J durante o exercício é diagnóstica de isquemia cardíaca significativa.","d":"o ponto J é o ponto de referência isoelétrico apropriado a ser analisado no ECG.","e":"a persistência da depressão de ST por 60 a 80 milissegundos após o ponto J é necessária para interpretar a resposta eletrocardiográfica como anormal.","gabarito":"E","materia":"Medicina","tema":"Cardiologia e Alterações Vasculares","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646325","enunciado":"Especializado - Especialidade: Medicina (Clínica Geral)","a":"Em relação à colite ulcerativa, é correto afirmar que a extensão da doença progride em até 50% dos pacientes com proctite ao fim de 10 anos.","b":"a taxa de recaída da doença é de 10% ao ano.","c":"cerca de 25% dos pacientes com pancolite acabam necessitando de colectomia.","d":"a terapia de manutenção com 5-aminosalicilato r eduz o risco de câncer colorretal em 10%.","e":"a incidência de câncer colorretal é de 20% aos 20 anos e 40% aos 30 anos.","gabarito":"C","materia":"Medicina","tema":"Gastroenterologia","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646324","enunciado":"Especializado - Especialidade: Medicina (Clínica Geral) Homem de 54 anos com diagnóstico de AIDS apresenta quadro de 2-3 semanas com mal-estar, náuseas, vômitos e 3 desconforto abdominal superior. Exames atuais mostram: hemoglobina 10 g/dL; leucócitos: 4.800/mm ; plaquetas: 106 3 mil/mm ; bilirrubina direta: 5,1 mg/dL; alanina aminotransferase: 79 U/L; fosfatase alcalina: 390 U/L. A contagem de CD4+ é 3 de 9 células/mm e a carga viral do HIV de 77.000/mL. A colangiopancreatografia retrógrada endoscópica mostra dilatação do ducto viliar comum com margens suaves e afunilamento terminal; há múltiplas estenoses e dilatações saculares alternadas da árvore biliar intra-hepática de ambos os lobos hepáticos. Nenhum cálculo biliar é visualizado em exames de","a":"imagem. infecção oportunista que está mais associada a essa condição é:","b":"A microsporídio. micobactéria.","c":"adenovírus.","d":"criptosporídio.","e":"histoplasmose.","gabarito":"D","materia":"Medicina","tema":"Anatomia e Fisiologia Humana em Medicina","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646323","enunciado":"Especializado - Especialidade: Medicina (Clínica Geral) Homem de 63 anos com histórico de doença do refluxo gastroesofágico realiza uma endoscopia digestiva alta para vigilância para esôfago de Barrett com os seguintes achados: ausência de lesões visíveis; biópsias mostram histologia consistente com esôfago de Barrett e com evidência de displasia de baixo grau em três amostras (achados confirmados por um segundo patologista especialista).","a":"Nesse sentido, a conduta correta é: indicar a esofagectomia laparoscópica.","b":"repetir a endoscopia em seis meses.","c":"indicar a remoção do esôfago de Barret por radiofrequência.","d":"indicar a ressecção endoscópica do esôfago de Barrett.","e":"repetir a endoscopia em dois anos.","gabarito":"B","materia":"Medicina","tema":"Gastroenterologia","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646322","enunciado":"Especializado - Especialidade: Medicina (Clínica Geral) Um paciente é acompanhado com o diagnóstico prévio de transtorno bipolar tipo II. Nessa situação, com maior","a":"probabilidade, o achado esperado ao longo do tempo é: episódios maníacos que não respondem ao tratamento com estabilizadores de humor.","b":"a presença de características psicóticas.","c":"episódios maníacos recorrentes na ausência de depressão.","d":"a ciclagem rápida entre depressão grave e mania.","e":"a recorrência de episódios depressivos e hipomaníacos.","gabarito":"E","materia":"Medicina","tema":"Anatomia e Fisiologia Humana em Medicina","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646321","enunciado":"Especializado - Especialidade: Medicina (Clínica Geral) Homem de 58 anos de idade com histórico de diabetes tipo 2, doença renal crônica leve e gota em uso de metformina (2g/dia), rosuvastatina (20 mg/dia) e aspirina (100 mg/dia) é atendido em consulta de retorno. O diagnóstico de gota foi feito há vários anos, mas nunca foi tratado. Relata sofrer ataques a cada ano, cada um dos quais o deixa incapacitado. A maioria de seus ataques ocorreu em sua primeira articulação MTF, mas uma foi no joelho. Ele já experimentou febuxostate no passado, mas sentiu muitos efeitos adversos e não quer tentar o medicamento novamente. Não há de nefrolitíase. Sinais vitais são normais. O exame físico não demonstra artrite, nem tofos. Exames de sangue atuais: urato: 8,4 mg/dL; creatinina 2 1,3 mg/dL; HbA1C: 6,8%. A TFG estimada é de 66 mL/min/1,73m . O teste HLA-B∗5801 é positivo.","a":"Nesse paciente, a próxima melhor intervenção para esse paciente é: benzbromarona.","b":"descontinuação de aspirina.","c":"lesinurade.","d":"alopurinol em baixa dose.","e":"alopurinol em dose alta.","gabarito":"A","materia":"Medicina","tema":"Anatomia e Fisiologia Humana em Medicina","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646320","enunciado":"Especializado - Especialidade: Medicina (Clínica Geral) Mulher de 19 anos é avaliada com diarreia persistente não sanguinolenta, cólicas abdominais e distensão abdominal há cerca de 7 dias. Relata que viajou recentemente para o interior do Nordeste. Uma amostra fecal é coletada e mostra: coprocultura negativa; pesquisa de Giardia lamblia por reação em cadeia da polimerase é positiva. Nesse sentido, é correto afirmar que","a":"os trofozoítos invadem o epitélio e alteram o equilíbrio dos hormônios intestinais, ocasionando perda de fluidos e","b":"eletrólitos. ao entrar no duodeno, as bactérias intestinais quebram os cistos da Giardia, liberando o trofozoíto.","c":"a colonização de trofozoítos é limitada ao intestino delgado superior.","d":"os trofozoítos aderem à superfície da mucosa, causando liberação de citocinas e consequente perda de fluidos e","e":"eletrólitos. os trofozoítos invadem os tecidos e se entrelaçam no sistema linfático, facilitando a disseminação sistêmica.","gabarito":"D","materia":"Medicina","tema":"Endocrinologia","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646319","enunciado":"Especializado - Especialidade: Medicina (Clínica Geral) Mulher de 74 anos com histórico de veias varicosas e fratura não desviada do talus direito há 2 anos refere queimação,","a":"formigamento e dor ao longo da região plantar do pé e dedos do pé direito. compressão de qual nervo é a causa mais provável de seus sintomas?","b":"A Tibial anterior. Tibial posterior.","c":"Fibular superficial.","d":"Fibular comum.","e":"Plantar lateral.","gabarito":"B","materia":"Medicina","tema":"Ortopedia e Traumatologia","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646318","enunciado":"Especializado - Especialidade: Medicina (Clínica Geral) Considerando um paciente com um padrão generalizado de inibição social, sentimentos de inadequação e","a":"hipersensibilidade à avaliação negativa, o diagnóstico mais provável é transtorno de personalidade dependente.","b":"esquizoide.","c":"evitativa.","d":"histriônica.","e":"obsessivo-compulsiva.","gabarito":"C","materia":"Medicina","tema":"Anatomia e Fisiologia Humana em Medicina","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646317","enunciado":"Especializado - Especialidade: Medicina (Clínica Geral) Mulher de 34 anos se apresenta ao serviço de saúde com quadro de oligomenorreia. Os exames de sangue revelam T4 livre baixo e TSH elevado.","a":"Qual a característica cutânea que, mais provavelmente, ocorre nessa essa condição? A hiperidrose.","b":"O mixedema pré-tibial.","c":"A ictiose adquirida.","d":"O eritema palmar.","e":"A acropaquia tireoidiana.","gabarito":"C","materia":"Medicina","tema":"Endocrinologia","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646316","enunciado":"Especializado - Especialidade: Medicina (Clínica Geral) Paciente de 55 anos apresenta quadro de alteração visual há alguns meses. Ele apresenta aumento da pressão intraocular nos olhos direito (28 mmHg) e esquerdo (31 mmHg) e ângulos iridocorneais abertos. Há também evidência de afinamento da borda neurorretiniana e defeitos arqueados em testes perimétricos.","a":"Nesse paciente, o tratamento mais adequado é: betaxolol.","b":"brimonidine.","c":"dorzolamida.","d":"latanoprosta.","e":"pilocarpine.","gabarito":"D","materia":"Medicina","tema":"Oftalmologia","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646315","enunciado":"Especializado - Especialidade: Medicina (Clínica Geral) Mulher de 37 anos com diabetes tipo 1 apresenta quadro de 4 horas de duração com dor intensa em epigástrio e hipocôndrio direito que se irradia para as costas. Exames de sangue mostram: bilirrubina total: 2,1 mg/dL; alanina aminotransferase: 112 U/L; aspartato aminotransferase: 96 U/L; fosfatase alcalina: 168 U/L; albumina 3,9 g/L; amilase sérica:","a":"1.200 U/L; triglicerídeos: 695 mg/dL; hemoglobina glicada: 7,2%; função renal, eletrólitos e coagulograma são normais. etiologia mais provável da apresentação dessa paciente é:","b":"A litíase biliar. doença associada à IgG4.","c":"hipertrigliceridemia.","d":"álcool.","e":"medicamentosa.","gabarito":"A","materia":"Medicina","tema":"Endocrinologia","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646314","enunciado":"Especializado - Especialidade: Medicina (Clínica Geral) Homem de 17 anos com anemia falciforme requer colecistectomia. A hemoglobina atual é de 7,7 g/dL. Ele não foi transfundido ou sofreu de síndrome torácica aguda no último ano.","a":"Antes da cirurgia, a conduta correta é: indicar transfusão de troca para atingir um percentual de hemoglobina S abaixo de 70%.","b":"indicar transfusão simples para atingir uma hemoglobina de 10 g/dL.","c":"não há indicação de transfusão.","d":"indicar transfusão simples para atingir uma hemoglobina de 12 g/dL.","e":"indicar transfusão de troca para atingir um percentual de hemoglobina S abaixo de 30%.","gabarito":"E","materia":"Medicina","tema":"Hematologia","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646313","enunciado":"Especializado - Especialidade: Medicina (Clínica Geral) Homem de 46 anos apresenta quadro de ulceração peniana há cerca de 6 semanas, com melhora espontânea. Todavia, há cerca de 1 semana, ele evolui com linfadenopatia inguinal esquerda dolorosa. Não há corrimento uretral ou disúria. Relata relações sexuais frequentemente sem proteção.","a":"Considerando a principal hipótese diagnóstica, a etiologia mais provável é: Neisseria gonorrhoea.","b":"Vírus herpes simples.","c":"Chlamydia trachomatis.","d":"Calymmatobacterium granulomatis.","e":"Haemophilus ducreyi.","gabarito":"C","materia":"Medicina","tema":"Anatomia e Fisiologia Humana em Medicina","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646312","enunciado":"Especializado - Especialidade: Medicina (Clínica Geral) Paciente de 78 anos é visto após excisão e enxerto de pele de um carcinoma basocelular (CBC) do canto interno direito do olho. O relatório da patologia afirma que o CBC foi extirpado de forma incompleta na margem periférica lateral.","a":"Qual é o tratamento de escolha? Excisão da face lateral do enxerto de pele e 4 mm de tecido adicional.","b":"Excisão do enxerto de pele e cirurgia micrográfica de Mohs em todo o local.","c":"Seguimento clínico e tratamento, se recorrer.","d":"Cirurgia micrográfica de Mohs na área lateral ao enxerto de pele.","e":"Radioterapia no local do enxerto de pele.","gabarito":"B","materia":"Medicina","tema":"Oncologia","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646311","enunciado":"Especializado - Especialidade: Medicina (Clínica Geral) Paciente de 71 anos foi diagnosticado com carcinoma de células escamosas do esôfago. Constitui o fator de risco","a":"reconhecido mais relevante para essa doença: alcoolismo.","b":"doença do refluxo gastroesofágico.","c":"infecção por Helicobacter pylori.","d":"obesidade.","e":"uso crônico de bloqueadores anti-inflamatórios não hormonais.","gabarito":"A","materia":"Medicina","tema":"Oncologia","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646310","enunciado":"Especializado - Especialidade: Medicina (Clínica Geral) 2 Mulher nulípara de 40 anos de idade com índice de massa corpórea de 48 kg/m apresenta dismenorreia secundária. Os períodos menstruais ficaram mais intensos, mas ainda são regulares, e ela não é sexualmente ativa.","a":"Considerando a principal hipótese diagnóstica. A próxima investigação recomendada, nesse momento, é: laparoscopia diagnóstica.","b":"nível sérico de CA125.","c":"tomografia abdominal.","d":"ultrassonografia transvaginal.","e":"histeroscopia.","gabarito":"D","materia":"Medicina","tema":"Ginecologia e Obstetrícia","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646309","enunciado":"Especializado - Especialidade: Medicina (Clínica Geral) Homem de 37 anos apresenta dor e inchaço há 2 dias no joelho esquerdo. Não há trauma, comorbidades ou qualquer história de artrite. Ele relata que teve relações sexuais desprotegidas com mulheres nos últimos 5-15 dias. Sinais vitais: temperatura: 37,9 ºC; pressão arterial: 122 x 78 mmHg; frequência cardíaca: 66/min., frequência respiratória: 18/min.; saturação de oxigênio normal. O joelho esquerdo está quente, eritematoso, com amplitude de movimento limitada e um derrame palpável. O restante do exame físico não é contributivo. Hemograma, função renal, glicemia e eletrólitos são normais. A artrocentese é programada para contagem de células, coloração de Gram, cultura aeróbia padrão.","a":"Considerando a principal hipótese diagnóstica, nesse momento, a conduta correta é: iniciar cefepima e vancomicina.","b":"solicitar a pesquisa de cristais no líquido articular.","c":"solicitar a cultura do líquido articular no meio de Thayer-Martin.","d":"iniciar oxacilina.","e":"solicitar o anti-HIV e iniciar profilaxia pós-exposição para AIDS.","gabarito":"C","materia":"Medicina","tema":"Anatomia e Fisiologia Humana em Medicina","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646308","enunciado":"Especializado - Especialidade: Medicina (Clínica Geral) Mulher de 30 anos de idade é avaliada em consulta de retorno para investigação de síndrome nefrótica. A história médica pregressa inclui episódios recorrentes de infecção urinária, exigindo o uso de antibióticos. Ela também usa Ibuprofeno diariamente (600 mg/dia) há mais de 2 anos. A pressão arterial, glicemia e função renal são normais. O VDRL não é reativo. Anticorpos antinúcleo e complemento séricos são normais. Sorologias para HIV, hepatite B e C são negativos. Exame de urina: > 10 leucócitos/campo; 3 hemácias/campo; proteinúria 3+; cilindros hialinos discretos e alguns eosinófilos. Proteinúria de 4,6 gramas em 24 horas.","a":"Nessa paciente, a principal hipótese diagnóstica é: doença de Berger.","b":"nefropatia membranosa.","c":"glomerulosclerose focal segmentar.","d":"glomerulonefrite membranoproliferativa tipo 1.","e":"nefropatia por IgA.","gabarito":"C","materia":"Medicina","tema":"Nefrologia","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646307","enunciado":"Especializado - Especialidade: Medicina (Clínica Geral) Homem de 23 anos de idade refere dor no ombro esquerdo há 2 semanas. Ele não se lembra de nenhuma lesão, mas teve que interromper a prática de natação por causa da dor. Ao exame físico, não há edema ou vermelhidão no ombro afetado; a dor é agravada com supinação resistida do antebraço; ele também sente sensibilidade na região anterior do ombro.","a":"Qual é a provável etiologia do quadro descrito? Artrite da articulação acromioclavicular.","b":"Artropatia do manguito rotador.","c":"Capsulite adesiva do ombro.","d":"Luxação crônica da articulação glenoumeral.","e":"Tendinite bicipital.","gabarito":"E","materia":"Medicina","tema":"Anatomia e Fisiologia Humana em Medicina","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646306","enunciado":"Especializado - Especialidade: Medicina (Clínica Geral)","a":"Na população em geral, qual condição a seguir tem a maior prevalência? Abuso de substâncias.","b":"Transtorno da ansiedade.","c":"Transtorno do humor.","d":"Demência.","e":"Esquizofrenia.","gabarito":"B","materia":"Medicina","tema":"Anatomia e Fisiologia Humana em Medicina","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646305","enunciado":"Especializado - Especialidade: Medicina (Clínica Geral) Mulher de 27 anos é avaliada por tosse e aperto no peito que ocorrem durante e após o exercício. Ela treinou para sua primeira maratona, mas não conseguiu aumentar a intensidade do treinamento por causa desses sintomas. Não há tosse ou aperto no peito em qualquer outro momento, nem estridor ou inspiração ruidosa durante os episódios que ela tem. Os sinais vitais e restante do exame físico são normais. A espirometria basal é normal. O teste de esforço demonstra uma o diminuição significativa no volume expiratório final de 1 segundo desde o início.","a":"Nessa situação, considerando as opções descritas a seguir, a melhor medicação inalatória a ser prescrita é: budesonida duas vezes ao dia.","b":"ipratrópio antes dos exercícios.","c":"salmeterol 2 vezes ao dia.","d":"tiotrópio 1 vez ao dia.","e":"budesonida/formoterol antes dos exercícios.","gabarito":"E","materia":"Medicina","tema":"Anatomia e Fisiologia Humana em Medicina","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646304","enunciado":"Especializado - Especialidade: Medicina (Clínica Geral) Mulher de 35 anos com histórico de hipertensão arterial (HÁ) está com planos de engravidar. No momento, ela faz uso de lisinopril.","a":"Nessa situação, é correto afirmar que a terapia anti-hipertensiva crônica durante a gravidez não é tão eficaz na prevenção da pré-eclâmpsia.","b":"o labetalol deve ser evitado durante a gravidez.","c":"o lisinopril deve ser trocado pela olmesartana.","d":"o tratamento anti-hipertensivo atual deve ser mantido antes e durante a gravidez.","e":"mulheres com HA preexistente têm incidência muito maior de pré-eclâmpsia em comparação com aquelas com HA iniciada na gravidez.","gabarito":"A","materia":"Medicina","tema":"Cardiologia e Alterações Vasculares","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646303","enunciado":"Especializado - Especialidade: Medicina (Clínica Geral) Mulher de 58 anos é avaliada com quadro de erupção cutânea do tipo urticária. Na revisão de seus medicamentos, qual é","a":"aquele que, com maior probabilidade, pode estar exacerbando a urticária dela? Fenitoína.","b":"Doxepina.","c":"Metildopa.","d":"Aspirina.","e":"Prometazina.","gabarito":"D","materia":"Medicina","tema":"Anatomia e Fisiologia Humana em Medicina","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646302","enunciado":"Especializado - Especialidade: Medicina (Clínica Geral) Mulher de 73 anos com histórico de 32 anos de artrite reumatoide soropositiva está em programação para ser submetida à artroplastia de quadril esquerdo. O tratamento atual consiste em metotrexato (20 mg/semana) e adalimumabe (40 mg/cada 2 semanas). Ela não tem outros problemas médicos.","a":"Nessa paciente, o próximo passo mais importante na avaliação pré-operatória é: radiografia da coluna cervical em incidências de flexão/extensão lateral.","b":"testes de função adrenal.","c":"provas de função pulmonar.","d":"ressonância magnética da coluna cervical.","e":"cintilografia do miocárdio com perfusão.","gabarito":"A","materia":"Medicina","tema":"Anatomia e Fisiologia Humana em Medicina","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646301","enunciado":"Especializado - Especialidade: Medicina (Clínica Geral) Homem de 27 anos de idade é avaliado em consulta de retorno devido à doença renal crônica progressiva com creatinina 2 sérica atual de 2,2 mg/dL (TFGe: 44 mL/min/1,73 m ) e proteinúria de 3,5 g/dia. Ele tem histórico de diabete melito tipo 1 há 20 anos em uso enalapril (40 mg/dia) e insulina em múltiplas doses. A HbA1c atual é de 6,5% e a pressão arterial de 130 x 80 mmHg. A sua ingestão dietética de proteínas é de 1,5 a 2,0 mk/kg/dia e o peso é de 70 kg.","a":"Em relação à proteinúria e função renal, a conduta correta é recomendar a realização de fístula para início de diálise precoce no futuro.","b":"adicionar um antagonista do receptor de angiotensina.","c":"reduzir a ingestão de proteína oral.","d":"aumentar a ingestão de proteína oral para compensar a proteinúria.","e":"solicitar uma biópsia renal.","gabarito":"C","materia":"Medicina","tema":"Nefrologia","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646300","enunciado":"Especializado - Especialidade: Medicina (Clínica Geral) Em relação aos mecanismos possíveis pelos quais os diuréticos tiazídicos podem causar hiponatremia, é correto afirmar","a":"que a excreção de água livre é maior devido ao aumento de prostaglandinas renais.","b":"a ação agonista na hipófise causa a liberação excessiva de hormônio antidiurético.","c":"o aumento de eletrólitos nos ductos coletores causa maior excreção renal de água.","d":"o efeito direto nos túbulos renais proximais leva à disfunção das células epiteliais.","e":"há regulação positiva na expressão do receptor 2 de aquaporina no ducto coletor.","gabarito":"E","materia":"Medicina","tema":"Anatomia e Fisiologia Humana em Medicina","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646299","enunciado":"Especializado - Especialidade: Medicina (Clínica Geral) Em relação à morte súbita cardíaca em atletas jovens (MSCAJ), é correto afirmar que","a":"os pacientes que sofrem MSCAJ devido à cardiomiopatia hipertrófica geralmente apresentam sintomas cardíacos","b":"prévios. a MSCAJ nem sempre está relacionada à doença cardíaca estrutural subjacente.","c":"a origem anômala da artéria coronária direita a partir da coronária esquerda é a anormalidade congênita mais comum","d":"que resulta em MSCAJ. a estenose aórtica congênita é a causa estrutural mais comum de MSCAJ.","e":"histórico pré-treinamento normal e o exame físico excluem a possibilidade de cardiomiopatia hipertrófica.","gabarito":"B","materia":"Medicina","tema":"Cardiologia e Alterações Vasculares","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646298","enunciado":"Especializado - Especialidade: Medicina (Clínica Geral)","a":"Qual organismo é mais frequentemente envolvido na otite média crônica? Pseudomonas aeruginosa.","b":"Escherichia coli.","c":"Haemophilus influenzae.","d":"Bacteroides fragilis.","e":"Staphylococcus epidermidis.","gabarito":"A","materia":"Medicina","tema":"Anatomia e Fisiologia Humana em Medicina","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646297","enunciado":"Especializado - Especialidade: Medicina (Clínica Geral) Mulher de 46 anos com artrite reumatoide faz uso de hidroxicloroquina 400 mg por dia nos últimos 10 anos. Ela se sente bem no geral e nega qualquer dor e inchaço nas articulações. No entanto, no último 1 mês, ela notou que vem enxergando halos ao redor da luz.","a":"Nessa circunstância, a toxicidade ocular mais provável relacionada à hidroxicloroquina é episclerite.","b":"retinopatia.","c":"iridociclite.","d":"neurite óptica.","e":"depósitos na córnea.","gabarito":"E","materia":"Medicina","tema":"Anatomia e Fisiologia Humana em Medicina","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646296","enunciado":"Especializado - Especialidade: Medicina (Clínica Geral)","a":"Qual afirmação sobre transtornos de humor é verdadeira? Existe uma correlação entre a hiposecreção de cortisol e a depressão.","b":"O status socioeconômico mais elevado leva ao aumento da depressão.","c":"O transtorno bipolar tem prevalência igual para homens e mulheres.","d":"Cerca de 95% das pessoas com transtorno depressivo maior recebem tratamento adequado.","e":"A depressão maior é mais comum em homens do que em mulheres.","gabarito":"C","materia":"Medicina","tema":"Anatomia e Fisiologia Humana em Medicina","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646295","enunciado":"Especializado - Especialidade: Medicina (Clínica Geral) Homem de 30 anos, previamente hígido, sem comorbidades, apresenta quadro de 6 horas com náuseas, vômitos, dor intensa no flanco e hematúria. Considerando a principal hipótese diagnóstica, o exame de imagem abdominal de escolha com maior acurácia nesse","a":"paciente é ressonância magnética com contraste.","b":"urografia intravenosa.","c":"ultrassonografia.","d":"tomografia multidetector.","e":"radiografia simples.","gabarito":"D","materia":"Medicina","tema":"Anatomia e Fisiologia Humana em Medicina","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2646288","enunciado":"Especializado - Especialidade: Medicina (Clínica Geral)","a":"O que caracteriza um estudo epidemiológico do tipo ecológico? Análise de informações agregadas em grupos populacionais, em vez de dados individuais.","b":"Coleta de dados em nível individual e acompanhamento longitudinal dos participantes.","c":"Coleta de dados por meio de entrevistas com pacientes diagnosticados com a doença.","d":"Ter como objeto de estudo questões ambientais e seus efeitos sobre os indivíduos.","e":"Investigação de casos isolados de doenças em diferentes regiões geográficas.","gabarito":"A","materia":"Direito Sanitário","tema":"Saúde Pública","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2638205","enunciado":"Especializado - Especialidade: Engenharia Civil As medidas da planta de um terreno retangular, desenhado em escala 1:500, são 5 cm por 10 cm. O perímetro real deste","a":"terreno é 75 m.","b":"200 m","c":"50 m.","d":"100 m","e":"150 m.","gabarito":"E","materia":"Engenharia Civil","tema":"Edificação","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2638204","enunciado":"Especializado - Especialidade: Engenharia Civil","a":"Para esticar objetos cruzados por uma janela ou polígono de seleção no programa AutoCAD, utiliza-se o comando ARRAY.","b":"SCALE.","c":"OFFSET.","d":"STRETCH.","e":"DIVIDE.","gabarito":"D","materia":"Engenharia Civil","tema":"Desenho na Engenharia Civil ,AutoCAD","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2638202","enunciado":"Especializado - Especialidade: Engenharia Civil O comando do programa de desenho AutoCAD que arredonda e faz a concordância das arestas de duas linhas, a partir de","a":"uma medida de raio definida pelo usuário, é CHAMFER.","b":"FILLET.","c":"ROTATE.","d":"ARRAY.","e":"TRIM.","gabarito":"B","materia":"Engenharia Civil","tema":"Desenho na Engenharia Civil ,AutoCAD","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2638201","enunciado":"Especializado - Especialidade: Engenharia Civil Na engenharia de avaliações, o método que identifica o valor do bem, alicerçado no seu aproveitamento eficiente, baseado em modelo de estudo de viabilidade técnico-econômica, mediante hipotético empreendimento compatível com as características do bem e com as condições do mercado no qual está inserido, considerando-se cenários viáveis para","a":"execução e comercialização do produto, é denominado método comparativo direto de dados de mercado.","b":"evolutivo.","c":"involutivo.","d":"da capitalização da renda.","e":"comparativo direto de custo.","gabarito":"C","materia":"Engenharia Civil","tema":"Planejamento e Controle de Obras","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2638199","enunciado":"Especializado - Especialidade: Engenharia Civil Nas atividades de avaliação de bens, a perda de valor de um bem, devido a modificações em seu estado ou qualidade, é","a":"denominada depreciação.","b":"obsoletismo.","c":"mutilação.","d":"deterioração.","e":"decrepitude.","gabarito":"A","materia":"Engenharia Civil","tema":"Avaliação Imobiliária em Engenharia Civil","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2638195","enunciado":"Especializado - Especialidade: Engenharia Civil","a":"No acompanhamento e fiscalização de obras, é prerrogativa do fiscal técnico, ser consultado no caso de modificação de projeto.","b":"definir com precisão e clareza os objetivos e elementos necessários à elaboração do programa do projeto.","c":"vetar o emprego de pessoal comprovadamente desqualificado para a atividade que exerce.","d":"tomar as providências pela guarda e segurança do empreendimento.","e":"fornecer as diretrizes básicas para a elaboração e aprovação de projetos.","gabarito":"C","materia":"Engenharia Civil","tema":"Planejamento e Controle de Obras ,Fiscalização de Obras","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2638194","enunciado":"Especializado - Especialidade: Engenharia Civil Após as medições dos serviços de engenharia realizados em um contrato, foram necessários efetuar dois termos aditivos sequenciais. O primeiro termo aditivo foi uma adição de 20% e o segundo termo aditivo foi uma supressão de 10% sobre o","a":"contrato aditado. Estes termos aditivos mantiveram inalterado o total do contrato inicial.","b":"aumentaram o contrato inicial em 8%.","c":"aumentaram o contrato inicial em 10%.","d":"reduziram o contrato inicial em 10%.","e":"reduziram o contrato inicial em 8%.","gabarito":"B","materia":"Engenharia Civil","tema":"Normas e Legislações","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2638193","enunciado":"Especializado - Especialidade: Engenharia Civil Para a construção de uma edificação foram previstas as seguintes despesas: R$ 600.000,00 de custo direto, R$ 40.000,00 de","a":"custo indireto, 5% de administração central, 12% de lucro e 8% de impostos. O preço de venda desta edificação é R$ 750.000,00.","b":"R$ 680.000,00.","c":"R$ 790.000,00.","d":"R$ 870.000,00.","e":"R$ 840.000,00. Direito Administrativo>Licitações e Lei nº 14.133 de 2021 ,","gabarito":"E","materia":"Engenharia Civil","tema":"Planejamento e Controle de Obras","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_650","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio Especializado - Especialidade: Engenharia Civil o Segundo a Lei Federal n 14.133/2021, nas obras licitadas pela Administração Pública, quando for necessária a alteração do valor contratual, em decorrência de acréscimos do valor inicial atualizado do contrato, o máximo acréscimo percentual","a":"permitido para reforma de edifícios é 50%.","b":"15%.","c":"30%.","d":"65%.","e":"25%.","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2638191","enunciado":"","a":"Especializado - Especialidade: Engenharia Civil construção de uma obra de engenharia, composta de 5 atividades, nomeadas de A até E, seguiu o cronograma físico- financeiro a seguir. Meses Atividade Custo (%) 1 2 3 4 5 6","b":"A 60%40% 5 20%20%40%20% 30","c":"30%60%10% 40","d":"40%50%10% 20","e":"100% 5 Ao findar o quarto mês, o custo percentual executado da obra é A 35%. B 56%. C 42%. D 73%. E 68%.","gabarito":"D","materia":"Engenharia Civil","tema":"Planejamento e Controle de Obras ,Planejamento e Gerenciamento de Obras","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2638190","enunciado":"Especializado - Especialidade: Engenharia Civil Uma construtora vendeu uma edificação por R$ 440.000,00. Se o BDI praticado pela construtora é 25%, então, os custos","a":"diretos da construção é R$ 336.000,00.","b":"R$ 381.000,00.","c":"R$ 375.000,00.","d":"R$ 352.000,00.","e":"R$ 324.000,00.","gabarito":"D","materia":"Engenharia Civil","tema":"Planejamento e Controle de Obras","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2638189","enunciado":"Especializado - Especialidade: Engenharia Civil Para montar o metro quadrado de formas plastificadas para estruturas de concreto aparente são necessários os seguintes insumos: 2 h de carpinteiro (R$ 16,00/h), 2 h de ajudante carpinteiro (R$ 12,00/h), 3 m de pontalete de pinho (R$ 10,00/m), 2 2 2 2 0,20 m de tábuas de pinho (R$ 20,00/m ), 0,30 m de chapa compensada plastificada (R$ 30,00/m ) e 0,10 kg de prego (R$ 10,00/kg). Considerando o percentual de encargos sociais e trabalhistas de 125% e o BDI de 30% praticado pela construtora,","a":"o preço do metro quadrado desse serviço é R$ 155,00.","b":"R$ 118,00.","c":"R$ 221,00.","d":"R$ 148,00.","e":"R$ 130,00.","gabarito":"C","materia":"Engenharia Civil","tema":"Planejamento e Controle de Obras","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2638188","enunciado":"Especializado - Especialidade: Engenharia Civil Na execução e montagem da estrutura metálica de uma cobertura residencial, para cada metro quadrado de projeção horizontal da cobertura, utilizam-se 4 kg de perfis metálicos estruturais (R$ 40,00/kg) e 5 h de montador (R$ 16,00/h). Pode- se afirmar que, nesta composição, reduzindo-se o custo dos perfis metálicos em 30%, gera-se uma economia do custo","a":"unitário deste serviço de 20%.","b":"15%.","c":"18%.","d":"25%.","e":"22%.","gabarito":"A","materia":"Engenharia Civil","tema":"Estruturas ,Estruturas Metálicas ,Planejamento e Controle de Obras","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2638187","enunciado":"Especializado - Especialidade: Engenharia Civil Na verificação da segurança contra o deslizamento da base dos muros de contenção, deve-se utilizar o coeficiente de","a":"segurança mínimo de 4,0.","b":"3,5.","c":"3,0.","d":"2,0.","e":"1,5.","gabarito":"E","materia":"Engenharia Civil","tema":"Geotecnia ,Escavações e Contenções","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2638186","enunciado":"","a":"Especializado - Especialidade: Engenharia Civil viga engastada de aço da figura a seguir está submetida a uma carga uniformemente distribuída de 5 kN/m em todo o seu vão de 2 m. (Arquivo pessoal; imagem usada com autorização) Se a seção transversal da viga é retangular com 6 cm de base e 10 cm de altura e o módulo de elasticidade do aço é 200 GPa, então, o deslocamento vertical máximo na extremidade livre da viga é","b":"A 15,0 mm. 10,0 mm.","c":"20,0 mm.","d":"5,0 mm.","e":"1,0 mm.","gabarito":"B","materia":"Engenharia Civil","tema":"Estruturas ,Resistencia dos Materiais","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2638185","enunciado":"","a":"Especializado - Especialidade: Engenharia Civil barra da figura a seguir está fixada em uma estrutura por meio de dois rebites e, na extremidade livre, está submetida a uma força vertical de 20 kN. (Arquivo pessoal; imagem usada com autorização) 2 Se a área da seção transversal de cada rebite é 5,0 cm , as tensões de cisalhamento nos rebites 1 e 2, em módulo, são, respectivamente, em MPa,","b":"A 60 e 80. 90 e 107.","c":"240 e 320.","d":"120 e 160.","e":"40 e 53.","gabarito":"D","materia":"Engenharia Civil","tema":"Estruturas ,Resistencia dos Materiais","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2638184","enunciado":"","a":"Especializado - Especialidade: Engenharia Civil viga simplesmente apoiada com dois balanços da figura a seguir está submetida a uma carga uniformemente distribuída de 5 kN/m em todo o seu vão de 8 m e a uma carga concentrada de 20 kN em cada extremidade dos balanços. (Arquivo pessoal; imagem usada com autorização) O momento fletor máximo que traciona as fibras inferiores da viga, em kNm, é","b":"A 60. 50.","c":"20.","d":"10.","e":"80.","gabarito":"C","materia":"Engenharia Civil","tema":"Estruturas ,Resistencia dos Materiais","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2638183","enunciado":"Especializado - Especialidade: Engenharia Civil O eixo de aço da figura a seguir tem 200 mm de comprimento, está engastado em uma das extremidades e está submetido a um momento de torção de 40 kNm. (Arquivo pessoal; imagem usada com autorização) Se o módulo de elasticidade transversal do aço é 80 GPa e o momento polar de inércia da seção transversal do eixo é 1 000 4","a":"cm , então, o ângulo de torção, na extremidade livre do eixo de aço, em módulo e em radianos, é 0,200.","b":"0,020.","c":"0,001.","d":"0,002.","e":"0,010.","gabarito":"E","materia":"Engenharia Civil","tema":"Estruturas ,Resistencia dos Materiais","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2638182","enunciado":"","a":"Especializado - Especialidade: Engenharia Civil barra da figura a seguir, com 0,90 m de comprimento, está engastada nas duas extremidades. (Arquivo pessoal; imagem usada com autorização) Ao se aplicar uma força de 15 kN no ponto C, as reações horizontais nos engastamentos A e B são, respectivamente, em módulo e em kN,","b":"A 10,0 e 5,0. 12,0 e 3,0.","c":"3,0 e 12,0.","d":"6,0 e 9,0.","e":"8,0 e 4,0.","gabarito":"A","materia":"Engenharia Civil","tema":"Estruturas ,Resistencia dos Materiais","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2638181","enunciado":"","a":"Especializado - Especialidade: Engenharia Civil viga da figura a seguir é suportada por dois cabos de aço nos pontos A e B e submetida a uma carga concentrada de 100 kN no ponto C. (Arquivo pessoal; imagem usada com autorização) 2 Se a área da seção transversal dos cabos é 5 cm , as tensões de tração nos cabos A e B são, respectivamente, em MPa,","b":"A 20 e 80. 50 e 150.","c":"5 e 15.","d":"10 e 50.","e":"40 e 100.","gabarito":"B","materia":"Engenharia Civil","tema":"Estruturas ,Resistencia dos Materiais","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2638180","enunciado":"Especializado - Especialidade: Engenharia Civil Um perfil de aço MR250 compacto com contenção lateral contínua deve ser utilizado como viga. Considerando as 4 combinações das ações normais para o escoamento e, se o módulo plástico do perfil é 2200 cm , então, o momento fletor","a":"resistente de cálculo é 500 kNm.","b":"350 kNm.","c":"250 kNm.","d":"400 kNm.","e":"650 kNm.","gabarito":"A","materia":"Engenharia Civil","tema":"Estruturas ,Resistencia dos Materiais","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2638179","enunciado":"","a":"Especializado - Especialidade: Engenharia Civil treliça de aço da figura a seguir está submetida a três cargas concentradas de 400 kN. (Arquivo pessoal; imagem usada com autorização) 2 Se o módulo de elasticidade do aço é 200 GPa e a área da seção transversal das barras é 20 cm , então, o encurtamento da barra AB e o alongamento da barra AE são, respectivamente, em milímetros,","b":"A 15,0 e 12,0. 17,5 e 15,0.","c":"20,0 e 18,0.","d":"12,5 e 8,0.","e":"25,0 e 16,0.","gabarito":"D","materia":"Engenharia Civil","tema":"Estruturas ,Resistencia dos Materiais","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2638178","enunciado":"Especializado - Especialidade: Engenharia Civil As duas chapas de aço com 200 mm de largura e 10 mm de espessura da figura a seguir estão emendadas por traspasse, com 8 parafusos de 20 mm de diâmetro, cujos furos foram realizados por punção. (Arquivo pessoal; imagem usada com autorização)","a":"Ao se aplicar nessas chapas uma força de tração de 212 kN, a tensão característica de tração nas chapas é 152 MPa.","b":"106 MPa.","c":"200 MPa.","d":"100 MPa.","e":"265 MPa.","gabarito":"C","materia":"Engenharia Civil","tema":"Estruturas ,Resistencia dos Materiais","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2638177","enunciado":"Especializado - Especialidade: Engenharia Civil O perfil de aço de seção vazada da figura a seguir deve ser utilizado em uma estrutura metálica como viga simplesmente apoiada com contenção lateral contínua e sujeita ao momento fletor de 11,75 kNm.","a":"(Arquivo pessoal; imagem usada com autorização) tensão normal máxima na flexão que traciona as fibras inferiores da viga é","b":"A 150 MPa. 115 MPa.","c":"100 MPa.","d":"120 MPa.","e":"130 MPa.","gabarito":"A","materia":"Engenharia Civil","tema":"Estruturas ,Resistencia dos Materiais","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2638176","enunciado":"Especializado - Especialidade: Engenharia Civil No projeto e na execução de fundações, a estaca moldada in loco e executada pela cravação, por meio de sucessivos golpes de um pilão, de um tubo de ponta fechada por uma bucha seca, constituída de pedra e areia, previamente firmada na","a":"extremidade inferior do tubo por atrito, além de possuir base alargada e ser integralmente armada, é denominada estaca Strauss.","b":"raiz.","c":"de reação.","d":"hélice contínua.","e":"Franki.","gabarito":"E","materia":"Engenharia Civil","tema":"Geotecnia ,Fundação","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2638175","enunciado":"Especializado - Especialidade: Engenharia Civil","a":"No projeto e execução de fundações, a dimensão mínima em planta, das sapatas isoladas ou dos blocos, é 50 cm.","b":"100 cm.","c":"60 cm.","d":"40 cm.","e":"35 cm.","gabarito":"C","materia":"Engenharia Civil","tema":"Geotecnia ,Fundação","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2638174","enunciado":"Especializado - Especialidade: Engenharia Civil O bloco de concreto de duas estacas da figura a seguir foi dimensionado para suportar a carga de um pilar de 320 kN.","a":"(Arquivo pessoal; imagem usada com autorização) força de compressão em cada biela do bloco é","b":"A 80 kN. 200 kN.","c":"120 kN.","d":"240 kN.","e":"160 kN.","gabarito":"B","materia":"Engenharia Civil","tema":"Estruturas ,Resistencia dos Materiais","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2638173","enunciado":"Especializado - Especialidade: Engenharia Civil No dimensionamento de elementos estruturais de fundação deve ser considerado o peso próprio de blocos de coroamento","a":"ou sapatas ou considerar o percentual mínimo da carga vertical permanente de 4,0 %.","b":"2,5 %.","c":"7,5 %.","d":"10,0 %.","e":"5,0 %.","gabarito":"E","materia":"Engenharia Civil","tema":"Geotecnia ,Fundação","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2638172","enunciado":"Especializado - Especialidade: Engenharia Civil Um edifício térreo com laje e altura total de 4,0 m deve ser construído com elementos de concreto pré-moldados, executados conforme o especificado em norma da ABNT, sem encunhamento de outros elementos. O deslocamento","a":"horizontal global máximo da estrutura, considerando a combinação frequente das ações, é igual a 12,0 mm.","b":"10,0 mm.","c":"15,0 mm.","d":"8,0 mm.","e":"5,0 mm.","gabarito":"D","materia":"Engenharia Civil","tema":"Estruturas ,Resistencia dos Materiais","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2638170","enunciado":"Especializado - Especialidade: Engenharia Civil Uma viga simplesmente apoiada de concreto protendido de seção retangular com 0,40 m de base e 1,50 m de altura, está submetida ao momento fletor característico de 450 kNm. Se for aplicada uma força de protensão de 480 kN nas cordoalhas de aço em toda a extensão da viga e situadas a 0,50 m abaixo do centro de gravidade da seção transversal, a tensão","a":"característica nas fibras inferiores da viga é, em MPa, 0,60.","b":"0,80.","c":"1,60.","d":"2,40.","e":"3,00.","gabarito":"A","materia":"Engenharia Civil","tema":"Estruturas ,Resistencia dos Materiais","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2638163","enunciado":"Especializado - Especialidade: Engenharia Civil Uma estrutura de concreto foi projetada para ser montada com 20 vigas de concreto armado de 5 m de comprimento e seção transversal retangular com 40 cm de altura e a largura mínima permitida por norma. As vigas devem ser fabricadas no canteiro de obras com o concreto lançado e adensado manualmente. O volume de concreto necessário para essas vigas é","a":"3 4,0 m .","b":"3 4,8 m .","c":"3 3,2 m .","d":"3 6,0 m .","e":"3 8,0 m .","gabarito":"B","materia":"Engenharia Civil","tema":"Estruturas ,Resistencia dos Materiais","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2638158","enunciado":"Especializado - Especialidade: Engenharia Civil Uma viga simplesmente apoiada de concreto armado de seção retangular, que está submetida a uma carga uniformemente distribuída de cálculo de 48 kN/m em todo o seu vão de 5 m, foi dimensionada à flexão simples no estado-limite último, para as combinações normais das ações. Se o braço de alavanca entre a resultante das forças de compressão e de tração na flexão é 57,5 cm, então, a área da armadura longitudinal de tração de aço CA50 é","a":"2 3,0 cm .","b":"2 3,9 cm .","c":"2 6,0 cm .","d":"2 2,7 cm .","e":"2 4,8 cm .","gabarito":"C","materia":"Engenharia Civil","tema":"Estruturas ,Resistencia dos Materiais","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2638147","enunciado":"Especializado - Especialidade: Engenharia Civil","a":"Para os tipos de impermeabilização que requeiram substrato seco, a argamassa de regularização deve ter idade mínima de 5 dias.","b":"2 dias.","c":"3 dias.","d":"10 dias.","e":"7 dias.","gabarito":"E","materia":"Engenharia Civil","tema":"Edificação ,Impermeabilização em Engenharia Civil","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2638129","enunciado":"Especializado - Especialidade: Engenharia Civil","a":"Um dos materiais constituintes da camada impermeável no sistema de impermeabilização cimentícia é argamassa modificada com polímeros.","b":"membrana de asfalto elastomérico.","c":"membrana de poliuretano.","d":"membrana de poliureia.","e":"membrana epoxídica.","gabarito":"A","materia":"Engenharia Civil","tema":"Edificação ,Impermeabilização em Engenharia Civil","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2638125","enunciado":"Especializado - Especialidade: Engenharia Civil Para garantir as condições mínimas de proteção da construção contra a passagem de fluidos após a execução da impermeabilização, recomenda-se ser efetuado ensaio de estanqueidade com água limpa para verificação de falhas na","a":"execução do tipo de impermeabilização utilizado, com duração mínima de 48 h.","b":"24 h.","c":"10 h.","d":"72 h.","e":"6 h.","gabarito":"D","materia":"Engenharia Civil","tema":"Edificação ,Impermeabilização em Engenharia Civil","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2638120","enunciado":"Especializado - Especialidade: Engenharia Civil Sobre os processos de envelhecimento e deterioração do concreto, o mecanismo responsável por dissolver e carrear os","a":"compostos hidratados da pasta de cimento por ação de águas puras, carbônicas agressivas, ácidas e outras, é denominado despassivação por carbonatação.","b":"lixiviação.","c":"reação álcali-agregado.","d":"despassivação por ação de cloretos.","e":"expansão por sulfato.","gabarito":"B","materia":"Engenharia Civil","tema":"Edificação ,Patologias","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2638117","enunciado":"","a":"Especializado - Especialidade: Engenharia Civil rápida evaporação da água da superfície do concreto que ocorre após a concretagem, principalmente em locais de tempo quente e seco, pode ocasionar a formação de fissuras superficiais do concreto no estado plástico por","b":"A sedimentação. segregação.","c":"lixiviação.","d":"concentrações de esforços.","e":"retração superficial.","gabarito":"E","materia":"Engenharia Civil","tema":"Edificação ,Patologias","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2638110","enunciado":"Especializado - Especialidade: Engenharia Civil Considere a face inferior de uma laje maciça de concreto armado da figura a seguir. A laje está apoiada em quatro vigas. (Arquivo pessoal; imagem usada com autorização) Em decorrência de deficiência de sua capacidade resistente, a laje apresenta várias fissuras, que são causadas por","a":"insuficiência de armadura nos cantos superiores da laje.","b":"para momentos volventes.","c":"longitudinal de flexão.","d":"de torção.","e":"para resistir aos esforços cortantes.","gabarito":"C","materia":"Engenharia Civil","tema":"Estruturas ,Resistencia dos Materiais","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2638103","enunciado":"","a":"Especializado - Especialidade: Engenharia Civil viga de concreto armado da figura a seguir foi dimensionada para suportar parte das cargas de uma laje e apresenta fissuras inclinadas próximas aos apoios. (Arquivo pessoal; imagem usada com autorização) A causa mais provável dessa patologia é a insuficiência de armadura","b":"A para resistir ao momento volvente. transversal de cisalhamento.","c":"longitudinal de flexão.","d":"para resistir ao momento que traciona as fibras superiores da viga.","e":"de pele.","gabarito":"B","materia":"Engenharia Civil","tema":"Estruturas ,Resistencia dos Materiais","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2638052","enunciado":"Especializado - Especialidade: Arquivologia Pela Lei no 13.709, de 14 de agosto de 2018, é correto afirmar que","a":"o tratamento de dados pessoais pelas pessoas jurídicas de direito público e privado referidas na Lei de Acesso à Informação poderá ser realizado para o atendimento de sua finalidade pública ou particular","b":"os vazamentos individuais ou os acessos não autorizados a dados não poderão ser objeto de conciliação direta entre controlador e titular sendo o controlador sujeito de forma automática à aplicação das penalidades.","c":"a transferência internacional de dados pessoais é proibida para países ou organismos internacionais, para cláusulas- padrão contratuais e cooperação jurídica internacional entre órgãos públicos de inteligência e investigação.","d":"os agentes de tratamento devem adotar medidas de segurança para proteger os dados pessoais de acessos não autorizados, não sendo responsabilizados por situações acidentais ou ilícitas de destruição, perda e alteração.","e":"o tratamento de dados pessoais de crianças deverá ser realizado com o consentimento específico e em destaque dado por pelo menos um dos pais ou pelo responsável legal.","gabarito":"E","materia":"Direito Digital","tema":"Lei nº 13.709 de 2018 - Lei Geral de Proteção de Dados Pessoais (LGPD)","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2638051","enunciado":"Especializado - Especialidade: Arquivologia De acordo com a Lei Geral de Proteção de Dados Pessoais, a utilização de meios técnicos razoáveis e disponíveis no momento do tratamento, por meio dos quais um dado perde a possibilidade de associação, direta ou indireta, a um","a":"indivíduo, define uso compartilhado.","b":"eliminação.","c":"bloqueio.","d":"anonimização.","e":"consentimento.","gabarito":"D","materia":"Direito Digital","tema":"Lei nº 13.709 de 2018 - Lei Geral de Proteção de Dados Pessoais (LGPD)","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2638050","enunciado":"Especializado - Especialidade: Arquivologia Pela Lei no 12.527, de 18 de novembro de 2011, considera-se que","a":"primariedade é definida como qualidade da informação que tenha sido produzida, expedida, recebida ou modificada","b":"por determinado indivíduo, equipamento ou sistema. integridade é definida como a qualidade da informação não modificada, inclusive quanto à origem, trânsito e destino.","c":"documento é definido como os dados, processados ou não, que podem ser utilizados para produção e transmissão de conhecimento, contidos em qualquer meio, suporte ou formato.","d":"informação é definida como um conjunto de ações referentes à produção, recepção, classificação, utilização, acesso, reprodução, transporte, transmissão, distribuição, arquivamento, armazenamento, eliminação, avaliação, destinação ou controle.","e":"autenticidade é definida como a qualidade da informação coletada na fonte, com o máximo de detalhamento possível e sem modificações.","gabarito":"B","materia":"Legislação Federal","tema":"Lei nº 12.527 de 2011 - Lei de Acesso à Informação e Decreto nº 7.724 de 2012","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2638049","enunciado":"Especializado - Especialidade: Arquivologia","a":"De acordo com a Lei de Acesso à Informação, é correto afirmar que o fomento ao desenvolvimento da cultura de transparência na administração pública é uma diretriz a ser observada.","b":"como diretriz básica e fundamental devem ser instituídos nos órgãos públicos a publicidade e o sigilo como preceito","c":"geral. a utilização de meios de comunicação viabilizados pela tecnologia da informação deve ser observada como exceção.","d":"o desenvolvimento do controle social da administração pública deve ser restrito a órgãos específicos.","e":"as informações de interesse público devem ser divulgadas na dependência das solicitações a serem feitas pela sociedade.","gabarito":"A","materia":"Legislação Federal","tema":"Lei nº 12.527 de 2011 - Lei de Acesso à Informação e Decreto nº 7.724 de 2012","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2638048","enunciado":"Especializado - Especialidade: Arquivologia Conforme o Decreto no 10.148, de 2 de dezembro de 2019, é correto afirmar que","a":"compete ao Arquivo Nacional, na qualidade de órgão central dos arquivos brasileiros, submeter as propostas de diretrizes e normas à aprovação do Ministro de Estado da Justiça e Segurança Pública e ao Ministério Público.","b":"compete à Comissão de Coordenação do Sistema de Gestão de Documentos e Arquivos propor diretrizes e normas relativas à gestão e à preservação de documentos e arquivos, no âmbito da administração pública federal.","c":"fica instituída no âmbito do Arquivo Nacional, a Comissão de Coordenação do Sistema de Gestão de Documentos e Arquivos da administração pública federal, estadual e municipal.","d":"deve o Conselho Nacional de Arquivos monitorar a aplicação das normas e de seus resultados com vistas à modernização e ao aprimoramento do Sistema Nacional de Arquivos como estabelecido pelo decreto.","e":"cabe ao Arquivo Nacional, por meio de sua diretoria, orientar os órgãos integrantes dos arquivos públicos e privados quanto às modificações necessárias ao aprimoramento dos mecanismos de gestão de documentos e arquivos.","gabarito":"B","materia":"Arquivologia","tema":"Legislação Arquivística","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2638047","enunciado":"Especializado - Especialidade: Arquivologia De acordo com o Decreto no 4.073 de 3 de janeiro de 2002, compete ao CONARQ","a":"regular e legislar sobre o inter-relacionamento de arquivos públicos e privados com vistas ao intercâmbio e à integração sistêmica das atividades arquivísticas.","b":"recomendar providências para a apuração e a reparação de atos lesivos à política nacional de arquivos públicos e privados.","c":"coordenar a elaboração e a implementação de planos nacionais de desenvolvimento cultural com metas e prioridades para a política nacional de arquivos públicos e privados.","d":"centralizar, com vistas à padronização, a capacitação técnica dos recursos humanos de arquivo nas instituições parceiras ao Conselho.","e":"estabelecer diretrizes para o funcionamento do Sistema Nacional de Arquivos, Bibliotecas e Museus, visando à gestão, à preservação e ao acesso aos documentos brasileiros.","gabarito":"B","materia":"Arquivologia","tema":"Legislação Arquivística ,Decreto nº 4.073/02 - Regulamenta a Política Nacional de Arquivos","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2638045","enunciado":"Especializado - Especialidade: Arquivologia Conforme estabelecido na Lei dos Arquivos,","a":"fica resguardado em relação aos documentos de arquivo, o direito de indenização pelo dano material ou moral decorrente da violação do sigilo, com prejuízo das ações penal, civil e administrativa.","b":"a Administração Pública solicitará ao Ministério Público autorização para a consulta aos documentos pertencentes aos arquivos públicos na forma estabelecida pela lei.","c":"o acesso às informações contidas em documentos de arquivo dos órgãos públicos fica ressalvado quando o sigilo seja imprescindível à segurança da sociedade e do Estado, bem como à inviolabilidade da intimidade, da vida privada, da honra e da imagem das pessoas.","d":"o direito a receber dos órgãos públicos informações de interesse particular ou de interesse coletivo ou geral, contidas em documentos de arquivos, é restrito a funcionários públicos e serão prestadas no prazo da lei.","e":"a cessação de atividades de instituições públicas e de caráter público implica na eliminação de sua documentação pela instituição arquivística pública ou pela instituição sucessora.","gabarito":"C","materia":"Arquivologia","tema":"Legislação Arquivística ,Lei nº 8.159/91 - Política Nacional de Arquivos","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2638044","enunciado":"Especializado - Especialidade: Arquivologia De acordo com a Lei de Arquivos – Lei no 8.159, de 8 de janeiro de 1991, é correto afirmar que","a":"a legislação federal definirá os critérios de organização e vinculação dos arquivos estaduais e municipais, bem como a gestão e o acesso aos documentos, observado o disposto na Constituição Federal.","b":"a eliminação de documentos produzidos por instituições públicas e de caráter público será realizada mediante autorização do Ministério Público, na sua específica esfera de competência.","c":"os arquivos privados identificados como de interesse público e social não poderão ser alienados com dispersão ou perda da unidade documental, nem transferidos para o exterior.","d":"a gestão e o recolhimento dos documentos produzidos e recebidos pelo Poder Judiciário Federal no exercício de suas funções, tramitados em juízo e oriundos de cartórios e secretarias competem ao Arquivo Nacional.","e":"os conjuntos de documentos produzidos e recebidos por entidades privadas encarregadas da gestão de serviços públicos no exercício de suas atividades são considerados documentos privados de caráter prescritível.","gabarito":"C","materia":"Arquivologia","tema":"Legislação Arquivística ,Lei nº 8.159/91 - Política Nacional de Arquivos","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2638043","enunciado":"","a":"Especializado - Especialidade: Arquivologia digitalização precisa de um conjunto de procedimentos e técnicas para assegurar a capacidade dos objetos digitais a serem acessados face às mudanças tecnológicas, de forma que a passagem de uma plataforma computacional em vias de descontinuidade para uma outra mais moderna define","b":"A a cadeia de preservação. a cópia de segurança.","c":"o carimbo digital de tempo.","d":"a emulação.","e":"a migração.","gabarito":"E","materia":"Arquivologia","tema":"Microfilmagem e Automação ,Digitalização de Documentos","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2638042","enunciado":"Especializado - Especialidade: Arquivologia No processo de digitalização, a atividade de reconhecimento em meio eletrônico que se caracteriza pelo estabelecimento de uma relação única, exclusiva e intransferível entre uma chave de criptografia e uma pessoa física, jurídica, máquina ou","a":"aplicação, denomina-se assinatura digital.","b":"geração de documento arquivístico digital.","c":"concessão de chave privada.","d":"certificação digital.","e":"estabelecimento de identificador único.","gabarito":"D","materia":"Arquivologia","tema":"Microfilmagem e Automação ,Digitalização de Documentos","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2638041","enunciado":"Especializado - Especialidade: Arquivologia De acordo com a legislação de microfilmagem, é correto afirmar que","a":"ao final da microfilmagem de cada série, deve constar o número do microfilme, ordenação, identificação e resumo da série de documentos que foram microfilmados.","b":"a imagem de abertura de um microfilme deve fazer menção, quando for o caso, de que a série de documentos a serem microfilmados é continuação da série contida em microfilme anterior.","c":"na microfilmagem de documentos, cada série será precedida de imagem de abertura, sem identificação do detentor dos documentos microfilmados para garantia de sigilo.","d":"no início da série microfilmada é obrigatória a imagem de abertura com a inclusão do termo de encerramento atestando a fiel observância às disposições legais.","e":"os documentos da mesma série omitidos, quando da microfilmagem por falha de operação ou problema técnico, serão reproduzidos novamente, sendo permitido corte ou inserção no filme original.","gabarito":"B","materia":"Arquivologia","tema":"Legislação Arquivística ,Lei nº 5.433/68 – Microfilmagem","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2638039","enunciado":"Especializado - Especialidade: Arquivologia Para conservação dos acervos de documentos em exposições de curto, médio e longo prazo nos arquivos deve-se tomar","a":"alguns cuidados especiais, entre eles, colocar as lâmpadas dentro das vitrines de exposição.","b":"utilizar materiais que mantenham as vitrines úmidas.","c":"proteger os objetos expostos com filtros especiais.","d":"manter o nível de luz o mais alto possível.","e":"expor um objeto valioso por muito tempo.","gabarito":"C","materia":"Arquivologia","tema":"Microfilmagem e Automação ,Conservação e Preservação de Documentos Eletrônicos","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2638028","enunciado":"Especializado - Especialidade: Arquivologia Assinale a alternativa correta.","a":"As flutuações de temperatura e umidade relativa do ar são muito mais nocivas do que os índices superiores aos considerados ideais, desde que estáveis e constantes.","b":"A temperatura e a umidade relativa do ar muito altas quando detectadas nos espaços dos arquivos transparecem em documentos distorcidos e ressecados.","c":"A circulação do ar no ambiente representa um fator importante para aumentar os efeitos prejudiciais da temperatura e umidade relativa quando elevadas.","d":"Os materiais dos arquivos são higroscópicos, isto é, liberam umidade facilmente e, portanto, se expandem com as variações para baixo de temperatura e umidade relativa do ar.","e":"A umidade relativa baixa do ar proporciona as condições necessárias para desencadear intensas reações químicas nos materiais, detectadas na presença de colônias de fungos.","gabarito":"A","materia":"Arquivologia","tema":"Conservação e Preservação ,Armazenamento e Acondicionamento","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2638023","enunciado":"Especializado - Especialidade: Arquivologia Suporte circular plano, com grande capacidade de armazenamento, em que se registram sinais visuais, sonoros ou","a":"audiovisuais, por gravação digital. Trata-se da definição do suporte documental denominado filme cinematográfico.","b":"disco magnético.","c":"microfilme positivo.","d":"filme de nitrato.","e":"disco ótico.","gabarito":"E","materia":"Arquivologia","tema":"Conceitos Fundamentais ,Conceitos e Definições","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2638021","enunciado":"Especializado - Especialidade: Arquivologia Pode receber denominações abrangentes, vale coletivamente pela atividade que representa, define-se pela procedência e, enquanto acumulação, interessa principalmente ao produtor e ao pesquisador; vigora para os arquivos corrente,","a":"intermediário, permanente e uso secundário. Trata-se da definição de ordenação de documentos.","b":"prazo de vigência.","c":"guarda permanente.","d":"tipo documental.","e":"código de classificação.","gabarito":"D","materia":"Arquivologia","tema":"Conceitos Fundamentais ,Tipologia Documental","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2638018","enunciado":"Especializado - Especialidade: Arquivologia O gênero documental integrado por documentos que contêm imagens fixas, impressas, desenhadas ou fotografadas","a":"denomina-se filmografia.","b":"acervo de gravuras.","c":"arquivo fotográfico.","d":"documento audiovisual.","e":"documento iconográfico.","gabarito":"E","materia":"Arquivologia","tema":"Gestão de Documentos / Arquivos Corrente e Intermediário ,Classificação de Documentos","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2638015","enunciado":"","a":"Especializado - Especialidade: Arquivologia espécie documental que corresponde a um documento diplomático testemunhal de assentamento que apresenta como protocolo inicial o número do documento, nome da entidade subscritora, data cronológica, nome e qualificação das pessoas presentes, declaração de abertura e como texto traz os assuntos discutidos, denomina-se","b":"A certificado auto.","c":"ata.","d":"certidão.","e":"escritura.","gabarito":"C","materia":"Arquivologia","tema":"Conceitos Fundamentais ,Tipologia Documental","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2638013","enunciado":"Especializado - Especialidade: Arquivologia Ordenamento físico dos documentos visando torná-los inteligíveis e utilizáveis, realizado com base em sua classificação e","a":"em princípios e métodos específicos. Trata-se da definição de arranjo.","b":"guarda.","c":"desmembramento.","d":"retenção.","e":"arquivamento.","gabarito":"A","materia":"Arquivologia","tema":"Arquivos Permanentes ,Arranjo","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2638011","enunciado":"Especializado - Especialidade: Arquivologia Especificação de requisitos que estabelece um conjunto de condições a serem cumpridas pela organização produtora/recebedora de documentos, pelo sistema informatizado de gestão arquivística e pelos próprios documentos a","a":"fim de garantir a sua confiabilidade e autenticidade, assim como seu acesso. Trata-se da definição de GED.","b":"e-ARQ Brasil.","c":"RDC-Arq.","d":"Archivematica.","e":"AtoM.","gabarito":"B","materia":"Arquivologia","tema":"Microfilmagem e Automação ,Automação de Arquivos","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2638009","enunciado":"Especializado - Especialidade: Arquivologia No que concerne ao Sistema Informatizado de Gestão Arquivística de Documentos, é correto afirmar que","a":"traz características inovadoras de forma que o sucesso de implantação independa da incorporação prévia de um","b":"programa de gestão arquivística de documentos. possui um conjunto de procedimentos e operações técnicas focado na descrição arquivística de documentos digitais.","c":"se trata de sistema desenvolvido prioritariamente para otimizar o acesso e a recuperação de documentos arquivísticos.","d":"apresenta ações aplicáveis a documentos convencionais, ao registrar suas referências, incorporando imagens digitalizadas e a documentos digitais.","e":"processa eletronicamente material em ambientes híbridos, isto é, documentos digitais e não digitais separadamente em sistemas diferentes.","gabarito":"D","materia":"Arquivologia","tema":"Gestão de Documentos / Arquivos Corrente e Intermediário ,Ciclo Vital /Teoria das Três Idades","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2638008","enunciado":"Especializado - Especialidade: Arquivologia Assinale a alternativa que contém exclusivamente rotinas para destinação dos documentos na fase intermediária.","a":"Elaborar termo de eliminação, eliminar as cópias e vias cujo original ou um exemplar encontrem-se no mesmo conjunto ou dossiê e operacionalizar a transferência, seguindo orientações do setor responsável pelo arquivamento.","b":"Separar os documentos a serem destinados, verificando se cumpriram o prazo de guarda estabelecido para a fase, proceder à alteração de suporte, se for o caso, e proceder ao registro dos documentos eliminados.","c":"Operacionalizar o recolhimento, segundo orientações da instituição arquivística responsável pela guarda permanente, organizar os documentos produzidos e recebidos pelo órgão e separar os documentos produzidos.","d":"Verificar se os documentos a serem destinados estão organizados de acordo com os conjuntos documentais definidos na tabela de temporalidade, elaborar listagem dos documentos destinados à transferência para a próxima fase e proceder à classificação.","e":"Elaborar listagem dos documentos destinados ao recolhimento, proceder o registro dos documentos produzidos e recebidos, realizar a descrição arquivística.","gabarito":"B","materia":"Arquivologia","tema":"Gestão de Documentos / Arquivos Corrente e Intermediário ,Ciclo Vital /Teoria das Três Idades","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2638004","enunciado":"Especializado - Especialidade: Arquivologia Analise o quadro a seguir. 000 ADMINISTRAÇÃO GERAL 010 ORGANIZAÇÃO E FUNCIONAMENTO 012COMUNICAÇÃO SOCIAL 012.1 RELAÇÕES COM A IMPRENSA 012.11 CREDENCIAMENTO DE JORNALISTAS (Código de classificação de documentos de arquivo para a administração pública: atividades-meio, 2001) Em relação ao Código de classificação de documentos é correto afirmar que","a":"no código de classificação, as funções e atividades são entendidas como assunto e estão organizadas em ordem","b":"alfabética. os códigos numéricos refletem a superordenação dos subgrupos ao grupo, do grupo à subclasse e desta, à classe.","c":"o modelo adotado é o de código de classificação decimal com código numérico divido em cem classes com sucessivas","d":"divisões. a classe principal 000 corresponde ao grande subgrupo de atividades desenvolvidas pelo órgão.","e":"os assuntos recebem códigos numéricos os quais refletem a hierarquia funcional do órgão. Arquivologia>Gestão de Documentos / Arquivos Corrente e Intermediário ,","gabarito":"E","materia":"Arquivologia","tema":"Gestão de Documentos / Arquivos Corrente e Intermediário ,Protocolo","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_703","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio Especializado - Especialidade: Arquivologia No que se refere ao método de arquivamento alfabético, é correto afirmar que","a":"os sobrenomes compostos de um substantivo e um adjetivo ou ligados por hífen podem ser separados na","b":"alfabetação. os títulos pessoais devem ser considerados na alfabetação dos nomes completos.","c":"os nomes espanhóis são registrados pelo último sobrenome que corresponde ao sobrenome da família do pai.","d":"os artigos, as preposições e as conjunções como “a, o, de, da, do, e” devem ser considerados na alfabetação dos","e":"nomes e sobrenomes. as iniciais abreviativas de prenomes têm precedência na alfabetação de sobrenomes iguais. Arquivologia>Gestão de Documentos / Arquivos Corrente e Intermediário ,Transferência / Recolhimento ,","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_704","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio Especializado - Especialidade: Arquivologia Assinale a alternativa que contém exclusivamente atividades relacionadas à rotina de expedição de documentos na unidade emissora.","a":"Conferir o registro do documento, registrar o envio, providenciar cópia do documento, emitir relação de remessa e acondicionar o documento.","b":"Conferir o remetente do destinatário, atestar o recebimento do documento em trânsito, formalizar o encerramento do volume, emitir nova folha líder e conferir o despacho.","c":"Expedir o documento, devolver a relação de remessa, conferir a instrução, conferir a numeração de folhas e registrar o encaminhamento.","d":"Emitir relação de remessa, conferir o documento, atestar o recebimento do documento, conferir a solicitação de autuação e pesquisar antecedentes.","e":"Registrar o processo, ordenar os documentos, colar os documentos, inutilizar os espaços em branco e encaminhar o processo.","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637994","enunciado":"","a":"Especializado - Especialidade: Arquivologia movimentação de um processo de uma unidade à outra, interna ou externa, através de sistema próprio denomina-se","b":"A distribuição. tramitação.","c":"notação.","d":"desentranhamento.","e":"transferência.","gabarito":"B","materia":"Arquivologia","tema":"Gestão de Documentos / Arquivos Corrente e Intermediário ,Protocolo","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637991","enunciado":"Especializado - Especialidade: Arquivologia Conjunto de procedimentos e operações técnicas que visam a agrupar os documentos de arquivo relacionando-os ao órgão","a":"produtor, à função, à subfunção e à atividade responsável por sua produção ou acumulação. Trata-se da definição de pesquisa documental.","b":"utilização dos documentos.","c":"classificação de documentos.","d":"acesso à informação.","e":"descrição arquivística.","gabarito":"C","materia":"Arquivologia","tema":"Gestão de Documentos / Arquivos Corrente e Intermediário ,Protocolo","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637990","enunciado":"Especializado - Especialidade: Arquivologia Assinale a alternativa que apresenta exclusivamente atividades relacionadas ao recebimento de documentos.","a":"Separar a correspondência oficial da que é particular; separar a correspondência oficial de caráter ostensivo da de caráter sigiloso; encaminhar a correspondência sigilosa aos respectivos destinatários.","b":"Tomar conhecimento da correspondência pela leitura, verificando a existência de antecedentes; encaminhar os documentos aos respectivos destinos; arquivar uma cópia por assunto no respectivo dossiê.","c":"Verificar a classificação atribuída no ato do recebimento; anotar abaixo do número e da data a primeira distribuição e o código de assunto; arquivar todos os documentos de acordo com o método adotado.","d":"Receber os documentos e examiná-los a fim de não serem guardados aqueles cujas ações ainda não tenham sido concluídas; preencher em duas vias o formulário de recibo; receber de vários setores os documentos a serem distribuídos.","e":"Receber a correspondência por malotes, balcão ou correio; colocar carimbo com numerador ou datador; classificar as cópias de correspondência expedida, anotando o código adotado em todas as cópias. Arquivologia>Gestão de Documentos / Arquivos Corrente e Intermediário ,Ciclo Vital /Teoria das Três Idades ,","gabarito":"A","materia":"Arquivologia","tema":"Gestão de Documentos / Arquivos Corrente e Intermediário ,Transferência / Recolhimento","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_708","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio Especializado - Especialidade: Arquivologia Analise o quadro a seguir. Número do doc. Código Procedência Data de entrada Espécie Data do doc. Nº de origem Assunto DistribuiçãoData Recebido Data 1ª 2º 3º 4º 5º","a":"Assinale a alternativa que indica o nome do impresso apresentado. Ficha de protocolo.","b":"Formulário de procedência.","c":"Formulário de recebimento.","d":"Modelo de fluxo.","e":"Ficha de assunto.","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637985","enunciado":"Especializado - Especialidade: Arquivologia Assinale a alternativa que apresenta exclusivamente atividades relacionadas ao momento de produção dos documentos.","a":"Controle dos documentos, preservação do patrimônio documental, racionalização e eficiência da utilização de","b":"documentos. Efetivação de programa de avaliação, proteção de conjuntos documentais e eliminação de documentos.","c":"Estabelecimento de rotinas de arquivamento, definição de prazos e vigências de documentos, elaboração de normas","d":"de acesso. Implantação de sistemas de arquivo, seleção dos sistemas de reprodução e automatização do uso.","e":"Elaboração de formulários, implantação de sistemas de organização e aplicação de tecnologias aos procedimentos administrativos.","gabarito":"E","materia":"Arquivologia","tema":"Conceitos Fundamentais ,Conceitos e Definições","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637981","enunciado":"Especializado - Especialidade: Arquivologia Assinale a alternativa correta.","a":"Naturalidade define-se pelo fato de que os documentos não são produzidos com a intenção de privilegiar os interesses do seu produtor ou do futuro pesquisador.","b":"Autenticidade é a qualidade de um documento quando preenche as formalidades necessárias para que se reconheça sua proveniência, independentemente da veracidade do respectivo conteúdo.","c":"Organicidade provém do fato de que cada registro documental assume um lugar único na estrutura documental do grupo ao qual pertence e no universo documental.","d":"Imparcialidade é característica dos registros documentais que se referem à maneira como os documentos se acumulam no curso das transações de acordo com as necessidades da matéria em pauta.","e":"Unicidade é a qualidade segundo a qual os arquivos espelham a estrutura, funções e atividades da entidade produtora/acumuladora em suas relações internas e externas.","gabarito":"B","materia":"Arquivologia","tema":"Conceitos Fundamentais ,Teoria e Abordagem Arquivística","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637976","enunciado":"Especializado - Especialidade: Arquivologia Em relação a características de documentos nas instituições de custódia (bibliotecas, arquivos e museus), é correto afirmar que","a":"o tipo de suporte em arquivos prevê a existência de documentos manuscritos, impressos e audiovisuais em","b":"exemplares múltiplos. a entrada de documentos no arquivo ocorre a partir de processos de compra, doação ou pesquisa realizada.","c":"o tipo de conjunto de documentos nos arquivos é denominado coleção e são reunidos pelo conteúdo ou pelo que","d":"representam. a entrada de documentos nos museus ocorre por compra, doação e permuta de fontes múltiplas.","e":"o conjunto de documentos nas bibliotecas é conhecido como fundo e os documentos são reunidos a partir de sua origem.","gabarito":"D","materia":"Arquivologia","tema":"Conceitos Fundamentais","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637972","enunciado":"Especializado - Especialidade: Arquivologia Corresponde ao conjunto das atividades que um órgão público ou empresa privada exerce para a consecução de seus","a":"objetivos, sendo que essas atividades podem ser diretas e essenciais ou indiretas e auxiliares. Trata-se da definição de fundo.","b":"função.","c":"atividades-meio.","d":"valor mediato.","e":"amostragem. Arquivologia>Conceitos Fundamentais ,Conceitos e Definições ,","gabarito":"B","materia":"Arquivologia","tema":"Conceitos Fundamentais ,Conceitos e Definições","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_713","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio Especializado - Especialidade: Arquivologia De acordo com a Teoria das Três Idades,","a":"arquivo permanente é um conjunto de documentos com valor informativo e probatório, com uso pouco frequente e que aguarda destinação.","b":"valor secundário é o valor que um documento possui para a atividade administrativa de uma entidade produtora, na medida em que informa, fundamenta ou prova seus atos.","c":"valor primário é atribuído ao documento em função do interesse que possa ter para a entidade produtora, levando-se em conta a sua utilidade para fins administrativos, legais e fiscais.","d":"arquivo intermediário é um conjunto de documentos em tramitação, objeto de consultas frequentes pela entidade que o produziu, a quem compete a sua administração.","e":"arquivo corrente consiste no conjunto de documentos preservados em caráter definitivo em função de seu valor e que também é chamado de arquivo histórico ou geral.","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637968","enunciado":"Especializado - Especialidade: Arquivologia Sucessivas fases por que passam os documentos de um arquivo da sua produção à guarda permanente ou eliminação.","a":"Trata-se da definição de curadoria documental.","b":"gestão documental.","c":"preservação de documentos.","d":"ciclo vital dos documentos.","e":"gestão de depósito.","gabarito":"D","materia":"Arquivologia","tema":"Conceitos Fundamentais ,Conceitos e Definições","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637967","enunciado":"Especializado - Especialidade: Arquivologia No que concerne aos princípios arquivísticos, é correto afirmar que o princípio","a":"da imprescritibilidade é aquele que consiste em resguardar um fundo de misturas com outros, de parcelamentos e de eliminações indiscriminadas.","b":"da integridade arquivística é aquele segundo o qual documentos deveriam ser transferidos para a custódia de arquivos com jurisdição arquivística sobre o território ao qual se reporta o seu conteúdo, sem levar em conta o lugar em que foram produzidos.","c":"do respeito à ordem original é aquele segundo o qual o arquivo deveria conservar o arranjo dado pela entidade coletiva, pessoa ou família que o produziu.","d":"do respeito aos fundos é aquele pelo qual é assegurado ao Estado o direito sobre os arquivos públicos, sem limitação de tempo, por serem estes considerados bens públicos inalienáveis.","e":"da pertinência é aquele segundo o qual o arquivo produzido por uma entidade coletiva, pessoa ou família não deve ser misturado aos de outras entidades produtoras.","gabarito":"C","materia":"Arquivologia","tema":"Conceitos Fundamentais ,Teoria e Abordagem Arquivística","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637966","enunciado":"Especializado - Especialidade: Arquivologia Uma categoria abstrata que se materializa quando é registrada e representa uma sucessão de atos ou fragmentos que","a":"possam ser definidos como fatos. Trata-se da definição de informação arquivística.","b":"função jurídica.","c":"valor.","d":"custódia.","e":"suporte material.","gabarito":"A","materia":"Arquivologia","tema":"Conceitos Fundamentais ,Conceitos e Definições","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637965","enunciado":"Especializado - Especialidade: Arquivologia Em relação às origens e à história dos arquivos, é correto afirmar que","a":"há um consenso bem estabelecido na Arquivologia que os arquivos surgiram no período pré-histórico, quando os habitantes registravam nas paredes e grutas as informações a respeito do cotidiano.","b":"existe na abordagem diplomática a relação entre o surgimento dos arquivos e a escrita, o que possibilitou a documentação dos registros e vincula o aparecimento dos arquivos às civilizações asiáticas cerca de 5 mil anos atrás.","c":"o primeiro período histórico dos arquivos vai da antiguidade até metade do século XVII, marcado pela concepção de arquivo com conceito historicista e pela prevalência do valor histórico dos documentos.","d":"o segundo e último período da história dos arquivos ocorre do início do século XVIII até o momento atual caracterizado pelo conceito de arquivo patrimonial e administrativo, associado à importância do valor jurídico dos documentos.","e":"a perspectiva diacrônica busca compreender os arquivos desde o surgimento da escrita, no berço das civilizações pré- clássicas, passando pelas práticas greco-romanas chegando até a prática moderna.","gabarito":"E","materia":"Arquivologia","tema":"Conceitos Fundamentais ,História da Arquivologia","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637945","enunciado":"","a":"Especializado - Especialidade: Serviço Social saúde do trabalhador vem se apresentando como uma importante área de atuação do assistente social nas últimas décadas. Suas atribuições estão voltadas para o atendimento individual ou em grupo, para a pesquisa, assessoramento e mobilização dos trabalhadores, muitas vezes compondo equipe multiprofissional. Os assistentes sociais também ocupam espaços de gestão e planejamento e realizam pesquisas nessa área, tendo sempre como diretriz","b":"A a laborterapia. o projeto ético-político profissional.","c":"a cultura organizacional.","d":"a perspectiva funcional-interativa.","e":"a reabilitação ocupacional.","gabarito":"B","materia":"Serviço Social","tema":"Assistência Social no Serviço Social ,Proteção Social Básica","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637944","enunciado":"","a":"Especializado - Especialidade: Serviço Social saúde do trabalhador é um campo estratégico que requer conhecimentos e práticas nos níveis técnico, social e humano. Voltado para analisar e intervir nas relações de trabalho que provocam doenças e agravos, configura-se como um campo interdisciplinar e interinstitucional; seus marcos referenciais são os da Saúde Coletiva, ou seja, a promoção, a prevenção e","b":"A a vigilância. o cuidado.","c":"a cura.","d":"a intervenção.","e":"a equidade.","gabarito":"A","materia":"Serviço Social","tema":"Assistência Social no Serviço Social ,Proteção Social Básica","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637943","enunciado":"","a":"Especializado - Especialidade: Serviço Social Rede de Atenção Psicossocial (RAPS), prevê a oferta de cuidado integral a toda pessoa com transtorno mental, por meio de assistência multiprofissional. Apesar da universalidade do atendimento da RAPS, há uma prevalência de pessoas que buscam seus serviços, que sofrem com o transtorno mental aliado a uma série de expressões da questão social. Acumulando conhecimento e experiência na intersetorialidade, o Assistente Social, na interface com a Política de Saúde Mental, é o profissional que evidencia as condições de vida das pessoas com transtornos mentais e seus familiares, que afetam o processo","b":"A de alta hospitalar. saúde-doença.","c":"de internação compulsória.","d":"de autoestima.","e":"independência-interdição.","gabarito":"B","materia":"Serviço Social","tema":"Serviço Social e Equipe Multi e Interdisciplinar","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637942","enunciado":"Especializado - Especialidade: Serviço Social No regime adotado pela previdência pública na maioria dos países, faz-se o cálculo de contribuições necessárias a serem arrecadadas em determinado período de tempo para cobrir benefícios do mesmo período. A contribuição corresponde a um percentual sobre a remuneração do contribuinte; é um regime de caixa, em que as entradas são iguais às saídas, sem","a":"sobras. Trata-se de um modelo baseado na repartição simples ou regime orçamentário.","b":"compensatória.","c":"capital de cobertura.","d":"binária.","e":"pré-laborativo.","gabarito":"A","materia":"Direito Previdenciário","tema":"Financiamento do Regime Geral da Previdência Social","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637941","enunciado":"Especializado - Especialidade: Serviço Social Constitui uma das finalidades da atuação do Assistente Social no campo sociojurídico, subsidiar ou assessorar a autoridade judiciária no conhecimento dos aspectos socioeconômicos, culturais, interpessoais, familiares, institucionais e comunitários, sobre determinada situação, em vista de uma decisão judicial. De acordo com a Lei no 8.662/1993 que regulamenta a profissão do assistente social, realizar vistorias, perícias técnicas, laudos periciais, informações e pareceres sobre a matéria","a":"de Serviço Social, constitui uma de suas prerrogativas básicas.","b":"obrigações jurídicas.","c":"ações interativas.","d":"competências técnicas.","e":"atribuições privativas. Direito da Criança e do Adolescente - Estatuto da Criança e do Adolescente (ECA) - Lei nº 8.069 de 1990>","gabarito":"E","materia":"Serviço Social","tema":"Serviço Social no campo sócio jurídico","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_723","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio Especializado - Especialidade: Serviço Social O ECA estabelece o direito de acesso da criança e do adolescente não apenas à Justiça da Infância e da Juventude, mas também a todos os órgãos jurisdicionais. Define o Estatuto que os menores de dezesseis anos serão representados e os maiores de dezesseis e menores de vinte e um anos assistidos por seus pais, tutores ou curadores, na forma da legislação o civil ou processual. Ainda de acordo com o ECA (art.141, § 1 ) a assistência judiciária gratuita será prestada aos que dela","a":"necessitarem, através de defensor público ou centros de defesa.","b":"assistência voluntária.","c":"advogado nomeado.","d":"parceria com a OAB.","e":"perito pro labore. Direito da Criança e do Adolescente - Estatuto da Criança e do Adolescente (ECA) - Lei nº 8.069 de 1990>","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_724","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio Especializado - Especialidade: Serviço Social O Conselho Tutelar foi previsto com a função de coibir ameaças e violação de direitos. Além desse órgão, a lei definiu a implantação Fundos e dos Conselhos dos Direitos da Criança e do Adolescente. As alterações do ECA, favoreceram o aperfeiçoamento da sistemática prevista para garantia dos direitos; proporcionou a implementação da Política de Atendimento e da atuação dos órgãos que compõem o Sistema de Garantias de Direitos, em consonância com o paradigma","a":"da proteção integral. Nesta concepção, o Conselho Tutelar assumiu papel de extrema importância como uma estratégia reguladora.","b":"uma instância consultiva.","c":"um órgão mediador de conflitos.","d":"um mecanismo extrajudicial.","e":"um instrumento competente. Direito da Criança e do Adolescente - Estatuto da Criança e do Adolescente (ECA) - Lei nº 8.069 de 1990>","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_725","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio Especializado - Especialidade: Serviço Social Uma das atribuições do Conselho Tutelar é atender e aconselhar os pais ou o responsável, aplicando medidas a eles pertinentes, previstas no artigo 129 (I a VII) do ECA. A perda da guarda, a destituição da tutela e a suspensão ou destituição do poder familiar são medidas aplicáveis pela autoridade judicial, assim como a determinação do afastamento do agressor da moradia comum, na hipótese de maus-tratos, opressão ou abuso sexual impostos pelos pais ou responsável,","a":"determinação essa prevista no artigo 130 do Estatuto como uma medida auxiliar.","b":"cautelar.","c":"protetiva.","d":"socioeducativa.","e":"contenciosa. Direito da Criança e do Adolescente - Estatuto da Criança e do Adolescente (ECA) - Lei nº 8.069 de 1990>","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_726","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio Especializado - Especialidade: Serviço Social o o O ECA (Lei n 8069/1990) rompeu com o caráter assistencial, curativo e, sobretudo, corretivo-repressivo dos códigos de menores, antes vigentes no Brasil. Essa lei propõe uma releitura sobre a prática do ato infracional, a partir da separação por critério etário na aplicação das medidas e assegurando a exclusividade das medidas socioeducativas aos adolescentes considerados autores de ato infracional. Tais medidas são atividades impostas aos adolescentes com a finalidade de reintegrá-los ao convívio social. Nesse sentido, é correto afirmar que o cessar de ocorrências de ato infracional na infância e","a":"adolescência, implica assegurar direitos.","b":"correção de condutas.","c":"adaptação ao meio.","d":"ocupação do tempo livre.","e":"mudanças no modo de educar. Direito da Criança e do Adolescente - Estatuto da Criança e do Adolescente (ECA) - Lei nº 8.069 de 1990>","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_727","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio Especializado - Especialidade: Serviço Social Ao abordar as medidas de proteção à criança e ao adolescente, o ECA ressalta o dever da sociedade em geral e do poder público em especial, além da família, de assegurar seus direitos básicos. Nessa perspectiva, são sujeitos-alvos das medidas de proteção todas as crianças e adolescentes que tenham seus direitos ameaçados ou violados. De acordo com o art. 98, III do ECA as medidas específicas de proteção à criança e ao adolescente são aplicáveis sempre que os direitos nele reconhecidos forem ameaçados ou violados por ação ou omissão da sociedade ou do Estado, por falta, omissão ou abuso","a":"dos pais ou responsável assim como em âmbito subjetivo.","b":"em contexto privado.","c":"em função da displicência estrutural.","d":"em detrimento de sua reação.","e":"em razão de sua conduta. Direito da Criança e do Adolescente - Estatuto da Criança e do Adolescente (ECA) - Lei nº 8.069 de 1990>","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_728","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio Especializado - Especialidade: Serviço Social Conforme determina o Estatuto da Criança e do Adolescente (ECA) as entidades de atendimento são responsáveis pela manutenção das próprias unidades, assim como pelo planejamento e execução de programas de proteção e socio- educativos destinados a crianças e adolescentes. Ainda, no que se refere às entidades não-governamentais somente o poderão funcionar depois de devidamente registrada no órgão competente. Conforme prevê o § 2 do artigo 91, o registro","a":"terá validade máxima de quatro anos e, reavaliar periodicamente, o cabimento de sua renovação, cabe ao Ministério Público.","b":"Gestor da Assistência Social.","c":"Conselho Municipal dos Direitos da Criança e do Adolescente.","d":"Coletivo Independente das Entidades Sociais.","e":"Conselho Tutelar. Serviço Social>Assistência Social no Serviço Social ,","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_729","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio Especializado - Especialidade: Serviço Social O artigo 24 da Lei Orgânica da Assistência Social (LOAS) caracteriza os Programas de Assistência Social como ações integradas e complementares com objetivos, tempo e área de abrangência definidos para qualificar, incentivar e melhorar o os benefícios e os serviços assistenciais. O parágrafo § 1 do citado artigo estabelece que tais programas serão definidos pelos respectivos Conselhos de Assistência Social, obedecidos os objetivos e princípios que regem a LOAS, com prioridade","a":"para a maternidade.","b":"pessoa desempregada.","c":"integração à vida comunitária.","d":"inserção profissional e social.","e":"reabilitação de pessoas com deficiência.","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637933","enunciado":"Especializado - Especialidade: Serviço Social No âmbito da Seguridade Social brasileira, a saúde é direito de todos e dever do Estado, garantido mediante políticas sociais e econômicas que visem à redução do risco de doença e de outros agravos e ao acesso universal e igualitário às ações e o serviços. De acordo com previsões do art. 199 (§1 ) da Constituição Federal, as instituições privadas, tendo preferência as entidades filantrópicas e as sem fins lucrativos, poderão participar de forma complementar do Sistema Único de Saúde,","a":"segundo diretrizes deste, mediante contrato de direito público ou voluntariado.","b":"convênio.","c":"apoio financeiro.","d":"contrapartida técnica.","e":"parceria.","gabarito":"B","materia":"Direito Constitucional","tema":"Previdência Social ,Ordem Social","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637932","enunciado":"Especializado - Especialidade: Serviço Social Compreender os espaços ocupacionais do assistente social requer situá-los no contexto de revitalização capitalista, no qual reafirma-se a centralidade do mercado como regulador das relações sociais. É esse contexto que atribui novos contornos ao mercado profissional, marcado por novas habilidades, competências e atribuições. É correto afirmar que o espaço ocupacional é um produto histórico, condicionado pelo nível de luta entre as classes fundamentais e suas alianças e pelas","a":"respostas teórico-práticas dadas pela categoria profissional, afiançadoras de isonomia.","b":"garantidoras de resultados.","c":"densas de conteúdo político.","d":"asseguradoras de previsibilidade.","e":"plenas de compreensão.","gabarito":"C","materia":"Serviço Social","tema":"Profissão do Assistente Social e o Código de Ética do Serviço Social","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637931","enunciado":"Especializado - Especialidade: Serviço Social Na história recente dos processos de trabalho verificam-se profundas transformações, que repercutiram no cotidiano das práticas profissionais. A prática do assistente social, entendida como processo de trabalho, implica uma matéria-prima, meios de trabalho e seu produto. Tendo como objeto a questão social, o conhecimento e o instrumental técnico-operativo como meios, esse trabalho tem um efeito nas condições materiais da população. Embora nem sempre se corporifiquem como coisas materiais autônomas, o produto do trabalho do assistente social tem uma objetividade social, expressando-se","a":"sob a forma de serviços.","b":"ncentivos.","c":"mais-valia.","d":"reconhecimento.","e":"ocupação. Serviço Social>","gabarito":"A","materia":"Serviço Social","tema":"Surgimento e Institucionalização do Serviço Social","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_733","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","a":"Especializado - Especialidade: Serviço Social prestação de serviços e a assistência pública é um dos princípios estruturantes do Estado de Bem-Estar Social. Nessa perspectiva, a universalidade dos serviços sociais como saúde, educação, segurança social, habitação e a implantação de uma rede socioassistencial, são responsabilidades do Estado, para a manutenção das condições de vida dos cidadãos. Na sua contramão, o processo de privatização e desmonte de serviços sociais, o abandono na formação e educação continuada dos seus prestadores, são rebatimentos quantitativos e qualitativos na assistência pública, provocados pela reforma do Estado em sua vertente","b":"A crítica. intervencionista.","c":"progressista.","d":"neoliberal.","e":"pós-moderna. Serviço Social>Surgimento e Institucionalização do Serviço Social ,","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_734","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio Especializado - Especialidade: Serviço Social Embora pouco expressiva, a atuação do assistente social nos movimentos sociais realizou-se por meio da própria mobilização e organização política da categoria, integrada ao processo organizativo dos trabalhadores. A participação popular situa-se nessa mesma contextualidade, como elemento de politização das relações sociais, da democratização da sociedade, de intervenção crítica das classes subalternas e, para a profissão, como elemento estratégico para seu","a":"desenvolvimento pedagógico-laborativo.","b":"pleno.","c":"plural.","d":"teórico-político.","e":"adequado.","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637928","enunciado":"Especializado - Especialidade: Serviço Social Embora não haja padrão estatal imutável e absoluto, o Estado pode assumir forma política e historicamente definida. Entre as definições de Estado está aquela que destaca a presença constante de quatro elementos que o constituem: um conjunto de instituições e prerrogativas; uma máquina burocrática; um conjunto de condutas e comportamentos gerais, previsíveis e","a":"regulados; e o território, espaço geograficamente delimitado onde o poder estatal é exercido, ora denominado como contexto.","b":"campo.","c":"locus.","d":"realidade.","e":"sociedade.","gabarito":"E","materia":"Serviço Social","tema":"Políticas Sociais","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637927","enunciado":"","a":"Especializado - Especialidade: Serviço Social história social das crianças e dos adolescentes revela que a desqualificação das famílias em situação de pobreza, tratadas como incapazes, deu sustentação à prática de destituição do poder familiar. Atravessam o cotidiano político-institucional nos tribunais, processos envolvendo famílias empobrecidas que, embora contem com relações de solidariedade parental, têm experimentado a diminuição da sua capacidade de proteger seus membros. Considerando que a falta ou a carência de recursos materiais não constitui motivo suficiente para a perda ou a suspensão do poder familiar e para garantir o direito da criança e do adolescente à convivência familiar é de fundamental importância a implementação de políticas de","b":"A apoio à família. apadrinhamento familiar.","c":"acolhimento institucional.","d":"inserção laborativa.","e":"recuperação de danos.","gabarito":"A","materia":"Serviço Social","tema":"Proteção Social à Criança, ao Adolescente e à Família","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637926","enunciado":"","a":"Especializado - Especialidade: Serviço Social configuração da família está diretamente relacionada ao contexto social, econômico, político e cultural, em que ela vive. Estudiosos do tema entendem que a família é um espaço extremamente complexo que se reconstrói e se reconfigura cotidianamente a partir das relações que se estabelecem entre seus membros e entre outras esferas da sociedade. No que diz respeito às suas crianças e adolescentes, o cenário brasileiro constitui terreno fértil para o avanço da violação de direitos humanos, considerando suas bases históricas de extrema desigualdade econômica e social e de","b":"A desestruturação familiar. violência estrutural.","c":"desmotivação laboral.","d":"dependência generalizada.","e":"tutela estatal.","gabarito":"B","materia":"Serviço Social","tema":"Proteção Social à Criança, ao Adolescente e à Família","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637925","enunciado":"Especializado - Especialidade: Serviço Social Concebidas e implementadas isoladamente, a setorização das políticas públicas tem configurado a ação do Estado no Brasil. Como consequência dessa setorização, a fragmentação e sobreposição das ações submetem famílias, indivíduos e grupos atendidos a um paralelismo de intervenções e, muitas vezes, à duplicidade de cadastros e procedimentos para acesso aos serviços públicos. Somada à interdisciplinaridade das equipes profissionais, a intersetorialidade, como estratégia de","a":"enfrentamento da fragmentação, pressupõe articulação entre os setores, complementariedade das ações e equipes competitivas.","b":"ajustes das áreas.","c":"alternância de gestão.","d":"modelos padronizados.","e":"decisão política.","gabarito":"E","materia":"Serviço Social","tema":"Políticas Sociais","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637924","enunciado":"Especializado - Especialidade: Serviço Social O assistente social é frequentemente acionado a realizar estudo social a partir de objetivos postos pela instituição. Os documentos produzidos pelos assistentes sociais no campo sociojurídico podem e devem servir também como uma forma de garantir direitos à população. Tem um caráter dinâmico e flexível quando se consideram as finalidades da documentação: atendimento direto, assessoria, registros em conjunto com outros profissionais. Sua utilização também está","a":"vinculada ao arcabouço teórico e ético-político do Serviço Social e a uma postura de imparcialidade.","b":"à produção de provas.","c":"ao direito ao contraditório.","d":"à responsabilização do usuário.","e":"aos objetivos do profissional.","gabarito":"E","materia":"Serviço Social","tema":"Planejamento, Monitoramento e Avaliação de Planos, Programas e Projetos","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637923","enunciado":"Especializado - Especialidade: Serviço Social Um dos eixos do trabalho do assistente social consiste na realização de investigações sobre as condições de vida dos indivíduos e famílias, utilizando-se de instrumentos e técnicas tais como as entrevistas, visitas domiciliares e estudos sociais. Já, o uso ampliado de instrumentos de investigação está voltado para a realização de diagnósticos da realidade social das famílias. Para além de um conhecimento produzido pelo assistente social sobre situações individuais, trata-se de buscar","a":"dados de realidade de conjuntos da população; daí a importância das diretrizes institucionais.","b":"tendências teóricas.","c":"metodologias de pesquisa.","d":"escolhas profissionais.","e":"abordagens pré-existentes.","gabarito":"C","materia":"Serviço Social","tema":"Planejamento, Monitoramento e Avaliação de Planos, Programas e Projetos","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637922","enunciado":"Especializado - Especialidade: Serviço Social Na ação cotidiana do assistente social, os sistemas de avaliação e controle devem ser coerentes com os objetivos que se quer atingir. Nessa perspectiva, três focos podem ser identificados: a avaliação da instituição, dos serviços prestados aos seus usuários e a avaliação do desempenho desse profissional. Nessa linha, é fundamental manter um sistema mínimo de controle e avaliação construído a partir de indicadores de processo, de eficácia e de efetividade. Na avaliação, o indicador é","a":"a unidade que permite medir o alcance de um objetivo ou de uma hipótese.","b":"demanda.","c":"dimensão.","d":"meta.","e":"etapa.","gabarito":"D","materia":"Serviço Social","tema":"Planejamento, Monitoramento e Avaliação de Planos, Programas e Projetos","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637921","enunciado":"Especializado - Especialidade: Serviço Social Os assistentes sociais são chamados a atuar na esfera do planejamento, gestão, monitoramento e avaliação de políticas, compondo equipes multiprofissionais. Em se tratando de políticas sociais, a perspectiva que entende que elas devem ser avaliadas como um conjunto de programas, projetos e ações que devem universalizar direitos, destaca a importância da processualidade da construção desses direitos. Nesse sentido, a avaliação de políticas sociais deve se sobrepor à mera","a":"utilização de métodos e técnicas e compreender o significado do papel do Estado e dos limites institucionais.","b":"das classes sociais.","c":"das alianças propostas.","d":"dos segmentos especializados.","e":"dos parceiros engajados.","gabarito":"B","materia":"Serviço Social","tema":"Planejamento, Monitoramento e Avaliação de Planos, Programas e Projetos","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637920","enunciado":"Especializado - Especialidade: Serviço Social O Planejamento Estratégico, inicialmente desenvolvido para o setor privado, passa a ser incorporado e operacionalizado também no setor público. É um instrumento de gerenciamento utilizado para lidar com situações complexas e com processos de transformação dinâmicos, pressupondo a implementação de ações concretas. A referida metodologia é composta por quatro momentos que objetivam superar os problemas principais do planejamento: o explicativo, o","a":"normativo, o estratégico e o analítico-pedagógico.","b":"pós-facto.","c":"resolutivo-funcional.","d":"avaliativo.","e":"tático-operacional.","gabarito":"E","materia":"Serviço Social","tema":"Instrumentos Técnicos-Operativos do Serviço Social ,Instrumentos e Técnicas de Intervenção","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637919","enunciado":"Especializado - Especialidade: Serviço Social O trabalho do assistente social requer uma postura investigativa sobre o dia a dia dos usuários, as particularidades de suas vidas, suas demandas, carências e necessidades. Nesse sentido, é preciso considerar as mudanças que se processam cotidianamente na sociedade e que alteram o contexto social produzindo, consequentemente, novas necessidades. Diante de tantas demandas postas no cotidiano, além da adoção de uma atitude interdisciplinar, a ação profissional só adquire","a":"alcance social mediante a incorporação de uma postura investigativa, equação esta que possibilita ultrapassar o pragmatismo.","b":"fortalecer as subjetividades.","c":"solucionar o imediato.","d":"minorar os conflitos.","e":"acomodar expectativas. Serviço Social>","gabarito":"A","materia":"Serviço Social","tema":"Planejamento, Monitoramento e Avaliação de Planos, Programas e Projetos","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_745","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio Especializado - Especialidade: Serviço Social Os assistentes sociais acumulam uma experiência de trabalho com coletivos, seja com grupos, comunidades ou pelos vínculos estabelecidos com os movimentos sociais. Nos anos 1990, essa atuação atrela-se aos conselhos de controle social. Assim, a inovação não é a atuação dos assistentes sociais junto a práticas coletivas, mas a configuração dessas formas organizativas. É na atuação do assistente social em relação aos movimentos sociais que há uma mudança de enfoque: ela","a":"não visa a integração social, mas a mobilização da população, sua organização, sua participação e o incremento da consciência de classe.","b":"da intervenção doutrinária.","c":"da ideologia do progresso.","d":"do movimento das massas.","e":"da dimensão solidária.","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637917","enunciado":"Especializado - Especialidade: Serviço Social No Serviço Social tradicional, a intervenção centrada em coletivos ficou conhecida como Desenvolvimento de Comunidade (DC). A proposta de DC baseou-se na perspectiva de integração das comunidades aos programas de desenvolvimento e modernização do país. Coerente com as diferentes vertentes do Serviço Social pós-reconceituação, o trabalho com comunidades seguiu em mais duas perspectivas: a que entendia o desenvolvimento como mudanças, mas sempre no bojo","a":"do ordenamento capitalista e aquela que concebia o desenvolvimento como instrumento de retrocesso coletivo.","b":"emancipação totalitária.","c":"uma nova ordem societária.","d":"uma recomposição política.","e":"retomada conservadora.","gabarito":"C","materia":"Serviço Social","tema":"Assistência Social no Serviço Social ,Proteção Social Básica","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637916","enunciado":"Especializado - Especialidade: Serviço Social Para a efetivação de sua ação, os profissionais acionam um conjunto de instrumentos e técnicas, entre as quais, o trabalho com grupos. No Serviço Social, a abordagem grupal passou por uma ressignificação, a partir dos questionamentos em relação à sua prática inspirada em modelos interativos e subalternizantes. A redefinição da profissão, a partir da adoção do","a":"paradigma crítico-dialético, reaproximou os assistentes sociais das abordagens grupais presentes na prática restaurativa.","b":"educação popular.","c":"perspectiva sistêmica.","d":"cultura da não violência.","e":"resolução de conflitos.","gabarito":"B","materia":"Serviço Social","tema":"Instrumentos Técnicos-Operativos do Serviço Social ,Instrumentos e Técnicas de Intervenção","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637915","enunciado":"","a":"Especializado - Especialidade: Serviço Social abordagem individual tem predominância entre os instrumentos de intervenção do Serviço Social, desde o início da institucionalização da profissão no Brasil. Como componente do acervo metodológico dos assistentes sociais, o atendimento individual é acionado como parte do processo de intervenção nas relações sociais. A configuração desse instrumental técnico-operativo acompanha as alterações históricas da base sócio-organizacional do Serviço Social e caracteriza-se por tratamentos diferenciados conferidos pelos diversos","b":"A métodos vigentes. modelos institucionais.","c":"limites organizacionais.","d":"projetos profissionais.","e":"cenários complexos.","gabarito":"D","materia":"Serviço Social","tema":"Instrumentos Técnicos-Operativos do Serviço Social ,Instrumentos e Técnicas de Intervenção","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637914","enunciado":"Especializado - Especialidade: Serviço Social Emerge nas últimas décadas um arcabouço jurídico-político que incide sobre a dimensão ético-legal da profissão. Trata-se de um aparato normativo-legal, que conjuga matéria estritamente profissional com legislação social de caráter mais abrangente que, embora não exclusiva da profissão, a ela diz respeito, por referir-se aos diversos segmentos e áreas de atuação profissional. Impõe-se ao assistente social a apropriação desse arsenal legal e institucional, agregando-o aos","a":"valores éticos e os objetivos políticos que imprimem à ação profissional uma determinada tendência plural.","b":"prerrogativa técnica.","c":"direção social.","d":"flexibilidade prática.","e":"marca subjetiva.","gabarito":"C","materia":"Serviço Social","tema":"Serviço Social no campo sócio jurídico","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637913","enunciado":"","a":"Especializado - Especialidade: Serviço Social dimensão técnico-operativa é a forma de aparecer da profissão, pela qual é conhecida e reconhecida. Sua concepção ultrapassa o uso dos instrumentos e técnicas, não se restringindo a intervenções pré-estabelecidas. Trata-se de um conjunto de ações, orientadas pelas dimensões teórico-metodológica e ético-política, que inclui o uso de instrumental, as habilidades, as estratégias e as táticas, definidas pelo assistente social. Inclui também o conhecimento necessário para operar os diferentes recursos técnicos, que podem ser de caráter individual, coletivo ou administrativo, denominados/as","b":"A talentos. processos.","c":"protocolos.","d":"burocracias.","e":"procedimentos.","gabarito":"E","materia":"Serviço Social","tema":"Instrumentos Técnicos-Operativos do Serviço Social ,Instrumentos e Técnicas de Intervenção","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637912","enunciado":"","a":"Especializado - Especialidade: Serviço Social dimensão teórico-metodológica da profissão diz respeito ao modo de ler, de interpretar, de se relacionar com o ser social, encontrando-se estreitamente ligada à maneira de explicar a sociedade e os fenômenos particulares que a constituem. Orientada por uma perspectiva teórico-metodológica ancorada na teoria social crítica, a apreensão da realidade e a produção de conhecimentos no interior do Serviço Social estão vinculadas a fundamentos de um projeto de","b":"A consolidação de valores universais. manutenção da ordem social.","c":"reificação do ser humano.","d":"restauração da solidariedade.","e":"transformação da sociedade.","gabarito":"E","materia":"Serviço Social","tema":"Pesquisa em Serviço Social","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637911","enunciado":"","a":"Especializado - Especialidade: Serviço Social ética profissional busca na filosofia o suporte para fundamentar a sua reflexão e teorização, oferecendo elementos para uma intervenção consciente. Na prática, a ética se objetiva como ação moral, por meio da normatização de deveres e valores explicitados em um código profissional. O que dá materialidade e organicidade à consciência ética dos profissionais é o pertencimento a um projeto profissional que possa responder às suas projeções profissionais e","b":"A organizativas. societárias.","c":"institucionais.","d":"interdisciplinares.","e":"pessoais. Serviço Social>","gabarito":"B","materia":"Serviço Social","tema":"Profissão do Assistente Social e o Código de Ética do Serviço Social","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_753","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","a":"Especializado - Especialidade: Serviço Social escravidão, o racismo e o capitalismo se entrelaçam na constituição da sociedade brasileira, em processos marcados por continuidades e rupturas. O racismo, como o pensamento dominante, constituiu-se como elemento integrador da organização econômica e política da sociedade, base da relação conflituosa entre capital e trabalho, e assim, da chamada questão social. O cruzamento rápido e acentuado de relações capitalistas sob uma base escravista reafirma a relação intrínseca entre a questão social e as relações étnico-raciais na formação da classe trabalhadora e de seus processos de","b":"A resistência. linearidade.","c":"indiferença.","d":"exclusividade.","e":"acomodação.","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637909","enunciado":"","a":"Especializado - Especialidade: Serviço Social razão para ultrapassar o plano da imediaticidade e compreender o processo de apreensão da totalidade e de seus complexos dinâmicos tem que construir intelectivamente mediações, expressas pela dialética singular-universal-particular. Portanto, a mediação é uma categoria reflexiva, mas também é uma categoria objetiva; por estar presente em qualquer realidade, independentemente do sujeito, a mediação possui também uma dimensão","b":"A subjetiva. arbitrária.","c":"ontológica.","d":"prática.","e":"inerente.","gabarito":"C","materia":"Serviço Social","tema":"Planejamento, Monitoramento e Avaliação de Planos, Programas e Projetos","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_755","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio Especializado - Especialidade: Serviço Social Como uma das referências do Serviço Social, a metodologia dialógica fundamenta-se nos conceitos de pessoa e transformação social. Direcionada aos sujeitos em suas vivências, centra a ação profissional no atendimento individual, que se desenvolve por meio de um processo de ajuda psicossocial. Apropriando-se também da visão de comunidade, essa tendência é analisada por teóricos do Serviço Social como uma forma de reatualização do conservadorismo presente no","a":"pensamento inicial da profissão, de inspiração construtivista.","b":"ideológica.","c":"socialista.","d":"fenomenológica.","e":"humanista.","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637907","enunciado":"Especializado - Especialidade: Serviço Social Na trajetória histórica do Serviço Social se definem diversas tendências voltadas à sua fundamentação teórico- metodológica. Uma dessas tendências é caracterizada pela busca de eficiência e eficácia na produção de conhecimento e na intervenção profissional em processos e relacionamentos interpessoais e no enfrentamento da marginalidade e da pobreza, na perspectiva de integração social. Caracterizada pela incorporação de abordagens funcionalistas, estruturalistas e sistêmicas, trata-se de um desdobramento teórico-metodológico que, no âmbito do Movimento de Reconceituação, é","a":"denominado/a vertente modernizadora.","b":"corrente crítica.","c":"teoria emancipadora.","d":"matriz pós-contemporânea.","e":"paradigma exemplar.","gabarito":"","materia":"Serviço Social","tema":"Surgimento e Institucionalização do Serviço Social","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637906","enunciado":"Especializado - Especialidade: Serviço Social O método materialista histórico-dialético não é uma operação subjetiva que, por meio da aplicação de um conjunto de procedimentos fixos abstratamente construídos, resulta na confirmação de uma dada teoria. Ao contrário, o método nessa perspectiva parte da realidade social e, por meio de aproximações sucessivas, capta suas múltiplas determinações, reproduzindo no pensamento aquilo que foi apreendido do real. Para o materialismo histórico-dialético, o pensamento e o conhecimento não são causas das determinações materiais, mas a reprodução conceitual da realidade em sua aparência,","a":"essência e contradições, ou seja, é o consenso objetivado.","b":"o concreto pensado.","c":"o limite conceitual.","d":"a pluralidade factual.","e":"a antítese teórica.","gabarito":"","materia":"Serviço Social","tema":"Surgimento e Institucionalização do Serviço Social","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637891","enunciado":"Especializado - Especialidade: Serviço Social Leia o texto para responder às questões de números 08 a 10. Minha empregada, Mme. Thérèse, que já ia se conformando em ser chamada de dona Teresa, caiu doente. Mandou- me um bilhete com a letra meio trêmula, falando em reumatismo. Dias depois apareceu, mas magra, mais pálida e menor; explicou-me que tudo fora consequência de uma corrente de ar. Que meu apartamento tem um courant d’air terrível, de tal modo que, ____________, chegando em casa, nem teve coragem de tirar a roupa, caiu na cama. “Dói-me o corpo inteiro, senhor; o corpo inteiro.” O mesmo caso, ajuntou, houve cerca de 15 anos atrás, quando trabalhava em um apartamento que tinha uma corrente de ar exatamente igual __________ essa de que hoje sou sublocatário. Fez uma pausa. Fungou. Contou o dinheiro que eu lhe entregava, agradeceu __________ dispensa do troco. Foi lá dentro apanhar umas pobres coisas que deixara. Entregou-me a chave, fez qualquer observação sobre o aquecedor _________ gás – e depois, no lugar de sair ________ rua, deixou-se ficar imóvel e calada, de pé, em minha frente. (Rubem Braga, “Dona Teresa”. 200 crônicas escolhidas. Adaptado) Nos enunciados reescritos a partir das informações do texto, a colocação pronominal e a regência atendem à norma-","a":"padrão em: Não fosse a corrente de ar que lhe acometera, Mme. Thérèse já teria-se conformado em ser chamada de dona Teresa.","b":"Dona Teresa certamente vira-se abalada com a corrente de ar, pois veio no meu apartamento magra, mais pálida e menor.","c":"Dona Teresa me contou que, há cerca de 15 anos atrás, tinha exposto-se em uma corrente de ar em um outro apartamento.","d":"Quando voltou, Mme. Thérèse informou-me de que sua debilidade era proveniente de uma corrente de ar no meu apartamento.","e":"Eu entreguei o dinheiro a dona Teresa, ela contou-o. Depois foi lá dentro apanhar umas pobres coisas que se esquecera.","gabarito":"","materia":"Português","tema":"Sintaxe ,Regência ,Morfologia - PronomesColocação Pronominal","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637766","enunciado":"Especializado - Especialidade: Informática","a":"o Portaria n 162 do Conselho Nacional de Justiça contém o anexo IV, intitulado Manual de Referência – Proteção de Infraestruturas Críticas de TIC. Nesse anexo é estabelecida uma classificação para a organização, de acordo com seu porte, havendo três níveis, sendo que no Grupo","b":"A 1 estão as organizações com média experiência em segurança cibernética. 1 estão as organizações com nível elevado de recursos disponíveis.","c":"1 estão as organizações com nível limitado de recursos disponíveis.","d":"2 estão as organizações com alta experiência em segurança cibernética.","e":"3 estão as organizações com pouca experiência em segurança cibernética.","gabarito":"","materia":"Segurança da Informação","tema":"Análise de Vulnerabilidade e Gestão de Riscos","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637765","enunciado":"Especializado - Especialidade: Informática","a":"o Resolução n 91 do Conselho Nacional de Justiça institui o Modelo de Requisitos para Sistemas Informatizados de Gestão de Processos e Documentos do Judiciário Brasileiro. Nesse modelo, em seu capítulo correspondente à fase captura de documentos, há o tratamento que deve ser atribuído a documentos automodificáveis, sendo certo que, de forma explícita, essa resolução estabelece que","b":"A tais documentos devem ter a parte automodificável excluída. tais documentos devem ser criptografados e armazenados na nuvem do GestãoDoc.","c":"há a recomendação para que sejam evitados tais tipos de documentos no Sistema GestãoDoc.","d":"tais documentos não necessitam de atenção diferenciada, devendo ser tratados como documentos que não exibam","e":"tal característica. esse tipo de documento pode ser armazenado por um período máximo de 180 dias.","gabarito":"","materia":"Legislação dos TRFs","tema":"Conselho Nacional de Justiça (CNJ) ,Resoluções do CNJ","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637764","enunciado":"","a":"Especializado - Especialidade: Informática precisão é uma das métricas utilizadas para avaliação de modelos de aprendizado supervisionado voltados para a classificação. Utilizando a nomenclatura TP (Verdadeiro Positivo), FP (Falso Positivo), TN (Verdadeiro Negativo) e FN (Falso Negativo), pode-se afirmar corretamente que a equação da precisão é:","b":"A TP/(TP + FP) TN/FN","c":"FP/(FP + TN)","d":"(TP + TN)/(TP + FP + TN + FN)","e":"TP/(TP + FN)","gabarito":"","materia":"Arquitetura de Software","tema":"Banco de Dados","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637763","enunciado":"Especializado - Especialidade: Informática Dentre o portfólio de produtos da empresa WMware são encontrados produtos voltados para ambientes multi-cloud,","a":"virtualização e gerenciamento remoto. Um exemplo de hipervisor da empresa é o VMware ESXi","b":"AWS","c":"Aria","d":"Azure","e":"vMotion","gabarito":"","materia":"Arquitetura de Software","tema":"Conceitos Básicos em Governança de TI","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637762","enunciado":"Especializado - Especialidade: Informática Segundo a Lei Geral de Proteção de Dados Pessoais (LGPD), o controlador deverá comunicar à autoridade nacional e ao titular dos dados a ocorrência de incidente de segurança que possa acarretar risco ou dano relevante aos titulares, e a comunicação","a":"deverá indicar as medidas técnicas e de segurança utilizadas para a proteção dos dados, não devendo mais observar eventuais segredos comercial e industrial envolvidos.","b":"não deve mencionar publicamente as medidas que foram ou que serão adotadas para reverter ou mitigar os efeitos","c":"do prejuízo, a fim de evitar que elas sejam eventualmente anuladas pelos causadores do incidente. deverá publicar em um veículo de grande circulação todos os dados dos titulares que foram vazados no incidente.","d":"deverá mencionar, no mínimo, algumas informações, como a descrição da natureza dos dados pessoais afetados e os","e":"riscos relacionados ao incidente. será feita em até 120 dias após a ocorrência incidente, sob pena de aplicação de multa, caso contrário.","gabarito":"","materia":"Direito Digital","tema":"Lei nº 13.709 de 2018 - Lei Geral de Proteção de Dados Pessoais (LGPD)","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637761","enunciado":"Especializado - Especialidade: Informática Uma função de hash criptográfica h retorna um valor de tamanho t, em bits, quando aplicada a uma mensagem m. O","a":"tamanho esperado do hash de mm, em que mm representa a mensagem m concatenada com ela mesma, é: t / 2","b":"t","c":"não é possível determinar sem conhecer a mensagem real.","d":"2t","e":"2 t","gabarito":"","materia":"Arquitetura de Software","tema":"Segurança da Informação","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637760","enunciado":"Especializado - Especialidade: Informática","a":"Na terminologia relacionada a malwares, o termo Drive-by-Download corresponde à exibição de propagandas indesejadas ao usuário, em geral na forma de pop-ups ou banners.","b":"a um tipo de vírus que usa código de macro ou linguagem de script, usualmente embutido em um documento, e ativado quando esse documento é visualizado ou editado.","c":"a um programa de computador que pode ser executado independentemente e propagar cópias de si mesmo para outras estações na rede, explorando vulnerabilidades.","d":"a um ataque que usa código colocado em um website comprometido que explora vulnerabilidades de navegadores","e":"quando o mesmo é visitado. ao envio indevido do histórico de downloads do navegador web para um atacante, sem o conhecimento do usuário.","gabarito":"","materia":"Arquitetura de Software","tema":"Segurança da Informação","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637759","enunciado":"","a":"Especializado - Especialidade: Informática norma ABNT NBR ISO/IEC 27002:2022 (Segurança da informação cibernética e proteção à privacidade – Controles de segurança da informação) estabelece, em seu capítulo 5, uma seção sobre inteligência de ameaças, na qual preconiza que tal tipo de inteligência seja dividido ou classificado em três camadas para tratamento de ameaças. Essas três camadas são as inteligências de ameaças","b":"A interna, mista e externa. irrelevante, média e grave.","c":"de sistema, de invasão e de pessoas.","d":"preliminar, de objetivo e de finalização.","e":"estratégica, tática e operacional.","gabarito":"","materia":"Segurança da Informação","tema":"ISO 27002","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637758","enunciado":"Especializado - Especialidade: Informática Armazenamento de dados na nuvem provê uma solução flexível e de alta disponibilidade para os seus usuários","a":"armazenarem arquivos. Um exemplo de solução deste tipo é o KVM","b":"Docker","c":"Dropbox","d":"Hyper-V","e":"Virtualbox","gabarito":"","materia":"Arquitetura de Software","tema":"Internet ,Nuvem (\"cloud computing\" e \"cloud storage\")","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637756","enunciado":"Especializado - Especialidade: Informática Uma empresa possui N discos rígidos que serão utilizados para armazenar seu volume de dados com o nível RAID 0. É correto afirmar que a quantidade de discos que irá armazenar o volume original dos dados (sem considerar paridade e","a":"redundância) é N-2","b":"N","c":"N-1","d":"N/2","e":"N/4","gabarito":"","materia":"Arquitetura de Software","tema":"Banco de Dados","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637755","enunciado":"Especializado - Especialidade: Informática Uma estimativa da latência entre uma origem e um destino na Internet, sabendo-se que o Round-Trip Time medido entre","a":"esses pontos é de 28 ms, corresponde a 14 ms.","b":"28 ms.","c":"56 ms.","d":"112 ms.","e":"224 ms.","gabarito":"","materia":"Redes de Computadores","tema":"Protocolo","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637754","enunciado":"","a":"Especializado - Especialidade: Informática respeito do protocolo SNMP, assinale a alternativa correta.","b":"A Mensagens do tipo Trap correspondem a notificações assíncronas enviadas de gerente para agente. Uma desvantagem do protocolo é não possuir segurança baseada em criptografia, em nenhuma de suas versões.","c":"Contadores de 64 bits foram introduzidos no SNMPv2, não sendo suportados no SNMPv1.","d":"Mensagens do tipo GetBulk Request são suportadas desde o SNMPv1.","e":"O SNMP precisa de um protocolo de transporte orientado a conexão e, por isso, não é utilizado sobre UDP.","gabarito":"","materia":"Redes de Computadores","tema":"Protocolo ,SNMP (Simple NetWork Management Protocol)","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637753","enunciado":"Especializado - Especialidade: Informática Um pacote de dados referente a uma resposta a uma consulta DNS foi capturado por um aplicativo de monitoramento de rede (sniffer). Para esse pacote, o sniffer exibiu o seguinte trecho de conteúdo, onde dois valores foram ocultados e substituídos propositalmente pelas letras x e y, indicadas de forma sublinhada. Queries www.isc.org: type ANY, class IN Answers www.isc.org: type x, class IN, addr 2001:4f8:0:2::d www.isc.org: type y, class IN, addr 204.152.184.88 Os conteúdos omitidos são:","a":"x = A y = AAAA.","b":"x = PTR y = A","c":"x = CNAME y = AAAA","d":"x = AAAA y = A.","e":"x = CNAME y = A","gabarito":"","materia":"Arquitetura de Software","tema":"Segurança da Informação","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637752","enunciado":"Especializado - Especialidade: Informática","a":"Assinale a alternativa correta relacionada com os padrões de redes sem fio IEEE 802.11b/g/n. O padrão IEEE 802.11g não aceita a autenticação WEP estática.","b":"O padrão IEEE 802.11n utiliza o método de transmissão MIMO-OFDM.","c":"Uma semelhança entre os padrões IEEE 802.11b e IEEE 802.11g é que ambos operam na velocidade 65 Mbps.","d":"O padrão IEEE 802.11b opera na faixa de frequência 5,8 GHz.","e":"Os padrões IEEE 802.11b, IEEE 802.11g e IEEE 802.11n apresentam algumas semelhanças, como operarem nas faixas de frequência 2,4 GHz e/ou 5 GHz.","gabarito":"","materia":"Arquitetura de Software","tema":"Redes de Computadores","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637751","enunciado":"Especializado - Especialidade: Informática De acordo com a norma ABNT NBR 14565:2019, a categoria 05 é relacionada a componentes usados para a transmissão de","a":"sinais até 1000 MHz.","b":"50 MHz.","c":"20 MHz.","d":"16 MHz.","e":"100 MHz.","gabarito":"","materia":"Arquitetura de Software","tema":"Redes de Computadores","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637750","enunciado":"Especializado - Especialidade: Informática No cabeçalho do protocolo TCP, quando o flag SYN está ativado (valor 1), o campo denominado Sequence Number representa","a":"o próximo número de sequência que o transmissor do segmento aguarda da outra parte, confirmando o recebimento","b":"dos bytes com números de sequência anteriores. um offset dentro da área de dados apontando para o último byte de dados urgente.","c":"um valor de checksum de 16 bits usado para checagem de erros, calculado com base no cabeçalho do segmento TCP, no payload e em um pseudocabeçalho IP.","d":"o número de sequência acumulado do primeiro byte de dados carregado pelo segmento, considerando o contexto dos","e":"segmentos transmitidos anteriormente na conexão. o número de sequência inicial da conexão adotado pelo transmissor do segmento.","gabarito":"","materia":"Arquitetura de Software","tema":"Redes de Computadores","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637749","enunciado":"Especializado - Especialidade: Informática Diversos elementos são utilizados na interconexão de redes de computadores, cada um atuando em uma das camadas do modelo de referência de TCP/IP. Assinale a alternativa que relaciona corretamente elementos de interligação com a camada","a":"na qual ele atua. Roteadores – Camada de Rede.","b":"Hubs e Switches – Camada de Transporte.","c":"Bridges e Gateways – Camada de Enlace de Dados.","d":"Switches e Repetidores – Camada de Enlace de Dados.","e":"Repetidores e Bridges – Camada Física.","gabarito":"A","materia":"Arquitetura de Software","tema":"Redes de Computadores","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637748","enunciado":"Especializado - Especialidade: Informática Assinale a afirmativa correta relacionada ao protocolo UDP (User Datagram Protocol).","a":"O cabeçalho do UDP possui os campos: Porta de Origem, Porta de Destino, Comprimento do UDP e Checksum do","b":"UDP. O UDP realiza retransmissão após a recepção de um segmento incorreto.","c":"O UDP realiza controle de fluxo de controle de congestionamento.","d":"O UDP transmite segmentos que consistem em um cabeçalho de 16 bytes, seguido pela carga útil.","e":"Trata-se de um protocolo de transporte orientado a conexões.","gabarito":"A","materia":"Arquitetura de Software","tema":"Redes de Computadores","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637746","enunciado":"Especializado - Especialidade: Informática O sistema operacional Windows 10 possui diversas ferramentas administrativas, como a denominada","a":"Monitor de Desempenho, que permite comparar o desempenho do computador com outros similares conectados na","b":"mesma rede. Monitor de Programas, que permite avaliar os recursos exigidos à execução de cada programa.","c":"Monitor de Recursos, que permite visualizar, por exemplo, processos com atividade de rede e conexões TCP.","d":"Corretor de Problemas, que permite especificar que defeitos o sistema operacional deve tentar corrigir automaticamente quando eles ocorrerem.","e":"Agendador de Tarefas, cuja função é colocar automaticamente na agenda do usuário os horários nos quais o computador realizará tarefas administrativas.","gabarito":"C","materia":"Arquitetura de Software","tema":"Conceitos Básicos em Governança de TI","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637745","enunciado":"Especializado - Especialidade: Informática No terminal de um sistema operacional Linux foi digitado o seguinte comando echo “data” >> file.txt","a":"Considerando que o arquivo file.txt originalmente possuía algum conteúdo armazenado, é correto afirmar que o novo conteúdo do arquivo será “data”.","b":"o novo conteúdo do arquivo será o conteúdo anterior, acrescido de “data” no final.","c":"o arquivo será renomeado para “data.txt”.","d":"o comando irá imprimir “data” no terminal, seguido do conteúdo do arquivo.","e":"será impresso “data” no terminal, caso o arquivo possua essa string em seu conteúdo.","gabarito":"B","materia":"Arquitetura de Software","tema":"Conceitos Básicos em Governança de TI","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637744","enunciado":"Especializado - Especialidade: Informática O seguinte comando do Docker foi emitido em um terminal de um computador com sistema operacional Linux. docker inspect myobject O resultado obtido foi [ { \"CreatedAt\": \"2023-06-06T03:08:08Z\", \"Driver\": \"local\", \"Labels\": {}, \"Mountpoint\": \"(...)/myobject/_data\", \"Name\": \"myobject\", \"Options\": {}, \"Scope\": \"local\" } ] em que parte do valor de Mountpoint foi propositalmente ocultado pelo trecho (...).","a":"Pode-se concluir que a construção myobject se refere a uma imagem.","b":"um container.","c":"um nó.","d":"um volume.","e":"uma rede.","gabarito":"D","materia":"Arquitetura de Software","tema":"Conceitos Básicos em Governança de TI","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637743","enunciado":"Especializado - Especialidade: Informática O comando git log tem como objetivo apresentar um histórico dos commits realizados. Um usuário digitou o comando git log --oneline","a":"Pode-se afirmar corretamente que a opção --oneline fará esse comando apresentar um identificador de cada commit realizado, a qual branch ele pertence e seu autor.","b":"um identificador de cada commit realizado, sua hora, seu autor e sua descrição.","c":"somente um identificador de cada commit realizado e sua descrição.","d":"somente um identificador de cada commit realizado, juntamente com sua hora.","e":"um identificador de cada commit realizado, sua hora e seu autor.","gabarito":"C","materia":"Arquitetura de Software","tema":"Software","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637742","enunciado":"Especializado - Especialidade: Informática Em APIs RESTful, o verbo HTTP OPTIONS tem o propósito de","a":"obter uma resposta contendo um cabeçalho idêntico àquele que seria retornado pelo verbo GET, mas sem o corpo da","b":"resposta. alterar valores de opções de configuração vigentes no servidor web que hospeda o serviço.","c":"efetuar modificações parciais em um recurso.","d":"obter um grupo de recursos do mesmo tipo, sem informar um identificador específico.","e":"obter informações sobre opções de comunicação disponíveis para um recurso.","gabarito":"E","materia":"Arquitetura de Software","tema":"Software","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637741","enunciado":"Especializado - Especialidade: Informática O tipo de teste de software que visa verificar as menores partes testáveis de um sistema, individualmente, é conhecido","a":"como teste de unidade.","b":"aceitação.","c":"usabilidade.","d":"sistema.","e":"integração.","gabarito":"A","materia":"Engenharia de Software","tema":"Teste de Software","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637740","enunciado":"Especializado - Especialidade: Informática Sistemas de controle de versionamento Git possuem suporte a ramificações (branches). Um usuário pode deletar uma","a":"dessas ramificações locais por meio do comando git branch -i","b":"git branch -d","c":"git reset –q","d":"git rm -f","e":"git rm -r","gabarito":"B","materia":"Arquitetura de Software","tema":"Software","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637739","enunciado":"Especializado - Especialidade: Informática O design pattern criacional caracterizado por manter um conjunto de objetos que podem ser reutilizados, em geral quando","a":"sua criação é custosa, é conhecido como Reusable objects.","b":"Abstract factory.","c":"Template method.","d":"Object pool.","e":"Factory method.","gabarito":"D","materia":"Arquitetura de Software","tema":"Padrões de projeto (Design Patterns)","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637738","enunciado":"Especializado - Especialidade: Informática O seguinte trecho de um XML Schema define um tipo chamado mytype, em que xs representa o namespace http://www.w3.org/2001/XMLSchema. <xs:simpleType name=\"mytype\"> <xs:restriction base=\"xs:string\"> <xs:pattern value=\"[0-9]{7}\" /> </xs:restriction> </xs:simpleType>","a":"Assinale a alternativa que descreve o valor aceito por esse tipo. Uma string com até 7 caracteres, sendo que cada caractere pode ser um dígito de 0 a 9.","b":"Uma string com exatamente 7 caracteres, sendo que cada caractere pode ser um dígito de 0 a 9.","c":"Uma string com um número arbitrário de caracteres, sendo que cada caractere pode ser um dígito de 0 a 9, seguida por um caractere 7 no final.","d":"Uma string com um número arbitrário de caracteres, sendo que cada caractere pode ser o dígito 0 ou o dígito 9, seguida por um caractere 7 no final.","e":"Uma string iniciada por um caractere que pode ser um dígito de 0 a 9, seguida por um número arbitrário de caracteres 7 no final.","gabarito":"B","materia":"Programação","tema":"XML (Extensible Markup Language) ,Linguagens de marcação","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637737","enunciado":"Especializado - Especialidade: Informática O seguinte código JavaScript console.log(\"1\"); setTimeout(() => { console.log(\"2\"); }, 1); process.nextTick(() => { console.log(\"3\"); }); quando executado no Node.js produz a saída:","a":"2 1 3","b":"3 1 2","c":"3 2 1","d":"1 2 3","e":"1 3 2","gabarito":"E","materia":"Arquitetura de Software","tema":"Software","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637736","enunciado":"","a":"Especializado - Especialidade: Informática linguagem PHP possui um conjunto de variáveis denominadas superglobais. Estas são variáveis que estão disponíveis em todos os escopos, sendo um exemplo de uma delas a","b":"A $_PUT $_HEAD","c":"$_POST","d":"$_CONNECT","e":"$_TRACE","gabarito":"C","materia":"Arquitetura de Software","tema":"Software","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637735","enunciado":"Especializado - Especialidade: Informática Observe o seguinte trecho de código escrito na linguagem Python. def f(n): return lambda a : 1 + n f1 = f(2) f2 = f(3) print(f1(3) + f2(1))","a":"Analisando esse trecho de código é correto afirmar que ele irá imprimir o valor 7","b":"5","c":"12","d":"4","e":"14","gabarito":"A","materia":"Arquitetura de Software","tema":"Software","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637734","enunciado":"","a":"Especializado - Especialidade: Informática seguir é apresentado um pequeno código em CSS. p { color: #0000FF; } Pode-se afirmar corretamente que este código fará com que os parágrafos escritos na página HTML estejam na cor","b":"A verde. preta.","c":"vermelha.","d":"azul.","e":"branca.","gabarito":"D","materia":"Arquitetura de Software","tema":"Software","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637733","enunciado":"Especializado - Especialidade: Informática Na linguagem HTML5, o elemento input aceita diversos valores para o atributo type, dentre eles os destinados a datas e","a":"horas, como: datetime-local e datetime-Greenwich.","b":"datetime e date.","c":"fortnight e week.","d":"seconds e miliseconds.","e":"year e month.","gabarito":"B","materia":"Programação","tema":"HTML (HyperText Markup Language) ,Linguagens de marcação","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637732","enunciado":"Especializado - Especialidade: Informática Considere a seguinte tabela de um banco de dados relacional: Loja (Código, Tipo, Cidade) O comando SQL para excluir registros da tabela Loja com a condição de ter a string “Sul” no nome da cidade é:","a":"DELETE Cidade = ‘%Sul% FROM Loja;","b":"DELETE Loja HAVING Cidade LIKE ‘_Sul_’","c":"DELETE FROM Loja WHERE Cidade LIKE ‘%Sul%’","d":"DELETE Loja WHERE Cidade IN ‘Sul’","e":"DELETE FROM Cidade IN ‘Sul’ FROM Loja;","gabarito":"C","materia":"Arquitetura de Software","tema":"Banco de Dados","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637731","enunciado":"Especializado - Especialidade: Informática Considere as duas seguintes tabelas de um banco de dados relacional: Curso (ID, Especialidade, Tipo) Aluno (Número, Nome, Cidade, ID) ID é chave estrangeira na tabela Aluno, com origem na chave primária ID de Curso. O comando SQL para obter o nome dos alunos, a especialidade e o tipo de curso em que estão matriculados é:","a":"SELECT Nome, Especialidade, Tipo FROM Curso, Aluno;","b":"SELECT Nome, Especialidade, Tipo FROM Curso.ID = Aluno.ID;","c":"SELECT Nome, Especialidade, Tipo FROM Curso, Aluno WHERE ID = ID;","d":"SELECT Nome, Especialidade, Tipo FROM Curso, Aluno (Curso.ID = Aluno.ID);","e":"SELECT Nome, Especialidade, Tipo FROM Curso, Aluno WHERE Curso.ID = Aluno.ID;","gabarito":"E","materia":"Arquitetura de Software","tema":"Banco de Dados","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637730","enunciado":"Especializado - Especialidade: Informática","a":"Na programação orientada a objetos, utiliza-se o princípio de construtores, sobre os quais é correto afirmar que representam métodos sem nome de uma classe.","b":"representam um método de uma classe que possui o mesmo nome da classe da qual faz parte.","c":"não são utilizados em programas com número muito grande de classes.","d":"são utilizados exclusivamentes para substituir objetos já criados anteriormente.","e":"têm a finalidade de excluir classes que não possuam objetos criados.","gabarito":"B","materia":"Arquitetura de Software","tema":"Software","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637729","enunciado":"Especializado - Especialidade: Informática Um trecho de programa, expresso na forma de uma pseudolinguagem (Português Estruturado), é apresentado a seguir. Início Inteiro: i, j, k, a; ... Para i de 3 até 6 faça Para j de 4 até 7 faça Para k de 2 até 8 faça [ a ← a + 1; ] ... Fim.","a":"É correto afirmar que, a variável a, após a execução de desse trecho de programa, terá sido incrementada 8 vezes.","b":"54 vezes.","c":"336 vezes.","d":"112 vezes.","e":"6 vezes.","gabarito":"D","materia":"Arquitetura de Software","tema":"Software","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637728","enunciado":"Especializado - Especialidade: Informática Um algoritmo, apresentado a seguir, foi elaborado na forma de uma pseudolinguagem (Português Estruturado). Início Inteiro: k, m, n, i; k ← 1; m ← k + 1; n ← k + m - 1; Para i de 3 até 6 faça [ k ← k + 1; Se (m > n) Então [ k ← k + 1; m ← n; n ← k; ] Senão [ k ← k + 2; n ← m; m ← k; ] ] k ← m + n; Fim.","a":"Assinale a alternativa que apresenta o valor recebido pela variável k ao final da execução desse algoritmo. 16","b":"17","c":"14","d":"15","e":"13","gabarito":"E","materia":"Arquitetura de Software","tema":"Software","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637727","enunciado":"Especializado - Especialidade: Informática O COBIT 2019 estabelece 5 domínios sob os quais classifica objetivos de governança e de gestão, sendo correto afirmar que","a":"o objetivo de gestão Problema Gerenciado faz parte do domínio Monitorar, Avaliar e Analisar.","b":"Otimização de Risco Assegurada faz parte do domínio Alinhar, Planejar e Organizar.","c":"Inovação Gerenciada faz parte do domínio Alinhar, Planejar e Organizar.","d":"Qualidade Gerenciada faz parte do domínio Construir, Adquirir e Implementar.","e":"Sistema de Controle Interno Gerenciado faz parte do domínio Entregar, Serviço e Suporte.","gabarito":"C","materia":"Governança de TI","tema":"COBIT","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637726","enunciado":"Especializado - Especialidade: Informática a","a":"O PMBOK 6 edição define as denominadas partes interessadas no projeto, sendo correto afirmar que partes interessadas externas incluem fornecedores.","b":"partes interessadas internas incluem os clientes.","c":"são definidos três tipos de partes interessadas: internas, independentes e externas.","d":"patrocinadores não são componentes nem de partes internas, nem partes externas.","e":"agências reguladoras não compõem as partes interessadas externas.","gabarito":"A","materia":"Arquitetura de Software","tema":"Conceitos Básicos em Governança de TI ,Software","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2637725","enunciado":"","a":"Especializado - Especialidade: Informática norma ABNT NBR-ISO/IEC/IEEE 12207:2021 (Engenharia de Sistemas e Software – Processos de Ciclo de Vida de Software) agrupa as atividades que podem ser executadas durante o ciclo de vida de um sistema de software nos seguintes grupos de processos:","b":"A (i) de Iniciação; (ii) Provisório; (iii) de Projeto; e (iv) Definitivo. (i) de Acordo; (ii) Organizacionais Habilitadores de Projeto; (iii) de Gerenciamento Técnico; e (iv)Técnicos.","c":"(i) de Aquisição; (ii) de Gerenciamento de Decisão; (iii) de Proteção; e (iv) de Testes.","d":"(i) de Gerenciamento de Portfólio; (ii) de Análise; (iii) de Certificação; e (iv) Homologatório.","e":"(i) Preliminar; (ii) Completo; (iii) de Integração; e (iv) de Encerramento.","gabarito":"B","materia":"Arquitetura de Software","tema":"Software","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário / Área: Apoio","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2465227","enunciado":"Especialidade: Agente da Polícia Judicial o Nos termos da Resolução n 344, de 9 de setembro de 2020, do Conselho Nacional de Justiça, que regulamenta o exercício do poder de polícia administrativa no âmbito dos tribunais, dispondo sobre as atribuições funcionais dos agentes e","a":"inspetores da polícia judicial, é correto afirmar que: a polícia administrativa dos tribunais será exercida com exclusividade pela polícia judicial.","b":"os corregedores dos tribunais respondem pelo poder de polícia administrativa do tribunal.","c":"é incumbência da Polícia Civil o exercício da polícia administrativa dos tribunais, que será coordenado pelos","d":"Presidentes dos Tribunais. os presidentes dos tribunais respondem pelo poder de polícia administrativa do tribunal.","e":"é incumbência da Polícia Militar o exercício da polícia administrativa dos tribunais, que será coordenado pelos Presidentes dos Tribunais.","gabarito":"D","materia":"Legislação dos TRFs","tema":"Conselho Nacional de Justiça (CNJ) ,Resoluções do CNJ","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2465226","enunciado":"Especialidade: Agente da Polícia Judicial o Nos termos da Resolução n 383, de 25 de março de 2021, do Conselho Nacional de Justiça, que cria o Sistema de Inteligência de Segurança Institucional do Poder Judiciário (SInSIPJ) e dá outras providências, é correto afirmar que, entre","a":"outros, integra o SInSIPJ: a Procuradoria Geral de Justiça.","b":"a Defensoria Geral da União.","c":"o Conselho da Justiça Federal, como órgão coordenador.","d":"o Tribunal Superior Eleitoral.","e":"o Supremo Tribunal Federal, como órgão central. Direito Penal>Legislação Penal Especial ,","gabarito":"D","materia":"Legislação dos TRFs","tema":"Conselho Nacional de Justiça (CNJ) ,Resoluções do CNJ","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_801","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa - Especialidade: Agente da Polícia Judicial o Nos termos da Resolução n 467, de 28 de junho de 2022, do Conselho Nacional de Justiça, que regulamenta, no âmbito do o o o Poder Judiciário, o disposto nos artigos. 6 , inciso XI, e 7 -A, ambos da Lei n 10.826/2003, com as alterações promovidas o pela Lei n 12.694/2012 e alterações posteriores, é correto afirmar:","a":"as armas eventualmente cedidas, emprestadas ou destinadas deverão ser registradas no SINARM em nome do tribunal.","b":"as armas eventualmente cedidas, emprestadas ou destinadas deverão ser registradas no Comando do Exército, em nome do tribunal.","c":"as armas de fogo institucionais e particulares poderão ser brasonadas e gravadas com inscrição que identifique o tribunal a que pertencem, de acordo com as normas vigentes.","d":"as armas de fogo institucionais e particulares deverão ser brasonadas e gravadas com inscrição que identifique o tribunal ou servidor a que pertencem, de acordo com as normas vigentes.","e":"as armas eventualmente cedidas, emprestadas ou destinadas poderão a critério do tribunal, ser registradas no SINARM. Direito Penal>Legislação Penal Especial ,","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_802","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa - Especialidade: Agente da Polícia Judicial o Nos termos da Lei n 10.826/2003, é correto afirmar que o crime de importar, exportar, favorecer a entrada ou saída do","a":"território nacional, a qualquer título, de arma de fogo, acessório ou munição, sem autorização da autoridade competente é apenado com detenção.","b":"possui causa de aumento de pena.","c":"está previsto no Código Penal.","d":"possui forma qualificada.","e":"possui modalidade culposa.","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2465223","enunciado":"Especialidade: Agente da Polícia Judicial o Assinale a alternativa que, nos termos do Código de Trânsito Brasileiro (Lei n 9.503/1997), contenha corretamente duas","a":"penalidades. Remoção do veículo e multa.","b":"Suspensão do direito de dirigir e repreensão por escrito.","c":"Frequência obrigatória em curso de reciclagem e advertência por escrito.","d":"Repreensão por escrito e multa.","e":"Advertência por escrito e remoção do veículo. Legislação Federal>","gabarito":"C","materia":"Legislação de Trânsito","tema":"Penalidades","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_804","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa - Especialidade: Agente da Polícia Judicial","a":"o Lei n 5.553/1968 determina que a nenhuma pessoa física, bem como a nenhuma pessoa jurídica, de direito público ou de direito privado, é lícito reter qualquer documento de identificação pessoal, ainda que apresentado por fotocópia autenticada ou pública-forma, inclusive comprovante de quitação com o serviço militar, título de eleitor, carteira profissional, certidão de registro de nascimento, certidão de casamento, comprovante de naturalização e carteira de identidade de estrangeiro. Diante dessa situação, é correto afirmar que a retenção de qualquer documento a que se refere a Lei constitui","b":"A apenas uma infração administrativa punível com advertência. contravenção penal, punível com pena de prisão simples ou multa.","c":"contravenção penal, punível com pena de detenção ou multa.","d":"crime, punível com pena de detenção ou multa.","e":"apenas uma infração administrativa punível com repreensão. Estatuto da Pessoa com Deficiência - Lei nº 13.146 de 2015>Legislação das Pessoas com Deficiência ,","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_805","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa - Especialidade: Agente da Polícia Judicial o o Nos termos da Lei n 10.048/2000 (Prioridade de atendimento), as pessoas com deficiência, as pessoas com transtorno do espectro autista, as pessoas idosas com idade igual ou superior a 60 (sessenta) anos, as gestantes, as lactantes, as pessoas com criança de colo, os obesos, as pessoas com mobilidade reduzida e os doadores de sangue terão atendimento prioritário.","a":"É correto afirmar que a infração ao disposto nesta lei não acarreta qualquer responsabilização em razão da ausência de previsão legal.","b":"poderá acarretar a responsabilização criminal pelo cometimento de um crime apenado com multa.","c":"poderá acarretar a responsabilização criminal pelo cometimento de uma contravenção penal.","d":"poderá acarretar a responsabilização criminal pelo cometimento de um crime apenado com detenção.","e":"poderá acarretar ao responsável no caso de empresas concessionárias de serviço público, a multa. Estatuto da Pessoa com Deficiência - Lei nº 13.146 de 2015>Legislação das Pessoas com Deficiência ,","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_806","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa - Especialidade: Agente da Polícia Judicial o Nos termos da Lei n 10.098/2000, é correto afirmar que","a":"Os banheiros de uso público existentes ou a construir em parques, praças, jardins e espaços livres públicos deverão ser acessíveis e dispor, pelo menos, de dois sanitários e dois lavatórios que atendam às especificações das normas técnicas da ABNT.","b":"Os banheiros de uso público existentes ou a construir em parques, praças, jardins e espaços livres públicos deverão ser acessíveis e dispor, pelo menos, de quatro sanitários e dois lavatórios que atendam às especificações das normas técnicas da ABNT.","c":"O número mínimo de banheiros químicos acessíveis corresponderá a 10% (dez por cento) do total, garantindo-se, pelo menos, 1 (uma) unidade acessível caso a aplicação do percentual resulte em fração inferior a 1 (um).","d":"O número mínimo de banheiros químicos acessíveis corresponderá a 25% (vinte e cinco por cento) do total, garantindo-se, pelo menos, 1 (uma) unidade acessível caso a aplicação do percentual resulte em fração inferior a 1 (um).","e":"O número mínimo de banheiros químicos acessíveis corresponderá a 10% (dez por cento) do total, garantindo-se pelo menos 2 (duas) unidades acessíveis caso a aplicação do percentual resulte em fração inferior a 1 (um).","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2465219","enunciado":"Especialidade: Agente da Polícia Judicial o Nos termos da Lei n 10.741/2003, é correto afirmar que o crime de deixar de prestar assistência à pessoa idosa, quando possível fazê-lo sem risco pessoal, em situação de iminente perigo, ou recusar, retardar ou dificultar sua assistência à","a":"saúde, sem justa causa, ou não pedir, nesses casos, o socorro de autoridade pública é apenado com reclusão.","b":"possui modalidade culposa.","c":"possui forma qualificada.","d":"possui causa de aumento de pena.","e":"está previsto no Código Penal.","gabarito":"D","materia":"Estatuto da Pessoa Idosa - Lei nº 10.741 de 2003","tema":"Crimes","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2465218","enunciado":"Especialidade: Agente da Polícia Judicial o Nos termos da Lei n 7.716/1989, é correto afirmar que o crime de injuriar alguém, ofendendo-lhe a dignidade ou o decoro,","a":"em razão de raça, cor, etnia ou procedência nacional possui modalidade culposa.","b":"é apenado com detenção.","c":"está previsto no Código Penal.","d":"possui forma qualificada.","e":"possui causa de aumento de pena. Direito Penal>Legislação Penal Especial ,","gabarito":"E","materia":"Direito Penal","tema":"Legislação Penal Especial ,Crimes Resultantes de Preconceito de Raça ou Cor – Lei nº 7.716 de 1989","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_809","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa - Especialidade: Agente da Polícia Judicial o","a":"Nos termos da Lei n 13.869/2019, poderá ser sujeito ativo do crime de abuso de autoridade, entre outros, a administração pública indireta.","b":"os membros do Poder Judiciário.","c":"as pessoas jurídicas.","d":"a administração pública direta.","e":"os integrantes dos órgãos de imprensa. Direito Processual Penal>","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2465216","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa - Especialidade: Agente da Polícia Judicial o","a":"Nos termos da Lei n 9.099/1995, consideram-se infrações penais de menor potencial ofensivo as contravenções penais e os crimes a que a lei comine pena máxima de detenção não superior a 4 (quatro) anos.","b":"as contravenções penais e os crimes a que a lei comine pena máxima não superior a 6 (seis) anos, cumulada ou não com multa.","c":"apenas as contravenções penais a que a lei comine pena máxima não superior a 2 (dois) anos, cumulada ou não com multa.","d":"as contravenções penais e os crimes a que a lei comine pena máxima não superior a 2 (dois) anos, cumulada ou não com multa.","e":"as contravenções penais e os crimes a que a lei comine pena máxima não superior a 4 (quatro) anos, cumulada ou não com multa.","gabarito":"D","materia":"Procedimento comum sumaríssimo - Lei nº 9.099 de 1995 - Lei dos Juizados Especiais Criminais - JECRIM","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2465215","enunciado":"Especialidade: Agente da Polícia Judicial Nos termos do Código de Processo Penal, é correto afirmar que, após receber o auto de prisão em flagrante, o juiz deverá promover audiência de custódia com a presença do acusado, seu advogado constituído ou membro da Defensoria Pública e","a":"o membro do Ministério Público, no prazo máximo de até (C 48 (quarenta e oito) horas após a realização da prisão.","b":"10 (dez) horas após a entrega da nota de culpa.","c":"24 (vinte e quatro) horas após a entrega da nota de culpa.","d":"10 (dez) horas após a realização da prisão.","e":"24 (vinte e quatro) horas após a realização da prisão","gabarito":"E","materia":"Direito Processual Penal","tema":"Da Prisão e da Liberdade Provisória ,Da Prisão em Flagrante","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2465214","enunciado":"Especialidade: Agente da Polícia Judicial Nos termos do Código Penal, assinale a alternativa correta.","a":"O crime de peculato é descrito como apropriar-se o funcionário público de dinheiro, valor ou qualquer outro bem","b":"móvel, público ou particular, de que tem a posse em razão do cargo, ou desviá-lo, em proveito próprio ou alheio. O crime de feminicídio culposo possui pena de detenção e causa de aumento de pena.","c":"O crime de prevaricação é o único que possui modalidade culposa dos crimes contra a administração.","d":"O crime de roubo é descrito como constranger alguém, mediante violência ou grave ameaça, e com o intuito de obter","e":"para si ou para outrem indevida vantagem econômica, a fazer, tolerar que se faça ou deixar de fazer alguma coisa. Todos os crimes contra o patrimônio possuem qualificadoras.","gabarito":"A","materia":"Direito Penal","tema":"Crimes contra a administração pública ,Peculato","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2465213","enunciado":"Especialidade: Agente da Polícia Judicial Considere a expressão: atividade que objetiva neutralizar a inteligência adversa.","a":"É correto afirmar que essa expressão se refere à inteligência emocional.","b":"contrainteligência.","c":"inteligência militar.","d":"inteligência de guerra.","e":"inteligência terrorista.","gabarito":"B","materia":"Segurança e Transporte","tema":"Segurança da Informação","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2465212","enunciado":"Especialidade: Agente da Polícia Judicial Durante a sua atuação profissional, o agente é surpreendido com um caso de parada circulatória. Com relação às noções de primeiros socorros, assinale a alternativa que corretamente descreva uma observação necessária na hipótese de","a":"reconhecimento dessa situação. Embaçamento de superfície polida (não ocorre).","b":"Febre alta.","c":"Contração das pupilas com a luz.","d":"Ruído da respiração (inexistente).","e":"Movimento do tórax.","gabarito":"C","materia":"Segurança e Transporte","tema":"Técnicas Operacionais de Segurança","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2465211","enunciado":"Especialidade: Agente da Polícia Judicial Considere que, durante um incêndio, o agente necessite utilizar os extintores disponíveis. Assinale a alternativa que","a":"contempla corretamente um tipo de extintor, seguido de sua aplicação. O extintor de pó químico seco é utilizado no combate aos incêndios de classes B e C.","b":"O extintor de água pressurizada é utilizado no combate aos incêndios de classe B.","c":"O extintor de água pressurizada é utilizado no combate aos incêndios de classe B.","d":"O extintor de gás carbônico é utilizado no combate aos incêndios de classe A.","e":"O extintor de pó químico seco é utilizado exclusivamente no combate aos incêndios de classes D.","gabarito":"A","materia":"Segurança e Transporte","tema":"Combate a Incêndio","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2465210","enunciado":"Especialidade: Agente da Polícia Judicial _____________ serve para extinguir incêndios de classe “A” e “B”, age primeiramente por abafamento e, secundariamente, por resfriamento.","a":"Assinale a alternativa que corretamente preenche a lacuna do enunciado. A areia","b":"A água","c":"O pó químico seco","d":"A espuma","e":"O gás carbônico","gabarito":"D","materia":"Segurança e Transporte","tema":"Combate a Incêndio","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2465209","enunciado":"Especialidade: Agente da Polícia Judicial","a":"No que concerne às classes de incêndios, é correto afirmar que a Classe “D” corresponde a materiais radioativos.","b":"metais pirofóricos.","c":"sólidos inflamáveis.","d":"equipamentos elétricos.","e":"líquidos inflamáveis.","gabarito":"B","materia":"Segurança e Transporte","tema":"Combate a Incêndio","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2465208","enunciado":"Especialidade: Agente da Polícia Judicial","a":"Assinale a alternativa que apresenta corretamente uma medida operacional preventiva de segurança. Acionamento dos órgãos policiais.","b":"Elaboração de Boletim de Ocorrência.","c":"Contratação de profissionais de saúde.","d":"Prisão em flagrante de criminosos.","e":"Abordagem à distância de pessoas.","gabarito":"E","materia":"Segurança e Transporte","tema":"Técnicas Operacionais de Segurança","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2465207","enunciado":"Especialidade: Agente da Polícia Judicial","a":"São meios de propagação de calor: sólido, líquido e gasoso.","b":"convecção, condução e produção.","c":"condução, convecção e irradiação.","d":"leve, médio e pesado.","e":"conexão, condução e produção.","gabarito":"C","materia":"Segurança e Transporte","tema":"Combate a Incêndio","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2465206","enunciado":"Especialidade: Agente da Polícia Judicial Durante um incêndio existe uma temperatura mínima em que os corpos combustíveis começam a desprender vapores que se queimam em contato com uma fonte externa de calor; não havendo a duração prolongada da queima devido à quantidade de vapores insuficiente, as chamas não se mantêm, não se sustentam, por não existirem vapores suficientes.","a":"É correto afirmar que, no combate a incêndios, o enunciado se refere ao ponto de explosão.","b":"vaporização.","c":"combustão.","d":"fulgor.","e":"ignição.","gabarito":"D","materia":"Segurança e Transporte","tema":"Combate a Incêndio","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2465205","enunciado":"Especialidade: Agente da Polícia Judicial Na administração de uma empresa ou no serviço público, determina-se a instalação e a configuração de soluções, tais","a":"como: antivírus, firewall, antimalware, antispyware, antiramsonware e etc. medida contida no enunciado refere-se","b":"A à segurança da informação. à segurança patrimonial.","c":"às barreiras.","d":"à segurança de dignitários.","e":"à segurança física.","gabarito":"A","materia":"Segurança e Transporte","tema":"Segurança da Informação","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2465204","enunciado":"Especialidade: Agente da Polícia Judicial É considerada estratégica em determinadas situações, já que as perdas patrimoniais podem cessar as atividades da empresa. Seu valor na cadeia estratégica aumenta de acordo com o valor agregado do produto final comercializado pela empresa.","a":"É correto afirmar que o enunciado se refere a planejamento estratégico.","b":"segurança patrimonial.","c":"segurança de dignitário.","d":"segurança pública.","e":"plano de ação.","gabarito":"B","materia":"Segurança e Transporte","tema":"Segurança Física e Patrimonial","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2465203","enunciado":"Especialidade: Agente da Polícia Judicial","a":"É correto afirmar que barreiras perimetrais, circuito fechado de TV e sistemas de alarmes são consideradas medidas estáticas.","b":"pontos vulneráveis.","c":"pontos estratégicos.","d":"pontos dinâmicos.","e":"medidas dinâmicas.","gabarito":"A","materia":"Segurança e Transporte","tema":"Segurança da Informação","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2465202","enunciado":"Especialidade: Agente da Polícia Judicial É correto afirmar que a atuação inteligente do vigilante, como pessoa capacitada para fazer a segurança física das instalações e dos dignitários, por meio da identificação pessoal, da abordagem à distância, da sinalização, entre outras","a":"ações, é considerada medida estática.","b":"ponto dinâmico.","c":"medida dinâmica.","d":"ponto estratégico.","e":"ponto vulnerável.","gabarito":"C","materia":"Segurança e Transporte","tema":"Segurança de Dignatários","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2465201","enunciado":"Especialidade: Agente da Polícia Judicial","a":"Assinale a alternativa que corretamente apresenta uma medida de segurança adotada no controle de acesso de pessoas. Acionar as forças policiais.","b":"Julgar as pessoas pela aparência.","c":"Evitar a realização de inspeção visual.","d":"Realizar abordagem à distância.","e":"Auxiliar a descarregar mercadorias.","gabarito":"D","materia":"Segurança e Transporte","tema":"Técnicas Operacionais de Segurança","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2465200","enunciado":"","a":"Especialidade: Agente da Polícia Judicial segurança em torno da autoridade dispõe-se em círculos concêntricos, orientados de acordo com o sentido de seu deslocamento. É correto afirmar que o primeiro círculo é composto pela","b":"A segurança velada. proteção em escudo.","c":"bloqueio de aproximação.","d":"segurança privada.","e":"segurança aproximada.","gabarito":"E","materia":"Segurança e Transporte","tema":"Segurança de Dignatários","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2465199","enunciado":"Especialidade: Agente da Polícia Judicial Considere a hipótese de um agente receber a atribuição de inspecionar (inspeção de segurança), objetivando a detecção e a neutralização de quaisquer objetos, artefatos ou equipamentos que se constituam num risco para a segurança do dignitário. Nesta situação, busca-se identificar previamente qualquer perigo potencial, armadilhas, artefatos explosivos ou equipamentos de vigilância clandestina.","a":"É correto afirmar que o enunciado se refere à técnica denominada higienização.","b":"varredura.","c":"limpeza.","d":"investigação.","e":"proteção.","gabarito":"B","materia":"Segurança e Transporte","tema":"Técnicas Operacionais de Segurança","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2465198","enunciado":"Especialidade: Agente da Polícia Judicial É correto afirmar que, entre outras, trata-se de uma metodologia para a análise dos riscos pertinentes a uma autoridade e o","a":"consequente planejamento de sua segurança: procurar, inicialmente, definir quais são as potenciais ameaças que incidem sobre a pessoa protegida.","b":"verificar se o dignitário possui algum animal de estimação.","c":"relacionar as empresas que fazem blindagem de veículos.","d":"em qualquer situação, não argumentar com o dignitário sobre os aspectos de segurança, pois a equipe é técnica e","e":"responsável. adquirir armamentos compatíveis, mesmo que isso implique em descumprimento de legislação de porte de arma.","gabarito":"A","materia":"Segurança e Transporte","tema":"Segurança de Dignatários","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2465197","enunciado":"Especialidade: Agente da Polícia Judicial Recursos utilizados pelos órgãos de Inteligência para a obtenção de informações. Consiste em introduzir um elemento (cuja verdadeira identidade é mantida em sigilo) em contato com pessoas ou certo grupo de pessoas, com o objetivo de coletar","a":"informações. Acompanhamento.","b":"Penetração.","c":"Monitoramento.","d":"Infiltração.","e":"Aproximação.","gabarito":"D","materia":"Segurança e Transporte","tema":"Segurança da Informação","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2465196","enunciado":"Especialidade: Agente da Polícia Judicial Considere a hipótese de um agente receber a atribuição de produzir conhecimentos e a realizar ações voltadas para a proteção de dados, conhecimentos, infraestruturas críticas (comunicações, transportes, tecnologias de informação, entre outros ativos sensíveis e sigilosos de interesse do Estado e da sociedade).","a":"É correto afirmar que a atribuição desse agente pode receber corretamente a denominação de inteligência estatal.","b":"contraespionagem.","c":"inteligência da informação.","d":"espionagem.","e":"contrainteligência.","gabarito":"E","materia":"Segurança e Transporte","tema":"Segurança da Informação","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2465195","enunciado":"","a":"Especialidade: Agente da Polícia Judicial Confidencialidade, Integridade, Disponibilidade, Autenticidade e Legalidade são os cinco pilares da segurança","b":"A patrimonial. física.","c":"da informação.","d":"de dignitário.","e":"pública. Segurança e Saúde no Trabalho>NR 23 - Norma Regulamentadora nº 23 - Proteção Contra Incêndio ,","gabarito":"C","materia":"Segurança e Transporte","tema":"Segurança da Informação","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_832","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa - Especialidade: Agente da Polícia Judicial Nos termos da NR-23 — Proteção Contra Incêndios, a organização deve providenciar para todos os trabalhadores","a":"informações, entre outros itens, sobre curso de bombeiros voluntários.","b":"dispositivos de alarme existentes.","c":"uso adequado dos equipamentos de Circuito Fechado de TV.","d":"utilização de armamentos não letais.","e":"aplicação de primeiros-socorros.","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2465193","enunciado":"Especialidade: Agente da Polícia Judicial Conjunto de medidas e procedimentos utilizados para prevenir ou minimizar as consequências dos acidentes de trânsito. Baseia-se na noção de que em todo acidente sempre está presente uma falha humana relacionada ou a negligência, ou imprudência, ou imperícia. Pretende- -se que o motorista que emprega essas medidas seja um elemento ativo na alteração ou eliminação dos fatores que possam vir a causar acidentes.","a":"É correto afirmar que o enunciado se refere a utilização de cones.","b":"direção defensiva.","c":"direção ofensiva.","d":"implantação de regras de trânsito.","e":"frequência de cursos de trânsito.","gabarito":"B","materia":"Segurança e Transporte","tema":"Segurança Veicular","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2465192","enunciado":"Especialidade: Agente da Polícia Judicial Considere a situação de um ataque ao dignitário, utilizando-se arma branca.","a":"É correto afirmar que, nessa hipótese, a equipe de segurança deve evitar a utilização de arma de eletrochoque.","b":"retirar o dignitário sem tomar qualquer outra atitude.","c":"não utilizar em qualquer hipótese a arma de fogo para incapacitar a agressão.","d":"acionar os órgãos policiais.","e":"tentar imobilizar e desarmar o agressor utilizando a defesa pessoal.","gabarito":"E","materia":"Segurança e Transporte","tema":"Segurança de Dignatários","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2465191","enunciado":"Especialidade: Agente da Polícia Judicial Nos deslocamentos do dignitário o tamanho de um comboio variará em função _____________e______________ .","a":"Assinale a alternativa que completa, correta e respectivamente, as lacunas da frase. do grau de risco do dignitário ... dos recursos disponíveis para prover-lhe proteção","b":"do local ... da importância da autoridade","c":"dos órgãos da imprensa existentes ... da distância a ser percorrida","d":"da distância a ser percorrida ... do horário previsto na agenda","e":"do estado emocional do dignitário ... da relevância do evento","gabarito":"A","materia":"Segurança e Transporte","tema":"Segurança de Dignatários","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2465190","enunciado":"Especialidade: Agente da Polícia Judicial","a":"É correto afirmar que, nos deslocamentos do dignitário, o tamanho mínimo do comboio será de quatro veículos.","b":"cinco veículos.","c":"três veículos.","d":"dois veículos.","e":"um veículo.","gabarito":"D","materia":"Segurança e Transporte","tema":"Segurança de Dignatários","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2465189","enunciado":"Especialidade: Agente da Polícia Judicial Deve-se ter em mente que um dos momentos mais vulneráveis para a segurança de um dignitário se dá durante seus deslocamentos.","a":"É correto afirmar que, nos deslocamentos rotineiros, a segurança deve obedecer ao itinerário solicitado pelo dignitário.","b":"se deve sempre realizar o deslocamento com escolta policial.","c":"se deve procurar sempre realizá-los no mesmo horário, mas utilizando itinerários diferentes.","d":"se deve procurar sempre realizar por meio de helicópteros.","e":"serão obrigatórias as variações de horários e itinerários.","gabarito":"E","materia":"Segurança e Transporte","tema":"Segurança de Dignatários","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2465188","enunciado":"Especialidade: Agente da Polícia Judicial Durante a execução da atividade de segurança, considere um agente que responde mais diretamente pela proteção do dignitário. Na formação de agentes, independentemente do quantitativo envolvido, esse agente será o elemento que atuará mais próximo do protegido. Se todas as medidas de segurança falharem, ele atuará como “escudo-humano” da autoridade.","a":"É correto afirmar que o referido agente receberá a denominação, na segurança aproximada, de Alvo.","b":"Águia.","c":"Colete.","d":"Escudo.","e":"Mosca.","gabarito":"E","materia":"Segurança e Transporte","tema":"Segurança de Dignatários","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2465187","enunciado":"Especialidade: Agente da Polícia Judicial o De acordo com o disposto na Resolução CNJ n 325/2020, que trata da gestão estratégica do Poder Judiciário, é correto afirmar que","a":"a Estratégia do Judiciário é executada de forma colaborativa e participativa sob a coordenação da Corregedoria Geral dos Tribunais.","b":"a execução da Estratégia Nacional do Poder Judiciário é de responsabilidade de ministros, conselheiros, magistrados de primeiro e segundo graus, servidores e colaboradores do Poder Judiciário.","c":"os órgãos do Poder Judiciário criarão unidade de gestão estratégica para redigir as normas e aplicar as sanções relacionadas à implementação do planejamento estratégico.","d":"a formulação das Metas Nacionais, a ser divulgada anualmente, é regulamentada por ato do Presidente do Supremo Tribunal Federal.","e":"as propostas orçamentárias dos tribunais e dos conselhos de justiça deverão reservar, no mínimo, 10% (dez por cento) de seu orçamento para seus respectivos planos estratégicos. Estatuto da Pessoa com Deficiência - Lei nº 13.146 de 2015>","gabarito":"B","materia":"Legislação dos TRFs","tema":"Conselho Nacional de Justiça (CNJ) ,Resoluções do CNJ","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_840","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa - Especialidade: Agente da Polícia Judicial o Conforme disposto expressamente na Lei n 13.146/2015, se, no exercício de suas funções, os juízes e os tribunais tiverem","a":"conhecimento de fatos que caracterizem as violações previstas nessa Lei, devem instituir comissão de sindicância para apuração dos fatos e posterior abertura de processo administrativo.","b":"mandar instaurar o inquérito policial para apuração e aplicação das sanções cabíveis.","c":"remeter peças ao Ministério Público para as providências cabíveis.","d":"aplicar as sanções e multas previstas na Lei.","e":"instaurar o inquérito civil para apuração dos fatos e, posteriormente, aplicar as sanções previstas na Lei.","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2465184","enunciado":"Especialidade: Agente da Polícia Judicial Suponha que, em um determinado processo criminal que tramita na Justiça Estadual, constatou-se que, no caso a ser julgado, houve grave violação de direitos humanos. Contudo, no referido feito, já há sentença proferida, estando o processo em fase de recurso para o Tribunal de Justiça. Nessa situação hipotética e considerando-se o disposto na Constituição Federal, é correto afirmar que","a":"o Procurador-Geral de Justiça, com a finalidade de assegurar o cumprimento de obrigações decorrentes de tratados internacionais de direitos humanos dos quais o Brasil seja parte, poderá suscitar, perante o Tribunal Regional Federal, incidente de deslocamento de competência para a Justiça Federal.","b":"o Procurador-Geral da República, com a finalidade de assegurar o cumprimento de obrigações decorrentes de tratados internacionais de direitos humanos dos quais o Brasil seja parte, poderá suscitar, perante o Supremo Tribunal Federal, incidente de deslocamento de competência para a Justiça Federal.","c":"o Procurador-Geral da República, com a finalidade de assegurar o cumprimento de obrigações decorrentes de tratados internacionais de direitos humanos dos quais o Brasil seja parte, poderá suscitar, perante o Supremo Tribunal Federal, incidente de deslocamento de competência para o Superior Tribunal de Justiça.","d":"o Procurador-Geral da República, com a finalidade de assegurar o cumprimento de obrigações decorrentes de tratados internacionais de direitos humanos dos quais o Brasil seja parte, poderá suscitar, perante o Superior Tribunal de Justiça, incidente de deslocamento de competência para a Justiça Federal.","e":"não poderá haver pedido de deslocamento de competência do referido processo, tendo em vista que o feito já foi sentenciado, sob pena de supressão de instância.","gabarito":"D","materia":"Direito Constitucional","tema":"Tribunais Regionais Federais e Juízes Federais ,Organização do Poder Judiciário","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2465183","enunciado":"Especialidade: Agente da Polícia Judicial Ariadne e Narciso são servidores públicos federais, ocupantes de cargo de provimento efetivo, sendo que a primeira é professora universitária e o segundo é agente penitenciário. Nessa situação hipotética, considerando o disposto na Constituição Federal, é correto afirmar que Ariadne","a":"não terá direito à aposentadoria especial, ainda que exerça o magistério, mas Narciso poderá ter critérios diferenciados para obtenção da aposentadoria, por meio de lei complementar de competência da União.","b":"não terá direito à aposentadoria especial, ainda que exerça o magistério, mas Narciso poderá ter critérios diferenciados para obtenção da aposentadoria, por meio de lei ordinária federal.","c":"poderá ter direito à aposentadoria com idade reduzida em cinco anos em razão do exercício da função de magistério, enquanto Narciso poderá ter critérios diferenciados para obtenção da aposentadoria, por meio de lei complementar federal.","d":"e Narciso poderão ter idade mínima reduzida em 5 (cinco) anos em relação aos demais servidores submetidos ao regime próprio de previdência social, para obtenção de aposentadoria, estabelecida por lei complementar federal.","e":"e Narciso não terão direito à aposentadoria especial, devendo sujeitar-se às mesmas regras do regime próprio de previdência social aplicáveis a todos os servidores federais.","gabarito":"A","materia":"Direito Constitucional","tema":"Administração Pública – Disposições Gerais e Servidores Públicos ,Servidores Públicos","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2465181","enunciado":"Especialidade: Agente da Polícia Judicial Nos termos do que dispõe expressamente a Carta Magna sobre os direitos sociais, é correto afirmar que","a":"é garantia do trabalhador relação de emprego protegida contra despedida imotivada, com ou sem justa causa, que preverá verba trabalhista indenizatória, dentre outros direitos.","b":"é direito do trabalhador a irredutibilidade do salário, salvo o disposto em convenção ou acordo coletivo, e garantia de salário, nunca inferior ao mínimo, ao que percebe remuneração variável.","c":"o programa permanente de transferência de renda garante uma renda básica a todo brasileiro ou família que comprove receber menos que um salário mínimo mensal.","d":"é direito do trabalhador urbano ou rural o seguro-desemprego, correspondente a um salário mínimo mensal, em caso de desemprego, exceto se demitido por justa causa.","e":"deve ser garantida ao trabalhador participação nos lucros, ou resultados, vinculada à remuneração, e participação na gestão da empresa, definida em lei, além de salário-família ao trabalhador que possuir dependente menor de idade.","gabarito":"B","materia":"Direito Constitucional","tema":"Direitos Sociais","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2465180","enunciado":"Especialidade: Agente da Polícia Judicial No que diz respeito às autarquias, é correto afirmar que","a":"estão sujeitas à prescrição trienal, significando que a cobrança de suas dívidas e direitos prescrevem, em regra, em três anos, mas em alguns casos a prescrição pode ocorrer em cinco anos.","b":"gozam da garantia da imprescritibilidade de seus bens, que são tidos como bens públicos, não podendo eles ser adquiridos por terceiros através de usucapião, nem tampouco podem ser objeto de desapropriação.","c":"possuem imunidade tributária, sendo vedada a instituição de impostos, taxas e contribuições sobre o seu patrimônio, renda e serviços, desde que vinculados a suas finalidades essenciais.","d":"possuem prazo especial para se defender em juízo, conforme estabelecido no Código de Processo Civil, sendo em quádruplo para contestar e em dobro para recorrer, estando, ainda, sujeitas ao duplo grau obrigatório de jurisdição.","e":"gozam da garantia da impenhorabilidade dos seus bens, que são públicos e não podem ser objeto de constrição em processo de cobrança judicial, devendo o credor se submeter aos precatórios para a satisfação do seu crédito.","gabarito":"E","materia":"Direito Administrativo","tema":"Organização da Administração Pública ,Autarquias","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2465179","enunciado":"Especialidade: Agente da Polícia Judicial Sormena é servidora pública federal, mas detectou-se que ela está acumulando ilegalmente o seu cargo público de provimento efetivo com um emprego público que assumiu posteriormente ao cargo. Tendo em vista essa situação o hipotética, a Lei n 8.112/90 estabelece que a autoridade competente deverá","a":"instaurar processo administrativo disciplinar para a devida apuração e, atendidos os princípios do contraditório e da ampla defesa, devidamente comprovada a acumulação ilegal, decretar a demissão de Sormena do emprego público, podendo ela manter o cargo público.","b":"instaurar processo administrativo disciplinar para a devida apuração e, atendidos os princípios do contraditório e da ampla defesa, devidamente comprovada a acumulação ilegal, promover a exoneração de Sormena do cargo e do emprego públicos.","c":"notificar a servidora, diretamente, para apresentar opção no prazo improrrogável de trinta dias, contados da data da ciência e, na hipótese de omissão, adotará procedimento sumário para a sua apuração e regularização imediata.","d":"notificar a servidora, por intermédio de sua chefia imediata, para apresentar opção no prazo improrrogável de dez dias, contados da data da ciência e, na hipótese de omissão, adotará procedimento sumário para a sua apuração e regularização imediata.","e":"encaminhar o caso ao Ministério Público, para instauração de inquérito para a devida apuração dos fatos e, comprovada a infração disciplinar, a sua demissão do cargo ou do emprego, podendo Sormena manter o que assumiu em primeiro.","gabarito":"D","materia":"Direito Administrativo","tema":"Agentes públicos e Lei 8.112 de 1990 ,Acumulação de cargos e funções","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2465178","enunciado":"Especialidade: Agente da Polícia Judicial Assinale a alternativa correta a respeito do poder regulamentar.","a":"O poder normativo conferido às autarquias de regime especial autoriza que elas definam, por meio de resolução, infrações e penalidades administrativas sobre o serviço por elas prestado.","b":"Esse poder, que se constitui em função normativa do Executivo, é a prerrogativa conferida à Administração Pública de editar atos gerais para complementar, disciplinar e alterar as leis de modo a permitir a sua efetiva aplicação.","c":"É vedado ao legislador estabelecer prazo para regulamentação da lei, devendo esta ser aplicada de imediato, ainda que não regulamentada, gerando plenos efeitos aos seus destinatários, tendo em vista sua efetiva exequibilidade.","d":"Os decretos são os atos de exercício do poder regulamentar do Chefe do Executivo, sendo exemplos típicos de sua função os decretos de intervenção federal ou estadual e os decretos de estado de defesa e de estado de sítio.","e":"Tem fundamento no poder regulamentar os atos de organização e funcionamento da Administração, de conteúdo normativo, denominados de atos ordinatórios, destinados ao setor interno da Administração para dispor sobre seus serviços e órgãos.","gabarito":"A","materia":"Direito Administrativo","tema":"Poderes da Administração","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2465177","enunciado":"Especialidade: Agente da Polícia Judicial O grupo de esgrimistas formado por Luiz, Manoel, Nelson, Paulo, Quincas e Raul tem, juntos, 66 títulos conquistados. Cada um desses rapazes tem um único irmão, que é alguém desse mesmo grupo. O número de títulos de Luiz é o triplo do número de títulos do irmão de Paulo. Raul venceu um torneio a menos do que seu irmão. Manoel tem 14 títulos, Quincas tem 6 e Nelson tem 5. O número de títulos somados de quaisquer dois desses rapazes é menor do que 33. Paulo não é","a":"irmão de Nelson. Raul tem mais títulos do que Paulo. O número de títulos conquistados pelo irmão de Quincas é 13.","b":"5.","c":"10.","d":"6.","e":"14.","gabarito":"C","materia":"Matemática","tema":"Raciocínio Lógico","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2465176","enunciado":"Especialidade: Agente da Polícia Judicial Um clube do livro é formado por 198 pessoas. Semana passada foram sugeridos três livros para leitura, que serão designados por X, Y e Z. Todos os membros do clube leram pelo menos um dos livros, sendo que 15 deles leram os três. Quem leu o livro X também leu o livro Y. O número de membros que leu apenas o livro Z é igual ao total de membros que leram exatamente dois títulos. Sabendo que 48 pessoas leram o livro X e 114 pessoas leram o livro Y, o número de pessoas","a":"que leu apenas o livro Y foi 16.","b":"15.","c":"17.","d":"18.","e":"19.","gabarito":"B","materia":"Raciocínio Lógico","tema":"Diagramas de Venn (Conjuntos)","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2465175","enunciado":"Especialidade: Agente da Polícia Judicial o o Seja a sequência 21035, 12053, 35021, 53012, 21135, 12153, …, de acordo com o seu padrão de construção, o 40 , 41 e o o","a":"42 termos são, respectivamente, 53912, 211035 e 121053. O 111 termo dessa sequência é 352621.","b":"532712.","c":"122553.","d":"352721.","e":"212635.","gabarito":"D","materia":"Raciocínio Lógico","tema":"Sequências Lógicas de Números, Letras, Palavras e Figuras","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2465174","enunciado":"","a":"Especialidade: Agente da Polícia Judicial contrapositiva da proposição “Se todos colaboraram, então a casa ficou arrumada e o chão não ficou sujo” é a proposição:","b":"A Se pelo menos uma pessoa não colaborou, então a casa não ficou arrumada ou o chão ficou sujo. Se a casa não ficou arrumada ou o chão não ficou sujo, então pelo menos uma pessoa não colaborou.","c":"Todos colaboraram ou a casa ficou arrumada e o chão não ficou sujo.","d":"Alguém não colaborou e a casa ficou arrumada e o chão não ficou sujo.","e":"Se a casa não ficou arrumada ou o chão ficou sujo, então pelo menos uma pessoa não colaborou. Matemática>Aritmética e Problemas ,Sistemas de Numeração e Operações Fundamentais ,","gabarito":"E","materia":"Raciocínio Lógico","tema":"Fundamentos de Lógica ,Proposições Simples e Compostas e Operadores Lógicos","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_851","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa - Especialidade: Agente da Polícia Judicial Três amigos universitários resolveram todos os exercícios de uma lista. Esses amigos não resolveram a lista em conjunto, mas cada um resolvia, sozinho, certo número de exercícios e passava os exercícios não resolvidos para o próximo. O primeiro amigo resolveu 30 exercícios em um dia e, no dia seguinte, resolveu um sexto do que ainda faltava, passando a lista para o próximo. O segundo amigo resolveu 30 exercícios em um dia e, no dia seguinte, resolveu um sexto do que ainda faltava, passando a lista para o próximo. O terceiro amigo recebeu a lista e fez, em um mesmo dia, todos os 50 exercícios","a":"que faltavam. O número total de exercícios dessa lista estava compreendido entre 175 e 200.","b":"150 e 175.","c":"125 e 150.","d":"100 e 125.","e":"200 e 225.","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2465171","enunciado":"Especialidade: Agente da Polícia Judicial Certo dia, em um parque, os visitantes chegaram em grupos de 4 pessoas, sendo 2 adultos e 2 crianças, ou em grupos de 3 pessoas, sendo 2 adultos e 1 criança. O momento em que o parque tinha mais visitantes foi às 12h, quando a razão entre o número de crianças e o número de adultos era 4/5. Até esse momento, nenhum grupo saiu do parque e, após esse momento, não chegaram outros grupos. Das 12h às 15h, saíram do parque 50 grupos de 4 pessoas e 80 grupos de 3 pessoas, de maneira que a razão entre o número de crianças e o número de adultos passou a ser 6/7. Nesse dia, o total de","a":"adultos que visitaram o parque foi 700.","b":"650.","c":"600.","d":"750.","e":"800.","gabarito":"D","materia":"Matemática","tema":"Aritmética e Problemas ,Razão e Proporção; e Números Proporcionais","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2465170","enunciado":"Especialidade: Agente da Polícia Judicial Um grupo de 11 amigos estava em um passeio de barco quando uma pane mecânica inutilizou o motor e o barco parou. Para voltar à terra firme eles remaram com os 5 remos que havia no barco, em uma linha reta, de maneira que, durante toda essa volta, sempre havia 5 amigos remando, que iam se revezando com os demais amigos. Por conta de ventos contrários, a cada quilômetro real remado entre o local da pane e a terra firme, o barco voltou 200 metros, os quais foram novamente remados sem vento contra e, consequentemente, sem arrasto para trás. Ao chegarem à terra firme, foi constatado que a média aritmética dos números de quilômetros remados por cada amigo foi 6 km. Logo, no momento da","a":"pane, a distância entre o barco e a terra firme era 10,56 km.","b":"10 km.","c":"9,43 km.","d":"8 km.","e":"11 km.","gabarito":"E","materia":"Matemática","tema":"Aritmética e Problemas ,Raciocínio Lógico ,Sistemas de Numeração e Operações Fundamentais","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2465169","enunciado":"Especialidade: Agente da Polícia Judicial Uma empresa mudou de endereço e todos os seus 500 funcionários empacotaram seus próprios pertences e os levaram para o novo prédio. Essa mudança levou 4 dias e os funcionários tinham números diferentes de caixas a serem transportadas, que não necessariamente foram levadas em um mesmo dia. No primeiro dia, uma parte dos funcionários transportou, cada um, uma de suas caixas. No segundo dia, 20% dos funcionários que ainda não havia transportado caixas, transportou 2 caixas cada. No terceiro dia, 30% de quem já havia transportado 1 caixa transportou mais 1 caixa e 40% de quem já havia transportado 2 caixas transportou mais 2 caixas. No último dia, faltavam apenas as 300 caixas dos 160","a":"funcionários que ainda não tinham transportado caixa alguma. O total de caixas transportadas nesses 4 dias foi 765.","b":"802.","c":"654.","d":"691.","e":"728.","gabarito":"B","materia":"Matemática","tema":"Aritmética e Problemas ,Sistemas de Numeração e Operações Fundamentais ,Porcentagem","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2465168","enunciado":"Especialidade: Agente da Polícia Judicial Três boias marítimas enviam dados para uma base de pesquisa em intervalos regulares de tempo. A boia A envia os dados a cada 8 minutos, a boia B a cada 18 minutos e a boia C a cada 11 horas. Se em uma segunda-feira, às 20h, a base recebeu","a":"dados dessas 3 boias, o próximo dia em que chegaram dados, em um mesmo horário, dessas três boias foi em uma quarta-feira.","b":"um sábado.","c":"uma quinta-feira.","d":"uma terça-feira.","e":"um domingo.","gabarito":"C","materia":"Raciocínio Lógico","tema":"Raciocínio Matemático","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2465167","enunciado":"Especialidade: Agente da Polícia Judicial As pitangueiras d’antanho* Tem seus 23 anos, e eu a conheço desde os oito ou nove, sempre assim, meio gordinha, engraçada, de cabelos ruivos. Foi criada, a bem dizer, na areia do Arpoador; nasceu e viveu em uma daquelas ruas que vão de Copacabana a Ipanema, de praia a praia. A família mudou-se quando a casa foi comprada para construção de edifício. Certa vez me contou: – Em meu quarteirão não há uma só casa de meu tempo de menina. Se eu tivesse passado anos fora do Rio e voltasse agora, acho que não acertaria nem com a minha rua. Tudo acabou: as casas, os jardins, as árvores. É como se eu não tivesse tido infância... Falta-lhe uma base física para a saudade. Tudo o que parecia eterno sumiu. Outra senhora disse então que se lembrava muito de que, quando era menina, apanhava pitangas em Copacabana; depois, já moça, colhia pitangas na Barra da Tijuca; e hoje não há mais pitangas. Disse isso com uma certa animação, e depois ficou um instante com o ar meio triste – a melancolia de não ter mais pitangas, ou, quem sabe, a saudade daquela manhã em que foi com o namorado colher pitangas. Também em minha infância, há pitangueiras de praia. Não baixinhas, em moitas, como aquelas de Cabo Frio, que o vento não deixa crescer; mas altas; e suas copas se tocavam e faziam uma sombra varada por pequenos pontos de sol. (Rubem Fonseca, “As pitangueiras d’antanho”. 200 crônicas escolhidas, 2001. Fragmento)","a":"* d’antanho: de épocas passadas concordância nominal está de acordo com a norma-padrão em: Ela falou com certa animação, depois ficou um instante com a expressão meia triste – a melancolia de não ter mais A","b":"pitangas. É necessária sabedoria para lidar com melancolias advindo da saudade das pitangas que outrora nos encantaram.","c":"O matiz das conversas deixou-me claro que tanto a moça quanto a senhora estavam saudosas das pitangueiras.","d":"A senhora falou-me que havia bastante pitangas em Copacabana e na Barra da Tijuca e ela as apanhava sempre.","e":"A moça lamentou que não havia uma só casa de seu tempo de infância, o que me fez sentir uma dó imensa dela.","gabarito":"C","materia":"Português","tema":"Sintaxe ,Concordância verbal, Concordância nominal","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2465166","enunciado":"Especialidade: Agente da Polícia Judicial Para a moça de cabelos ruivos, as ruas que vão de Copacabana a Ipanema atualmente estão diferentes, não se assemelham_____________ de outrora; nada mais é compatível_____________ seu tempo de criança,_____________ ela não esquece.","a":"Em conformidade com a norma-padrão, as lacunas do enunciado devem ser preenchidas, respectivamente, com: às ... de ... de que","b":"com as ... a ... que","c":"nas ... com ... de que","d":"com as ... em ... que","e":"às ... com ... que","gabarito":"E","materia":"Português","tema":"Sintaxe ,Regência","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2465165","enunciado":"Especialidade: Agente da Polícia Judicial o Na passagem – Falta-lhe uma base física para a saudade. Tudo o que parecia eterno sumiu. (4 parágrafo) –, os termos","a":"destacados são, correta e respectivamente, pronomes pessoal e demonstrativo.","b":"possessivo e pessoal.","c":"demonstrativo e pessoal.","d":"indefinido e demonstrativo.","e":"pessoal e possessivo.","gabarito":"A","materia":"Português","tema":"Morfologia - Pronomes","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2465164","enunciado":"Especialidade: Agente da Polícia Judicial Considere as passagens: o • A família mudou-se quando a casa foi comprada para construção de edifício. (1 parágrafo) o • Disse isso com uma certa animação... (5 parágrafo) o • ... a melancolia de não ter mais pitangas... (5 parágrafo)","a":"No contexto em que estão empregadas, as preposições destacadas exprimem, correta e respectivamente, sentidos de instrumento; modo; modo.","b":"comparação; meio; consequência.","c":"instrumento; intensidade; modo.","d":"finalidade; modo; causa.","e":"finalidade; assunto; causa.","gabarito":"D","materia":"Português","tema":"Morfologia ,Preposições","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2465163","enunciado":"","a":"Especialidade: Agente da Polícia Judicial correlação entre os tempos verbais atende à norma-padrão em:","b":"A Se eu tenha que passar uns anos fora do Rio e volte depois, acho que não acertara nem com a minha rua. Se eu tenho que passar uns anos fora do Rio e voltaria depois, acho que não acertaria nem com a minha rua.","c":"Se eu ter que passar uns anos fora do Rio e voltar depois, acho que não acerto nem com a minha rua.","d":"Se eu tiver que passar uns anos fora do Rio e voltar depois, acho que não acertarei nem com a minha rua.","e":"Se eu tive que passar uns anos fora do Rio e voltarei depois, acho que não acertava nem com a minha rua.","gabarito":"D","materia":"Português","tema":"Morfologia - Verbos","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2465162","enunciado":"Especialidade: Agente da Polícia Judicial Na passagem do terceiro parágrafo – Tudo acabou: as casas, os jardins, as árvores. É como se eu não tivesse tido infância...","a":"– as vírgulas e as reticências indicam, correta e respectivamente: explicação; omissão de fato.","b":"omissão de verbo; esquecimento de fala.","c":"enumeração; sugestão de emoção.","d":"detalhamento; ambiguidade da informação.","e":"exemplificação; finalização de relato.","gabarito":"C","materia":"Português","tema":"Pontuação ,Uso da Vírgula","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2465161","enunciado":"Especialidade: Agente da Polícia Judicial o Com a frase – ... ou, quem sabe, a saudade daquela manhã em que foi com o namorado colher pitangas. (5 parágrafo) –, o","a":"narrador faz uma afirmação sobre a animação da mulher por lembrar-se do namorado.","b":"conjectura sobre o que pode significar o ar meio triste da senhora.","c":"crítica sobre o descaso da mulher quanto aos bons momentos vividos.","d":"conjectura sobre a felicidade da mulher com as pitangueiras do local.","e":"crítica sobre as considerações da mulher a respeito das pitangueiras.","gabarito":"B","materia":"Português","tema":"Interpretação de Textos ,Noções Gerais de Compreensão e Interpretação de Texto","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2465160","enunciado":"Especialidade: Agente da Polícia Judicial","a":"De acordo com o texto, a falta de base física para a saudade da moça se deve à mudança do Arpoador para um lugar distante.","b":"à vida adulta permeada de melancolias.","c":"ao perfil das praias modernas sem as pitangueiras.","d":"às lembranças causadas pelas pitangueiras.","e":"ao processo de transformação do espaço urbano.","gabarito":"E","materia":"Português","tema":"Interpretação de Textos ,Noções Gerais de Compreensão e Interpretação de Texto","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2465159","enunciado":"Especialidade: Agente da Polícia Judicial Leia a charge.","a":"Implícita na fala do peixe, a charge traz uma crítica à espécie humana.","b":"ao pesquisador.","c":"à fauna marinha.","d":"às fake news.","e":"à pesquisa científica.","gabarito":"A","materia":"Português","tema":"Interpretação de Textos ,Noções Gerais de Compreensão e Interpretação de Texto","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2465158","enunciado":"Especialidade: Agente da Polícia Judicial Em uma realidade cada vez mais complexa e desafiadora, é natural que os governos venham aderindo ____________ transformações digitais e tecnológicas na formulação e implementação de suas políticas e entregas aos cidadãos. Assim, atuam como catalisadores de inovações direcionadas ____________ geração de mais valor público. (Pedro Cavalcante, Nem tudo são flores no mundo da Inteligência Artificial. https://www.estadao.com.br/politica, 07.08.2013. Adaptado)","a":"De acordo com a norma-padrão, as lacunas do texto devem ser preenchidas, respectivamente, com: à ... à","b":"a ... à","c":"as ... a","d":"às ... a","e":"à ... a","gabarito":"B","materia":"Português","tema":"Crase ,Crase","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2465157","enunciado":"Especialidade: Agente da Polícia Judicial Inteligência artificial: a era do “deus” máquina No teatro grego antigo, quando não havia solução para um impasse, um ator interpretando uma divindade descia ao palco pendurado num guindaste, resolvia o problema e, assim, acabava a peça. Era o Deus ex-machina – o deus surgido da máquina. Com o avanço sem precedentes da inteligência artificial (IA), é justo pensar que, no mundo contemporâneo, a máquina é a própria deidade. Para ela, nada parece impossível. Da confecção de discursos em segundos à criação de obras de arte; da identificação de medicamentos promissores ao diagnóstico preciso de doenças, tudo é resolvido pelo “deus algoritmo”. E, ao observar sua invenção “surgindo do guindaste”, o homem pode se perguntar qual lugar ocupará neste enredo. Segundo especialistas,","a":"porém, o perigo não está na criatura e, sim, no uso que o criador faz dela. inteligência artificial faz parte da rotina, ainda que não se perceba. O GPS que indica o percurso, a atendente virtual, o internet banking são exemplos de seu uso no dia a dia. Só que, até agora, ninguém temia os mecanismos de busca dos navegadores, os sistemas de reconhecimento facial dos condomínios ou a sugestão de filmes apresentadas pelos aplicativos de streaming. Então, as máquinas começaram a gerar imagens perfeitas de pessoas inexistentes, escrever reportagens com acurácia, resolver enigmas matemáticos em frações de segundos, dirigir e voar sozinhas, elaborar defesas jurídicas e até “ler” pensamentos em experimentos científicos. A ponto de, em um editorial da revista Science, um grupo de cientistas pedir a moratória de pesquisas até alguma regulamentação ética da IA. A discussão sobre riscos e avanços da IA ultrapassa o campo da ciência da computação; é também filosófica. Já na Grécia Antiga, filósofos questionavam a essência da inteligência e se ela era um atributo somente humano. Hoje, esse é um dos centros da discussão sobre IA: sistemas programados e alimentados por seres humanos poderão ultrapassar em astúcia seus criadores? Não, garante um dos maiores especialistas no tema, o cientista da computação francês Jean-Gabriel Ganascia, da Universidade de Sorbonne que, já em 1980, obteve mestrado em inteligência artificial em Paris. (Paloma Oliveto, Inteligência artificial: a era do ‘deus’ máquina. https://www.correiobraziliense.com.br/ciencia-e-saude. Adaptado) Assinale a alternativa que atende à norma-padrão de concordância verbal, de emprego de pronome e de colocação pronominal. No teatro grego antigo, quando surgia os impasses, um ator interpretando uma divindade descia ao palco pendurado A num guindaste e resolvia-os.","b":"De acordo com especialistas, porém, o perigo não está nas criaturas que vem sendo criadas e, sim, na forma como os criadores usam-as.","c":"Ainda que não se perceba, há vários exemplos do dia a dia que mostra como a inteligência artificial vem influenciando- o bastante.","d":"Um grupo de cientistas pediram a moratória de pesquisas até alguma regulamentação ética da IA, talvez porque a IA lhes inquietou.","e":"Um dos que não acredita que a Inteligência Artificial ultrapassará o homem em astúcia é Ganascia, que a estuda há vários anos em Paris.","gabarito":"E","materia":"Português","tema":"Morfologia - Pronomes ,Colocação Pronominal","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2465156","enunciado":"","a":"Especialidade: Agente da Polícia Judicial conjunção “embora” substitui corretamente a expressão destacada em:","b":"A .. resolvia o problema e, assim, acabava a peça. No teatro grego antigo, quando não havia solução para um impasse...","c":"A inteligência artificial faz parte da rotina, ainda que não se perceba.","d":"Segundo especialistas, porém, o perigo não está na criatura...","e":"Então, as máquinas começaram a gerar imagens perfeitas de pessoas...","gabarito":"C","materia":"Português","tema":"Morfologia ,Conjunções: Relação de causa e consequência","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2465155","enunciado":"Especialidade: Agente da Polícia Judicial","a":"O termo destacado atribui sentido de indefinição ao substantivo em: Segundo especialistas, porém, o perigo não está na criatura e, sim, no uso que o criador faz dela.","b":"... resolvia o problema e, assim, acabava a peça. Era o Deus ex-machina – o deus surgido da máquina.","c":"... ninguém temia os mecanismos de busca dos navegadores, os sistemas de reconhecimento facial...","d":"... quando não havia solução para um impasse, um ator interpretando uma divindade descia ao palco...","e":"Não, garante um dos maiores especialistas no tema, o cientista da computação francês Jean-Gabriel Ganascia...","gabarito":"D","materia":"Português","tema":"Morfologia ,Substantivos","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2465153","enunciado":"","a":"Especialidade: Agente da Polícia Judicial expressão destacada contém termo(s) em sentido figurado em: o A ... e se ela era um atributo somente humano. (5 parágrafo)","b":"o ... ninguém temia os mecanismos de busca dos navegadores... (3 parágrafo)","c":"o ... descia ao palco pendurado num guindaste... (1 parágrafo)","d":"o ... resolver enigmas matemáticos em frações de segundos... (4 parágrafo)","e":"o ... o homem pode se perguntar qual lugar ocupará neste enredo. (2 parágrafo)","gabarito":"E","materia":"Português","tema":"Interpretação de Textos ,Figuras de Linguagem","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2465152","enunciado":"Especialidade: Agente da Polícia Judicial No desenvolvimento atual da inteligência artificial, o autor pondera que ela","a":"ganhou notoriedade na vida cotidiana, mas já tinha ampla divulgação na Antiguidade, como mostra o exemplo do teatro grego.","b":"atingiu limites preocupantes, de modo que um grupo de cientistas pediu moratória de pesquisas até alguma regulamentação ética de seus usos.","c":"assombra a maioria das pessoas, ainda que sua disseminação seja incipiente e de impacto limitado nas tarefas comuns do dia a dia.","d":"tem criado soluções duvidosas para o dia a dia dos seres humanos, razão pela qual passa despercebida na maioria das vezes.","e":"deixou de ter importância pelos critérios da tecnologia, uma vez que o aspecto mais debatido tem sido suas nuances filosóficas.","gabarito":"B","materia":"Português","tema":"Interpretação de Textos ,Noções Gerais de Compreensão e Interpretação de Texto","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2465151","enunciado":"Especialidade: Agente da Polícia Judicial No texto, afirma-se que o homem atualmente está vivendo sob o “deus algoritmo”. Para comprovar essa ideia, o autor","a":"recorre a situações da vida cotidiana, permeada pelos recursos da inteligência artificial.","b":"a exemplos de discussões clássicas, como os questionamentos de filósofos gregos.","c":"a declarações de Jean-Gabriel Ganascia, que vê os humanos sob domínio das máquinas.","d":"à existência de impasses, que não foram resolvidos pelo homem nem pelas máquinas.","e":"à falta de critérios científicos específicos para definir o que seja a inteligência artificial.","gabarito":"A","materia":"Português","tema":"Interpretação de Textos ,Noções Gerais de Compreensão e Interpretação de Texto","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2465150","enunciado":"Especialidade: Agente da Polícia Judicial Leia a tira para responder à questão.","a":"Assinale a alternativa em que a reescrita de informações da tira atende à norma-padrão. Me escreva um poema sobre mim, Franklin, no estilo de Paulo Leminski.","b":"Franklin, escreva um poema para mim ler, falando no estilo Paulo Leminski.","c":"Escreva-me um poema à Paulo Leminski que fale de mim, Franklin.","d":"Franklin, escreva um poema à meu respeito, no estilo de Paulo Leminski.","e":"Escreva um poema para eu à Paulo Leminski, falando sobre a minha pessoa.","gabarito":"C","materia":"Português","tema":"Interpretação de Textos ,Noções Gerais de Compreensão e Interpretação de Texto","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2465149","enunciado":"Especialidade: Agente da Polícia Judicial","a":"No primeiro e no terceiro quadros, a vírgula tem empregos diferentes, pois separa, correta e respectivamente, o aposto e o vocativo.","b":"o vocativo e o predicado.","c":"o sujeito e o vocativo.","d":"o vocativo e o aposto.","e":"o sujeito e o predicado.","gabarito":"D","materia":"Português","tema":"Pontuação ,Uso da Vírgula","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2465148","enunciado":"Especialidade: Agente da Polícia Judicial","a":"O efeito de humor na tira tem relação com o desconhecimento expresso pelo robô sobre o que seja poema.","b":"a indignação do robô diante do pedido de escrita de um poema.","c":"a incapacidade de o homem escrever um poema, omitida do robô.","d":"a resposta do robô, que mente ao afirmar desconhecer o que seja um poema.","e":"a burrice artificial do robô, mesmo tendo atendido ao pedido do homem.","gabarito":"A","materia":"Português","tema":"Interpretação de Textos ,Noções Gerais de Compreensão e Interpretação de Texto","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa -","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_875","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário - Área: Administrativa Conforme previsão expressa na CLT, mediante previsão em convenção ou acordo coletivo de trabalho, o contrato de trabalho poderá ser suspenso, para participação do empregado em curso ou programa de qualificação profissional","a":"oferecido pelo empregador, com duração equivalente à suspensão contratual, por um período de: um a seis meses, com aquiescência formal do empregado.","b":"dois a seis meses, independentemente da aquiescência do empregado.","c":"até cinco meses, sem a necessidade de aquiescência do empregado.","d":"dois a cinco meses, com aquiescência formal do empregado.","e":"até 12 meses, com aquiescência do empregado. Segurança e Saúde no Trabalho>","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário - Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2374324","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário - Área: Administrativa Com relação às atividades insalubres ou perigosas, assinale a alternativa correta nos termos da CLT.","a":"O trabalho em condições de periculosidade assegura ao empregado um adicional de 35% (trinta e cinco por cento) sobre o salário com os acréscimos resultantes de gratificações, prêmios ou participações nos lucros da empresa.","b":"Não poderão ser descontados ou compensados do adicional outros da mesma natureza eventualmente já concedidos ao vigilante por meio de acordo coletivo.","c":"Quando não for possível que a gestante ou a lactante afastada exerça suas atividades em local salubre na empresa, a hipótese será considerada como gravidez de risco e ensejará a percepção de salário-maternidade durante todo o período de afastamento.","d":"O Médico do Trabalho ou Engenheiro do Trabalho aprovará o quadro das atividades e operações insalubres e adotará normas sobre os critérios de caracterização da insalubridade, os limites de tolerância aos agentes agressivos, meios de proteção e o tempo máximo de exposição do empregado a esses agentes.","e":"A empregada gestante deverá ser afastada de atividades consideradas insalubres em grau máximo, médio ou mínimo, sem prejuízo de sua remuneração, perdendo o direito somente quanto ao valor do adicional de insalubridade enquanto durar seu afastamento.","gabarito":"C","materia":"NR 15 - Norma Regulamentadora n° 15 - Atividades e Operações Insalubres (Acústica","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário - Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2374323","enunciado":"Administrativa","a":"Sobre o aviso prévio, nos termos da CLT, assinale e alternativa correta. falta de aviso prévio por parte do empregado não dá ao empregador o direito de descontar os salários A","b":"correspondentes ao prazo respectivo. Não é devido o aviso prévio na despedida indireta.","c":"Tratando-se de salário pago na base de tarefa, o cálculo será feito de acordo com a média dos últimos 6 (seis) meses de serviço.","d":"O horário normal de trabalho do empregado, durante o prazo do aviso e se a rescisão tiver sido promovida pelo empregado, será reduzido de 4 (quatro) horas diárias, sem prejuízo do salário integral.","e":"Dado o aviso prévio, a rescisão torna-se efetiva depois de expirado o respectivo prazo, mas, se a parte notificante reconsiderar o ato, antes de seu termo, à outra parte é facultado aceitar ou não a reconsideração.","gabarito":"E","materia":"Direito do Trabalho","tema":"Aviso prévio ,Cessação do contrato de emprego","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário - Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2374322","enunciado":"Administrativa Assinale a alternativa correta nos termos da CLT.","a":"Sempre que uma ou mais empresas, tendo, embora, cada uma delas, personalidade jurídica própria, estiverem sob a direção, controle ou administração de outra, ou ainda quando, mesmo guardando cada uma sua autonomia, integrem grupo econômico, serão responsáveis solidariamente pelas obrigações decorrentes da relação de emprego.","b":"Sempre que uma ou mais empresas integrarem grupo econômico, serão responsáveis subsidiariamente pelas","c":"obrigações decorrentes da relação de emprego. Caracterizará grupo econômico a mera identidade de sócios entre empresas.","d":"Não caracteriza grupo econômico a mera identidade de sócios, ainda que haja a demonstração do interesse integrado, a efetiva comunhão de interesses e a atuação conjunta das empresas dele integrantes.","e":"O sócio retirante responde solidariamente pelas obrigações trabalhistas da sociedade relativas ao período em que figurou como sócio, nas ações ajuizadas até cinco anos depois de averbada a modificação do contrato.","gabarito":"A","materia":"Direito do Trabalho","tema":"Do Grupo, Da Sucessão e Da Responsabilidade dos Empregadores ,Das relações laborais","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário - Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2374321","enunciado":"Administrativa Sobre o Princípio da singularidade do Direito do Trabalho, assinale a alternativa correta.","a":"Expressa que para cada decisão é possível a interposição de apenas um recurso, ainda que cabível a interposição de","b":"Recurso Especial e Extraordinário. Também é conhecido como princípio da unirrecorribilidade.","c":"Norteia que os recursos não podem ser utilizados sucessivamente, mas sim simultaneamente, obedecendo-se à","d":"ordem de hierarquia dos órgãos jurisdicionais. É o princípio que autoriza a interposição de mais de um recurso referente à mesma decisão prolatada.","e":"A apresentação de novo recurso tratando da mesma matéria do anterior, que não fora recebido por intempestivo, não ferirá este princípio. Contabilidade Pública>Demonstrações Contábeis ,Demonstração de Fluxo de Caixa - DFC ,","gabarito":"B","materia":"Direito Processual do Trabalho","tema":"Sistema recursal trabalhista ,Princípios do Sistema Recusal Trabalhista","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário - Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2374320","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário - Área: Administrativa Uma determinada entidade pública apresentou, hipoteticamente, os seguintes valores extraídos da contabilidade em 31 de dezembro de 2023: Saldo em Espécie para o Exercício Seguinte ► R$ 130.630.000,00 Saldo em Espécie do Exercício Anterior ► R$ 115.200.000,00 Em 31 de dezembro de 2023, esses valores em reais representam, de acordo com as demonstrações","a":"contábeis aplicadas do setor público, resultado líquido dos fluxos de caixa das operações.","b":"resultado financeiro do exercício.","c":"fluxo de caixa das operações de financiamento.","d":"geração líquida de caixa e equivalente de caixa.","e":"capital circulante líquido.","gabarito":"B","materia":"Normas e Legislações de Contabilidade Pública","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário - Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2374319","enunciado":"Administrativa Uma entidade pública emitiu títulos públicos, sem cupons, em 31 de dezembro de 2022, no valor de R$5.000.000,00, para resgate em um ano, portanto considerado de curto prazo, e juros pós-fixados. Em 31 de janeiro de 2023, o valor dos juros calculados pelo índice estipulado em contrato foi de R$ 89.000,00.","a":"Nesse caso, a apropriação patrimonial dos encargos nesse primeiro mês será: D Juros e Encargos da Dívida Mobiliária C Debêntures e Outros Títulos de Dívida a Curto Prazo (P)","b":"D Crédito Disponível C Crédito Empenhado a Liquidar","c":"C Debêntures e Outros Títulos de Dívida a Curto Prazo – Juros e Encargos a Pagar","d":"Debêntures e Outros Títulos de Dívida juros e encargos – Dívida imobiliária","e":"D D Crédito Empenhado a Liquidar C Juro Empenhado em Liquidação D Disponibilidade por Destinação de Recursos C Juros e Encargos da Dívida Mobiliária","gabarito":"A","materia":"Contabilidade Pública","tema":"Normas e Legislações de Contabilidade Pública","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário - Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2374318","enunciado":"Administrativa Segundo os preceitos da contabilidade orçamentária e financeira, uma entidade pública deverá classificar os restos a pagar,","a":"excluídos os serviços da dívida, como contas a pagar serviços e insumos.","b":"dívida pública consolidada.","c":"dívida pública fundada.","d":"os serviços da dívida a pagar.","e":"dívida flutuante. Contabilidade Pública>Normas e Legislações de Contabilidade Pública ,","gabarito":"E","materia":"Contabilidade Pública","tema":"Ingressos e Dispêndios Públicos ,Dívida Pública: Flutuante e Consolidada","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário - Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_883","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário - Área: Administrativa Os ativos que normalmente podem ser conservados por um número significativamente maior de anos do que a maioria dos","a":"bens do ativo imobilizado são denominados ativos Patrimoniais.","b":"de infraestrutura.","c":"Públicos.","d":"de longo prazo.","e":"Permanentes.","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário - Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2374316","enunciado":"Administrativa No que tange à estrutura conceitual para elaboração e divulgação da informação contábil, é correto afirmar:","a":"todas as entidades governamentais dependem de dois tipos de informações financeiras, sendo (i) Estatísticas de Finanças Públicas do Setor Governo Geral, com o propósito de permitir a análise macroeconômica; e (ii) Demonstrações Contábeis de Propósito Geral para a responsabilização e tomada de decisão em relação à entidade.","b":"os objetivos da elaboração e divulgação da informação contábil estão relacionados exclusivamente ao controle orçamentário e de responsabilização das origens ao fornecimento de informações ao setor privado.","c":"no setor público, a principal razão de se manterem ativos imobilizados e outros ativos é voltada para o potencial de serviços desses ativos, e não para a sua capacidade de gerar fluxos de caixa.","d":"as características qualitativas da informação incluída nos Relatórios Contábeis de Propósito Geral são tempestividade, materialidade, competência, transparência e eficiência.","e":"governos e outras entidades do setor público podem manter itens que contribuam para o legado cultural e histórico da nação ou da região, como, por exemplo, eventos culturais e socioambientais.","gabarito":"C","materia":"Contabilidade Pública","tema":"Contabilidade Pública - Noções Introdutórias","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário - Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2374315","enunciado":"Administrativa No que tange aos métodos de previsão de demanda, é correto afirmar que","a":"devem ser táticos para aumentar a eficiência operacional, resultando em ganhos como redução de recursos e de custos.","b":"são direcionados para atender as generalidades de um negócio, como sazonalidades, durabilidade do produto e desafios logísticos.","c":"possibilitam acesso a informações sobre a demanda de um produto, comparando os resultados passados com previsões futuras para o setor.","d":"permitem visualizar, analisar e prever o padrão de consumo dos clientes, como também realizar as estimativas para o estoque.","e":"avaliam a inserção de estoque de novos produtos, de modo a criar um plano alternativo para mitigar situações de vulnerabilidade financeira.","gabarito":"D","materia":"Administração de Recursos Materiais","tema":"Classificação de Materiais ,Classificação por Tipo de Demanda","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário - Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2374314","enunciado":"","a":"Administrativa gestão patrimonial pode ser entendida como o balanço realizado para manter o controle de custos e o acompanhamento do patrimônio de uma organização, sendo o inventário patrimonial um dos instrumentos dessa gestão. Considerando-se o exposto, assinale a alternativa que está em desacordo com um dos objetivos desse inventário.","b":"A Embasar tomadas de decisões assertivas e seguras aos gestores, visando evitar ou minimizar prejuízos financeiros. Viabilizar, tempestivamente, informações aos órgãos fiscalizadores, quando solicitadas.","c":"Verificar a existência e a localização física dos bens, assim como o estado de conservação e perfeita caracterização desses.","d":"Propiciar a correta contabilização dos passivos permanentes, permitindo a confrontação dos registros patrimoniais com os financeiros.","e":"Oportunizar a regularização das inconsistências e permitir a apuração de responsabilidades quando se fizer necessário. Administração de Recursos Materiais>Classificação de Materiais ,","gabarito":"D","materia":"Administração de Recursos Materiais","tema":"Armazenagem ,Inventários","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário - Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_887","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário - Área: Administrativa As organizações podem adotar vários tipos de classificação de materiais, dependendo do mercado em que atuam e dos seus objetivos. A classificação denominada de “Curva ABC”","a":"é utilizada para determinar a importância dos materiais em decorrência do valor expresso pelo próprio consumo em determinado período.","b":"objetiva verificar se os materiais utilizados são de fácil ou difícil aquisição, visando agilizar a reposição e evitar a falta deles.","c":"avalia o grau de criticidade ou de dificuldade para a obtenção do material, considerada a sua importância operacional para a organização.","d":"considera os materiais de reposição específica, em que demanda não é previsível e a decisão de estocar tem como premissa o risco.","e":"se refere ao critério que evidencia a popularidade dos materiais em estoque, consideradas as suas movimentações durante um certo período.","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário - Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2374312","enunciado":"Administrativa Quando a licitação envolver o fornecimento de bens, uma das hipóteses em que a Administração Pública poderá, excepcionalmente, indicar uma ou mais marcas ou modelos, desde que isso seja que formalmente justificado é","a":"resultante de padronização do objeto, observada a identificação de determinada marca ou de modelos utilizados apenas como referência.","b":"decorrente de declaração de atendimento satisfatório emitida por outro órgão de nível federativo equivalente ao que tenha adquirido o referido produto.","c":"o aproveitamento das peculiaridades do mercado local, visando sempre que possível a economicidade, desde que observados os parâmetros de qualidade.","d":"devido à necessidade de alterar a compatibilidade com plataformas e sistemas informatizados já adotados pelas entidades administrativas.","e":"quando determinada marca ou modelo comercializados por mais de um fornecedor são os únicos capazes de atender às necessidades do contratante.","gabarito":"E","materia":"Direito Administrativo","tema":"Licitações e Lei nº 14.133 de 2021","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário - Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2374311","enunciado":"Administrativa Com relação ao Lote Econômico de Compra, é correto afirmar que","a":"é um modelo matemático que visa definir a quantidade ideal de produtos a ser comprada por lote com o objetivo de encontrar o equilíbrio entre as vantagens e as desvantagens de manter o estoque, minimizando o custo total.","b":"gira em torno de um ponto referencial, visando uma economia na compra de um determinado produto e que compreende o menor custo total quando ocorre uma divergência entre o custo do pedido e o custo de posse.","c":"é a quantidade de um determinado produto em estoque que, ao ser atingida, não requer um novo pedido de compra, uma vez que não contribui para a garantia da continuidade do processo produtivo.","d":"é um indicador que reflete a quantidade média de produtos adquiridos por lote, pressupondo a variação da demanda, que não é uniforme, e os descontos aplicados aos custos variáveis de estoque.","e":"é uma metodologia que se refere à quantidade de material a ser adquirido para obtenção do mínimo custo total, desconsiderando-se as despesas de armazenagem, os juros do capital empatado, a falta de estoque e as despesas gerais de compra.","gabarito":"A","materia":"Logística","tema":"Lote Econômico de Compra","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário - Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2374310","enunciado":"Administrativa As organizações estão cada vez mais interessadas em localizar e distinguir suas competências e, dessa forma, têm criado categorias distintivas. Para que uma competência seja incluída na categoria essencial à organização, ela precisa atender simultaneamente a três condições. Escolha a alternativa que apresenta corretamente essas condições.","a":"Ser alicerce para variadas atividades da organização; demonstrar fácil adaptação às exigências do ambiente interno; ser pouco ligada às vantagens competitivas para a organização.","b":"Ser desvinculada do aprendizado dos funcionários da organização; servir de base especificamente para os serviços e produtos atuais; ser dependente do estímulo efetuado pelas lideranças organizacionais.","c":"Agregar valor de forma consistente aos seus clientes; ser capaz de diferenciar e distanciar a organização de seus concorrentes; ter capacidade de expansão, favorecendo o futuro crescimento da organização.","d":"Ter valor percebido pelos funcionários; ser pouco diferenciada frente às empresas competidoras; ter capacidade de sustentar a manutenção dos produtos e serviços existentes.","e":"Caracterizar-se como uma habilidade isolada; ser basicamente representada pelos processos de racionalização do trabalho; ser capaz de propiciar uma profunda reflexão individual. Gestão de Pessoas>Comportamento de Pessoas nas Organizações ,","gabarito":"C","materia":"Gestão de Pessoas","tema":"Gestão de Competências","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário - Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_891","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário - Área: Administrativa Você trabalha em uma grande empresa hoteleira, a Great, como consultor interno de Recursos Humanos. Tal empresa tem adquirido gradualmente várias redes hoteleiras. No momento, um grande desafio enfrentado na condução do negócio é a diferença cultural entre as organizações adquiridas pela Great. Enquanto esta é uma empresa dinâmica e empreendedora, as empresas adquiridas, que agora estão em processo de fusão com a nova empresa proprietária, se caracterizam por uma","a":"cultura tradicionalista, paternalista e autocrática. Direção da empresa pede que você mostre um caminho que resolva da melhor forma possível o problema em questão. Aponte, entre as alternativas a seguir, a que representa a melhor medida a ser tomada prioritariamente. Evitar informações sobre histórias e folclore organizacional, uma vez que dificultam a compreensão da missão, visão e A valores básicos da organização.","b":"Investir, especialmente entre os funcionários que vieram das empresas adquiridas, na aprendizagem de valores, em normas e padrões de comportamento, por meio da socialização organizacional.","c":"Definir e estimular, junto ao corpo gerencial, a ocorrência de práticas que permitam emergir os valores organizacionais predominantes entre os funcionários que pertenciam às empresas adquiridas.","d":"Implementar ações nas áreas operacionais da empresa, de modo a facilitar a comunicação dos trabalhadores sobre os","e":"novos objetivos organizacionais. Realizar cursos ou treinamentos voltados a ampliar os conhecimentos técnicos de todos os membros da organização.","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário - Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2374308","enunciado":"Administrativa Assinale a alternativa em que todos os procedimentos citados são considerados técnicas de seleção de pessoas, geralmente utilizadas para a escolha dos ocupantes de cargos nas organizações.","a":"Contatos com escolas e universidades, recrutamento externo, autoavaliação do candidato, indicação feita por","b":"funcionários. Recrutamento virtual, quadro de avisos na portaria, consulta aos arquivos de candidatos, entrevista de triagem.","c":"Entrevista preliminar, entrevista técnica, testes de aptidões, técnicas de simulação.","d":"Anúncios em jornais e revistas, descrição de cargo, avaliação de desempenho, entrevista de desligamento.","e":"Análise de cargo, quadro de avisos na portaria, anúncio em empresas de consultoria, redação de um texto técnico.","gabarito":"C","materia":"Gestão de Pessoas","tema":"Recrutamento e Seleção ,Agregando Pessoas","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário - Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2374307","enunciado":"Administrativa Existem diversas teorias sobre motivação. Uma delas é a primeira das teorias de motivação relacionadas com o processo motivacional. Tem como base a comparação que comumente as pessoas fazem a respeito de suas contribuições à organização e de suas recompensas recebidas, em relação às contribuições e recompensas dos outros.","a":"Trata-se da teoria das necessidades adquiridas, de McClelland.","b":"da expectância, de Vroom.","c":"da hierarquia das necessidades, de Maslow.","d":"da equidade, de Adams.","e":"da definição de objetivos, de Locke. Gestão de Pessoas>Administração de Recursos Humanos em Gestão de Pessoas ,","gabarito":"D","materia":"Administração Geral","tema":"Gestão Estratégica ,Liderança e Motivação","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário - Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_894","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário - Área: Administrativa Em decorrência da competitividade acirrada gerada pelo desenvolvimento tecnológico e pelo processo de globalização das últimas décadas, a forma de administrar em geral, incluída a gestão de pessoas, vem-se modificando significativamente nas organizações, fazendo com que","a":"os trabalhadores de modo geral tenham menor necessidade de saber se relacionar com as pessoas no contexto organizacional, dado que um maior nível de conhecimento técnico torna menos relevantes as questões ligadas ao relacionamento humano.","b":"a Gestão de Pessoas, que é a observação e o acompanhamento do comportamento humano nas organizações, tenha sua importância reduzida, dada a facilidade em se encontrar profissionais com bom preparo no emprego de novas tecnologias de informação.","c":"as empresas dediquem menos tempo a atividades de integração de pessoas e grupos, uma vez que o engajamento das pessoas em seu ambiente de trabalho tem ocorrido mais naturalmente, ou seja, sem a necessidade de o corpo diretivo investir em ações com tal objetivo.","d":"seus dirigentes busquem novas alternativas para gerir pessoas, cujo grande desafio é reconhecer em cada colaborador a sua individualidade e saber gerenciá-lo dentro desse ambiente de diversidade.","e":"ocorra, por parte dos gestores, uma menor preocupação em harmonizar as necessidades dos funcionários com as da organização, bem como menor ênfase em desenvolvimento pessoal e profissional, de modo a tornar cada colaborador responsável por seu desenvolvimento.","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário - Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2374305","enunciado":"","a":"Administrativa abertura de modalidade de crédito adicional destinado ao reforço de dotação orçamentária já existente no orçamento é uma das ressalvas ao princípio orçamentário","b":"A do orçamento bruto. da unidade ou totalidade.","c":"da universalidade.","d":"da não-vinculação.","e":"da exclusividade.","gabarito":"E","materia":"Administração Financeira e Orçamentária","tema":"Princípios Orçamentários","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário - Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2374304","enunciado":"Administrativa O Poder Executivo deve destinar os recursos correspondentes às dotações orçamentárias, inclusive os créditos","a":"suplementares e especiais, em duodécimos, aos órgãos do Poder Judiciário, até o dia 20 de cada mês.","b":"15 de cada mês.","c":"5 de cada mês.","d":"10 de cada mês.","e":"1º de cada mês. Administração Financeira e Orçamentária>Despesa Pública ,","gabarito":"A","materia":"Administração Financeira e Orçamentária","tema":"Créditos Adicionais","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário - Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_897","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário - Área:","a":"Administrativa União apresentou, em determinado período de apuração, receita corrente líquida (RCL) no valor de R$ 1 bilhão. Assim, o limite da despesa total com pessoal do Poder Judiciário federal é de","b":"A R$ 30 milhões. R$ 20 milhões.","c":"R$ 2 milhões.","d":"R$ 60 milhões.","e":"R$ 6 milhões. Contabilidade Pública>Contabilidade Pública - Noções Introdutórias ,Ingressos e Dispêndios Públicos ,","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário - Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_898","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário - Área: Administrativa No ano passado, um órgão do Poder Judiciário realizou a aquisição de computadores. Dito isso, é correto afirmar que se","a":"essa despesa foi empenhada e não liquidada no exercício financeiro da aquisição, ela foi inscrita em restos a pagar processados.","b":"liquidada e paga no exercício financeiro da aquisição, ela foi inscrita em restos a pagar não processados.","c":"liquidada e não paga no exercício financeiro da aquisição, ela foi inscrita em restos a pagar processados.","d":"não liquidada e não paga no exercício financeiro da aquisição, ela foi inscrita em restos a pagar processados.","e":"empenhada, liquidada e paga no exercício financeiro da aquisição, ela foi inscrita em restos a pagar processados.","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário - Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2374301","enunciado":"Administrativa","a":"Configura-se como um exemplo de dívida ativa tributária o crédito da Fazenda Pública proveniente de descumprimento de contrato com a União.","b":"custa processual.","c":"Fundo de Garantia do Tempo de Serviço.","d":"Imposto de Renda.","e":"multa trabalhista.","gabarito":"D","materia":"Contabilidade Geral","tema":"Legislação Tributária na Contabilidade Geral ,Regulamento do Imposto de Renda - RIR","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário - Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2374300","enunciado":"Administrativa Um órgão público necessita redesenhar seus processos e escolheu uma notação de modelagem de processos que","a":"contempla elementos como atividades, eventos, decisões, piscinas, raias e conectores, sendo conhecida como PDCA.","b":"BPMN.","c":"5W2H.","d":"GUT","e":"SWOT.","gabarito":"B","materia":"Modelagem de Processos de Negócio (BPM)","tema":"Balanced Scorecard em BPM","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário - Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2374299","enunciado":"Administrativa Na gestão de um importante projeto público, uma equipe de trabalho reúne-se diariamente, por no máximo 15 minutos, e cada integrante responde a questões como “o que eu fiz ontem?”, “o que eu vou fazer de agora em diante?” e “existe algum","a":"impedimento para realizar minhas atividades?”. Essa atividade diz respeito a uma das características da metodologia ágil: Lean.","b":"Kanban.","c":"Feature-driven Development (FDD).","d":"eXtreme Programming (XP).","e":"Scrum.","gabarito":"E","materia":"Administração Pública","tema":"Gestão por Processos","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário - Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2374298","enunciado":"Administrativa Com vistas a permitir maior celeridade na gestão processual, a adoção de um novo sistema vem sendo discutida em um órgão do Poder Judiciário. Para ajudar nessa decisão, foi utilizada uma técnica de representação gráfica de alternativas,","a":"incluindo as probabilidades dos resultados associados a cada uma das alternativas, denominada Árvore de Decisão.","b":"Diagrama de Ishikawa.","c":"Matriz de Prioridades.","d":"Diagrama de Pareto.","e":"Método de Delineamento de Problemas Organizacionais (MDPO).","gabarito":"A","materia":"Administração Geral","tema":"Processo Decisório ,Conceitos e Métodos do Processo Decisório","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário - Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2374297","enunciado":"Administrativa Qual teoria da liderança situacional defende que quanto mais maduro o seguidor, menos intenso deve ser o uso da autoridade pelo líder e mais intensa a orientação para o relacionamento, e, inversamente, quanto mais imaturo o seguidor,","a":"maior intensidade no uso da autoridade, com menor ênfase no relacionamento? Modelo de Hersey-Blanchard.","b":"Modelo de Fiedler.","c":"Modelo de Tannenbaum e Schmidt.","d":"Grade Gerencial de Blake e Mouton.","e":"Teoria dos Traços de Liderança.","gabarito":"A","materia":"Administração Geral","tema":"Gestão Estratégica ,Liderança e Motivação","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário - Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2374296","enunciado":"Administrativa Na repartição, há um servidor que sempre se coloca como o detentor da única e melhor forma de realizar a gestão. Em contrapartida, há outro que considera que sempre há mais de um modo de alcançar determinado objetivo. Este último","a":"modo de enxergar as questões organizacionais é um dos preceitos trazidos pela teoria estruturalista.","b":"científica.","c":"das relações humanas.","d":"contingencial.","e":"dos sistemas.","gabarito":"D","materia":"Administração Geral","tema":"Organizações, Sistemas e Métodos ,Estrutura Organizacional na Administração Geral","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário - Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2374295","enunciado":"","a":"Administrativa extinção de ato administrativo válido por motivo de interesse público superveniente que o torna inconveniente ou inoportuno denomina-se invalidação, gera efeitos ex nunc e está sujeita ao controle tanto da Administração Pública quanto do Poder Judiciário, A","b":"por envolver matéria de mérito. revogação, gera efeitos ex tunc e atinge atos administrativos vinculados, em razão do princípio da autotutela.","c":"revogação, gera efeitos ex nunc e é declarada de ofício pela Administração Pública e atinge atos administrativos discricionários.","d":"invalidação, gera efeitos ex nunc e está sujeita ao controle exclusivo da Administração Pública, em razão do princípio da autotutela.","e":"invalidação, gera efeitos ex tunc e está sujeita ao controle exclusivo do Poder Judiciário, por envolver matéria de mérito. Direito Administrativo>Lei nº 8.112-1990 - Regime jurídico dos servidores públicos federais ,","gabarito":"C","materia":"Direito Administrativo","tema":"Atos administrativos ,Conceito e classificação dos atos administrativos","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário - Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_906","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário - Área: Administrativa Acerca do Processo Administrativo Disciplinar, segundo o regramento que lhe é conferido pela Lei nº 8.112/1990, é correto afirmar que","a":"o processo disciplinar poderá ser revisto, dentro do prazo de cinco anos contados da publicação da decisão, a pedido ou de ofício quando se aduzirem fatos novos ou circunstâncias suscetíveis de justificar a inocência do punido, constituindo, a simples alegação de injustiça da penalidade, fundamento para a revisão.","b":"o processo administrativo disciplinar será conduzido por uma comissão composta por três servidores ocupantes de cargo efetivo ou em comissão designados pela autoridade competente que escolherá, dentre eles, o presidente que poderá ser servidor de cargo efetivo ou em comissão, desde que seja do mesmo nível do indiciado. os autos da sindicância integrarão o processo disciplinar, como peça informativa da instrução e, na hipótese de o","c":"relatório da sindicância concluir que a infração está capitulada como ilícito penal, a autoridade competente encaminhará cópia dos autos ao Ministério Público, caso em que será imprescindível a imediata instauração do processo disciplinar.","d":"o prazo para a conclusão do processo disciplinar não excederá 45 (quarenta e cinco) dias, contados da data da publicação do ato que constituir a comissão, admitida a sua prorrogação, por igual prazo, quando as circunstâncias exigirem.","e":"julgada procedente a revisão do processo administrativo disciplinar, será declarada sem efeito a penalidade aplicada, restabelecendo-se todos os direitos do servidor, exceto em relação à destituição do cargo em comissão, que será convertida em exoneração.","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário - Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2374293","enunciado":"Administrativa Considerando as disposições da Lei nº 8.249/1992, no que se refere ao instituto da prescrição, assinale a alternativa correta.","a":"O inquérito civil para apuração do ato de improbidade será concluído no prazo improrrogável de 360 dias úteis, mediante ato fundamentado submetido à revisão da instância competente do órgão ministerial, conforme dispuser o regulamento.","b":"Nas ações e nos acordos por ela regidos não haverá adiantamento de custas de preparo, de emolumentos, de honorários periciais e de quaisquer outras despesas.","c":"A instauração de inquérito civil ou processo administrativo para apuração dos ilícitos aos quais se refere interrompe o curso do prazo prescricional por, no máximo 180 dias úteis, iniciando sua contagem, por inteiro, após sua conclusão ou, caso não concluído o processo, esgotado o prazo de interrupção.","d":"A ação para aplicação das sanções nela previstas prescreve em 5 anos, contados a partir da ocorrência do fato ou, no caso de infrações permanentes, do dia em que cessou a permanência.","e":"O prazo prescricional de 10 anos se suspende pela publicação de decisão ou acórdão do Superior Tribunal de Justiça que confirma acórdão condenatório ou que reforma acórdão de improcedência. Direito Administrativo>Lei nº 8.112-1990 - Regime jurídico dos servidores públicos federais ,","gabarito":"B","materia":"Direito Administrativo","tema":"Improbidade administrativa - Lei nº 8.429 de 1992 e Lei nº 14.230 de 2021","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário - Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_908","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Prova: VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário - Área: Administrativa De acordo com Lei nº 8.112/1990, no que se refere às vantagens que se estabelecem em relação ao servidor, é correto afirmar que","a":"aquele que, não sendo servidor da União, for nomeado para cargo em comissão, com mudança de domicílio, será concedida ajuda de custo.","b":"havendo percepção de auxílio-moradia pelo servidor, no caso de falecimento, exoneração, colocação de imóvel funcional à disposição, o auxílio continuará a ser pago por 90 dias.","c":"o servidor que se deslocar dentro da mesma região metropolitana, aglomeração urbana ou microrregião, constituídas de municípios limítrofes, independentemente de haver pernoite fora da sede, fará jus a diárias.","d":"quando, por força das atribuições que sejam próprias do cargo, o servidor realizar despesas com a utilização de meio próprio de locomoção para execução de serviços externos, será indevida a indenização de transporte.","e":"o servidor que trabalhe com habitualidade em local, concomitantemente, insalubre e perigoso, fará jus, cumulativamente, aos adicionais de insalubridade e periculosidade.","gabarito":"","materia":"Geral","tema":"","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário - Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2374290","enunciado":"","a":"Administrativa Constituição Federal estabelece que se o Presidente do Tribunal retardar a liquidação regular de precatórios, incorrerá em crime de responsabilidade, e responderá, também, perante o Conselho Nacional de Justiça, desde que A","b":"sua conduta tenha sido dolosa. responderá por falta disciplinar e, ainda, por crime de responsabilidade, desde que tenha havido conduta comissiva.","c":"ficará sujeito à pena de exoneração do cargo e responderá por ato de improbidade administrativa, seja por ato omissivo ou comissivo.","d":"incorrerá em crime de responsabilidade e responderá, também, perante o Conselho Nacional de Justiça, por ato comissivo ou omissivo.","e":"ficará sujeito à pena de exoneração do cargo e responderá por ato de improbidade administrativa, desde que a sua conduta tenha sido dolosa.","gabarito":"D","materia":"Direito Constitucional","tema":"Disposições Gerais no Poder Judiciário ,Poder Judiciário","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário - Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2374289","enunciado":"Administrativa Considerando o disposto na Constituição Federal no tocante às normas que regulam a promoção dos magistrados, é correto afirmar que","a":"na apuração de antiguidade, o tribunal somente poderá recusar o juiz mais antigo pelo voto fundamentado da maioria","b":"absoluta de seus membros. é obrigatória a promoção do juiz que figure por três vezes consecutivas ou cinco alternadas em lista de merecimento.","c":"a promoção por merecimento pressupõe três anos de exercício na respectiva entrância e integrar o juiz a primeira quinta parte da respectiva lista de antiguidade.","d":"a aferição do merecimento se dará pelo desempenho e pelos critérios subjetivos de produtividade e excelência no exercício da jurisdição.","e":"não será promovido o juiz que, injustificadamente, retiver autos em seu poder além do prazo legal, devendo devolvê- los ao cartório em 24 horas, ainda que sem despacho ou decisão.","gabarito":"B","materia":"Direito Constitucional","tema":"Disposições Gerais no Poder Judiciário ,Poder Judiciário","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário - Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2374288","enunciado":"Administrativa Determinado município encaminhou pedido à Justiça Eleitoral para que nas próximas eleições municipais seja realizada, concomitantemente, uma consulta popular sobre uma questão de interesse local. Nessa situação hipotética, considerando","a":"o disposto na Constituição Federal, assinale a alternativa que representa a correta resposta ao referido pleito municipal. consulta não poderá ser realizada concomitantemente com as eleições, para evitar vício eleitoral, devendo ser A realizada em momento distinto, até 6 (seis) meses antes ou depois do pleito eleitoral.","b":"A consulta popular deverá ser aprovada pela Câmara Municipal e encaminhada à Justiça Eleitoral até 6 (seis) meses antes da data das eleições, observados os limites operacionais relativos ao número de quesitos.","c":"A consulta popular poderá ser realizada, e as manifestações favoráveis e contrárias às questões ocorrerão durante as campanhas eleitorais, com a utilização de propaganda gratuita no rádio e na televisão.","d":"A consulta popular poderá ser realizada, mas as manifestações favoráveis e contrárias às questões ocorrerão fora do período das campanhas eleitorais, com a utilização de propaganda gratuita no rádio e na televisão.","e":"A consulta popular deverá ser aprovada pela Câmara Municipal e encaminhada à Justiça Eleitoral até 90 (noventa) dias antes da data das eleições, observados os limites operacionais relativos ao número de quesitos.","gabarito":"E","materia":"Direito Constitucional","tema":"Direitos Políticos","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário - Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2374287","enunciado":"Administrativa Assinale a alternativa que está em conformidade com a Constituição Federal no que tange aos direitos e garantias fundamentais.","a":"Nenhum brasileiro será extraditado, salvo o naturalizado por crime comum, nem o estrangeiro que tenha contraído matrimônio com brasileira ou tenha filho brasileiro.","b":"Viola o princípio constitucional do juiz natural convocação de desembargadores para atuar nos tribunais superiores, com base em Regimento Interno.","c":"O particular, como cidadão, não tem legitimidade para impetrar mandado de segurança em face da Mesa do Senado na defesa de interesse de toda a coletividade.","d":"O sigilo profissional e a inviolabilidade domiciliar, constitucionalmente assegurados, vedam o cumprimento de mandado de busca e apreensão em escritório de advocacia.","e":"A vedação de prisão civil por dívida alcança o responsável pelo inadimplemento voluntário e inescusável de obrigação alimentícia, mas protege o depositário infiel.","gabarito":"C","materia":"Direito Constitucional","tema":"Teoria dos Direitos Fundamentais","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário - Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2374286","enunciado":"Administrativa","a":"Considerando a doutrina sobre a aplicabilidade das normas constitucionais, assinale a alternativa correta. Constituição Federal, pelo seu elevado grau de aplicabilidade, não contempla as denominadas normas A constitucionais de princípio institutivo.","b":"A vedação de servidor, participante de regime próprio, filiar-se ao regime geral de previdência social como segurado facultativo é norma de eficácia plena.","c":"O direito ao salário-família pago em razão do dependente do trabalhador de baixa renda é norma constitucional de","d":"eficácia plena. O procedimento de criação de municípios, estabelecido na CF, é exemplo de norma constitucional de eficácia contida.","e":"A norma constitucional que assegurou autonomia funcional e administrativa às Defensorias Públicas Estaduais é de eficácia contida. Direito Administrativo>Lei nº 8.112-1990 - Regime jurídico dos servidores públicos federais ,","gabarito":"B","materia":"Direito Constitucional","tema":"Teoria da Constituição ,Classificação das Normas Constitucionais","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário - Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_914","enunciado":"Ano: 2023 Banca: VUNESP Órgão: TRF - 3ª REGIÃO Provas: VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade: Contadoria ... Hermes é servidor público federal e, injustificadamente, recusou-se a ser submetido à inspeção médica determinada pela autoridade competente. Nessa situação hipotética, considerando o disposto na Lei nº 8.112/90, no tocante às penalidades disciplinares cabíveis, é","a":"correto afirmar que Hermes está sujeito à suspensão de até 30 (trinta) dias, sendo vedada a conversão da penalidade em multa.","b":"suspensão de até 15 (quinze) dias, mas, por conveniência do serviço, a penalidade poderá ser convertida em multa,","c":"ficando obrigado a permanecer em serviço. suspensão de até 15 (quinze) dias, sendo vedada a conversão da penalidade em multa.","d":"advertência e, não atendida a determinação pela segunda vez, multa de até 50% (cinquenta por cento) por dia de","e":"vencimento ou remuneração. advertência e, não atendida a determinação pela segunda vez, suspensão por até 30 (trinta) dias.","gabarito":"","materia":"Geral","tema":"","origem":"","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO Provas: VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade:","concurso":"TRF3"},{"id":"Q2374280","enunciado":"Administrativa Uma senha de seis dígitos, todos numéricos, corresponde ao 10º elemento da seguinte sequência numérica: 2, 11, 47, 191, 767, 3071, ... Considerando-se que a senha seja mpqxyz, em que m, p, q, x, y, z representam os algarismos","a":"dessa senha, o número que representa y é 7.","b":"5.","c":"3.","d":"1.","e":"9.","gabarito":"C","materia":"Raciocínio Lógico","tema":"Problemas Lógicos","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário - Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2374279","enunciado":"Administrativa Considere a seguinte afirmação: “Existe, pelo menos, um candidato que, se ele não dormiu bem à noite, então não foi aprovado no concurso.”","a":"Uma negação lógica para a afirmação apresentada é: Todos os candidatos não dormiram bem à noite e foram aprovados no concurso.","b":"Existe candidato que, se foi aprovado no concurso, então dormiu bem à noite.","c":"Não existe candidato que não dormiu bem à noite e foi aprovado no concurso.","d":"Existe mais de um candidato que, se ele não dormiu bem à noite, então não foi aprovado no concurso.","e":"Todos os candidatos dormiram bem à noite e foram aprovados no concurso.","gabarito":"A","materia":"Raciocínio Lógico","tema":"Fundamentos de Lógica ,Proposições Simples e Compostas e Operadores Lógicos","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário - Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2374278","enunciado":"Administrativa Considere verdadeiras as seguintes afirmações: I. Se o evento é hoje, então descansei ontem. II. O evento não é hoje ou amanhã vou descansar. III. Ou estudo hoje ou não descansarei amanhã. IV. Não descansarei amanhã.","a":"Uma conclusão verdadeira que se pode extrair das informações apresentadas é: Estudo hoje.","b":"Não estudo hoje.","c":"Não descansei hoje.","d":"O evento é hoje.","e":"Descansei ontem.","gabarito":"B","materia":"Raciocínio Lógico","tema":"Problemas Lógicos","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário - Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q2374277","enunciado":"Contadoria ... Três terrenos retangulares, um ao lado outro, têm as laterais com a mesma medida. O primeiro terreno tem a medida de frente correspondente a 3 m a menos que metade da medida lateral; o segundo terreno tem medida de frente correspondente à quinta parte da medida lateral; e o terceiro terreno tem 9 m a mais de frente que tem o segundo terreno. 2 Sabendo-se que a média aritmética simples das áreas dos três terrenos é 850 m , a medida da frente do primeiro terreno é","a":"de 18 m.","b":"19 m.","c":"22 m.","d":"20 m.","e":"21 m.","gabarito":"C","materia":"Matemática","tema":"Aritmética e Problemas ,Médias","origem":"","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO Provas: VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade:","concurso":"TRF3"},{"id":"Q2374276","enunciado":"Contadoria ... O preço unitário de venda de um produto, que era praticado em 2020, teve um único aumento, em 2021, de 10%. Em 2022, foi concedido, sobre o preço de venda reajustado em 2021, um único desconto de 5%.","a":"É correto afirmar que o desconto concedido em 2022 correspondeu, do preço do produto que era praticado em 2020, a: 4,5%","b":"5,0%","c":"6,0%","d":"6,5%","e":"5,5%","gabarito":"E","materia":"Matemática","tema":"Aritmética e Problemas ,Porcentagem","origem":"","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO Provas: VUNESP - 2024 - TRF - 3ª REGIÃO - Analista Judiciário - Especialidade:","concurso":"TRF3"},{"id":"Q2374275","enunciado":"Administrativa Minha empregada, Mme. Thérèse, que já ia se conformando em ser chamada de dona Teresa, caiu doente. Mandou- me um bilhete com a letra meio trêmula, falando em reumatismo. Dias depois apareceu, mas magra, mais pálida e menor; explicou-me que tudo fora consequência de uma corrente de ar. Que meu apartamento tem um courant d’air terrível, de tal modo que, __________ , chegando em casa, nem teve coragem de tirar a roupa, caiu na cama. “Dói-me o corpo inteiro, senhor; o corpo inteiro.” O mesmo caso, ajuntou, houve cerca de 15 anos atrás, quando trabalhava em um apartamento que tinha uma corrente de ar exatamente igual _____ essa de que hoje sou sublocatário. Fez uma pausa. Fungou. Contou o dinheiro que eu lhe entregava, agradeceu ______ dispensa do troco. Foi lá dentro apanhar umas pobres coisas que deixara. Entregou-me a chave, fez qualquer observação sobre o aquecedor _____ gás – e depois, no lugar de sair _____ rua, deixou-se ficar imóvel e calada, de pé, em minha frente. (Rubem Braga, “Dona Teresa”. 200 crônicas escolhidas. Adaptado) Nos enunciados reescritos a partir das informações do texto, a colocação pronominal e a regência atendem à norma- padrão em:","a":"Dona Teresa me contou que, há cerca de 15 anos atrás, tinha exposto-se em uma corrente de ar em um outro","b":"apartamento. Não fosse a corrente de ar que lhe acometera, Mme. Thérèse já teria-se conformado em ser chamada de dona Teresa.","c":"Eu entreguei o dinheiro a dona Teresa, ela contou-o. Depois foi lá dentro apanhar umas pobres coisas que se esquecera.","d":"Quando voltou, Mme. Thérèse informou-me de que sua debilidade era proveniente de uma corrente de ar no meu apartamento.","e":"Dona Teresa certamente vira-se abalada com a corrente de ar, pois veio no meu apartamento magra, mais pálida e menor. Filosofia do Direito>A Filosofia do Direito em Diferentes Momentos Históricos ,","gabarito":"D","materia":"Português","tema":"Sintaxe ,Regência ,Morfologia - PronomesColocação Pronominal","origem":"VUNESP - 2023 - TRF - 3ª REGIÃO - Analista Judiciário - Área:","ano":"2023","banca":"VUNESP Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_921","enunciado":"Ano: 2022 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto Adequada leitura do contexto social é fundamental na tomada de decisão pelos juízes federais. Foquemos no uso pela hermenêútica constitucional do princípio da proporcionalidade “lato sensu”. O olhar externo da “sociologia compreensiva” permite colocar a atuação decisória do juiz em plano mais amplo, o da ação social: i)As pessoas são capazes de interpretar suas realidades sociais (valores, crenças, emoções, costumes, poder etc.) e de a elas atribuir sentido; ii) têm capacidade de levar em conta os fins, os meios e as consequências — inclusive secundárias — de seus atos; iii) identicamente são hábeis a agir em conformidade a valores — pela crença no valor em si de determinadas condutas (ética, estética, religiosa etc.), independentemente do sucesso pessoal, iv) atuam, também, determinadas por afetos e estados sentimentais e/ou movidas pela tradição — hábitos, costumes, cotidiano. Em suma, temos o pluralismo dos motivos na ação social. À hermenêutica judicial motiva-se apenas em parte dos tópicos acima, restando ainda em aberto ou em construção o papel dos afetos e emoções. Pois bem, o sociólogo que desenvolve essa sociologia compreensiva, utilizada como pano de fundo para a","a":"abordagem acima da intepretação constitucional, é: Émile Durkheim.","b":"Auguste Comte.","c":"Max Weber.","d":"Niklas Luhmann. Filosofia do Direito>A Filosofia do Direito em Diferentes Momentos Históricos ,","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_922","enunciado":"Ano: 2022 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto É comum aos juízes estarem diante dos chamados “casos dificeis”. Nesse tema, um dos grandes debates que ainda se desenvolve na Teoria do Direito é aquele referente à existência (ou não) de discricionariedade judicial para definir o Direito das partes nos hard cases. Uma dessas perspectivas sustenta que o Direito é um fenômeno basicamente comunicacional e que a linguagem jurídica tem inevitavelmente textura aberta, o que propicia o surgimento de casos difíceis, hipótese em que não é possível a identificação do Direito com singela aplicação do método da subsunção. Nessa visão, métodos clássicos de interpretação não são suficientes para a tomada de decisão e só há um caminho ao juiz: realizar interpretação","a":"estipulando um novo significado de maneira discricionária. Essa perspectiva da teoria do Direito é sustentada pelo: Jusnaturalismo de John Finnis.","b":"Positivismo de Herbert Hart.","c":"Pós-positivismo de Ronald Dworkin.","d":"Agir comunicativo em Habermas.","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1959593","enunciado":"Maria foi durante muitos anos ativista de uma ONG ambiental. Morava com a companheira Monique e a irmã Ana, quando foi assassinada. Logo depois surgiram vídeos no Youtube ofensivos à honra e à memória de Maria. Monique e Ana ingressaram com medida judicial postulando tutela de urgência para — além de obter a retirada dos vídeos ofensivos da plataforma — que o Youtube e os provedores de conexão fornecessem elementos que permitissem a identificação cadastral (nome, RG, CPF, endereço) dos usuários que postaram conteúdos caluniosos contra Maria, para fins de reparação de dano moral. Nesse cenário, quanto à responsabilidade dos provedores (de conexão e de aplicação) relativamente aos dados pessoais dos usuários, é CORRETO afirmar que:","a":"Tanto o Youtube quanto as empresas provedoras de acesso à internet devem fornecer, a partir do endereço IP, os dados cadastrais pessoais dos usuários que cometam atos ilícitos pela rede.","b":"Apenas o Youtube — como provedor de aplicação de internet — está obrigado a guardar e fornecer dados pessoais dos usuários, sendo insuficiente a apresentação dos registros de número IP.","c":"Apenas os provedores de acesso têm o dever jurídico de guardar dados cadastrais de cada um dos usuários durante o prazo de prescrição de eventual ação de reparação civil.","d":"Os provedores de conexão de internet não são obrigados a guardar e fornecer dados pessoais dos usuários, sendo suficiente a apresentação dos registros de número IP. Filosofia do Direito>A Filosofia do Direito em Diferentes Momentos Históricos ,","e":"","gabarito":"C","materia":"Direito Digital","tema":"Lei nº 12.965 de 2014 - Marco Civil da Internet ,Provisão de Conexão e de Aplicações de Internet","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_924","enunciado":"Ano: 2022 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto Ao contrário das ciências da natureza (física, química, biologia), é bastante difícil falar em conceito ou mesmo ideia do que é o Direito. Essa dificuldade advém do fato - de o Direito ser fenômeno histórico e social. De fato, o conteúdo das normas das comunidades — ao contrário das leis da física — varia no tempo e no espaço. O que temos são approachs (aproximações), faces de um grande poliedro. Uma dessas abordagens captura o aspecto do Direito enquanto “técnica social especifica” para se lograr a observância das normas, como se extrai de um autor: “O que o assim chamado Direito dos antigos babilônios tem em comum com o — igualmente assim chamado — Direito que prevalece hoje nos Estados Unidos ? (.....) pois a palavra (Direito) refere-se à técnica social especifica de uma ordem coercitiva, que, apesar das enormes diferenças entre o Direito da Antiga Babilônia e o dos Estados Unidos hoje (...) é essencialmente a mesma para todos esses povos que diferem tão amplamente em tempo, lugar e cultura — a técnica social que consiste em ocasionar a conduta social desejada dos homens por meio da","a":"ameaça de coerção no caso de conduta contrária”. A perspectiva acima reproduz a abordagem do: Direito como integridade em Dworkin.","b":"Direito como conjunto de normas e procedimentos em Alexy.","c":"Positivismo normativista de Kelsen.","d":"Realismo jurídico norte-americano de Holmes.","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1959591","enunciado":"","a":"Cidade de São Paulo — vez que historicamente promoveu segregação sócio-espacial da população negra — evidencia característica sempre presente no racismo. Mais especificamente: “O privilégio racial no acesso à propriedade (...) deve ser compreendido, portanto, como uma manifestação do racismo (...) que promove a segregação socioespacial da população negra (...). O racismo é fator (...) organizador das relações econômicas que afetam a ocupação do espaço urbano. Referida segregação socioespacial tem caráter cíclico ao condicionar indiretamente a forma de ocupação do espaço urbano da maioria da população negra, traduzida por zonas perifericas e desprovidas de infraestrutura adequada e de um entorno que oportunize uma melhor sociabilidade.” (Anna Lyvia Roberto Custódio Ribeiro, 2020). Essa característica sempre presente no racismo o revela como “elemento que integra a organização econômica e política da sociedade. Em suma, O que queremos explicitar é que O racismo é a manifestação 'normal' de uma sociedade, e não um fenômeno patológico ou que expressa algum tipo de “anormalidade”. O racismo fornece o sentido, a lógica e a tecnologia para a reprodução das formas de desigualdade e violência que moldam a vida social contemporânea.” (Silvio Luiz de Almeida, 2019). A essa característica ou fator sempre presente no racismo denominamos:","b":"A Racismo estrutural. Racismo intergeracional.","c":"Racismo individual.","d":"Racismo interseccional. Direito Internacional Público>Sujeitos de Direito Internacional Público: Estados ,","e":"","gabarito":"A","materia":"Direitos Humanos","tema":"Sistema Global de Proteção dos Direitos Humanos: Instrumentos Normativos","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_926","enunciado":"Ano: 2022 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto Dadas as assertivas que se seguem, assinale a alternativa CORRETA:","a":"O controle de convencionalidade de matriz internacional é realizado pela Corte Interamericana de Direitos Humanos tanto no exercício de sua jurisdição contenciosa quanto na sua jurisdição consultiva, ficando excluída somente a aferição de compatibilidade de norma constitucional em face da Convenção Americana de Direitos Humanos.","b":"A suspensão de direitos e garantias previstas em tratados de direitos humanos obedece limites materiais, temporais e procedimentais, como se vê, por exemplo, na impossibilidade de suspensão do direito à integridade pessoal, liberdade de pensamento, consciência e de religião na Convenção Americana sobre Direitos Humanos.","c":"A responsabilidade internacional do Estado não abarca os atos comissivos ou omissivos imputados ao Poder Judiciário nacional, devido à impossibilidade, em nome da separação dos poderes, do Poder Executivo interferir na condução dos atos judiciais.","d":"O Protocolo de Ushuaia sobre o Compromisso Democrático no Mercosul prevê a adoção de medidas de reação em caso de ruptura da ordem democrática em Estado membro do bloco, adotadas por maioria e sem a participação do Estado afetado. Direito Internacional Público>Extradição, Expulsão e Deportação ,Fontes do Direito Internacional Público: Tratados Interna","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_927","enunciado":"Ano: 2022 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto Dadas as assertivas que se seguem, assinale a alternativa CORRETA:","a":"a Convenção das Nações Unidas sobre a Eliminação de Todas as Formas de Discriminação Racial não prevê o dever dos Estados de considerar delitos puníveis por lei qualquer difusão de ideias baseadas na superioridade ou ódio raciais.","b":"Uma regra prevista em um tratado pode se tornar obrigatória para Estados não partes, caso tal regra seja também uma regra consuetudinária de Direito Internacional. A Convenção Contra a Tortura e Outros Tratamentos ou Penas Cruéis, Desumanos ou Degradantes proíbe a devolução","c":"ou extradição de uma pessoa para outro Estado quando houver razões substanciais para crer que a mesma corre perigo de ali ser submetida a tortura, mas aceita, em nome da soberania, que o Estado efetue a expulsão em tal situação.","d":"O Direito Internacional do Meio Ambiente contempla o direito humano ao meio ambiente equilibrado, sadio e seguro, tal qual consta expressamente, de maneira pioneira, no Pacto Internacional sobre Direitos Econômicos, Sociais e Culturais.","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1959588","enunciado":"Dadas as assertivas que se seguem, assinale a alternativa CORRETA: De acordo com a Convenção das Nações Unidas sobre o Direito do Mar, em caso de abalroamento ocorrido entre","a":"navio de bandeira brasileira e outro de bandeira de Estado estrangeiro no alto mar que possa acarretar uma responsabilidade penal a estrangeiro em serviço no navio estrangeiro, o procedimento penal contra tal pessoa pode ser iniciado perante autoridade judicial brasileira.","b":"Em ação proposta no Brasil relativa a ato de império de Estado estrangeiro, não se admite a renúncia à imunidade de jurisdição por parte do Estado estrangeiro réu, devendo ser extinta eventual ação por ausência de jurisdição do juízo brasileiro.","c":"De acordo com a Convenção de Viena sobre Relações Consulares, os funcionários consulares terão direito de visitar o nacional do Estado que envia, o qual esteja detido, e providenciar sua defesa em juízo, mesmo contra a vontade do interessado, em nome da indisponibilidade do direito à liberdade.","d":"A delonga injustificada em investigação penal ou processo criminal nacional pode justificar o exercício da jurisdição internacional pelo Tribunal Internacional Penal (TPI). Direitos Humanos>Sistema Global de Proteção dos Direitos Humanos: Instrumentos Normativos ,","e":"","gabarito":"D","materia":"Direitos Humanos","tema":"Estatuto de Roma e o Tribunal Penal Internacional","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_929","enunciado":"Ano: 2022 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto Dadas as assertivas que se seguem, assinale a alternativa CORRETA:","a":"Nos casos em que a nacionalidade tenha sido obtida por declaração falsa ou fraude, a Convenção para a Redução dos Casos de Apatridia (1961) prevê que a privação da nacionalidade seja feita por cancelamento automático da naturalização por ato administrativo.","b":"A Convenção Internacional sobre os Direitos das Pessoas com Deficiência prevê que as pessoas com deficiência não sejam excluídas do sistema educacional geral sob alegação de deficiência.","c":"De acordo com a Declaração da Organização das Nações Unidas sobre os Direitos dos Povos Indiígenas, os povos indígenas têm o direito à consulta prévia, mas não possuem o direito ao consentimento prévio antes da adoção e aplicação de medidas legislativas e administrativas que os afetem.","d":"O modo indireto de proteção dos direitos sociais consiste na proteção dos direitos sociais como facetas dos direitos civis e políticos. Até o momento, na jurisprudência da Corte Interamericana de Direitos Humanos, somente esse modo de proteção é utilizado.","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1959586","enunciado":"Dadas as assertivas que se seguem, assinale a altemativa CORRETA:","a":"O objetivo principal do Protocolo de Istambul é fornecer aos Estados auxílio na coleta e utilização de provas da prática do desaparecimento forçado, possibilitando, consequentemente, a responsabilização dos infratores.","b":"As Regras das Nações Unidas para o Tratamento de Mulheres Presas e Medidas Não Privativas de Liberdade para Mulheres Infratoras (Regras de Bangkok) permitem a imposição de sanções de isolamento ou segregação disciplinar às gestantes e mães em periodo de amamentação. Os Princípios básicos sobre o uso da força e armas de fogo pelos funcionários responsáveis pela aplicação da lei","c":"estipulam que os funcionários responsáveis pela aplicação da lei devem esforçar-se por dispersar as reuniões ilegais mas não violentas sem recurso à força e, quando isso não for possível, limitar a utilização da força ao estritamente necessário.","d":"Os Princípios de Bangalore tratam dos valores que devem nortear a atuação do juiz, tendo como valor a imparcialidade focada no seu aspecto objetivo e não subjetivo. Direito Internacional Privado>Direito Processual Internacional ,","e":"","gabarito":"C","materia":"Tratados Internacionais","tema":"Tratados Internacionais de Defesa e Segurança","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_931","enunciado":"Ano: 2022 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","a":"Dadas as assertivas que se seguem, assinale a alternativa CORRETA: via de transmissão da cooperação jurídica internacional denominada “autoridade central” consiste em órgão de comunicação estatal, o qual possui a função de gerenciar o trâmite dos pleitos cooperacionais, recebendo e enviando- A os a outro Estado, zelando ainda pela adequação das solicitações enviadas e recebidas aos termos da legislação de regência. Pode ainda, a depender do tratado, a autoridade central exercer funções de execução dos deveres impostos ao Estado-Parte.","b":"O reconhecimento e execução de sentença estrangeira em um Estado podem ser realizados por meio do modo de controle limitado, também chamado de juízo de delibação, pelo qual o Estado do foro afere determinados aspectos referentes à sentença estrangeira, mas exige, simultaneamente, a análise do mérito completo da decisão.","c":"A Convenção da Haia sobre a Obtenção de Provas no Exterior em matéria civil e comercial prevê que a autoridade judicial deve aplicar integralmente a legislação do Estado Requerente no que diz respeito às formalidades a serem seguidas na obtenção da prova.","d":"O Protocolo de Las Leñas de Cooperação e Assistência Jurisdicional em Matéria Civil, Comercial, Trabalhista e Administrativa, de 1992, proíbe que seja aplicado o reconhecimento e execução de sentenças em matéria de reparação de danos e restituição de bens pronunciadas na esfera penal. Direito Internacional Privado>","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_932","enunciado":"Ano: 2022 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto Dadas as assertivas que se seguem, assinale a alternativa CORRETA:","a":"O princípio do favorecimento é operacionalizado pela adoção de duas ou mais regras de conexão, levando à possibilidade de incidência potencial de várias leis, cuja aplicação será dependente de critério espacial (e não mais material).","b":"O princípio da proximidade adota o método multilateral indireto; contudo, a sede de determinada situação e a localização do ordenamento são aferidas de acordo com os vínculos in concreto com a situação, podendo servir como cláusula de exceção, correção ou escape, e, ainda, critério inicial de fixação da lei aplicável.","c":"O método do reconhecimento exige, usualmente, uma situação jurídica consolidada, de acordo com a lei estrangeira de sua formação, mesmo com a ofensa à ordem pública do Estado do foro que reconhece a situação.","d":"O Direito Internacional Privado conta com conjunto de normas de soít Law veiculadas por meio da edição de leis- modelo e recomendações, as quais representam instrumentos internacionais vinculantes impondo aos Estados que adotem legislação interna compatível. Direito Internacional Privado>","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_933","enunciado":"Ano: 2022 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto Dadas as assertivas que se seguem, assinale a alternativa CORRETA:","a":"O conteúdo da cláusula de ordem pública no Direito Internacional Privado é definido a partir do contexto social e valores do Estado estrangeiro de origem da lei a ser aplicada pelo Estado do foro.","b":"O silêncio de um tratado de Direito Internacional Privado no que tange à cláusula de ordem pública implica que seu uso, baseado em outro diploma normativo, é proibido pelo aplicador da citada norma no Brasil.","c":"O recurso à ordem pública na escolha das leis possui duas fases sucessivas: a primeira, é o afastamento da lei estrangeira indicada pelo uso das regras de conexão; a segunda, é a designação de outra regra (em geral, a do próprio foro) para regular o fato transnacional.","d":"A Convenção sobre os aspectos civis do sequestro intemacional de crianças (1980) prevê, de modo expresso, uma cláusula de proteção à ordem pública, repetindo a tradição de tal menção nos tratados celebrados sob os auspícios da Conferência da Haia de Direito Internacional Privado. Direito Ambiental>Direito constitucional ambiental ,","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_934","enunciado":"Ano: 2022 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto Em maio de 2022, no Incidente de Assunção de Competência (IAC 13), o Superior Tribunal de Justiça estabeleceu quatro teses relativas ao direito de acesso à informação no direito ambiental. A base para julgamento deste IAC 13 pelo Superior Tribunal de Justiça foi a incidência, na hipótese, da Lei de Acesso à Informação (LAI), de 2011, e da Lei de Acesso à Informação Ambiental, de 2003. À luz da legislação e ou da jurisprudência dominante, assinale a alternativa CORRETA: Os órgãos e entidades da Administração Pública, integrantes do Sistema Nacional do Meio Ambiente — SISNAMA,","a":"ficam obrigados a permitir o acesso público aos documentos, expedientes e processos administrativos que tratem de matéria ambiental e a fornecer todas as informações ambientais que estejam sob sua guarda, com exceção de informações relativas ao agronegócio, como sobre as que envolvem o uso de substâncias tóxicas e perigosas e de organismos geneticamente modificados.","b":"Os entes federativos não têm obrigação de franquear amplo acesso às informações acerca da execução de Planos de Manejos de Áreas de Proteção Ambiental (APA), podendo permitir o acesso a órgãos públicos e a entidades ambientais cadastradas.","c":"Na obrigação de transparência ambiental pelo Estado, não cabe falar em transparência reativa, aquela decorrente do dever de produção de informação ambiental ainda inexistente no âmbito da administração pública.","d":"Para assegurar o direito constitucional ao meio ambiente sadio e equilibrado, o poder público tem o dever de promover a educação ambiental em todos os níveis de ensino e a conscientização pública para a preservação ambiental.","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_935","enunciado":"Ano: 2022 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto Concretizando os dispositivos constitucionais do direto ao meio ambiente e do direito às cidades sustentáveis, em 02 de agosto de 2010, passou a vigorar a Lei nê 12.305, que instituiu a Política Nacional de Residuos Sólidos (PNRS). Segundo dados do Panorama dos Resíduos Sólidos no Brasil (2020), a geração saiu de 66,7 milhões de toneladas em 2010 para 79,1 milhões em 2019, com aumento de 12,4 milhões de toneladas numa década. O mesmo estudo diz ainda que cada brasileiro produz, em média, 378,2 kg de lixo por ano, o que corres- ponde a mais de 1 kg por dia (Fonte: Agência Senado). É nítido o impacto ambiental dos milhões de toneladas de resíduos que, quando descartados sem observância das normas, contaminam rios, lagos, córregos, olhos-d'água, nascentes, solos, lençóis freáticos, etc. Nesse contexto, à luz da legislação e","a":"jurisprudência do Supremo Tribunal Federal, é CORRETO afirmar que: obrigação do Município em adotar as medidas administrativas necessárias à correta gestão dos resíduos sólidos no A âmbito do seu território é passível de controle pelo Judiciário.","b":"As ações voltadas para efetivar a Política Nacional de Resíduos Sólidos (PNRS) são determinantes para o Poder Público e indicativas para o setor empresarial e a coletividade.","c":"A responsabilidade de estruturar e implementar os sistemas de logística reversa, mediante retomo dos produtos após o uso pelo consumidor, é do Poder Público, via serviço público de limpeza urbana e de manejo dos resíduos sólidos.","d":"O lançamento de rejeitos ou resíduos sólidos são permitidos em corpos hídricos atestados pelo poder público como impróprios para banho ou consumo da água.","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1959580","enunciado":"No licenciamento ambiental, quando há povos indígenas, comunidades quilombolas e outras comunidades tradicionais no local ou nas proximidades do empreendimento ou serviço, a avaliação de impactos socioambientais, além de seguir as normas ambientais pertinentes, requer ainda a estrita observância da Constituição brasileira de 1988 e, no que couber, da Convenção nº 169 da Organização Internacional do Trabalho (OIT), especialmente no que concerne à previsão do Direito à Consulta e ao Consentimento Prévio, Livre e Informado. Dadas as assertivas abaixo, assinale a alternativa CORRETA: I. Cada vez que sejam previstas medidas legislativas ou administrativas suscetíveis de afetar os povos indígenas, comunidades quilombolas e outras comunidades tradicionais, é dever do Estado lhes garantir o direito de consulta livre, prévia e informada. II. O Estado deverá zelar para sejam efetuados estudos junto aos povos indígenas, comunidades quilombolas e outras comunidades tradicionais, com o objetivo de se avaliar a incidência social, espiritual e cultural que as atividades submetidas ao licenciamento ambiental possam ter sobre esses povos e comunidades. III. É possível haver compatibilidade entre meio ambiente e terras indígenas, ainda que estas envolvam áreas de conservação ambiental e/ou áreas de preservação ambiental. Esta compatibilidade é que autoriza a dupla afetação, sob a administração do competente órgão ambiental, devendo-se observar a Convenção nº 169 da OIT, especialmente quanto à necessidade da consulta livre, prévia e informada dos povos indígenas na elaboração do plano de administração conjunta","a":"ou gestão compartilhada do espaço ambientalmente protegido. l e ll estão corretas.","b":"Il e Ill estão corretas.","c":"l e Ill estão corretas.","d":"Todas estão corretas.","e":"","gabarito":"D","materia":"Direitos Humanos","tema":"Organização Internacional do Trabalho ,Povos Indígenas e Tribais (C169)","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1959579","enunciado":"Sobre o regime de responsabilidade para reparação e indenização de danos ambientais, à luz da legislação e da jurisprudência dominante do Supremo Tribunal Federal e Superior Tribunal de Justiça, é CORRETO afirmar que:","a":"As leis de Biossegurança (Lei nº 11.105/05), de Residuos Sólidos (Lei nº 12.305/10) e o Código Florestal (Lei nº 12.651/12) não preveem expressamente o regime de responsabilidade objetiva para reparação e indenização de danos causados ao meio ambiente e a terceiros afetados.","b":"A responsabilidade civil da administração pública por danos ao meio ambiente, decorrente de sua omissão no dever de fiscalização, é de caráter solidário, mas de execução subsidiária.","c":"Na hipótese de omissão estatal no dever de fiscalizar os danos ao meio ambiente, o Estado é considerado poluidor direto.","d":"No âmbito civil, o espectro de sujeitos responsáveis pelo dano ambiental fica restrito aqueles que diretamente realizam condutas e atividades lesivas, sejam pessoas físicas ou jurídicas.","e":"","gabarito":"B","materia":"Direito Ambiental","tema":"Responsabilidade ambiental ,Responsabilidade civil por danos ao meio ambiente","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1959578","enunciado":"O Supremo Tribunal Federal julgou, recentemente (em 2022), por unanimidade, a Ação Direta de Inconstitucionalidade nº 2.142 (ADI 2.142), que teve por finalidade questionar os limites da competência concorrente estadual em matéria ambiental. No julgamento desta ADI 2.142, foi fixada a seguinte tese: “É inconstitucional interpretação do ari. 264 da Constituição do Estado do Ceará de que decorra a supressão da competência dos Municípios para regular e executar o licenciamento ambiental de atividades e empreendimentos de impacto local.\" Em matéria ambiental, sobre a repartição de competência entre os entes federativos, à luz da legislação e da jurisprudência dominante do Supremo Tribunal Federal e Superior Tribunal de Justiça, é CORRETO afirmar que: Os municípios têm competência originária para tratar as atividades de interesse local predominante, cabendo-lhes","a":"ainda exercer atribuições originárias da União, dos Estados e do Distrito Federal, desde que seja firmado convênio e que o município destinatário da delegação disponha de órgão ambiental capacitado a executar as ações administrativas a serem delegadas e de conselho de meio ambiente.","b":"Em Área de Proteção Ambiental (APA) municipal, a competência para licenciamento ambiental será exclusiva do Município.","c":"A competência e autonomia do Município são reconhecidas pelo Judiciário em matéria de fiscalização e de licenciamento ambiental, mas não para aplicação de sanções administrativas.","d":"Os empreendimentos e atividades poderão ser licenciados ambientalmente por dois entes federativos, quando houver complexidade técnica e consequências para municípios limitrofes. Direito Ambiental>Proteção do Meio Ambiente em Normas Infraconstitucionais ,","e":"","gabarito":"A","materia":"Direito Ambiental","tema":"Federação e competências em matéria ambiental ,Competências legislativa e material","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_939","enunciado":"Ano: 2022 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto Os noticiários têm reportado, cada vez com maior frequência, situações graves que vinculam mudanças climáticas a desastres. Sob o ponto de vista jurídico, o Direito dos Desastres está relacionado com a gestão do risco e visa gerir as fases de um evento catastrófico. No âmbito normativo brasileiro, a Lei 12.608/2012, além de autorizar a criação de sistema de informações e monitoramento de desastres, instituiu a Política Nacional de Proteção e Defesa Civil - PNPDEC; e a Lei 12.187/2009, instituiu a Política Nacional sobre Mudança do Clima — PNMC, estabelecendo princípios, objetivos, diretrizes e instrumentos. A PNPDEC, nos termos do art. 32, parágrafo único da Lei 12.608/2012, deve se integrar à política de mudanças climáticas. Sobre este assunto, à luz da legislação e da jurisprudência dominante do Supremo Tribunal Federal e Superior Tribunal de Justiça, dadas as assertivas abaixo, assinale a alternativa CORRETA: I. É dever da União, dos Estados, do Distrito Federal e dos Municípios adotar as medidas necessárias à redução dos riscos de desastre. II. Compete à União apoiar os Estados, o Distrito Federal e os Municípios no mapeamento das áreas de risco, nos estudos de identificação de ameaças, suscetibilidades, vulnerabilidades e risco de desastre e nas demais ações de prevenção, mitigação, preparação, resposta e recuperação. III. A Política Nacional sobre a Mudança do Clima (PNMC) deve ser executada pelos entes políticos e pelos órgãos da administração pública, com observância dos princípios da precaução, da prevenção, da participação cidadã, do desenvolvimento sustentável, visando, dentre outros, à preservação, à conservação e à recuperação dos recursos","a":"ambientais, com particular atenção aos grandes biomas naturais tidos como Patrimônio Nacional. l e ll estão corretas.","b":"Il e Ill estão corretas.","c":"l e Ill estão corretas.","d":"I, Il e Ill estão corretas.","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1959576","enunciado":"Sobre a Reparação do Dano Ambiental, à luz da legislação e da jurisprudência dominante do Supremo Tribunal Federal e Superior Tribunal de Justiça, é CORRETO afirmar que:","a":"Houve, no Supremo Tribunal Federal, reconhecimento de repercussão geral de matéria relativa à prescrição de pedido de reparação de dano ambiental e foi fixada a seguinte tese: “E imprescritível a pretensão de reparação civil de dano ambiental”.","b":"O empreendedor somente será obrigado a reparar o dano que sua atividade causou ao meio ambiente, se a licença ambiental estiver irregular ou se houver falha na realização do estudo ambiental e na apresentação do relatório de impacto ambiental (EIA/RIMA).","c":"Quanto ao dano ambiental, não se admite a acumulação da condenação do réu à obrigação de fazer ou à de não fazer com a obrigação de indenizar.","d":"As obrigações ambientais possuem natureza propter rem, não se admitindo que o credor exija, em juízo, cumprimento de obrigações ambientais do proprietário ou possuidor anterior, sendo possível, ao credor, escolher entre o proprietário ou o possuidor atual. Direito Ambiental>Federação e competências em matéria ambiental ,","e":"","gabarito":"A","materia":"Direito Ambiental","tema":"Responsabilidade ambiental ,Responsabilidade civil por danos ao meio ambiente","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_941","enunciado":"Ano: 2022 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto Sobre os sítios arqueológicos como bens culturais ambientais, à luz da legislação e da jurisprudência dominante do Supremo Tribunal Federal e Superior Tribunal de Justiça, é CORRETO afirmar que:","a":"Os sítios arqueológicos podem ser de propriedade pública ou privada, cabendo à União, aos Estados, ao Distrito","b":"Federal e aos Municípios, o exercício compartilhado da tarefa de protegê-los e guardá-los. Os sítios arqueológicos são bens da União e podem ser tombados por quaisquer dos entes federativos.","c":"Os sítios arqueológicos são bens públicos, e a dominialidade pode ser federal, estadual, distrital e municipal, a depender da localização, extensão e relevância dos sítios.","d":"Os sítios arqueológicos não podem ser inscritos no Livro de Registro de Lugares nem receber o título de Patrimônio Cultural do Brasil, nos termos do Decreto nº 3551/2000, que institui o Registro de Bens Cuiturais de Natureza Imaterial e cria o Programa Nacional do Patrimônio Imaterial.","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1959574","enunciado":"Leia atentamente as assertivas abaixo sobre bens públicos e assinale a altemativa CORRETA: I. Sendo os bens de uso comum destinados à utilização de todos, o Poder Público não pode impor qualquer tipo de ônus para sua utilização. Il. As terras tradicionalmente ocupadas pelos índios são bens públicos de domínio da União afetadas ao Estado-membro a que pertencem.","a":"Ill. As repartições públicas e universidades públicas são bens de uso especial. As assertivas I e Ill estão corretas.","b":"As assertivas I e Il estão erradas.","c":"As assertivas I, Il e Ill estão corretas.","d":"As assertivas I e Ill estão erradas.","e":"","gabarito":"B","materia":"Direito Administrativo","tema":"Bens Públicos na Administração Pública ,Conceito, classificação, afetação e desafetação","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1959573","enunciado":"","a":"É competência privativa do Presidente da República: Extinguir, por decreto, cargo público desde que tenha sido criado por decreto.","b":"Organizar, por decreto, o funcionamento da Administração Pública Federal, criando ou extinguindo órgãos públicos.","c":"Extinguir, por decreto, funções ou cargos públicos, criados por lei, quando vagos.","d":"Organizar, por decreto, o funcionamento da Administração Pública Federal mesmo implicando aumento de despesas.","e":"","gabarito":"C","materia":"Direito Constitucional","tema":"Poder Executivo","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1959572","enunciado":"À Lei nº 14.133/21 prevê que a alienação de bens imóveis pela Administração Pública, subordinada à existência de interesse público justificado, será precedida de avaliação, exigirá autorização legislativa e dependerá de licitação na modalidade leilão. Nesse tema, assinale a alternativa CORRETA:","a":"Se o imóvel, objeto da alienação, estiver ocupado, deverá ser desocupado antes de precedida a avaliação, evitando eventual desvalorização.","b":"Será concedido direito de preferência ao licitante que, submetendo-se a todas as regras do edital, comprove a ocupação do imóvel objeto da licitação.","c":"Bens imóveis ocupados não podem ser objeto de alienação, salvo se houver a concordância daquele que está a ocupar o imóvel.","d":"Não existe direito de preferência na alienação de bem público ocupado, pois a licitação é procedimento que deve resultar em tratamento isonômico a qualquer licitante interessado. Direito Administrativo>Improbidade administrativa - Lei nº 8.429 de 1992 e Lei nº 14.230 de 2021 ,","e":"","gabarito":"B","materia":"Direito Administrativo","tema":"Licitações e Lei nº 14.133 de 2021 ,Alienações e Instrumentos Auxiliares","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1959570","enunciado":"","a":"Ano: 2022 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto Administração Pública, no exercício do poder de autotutela, pode examinar seus atos e comportamentos no que afeta ao mérito e à legalidade. Com base nesse enunciado, é CORRETO afirmar que: A Administração Pública pode revogar seus próprios atos quando eivados de vícios que os tornam ilegais, porque A deles não se originam direitos.","b":"A Administração Pública pode anular seus próprios atos sempre que entender conveniente ou oportuno, respeitando o direito adquirido.","c":"A Administração Pública pode anular seus próprios atos quando eivados de vícios que os tornam ilegais, salvo se implicarem em direito adquirido.","d":"A Administração Pública pode anular seus próprios atos, quando eivados de vícios que os tornam ilegais, porque deles não se originam direitos.","e":"","gabarito":"D","materia":"Extinção dos atos administrativos","tema":"","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1959569","enunciado":"","a":"Emenda Constitucional nº 103 de 2019, ao incluir o § 13 do artigo 37, dispôs sobre a transferência de servidor com o fim de provê-lo em cargo cujas atribuições e responsabilidades sejam compatíveis com a limitação que tenha sofrido em sua capacidade física ou mental, enquanto permanecer nesta condição, desde que possua a habilitação e o hível de escolaridade exigidos para o cargo. Quanto à nomenclatura deste tipo de provimento e sua remuneração, é CORRETO afirmar:","b":"A Trata-se da readaptação, sendo mantida a remuneração de origem Trata-se da readaptação, sendo alterada a remuneração de acordo com o novo cargo.","c":"Trata-se da reversão, sendo mantida a remuneração de origem.","d":"Trata-se da reversão, sendo alterada a remuneração de acordo com o novo cargo. Direito Administrativo>Responsabilidade civil do estado ,","e":"","gabarito":"A","materia":"Direito Administrativo","tema":"Agentes públicos e Lei 8.112 de 1990 ,Sistema constitucional de remuneração","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1959568","enunciado":"","a":"Ano: 2022 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto responsabilidade civil das pessoas jurídicas de direito público e de direito privado prestadoras de serviços públicos, estampada no § 6º do artigo 37 da Constituição Federal é a do risco administrativo ou objetiva. Sobre este tema, assinale a alternativa CORRETA: As pessoas jurídicas de direito privado prestadoras de serviços públicos responderão objetivamente pelos danos que A seus agentes causarem a terceiros após apurada a responsabilidade direta do causador do dano.","b":"Uma vez constatada a responsabilidade civil da pessoa jurídica de direito público causadora do dano, não caberá direito de regresso contra o agente causador do dano, pois este é servidor público e agiu no desempenho de suas funções.","c":"As pessoas jurídicas de direito público e as de direito privado prestadoras de serviços públicos responderão pelos danos que seus agentes, nessa qualidade, causarem a terceiros, assegurado o direito de regresso contra o responsável nos casos de dolo ou culpa. A responsabilidade civil por danos causados a terceiros, na execução de um serviço público, é objetiva quando o","d":"serviço for prestado diretamente pelo Poder Público. Se o serviço for prestado por delegação a pessoa jurídica de direito privado, a responsabilidade por danos causados a terceiros também será objetiva mas deverá estar expressamente prevista em contrato.","e":"","gabarito":"C","materia":"Reparação do dano, ação de indenização, ação regressiva e prescrição.","tema":"","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1959567","enunciado":"É considerada justa indenização na desapropriação aquela que compreende o valor do bem, juros moratórios e compensatórios, correção monetária, honorários advocatícios e outras despesas, suficiente a garantir ao proprietário adquirir outro bem equivalente. Sobre os juros, é CORRETO afirmar que:","a":"Tanto na desapropriação direta quanto na indireta, os juros compensatórios são devidos independentemente da","b":"efetiva posse ou ocupação do imóvel. Os juros compensatórios, na desapropriação direta ou indireta, contam-se a partir da imissão na posse do imóvel.","c":"Na desapropriação indireta, os juros compensatórios são devidos desde a antecipada imissão na posse e, na desapropriação direta, a partir da efetiva ocupação o imóvel.","d":"Na desapropriação direta, os juros compensatórios são devidos desde a antecipada imissão na posse e, na desapropriação indireta, a partir da efetiva ocupação o imóvel.","e":"","gabarito":"D","materia":"Direito Administrativo","tema":"Intervenção do estado na propriedade ,Noções gerais e desapropriação","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1959566","enunciado":"","a":"Concessão de serviço público é a delegação da prestação do serviço, feita pelo Poder Concedente, mediante licitação, na modalidade concorrência ou diálogo competitivo, a pessoa jurídica ou consórcio de empresas que demonstre capacidade para seu desempenho, por sua conta e risco e por prazo determinado. Concessão de serviço público é a delegação da prestação do serviço, feita pelo Poder Concedente, mediante licitação,","b":"na modalidade concorrência ou pregão, dependendo tratar-se de serviços comuns ou não, a pessoa jurídica ou consórcio de empresas que demonstre capacidade para seu desempenho, por sua conta e risco e por prazo determinado.","c":"Permissão de serviço público é a delegação, a titulo precário ou não, dispensada a licitação, feita pelo Poder Concedente à pessoa física ou jurídica que demonstre capacidade para seu desempenho, por sua conta e risco.","d":"Permissão de serviço público é a delegação, a título precário ou não, mediante licitação em modalidade condizente com o valor da contratação, feita pelo Poder Concedente à pessoa física ou jurídica que demonstre capacidade para seu desempenho, por sua conta e risco.","e":"Nos termos do artigo 175 da Constituição Federal, a prestação de serviços públicos dar-se-à diretamente ou por delegação. CORRETO afirmar que:","gabarito":"A","materia":"Direito Administrativo","tema":"Serviços Públicos ,Delegação dos Serviços Públicos - Concessão e Permissão","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1959565","enunciado":"","a":"Com relação ao processo administrativo tributário federal é CORRETO afirmar que: decisão final administrativa favorável ao contribuinte faz coisa julgada e extingue o crédito tributário, não podendo A ser desafiada mediante processo judicial a não ser por vício formal ou fraude que possa macular a decisão.","b":"A decisão administrativa final contrária ao contribuinte não pode ser levada ao Judiciário através de mandado de segurança, mesmo se não houver necessidade de produção de novas provas.","c":"As provas produzidas no processo administrativo não podem ser emprestadas ao processo judicial, devendo neste âmbito ser produzidas novas provas.","d":"As questões processuais administrativas (hipóteses de recursos e requisitos de admissibilidade) não podem ser objeto de reapreciação pelo Judiciário, ao qual cabe somente apreciar o mérito da questão, avaliação de provas produzidas e deliberação sobre novas provas. Direito Tributário>Limitações Constitucionais ao Poder de Tributar - Princípios Tributários ,","e":"","gabarito":"A","materia":"Direito Tributário","tema":"Execução Fiscal e Processo Tributário ,Processo Administrativo","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_951","enunciado":"Ano: 2022 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","a":"Em termos de princípios tributários e de interpretação dominantes na doutrina e jurisprudência é CORRETO afirmar que: O interesse arrecadatório do Estado, além de fundamental, constitui-se num princípio jurídico per se.","b":"A interpretação econômica no Direito Tributário, mesmo entendida como a aplicação dos institutos de direito privado, tais como simulação, abuso de direito e dissimulação, é compatível com o direito do contribuinte de planejar suas atividades buscando reduzir a carga tributária.","c":"Os comentários da Convenção Modelo dos Acordos de Dupla Tributação da OCDE não podem ser utilizados como argumentos persuasivos de interpretação das Convenções brasileiras que a seguem, porque o Brasil ainda não é membro da OCDE.","d":"O princípio da proporcionalidade não é aplicável em matéria tributária quanto às normas substantivas relativas ao fato gerador ou base de cálculo para se determinar sua propriedade e alcance, mas é aplicável às normas procedimentais adjetivas, especialmente as que se referem ao devido processo legal.","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1959563","enunciado":"","a":"Sobre o sigilo bancário para efeitos tributários no Brasil é CORRETO afirmar que: Convenção Multilateral sobre Assistência Administrativa Mútua em Assuntos Fiscais ratificada pelo Brasil prevê troca automática de informações entre autoridades tributárias dos países signatários, mas no Brasil ela deve ser aplicada A restritivamente em função das garantias do devido processo legal, devendo o contribuinte afetado ser notificado previamente sobre a troca de informações.","b":"A Lei Complementar nº 105/2001, que permite o acesso aos dados financeiros do contribuinte e a troca de informações entre autoridades tributárias, é constitucional também em função do dever fundamental de pagar tributos e do dever de fiscalização da autoridade tributária, com a finalidade de evitar a evasão fiscal.","c":"Segundo o Superior Tribunal de Justiça, a Lei Complementar nº 105/2001, que dispensou a autorização judicial prévia para a quebra do sigilo bancário voltada à viabilização da constituição do crédito tributário, não pode ser aplicada retroativamente a fatos pretéritos à sua vigência, ainda que seja uma lei formal ou procedimental.","d":"Como direito humano fundamental não absoluto, o sigilo bancário pode ser quebrado mesmo por ato ilícito (acesso e divulgação por agentes privados), para fins de fiscalização e cobrança de tributos. Direito Tributário>Legislação do Direito Tributário ,Integração e interpretação da Lei Tributária ,","e":"","gabarito":"B","materia":"Legislação Federal","tema":"Lei complementar 105 de 2001 - sigilo das operações de instituições financeiras","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_953","enunciado":"Ano: 2022 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto Um Acordo de Dupla Tributação (Tratado) entre o Brasil e o país X prevê uma isenção para a remessa de juros, cuja definição no Tratado é mais abrangente (inclusive com referências a quaisquer rendimentos semelhantes) do que previsto na legislação interna brasileira. O fisco brasileiro entendeu que determinado rendimento não poderia ser considerado “juros” por não estar expressamente mencionado no Tratado como tal e, portanto, deveria ser tributado. Além disto, em matéria de isenção deveria ser adotada interpretação literal, conforme comando do Código Tributário Nacional. Assinale a","a":"solução CORRETA, que contém o argumento jurídico pertinente para o caso: isenção deve ser aplicável, pois prevalece o Tratado quanto à definição de “juros” e sua interpretação deve estar A sujeita às normas de interpretação e aplicação dos Tratados prevista na Convenção de Viena sobre o Direito dos Tratados, ratificada e promulgada pelo Brasil (interpretação de acordo com o objeto, finalidade e contexto da norma).","b":"A isenção deveria ser aplicada pela prevalência do Tratado, mas somente se o outro país contratante (X) concordar","c":"com a interpretação da norma específica, de acordo com a Convenção de Viena sobre o Direito dos Tratados. A isenção não é aplicável, pois o conceito restrito da legislação interna prevalece sobre o conceito do Tratado.","d":"A isenção não é aplicável, embora o Tratado deva prevalecer sobre a lei interna quanto ao conceito de juros, pois em matéria de interpretação deve prevalecer a lei complementar (CTN) que estabelece a interpretação literal e não a Convenção de Viena.","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_954","enunciado":"Limitações Constitucionais ao Poder de Tributar - ImunidadesImunidade Recíproca ,Imunidade dos Templos de qualquer c","a":"Imunidade Tributária dos partidos políticos, Sindicatos dos Trabalhadores e entidades educacionais e assistenciais sem fins imunidade tributária Cultural ,A imunidade dos fonogramas e videofonogramas ,Legislação do Direito Tributário ,","b":"","c":"","d":"","e":"","gabarito":"","materia":"Geral","tema":"","origem":"","ano":"","banca":"","orgao":"","concurso":"TRF3"},{"id":"TRF3_955","enunciado":"Ano: 2022 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","a":"Sobre a relação entre tributação e defesa do meio ambiente, assinale a afirmativa CORRETA: defesa do meio ambiente, inclusive mediante tratamento diferenciado conforme o impacto ambiental dos produtos e serviços e de seus processos de elaboração e prestação (Título VII - Da ordem econômica e financeira — capítulo I — A Dos princípios gerais da atividade econômica, conforme preceito especifico do art. 170, VI da CF/88) não se aplica à matéria tributária que está toda regulada no Título VI - Da tributação e do orçamento, no capítulo próprio I — Do Sistema Tributário Nacional (arts. 145-162 da CF/88).","b":"A defesa do meio ambiente, conforme art. 170, VI, mencionado na alínea anterior como princípio programático da atividade econômica, ainda que seja aplicável à matéria tributária, não autoriza o intérprete da legislação federal tributária a adotar interpretação conforme a Constituição que seja mais favorável ao meio ambiente.","c":"Isenção fiscal concedida a prazo certo e sob condição de determinada obrigação de preservação ambiental não pode ser revogada a qualquer momento, mesmo na eventualidade de descumprimento da condição, até que seja definitivamente apurado.","d":"De acordo com o tratado do GATT não é possível à lei brasileira discriminar produtos nacionais e estrangeiros similares, tributando estes últimos mais gravosamente se forem mais danosos ao meio ambiente.","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1959557","enunciado":"Assinale a afirmativa CORRETA:","a":"De acordo com a jurisprudência do Superior Tribunal de Justiça, cabe compensação de tributo recolhido indevidamente com débito tributário do contribuinte cobrado em execução fiscal, se o crédito do contribuinte for anterior ao seu débito.","b":"Segundo a jurisprudência dominante, tem direito à compensação ou repetição de indébito das contribuições do PIS/COFINS no regime não cumulativo o contribuinte de direito que tenha assumido o ônus do seu encargo, aplicando-se o art. 166 do Código Tributário Nacional.","c":"A base de cálculo, faturamento ou receita bruta das contribuições do PIS/COFINS englobam a parcela do ICMS incidente sobre a venda da mercadoria e que está embutida no preço da mesma.","d":"Segundo o Superior Tribunal de Justiça, o crédito de PIS/COFINS no regime não cumulativo é possível quando os insumos adquiridos forem essenciais ou relevantes para a atividade econômica da empresa.","e":"","gabarito":"D","materia":"Direito Tributário","tema":"Tributos Federais","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1959555","enunciado":"Assinale a afirmativa CORRETA quanto aos princípios orçamentários:","a":"O princípio da especialização exige que as receitas apareçam de maneira discriminada, de forma que as origens dos recursos sejam detalhadas para concessões genéricas de despesas.","b":"O princípio da exclusividade exige que a lei orçamentária contenha apenas matéria de receitas e despesas, não permitindo exceções como a autorização para abertura de créditos suplementares e contratações de operações de crédito.","c":"O princípio da universalidade determina que todas as receitas e todas as despesas estejam previstas no orçamento, sendo indispensável para o controle parlamentar.","d":"O princípio do equilíbrio como regra de ouro das finanças públicas significa que a despesa autorizada em cada exercício não pode ser superior ao total de receitas estimadas, não se admitindo como exceção o endividamento para investimento.","e":"","gabarito":"C","materia":"Direito Financeiro","tema":"O Orçamento: Aspectos Gerais ,Princípios orçamentários","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1959554","enunciado":"","a":"Assinale a alternativa CORRETA: alienação fiduciária regulada pela Lei nº 9.514/97 é negócio jurídico pelo qual o devedor, ou fiduciante, com o A escopo de garantia, contrata a transferência ao credor, ou fiduciário, da propriedade resolúvel de coisa móvel ou imóvel.","b":"A alienação fiduciária regulada pelo Decreto-Lei nº 911/69 é negócio jurídico pelo qual o devedor, ou fiduciante, com o escopo de garantia, contrata a transferência ao credor, ou fiduciário, da propriedade resolúvel de coisa móvel ou imóvel.","c":"A alienação fiduciária regulada pelo Decreto-Lei nº 911/69 é negócio jurídico pelo qual o devedor, ou fiduciante, com o escopo de garantia, contrata a transferência ao credor, ou fiduciário, da propriedade resolúvel de coisa imóvel.","d":"A alienação fiduciária regulada pela Lei nº 9.514/97 é negócio jurídico pelo qual o devedor, ou fiduciante, com o escopo de garantia, contrata a transferência ao credor, ou'fiduciário, da propriedade resolúvel de coisa imóvel.","e":"","gabarito":"D","materia":"Direito Empresarial (Comercial)","tema":"Alienação Fiduciária ,Contratos Empresariais","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1959553","enunciado":"Analise as proposições abaixo e assinale a altemativa CORRETA: |. A dissolução da sociedade limitada observa e respeita as mesmas regras dispostas para a sociedade em nome coletivo e para a sociedade simples. Il. A dissolução da sociedade limitada respeita as mesmas regras dispostas para a sociedade em nome coletivo, para a sociedade simples e para a sociedade anônima. III. A sociedade anônima rege-se por lei especial, não havendo disciplina jurídica no Código Civil. IV. É possível o deferimento, mesmo em situações excepcionais, da dissolução parcial de sociedades anônimas fechadas, em especial quando são incluídas cláusulas estatutárias que inviabilizam a livre circulação dos títulos de participação societária e está presente um caráter eminentemente familiar, e as qualidades pessoais dos sócios adquirem relevância","a":"para o desenvolvimento das atividades sociais. Todas estão corretas.","b":"Apenas | e Il estão corretas.","c":"Apenas Ill e IV estão corretas.","d":"Apenas I e IV estão corretas.","e":"","gabarito":"D","materia":"Direito Empresarial (Comercial)","tema":"Direito Societário ,Sociedade Limitada","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1959552","enunciado":"","a":"Assinale a alternativa CORRETA: É caracteristica da sociedade cooperativa a existência de capital social que pertence aos seus cooperados.","b":"É característica da sociedade cooperativa a existência de capital social variável ou ausente.","c":"Na cooperativa, há a intransferibilidade das quotas do capital a terceiros estranhos à sociedade, sendo inviável a sua penhora.","d":"Os sócios-cooperados pretendem extrair lucros e obter outros benefícios, como a facilidade de comercialização de mercadorias e melhor acesso à assistência técnica e às novas tecnologias.","e":"","gabarito":"B","materia":"Direito Empresarial (Comercial)","tema":"Direito Societário ,Tipos societários menores","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1959551","enunciado":"Assinale a alternativa CORRETA: I. O mutuário do Sistema Financeiro Habitacional pode ser compelido a contratar o seguro habitacional obrigatório com a instituição financeira mutuante ou com a seguradora por ela indicada. II. Os credores estrangeiros têm os mesmos direitos conferidos aos credores nacionais nos processos de recuperação judicial, de recuperação extrajudicial ou de falência, respeitada a ordem de classificação dos créditos previstas na legislação de referência e não serão discriminados em razão de sua nacionalidade ou da localização de sua sede, estabelecimento residência ou domicílio. III. Qualquer das partes contratantes pode encerrar o contrato de conta de depósitos bancários, desde que haja comunicação prévia nos termos de Resolução do Banco Central. IV. A cédula de crédito bancário na modalidade de crédito rotativo ou cheque especial não é considerada como título","a":"executivo extrajudicial. Apenas as assertivas I e Il são corretas.","b":"Apenas as assertivas Ill e IV são corretas.","c":"Apenas as assertivas Il e IV são corretas.","d":"Apenas as assertivas Il e IIl são corretas.","e":"","gabarito":"D","materia":"Direito Civil","tema":"Contratos em Espécie ,Empréstimo: Comodato e Mútuo","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1959550","enunciado":"Assinale a altemativa CORRETA a propósito da proteção do conjunto-imagem dos produtos:","a":"Segundo entendimento do Superior Tribunal de Justiça, o conjunto-imagem depende de registro no Instituto Nacional","b":"de Propriedade Industrial. A proteção do conjunto-imagem decorre da proteção da propriedade intelectual e da vedação à concorrência desleal.","c":"Considera-se que não há plena identidade conceitual entre as expressões “conjunto-imagem” e “trade-dress”.","d":"Para a configuração da prática da concorrência desleal no uso do conjunto-imagem basta a demonstração da confusão ou associação indevida. Direito Processual Civil - Novo Código de Processo Civil - CPC 2015>Competência no Processo Civil ,","e":"","gabarito":"B","materia":"Direito Empresarial (Comercial)","tema":"Direito da Propriedade Industrial ,Bens tutelados","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_963","enunciado":"Ano: 2022 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","a":"Assinale a altemativa CORRETA; As demandas ajuizadas contra o Banco do Brasil devem ter curso perante a Justiça Federal.","b":"As demandas ajuizadas contra a FUNAI devem ter curso perante a Justiça Federal.","c":"As demandas ajuizadas contra a Caixa Econômica Federal só têm curso perante a Justiça Federal quando há interesse","d":"da União Federal. As demandas ajuizadas contra a ANEEL devem ter curso perante a Justiça Estadual, Direito Processual Civil - Novo Código de Processo Civil - CPC 2015>Demais Legislações Extravagantes ,","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_964","enunciado":"Ano: 2022 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto Examine as assertivas abaixo e assinale a altemativa CORRETA, a propósito da aplicação das normas do processo civil coletivo: I. Em resposta a ação civil pública intentada pelo Ministério Público Federal para a recuperação de danos decorrentes de lançamento de óleo no mar, a empresa responsável alega que é nulo o inquérito civil, no qual foi produzido laudo técnico que constatou a natureza, a quantidade do material lançado e a extensão dos impactos ao meio ambiente, pois não observou o princípio do contraditório. A decisão acolheu tal preliminar considerando que o inquérito civil está submetido ao princípio do contraditório, nos termos de previsão expressa da Lei nº 7347/85, bem como do entendimento do Superior Tribunal de Justiça. II. O Instituto do Patrimônio Histórico e Artístico Nacional — IPHAN celebrou termo de ajustamento de conduta com o proprietário de um bem tombado cujas cláusulas determinavam o cumprimento de diversas obrigações de fazer para a demolição de obras que desfiguraram a fachada do imóvel tombado. Em embargos à execução, o proprietário alega que a convenção das partes não tem força executiva. Por consequência, ausente título executivo, impõe-se a extinção da execução sem resolução de mérito. Os embargos à execução foram julgados improcedentes, uma vez que a força executiva do termo de ajustamento de conduta advém de previsão expressa da Lei nº 7.347/85, com a redação dada pelo Código de Defesa do Consumidor, sendo título hábil a justificar a ação de execução autônoma. IIl. Em ação civil pública foi homologado acordo celebrado pela Procuradoria Regional dos Direitos do Cidadão de São Paulo, órgão do Ministério Público Federal, pelo Sindicato Nacional dos Aposentados, Pensionistas e Idoso e pelo Instituto Nacional do Seguro Social em que ficou estabelecido cronograma e condições de revisão de todas as aposentadorias por invalidez, auxílio-doença e pensões por morte concedidas até 2002. Posteriormente, identificando que sua aposentadoria não foi revisada nos termos do acordo, Maria resolve propor ação individual de cumprimento do acordo. A petição inicial foi indeferida, por se considerar exclusiva a legitimidade ativa do Ministério Público Federal para a promoção do cumprimento de sentença de ação coletiva, invocando jurisprudência consolidada do Superior Tribunal de Justiça. IV. A Defensoria Pública da União e o Ministério Público Federal propuseram em litisconsórcio ação civil publica para inclusão na Relação Nacional de Medicamentos, no âmbito do Sistema Único de Saúde, de medicamentos comprovadamente mais eficazes e modernos, devidamente registrados na ANVISA, concebidos para tratamento de linforma não-Hodgkin e câncer de mama, em atendimento ao direito à saúde e à integralidade do SUS. Em sede de contestação, a União Federal alegou em preliminar a ilegitimidade ativa da Defensoria Pública da União para a propositura da ação civil pública, uma vez que os titulares do direito à saúde não são necessariamente pessoas hipossuficientes. Em despacho saneador, foi afastada tal preliminar, pois a redação atual da Lei nº 7.347/85 confere à Defensoria Pública legitimidade ativa para propor a ação civil pública, à luz também da sua vocação constitucional, sendo que, no caso, boa parte da população","a":"dependente do SUS é hipossuficiente a justificar a atuação da instituição. Apenas a assertiva III é incorreta.","b":"As assertivas | e III são incorretas.","c":"Apenas a assertiva | é incorreta.","d":"Todas as assertivas são incorretas. Direito Processual Civil - Novo Código de Processo Civil - CPC 2015>Competência no Processo Civil ,","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_965","enunciado":"Ano: 2022 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto Analise as proposições abaixo e assinale a alternativa CORRETA: I. Os embargos de terceiro são modalidade de intervenção de terceiros coata, na qual o terceiro se vê obrigado a ingressar no processo por força de constrição realizada sobre o seu patrimônio; II. Compete ao Superior Tribunal Justiça decidir os conflitos de competência entre juizados especiais federais e juízos federais da mesma seção judiciária. III.Há conflito de competência negativo quando dois ou mais juízes se consideram competentes. IV. O auxílio direto é espécie de cooperação jurídica internacional e demanda um juízo de delibação por parte do Superior","a":"Tribunal de Justiça. Todas estão incorretas.","b":"Apenas I e Il estão corretas.","c":"Apenas a alternativa I está correta.","d":"As alternativas I, Il e IV estão corretas. Direito Processual Civil - Novo Código de Processo Civil - CPC 2015>Competência no Processo Civil ,","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_966","enunciado":"Ano: 2022 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","a":"Assinale a alternativa CORRETA: Duas ou mais ações são conexas quando houver identidade de partes, sendo irrelevante a causa de pedir e o pedido.","b":"Duas ou mais ações são conexas, desde que haja identidade de partes, causa de pedir e de pedido.","c":"Os processos serão reunidos para julgamento conjunto sempre que houver o risco de prolação de decisões conflitantes ou contraditórias caso decididos separadamente.","d":"Não obstante a conexão não determinar a reunião dos processos, se um deles já foi julgado, é dever do magistrado suspender um deles por prejudicialidade externa por até um ano. Direito Processual Civil - Novo Código de Processo Civil - CPC 2015>Intervenção de Terceiro ,","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_967","enunciado":"Ano: 2022 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto Assinale a alternativa CORRETA:","a":"O Incidente de Desconsideração da Personalidade Jurídica é instituto. de direito material voltado para permitir a desconsideração da personalidade jurídica, seja ela direta ou inversa.","b":"O Incidente de Desconsideração da Personalidade Jurídica é uma ação incidental semelhante aos embargos de terceiro na qual se veicula uma pretensão em face dos sucessores do devedor originário.","c":"O Incidente de Desconsideração da Personalidade Jurídica, no processo já em curso, é um incidente processual no qual se procura estender a responsabilidade patrimonial a terceiros, que não figuravam como partes na demanda originária.","d":"O Incidente de Desconsideração da Personalidade Jurídica é modalidade de intervenção de terceiros que apenas tem cabimento quando constatado o desvio de finalidade da pessoa jurídica. Direito Processual Civil - Novo Código de Processo Civil - CPC 2015>Incidente de Assunção de Competência ,","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_968","enunciado":"Ano: 2022 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto Assinale a alternativa CORRETA:","a":"O Incidente de Resolução de Demandas Repetitivas é instituto voltado a solucionar questão de direito, com grande repercussão social, com repetição em múltiplos processos.","b":"O Incidente de Assunção de Competência é instituto voltado a tutelar a homogeneidade do direito, quando há demandas repetitivas e em andamento.","c":"O Incidente de Assunção de Competência destina-se a solucionar parte, parcela ou a totalidade de demandas que versem sobre direitos individuais homogêneos, coletivos stricto sensu e difusos.","d":"O Incidente de Assunção de Competência é instituto voltado a solucionar questão de direito, com grande repercussão social, sem repetição em múltiplos processos. Direito Notarial e Registral>Registro de Imóveis ,Aspectos Gerais dos Registros Públicos e a Lei 6.015/1973 ,","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_969","enunciado":"Ano: 2022 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto Assinale a alternativa CORRETA: Não há previsão em nosso ordenamento jurídico para o registro no Cartório de Imóveis de uma ação de","a":"conhecimento que tenha por objetivo o recebimento de um crédito, pois só se contempla a hipótese de registro das citações de ações reais ou reipersecutórias, relativas a imóveis (ex vi art. 197, nº 21, inc. I, da Lei de Registros Públicos — Lei nº 6.015/1973).","b":"A Lei de Registros Públicos (Lei nº 6.015/1973) autoriza o registro de toda e qualquer ação pessoal e real que tenha o condão de levar o demandado à insolvência, com vista a evitar a fraude de execução.","c":"A averbação no registro de imóveis, de veículos ou de outros bens sujeitos à penhora, arresto ou indisponibilidade poderá ser obtida pelo exequente por meio de certidão com identificação das partes e do valor da causa, desde que a execução seja admitida pelo juiz.","d":"O art. 828 do CPC autoriza o registro de toda e qualquer ação de natureza patrimonial, seja ela fundada em direito real ou pessoal.","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1959542","enunciado":"Assinale a alternativa CORRETA quanto à aplicação das normas processuais de procedimentos especiais em legislação extravagante: Foi concedida liminar em mandado de segurança para que o Secretário de Assistência Farmacêutica do Ministério da Saúde concedesse a Ana o remédio para tratamento da doença retinose pigmentar, grave doença ocular. Posteriormente, no momento da prolação da sentença, após as informações da autoridade coatora e do parecer do","a":"Ministério Público Federal, que demonstravam que o medicamento era experimental, não aprovado pela Agência de Vigilância Sanitária, inclusive por não haver estudos de comprovação da sua eficácia terapêutica, o magistrado, revendo seu posicionamento inicial, denegou a ordem na sentença, e expressamente sustentou a impossibilidade de manutenção da medida liminar quando há decisão final denegatória. Quanto a este aspecto processual, a decisão foi compatível com o entendimento dos Tribunais Superiores sobre a matéria. Lúcio trabalhou na época da ditadura militar em uma repartição que teria sido alvo de investigações sigilosas pelo Serviço Nacional de Informação, o que descobriu após a leitura de um artigo acadêmico sobre justiça de transição.","b":"Intentando conhecer os eventuais dados que existiam a seu respeito impetra um Habeas Data, defendendo que a tutela do direito à autodeterminação das informações sobre si próprio, ainda mais em questão tão sensível, justifica o seu interesse de agir para impetração da ação, independentemente da configuração da recusa de informações por parte da autoridade administrativa. A decisão acolheu a alegação feita por Lúcio, o que está em consonância com entendimento dos Tribunais Superiores sobre a matéria. A cidadã Maria intenta ação popular para anular ato de Ministro de Estado da Saúde que supostamente teria lesado o patrimônio público ao adquirir medicamentos sem comprovada eficácia terapêutica para o Sistema Único de Saúde. O Ministro de Estado alega, como preliminar em sua contestação, a incompetência do juízo federal de primeiro grau em","c":"virtude de ter prerrogativa de foro para anulação de seus atos no Supremo Tribunal Federal. A decisão acolheu a preliminar, aplicando analogicamente o artigo 105, inc. I, alinea b, da Constituição Federal, que confere ao Supremo Tribunal Federal a competência para julgar atos de Ministro de Estado em mandado de segurança. A decisão está em consonância com o entendimento dos Tribunais Superiores quanto à existência de prerrogativa de foro para julgamento em ação popular. Manoel, servidor público federal, requereu administrativamente a concessão de um beneficio concedido a vários servidores que estavam nas mesmas condições que as suas. Contudo, a autoridade administrativa decidiu examinar o","d":"pedido apenas após o retorno de suas férias. Em face dessa decisão, Manoel simultaneamente interpôs recurso administrativo que tinha efeito suspensivo, e ao mesmo tempo impetrou mandado de segurança para obter a concessão do benefício. A decisão reconheceu a ausência de interesse jurídico na impetração do mandado de segurança, em virtude da existência de recurso com efeito suspensivo, o que está em consonância com o entendimento dos Tribunais Superiores. Direito Processual Civil - Novo Código de Processo Civil - CPC 2015>","e":"","gabarito":"A","materia":"Direito Processual Civil - Novo Código de Processo Civil - CPC 2015","tema":"Aplicação das Normas Processuais","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_971","enunciado":"Ano: 2022 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto Emília trabalhou de 1987 a 1994 como celetista nos quadros do município de São Bernardo, até que houve a implantação do Regime Jurídico Único transformando o vínculo dos servidores em estatutário. Alegando ter adquirido uma tendinite no período em que era celetista, intentou ação em face do Instituto Nacional de Seguro Social pleiteando a concessão do benefício previdenciário de auxílio-acidente. A Autarquia Previdenciária sustentou que a desvinculação de Emília do regime geral de previdência social tornaria seu pedido juridicamente impossível, o que deveria resultar na extinção do processo sem resolução de mérito.","a":"Assinale a alternativa CORRETA à luz do CPC de 2015: decisão deve reconhecer a ausência da condição da ação referente à possibilidade jurídica do pedido em razão da A inexistência de regulação normativa a justificar o pleito e determinar a extinção do processo sem resolução de mérito.","b":"A decisão deve ser pelo prosseguimento do processo, apesar de ser possível a extinção do feito sem exame do mérito por impossibilidade jurídica do pedido, em virtude de ser aplicável ao caso a teoria da asserção, segundo a qual as condições de ação devem ser examinadas à luz do alegado pelas partes.","c":"A decisão deve ser pelo prosseguimento do processo, pois a alegada impossibilidade jurídica do pedido confunde-se com o mérito da demanda.","d":"A decisão deve ser pelo prosseguimento do processo considerando que a possibilidade jurídica do pedido é uma questão de mérito, pois o Código de Processo Civil de 2015 não adota a categoria jurídica das condições da ação. Legislação Federal>","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1959539","enunciado":"Ano: 2022 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto Analise as proposições abaixo assinale a alternativa 45. CORRETA: I. o Ministério Público Federal não possui legitimidade para defesa dos interesses de mutuários do Sistema Financeiro da Habitação (SFH). II. Nas ações referentes ao Sistema Financeiro da Habitação, a Caixa Econômica Federal não tem legitimidade passiva para responder por eventuais vícios de construção nos imóveis financiados, salvo quando realiza atividade distinta daquela própria de agente financeiro stricto sensu. III. O mutuário do SFH deve contratar o seguro habitacional obrigatório com a instituição financeira mutuante ou com a seguradora por ela indicada. IV. Nos contratos celebrados no âmbito do SFH não é permitida a capitalização de juros, ressalvada a demonstração de sua","a":"necessidade pela Caixa Econômica Federal. Apenas a assertiva II é verdadeira.","b":"Apenas a assertiva I é verdadeira.","c":"Apenas a assertiva Ill é verdadeira.","d":"Apenas a assertiva IV é verdadeira.","e":"","gabarito":"A","materia":"Lei 4.380 de 1964 - Banco Nacional de Habitação - BNH e Sistema Financeiro de Habitação - SFH e legislação específica","tema":"","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1959538","enunciado":"Analise as proposições abaixo e assinale a alternativa CORRETA: I. A responsabilidade fundada no risco da atividade configura-se quando a atividade normalmente desenvolvida pelo autor do dano causar a pessoa determinada um ônus maior do que aos demais membros da comunidade. II. A obrigação de reparar o dano deve levar em consideração a proteção da vítima, a atividade do ofensor e a prevenção e o interesse da sociedade. III. A incidência da cláusula geral de responsabilidade sem culpa leva em conta o risco inerente da atividade e sua ligação a uma obrigação de resultado, em que falhe o dever de segurança que razoavelmente se poderia esperar do que é um serviço prestado. IV. A responsabilidade sem culpa aplica-se sempre que a atividade normalmente desenvolvida, mesmo sem defeito, e não essencialmente perigosa, induza, por sua natureza, risco especial e diferenciado aos direitos de outrem, sendo critérios da","a":"avaliação de tal risco, exemplificativamente, a estatística, a prova técnica e as máximas de experiência, Todas as assertivas estão corretas.","b":"Apenas le Il estão corretas.","c":"Apenas a Ill está incorreta.","d":"Apenas a IV está incorreta.","e":"","gabarito":"A","materia":"Direito Civil","tema":"Responsabilidade civil ,Elementos Essenciais – Conduta, Nexo Causal, Culpa e Dano","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1959537","enunciado":"","a":"Assinale a alternativa CORRETA: servidão proporciona utilidade para o prédio dominante e grava o prédio serviente, que pertence a diverso dono e A constitui-se mediante declaração expressa dos proprietários, ou por testamento, e subsequente registro no Cartório de Títulos e Documentos. Mediante recebimento de indenização que atenda, também, à desvalorização da área remanescente, o proprietário é","b":"obrigado a tolerar a passagem, através de seu imóvel, de cabos, tubulações e outros condutos subterrâneos de serviços de utilidade pública, em proveito de proprietários vizinhos, quando de outro modo for impossível ou excessivamente onerosa. No entanto, o proprietário prejudicado pode exigir que a instalação seja feita de modo","c":"menos gravosa à propriedade, bem como, depois, seja removida, à sua custa, para outro local do imóvel. A propriedade de solo abrange jazidas, minas e demais recursos minerais e os potenciais de energia hidráulica.","d":"Somente o proprietário pode ajuizar ação reivindicatória de caráter petitório, não possuindo o usufrutuário legitimidade e interesse para ajuizá-la, mas apenas o nu proprietário.","e":"","gabarito":"B","materia":"Direito Civil","tema":"Direito das Coisas / Direitos Reais ,Direito de Vizinhança ,Servidões","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1959536","enunciado":"Assinale a assertiva CORRETA:","a":"O mandato é contrato de acordo com o qual uma pessoa capaz ou incapaz recebe de outrem poderes para, em seu","b":"nome, praticar atos ou administrar interesses. O mandato é o instrumento da procuração.","c":"O mandato pode se dar por instrumento particular e deve conter a indicação do lugar no qual foi passado, a qualificação do outorgante, a data e objetivo da outorga com a designação e a extensão dos poderes conferidos.","d":"O terceiro com quem o mandatário tratar não poderá exigir que a procuração traga a firma reconhecida, por ser formalidade que a lei não exige.","e":"","gabarito":"C","materia":"Direito Civil","tema":"Contratos em Espécie ,Depósito, Mandato, Comissão, Agência e Distribuição","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1959535","enunciado":"Analise as assertivas abaixo, à luz da disciplina dos direitos reais, e assinale a alternativa CORRETA: I. Considera-se que o imóvel financiado pela Caixa Econômica Federal com recursos do Sistema Financeiro Habitacional não se equipara a bem público, sendo, portanto, admissível a ocorrência da usucapião. II. Para fins de usucapião de domínio útil de terreno de marinha não se distingue se a posse advém do regime de ocupação ou da enfiteuse. III. As servidões de passagem que atravessam propriedades privadas para garantir acesso público às praias marítimas podem ser fechadas pelos proprietários quando há a desafetação da praia como bem público. IV. A decretação da Emergência em Saúde Pública de Importância Nacional decorrente da infecção humana pelo Coronavirus não resultou em nenhuma política legislativa que tenha reforçado, ainda que temporariamente, a proteção da","a":"posse provisória de imóvel público em face de desocupação coletiva forçada. Estão incorretas apenas as assertivas Il e III.","b":"Estão incorretas apenas as assertivas Ill e IV.","c":"Estão incorretas apenas as assertivas I e Il.","d":"Todas as assertivas estão incorretas.","e":"","gabarito":"D","materia":"Direito Civil","tema":"Direito das Coisas / Direitos Reais ,Posse - Teoria, Classificação e Aquisição ,UsucapiãoServidões","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1959534","enunciado":"","a":"partir do exame das assertivas abaixo, assinale a alternativa CORRETA: I. O comando do Código Civil que assegura que os prazos prescricionais não correm contra os menores de 16 anos os beneficia de forma ampla e não se restringe apenas às relações reguladas pelo próprio Código; assim, nos feitos nos quais se controverte a incidência do Decreto nº 20.910/1932, também deve ser aplicada a regra de que o curso da prescrição não corre se o titular do direito violado é menor de 16 anos. II. A pretensão da Coordenação de Aperfeiçoamento de Pessoal de Nível Superior (CAPES) de obter ressarcimento de gastos com curso de doutorado realizado e não concluído é prescritível, consoante as regras de prescrição dos atos ilícitos. III. As normas sobre prescrição e decadência em matéria civil devem necessariamente ser disciplinadas em lei complementar, conforme entendimento vinculante do Supremo Tribunal Federal. IV. O direito ao uso de nome social por pessoa travesti ou transexual nos documentos oficiais e nos registros dos sistemas de informação de cadastros, de programas, de serviços, de fichas de formulários, de prontuários e congêneres dos órgãos e das entidades da administração pública federal não se submete à decadência, podendo ser exercido a qualquer tempo.","b":"A Estão corretas as assertivas I e III. Estão corretas as assertivas II, III, IV.","c":"Estão corretas as assertivas I, II e IV.","d":"Estão corretas as assertivas II e III. Direito Digital>Lei nº 13.709 de 2018 - Lei Geral de Proteção de Dados Pessoais (LGPD) ,","e":"","gabarito":"C","materia":"Direito Civil","tema":"Prescrição e Decadência ,Parte Geral","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_978","enunciado":"Ano: 2022 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto Pesquisadores da área de saúde de uma Universidade pública federal estão realizando uma pesquisa para investigar a hipótese de que a COVID-19 impactou de maneira desigual a população negra no país. Para tanto, requereram o acesso à base de dados pessoais do Sistema Único de Saúde às autoridades sanitárias federais. Assinale a alternativa CORRETA quanto à incidência da Lei Geral de Proteção de Dados à hipótese:","a":"Como o dado sobre a origem racial ou étnica é considerado um dado pessoal sensível pela legislação, apenas com o consentimento de cada indivíduo seria possível esse acesso. Na realização de estudos em saúde pública, os órgãos de pesquisa poderão ter acesso a bases de dados pessoais,","b":"inclusive a origem racial ou étnica, desde que os estudos sejam mantidos em ambiente controlado e seguro, respeitando-se, sempre que possível, a anonimização ou pseudonimização dos dados, e observância dos padrões éticos nos termos da legislação.","c":"O órgão de pesquisa será o responsável pela segurança da informação, admitindo-se, apenas em circunstâncias excepcionais, a transferência dos dados a terceiros como previsto na legislação.","d":"A Lei Geral de Proteção de Dados não tem disciplina sobre tratamento de dados pessoais realizados para fins exclusivamente acadêmicos.","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1959532","enunciado":"Lia firmou um contrato de mútuo com a Caixa Econômica Federal dando como garantia pignoraticia algumas joias. Havia uma cláusula contratual, comum a todos os contratos desta modalidade firmados pela instituição bancária, de que a eventual necessidade de ressarcimento do valor das joias, em virtude de extravio, roubo ou furto, teria como parâmetro a avaliação unilateral realizada pelo Banco, em geral bem abaixo do valor de mercado. As joias foram roubadas da agência bancária na qual estavam depositadas por uma quadrilha de ladrões de banco. Lia, inconformada com a perda das joias, propôs ação na Justiça Federal pleiteando a reparação dos danos materiais pelo ressarcimento integral do valor de mercado das joias, conforme prova técnica a ser produzida durante a instrução. Assinale a alternativa CORRETA à luz do entendimento doutrinário e jurisprudencial sobre o tema: Como se trata de ocorrência de caso fortuito ou força maior, uma vez que o roubo foi praticado por terceiros, apesar","a":"da adoção de todas as medidas de segurança pertinentes pelo banco, sendo o problema de segurança pública fora da alçada da instituição, não há responsabilidade da Caixa Econômica Federal, como credora pignoratícia, de ressarcir ao proprietário a perda das joias, nos termos da disciplina sobre penhor prevista no Código Civil. Como há um risco profissional assumido pelo banco quanto à perda do bem, previsto no contrato de penhor, o que","b":"faz lei entre as partes, a credora pignoratícia é responsável pelo ressarcimento, devendo-se observar, todavia, o limite de indenização previsto no contrato, que fixou os bens dados como garantia e suas especificações, nos termos do Código Civil, único conjunto de normas aplicáveis às relações travadas entre clientes e instituições financeiras. No caso, além das regras do Direito Civil, também incidem na hipótese as normas do Código de Defesa do","c":"Consumidor, aplicáveis às instituições financeiras em suas relações com os clientes, ressalvadas as questões de remuneração dos empréstimos financeiros, o que ensejaria a responsabilidade da Caixa Econômica Federal que assumiu o risco profissional de custódia e de restituição da coisa após o pagamento da dívida, que deve se dar, contudo, nos limites das cláusulas do contrato, porquanto de pleno conhecimento da cliente não hipossuficiente. No caso, além das regras do Direito Civil, também incidem na hipótese, as normas do Código de Defesa do Consumidor, aplicáveis às instituições financeiras em suas relações com os clientes, ressalvadas as questões de","d":"remuneração dos empréstimos financeiros, o que ensejaria a responsabilidade da Caixa Econômica Federal que assumiu o risco profissional de custódia e de restituição da coisa após o pagamento da dívida, não podendo prevalecer em contrato de adesão cláusulas que coloquem o consumidor em desvantagem exagerada, incompatíveis com a boa-fé e a equidade, o que impõe que a Caixa seja responsável por pagar o valor real das joias conforme apurado em perícia. Estatuto da Pessoa com Deficiência - Lei nº 13.146 de 2015>","e":"","gabarito":"D","materia":"Direito Civil","tema":"Direito das Coisas / Direitos Reais ,Direitos Reais de Garantia - Penhor, Anticrese e Hipoteca","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1959531","enunciado":"Ano: 2022 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto Assinale a alternativa CORRETA referente aos direitos das pessoas com deficiência:","a":"Os serviços de radiodifusão sonora e de imagens devem permitir o uso da linguagem de sinais ou outra subtitulação, para garantir o direito de acesso à informação às pessoas com deficiência auditiva.","b":"A construção, ampliação ou reforma de edifícios públicos federais deverão ser executadas de modo que sejam ou tornem acessíveis às pessoas com deficiência ou com mobilidade reduzida, ressal- vada a reserva do possível conforme previsto na Lei nº 10.098/2000.","c":"Nos termos da Lei nº 13.146/2015, considera-se pessoa com deficiência aquela que tem impedimento de longo prazo de natureza física, mental, intelectual ou sensorial, o qual, em interação com uma ou mais barreiras, pode impedir a sua capacidade de trabalho e a interação com as demais pessoas.","d":"As pessoas com deficiência visual acompanhadas de cão-guia têm direito a ingressarem e permanecerem com o animal em todos os meios de transporte, exceto no transporte aéreo.","e":"","gabarito":"A","materia":"Disposições Preliminares","tema":"","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1959530","enunciado":"Nos termos da legislação consumerista, consumidor é toda pessoa física ou jurídica que adquire ou utiliza produto ou serviço como destinatário final. Fundamental, portanto, para se aferir o alcance da proteção legal, a compreensão prática do que se entende por “destinatário final”. Considere o seguinte caso: Caio Prado médico recém formado iniciou residência médica no HC da FMUSP e, embora não detivesse conhecimentos de direito imobiliário, construção ou incorporação, adquiriu com sua poupança seu primeiro imóvel: um studio de 1 dormitório — em fase final de construção - de uma incorporadora imobiliária, para uso pessoal ou revender com lucro ou, ainda, obter renda complementar com locação. Sucede que após a entrega do flat houve divergências na interpretação do contrato entre Caio Prado e a construtora. Quanto à aplicação do CDC à relação contratual de compra e venda acima, assinale a alternativa CORRETA:","a":"Caio não pode ser caracterizado como hipossuficients sob o ponto de vista econômico, portanto não recebe proteção do CDC.","b":"Como Caio adquiriu o imóvel com finalidade de re- venda ou renda não faz jus ao amparo do CDC, pois se trata de","c":"consuma intermediário. Caio é técnica e/ou juridicamente vulnerável, devendo receber proteção da legislação consumerista,","d":"Caio fará jus à proteção do CDC desde que utilize o studio para uso pessoal ou familiar, de acordo com a teoria finalista.","e":"","gabarito":"C","materia":"Direito do Consumidor","tema":"Elementos da Relação Jurídica de Consumo ,Consumidor","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1959529","enunciado":"Como agente normativo e regulador de atividade econômica em sentido estrito, o Estado brasileiro, atualmente,","a":"exerce as funções de fiscalização, incentivo e planejamento, todas em caráter vinculante para o agente econômico","b":"privado. pode, por meio de Lei estadual, permitir a exploração da atividade de bingos, loterias e jogos de azar.","c":"pode, por meio de Lei nacional, impedir a instalação de novos estabelecimentos industriais de um mesmo ramo em uma mesma área geográfica ou a ela contígua.","d":"deve reprimir o abuso do poder econômico que vise ao aumento arbitrário dos lucros, mesmo que obtido em regime de concorrência.","e":"","gabarito":"D","materia":"Direito Constitucional","tema":"Ordem Econômica e Financeira ,Princípios Gerais da Atividade Econômica","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1959528","enunciado":"São preceitos constitucionais em vigor no Brasil, diretamente relacionados com a proteção do mercado interno e com o","a":"desenvolvimento regional, respectivamente, a irrestrita liberdade de iniciativa econômica e o orçamento participativo para a realização da infraestrutura.","b":"o direito à apropriação privada do lucro empresarial e as regiões metropolitanas.","c":"a subsidiariedade da iniciativa pública na Economia e a parceria público-privada.","d":"a viabilização da autonomia tecnológica do país e os juros favorecidos para financiamento de atividades prioritárias. Direito Processual Penal>Das Provas ,Sistemas de apreciação e valoração ,Confissão no Processo Penal","e":"","gabarito":"D","materia":"Direito Constitucional","tema":"Ciência, Tecnologia e Comunicação Social ,Ordem Social","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_984","enunciado":"Ano: 2022 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto O Superior Tribunal de Justiça alterou sua jurisprudência sobre temas relevantes do processo penal, podendo-se afirmar que, recentemente, o tribunal estabeleceu que:","a":"O protagonismo da juíza na inquirição das testemunhas pode levar à declaração de nulidade da ação penal, por malferir o princípio acusatório.","b":"A busca pessoal ou veicular, sem mandado judicial, motivada apenas pela impressão subjetiva da polícia sobre a aparência ou atitude suspeita do indivíduo é, em regra, ilegal. Contudo, caso seja encontrada droga com o suspeito, há a convalidação da medida, por se tratar de corpo de delito, nos termos do art. 244 do CPP.","c":"A confissão, ainda que parcial, qualificada ou extrajudicial, deve levar à aplicação de circunstância atenuante do art. 65, III, d, do Código Penal. Todavia, caso tenha sido retratada, não incide a atenuante.","d":"A busca pessoal realizada com base isoladamente em denúncia anônima é ilegal, mas a prova amealhada a partir dela não será considerada nula se estiver configurado crime permanente.","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1959526","enunciado":"","a":"Sobre a prisão cautelar, assinale a alternativa CORRETA: citação por edital não constitui fundamento idôneo para a decretação da prisão preventiva, uma vez que a não A localização do réu não indica presunção de fuga.","b":"O princípio da homogeneidade estabelece que a prisão preventiva, por sua natureza cautelar, é legitima nos casos em que a sanção abstratamente prevista ou imposta na sentença condenatória recorrível não resulte em constrição pessoal.","c":"Nos casos em que os requisitos de cautelaridade estiverem bem caracterizados, o tribunal pode suprir deficiências de fundamentação do decreto prisional em sede de julgamento de Habeas Corpus.","d":"A decretação de prisão preventiva deve estar fundamentada em fatos concretos e atuais que a justifiquem, ou na gravidade abstrata do delito, quando se tratar de crime hediondo.","e":"","gabarito":"A","materia":"Direito Processual Penal","tema":"Da Prisão e da Liberdade Provisória ,Da Prisão Preventiva","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1959525","enunciado":"Leia as afirmações abaixo sobre a colaboração premiada e, ao final, indique a alternativa CORRETA: I. O Supremo Tribunal Federal reconheceu a inconstitucionalidade da realização de acordo de colaboração premiada por Delegado de Polícia, por se tratar de âmbito de atuação exclusiva do Ministério Público, na qualidade de dominus litis. II. O Ministério Público poderá deixar de oferecer denúncia se a colaboração se referir a infração desconhecida pelas autoridades, o colaborador não for o líder da organização criminosa e tiver sido o primeiro a prestar colaboração efetiva. III. A colaboração premiada é meio de obtenção de prova, sendo a palavra do colaborador suficiente para a condenação se","a":"confirmada por outros colaboradores, a denominada corroboração cruzada, ou por outros elementos de prova. Apenas as afirmações I e Il estão corretas.","b":"Apenas as afirmações Il e Ill estão corretas.","c":"Apenas a afirmação II está correta.","d":"Todas as afirmações estão corretas.","e":"","gabarito":"C","materia":"Direito Processual Penal","tema":"Lei de Organização Criminosa – Lei nº 12.850 de 2013","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1959524","enunciado":"Sobre o inquérito policial, é CORRETO afirmar que:","a":"O indiciamento, quando não realizado pela autoridade policial, deve ser determinado pelo magistrado, de ofício ou atendendo a requerimento do Ministério Público, na decisão de recebimento da denúncia.","b":"Embora a existência de inquéritos policiais e ações penais em curso não possa ser considerada maus antecedentes, pode ser utilizada para agravar a pena-base como indicativo de personalidade voltada para a prática de crimes. O pedido de arquivamento de inquérito policial fundamentado na ausência de elementos que permitam ao","c":"Procurador-Geral da República formar a opínio delicti não pode ser recusado pelo Supremo Tribunal Federal. Apenas nas hipóteses em que o fundamento for a atipicidade da conduta ou a extinção da punibilidade, pode o Supremo Tribunal Federal analisar o mérito do pedido.","d":"Notícia anônima detalhada, contendo narração de fatos específicos, constitui elemento idôneo para instauração de inquérito policial, cujo objetivo será buscar indícios que corroborem a narrativa. Direito Processual Penal>Das Provas ,Sistemas de apreciação e valoração ,","e":"","gabarito":"C","materia":"Direito Processual Penal","tema":"Inquérito Policial ,Encerramento do Inquérito Policial","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_988","enunciado":"Ano: 2022 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto Assinale a alternativa CORRETA:","a":"No caso de mora no atendimento a requisições judiciais de dados telemáticos, a falta de previsão no Código de","b":"Processo Penal inviabiliza a fixação de astreintes. O colaborador deve apresentar seus memoriais finais antes dos corréus delatados.","c":"Se o juiz decreta a interceptação telefônica, com base em denúncia anônima rica em detalhes, a cognição judicial","d":"supre a falta de diligências preliminares por parte da Polícia. Não se pode falar em distribuição do ônus da prova entre as partes no processo penal liberal.","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1959521","enunciado":"Mévio foi condenado por descaminho, por internalizar joias no Brasil sem o pagamento dos tributos devidos. Na dosimetria, na primeira fase, três circunstâncias judiciais foram valoradas negativamente: a culpabilidade, tendo em vista o alto poder aquisitivo do réu, a personalidade, por sua ganância e as consequências do delito, pois expressivo o valor das joias e tributos incidentes. A juíza fixou a pena-base no dobro do mínimo legal, isto é, em 2 anos de reclusão. Em sua apelação, Mévio requereu a fixação da pena-base no mínimo; o Ministério Público não recorreu. O Tribunal afastou as circunstâncias referentes à culpabilidade e à personalidade, mas manteve inalterada a pena-base, pois considerou expressivo e inusual o valor das joias apreendidas. Assinale a alternativa CORRETA:","a":"OTribunal devia ter afastado também a circunstância referente às consequências do delito, pois a sonegação de tributos é elementar do tipo de descaminho.","b":"Considerando-se o efeito devolutivo da apelação e a discricionariedade permitida pelo art. 59 do Código Penal, o","c":"Tribunal podia ter decidido da forma indicada. Eventual reformatio in pejus na dosimetria afere-se apenas levando-se em conta a totalidade da pena imposta.","d":"Impunha-se a redução da pena-base pelo Tribunal, sob pena de reformatio in pejus. Direito Processual Penal>Recursos Criminais ,Sentença e Coisa Julgada ,Efeitos dos Recursos Criminais","e":"","gabarito":"D","materia":"Direito Processual Penal","tema":"Recursos Criminais ,Sentença e Coisa Julgada ,Efeitos dos Recursos Criminais","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_990","enunciado":"Ano: 2022 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto Tício foi denunciado por estelionato simples, em continuidade delitiva, tendo o Ministério Público deixado de oferecer a suspensão condicional do processo. Na sentença, a juíza afastou a continuidade e condenou o réu a uma pena definitiva de 1 ano de reclusão e 10 dias-multa. O Ministério Público apelou da sentença apenas para que fosse reconhecida a","a":"continuidade delitiva. Não houve recurso da defesa. Assinale a alternativa CORRETA: Com o advento da sentença, está definitivamente preclusa a possibilidade de suspensão condicional do processo.","b":"O Tribunal, negando provimento à apelação da acusação, decisão que transitou em julgado, deverá determinar a remessa dos autos ao Parquet para eventual proposta de suspensão condicional do processo.","c":"Somente a desclassificação de delito, operada na sentença, poderia ensejar nova possibilidade de oferecimento da suspensão condicional do processo.","d":"A magistrada de primeiro grau, sobrestando o juízo de admissibilidade do recurso, deve remeter os autos ao Parquet para eventual proposta de suspensão condicional do processo.","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1959519","enunciado":"Leia o texto abaixo e, ao final, indique a alternativa CORRETA: Policial rodoviário federal recebe de um particular determinada quantia a título de gratificação pela recuperação de gado furtado, encontrado na proximidade de rodovia federal. O pagamento não fora solicitado ou prometido anteriormente,","a":"tendo o particular espontaneamente decidido realizá-lo após a recuperação da rês. Houve configuração apenas de crime de corrupção passiva.","b":"Houve configuração de crimes de crimes de corrupção ativa e passiva.","c":"Houve configuração apenas de crime de corrupção ativa.","d":"Não houve configuração de crime.","e":"","gabarito":"A","materia":"Direito Penal","tema":"Crimes contra a administração pública ,Corrupção passiva","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1959517","enunciado":"","a":"respeito de temas da teoria geral do Direito Penal, assinale a alternativa CORRETA: O Supremo Tribunal Federal considera o crime de injúria racial prescritível, pois não pode ser equiparado a crime de A racismo, constitucionalmente considerado imprescritível. Tal equiparação violaria o princípio da estrita legalidade penal.","b":"No concurso de crimes, a pena considerada para fins de fixação da competência do Juizado Especial Criminal será verificada individualmente a partir da pena máxima cominada a cada delito isoladamente, no caso de concurso material; ou desprezando-se a exasperação, na hipótese de concurso formal ou crime continuado.","c":"Quando se tratar de crime continuado, a prescrição regula-se pela pena final imposta na sentença, ou seja, computando-se o acréscimo decorrente da continuação.","d":"A lei penal mais grave aplica-se ao crime continuado ou ao crime permanente se a sua vigência é anterior à cessação da continuidade delitiva ou da permanência.","e":"","gabarito":"D","materia":"Direito Penal","tema":"Teoria Geral do Delito","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1959516","enunciado":"","a":"Assinale a alternativa CORRETA: Na chamada autoria colateral, não há vínculo subjetivo entre os autores.","b":"Os únicos requisitos do concurso de pessoas são: pluralidade de participantes; pluralidade de condutas; relevância causal de cada conduta; e identidade de infração penal.","c":"O crime de aborto com o consentimento da gestante não configura exceção à teoria monista unitária do concurso de","d":"pessoas. O delito de associação para o tráfico de drogas possui natureza hedionda. Direito Penal>Legislação Penal Especial ,","e":"","gabarito":"A","materia":"Direito Penal","tema":"Concurso de Pessoas ,Noções gerais de Concursos de Pessoas ,Cooperação dolosamente distinta","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_994","enunciado":"Ano: 2022 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto Sobre os crimes tributários, assinale a alternativa CORRETA:","a":"Para fins de extinção da punibilidade, considera-se equivalente ao pagamento do tributo a garantia do juízo cível em processo de execução fiscal.","b":"No caso de crime previsto no art. 2º da Lei 8.137/90, a prescrição tem como termo “a quo” a data da constituição definitiva do crédito tributário.","c":"Se o agente sonegou imposto de renda nos anos de 2014 e 2015, por omitir receitas em suas declarações, aplica-se o crime continuado.","d":"Não configura bis in idem a majoração da pena-base em razão do valor sonegado e a aplicação concomitante da causa de aumento prevista no art. 12, |, da Lei 8.137/90. Direito Penal>Penas privativas de liberdade ,Noções gerais de dosimetria da pena privativa de liberdade ,","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_995","enunciado":"Ano: 2022 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto Sobre a dosimetria das penas e a substituição da pena privativa de liberdade por restritivas de direitos, é CORRETO afirmar:","a":"o antecedente negativo pode ser reconhecido quando o delito ocorreu após a conduta criminosa em julgamento,","b":"desde que o trânsito em julgado da decisão respectiva se verifique antes da sentença. a chamada “prescrição da reincidência” ocorre após 5 (cinco) anos do trânsito em julgado da decisão condenatória.","c":"a reincidência genérica não impede a substituição da pena privativa de liberdade por restritivas de direitos.","d":"A circunstância judicial dos maus antecedentes não pode ser reconhecida se passados mais de 5 (cinco) anos do cumprimento ou extinção da pena.","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1959512","enunciado":"Tício foi condenado pela prática do art. 183 da Lei de Telecomunicações, por ter prestado serviços de telecomunicações na modalidade Serviço de Comunicação Multimídia (SCM), sem autorização da Anatel Após o trânsito em julgado e início do cumprimento da pena, sobreveio norma da Anatel que dispensou a necessidade de autorização quando o número de usuários desse tipo de serviço for inferior a 5000 (cinco mil). Considerando que Tício havia prestado o serviço para número inferior a 5000 usuários, assinale a altemativa CORRETA:","a":"Eventual abolítio criminis não pode levar à extinção da punibilidade no presente caso, tendo em vista o trânsito em","b":"julgado da decisão condenatória. Há no caso abolítio criminis capaz de levar à extinção da punibilidade de Tício.","c":"Não há abolitio criminis quando, tratando-se de norma penal em branco, houver modificação apenas da norma complementar emanada de órgão administrativo.","d":"Por se tratar de complemento meramente secundário da norma penal em branco, não se aplica a novatio legis in melius.","e":"","gabarito":"B","materia":"Direito Penal","tema":"Causas de extinção da punibilidade ,Abolitio criminis","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1959511","enunciado":"Sobre o benefício de pensão por morte, assinale a alternativa que está de acordo com a Emenda Constitucional 103/2019:","a":"É vedada a acumulação de pensão por morte deixada por cônjuge ou companheiro de um regime de previdência social com aposentadoria concedida por outro regime, seja ele o Regime Geral de Previdência Social ou regime próprio de previdência social. Consideram-se dependentes do segurado, para fins de concessão de pensão por morte, o cônjuge, a companheira, o","b":"companheiro e o filho não emancipado, de qualquer condição, menor de 21 anos ou inválido ou que tenha deficiência intelectual ou mental ou deficiência grave; os pais; o irmão não emancipado, de qualquer condição, menor de 21 anos ou inválido ou que tenha deficiência intelectual ou mental ou deficiência grave. As cotas por dependente cessarão com a perda dessa qualidade e serão reversíveis aos demais dependentes.","c":"Equiparam-se ao filho, para fins de recebimento de pensão por morte, exclusivamente o enteado e o menor tutelado, desde que comprovada a dependência econômica.","d":"É vedada a acumulação de pensão por morte deixada por cônjuge ou companheiro de um regime de previdência social com pensão por morte concedida por outro regime de previdência social.","e":"","gabarito":"C","materia":"Direito Previdenciário","tema":"Benefícios em Espécie ,Pensão por Morte","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1959510","enunciado":"Sobre o auxilio-inclusão, assinale a alternativa CORRETA:","a":"O valor do auxílio-inclusão percebido por um membro da família será considerado no cálculo da renda familiar mensal per capita para fins de concessão e de manutenção de outro auxílio-inclusão no âmbito do mesmo grupo familiar.","b":"O auxílio-inclusão será devido a partir da data do requerimento e o seu valor corresponderá a 60% (sessenta por cento) do valor do benefício de prestação continuada em vigor. O valor do auxílio-inclusão e o da remuneração do beneficiário do auxílio-inclusão (limitada a 2 salários-mínimos)","c":"percebidos por um membro da família serão considerados no cálculo da renda familiar per capita para fins de manutenção de benefício de prestação continuada concedido anteriormente a outra pessoa do mesmo grupo","d":"familiar. O pagamento do auxilio-inclusão não poderá ser acumulado com o pagamento de seguro-desemprego.","e":"","gabarito":"D","materia":"Direito Previdenciário","tema":"Benefícios em Espécie","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1959509","enunciado":"Assinale a alternativa CORRETA, à luz da legislação e da jurisprudência do Superior Tribunal de Justiça e da TNU:","a":"O tempo de trabalho rural, como segurado especial, posterior ao advento da Lei 8.213/91, pode ser considerado, para fins de concessão de aposentadoria por tempo de contribuição, independentemente do recolhimento de contribuições previdenciárias, exceto para efeito de carência. A aposentadoria por idade do trabalhador rural será devida ao segurado especial, que exerce atividade rural em","b":"regime de economia familiar, desde que tenha completado a idade mínima de 55 anos para mulheres ou 60 anos para homens e tenha cumprido a carência de 180 meses atividade rural imediatamente anterior ao requerimento do benefício ou à data do implemento da idade mínima, sendo vedado o exercício atividade urbana intercalada. Para fins de concessão de aposentadoria por idade híbrida ao trabalhador urbano, será permitido o cômputo, como","c":"carência, do tempo de serviço rural anterior ao advento da Lei 8.213/91, ainda que remoto e descontínuo e mesmo que não tenha sido efetivado o recolhimento das contribuições, nos termos do art. 48, parágrafo 3º, da Lei nº 8.213/91, seja qual for a predominância do labor misto exercido no periodo de carência ou o tipo de trabalho exercido no momento do implemento do requisito etário ou do requerimento administrativo. Acomprovação do tempo de labor rural exige a apresentação de início de prova material, o que, segundo a","d":"jurisprudência do Superior Tribunal de Justiça e da TNU, não se confunde com prova plena. Além disso, diante das dificuldades do trabalhador rural de obtenção de prova escrita, não há exigência de que o documento apresentado como início de prova material seja contemporâneo aos fatos alegados ou que abranja todo o período que se quer comprovar.","e":"","gabarito":"C","materia":"Direito Previdenciário","tema":"Jurisprudência","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1959508","enunciado":"“A” recebe pensão por morte desde 12/04/2011. “B', o instituidor da pensão, era beneficiário de aposentadoria por tempo de contribuição e recebia o benefício desde 10/02/2009. “B” havia sido vencedor de ação trabalhista, que lhe garantiu a majoração dos salários de contribuição referentes ao período de 01/2005 a 12/2008. O trânsito em julgado da sentença trabalhista ocorreu em 15/07/2015. “B” nunca requereu a revisão do benefício de aposentadoria. Em 03/03/2022, “A” formulou requerimento administrativo de revisão da renda mensal inicial do benefício de pensão por morte, para incluir, no cálculo da pensão, o aumento dos salários de contribuição do falecido no período de 01/2005 a 12/2008, tal como reconhecido na ação trabalhista. O INSS, ao analisar o requerimento de “A”, reconheceu a decadência do direito à revisão. Inconformada com a decisão administrativa, “A” ajuizou ação judicial em 03/05/2022. Sobre a decadência, assinale a alternativa que está em consonância com a legislação e a jurisprudência do Superior Tribunal de Justiça e da TNU:","a":"não ocorreu a decadência, pois o prazo de 10 anos deve ser contado a partir do trânsito em julgado da sentença trabalhista.","b":"não se aplica o instituto da decadência, pois a questão não foi apreciada no ato administrativo de análise de concessão do benefício previdenciário.","c":"ocorreu a decadência, pois o prazo de 10 anos deve ser contado a partir do início do recebimento da pensão por morte.","d":"ocorreu a decadência, pois o prazo de 10 anos deve ser contado a partir do início do recebimento da aposentadoria pelo instituidor da pensão. Direito Previdenciário>Beneficiários do Regime Geral de Previdência Social - RGPS ,","e":"","gabarito":"A","materia":"Direito Previdenciário","tema":"Prescrição e Decadência ,Jurisprudência ,Processo Administrativo Previdenciário","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1001","enunciado":"Ano: 2022 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto “A”, beneficiário de auxílio-acidente desde 05/06/2007, recolheu contribuições como contribuinte individual no período de 01/2017 a 01/2021. Ficou incapacitado, de forma total e permanente, em 18/05/2022. Sobre a qualidade de segurado de “A”,","a":"é CORRETO afirmar que: manteve a qualidade de segurado até 31/01/2021.","b":"não perdeu a qualidade de segurado, pois está em gozo de auxilio-acidente.","c":"manteve a qualidade de segurado até 31/01/2022.","d":"manteve a qualidade de segurado até 15/03/2022.","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1959506","enunciado":"Assinale a alternativa CORRETA:","a":"Após a entrada em vigor da Emenda Constitucional nº 103, de 12 de novembro de 2019, não é mais possível a concessão de aposentadoria mediante a conversão de tempo especial em comum, em razão de vedação expressa. De acordo com a jurisprudência da TNU — Turma Nacional de Uniformização, é possível, no curso do processo","b":"judicial, a reafirmação da Data de Entrada de Requerimento (DER) para a concessão de benefícios previstos nas regras de transição da Emenda Constitucional 103/19, mesmo que o requerimento original preceda a vigência desta Emenda Constitucional.","c":"O direito adquirido permite que o segurado do Regime Geral de Previdência Social, que tenha cumprido todos os requisitos para obtenção de aposentadoria até a entrada em vigor da Emenda Constitucional 103/19, conjugue vantagens do novo sistema com aquelas aplicáveis ao regime anterior.","d":"As restrições relativas à acumulação do benefício de pensão por morte, previstas na Emenda Constitucional 103/19, não serão aplicadas se o direito ao benefício houver sido adquirido antes da entrada em vigor da Emenda Constitucional. Considera-se adquirido o direito na data do requerimento.","e":"","gabarito":"B","materia":"Direito Previdenciário","tema":"Jurisprudência","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1959505","enunciado":"Suponha, no contexto da Constituição brasileira de 1988, a entrada em vigor de uma Emenda Constitucional que suprima a liberdade de reunião, como medida adotada em um contexto de combate ao terrorismo. É CORRETO afirmar, a esse respeito, que","a":"essa Emenda terá como fundamento de validade o dever estatal de proteção da vida, e sua constitucionalidade é reafirmada pela escala positivada constitucionalmente de “valores prioritários”.","b":"em se utilizando a interpretação conforme a Constituição, com base na vedação da simetria, pode-se decretar a nulidade da hipótese de incidência dessa Emenda Constitucional às autoridades dos níveis federativos dos Estados- membros e dos Municípios.","c":"é flagrantemente inconstitucional, por eliminar um direito fundamental, sendo competente para reconhecer a inconstitucionalidade o Supremo Tribunal Federal, hipótese em que se exige a maioria de 2/3 (dois terços) de seus membros (full bench).","d":"cada magistrado, nos processos comuns em curso cuja decisão dependa dessa novel Emenda à Constituição, poderá afastá-la, por inconstitucionalidade, nos fundamentos da decisão, inclusive de ofício. Direito Constitucional>Controle de Constitucionalidade ,","e":"","gabarito":"D","materia":"Direito Constitucional","tema":"Controle de Constitucionalidade ,Direitos Individuais ,Direito à Liberdade","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1004","enunciado":"Ano: 2022 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto No julgamento da Arguição de Descumprimento de Preceito Fundamental (ADPF) nº 756 ficou registrado que “[...] incumbe ao Supremo Tribunal Federal exercer o seu poder contramajoritário, oferecendo a necessária resistência às ações e omissões de outros Poderes da República de maneira a garantir a integral observância dos ditames constitucionais, na espécie, daqueles [que] dizem respeito à proteção da vida e da saúde.”. A partir desse trecho, assinale a alternativa CORRETA:","a":"as decisões adotadas no âmbito da ADPF não produzem efeitos erga omnes, mas seus fundamentos são vinculantes para o Poder Judiciário.","b":"o chamado “poder contramajoritário” viola diretamente o sistema democrático brasileiro, que adota o govemo da maioria e a constitucionalidade automática, insindicável, das decisões emanadas das respetivas instâncias assim eleitas.","c":"o papel do Poder Judiciário deve ser sempre alinhado com as decisões majoritárias dos poderes representativos eleitos, pois o Supremo Tribunal Federal detém o monopólio do controle de constitucionalidade das leis e dos decretos presidenciais.","d":"a decisão do Supremo Tribunal Federal em sede de ADPF pode fixar as condições e o modo de interpretação e aplicação de qualquer preceito fundamental violado.","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1959503","enunciado":"Quanto à “Reforma do Judiciário”, realizada pela Emenda Constitucional nº 45, de 2004, assinale a alternativa CORRETA:","a":"foi alterada a estrutura do recurso extraordinário, que passou a assumir sempre caráter rescisório e, quanto ao controle difuso-concreto da constitucionalidade dos atos normativos, houve objetivização dos processos comuns.","b":"foram alteradas as competências expressas de alguns tribunais e foi admitida a edição de súmula vinculante, de ofício, pelo Supremo Tribunal Federal, ou seja, sem qualquer provocação de legitimados ou partes interessadas.","c":"a ação declaratória de constitucionalidade teve sua legitimidade ativa reduzida e a reclamação constitucional foi renomeada para representação constitucional, mantendo as mesmas hipóteses de cabimento.","d":"extinguiu-se a possibilidade de que em ação direta de inconstitucionalidade por omissão o Supremo Tribunal Federal determine ao órgão administrativo que adote, em trinta dias, as providências necessárias para tornar efetiva a norma.","e":"","gabarito":"B","materia":"Direito Constitucional","tema":"Poder Judiciário","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1959502","enunciado":"Sobre as prerrogativas constitucionais atuais dos parlamentares federais no Brasil, assinale a alternativa CORRETA:","a":"a prisão em flagrante delito de Senador da República só é possível em crimes relacionados ao exercício do mandato ou abuso do cargo.","b":"após a prisão em flagrante delito, os autos devem ser remetidos à respectiva Casa legislativa à qual pertença o parlamentar, para deliberação parlamentar sobre a prisão.","c":"qualquer processo e investigação ficam suspensos até que o Congresso Nacional delibere sobre a conveniência de sua continuidade durante o exercício do mandato parlamentar.","d":"tem-se a imunidade material, que se aplica aos parlamentares e seus suplentes, independentemente de estarem nas dependências físicas do Congresso Nacional. Direito Constitucional> Poder Constituinte Originário, Derivado e Decorrente - Reforma (Emendas e Revisão) e Mutação da Constituição ,","e":"","gabarito":"B","materia":"Direito Constitucional","tema":"Poder Legislativo ,Vedações, Garantias e Imunidades Parlamentares","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1007","enunciado":"Teoria da Constituição ,Poder Executivo ,Congresso Nacional Ano: 2022 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto Considere as seguintes afirmações e assinale a alternativa CORRETA: I. Pelo spoil system, atualmente praticado no Brasil, a indicação para cargos públicos de confiança no Poder Executivo é rotineiramente utilizada para obter alianças ou apoios políticos, prosperando o apadrinhamento e a troca de favores. II. A aprovação final de leis no Congresso Nacional opera, em grande medida, por meio do sistema comissional, e não em sessão plenária. III. Municípios não podem aprovar leis municipais em contradição com as leis federais, cabendo à Justiça Federal a competência originária para restabelecer a superioridade e unidade da legislação federal. IV. É vedado o overruling de decisão proferida pelo Supremo Tribunal Federal por meio da aprovação de Emenda","a":"Constitucional, sendo esta hipótese, necessariamente, de inconstitucionalidade da respectiva Emenda Constitucional. Apenas as afirmações I e Il são corretas.","b":"A afirmação IV está correta.","c":"A afirmação Il está errada e a afirmação Ill está correta apenas para as competências comuns.","d":"A afirmação I está correta e a afirmação Il foi correta apenas para o período do regime militar. Direito Constitucional>Controle de Constitucionalidade ,Súmula Vinculante ,","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1959500","enunciado":"Ano: 2022 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto Sobre o controle de constitucionalidade e seus efeitos, no Brasil, pode-se assegurar que, atualmente,","a":"o enunciado de súmula vinculante possui efeito impeditivo de recurso e é considerado fundamento suficiente para a decisão judicial, vinculando exclusivamente a Administração Pública.","b":"no julgamento da arguição de descumprimento de preceito fundamental pelo Supremo Tribunal Federal este não pode adotar efeitos prospectivos, sendo igualmente vedados os efeitos aditivos ou legislativos.","c":"a ação direta de inconstitucionalidade de Lei Federal julgada procedente por decisão de Tribunal Regional Federal vincula apenas os magistrados federais da respectiva Região.","d":"na chamada fase de julgamento da modulação temporal dos efeitos da decisão, em sede de controle abstrato, no Supremo Tribunal Federal, a retroatividade da decisão de inconstitucionalidade exige apenas a maioria simples dos integrantes da Corte. Direito Constitucional>Controle de Constitucionalidade ,","e":"","gabarito":"D","materia":"Controle Repressivo do Poder Judiciário: o Controle Difuso ou Aberto","tema":"","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1009","enunciado":"Ano: 2022 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto No Brasil, os fenômenos da inconstitucionalidade e da não-recepção têm semelhanças, mas apresentam regime jurídico diverso, especialmente porque a inconstitucionalidade exige, sempre,","a":"para o controle de atos normativos, que estes tenham sido editados posteriormente à entrada em vigor da Constituição-parâmetro, enquanto a não-recepção opera como juízo de inexistência de atos normativos editados anteriormente à Constituição-parâmetro em vigor e com conteúdo incompatível com esta.","b":"um controle judicial, pela via de alguma das ações específicas, diferentemente da não-recepção, que pode ser reconhecida por qualquer agente público.","c":"um juízo comparativo entre lei ou ato normativo, de uma parte, e Constituição em vigor, de outra parte, diferentemente da não-recepção, que só pode operar entre ato administrativo anteriormente editado em comparação com a Constituição-parâmetro em vigor.","d":"um juízo comparativo entre qualquer lei em vigor e Constituição, podendo ser esta a atual ou a anterior, enquanto que adota-se a não-recepção apenas para estabelecer a ilegitimidade de leis publicadas anteriormente à Constituição em vigor, perante a Constituição anterior.","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1959498","enunciado":"","a":"Conforme o Estatuto constitucional da Magistratura, o juiz necessita residir na respectiva comarca de sua atividade jurisdicional.","b":"está protegido pela garantia da inamovibilidade, sendo vedada qualquer forma de permuta entre magistrados.","c":"goza da irredutibilidade de subsídio, garantida apenas após dois anos de exercício do cargo.","d":"poderá ser removido ou colocado em disponibilidade, por interesse público, em virtude de decisão adotada pelo voto da maioria absoluta do Conselho Nacional de Justiça. Direito Constitucional>Classificação das Constituições ,Teoria da Constituição ,","e":"","gabarito":"D","materia":"Legislação dos TRFs","tema":"Lei Complementar 35 de 1979 - Lei Orgânica da Magistratura","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1011","enunciado":"Ano: 2022 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto Sobre a seguinte tese: “São sempre necessárias leis específicas e expressas para efetivar e concretizar normas programáticas ou sociais da Constituição brasileira de 1988”, assinale, segundo o Direito Constitucional brasileiro, a alternativa CORRETA:","a":"se trata de uma livre opção interpretativa, podendo tal exigência ser invocada legitimamente para evitar as","b":"dificuldades advindas de uma Constituição social extremamente custosa para uma economia periférica. decorre da impossibilidade de aplicação direta de “princípios constitucionais” por decisões judiciais.","c":"é a base, historicamente falando, de uma teoria de bloqueio, especialmente quanto ao Estado Social, e reforça uma visão legicêntrica do sistema jurídico.","d":"autoriza o cabimento da ação popular, respeitada a condicionante de que se trate de omissão que tone inviável o exercício dos direitos constitucionais e das prerrogativas inerentes à nacionalidade, soberania e cidadania.","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1959496","enunciado":"Sobre a história, teoria e prática dos direitos constitucionais e fundamentais no Brasil, assinale a alternativa CORRETA:","a":"o Supremo Tribunal Federal entende que a ordem de desindexação, quando direcionada a provedores de internet com atuação no Brasil, equivale ao direito ao esquecimento, e admite sua incidência na internet como um direito fundamental individual.","b":"é vedado, por atentar contra a soberania nacional, o uso de jurisprudência constitucional estrangeira na jurisprudência brasileira, especialmente quando resultar em redução do programa normativo dos direitos","c":"fundamentais expressos na Constituição de 1988. a Constituição de 1891, em norma inovadora, garantiu a representação da minoria na Câmara dos Deputados.","d":"o juiz das garantias, criado recentemente para atuar após o juiz da causa, na análise do cumprimento integral dos direitos fundamentais em cada processo, pode ser caracterizado como uma primeira fase revisora de decisões judiciais, reforçando a cultura garantista.","e":"","gabarito":"C","materia":"Direito Constitucional","tema":"Teoria dos Direitos Fundamentais","origem":"TRF - 3ª REGIÃO - 2022 - TRF - 3ª REGIÃO - Juiz Substituto","ano":"2022","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085975","enunciado":"Um programador está criando o menu principal da página de abertura de um site, que conterá o bloco principal de links de navegação. Considerando os elementos semânticos da linguagem HTML5, estes links devem ficar imediatamente no interior","a":"da tag <mark>","b":"<progress>","c":"<choose>","d":"<nav>","e":"<navigation>","gabarito":"D","materia":"Programação","tema":"HTML (HyperText Markup Language) ,Linguagens de marcação","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085974","enunciado":"Considere, em uma página web que usa ASP.Net, que há um vetor chamado colaboradores, que contém o nome de 10","a":"funcionários. Para percorrer esse vetor exibindo cada um destes nomes em um parágrafo HTML utiliza-se a instrução @for(int i=0;iccolaboradores.length;i++){<p><%@colaboradores.getNome();%> </p>}","b":"@foreach (var fun in colaboradores){<p>@fun</p>}","c":"@for(int i=0;i<=colaboradores.length;i++){<p>@nome in colaboradores</p>}","d":"@foreach (string f from colaboradores){ <p>${ f} </p>}","e":"@while (string fun in colaboradores){<p>${fun}</p> @next}","gabarito":"B","materia":"Programação","tema":".Net ,ASP ,Linguagens de programaçãoLinguagens de marcação","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085973","enunciado":"","a":"Para concatenar a string \"TRF\" com a variável reg que contém o valor inteiro 3, em Java e PHP, utilizam-se, respectivamente, String(\"TRF\") +reg e str(\"TRF\").$reg","b":"\"TRF\"+reg e \"TRF\".$reg","c":"\"TRF\"+reg e \"TRF\"+$reg","d":"\"TRF\",reg e Concat(\"TRF\",$reg)","e":"String.Concat( \"TRF\",reg) e \"TRF\"+$reg","gabarito":"B","materia":"Programação","tema":"Java ,PHP ,Linguagens de programação","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085971","enunciado":"Em uma página JSP, para que se possa instanciar objetos da classe Cliente, que se encontra no pacote modelo, será","a":"necessário importar esta classe utilizando-se a instrução <%@import src=\"modelo.Cliente\"%>","b":"<%@import package=\"model\" class=\"Cliente\"%>","c":"<%@page import=\"modelo.Cliente\"%>","d":"<%!import(\"modelo.Cliente\")%>","e":"<%@import href= \"modelo.Cliente\"%>","gabarito":"C","materia":"Programação","tema":"JSP (JavaServer Pages)","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085970","enunciado":"No método main da classe principal de uma aplicação Java SE foi realizada a chamada abaixo ao método aumentarSalario, da mesma classe, que aumenta o salário em 10%: double salarioNovo, salarioAtual= 10678.67; salarioNovo = aumentarSalario(salarioAtual);","a":"O método aumentarSalario pode ser escrito corretamente utilizando protected static float aumentarSalario(double salarioAtual) { return salarioAtual * 1.1; }","b":"public static void aumentarSalario(double salarioAtual) { return salarioAtual * 1.1; }","c":"public static double aumentarSalario(double[ ] salarioAtual) { return salarioAtual * 1.1; }","d":"private static double aumentarSalario(double sAtual) { return sAtual * 1.1; }","e":"private static double aumentarSalario(salarioAtual) { return salarioAtual * 0.1;}","gabarito":"D","materia":"Programação","tema":"Plataforma Java ,Java SE","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085969","enunciado":"Considere o trecho abaixo, em uma aplicação Java em condições ideais.","a":"Os valores que serão armazenados nas variáveis x, y e z são, respectivamente, true - true e true.","b":"false - true e false.","c":"false - false e false.","d":"true - false e false.","e":"true - false e true.","gabarito":"E","materia":"Programação","tema":"Java ,Linguagens de programação","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085968","enunciado":"Considere o método Java abaixo. Caso o driver JDBC não esteja disponível na aplicação e não exista o banco de dados trf3, as exceções que deverão ser","a":"tratadas nas lacunas I e II são, correta e respectivamente, NullPointerExceptionException e DatabaseException.","b":"DriverNotFoundException e MySQLException.","c":"JDBCDriverException e DatabaseException.","d":"ClassNotFoundException e SQLException.","e":"JDBCDriverException e DatabaseSQLException.","gabarito":"D","materia":"Programação","tema":"Java ,JDBC ,Linguagens de programação","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085967","enunciado":"Considere o método abaixo, retirado de uma aplicação Java em condições ideais.","a":"Para corrigir o erro que será gerado quando o método entrada for executado, deve-se mudar cont<=3 no comando for para cont <=2.","b":"n = new double[3] para n = new array[3].","c":"cont<=3 no comando for para cont>=3.","d":"cont++ para cont=cont+l.","e":"\"Valor\" + (cont + 1) para \"Valor\" . (cont + 1 ).","gabarito":"A","materia":"Programação","tema":"Java ,Linguagens de programação","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085966","enunciado":"","a":"instrução < !ELEMENT funcionário (nome, (RG | CPF) + )> , presente em um DTD para um documento XML, indica que","b":"A no interior do elemento funcionário deve existir ou o elemento RG ou CPF , sendo aceitável qualquer um dos dois. RG e CPF são elementos opcionais, ou seja, não precisa existir nem RG nem CPF no interior do elemento funcionário.","c":"há obrigatoriedade dos elementos RG e CPF no interior do elemento nome.","d":"o elemento nome é opcional, mas o elemento RG é obrigatório no interior do elemento funcionário.","e":"há obrigatoriedade dos elementos RG e CPF no interior do elemento funcionário.","gabarito":"A","materia":"Programação","tema":"XML (Extensible Markup Language) ,Linguagens de marcação","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085965","enunciado":"Considere o trecho abaixo em uma página web que utiliza JSF. Para que seja obtida uma instância de Pessoa e chamado o método getNome a partir dessa instância, mostrando no campo","a":"do formulário o nome obtido, a lacuna i deve ser preenchida corretamente por pessoa.getNome()","b":"{ pessoa.getNome();}","c":"jsf->pessoa.nome","d":"# [pessoa.getNome()]","e":"# {pessoa.nome}","gabarito":"E","materia":"Programação","tema":"JSF (Java Server Faces) ,Frameworks Java","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085964","enunciado":"Em C#, para converter um número, digitado no campo txtidade de um formulário, em um inteiro de 32 bits, e armazenar","a":"esse número na variável idade, do tipo int, utiliza-se a instrução idade = Convert.ToUInt ( txtidade.Text ( ) ) ;","b":"idade = txtidade.Text ( ) . toInt 32 ( ) ;","c":"idade = Integer . Parse lnt 32 (txt idade.Text ) ;","d":"idade = Integer . parselnt (txtIdade . getText ( ) ) ;","e":"idade = Convert .ToInt32 (txtidade .Text ) ;","gabarito":"E","materia":"Programação","tema":"Linguagens de programação ,C Sharp","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085963","enunciado":"Considere conn um objeto que contém uma conexão com um banco de dados SQL Server e que essa conexão está aberta e em condições ideais. Considere, ainda, que sql é uma variável do tipo string que contém a instrução INSERT abaixo. sql = \"INSERT INTO cliente (nome, cpf) VALUES(®nome,@cpf) \" ; Após o comando SqlCommand cmd = new SqlCommand(sql, conn) ; , que Cria um objeto do tipo SqlCommand com a instrução SQL e a conexão, para incluir o conteúdo do campo txtNome do formulário como parâmetro @nome na instrução","a":"INSERT utiliza-se o comando cmd. SetParameter(txtNome.Text, \"@nome\") ;","b":"cmd.Parameters.Add(new SqlParameter(\"@nome\", txtNome.Text));","c":"cmd.BindParam.Add(txtNome.Text, \"@nome\");","d":"cmd.Parameters.Append(new Parameter(txtNome.Text,\"@nome\"));","e":"cmd.BindParam(new BindParam(txtNome.Text, \"@nome\"));","gabarito":"B","materia":"Banco de Dados","tema":"SQL Server","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085962","enunciado":"Na classe de conexão com o banco de dados de uma aplicação C# criada com o Visual Studio, em condições ideais, foi criado o método abaixo. public static ..I.. getConnection ( ) { ..II.. return conn; } Considerando a existência de um banco de dados chamado DB_TRF3, em condições ideais, preenchem, correta e respectivamente, as lacunas I e II :","a":"I - SqlConnection II - Sql Connection conn = new Sql Connection ( @ \" Data Source = .\\ SQLEXPRESS ; Initial Catalog = DB_TRF3 ; Integrated Security = True ; Pooling = False \" ) ;","b":"I - Connection II - Connection conn = new Connection.getConnection (@ \"Data Source = .\\ SQLEXPRESS ; Initial Catalog = DB_TRF3 ; Integrated Security = True ; Pooling = False \" ) ;","c":"I - ODBCConnection II - ODBCConnection conn = new ODBCConnection (@\"Data Source = .\\ SQLEXPRESS ; Initial Catalog = DBTRF3 / D i g i t a l S e c u r i t y = T r u e ; P o o l i n g = T r u e \" );","d":"I - Connection II - Connection conn = Driver Manager .get Connection (\"odbc : sqlserver ://localhost: 1433 /DB _TRF3\" , \"root \" , \" \");","e":"I - SqlConnection II - Sql Connection conn = DriverManager.get SqlConnection( \"odbc : sqlserver:// localhost : 1433 / DB_TRF3\" , \"root \" , \" \");","gabarito":"A","materia":"Programação","tema":"Linguagens de programação ,C Sharp","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085961","enunciado":"O principal namespace da ADO .NET, que contém as classes utilizadas pelos provedores de acessos (que representam","a":"tabelas, colunas, linhas etc.) é denominado System.Data","b":"ODBCNet.DataSet","c":"SqlClient.Connection","d":"OleDb.Data","e":"SqlDb.Connection","gabarito":"A","materia":"Programação","tema":".Net","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085960","enunciado":"","a":"SCRUM atende aos princípios do Manifesto Ágil porque pessoas de negócio e desenvolvedores devem trabalhar diariamente em conjunto por todo o projeto.","b":"não aceita mudanças nos requisitos durante o desenvolvimento e por isso as entregas são mais ágeis.","c":"as entregas ocorrem sempre no prazo, nunca adiantadas ou atrasadas.","d":"mais importante que a motivação dos desenvolvedores é a disciplina gerencial imposta que organiza e agiliza o desenvolvimento.","e":"não admite a comunicação direta entre os desenvolvedores, pessoalmente. Isso só pode ser feito por intermédio de um gerente ou coordenador.","gabarito":"A","materia":"Engenharia de Software","tema":"Processos de Software - Desenvolvimento Ágil ,Scrum","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085959","enunciado":"De acordo com as diversas definições da Arquitetura Orientada a Serviços - SOA, ela","a":"aumenta o custo de manutenção das aplicações porque é uma tecnologia que necessita de muitos recursos operacionais.","b":"necessita ser adquirida e pode ser instalada em quaisquer ambientes operacionais com alguma customização,","c":"dependendo da tecnologia utilizada. é um web Service de alta performance em virtude de sua arquitetura informal e adaptável.","d":"necessita ser adquirida e pode ser instalada em quaisquer ambientes operacionais sem customização alguma.","e":"não é, por si só, uma tecnologia e nem uma metodologia, contudo pode ser considerada uma filosofia arquitetural.","gabarito":"E","materia":"Arquitetura de Software","tema":"SOA (Service-oriented architecture)","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085958","enunciado":"","a":"estrutura da mensagem SOAP é definida em um documento XML que contém o elemento","b":"A <SOAP-ENV:header>que contém o corpo da mensagem. <SOAP-ENV:hdrfault> que contém os erros que podem ocorrer.","c":"<SOAP-ENV:envelope> que, como raiz, define que se trata de uma mensagem SOAP.","d":"<SOAP-ENV:body> que estabelece informações específicas como autenticação.","e":"<SOAP-ENV:transacktfault> que contém os erros de comunicação.","gabarito":"C","materia":"Arquitetura de Software","tema":"SOAP (Simple Object Access Protocol)","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085957","enunciado":"Os documentos WSDL devem conter, principalmente, os elementos: 1. definição dos tipos de dados usados pelo web Service (XML Schema). 2. definição dos elementos de dados para cada operação. 3. descrição das operações que podem ser feitas e mensagens envolvidas. 4. definição do protocolo e formato de dados para cada tipo de porta.","a":"Esses elementos são, respectivamente, type - portType - biding e message.","b":"types - message - portType e binding.","c":"wsdl - type - message e portType.","d":"message - biding - portType e wsdl.","e":"portType - type - message e biding.","gabarito":"B","materia":"Arquitetura de Software","tema":"WSDL","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085956","enunciado":"Um Analista em TI necessita desenvolver um projeto otimizando o reuso das classes. Para tanto, ele está analisando uma solução que possibilita a existência de várias interfaces com o usuário que podem ser modificadas sem que haja a necessidade da alteração das regras de negócio, proporcionando assim muito mais flexibilidade e oportunidades de reuso das classes. O modelo de arquitetura padrão que atende essa necessidade porque contempla a divisão do projeto em camadas muito","a":"bem definidas é o MVC.","b":"SOAP.","c":"SPRINT.","d":"XML.","e":"ASP.","gabarito":"A","materia":"Arquitetura de Software","tema":"MVC (Model-view-controller)","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085955","enunciado":"Considere manter a integridade da linha de base (baseline) como sendo uma atividade de realização recomendada no CMMI 1.3 para desenvolvimento. Essa recomendação é objeto da área de processo de suporte de nível 2 de maturidade","a":"denominada definição do processo organizacional.","b":"gestão de suporte a mudanças.","c":"medições e análises.","d":"gerência de configuração.","e":"integração de produtos.","gabarito":"D","materia":"Governança de TI","tema":"CMMI (Capability Maturity Model Integration)","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085954","enunciado":"De acordo com o MPS.BR, Guia Geral MPS de Software, o propósito do processo Desenvolvimento de Requisitos é definir os","a":"requisitos do cliente, do produto e, também, dos componentes do produto.","b":"cliente e do produto, apenas.","c":"produto e dos componentes do produto, apenas.","d":"cliente, apenas.","e":"produto, apenas.","gabarito":"A","materia":"Governança de TI","tema":"MPS.BR","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085953","enunciado":"","a":"Reunião Diária do Scrum é A executada no final da Sprint para inspecionar o incremento e adaptar o Backlog do Produto, se necessário.","b":"um time-boxed de 15 minutos, durante o qual um “Pronto”, versão incremental potencialmente utilizável do produto, é criado.","c":"uma oportunidade para o Time Scrum inspecionar a si próprio e criar um plano para melhorias a serem aplicadas na próxima Sprint.","d":"um time-boxed de 15 minutos, para que o Time de Desenvolvimento possa sincronizar as atividades e criar um plano","e":"para as próximas 24 horas. um time-boxed de 60 minutos, durante o qual os produtos de uma Sprint são definidos.","gabarito":"D","materia":"Engenharia de Software","tema":"Processos de Software - Desenvolvimento Ágil ,Scrum","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085952","enunciado":"No Processo Unificado, um release do produto é criado, distribuído aos usuários e instalado em seu local de trabalho, no","a":"fluxo (workflow) de Análise e Projeto.","b":"Implantação.","c":"Gerenciamento de projeto.","d":"Implementação.","e":"Modelagem de negócios.","gabarito":"B","materia":"Engenharia de Software","tema":"RUP (Rational Unified Process) - Processo Unificado Rational ,Processos de Software","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085951","enunciado":"Durante um levantamento, um Analista em TI obteve a seguinte lista de requisitos: 1. O sistema, em todas as suas funções de consulta, não poderá exceder o tempo de resposta de até 15 milissegundos. 2. Os advogados devem ser capazes de pesquisar as listas de agendamento de todos os juízes. 3. O sistema deve gerar, a cada dia, para cada unidade do Tribunal, a lista dos juízes disponíveis para as consultas daquele dia. 4. O sistema de pesquisa de processos deve estar disponível para todas unidades do Tribunal durante as horas normais de atendimento ao público (de segunda à sexta-feira, das 10h às 16h). Períodos de não operação dentro do horário normal de trabalho não podem exceder 10 segundos em um dia. Atribuindo-se RF para os Requisitos Funcionais e NF para os Não Funcionais, a lista de requisitos acima apresentada (1, 2, 3","a":"e 4), pela ordem, descreve, respectivamente: NF - NF - RF - RF.","b":"RF - RF - NF - NF.","c":"NF - RF - RF - NF.","d":"RF - NF - RF - NF.","e":"NF - RF - NF - RF.","gabarito":"C","materia":"Engenharia de Software","tema":"Engenharia de Requisitos","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085950","enunciado":"","a":"Normalmente, na engenharia de software, antes de especificar os requisitos, deve-se realizar as etapas de modelagem de dados; modelagem funcional; e revisão da documentação.","b":"modelagem de negócio; elicitação e análise; classificação e registro.","c":"levantamento detalhado e classificação; definição do escopo; e priorização e negociação.","d":"modelagem funcional; definição do escopo e classificação; e modelagem de negócio.","e":"descoberta; classificação e organização; e priorização e negociação.","gabarito":"E","materia":"Engenharia de Software","tema":"Metodologia de desenvolvimento de software ,Engenharia de Requisitos","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085949","enunciado":"Em uma visão espiral do processo de engenharia de requisitos, a partir do início até sua conclusão, a especificação de","a":"requisitos ocorre na seguinte ordem: especificação de requisitos de negócio, de usuário e de sistema.","b":"sistema, de negócio e de usuário.","c":"negócio, de sistema e de usuário.","d":"sistema, de usuário e de negócio.","e":"usuário, de negócio e de sistema.","gabarito":"A","materia":"Engenharia de Software","tema":"Engenharia de Requisitos","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085948","enunciado":"Um Analista em TI foi designado para gerenciar um projeto de software e, como gerente, ele deve iniciar pela comunicação à equipe e aos clientes de como o trabalho será feito, buscar antecipar eventuais problemas que possam surgir no decorrer","a":"do projeto e estabelecer soluções alternativas a eles. De modo geral, a formalização desses quesitos é registrada no plano de comunicação.","b":"na especificação de requisitos funcionais.","c":"na definição do escopo do projeto.","d":"no plano de projeto.","e":"na especificação de requisitos não funcionais.","gabarito":"D","materia":"Engenharia de Software","tema":"Gestão de Projetos em Engenharia de Software","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085947","enunciado":"No modelo em espiral de processo de software (Boehm), antes de cada atividade de prototipação, é sempre realizada uma","a":"atividade de plano de desenvolvimento.","b":"validação de requisitos.","c":"teste de aceitação.","d":"análise de riscos.","e":"plano de ciclo de vida.","gabarito":"D","materia":"Engenharia de Software","tema":"Outros modelos de Processo de Software ,Processos de Software","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085946","enunciado":"Considere a figura abaixo.","a":"O modelo de processo de software representado é orientado a reuso.","b":"desenvolvimento incremental.","c":"em cascata.","d":"processo empírico.","e":"processo unificado.","gabarito":"B","materia":"Engenharia de Software","tema":"Outros modelos de Processo de Software ,Processos de Software","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085945","enunciado":"Em uma contagem de pontos de função, um ALI - Arquivo Lógico Interno, com grau de complexidade média, contribui para","a":"a contagem com 50 pontos.","b":"20 pontos.","c":"10 pontos.","d":"07 pontos.","e":"15 pontos.","gabarito":"C","materia":"Engenharia de Software","tema":"Métricas de Software ,Análise de Pontos de Função","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085944","enunciado":"Em Análise de Pontos de Função, uma Consulta Externa - CE constitui-se de dados extraídos de","a":"Arquivos Lógicos Externos (ALEs) para, após os cálculos necessários, efetuar a atualização dos Arquivos Lógicos Internos (ALIs).","b":"Arquivos Lógicos Internos (ALIs), de Arquivos de Interface Externa (AlEs) e/ou de Informações de Controle, após realizar cálculos e atualizar os arquivos que são enviados para fora da fronteira do sistema.","c":"Arquivos Lógicos Externos (ALEs), de Arquivos de Interface Interna (Alls) e de Informações de Controle, podendo realizar cálculos e manutenção nos arquivos que cruzam a fronteira para dentro do sistema.","d":"Arquivos Lógicos Externos (ALEs), de Arquivos de Interface Externa (AlEs) e de Informações de Controle, podendo realizar cálculos e manutenção nos arquivos que cruzam a fronteira para dentro do sistema.","e":"Arquivos Lógicos Internos (ALIs), de Arquivos de Interface Externa (AlEs) e/ou de Informações de Controle sem realizar cálculos ou manutenção nos arquivos que cruzam a fronteira do sistema e sem alterar seu comportamento.","gabarito":"E","materia":"Engenharia de Software","tema":"Métricas de Software ,Análise de Pontos de Função","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085943","enunciado":"","a":"Programação Orientada a Objetos - POO tem alguns mecanismos para garantir maior segurança no código. Mais especificamente, nos casos dos atributos de classes, a recomendação é utilizar a visibilidade private para os atributos de uma classe. Assim, considerando que uma classe tenha sido criada com a visibilidade private,","b":"A atributos e métodos são acessíveis somente dentro das classes que pertençam ao mesmo pacote. aqueles que tenham acesso à classe terão acesso também a qualquer membro.","c":"atributos e métodos são acessíveis dentro da própria classe, das subclasses e das classes que façam parte do mesmo","d":"pacote. a classe pode ser instanciada por qualquer outra classe.","e":"o acesso aos atributos dessa classe deve ser feito somente por operações definidas na mesma classe que contêm os atributos desejados.","gabarito":"E","materia":"Programação","tema":"Programação Orientada a Objetos","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085942","enunciado":"O Polimorfismo, um dos Pilares da Programação Orientada a Objetos - POO,","a":"ocorre quando uma classe tem um relacionamento do tipo “1 para” com outra classe e isso implica no modo como a definição das classes devem ocorrer nas aplicações.","b":"consiste em esconder os atributos da classe de quem for utilizá-la. Isso se deve a: 1 - para quem for usar a classe não a use de forma errada; e 2 - para que implementação seja feita por meio dos métodos get e set.","c":"permite que um mesmo método possa ter vários comportamentos e a definição de qual comportamento será executado se dá pelo valor diferente de um de seus atributos.","d":"é um conceito que permite que as características bem como as operações, de um modo global, possam ser repassadas para várias funcionalidades da aplicação.","e":"permite utilizar atributos e operações diferentes de uma subclasse, acrescentando ou substituindo características herdadas da classe pai.","gabarito":"C","materia":"Engenharia de Software","tema":"Orientação a Objetos","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085941","enunciado":"Um Caso de Uso é uma especificação de uma sequência de interações entre um sistema e os agentes externos que utilizam o sistema. Há vários formatos de descrição de Caso de Uso propostos na literatura, assim como vários graus de abstração utilizados. Considere a descrição de Caso de Uso abaixo. O Cliente chega ao caixa eletrônico e insere seu cartão. O Sistema requisita a senha do Cliente. Após o Cliente fornecer a senha e esta ser validada o Sistema exibe as opções de operações possíveis. O Cliente opta por realizar um saque. Então o Sistema requisita o total a ser sacado. O Sistema fornece a quantia desejada e imprime o recibo para o Cliente.","a":"Trata-se de uma descrição de Caso de Uso inválida, pois contém comportamento interno do sistema.","b":"contínua de Caso de Uso com formato essencial.","c":"contínua de Caso de Uso com formato real.","d":"de Caso de Uso de Negócio com descrição contínua.","e":"contínua de Caso de Uso hipotético com cenário de 1° instância.","gabarito":"C","materia":"Engenharia de Software","tema":"UML ,Diagrama de Casos de Uso","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085940","enunciado":"No contexto software versus ser humano, existem duas áreas em evolução: User Experience Design - UX, que se preocupa com o ponto de contato de um produto/serviço com as pessoas, e User Interface - UI. Apesar de estarem relacionadas, essas","a":"áreas são muito diferentes. No caso da UI, o primeiro ponto de avaliação do usuário e a maior influência para isso são Robustez e Eficácia.","b":"Eficácia e Familiaridade.","c":"Familiaridade e Apresentação.","d":"Apresentação e Robustez.","e":"Clareza e Eficácia.","gabarito":"E","materia":"Arquitetura de Software","tema":"Usabilidade ,Acessibilidade de Software","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085939","enunciado":"Com relação às técnicas de Levantamento de Requisitos, os requisitos que descrevem como funcionários de determinada área realmente trabalham, em vez da maneira pela qual as descrições dos processos dizem que esses funcionários devem","a":"trabalhar, são mais bem obtidos pela técnica questionário.","b":"estudo etnográfico.","c":"brainstorming.","d":"prototipagem.","e":"entrevista.","gabarito":"B","materia":"Engenharia de Software","tema":"Engenharia de Requisitos","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085938","enunciado":"No roteiro SCRUM, de gerenciamento Ágil, a atividade que discute funcionalidades de modo a atualizar o que já foi feito, o que será feito e dificuldades é","a":"Sprint Review que pretende validar a entrega do momento quando termina uma Sprint. Realiza-se a reunião que fará a demonstração do produto ou funcionalidade sendo entregue.","b":"Sprint Backlog, onde o conjunto planejado, selecionado junto ao Backlog do Produto, é definido para compor uma Sprint. Somente as entregas que compõem a Sprint serão detalhas em atividades menores e as restantes serão “congeladas”, não sendo detalhadas ainda.","c":"Sprint Goal resultado da negociação entre o time de desenvolvimento e o Product Owner - PO reconhecido como necessidade(s) fundamental(ais) do cliente nesse momento.","d":"Daily Scrum, reunião que ocorre diariamente, durante 15 minutos, com todos participantes em pé, onde se atualiza a situação presente da Sprint sendo trabalhada.","e":"Product Backlog onde se produz uma lista contendo todas as funcionalidades desejadas para um produto em sua situação atual.","gabarito":"D","materia":"Engenharia de Software","tema":"Processos de Software - Desenvolvimento Ágil ,Scrum","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085937","enunciado":"Considere o modelo de ciclo de vida de software constituído por rotinas de trabalho com a participação de todos os membros da equipe, onde falhas não são toleráveis e por isso, entre as atividades, duas têm grande importância no processo: uma delas dedicada ao planejamento da etapa e outra à de análise de riscos. As atividades são apoiadas pela geração de protótipos. Suporta o desenvolvimento de sistemas complexos e de grande porte.","a":"Trata-se do modelo Interativo e Incremental.","b":"RAD - Rapid Application Development.","c":"Espiral.","d":"Cascata.","e":"Evolutivo.","gabarito":"C","materia":"Engenharia de Software","tema":"Outros modelos de Processo de Software ,Processos de Software","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085936","enunciado":"Os conceitos alta coesão e baixo acoplamento, utilizados no processo de desenvolvimento de software, são princípios","a":"essenciais de Abstração.","b":"Modularidade.","c":"Incrementação.","d":"Separação de Interesses.","e":"Generalidade.","gabarito":"B","materia":"Engenharia de Software","tema":"Acoplamento e Coesão","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085935","enunciado":"","a":"Atenção: A questão corresponde à Gestão Pública. consagrada metodologia de gestão estratégica denominada Balanced Scorecard (BSC) pressupõe identificar as forças e fraquezas da organização, bem com as ameaças e oportunidades apresentadas, estabelecendo A a graduação daí decorrente e classificando a organização de acordo com o sua posição relativa em face dos benchmarkings do setor.","b":"estabelecer uma relação de causa e efeito entre as competências disponíveis na organização e os objetivos estratégicos estabelecidos, descrevendo essa relação em uma matriz com guias operacionais.","c":"priorizar a perspectiva financeira, que é alocada no topo do diagrama de fluxo de processos e estabelece o score (pontuação) atingido em face do grau de maturidade do gerenciamento desses processos.","d":"realizar um mapeamento das competências disponíveis na organização e das necessidades técnicas e comportamentais requeridas, de forma a completar esse gap (lacuna) com medidas de gestão de recursos humanos.","e":"descrever a estratégia de forma clara, através de objetivos estratégicos em quatro perspectivas: financeira; mercadológica (dos clientes); processos internos; e aprendizado/inovação.","gabarito":"E","materia":"Governança de TI","tema":"Balanced Scorecard em Governança de T.I. (BSC)","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085934","enunciado":"Atenção: A questão corresponde à Gestão Pública. Uma metodologia largamente utilizada para gestão de projetos é a Criticai Path Method (CPM), ou método do caminho crítico, segundo a qual","a":"as etapas iniciais do projeto, integrantes do denominado caminho crítico, são as mais desafiadoras e, uma vez superadas, os riscos de atraso do projeto diminuem significativamente.","b":"devem ser eliminados todos os gargalos existentes na organização, objetivando a redução do tempo médio dos projetos em curso, sendo considerado caminho crítico tal sequência de obstáculos.","c":"as atividades que condicionam o tempo total do projeto inserem-se no denominado caminho crítico e, diversamente das demais, não podem sofrer atrasos sob pena de impactar o prazo estabelecido para o projeto.","d":"o tempo de conclusão do projeto é uma variável secundária, devendo a organização concentrar seus esforços na realização das atividades de forma qualitativa, que é o verdadeiro caminho crítico a ser percorrido e cuja conclusão agrega valor ao projeto.","e":"a gestão eficiente de um projeto deve levar em conta a análise probabilística de diferentes cenários, do mais otimista ao mais pessimista, este último identificado como o caminho crítico a ser evitado. Segurança e Saúde no Trabalho>Normas Brasileiras e Estrangeiras Aplicáveis à Saúde e Segurança ,","gabarito":"C","materia":"Gerência de Projetos","tema":"Gerenciamento de Projetos, Programas e Portfólio","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1054","enunciado":"Ano: 2019 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Informática Uma das abordagens mais recentes sobre gestão de riscos no âmbito das organizações está contida na norma técnica ABNT","a":"NBR ISO 31000 - Gestão de Risco, segundo a qual o denominado “tratamento de risco” consiste em processo para modificar o risco, atuando sobre a probabilidade ou consequência do risco.","b":"estabelecer referências em face das quais a significância de um risco é avaliada.","c":"identificar a natureza do risco, entre provável, possível ou remoto, e determinar a sua alocação.","d":"aferir o grau de probabilidade da materialização do risco, utilizando cenários de comparabilidade.","e":"avaliar a magnitude da consequência do risco para fins de explicitação e quantificação nas demonstrações financeiras. Administração Pública>Gestão por Processos ,Gestão de Politicas Públicas ,","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085932","enunciado":"","a":"Ano: 2019 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Informática adoção de um sistema de compliance no âmbito de uma determinada entidade pública significa uma alternativa para reparar prejuízos causados por corrupção praticada por seus agentes, assumido em acordo de A leniência como sucedâneo de condenação pecuniária.","b":"a utilização de indicadores para mensurar o atingimento de metas com o objetivo de conferir previsibilidade e confiabilidade à sua atuação, agregando valor à entidade.","c":"a imposição de medidas restritivas, de ordem sancionatória, decorrentes de condenação por práticas de corrupção identificadas no âmbito da organização.","d":"a adoção de um conjunto de disciplinas a fim de cumprir e se fazer cumprir as normas legais e regulamentares, bem como evitar, detectar e tratar quaisquer desvios ou inconformidades que possam ocorrer.","e":"o compromisso de uma atuação socialmente responsável, cumprindo o papel de agente de governança corporativa em conjunto com os demais agentes estratégicos inseridos nesse sistema (stakeholders).","gabarito":"D","materia":"Eficiência, eficácia e efetividade no serviço públicoGestão por resultados","tema":"","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085931","enunciado":"","a":"Constituição Federal de 1988 assegura a todos o direito ao meio ambiente ecologicamente equilibrado, impondo, para tanto, algumas obrigações ao Poder Público, entre as quais a de definir os espaços territoriais e seus componentes a serem especialmente protegidos,","b":"A em todas as unidades da federação, cuja alteração ou supressão somente é permitida por lei. exclusivamente em terras de titularidade da União, que devem ser classificadas como Parques Nacionais.","c":"cuja instituição se dá obrigatoriamente por lei federal, vedada qualquer tipo de exploração econômica.","d":"imposta, exclusivamente, aos Municípios, por se tratar de matéria de interesse local.","e":"o que se dá mediante tombamento ou desapropriação, assegurada a indenização ao proprietário original da área. Legislação Federal>","gabarito":"A","materia":"Direito Constitucional","tema":"Meio Ambiente ,Ordem Social","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1057","enunciado":"Ano: 2019 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Informática Entre os objetivos e as finalidades que se pretende assegurar por meio da adoção do procedimento licitatório, inserem-se não apenas a isonomia e a seleção da melhor proposta para a Administração, mas também a promoção do desenvolvimento nacional sustentável. Nesse contexto, à luz das disposições da Lei n° 8.666/1993 e do Decreto n° 7.746/2012, a Administração pública federal direta, autárquica, fundacional e as empresas estatais federais dependentes","a":"somente poderão adotar critérios de sustentabilidade como especificação técnica do objeto, vedada a sua previsão como obrigação da contratada, dado o potencial de restrição do caráter competitivo do certame.","b":"deverão adotar, na aquisição de bens e na contratação de obras e serviços, critérios e práticas de sustentabilidade, justificando a adequação do objeto da contratação e das obrigações da contratada e tais práticas, resguardado o caráter competitivo do certame.","c":"deverão adotar os critérios de sustentabilidade previstos na referida normatização como fator de julgamento, exclusivamente nas licitações do tipo melhor técnica ou técnica e preço.","d":"estão obrigadas a adotar os critérios de sustentabilidade previstos na referida normatização como fator de equalização das propostas, conferindo vantagem de até 10% para os licitantes que cumprirem os requisitos fixados com base em tais critérios.","e":"deverão adotar, como critério de desempate nas licitações na modalidade pregão, o cumprimento de requisitos de sustentabilidade fixados no edital, aderentes às premissas fixadas na normatização citada. Estatuto da Pessoa com Deficiência - Lei nº 13.146 de 2015>Legislação das Pessoas com Deficiência ,","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1058","enunciado":"Ano: 2019 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Informática Nos termos da Lei n° 10.098/2000, a Administração pública federal","a":"direta e indireta destinará, semestralmente, dotação orçamentária para as adaptações, eliminações e supressões de barreiras arquitetônicas existentes nos edifícios de uso público de sua propriedade e naqueles que estejam sob sua administração ou uso.","b":"direta, apenas, destinará, anualmente, dotação orçamentária para as adaptações e supressões de barreiras arquitetônicas existentes nos edifícios de uso público de sua propriedade e naqueles que estejam sob sua administração ou uso.","c":"direta e indireta destinará, anualmente, dotação orçamentária para as adaptações, eliminações e supressões de barreiras arquitetônicas existentes nos edifícios de uso público de sua propriedade e naqueles que estejam sob sua administração ou uso.","d":"direta, apenas, destinará, anualmente, dotação orçamentária para as adaptações e supressões de barreiras arquitetônicas existentes nos edifícios de uso público de sua propriedade, excluídos aqueles que estejam sob sua administração ou uso, competindo, nesse caso, ao proprietário zelar pelas normas de acessibilidade.","e":"direta e indireta destinará, semestral mente, dotação orçamentária para as adaptações e supressões de barreiras arquitetônicas existentes nos edifícios de uso público de sua propriedade, excluídos aqueles que estejam sob sua administração ou uso, competindo, nesse caso, ao proprietário zelar pelas normas de acessibilidade. Estatuto da Pessoa com Deficiência - Lei nº 13.146 de 2015>","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1059","enunciado":"Ano: 2019 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Informática Nos termos da Lei n° 13.146/2015, especificamente no que concerne ao direito à saúde da pessoa com deficiência, quando","a":"esgotados os meios de atenção à saúde da pessoa com deficiência no local de residência, não será prestado atendimento fora de domicílio.","b":"será prestado atendimento fora de domicílio, para fins de diagnóstico e de tratamento, garantidos o transporte e a acomodação da pessoa com deficiência e de seu acompanhante.","c":"será prestado atendimento fora de domicílio, para fim exclusivo de tratamento e desde que se trate de situação emergencial, garantidos o transporte e a acomodação da pessoa com deficiência, excluído seu acompanhante, que deverá arcar com suas próprias expensas.","d":"será prestado atendimento fora de domicílio, para fins de diagnóstico e tratamento, garantida somente a acomodação da pessoa com deficiência e de seu acompanhante.","e":"será prestado atendimento fora de domicílio, para fim exclusivo de tratamento e desde que se trate de situação emergencial, garantidos o transporte e a acomodação da pessoa com deficiência e de seu acompanhante.","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085927","enunciado":"De acordo com a Constituição Federal de 1988, a homologação de sentença estrangeira, a extradição solicitada por Estado","a":"estrangeiro e a concessão de exequatur às cartas rogatórias serão processadas e julgadas originariamente pelo Superior Tribunal de Justiça, nas três hipóteses.","b":"Supremo Tribunal Federal, Supremo Tribunal Federal e Superior Tribunal de Justiça, respectivamente.","c":"Supremo Tribunal Federal, Superior Tribunal de Justiça e Supremo Tribunal Federal, respectivamente.","d":"Superior Tribunal de Justiça, Supremo Tribunal Federal e Superior Tribunal de Justiça, respectivamente.","e":"Supremo Tribunal Federal, nas três hipóteses.","gabarito":"D","materia":"Direito Constitucional","tema":"Supremo Tribunal Federal ,Superior Tribunal de Justiça ,Organização do Poder Judiciário","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085926","enunciado":"Acerca dos Municípios na organização do Estado brasileiro, considere: I . A fiscalização do Município será exercida pelo Poder Legislativo Municipal, mediante controle externo. II . Compete ao Município organizar e prestar, diretamente ou sob regime de concessão ou permissão, os serviços públicos de interesse local, incluído o de transporte coletivo. III . A Câmara Municipal não gastará mais de setenta por cento de sua receita com folha de pagamento, não computado o gasto com o subsídio de seus Vereadores, constituindo crime de responsabilidade do Presidente da Câmara Municipal o desrespeito a essa regra. IV . É assegurada a inviolabilidade dos Vereadores por suas opiniões, palavras e votos no exercício do mandato e na circunscrição do Município.","a":"De acordo com a Constituição Federal de 1988, está correto o que consta APENAS de I, II e IV.","b":"I e II .","c":"I, II e III.","d":"II e IV.","e":"III e IV.","gabarito":"A","materia":"Direito Constitucional","tema":"Organização do Estado – Municípios ,Organização Político-Administrativa do Estado","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085923","enunciado":"Havia cinco garrafas de vinhos em uma adega. O preço médio desses vinhos era R$ 120,00. Uma garrafa desapareceu e o","a":"preço médio das quatro garrafas que sobraram passou para R$ 110,00. O valor, em reais, da garrafa que desapareceu é 130,00.","b":"120,00.","c":"150,00.","d":"140,00.","e":"160,00.","gabarito":"E","materia":"Matemática","tema":"Aritmética e Problemas ,Médias","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085922","enunciado":"Dez times estão inscritos em um campeonato de basquete. Cada time deve jogar exatamente uma vez com cada um dos outros times. A cada jogo o vencedor ganha 3 pontos e, se houver empate, cada um dos times ganha 1 ponto. Se, ao final do","a":"campeonato, o total de pontos distribuídos para todos os times for 125, o número de empates terá sido 8.","b":"12.","c":"10.","d":"11.","e":"9.","gabarito":"C","materia":"Matemática","tema":"Álgebra ,Problemas","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085921","enunciado":"Um carro percorreu 3.000 km. A cada dia de viagem, a partir do primeiro, ele dobrou a distância percorrida no dia anterior.","a":"Se ele finalizou a viagem em quatro dias, a distância percorrida, em quilômetros, no primeiro dia foi de 100.","b":"200.","c":"150.","d":"250.","e":"300.","gabarito":"B","materia":"Matemática","tema":"Aritmética e Problemas ,Regra de Três","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085920","enunciado":"1 Nosso cérebro é uma complexa estrutura forjada pela evolução. Por outro lado, é também primitivo. É curioso pensar que o mais erudito dos moradores deste planeta tenha o mesmo hardware que um caçador-coletor que passou a vida errando em uma pequena érea em busca da sobrevivência. 2 Estou sendo injusto em minha descrição. Nosso ancestral era capaz de tecer, realizar pequenas cirurgias, fazer ferramentas de pedra. Tente criar algo assim em casa e você verá que somos menos autônomos do que um coletor do Paleolítico. Mas estou sendo preciso quando comparo nossos cérebros. 3 Desenvolvida para uma chave amigo-inimigo, nossa mente tende a rotular o que vê, julgando a novidade de acordo com seu conhecimento prévio. Isso garantiu nossa vida por muitas gerações: se eu comer algo que me faz mal, toda vez que olhar para algo semelhante, sentirei repulsa. Isso pode ser bom para evitar perigos, porém cria problemas para nossa atualidade. 4 Se eu tivesse que arriscar um esboço do que seria o pensamento médio das pessoas, hoje, ele seria similar ao dos antepassados paleolíticos. Formamos bandos com facilidade. Yuval Harari chama a atenção para como a detração é uma poderosa cola social. Fofocando, crio laços, forjo alianças. Desde sempre, nossa espécie classifica o que vê antes de compreender o que tem na sua frente. O pavor instintivo da novidade me faz rejeitá-la. Classificar, para o cérebro primitivo que se contenta em viver na caverna, é mais importante do que entender. 5 É claro que também somos uma espécie que foge da natureza animal e que cria culturas. Portanto, há um instinto inquisitivo, que gosta de descobrir coisas novas, explorá-las. No entanto, a sensação é que ele anda em baixa em nossos tempos. Encerrar em caixas herméticas dá segurança. 6 Alguns associam a rotulação imediata a um traço humano. A sociedade ficou mais complexa, mas, em nossa essência, somos os mesmos. Por outro lado, há quem afirme que o tempo curto da internet, o imediatismo atual, produz superficialidade, impede o raciocínio profundo, pois este requer o questionamento de bolhas epistêmicas e, mercadoria cada vez mais rara, tempo de ponderação. Não seria uma essência, necessariamente, todavia um feitiço, uma tentação oferecida por algoritmos do universo digital. 7 Resistir à tentação é um desafio. Pensar em aprofundar, dar uma segunda olhada, fugir do rótulo: parecem atitudes que exigem o desafio da vontade férrea. Deixar que sentidos mais amplos invadam sua percepção sem julgar de imediato é um ato de resistência.","a":"(Adaptado de: KARNAL, Leandro. Disponível em: https://cultura.estadao.com.br) frase que admite transposição para a voz passiva está em:","b":"A somos uma espécie que foge da natureza animal (5° parágrafo) Nosso ancestral era capaz de tecer (2° parágrafo)","c":"a sensação é que ele anda em baixa em nossos tempos (5° parágrafo)","d":"Resistir à tentação é um desafio (7° parágrafo)","e":"Alguns associam a rotulação imediata a um traço humano (6° parágrafo)","gabarito":"E","materia":"Português","tema":"Morfologia - Verbos ,Flexão de voz (ativa, passiva, reflexiva)","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085919","enunciado":"Estou sendo injusto em minha descrição. (2° parágrafo) Transposto para o discurso indireto, o trecho transcrito acima assume a seguinte redação:","a":"Leandro Karnal afirmou que vai estar sendo injusto em sua descrição.","b":"estar sendo injusto em minha descrição.","c":"que estava sendo injusto em sua descrição.","d":"ter sido injustiçado em sua descrição.","e":"que fora injusto em minha descrição.","gabarito":"C","materia":"Português","tema":"Interpretação de Textos ,Tipos de Discurso: Direto, Indireto e Indireto Livre","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085918","enunciado":"Não seria uma essência, necessariamente, todavia um feitiço (6° parágrafo)","a":"O segmento sublinhado expressa, no contexto, ideia de contraste.","b":"adição.","c":"temporalidade.","d":"finalidade.","e":"condição.","gabarito":"A","materia":"Português","tema":"Interpretação de Textos ,Significação Contextual de Palavras e Expressões. Sinônimos e Antônimos.","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085917","enunciado":"","a":"Considerando o contexto, o termo em destaque pode ser substituído pelo que se encontra entre parênteses em: Encerrarem caixas herméticas (ilimitadas) dá segurança - 5° parágrafo","b":"a detração (retraimento) é uma poderosa cola social - 4° parágrafo","c":"o questionamento de bolhas epistêmicas(cognitivas) - 6° parágrafo","d":"atitudes que exigem o desafio da vontade férrea(essencial) - 7° parágrafo","e":"somos menos autônomos(influentes) do que um coletor do Paleolítico - 2° parágrafo","gabarito":"C","materia":"Português","tema":"Interpretação de Textos ,Significação Contextual de Palavras e Expressões. Sinônimos e Antônimos.","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085916","enunciado":"Depreende-se do texto que","a":"a tendência atual de replicar informações obtidas na internet sem a devida ponderação tornou o homem moderno","b":"análogo ao primitivo. está em declínio, na atualidade, a faculdade de refletir sobre os fatos e observá-los com atenção antes de classificá-los.","c":"o tempo, cada vez mais escasso na sociedade atual, é desperdiçado com o uso excessivo da internet.","d":"poucos são capazes de divergir de ideias de senso comum que se propagam nas redes sociais.","e":"decorre da superficialidade inerente ao universo digital o empobrecimento das relações humanas.","gabarito":"B","materia":"Português","tema":"Interpretação de Textos ,Noções Gerais de Compreensão e Interpretação de Texto","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085695","enunciado":"Uma classe C o la b o r a d o r de uma aplicação Java tem o método abaixo.","a":"Para instanciar um objeto dessa classe e armazenar o nome \" Pedro \" no atributo nome utiliza-se","b":"","c":"","d":"","e":"","gabarito":"D","materia":"Programação","tema":"Java ,Linguagens de programação","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085694","enunciado":"Considere o código P H P abaixo, que faz a conexão com um banco de dados.","a":"Para o código estar correto, as lacunas i e l i devem ser, respectiva e corretamente, preenchidas por mysqli_connect — SQLException","b":"PDOConnect — PDOException","c":"mysqli_connect — Exception","d":"new PDO — PDOException","e":"database_connect — DataBaseException","gabarito":"D","materia":"Programação","tema":"PHP ,Linguagens de programação","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085693","enunciado":"No interior do método m a in da classe principal de uma aplicação Java S E um método foi chamado usando as instruções abaixo. double [ ] dados ; double [] d={1,20,7,8}; dados = Aluno . cadastraDados (d) ;","a":"O método cadastra Dados na classe Alunodeve ter a declaração public static double [ ] cadastra Dados (double [ ] d)","b":"public static double [ ] cadastraDados (doubled)","c":"public double [ ] cadastraDados (double[ ]d)","d":"public final double [ ] cadastraDados (double d[])","e":"public static double cadastraDados (double [ ] d)","gabarito":"A","materia":"Programação","tema":"Plataforma Java ,Java SE","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085692","enunciado":"","a":"No Linux Red Hat, para mostrar o espaço em disco, incluindo espaço usado e disponível, utiliza-se o com ando df -h","b":"dir- s","c":"tune2fs - d","d":"free -h","e":"top - a","gabarito":"A","materia":"Sistemas Operacionais","tema":"Linux","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085691","enunciado":"Considere o fragmento abaixo de uma página HTML5 que utiliza elementos semânticos. Para inserir a legenda \" Figura 1 - Foto das dependências do TRF 3 \" na imagem, após <img src=\"trf. jpg\" alt= \"TRF3\" > deve-","a":"se colocar a instrução <label> Figura 1 - Foto das dependências do TRF3 </label>","b":"<title> Figura 1 - Foto das dependências do TRF3 </title>","c":"<legend> Figura 1 - Foto das dependências do TRF3 </legend>","d":"<figlable> Figura 1 - Foto das dependências do TRF3 </figlabell>","e":"<figcaption> Figura 1 - Foto das dependências do TRF3 </figcaption>","gabarito":"E","materia":"Programação","tema":"HTML (HyperText Markup Language) ,Linguagens de marcação","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085690","enunciado":"Considere o documento XM L abaixo. Para definir que o elemento name deve possuir um atributo i d e que este atributo deve obrigatoriamente conter um valor,","a":"a lacuna I deve ser corretamente preenchida por < !ATTLIST name id CDATA # IMPLIED>","b":"<!ELEMENT name ATTRIBUTE id PCDATA REQUIRED>","c":"< !ATTLIST name id CDATA # FIXED id >","d":"< !ELEMENT name ATTRIBUTE id CDATA #REQUIRED>","e":"< !ATTLIST name id CDATA #REQUIRED>","gabarito":"E","materia":"Programação","tema":"XML (Extensible Markup Language) ,Linguagens de marcação","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085689","enunciado":"Considere o fragmento de página JSP abaixo. <body> <% S t r i n g nome = r e q u e s t . g e t P a r a m e t e r ( \" n o m e \" ) ; %> < form method = \"post\" actio n = \"Controle \" > <input type = \"text\" name=\"nome\" I /> < /form > < /body> Para aparecer no campo nome do formulário o conteúdo","a":"recebido na variável nome a lacuna I deve ser corretamente preenchida por value=\"<%nome%>\"","b":"useBean=\"${nome}\";","c":"value=\"<%@nome%>\"","d":"value=\"<%=nome%>\"","e":"useBean = \"$nome\";","gabarito":"D","materia":"Programação","tema":"JSP (JavaServer Pages)","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085688","enunciado":"Um laço de repetição foi criado em Java utilizando os comandos abaixo. Pode-se afirmar corretamente que","a":"terá o mesmo resultado","b":"os comandos não precisam estar dentro das chaves do","c":"while. pode ser substituído por sem alteração no resultado.","d":"fará a mesma","e":"contagem, só que regressiva. a variável i terá o valor 100 após a execução terminar o laço de repetição","gabarito":"C","materia":"Programação","tema":"Java ,Linguagens de programação","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085687","enunciado":"","a":"Java possui um conjunto de tipos de dados conhecidos como primitivos, dos quais NÃO faz parte o tipo short.","b":"long.","c":"string.","d":"byte.","e":"float.","gabarito":"C","materia":"Algoritmos e Estrutura de Dados","tema":"Algoritmos ,Tipos de Dados","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085686","enunciado":"Um Analista foi encarregado de criar, em linha de comando, a Unidade Organizacional \"Impressoras\" na raiz de um domínio. Considerando que a rede utiliza o Windows Server 2008 R2 e que a organização tem nome de domínio","a":"Advogados.com.br , utilizou corretamente o comando dsset ou = \"Impressoras\" dc= \"Advogados\" dc= \"com \" dc = \" br \"","b":"dsadd ou \"ou = Impressoras,dc = Advogados, dc = com,dc = br \"","c":"adset ou = \" Impressoras \" dc = \"Advogados.com.br \"","d":"adadd\" ou = Impressoras\" \"dc= Advogados ,dc= com ,dc= br \"","e":"addou \"ou = Impressoras\" \"dc= Advogados ;dc= com ;dc= br\"","gabarito":"B","materia":"Sistemas Operacionais","tema":"Windows ,Windows 2008 Server","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085685","enunciado":"No Windows Server 2008 R2, em inglês, para instalar o Active Directory abre-se o Server Manager e clica-se em Add Roles para adicionar uma função (ou papel). Aparecerá um aviso onde se deve clicar no botão Next para se chegar à janela de seleção da Server Role que se deseja instalar no servidor. A Role que deve ser selecionada quando se quer arm azenar informações sobre objetos na rede e disponibilizar e ssa s informações para usuários e administradores, usando controladores para con ceder aos usuários o acesso a recursos permitidos em qualquer local da rede por meio de um processo de login único, é a","a":"Active Directory Domain Services.","b":"Certificate Services.","c":"Federation Services.","d":"Lightning Directory Services.","e":"Rights Management Services.","gabarito":"A","materia":"Sistemas Operacionais","tema":"Windows ,Administração de usuários (AD - Active Directory) ,Windows 2008 Server","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085684","enunciado":"Em uma aplicação PH P , considere $conn um objeto que contém uma conexão válida com um banco de dados e $n uma variável string que contém o nome de uma pessoa. A pó s a conexão com o banco de dados ter sido efetuada, a instrução abaixo prepara uma instrução S Q L parametrizada. $stmt = $conn-> prepare ( \"INSERT INTO Usuarios (nome) VALUES (:nome)\");","a":"Para passar o conteúdo da variável $n como parâmetro para a instrução SQL acima utiliza-se o com ando $stmt - > setParam ( ': nome ' , $n );","b":"$stmt - > bind Param ( $ n - > ': nome') ;","c":"$stmt - > bindParam ( ': nome ' , $n);","d":"$stmt - > setParameter ($n - > ':nome') ;","e":"$stmt-> param ($ n , ':nome') ;","gabarito":"C","materia":"Programação","tema":"PHP ,Linguagens de programação","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085683","enunciado":"Em uma aplicação Java, um vetor n foi criado por meio da instrução double n=new double [ 3 ] ; e alimentado com 3 valores","a":"reais. Para exibir o conteúdo da segunda posição (índice) deste vetor utiliza-se a instrução","b":"","c":"","d":"","e":"","gabarito":"B","materia":"Programação","tema":"Java ,Linguagens de programação","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085682","enunciado":"","a":"47. Para definir o elemento c l i e n t e como tipo string em um X M L Schema utiliza-se a instrução <xml : element name=\"cliente type=\"string\">Paulo</xml:element>","b":"<xsl : element id = \"cliente\" type = \"xsl : string\"/>","c":"<xs : element name = \"cliente\" type = \"xs : string\" / >","d":"<xs : element id = \"cliente\" type = \"xs : varchar \"/> Paulo</xml : element>","e":"<xml: element name = \"cliente\" type = \"string \"value=\"Paulo\"/ >","gabarito":"C","materia":"Programação","tema":"XML (Extensible Markup Language) ,Linguagens de marcação","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085681","enunciado":"Um Analista está construindo um site com A S P e deseja inserir o mesmo rodapé, existente no arquivo r o d a p e . c s h t m l, em todas as páginas. Para importar o conteúdo do arquivo para o local da página onde deseja colocar o rodapé deverá","a":"utilizar o método <@ import src = \"rodape.cshtml\"/>","b":"@RenderPage ( \"rodape.cshtml\" )","c":"<%@import ssrc=\"rodape;cshtml\"%>","d":"<include file=\"rodape.cshtml\"/>","e":"@ImportFile (\"rodape.cshml\")","gabarito":"B","materia":"Programação","tema":"ASP","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085680","enunciado":"","a":"Dentre os objetivos da fast ethernet em relação à ethernet-padrão, estão aumentar a taxa de dados para 100 Gbps e mudar o endereçamento de 48 para 96 bits.","b":"manter o mesmo formato de frame, todavia aumentar seus comprimentos mínimo e máximo.","c":"aumentar a taxa de dados para 100 Mbps, torná-lo compatível com a ethernet-padrão e manter os mesmos","d":"comprimentos máximo e mínimo de um frame. mudar o formato do frame para poder adaptar o aumento de seus comprimentos mínimo e máximo.","e":"aumentar a taxa de dados para 1 Gbps, aumentar seus comprimentos mínimo e máximo e mudar o endereçamento de 48 para 96 bits.","gabarito":"C","materia":"Redes de Computadores","tema":"Arquiteturas de Rede ,Ethernet","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085679","enunciado":"","a":"Em uma rede comutada por circuitos a configuração de chamadas não é necessária.","b":"os pacotes não chegam em ordem.","c":"a largura de banda disponível é dinâmica.","d":"o caminho físico não é dedicado.","e":"a falha de um switch é fatal e o modo de tarifação é por minuto.","gabarito":"E","materia":"Redes de Computadores","tema":"Equipamentos de Redes ,Switches ,Comutação de células","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085678","enunciado":"Considere que um computador A pode se comunicar com um computador C usando Telnet. Ao mesmo tempo, o computador A se comunica com o computador B usando FTP. Para esses processos receberem dados simultaneamente, é necessário um método de identificação dos diferentes processos. Na arquitetura TCP/IP, o identificador atribuído a um","a":"processo na camada de transporte é chamado de endereço de processo.","b":"lógico.","c":"específico.","d":"de porta.","e":"físico.","gabarito":"D","materia":"Redes de Computadores","tema":"Arquitetura TCP/IP","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085677","enunciado":"No âmbito dos protocolos e serviços de comunicação de dados, o ICMP é","a":"um mecanismo usado por hosts e gateways para enviar notificações de problemas ocorridos com datagramas de volta","b":"ao emissor. usado para associar um endereço lógico a um endereço físico.","c":"usado para facilitar a transmissão simultânea de uma mensagem a um grupo de destinatários.","d":"um protocolo que permite que um host descubra seu endereço Internet quando conhece apenas seu endereço físico.","e":"um mecanismo de transmissão usado pelos protocolos TCP/IP, sendo um protocolo sem conexão e não confiável.","gabarito":"A","materia":"Redes de Computadores","tema":"Protocolo ,ICMP ( Internet Control Message Protocol)","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085676","enunciado":"Para se ter acesso à opção que permite organizar os ícones automaticamente na área de trabalho do Windows 7, em","a":"português, deve-se clicar com o botão direito do mouse na área de trabalho e depois selecionar E x i b i r .","b":"pressionar simultaneamente <alt> + <tab> na área de trabalho e depois selecionar o r g a n iz a r.","c":"pressionar <windows> + <e> e depois selecionar d i s p o r Í c o n e s .","d":"clicar no ícone do menu I n i c i a r , escolher configurações e selecionar E x i b i r .","e":"pressionar simultaneamente <ctrl> + <tab> na área de trabalho e depois selecionar o r g a n i z a r .","gabarito":"A","materia":"Noções de Informática","tema":"Sistema Operacional ,Windows","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085675","enunciado":"Considerando as formas de ataque pela internet,","a":"e-mail spoofing é uma técnica que consiste em alterar campos do cabeçalho de um e-mail, de forma a aparentar que ele foi enviado de uma determinada origem quando, na verdade, foi enviado de outra.","b":"scan é uma técnica pela qual um atacante utiliza um computador para tirar de operação um serviço, um computador ou uma rede conectada à internet.","c":"defacement é uma técnica que consiste em trocar a senha, dificultando o acesso novamente ao site ou computador invadido.","d":"sniffing é uma técnica que consiste em inspecionar os dados trafegados em redes de computadores, por meio do uso de programas específicos chamados de spoofers.","e":"brute fake é uma técnica que consiste em adivinhar, por tentativa e erro, um nome de usuário e senha e, assim, executar processos e acessar sites, computadores e serviços em nome e com os mesmos privilégios deste usuário.","gabarito":"A","materia":"Noções de Informática","tema":"Segurança da Informação ,Ataques","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085674","enunciado":"Ao longo da existência das redes Wi-Fi, para resolver alguns riscos inerentes a seu uso, foram desenvolvidos mecanismos de segurança, como","a":"WPA: mecanismo desenvolvido para resolver todas as fragilidades do wireless. É o nível máximo de segurança","b":"recomendado. WPA-2: similar ao W PA, mas com criptografia considerada mais forte. É o mecanismo mais recomendado.","c":"WHIP-11G: primeiro mecanismo de segurança lançado. Foi considerado frágil e, por isso, seu uso foi descontinuado.","d":"WEP-II Strong Wired: fortíssimo mecanismo de segurança. É considerado o mais forte de todos e o mais recomendado.","e":"WPA-2: mecanismo desenvolvido para resolver algumas das fragilidades do W EP. É o nível mínimo de segurança recomendado.","gabarito":"B","materia":"Redes de Computadores","tema":"Redes sem Fio","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085673","enunciado":"","a":"O Gerenciamento de Serviços estabelecido na ITIL v.3 tem por função específica gerenciar os incidentes, requisições de serviço e, também, a comunicação com os usuários.","b":"deve ser executado pelos provedores de serviços de TI por meio da combinação adequada de pessoas, processos e tecnologia.","c":"é a quem cabe, como atividade especial, definir todos os aspectos de um serviço de TI e seus requisitos em cada fase","d":"do seu ciclo de vida. é uma técnica usada na avaliação do impacto de incidentes de serviço no negócio.","e":"é a estrutura de políticas, processos, funções, normas, orientações e ferramentas que garante que uma organização tem qualidade adequada para atender aos objetivos de negócio ou níveis de serviço de maneira confiável.","gabarito":"B","materia":"Governança de TI","tema":"ITIL ,ITIL v. 3","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085672","enunciado":"Considerando a execução do processo de gerenciamento de mudança na ITIL v.3, após receber o pedido do solicitador da","a":"mudança, o gestor deve aferir a prioridade da mudança. Em seguida, ele notificará o Change Organization Advisory para providenciar as mudanças e enviá-las para teste.","b":"Builder e conduzirá reuniões regulares com ele para garantir que todas as mudanças sejam tratadas devidamente.","c":"Manager para providenciar as mudanças e enviá-las para teste.","d":"Advisory Board e conduzirá reuniões regulares com essa instância para garantir que todas as mudanças sejam tratadas","e":"devidamente. Board Owner que autoriza a implantação da mudança e informa a todos os que serão afetados por ela.","gabarito":"D","materia":"Governança de TI","tema":"ITIL ,ITIL v. 3","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085671","enunciado":"","a":"execução do processo de gerenciamento de incidentes preconizado na ITIL v.3 deve cumprir alguns passos principais a fim de não comprometer ou, pelo menos, a fim de minimizar o impacto no SLA estabelecido entre a prestadora de serviço e seus clientes. Após a recepção do comunicado de incidente (identificação do incidente), os quatro próximos passos devem ser, pela ordem,","b":"A Classification, Recording, Diagnosis e Matching. Recording, Matching, Classification e Diagnosis","c":"Diagnosis, Classification, Matching e Recording.","d":"Classification, Diagnosis, Recording e Matching.","e":"Recording, Classification, Matching e Diagnosis","gabarito":"E","materia":"Governança de TI","tema":"ITIL ,Gerência de Serviços ,ITIL v. 3","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085670","enunciado":"","a":"Na Norma ISO/IEC/IEEE 12207:2017, os processos de ciclo de vida são agrupados em Agreement, Organizational Project-Enabling, Technical Management e Technical.","b":"Agreement, Technical Management e Technical, apenas.","c":"Technical Management e Technical, apenas.","d":"Organizational Project-Enabling e Techinal Management, apenas.","e":"Agreement, Organizacional Project-Enabling e Technical, apenas.","gabarito":"A","materia":"Arquitetura de Software","tema":"Ciclo de Vida","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085669","enunciado":"Uma diferença crítica entre um processo gerenciado e um processo definido, no CMMI 1.3, está no escopo da aplicação dos procedimentos, padrões e descrições do processo. No processo gerenciado, os procedimentos, padrões e descrições do processo","a":"são o produto do comando do alto escalão da organização em determinar seu uso corporativo e geral mediante","b":"sanções administrativas no caso de não cumprimento. são aplicáveis a um projeto, grupo ou unidade organizacional específicos.","c":"são o produto da boa vontade dos colaboradores da organização, em realizar essas atividades de modo coerente.","d":"não são aplicáveis de forma evidente. Ficam subentendidos e só podem ser observados quando da execução do","e":"processo. são aplicáveis uniformemente em todos os processos da organização.","gabarito":"B","materia":"Governança de TI","tema":"CMMI (Capability Maturity Model Integration)","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085668","enunciado":"Considere as capacidades dos processos conforme orientações constantes do M PS .BR - Guia Geral M PS de Software. No que diz respeito ao atendimento aos atributos do processo (AP), pelo atendimento aos resultados esperados dos atributos do processo (RAP), se 1. um processo padrão é descrito, incluindo diretrizes para sua adaptação; 2. a sequência e interação do processo padrão com outros processos são determinadas; 3. os papéis e competências requeridos para executar o","a":"processo são identificados como parte do processo padrão; então, o processo é controlado.","b":"gerenciado.","c":"medido.","d":"definido.","e":"executado.","gabarito":"D","materia":"Governança de TI","tema":"MPS.BR","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085667","enunciado":"Além de ações, atividades, eventos e objetos, os diagramas de atividade da UM L 2.5 admitem um conjunto de nós de controle do processo, tais como os das figuras abaixo:","a":"As figuras 1, 2 e 3 representam, respectivamente, bifurcação ou junção - desvio temporário - início de atividade.","b":"final de atividade - decisão ou merge - bifurcação ou junção.","c":"repetição - retorno - conclusão.","d":"repetição - decisão ou merge - bifurcação ou junção.","e":"início de atividade - desvio condicional - conclusão.","gabarito":"B","materia":"Engenharia de Software","tema":"UML ,Diagrama de Atividades","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085666","enunciado":"Considere a figura abaixo, parte integrante de um diagrama da UML 2.5.","a":"Ela representa um objeto estático e mostra duas strings de visibilidade oculta como parte das especificações dos atributos.","b":"uma dependência e mostra uma string de visibilidade oculta e outra de multiplicidade como parte das especificações","c":"das operações da classe. uma classe e mostra duas strings de multiplicidade como parte das especificações dos atributos.","d":"um objeto dinâmico e mostra duas strings de multiplicidade como parte das especificações das operações da classe.","e":"uma classe abstrata e mostra uma string de visibilidade oculta e outra de multiplicidade como parte das especificações dos atributos.","gabarito":"C","materia":"Engenharia de Software","tema":"UML ,Diagrama de Classes","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085665","enunciado":"","a":"Em Gerenciamento de Transações, as quatro propriedades que garantem uma transação são: Atualização, Completeza, Durabilidade e Isolamento.","b":"Atomicidade, Completeza, Durabilidade e Delegação.","c":"Atualização, Consistência, Durabilidade e Integração.","d":"Atomicidade, Consistência, Durabilidade e Isolamento.","e":"Atualização, Criação, Inserção e Exclusão.","gabarito":"D","materia":"Banco de Dados","tema":"Gerência de Transações","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085664","enunciado":"Considere a relação representativa de uma Nota Fiscal. Ela tem um número (único - não pode se repetir), uma data, nome do vendedor, dados do cliente (cpf, nome, endereço, celular) e um conjunto de linhas correspondentes aos produtos que o cliente comprou (cada linha tem: código-produto, nome-produto, preço-produto, quantidade-comprada e preço-do-item (= a","a":"preço-produto x quantidade-comprada)). Ao aplicar a 1 Forma Normal a relação derivada será uma tabela de produtos.","b":"existirão tantas relações quantas forem as linhas que se repetem.","c":"existirão tantas relações quantos forem os itens componentes dos produtos","d":"cada relação derivada terá, obrigatoriamente, chave composta.","e":"existirão duas relações derivadas que são: produtos e vendedores.","gabarito":"D","materia":"Banco de Dados","tema":"Formas normais","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085663","enunciado":"Em Normalização, a Dependência Funcional - DF, se caracteriza quando","a":"para saber o valor de um atributo DF, basta saber o valor de qualquer um dos atributos pertencentes à chave","b":"composta. tem-se mais de um atributo na chave, portanto chave composta, descrevendo a mesma entidade (ou objeto).","c":"para saber o valor de um atributo DF, não chave, basta conhecer o valor do atributo chave.","d":"o atributo chave é, obrigatoriamente, composto por dois ou mais atributos e fica implícito que cada atributo parte da chave é DF de cada um dos demais atributos componentes dessa chave.","e":"o atributo chave é, obrigatoriamente, composto por dois ou mais atributos e fica implícito que a chave toda, todos os seus atributos componentes, é DF de cada atributo isolado que compõe essa mesma chave.","gabarito":"C","materia":"Banco de Dados","tema":"Formas normais","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085662","enunciado":"Em uma instrução SQL, a cláusula GROUP BY, se utilizada juntamente com funções de grupo, deve estar em uma posição específica como SELECT coluna1 [, coluna2, ... ] . função_de_grupo, [ função_de_grupo, ...] FROM tabela","a":"ORDER BY coluna2 GROUP BY coluna4 [, coluna5, ...] HAVING coluna5 > 10 WHERE condição; SELECT coluna1 [, coluna2, ... ] . função_de_grupo, [ função_de_grupo, ...] FROM tabela","b":"WHERE condição ORDER BY coluna2 GROUP BY coluna4 [, coluna5, ...] HAVING coluna5 > 10; SELECT coluna1 [, coluna2, ... ] . função_de_grupo, [ função_de_grupo, ...] FROM tabela","c":"WHERE condição GROUP BY coluna4 [, coluna5, ...] HAVING coluna5 > 10 ORDER BY coluna2; SELECT coluna1 [, coluna2, ... ] . função_de_grupo, [ função_de_grupo, ...] FROM tabela","d":"HAVING coluna5 > 10 ORDER B Y coluna2 WHERE condição GROUP BY coluna4 [, coluna5, ...] ; SELECT coluna1 [, coluna2, ... ] . função_de_grupo, [ função_de_grupo, ...] FROM tabela","e":"HAVING coluna5 > 10 WHERE condição ORDER BY coluna2 GROUP BY coluna4 [, coluna5, ...];","gabarito":"C","materia":"Banco de Dados","tema":"SQL","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085661","enunciado":"O conceito CONSTRAINT é uma garantia de qualidade da informação, também conhecida como “integridade referencial” que significa que","a":"um registro pode estar sendo excluído por um Cliente, quase que no mesmo lapso de tempo que um outro Cliente está alterando seus valores.","b":"nenhum dado pode ser guardado em uma tabela, em um campo ou coluna, cujo tipo de dado seja diferente, gerando uma agressão à integridade relacional ou física do atributo.","c":"nenhum SGBD Servidor em atuação “cliente-servidor” pode ser desligado enquanto Clientes (APPs e SGBDs) estiverem operacionais.","d":"o SGBD Servidor precisa ordenar as operações controlando o tempo da ocorrência para que não perca a qualidade ou integridade referencial, quando um determinado dado de uma linha ou registro de tabela sofre várias alterações, partindo de diversos usuários Clientes, em um espaço de tempo muito pequeno.","e":"o SGBD administra todas as atualizações para impedir que uma relação “1 para N” perca a sua validade ou integridade referencial.","gabarito":"E","materia":"Banco de Dados","tema":"SGBD - Sistema de Gerenciamento de Banco de Dados","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085660","enunciado":"Os Sistemas Gerenciadores de Bancos de Dados - SGBDs, antes da virada do século, apresentavam duas linguagens para sua administração e utilização: DDL e DML. Na atualidade, conceitualmente, os autores as distribuem em cinco categorias.","a":"O comando GRANT, por exemplo, é categorizado como DML - Data Manipulation Language.","b":"DTL - Data T ransaction Language.","c":"DQL - Data Query Language.","d":"DDL - Data Definition Language.","e":"DCL - Data Control Language.","gabarito":"E","materia":"Banco de Dados","tema":"SGBD - Sistema de Gerenciamento de Banco de Dados","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085659","enunciado":"No Ciclo de Vida de Desenvolvimento de Serviços, no que diz respeito aos conceitos e princípios do paradigma de","a":"Orientação a Serviços, a tarefa que define as características de SOA que se quer implementar e suportar faz parte da Implantação de Serviços.","b":"do Teste de Serviços.","c":"da Análise Orientada a Serviços.","d":"do Desenvolvimento de Serviços.","e":"do Projeto Orientado a Serviços.","gabarito":"E","materia":"Arquitetura de Software","tema":"SOA (Service-oriented architecture)","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085658","enunciado":"Com relação à Comunicação da Arquitetura Cliente-Servidor, a característica transacional que melhor se aplica é: Quando o Servidor recebe do Cliente, um conjunto de operações que se iniciam a partir de um I e se encerram após o Cliente enviar um II ou o cancelamento de toda a transação por ocorrência do III . Completam, correta e respectivamente, as lacunas I , II e","a":"III : BEGIN TRANSACTION - COMM IT ou RO LLBACK - TIMEOUT","b":"INITIATE TRANSACTION - COMMIT ou ROLLBACK - TIMESTAMP","c":"INITIATE TRANSACTION - CONCLUD E ou ROLLBACK - TIMEOUT","d":"BEGIN TRANSACTION - SUCCESS ou ROLLBACK - TIMESTAMP","e":"BEGIN TRANSACTION - COMPLETE ou ROLLBACK - TIMEOUT","gabarito":"A","materia":"Arquitetura de Software","tema":"Arquitetura Cliente-Servidor","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085657","enunciado":"Em C++, a chamada de uma função provoca o desvio do controle de execução para o início do código da função. Quando do seu término, o controle de execução volta para a instrução seguinte à sua chamada. Funções poupam espaço de memória, mas requerem mais tempo de execução. Se houver uma função muito pequena em relação à quantidade de instruções, em","a":"seu lugar utiliza-se DO WHILE.","b":"INCLUDE.","c":"PER FO R M","d":"INLINE.","e":"DO UNTIL.","gabarito":"D","materia":"Programação","tema":"C++ (mais mais) ,Linguagens de programação","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085656","enunciado":"O NHibernate Driver é um driver específico para acesso a determinados bancos de dados. Ele utiliza as interfaces ou conjunto de classes que expõem serviços de acesso a dados. Interfaces como IDbConnection, IDbCommand, IDbDataReader e","a":"IDataParameter estão contidas em DAO.NET.","b":"ADO.NET.","c":"API ODBC","d":"O LE DB.","e":"SQL.NET.","gabarito":"B","materia":"Programação","tema":"Hibernate ,Frameworks Java","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085655","enunciado":"Martinho, brasileiro nato, tem 65 anos de idade, é analfabeto e deseja votar nas eleições que se aproximam, pois seu filho César, que tem 20 anos e também é analfabeto, pretende se candidatar ao cargo de Vereador. Nessa situação, de acordo com a Constituição Federal de 1988, com base apenas nas informações fornecidas, para Martinho o voto é","a":"proibido, em razão de seu analfabetismo, sendo que César não poderá se candidatar ao cargo pretendido, por ser","b":"analfabeto. facultativo, em razão de sua idade, sendo que César não pode se candidatar a esse cargo, pois não tem ainda 21 anos.","c":"obrigatório, sendo que César não pode se candidatar ao cargo pretendido, por ser analfabeto.","d":"obrigatório, não havendo impedimento para a candidatura de César.","e":"facultativo, em razão de seu analfabetismo, sendo que César não pode se candidatar ao cargo pretendido, por ser analfabeto.","gabarito":"E","materia":"Direito Constitucional","tema":"Direitos Políticos","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085654","enunciado":"O servidor público estável João perdeu seu cargo e sua vaga foi ocupada por Décio, também servidor público estável. Porém, João teve sua demissão invalidada por sentença judicial transitada em julgado e foi reintegrado. Nesse caso, de acordo com a Constituição Federal de 1988, Décio","a":"não poderá ser reconduzido ao cargo de origem, mas terá direito a indenização, ficando em disponibilidade, sem remuneração, até seu adequado aproveitamento em outro cargo.","b":"será reconduzido ao cargo de origem, com direito a indenização, aproveitado em outro cargo ou posto em disponibilidade com remuneração proporcional ao tempo de serviço.","c":"não poderá ser reconduzido ao cargo de origem, mas terá direito a indenização, ficando em disponibilidade, com remuneração proporcional ao tempo de serviço, até seu adequado aproveitamento em outro cargo.","d":"será reconduzido ao cargo de origem, sem direito a indenização, aproveitado em outro cargo ou posto em disponibilidade com remuneração proporcional ao tempo de serviço.","e":"será reconduzido ao cargo de origem, com direito a indenização, aproveitado em outro cargo ou posto em disponibilidade sem direito a remuneração. Direito Administrativo>Lei nº 8.112-1990 - Regime jurídico dos servidores públicos federais ,","gabarito":"D","materia":"Direito Administrativo","tema":"Agentes públicos e Lei 8.112 de 1990 ,Provimento e vacância","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1112","enunciado":"Ano: 2019 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática De acordo com o previsto na Lei no 8.112/1990 para as penalidades disciplinares, a","a":"demissão só pode ser aplicada para caso de servidor já apenado, ainda que por outra infração disciplinar, com","b":"suspensão. advertência deve ser necessariamente acompanhada da imposição de multa pecuniária, de caráter pedagógico.","c":"advertência e a suspensão ficam registradas na ficha do servidor apenado, não podendo ser canceladas durante a","d":"atividade. primeira infração disciplinar praticada pelo servidor efetivo deve necessariamente ser apenada com advertência.","e":"reincidência de infrações passíveis de punição com advertência enseja aplicação de suspensão.","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085652","enunciado":"Ano: 2019 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática Um particular apresentou requerimento de licença de funcionamento para seu estabelecimento comercial. Protocolou o pedido no órgão municipal equivocado, cujo diretor, inadvertidamente, deferiu o pedido, sem atentar que a natureza da atividade que o particular pretendia realizar se subordinava a atribuições legalmente previstas para outro órgão municipal. O ato de licença deferido","a":"é válido, ainda que contenha impropriedades, tendo em vista que o erro da Administração pública não projeta efeitos sobre o particular interessado.","b":"possui vício de competência, sendo necessário o encaminhamento de pedido para análise pelo órgão competente, que emitirá licença válida.","c":"reputa-se inalterável após o decurso do prazo de 30 dias, o mesmo estabelecido para a interposição de recurso","d":"administrativo pelo particular. está eivado de vício de finalidade, o que enseja a anulação do ato, decisão privativa da autoridade competente.","e":"não pode ser questionado sob o aspecto da validade, considerando que a competência é municipal e os órgãos públicos não têm personalidade jurídica própria.","gabarito":"B","materia":"Requisitos do ato administrativo – competência, finalidade, forma, motivo e objeto","tema":"","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085651","enunciado":"Suponha que uma determinada entidade integrante da Administração pública decida implementar, no âmbito de seu planejamento estratégico, o Balanced Scorecard (BSC). Entre outros aspectos, tal aplicação envolverá","a":"mapear os principais fatores de risco da atuação da entidade e elaborar as provisões necessárias para suportar sua","b":"eventual ocorrência. o foco nos resultados da entidade, que são priorizados de acordo com o impacto no resultado econômico.","c":"elaboração de um fluxograma, indicando todas as etapas das cadeias de processos geradores de valor para a entidade.","d":"alinhar missão, visão e estratégias da organização a um conjunto equilibrado de indicadores, financeiros e não financeiros.","e":"a elaboração de um diagrama, atribuindo pontuação para o peso relativo dos aspectos qualitativos e quantitativos envolvidos nas ações estratégicas da organização.","gabarito":"D","materia":"Governança de TI","tema":"Balanced Scorecard em Governança de T.I. (BSC)","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085650","enunciado":"Entre as ferramentas ordinariamente utilizadas na gestão de projetos pelas organizações, pode-se citar o COBIT, que","a":"é uma metodologia para elaboração do planejamento estratégico da companhia e alocação dos projetos de acordo","b":"com sua aderência às metas estabelecidas. corresponde a um diagrama de causa e efeito (inputs e outputs) presentes nos principais projetos da organização.","c":"consiste em um guia de melhores práticas utilizado na gestão de tecnologia da informação, que permite identificar quais projetos possuem maiores chances de sucesso.","d":"avalia os diferentes cenários probabilísticos dos riscos envolvidos na execução de projetos e apresenta ações de mitigação.","e":"mapeia todas as etapas envolvidas nos projetos prioritários da organização e aponta aquelas que podem ser suprimidas com vistas à redução do tempo de execução.","gabarito":"C","materia":"Governança de TI","tema":"COBIT","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085649","enunciado":"Suponha que determinada organização pretenda adotar um sistema robusto de gestão de riscos, utilizando os conceitos trazidos pela norma técnica ABN T NBR ISO 31000 - Gestão de Risco. O primeiro passo, então, é a própria compreensão","a":"pelos integrantes da organização do conceito de “risco”, que, nesse contexto, corresponde a consequências e impactos não mensuráveis de ações ou medidas adotadas de forma consciente pela organização.","b":"a potenciais consequências negativas de um comportamento inadequado ou imprevidente, cuja certeza de ocorrência","c":"é assumida. a eventos que estão fora da governabilidade da empresa e cuja probabilidade de ocorrência não pode ser aferida.","d":"ao efeito da incerteza nos objetivos, cujas consequências podem ser positivas ou negativas.","e":"a condições de atuação da organização no cenário em que se situa, quando este se mostra adverso. Ética na Administração Pública>Introdução, Ética e Moral e Orientações Gerais ,","gabarito":"D","materia":"Gerência de Projetos","tema":"Áreas de conhecimento ,Gerenciamento dos riscos","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1117","enunciado":"Ano: 2019 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática Considere as assertivas abaixo. I. A exigência de elevador adaptado é obrigatória para todos os edifícios de uso privado destinados às habitações unifamiliares. II . Uma vez cumprida a exigência de elevador adaptado, não é necessário que os demais elementos de uso comum do edifício também atendam requisitos de acessibilidade. III . A exigência de elevador adaptado aplica-se, em regra, a edifícios de uso privado a serem construídos com mais de um pavimento além do pavimento de acesso. IV . Os edifícios de uso privado em que seja obrigatória a instalação de elevadores deverão conter, dentre outros requisitos, percurso acessível que una a edificação à via pública, às edificações e aos serviços anexos de uso comum e aos edifícios vizinhos. No que","a":"concerne à acessibilidade nos edifícios de uso privado, prevista na Lei nº 10.098/2000, está correto o que consta A PENAS de II e III .","b":"III e IV.","c":"I e IV.","d":"I e II.","e":"I, III e IV. Estatuto da Pessoa com Deficiência - Lei nº 13.146 de 2015>","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1118","enunciado":"Ano: 2019 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática Maria é pessoa com deficiência, em situação de dependência que não dispõe de condições de autossustentabilidade e com","a":"vínculos familiares fragilizados. Nos termos da Lei no 13.146/2015, Maria tem direito à moradia digna em residência inclusiva","b":"em moradia para a vida independente, exclusivamente.","c":"obrigatoriamente no seio de sua família natural.","d":"obrigatoriamente no seio de família substituta.","e":"em qualquer residência, desde que a proteção integral em qualquer modalidade de residência seja prestada no âmbito do SUS (Sistema Único de Saúde) e não do SUAS (Sistema Único de Assistência Social).","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085643","enunciado":"Considere a conta armada abaixo, onde A, B e C representam algarismos distintos.","a":"Assim, A + C vale 12.","b":"9.","c":"10.","d":"11.","e":"8.","gabarito":"B","materia":"Matemática","tema":"Aritmética e Problemas ,Sistemas de Numeração e Operações Fundamentais","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085642","enunciado":"Em uma embaixada, 60% dos funcionários falam inglês, 45% falam alemão e 30% deles não falam nenhuma das duas","a":"línguas. Se, exatamente, 14 funcionários falam inglês e alemão, o número de funcionários dessa embaixada é igual a 60.","b":"90.","c":"80.","d":"100.","e":"40.","gabarito":"E","materia":"Matemática","tema":"Aritmética e Problemas ,Porcentagem","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085641","enunciado":"Em um teste, Maria deve acertar pelo menos 70% das questões para ser aprovada. Ela já fez 24 questões e sabe que acertou 15 delas e não sabe responder 9. Se não acertar essas 9 questões e acertar todas as outras, ela passará no teste;","a":"porém, se não acertar pelo menos uma dessas outras, ela não será aprovada. O número de questões desse teste é 30.","b":"36.","c":"45.","d":"42.","e":"39.","gabarito":"A","materia":"Matemática","tema":"Aritmética e Problemas ,Porcentagem","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085640","enunciado":"Atente para as seguintes frases: I. O autor tem medo de ir para o céu. II . O autor prende-se aos prazeres materiais. III . No céu não há prazeres materiais.","a":"Essas três frases integram-se com correção e coerência num único período em: O autor teme ir para o céu porque lá não há os prazeres materiais aos quais se prende.","b":"Visto que não terão no céu seus prazeres materiais, o autor teme já não se prender a eles.","c":"Não havendo no céu os prazeres materiais que lhe prendem, o autor teme ir ao mesmo.","d":"Preso que está nos prazeres materiais, o autor teme ir para o céu aonde não mais existem.","e":"O medo de ir para o céu é sentido ao autor pela materialidade dos prazeres que ele tem.","gabarito":"A","materia":"Português","tema":"Interpretação de Textos ,Coesão e coerência ,Redação - Reescritura de texto","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085639","enunciado":"","a":"Respeitam-se as normas de concordância verbal numa forma da voz passiva na frase: Tanto à Cecília Meireles como ao autor do texto assaltam o medo de morrer,","b":"O autor sente que rios e árvores, tudo o que é da natureza habitam seu corpo.","c":"Pelo vento frio das tardes jamais serão agraciados os seres a que falta um corpo.","d":"As alegrias que houverem no outro mundo já não terão raízes em nosso corpo.","e":"São das alegrias materiais que o autor se ressentirá caso o destinem ao paraíso.","gabarito":"C","materia":"Português","tema":"Sintaxe ,Concordância verbal, Concordância nominal","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085638","enunciado":"","a":"Não haverá, no contexto, prejuízo para a correção e para o sentido fundamental caso se substitua a expressão a algum lugar enfim se chega (1º parágrafo) por aonde não está mais distante.","b":"Nenhum mundo além poderá consolar-me (2º parágrafo) por Acolá não me impressiona.","c":"por bem-aventurado que seja (2º parágrafo) por ainda que contenhe bem-aventurança.","d":"A alegria animal está vedada (3º parágrafo) por Interdita-se do prazer dos animais.","e":"ao que consta, não sofrem os efeitos (3º parágrafo) por ao que se sabe, não os atingem as consequências.","gabarito":"E","materia":"Português","tema":"Interpretação de Textos ,Coesão e coerência ,Redação - Reescritura de texto","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085637","enunciado":"","a":"No contexto, estabelecem entre si uma relação de oposição de sentido os segmentos medo de morrer / não quero ir para o céu.","b":"não sofrem os efeitos da gravidade / quedas dos muros.","c":"cheiro bom do capim-gordura / sentir o vento frio das tardes.","d":"seres etéreos / Sua leveza os protege.","e":"somente sobre-humanas companhias / ficam flutuando no espaço.","gabarito":"B","materia":"Português","tema":"Interpretação de Textos ,Noções Gerais de Compreensão e Interpretação de Texto","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085636","enunciado":"","a":"Fundamentalmente, o autor confessa que tem medo de morrer e ir para o céu porque diz ignorar o que lhe reserva o lado enigmático do mundo, para além da vida","b":"as exigências de seu espírito religioso são tão altas que podem frustrar-se no paraíso.","c":"o sentimento da eternidade assusta pelo que há nela de implacável.","d":"se compraz com tudo o que a vida lhe oferece em sua natureza material.","e":"desconhece o sentido da bem-aventurança que a morte lhe revelará.","gabarito":"D","materia":"Português","tema":"Interpretação de Textos ,Noções Gerais de Compreensão e Interpretação de Texto","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085200","enunciado":"","a":"Constituição Federal de 1988 faz referência às limitações do poder de tributar, dispondo que é proibido ao Governo Federal criar imposto que implique distinção ou preferência em relação a um Estado, em A detrimento de outro, sendo permitido, contudo, dar incentivos tributários com a finalidade de promover o equilíbrio do desenvolvimento entre as diferentes regiões do País.","b":"proibido à União tributar a renda dos empréstimos concedidos aos Estados e Municípios (juro recebido pelo credor) e os salários dos funcionários públicos ou privados em níveis superiores a 12%, sob pena de caracterizar confisco.","c":"proibido incidir dois ou mais tributos federais, estaduais ou municipais na importação, sob pena de caracterizar bitributação (bis in idem).","d":"vedado à União conceder isenção de tributo federal, estadual ou municipal, sob pena de caracterizar falta de isonomia entre contribuintes, regiões, produtos ou consumidores.","e":"permitido aos Estados e ao Distrito Federal instituir isenções de tributos federais nas compras de mercadorias e prestações de serviços realizadas em seus territórios, desde que seja mediante lei específica e com o objeto de estimular o consumo, a redução da pobreza e a pequena empresa.","gabarito":"A","materia":"Direito Tributário","tema":"Limitações Constitucionais ao Poder de Tributar - Princípios Tributários ,Princípio da Isonomia","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085199","enunciado":"Conforme a Constituição Federal de 1988, compete à União instituir impostos sobre","a":"o comércio internacional, abrangendo importação e exportação, o comércio local e interestadual de mercadorias e a","b":"prestação de serviços. pequenas, médias e grandes fortunas, propriedade de imóvel rural e urbano, e seguros de vida e saúde.","c":"proventos de qualquer natureza, câmbio, seguro, importação e exportação.","d":"comércio em geral, prestação de serviço, produtos rurais, artesanais e orgânicos.","e":"comércio interestadual e internacional, produção de produtos industriais e rurais, renda e propriedade rural.","gabarito":"C","materia":"Direito Tributário","tema":"Competência Tributária ,Partilha e Tipologia (Repartição de Competência)","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085198","enunciado":"","a":"Constituição Federal de 1988, na parte que trata das limitações ao poder de tributar, estabelece que é vedado à União instituir ou aumentar um tributo sem lei que o estabeleça, mas a redução do tributo, a isenção, a A redução da base de cálculo ou a concessão de crédito presumido não dependem de lei, podendo ser veiculadas por decreto do poder executivo federal.","b":"é vedado ao Município utilizar tributo com efeito de confisco, mas é permitido alterar a base de cálculo do imposto sobre serviços de qualquer natureza, para um valor maior ou menor, por meio de decreto municipal, com vigência imediata.","c":"é vedado aos Estados estabelecer limitações ao tráfego de pessoas ou bens, por meio de tributos interestaduais ou intermunicipais, sendo permitida a cobrança de pedágio pela utilização de vias conservadas pelo Poder Público.","d":"é permitido cobrar tributos no mesmo exercício financeiro em que haja sido publicada a lei que os instituiu ou aumentou, quando se trata do imposto sobre propriedade de veículos automotores.","e":"não se pode instituir impostos sobre as instituições de educação e de assistência social, tenham elas finalidade de lucro, ou não, pois são atividades de relevância social especial.","gabarito":"C","materia":"Direito Tributário","tema":"Limitações Constitucionais ao Poder de Tributar - Princípios Tributários","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085196","enunciado":"","a":"lei complementar se distingue da lei ordinária pelo quórum necessário para aprovação pelos parlamentares e por ser o veículo normativo exclusivo para tratar de determinados temas previstos na Constituição Federal de 1988. Cabe exclusivamente à lei complementar: instituir o imposto sobre grandes fortunas; o imposto sobre a renda e proventos de qualquer natureza; o imposto A extraordinário no caso de guerra externa ou sua iminência e o empréstimo compulsório no caso de investimento público de caráter urgente e de relevante interesse nacional. dispor sobre conflitos de competência, em matéria tributária, entre a União, os Estados, o Distrito Federal e os","b":"Municípios; regular as limitações constitucionais ao poder de tributar; e estabelecer normas gerais em matéria de legislação tributária, assim como obrigação, lançamento, crédito, prescrição e decadência tributários; além de outras matérias mencionadas na Constituição.","c":"instituir contribuições sociais, de intervenção no domínio econômico e de interesse das categorias profissionais ou econômicas e, também, estabelecer normas gerais em matéria de legislação tributária para definição de tributos e de suas espécies, além de outras matérias de natureza tributária.","d":"instituir, pela União, empréstimo compulsório para atender a despesas extraordinárias, decorrentes de calamidade pública, de guerra externa ou sua iminência; estabelecer as alíquotas mínimas nas operações internas do ICMS e fixar alíquotas máximas nas mesmas operações para resolver conflito específico que envolva interesse de Estados.","e":"estabelecer normas gerais em matéria de legislação tributária sobre obrigação, lançamento, crédito, prescrição e decadência tributários, além de outras hipóteses; e instituir os impostos sobre fortunas e sobre operações de crédito, câmbio e seguro, ou relativas a títulos ou valores mobiliários. Direito Tributário>Limitações Constitucionais ao Poder de Tributar - Princípios Tributários ,","gabarito":"B","materia":"Direito Constitucional","tema":"Ordem Econômica e Financeira ,Sistema Tributário Nacional","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1131","enunciado":"Ano: 2019 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa Sob o título “Das limitações do Poder de Tributar”, a Constituição Federal de 1988 consagra o princípio da","a":"anterioridade, segundo o qual a União, os Estados, o Distrito Federal e os Municípios não podem exigir ou aumentar tributo sem lei que o estabeleça.","b":"legalidade, dispondo que a União, os Estados, o Distrito Federal e os Municípios não podem cobrar tributos em relação a fatos geradores ocorridos antes do início da vigência da lei que os houver instituído ou aumentado.","c":"irretroatividade da lei tributária, que veda aos entes políticos tributantes cobrar tributo no mesmo exercício financeiro em que haja sido publicada a lei que os instituiu ou aumentou.","d":"igualdade tributária, dispondo que os entes políticos da Federação não podem instituir tratamento desigual entre contribuintes que se encontrem em situação equivalente, devendo levar em consideração a ocupação profissional ou função por eles exercida, bem como a denominação jurídica dos rendimentos, títulos ou direitos.","e":"não discriminação tributária, que veda aos Estados, ao Distrito Federal e aos Municípios estabelecer diferença tributária entre bens e serviços, de qualquer natureza, em razão de sua procedência ou destino. Direito Previdenciário>Beneficiários do Regime Geral de Previdência Social - RGPS ,","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1132","enunciado":"Ano: 2019 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa Considere as afirmações abaixo. I. Mantém a qualidade de segurado, independentemente de contribuições até 6 meses após a cessação das contribuições, o segurado facultativo. II. Mantém a qualidade de segurado, independentemente de contribuições até 4 meses após o licenciamento, o segurado incorporado às Forças Armadas para prestar serviço militar. III. Mantém a qualidade de segurado, independentemente de contribuições, sem limite de prazo, quem está em gozo de benefício, exceto do auxílio-acidente. IV. A perda da qualidade de segurado ocorrerá no dia seguinte ao do término do prazo fixado no Plano de Custeio da Seguridade Social para recolhimento da contribuição referente ao mês imediatamente posterior ao do final dos prazos estabelecidos pela Lei n° 8.213/1991.","a":"Está correto o que consta APENAS de II e IV.","b":"I, III e IV.","c":"I e IV","d":"II, III e IV.","e":"I, II e III. Direito Previdenciário>Beneficiários do Regime Geral de Previdência Social - RGPS ,","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085188","enunciado":"Considere os seguintes casos hipotéticos: I. Paulo, funcionário público no exercício do seu cargo, cometeu crime de corrupção passiva ao exigir dinheiro de uma determinada pessoa para deixar de praticar determinado ato de ofício. II. Júlio cometeu crime de cárcere privado (artigo 148, do Código Penal) ao invadir a casa da ex-namorada, que não queria reatar o relacionamento amoroso. III. Afonso cometeu crime de roubo (artigo 157, do Código Penal) contra um hipermercado situado na cidade de São Paulo, em comparsaria com outros elementos. IV. Manoel, funcionário público, cometeu crime de peculato após se apropriar de dinheiro de que teve a posse em razão do seu cargo. Presentes todos os requisitos legais previstos na Lei n° 7.960/1989, que dispõe sobre a prisão temporária, o magistrado","a":"competente poderá decretar a prisão temporária de: Paulo, Júlio e Manoel, apenas.","b":"Paulo, Júlio, Afonso e Manoel.","c":"Paulo, Afonso e Manoel, apenas.","d":"Júlio e Afonso, apenas.","e":"Júlio e Manoel, apenas. Direito Processual Penal>Das Citações e Intimações ,Procedimento Penal ,Procedimento comum ordinário","gabarito":"D","materia":"Direito Processual Penal","tema":"Da Prisão e da Liberdade Provisória ,Da Prisão Temporária","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1134","enunciado":"Ano: 2019 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa Marina está respondendo, em liberdade, processo por crime de contrabando em uma das varas com competência criminal da Justiça Federal de Campo Grande/MS. No momento da sua prisão em flagrante, ao ser qualificada, Marina declarou o seu endereço residencial na Avenida Lilás, n° 1, apartamento 12, na cidade de Campo Grande, endereço esse ratificado quando da concessão do benefício da liberdade provisória pelo magistrado competente. Ao término do inquérito policial, o Ministério Público Federal denunciou Marina pelo crime do artigo 334-A, Código Penal (contrabando). A denúncia foi recebida e a ré devidamente citada para responder à ação penal, apresentando sua defesa preliminar. Após manter o recebimento da denúncia, o magistrado competente designou audiência de instrução, debates e julgamento. Expedido mandado de intimação para a audiência, Marina não é encontrada no endereço que forneceu, tendo mudado de domicílio sem comunicar o juízo. No dia da audiência Marina não compareceu ao ato processual. Nesse caso, o magistrado que preside a ação penal deverá","a":"redesignar a audiência de instrução e determinar a realização de pesquisas por meio do sistema SIEL (Tribunal Regional Eleitoral) e Bacenjud, para tentar localizar e intimar pessoalmente a ré Marina.","b":"redesignar a audiência de instrução e determinar a intimação de Marina por edital para a nova data que será","c":"agendada. determinar a suspensão do processo e do curso do prazo prescricional até a localização de Marina.","d":"realizar normalmente a audiência de instrução e, posteriormente, determinar a intimação de Marina por edital para uma nova audiência de interrogatório.","e":"determinar o regular prosseguimento do processo até julgamento sem a presença da acusada Marina, declarando a sua revelia. Direito Processual Penal>Recursos Criminais ,Mandado de Segurança no Processo Penal ,","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1135","enunciado":"Ano: 2019 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa Maurilio e Pedro foram investigados pela Polícia Federal pelos crimes de formação de quadrilha, corrupção ativa e lavagem de dinheiro. Encerrado e relatado o inquérito policial, o Ministério Público ofereceu denúncia contra Maurilio e Pedro e apresentou requerimento ao magistrado competente para decretação das prisões preventivas dos denunciados. O magistrado, ao proferir o despacho inicial admitindo a denúncia, indeferiu o requerimento de prisão preventiva, entendendo que estavam ausentes os requisitos legais para tanto. Inconformado, o Ministério Público Federal poderá","a":"interpor agravo de instrumento, no prazo de 10 dias.","b":"recurso em sentido estrito, no prazo de 05 dias.","c":"correição parcial, no prazo de 05 dias.","d":"apelação, no prazo de 05 dias.","e":"mandado de segurança, no prazo de 10 dias.","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085185","enunciado":"Lucas está sendo processado por crime de peculato (artigo 312, do Código Penal) em uma das varas da Justiça Federal de Campo Grande, com competência criminal. Ao término da regular instrução do feito, o Magistrado competente proferiu sentença, que condenou Lucas a cumprir pena de 04 anos de reclusão, em regime inicial semiaberto, e ao pagamento de 10 dias-multa. Uma das teses veiculadas pelos advogados do réu, Lucas, não foi analisada na sentença proferida pelo Magistrado. Nesse caso, Lucas, por meio de seus advogados, poderá interpor embargos de declaração a partir da","a":"publicação da sentença condenatória, no prazo de 02 dias.","b":"05 dias.","c":"10 dias.","d":"15 dias.","e":"03 dias. Direito Processual Penal>Ação Penal ,Condições para o Exercício da Ação Penal ,","gabarito":"A","materia":"Direito Processual Penal","tema":"Recursos Criminais ,Embargos de Declaração nos Recursos Criminais","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1137","enunciado":"Ano: 2019 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa Maurício esteve em uma festa realizada em uma casa noturna, situada na cidade de São Paulo, no dia 10 de julho de 2019. Acabou se envolvendo em uma briga e foi agredido por duas pessoas não identificadas. Maurício registrou Boletim de Ocorrência e foi submetido a exame de corpo de delito, que constatou que ele sofreu lesões corporais de natureza leve. No curso das investigações, de posse das imagens das câmeras de segurança do estabelecimento, foi possível identificar os dois agressores. Maurício compareceu ao Distrito Policial e realizou o reconhecimento pessoal dos seus agressores em 15 de agosto de 2019, os quais foram devidamente qualificados nessa data. No dia 10 de setembro de 2019, Maurício faleceu em decorrência de um infarto, deixando uma esposa, Fabíola. No caso hipotético apresentado, tratando-se de crime que se processa mediante representação do ofendido, Fabíola, na condição de cônjuge do falecido, deverá ofertar a necessária","a":"representação para ver os agressores do seu finado esposo processados criminalmente no prazo de 03 meses, contado a partir da data do óbito de Maurício.","b":"06 meses, contado a partir do dia 10 de julho de 2019.","c":"06 meses, contado a partir do dia 15 de agosto de 2019.","d":"06 meses, contado a partir da data do óbito de Maurício.","e":"03 meses, contado a partir do dia 10 de julho de 2019.","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085183","enunciado":"Sobre as questões processuais previstas na Lei n° 9.613/1998, que dispõe sobre os crimes de lavagem de dinheiro, é correto afirmar:","a":"Decretadas medidas assecuratórias de bens do investigado provenientes dos crimes de lavagem de dinheiro, pelo magistrado competente, se eles estiverem sujeitos a qualquer grau de deterioração ou depreciação, proceder-se-á à alienação antecipada para preservação do valor dos bens.","b":"O juiz, jamais de ofício, mas mediante requerimento do Ministério Público ou da parte interessada, poderá decretar a alienação antecipada de bens sob constrição, provenientes de crimes de lavagem de dinheiro, que foram objeto de medidas assecuratórias.","c":"O processo e julgamento dos crimes previstos nesta lei dependem do processo e julgamento das infrações penais antecedentes, ainda que praticadas em outro país.","d":"O processo e julgamento dos crimes previstos na Lei n° 9.613/1998 são regidos por procedimento especial orientado pelo referido diploma legal, aplicando-se apenas subsidiariamente o rito comum dos crimes punidos com reclusão, previsto no Código de Processo Penal, da competência do juiz singular.","e":"O juiz não poderá manter a constrição de bens, direitos e valores de origem lícita comprovada, ainda que destinados ao pagamento de reparação dos danos, prestações pecuniárias e multas, decorrentes da infração penal.","gabarito":"A","materia":"Direito Penal","tema":"Lei da Lavagem de Dinheiro - Lei nº 9.613 de 1998 ,Legislação Penal Especial","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085182","enunciado":"Sobre a competência penal da Justiça Federal, é INCORRETO afirmar que compete","a":"aos juízes federais processar e julgar os crimes previstos em tratado ou convenção internacional, quando, iniciada a execução no País, o resultado tenha ou devesse ter ocorrido no estrangeiro, ou reciprocamente.","b":"aos juízes federais processar e julgar os crimes cometidos a bordo de navios ou aeronaves, ressalvada a competência da Justiça Militar.","c":"aos Tribunais Regionais Federais julgar originariamente os membros do Ministério Público da União nos crimes comuns, ressalvada a competência da Justiça Eleitoral.","d":"ao Superior Tribunal de Justiça julgar, em recurso ordinário, decisões concessivas de habeas corpus decididos em","e":"última ou única instância pelos Tribunais Regionais Federais. aos Tribunais Regionais Federais processar e julgar as revisões criminais de julgados dos juízes federais da região.","gabarito":"D","materia":"Direito Processual Penal","tema":"Competência no Processo Penal ,Competência criminal da Justiça Federal","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085181","enunciado":"De acordo com a Lei n° 10.259/2001, compete ao Juizado Especial Federal Cível processar, conciliar e julgar causas de competência da Justiça Federal até o valor de sessenta salários mínimos, com algumas exceções. NÃO são excluídas da","a":"competência do Juizado Especial Federal Cível as ações de mandado de segurança.","b":"que versarem sobre bens imóveis da União.","c":"que versarem sobre direitos ou interesses difusos.","d":"de desapropriação de bens móveis.","e":"para a anulação de lançamento fiscal.","gabarito":"E","materia":"Direito Processual Civil - Novo Código de Processo Civil - CPC 2015","tema":"Juizado Especial ,Juizado Especial Federal","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085179","enunciado":"Na audiência de instrução e julgamento, o juiz","a":"exerce o poder de polícia, incumbindo-lhe ordenar que se retirem da sala de audiência quaisquer pessoas que se comportarem inconvenientemente.","b":"só deverá tentar conciliar as partes se não tiver havido prévia audiência de conciliação, ou se alguma delas informar, por ocasião da abertura dos trabalhos, que pretende formular proposta de acordo.","c":"somente poderá proferir sentença se todas as partes e o Ministério Público, nos feitos dos quais participar, concordarem em apresentar suas alegações finais oralmente ou dispensarem a sua apresentação.","d":"não poderá obstar os advogados ou o Ministério Público de intervir ou apartear enquanto depuserem as testemunhas, ainda que sem a sua licença.","e":"poderá, independentemente da concordância das partes, cindir a produção da prova oral, tomando o depoimento das testemunhas presentes e designando outra data para a oitiva das ausentes. Direito Processual Civil - Novo Código de Processo Civil - CPC 2015>Atos Processuais ,","gabarito":"A","materia":"Direito Processual Civil - Novo Código de Processo Civil - CPC 2015","tema":"Audiência de Instrução e Julgamento - AIJ","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1142","enunciado":"Ano: 2019 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa Segundo o Código de Processo Civil, é possível estabelecer calendário para a prática dos atos processuais, quando for o caso. Esse calendário será fixado de comum acordo entre","a":"as partes, independentemente da concordância do juiz, que ficará obrigado a observar os prazos e datas nele estabelecidos, inclusive no tocante à realização das audiências ou outros atos que demandem a sua presidência.","b":"as partes, independentemente da concordância do juiz, que ficará obrigado a observar os prazos e datas nele estabelecidos, exceto no tocante à realização das audiências ou outros atos que demandem a sua presidência, os quais serão designados conforme a disponibilidade da pauta.","c":"as partes e o juiz, que ficará obrigado a observar os prazos nele estabelecidos, inclusive para a prolação das decisões, os quais somente poderão ser modificados em casos excepcionais, devidamente justificados.","d":"as partes e o juiz, que ficará obrigado a observar os prazos nele estabelecidos, inclusive para a prolação das decisões, salvo se inferiores àqueles dispostos em lei.","e":"as partes e o juiz, que não poderá, em nenhuma hipótese, modificar os prazos nele estabelecidos, salvo expressa concordância de todos os litigantes. Direito Processual Civil - Novo Código de Processo Civil - CPC 2015>Da Comunicação dos Atos Processuais ,","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1143","enunciado":"Ano: 2019 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa De acordo com o Código de Processo Civil, a carta precatória","a":"deverá ser instruída com as cópias necessárias à realização do ato deprecado, vedada, em qualquer hipótese, a remessa de documento original.","b":"tem caráter itinerante, podendo, mesmo antes de lhe ser ordenado o cumprimento, ser encaminhada a juízo diverso do que dela consta, a fim de se praticar o ato.","c":"será expedida, preferencialmente, por meio físico, salvo quando enviada a órgão jurisdicional integrante do mesmo tribunal, caso em que adotará preferencialmente o meio eletrônico.","d":"não poderá, em nenhuma hipótese, ter seu cumprimento recusado pelo juízo deprecado, sob pena de, assim o fazendo, incorrer em responsabilidade funcional.","e":"deverá ser transmitida por correio, malote, pela internet ou por qualquer outro meio idôneo que garanta a aferição da sua autenticidade, sendo vedada a transmissão por telefone. Direito Processual Civil - Novo Código de Processo Civil - CPC 2015>Sujeitos da Relação Processual ,","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1144","enunciado":"Ano: 2019 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa De acordo com o Código de Processo Civil, aos auxiliares da justiça,","a":"inclusive ao oficial de justiça, aplicam-se, no que couber, os motivos de impedimento e de suspeição previstos para o juiz.","b":"com exceção do perito, aplicam-se, no que couber, os motivos de impedimento previstos para o juiz, mas não os de suspeição.","c":"com exceção do oficial de justiça, do perito e do chefe de secretaria, não se aplicam os motivos de impedimento ou suspeição previstos para o juiz.","d":"com exceção do mediador, aplicam-se, no que couber, os motivos de impedimento e de suspeição previstos para o juiz.","e":"com exceção do perito, não se aplicam os motivos de suspeição previstos para o juiz, mas outros estabelecidos especificamente segundo a função que exercem no processo.","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085175","enunciado":"","a":"De acordo com o Código de Processo Civil, o pedido de cooperação jurisdicional, no âmbito nacional, exige forma prevista em lei, podendo ser executado como atos concertados entre os juízes cooperantes.","b":"exige forma prevista em lei, podendo ser executado como prestação de informações.","c":"exige forma prevista em lei, podendo ser executado como reunião de processos.","d":"prescinde de forma específica, podendo ser executado como auxílio direto.","e":"prescinde de forma específica, desde que realizado entre órgãos jurisdicionais do mesmo ramo do Poder Judiciário.","gabarito":"D","materia":"Direito Processual Civil - Novo Código de Processo Civil - CPC 2015","tema":"Competência no Processo Civil","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085174","enunciado":"Rodolfo é juiz estadual, não tendo nunca retido, injustificadamente, autos em seu poder além do prazo legal, devolvendo-os sempre ao cartório com o devido despacho ou decisão. Exerce a sua função na mesma entrância para a qual foi promovido por antiguidade há dois anos, já tendo figurado por cinco vezes alternadas em lista de merecimento para promoção de entrância para entrância, integrando, atualmente, a primeira quinta parte da lista de antiguidade. Em conformidade com a Constituição Federal de 1988 e considerando apenas os dados fornecidos, Rodolfo","a":"não pode ser promovido por merecimento, pois tal promoção pressupõe o tempo mínimo de três anos de exercício na respectiva entrância.","b":"não pode ser promovido por merecimento, pois para tanto é obrigatória a promoção do juiz que figure por três vezes","c":"consecutivas em lista de merecimento. deve ser promovido por merecimento, respeitadas as normas incidentes na espécie.","d":"deve ser promovido por merecimento, sendo que o tribunal somente poderá recusar tal promoção pelo voto fundamentado de dois quintos de seus membros, conforme procedimento próprio, e assegurada ampla defesa, repetindo-se a votação até fixar-se a indicação.","e":"não pode ser promovido por merecimento, pois tal promoção pressupõe o tempo mínimo de cinco anos de exercício na respectiva entrância e integrar o juiz a primeira terça parte da lista de antiguidade. Direito Constitucional>Presidente da República, Vice-Presidente da República e Ministros de Estado. ,","gabarito":"C","materia":"Direito Constitucional","tema":"Poder Judiciário ,Garantias do Poder Judiciário e de seus Membros","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1147","enunciado":"Ano: 2019 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa De acordo com a Constituição Federal de 1988, dispor, mediante decreto, sobre a organização e funcionamento da Administração federal, quando não implicar aumento de despesa nem criação ou extinção de órgãos públicos, é da competência","a":"exclusiva do Presidente da República, podendo ele delegar essa atribuição apenas ao Ministro da Justiça, que observará os limites traçados na respectiva delegação.","b":"privativa do Presidente da República, podendo ele delegar essa atribuição ao Presidente da Câmara dos Deputados, ao Presidente do Senado Federal ou ao Ministro da Justiça, que observarão os limites traçados na respectiva","c":"delegação. privativa do Presidente da República, não podendo ele delegar essa atribuição.","d":"exclusiva do Presidente da República, podendo ele delegar essa atribuição apenas aos Ministros de Estado, que observarão os limites traçados na respectiva delegação.","e":"privativa do Presidente da República, podendo ele delegar essa atribuição aos Ministros de Estado, ao Procurador- Geral da República ou ao Advogado-Geral da União, que observarão os limites traçados na respectiva delegação.","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085172","enunciado":"Com relação à estabilidade dos servidores públicos, considere: I. São estáveis somente após cinco anos de efetivo exercício os servidores nomeados para cargo de provimento efetivo em virtude de concurso público. II. Como condição para a aquisição da estabilidade, é obrigatória a avaliação especial de desempenho por comissão instituída para essa finalidade. III. Invalidada por sentença judicial a demissão do servidor estável, tendo sido extinto o cargo que ele ocupava ou declarada a sua desnecessidade, referido servidor ficará em disponibilidade, com remuneração proporcional ao tempo de serviço, até seu adequado aproveitamento em outro cargo.","a":"Em conformidade com a Constituição Federal de 1988, está correto o que consta de I e II, apenas.","b":"I, II e III.","c":"II e III, apenas.","d":"I, apenas.","e":"III, apenas.","gabarito":"C","materia":"Direito Constitucional","tema":"Administração Pública – Disposições Gerais e Servidores Públicos ,Servidores Públicos","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085171","enunciado":"Edineia, trabalhadora urbana, foi dispensada sem justa causa de seu emprego e entende que possui créditos resultantes dessa relação de trabalho. Em conformidade com a Constituição Federal de 1988, Edineia tem direito de propor ação, em","a":"face de seu ex-empregador, com prazo prescricional de cinco anos, até o limite de dois anos após a extinção do contrato de trabalho.","b":"com prazo prescricional de dez anos, até o limite de cinco anos após a extinção do contrato de trabalho.","c":"a qualquer tempo, uma vez que o direito ao trabalho é um direito fundamental e, portanto, imprescritível.","d":"com prazo prescricional de dez anos, até o limite de dois anos após a extinção do contrato de trabalho.","e":"com prazo prescricional de cinco anos, até o limite de cinco anos após a extinção do contrato de trabalho.","gabarito":"A","materia":"Direito Constitucional","tema":"Direitos Sociais","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085170","enunciado":"Considere as seguintes situações: I. Paula, brasileira, estava na Irlanda a serviço do Brasil, quando nasceu seu filho Bernardo. II. Mercedes, chilena, veio ao Brasil para desfrutar suas férias, quando nasceu sua filha Angelita. III. Manuela, brasileira, apenas estudava inglês na Austrália, quando nasceu seu filho Anthony, o qual não foi registrado em repartição brasileira competente. Nos termos da Constituição Federal de 1988, Bernardo é brasileiro nato, pois nasceu no estrangeiro quando sua mãe, brasileira, estava a serviço do Brasil; Angelita é","a":"brasileira nata, desde que venha a residir no Brasil e opte, em qualquer tempo, depois de atingida a maioridade, pela nacionalidade brasileira, pois sua mãe é estrangeira; Anthony poderá adquirir a nacionalidade brasileira apenas por meio da naturalização, pois, apesar de ser filho de mãe brasileira, nasceu no estrangeiro e não foi registrado em repartição brasileira competente. é brasileiro nato, pois nasceu no estrangeiro quando sua mãe, brasileira, estava a serviço do Brasil; Angelita não é","b":"brasileira nata, mesmo que nascida em território nacional brasileiro, pois sua mãe é chilena e não estava no país a serviço do Brasil; Anthony não poderá ser considerado brasileiro nato, ainda que sua mãe seja brasileira, pois nasceu no estrangeiro e não foi registrado em repartição brasileira competente. não é brasileiro nato, ainda que filho de mãe brasileira, pois nasceu no estrangeiro; Angelita é brasileira nata, pois","c":"nasceu no Brasil, e sua mãe, estrangeira, não estava a serviço de seu país; Anthony não poderá ser considerado brasileiro nato, ainda que sua mãe seja brasileira, pois nasceu no estrangeiro e não foi registrado em repartição brasileira competente.","d":"e Anthony são brasileiros natos, mesmo que nascidos em território estrangeiro, pois são filhos de mãe brasileira; Angelita não é brasileira nata, mesmo que nascida em território nacional brasileiro, pois sua mãe é chilena e não estava no país a serviço do Brasil. é brasileiro nato, pois nasceu no estrangeiro quando sua mãe, brasileira, estava a serviço do Brasil; Angelita é","e":"brasileira nata, pois nasceu no Brasil, e sua mãe, estrangeira, não estava a serviço de seu país; Anthony é brasileiro nato, desde que venha a residir no Brasil e opte, em qualquer tempo, depois de atingida a maioridade, pela nacionalidade brasileira.","gabarito":"E","materia":"Direito Constitucional","tema":"Direitos da Nacionalidade","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085169","enunciado":"Joana é brasileira nata, analfabeta e tem 18 anos de idade. Carlos é brasileiro nato, estudante e tem 16 anos de idade. Aparecida é brasileira nata, enfermeira aposentada e tem 79 anos de idade. Marc é brasileiro naturalizado, professor universitário e tem 35 anos de idade. Considerando-se somente os dados fornecidos, em conformidade com a Constituição","a":"Federal de 1988, o voto é obrigatório para Aparecida, facultativo para Joana e Carlos e proibido para Marc.","b":"facultativo para Joana, Carlos, Aparecida e Marc.","c":"obrigatório para Marc e facultativo para Joana, Carlos e Aparecida.","d":"facultativo para Joana, Carlos e Aparecida e proibido para Marc.","e":"facultativo para Carlos e Aparecida e proibido para Joana e Marc.","gabarito":"C","materia":"Direito Constitucional","tema":"Direitos Políticos","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085168","enunciado":"Pablo, viúvo, estrangeiro, faleceu em sua terra natal, onde era domiciliado, deixando dois únicos filhos: Marina, brasileira naturalizada, e Gabriel, brasileiro nato. Em conformidade com a Constituição Federal de 1988, a sucessão dos imóveis de","a":"Pablo situados no Brasil será regulada pela lei pessoal de Pablo em relação a Marina e pela lei brasileira em relação a Gabriel.","b":"sempre pela lei brasileira, uma vez que os imóveis se encontram no Brasil, ainda que a lei pessoal de Pablo seja mais favorável a Marina e Gabriel.","c":"sempre pela lei pessoal de Pablo, uma vez que ele nasceu em território estrangeiro, ainda que a lei brasileira seja mais","d":"favorável a Marina e Gabriel. pela lei brasileira, salvo se a lei pessoal de Pablo for mais favorável a Marina e Gabriel.","e":"sempre pela lei pessoal de Pablo, uma vez que teve como último domicílio sua terra natal, ainda que a lei brasileira seja mais favorável a Marina e Gabriel. Direito Administrativo>Responsabilidade civil do estado ,","gabarito":"D","materia":"Direito Constitucional","tema":"Direitos Individuais ,Direito de Propriedade e Função Social da Propriedade","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1153","enunciado":"Ano: 2019 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa Julio exerce cargo público efetivo de motorista em uma autarquia federal e, durante o exercício funcional, envolveu-se em acidente que causou danos patrimoniais a terceiros. Nesse caso, no tocante ao regime de responsabilidade civil, o referido","a":"servidor responderá de forma objetiva e solidária com a autarquia.","b":"não responderá em hipótese alguma, pois se trata de hipótese de responsabilidade integral da União.","c":"responderá de forma subjetiva apenas se incluído no polo passivo da ação pelo terceiro afetado.","d":"responderá de forma objetiva e subsidiária em relação à autarquia.","e":"responderá de forma subjetiva e por meio de ação regressiva. Direito Administrativo>Lei nº 8.112-1990 - Regime jurídico dos servidores públicos federais ,","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1154","enunciado":"Ano: 2019 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa No tocante às licenças e afastamentos dos servidores públicos, a Lei n° 8.112/1990, que estabelece o regime jurídico aplicável aos servidores públicos federais, dispõe que","a":"a licença ao servidor para acompanhar cônjuge ou companheiro, que foi deslocado para outro ponto do território nacional, para o exterior ou para o exercício de mandato eletivo dos Poderes Executivo e Legislativo, será por prazo indeterminado e com proventos proporcionais.","b":"o servidor investido em mandato eletivo ou classista poderá ser removido ou redistribuído de ofício para localidade diversa daquela onde exerce o mandato, desde que justificadamente.","c":"a licença por motivo de doença em pessoa da família somente será deferida se a assistência direta do servidor for indispensável e não puder ser prestada simultaneamente com o exercício do cargo ou mediante compensação de horário.","d":"o servidor candidato a cargo eletivo na localidade onde desempenha suas funções e que exerça cargo de direção, chefia, assessoramento, arrecadação ou fiscalização, dele será afastado, a partir do dia imediato ao do registro de sua candidatura perante a Justiça Eleitoral, somente a ele retornando no ano seguinte ao pleito.","e":"após cada quinquênio de efetivo exercício, o servidor poderá, a seu exclusivo critério, afastar-se do exercício do cargo efetivo, com a respectiva remuneração, por até três meses, para tratar de interesses particulares. Direito Administrativo>Lei nº 8.112-1990 - Regime jurídico dos servidores públicos federais ,","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085163","enunciado":"Para maior especialização na execução de atividades de sua competência, os entes políticos podem promover a criação de entidades descentralizadas, que comporão a chamada Administração Indireta. No tocante à Administração Indireta,","a":"a empresa pública é entidade dotada de personalidade jurídica de direito privado, com patrimônio próprio e capital exclusivamente estatal, devendo revestir-se obrigatoriamente da forma de sociedade anônima.","b":"as entidades da Administração Indireta que sejam dotadas de personalidade jurídica de direito privado, em vista da maior flexibilidade do seu regime jurídico, são dispensadas de fazer licitação para realizar suas contratações.","c":"somente por lei federal poderá ser criada autarquia e autorizada a instituição de empresa pública, de sociedade de economia mista e de fundação, seja qual for o ente político envolvido. a empresa pública, a sociedade de economia mista e as respectivas subsidiárias, que explorem atividade econômica","d":"de produção ou comercialização de bens ou de prestação de serviços, estão sujeitas a regime de licitação e contratação pública idêntico ao aplicável aos órgãos da Administração Direta e às entidades de direito público, como as autarquias.","e":"a vedação constitucional à acumulação de cargos, empregos e funções públicas abrange também as autarquias, fundações, empresas públicas, sociedades de economia mista, suas subsidiárias e sociedades controladas, direta ou indiretamente, pelo poder público.","gabarito":"E","materia":"Direito Administrativo","tema":"Organização da Administração Pública ,Administração Indireta","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085162","enunciado":"","a":"Lei Federal n° 9.784/1999 - Lei do Processo Administrativo - impõe como critério a ser observado na atuação nos processos administrativos a vedação à aplicação retroativa de nova interpretação (art. 2°, parágrafo único, XIII). Tal diretriz prestigia especialmente o princípio da","b":"A segurança jurídica. moralidade administrativa.","c":"eficiência.","d":"impessoalidade.","e":"autotutela.","gabarito":"A","materia":"Direito Administrativo","tema":"Processo Administrativo - Lei nº 9.784 de 1999 e Lei nº 14.210 de 2021","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085161","enunciado":"O poder hierárquico é um elemento importante na coordenação dos agentes incumbidos do exercício de determinadas funções estatais. Tal poder","a":"está presente também na relação entre o governador de um estado e os prefeitos dos municípios situados em seu","b":"território. pressupõe a faculdade de avocar e delegar atribuições, seja qual for a matéria envolvida.","c":"impõe o dever de obediência, ainda que manifesta a ilegalidade da ordem recebida.","d":"permite a revisão de ofício dos atos dos subordinados, seja por razões de mérito, seja por razões de legalidade, ressalvados eventuais limites impostos pela lei.","e":"explica a relação de controle que existe entre um ente da Administração Indireta e o órgão da Administração Direta responsável pela sua supervisão.","gabarito":"D","materia":"Direito Administrativo","tema":"Poderes da Administração ,Poder normativo, poder hierárquico e poder disciplinar","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085160","enunciado":"","a":"Atenção: A questão corresponde à Gestão Pública. aplicação da metodologia de gestão por competências nas organizações pressupõe uma etapa de mapeamento de competências, que identifica as principais deficiências técnicas dos colaboradores da organização, a fim de promover programas de A treinamento e capacitação eficientes.","b":"é realizada ao final do processo, como resultado (output) das melhorias implementadas pelo processo de formação dos colaboradores e adequação dos processos de trabalho.","c":"corresponde a uma análise externa, identificando as referências de boas práticas no segmento de recursos humanos a serem transpostas para a organização.","d":"consiste na prospecção dos melhores profissionais disponíveis no mercado, que devem ser recrutados como disseminadores de conhecimento na organização.","e":"deve ser realizada no início do processo, juntamente com a mensuração, tendo por escopo identificar as competências técnicas e comportamentais necessárias para cada uma das atividades da organização. Gerência de Projetos>Áreas de conhecimento ,Gerenciamento de escopo ,Gerenciamento do tempo","gabarito":"E","materia":"Gestão de Pessoas","tema":"Gestão de Competências","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085159","enunciado":"Ano: 2019 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa Entre as metodologias consagradas de gestão de projetos, a denominada Program Evaluation and Review Technique (PERT), apresenta como traço marcante","a":"o foco na redução de custo do projeto, com revisão dos insumos aplicados, objetivando a melhoria da relação custo- benefício.","b":"uma técnica de revisão das etapas do projeto e redução de escopo de forma a diminuir significativamente sua duração.","c":"a identificação dos pontos críticos do projeto, estabelecendo uma estratégia de enfrentamento a partir do pior cenário identificado.","d":"a avaliação do tempo de duração das atividades do projeto de acordo com a média ponderada de estimativas otimista, pessimista e realista.","e":"o foco na qualidade do produto ou serviço oriundo do projeto, sem preocupação com tempo de duração e custos envolvidos.","gabarito":"D","materia":"Gerenciamento de custos","tema":"","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085158","enunciado":"No que concerne ao tema de gestão de riscos, os conceitos correntes na literatura sobre o tema, incluída a mais recente","a":"abordagem feita pela norma técnica ABNT NBR ISO 31000 - Gestão de Risco, definem avaliação de riscos como adoção de medidas corretivas para neutralizar ou mitigar eventos que possam impactar os resultados da organização.","b":"elemento que, individualmente ou combinado, tem o potencial intrínseco para dar origem ao risco.","c":"processo de comparar os resultados da análise de riscos com os critérios de risco para determinar se o risco e/ou sua magnitude é aceitável ou tolerável.","d":"conjunto de medidas preventivas para evitar ou reduzir a ocorrência de eventos que possam ensejar riscos à organização.","e":"processo de tomada de decisão, exclusivo da alta direção da organização, com base no qual são assumidos alguns riscos inerentes ao negócio.","gabarito":"C","materia":"Gerência de Projetos","tema":"Áreas de conhecimento ,Gerenciamento dos riscos","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085157","enunciado":"O sistema de compliance de uma organização é informado pelos princípios de governança corporativa, entre os quais se insere a equidade, que, nesse contexto, pode ser definida como","a":"o tratamento justo e isonômico de todos os sócios e demais partes interessadas, levando em consideração seus direitos, deveres, necessidades, interesses e expectativas.","b":"o conjunto de todas as informações cuja divulgação seja do interesse da sociedade, e não apenas aquelas impostas por disposições de leis ou regulamentos.","c":"a responsabilização dos administradores pelos seus atos, com a reparação dos danos causados à companhia e à sociedade.","d":"a mitigação das sanções aplicáveis àqueles que violem leis ou regulamentos, em face de compromissos de assunção de não reincidência e melhoria dos controles internos.","e":"o ponto de equilíbrio entre o retorno esperado pelos acionistas da companhia, que possui o legítimo escopo de obtenção de lucro, e a responsabilidade social da mesma, que pode impactar sua lucratividade. Legislação Federal>","gabarito":"A","materia":"Administração Pública","tema":"Governabilidade, Governança e Accountability ,Governança e governabilidade","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1162","enunciado":"Ano: 2019 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa Considere que um determinado órgão integrante da Administração pública federal pretenda adquirir determinados produtos, mediante procedimento licitatório, priorizando, no processo de compra, critérios e práticas sustentáveis. De acordo com as disposições da Lei n° 8.666/1993 e normatização específica, esse escopo","a":"é de possível atingimento desde que adotada licitação do tipo técnica e preço, pontuando-se os licitantes que apresentarem a melhor solução técnica para o fornecimento aderente às práticas de sustentabilidade fixadas.","b":"somente poderá ser atingido mediante a previsão, no instrumento convocatório, de certificação ambiental dos produtos, como critério de qualificação técnica ou requisito prévio para assinatura do contrato.","c":"poderá ser atingido com a previsão, no instrumento convocatório, de especificações técnicas do objeto do certame adequadas às práticas de sustentabilidade, resguardado o caráter competitivo da licitação.","d":"poderá ser atingido com o mecanismo de equalização das propostas, considerando-se mais vantajosa aquela mais bem classificada em função da combinação de menor preço e menor impacto ambiental.","e":"não é viável, eis que colidente com o caráter de ampla competição do procedimento licitatório, admitindo-se, contudo, a contratação direta, com dispensa de licitação, de cooperativas, microempresas e empresários individuais que adotem práticas sustentáveis de produção, devidamente certificadas. Direito Ambiental>Proteção do Meio Ambiente em Normas Infraconstitucionais ,","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1163","enunciado":"Ano: 2019 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa Entre os instrumentos previstos na Lei federal n° 12.305/2010, que institui a Política Nacional de Resíduos Sólidos, inserem- se os planos de resíduos sólidos, os quais englobam, entre outros, os planos de gerenciamento de recursos sólidos","a":"obrigatórios apenas para os resíduos industriais ou gerados por empreendimentos sujeitos a licenciamento ambiental.","b":"que não são exigíveis para os geradores de resíduos sólidos urbanos, correspondentes aos domiciliares e aos de limpeza urbana.","c":"que constituem instrumento específico para os resíduos hospitalares, contemplando medidas de coleta, descarte e destruição.","d":"também denominados logística reversa, decorrentes de obrigação imposta a produtores de produtos classificados como perigosos.","e":"dirigidos exclusivamente aos entes públicos e concessionárias prestadoras de serviços de saneamento básico e coleta de lixo. Estatuto da Pessoa com Deficiência - Lei nº 13.146 de 2015>Legislação das Pessoas com Deficiência ,","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1164","enunciado":"Ano: 2019 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa Em uma situação hipotética, a Prefeitura de São Paulo realizará evento comemorativo em praça pública para homenagear importante data para a cidade. Para a realização do evento, serão disponibilizados 30 banheiros químicos. Nos termos da Lei n° 10.098/2000, o evento deverá contar com banheiros químicos acessíveis às pessoas com deficiência ou com","a":"mobilidade reduzida em número mínimo de 3","b":"9.","c":"6","d":"1","e":"2. Estatuto da Pessoa com Deficiência - Lei nº 13.146 de 2015>","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1165","enunciado":"Ano: 2019 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa José é pessoa com deficiência e está internado em hospital público para tratamento de determinada doença. Nos termos da Lei n° 13.146/2015, José tem direito","a":"apenas a acompanhante, devendo o órgão ou a instituição de saúde proporcionar condições adequadas para sua permanência por, no máximo, doze horas.","b":"a acompanhante ou a atendente pessoal, devendo o órgão ou a instituição de saúde proporcionar condições adequadas para sua permanência em tempo integral.","c":"a acompanhante ou a atendente pessoal, devendo o órgão ou a instituição de saúde proporcionar condições adequadas para sua permanência por, no máximo, quinze horas.","d":"apenas a atendente pessoal, devendo o órgão ou a instituição de saúde proporcionar condições adequadas para sua permanência por, no máximo, doze horas.","e":"apenas a acompanhante, devendo o órgão ou a instituição de saúde proporcionar condições adequadas para sua permanência por, no máximo, quinze horas.","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085152","enunciado":"Em uma urna há 3 bolas verdes, 3 vermelhas, 3 azuis e 3 amarelas, todas iguais ao tato. São retiradas, ao acaso, 10 bolas","a":"dessa urna. Então, com certeza, 3 bolas de mesma cor foram retiradas.","b":"3 bolas verdes ou 3 bolas vermelhas foram retiradas.","c":"2 bolas de cores distintas ficaram na urna.","d":"3 bolas verdes, 3 bolas vermelhas e 3 bolas azuis foram retiradas.","e":"3 bolas verdes foram retiradas.","gabarito":"A","materia":"Raciocínio Lógico","tema":"Casa dos Pombos","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085151","enunciado":"Ana, Beto e Carlos têm juntos 39 bolas de gude. Se Beto der 5 bolas para Carlos, Carlos der 4 bolas para Ana e Ana der 2","a":"bolas para Beto, os três ficam com a mesma quantidade de bolas. O número de bolas de Beto antes das trocas é 12.","b":"15.","c":"14.","d":"13","e":"16.","gabarito":"E","materia":"Raciocínio Lógico","tema":"Problemas Lógicos","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085150","enunciado":"Um engenheiro introduziu um novo método na fabricação de um produto que reduziu o custo de fabricação em 50%. Um ano depois, outra modificação no processo de fabricação foi feita e reduziu o custo em 15%. Após as duas modificações na","a":"produção, o custo inicial, em porcentagem, foi reduzido em 65,5.","b":"63,5.","c":"47,5.","d":"57,5.","e":"45,5.","gabarito":"D","materia":"Matemática","tema":"Aritmética e Problemas ,Porcentagem","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085149","enunciado":"O número de matriculados nas disciplinas de Cálculo, Estatística e Microeconomia é 150. Sabe-se que 12 deles cursam simultaneamente Microeconomia e Estatística, e que 80 deles cursam somente Cálculo. Os alunos matriculados em Microeconomia não cursam Cálculo. Se a turma de Cálculo tem 96 alunos e a de Estatística, 35, o número de alunos na","a":"turma de Microeconomia é 12.","b":"47.","c":"7.","d":"28.","e":"23.","gabarito":"B","materia":"Raciocínio Lógico","tema":"Problemas Lógicos","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085148","enunciado":"1 Existe uma enfermidade moderna que afeta dois terços dos adultos. Seus sintomas incluem falta de apetite, dificuldade para controlar o peso, baixa imunidade, flutuações de humor, entre outros. Essa enfermidade é a privação de sono crônica, que vem crescendo na esteira de dispositivos que emitem luz azul. 2 Por milênios, a luz azul existiu apenas durante o dia. Velas e lenha produziam luz amarelo-avermelhada e não havia iluminação artificial à noite. A luz do fogo não é problema porque o cérebro interpreta a luz vermelha como sinal de que chegou a hora de dormir. Com a luz azul é diferente: ela sinaliza a chegada da manhã. 3 Assim, um dos responsáveis pelo declínio da qualidade do sono nas duas últimas décadas é a luz azulada que emana de aparelhos eletrônicos; mas um dano ainda maior acontece quando estamos acordados, fazendo um malabarismo obsessivo com computadores e smartphones. 4 A maioria das pessoas passam de uma a quatro horas diárias em seus dispositivos eletrônicos - e muitos gastam bem mais que isso. Não é problema de uma minoria. Pesquisadores nos aconselham a usar o celular por menos de uma hora diariamente. Mas o uso excessivo do aparelho é tão predominante que os pesquisadores cunharam o termo“nomofobia\" (uma abreviatura da expressão inglesa no-mobile-phobiaj para descrever a fobia de ficar sem celular. 5 O cérebro humano exibe diferentes padrões de atividade para diferentes experiências. Um deles retrata reações cerebrais de um viciado em jogos eletrônicos. “Comportamentos viciantes ativam o centro de recompensa do cérebro\", afirma Claire Gillan, neurocientista que estuda comportamentos obsessivos. “Contanto que a conduta acarrete recompensa, o cérebro a tratará da mesma maneira que uma droga\". (Adaptado de: ALTER, Adam. Irresistível. São Paulo: Objetiva, edição digital) Existe uma enfermidade moderna que afeta dois terços dos adultos. // Essa enfermidade é a privação de sono crônica, que vem crescendo na esteira de dispositivos que emitem luz azul. (1° parágrafo) As frases acima estão reescritas em um único período, com correção e coerência, do seguinte modo:","a":"Afetam dois terços dos adultos a privação de sono crônica, uma enfermidade moderna, que tem crescido na esteira dos dispositivos que emitem luz azul.","b":"Uma enfermidade moderna, à qual afeta dois terços dos adultos, é a privação de sono crônica, que tem crescido na esteira de dispositivos que emitem luz azul.","c":"A enfermidade moderna, que vem afetando dois terços dos adultos e crescendo na esteira de dispositivos dos quais emitem luz azul é a privação de sono crônica.","d":"Tem vindo crescendo junto aos dispositivos que emitem luz azul, a privação de sono crônica: uma enfermidade moderna, que afeta dois terços dos adultos.","e":"A privação de sono crônica, uma enfermidade moderna que vem crescendo na esteira de dispositivos que emitem luz azul, afeta dois terços dos adultos.","gabarito":"E","materia":"Português","tema":"Interpretação de Textos ,Redação - Reescritura de texto","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085147","enunciado":"O cérebro humano exibe diferentes padrões de atividade para diferentes experiências. (5° parágrafo)","a":"Transpondo-se a frase acima para a voz passiva, a forma verbal resultante será: são exibidas","b":"são exibidos","c":"exibe-se","d":"é exibido","e":"exibiam-se","gabarito":"B","materia":"Português","tema":"Interpretação de Textos ,Redação - Reescritura de texto","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085146","enunciado":"","a":"Estabelece relação de referência a uma expressão mencionada anteriormente no texto o termo sublinhado em o cérebro interpreta a luz vermelha como sinal de que chegou a hora de dormir (2° parágrafo)","b":"Não é problema de uma minoria (4° parágrafo)","c":"fazendo um malabarismo obsessivo com computadores e smartphones (3° parágrafo)","d":"Pesquisadores nos aconselham a usar o celular por menos de uma hora diariamente (4° parágrafo)","e":"o cérebro a tratará da mesma maneira que uma droga (5° parágrafo) Português>Interpretação de Textos ,Significação Contextual de Palavras e Expressões. Sinônimos e Antônimos. ,","gabarito":"E","materia":"Português","tema":"Coesão e coerência","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1173","enunciado":"Ano: 2019 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa Sem prejuízo para o sentido, o trecho sublinhado em Contanto que a conduta acarrete recompensa (último parágrafo) pode","a":"ser substituído por Conforme","b":"Desde que","c":"Pois que","d":"Ainda que","e":"Conquanto","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085144","enunciado":"O verbo que pode ser corretamente flexionado em uma forma do singular, sem que nenhuma outra alteração seja feita na","a":"frase, está em: A maioria das pessoas passam de uma a quatro horas diárias em seus dispositivos eletrônicos","b":"Seus sintomas incluem falta de apetite","c":"Velas e lenha produziam luz amarelo-avermelhada","d":"Comportamentos viciantes ativam o centro de recompensa do cérebro","e":"e muitos gastam bem mais que isso","gabarito":"A","materia":"Português","tema":"Sintaxe ,Concordância verbal, Concordância nominal","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085143","enunciado":"","a":"respeito da pontuação do texto, afirma-se corretamente: No trecho Essa enfermidade é a privação de sono crônica, que vem crescendo na esteira de dispositivos que emitem luz azul A (1° parágrafo), uma vírgula pode ser colocada imediatamente após “dispositivos”, sem prejuízo da correção e do","b":"sentido. No trecho - e muitos gastam bem mais que isso (4° parágrafo), o sinal de travessão introduz uma oposição.","c":"No segmento Por milênios, a luz azul existiu apenas durante o dia (2o parágrafo), a vírgula indica mudança de sujeito.","d":"Sem prejuízo da correção, no segmento Com a luz azul é diferente: ela sinaliza a chegada da manhã (2° parágrafo), o sinal de dois-pontos pode ser substituído por pois, precedido de vírgula.","e":"Em Seus sintomas incluem falta de apetite, dificuldade para controlar o peso, baixa imunidade e flutuações de humor (1° parágrafo), as vírgulas isolam um segmento explicativo. Português>Interpretação de Textos ,Sintaxe ,","gabarito":"D","materia":"Português","tema":"Pontuação ,Uso da Vírgula ,Uso dos dois-pontosTravessão","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085142","enunciado":"Ano: 2019 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa Mas o uso excessivo do aparelho é tão predominante que os pesquisadores cunharam o termo “nomofobia\" (uma abreviatura da expressão inglesa no-mobile-phobiaj para descrever a fobia de ficar sem celular. (4° parágrafo)","a":"O trecho sublinhado exprime uma consequência.","b":"oposição.","c":"finalidade.","d":"condição.","e":"causa.","gabarito":"A","materia":"Orações subordinadas adverbiais: Causal","tema":"","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1085141","enunciado":"Considere as afirmações abaixo. I. Critica-se no último parágrafo a dependência psicológica do celular, chamada por especialistas de “nomofobia”, característica de uma minoria que o utiliza de maneira abusiva. II. No texto, associa-se a perda da qualidade do sono ao uso de dispositivos eletrônicos que emitem luz azul. III. O autor expressa sentimento de nostalgia ao enaltecer uma época em que a maior parte da iluminação noturna provinha de luzes amarelo-avermelhadas.","a":"Está correto o que consta APENAS de II e III","b":"I e II.","c":"II.","d":"I","e":"I e III. Direito Previdenciário>Planos de Benefício da Previdência Social - Lei nº 8.213, de 24 de Julho de 1991 ,","gabarito":"C","materia":"Português","tema":"Interpretação de Textos ,Noções Gerais de Compreensão e Interpretação de Texto","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Técnico Judiciário - Administrativa","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1083623","enunciado":"As mini-reformas previdenciárias introduziram diversas alterações para a legislação previdenciária em 2019. Sobre as recentes modificações legais, a pensão por morte para o servidor público será devida ao conjunto dos dependentes do segurado que falecer,","a":"aposentado ou não, a contar da data do óbito, quando requerida em até 120 dias após o óbito, para os filhos menores de 16 anos, ou em até 60 dias após o óbito, para os demais dependentes; a contar do requerimento, quando requerida após o prazo acima previsto ou da decisão judicial, na hipótese de morte presumida. o Instituto Nacional do Seguro Social (INSS) manterá programa permanente de revisão da concessão e da manutenção dos benefícios por ele administrados, a fim de apurar irregularidades ou erros materiais. Na hipótese de haver indícios","b":"de irregularidade ou erros materiais na concessão, na manutenção ou na revisão do benefício, o INSS notificará o beneficiário, o seu representante legal (ou o seu procurador) para apresentar defesa, provas ou documentos dos quais dispuser, no prazo de 45 dias, no caso de trabalhador urbano, e 90 dias, no caso de trabalhador rural individual e avulso, agricultor familiar ou segurado especial.","c":"as provas de união estável e de dependência econômica exigem início de prova material contemporânea dos fatos, produzido em período não superior a 24 meses anterior à data do óbito ou do recolhimento à prisão do segurado, não admitida a prova exclusivamente testemunhal, sem exceção.","d":"o segurado manterá a sua qualidade quando estiver recebendo benefício previdenciário, exceto quando estiver percebendo auxílio-acidente. Sendo assim, para que o segurado mantenha a sua qualidade, deverá contribuir mensalmente para o Regime Geral de Previdência Social. o salário de benefício do segurado que contribuir em razão de atividades concomitantes será calculado com base na","e":"soma integral dos salários de contribuição da atividade principal e proporcionalidade dos salários de contribuição das atividades secundárias exercidas na data do requerimento ou do óbito, ou no período básico de cálculo. Este valor será limitado ao teto previdenciário.","gabarito":"D","materia":"Direito Previdenciário","tema":"Legislação Previdenciária","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1083621","enunciado":"O Código Tributário Nacional define tributo como toda prestação pecuniária compulsória, em moeda ou cujo valor nela se possa exprimir, que não constitua sanção de ato ilícito, instituída em lei e cobrada mediante atividade administrativa plenamente vinculada, dispondo, também,","a":"que a natureza jurídica específica do tributo é determinada pelo fato gerador da respectiva obrigação, sendo que, para qualificá-la, há necessidade de se levar em conta sua denominação e demais características formais previstas em lei, bem como a destinação legal do produto da sua arrecadação.","b":"de forma expressa, que são tributos: o imposto, a taxa, a contribuição de melhoria, as contribuições sociais, a contribuição para o custeio do serviço de iluminação pública, a contribuição sobre movimentação financeira e a tarifa de pedágio.","c":"que as taxas têm como fato gerador o exercício regular do poder de polícia, ou a utilização, efetiva ou potencial, de serviço público específico e divisível, prestado ao contribuinte ou posto à sua disposição.","d":"que a taxa pode ter base de cálculo ou fato gerador idênticos aos que correspondam a imposto, podendo ser calculada em função do capital das empresas.","e":"que somente os Municípios podem instituir contribuição de melhoria para fazer face ao custo de obras públicas de que decorra valorização imobiliária, tendo como limite individual a despesa realizada e como limite total o acréscimo de valor que da obra resultar para cada imóvel beneficiado.","gabarito":"C","materia":"Direito Tributário","tema":"Conceito de Tributo e Espécies Tributárias ,Conceito legal de tributo ,Taxa e Tarifas","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1083620","enunciado":"","a":"relação jurídica tributária tem como sujeito ativo o Estado-fiscal e, como sujeito passivo, o contribuinte ou o responsável, dispondo o Código Tributário Nacional que não é considerado contribuinte, mas, simplesmente, responsável o sujeito passivo que tem relação pessoal e direta A com a situação que constitua o respectivo fato gerador.","b":"o sujeito ativo competente para criar o tributo pode, através de lei, atribuir as funções de arrecadar ou de fiscalizar tributos a outra pessoa jurídica de direito público.","c":"o sujeito ativo da relação jurídica tributária tem o dever de exercer a competência que lhe foi atribuída, dispondo a Constituição Federal que o seu não-exercício autoriza que outro ente federado exerça tal competência tributária.","d":"o sujeito passivo da obrigação principal é a pessoa obrigada às prestações que constituam o seu objeto, prestações essas que não se confundem com o pagamento de tributo ou de penalidade pecuniária.","e":"as convenções entre particulares podem ser utilizadas para modificar a definição legal do sujeito passivo das obrigações tributárias, inclusive para alterar a responsabilidade pelo pagamento de tributos, podendo ser opostas à Fazenda Pública sem necessidade de autorização de lei. Direito Tributário>Legislação do Direito Tributário ,Integração e interpretação da Lei Tributária ,","gabarito":"B","materia":"Direito Tributário","tema":"Obrigação Tributária ,Capacidade, Domicílio e Sujeitos da Obrigação Tributária","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1181","enunciado":"Ano: 2019 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária O Código Tributário Nacional (CTN) traz regras sobre a aplicação e interpretação da lei tributária, dispondo que: I. a legislação tributária é aplicada imediatamente aos fatos geradores futuros e aos pendentes, assim entendidos somente aqueles que se encontram suspensos por medida liminar judicial, decorrente de mandado de segurança ou de outra ação judicial prevista em nossa legislação. II. como o lançamento se reporta à data da ocorrência do fato gerador da obrigação e rege-se pela lei então vigente, a lei tributária nunca pode ser aplicada a ato ou fato pretérito, tendo em vista o princípio constitucional da irretroatividade da lei tributária. III. a lei tributária que define infrações ou lhe comina penalidades é interpretada da maneira mais favorável ao acusado, em caso de dúvida quanto à capitulação legal do fato e à autoria, à imputabilidade ou à punibilidade do acusado, além de outras hipóteses previstas no CTN. IV. interpreta-se literalmente a legislação tributária que disponha sobre suspensão ou exclusão do crédito tributário, sobre outorga de isenção e sobre a dispensa do cumprimento de obrigações tributárias acessórias.","a":"Está correto o que consta APENAS de I e III.","b":"II e IV","c":"I e II.","d":"II, III e IV.","e":"III e IV.","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1083618","enunciado":"Considerando o disposto nos artigos 96 a 100 do Código Tributário Nacional e a hierarquia das normas, as fontes do Direito Tributário podem ser classificadas em fontes primárias e secundárias. Tendo em vista tal classificação, são fontes primárias","a":"do Direito Tributário, dentre outras, as emendas constitucionais, as leis complementares e ordinárias, os decretos-legislativos e os tratados internacionais.","b":"as resoluções do Senado, as portarias, o decreto-regulamentar, as instruções normativas e o costume.","c":"o decreto-lei, os decretos do Executivo, o decreto-legislativo, as portarias e os pareceres normativos.","d":"a emenda constitucional, as leis e os decretos, as instruções normativas e as portarias expedidas pelas autoridades competentes.","e":"os decretos do Executivo que alteram alíquotas e regulamentam tributos, as portarias, as instruções normativas e os pareceres sobre matéria tributária.","gabarito":"A","materia":"Direito Tributário","tema":"Legislação do Direito Tributário ,Conceito de Legislação Tributária","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1083617","enunciado":"O Ministério Público Federal, por intermédio dos Procuradores da República Manoel e Joaquim, ajuizou ação penal contra Ricardo, Rodrigo e Pedro, donos de uma empreiteira com sede na cidade de São Paulo, pelos crimes de tráfico de influência, formação de quadrilha e lavagem de dinheiro. A denúncia foi distribuída para uma das varas da Justiça Federal de São Paulo, com competência criminal, e recebida pelo magistrado federal competente. No curso da ação penal, os advogados de Ricardo, Rodrigo e Pedro apresentaram exceção de suspeição dos Procuradores da República Manoel e Joaquim. Nesse caso, o juiz, depois de ouvir os Procuradores da República, decidirá a exceção,","a":"com possibilidade de recurso em sentido estrito, não cabendo qualquer dilação probatória, devendo a parte que","b":"suscitar o incidente apresentar todas as provas com a petição que instruir o pedido. com possibilidade de recurso em sentido estrito, podendo antes admitir a produção de provas no prazo de três dias.","c":"sem recurso, não cabendo qualquer dilação probatória, devendo a parte que suscitar o incidente apresentar todas as","d":"provas com a petição que instruir o pedido. sem recurso, podendo antes admitir a produção de provas no prazo de três dias.","e":"com possibilidade de recurso em sentido estrito, podendo antes admitir a produção de provas no prazo de 20 dias. Direito Processual Penal>Competência no Processo Penal ,","gabarito":"D","materia":"Direito Processual Penal","tema":"Das Questões e Processos Incidentes ,Suspeição e impedimento","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1184","enunciado":"Ano: 2019 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária Tácito, empresário, residente na cidade de Campo Grande-MS, durante uma fiscalização realizada em sua empresa por um auditor fiscal da receita federal, no mês de novembro de 2018, ofereceu ao referido funcionário público a quantia de R$ 20.000,00 para que sua empresa não fosse autuada após a constatação de sonegação tributária, cometendo, portanto, o crime de corrupção ativa, disposto no artigo 333 do Código Penal. No curso das investigações, Tácito foi eleito no último pleito eleitoral para o cargo de Senador da República. O inquérito policial foi relatado e o Ministério Público Federal deverá oferecer denúncia. Nesse caso hipotético, a competência para processar e julgar a ação penal que será instaurada contra o","a":"atual Senador Tácito será do Supremo Tribunal Federal.","b":"de uma das Varas Federais de Campo Grande-MS, com competência criminal.","c":"do Superior Tribunal de Justiça.","d":"do Tribunal Regional Federal da 3ª Região.","e":"de uma das varas criminais da Justiça Comum Estadual, da comarca de Campo Grande-MS.","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1083614","enunciado":"Mariana e Paula, sócias proprietárias da empresa “X”, estão respondendo processo criminal pelo crime de apropriação indébita previdenciária (artigo 168-A, do Código Penal), pois deixaram de repassar à previdência social as contribuições recolhidas dos contribuintes, no prazo e forma legal. No curso do processo, entendendo que estavam presentes todos os requisitos previstos no Código Penal, o magistrado competente concedeu o perdão judicial e julgou extintas as","a":"punibilidades de Mariana e Paula. Inconformado com a decisão, o Ministério Público poderá interpor recurso em sentido estrito, no prazo de dez dias.","b":"de apelação, no prazo de cinco dias.","c":"em sentido estrito, no prazo de cinco dias.","d":"de apelação, no prazo de dez dias.","e":"de apelação, no prazo de quinze dias.","gabarito":"C","materia":"Direito Processual Penal","tema":"Recursos Criminais ,Recurso em sentido estrito ,Apelação no Processo Penal","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1083613","enunciado":"Miguel e Mauro viajaram para Foz do Iguaçu, no estado do Paraná, e lá atravessaram a Ponte Internacional da Amizade para ingresso no Paraguai, em Ciudad del Este, onde compraram um carregamento de 100 mil pacotes de cigarros, para revender no Brasil, e precisavam retornar ao território nacional com a mercadoria, mas não possuíam autorização para importação. Para tanto, Miguel, que é piloto de aeronave, e Mauro alugaram um avião e realizaram o transporte aéreo da mercadoria do Paraguai para uma fazenda situada no estado do Paraná, próxima a Foz do Iguaçu. No momento em que aterrizaram, e desembarcaram em território nacional, com a mercadoria, Miguel e Mauro foram presos em flagrante pela Polícia Federal. No caso hipotético apresentado, Miguel e Mauro cometeram crime de","a":"descaminho, e estão sujeitos à pena de 01 a 04 anos de reclusão, sem qualquer majoração, pois o descaminho foi praticado em avião clandestino.","b":"descaminho, e estão sujeitos à pena de 01 a 04 anos de reclusão, que deverá ser aplicada em dobro, pois o descaminho foi realizado em transporte aéreo.","c":"contrabando, e estão sujeitos à pena de 02 a 05 anos de reclusão, que deverá ser majorada de 1/3 a metade, pois o contrabando foi realizado em transporte aéreo.","d":"descaminho, e estão sujeitos à pena de 01 a 04 anos de reclusão, que deverá ser majorada de 1/3 a metade, pois o descaminho foi realizado em transporte aéreo.","e":"contrabando, e estão sujeitos à pena de 02 a 05 anos de reclusão, que deverá ser aplicada em dobro, pois o contrabando foi realizado em transporte aéreo.","gabarito":"E","materia":"Direito Penal","tema":"Crimes contra a administração pública ,Contrabando ,Descaminho","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1083612","enunciado":"Considere as seguintes situações hipotéticas de crimes de furto e roubo: I. Paulo, durante o período noturno, ingressou no quarto do seu pai, João, de 70 anos de idade, e subtraiu a quantia de R$ 3.000,00 em dinheiro que estava ocultada no guarda-roupas. II. Mariano, policial militar, apontou a arma de fogo para a esposa Rita, com quem é regularmente casado e convive na mesma residência, e subtraiu diversas joias em ouro pertencentes a ela, fugindo em seguida. III. Os irmãos Michael e Josué estavam em uma festa na cidade de São Paulo, que acontecia em uma casa noturna. No curso da festa, Michael saiu da casa noturna e furtou o veículo de propriedade de Josué, entregando o bem para um comparsa, retornando para a festa logo em seguida. IV. Davi, em comparsaria com Felício, praticou furto noturno, mediante arrombamento, contra o estabelecimento comercial de propriedade de Rodolfo, filho legítimo de Davi. De acordo com o Código Penal, o Ministério Público poderá ajuizar ação penal pública incondicionada, e postular a","a":"aplicação das sanções previstas, contra Mariano Paulo, Davi e Felício.","b":"Michael e Davi.","c":"Paulo e Michael.","d":"Paulo e Felício.","e":"Michael e Felício.","gabarito":"D","materia":"Direito Penal","tema":"Crimes contra o patrimônio ,Furto ,Roubo","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1083611","enunciado":"Ricardo e Mauro, donos de uma madeireira no estado de Goiás, cortaram árvores e promoveram incêndios criminosos na floresta do Parque Nacional da Chapada dos Veadeiros, e foram presos em flagrante pela polícia, seguindo-se o indiciamento pelos crimes dos artigos 39 (Cortar árvores em floresta considerada de preservação permanente, sem permissão da autoridade competente) e 41 (Provocar incêndio em mata ou floresta), ambos da Lei n° 9.605/1998. Para os","a":"fatos imputados a Ricardo e Mauro, se os crimes foram cometidos durante a noite, a pena é aumentada de um sexto a um terço.","b":"a pena é aumentada em até um sexto.","c":"a pena é aumentada até a metade.","d":"não haverá qualquer aumento na pena prevista para os dois tipos penais.","e":"a pena de detenção será substituída pela de reclusão, com majoração de um a dois terços.","gabarito":"A","materia":"Direito Ambiental","tema":"Responsabilidade ambiental ,Lei de Crimes Ambientais - Lei nº 9.605 de 1998","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1083609","enunciado":"Em ação de obrigação de fazer movida pela União contra Francisco, o juiz proferiu sentença acolhendo o pedido e deferindo, no mesmo ato, a antecipação dos efeitos da tutela, para que o réu desse cumprimento à obrigação no prazo de dez dias, sob pena de multa diária. O réu então interpôs, tempestivamente, embargos de declaração, arguindo omissão da sentença acerca da ocorrência de prescrição, matéria que até então não fora suscitada no processo. Nesse caso, os embargos declaratórios","a":"não são cabíveis, pois não poderia haver omissão quanto a matéria que nem mesmo fora invocada pelas partes; ainda assim, a mera interposição dos embargos suspende o prazo para a interposição do recurso de apelação, bem como a eficácia da sentença embargada.","b":"não são cabíveis, pois não poderia haver omissão quanto a matéria que nem mesmo fora invocada pelas partes; ainda assim, a mera interposição dos embargos interrompe o prazo para a interposição do recurso de apelação, mas não suspende a eficácia da sentença embargada.","c":"são cabíveis, pois a prescrição é matéria sobre a qual o juiz deve se pronunciar de ofício; ademais, a mera interposição dos embargos interrompe o prazo para a interposição do recurso de apelação, mas não suspende a eficácia da sentença embargada.","d":"são cabíveis, pois a prescrição é matéria sobre a qual o juiz deve se pronunciar de ofício; ademais, a mera interposição dos embargos suspende o prazo para a interposição do recurso de apelação, mas não a eficácia da sentença embargada.","e":"são cabíveis, pois a prescrição é matéria sobre a qual o juiz deve se pronunciar de ofício; ademais, a mera interposição dos embargos interrompe o prazo para a interposição do recurso de apelação, além de suspender a eficácia da sentença embargada.","gabarito":"C","materia":"Direito Processual Civil - Novo Código de Processo Civil - CPC 2015","tema":"Recursos ,Embargos de Declaração","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1083608","enunciado":"Considere as seguintes proposições acerca das nulidades: I. Se a parte interessada na declaração da nulidade deixar de alegá-la na primeira oportunidade em que lhe couber falar nos autos, ocorrerá a preclusão, ainda que se trate de nulidade que o juiz deva decretar de ofício. II. Se o processo tiver tramitado sem conhecimento do membro do Ministério Público, em feito no qual devesse intervir, o juiz deverá decretar a invalidade dos atos praticados a partir do momento em que ele deveria ter sido intimado; entretanto, a nulidade só pode ser decretada após a intimação do Ministério Público, que se manifestará sobre a existência ou a inexistência de prejuízo. III. A decretação da nulidade por descumprimento da forma prevista em lei poderá ser requerida pela parte que lhe deu causa, mas ela responderá pelas custas do retardamento do processo, além de incorrer nas sanções previstas para a litigância de má-fé. IV. Nos casos em que puder decidir o mérito a favor da parte a quem aproveite a decretação da nulidade, o juiz não deverá pronunciá-la nem mandará repetir o ato ou suprir-lhe a falta. V. Quando a lei prescrever determinada forma, o juiz considerará válido o ato se, realizado de outro modo, lhe alcançar a finalidade, desde que haja a concordância de todas as partes.","a":"De acordo com o Código de Processo Civil, está correto o que consta APENAS de I e II.","b":"I e III.","c":"II e IV.","d":"III e V.","e":"IV e V. Direito Processual Civil - Novo Código de Processo Civil - CPC 2015>Intervenção de Terceiro ,","gabarito":"C","materia":"Direito Processual Civil - Novo Código de Processo Civil - CPC 2015","tema":"Da Nulidade dos Atos Processuais","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1191","enunciado":"Ano: 2019 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária Renato ajuizou ação de cobrança contra ZWXY Construções Ltda., requerendo, na própria petição inicial, a desconsideração da sua personalidade jurídica, com a demonstração preliminar do preenchimento dos pressupostos legais específicos. Nesse caso, de acordo com o Código de Processo Civil,","a":"deverá ser determinada a instauração do incidente de desconsideração da personalidade jurídica, com a suspensão do processo.","b":"deverá ser determinada a instauração do incidente de desconsideração da personalidade jurídica, sem a suspensão do processo.","c":"dispensa-se a instauração do incidente de desconsideração da personalidade jurídica, mas o processo deverá","d":"permanecer suspenso até a decisão desse requerimento. dispensa-se a instauração do incidente de desconsideração da personalidade jurídica e o processo não será suspenso.","e":"o requerimento deverá ser liminarmente rejeitado, pois o incidente de desconsideração da personalidade jurídica só pode ser instaurado na fase de cumprimento de sentença. Direito Processual Civil - Novo Código de Processo Civil - CPC 2015>Competência no Processo Civil ,","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1192","enunciado":"Ano: 2019 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária Determinada autarquia federal moveu contra uma mesma associação privada duas ações distintas, com pedidos e causas de pedir diversos uma da outra, mas ambas versando sobre o mesmo bem. Os processos das ações foram distribuídos a diferentes Varas da Justiça Federal. Nesse caso,","a":"existe conexão entre os processos, que deverão ser reunidos para julgamento conjunto, ainda que um deles já tenha sido sentenciado.","b":"existe conexão entre os processos, que deverão ser reunidos para julgamento conjunto, salvo se algum deles tiver sido sentenciado.","c":"existe conexão entre os processos, mas nenhum deles poderá ser reunido ao outro, dado que distribuídos a juízos distintos.","d":"não existe conexão entre os processos, mas eles deverão ser reunidos para julgamento conjunto, caso exista o risco de prolação de decisões conflitantes ou contraditórias, salvo se um deles já houver sido sentenciado.","e":"como não existe conexão entre os processos, eles não poderão ser reunidos para julgamento conjunto em nenhuma hipótese. Direito Processual Civil - Novo Código de Processo Civil - CPC 2015>Competência no Processo Civil ,","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1193","enunciado":"Ano: 2019 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária XYZ Indústria Farmacêutica S.A. ajuizou, perante a Justiça Comum, pedido de recuperação judicial, cujo processamento foi deferido pelo juiz. No curso do processo, a União compareceu nos autos informando ter interesse no feito, por ter contratado a recuperanda para o fornecimento de medicamentos em âmbito nacional, cuja interrupção comprometeria o sistema de saúde do país. Nesse caso, o processo deverá","a":"ser remetido à Justiça Federal, desde que tenha havido requerimento da União nesse sentido; no entanto, caso o Juízo Federal não vislumbre interesse jurídico da União, deverá devolver o processo à Justiça Comum.","b":"ser remetido à Justiça Federal, desde que tenha havido requerimento da União nesse sentido; no entanto, caso o Juízo Federal não vislumbre interesse jurídico da União, deverá suscitar conflito de competência.","c":"ser remetido à Justiça Federal, independentemente de requerimento da União nesse sentido; no entanto, caso o Juízo Federal não vislumbre interesse jurídico da União, deverá devolver o processo à Justiça Comum.","d":"ser remetido à Justiça Federal, independentemente de requerimento da União nesse sentido; no entanto, caso o Juízo Federal não vislumbre interesse jurídico da União, deverá suscitar conflito de competência.","e":"permanecer tramitando na Justiça Comum, ainda que a União tenha expressamente requerido sua remessa à Justiça Federal.","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1083604","enunciado":"","a":"Insere-se na competência originária do Superior Tribunal de Justiça processar e julgar o recurso especial interposto contra acórdão dos tribunais regionais federais.","b":"os conflitos entre a União e os Estados, a União e o Distrito Federal, ou entre uns e outros.","c":"a ação em que todos os membros da magistratura sejam direta ou indiretamente interessados.","d":"o mandado de injunção, quando a elaboração da norma regulamentadora for atribuição de outro tribunal superior,","e":"com exceção do Supremo Tribunal Federal. os pedidos de homologação de sentença estrangeira.","gabarito":"E","materia":"Direito Constitucional","tema":"Superior Tribunal de Justiça ,Organização do Poder Judiciário","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1083603","enunciado":"Fernanda e Joaquim celebraram transação a respeito de litígio que já havia sido decidido por sentença passada em julgado.","a":"Nesse caso, a transação é nula, se algum dos transatores não tinha ciência dessa sentença.","b":"nula, desde que ambos os transatores não tivessem ciência dessa sentença.","c":"anulável, no prazo decadencial de quatro anos, por iniciativa de qualquer dos transatores que não tivesse ciência","d":"dessa sentença. válida, ainda que os transatores não tivessem ciência dessa sentença.","e":"nula, mesmo que ambos os transatores tivessem ciência dessa sentença. Direito Civil>Contratos em Geral ,Constituição da Relação Contratual - sujeitos, forma e objeto ,","gabarito":"A","materia":"Direito Civil","tema":"Transação e Compromisso","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1196","enunciado":"Ano: 2019 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária Considere as seguintes proposições acerca dos contratos: I. Nos contratos de adesão, serão válidas as cláusulas que estipulem a renúncia antecipada do aderente a direito resultante da natureza do negócio, desde que redigidas de forma clara e com destaque. II. É vedado, em qualquer hipótese, celebrar contrato que tenha por objeto a herança de pessoa viva. III. Considera-se celebrado o contrato no lugar em que foi aceito, se diverso daquele onde foi proposto. IV. Se o contrato for aleatório, por se referir a coisas existentes, mas expostas a risco, assumido pelo adquirente, o alienante terá direito a todo o preço mesmo que a coisa já não existisse no dia do contrato. V. O contrato preliminar deve conter, inclusive quanto à forma, todos os requisitos essenciais ao contrato a ser celebrado.","a":"De acordo com o Código Civil, está correto o que consta APENAS de I e II.","b":"I e III.","c":"II e IV.","d":"III e V.","e":"IV e V.","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1083601","enunciado":"Luciano, empregado de XPTO Carretos e Mudanças Ltda., dirigia o caminhão da empresa, a fim de realizar a mudança de determinado cliente, quando, por imperícia e imprudência, atropelou Renata, que sofreu, por conta do acidente, lesões","a":"corporais graves. Nesse caso, de acordo com o Código Civil, a empresa XPTO responde subsidiariamente a Luciano pelos danos causados a Renata, somente se tiver procedido com culpa in eligendo.","b":"subsidiariamente a Luciano pelos danos causados a Renata, independentemente de culpa.","c":"solidariamente com Luciano pelos danos causados a Renata, somente se tiver procedido com culpa in eligendo.","d":"solidariamente com Luciano pelos danos causados a Renata, independentemente de culpa.","e":"solidariamente com Luciano pelos danos materiais causados a Renata, mas subsidiariamente a ele pelos danos morais, independentemente de culpa em qualquer dos casos.","gabarito":"D","materia":"Direito Civil","tema":"Responsabilidade civil ,Modalidades da Responsabilidade Civil","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1083600","enunciado":"","a":"De acordo com o Código Civil, o penhor constitui-se pelo contrato, independentemente da efetiva transferência da posse da coisa dada em garantia.","b":"não pode ser parcialmente remido pelos sucessores do devedor na proporção dos seus quinhões, mas qualquer deles","c":"pode fazê-lo no todo. dispensa qualquer tipo de registro.","d":"não se extingue pelo perecimento da coisa empenhada por culpa do devedor.","e":"agrícola que recai sobre colheita pendente não abrange a imediatamente seguinte, mesmo no caso de frustrar-se ou ser insuficiente a que se deu em garantia.","gabarito":"B","materia":"Direito Civil","tema":"Direito das Coisas / Direitos Reais ,Direitos Reais de Garantia - Penhor, Anticrese e Hipoteca","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1083599","enunciado":"Ricardo, maior de 16 anos, não consegue, por causa permanente, exprimir sua vontade. Nesse caso, de acordo com o","a":"Código Civil, Ricardo é absolutamente incapaz de exercer pessoalmente os atos da vida civil, não correndo contra ele a prescrição.","b":"é absolutamente incapaz de exercer pessoalmente os atos da vida civil, mas contra ele corre a prescrição.","c":"é incapaz, relativamente a certos atos ou à maneira de os exercer, não correndo contra ele a prescrição.","d":"é incapaz, relativamente a certos atos ou à maneira de os exercer, mas contra ele corre a prescrição.","e":"não é incapaz, absoluta ou relativamente, mas contra ele não corre a prescrição.","gabarito":"D","materia":"Direito Civil","tema":"Personalidade, Pessoa Natural e Capacidade ,Parte Geral","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1083598","enunciado":"Na celebração de contrato de compra e venda, vendedor e comprador procederam com dolo, que foi a causa do negócio. Nesse caso, de acordo com o Código Civil,","a":"qualquer das partes poderá invocar o dolo da outra para anular o negócio, mas nenhuma delas poderá reclamar","b":"indenização. qualquer das partes poderá invocar o dolo da outra para anular o negócio, ou reclamar indenização.","c":"nenhuma das partes poderá invocar o dolo da outra para anular o negócio, ou reclamar indenização.","d":"qualquer das partes poderá invocar o dolo da outra para reclamar indenização, mas não para anular o negócio.","e":"somente a parte mais prejudicada poderá invocar o dolo da outra para anular o negócio, ou reclamar indenização.","gabarito":"C","materia":"Direito Civil","tema":"Defeitos do Negócio Jurídico ,Parte Geral","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1083597","enunciado":"Determinada Defensoria Pública estadual ajuizou ação civil pública, visando compelir Município localizado no Estado em que atua a manter em funcionamento creches e escolas da rede municipal de forma ininterrupta, sob o fundamento de inconstitucionalidade de lei municipal que autorizaria a suspensão de seu funcionamento durante períodos de férias escolares. À luz da disciplina normativa pertinente e da jurisprudência do Supremo Tribunal Federal na matéria,","a":"a Defensoria Pública estaria legitimada em tese para a propositura de ação civil pública, embora, no caso, a ação não seja cabível, por ter por objeto o controle de constitucionalidade de lei municipal em abstrato.","b":"a Defensoria Pública estaria legitimada em tese para a propositura de ação civil pública, embora, no caso, a ação não seja cabível, por não ser possível demonstrar que os titulares dos direitos difusos tutelados sejam pessoas necessitadas.","c":"a Defensoria Pública está legitimada para a propositura da referida ação civil pública, que tem por objeto a tutela de direitos difusos de que são titulares, em tese, pessoas necessitadas, sendo admissível o controle de constitucionalidade de lei nesta sede, em caráter incidental.","d":"o Ministério Público, e não a Defensoria Pública, estaria legitimado para a propositura de ação civil pública tendo por objeto a tutela de direitos difusos, embora seja admissível o controle de constitucionalidade de lei nesta sede, em caráter incidental.","e":"o Ministério Público, e não a Defensoria Pública, estaria legitimado para a propositura de ação civil pública visando à tutela de direitos difusos, ademais de, no caso, a ação não ser cabível, por ter por objeto o controle de constitucionalidade de lei municipal em abstrato. Direito Constitucional>Controle de Constitucionalidade ,","gabarito":"C","materia":"Legislação Federal","tema":"Lei Nº 7.347 de 1985 - Disciplina a Ação Civil Pública","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1202","enunciado":"Ano: 2019 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária Determinada empresa ajuizou ação visando à anulação de penalidade que lhe havia sido imposta por órgão da Administração federal, sob a alegação de que a lei em que prevista resultara de projeto que, após aprovado com alterações substanciais pela Casa legislativa revisora, teria seguido diretamente à sanção presidencial, sem antes retornar à Casa inicial, razão pela qual seria formalmente inconstitucional. A ação foi julgada procedente em primeira instância, com fundamento na inconstitucionalidade da lei em que prevista a penalidade. Tendo sido interposto recurso, o processo aguarda julgamento por órgão fracionário do Tribunal Regional Federal (TRF) respectivo. Nessa hipótese, diante da Constituição Federal de 1988 e da jurisprudência do Supremo Tribunal Federal (STF),","a":"embora tenha havido irregularidade no trâmite do projeto legislativo, não compete aos órgãos judiciais declarar em caráter incidental a inconstitucionalidade formal da lei, o que somente se admite em sede de controle concentrado, exercido por meio de ação direta de competência originária do STF.","b":"houve, de fato, irregularidade no trâmite do projeto de lei, possuindo os órgãos judiciais competência para reconhecer incidentalmente a inconstitucionalidade da lei, embora no âmbito do TRF a declaração respectiva dependa de decisão da maioria absoluta dos membros do Tribunal ou de seu órgão especial.","c":"embora tenha havido irregularidade no trâmite do projeto legislativo, a sanção presidencial teria o condão de convalidá-la, não havendo que se falar por esse motivo em inconstitucionalidade da lei, possuindo o TRF competência para reconhecer sua constitucionalidade por meio de órgão fracionário.","d":"embora tenha havido irregularidade no trâmite do projeto legislativo, a sanção presidencial teria o condão de convalidá-la, não havendo que se falar por esse motivo em inconstitucionalidade da lei, possuindo o TRF competência para reconhecer sua constitucionalidade, desde que observada a cláusula de reserva de plenário.","e":"houve, de fato, irregularidade no trâmite do projeto de lei, possuindo os órgãos judiciais competência para afastar a aplicação da lei ao caso concreto, inclusive órgão fracionário do TRF, desde que não declare sua inconstitucionalidade.","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1083594","enunciado":"No exercício de sua função de fiscalização financeira, contábil e orçamentária, a Assembleia Legislativa de determinado Estado da federação apurou que, contrariamente ao informado pelo Executivo, em prestação de contas, o Estado teria deixado de observar o percentual mínimo exigido na aplicação de recursos em ações e serviços públicos de saúde. Políticos de oposição ao governo estadual alegam haver no caso razões para intervenção da União no referido Estado. Nessa hipótese, à luz da disciplina constitucional da matéria, a decretação da intervenção é, em tese,","a":"cabível, e dependerá de provimento, pelo Supremo Tribunal Federal, de representação do Procurador-Geral da","b":"República. cabível, e dependerá de solicitação do Poder Legislativo do referido Estado ao Presidente da República.","c":"cabível, e dependerá de requisição do Poder Judiciário do referido Estado ao Presidente da República.","d":"cabível, devendo o decreto ser submetido à apreciação da Assembleia Legislativa no prazo de 24 horas, salvo se a suspensão do ato impugnado bastar ao restabelecimento da normalidade.","e":"descabida, uma vez que, embora o Estado não tenha observado a aplicação do mínimo exigido da receita estadual nas ações e serviços públicos de saúde, essa hipótese não enseja a decretação de intervenção federal.","gabarito":"A","materia":"Direito Constitucional","tema":"Intervenção Federal e Estadual ,Organização Político-Administrativa do Estado","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1083593","enunciado":"Considere que, em sede de primeira instância, tenha sido proferida sentença por juiz federal julgando procedente ação em que o autor, pessoa jurídica de direito privado, pretendia eximir-se do cumprimento de determinada obrigação legal, sob o fundamento de inconstitucionalidade da lei federal que a impunha. Enquanto pendente de julgamento recurso perante o Tribunal Regional Federal (TRF) competente, foi publicada súmula vinculante do Supremo Tribunal Federal (STF) sobre a matéria, afirmando ser constitucional a exigência constante da referida lei, sem ressalvas quanto à produção de efeitos ou à eficácia do enunciado respectivo. Nessa hipótese, à luz da disciplina normativa pertinente e da jurisprudência do STF, ao julgar o recurso, o TRF","a":"deverá decidir em conformidade com o teor da súmula vinculante, aplicando-a ao caso, sendo dado ao autor da ação ajuizar reclamação perante o STF, para cassação da decisão de segunda instância, caso pretenda restabelecer a sentença.","b":"não estará obrigado a decidir em conformidade com o teor da súmula vinculante, uma vez que a sentença foi proferida em primeira instância antes de a súmula ter sido editada e publicada.","c":"estará legitimado a propor a revisão da súmula vinculante ao STF, o que autoriza a suspensão do processo pendente de julgamento em segunda instância, até decisão final do STF sobre a revisão do enunciado.","d":"deverá decidir em conformidade com o teor da súmula vinculante, aplicando-a ao caso, não sendo cabível ao autor da ação, diante da aplicação devida da súmula, interpor recurso extraordinário, reclamação ou proposta de revisão do enunciado perante o STF.","e":"deverá decidir em conformidade com o teor da súmula vinculante, aplicando-a ao caso, sendo dado ao autor da ação interpor recurso extraordinário, para reforma da decisão de segunda instância, caso pretenda restabelecer a sentença, presumida a repercussão geral.","gabarito":"D","materia":"Direito Constitucional","tema":"Controle de Constitucionalidade ,Súmula Vinculante","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1083591","enunciado":"Abílio Silva foi empossado em cargo público efetivo e praticou diversos atos administrativos no exercício de tal cargo. Todavia, o concurso que gerou o provimento do cargo foi anulado, sem que ele tenha contribuído para a nulidade. Nessa","a":"situação, os atos praticados por ele são válidos, visto que atuou como funcionário de fato.","b":"nulos, pois praticados com usurpação de poder.","c":"anuláveis, pois praticados com vício de motivo.","d":"irregulares, por desvio de finalidade.","e":"inexistentes, pois praticados com objeto juridicamente impossível.","gabarito":"A","materia":"Direito Administrativo","tema":"Atos administrativos ,Existência, Validade e Eficácia do Ato Administrativo","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1083590","enunciado":"","a":"Lei n° 11.416/2006 dispõe sobre as Carreiras dos Servidores do Poder Judiciário da União e estatui o seguinte: A promoção é a movimentação do servidor de um padrão para o seguinte dentro de uma mesma classe, observado o A interstício de um ano, sob os critérios fixados em regulamento e de acordo com o resultado de avaliação formal de desempenho. A progressão funcional é a movimentação do servidor do último padrão de uma classe para o primeiro padrão da","b":"classe seguinte, observado o interstício de um ano em relação à progressão funcional imediatamente anterior, dependendo, cumulativamente, do resultado de avaliação formal de desempenho e da participação em curso de aperfeiçoamento oferecido, preferencialmente, pelo órgão, na forma prevista em regulamento.","c":"Os órgãos do Poder Judiciário da União fixarão em ato próprio a lotação dos cargos efetivos, das funções comissionadas e dos cargos em comissão nas unidades componentes de sua estrutura, admitida a transformação, sem aumento de despesa, de função comissionada em cargo em comissão ou vice-versa.","d":"70%, pelo menos, dos cargos em comissão nos Quadros de Pessoal dos órgãos do Poder Judiciário serão destinados a servidores efetivos integrantes de seu quadro de pessoal, na forma prevista em regulamento.","e":"É vedada a percepção da Gratificação de Atividade Externa pelo servidor designado para o exercício de função comissionada ou nomeado para cargo em comissão. Direito Administrativo>Lei nº 8.112-1990 - Regime jurídico dos servidores públicos federais ,","gabarito":"E","materia":"Legislação dos TRFs","tema":"Lei nº 11.416-2006 - Carreiras dos Servidores do Poder Judiciário da União","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1207","enunciado":"Ano: 2019 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária Nos termos da Constituição Federal de 1988 e da legislação aplicável, o regime jurídico das sociedades de economia mista confere a essas entidades","a":"a dispensa de realizar licitações quando se tratar da comercialização, prestação ou execução, de forma direta, de produtos, serviços ou obras especificamente relacionados com seus respectivos objetos sociais.","b":"o privilégio processual de prazo em dobro para todas as suas manifestações processuais, cuja contagem terá início a partir da intimação pessoal.","c":"a prerrogativa de pleitear ao presidente do tribunal ao qual couber o conhecimento do respectivo recurso a suspensão da execução da liminar ou de sentença, de modo a evitar grave lesão à ordem, à saúde, à segurança e à","d":"economia públicas. a obrigação de sempre observar o teto remuneratório constitucional na remuneração de seus agentes.","e":"a sujeição ao regime de pagamento de suas dívidas por precatório, nos termos do art. 100 da Constituição Federal, independentemente da natureza de suas atividades.","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1083586","enunciado":"No tocante à delegação e avocação de competências administrativas, a Lei Federal de Processo Administrativo - Lei n° 9.784/1999, quanto ao uso de tais mecanismos na modalidade vertical (observando a linha hierárquica) ou na modalidade","a":"horizontal (sem observar a linha hierárquica), admite a avocação e a delegação em ambas as modalidades.","b":"avocação em ambas as modalidades, mas a delegação apenas na modalidade vertical.","c":"delegação em ambas as modalidades, mas a avocação apenas na modalidade vertical.","d":"delegação apenas na modalidade vertical e a avocação apenas na modalidade horizontal.","e":"delegação em ambas as modalidades, mas a avocação apenas na modalidade horizontal.","gabarito":"C","materia":"Direito Administrativo","tema":"Processo Administrativo - Lei nº 9.784 de 1999 e Lei nº 14.210 de 2021","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1083585","enunciado":"Atenção: A questão corresponde à Gestão Pública. Suponha que determinada entidade pública tenha contratado uma consultoria especializada, objetivando a implementação de metodologia Balanced Scorecard (BSC), a fim de obter melhorias em sua atuação. Na fase inicial dos trabalhos, a","a":"consultoria envolveu todos os servidores e gestores públicos para estabelecer a missão da entidade, o que significa identificar as crenças, normas e padrões estabelecidos, formadores da cultura vigente na organização.","b":"fixar as metas a serem perseguidas pela entidade, no curto, médio e longo prazo.","c":"estabelecer um consenso entre os membros da organização sobre o futuro que se deseja para a mesma.","d":"prospectar os cenários potenciais para a atuação da organização, identificando oportunidades e ameaças.","e":"identificar, com clareza, a razão de ser da entidade, ou seja, seu propósito fundamental.","gabarito":"E","materia":"Administração Geral","tema":"Gestão Estratégica ,Missão, Visão e Negócio","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1083584","enunciado":"Considere a seguinte afirmação sobre a implementação, no setor público, da metodologia de gestão por competências, amplamente aplicada no setor privado: “A etapa de mapeamento de competências, própria de tal metodologia, é inviável para o poder público por várias razões, especialmente em função do mandamento constitucional de contratação mediante concurso público, salvo para os cargos de livre provimento”. À luz do conteúdo dessa etapa, tal assertiva afigura-se","a":"equivocada, eis que o mapeamento por competências é uma etapa posterior à contratação de pessoal, ligada única e exclusivamente à remuneração por resultados, o que pode ser implementado, ainda que parcialmente, em carreiras públicas, nos termos da lei.","b":"correta, eis que o mapeamento de competências consiste na prospecção dos melhores talentos disponíveis no mercado, o que em nada se aproveita na sistemática de concurso público para seleção e provimento de cargos efetivos, que pressupõe a ampla competição.","c":"parcialmente correta, eis que o mapeamento de competências, embora não atrelado a requisitos necessários ou desejáveis para o provimento dos cargos da organização, é mandatório para o sistema de promoção dos seus integrantes, o que não se coaduna com o regime público de promoções por merecimento e antiguidade.","d":"equivocada, eis que o mapeamento nada mais é do que a identificação da lacuna existente entre as competências requeridas pelos cargos e aquelas efetivamente disponíveis na organização, o que pode ser levado em conta na elaboração do conteúdo de concursos públicos, observadas as atribuições legais dos cargos.","e":"correta, pois o mapeamento de competências destina-se ao provimento apenas de posições da alta direção das organizações, o que, no setor público, se dá pela escolha e nomeação de agentes políticos, como Ministros e Secretários de Estado, e não pela sistemática de seleção de talentos.","gabarito":"D","materia":"Gestão de Pessoas","tema":"Gestão de Competências","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1083583","enunciado":"","a":"O conceito de gestão de riscos atrelado às boas práticas de governança corporativa contempla o monitoramento, avaliação e classificação exclusivamente dos riscos de imagem e de integridade.","b":"a identificação das incertezas nos processos da organização, a medição da probabilidade de danos e seus possíveis impactos.","c":"apenas medidas de identificação e classificação dos riscos, cabendo ao sistema de compliance as medidas de","d":"mitigação. medidas de mitigação de riscos, aplicáveis apenas àqueles riscos classificados como gerenciáveis.","e":"a eliminação dos riscos aos quais a organização está exposta, salvo os riscos legais, que são tratados no bojo do programa de conformidade.","gabarito":"B","materia":"Administração Pública","tema":"Governabilidade, Governança e Accountability","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1083582","enunciado":"De acordo com as publicações mais reconhecidas sobre o tema, como o Código de Melhores Práticas de Governança Corporativa publicado pelo Instituto Brasileiro de Governança Corporativa (IBGC), os princípios básicos de governança corporativa relacionam-se diretamente com a identidade da organização, influenciando a deliberação ética e norteando a atuação dos agentes de governança e o funcionamento do sistema de compliance. Um desses princípios básicos é a accountability, que significa:","a":"a prestação de contas, pelos agentes da governança, de sua atuação de modo claro, conciso, compreensível e tempestivo, assumindo integralmente as consequências de seus atos e omissões.","b":"ter como objetivo precípuo o melhor uso dos insumos na produção de bens e serviços, com a busca constante de aperfeiçoamento da entidade e de seus colaboradores.","c":"a elaboração das demonstrações financeiras e dos demais documentos contábeis e registros patrimoniais com a observância das normas técnicas e das boas práticas internacionais.","d":"a obrigação de reduzir as externalidades negativas e gerenciar os fatores de risco, buscando a sustentabilidade econômico-financeira da entidade, no curto, médio e longo prazo.","e":"responsabilidade social, que deve ser colocada acima do lucro aos acionistas, e ambiental, com a busca da sustentabilidade e perenidade da organização, em face da sua missão atual e com as futuras gerações. Direito Ambiental>Proteção do Meio Ambiente em Normas Infraconstitucionais ,","gabarito":"A","materia":"Administração Pública","tema":"Governabilidade, Governança e Accountability","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1083580","enunciado":"O conceito de desenvolvimento sustentável, tal como tratado no Relatório Brundtland, elaborado pela Comissão Mundial sobre o Meio Ambiente e Desenvolvimento criada pela Assembleia das Nações Unidas em 1983, predica que","a":"o modelo ecologicamente sustentável não se compatibiliza com desenvolvimento econômico, cabendo uma escolha ética pelo primeiro por parte das futuras gerações.","b":"os recursos naturais são finitos e toda forma de desenvolvimento que utilize esses insumos deve ser tida como deletéria.","c":"o desenvolvimento pressupõe degradação, daí porque os países mais desenvolvidos devem ser taxados e a receita revertida para países que optaram por preservar sua biodiversidade.","d":"se deve adequar, compulsoriamente, a velocidade das mudanças tecnológicas à capacidade de absorção pelo ecossistema dos impactos correspondentes.","e":"se deve satisfazer as necessidades presentes, sem comprometer a capacidade das gerações futuras de suprir suas próprias necessidades. Estatuto da Pessoa com Deficiência - Lei nº 13.146 de 2015>","gabarito":"E","materia":"Direito Ambiental","tema":"Sustentabilidade ,Conceito de Desenvolvimento Sustentável","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1214","enunciado":"Ano: 2019 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária De acordo com a Lei n° 13.146/2015, o processo de habilitação e reabilitação é um direito da pessoa com deficiência e baseia-se em avaliação multidisciplinar das necessidades, habilidades e potencialidades de cada pessoa, observada, dentre","a":"outras, a seguinte diretriz: adoção de medidas para compensar perda ou limitação funcional, buscando o desenvolvimento de aptidões.","b":"diagnóstico precoce e intervenção tardia.","c":"oferta de rede de serviços desarticulados, com atuação intrasetorial, nos diferentes níveis de complexidade, para atender às necessidades específicas da pessoa com deficiência.","d":"prestação de serviços próximo ao domicílio da pessoa com deficiência, exceto na zona rural, respeitadas a organização das Redes de Atenção à Saúde (RAS) nos territórios locais e as normas do Sistema Único de Saúde (SUS).","e":"atuação provisória e integrada de políticas públicas que possibilitem a plena participação social da pessoa com deficiência. Estatuto da Pessoa com Deficiência - Lei nº 13.146 de 2015>Legislação das Pessoas com Deficiência ,","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1215","enunciado":"Ano: 2019 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária Considere a seguinte situação hipotética: em 2018, determinada empresa concessionária de serviço de transporte coletivo não reservou assentos, devidamente identificados, aos idosos, gestantes, lactantes, pessoas portadoras de deficiência e pessoas acompanhadas por crianças de colo, razão pela qual foi multada, nos termos da Lei n° 10.048/2000. Em 2019, a empresa praticou a mesma infração, uma vez que alguns veículos de sua frota desrespeitaram a norma supracitada. Nos termos da Lei n° 10.048/2000, a empresa estará sujeita, por cada veículo que descumpriu a norma legal, ao pagamento de","a":"multa de R$ 500 00 a R$ 2.500 00.","b":"R$ 1.000,00 a R$ 5.000,00.","c":"R$ 250 00 a R$ 1.500, 00.","d":"R$ 500 00 a R$ 2.000 00.","e":"R$ 250 00 a R$ 2.500 00.","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1083577","enunciado":"Serão confeccionados números em cobre para numerar as portas dos apartamentos de um condomínio de 5 torres com 8 andares cada uma e com quatro apartamentos por andar. A numeração seguirá a seguinte regra: os apartamentos do andar k terão números k1, k2, k3 e k4, isto é, no primeiro andar de cada torre estarão os apartamentos 11, 12, 13 e 14. A","a":"quantidade de algarismos 3 que será confeccionada é igual a 30.","b":"12.","c":"100.","d":"80.","e":"60.","gabarito":"E","materia":"Matemática","tema":"Álgebra ,Problemas","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1083576","enunciado":"","a":"Somando-se 26 ao menor número de três algarismos e dividindo essa soma pelo maior número de um algarismo tem-se 10.","b":"16.","c":"13.","d":"14.","e":"12.","gabarito":"D","materia":"Matemática","tema":"Aritmética e Problemas ,Sistemas de Numeração e Operações Fundamentais","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1083575","enunciado":"Ana, Beth, Carla, Diana e Natalina fazem aniversário, não necessariamente nessa ordem, em 1° de março, 17 de maio, 20 de julho, 20 de março e 25 de dezembro. Beth e Carla nasceram no mesmo mês, Ana e Carla nasceram no mesmo dia, mas em meses diferentes. Natalina recebeu seu nome devido ao dia de seu nascimento. Com certeza, quem nasceu em 17 de maio","a":"foi Natalina.","b":"Diana.","c":"Carla.","d":"Beth.","e":"Ana.","gabarito":"B","materia":"Raciocínio Lógico","tema":"Orientação Espacial e Temporal","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1083574","enunciado":"Na tabela abaixo foram registradas as classificações obtidas por 50 alunos de uma turma.","a":"De acordo com os dados apresentados, 50% dos alunos obtiveram classificação 1, 2 ou 3.","b":"20% dos alunos obtiveram classificação 4 ou 5.","c":"30% dos alunos obtiveram classificação 4.","d":"15% dos alunos obtiveram classificação 1.","e":"90% dos alunos obtiveram classificação 3, 4 ou 5. Português>Ortografia ,Problemas da língua culta ,Por que- porque/ porquê/ por quêOnde-aonde ,Sintaxe ,","gabarito":"C","materia":"Matemática","tema":"Aritmética e Problemas ,Porcentagem","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1220","enunciado":"Ano: 2019 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária [Gravado na pele] Dizem que a tatuagem data do paleolítico, quando era usada por povos nativos da Ásia. Além da beleza das formas e cores, há algo de simbólico nessas inscrições corporais. Os índios pintam o corpo em cerimônias, festas e rituais de guerra. Os marinheiros, cujas pátrias são os portos e os oceanos, ostentam em sua pele símbolos que evocam a breve permanência em terra firme e a longa travessia marítima: âncoras, ilhas, mapas, peixes, pássaros, bússolas. Antes de ser uma febre no Brasil, a tatuagem inspirou uma música de Chico Buarque e Ruy Guerra. Quero ficar no teu corpo feito tatuagem, diz a letra dessa belíssima canção. Para um observador parado à beira-mar, um observador que teme o sol forte e protege a cabeça com um chapéu, cada tatuagem é uma descoberta, uma viagem do olhar. Jovens e velhos exibem tatuagens; uso o verbo exibir porque talvez haja uma ponta de exibicionismo nessa arte antiga de fazer da pele uma pintura para toda a vida. Numa única manhã ensolarada, sob meu chapéu, vi tatuagens de vários tipos e tamanhos, li nomes próprios, adjetivos, bilhetes, e até mesmo uma mensagem cifrada, cuja revelação será sempre adiada: Amanhã saberás o segredo... (Adaptado de: HATOUM, Milton. Um solitário à espreita. São Paulo: Companhia das Letras, 2013, p. 122)","a":"Está plenamente adequado o emprego de ambos os elementos sublinhados na frase: As economias que provieram de seus salários, ele as despendeu em sessões de tatuagem.","b":"Elas interviram quando ele se dispôs a apagar uma tatuagem que o custara tão caro.","c":"A propósito de tatuagens, o velho lhes vê como assessórios inúteis que marcam um corpo.","d":"Depois de se deixar seduzir a uma tatuagem, conheceu o remorso em cujose martirizou.","e":"Ele diz não saber porquê a tatuagem goza de tanto prestígio aonde quer que surja.","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1083572","enunciado":"","a":"Além da beleza das formas e cores, há algo de simbólico nessas inscrições corporais. frase acima ganha nova redação, na qual se mantêm a coerência básica, a clareza e a correção da linguagem, no seguinte caso:","b":"A Nessas inscrições corporais, a despeito da beleza das formas e cores, ocorre-lhes algum simbolismo. Em tais inscrições corporais o simbolismo desperta-lhes igualmente a beleza das formas e cores simbólicas.","c":"Algo de simbólico se revela, além das belas formas e cores, nessas inscrições corporais.","d":"Essas formas simbólicas, em cujas há cores e beleza, apresentam-se como inscrições corporais.","e":"O simbólico dessas inscrições corporais manifesta-se para muito além das formas e cores que houverem.","gabarito":"C","materia":"Português","tema":"Interpretação de Textos ,Coesão e coerência ,Redação - Reescritura de texto","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1083571","enunciado":"","a":"Na frase Quero ficar no teu corpo feito tatuagem, da canção de Chico Buarque e Ruy Guerra, deve-se entender que há o desejo de que essa mesma frase seja gravada no corpo da pessoa amada.","b":"a expressão feito tatuagem está empregada no sentido de tal e qual tatuagem.","c":"o corpo da pessoa amada deve aparecer a quem o olha como se fosse uma tatuagem","d":"o amor pela pessoa amada acaba tendo a mesma efemeridade de uma tatuagem.","e":"há a esperança de que a paixão impossível acabe se representando numa tatuagem.","gabarito":"B","materia":"Português","tema":"Interpretação de Textos ,Noções Gerais de Compreensão e Interpretação de Texto","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1083570","enunciado":"Ao desenvolver suas impressões sobre a tatuagem, o autor acredita que ela,","a":"sendo um fenômeno relativamente recente, difundiu-se pela atuação dos artistas plásticos que a conceberam em primeira mão.","b":"apesar dos dissabores que causa, já o persuadiu a tatuar-se em razão da beleza dos símbolos que se imprimem na","c":"pele. tendo nascido em tempos remotos, conserva plena e exclusiva fidelidade aos primeiros símbolos que a celebrizaram.","d":"exibindo-se em tantos corpos que passam, oferece a um observador uma revelação contínua de novos elementos.","e":"embora limitada a formas simbólicas, faz pensar em frases que revelariam o mistério que ela oculta dentro de si mesma.","gabarito":"D","materia":"Português","tema":"Interpretação de Textos ,Noções Gerais de Compreensão e Interpretação de Texto","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1083569","enunciado":"","a":"[Como se estrutura uma sociedade?] pergunta formulada acima é uma constância da história social. Alguns antropólogos têm afirmado que a estrutura social é a rede de todas as relações de pessoa-a-pessoa, numa dada sociedade. Mas tal definição é por demais ampla. Não estabelece distinção entre os elementos efêmeros e os mais persistentes na atividade social, e torna quase impossível distinguir a noção de estrutura de uma sociedade da totalidade da própria sociedade. No extremo oposto, está a noção de estrutura social compreendendo, somente, as relações entre os grupos principais na sociedade, que persistem por muitas gerações, mas exclui outros como a família, que se dissolve de uma geração para outra. Essa definição é limitada demais. Uma terceira noção de estrutura social enfatiza não tanto as relações reais entre pessoas ou grupos, mas as relações esperadas ou mesmo as relações ideais. De acordo com esse ponto de vista, o que realmente dá à sociedade sua forma e permite a seus membros exercerem suas atividades são as expectativas ou mesmo as crenças idealizadas do que está feito, ou do que deverá ser feito pelos outros membros. Não falta quem veja tal formulação como bastante insatisfatória. Em vez de respostas prontas à pergunta aqui tratada, será preciso sempre reconhecer que a validade de qualquer uma delas estará presa à validação do critério que a sustenta. (Adaptado de: FIRTH, Raymond. In: VV.AA. Homem e sociedade. Trad. Amadeu José Duarte Lanna. São Paulo: Nacional, 1975, p. 35-36) O verbo indicado entre parênteses deverá flexionar-se numa forma do singular para integrar corretamente a frase: A As respostas que se (aguardar) para essa questão prendem-se aos critérios a serem observados.","b":"A propósito dessa exata definição de estrutura com que se (afligir) os antropólogos, estamos longe de qualquer","c":"consenso. Não (dever) caber aos sociólogos ou antropólogos definir açodadamente o que seja uma estrutura social.","d":"Àqueles que (haver) de pesquisar o funcionamento de uma sociedade recomenda-se sensatez na escolha de um critério.","e":"A validação dos critérios que se (apresentar) como parâmetros aceitáveis deve receber o aval de todos os envolvidos na definição.","gabarito":"C","materia":"Português","tema":"Sintaxe ,Concordância verbal, Concordância nominal","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1083568","enunciado":"","a":"Está clara e correta a redação desta livre consideração sobre o texto: menos que se sigam algum critério aceitável, os estudiosos da sociedade se apresentam como problemáticos no A caso de sua definição estrutural.","b":"Os diferentes critérios para a definição do que seja a estrutura social são julgados, por razões diversas, como insatisfatórios.","c":"Há quem julguem as relações sociais como um produto que ao mesmo tempo considere que as individualidades já as constituam por si mesmas.","d":"Não é por formularem alguma ordem ideal para as relações sociais definidas como expectativas que se obtêm, apenas por isso, a validade de uma estrutura.","e":"O autor do texto leva-nos à crer que, a depender do critério que adotássemos, nossa definição de estrutura social terá validade nessa dependência. Português>Interpretação de Textos ,Significação Contextual de Palavras e Expressões. Sinônimos e Antônimos. ,","gabarito":"B","materia":"Português","tema":"Interpretação de Textos ,Noções Gerais de Compreensão e Interpretação de Texto","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1226","enunciado":"Ano: 2019 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","a":"Considerando-se o contexto, traduz-se adequadamente o sentido de um segmento do texto em: rede de todas as relações de pessoa-a-pessoa (1° parágrafo) = somatória de todas as individualidades.","b":"persistem por muitas gerações (2° parágrafo) = difundem uma permanência gerativa.","c":"enfatiza não tanto as relações reais (3° parágrafo) = releva sobremaneira as conexões efetivas.","d":"permite a seus membros exercerem (3° parágrafo) = faculta o desmembramento do exercício.","e":"estará presa à validação do critério (4° parágrafo) = dependerá da aceitabilidade do parâmetro.","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q1083566","enunciado":"Deve-se entender da leitura do texto que, ao se considerar a pergunta formulada no título,","a":"a definição dada no primeiro parágrafo não satisfaz porque, em sua amplitude, formula ideais de conduta coletiva em vez de analisar práticas individuais.","b":"a noção aventada no segundo parágrafo pecaria por não distinguir entre os elementos transitórios e os elementos duradouros de uma sociedade.","c":"a hipótese levantada no terceiro parágrafo é dada como insatisfatória porque valoriza as relações pragmáticas já estabelecidas numa sociedade.","d":"o reconhecimento de um parâmetro válido para a definição do que seja uma estrutura social é indispensável para que se aceite essa definição.","e":"a validação do conceito mesmo de estrutura social deve preceder toda e qualquer análise de caso que se proponha numa fundamentação aceitável. Direito Internacional Privado>Direito Processual Internacional ,","gabarito":"D","materia":"Português","tema":"Interpretação de Textos ,Noções Gerais de Compreensão e Interpretação de Texto","origem":"FCC - 2019 - TRF - 3ª REGIÃO - Analista Judiciário - Área Judiciária","ano":"2019","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1228","enunciado":"Ano: 2018 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal Substituto Cuidando-se dos efeitos civis do sequestro internacional de crianças, de acordo com e nos estritos termos da convenção concluída na cidade de Haia, em 25/10/1980, considere as seguintes assertivas: I – Qualquer decisão que, baseada nos termos da Convenção, determine o retorno da criança, não afeta os fundamentos do direito de guarda. II – Se restar provado que a criança já está integrada no seu novo meio, por mais de um ano, a autoridade judicial ou administrativa não está obrigada a determinar o seu retorno. III – Decisão fundamentada quanto ao direito de guarda pode servir de base para justificar a recusa de retorno da criança, nos termos da Convenção, podendo as autoridades judiciais ou administrativas do Estado requerido levar em consideração os motivos dessa decisão na aplicação da Convenção. IV – É lícita a exigência de prestação de caução ou depósito para garantir o pagamento dos custos e despesas relativas aos procedimentos previstos na convenção, podendo o interessado, se o caso, alegar impossibilidade de arcar com tais gastos,","a":"caso em que poderá ser eximido de tais pagamentos. Todas as assertivas são corretas.","b":"A assertiva III é a única correta.","c":"As assertivas I e II são as únicas corretas.","d":"As assertivas III e IV são as únicas corretas. Direito Internacional Privado>","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1229","enunciado":"Ano: 2018 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal Substituto Sobre o tema da solução de controvérsias de abrangência internacional (arbitragem), avalie as seguintes assertivas: I - Mesmo que a arbitragem tenha transcorrido totalmente em território nacional (audiências, reuniões), se a sentença arbitral for proferida fora do Brasil, tratar-se-á de sentença estrangeira, exigindo, unicamente, a homologação pelo Superior Tribunal de Justiça para a regular produção de efeitos. II – No tocante ao reconhecimento ou execução de sentença arbitral estrangeira, os tratados internacionais têm prevalência sobre a lei interna, que só possui aplicação subsidiária e nos termos da legislação própria. III – Nos termos da Convenção de Nova Iorque (Decreto 4.311/2002), pode ser indeferido o reconhecimento ou execução de uma sentença arbitral se houver prova de que a parte contra a qual a sentença é invocada não recebeu notificação adequada sobre a designação do árbitro ou do processo de arbitragem, ou lhe foi impossível, por outras razões, apresentar seus argumentos; IV – É causa bastante ao indeferimento do reconhecimento ou execução de sentença arbitral estrangeira a comprovação de que referida sentença ainda não se tornou obrigatória para as partes, foi","a":"anulada ou suspensa por ordem de autoridade do país em que foi proferida. Todas as assertivas estão corretas.","b":"Apenas as assertivas II e IV estão corretas.","c":"A assertiva I é a única correta.","d":"Apenas as assertivas I, III e IV estão corretas. Direito Internacional Privado>","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1230","enunciado":"Ano: 2018 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal Substituto Consoante ensinamentos da doutrina, na seara do Direito Internacional Privado, sabe-se que as regras de conexão estabelecem qual o direito aplicável às diversas situações jurídicas conectadas a mais de um sistema legal, após a necessária qualificação e em determinadas situações pode ocorrer o fenômeno denominado reenvio. Avalie, a seguir, as seguintes assertivas e, depois, expresse sua convicção: I – O processo de qualificação, ou de classificação, que leva ao elemento de conexão, considera um de três diferentes aspectos: o sujeito, o objeto ou o ato jurídico. II – Como exemplos de regras de conexão, podemos citar: lex loci solutionis (lei do local onde as obrigações ou a obrigação principal do contrato, deve ser cumprida); lex damni (lei do local onde se manifestaram as consequências do ato ilícito, para reger a obrigação de indenizar); lex monetae (lei do país em cuja moeda a dívida ou outra obrigação legal é expressa); lei mais favorável, descrita como a lei mais benéfica em situações específicas. III – A lei qualificadora não coincide, necessariamente, com a lei aplicável. IV – O reenvio pode ocorrer em dois graus; em primeiro grau, quando um país nega competência à sua lei em favor de outro país, que, a seu turno, também nega competência à sua lei, configurando uma recusa recíproca; em segundo grau, o reenvio pode ocorrer quando a lei do país ”A” manda aplicar a lei do país ”B”, e a lei do país “B” determina que se aplique a","a":"lei do país “C”. Todas as assertivas estão corretas.","b":"Apenas as assertivas I, II e IV estão corretas.","c":"Apenas as assertivas I, III e IV estão corretas.","d":"A assertiva I é a única correta.","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q904839","enunciado":"Substituto Sobre o MERCOSUL e sua disciplina jurídica, reflita sobre as seguintes assertivas: I – Derrogando o Protocolo de Brasília, o Protocolo de Olivos, assinado aos 18.02.2002, aprovado pelo Decreto Legislativo 712, de 2003, e promulgado no Brasil pelo Dec. 4.982/2004, estabelece mecanismos para solução de controvérsias entre os Estados Partes; e o procedimento arbitral ”ad hoc” será utilizado, caso o conflito não tenha sido solucionado por negociação direta, nem por intervenção do Grupo Mercado Comum. II – São órgãos componentes da estrutura institucional do Mercosul: (i) Conselho do Mercado Comum (CMC); (ii) Grupo Mercado Comum (GMC); (iii) Comissão de Comércio do Mercosul (CMC); (iv) Comissão Parlamentar Conjunta (CPC); (v) Foro Consultivo Econômico-Social (FCES); (vi) Secretaria Administrativa do Mercosul (SAM); (vii) Conselho de Segurança (CS). III – São fontes jurídicas do MERCOSUL: (i) o Tratado de Assunção, seus protocolos e os instrumentos adicionais ou complementares; (ii) os acordos celebrados no âmbito do Tratado de Assunção e seus protocolos; (iii) as decisões do Conselho Mercado Comum, as Resoluções do Grupo Mercado Comum e as Diretrizes da Comissão de Comércio do Mercosul, adotadas desde a entrada em vigor do Tratado de Assunção. IV – As normas produzidas pelo Conselho Mercado Comum, pelo Grupo Mercado Comum e pela Comissão de Comércio do Mercosul, além de possuírem caráter obrigatório, deverão, quando necessário, ser incorporadas aos ordenamentos","a":"jurídicos nacionais mediante os procedimentos previstos pela legislação de cada país. Apenas as assertivas I e III são incorretas.","b":"A assertiva II é a única incorreta.","c":"Apenas as assertivas II e IV são incorretas.","d":"A assertiva IV é a única incorreta.","e":"","gabarito":"B","materia":"Direito Internacional Público","tema":"Mercosul","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q904838","enunciado":"Substituto Relativamente à Convenção Interamericana sobre Asilo Diplomático e à Convenção Interamericana sobre Asilo Territorial, assinadas em Caracas, aos 28.03.1954, analise as seguintes assertivas: I - É ilícito conceder asilo a pessoas que, na ocasião em que o solicitem, tenham sido acusadas de delitos comuns, processadas ou condenadas por esse motivo pelos tribunais ordinários competentes, sem haverem cumprido as penas respectivas; nem a desertores das forças de terra, ar e mar, salvo quando os fatos que motivarem o pedido de asilo, em qualquer hipótese, apresentem caráter nitidamente político. II - O asilo diplomático só poderá ser concedido em casos de urgência e pelo tempo estritamente indispensável para que o asilado deixe o país com as garantias concedidas pelo governo do Estado territorial, a fim de não correrem perigo sua vida, sua liberdade ou sua integridade pessoal, ou para que de outra maneira o asilado seja posto em segurança. III - Um Estado parte tem direito de pedir a outro Estado parte que restrinja aos asilados ou refugiados políticos a liberdade de reunião ou associação, que a legislação interna deste reconheça a todos os estrangeiros dentro do seu território. IV - Não viola o tratado o Estado que, tendo concedido asilo ou refúgio a determinado indivíduo, proceda à sua vigilância ou ao internamento em distância prudente de suas fronteiras, a pedido do Estado interessado, quando se tratar de dirigentes notórios de movimento subversivo assim como daqueles sobre os quais existam provas de que se dispõem a incorporar-se","a":"no mesmo movimento. Todas as assertivas são incorretas.","b":"A assertiva III é a única incorreta.","c":"A assertiva IV é a única incorreta.","d":"As assertivas I, II e IV são incorretas. Direito Internacional Público>Fontes do Direito Internacional Público: Tratados Internacionais ,","e":"","gabarito":"B","materia":"Direitos Humanos","tema":"Sistema Interamericano de Proteção aos Direitos Humanos: Instrumentos Normativos","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1233","enunciado":"Ano: 2018 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal Substituto Em se tratando da Convenção de Viena sobre o Direito dos Tratados, aberta à assinatura em Viena, aos 23.05.1969, pondere as seguintes afirmações e indique a alternativa CORRETA: I – Se a interpretação do tratado deixa o sentido ambíguo ou obscuro, ou, ainda, conduz a um resultado que seja manifestamente absurdo, fica o intérprete autorizado a buscar meios suplementares de interpretação, inclusive aos trabalhos preparatórios e às circunstâncias de sua conclusão. II – Acordos posteriores entre as partes, relativos à interpretação do tratado ou à aplicação de seus dispositivos, somente podem influir na sua interpretação se forem consonantes com a jurisprudência da Corte Internacional de Justiça. III – A reserva é um direito que compete ao Estado e que pode ser exercido, sempre por escrito, em mais de um momento, ou seja, quando da assinatura, ratificação, aceitação ou adesão, mesmo que tal conduta (formulação da reserva) seja rechaçada pelo tratado, pois prevalece, no caso, a autonomia de vontade e o pacta sunt servanda. IV – É desnecessário o consentimento de um Estado que tenha aceitado uma reserva, a qual pode ser retirada a qualquer momento por quem a formulou; mas, nesse caso, é imprescindível que o tratado dispense ou não exija tal consentimento do Estado que aceitara ou fizera objeção à","a":"reserva. Todas as assertivas são corretas.","b":"As assertivas II e III são as únicas corretas.","c":"As assertivas I e IV são as únicas corretas.","d":"A assertiva I é a única correta. Direito Internacional Público>Fontes do Direito Internacional Público: Tratados Internacionais ,","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1234","enunciado":"Ano: 2018 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal Substituto Sobre a aplicação de tratados internacionais com normas contraditórias entre si, devem ser respeitadas certas regras, que são enunciadas pela Convenção de Viena. Aponte, portanto, a afirmação INCORRETA:","a":"quando os dois tratados não têm como contratantes os mesmos Estados, estabelecendo-se entre um Estado parte em ambos os tratados e um Estado parte somente no tratado mais recente, aplica-se o mais recente.","b":"quando os dois tratados não têm como contratantes os mesmos Estados, estabelecendo-se entre um Estado parte em","c":"ambos os tratados e um Estado parte somente no tratado anterior, aplica-se o tratado anterior. entre os Estados parte nos dois tratados só se aplica o anterior no que ele não for compatível com o novo tratado.","d":"a violação de um tratado pode sujeitar o Estado a ser responsabilizado em âmbito internacional, sendo que os conflitos porventura existentes são na maioria das vezes resolvidos por meio de interpretação.","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q904835","enunciado":"Substituto Considere as seguintes assertivas e assinale a INCORRETA:","a":"Sobre as fontes do Direito Internacional Público, a doutrina clássica afirma que tratado e costume possuem o mesmo valor sem que um tenha primazia sobre o outro; por isso, um pode derrogar ou modificar o outro.","b":"O ato unilateral tem sido considerado pela doutrina como fonte do Direito Internacional, apesar de não constar expressamente do rol previsto no artigo 38 do Estatuto da Corte Internacional de Justiça, tendo, como exemplo, as resoluções das organizações internacionais. Dentre os princípios gerais de direito no âmbito interno, os seguintes foram consagrados na jurisprudência","c":"internacional, segundo doutrina: (i) proibição ao abuso de direito; (ii) responsabilidade internacional decorrente de atos ilícitos e restituição do que foi adquirido por enriquecimento ilícito; (iii) exceção da prescrição liberatória; (iv) obrigação de reparar os danos emergentes e lucros cessantes.","d":"O recurso à equidade prescinde da concordância das partes para ser validamente utilizado pelo juiz internacional ao proferir sua decisão. Direito Ambiental>Proteção do Meio Ambiente em Normas Infraconstitucionais ,","e":"","gabarito":"D","materia":"Direito Internacional Público","tema":"Fontes do Direito Internacional Público: Tratados Internacionais","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1236","enunciado":"Ano: 2018 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal Substituto","a":"De acordo com a Política Nacional de Resíduos Sólidos prevista na Lei nº 12.305/2010, é CORRETO afirmar que: Política Nacional de Resíduos Sólidos reúne o conjunto de princípios, objetivos, instrumentos, diretrizes, metas e A ações a serem seguidos pela União, Estados, Distrito Federal e Municípios, de maneira independente e concorrente, nos termos do artigo 4º da lei.","b":"O princípio do protetor-recebedor, também denominado princípio da visão sistêmica, implica a observância das variáveis ambiental, social e cultural na gestão dos resíduos sólidos, além do respeito às diversidades locais e regionais.","c":"Não há distinção entre resíduos sólidos e rejeitos, eis que ambos, na definição legal, são os materiais, objetos ou substâncias resultantes de atividades humanas em sociedade a cuja destinação final se procede.","d":"São instrumentos da Política Nacional de Resíduos Sólidos a coleta seletiva, os inventários e o sistema declaratório anual de resíduos sólidos, entre outros.","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q904833","enunciado":"","a":"Substituto respeito do licenciamento ambiental, é CORRETO afirmar que: Conforme a Lei Complementar nº 140/2011, os empreendimentos e atividades são licenciados ou autorizados, A ambientalmente, apenas pela União, Estados ou Distrito Federal de forma concorrente, tendo em vista a competência prevista no artigo 24 da Constituição Federal.","b":"De acordo com a Lei Complementar nº 140/2011 e com a Lei nº 6.938/81, o licenciamento ambiental abrange o estudo de impacto ambiental e a revisão de atividades efetiva ou potencialmente poluidoras.","c":"É o procedimento administrativo destinado a licenciar atividades ou empreendimentos utilizadores de recursos ambientais, efetiva ou potencialmente poluidores ou capazes, sob qualquer forma, de causar degradação ambiental.","d":"Em face da supremacia da União em determinar os critérios a serem observados quanto à proteção do meio ambiente, apenas a concessão de autorização do Poder Público federal poderá contrariar regra municipal ou estadual que estabeleça zoneamento para determinado espaço territorial. Direito Ambiental>Proteção do Meio Ambiente em Normas Infraconstitucionais ,","e":"","gabarito":"C","materia":"Direito Ambiental","tema":"Instrumentos da Política Nacional do Meio Ambiente ,Licenciamento e licença ambiental","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1238","enunciado":"Ano: 2018 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","a":"Substituto respeito da Lei nº 11.105/2005 (Lei de Biossegurança), que regulamenta os incisos II, IV e V do parágrafo 1º do artigo 225 da Constituição Federal, é CORRETO afirmar que: As atividades e projetos que envolvam OGM (Organismos Geneticamente Modificados) e seus derivados, relacionados ao ensino com manipulação de organismos vivos, à pesquisa científica e ao desenvolvimento tecnológico, nos termos A do artigo 2º, parágrafo 2º, podem ser realizados por pessoas físicas em atuação autônoma e independente, desde que mantenham vínculo empregatício ou qualquer outro com pessoas jurídicas.","b":"Para os efeitos desta lei está incluído na categoria de OGM aquele resultante de técnicas que impliquem a introdução direta de material hereditário em um organismo, inclusive fecundação in vitro, conjugação, transdução e transformação.","c":"Aplicam-se os dispositivos desta lei quando a modificação genética for obtida por meio da mutagênese, fusão celular e autoclonagem de organismos, ainda que implique a utilização de OGM como receptor ou doador.","d":"Dentre as diversas atividades relativas aos OGM, estão abrangidas pela lei a construção, o cultivo, a manipulação e a pesquisa, estabelecendo-se normas de segurança e mecanismos de fiscalização.","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q904831","enunciado":"","a":"Substituto respeito da responsabilidade por dano ecológico é CORRETO afirmar que: Segundo a teoria do risco criado, a responsabilidade pelo dano ecológico é objetiva, admitindo-se as excludentes de A culpa da vítima e força maior.","b":"Pela teoria do risco integral é suficiente a demonstração do nexo causal e do dano para que exista o dever de repará- lo, exceto em caso de ações de particulares praticadas de forma clandestina.","c":"Diante da impossibilidade da produção de prova negativa, segundo o Superior Tribunal de Justiça, não é possível se exigir de quem supostamente promoveu o dano ambiental que comprove que não o causou ou que a substância lançada ao meio ambiente não lhe é potencialmente lesiva.","d":"Em face da proporção e da intensidade que o dano ecológico pode alcançar é que a Lei nº 6.938/81 instituiu um fundo nacional para suprir situações de lesão em matéria de poluição como auxílio à reparação de seus efeitos. Direito Ambiental>Política Nacional do Meio Ambiente-PNMA – Lei nº 6.938 de 1981 ,","e":"","gabarito":"A","materia":"Direito Ambiental","tema":"Responsabilidade ambiental ,Responsabilidade civil por danos ao meio ambiente","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1240","enunciado":"Ano: 2018 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal Substituto o","a":"De acordo com o artigo 9 da Lei nº 6.938/81, NÃO são instrumentos da Política Nacional do Meio Ambiente: O estabelecimento de padrões de qualidade ambiental, o zoneamento e a avaliação de impactos ambientais.","b":"Os órgãos e entidades que constituem o Sistema Nacional do Meio Ambiente – SISNAMA.","c":"Os incentivos à criação de tecnologia voltados para a melhoria da qualidade ambiental e os instrumentos econômicos, como concessão florestal, servidão ambiental e seguro ambiental.","d":"O sistema nacional de informações sobre o meio ambiente e o Cadastro Técnico Federal de Atividades e Instrumentos de Defesa Ambiental.","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q904829","enunciado":"Substituto Recentemente o Supremo Tribunal Federal concluiu o julgamento das Ações Diretas de Constitucionalidade 4901, 4902, 4903, 4937 e da Ação Declaratória de Constitucionalidade 42, as quais tratavam de diversos dispositivos da Lei nº 12.651/2012, denominada Código Florestal. De acordo com referido julgamento, é CORRETO afirmar que:","a":"O Supremo Tribunal Federal decidiu pela inconstitucionalidade da anistia concedida a todo aquele que tenha praticado a supressão de vegetação em área de preservação permanente, reserva legal ou de uso restrito anteriores a 22 de julho de 2008, nos termos do artigo 59 da Lei nº 12.651/2012. Ao declarar a inconstitucionalidade das expressões “gestão de resíduos” e “instalações necessárias à realização de","b":"competições esportivas”, contidas no artigo 3º, VIII, alínea b, da Lei nº 12.651/2012, o Supremo Tribunal Federal reduziu as hipóteses em que se permite o desmatamento de área de preservação permanente por motivo de utilidade pública. O Supremo Tribunal Federal considerou constitucional o mecanismo da Cota de Reserva Ambiental (CRA) que permite","c":"a compensação da Reserva Legal de imóvel rural, afastando, porém, a exigência prevista no Código Florestal de que referida compensação somente poderia ser realizada em áreas pertencentes ao mesmo bioma e que mantivessem identidade ecológica. Embora tenha reconhecido a constitucionalidade da maior parte dos dispositivos do Código Florestal, o Supremo","d":"Tribunal Federal também admitiu que a redução da área de reserva legal prevista na norma estabeleceu um padrão de proteção ambiental inferior ao que existia antes de sua vigência, em afronta ao princípio da vedação ao retrocesso e em contrariedade ao artigo 225 da Constituição Federal. Direito Ambiental>Direito constitucional ambiental ,","e":"","gabarito":"B","materia":"Direito Ambiental","tema":"Código Florestal – Lei nº 12.651 de 2012 ,Outros temas de Código Florestal","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1242","enunciado":"Ano: 2018 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal Substituto Considerando o artigo 225 da Constituição Federal, assinale a alternativa CORRETA:","a":"Cabe ao Poder Público o controle e a fiscalização da atividade mineradora, especialmente sobre a poluição causada, havendo discricionariedade quanto à aplicação de penalidades administrativas e penais, quando houver a integral reparação do dano pelo poluidor.","b":"Aquele que explorar recursos minerais está obrigado a reparar o meio ambiente, devendo reabilitar o solo contaminado e recuperar integralmente as condições em que se encontrava antes do exercício da atividade, sob pena de imposição de sanções penais e administrativas.","c":"A exploração dos recursos minerais está condicionada à reparação do meio ambiente degradado, de acordo com solução técnica exigida pelo órgão público competente, na forma da lei.","d":"Incumbe ao Poder Público proteger a fauna e a flora, vedadas as práticas que coloquem em risco sua função ecológica, provoquem a extinção de espécies ou submetam os animais a qualquer crueldade, inclusive quando utilizados para a prática desportiva ou outras formas de manifestações culturais. Direito Ambiental>Princípios do direito ambiental ,Desenvolvimento sustentável ,","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1243","enunciado":"Ano: 2018 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","a":"Substituto respeito dos princípios que sustentam o direito ambiental brasileiro é CORRETO afirmar que: O princípio do desenvolvimento sustentável envolve a substituição de norma de expansão quantitativa por uma A melhoria qualitativa como caminho para o progresso, trazendo a integração entre a proteção ambiental e o desenvolvimento econômico para o benefício das presentes e futuras gerações.","b":"O princípio usuário-pagador pressupõe uma prática ilícita daquele que utiliza o recurso ambiental, sendo possível a exigência de pagamento quando houver o cometimento de faltas ou infrações.","c":"O princípio da precaução contido no artigo 225 da Constituição Federal impõe ao Poder Público a obrigação de controlar atividades de risco quando importarem ameaças de danos irreversíveis e conhecidos pela ciência, sendo liberada a atividade se não houver prova do prejuízo.","d":"A Lei de Política Nacional do Meio Ambiente obriga a reparação dos danos causados pelo poluidor à fauna, à flora e ao meio ambiente, devendo ser demonstrada a culpa em sua conduta, exceto em caso de prejuízo causado pela atividade nuclear.","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1244","enunciado":"Ano: 2018 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal Substituto Um dos principais objetivos do “Consenso de Washington” (1989) foi fornecer um receituário para implantar o neoliberalismo na América Latina, sendo um dos principais vetores a redução do papel do Estado na economia. Nesse contexto, tivemos no Brasil as privatizações e a mudança do perfil do Estado, de interventor e/ou empresário para o Estado regulador. Esse foi o cenário em que nasceram as agências reguladoras. Com base no regime jurídico a que elas se submetem, indique a afirmação CORRETA:","a":"As agências reguladoras regulam e controlam as atividades objeto de concessão, permissão ou autorização de serviços públicos ou de concessão para exploração de bem público, vedados os atos de repressão (sanção) com fundamento no poder de polícia.","b":"As agências reguladoras são as únicas entidades da Administração Pública competentes para regular a atividade econômica.","c":"No seu âmbito de atuação, as agências reguladoras podem exercer todas as prerrogativas e funções que a lei outorga ao Poder Público na gestão de contratos e atos de delegação relacionados ao serviço público.","d":"No exercício de atividade típica de regulação, as decisões das agências reguladoras podem ser reformadas por meio de recurso hierárquico endereçado ao chefe do Poder Executivo.","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q904825","enunciado":"","a":"Substituto Lei nº 11.079, de 2004, instituiu normas gerais para a contratação da chamada “parceria público-privada” no âmbito do Poder Público. Esse tipo de contrato administrativo de concessão pode ser feito nas seguintes modalidades: Patrocinada, quando envolver, além do recebimento da tarifa cobrada dos usuários do serviço público, o pagamento A de contraprestação do parceiro privado ao parceiro público.","b":"Administrativa, quando a própria Administração Pública seja a usuária direta ou indireta da prestação dos serviços,","c":"ainda que envolva a execução de obras ou a instalação de bens. Comum, quando não envolver o pagamento de contraprestação pecuniária do parceiro público ao parceiro privado.","d":"Especial, quando o serviço público não é sujeito ao pagamento de tarifa.","e":"","gabarito":"B","materia":"Direito Administrativo","tema":"Parcerias público-privadas ,Serviços Públicos","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q904824","enunciado":"Substituto Indique a afirmação CORRETA:","a":"O contrato de concessão de serviço público não pode prever a arbitragem como mecanismo para a resolução de disputas entre as partes.","b":"A transferência do controle societário da empresa concessionária do serviço público, sem prévia anuência do poder concedente, sujeita a empresa ao pagamento de multa.","c":"A caducidade da concessão pode ser declarada quando o serviço estiver sendo prestado de forma inadequada ou ineficiente, a critério do poder concedente.","d":"A encampação, caracterizada pela retomada do serviço público pelo poder concedente durante o prazo da concessão, é condicionada à existência de lei autorizadora específica e ao pagamento de indenização ao concessionário.","e":"","gabarito":"D","materia":"Direito Administrativo","tema":"Serviços Públicos ,Delegação dos Serviços Públicos - Concessão e Permissão","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q904821","enunciado":"Substituto É obrigatória a aprovação prévia em concurso público para a ocupação de cargos e empregos públicos efetivos. Trata-se da realização do princípio da igualdade de acesso ao serviço público. Com base nesse enunciado, indique a afirmação CORRETA:","a":"Limites de idade, sexo, altura e capacitação profissional devem ser estabelecidos em regulamento do concurso e não apenas no edital.","b":"Para que o candidato possa fazer jus às vagas reservadas aos portadores de deficiência, estas precisam necessariamente causar dificuldades no desempenho das funções do cargo disputado, em função da aplicação do princípio da congruência.","c":"O princípio da igualdade de gênero impede que o edital de concurso público preveja a participação apenas de concorrentes de determinado sexo.","d":"Conflita com o princípio da razoabilidade a eleição, como critério de desempate, do desempenho profissional anterior, relacionado com a titularidade do serviço para o qual se realiza o concurso.","e":"","gabarito":"D","materia":"Direito Administrativo","tema":"Agentes públicos e Lei 8.112 de 1990 ,Concurso público","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q904819","enunciado":"","a":"Substituto jurisprudência do Supremo Tribunal Federal é firme no sentido de que o direito de greve do servidor público é assegurado, ainda que não tenha sido publicada a lei complementar de que trata o inciso VII do art. 37 da Constituição Federal. Além disso, também de acordo com o STF: A O servidor público tem direito à remuneração pelos dias parados, em qualquer hipótese.","b":"O servidor público tem direito à remuneração pelos dias parados, somente se o movimento grevista foi motivado por conduta ilícita do sindicato da categoria.","c":"O servidor público tem direito à remuneração pelos dias parados, somente se o movimento grevista foi motivado por","d":"conduta ilícita do Poder Público. O servidor público não tem direito à remuneração pelos dias parados, em nenhuma hipótese.","e":"","gabarito":"C","materia":"Direito Constitucional","tema":"Administração Pública – Disposições Gerais e Servidores Públicos ,Servidores Públicos","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q904818","enunciado":"","a":"Substituto Lei nº 8.987, de 1995, dispõe sobre o regime de concessão e permissão para a prestação de serviços públicos. No capítulo sobre política tarifária está previsto que: Após a apresentação da proposta, é possível realizar-se a revisão da tarifa, para mais ou para menos, caso haja A qualquer alteração na legislação tributária – exceto do imposto sobre a renda – quando comprovado o impacto no","b":"cálculo do seu valor. A tarifa do serviço público será fixada no contrato, de comum acordo entre as partes.","c":"É vedada a cobrança de tarifas diferenciadas em função da existência de custos específicos para o atendimento de diferentes segmentos de usuários.","d":"É vedada a inclusão no contrato de cláusula de revisão do valor da tarifa, com o objetivo de manter-se o equilíbrio econômico-financeiro.","e":"","gabarito":"A","materia":"Direito Administrativo","tema":"Serviços Públicos ,Delegação dos Serviços Públicos - Concessão e Permissão","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q904815","enunciado":"Substituto O art. 87, inciso IV, da Lei nº 8.666, de 1993, prevê que a inexecução do contrato firmado com a Administração Pública pelo contratado pode ocasionar a aplicação de uma série de sanções, dentre as quais a declaração de inidoneidade do contratado para licitar ou contratar com a Administração Pública. Isso quer dizer que, se houver inexecução do contrato:","a":"O contratado fica impedido de participar de novas licitações do Poder Público e os contratos em andamento devem ser imediatamente rescindidos.","b":"O contratado fica impedido de participar de novas licitações do Poder Público, mas os contratos em andamento continuam a ser executados normalmente.","c":"O contratado fica impedido de participar de novas licitações e os seus direitos e obrigações, relativos aos contratos em andamento, devem ser cedidos a terceiro por ele indicado.","d":"O contratado não fica impedido de participar de novas licitações do Poder Público, mas os contratos em andamento devem ser imediatamente rescindidos. Direito Administrativo>Organização da Administração Pública ,Administração Indireta ,","e":"","gabarito":"B","materia":"Direito Administrativo","tema":"Contratos Administrativos ,Duração, Extinção, Inexecução, Sanções e Responsabilidade","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1251","enunciado":"Ano: 2018 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","a":"Substituto possibilidade de criação, pela União, de pessoas jurídicas de direito público e de direito privado, com atribuições para prestar serviços públicos, caracteriza uma das faces mais relevantes da Administração Indireta. Nesse tema, indique a afirmação CORRETA: É legítima a criação, por lei, de pessoa jurídica de direito público, a ela atribuindo-se a execução de determinado A serviço público, retendo, porém, a União, a titularidade sobre tal serviço.","b":"Lei que crie sociedade de economia mista controlada pela União pode conter cláusula genérica que permita àquela sociedade adquirir participação em outras empresas.","c":"Nas hipóteses de descentralização, em que a União crie por lei autarquia vinculada a um ministério, haverá relação hierárquica entre o ente autárquico e o órgão ministerial, porém não o controle político.","d":"Em nome do princípio da eficiência e da boa gestão, admite-se que lei federal autorize genericamente a União a criar sociedades de economia mista e fundações que sejam necessárias para dar cumprimento ao planejamento setorial.","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q904813","enunciado":"Substituto São princípios constitucionais implícitos ou reconhecidos da Administração Pública, porquanto consectários lógicos dos","a":"preceitos da Lei Maior: Impessoalidade e eficiência.","b":"Razoabilidade e legalidade.","c":"Segurança jurídica e moralidade.","d":"Prevalência do interesse público e proporcionalidade.","e":"","gabarito":"D","materia":"Direito Administrativo","tema":"Princípios da Administração Pública ,Regime jurídico administrativo","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q904812","enunciado":"","a":"Substituto Primeira Seção do Superior Tribunal de Justiça firmou orientação no sentido de que \"as contribuições especiais atípicas (de intervenção no domínio econômico) são constitucionalmente destinadas a finalidades não diretamente referidas ao sujeito passivo, o qual não necessariamente é beneficiado com a atuação estatal e nem a ela dá causa (referibilidade). Esse é o traço característico que as distingue das contribuições de interesse de categorias profissionais e de categorias econômicas\" (EREsp 724.789/RS, Rel. Min. Eliana Calmon, Primeira Seção, DJ 28.5.2007). À luz dessa decisão, é CORRETO afirmar que A referibilidade é condição constitucional necessária para a incidência das contribuições de intervenção no domínio A econômico.","b":"As contribuições de intervenção no domínio econômico só podem ser cobradas de sujeito passivo diretamente relacionado com a atuação estatal a ser financiada.","c":"A referibilidade é condição constitucional necessária para a incidência das contribuições de interesse de categoria","d":"profissional. As contribuições especiais atípicas são cobradas de sujeitos passivos vinculados a categorias profissionais.","e":"","gabarito":"C","materia":"Direito Tributário","tema":"Tributos Federais ,Contribuições Profissionais","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q904811","enunciado":"Substituto Indique a conclusão CORRETA. A Contribuição para o Financiamento da Seguridade Social – COFINS, exigida das pessoas","a":"jurídicas: Pode incidir de acordo com dois regimes jurídicos distintos: cumulativo e não cumulativo.","b":"Tem por base de cálculo as receitas de vendas canceladas.","c":"Quando incidente no regime cumulativo, é calculada deduzindo-se o valor dos créditos correspondentes à depreciação dos bens do ativo não circulante.","d":"Quando incidente no regime não cumulativo, tem por base de cálculo o valor dos insumos utilizados na produção das mercadorias adquiridas.","e":"","gabarito":"A","materia":"Direito Tributário","tema":"Tributos Federais ,Contribuições para a Seguridade Social","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q904810","enunciado":"Substituto Indique a conclusão CORRETA. O Imposto sobre Operações de Crédito, Câmbio e Seguro, ou relativas a Títulos ou Valores Mobiliários (IOF):","a":"Somente incide sobre operações desenvolvidas no âmbito do mercado financeiro, ou seja, quando há intervenção de instituição financeira autorizada a funcionar pelo Banco Central do Brasil.","b":"Pode ter sua alíquota alterada por meio de decreto do Poder Executivo e sem observância do princípio da","c":"anterioridade, desde que obedecidas as condições e os limites previstos em lei. Incide sobre qualquer movimentação financeira de recursos.","d":"Será seletivo em função da essencialidade da operação financeira.","e":"","gabarito":"B","materia":"Direito Tributário","tema":"Tributos Federais ,IOF","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q904809","enunciado":"Substituto Indique a conclusão CORRETA. A receita de venda de mercadoria por pessoa jurídica tributada pelo lucro real deve ser","a":"oferecida à tributação no período-base em que: O preço for recebido e contabilizado de acordo com o regime de caixa.","b":"O preço for utilizado para aumento de capital.","c":"For iniciado o processo de industrialização do produto final.","d":"Houver a tradição da mercadoria para o comprador.","e":"","gabarito":"D","materia":"Direito Tributário","tema":"Tributos Federais ,IRPF e IRPJ","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q904808","enunciado":"Substituto Indique a conclusão CORRETA. A despesa operacional, para ser dedutível da base de cálculo do imposto sobre a renda da","a":"pessoa jurídica tributada pelo lucro real, deve ser: Paga de acordo com o regime de competência.","b":"Usual e normal à atividade da empresa.","c":"Incorrida de acordo com o regime de caixa.","d":"Autorizada pela fiscalização federal. Direito Tributário>Legislação do Direito Tributário ,Suspensão do Crédito Tributário ,Moratória","e":"","gabarito":"B","materia":"Direito Tributário","tema":"Tributos Federais ,IRPF e IRPJ","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q904807","enunciado":"Ano: 2018 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal Substituto","a":"Indique a afirmação INCORRETA: Os tratados internacionais para evitar a dupla tributação prevalecem sobre a legislação interna brasileira.","b":"O aplicador da lei não pode empregar a analogia para exigir tributo não previsto em lei.","c":"A compensação pode ser promovida pelo sujeito passivo, mesmo sem lei que a preveja, desde que seja realizada","d":"entre tributos e contribuições da mesma espécie. A moratória suspende a exigibilidade do crédito tributário.","e":"","gabarito":"C","materia":"Extinção do Crédito Tributário","tema":"","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q904806","enunciado":"Substituto Indique a afirmação INCORRETA:","a":"Tributo é toda prestação pecuniária compulsória, em moeda ou cujo valor nela se possa exprimir, instituída em lei,","b":"que não constitua sanção por ato ilícito. Medida provisória pode estabelecer a extinção de tributo.","c":"Lei que disponha sobre outorga de isenção deve ser interpretada literalmente.","d":"Os decretos restringem o conteúdo e o alcance das leis em função das quais são expedidos. Direito Tributário>Limitações Constitucionais ao Poder de Tributar - Princípios Tributários ,","e":"","gabarito":"D","materia":"Direito Tributário","tema":"Legislação do Direito Tributário ,Tratados em Direito Tributário","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1260","enunciado":"Ano: 2018 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal Substituto Considerando que dentre as limitações constitucionais ao poder de tributar insere-se a vedação ao uso do tributo com efeito de confisco, indique qual a afirmação CORRETA:","a":"O Poder Executivo pode criar multas em percentuais que excedam o valor do tributo cobrado, visto que a imposição","b":"de multa tem o duplo objetivo de educar o contribuinte e de ressarcir o Poder Público. A multa correspondente a 90% do valor do tributo devido não tem caráter confiscatório.","c":"A falta de atualização monetária da tabela de incidência do imposto de renda na fonte sobre os salários tem natureza de confisco.","d":"É possível a cobrança de multa confiscatória desde que observado o princípio da praticidade da arrecadação e da prevalência do interesse público sobre o privado.","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q904803","enunciado":"Substituto","a":"Indique a afirmação CORRETA: Lei ordinária não pode dispor sobre dívida pública e sobre emissão e resgate de títulos da dívida pública.","b":"É da competência da cada pessoa política dispor, mediante decreto regulador, sobre sua dívida pública externa e","c":"interna, incluída a de suas autarquias, fundações e demais entidades controladas. Cabe ao Conselho Monetário Nacional exercer a competência constitucional para emitir moeda em nome da União.","d":"O orçamento da seguridade social abrange todas as entidades e órgãos a ela vinculados por determinação legal, mas não está incluído na lei orçamentária anual. Direito Empresarial (Comercial)>Direito da Propriedade Industrial ,Requisitos para registro e patente ,","e":"","gabarito":"A","materia":"Direito Constitucional","tema":"Ordem Econômica e Financeira ,Finanças Públicas – Orçamento","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1262","enunciado":"Ano: 2018 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal Substituto","a":"Sobre as patentes mail box, apreciadas pelo STJ em 2018, é CORRETO afirmar que: Seu prazo de vigência é de 20 anos, contados da data de concessão.","b":"Por conta da expedição tardia da carta-patente pelo INPI [back log], a invenção do recorrente resta desprovida de amparo legal até que esse ato administrativo seja praticado, justificando o prazo de proteção de 15 anos, contado a partir da data da concessão da patente.","c":"Cuidando de eventual conflito envolvendo tratado internacional e lei interna, o STF assentou que vigora no Brasil um sistema que considera que o tratado internacional é hierarquicamente superior à lei interna.","d":"A proteção ordinária conferida ao titular de patentes consiste em privilégio que excepciona a regra geral de nosso ordenamento jurídico, cujo objetivo visa a assegurar a ampla concorrência e a livre iniciativa. Assim, concessão de uma patente é uma exceção, que deve ser interpretada restritivamente.","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q904801","enunciado":"Substituto","a":"Sobre a intepretação dos contratos entre empresas, é CORRETO afirmar: O princípio do pacta sunt servanda é um dos principais vetores de interpretação dos contratos empresariais.","b":"O preâmbulo do contrato deve ser utilizado pelo intérprete para revelar o motivo individual que impeliu cada uma das partes à celebração, pois a motivação do declarante individualmente considerado é importante diretriz de interpretação dos contratos empresariais.","c":"Ao julgador é defeso modificar a cláusula penal ajustada pelas partes empresárias, que não se encontram em situação de paridade econômica.","d":"São aplicáveis os princípios consolidados e as regras de direito do consumidor, quando do contrato participam sociedades com disparidade de poder econômico.","e":"","gabarito":"A","materia":"Direito Empresarial (Comercial)","tema":"Contratos Empresariais","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q904800","enunciado":"Substituto","a":"Assinale a alternativa CORRETA: O acionista controlador que aliena suas quotas sociais não pode concorrer com a sociedade pelo prazo de 4 anos.","b":"O alienante do estabelecimento empresarial não pode concorrer com o comprador pelo prazo estabelecido no contrato, que poderá ser superior a 5 anos.","c":"No contrato de distribuição, não é potestativa a cláusula que permite ao fabricante fixar o preço da mercadoria de acordo com suas tabelas.","d":"A existência de dependência econômica do distribuidor em relação ao fornecedor autoriza a aplicação do Código de Defesa do Consumidor ao contrato, conforme jurisprudência pacífica do STJ.","e":"","gabarito":"C","materia":"Direito Empresarial (Comercial)","tema":"Direito Societário ,Aspectos gerais do Direito Societário","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q904798","enunciado":"","a":"Substituto sociedade anônima fechada “X” emite debêntures, subscritas em sua totalidade pelo banco “Y”. A escritura de emissão estipula que “X” somente poderá empreender novos negócios se devidamente autorizada por “Y”. Assinale a alternativa CORRETA:","b":"A Nos termos da Lei das Sociedades por Ações (Lei nº 6.404, de 1976), “Y” é controlador de “X”. A emissão de debêntures deverá ser registrada no Banco Central do Brasil.","c":"A totalidade dos acionistas de “X” deverá aprovar a emissão.","d":"A garantia das debêntures pode ser flutuante.","e":"","gabarito":"D","materia":"Direito Empresarial (Comercial)","tema":"Direito Societário ,Sociedade Anônima","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q904797","enunciado":"Substituto Sobre os embargos de declaração é CORRETO afirmar:","a":"Eles não são via processual adequada para a correção de erro material uma vez que esse tipo de vício não está sujeito a preclusão.","b":"Se opostos contra decisão unipessoal, podem ser conhecidos como agravo interno, a ser julgado também monocraticamente.","c":"Se eles forem rejeitados ou não houver alteração de resultado, o recurso interposto pela outra parte antes da publicação do julgamento dos embargos precisará ser ratificado, sob pena de preclusão lógica.","d":"Na reiteração de embargos manifestamente protelatórios, haverá elevação da multa e a interposição de qualquer recurso fica condicionada ao depósito prévio do valor, mas essa condição não se aplica ao beneficiário da justiça gratuita.","e":"","gabarito":"D","materia":"Direito Processual Civil - Novo Código de Processo Civil - CPC 2015","tema":"Recursos ,Embargos de Declaração","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q904796","enunciado":"Substituto","a":"Sobre a coisa julgada é INCORRETO afirmar: decisão concessiva de tutela antecipada estabilizada, segundo a lei, não faz coisa julgada material, ainda que a A estabilidade só possa ser afastada mediante a propositura de ação própria que busque a revisão, reforma ou anulação do que se decidiu.","b":"A decisão que determina a expedição de mandado monitório, se não for cumprida a prestação pelo requerido, nem forem apresentados embargos, enseja a formação de coisa julgada material e, portanto, ação rescisória.","c":"Como regra, a improcedência por insuficiência de provas não impede nova propositura da mesma demanda e julgamento do mérito respectivo se o interessado apresentar novos elementos de prova, desde que não ocorra prescrição ou decadência.","d":"Em ação de dissolução parcial de sociedade, segundo a lei, a pessoa jurídica ficará vinculada pela coisa julgada, ainda que não citada, desde que todos seus sócios o sejam.","e":"","gabarito":"C","materia":"Direito Processual Civil - Novo Código de Processo Civil - CPC 2015","tema":"Coisa Julgada no Processo Civil","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q904795","enunciado":"Substituto Em tema de prova pericial afigura-se CORRETO afirmar:","a":"O critério para que o juiz determine a produção de prova técnica simplificada é a prevalência da oralidade no","b":"processo. Se o laudo for inconclusivo o juiz poderá reduzir a remuneração do perito.","c":"No caso em que as partes, de comum acordo, escolham o perito, compete exclusivamente àquelas a formulação de quesitos.","d":"Sendo vedado ao perito ultrapassar os limites de sua designação, ele deve se abster de emitir opiniões pessoais que excedam o exame técnico ou científico do objeto da perícia, de ouvir testemunhas ou de obter documentos que estejam em poder da parte. Direito Processual Civil - Novo Código de Processo Civil - CPC 2015>Suspensão e Extinção do Processo ,","e":"","gabarito":"B","materia":"Direito Processual Civil - Novo Código de Processo Civil - CPC 2015","tema":"Provas em Espécie ,Prova Pericial","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1269","enunciado":"Ano: 2018 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal Substituto Relativamente à suspensão do processo, é INCORRETO afirmar:","a":"Ela não ocorrerá quando se arguir impedimento ou suspeição do membro do Ministério Público, quando este atuar como autor da demanda.","b":"É causa autorizadora da suspensão o parto ou adoção, quando a advogada responsável pelo processo constituir a única patrona da causa.","c":"Suspende-se a execução se os bens penhorados não forem alienados por ausência de licitantes, por um ano, após o que começará a correr o prazo de prescrição intercorrente.","d":"Se o conhecimento do mérito depender da verificação de fato delituoso, o juízo cível poderá examinar incidentalmente a questão prévia se, proposta a ação penal, decorrer o prazo de um ano sem pronunciamento do juízo criminal. Direito Processual Civil - Novo Código de Processo Civil - CPC 2015>Da Comunicação dos Atos Processuais ,","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1270","enunciado":"Ano: 2018 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal Substituto Sobre o ato de citação, é CORRETO afirmar:","a":"O gerente de filial ou agência presume-se autorizado pela pessoa jurídica estrangeira a receber citação para qualquer processo.","b":"Nos casos de litisconsórcio passivo necessário, o juiz de ofício determinará diretamente a citação de todos que devam","c":"ser litisconsortes. No caso de ação possessória em que figure no polo passivo grande número de pessoas, a citação será feita por edital.","d":"A procuração geral para o foro, salvo se previstos poderes especiais específicos, não habilita o advogado a receber citação, o que vale inclusive para a hipótese de reconvenção, por ter esta natureza jurídica de ação.","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q904792","enunciado":"Substituto Sobre a penhora é CORRETO afirmar:","a":"Poderá haver requerimento de substituição quando a penhora incidir sobre bens de baixa liquidez, exceto se observada a ordem legal de nomeação.","b":"Quando se tratar de ativos financeiros, a determinação de indisponibilidade que precede a conversão em penhora dar-se-á mediante prévia ciência do ato ao executado.","c":"No caso de penhora de crédito, se o terceiro negar o débito em conluio com o executado, a quitação dada pelo terceiro será considerada inválida perante o processo.","d":"A penhora de percentual de faturamento de empresa, segundo a lei, é medida subsidiária e será determinada se o executado não tiver outros bens penhoráveis ou se eles forem insuficientes ou de difícil alienação. Direito Processual Civil - Novo Código de Processo Civil - CPC 2015>Intervenção de Terceiro ,","e":"","gabarito":"D","materia":"Direito Processual Civil - Novo Código de Processo Civil - CPC 2015","tema":"Processo de Execução ,Da Execução em Geral","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1272","enunciado":"Ano: 2018 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal Substituto","a":"Sobre o incidente de desconsideração da personalidade jurídica é CORRETO afirmar que: Sua instauração impede atos de invasão patrimonial até que a questão sobre a desconsideração seja resolvida","b":"Se o pedido for acolhido, o marco considerado pela lei para eventual fraude de execução é o da citação da pessoa jurídica cuja personalidade se pretende desconsiderar.","c":"O julgamento favorável ao credor, pelo mérito do incidente, não impede que a pessoa jurídica cuja personalidade se busca desconsiderar rediscuta o mesmo tema pela via dos embargos de terceiro.","d":"Se a desconsideração for requerida na inicial, não haverá suspensão do processo e a questão deverá ser obrigatoriamente resolvida ao final da fase de conhecimento, pela sentença. Direito Processual Civil - Novo Código de Processo Civil - CPC 2015>Sujeitos da Relação Processual ,","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1273","enunciado":"Ano: 2018 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal Substituto Relativamente à gratuidade no processo civil, indique a afirmativa INCORRETA:","a":"Ela compreende, dentre outros, as taxas judiciais, os depósitos exigidos para interposição de recurso ou propositura de ação e, ainda, os honorários de perito e advocatícios, inclusive aqueles decorrentes da sucumbência.","b":"Sua concessão poderá ocorrer apenas em relação a algum dos atos processuais e poderá consistir em parcelamento de despesas.","c":"No caso de assistência por advogado particular, a gratuidade não abrange o preparo de recurso que verse exclusivamente sobre valor de honorários de sucumbência fixados em favor daquele primeiro.","d":"Quando houver recurso contra a decisão que a indeferir ou revogar, o recorrente estará dispensado do recolhimento de custas até decisão do relator sobre a questão, preliminarmente ao julgamento do recurso. Direito Processual Civil - Novo Código de Processo Civil - CPC 2015>Cumprimento de Sentença ,","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1274","enunciado":"Ano: 2018 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal Substituto","a":"No cumprimento de sentença, afigura-se CORRETO afirmar que: decisão judicial sujeita a recurso desprovido de efeito suspensivo poderá ser levada a protesto, depois de A transcorrido o prazo para pagamento.","b":"É título executivo judicial a decisão homologatória da autocomposição judicial, sendo que essa última pode versar relação jurídica que não tenha sido deduzida em juízo, desde que se limite aos sujeitos já presentes no processo.","c":"O cumprimento provisório, a ser realizado da mesma forma que o definitivo, corre por iniciativa e responsabilidade do exequente, e será iniciado mediante prestação de caução.","d":"Em se tratando de quantia certa, não ocorrendo o pagamento voluntário no prazo legal, o débito será acrescido de multa e de honorários advocatícios, ambos no percentual de dez por cento (10%) cada. Direito Processual Civil - Novo Código de Processo Civil - CPC 2015>Jurisdição ,","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1275","enunciado":"Ano: 2018 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal Substituto","a":"Sobre a jurisdição é CORRETO afirmar que: Ela é invariavelmente uma atividade estatal a cargo do Poder Judiciário.","b":"Seu escopo social é a pacificação mediante a eliminação dos conflitos.","c":"Seu escopo jurídico abrange a descoberta da verdade e a formação da coisa julgada material.","d":"Ela é sempre uma atividade voltada à atuação do direito objetivo em concreto.","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q904787","enunciado":"Substituto Sobre o pedido, como elemento da petição inicial, é CORRETO afirmar:","a":"Tratando-se de prestações sucessivas, elas se reputam incluídas independentemente de declaração do autor e serão abrangidas pela condenação as que se vencerem até julgamento em segundo grau de jurisdição.","b":"É lícito ao autor formular pedidos alternativos, para que o juiz conheça do posterior quando não puder acolher o anterior.","c":"É lícito ao autor cumular pedidos, desde que eles sejam compatíveis entre si, que haja uniformidade procedimental e","d":"que o juízo não seja relativamente incompetente para qualquer um dos pedidos. A interpretação do pedido deverá ocorrer no contexto geral da postulação. Direito Civil>Responsabilidade civil ,Responsabilidade Civil - Teorias, Espécies e Pressupostos. ,","e":"","gabarito":"D","materia":"Direito Processual Civil - Novo Código de Processo Civil - CPC 2015","tema":"Formação do Processo e Petição Inicial","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1277","enunciado":"Ano: 2018 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal Substituto Em tema de responsabilidade civil, é INCORRETO afirmar:","a":"O incapaz não responde por prejuízos que causar, exceto se os responsáveis por ele não tiverem a obrigação de fazê- lo ou se não dispuserem de meios suficientes.","b":"É do dono ou detentor do animal que causar dano o ônus de provar que o fato ocorreu por culpa da vítima ou força maior.","c":"É de cinco anos o prazo prescricional para a pretensão de restituição de valores pagos a título de comissão de corretagem ou de serviço de assistência técnico imobiliário.","d":"O dono do edifício ou construção responde por danos que decorrerem de sua ruína por falta de reparos cuja necessidade, segundo a lei, fosse manifesta.","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q904785","enunciado":"Substituto Em relação ao contrato de depósito voluntário, é CORRETO afirmar:","a":"O depositário poderá deixar de restituir a coisa, dentre outras razões, se houver motivo razoável para suspeitar que a coisa foi dolosamente obtida pelo depositante.","b":"O depositário poderá furtar-se à restituição da coisa se houver fundamento para alegar compensação, mesmo que essa última não se funde em outro contrato de depósito.","c":"Sendo dois ou mais depositantes e divisível a coisa depositada, o depositário só entregará a cada um a respectiva parte, ainda que entre eles haja solidariedade.","d":"A prova da existência do contrato pode ser feita exclusivamente por testemunhas, independentemente do respectivo valor.","e":"","gabarito":"A","materia":"Direito Civil","tema":"Contratos em Espécie ,Depósito, Mandato, Comissão, Agência e Distribuição","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q904784","enunciado":"Substituto","a":"É direito do credor hipotecário: Impedir que sobre o prédio hipotecado se constitua penhor rural.","b":"Sendo ele credor de segunda hipoteca, promover a execução sobre o imóvel mesmo antes de vencida a primeira, ainda que não seja insolvente o devedor.","c":"Celebrar hipoteca para garantia de dívida futura ou condicionada, ainda que não seja indicado o valor máximo do crédito a ser garantido.","d":"Sendo ele credor de hipoteca legal, exigir do devedor que reforce a garantia com outros bens, se demonstrar a insuficiência dos imóveis especializados. Direito Civil>Contratos em Espécie ,","e":"","gabarito":"D","materia":"Direito Civil","tema":"Direito das Coisas / Direitos Reais ,Direitos Reais de Garantia - Penhor, Anticrese e Hipoteca","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1280","enunciado":"Ano: 2018 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal Substituto","a":"Sobre o contrato de seguro, é INCORRETO afirmar: Ele será nulo se estipulado para garantia de risco proveniente de ato doloso do segurado ou do beneficiário.","b":"Se o segurado fizer declaração inexata ou omitir circunstância que possa influir na aceitação da proposta ou na taxa do prêmio, perderá o direito à garantia, mas nesse caso não ficará obrigado a pagar o prêmio vencido.","c":"No seguro de vida, o suicídio não é coberto nos dois primeiros anos de vigência do contrato, ressalvado o direito do beneficiário à devolução do montante da reserva técnica formada.","d":"Se o segurador expedir a apólice sabedor de que o risco que o contrato pretendia cobrir estava superado fica obrigado a pagar em dobro o prêmio estipulado. Direito Civil>Ato Jurídico, Fato Jurídico e Teoria Geral do Negócio Jurídico ,Parte Geral ,","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1281","enunciado":"Ano: 2018 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal Substituto Haverá simulação a gerar invalidade do negócio jurídico quando:","a":"Aquele que recebeu documento assinado com texto não escrito no todo ou em parte formá-lo ou completa-lo por si","b":"ou por meio de outrem, violando o pacto feito com o signatário. A parte alterar documento mediante a supressão ou interpolação unilateral de texto.","c":"O negócio aparentar conferir direitos a pessoas diversas às quais efetivamente eles se conferem.","d":"O ato envolver a transmissão gratuita de bens ou remissão de dívida quando já insolvente o devedor; ou a tal condição reduzido pelos referidos atos. Direito Civil>Contratos em Geral ,","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1282","enunciado":"Ano: 2018 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal Substituto Em matéria de extinção dos contratos é CORRETO afirmar:","a":"Considerando os postulados da boa-fé objetiva e da função social do contrato, é eventualmente possível, mesmo diante do inadimplemento, recusar-se a resolução do contrato pela invocação da teoria do substancial adimplemento.","b":"Na resolução do contrato por onerosidade excessiva, segundo a lei, os efeitos da sentença que a decretar retroagirão ao momento da ocorrência dos acontecimentos tidos por extraordinários e imprevisíveis.","c":"A resilição unilateral é vedada e deve ser juridicamente qualificada como violação do contrato a justificar sua resolução por justa causa.","d":"Não havendo no contrato expressa cláusula resolutiva, não há como presumir que exista disposição tácita de tal natureza.","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q904780","enunciado":"Substituto Em matéria de solidariedade, é INCORRETO afirmar:","a":"Se um dos credores solidários falecer, cada qual dos herdeiros só terá direito de exigir e receber a quota do crédito que corresponder ao seu quinhão, salvo se a obrigação for indivisível.","b":"Decisão judicial desfavorável a um dos credores solidários, ressalvada exceção pessoal que o devedor possa invocar em relação a qualquer daqueles, não pode prejudicar os demais.","c":"A propositura de demanda pelo credor somente em face de um ou de alguns dos devedores solidários configura renúncia tácita à solidariedade.","d":"Impossibilitando-se a prestação por culpa de um dos devedores solidários, só o culpado responderá por eventuais perdas e danos.","e":"","gabarito":"C","materia":"Direito Civil","tema":"Direito das Obrigações ,Modalidades de Obrigações","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q904779","enunciado":"Substituto","a":"Sobre as obrigações indivisíveis é CORRETO afirmar: A remissão da dívida por um dos credores não extingue a dívida para com os demais.","b":"A indivisibilidade e solidariedade são fenômenos iguais, na medida em que, se a prestação não for divisível e houver","c":"mais de um devedor, cada um será obrigado pela totalidade. Havendo mais de um credor, é vedado a apenas um deles receber a prestação por inteiro.","d":"Elas podem se configurar mesmo quando o objeto seja prestação consistente em fazer, e ainda que a obrigação de fazer posteriormente se resolva em perdas e danos.","e":"","gabarito":"A","materia":"Direito Civil","tema":"Direito das Obrigações ,Adimplemento, Modalidades de Pagamento e Extinção das Obrigações","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q904778","enunciado":"Substituto","a":"Sobre o mandato, é CORRETO afirmar que: O substabelecimento deve observar a mesma forma pela qual foi outorgado o mandato.","b":"Sem prévia e expressa concordância do mandante, é vedado ao mandatário reter, do objeto da operação que lhe foi cometida, valor suficiente para remunerar o que for devido por força do mandato.","c":"Havendo valores líquidos, o mandatário pode compensar os prejuízos a que deu causa com os proveitos que, por outro lado, tenha granjeado ao seu constituinte.","d":"É possível estabelecer a irrevogabilidade do mandato quando ela for condição de um negócio bilateral ou quando tiver sido estipulada no exclusivo interesse do mandatário. Legislação Federal>","e":"","gabarito":"D","materia":"Direito Civil","tema":"Contratos em Espécie ,Depósito, Mandato, Comissão, Agência e Distribuição","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1286","enunciado":"Ano: 2018 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal Substituto Segundo entendimento do Superior Tribunal de Justiça a respeito dos contratos do Sistema Financeiro da Habitação, é CORRETO afirmar que:","a":"As normas do Código de Defesa do Consumidor são aplicáveis a todos os contratos relacionados ao Sistema Financeiro da Habitação, independentemente da data de sua celebração.","b":"Nos contratos de seguro habitacional obrigatório no âmbito do Sistema Financeiro da Habitação, as seguradoras não são responsáveis pelos vícios decorrentes da construção.","c":"Não é admitida a cobrança do Coeficiente de Equivalência Salarial – CES – em contratos vinculados ao Sistema Financeiro da Habitação, ainda que exista expressa previsão contratual.","d":"O mutuário do Sistema Financeiro da Habitação não pode ser compelido a contratar seguro habitacional obrigatório com a instituição financeira mutuante ou com a seguradora por ela indicada. Direito Econômico>O Sistema Brasileiro de Defesa da Concorrência e a Lei nº 12.529 de 2011 ,","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q904775","enunciado":"Ano: 2018 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal Substituto","a":"Assinale a alternativa CORRETA: patente garante a seu detentor a inexistência de concorrência eventualmente oferecida por quaisquer produtos que A","b":"satisfaçam a mesma necessidade do consumidor. O CADE pode anular patentes em caso de abuso de posição dominante por parte de seu detentor.","c":"O mero paralelismo consciente dos preços entre agentes econômicos é insuficiente para comprovar a existência de um cartel.","d":"A jurisprudência administrativa do CADE é no sentido de condenar empresas por aumento arbitrário de lucros, no caso de abuso do direito de propriedade intelectual. Direito Econômico>O Sistema Brasileiro de Defesa da Concorrência e a Lei nº 12.529 de 2011 , Aspectos Gerais da Concorrência no Direito Econômico ,","e":"","gabarito":"C","materia":"Aspectos Gerais da Concorrência no Direito Econômico","tema":"","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1288","enunciado":"Soluções Consensuais de Conflitos: Acordo de Leniência, Compromisso de Cessação e Acordos em Controle de Concentraçã Ano: 2018 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal Substituto","a":"Assinale a alternativa CORRETA: Maiores os custos de transação em um mercado, maior o grau de dependência econômica nele existente.","b":"A celebração de acordos verticais tende a diminuir os custos de transação a serem incorridos pelos agentes econômicos partícipes.","c":"Os contratos de distribuição celebrados entre empresas ou grupos de empresas com faturamento superior a R$ 200","d":"milhões de reais devem ser submetidos à apreciação do CADE. Para a Escola de Chicago, cartel e preço predatório são as práticas antitruste mais nocivas à sociedade. Direito Econômico>O Sistema Brasileiro de Defesa da Concorrência e a Lei nº 12.529 de 2011 ,","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q904773","enunciado":"Ano: 2018 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","a":"Substituto fornecedora “A” escoa sua produção por meio de uma rede de distribuidores [rede “A”]. Em uma licitação, um dos distribuidores [“X”] celebra acordo com outros licitantes, não integrantes da rede “A”, e sagra-se vencedor do certame. Posteriormente, “X” é condenado pelo CADE, por participação em cartel, com base na Lei nº 12.529, de 2011. Assinale a alternativa CORRETA: \"A” é solidariamente responsável pela infração à ordem econômica cometida por “X”, mesmo sem ter participado do A acordo com os outros licitantes. A responsabilidade de “A”, no caso, é objetiva.","b":"Outro membro da rede “A” possui legitimidade para propor ação civil de reparação de danos contra “X”, por","c":"descumprimento do contrato existente entre “X” e “A”. A decisão do CADE não pode ser revista pelo Poder Judiciário.","d":"Mesmo antes de ser proferida a decisão do CADE reconhecendo a existência de infração à ordem econômica, os prejudicados podem propor ação de indenização contra X.","e":"","gabarito":"D","materia":"Infrações da Ordem Econômica e Penalidades","tema":"","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q904772","enunciado":"Substituto Relativamente à prova testemunhal, assinale a alternativa que contém uma afirmação CORRETA:","a":"Estão proibidas de depor as pessoas que, em razão de sua função, ministério, ofício ou profissão, devam guardar segredo, salvo se, desobrigadas pela parte interessada, quiserem dar seu depoimento.","b":"No rito comum ordinário e na primeira fase do júri, serão ouvidas no máximo oito testemunhas por fato criminoso; no rito sumário, serão ouvidas até cinco testemunhas e, no rito sumaríssimo e na segunda fase do júri, serão inquiridas no máximo três testemunhas por fato criminoso.","c":"Não serão computados, para fins de estabelecimento de oitiva de testemunhas, exclusivamente o ofendido e aqueles que não prestarem compromisso.","d":"Poderão recusar-se a depor os ascendentes, descendentes e afins em linha reta, salvo quando não for possível, por outro meio, obter-se a prova do fato e suas circunstâncias, sendo que, se optarem por prestar depoimento, prestarão compromisso de dizer a verdade.","e":"","gabarito":"A","materia":"Direito Processual Penal","tema":"Das Provas ,Prova testemunhal","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q904770","enunciado":"Substituto Relativamente à interceptação de comunicações telefônicas, de qualquer natureza, para prova em investigação criminal e em instrução processual penal, assinale a alternativa que contém uma afirmação CORRETA:","a":"Somente pode ser deferida a requerimento do Ministério Público, em qualquer fase da investigação policial ou na","b":"instrução processual penal. É admissível para a investigação de qualquer tipo de infração penal.","c":"Não poderá ser deferida se não houver indícios razoáveis da autoria ou participação em infração penal.","d":"Será deferida, ainda que a prova possa ser feita por outros meios disponíveis.","e":"","gabarito":"C","materia":"Direito Processual Penal","tema":"Lei da Interceptação Telefônica - Lei nº 9.296 de 1996","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q904769","enunciado":"Substituto","a":"Relativamente à colaboração premiada prevista na Lei nº 12.850/2013, é CORRETO afirmar que: É expressamente prevista como meio de obtenção da prova, em qualquer fase da persecução penal.","b":"Pode ser concedida pelo juiz de ofício ou por requerimento do Ministério Público.","c":"A personalidade do colaborador constitui requisito de validade do acordo de colaboração.","d":"A revelação da estrutura hierárquica e da divisão de tarefas da organização criminosa é sempre necessária para que haja o acordo de colaboração. Direito Processual Penal>","e":"","gabarito":"A","materia":"Direito Processual Penal","tema":"Lei de Organização Criminosa – Lei nº 12.850 de 2013","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q904767","enunciado":"Ano: 2018 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal Substituto Relativamente aos crimes de menor potencial ofensivo (Lei nº 9.099/1995 e Lei nº 10.259/2001), é INCORRETO afirmar que:","a":"Se o órgão do Ministério Público, na ação penal pública incondicionada, não oferecer proposta de transação penal, o juiz poderá fazê-lo, propondo ao autor do fato a imediata aplicação de multa ou pena restritiva de direitos.","b":"Os institutos despenalizantes de que trata a Lei nº 9.099/1995 e a Lei nº 10.259/2001 são aplicáveis às autoridades que gozam de prerrogativa de foro.","c":"A Lei nº 9.099/1995 não é aplicável no âmbito da Justiça Militar nem nos casos que envolvam violência doméstica ou familiar contra a mulher.","d":"Consideram-se infrações de menor potencial ofensivo, no âmbito da Justiça Federal, aquelas a que a lei comine pena máxima não superior a dois anos, cumuladas ou não com multa, exceto as contravenções penais.","e":"","gabarito":"A","materia":"Procedimento comum sumaríssimo - Lei nº 9.099 de 1995 - Lei dos Juizados Especiais Criminais - JECRIM","tema":"","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q904766","enunciado":"Substituto","a":"Assinale a alternativa CORRETA: O processo e julgamento do crime de lavagem de dinheiro prescinde da existência da infração penal antecedente.","b":"O crime de lavagem de dinheiro caracteriza-se pela ocorrência de crime antecedente expressamente previsto na lei","c":"específica. O processo de lavagem de dinheiro é composto por, pelo menos, três fases: ocultação, dissimulação e integração.","d":"A legislação brasileira exige a completude do ciclo de lavagem para que se caracterize o crime de lavagem de capitais.","e":"","gabarito":"C","materia":"Direito Penal","tema":"Lei da Lavagem de Dinheiro - Lei nº 9.613 de 1998 ,Legislação Penal Especial","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q904765","enunciado":"Substituto Durante o julgamento da Ação Penal nº 470 (“Mensalão”), a teoria do domínio do fato foi mencionada diversas vezes. Relativamente a essa teoria, leia as afirmações abaixo e, ao final, indique a alternativa CORRETA: I. Foi retomada e desenvolvida pelo jurista alemão Claus Roxin, na década de 1960, e tem por função dogmática distinguir entre autor e partícipe. II. A ideia reitora dessa teoria é de que autor é quem atua com o domínio do fato; é a figura central do acontecer típico. III. Foi adotada pelo Código Penal brasileiro ao dispor que quem, de qualquer modo, concorre para o crime incide nas penas a este cominadas, na medida de sua culpabilidade. IV. Segundo essa teoria, domínio do fato é o","a":"poder de evitar o fato. Assim, o chefe de uma organização criminosa responde pela mera posição. Apenas as afirmações I e III estão certas.","b":"Apenas as afirmações I e II estão certas.","c":"Apenas as afirmações II e IV estão certas.","d":"Apenas as afirmações III e IV estão certas.","e":"","gabarito":"B","materia":"Direito Penal","tema":"Concurso de Pessoas ,Noções gerais de Concursos de Pessoas ,Autoria e coautoriaParticipação","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q904763","enunciado":"Substituto","a":"De acordo com a jurisprudência sumulada do Superior Tribunal de Justiça: O princípio da insignificância é aplicável aos crimes cometidos contra a Administração Pública.","b":"Não é possível o agravamento da pena-base nos delitos praticados contra a Administração Pública com fundamento","c":"no elevado prejuízo causado aos cofres públicos. A elementar do crime de peculato não se comunica aos coautores e partícipes estranhos ao serviço público.","d":"A notificação do funcionário público, nos termos do art. 514 do Código de Processo Penal, não é necessária quando a ação penal for precedida de inquérito policial.","e":"","gabarito":"D","materia":"Direito Penal","tema":"Crimes contra a administração pública ,Noções Gerais de Crimes Contra a Administração Pública","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q904762","enunciado":"Substituto Leia as afirmações abaixo e, ao final, indique a alternativa CORRETA: I. O crime somente se consuma quando nele se reúnem todos os elementos de sua definição legal. II. O agente que, voluntariamente, desiste de prosseguir na execução do crime não responde pelos atos já praticados. III. A tentativa não é punível quando o crime não se consuma por ineficácia absoluta do meio ou por absoluta impropriedade do objeto.","a":"IV. O erro sobre a identidade da pessoa contra a qual o crime é praticado isenta de pena o agente, se o erro é inevitável. Apenas as afirmações III e IV estão certas.","b":"Apenas as afirmações I e II estão certas.","c":"Apenas as afirmações I e III estão certas.","d":"Apenas as afirmações II e IV estão certas.","e":"","gabarito":"C","materia":"Direito Penal","tema":"Tipicidade ,Conduta: ação / omissão ,ResultadoNexo de causalidade ,Consumação e tentativa","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q904761","enunciado":"Substituto","a":"Relativamente ao crime de redução a condição análoga à de escravo, assinale a alternativa INCORRETA: competência para processar e julgar quem comete esse crime é da Justiça Federal, caracterizando-se o delito por ser A do tipo misto alternativo.","b":"Não se restringe à área rural ou a locais longínquos, podendo ocorrer em área urbana, atividade industrial ou mesmo no trabalho doméstico.","c":"Caracteriza-se por ser a vítima submetida a trabalhos forçados ou a jornada exaustiva, bem como sujeita a condições degradantes de trabalho, restringindo-se, por qualquer meio, sua locomoção, em razão de dívida contraída com o empregador.","d":"Se a vítima é criança, adolescente, idoso ou pessoa com deficiência ou se o crime é cometido por motivo de preconceito de raça, cor, etnia, religião ou origem, a pena é aumentada de 1/3 (um terço). Direito Penal>Penas privativas de liberdade ,Noções gerais de dosimetria da pena privativa de liberdade ,","e":"","gabarito":"D","materia":"Direito Penal","tema":"Crimes contra a liberdade pessoal ,Redução à condição análoga à de escravo","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1299","enunciado":"Ano: 2018 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal Substituto José da Silva, réu primário e com condenações criminais anteriores, porém sem trânsito em julgado, confesso, cometeu crime de estelionato contra a Previdência Social, causando prejuízos significativos à autarquia, sendo condenado à pena de 1 (um) ano e 4 (quatro) meses de reclusão e 13 (treze) dias-multa, em regime inicial aberto. Com base nessas informações, é CORRETO afirmar:","a":"Ainda que primário, o juiz poderia ter aumentado a pena-base ante as circunstâncias judiciais desfavoráveis (CP, art. 59), sopesando, para tanto, os antecedentes criminais e as consequências do delito.","b":"A causa de aumento prevista no art. 171, § 3º, do Código Penal é aplicável ao caso por se tratar o ofendido de entidade de direito público, sendo a fração de aumento sempre fixa, em 1/3 (um terço).","c":"Se o juiz entender possível, a substituição da pena privativa de liberdade aplicada (CP, art. 44) poderá ser feita por uma pena de multa ou uma pena restritiva de direitos.","d":"A confissão do acusado não poderá ser levada em consideração na dosimetria da pena se for alegada alguma causa excludente de antijuridicidade ou culpabilidade (confissão qualificada).","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q904757","enunciado":"Substituto Assinale a alternativa CORRETA: Tramitando determinada demanda previdenciária nos Juizados Especiais Federais e se fazendo necessária a realização","a":"de prova técnica para o deslinde da controvérsia, se, após a apresentação do laudo médico, as partes controverterem sobre as conclusões científicas do perito nomeado, deverá o Juízo declinar da competência para processo e julgamento do feito para a vara federal comum, sob o argumento da complexidade da matéria envolvida. Tramitando determinada demanda previdenciária nos Juizados Especiais Federais, após a prolação de sentença de","b":"improcedência que se fundou em laudo médico, na análise do recurso contra ela interposto, poderá monocraticamente o relator, na Turma Recursal, ao não se sentir suficientemente esclarecido pelas conclusões do perito, determinar a realização de nova perícia, sem, entretanto, anular o julgado, com fundamento na aplicação subsidiária do disposto no CPC.","c":"Tramitando determinada demanda previdenciária nos Juizados Especiais Federais, após a realização de perícia médica que concluiu contrariamente ao alegado pelo autor, é direito subjetivo seu a realização de novo exame técnico, de forma a subsidiar o deslinde da controvérsia. Tramitando determinada demanda previdenciária nos Juizados Especiais Federais e havendo a condenação do INSS na","d":"implantação de determinado benefício e no pagamento dos valores atrasados é possível, se apurado que o valor devido supera os 60 (sessenta) salários mínimos, que o exequente opte pela expedição de RPV no valor do limite máximo e pela expedição de precatório dito complementar para pagamento do montante excedente. Direito Previdenciário>Benefícios em Espécie ,Aposentadoria por Idade ,Salário-MaternidadeAuxílio-Reclusão ,","e":"","gabarito":"B","materia":"Direito Processual Civil - Novo Código de Processo Civil - CPC 2015","tema":"Juizado Especial ,Juizado Especial Federal","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1301","enunciado":"Ano: 2018 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal Substituto Pode-se dizer que o equilíbrio financeiro e atuarial do sistema previdenciário será violado, eis que descreve hipótese não abarcada pelo ordenamento jurídico, pela:","a":"Concessão de pensão por morte ao filho não emancipado e menor de 21 (vinte e um) anos, do trabalhador que falece 2 (dois) dias depois de ter iniciado contrato de trabalho válido, mas ainda não registrado em CTPS.","b":"Concessão de auxílio-reclusão, devido à prisão do segurado de baixa renda, aos seus dependentes, mesmo que tenham quem lhes proveja o sustento ou possam trabalhar como forma de obtê-lo.","c":"Concessão de aposentadoria por idade ao produtor rural que todo mês, além de extrair o próprio sustento da atividade agropecuária exercida, comercializa significativo excedente da produção, mas deixa de recolher sobre esse valor as contribuições devidas ao RGPS.","d":"Concessão subsequente de salário-maternidade, sendo o primeiro à trabalhadora e mãe biológica do recém-nascido e que 1 (um) ano depois seja judicialmente destituída do pátrio poder; e o segundo à trabalhadora que vier a adotar esta criança, após a conclusão do procedimento de adoção.","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q904754","enunciado":"Substituto Em relação à pensão por morte é CORRETO afirmar que:","a":"É devida ao filho de qualquer condição, não emancipado e menor de 21 (vinte e um) anos ou de até 23 (vinte e três) anos, desde que comprove documentalmente estar cursando o ensino médio ou superior em instituição reconhecida pelo Ministério da Educação ou inválido ou que tenha deficiência intelectual ou mental ou deficiência grave.","b":"É devida, em igualdade de condições, ao companheiro homoafetivo do segurado e que com ele convivia no momento do falecimento, cuja dependência econômica é presumida, e à ex-esposa que dele dependia economicamente, porque beneficiária de pensão alimentícia fixada no acordo de separação.","c":"É devida aos pais do segurado falecido, maiores de 65 (sessenta e cinco) anos, sem fonte própria de renda, cuja dependência econômica, em razão disso, é presumida juris tantum.","d":"É devida à pessoa menor de 21 (vinte e um) anos ou maior de 60 (sessenta), desde que em condição de abandono, ou inválida ou que tenha deficiência intelectual ou mental ou deficiência grave, previamente designada como dependente econômico pelo segurado falecido. Direito Constitucional>Controle de Constitucionalidade ,","e":"","gabarito":"B","materia":"Direito Previdenciário","tema":"Benefícios em Espécie ,Pensão por Morte","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1303","enunciado":"Ano: 2018 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal Substituto O parâmetro do controle de constitucionalidade é encontrado na Constituição Federal, havendo tendência jurisprudencial e doutrinária no sentido de ampliação desse parâmetro a partir do conceito de “bloco de constitucionalidade”. Já o objeto da ADI genérica é norma veiculada por lei ou ato normativo que se mostre em confronto com o parâmetro. Sob essa ótica, é CORRETO afirmar que:","a":"Apenas admite-se o controle de constitucionalidade de Proposta de Emenda à Constituição (PEC) e de projeto de lei quando estes forem manifestamente ofensivos a cláusula pétrea ou violem procedimento formal previsto na Constituição para sua elaboração.","b":"Configura usurpação de competência do STF a tramitação de arguição de inconstitucionalidade (art. 948 do CPC) que tenha por objeto o mesmo dispositivo legal cuja validade esteja sendo discutida em sede de ADI na Suprema Corte.","c":"A Convenção sobre os Direitos das Pessoas com Deficiência e seu Protocolo Facultativo (Nova York, 2007), promulgada pelo Decreto nº 6.949/2009, faz parte do conceito de bloco de constitucionalidade.","d":"É admissível, conforme entendimento do STF, a tramitação de ADI que tenha por objeto norma declarada constitucional, em sede recurso extraordinário, pelo Plenário da Corte, dado o efeito inter partes da decisão prolatada em controle difuso.","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q904749","enunciado":"Substituto “Sob a inspiração do ideal liberal-individualista, esse ORGANISMO INTERNACIONAL tem salvaguardado o valor da liberdade e sua projeção na esfera privada e familiar, afirmando o direito de todo e qualquer indivíduo de desenvolver sua personalidade. Com base no princípio da proporcionalidade, tem invalidado interferências estatais abusivas. Ao proteger de forma indireta os direitos sociais, tem entendido que o direito à vida privada requer não apenas obrigações negativas do Estado, mas ainda prestações positivas, condenando a omissão estatal quando afronta o direito à vida privada – por exemplo degradação ambiental causada por empresa. Referida INSTITUIÇÃO é movida pelo respeito à vida privada e pelo ideal liberal-individualista como princípios basilares (cf. Flavia Piovesan, “Direitos Humanos e Justiça Internacional”, 7. ed., p.","a":"212, ADAPTADA). Assinale a INSTITUIÇÃO a que o texto acima se refere: Comissão Interamericana de Direitos Humanos.","b":"Corte Europeia de Direitos Humanos.","c":"Tribunal Penal Internacional.","d":"Corte Interamericana de Direitos Humanos. Direitos Humanos>Direitos Humanos no Ordenamento Nacional ,","e":"","gabarito":"B","materia":"Direitos Humanos","tema":"Sistema Europeu de Direitos Humanos","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1305","enunciado":"Ano: 2018 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal Substituto “(...) a União, na qualidade de ente federado com personalidade jurídica na esfera internacional, quem tem o poder de contrair obrigações jurídicas internacionais em matéria de direitos humanos, mediante ratificação de tratados. Consequentemente, a sistemática de monitoramento e fiscalização de tais obrigações recai na pessoa jurídica da União. Deste modo, por coerência, há de caber à União a responsabilidade para apurar, processar e julgar casos de violação de direitos humanos (...)” (extraído do Boletim dos Procuradores da República nº 14, junho 1999). Sob esse enfoque, a reforma constitucional de 2004 trouxe importante contribuição e pode-se julgar CORRETO que:","a":"De acordo com a jurisprudência do STJ, a ocorrência de grave violação a direitos humanos ocasiona ipso jure o acolhimento do Incidente de Deslocamento de Competência (IDC) para a Justiça Federal, suscitado pelo Procurador Geral da República.","b":"A primeira federalização de grave violação de direitos humanos deu-se no caso do homicídio do defensor de direitos humanos Manoel Mattos.","c":"A introdução do IDC pela Emenda Constitucional nº 45, de 2004, foi relevante por criar o único instrumento que possibilita à União cumprir, no plano interno, suas obrigações internacionais de defesa dos direitos humanos.","d":"No caso Dorothy Stang, o incidente foi acolhido pelo STJ por somar-se à grave violação dos direitos humanos, decorrente do assassinato da religiosa, a inércia das autoridades estaduais em processar e punir os autores do crime. Direito Constitucional>Teoria da Constituição ,Ordem Social ,Constitucionalismo","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1306","enunciado":"Ano: 2018 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal Substituto Um novo paradigma para o constitucionalismo surgiu entre o final do século XX e o início do século XXI. Procura ser uma resposta teórico-prática para a necessidade de se obterem eficácia e efetividade para as normas constitucionais, sobretudo as portadoras de direitos sociais. Implanta, no Brasil, modelo normativo-axiológico, com adoção expressa de valores e opções pela efetivação de políticas públicas com sede constitucional. Muitas destas bastante específicas, como os serviços de saúde, educação e assistência social a hipossuficientes. Esse paradigma constitucional possui algumas notas típicas,","a":"dentre as quais NÃO se encontram: Separação conceitual entre o direito constitucional e a moralidade política.","b":"Tendência a integração das diversas esferas da razão prática para solução dos casos constitucionais: o direito, a moral e a política.","c":"Compreensão da constitucionalidade enquanto critério último de validade das normas, em termos substantivos e não apenas formais.","d":"Os direitos constitucionais incorporam uma ordem objetiva de valores. Esses direitos e valores tornam-se onipresentes com “efeito irradiante” sobre os demais ramos do direito. Direito Constitucional>Poder Legislativo ,","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1307","enunciado":"Ano: 2018 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","a":"Substituto par das funções representativa e legislativa, o Congresso Nacional recebeu do Constituinte atribuições investigativas. Estas manifestam-se na esfera político-administrativa por meio de Comissões Parlamentares de Inquérito (CPIs). A respeito desses órgãos é CORRETO dizer que: A CPI deverá ter prazo certo, podendo deliberar, em face de razões de interesse público, devidamente A fundamentadas, sua prorrogação para além do termo final da legislatura em que foi constituída.","b":"Havendo provas de autoria e da ocorrência de ilícito penal, poderá a CPI, por decisão justificada, determinar a realização de medidas cautelares assecuratórias para garantir a eficácia de eventual futura condenação criminal.","c":"Embora sejam as CPIs limitadas constitucionalmente pela competência, conteúdo e matéria da investigação político- administrativa, em nome da separação dos poderes, não se lhes aplica o princípio da reserva constitucional de jurisdição.","d":"As CPIs podem, sem a necessidade de intervenção judicial, por decisão fundamentada, determinar quebra de sigilo fiscal, bancário e de dados.","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q904745","enunciado":"","a":"Substituto Constituição brasileira possui uma plêiade de princípios, muitos deles em conflito em casos concretos. Há vetores interpretativos que auxiliam o juiz no trabalho de construção da decisão. Um desses vetores da hermenêutica contemporânea (v.g., Canotilho) tem campo de atuação em hipóteses de colisão entre direitos fundamentais, sendo que subjacente a este princípio está a ideia de igual valor dos bens constitucionais que impede, como solução, o sacrifício de uns em relação aos outros e impõe condicionantes recíprocas. Esse vetor traduz o princípio da:","b":"A Concordância prática. Máxima efetividade.","c":"Correção funcional.","d":"Interpretação. Direitos Humanos>Sistema Interamericano de Proteção aos Direitos Humanos: Instituições ,","e":"","gabarito":"A","materia":"Direito Constitucional","tema":"Princípios de Interpretação Constitucional ,Teoria da Constituição","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1309","enunciado":"Ano: 2018 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","a":"Substituto narrativa dos direitos humanos tem sido no sentido de ampliar sua proteção. A esse respeito, “o termo interseccionalidade foi criado por Kimberle Crenshaw para retratar a incidência dos mais diversos fatores de discriminação em um caso concreto. Tal necessidade foi verificada a partir do momento em que o caráter universal dos direitos humanos mostrou-se insuficiente para tutelar e salvaguardar os direitos humanos” (cf. Caio Cezar Paiva e Thimotie A. Heemann, “Jurisprudência Internacional de Direitos Humanos”, 2. ed., 2017, p. 587). Fatores de discriminação não resolvidos, ou quando enfrentados de forma desconexa, se entrelaçam, aumentando a opressão em grandeza exponencial. Foi o que ocorreu com a violação de direitos de mulher refugiada, negra, pobre, analfabeta, homossexual e com a filha portadora de HIV, a quem foi negado pelo Estado o direito à educação. Ao apreciar essa situação, o Sistema Interamericano de Direitos Humanos reconheceu pela primeira fez o fenômeno da interseccionalidade. Trata-se do julgamento do caso:","b":"A Tereza de La Cruz Flore vs. Peru. Gonzalez Lluy vs. Equador.","c":"Cosme Rosa Genoveva vs. Brasil.","d":"Loayza Tamayo vs. Peru. Direitos Humanos>Sistema Interamericano de Proteção aos Direitos Humanos: Instituições ,","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1310","enunciado":"Ano: 2018 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal Substituto Em 1999, Damião Ximenes Lopes, pessoa com deficiência mental, foi internado na Casa de Repouso Guararapes, na cidade de Sobral (CE), pelo Sistema Único de Saúde (SUS), em perfeito estado físico. Poucos dias depois, sua mãe o encontrou agonizante, sangrando, com hematomas, sujo e com as mãos amarradas para trás, vindo a falecer nesse mesmo dia, sem qualquer assistência médica no momento de sua morte. Com a demora nos processos cível e criminal na Justiça daquele Estado na apuração de responsabilidades, a família, alegando violação do direito à vida, à integridade psíquica (dos familiares, pela ausência de punição aos autores do homicídio) e ao devido processo legal em prazo razoável, peticionou à Comissão Interamericana de Direitos Humanos (CIDH), que veio a processar o Estado brasileiro perante a Corte Interamericana de Direitos Humanos (Corte IDH). Com relação a esse caso, é CORRETO afirmar que:","a":"Em face do caráter subsidiário da jurisdição internacional, foi acolhida exceção de admissibilidade por ausência de esgotamento dos recursos internos, oposta pelo Estado brasileiro, tendo sido determinada pela Corte IDH a suspensão do feito até o exaurimento dos mecanismos internos de reparação.","b":"A forma federativa do Estado brasileiro justificou a condenação do Estado do Ceará em litisconsórcio passivo com a União.","c":"Foi aplicada pela Corte IDH a doutrina da eficácia horizontal da proteção internacional dos direitos humanos (“Drittwirkung”), responsabilizando o Estado brasileiro.","d":"Petição dos familiares da vítima endereçada à Corte IDH, após o trâmite regular em que se afastou as preliminares do Brasil de ausência de esgotamento dos recursos internos e denunciação à lide ao Ceará, foi acolhida com condenação da União.","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2018 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2018","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q631068","enunciado":"Geral Pacientes com hiperuricemia crônica desenvolvem com frequência manifestações clínicas características de gota, NÃO","a":"sendo parte delas a ocorrência de episódios recorrentes de deposição intra-articular de cristais.","b":"insuficiência renal aguda.","c":"nefrolitíase.","d":"artropatia crônica.","e":"depósitos nodulares de cristais em bainhas tendíneas.","gabarito":"B","materia":"Medicina","tema":"Doenças Reumatológicas e do Sistema Imunológico","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Medicina - Clínica","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q631067","enunciado":"Geral Uma mulher de 28 anos, previamente hígida, vem apresentando astenia, queda de cabelo e dores articulares, às vezes com sinais inflamatórios, em grandes e pequenas articulações, de forma recorrente, há 4 meses. Foram solicitados exames laboratoriais que revelaram discreta leucopenia, aumento da velocidade de hemossedimentação e FAN positivo. O médico decide solicitar a dosagem de outros autoanticorpos diante da suspeita de lúpus eritematoso sistêmico. São mais","a":"específicos para o diagnóstico dessa afecção os anticorpos: anti-DNA nativo e anti-peptídeo citrulinado cíclico.","b":"anti-RNP e anti-La/SSB.","c":"anti-Ro/SSA e anti La/SSB.","d":"anti-Sm e anti-fosfolípide.","e":"anti-DNA dupla hélice e anti-Sm.","gabarito":"E","materia":"Medicina","tema":"Doenças Reumatológicas e do Sistema Imunológico","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Medicina - Clínica","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q631066","enunciado":"Geral Uma mulher de 32 anos apresenta disúria e polaciúria há 1 dia. O exame clínico e o ginecológico são normais. O exame do sedimento urinário mostra 600 000 leucócitos/mL e a coloração pelo Gram mostra flora bacteriana ausente. A cultura de","a":"urina é negativa. A paciente nega uso de antibióticos recentemente. Esses achados levantam forte suspeita de uretrite asséptica.","b":"gonorreia.","c":"infecção por clamídia.","d":"tricomoníase.","e":"tuberculose do trato urinário.","gabarito":"C","materia":"Medicina","tema":"Ginecologia e Obstetrícia","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Medicina - Clínica","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q631065","enunciado":"Geral Um homem de 36 anos, com história de alcoolismo grave, é levado ao pronto socorro com agitação, tremores e sudorese intensos. Estava em casa, há 2 dias, em repouso por ter fraturado o pé em uma queda acidental. Apresenta desidratação, agitação e alucinações visuais, taquipneia, T = 37,7° C, pulso = 120 bat/min, PA = 128 × 68 mmHg, saturação O2 = 96%, com exame do coração, pulmões e abdome normais; sem déficits motores, sem rigidez de nuca e com asterix não obtido. Concomitante à restauração da volemia, a melhor opção para tratamento da agitação consiste na administração","a":"intravenosa de betabloqueador.","b":"haloperidol.","c":"fenobarbital.","d":"benzodiazepínico.","e":"risperidona.","gabarito":"D","materia":"Psiquiatria","tema":"Transtornos Relacionados a Substâncias ,Psicofarmacologia","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Medicina - Clínica","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q631064","enunciado":"Geral Um homem de 40 anos obeso, em tratamento de hipertensão leve, necessitou, nos últimos 30 dias, ser encaminhado, por 4 vezes, do trabalho para o pronto atendimento por apresentar dor precordial em aperto, com grande mal estar e sensação de morte iminente. Em todas as vezes foi dispensado, após a realização de ECG, exames laboratoriais e de imagem normais e orientado a procurar “ajuda psicológica”. Várias drogas têm mostrado eficácia no tratamento medicamentoso desse tipo","a":"de distúrbio. Resultados NEGATIVOS, no entanto, foram demonstrados com o emprego de inibidores da recaptação de serotonina-norepinefrina.","b":"anticonvulsivantes.","c":"antidepressivos tricíclicos.","d":"inibidores seletivos de recaptação da serotonina.","e":"benzodiazepínicos.","gabarito":"B","materia":"Medicina","tema":"Cardiologia e Alterações Vasculares","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Medicina - Clínica","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q631063","enunciado":"Geral No tratamento de pacientes com vertigem, as manobras que visam o reposicionamento de debris nos canais semicirculares","a":"podem ser úteis nos casos em que o diagnóstico é de neuronite vestibular.","b":"labirintite aguda.","c":"vertigem posicional paroxística benigna.","d":"síndrome de Menière.","e":"fístula perilinfática.","gabarito":"C","materia":"Medicina","tema":"Otorrinolaringologia","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Medicina - Clínica","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q631062","enunciado":"Geral É papel do médico promover no ambiente de trabalho a conscientização sobre prevenção de doenças. Na área oftalmológica, por exemplo, é importante orientar medidas preventivas, sabendo-se que no Brasil a principal causa de","a":"cegueira irreversível em adultos é degeneração macular.","b":"trauma ocular.","c":"retinopatia diabética.","d":"catarata.","e":"glaucoma.","gabarito":"E","materia":"Medicina","tema":"Oftalmologia","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Medicina - Clínica","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q631061","enunciado":"Geral O suporte terapêutico principal no manuseio dos pacientes portadores de doença pulmonar obstrutiva crônica, fora das","a":"crises de exacerbação, deve se basear no emprego de algumas medicações, EXCETO prednisona.","b":"teofilina.","c":"tiotrópio.","d":"formoterol.","e":"ipatrópio.","gabarito":"A","materia":"Medicina","tema":"Pneumologia","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Medicina - Clínica","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q631060","enunciado":"Geral","a":"Provas de função pulmonar em pacientes portadores de doença pulmonar obstrutiva crônica sintomática apresentam aumento da capacidade de difusão de CO, principalmente quando há predomínio de enfisema.","b":"volume expiratório forçado no 1° segundo pelo menos entre 70 e 80% do esperado.","c":"diminuição do volume pulmonar residual.","d":"aumento da capacidade pulmonar total.","e":"relação volume expiratório forçado no 1° segundo/capacidade vital forçada ao menos entre 70 e 80% do esperado.","gabarito":"D","materia":"Medicina","tema":"Pneumologia","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Medicina - Clínica","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q631059","enunciado":"Geral Um homem de 45 anos é internado por insuficiência cardíaca. A avaliação diagnóstica é de descompensação por uso irregular da medicação habitual: furosemida, espironolactona, carvedilol e captopril. Apresenta na radiografia de tórax aumento de área cardíaca, sinais de congestão pulmonar e derrame pleural moderado bilateral. Recebe furosemida IV e reconciliação da medicação habitual, com melhora parcial. No terceiro dia, como ainda estava desconfortável do ponto de vista respiratório, é realizada punção aliviadora do derrame pleural. A análise do fluido pleural mostra DHL 52% do limite superior sérico, relação DHL do líquido pleural/DHL sérico 0,56, relação da proteína total do líquido pleural/proteína total 3 sérica 0,52, presença de 8000 leucócitos/mm , com 54% linfócitos e células mesoteliais 8%, com bacterioscópico e cultura","a":"negativos. A causa mais provável do derrame pleural é insuficiência cardíaca.","b":"tuberculose pleural.","c":"tromboembolismo pulmonar.","d":"pneumonia.","e":"câncer.","gabarito":"A","materia":"Medicina","tema":"Pneumologia","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Medicina - Clínica","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q631058","enunciado":"Geral Considere, abaixo, 3 diferentes pacientes com pneumonia. 1. diagnóstico feito após 48 horas internado em unidade semi-intensiva por síndrome coronária aguda. 2. história de internação hospitalar por 2 dias para colecistectomia por colecistite aguda, há 70 dias. 3. quimioterapia endovenosa há 45 dias em clínica especializada. Para efeito de antibioticoterapia empírica devem ser considerados como portadores de pneumonia nosocomial, ou","a":"associada a cuidados de saúde, os pacientes 1 e 3.","b":"somente o paciente 2.","c":"os pacientes 1 e 2.","d":"somente o paciente 1.","e":"os pacientes 2 e 3.","gabarito":"C","materia":"Medicina","tema":"Pneumologia","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Medicina - Clínica","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q631057","enunciado":"","a":"Geral história natural da tuberculose primária, descrita após observação em uma determinada população por mais de 10 anos, mostrou que o sintoma inicial mais frequente dessa infecção é","b":"A perda de peso. febre.","c":"tosse produtiva.","d":"escarro hemoptoico.","e":"dor pleural.","gabarito":"B","materia":"Medicina","tema":"Doenças Infecto-Parasitárias","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Medicina - Clínica","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q631056","enunciado":"Geral Algumas empresas, ou órgãos públicos, solicitam testes para o diagnóstico de sífilis em exames admissionais. Uma mulher","a":"de 28 anos, assintomática, apresenta VDRL positivo, título 1:32, e FTA-ABS negativo. Esse achado NÃO pode ocorrer em portadores de lúpus eritematoso sistêmico.","b":"portadores de hepatopatia crônica.","c":"pessoas normais.","d":"indivíduos que tiveram a doença há mais de 10 anos e foram tratados com sucesso.","e":"gestantes.","gabarito":"D","materia":"Medicina","tema":"Doenças Infecto-Parasitárias","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Medicina - Clínica","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q631055","enunciado":"Geral Um homem de 30 anos apresenta lesões escamosas com eritema discreto e leve prurido de evolução crônica, desde a infância, com períodos de exacerbação, afetando o couro cabeludo, face, principalmente o sulco nasogeniano, regiões","a":"retroauriculares e genitais. O diagnóstico mais provável é de dermatite psoriática.","b":"atópica.","c":"de Duhring, ou herpetiforme.","d":"de “berloque”, ou fitodermatite.","e":"seborreica.","gabarito":"E","materia":"Medicina","tema":"Dermatologia","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Medicina - Clínica","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q631054","enunciado":"Geral Uma mulher de 24 anos, portadora de anemia falciforme, com estado vacinal desconhecido, procura atenção médica por apresentar febre e lesões cutâneas compatíveis com varicela há 1 dia. Tem filho de 3 anos com diagnóstico atual dessa infecção. Tem atraso menstrual de 40 dias e não realizou nenhum exame para diagnóstico de gravidez. A conduta mais","a":"adequada é tratar com ribavirina, somente se um teste hematológico confirmar gravidez.","b":"com aciclovir inicialmente, com intuito de evitar possíveis malformações fetais, e manter somente se for confirmada","c":"gravidez. com aciclovir para evitar complicações agudas da doença.","d":"com ribavirina, ou aciclovir, para evitar complicações tardias da doença, como herpes zoster.","e":"somente com sintomáticos e corticoesteroide sistêmico em dose baixa.","gabarito":"C","materia":"Medicina","tema":"Hematologia","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Medicina - Clínica","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q631053","enunciado":"Geral Uma mulher de 30 anos, na 9ª semana de gravidez, assintomática, procura o médico do seu local de trabalho com urocultura positiva para E. coli, sensível a todos antibióticos do painel rotineiramente testado. A conduta terapêutica mais","a":"adequada é tratar com beta-lactâmico, ou outro antibiótico adequado para a idade gestacional.","b":"com fluorquinolona, preferencialmente.","c":"somente se vier a apresentar sintomas.","d":"com nitrofurantoina ou fosfomicina, somente.","e":"se persistir com cultura positiva, apenas após a 12ª semana.","gabarito":"A","materia":"Medicina","tema":"Ginecologia e Obstetrícia","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Medicina - Clínica","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q631052","enunciado":"Geral","a":"Na grande maioria dos pacientes que procuram os prontos socorros com lombalgia aguda, a causa é estenose espinhal na região lombar.","b":"compressão na emergência de raízes nervosas na coluna.","c":"diminuição crítica do espaço intervertebral.","d":"inespecífica, ou seja, sem um fator determinante identificável.","e":"contratura espasmódica da musculatura paravertebral.","gabarito":"D","materia":"Medicina","tema":"Doenças Reumatológicas e do Sistema Imunológico ,Ortopedia e Traumatologia","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Medicina - Clínica","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q631051","enunciado":"Geral Diante de um paciente com dor no joelho é aventada a hipótese diagnóstica de osteoartrite. Classicamente os achados","a":"clínico-laboratoriais dessa afecção NÃO incluem rigidez matinal com duração abaixo de 30 minutos.","b":"3 presença de líquido sinovial, claro, viscoso, com celularidade em torno de 40.000 /mm .","c":"ausência de calor local à palpação.","d":"crepitação na mobilização ativa da articulação.","e":"a VHS abaixo de 40 mm/1 h.","gabarito":"B","materia":"Medicina","tema":"Doenças Reumatológicas e do Sistema Imunológico","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Medicina - Clínica","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q631050","enunciado":"Geral Uma mulher de 29 anos, que no seu trabalho faz uso diário, por muitas horas, do computador, é afastada do trabalho por apresentar síndrome do túnel do carpo. Esta afecção pode ser desencadeada por fatores associados ao trabalho, mas","a":"outras condições coexistentes favorecem o seu aparecimento, EXCETO: dislipidemia.","b":"hipotireoidismo.","c":"diabetes mellitus.","d":"obesidade.","e":"atrite reumatoide.","gabarito":"A","materia":"Medicina","tema":"Clínica Médica Humana","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Medicina - Clínica","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q631049","enunciado":"Geral Um homem de 54 anos procura o médico para uma avaliação clínica geral. Apresenta vários fatores de risco para doença cardiovascular e seu pai teve infarto fatal aos 58 anos de idade. A ocorrência de evento coronariano em parentes de primeiro grau é considerado fator familiar significativo para risco cardiovascular quando acontece, para homem e mulher,","a":"respectivamente, em idade abaixo de 50 e 55 anos.","b":"65 e 50 anos.","c":"60 e 55 anos.","d":"50 e 60 anos.","e":"55 e 65 anos.","gabarito":"E","materia":"Medicina","tema":"Cardiologia e Alterações Vasculares","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Medicina - Clínica","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q631048","enunciado":"","a":"Geral série de alterações clínicas que compõem um episódio agudo de febre reumática decorrem de uma infecção","b":"A estreptocócica de faringe ou pele. viral ou bacteriana de vias aéreas superiores.","c":"estafilocócica de pele ou estreptocócica de vias aéreas superiores.","d":"estreptocócica de faringe.","e":"estafilocócica ou estreptocócica que acometa a faringe ou a pele.","gabarito":"D","materia":"Medicina","tema":"Doenças Reumatológicas e do Sistema Imunológico","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Medicina - Clínica","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q631047","enunciado":"Geral Um homem de 22 anos, com história de asma na infância, refere apresentar, há 3 meses, episódios de tosse, falta de ar e sibilos que ocorrem 1 ou 2 vezes por semana, sem fator desencadeante evidente. Crê ter sido acordado devido aos sintomas apenas 2 vezes nesse período; usou albuterol inalatório algumas vezes com melhora. Está assintomático no momento, não apresenta sibilos e o volume expiratório forçado no primeiro segundo é de 82% do previsto. Além de toda a","a":"orientação pertinente à sua moléstia o primeiro passo na terapêutica medicamentosa deve ser: corticoesteroide inalatório de 12/12 horas.","b":"montelucaste oral à noite.","c":"beta-agonista inalatório de curta duração, sempre que necessário.","d":"beta-agonista inalatório de longa duração, de 12/12 horas.","e":"beta-agonista de longa duração associado a corticoesteroide, por via inalatória, de 12/12 horas.","gabarito":"C","materia":"Medicina","tema":"Farmacologia e Anestesiologia ,Pneumologia","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Medicina - Clínica","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q631046","enunciado":"Geral Uma mulher de 25 anos procura atenção médica por apresentar, há 2 dias, lesões de pele com prurido intenso, principalmente à noite, nas áreas afetadas: seios, em torno dos mamilos, axilas e nádegas. Tem um filho de 3 anos com quadro semelhante, com lesões nas axilas e face interna dos dedos. Ao exame apresenta pequenas lesões difusas nas áreas acometidas algumas com eritema e elevações, como pequenos túneis, e microvesículas e presença de crostas hemáticas por escarificação. Os dados permitem concluir que o melhor resultado terapêutico provavelmente será obtido com o","a":"emprego de ciprofloxacina por via oral.","b":"fluconazol sistêmico.","c":"dexametasona tópica.","d":"dexclorfeniramina de uso tópico e sistêmico.","e":"benzoato de benzila tópico.","gabarito":"E","materia":"Medicina","tema":"Farmacologia e Anestesiologia ,Dermatologia","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Medicina - Clínica","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q631045","enunciado":"Geral Um homem de 50 anos, portador de fibrilação atrial crônica é medicado com rivaroxabana, diltiazen e digoxina; faz uso também de metformina, fluoxetina e alprazolam. Refere ter tomado furosemida nos últimos 3 dias por ter se achado inchado. Ele procura o médico do seu local de trabalho com história de 2 dias de náusea, fadiga, letargia, breves episódios de desorientação espacial e há algumas horas notou pontos luminosos na visão periférica e que vê os objetos com cor amarelada. O pulso está irregular e acelerado, a pressão arterial é normal e não há outras alterações no exame físico. A","a":"principal hipótese diagnóstica é hipocalemia.","b":"intoxicação digitálica.","c":"crise seritoninérgica.","d":"hipoglicemia.","e":"hemorragia intracraniana.","gabarito":"B","materia":"Medicina","tema":"Cardiologia e Alterações Vasculares","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Medicina - Clínica","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q631044","enunciado":"Geral 2 Mulher de 52 anos, hábito sedentário, tabagista, IMC = 40 kg/m , em uso de losartana, amlodipina, hidroclorotiazida, metformina e sinvastatina, sem antecedentes cardiovasculares, depois de ler artigo na internet consulta o médico do seu local de trabalho se deveria iniciar o uso de ácido acetilsalicílico. A opinião correta do médico deve se basear no","a":"conhecimento de que o uso de aspirina, no caso dessa paciente, pode diminuir significativamente a chance de infarto do miocárdio não fatal.","b":"seria contraindicado pelo risco muito aumentado de hemorragia intracraniana a longo prazo.","c":"seria benéfico por reduzir significativamente a mortalidade cardiovascular.","d":"não teria indicação pela ausência de antecedente cardiovascular.","e":"será determinante na prevenção de eventos isquêmicos cardíacos e cerebrovasculares a curto prazo.","gabarito":"A","materia":"Medicina","tema":"Cardiologia e Alterações Vasculares","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Medicina - Clínica","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q631043","enunciado":"Geral Homem de 45 anos procura ambulatório de clínica geral com queixa de queda de rendimento laboral, já que com frequência cochila nas reuniões de trabalho e a esposa, que o acompanha, relata que ele ronca demais e que para de respirar algumas vezes por noite. A altura do paciente é 175 cm e o peso 130 kg. Das abaixo, a gasometria mais provável deste indivíduo é","a":"pH - 7,53 pCO2 (mmHg) - 25 bicarbonato (mEq/L) - 23","b":"pH - 7,25 pCO2 (mmHg) - 60 bicarbonato (mEq/L) - 25","c":"pH - 7,30 pCO2 (mmHg) - 30 bicarbonato (mEq/L) - 15","d":"pH - 7,33 pCO2 (mmHg) - 65 bicarbonato (mEq/L) - 35","e":"pH - 7,57 pCO2 (mmHg) - 40 bicarbonato (mEq/L) - 34","gabarito":"D","materia":"Medicina","tema":"Pneumologia","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Medicina - Clínica","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q631042","enunciado":"Geral Homem de 40 anos apresenta-se com dor ocular esquerda, olho vermelho de início súbito, fotofobia, lacrimejamento, pupila em midríase média fixa e arreativa. A visão está turva com halos coloridos ao redor de focos de luz. Há cefaleia e","a":"vômitos. A principal hipótese diagnóstica é quadro agudo de Migrânea.","b":"Uveite.","c":"Conjuntivite.","d":"Descolamento de retina.","e":"Glaucoma.","gabarito":"E","materia":"Medicina","tema":"Oftalmologia","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Medicina - Clínica","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q631041","enunciado":"","a":"Geral localização e provável etiologia das miringites bolhosas são, respectivamente:","b":"A Garganta e Mycoplasma pneumoniae. Olho e Pseudomonas aeroginosa.","c":"Orelha e Mycoplasma pneumoniae.","d":"Orelha e Pseudomonas aeroginosa.","e":"Olho e Mycoplasma pneumoniae.","gabarito":"C","materia":"Medicina","tema":"Otorrinolaringologia","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Medicina - Clínica","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q631040","enunciado":"","a":"Geral anamnese é um dos elementos mais importantes para o diagnóstico da dor lombar. NÃO é um caso que exige investigação mais rigorosa devido a ocorrência de sinais de alerta:","b":"A Idade < 15 anos ou > 60 anos. Dor diurna mais intensa que a noturna.","c":"Perda de peso.","d":"Duração > 6 semanas.","e":"Uso crônico de glicocorticoide.","gabarito":"B","materia":"Medicina","tema":"Ortopedia e Traumatologia","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Medicina - Clínica","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q631039","enunciado":"Geral Analisando-se diversos pacientes com síndrome do túnel do carpo, das abaixo, a característica MENOS provável de ser","a":"encontrada é: Predominância em homens, em proporção de 9:1.","b":"Associação clínica com diabetes, hipotireoidismo e obesidade.","c":"Dor na região tenar do 1° , 2° e 3° e face radial do 4° quirodáctilos.","d":"A eletroneuromiografia como método complementar mais importante para auxílio diagnóstico.","e":"Para casos leves a moderados a indicação de terapêutica múltipla com órteses noturnas e corticoide oral ou por infiltração.","gabarito":"A","materia":"Medicina","tema":"Ortopedia e Traumatologia","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Medicina - Clínica","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q631038","enunciado":"Geral","a":"NÃO é estratégia para a prevenção do câncer de pele: Evitar a exposição solar entre 10 e 16 horas.","b":"Redobrar os cuidados de fotoproteção nas grandes altitudes.","c":"Preferir o bronzeamento artificial ao natural.","d":"Reaplicar filtro de proteção solar a cada 2 horas ou após cada mergulho.","e":"Manter fotoproteção adequada desde a infância.","gabarito":"C","materia":"Medicina","tema":"Dermatologia ,Oncologia","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Medicina - Clínica","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q631037","enunciado":"Geral São fatores de risco e proteção para a ocorrência de câncer de ovário:","a":"RISCO - menopausa tardia PROTEÇÃO - terapia de reposição hormonal","b":"RISCO - anticoncepcional oral PROTEÇÃO - síndrome dos ovários policísticos","c":"RISCO - endometriose PROTEÇÃO - menarca precoce","d":"RISCO - obesidade PROTEÇÃO - maternidade precoce","e":"RISCO - amamentação PROTEÇÃO - mutação no gene BRCA2","gabarito":"D","materia":"Medicina","tema":"Ginecologia e Obstetrícia ,Oncologia","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Medicina - Clínica","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q631036","enunciado":"","a":"Geral profilaxia do angioedema hereditário inclui EVITAR esportes de contato ou impacto e as seguintes medicações de uso crônico:","b":"A prednisona associada a ranitidina. inibidores de ECA (em especial captopril).","c":"antagonista de receptor de bradicinina (icatibanto).","d":"difenidramina ou prometazina.","e":"andrógenos atenuados (danazol, oxandrolona).","gabarito":"E","materia":"Medicina","tema":"Alergia e Imunologia","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Medicina - Clínica","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q631035","enunciado":"Geral Das drogas abaixo, a mais indicada no tratamento da agitação psicomotora por síndrome de abstinência alcoólica em","a":"indivíduos com cirrose hepática avançada ou hepatite alcoólica aguda é lorazepan.","b":"clordiazepóxido.","c":"diazepam.","d":"fenitoina.","e":"haloperidol.","gabarito":"A","materia":"Psiquiatria","tema":"Transtornos Relacionados a Substâncias ,Psicofarmacologia","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Medicina - Clínica","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q631034","enunciado":"Geral Dos marcadores séricos abaixo o que teria maior utilidade no diferencial entre uma crise convulsiva tônico − clônica","a":"generalizada e um quadro de síncope é cálcio ionizável.","b":"CPK.","c":"TGP.","d":"glicemia capilar.","e":"sódio.","gabarito":"B","materia":"Medicina","tema":"Neurologia","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Medicina - Clínica","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q631033","enunciado":"Geral Em um caso típico de cefaleia em salva (cluster) as melhores condutas, para tratamento da crise aguda e tratamento","a":"preventivo, são, respectivamente, sumatriptano e octreotide.","b":"oxigênio inalatório e sumatriptano.","c":"corticoide e topiramato.","d":"oxigênio inalatório e verapamil.","e":"verapamil e topiramato.","gabarito":"D","materia":"Medicina","tema":"Farmacologia e Anestesiologia ,Neurologia","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Medicina - Clínica","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q631032","enunciado":"","a":"Geral dosagem periódica de TSH NÃO deve ser feita em pacientes em uso crônico de","b":"A carbonato de lítio. interferon.","c":"bromocriptina.","d":"amiodarona.","e":"metimazol.","gabarito":"C","materia":"Medicina","tema":"Endocrinologia","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Medicina - Clínica","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q631031","enunciado":"Geral Alimentação hipercalórica e sedentarismo são as grandes causas de ganho de peso. Entretanto, há fatores secundários que","a":"causam obesidade, EXCETO o uso de Prednisona e insulinoma.","b":"Amitriptilina e hipotireoidismo.","c":"Sulfonilureia e hipogonadismo.","d":"Insulina e síndrome dos ovários policísticos.","e":"Topiramato e doença de Addison.","gabarito":"E","materia":"Medicina","tema":"Clínica Médica Humana","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Medicina - Clínica","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q631030","enunciado":"Geral Lesões de pele simétricas em pontos de pressão e expostas ao sol. É frequente a distribuição em “bota”, ”luva”, “colar” e “borboleta na face”. Há distensão abdominal seguida de náusea e diarreia. Concomitantemente alterações de memória, discreta confusão mental evoluindo para mania, delírio e enfim demência.","a":"O texto acima descreve o quadro associado à deficiência de niacina.","b":"folato.","c":"tiamina.","d":"piridoxina.","e":"cobalamina.","gabarito":"A","materia":"Medicina","tema":"Distúrbios Nutricionais ,Hipovitaminoses","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Medicina - Clínica","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q631029","enunciado":"Geral Pancreatite, neoplasia de pâncreas, carcinoma medular de tireoide, náuseas, vômitos e diarreia são efeitos colaterais","a":"descritos com o uso desse medicamento que faz parte do arsenal terapêutico do diabetes tipo 2. Trata-se de vildagliptina.","b":"liraglutida.","c":"pioglitazona.","d":"repaglinida.","e":"glimepirida.","gabarito":"B","materia":"Medicina","tema":"Endocrinologia","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Medicina - Clínica","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q631028","enunciado":"Geral Foi colhida a glicemia de um paciente 2 horas após ingerir 75 gramas de glicose por via oral. O valor a partir do qual será","a":"feito o diagnóstico de diabetes mellitus é, em mg/dL, 180.","b":"140.","c":"200.","d":"126.","e":"115.","gabarito":"C","materia":"Medicina","tema":"Endocrinologia","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Medicina - Clínica","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q631027","enunciado":"Geral Em uma mulher de 30 anos com queixa crônica de astenia e que apresenta TSH muito elevado, o que será encontrado com","a":"MENOR probabilidade é obstipação.","b":"menorragia.","c":"galactorreia.","d":"hiporreflexia.","e":"hipotensão arterial.","gabarito":"E","materia":"Medicina","tema":"Endocrinologia","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Medicina - Clínica","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q631026","enunciado":"Geral Em um homem de 45 anos com antecedente de tuberculose e tomografia computadorizada mostrando destruição maciça","a":"de ambas as glândulas adrenais, é mais provável o encontro do seguinte dado laboratorial linfopenia.","b":"hipercalcemia.","c":"eosinófilos indetectáveis.","d":"hipernatremia.","e":"hiperglicemia.","gabarito":"B","materia":"Medicina","tema":"Endocrinologia","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Medicina - Clínica","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q631025","enunciado":"Geral Amenorreia, disfunção erétil e infertilidade são queixas que levam o médico a pensar, entre outras coisas, em prolactinoma solicitando, portanto, dosagem sérica de prolactina. Entretanto é fundamental saber que há múltiplas causas de","a":"hiperprolactinemia, EXCETO uso de metoclopramida.","b":"estresse físico.","c":"insuficiência renal crônica.","d":"hipertireoidismo.","e":"acromegalia.","gabarito":"D","materia":"Medicina","tema":"Urologia","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Medicina - Clínica","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q631024","enunciado":"Geral Pacientes com histórico de fibrilação atrial crônica, embolia de pulmão, trombose venosa profunda e coronariopatia são anticoagulados de diferentes maneiras. Analisando-se o tempo de trombopastina parcial ativado e o INR nestes pacientes,","a":"encontra-se, com maior probabilidade, valores normais naqueles que fazem uso de varfarina e heparina não fracionada.","b":"dabigatrana e enoxaparina.","c":"dabigatrana e heparina não fracionada.","d":"enoxaparina e varfarina.","e":"rivaroxabana e heparina não fracionada.","gabarito":"B","materia":"Medicina","tema":"Farmacologia e Anestesiologia ,Clínica Médica Humana","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Medicina - Clínica","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q631023","enunciado":"Geral","a":"Hidroxiureia e ácido fólico serão prescritos com maior probabilidade para pacientes com anemia, necrose asséptica de cabeça de fêmur e passado de osteomielite por salmonela.","b":"volume corpuscular médio bem diminuído e hemoglobina A2 > 5%.","c":"icterícia, pleurite e teste de Coombs positivo.","d":"volume corpuscular médio bem aumentado e ataxia.","e":"pagofagia e ferritina indetectável.","gabarito":"A","materia":"Medicina","tema":"Hematologia","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Medicina - Clínica","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q631022","enunciado":"Geral Homem de 20 anos apresenta história de epistaxe, gengivorragia e manchas pelo corpo. Encontra-se discretamente descorado, PA = 120 × 80 mmHg, pulso de 80 bpm. A ausculta cardiopulmonar é normal e não há visceromegalias à palpação abdominal. Petéquias são detectadas em tronco e membros inferiores. O hemograma mostra hemoglobina de 3 3 10,3 g/dL, plaquetas de 12.000 / mm e 6.500 leucócitos / mm . O coagulograma é normal. A conduta inicial mais adequada","a":"é apenas observação clínica.","b":"transfusão de 10 unidades de plaquetas.","c":"plasmaferese.","d":"corticoesteroide.","e":"globulina antitimocítica.","gabarito":"D","materia":"Medicina","tema":"Clínica Médica Humana","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Medicina - Clínica","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q631021","enunciado":"Geral Dentre as leucemias que acometem a população ocidental, é a mais comum (aproximadamente 25% a 30% de todas as leucemias). É predominantemente uma doença de pacientes idosos. O quadro clínico é extremamente variado, desde pacientes totalmente assintomáticos, até a apresentação de manifestações autoimunes (anemia hemolítica e reação exagerada a picada de mosquitos).","a":"O texto acima refere-se a leucemia mieloide aguda.","b":"mieloide crônica.","c":"linfocítica crônica.","d":"linfoblástica aguda.","e":"mielomonocítica crônica.","gabarito":"C","materia":"Medicina","tema":"Hematologia","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Medicina - Clínica","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q631020","enunciado":"Geral Homem de 45 anos com queda do estado geral procura assistência médica. Chama atenção a sua gasometria mostrando","a":"pH = 7,51 e bicarbonato = 32 mEq/L. A alteração mais provável de ser encontrada no seu eletrocardiograma é onda T apiculada.","b":"onda U.","c":"intervalo QTc encurtado.","d":"onda delta.","e":"onda J.","gabarito":"B","materia":"Medicina","tema":"Cardiologia e Alterações Vasculares","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Medicina - Clínica","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q631019","enunciado":"Geral","a":"Dentre os efeitos adversos observados em pacientes em uso de hidroclorotiazida estão o aumento dos níveis séricos de magnésio e ureia.","b":"sódio e glicose.","c":"potássio e pH.","d":"cloro e lípides.","e":"cálcio e ácido úrico.","gabarito":"E","materia":"Medicina","tema":"Farmacologia e Anestesiologia","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Medicina - Clínica","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q631018","enunciado":"Geral","a":"Na ausência de sintomas, situação que exige tratamento é bacteriúria em grávidas.","b":"fungúria em pacientes com sonda vesical.","c":"bacteriúria em idosas.","d":"leucocitúria em pacientes com sonda vesical.","e":"bacteriúria em diabéticos.","gabarito":"A","materia":"Medicina","tema":"Clínica Médica Humana","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Medicina - Clínica","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q631017","enunciado":"Geral","a":"Dentre os microorganismos abaixo, o agente NÃO patogênico é Cryptosporidium.","b":"Cytoisospora belli.","c":"Endolimax nana.","d":"Dientamoeba fragilis.","e":"Cyclospora cayetanensis.","gabarito":"C","materia":"Medicina","tema":"Doenças Infecto-Parasitárias","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Medicina - Clínica","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q631016","enunciado":"Geral","a":"Em pacientes com suspeita de síndrome do intestino irritável, recomenda-se a realização de colonoscopia se o número de evacuações for maior que três por dia.","b":"quando houver muco nas fezes.","c":"quando houver urgência para evacuar.","d":"se os sintomas se iniciarem após os 50 anos de idade.","e":"se o número de evacuações for maior ou igual a cinco por dia.","gabarito":"D","materia":"Medicina","tema":"Gastroenterologia","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Medicina - Clínica","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q631015","enunciado":"Geral Mulher de 40 anos procura assistência no ambulatório de clínica geral com queixa de disúria e polaciúria sem quadro de febre. Menstrua normalmente e o beta-HCG é negativo. O exame de urina mostra piúria microscópica e houve crescimento de E. coli na urocultura. O número de UFC (unidades formadoras de colônias) a partir do qual se caracteriza infecção","a":"urinária nesta paciente é igual ou maior que 1.000.","b":"100.","c":"10.000.","d":"100.000.","e":"1.000.000.","gabarito":"B","materia":"Medicina","tema":"Urologia","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Medicina - Clínica","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q631014","enunciado":"Geral","a":"Paciente com nefropatia diabética apresenta hipercalemia desproporcionalmente alta em relação à elevação de creatinina. alteração associada mais provável é RENINA - Normal A ALDOSTERONA - elevada","b":"RENINA - Elevada ALDOSTERONA - elevada","c":"RENINA - Diminuída ALDOSTERONA - elevada","d":"RENINA - Elevada ALDOSTERONA - diminuída","e":"RENINA - Diminuída ALDOSTERONA - diminuída","gabarito":"E","materia":"Medicina","tema":"Endocrinologia ,Urologia","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Medicina - Clínica","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q631013","enunciado":"Geral São avaliados pacientes com idade superior a 40 anos que apresentam o primeiro episódio de diverticulite colônica não","a":"complicada. Estes indivíduos têm risco futuro de diverticulite complicada maior que 50%.","b":"não devem ser tratados com antibióticos por via oral.","c":"devem ser submetidos posteriormente a cirurgia eletiva.","d":"podem apresentar sintomas urinários.","e":"devem ser submetidos a intervenção cirúrgica imediata.","gabarito":"D","materia":"Medicina","tema":"Gastroenterologia","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Medicina - Clínica","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q631012","enunciado":"Geral Considere as quatro formas de vitamina D, abaixo. I. sintetizada na pele e também presente na dieta. II. fornecida por dieta e suplementos. III. sintetizada no fígado.","a":"IV. sintetizada nos rins. correlação correta é 25-OH vitamina D - III 2 1,25-(OH) vitamina D - IV A Ergocalciferol - II Colecalciferol -I 25-OH vitamina D - I 2","b":"1,25-(OH) vitamina D - II Ergocalciferol - III Colecalciferol - IV 25-OH vitamina D - II 2","c":"1,25-(OH) vitamina D - III Ergocalciferol - I Colecalciferol - IV 25-OH vitamina D - III 2","d":"1,25-(OH) vitamina D - II Ergocalciferol - IV Colecalciferol - I 25-OH vitamina D - IV 2","e":"1,25-(OH) vitamina D - III Ergocalciferol - II Colecalciferol - I","gabarito":"A","materia":"Medicina","tema":"Clínica Médica Humana","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Medicina - Clínica","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q631011","enunciado":"Geral","a":"Em pacientes portadores de doença celíaca, os grãos que têm menor probabilidade de causar problemas são aveia e cevada.","b":"aveia e centeio.","c":"trigo e centeio.","d":"cevada e centeio.","e":"arroz e milho.","gabarito":"E","materia":"Medicina","tema":"Gastroenterologia","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Medicina - Clínica","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q631010","enunciado":"Geral Em brancos sem risco elevado de câncer colorretal, a idade, em anos, na qual o rastreamento para este tumor deve ser","a":"iniciado é 60.","b":"55.","c":"50.","d":"40.","e":"45.","gabarito":"C","materia":"Medicina","tema":"Gastroenterologia ,Oncologia","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Medicina - Clínica","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q631009","enunciado":"Geral","a":"O agente cuja eficácia para prevenir câncer de próstata foi comprovada é inibidor de 5-alfa redutase.","b":"selênio.","c":"vitamina C.","d":"vitamina E.","e":"tamsulozina. Engenharia Elétrica>Circuitos Elétricos na Engenharia Elétrica ,Circuitos Trifásicos em Engenharia Elétrica ,","gabarito":"A","materia":"Medicina","tema":"Oncologia","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Medicina - Clínica","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q631007","enunciado":"Em um circuito monofásico de alimentação de parte de um datacenter existe um conjunto de cargas elétricas, com características não-lineares, que resultam em um consumo de corrente com uma certa distorção harmônica. Um equipamento de medição de qualidade de energia informa que o valor eficaz da corrente fundamental nesse circuito é de 0,9 [p.u.], com um conteúdo com 3ª , 5ª e 7ª harmônicas com os valores eficazes de 0,3 [p.u.], 0,3 [p.u] e 0,1 [p.u.], respectivamente. Nessa condição, a magnitude da corrente eficaz distorcida (em [p.u]) e a distorção harmônica total (em %)","a":"são, aproximadamente, 1,3 e 92,9.","b":"1,6 e 48,4.","c":"0,9 e 25,2.","d":"1,0 e 48,4.","e":"1,0 e 25,2. Engenharia Elétrica>Distribuição na Engenharia Elétrica ,Equipamentos em Média Tensão ,","gabarito":"D","materia":"Engenharia Elétrica","tema":"Circuitos Elétricos na Engenharia Elétrica ,Circuitos CC","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Engenharia (Elétrica)","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1372","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Engenharia (Elétrica) Um relé eletromecânico de sobrecorrente instantânea, com ajuste de tempo definido (ANSI 50), possui duas bobinas de corrente, com entradas para corrente secundária de 1,0 [A] ou 5,0 [A], ajuste do multiplicador de corrente de pickup, ajuste do tempo definido, uma saída a relé de pickup, normalmente aberta, e uma saída a relé de trip, normalmente aberta. A respeito desse equipamento,","a":"todas as bobinas de corrente devem ser ligadas para prover uma grandeza de polarização e uma grandeza de atuação para o equipamento.","b":"a saída de pickup normalmente aberta se torna um contato elétrico fechado se a corrente em uma das bobinas do relé for superior à corrente ajustada no multiplicador de corrente de pickup. Assim que a corrente diminui, a saída de pickup volta a abrir.","c":"o ajuste de tempo definido permite modificar o limiar de atuação de corrente do relé, permitindo seu ajuste para diferentes correntes de atuação, conforme a aplicação.","d":"a saída de trip normalmente aberta se torna um contato elétrico fechado assim que o relé identificar uma situação de sobrecorrente, permanecendo fechada até que um usuário faça o reset ou desarme sua função de lockout (ANSI 86).","e":"o ajuste do multiplicador de corrente de pickup permite a seleção de uma ou mais curvas de tempo versus corrente, conforme a necessidade de coordenação da atuação do relé, com características inversa, extremamente inversa e muito inversa.","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Engenharia (Elétrica)","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q631005","enunciado":"Um engenheiro deseja efetuar o dimensionamento de um sistema de proteção contra descargas atmosféricas, pelo método de Franklin, em uma edificação que possui 19 [m] de altura. Para tanto, consultou a norma vigente e deparou-se com a tabela abaixo. Dado que o nível de proteção pretendido pelo engenheiro é II e que o raio de proteção é de 4 [m], a altura da haste aterrada, em relação ao plano que se quer proteger, supondo que se possa construir uma haste personalizada, com a altura","a":"desejada é, em [m], igual a 3,0.","b":"1,0.","c":"2,0.","d":"0,5.","e":"4,0.","gabarito":"E","materia":"Engenharia Elétrica","tema":"Instalações Elétricas em Engenharia Elétrica ,NBR 5419","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Engenharia (Elétrica)","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q631004","enunciado":"O nível de iluminamento necessário para o desempenho de uma atividade de montagem industrial é de 300 [lux]. Essa 2 atividade é desempenhada em um recinto de 7.200 [m ] que possui teto e paredes claros, piso escuro e bastante poeira ambiente. Nas condições dadas, a escolha do aparelho individual de iluminação (lâmpada e luminária) indica que o fator de utilização é de 80 [%], enquanto as condições do ambiente indicam que o fator de depreciação é de 90 [%]. Dado que o fluxo luminoso do aparelho individual de iluminação é de 3.000 [lm], o número de aparelhos que devem ser instalados para","a":"garantir o nível de iluminamento em questão é 500.","b":"250.","c":"2.500.","d":"1.500.","e":"1.000.","gabarito":"E","materia":"Engenharia Elétrica","tema":"Instalações Elétricas em Engenharia Elétrica ,Luminotécnica","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Engenharia (Elétrica)","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q631003","enunciado":"Instalações elétricas industriais podem suportar correntes de sobrecarga ou de curto-circuito durante intervalos de tempo reduzidos, que normalmente são inversamente proporcionais à magnitude dessas correntes. Nesse contexto, uma instalação elétrica industrial pode suportar correntes dessa natureza respeitando a seguinte curva: Onde: − t é o intervalo de tempo máximo a que a instalação elétrica pode suportar a corrente I (para correntes maiores ou iguais que as correntes típicas de sobrecarga); − I é a corrente de sobrecarga ou de curto-circuito a que a instalação elétrica está submetida. Considerando que essa instalação pode ser protegida por um relé de sobrecorrente cuja corrente mínima de pickup é 200 [A], a equação que descreve corretamente a curva que deve ser escolhida, para esse dispositivo de proteção, de modo a","a":"que ele seja capaz de proteger a instalação elétrica em questão é","b":"","c":"","d":"","e":"Engenharia Elétrica>Distribuição na Engenharia Elétrica ,Equipamentos em Média Tensão ,","gabarito":"A","materia":"Engenharia Elétrica","tema":"Distribuição na Engenharia Elétrica ,Proteção em Média Tensão","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Engenharia (Elétrica)","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1376","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Engenharia (Elétrica) São conhecidas as seguintes grandezas para o circuito de uma carga monofásica, alimentada por um condutor de fase e um condutor de neutro: − IB = 20,0 [A], como a corrente de projeto do circuito. − IZ = 30,0 [A], como a capacidade de condução de corrente dos condutores do circuito, em uma dada forma de instalação. Nessas condições, apresenta corretamente o emprego de dispositivos de proteção contra curtos-circuitos e sobrecargas, considerando a coordenação com os demais elementos do circuito:","a":"Podem ser aplicados dois fusíveis, cada um com corrente nominal de 12,0 [A], um no condutor de fase e um no condutor de neutro do circuito. Os fusíveis são instalados ambos a montante dos cabos de alimentação da carga.","b":"Pode ser aplicado um fusível, com corrente nominal de 30,0 [A], no condutor de fase do circuito. O fusível deve ser instalado a jusante do cabo de alimentação de fase, no ponto de ligação à carga.","c":"Podem ser aplicados dois disjuntores, cada um com corrente nominal de 12,0 [A], um no condutor de fase e um no condutor de neutro do circuito. Os disjuntores são instalados a montante do cabo de alimentação do circuito.","d":"Pode ser aplicado um disjuntor, com corrente nominal de 30,0 [A], no condutor de fase do circuito. O disjuntor deve ser instalado a montante do cabo de alimentação da fase do circuito.","e":"Podem ser aplicados dois disjuntores em paralelo, cada um com corrente nominal de 15,0 [A]. Os disjuntores são instalados a montante do cabo de alimentação da fase do circuito.","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Engenharia (Elétrica)","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q631001","enunciado":"No dimensionamento de condutores e eletrodutos em uma instalação elétrica,","a":"caso haja três ou mais condutores presentes dentro de um eletroduto, a taxa de ocupação do mesmo não deve ser superior a 40,0 [%].","b":"caso a taxa de ocupação de um eletroduto seja superior a 70,0 [%], deve-se reduzir a corrente de projeto da instalação, para diminuir a seção dos condutores utilizados, mantendo a seção do eletroduto, até que o fator de ocupação máximo seja atendido.","c":"o fator de ocupação está relacionado diretamente à quantidade de condutores energizados, e não considera os condutores não utilizados lançados dentro do eletroduto.","d":"caso haja passagem simultânea de circuitos de alimentação, telefonia, TV a cabo e infraestrutura de rede cabeada, o fator de utilização de um eletroduto ou calha elétrica deve ser inferior a 31,0 [%].","e":"a forma de acondicionamento dos condutores dentro de um eletroduto não impacta na corrente utilizada para o dimensionamento da capacidade de corrente dos condutores que serão utilizados.","gabarito":"A","materia":"Engenharia Elétrica","tema":"Instalações Elétricas em Engenharia Elétrica ,NBR 5410","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Engenharia (Elétrica)","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q631000","enunciado":"","a":"respeito dos esquemas de aterramento que podem ser considerados em uma instalação elétrica de baixa tensão, no esquema TN, a alimentação possui um ponto diretamente aterrado e as massas são ligadas ao ponto da A alimentação aterrado através de condutores de proteção.","b":"o esquema TN-S implica que o condutor de neutro ou o condutor de fase podem ser omitidos em uma instalação elétrica.","c":"no esquema IT todas as partes vivas são conectadas à terra através de um ponto de aterramento de baixa impedância. Todas as massas da instalação são aterradas nesse mesmo ponto.","d":"o esquema TN-S implica que o condutor de neutro e o condutor de fase podem ser interligados em uma única função, como condutor de proteção.","e":"quando um condutor desempenha simultaneamente a função de condutor de neutro e de fase, ele é denominado condutor de proteção ou PEN.","gabarito":"A","materia":"Engenharia Elétrica","tema":"Instalações Elétricas em Engenharia Elétrica ,Aterramentos","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Engenharia (Elétrica)","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630999","enunciado":"O diagrama unifilar, abaixo, descreve a instalação elétrica (F1+F2+N+PE, 127/220 [V], 60 [Hz]) de parte de uma edificação.","a":"Nesse diagrama, o cômodo A possui dois circuitos, um circuito de iluminação (F1+N) e outro circuito de tomada (F2+N+PE).","b":"A possui três circuitos, dois circuitos de iluminação (F1+N e F2+N) e outro circuito de tomada (F2+N+PE).","c":"A possui três circuitos, um circuito de iluminação (F1+N) e dois circuitos de tomadas (F1+N+PE e F2+N+PE).","d":"B possui dois circuitos, um circuito de iluminação (F1+N) e outro circuito de tomada (F1+F2+PE).","e":"B possui dois circuitos, um circuito de iluminação (F1+N) e outro circuito de tomada (F2+N+PE).","gabarito":"E","materia":"Engenharia Elétrica","tema":"Instalações Elétricas em Engenharia Elétrica ,NBR 5410","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Engenharia (Elétrica)","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630998","enunciado":"No dimensionamento dos condutores do circuito de alimentação de um motor deve ser considerada uma corrente de projeto no mínimo igual à corrente nominal do motor, nas condições de utilização. Um motor trifásico de indução, com rotor tipo gaiola de esquilo, com os parâmetros citados abaixo, deverá ser usado de forma ininterrupta em uma dada instalação elétrica em 60,0 [Hz]: − Frequência nominal = 60,0 [Hz]. − Escorregamento nominal = 5,0 [%]. − Potência nominal = 8,1 [kW]. − Tensão nominal = 220,0 [V]. − Fator de potência = 0,9 (indutivo). − Fator de serviço = 1,0. − Rendimento em potência nominal = 90,0 [%].","a":"Nessas circunstâncias, a corrente nominal do motor é, em [A], aproximadamente, 73,2.","b":"26,3.","c":"45,5.","d":"52,6.","e":"13,3.","gabarito":"B","materia":"Engenharia Elétrica","tema":"Máquinas Elétricas ,Máquina de Indução","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Engenharia (Elétrica)","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630997","enunciado":"Pode-se dividir as configurações de barra de subestações em dois grandes grupos: o primeiro grupo, das configurações com conectividade concentrada; e o segundo grupo, das configurações com conectividade distribuída. Com relação a essas configurações de barra,","a":"barra simples é uma das mais simples configurações de barra e pode ser utilizada em subestações de pequeno porte em média e alta tensão.","b":"a configuração de anel simples é concebida de modo a eliminar a necessidade de recomposição, por meio dos disjuntores fora de serviço, quando da manutenção dos seus disjuntores em serviço.","c":"a configuração de barra dupla com disjuntor e meio é empregada em subestações de pequeno e médio portes em virtude do seu custo reduzido.","d":"a configuração de barra principal e transferência é utilizada para que as manobras sejam realizadas com o desligamento das barras, liberando os disjuntores simultaneamente.","e":"barra dupla com disjuntor duplo é empregada em subestações que possuem elevado número de bays e baixa capacidade de potência por bay. Engenharia Elétrica>Distribuição na Engenharia Elétrica ,Equipamentos em Média Tensão ,","gabarito":"A","materia":"Engenharia Elétrica","tema":"Distribuição na Engenharia Elétrica ,Subestação","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Engenharia (Elétrica)","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1382","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Engenharia (Elétrica) Um grupo moto-gerador a diesel, com gerador elétrico tipo síncrono, trifásico, com autoexcitação estática, foi dimensionado para atender a uma aplicação como gerador de emergência para um sistema elétrico. A saída do gerador trifásico é ligada à rede elétrica de 60,0 [Hz] através de um disjuntor trifásico. Nesse sistema,","a":"o regulador de tensão é responsável por ajustar a tensão terminal do sistema na entrada de operação do grupo motogerador. Na ocasião da partida do grupo, uma bateria de pré-excitação é responsável por realizar o processo de autoexcitação da excitatriz estática.","b":"o regulador de velocidade é responsável por ajustar a velocidade do grupo gerador durante sua operação, mantendo a velocidade do motor diesel na condição de marcha lenta e mínimo consumo de combustível, de modo a garantir autonomia máxima, em detrimento da frequência da geração elétrica às cargas.","c":"o disjuntor de conexão do grupo à rede elétrica deve permanecer sempre fechado, mantendo o grupo moto-gerador ligado à energia elétrica da concessionária de forma contínua. No advento de falta de fornecimento, esse disjuntor é aberto para desligar o gerador elétrico da rede.","d":"um dispositivo eletrônico inteligente é responsável por realizar a conversão da tensão contínua de saída do gerador à tensão alternada da rede trifásica.","e":"quando ocorre uma falta de fornecimento de energia por parte da concessionária, o grupo moto-gerador que estava parado realiza sua partida, para então gerar a energia para o sistema. Isso é realizado de forma instantânea, sem interrupção no fornecimento.","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Engenharia (Elétrica)","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630994","enunciado":"O regulador de tensão é um equipamento que mantém um nível de tensão pré-determinado em um alimentador de distribuição, apesar das variações de carga. De um modo geral, esse equipamento é composto por um autotransformador com comutação automática de tape, através de um comutador sob carga. Nesse contexto, considere o regulador automático de tensão, abaixo. Esse regulador foi submetido a ensaios nas condições da figura e os dados obtidos foram: − VL = 1000 [V]. − VH = 1100 [V]. Dado que o número de espiras da bobina de entrada é Nc = 220, que as fases de todos os sinais são nulas e que as bobinas","a":"são ideais, o número de espiras da bobina secundária (SE) é 220.","b":"22.","c":"110.","d":"11.","e":"1100.","gabarito":"B","materia":"Engenharia Elétrica","tema":"Máquinas Elétricas ,Autotransformador","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Engenharia (Elétrica)","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630993","enunciado":"Descreve corretamente um transformador de instrumentação:","a":"O transformador de potencial indutivo é capaz de transformar uma alta tensão aplicada em seu enrolamento primário, seja contínua ou alternada, para uma tensão reduzida em seu enrolamento secundário, tipicamente 115,0 [V].","b":"O transformador de potencial capacitivo é utilizado em circuitos de baixa e média tensões, até 13,8 [kV], para transformar uma tensão contínua aplicada em seu enrolamento primário, para uma tensão reduzida em seu enrolamento secundário, tipicamente 115,0 [V].","c":"O transformador de potencial óptico permite a medição da potência luminosa de uma fonte de luz para aplicações em luminotécnica.","d":"O transformador de corrente indutivo é capaz de transformar uma alta corrente alternada aplicada em seu enrolamento primário para uma corrente reduzida em seu enrolamento secundário, tipicamente nos valores de 1 [A] ou 5 [A].","e":"O transformador de potencial óptico permite a medição direta de tensões eficazes, seja em corrente contínua ou alternada, através da luz que percorre uma fibra óptica ligada a um eletroímã, suscetível à intensidade do campo elétrico do condutor primário. Engenharia Elétrica>Análise de SEP ,Análise de Curto-circuitos ,Distribuição na Engenharia Elétrica","gabarito":"D","materia":"Engenharia Elétrica","tema":"Máquinas Elétricas ,Transformador de Corrente ,Transformador de Potencial","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Engenharia (Elétrica)","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1385","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Engenharia (Elétrica) Quando da ocorrência de uma falta dupla-fase a jusante de seu ponto de instalação, o religador","a":"permanece continuamente desligando e religando o circuito de distribuição (também a jusante), até que não ocorram mais atuações dos elementos de sobrecorrente, independentemente da falta ser transitória ou permanente.","b":"irá efetuar o trip de seu disjuntor apenas se for detectada que a falta é permanente. Após um certo tempo, o religador fecha novamente o disjuntor, mantendo-o alimentando a falta, e forçando a queima de algum fusível.","c":"irá atuar, pois se trata de um dispositivo apenas de manobra e não de proteção, e seu disjuntor é dimensionado para ser manobrado em carga.","d":"não irá atuar, pois se trata de um dispositivo apenas de manobra e não de proteção, e seu disjuntor não é dimensionado para ser manobrado em carga.","e":"efetua o trip de seu disjuntor de forma instantânea ou temporizada no momento da falta. Após um certo tempo, o religador pode ordernar o fechamento do disjuntor para reenergizar o circuito, dependendo da magnitude, do tipo de falta detectada e da quantidade de religamentos já efetuada. Engenharia Elétrica>Distribuição na Engenharia Elétrica ,Proteção em Média Tensão ,","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Engenharia (Elétrica)","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1386","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Engenharia (Elétrica) Acerca dos disjuntores e seccionadores, considere: I. A principal função dos disjuntores é interromper correntes de falta de forma rápida, com o intuito de limitar os danos causados aos equipamentos dos sistemas elétricos. II. Chaves fusíveis têm como função permitir a manobra em carga, de ramais e redes de distribuição de energia elétrica, bem como isolar esses componentes durante eventos de curto-circuito. III. Seccionadores podem ser empregados para isolar componentes do sistema de modo que seja possível efetuar tarefas de manutenção nesses componentes.","a":"Está correto o que consta em I, apenas.","b":"II, apenas.","c":"I e III, apenas.","d":"II e III, apenas.","e":"I, II e III.","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Engenharia (Elétrica)","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630990","enunciado":"Um banco de três transformadores monofásicos foi utilizado para compor um transformador trifásico, porém os dados de placa desses transformadores foram parcialmente perdidos e não há informações sobre a impedância de curto-circuito dos mesmos. No entanto, essa informação é importante para a determinação da corrente máxima de curto-circuito da instalação e o engenheiro responsável por ela decidiu efetuar o ensaio de curto-circuito à frequência industrial de 60 [Hz] em um dos transformadores monofásicos que compõem o banco. Os resultados do ensaio estão apresentados abaixo, considerando que as medidas foram obtidas do lado fonte: − Potência ativa: 300 [W]. − Corrente: 10 [A]. − Tensão: 50 [V].","a":"O valor da impedância de curto-circuito do transformador monofásico que compõe o banco, vista pela fonte, em [ohms], é 9 + j 12.","b":"8 + j 6.","c":"6 + j 8.","d":"4 + j 3.","e":"3 + j 4.","gabarito":"E","materia":"Engenharia Elétrica","tema":"Máquinas Elétricas ,Transformador de Potência","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Engenharia (Elétrica)","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630989","enunciado":"Com relação aos equipamentos denominados para-raios, considere: I. Varistores de óxido metálico são dispositivos usualmente empregados como para-raios em subestações e têm a função de limitar as sobretensões de qualquer natureza. II. Para-raios são instalados distantes dos principais equipamentos das subestações de modo a reduzir a probabilidade de incidência de descargas atmosféricas nesses equipamentos. III. Para-raios são equipamentos que podem contribuir com a confiabilidade, a economia e a continuidade de serviço dos sistemas elétricos.","a":"Está correto o que consta em I, apenas.","b":"II, apenas.","c":"I e III, apenas.","d":"II e III, apenas.","e":"I, II e III.","gabarito":"C","materia":"Engenharia Elétrica","tema":"Instalações Elétricas em Engenharia Elétrica ,NBR 5419","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Engenharia (Elétrica)","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630988","enunciado":"","a":"Em relação ao MS-Word 2013, arquivos em formato docx podem apenas ser salvos em PDF, mas não podem ser visualizados dentro do MS-Word 2013.","b":"PDF podem ser visualizados, editados e salvos em docx ou PDF.","c":"PDF podem ser visualizados e editados, mas salvos apenas em docx.","d":"PDF podem apenas ser visualizados dentro do MS-Word 2013.","e":"PDF exigem a aquisição e instalação da Microsoft para serem suportados.","gabarito":"B","materia":"Noções de Informática","tema":"Microsoft Word ,Editor de Textos - Microsoft Word e BrOffice.org Writer","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Engenharia (Elétrica)","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630987","enunciado":"Um usuário do MS-Word 2013, em sua configuração padrão, abriu um documento, selecionou a aba Exibição e clicou no botão cujo ícone se encontra representado abaixo, com a sua descrição removida.","a":"Essa ação provoca a ativação da opção “Modo de Leitura”.","b":"a exibição do documento no modo “Layout da Web”.","c":"a exibição do documento no modo “Layout de Impressão”.","d":"a formatação do documento de acordo com a folha de estilos escolhida para o arquivo.","e":"o alinhamento das figuras do documento. Noções de Informática>Planilhas Eletrônicas - Microsoft Excel e BrOffice.org Calc ,Microsoft Excel ,","gabarito":"A","materia":"Noções de Informática","tema":"Microsoft Word ,Editor de Textos - Microsoft Word e BrOffice.org Writer","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Engenharia (Elétrica)","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1391","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Engenharia (Elétrica) O elaborador de uma planilha no MS-Excel 2013, em sua configuração padrão, deseja que as fórmulas das suas células não possam ser visualizadas por outros usuários. Para tanto, após selecionar as células com o botão direito do mouse, na aba","a":"Proteção da caixa de diálogo Formatar Células que surge na tela, deve-se marcar a opção Ocultas.","b":"Escondidas.","c":"Invisíveis.","d":"Bloqueadas.","e":"Travadas.","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Engenharia (Elétrica)","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630985","enunciado":"Considere, abaixo, a representação de um optoacoplador típico. Para que o ponto Vs do optoacoplador apresente nível próximo de zero volts quando uma corrente alta circular no diodo da","a":"entrada, a configuração do circuito da saída deverá ser:","b":"","c":"","d":"","e":"","gabarito":"E","materia":"Engenharia Eletrônica","tema":"Eletrônica Analógica na Engenharia Eletrônica ,Diodo na Engenharia Eletrônica","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Engenharia (Elétrica)","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630984","enunciado":"O circuito abaixo apresenta um fototransistor em uma configuração típica.","a":"Para que o circuito opere no modo de chaveamento, deve-se ter Ic = 0.","b":"2 Ic > 10 × Vpp /R.","c":"Vpp > R × Ic.","d":"2 Vpp > 10 × R × Ic .","e":"Vpp < R × Ic.","gabarito":"E","materia":"Engenharia Eletrônica","tema":"Eletrônica Analógica na Engenharia Eletrônica ,Transistor","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Engenharia (Elétrica)","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630983","enunciado":"Considere, abaixo, um circuito que foi utilizado para acender um led, bem como uma tabela de características de diversos tipos de leds disponíveis. Deseja-se substituir o led branco do circuito por um de outra cor com as características da tabela, sem alterar os valores do resistor e da fonte de alimentação e sem que o novo led possa ser danificado. Supondo-se que os leds suportem até 10%","a":"acima de Imax sem se danificar, para a substituição pretendida, não se utiliza nenhum dos leds da tabela.","b":"utiliza-se apenas o led verde ou o led amarelo.","c":"utiliza-se apenas o led vermelho.","d":"utiliza-se apenas o led azul.","e":"utiliza-se qualquer um dos leds da tabela.","gabarito":"A","materia":"Engenharia Eletrônica","tema":"Eletrônica Analógica na Engenharia Eletrônica ,Diodo na Engenharia Eletrônica","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Engenharia (Elétrica)","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630982","enunciado":"Um Controlador Lógico Programável comanda um motor por meio de sua saída S. Para tanto, dois botões de contato momentâneos, normalmente abertos foram utilizados: B1 e B2. Uma chave principal C habilita o funcionamento desse sistema quando ela se encontra fechada. A função de cada botão é: − ao pressionar B1, o motor deve ligar e permanecer ligado. − ao pressionar B2, o motor deve desligar e permanecer desligado.","a":"O Diagrama em Escada que implementa a lógica de controle desse acionamento é:","b":"","c":"","d":"","e":"","gabarito":"A","materia":"Engenharia Eletrônica","tema":"Automação Industrial ,PLC","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Engenharia (Elétrica)","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630981","enunciado":"Considere o circuito eletropneumático abaixo. Nesse circuito,","a":"a haste do cilindro avança para a direita após um pulso rápido ocorrer no botão B1, que não deve permanecer","b":"pressionado durante o movimento. é utilizado um cilindro de ação simples.","c":"é utilizada uma válvula direcional de 5 vias e 2 posições, servocomandada, com retorno por mola.","d":"o botão B1 provoca o movimento da haste do cilindro para a direita, e o botão B2, para a esquerda.","e":"quando um botão que estiver pressionado for solto, a haste permanecerá na posição em que se encontrava nesse momento, não mais se movendo. Engenharia Elétrica>Distribuição na Engenharia Elétrica ,Equipamentos em Média Tensão ,","gabarito":"C","materia":"Engenharia Mecânica","tema":"Sistemas Fluidomecânicos ,Sistemas Hidráulicos e Pneumáticos","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Engenharia (Elétrica)","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1397","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Engenharia (Elétrica) Motores podem ser protegidos por diversos tipos de dispositivos. O dispositivo que protege contra sobrecarga, falta de fase","a":"e tensão é o fusível.","b":"relé bimetálico.","c":"termopar.","d":"termostato.","e":"varistor.","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Engenharia (Elétrica)","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630979","enunciado":"Um sistema de automação predial possui um painel de comando no qual a identificação dos seus botões pelas suas cores","a":"segue a norma IEC 73. Assim, uma das cores definidas para um botão de acionamento de um motor é verde.","b":"azul.","c":"cinza.","d":"amarelo.","e":"vermelho.","gabarito":"A","materia":"Engenharia Eletrônica","tema":"Automação Industrial ,PLC","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Engenharia (Elétrica)","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630978","enunciado":"Em uma instalação elétrica, a potência ativa consumida é de 100 kW e o fator de potência é de 0,8, o qual será corrigido","a":"para 0,9. Sobre essa instalação, a nova potência aparente será igual à de antes da correção.","b":"a nova potência ativa será de 90 kW.","c":"a nova potência reativa será igual à de antes da correção.","d":"as potências aparentes antes e depois da correção são, respectivamente 125 kVA e 111,1 kVA.","e":"as potências aparentes antes e depois da correção são, respectivamente 80 kVA e 90 kVA.","gabarito":"D","materia":"Engenharia Elétrica","tema":"Instalações Elétricas em Engenharia Elétrica ,Conservação da Energia","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Engenharia (Elétrica)","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630977","enunciado":"Considere o circuito abaixo.","a":"O valor da indutância equivalente Leq entre os pontos A e B encontra-se na faixa 0 H < Leq < 1 H.","b":"1 H ≤ Leq < 2 H.","c":"2 H ≤ Leq < 3 H.","d":"3 H ≤ Leq < 4 H.","e":"4 H ≤ Leq.","gabarito":"C","materia":"Engenharia Elétrica","tema":"Circuitos Elétricos na Engenharia Elétrica ,Circuitos CA ,Medidas Elétricas","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Engenharia (Elétrica)","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630975","enunciado":"Deseja-se calcular o equivalente de Thévenin (VTh e RTh) para o circuito abaixo, que é responsável por alimentar a carga RL. Os valores dos componentes desse circuito são: − R1 = 6 Ω, R2 = 30 Ω, R3 = 8 Ω, R4 = 8 Ω, R5 = 25 Ω, R6 = 100 Ω, RL = 12 Ω. − V1 = 60 V e V2 = 40 V.","a":"Nessas condições, VTh, RTh e a tensão na carga RL (VRL), são, respectivamente: 100 V, 2 Ω, 50 V.","b":"100 V, 4 Ω, 48 V.","c":"40 V, 8 Ω, 12 V.","d":"60 V, 6 Ω, 20 V.","e":"80 V, 8 Ω, 48 V.","gabarito":"E","materia":"Engenharia Elétrica","tema":"Circuitos Elétricos na Engenharia Elétrica ,Circuitos CC","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Engenharia (Elétrica)","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630974","enunciado":"Considere o circuito abaixo.","a":"O equivalente de Norton desse circuito é:","b":"","c":"","d":"","e":"","gabarito":"C","materia":"Engenharia Elétrica","tema":"Circuitos Elétricos na Engenharia Elétrica ,Circuitos CC","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Engenharia (Elétrica)","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630973","enunciado":"Considere o circuito abaixo. − R2 = 20 Ω e R3 = 80 Ω. − E1 = 480 V e E3 = 200 V. − i1 = 1 A e i2 = −2 A.","a":"Nessas condições, E2 = −200 V, i3 = 2 A, R1 = 20 Ω.","b":"E2 = −480 V, i3 = 3 A, R1 = 80 Ω.","c":"E2 = 100 V, i3 = 1 A, R1 = 20 Ω.","d":"E2 = 200 V, i3 = −1 A, R1 = 20 Ω.","e":"E2 = 480 V, i3 = −3 A, R1 = 40 Ω.","gabarito":"E","materia":"Engenharia Elétrica","tema":"Circuitos Elétricos na Engenharia Elétrica ,Circuitos CC","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Engenharia (Elétrica)","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630972","enunciado":"O circuito abaixo é baseado em quatro capacitores, que se encontram inicialmente descarregados. Os valores dos componentes são: − C1 = 2 μF, C2 = 4 μF, C3 = 1 μF, C4 = 5 μF. − E = 15 V.","a":"Após a chave S ser fechada e o circuito se estabilizar, tem-se que a carga em C1 e em C2 são iguais a 10 μC.","b":"carga em C1 é igual a de C3.","c":"carga em C2 é o dobro da carga de C4.","d":"tensão entre os terminais de C1 é igual a 10 V, e nos terminais de C4 igual a 2,5 V.","e":"tensão entre os terminais de C3 é igual à presente nos terminais de C2.","gabarito":"D","materia":"Engenharia Elétrica","tema":"Circuitos Elétricos na Engenharia Elétrica ,Circuitos CC","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Engenharia (Elétrica)","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630970","enunciado":"Do ponto de vista magnético, os materiais podem ser caracterizados por sua permeabilidade magnética, podendo-se distinguir os tipos de meios ferromagnéticos, diamagnéticos e paramagnéticos. Um exemplo de material classificado como","a":"diamagnético é: Alumínio.","b":"Cromo.","c":"Platina.","d":"Prata.","e":"Sódio.","gabarito":"D","materia":"Engenharia Elétrica","tema":"Eletromagnetismo na Engenharia Elétrica ,Materiais Elétricos","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Engenharia (Elétrica)","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630969","enunciado":"Deseja-se que um fio condutor possua resistência de 15 Ω. Sabe-se que as características do condutor são: − seção quadrada, de lados iguais a 1 mm. −8 − resistividade: 1,5 × 10 Ω . m.","a":"Desta forma, o comprimento do fio deverá ser, em m, igual a 1.","b":"10.000.","c":"100.","d":"1.000.","e":"10.","gabarito":"D","materia":"Engenharia Elétrica","tema":"Eletromagnetismo na Engenharia Elétrica ,Materiais Elétricos","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Engenharia (Elétrica)","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630968","enunciado":"No sistema elétrico há um tipo específico de meio de comunicação de dados denominado Power Line Communication − PLC, no qual se utiliza a infraestrutura do sistema elétrico para a comunicação de dados. Considerando o modelo OSI de sete","a":"camadas para a estruturação das redes de comunicação, o PLC é localizado na camada de Aplicação.","b":"Enlace de dados.","c":"Rede.","d":"Sessão.","e":"Transporte.","gabarito":"B","materia":"Engenharia Eletrônica","tema":"Automação Industrial ,PLC","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Engenharia (Elétrica)","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630967","enunciado":"","a":"O uso de inversores de frequência com controle vetorial, ao invés do controle escalar, é indicado para motores universais, quando se deseja realizar o controle preciso da velocidade.","b":"de indução trifásico, quando a rotação de operação é superior a 10.000 rpm.","c":"síncronos, quando não se pode medir ou estimar a orientação do campo magnético.","d":"universais, quando a faixa de variação de velocidade de rotação é ampla.","e":"de indução trifásico, quando se deseja realizar o controle do torque.","gabarito":"E","materia":"Engenharia Eletrônica","tema":"Eletrônica de Potência na Engenharia Eletrônica ,Inversores","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Engenharia (Elétrica)","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630966","enunciado":"Uma carga resistiva de 5 Ω é acionada por meio de um SCR e uma tensão de 127 V (valor eficaz). Para limitar o degrau de","a":"corrente em 20 A/μs, o valor do indutor a ser adicionado ao circuito é, em μH, aproximadamente, 45.","b":"3.","c":"32.","d":"9.","e":"18. Engenharia Eletrônica>Eletrônica Analógica na Engenharia Eletrônica ,Diodo na Engenharia Eletrônica ,","gabarito":"D","materia":"Engenharia Eletrônica","tema":"Eletrônica de Potência na Engenharia Eletrônica ,Tiristor","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Engenharia (Elétrica)","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1410","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Engenharia (Elétrica) Considere, abaixo, o circuito de acionamento de carga baseado em SCR ideal. Sabendo-se que Vg = 12 V; Ig (corrente de gatilho) = 100 mA; Vgk (máxima tensão de gatilho) = 2 V, o valor de Rg para","a":"possibilitar o disparo do SCR é, em Ω, 100.","b":"20.","c":"200.","d":"10.","e":"140.","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Engenharia (Elétrica)","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630964","enunciado":"","a":"figura abaixo mostra a curva característica de um dispositivo semicondutor de potência (tiristor). A região da curva identificada por I é denominada região de","b":"A amplificação. bloqueio.","c":"condução.","d":"depleção.","e":"saturação. Segurança e Saúde no Trabalho>","gabarito":"B","materia":"Engenharia Eletrônica","tema":"Eletrônica de Potência na Engenharia Eletrônica ,Tiristor","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Engenharia (Elétrica)","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630963","enunciado":"","a":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Engenharia (Elétrica) NR-10 estabelece procedimentos apropriados para realizar a desenergização do sistema elétrico. Considere os quatro procedimentos (do total de seis) constantes na NR-10: 1. Seccionamento; 2. Instalação da sinalização de impedimento de reenergização; 3. Proteção dos elementos energizados existentes na zona controlada; 4. Impedimento de reenergização. A ordem correta de execução desses procedimentos, desconsiderando os dois não apresentados, é","b":"A 1, 2, 4 e 3. 2, 1, 4 e 3.","c":"1, 4, 3 e 2.","d":"2, 3, 1 e 4.","e":"1, 3, 4 e 2. Segurança e Saúde no Trabalho>","gabarito":"C","materia":"NR 10 - Norma Regulamentadora nº 10 - Segurança em Instalações e Serviços em Eletricidade","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Engenharia (Elétrica)","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630962","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Engenharia (Elétrica) De acordo com a NR-10, em qualquer atividade ou procedimento junto ao sistema elétrico deve-se fazer uso dos equipamentos de proteção coletivo e/ou individual. O uso de equipamento de proteção contra queda é obrigatório em","a":"atividades com altura, a partir do solo, acima de 1,5 m.","b":"3 m.","c":"2 m.","d":"5 m.","e":"4 m.","gabarito":"C","materia":"NR 10 - Norma Regulamentadora nº 10 - Segurança em Instalações e Serviços em Eletricidade","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Engenharia (Elétrica)","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630961","enunciado":"Um voltímetro com escala de 0 [V] a 200 [V] é conectado a um Transformador de Potencial − TP 13.800/180 [V]. Sabendo-se","a":"que a leitura indicada no voltímetro é 174 [V], o valor da tensão primária, em [V], é 13.740.","b":"13.480.","c":"13.220.","d":"13.340.","e":"13.620.","gabarito":"D","materia":"Engenharia Elétrica","tema":"Máquinas Elétricas ,Transformador de Potencial ,Medidas Elétricas","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Engenharia (Elétrica)","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630960","enunciado":"Uma máquina de corrente contínua está operando como gerador com enrolamento de campo em paralelo. Sabendo-se que a especificação do gerador é: Potência nominal = 10 [kW]; Ea (tensão de armadura) na rotação nominal de 800 [rpm] = 100","a":"[V]; resistência do enrolamento de armadura é 0,2 [Ω], a tensão gerada nos terminais do gerador é, em [V], 100.","b":"98.","c":"80.","d":"112.","e":"68.","gabarito":"C","materia":"Engenharia Elétrica","tema":"Máquinas Elétricas ,Máquina de Corrente Contínua","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Engenharia (Elétrica)","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630959","enunciado":"Dentre os tipos de motores de corrente contínua, o que tem como característica apresentar uma grande variação de","a":"velocidade de rotação de acordo com o torque da carga movimentada, é o motor de excitação independente.","b":"série.","c":"de excitação composta.","d":"derivação.","e":"de excitação paralela.","gabarito":"B","materia":"Engenharia Elétrica","tema":"Máquinas Elétricas ,Máquina de Corrente Contínua","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Engenharia (Elétrica)","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630958","enunciado":"Uma máquina elétrica de corrente contínua é constituída de duas partes principais: o estator, no qual se encontra o enrolamento de campo, e o rotor, no qual se encontra o enrolamento de armadura. Na configuração como gerador com excitação de campo paralelo, os enrolamentos de campo e de armadura são conectados em paralelo. Nessa configuração, o","a":"processo inicial de geração requer o uso de uma alimentação no momento da partida.","b":"ocorre com o uso de um imã permanente acoplado ao estator.","c":"requer o uso de um capacitor de partida acoplado ao estator.","d":"ocorre devido à existência do fluxo magnético residual.","e":"necessita do uso de uma chave comutadora que desliga momentaneamente o estator.","gabarito":"D","materia":"Engenharia Elétrica","tema":"Máquinas Elétricas ,Máquina de Corrente Contínua","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Engenharia (Elétrica)","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630957","enunciado":"Um motor de indução trifásico de 6 polos / 60 [Hz], opera com carga e escorregamento de 2%. A velocidade de rotação do","a":"seu eixo é, em [rpm], 1.200.","b":"782.","c":"1.764.","d":"600.","e":"1.176.","gabarito":"E","materia":"Engenharia Elétrica","tema":"Máquinas Elétricas ,Máquina de Indução","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Engenharia (Elétrica)","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630956","enunciado":"Dentre os diversos tipos de máquinas, a máquina síncrona de polos girantes e rotores de polos salientes é destinada para","a":"utilização em geradores de turbina a vapor.","b":"estacionários a diesel.","c":"de usinas nucleares.","d":"hidroelétricos.","e":"de turbina a gás.","gabarito":"D","materia":"Engenharia Elétrica","tema":"Máquinas Elétricas ,Máquina Síncrona","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Engenharia (Elétrica)","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630955","enunciado":"Um transformador de potência monofásico apresenta a seguinte especificação: 13,8/0,66 [kV], 1 [MVA], 60 [Hz]. A corrente","a":"nominal no primário, em [A], é, aproximadamente, 660.","b":"1.320.","c":"72.","d":"138.","e":"1.515.","gabarito":"C","materia":"Engenharia Elétrica","tema":"Máquinas Elétricas ,Transformador de Potência","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Engenharia (Elétrica)","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630954","enunciado":"Considere um transformador trifásico com ligação Δ − Y e relação de transformação a = 100. Caso uma fonte trifásica ideal, conectada em estrela e com tensão de fase de 15 [kV] seja ligada ao primário, a tensão de fase no secundário será, em [V],","a":"aproximadamente, 260.","b":"183.","c":"150.","d":"87.","e":"1.500.","gabarito":"A","materia":"Engenharia Elétrica","tema":"Máquinas Elétricas ,Transformador de Potência","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Engenharia (Elétrica)","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630953","enunciado":"Um transformador real apresenta perdas no processo de transformação do primário para o secundário e vice-versa. Um","a":"dos tipos de perda é conhecido como perdas por correntes parasitas, que decorre da corrente induzida no enrolamento primário devido ao reflexo do enrolamento secundário.","b":"existência da resistência ôhmica nos enrolamentos, o que provoca a perda por geração de calor.","c":"existência de indutância mútua entre os enrolamentos, o que provoca a indução de correntes em ambos.","d":"corrente induzida no núcleo devido ao campo magnético, o que provoca a perda por geração de calor.","e":"corrente gerada pela histerese magnética, o que induz uma corrente defasada no enrolamento primário.","gabarito":"D","materia":"Engenharia Elétrica","tema":"Eletromagnetismo na Engenharia Elétrica","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Engenharia (Elétrica)","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630952","enunciado":"Com o objetivo de desenvolver um galvanômetro foi construída uma bobina indutora com 100 espiras, 5 [mm] de 2 comprimento, área transversal da espira de 0,4 [cm ] e núcleo de ar. Considerando a permeabilidade magnética do ar (μo) −7","a":"= 4 . π . 10 , a indutância da bobina é, em [μH], aproximadamente, 25.","b":"230.","c":"100.","d":"360.","e":"68.","gabarito":"C","materia":"Engenharia Elétrica","tema":"Eletromagnetismo na Engenharia Elétrica ,Materiais Elétricos ,Medidas Elétricas","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Engenharia (Elétrica)","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630951","enunciado":"Considere um fio condutor de diâmetro A, no qual percorre uma corrente I. Esse fio é submetido a um campo magnético B","a":"perpendicular a ele. A representação correta da força F gerada é apresentada em","b":"","c":"","d":"","e":"","gabarito":"B","materia":"Engenharia Elétrica","tema":"Eletromagnetismo na Engenharia Elétrica","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Engenharia (Elétrica)","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630950","enunciado":"2 Considere um material ferromagnético com secção (área) transversal de 1 [cm ], no qual existe um fluxo magnético −3 perpendicular de 20 × 10 [Wb]. Nessa situação, a densidade de fluxo magnético é, em [Gauss],","a":"2 2 . 10 .","b":"−2 5 . 10 .","c":"4 2 . 10 .","d":"2 5 . 10 .","e":"6. 2 . 10","gabarito":"E","materia":"Engenharia Elétrica","tema":"Eletromagnetismo na Engenharia Elétrica ,Materiais Elétricos","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Engenharia (Elétrica)","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630949","enunciado":"Um sistema de microgeração de energia elétrica trifásico conectado em estrela, construído de forma personalizada, fornece","a":"tensão de linha de 145 [V]/50 [Hz]. A tensão de fase nesse sistema é, em [V], aproximadamente, 110.","b":"251.","c":"84.","d":"103.","e":"73.","gabarito":"C","materia":"Engenharia Elétrica","tema":"Circuitos Elétricos na Engenharia Elétrica ,Circuitos Trifásicos em Engenharia Elétrica","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Engenharia (Elétrica)","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630753","enunciado":"Considere a sentença abaixo. To generate the swelling curve, it is first necessary to estimate three variables which affect the rate and potential magnitude of serviceability loss due to swelling … [ ] ... Generally, swelling need only be considered for fine-grained soils such as clays and silts.","a":"Os termos swelling e clays referem-se, respectivamente, a expansão e areias.","b":"inchamento e areias.","c":"inchamento e pedregulhos.","d":"expansão e argilas.","e":"dilatação e conchas.","gabarito":"D","materia":"Inglês","tema":"Tradução | Translation ,Vocabulário | Vocabulary","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Edificações","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630752","enunciado":"Curing is the process in which the concrete is protected from loss of moisture and kept within a reasonable temperature range. This process results in concrete with increased strength and decreased permeability. Curing is also a key player in mitigating cracks, which can severely affect durability.","a":"O termo strength pode ser traduzido como compressão.","b":"resistência.","c":"elasticidade.","d":"tração.","e":"flexão.","gabarito":"B","materia":"Inglês","tema":"Tradução | Translation ,Vocabulário | Vocabulary","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Edificações","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630751","enunciado":"","a":"O termo loss of moisture pode ser traduzido como aumento de umidade.","b":"aumento de resistência.","c":"aparência da mistura.","d":"crescimento da mistura.","e":"perda de umidade.","gabarito":"E","materia":"Inglês","tema":"Tradução | Translation ,Vocabulário | Vocabulary","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Edificações","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630750","enunciado":"","a":"sentença refere-se a","b":"A cura do concreto. dosagem do concreto.","c":"hidratação da argamassa.","d":"produção de concreto.","e":"aplicação do concreto.","gabarito":"A","materia":"Inglês","tema":"Interpretação de texto | Reading comprehension","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Edificações","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630749","enunciado":"","a":"Os termos mortar e masonry referem-se, respectivamente, a esquadria e alvenaria.","b":"alvenaria e tijolos.","c":"esquadria e verga.","d":"argamassa e alvenaria.","e":"argamassa e esquadria.","gabarito":"D","materia":"Inglês","tema":"Tradução | Translation ,Vocabulário | Vocabulary","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Edificações","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630748","enunciado":"Considere a sentença abaixo. In the repair and maintenance of traditional buildings it is always best practice to retain as much of the original material as possible. Where that is not possible, the most effective alternative involves the understanding and use of materials and techniques that were employed in the original construction.","a":"Na sentença, a expressão traditional building refere-se a edifícios históricos.","b":"edifícios convencionais.","c":"construções públicas.","d":"construções modernas.","e":"edifícios em ruínas.","gabarito":"A","materia":"Inglês","tema":"Tradução | Translation ,Vocabulário | Vocabulary","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Edificações","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630747","enunciado":"Em relação aos diversos comandos disponíveis no AutoCad, considere: I. ARRAY − Cria cópias múltiplas de objetos em uma disposição definida. II. COPY − Copia objetos com um ponto base especificado. III. SAVEAS − Salva um desenho ainda não nomeado ou renomeia o desenho corrente. IV. SCALE − Amplia objetos selecionados igualmente nas direções X, Y, e Z.","a":"Está correto o que consta em II, III e IV, apenas.","b":"I e III, apenas.","c":"I e II, apenas.","d":"III e IV, apenas.","e":"I, II, III e IV.","gabarito":"B","materia":"Edificações","tema":"Estudos Preliminares ,Desenho Técnico em Edificações","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Edificações","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630746","enunciado":"Ao identificar os arquivos eletrônicos dos desenhos de planta baixa, o técnico verificou a inexistência de cotas. Para","a":"determinar a medida da largura de uma porta utiliza-se o comando pan.","b":"trim.","c":"plot.","d":"list.","e":"dist.","gabarito":"E","materia":"Engenharia Civil","tema":"Desenho na Engenharia Civil ,AutoCAD","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Edificações","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630745","enunciado":"Para a reprodução, em papel, de desenhos referentes ao detalhamento arquitetônico de uma obra de implantação de uma","a":"edificação, foram criados arquivos, utilizando o software AutoCad, com extensão do tipo .dxf.","b":".ctb.","c":".plt.","d":".dwg.","e":".pdf. Edificações>Estudos Preliminares ,Limpeza e Preparo do Terreno ,Sistemas e Processos Construtivos","gabarito":"C","materia":"Engenharia Civil","tema":"Desenho na Engenharia Civil ,AutoCAD","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Edificações","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1436","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Edificações Para a realização de escavações em terrenos, a área deve ser previamente limpa. É necessário também examinar as propriedades vizinhas, visando verificar a necessidade de medidas preventivas. Sobre a segurança em escavações, considere: I. Em taludes instáveis com altura superior a 1,25 m deve ser previsto escoramento. II. O material escavado pode ser depositado inicialmente na borda do talude, antes da destinação final. III. Não é permitida a escavação quando houver a possibilidade de infiltração ou vazamento de gás. IV. Na escavação de tubulões, o diâmetro mínimo é de 0,80 m, podendo ser aceito o diâmetro de 0,70 m com justificativa técnica do engenheiro.","a":"Está correto o que consta em I e IV, apenas.","b":"II e III, apenas.","c":"I e II, apenas.","d":"III e IV, apenas.","e":"I, II, III e IV.","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Edificações","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630743","enunciado":"Na elaboração de um orçamento de obra devem ser considerados dois tipos de custos, os diretos e indiretos. Os itens","a":"apresentados são considerados no cálculo dos custos diretos EXCETO o salário da mão de obra produtiva.","b":"o aluguel do escritório administrativo.","c":"os encargos sociais da mão de obra produtiva.","d":"os equipamentos de obra.","e":"os materiais de obra. Edificações>Sistemas e Processos Construtivos ,Materiais de construção em Edificações ,","gabarito":"B","materia":"Edificações","tema":"Estudos Preliminares ,Orçamento nos Estudos Preliminares nem Edificações","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Edificações","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630741","enunciado":"Em relação aos tipos de manutenção, considere: I. Conservação é o conjunto de atividades técnicas e administrativas destinadas a preservar as características de desempenho técnico dos componentes da edificação. II. A atividade de manutenção executada após a ocorrência de falha ou de desempenho insuficiente dos componentes da edificação denomina-se manutenção corretiva. III. Manutenção preventiva é a atividade de manutenção executada antes da ocorrência de falha ou de desempenho insuficiente dos componentes da edificação. IV. Manutenção programada é a manutenção preventiva realizada em obediência a um Programa ou Plano de Manutenção dos componentes da edificação.","a":"Está correto o que consta em III, apenas.","b":"I e III, apenas.","c":"II e IV, apenas.","d":"I, II, III e IV.","e":"II, apenas.","gabarito":"D","materia":"Edificações","tema":"Procedimentos Finais e Manutenção ,Manutenção em Edificações","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Edificações","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630740","enunciado":"Um carrinho de obra será utilizado para carregar 6 tábuas de madeira com dimensões de comprimento igual a 2,0 m, de 3 largura igual a 0,4 m e espessura de 5 cm. Sabendo-se que o peso específico deste tipo de madeira é igual a 500 kgf/m , o","a":"peso total das 6 tábuas, em kgf, é igual a 12.","b":"400.","c":"1200.","d":"20.","e":"120.","gabarito":"E","materia":"Edificações","tema":"Sistemas e Processos Construtivos ,Marcenaria","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Edificações","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630739","enunciado":"Para a elaboração do dimensionamento de uma viga de uma estrutura de concreto armado foram determinados todos os carregamentos externos, acidentais e permanentes. A partir destes dados e das características geométricas da viga o projetista, utilizando os conceitos da física relativos à estática, calculou as reações de apoio e o diagrama de esforços","a":"internos. Os esforços internos determinados foram, no mínimo, flexão, tração e momento fletor.","b":"tração, cisalhamento e cortante.","c":"normal, cortante e momento fletor.","d":"normal, tração e momento fletor.","e":"normal, momento fletor e flexão.","gabarito":"C","materia":"Edificações","tema":"Sistemas e Processos Construtivos ,Estruturas nos Sistemas e Processos Construtivos","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Edificações","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630738","enunciado":"Considere a viga isostática abaixo e suas cargas concentradas.","a":"O valor das reações verticais no apoio A e no apoio B são, em N, respectivamente, iguais a 45 e 65.","b":"50 e 60.","c":"60 e 50.","d":"60 e 55.","e":"65 e 45.","gabarito":"C","materia":"Edificações","tema":"Sistemas e Processos Construtivos ,Estruturas nos Sistemas e Processos Construtivos","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Edificações","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630737","enunciado":"O projeto estrutural de uma marquise contempla uma viga isostática em balanço com carregamento distribuído retangular igual a 18 kN/m. Sabendo-se que o vão dessa viga possui 1,5 m, o valor de momento fletor máximo negativo, em kN/m, é","a":"igual a 40,5.","b":"27.","c":"12.","d":"20,25.","e":"18,9.","gabarito":"D","materia":"Edificações","tema":"Sistemas e Processos Construtivos ,Estruturas nos Sistemas e Processos Construtivos","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Edificações","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630736","enunciado":"Em relação ao projeto de instalações prediais de água quente, considere: I. Dependendo do tipo de material especificado e das peculiaridades da instalação, o projetista deve considerar a necessidade de seu isolamento térmico e acústico. II. Deve ser levado em consideração no projeto o efeito de dilatação e contração térmica da tubulação e devem ser cumpridas as especificações de instalação para cada tipo de material. III. As tubulações não devem ser solidárias aos elementos estruturais, devendo ser alojadas em passagens projetadas para este fim. IV. A velocidade da água nas tubulações deve ser superior a 3 m/s.","a":"Está correto o que consta APENAS em II.","b":"III e IV.","c":"I, II e IV.","d":"III.","e":"I, II e III.","gabarito":"E","materia":"Engenharia Civil","tema":"Instalações em Engenharia Civil ,Instalações Hidrosanitárias","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Edificações","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630735","enunciado":"No projeto de instalações prediais hidráulicas de água fria é necessário prever o Consumo Diário − CD, ou seja, o valor médio previsto para utilização em um edifício em 24 horas. É utilizado no dimensionamento do ramal predial, hidrômetro, ramal de alimentação, instalação de recalque e reservatórios. Na realização do dimensionamento, estima-se que a 2 população em um escritório (edifício institucional) seja de 1 pessoa/10 m e que a estimativa do consumo predial médio 2 diário per capita seja de 50 L/dia. Dada a implantação de um edifício de 3.000 m de área construída, o consumo mensal de 3","a":"água previsto (considerando a utilização nos 30 dias do mês) é, em m /mês, de 4.500.","b":"450.","c":"150.","d":"450.000.","e":"15.000.","gabarito":"B","materia":"Edificações","tema":"Sistemas e Processos Construtivos ,Instalações em Edificações","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Edificações","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630734","enunciado":"Em instalações prediais hidráulicas, são necessários diversos dispositivos para alimentação distribuição, controle e regulação da vazão a cada elemento da edificação atendido. A função do registro de utilização em um sistema predial de","a":"água fria é controlar a vazão da água utilizada na tubulação. Geralmente empregam-se registros de pressão ou válvula globo.","b":"interromper a passagem de água na tubulação. Geralmente emprega-se registro de gaveta ou esfera.","c":"interromper a passagem de água para os reservatórios.","d":"manter a tubulação a jusante em uma pressão estabelecida.","e":"evitar o refluxo por sucção de água na tubulação. Edificações>Sistemas e Processos Construtivos ,Estruturas nos Sistemas e Processos Construtivos ,","gabarito":"A","materia":"Edificações","tema":"Sistemas e Processos Construtivos ,Instalações em Edificações","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Edificações","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1446","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Edificações Em uma estrutura de concreto de uma edificação, é usual a especificação de resistências à compressão distintas para os elementos estruturais ou mesmo a utilização de tipos distintos de concreto. O controle tecnológico deve realizar os ensaios específicos e necessários para cada tipo e classe de concreto. Caso o concreto seja preparado na obra, os ensaios de abatimento de tronco de cone devem ser realizados com uma dada frequência ou sempre que uma dada situação ocorra.","a":"Entre as situações possíveis, NÃO é prevista em norma a realização do ensaio na primeira amassada do dia.","b":"3 a cada 100 m .","c":"ao reiniciar o preparo após uma interrupção na concretagem de, no mínimo, 2h.","d":"na troca dos operadores.","e":"cada vez que forem moldados corpos de prova.","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Edificações","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630731","enunciado":"Em uma obra de recuperação estrutural foi necessário o preenchimento de vazios em locais de difícil acesso, por se tratarem de cavidades muito estreitas ou locais com elevada densidade de obstáculos tais como armaduras, tubulações, entre outros. Buscou-se utilizar um material com fluidez que permitisse o preenchimento total da seção, sem a necessidade de adensamento. Este material também deveria possuir alta resistência inicial que permitisse a rápida liberação das fôrmas","a":"e rápida colocação da estrutura reparada ou reforçada em carga. O material utilizado deve ser argamassa de cal.","b":"gesso.","c":"clínquer.","d":"graute.","e":"rejunte.","gabarito":"D","materia":"Edificações","tema":"Sistemas e Processos Construtivos ,Estruturas nos Sistemas e Processos Construtivos","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Edificações","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630730","enunciado":"O aglomerante hidráulico é aquele cuja pasta apresenta a propriedade de endurecer apenas pela reação com a água e que,","a":"após seu endurecimento, resiste satisfatoriamente quando submetida à ação da água. Um exemplo deste material é a resina.","b":"o cimento asfáltico de petróleo.","c":"a cal virgem.","d":"o cimento Portland.","e":"o gesso. Edificações>Sistemas e Processos Construtivos ,Revestimento e Impermeabilização ,","gabarito":"D","materia":"Edificações","tema":"Sistemas e Processos Construtivos ,Materiais de construção em Edificações","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Edificações","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1449","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Edificações Na escolha das tintas a serem utilizadas para a pintura de ambientes internos de uma edificação residencial, optou-se pela","a":"utilização de tintas látex PVA. A ferramenta mais indicada para a sua aplicação é o rolo de lã de carneiro.","b":"o rolo de lã para epóxi.","c":"o rolo de espuma.","d":"a espátula.","e":"a pistola de pintura.","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Edificações","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630728","enunciado":"","a":"cobertura de uma tinta é a propriedade do material, ao revestir o substrato no qual foi aplicado, proporcionar opacidade. A cobertura é uma propriedade que pode ser verificada tanto no filme úmido quanto no seco e está relacionada à presença de um complemento denominado","b":"A pigmento. diluente.","c":"solvente.","d":"tíner.","e":"secante.","gabarito":"A","materia":"Edificações","tema":"Sistemas e Processos Construtivos ,Revestimento e Impermeabilização","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Edificações","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630727","enunciado":"Um edifício institucional será executado com fundações do tipo estacas, com o objetivo de atingir a resistência do solo em camadas mais profundas. Foi adotada no projeto a estaca tipo Strauss, a qual é","a":"executada mediante a introdução de um trado helicoidal contínuo no terreno e injeção de concreto pela própria haste central do trado simultaneamente com a sua retirada, sendo que a armadura é introduzida após a concretagem.","b":"armada e preenchida com cimento e areia, executada por meio de perfuração rotativa, revestida integralmente por um conjunto de tubos metálicos recuperáveis.","c":"constituída de segmentos de concreto pré-moldado e introduzida no terreno por meio de golpes de martelo de gravidade, de explosão, hidráulico ou vibratório.","d":"executada pela cravação, por meio de sucessivos golpes de um pilão de um tubo de ponta fechada por uma bucha seca. Esta estaca possui base alargada.","e":"executada por perfuração do solo com uma sonda e revestimento total com camisa metálica, realizando o lançamento do concreto e retirada gradativa do revestimento com simultâneo apiloamento do concreto.","gabarito":"E","materia":"Engenharia Civil","tema":"Geotecnia ,Fundação","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Edificações","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630726","enunciado":"No planejamento da construção de uma nova edificação, devem ser previstos serviços iniciais, como levantamento topográfico e serviços geotécnicos, para subsídio do projeto executivo. Os serviços geotécnicos correspondem à execução de sondagens e análise dos resultados, para escolha do tipo de fundação a ser adotada. Para uma edificação cuja área de 2","a":"projeção é igual a 1.400 m , o número de furos de sondagens a ser executado conforme a norma brasileira é 8.","b":"6.","c":"7.","d":"3.","e":"a critério do projetista.","gabarito":"C","materia":"Edificações","tema":"Estudos Preliminares ,Estudos Topográficos","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Edificações","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630725","enunciado":"Para o projeto de fundações é necessário o conhecimento prévio das características do solo. Uma forma de se obter informações sobre o subsolo é por meio das sondagens de simples reconhecimento com realização de ensaio SPT. O","a":"parâmetro obtido neste ensaio está relacionado ao adensamento.","b":"à umidade natural do solo.","c":"à resistência do solo à penetração do amostrador.","d":"ao índice de vazios de cada camada.","e":"à permeabilidade do solo.","gabarito":"C","materia":"Engenharia Civil","tema":"Geotecnia ,Sondagem ,Fundação","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Edificações","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630724","enunciado":"Em vias pavimentadas devem ser implantados dispositivos de drenagem superficial, que tem a finalidade de coletar os","a":"fluxos de água que escoam sobre a superfície do pavimento. NÃO é um dispositivo de drenagem superficial: sarjeta.","b":"trincheira.","c":"boca de lobo.","d":"boca de leão.","e":"gárgula.","gabarito":"B","materia":"Edificações","tema":"Sistemas e Processos Construtivos ,Estruturas nos Sistemas e Processos Construtivos","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Edificações","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630723","enunciado":"Em uma estrutura de pavimento, a camada de revestimento é a camada de rolamento, utilizada para melhorar o conforto, a durabilidade e a segurança, além de resistir ao desgaste. O material tipicamente utilizado como camada de revestimento em um pavimento asfáltico é o Concreto Betuminoso Usinado a Quente – CBUQ, composto por uma mistura de ligante","a":"asfáltico mais os agregados graúdos e miúdos. O tipo de ligante utilizado na produção do CBUQ é a emulsão asfáltica de ruptura lenta RL.","b":"a emulsão asfáltica de ruptura rápida RR.","c":"o cimento asfáltico de petróleo – CAP.","d":"o asfalto diluído de cura rápida.","e":"o cimento Portland – CP.","gabarito":"C","materia":"Edificações","tema":"Sistemas e Processos Construtivos ,Revestimento e Impermeabilização ,Coberturas e Pavimentos","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Edificações","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630722","enunciado":"Durante os serviços de pavimentação asfáltica, são mobilizados diversos equipamentos para a aplicação de materiais ou para os serviços de espalhamento, vibração e compactação. No planejamento dos serviços, o equipamento a ser indicado","a":"para a aplicação das emulsões asfálticas utilizadas para a imprimadura ligante é o rolo liso.","b":"a vibroacabadora.","c":"o motoscraper.","d":"o rolo de pneus.","e":"o espargidor de asfalto.","gabarito":"E","materia":"Edificações","tema":"Sistemas e Processos Construtivos ,Coberturas e Pavimentos","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Edificações","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630721","enunciado":"Em um sistema de drenagem o objetivo principal é coletar as águas e conduzi-las ao deságue adequado. Em um curso","a":"d’água, o fluxo de água ocorre de montante a jusante.","b":"jusante a montante.","c":"montante a nascente.","d":"nascente a montante.","e":"jusante a nascente.","gabarito":"A","materia":"Edificações","tema":"Sistemas e Processos Construtivos ,Instalações em Edificações","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Edificações","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630720","enunciado":"O objetivo da drenagem superficial é dar escoamento às águas que se acumulam na superfície de toda plataforma viária quando ocorre a precipitação pluviométrica. A operação da drenagem superficial depende da funcionalidade das estruturas construídas para retirada das águas da plataforma. Dispositivos condutores enterrados utilizados para dar passagem às","a":"águas provenientes da drenagem superficial e das contribuições das precipitações pluviométricas são as sarjetas.","b":"os poços de visita.","c":"as valetas de proteção.","d":"os bueiros de greide.","e":"as caixas coletoras.","gabarito":"D","materia":"Edificações","tema":"Sistemas e Processos Construtivos ,Instalações em Edificações","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Edificações","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630719","enunciado":"Durante a execução dos serviços de terraplenagem, a compactação consiste na redução dos vazios do solo por meio de processos mecânicos. Trata-se de um processo rápido, diferindo portanto do adensamento propriamente dito, que decorre de uma expulsão lenta da água dos vazios do solo. Sobre o processo de adensamento, considere: I. A variação de volume por adensamento ocorre somente na direção horizontal. II. O recalque total de uma camada adensável saturada será função da variação do seu índice de vazios. III. Na previsão de um recalque aplica-se uma relação diretamente proporcional entre o recalque e a espessura da camada adensável. IV. Nos solos granulares, a água flui lentamente devido à baixa permeabilidade e o gradiente é dissipado também de modo lento.","a":"Está correto o que consta APENAS em II e IV.","b":"I e II.","c":"I e III.","d":"II e III.","e":"I, II e IV.","gabarito":"D","materia":"Edificações","tema":"Estudos Preliminares ,Limpeza e Preparo do Terreno","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Edificações","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630718","enunciado":"Os serviços de terraplenagem são executados em cinco operações básicas: escavação, carregamento, transporte, espalhamento e compactação. Esta última operação consiste em adensar o solo espalhado e a liberação para medição é dada quando a camada atingir o Grau de Compactação − GC exigido. Entre os ensaios indicados a seguir, NÃO é utilizado","a":"para controle da compactação em campo: o “speedy”.","b":"a determinação do ponto de fulgor.","c":"o método da frigideira.","d":"o frasco de areia.","e":"o método do cilindro cortante. Edificações>Sistemas e Processos Construtivos ,Estruturas nos Sistemas e Processos Construtivos ,","gabarito":"B","materia":"Edificações","tema":"Estudos Preliminares ,Limpeza e Preparo do Terreno","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Edificações","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1461","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Edificações O projeto executivo de uma edificação com estrutura em concreto armado apresentava em seu orçamento a necessidade de 775 toneladas de concreto de cimento Portland. Ao tentar adquirir o concreto, o responsável pela compra, verificou que 3 3 o material era comercializado em volume, m . Considerando a massa específica do concreto igual a 2.500 kg/m seria 3","a":"necessária a compra de um volume total de concreto, em m , igual a 775.","b":"1,9375.","c":"0,31.","d":"310.","e":"1.937,5.","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Edificações","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630716","enunciado":"Na elaboração do orçamento de uma obra de implantação de uma edificação de pequeno porte verificou-se que para a implantação da estrutura e concreto armado seria necessária a implantação de formas. Para a quantificação deste material e posterior orçamento, sem considerar a necessidade de cimbramento, a unidade utilizada deve ser","a":"2 m .","b":"3 m .","c":"tonelada.","d":"hora.","e":"kg.","gabarito":"A","materia":"Edificações","tema":"Estudos Preliminares ,Orçamento nos Estudos Preliminares nem Edificações","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Edificações","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630715","enunciado":"","a":"implantação de um passeio de concreto prevê uma camada de lastro de concreto com espessura de 8 cm. A execução 2 desse serviço será paga em m . A tabela abaixo apresenta a composição desse serviço. Considerando o custo do saco de cimento de 50 kg igual a R$ 20,00, a hora do pedreiro custa R$ 10,00; a hora do servente 3 custa R$ 6,00 e o m de seixo rolado e da areia lavada é igual a R$ 1,00 cada. O custo total aproximado, em R$, a ser 2 cobrado para a execução de 50 m será igual a","b":"A 9.268,75. 308,83.","c":"741,50.","d":"3.100,00.","e":"1.310,00.","gabarito":"C","materia":"Edificações","tema":"Estudos Preliminares ,Orçamento nos Estudos Preliminares nem Edificações","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Edificações","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630714","enunciado":"Em relação às peças componentes do telhado, considere: I. A aresta inclinada delimitada pelo encontro entre duas águas que formam um ângulo saliente e é conhecida como um divisor de águas. II. A aresta inclinada delimitada pelo encontro entre suas águas que formam um ângulo reentrante e é conhecida como um captador de águas. III. A peça complementar de arremate entre o telhado e uma parede.","a":"As peças descritas em I, II e III, referem-se, respectivamente, ao espigão, rincão e rufo.","b":"beiral, rincão e cumeeira.","c":"espigão, rufo e chapuz.","d":"rincão, espigão e chapuz.","e":"rufo, cumeeira e cumeeira.","gabarito":"A","materia":"Edificações","tema":"Sistemas e Processos Construtivos ,Coberturas e Pavimentos","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Edificações","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630713","enunciado":"O projeto de um telhado de madeira apresenta o detalhamento de peças que serão colocadas horizontalmente e pregadas","a":"sobre os caibros para o apoio das telhas cerâmicas. Essas peças são conhecidas como ripas.","b":"cumeeiras.","c":"fiadas.","d":"terças.","e":"tesouras.","gabarito":"A","materia":"Engenharia Civil","tema":"Arquitetura na Engenharia Civil ,Cobertura","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Edificações","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630712","enunciado":"","a":"camada de revestimento de paredes destinada ao preparo da base com a finalidade de uniformizar a superfície quanto à absorção e melhorar a aderência é conhecida como","b":"A reboco. emboço.","c":"chapisco.","d":"argamassa colante.","e":"impermeabilização.","gabarito":"C","materia":"Engenharia Civil","tema":"Edificação ,Revestimento","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Edificações","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630711","enunciado":"","a":"descrição da janela que é constituída por uma ou várias folhas e que podem ser movimentadas mediante rotação em torno de um eixo vertical e não coincidente com as laterais das folhas é do tipo","b":"A basculante. pivotante vertical.","c":"sanfona.","d":"tombar.","e":"projetante deslizante.","gabarito":"B","materia":"Edificações","tema":"Sistemas e Processos Construtivos ,Esquadrias","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Edificações","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630710","enunciado":"Em relação aos tipos de janela, considere: I. O tipo de janela guilhotina é formada por uma única folha e se movimenta por deslizamento horizontal. II. As janelas de abrir de eixo vertical podem ser movimentadas mediante rotação em torno de eixos verticais fixos. III. O movimento de abertura da folha de uma janela tipo projetante é realizado somente para fora da edificação. IV. As janelas de correr são formadas por uma ou várias folhas que podem ser movimentadas por deslizamento horizontal no plano da janela.","a":"Está correto o que consta em I, II, III e IV.","b":"II e III, apenas.","c":"I e III, apenas.","d":"I e IV, apenas.","e":"II e IV, apenas.","gabarito":"E","materia":"Edificações","tema":"Sistemas e Processos Construtivos ,Esquadrias","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Edificações","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630709","enunciado":"Em relação às alvenarias, considere: I. Blocos secos de alta absorção devem ser umedecidos antes do assentamento. II. A argamassa deve ser aplicada em excesso e o posicionamento do bloco deve ser feito com pressão. III. Em alvenarias de tijolos/blocos à vista, o friso na junta deve ser feito entre 1 e 2 horas após o assentamento, cuidando para não tirar os blocos da posição. IV. Se a junta entre alvenaria e pilar for maior que 3 cm, a mesma deve ser preenchida com microconcreto.","a":"Está correto o que consta em I e IV, apenas.","b":"I e II, apenas.","c":"II e III, apenas.","d":"I, II, III e IV.","e":"III e IV, apenas.","gabarito":"D","materia":"Engenharia Civil","tema":"Edificação ,Alvenaria e Acabamento","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Edificações","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630708","enunciado":"Na execução de uma parede de alvenaria, com a finalidade de absorver tensões que se concentram nos contornos dos vãos (portas e janelas), oriundas de deformações impostas é necessário prever a execução de elementos estruturais específicos.","a":"O elemento localizado sobre o vão denomina-se contramarco.","b":"esquadria.","c":"verga.","d":"contraverga.","e":"marco. Engenharia Civil>Edificação ,Canteiro de Obras ,Planejamento e Controle de Obras","gabarito":"C","materia":"Engenharia Civil","tema":"Edificação ,Alvenaria e Acabamento","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Edificações","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1471","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Edificações Em relação a locação de obra, considere: I. Tem sua utilização no início da demarcação dos eixos, ou seja, é a cota 0,0. II. São gabaritos ou triângulos retângulos com lados de 30, 40 e 50 cm, variando geralmente até 150 cm. III. São estacas de madeira que servem para marcar o local de execução de um elemento estrutural.","a":"Os itens I, II e III, referem-se, respectivamente, a cota de arrasamento, esquadros e testemunhos.","b":"a cota de arrasamento, triangulação e testemunhos.","c":"o ponto notável, triangulação e piquetes.","d":"a referência de nível, esquadros e piquetes.","e":"a referência de nível, triangulação e pontaletes.","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Edificações","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630706","enunciado":"Obras de edifícios com mais de quatro pavimentos ou altura equivalente devem, obrigatoriamente, instalar plataformas de proteção. Elas servem para impedir que objetos cheguem ao chão em caso de queda, o que colocaria em risco quem passa","a":"no térreo. Com relação às barreiras de proteção, a principal deve ser instalada na altura da primeira laje ou, no mínimo, a um pé direito do nível do terreno.","b":"podem ser feitas de compensado de madeira, metálica ou tecido resistente.","c":"devem ser instaladas após a concretagem da laje e podem ser retiradas junto com o escoramento.","d":"o fechamento do perímetro com telas é facultativo e condicionado a presença de transporte vertical externo a","e":"edificação. edifícios com pavimentos no subsolo não precisam de plataformas de proteção adicionais.","gabarito":"A","materia":"Edificações","tema":"Segurança e Higiene do Trabalho","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Edificações","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630705","enunciado":"São conhecidas as coordenadas arbitrárias dos vértices de um terreno onde será implantada uma edificação destinada a instalações de apoio do Tribunal Regional Federal da 3ª Região, conforme tabela abaixo.","a":"2 área do terreno é, em m , igual a","b":"A 109. 1104.","c":"546.","d":"540.","e":"279.","gabarito":"E","materia":"Edificações","tema":"Sistemas e Processos Construtivos ,Instalações em Edificações","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Edificações","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630704","enunciado":"Em um levantamento topográfico, uma poligonal fechada de 5 lados desenvolvida por ângulos horários internos tem a caderneta de campo conforme a tabela abaixo.","a":"Com base nos dados, o erro de fechamento angular desta poligonal é igual a 03°.","b":"00°03’.","c":"00°00’03’’.","d":"00°30’.","e":"00°00’30’’.","gabarito":"B","materia":"Engenharia Civil","tema":"Topografia","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Edificações","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630703","enunciado":"Para a locação de obras é necessário conhecer as coordenadas dos vértices do terreno e da edificação, normalmente determinadas a partir da locação de uma poligonal topográfica. Em um levantamento topográfico, determina-se o azimute inicial no primeiro alinhamento da poligonal com o objetivo de orientar o levantamento. Em um levantamento de uma poligonal com os vértices A, B e C, são conhecidos o azimute entre o alinhamento A-B (AzAB = 125°20’25’’) e o rumo entre os","a":"alinhamentos B e C (RBC = 30°30’30’’ SO). O azimute entre os alinhamentos B e C (AZBC) é igual a 335°50’55’’.","b":"155°50’55’’.","c":"94°49’55’’.","d":"305°20°25’’.","e":"210°30’30’’.","gabarito":"E","materia":"Engenharia Civil","tema":"Topografia","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Edificações","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630702","enunciado":"Em relação ao dobramento dos desenhos técnicos, considere: I. O formato final do dobramento de cópias de desenhos em formatos A1 e A3 deve ser o formato A4. II. O dobramento deve ser feito a partir do lado direito, em dobras verticais. III. Para desenhos com formatos especiais, o dobramento deve ficar no padrão do formato A4. IV. Após o dobramento, o formato final da largura da folha na parte frontal deve ser igual a 198 mm.","a":"Está correto o que consta em I e III, apenas.","b":"II, III e IV, apenas.","c":"I, II e III, apenas.","d":"I e IV, apenas.","e":"I, II, III e IV.","gabarito":"C","materia":"Edificações","tema":"Estudos Preliminares ,Desenho Técnico em Edificações","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Edificações","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630701","enunciado":"Os desenhos técnicos, a serem elaborados para o projeto executivo de urbanização de uma praça, deverão ser entregues","a":"nos formatos A2 e A1 cujas dimensões deverão ser, em milímetros, respectivamente, iguais a 420 × 594 e 841 × 1189.","b":"210 × 297 e 594 × 841.","c":"210 × 297 e 841 × 1189.","d":"420 × 594 e 594 × 841.","e":"295 × 420 e 420 × 594.","gabarito":"D","materia":"Engenharia Civil","tema":"Desenho na Engenharia Civil ,Desenho Técnico na Engenharia Civil","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Edificações","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630700","enunciado":"","a":"prefeitura de São Paulo pretende iniciar a implantação de um ginásio esportivo com dimensões de 60 m e 90 m. As dimensões na representação gráfica, em cm, para uma planta baixa na escala de 1:200 são iguais, respectivamente, a","b":"A 120 e 180. 30 e 45.","c":"60 e 90.","d":"12 e 18.","e":"3,5 e 4,5.","gabarito":"B","materia":"Edificações","tema":"Estudos Preliminares ,Desenho Técnico em Edificações","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Edificações","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630699","enunciado":"","a":"tabela abaixo apresenta os resultados dos ensaios realizados das sondagens a trado que subsidiarão o projeto de pavimentação em um estacionamento e se referem ao valor de ISC (Índice de Suporte Califórnia) e de expansão. O valor da média e do desvio padrão para a expansão, sabendo-se que a variância é igual a 0,81, são, respectivamente, iguais a","b":"A 0,8 e 0,81. 1,1 e 0,90.","c":"1,1 e 0,78.","d":"0,8 e 0,65.","e":"1,4 e 0,96.","gabarito":"B","materia":"Edificações","tema":"Sistemas e Processos Construtivos ,Ensaios em Sistemas e Processos Construtivos","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Edificações","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630698","enunciado":"","a":"tabela abaixo apresenta os resultados dos ensaios realizados das sondagens a trado que subsidiarão o projeto de pavimentação em um estacionamento e se referem ao valor de ISC (Índice de Suporte Califórnia) e de expansão. Para o parâmetro ISC, o valor da mediana, em %, é igual a","b":"A 8,4. 7.","c":"7,5.","d":"8.","e":"6.","gabarito":"D","materia":"Edificações","tema":"Sistemas e Processos Construtivos ,Ensaios em Sistemas e Processos Construtivos","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Edificações","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630697","enunciado":"","a":"lei da física que afirma que a relação entre tensão e deformação em um material no regime elástico é linear é conhecida como a lei de","b":"A Kepler. Euler.","c":"Pascal.","d":"Newton.","e":"Hooke.","gabarito":"E","materia":"Física","tema":"Leis de Newton ,Dinâmica","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Edificações","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630696","enunciado":"","a":"gangorra disposta conforme a figura abaixo, possui uma força P1 igual a 40 kgf e uma força P2 igual a 70 kgf. A distância d2 é igual a 60 cm e para que a gangorra fique em equilíbrio na horizontal após a aplicação das forças, o comprimento total da barra, em cm, deve ser igual a","b":"A 165. 105.","c":"65.","d":"58.","e":"95.","gabarito":"A","materia":"Edificações","tema":"Sistemas e Processos Construtivos ,Estruturas nos Sistemas e Processos Construtivos","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Edificações","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630695","enunciado":"Na reforma de uma copa no edifício do Tribunal Regional Federal da 3ª Região será realizada a troca do revestimento cerâmico das paredes por novos com dimensões de 20 × 30 cm. O pé direito da copa é de 2,8 m e ela possui formato retangular de 2,2 m por 2,0 m. A compra será realizada por caixa fechada do revestimento cerâmico, sendo que cada caixa possui 20 peças. Desconsiderando as aberturas da porta e da janela e também a porcentagem destinada aos recortes ou","a":"perdas, a quantidade mínima de caixas fechadas a serem compradas é igual a 10.","b":"39.","c":"20.","d":"19.","e":"22.","gabarito":"C","materia":"Edificações","tema":"Procedimentos Finais e Manutenção ,Acabamento em Edificações","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Edificações","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q630694","enunciado":"Um terreno a ser desapropriado para ampliação do Tribunal Regional Federal da 3ª Região tem a forma trapezoidal, com 105 m de frente (base maior), 75 m de fundos (base menor) e 30 m de profundidade (altura). A área do terreno a ser 2","a":"desapropriado em m é igual a 5.400.","b":"2.700.","c":"1.575.","d":"1.125.","e":"5.063.","gabarito":"B","materia":"Edificações","tema":"Estudos Preliminares ,Limpeza e Preparo do Terreno ,Implantação do Canteiro de Obras","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Edificações","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629922","enunciado":"Utilizando o AACR2 para catalogar um recurso eletrônico disponível apenas por acesso remoto, uma bibliotecária registrou","a":"o modo de acesso na área da descrição física. Neste caso, o procedimento está correto; os detalhes físicos devem aparecer após a designação geral do material.","b":"incorreto; na área da descrição física, deve-se registrar os requisitos do sistema.","c":"incorreto; a área da descrição física indica o tipo e extensão do recurso.","d":"incorreto; o modo de acesso deve ser registrado na área das notas.","e":"correto; o registro deve conter a expressão Modo de acesso, seguido de dois pontos.","gabarito":"D","materia":"Biblioteconomia","tema":"AACR-2 ,Processos Técnicos ,Catalogação","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629921","enunciado":"Considere a página de rosto abaixo. Direito à Imagem: a decisão do Superior Tribunal de Justiça no caso de João do Rio versus Rede de Televisão Excelsior A. Boccanera, compilador","a":"Ao catalogar o item seguindo o AACR2, um bibliotecário determinou corretamente como entrada principal: Rio, João do, apelante.","b":"Boccanera, A., comp.","c":"Brasil. Superior Tribunal de Justiça.","d":"Rede de Televisão Excelsior, apelada.","e":"Direito à imagem.","gabarito":"C","materia":"Biblioteconomia","tema":"AACR-2 ,Processos Técnicos ,Catalogação","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629920","enunciado":"Uma bibliotecária está encarregada de catalogar uma série de ações cíveis de primeira instância, todas movidas contra o Governo do Estado de São Paulo no Tribunal Regional Federal da 3ª Região. Seguindo as normas do AACR2, a profissional","a":"corretamente escolheu como entrada principal a entidade com poder adjucatório: Tribunal Regional Federal da 3ª Região.","b":"o cabeçalho para a entidade processada: São Paulo (Estado).","c":"a pessoa ou entidade que move cada ação.","d":"o título uniforme apropriado: [Ações cíveis etc.].","e":"o título de cada ação.","gabarito":"C","materia":"Biblioteconomia","tema":"AACR-2 ,Processos Técnicos ,Catalogação","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629919","enunciado":"Na Classificação Decimal Universal, as subdivisões auxiliares especiais I. são listadas em um único lugar e, por definição, não têm aplicabilidade abrangente. II. expressam conceitos recorrentes a uma faixa limitada de assuntos. III. incluem, entre outras, as notações com -03, que indicam os materiais ou elementos que constituem os objetos ou produtos, -05, que especificam características relativas a pessoas, e o asterisco, usado para anteceder classificações extrínsecas à CDU. IV. devem ser aplicadas onde indicadas, sendo que a mesma notação pode ser usada com significado diferente. V. devem ser usadas como sufixos de outros números e não podem ser usadas independentemente. As afirmações que constam em","a":"II e IV estão incorretas; os conceitos que expressam não são recorrentes e as notações não podem ser usadas com significados diferentes.","b":"I e III estão incorretas; esses auxiliares aparecem em vários lugares da tabela e as notações -03, -05 e o asterisco são auxiliares comuns.","c":"I e V estão incorretas; os auxiliares especiais têm ampla aplicação na tabela e podem ser usados de maneira independente.","d":"III e IV estão incorretas; o asterisco é usado com função de síntese ou integração e os auxiliares especiais podem ser aplicados onde necessário.","e":"II e V estão incorretas; esses auxiliares aplicam-se à maioria dos assuntos e podem ser usados sozinhos quando indicado pelo sistema. Biblioteconomia>Classificação Decimal Universal ,Processos Técnicos ,","gabarito":"B","materia":"Biblioteconomia","tema":"Classificação Decimal Universal","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1489","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia Ao classificar uma obra que trata dos direitos humanos na forma de peça teatral, usando a Classificação Decimal Universal,","a":"um bibliotecário compôs a seguinte notação: 342.7(0:82-2). Conclui-se corretamente que a tabela auxiliar de forma não prevê um número específico para peça teatral.","b":"os dois pontos indicam uma relação entre forma e conteúdo na obra.","c":"a série com hífen -1/-9 é usada para expressar as formas literárias.","d":"o sinal (0:…) mostra que a notação que o segue não é uma subdivisão das tabelas principais.","e":"os parênteses indicam um subgrupamento de dois assuntos ligados por +, / ou:. Biblioteconomia>Classificação Decimal Universal ,Processos Técnicos ,","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1490","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia Seguindo a Classificação Decimal Universal, uma bibliotecária guardou alguns livros nas estantes na seguinte ordem: 342.511 342.511:323 342.511:371.214(091) 342.511+504.06 342.511/20 342.511=111 342.511(036) 342.511“20” Nesse caso, a ordem de arquivamento está","a":"correta; ao contrário da ordem de citação, a de arquivamento, ou vertical, procede do mais genérico ao mais","b":"específico. incorreta; as notações com o sinal de relação devem suceder as notações com auxiliares.","c":"incorreta; as notações com auxiliares como sufixos devem seguir a ordem: tempo, forma e língua.","d":"correta; essa ordem é fixa e segue o princípio de inversão, sendo o inverso da ordem de citação.","e":"incorreta; as notações com o sinal de coordenação e de extensão devem preceder o número simples. Biblioteconomia>Classificação Decimal Universal ,Processos Técnicos ,","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1491","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia Empregando a Classificação Decimal Universal, a equipe de bibliotecários do Tribunal Regional Federal da 3ª Região planeja separar os periódicos de direito do restante do acervo, porém mantendo juntas as coleções de cada país. O bibliotecário I propõe agrupá-los por assunto, assim: 34(05)(73), 34(05)(81) e assim por diante. O bibliotecário II acha melhor reuni-los sob a sua forma, assim: (05)34(73), (05)34(81) etc. Por fim, o bibliotecário III pensa em organizá-los segundo a forma e o lugar, assim: (05)(73)34, (05)(81)34 etc.","a":"Ocorre que os bibliotecários I, II e III estão corretos; a flexibilidade da ordem de citação torna possível diferentes arranjos.","b":"os bibliotecários I, II e III estão incorretos; a ordem de citação impõe que o lugar seja seguido da forma, e não o contrário.","c":"o bibliotecário I está incorreto; os auxiliares devem ser agrupados usando-se a barra inclinada: 34(05/73), 34(05/81)","d":"etc. o bibliotecário II está incorreto; o número principal não deve ser intercalado entre os números auxiliares.","e":"o bibliotecário III está incorreto; não se deve justapor dois auxiliares à frente do número principal, mas apenas um.","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629915","enunciado":"O tesauro se distingue do esquema de classificação porque I. o arranjo é explicitamente alfabético e implicitamente classificado. II. os elementos alfabético e classificado são apresentados separadamente. III. em qualquer ponto de entrada somente é oferecido um nível hierárquico para cima e outro para baixo. Observa-se que","a":"I, II e III estão corretos; tesauro e esquema de classificação controlam sinônimos, distinguem homógrafos e agrupam","b":"termos afins. I está incorreto; o arranjo é explicitamente classificado e implicitamente alfabético.","c":"III está incorreto; a estrutura oferece quantos níveis hierárquicos o vocabulário exigir.","d":"II está incorreto; os elementos alfabético e classificado aparecem em uma única sequência.","e":"I, II e III estão incorretos; arranjo e elementos são sistemáticos, enquanto as entradas oferecem dois níveis hierárquicos acima e abaixo.","gabarito":"D","materia":"Biblioteconomia","tema":"Conceitos Fundamentais ,Tesauros e Terminologia","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629914","enunciado":"Considere a estrutura de termos abaixo. DIREITOS DO CIDADÃO TG DIREITOS HUMANOS TE DIREITO À EDUCAÇÃO DIREITO À INFORMAÇÃO DIREITO DE GREVE GARANTIA CONSTITUCIONAL ISONOMIA CONSTITUCIONAL","a":"TR DIREITO ADQUIRIDO relação entre os termos DIREITOS DO CIDADÃO, DIREITOS HUMANOS e DIREITO DE GREVE é denominada","b":"A homonímica, porquanto é baseada no mesmo núcleo de conceitos similares ligados teoricamente. sintagmática, uma vez que é desencadeada por um processo ou por uma atividade.","c":"semântica, porque se estabelece de acordo com associações entre causa e efeito.","d":"sintática, considerando que mantém uma verdadeira relação lógica entre os termos.","e":"paradigmática, pois se apoia na existência de determinadas relações entre os significados.","gabarito":"E","materia":"Biblioteconomia","tema":"Linguagens Documentárias ,Conceitos Fundamentais ,Tesauros e Terminologia","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629913","enunciado":"No catálogo de assuntos da biblioteca do Tribunal Regional Federal da 3ª Região, encontra-se a seguinte entrada: CONFLITO AGRÁRIO − MIGRANTES − AÇÃO JUDICIAL − SÃO PAULO Essa entrada","a":"mostra uma estrutura flexível de permutação entre os termos, o que implica custos na multiplicação de entradas","b":"adicionais. permite acesso ao documento por meio de qualquer combinação dos termos a ele atribuídos, o que é uma vantagem.","c":"representa a multidimensionalidade das relações existentes entre os termos, o que auxilia na recuperação.","d":"apresenta termos que possuem peso igual, o que significa que todos têm a mesma importância no documento.","e":"oferece acesso ao documento apenas a quem procurar sob o primeiro termo, o que configura um problema.","gabarito":"E","materia":"Biblioteconomia","tema":"Linguagens Documentárias ,Conceitos Fundamentais ,Tesauros e Terminologia","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629912","enunciado":"","a":"direção da biblioteca do Tribunal Regional Federal da 3ª Região pretende avaliar o desempenho de seus indexadores. Para tanto, resolve realizar uma simulação de uma avaliação real, aplicando o seguinte método: I. Selecionar um conjunto de documentos recém adquiridos pela biblioteca. II. Elaborar três questões para as quais cada documento seja considerado uma resposta relevante. Uma questão deve abordar o assunto principal do documento, enquanto as outras devem abordar os assuntos secundários. III. Solicitar a especialistas a formulação de estratégias de busca para cada questão. IV. Encaminhar os documentos ao setor de processamento para que sejam indexados normalmente. V. Comparar a indexação com as estratégias de busca para determinar se os documentos seriam recuperados com os termos que lhes foram atribuídos. Nesse caso, observa-se que o problema com esse método é que ele julga um conjunto de termos de indexação como correto ou incorreto em A","b":"termos absolutos. o método só funciona quando o mesmo conjunto de documentos é indexado por diferentes indexadores.","c":"um método mais eficiente é realizar um processo de revisão feito por um profissional experiente antes da inclusão do","d":"documento no acervo. o método funciona bem se a amostra for grande o bastante e as estratégias de busca forem adequadas.","e":"o método é inconsistente na medida em que as questões a serem elaboradas devem abordar o assunto principal, e não os secundários.","gabarito":"D","materia":"Biblioteconomia","tema":"Processos Técnicos ,Indexação nos Processos Técnicos em Biblioteconomia","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629911","enunciado":"Uma busca realizada por um desembargador na base de dados da biblioteca do Tribunal Regional Federal da 3ª Região recuperou 29 documentos, dos quais ele considerou 9 úteis e 20 inúteis. Por outro lado, os bibliotecários sabem que existem na base de dados 14 documentos que o usuário consideraria úteis para atender a sua necessidade de informação.","a":"Nessa situação, em geral, para melhorar a revocação, é preciso fazer uma busca mais genérica, o que faria a precisão cair ainda mais.","b":"fazer uma busca mais específica, o que aumentaria mais a precisão.","c":"aumentar o número de termos de busca, o que reduziria mais a precisão.","d":"empregar termos equivalentes na busca, o que melhoraria a precisão.","e":"empregar termos compostos na busca, o que ampliaria a precisão. Biblioteconomia>Processos Técnicos ,Indexação nos Processos Técnicos em Biblioteconomia ,","gabarito":"A","materia":"Biblioteconomia","tema":"Processos Técnicos ,Busca e Recuperação da Informação","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1497","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia","a":"Nesse caso, o coeficiente de precisão é 9/20, que indica a capacidade que a base tem de recuperar os documentos úteis.","b":"9/14, que indica a extensão com que todos os documentos úteis são recuperados.","c":"9/29, que indica a relação de documentos úteis e o total de documentos recuperados.","d":"14/29, que indica a capacidade que a base tem de evitar documentos inúteis.","e":"20/29, que indica a medida de desempenho da base em recuperar os documentos úteis.","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629909","enunciado":"Em relação aos resumos, considere: I. Em um ambiente eletrônico, um resumo facilita a busca livre em textos, mas não suporta a aplicação de vocabulários controlados que visam à indexação em serviços de recuperação de informações. II. Seus propósitos são identificar rapidamente o conteúdo básico de um documento, determinar a sua relevância e decidir se o documento precisa ser lido na íntegra. III. A norma brasileira vincula a definição de resumo a um documento, enquanto a norma da ANSI, por exemplo, define resumo como a representação de um documento ou de uma apresentação oral. IV. Para a NBR 6028, a extensão dos resumos varia de acordo com o tipo de documento: até 100 palavras para comunicações breves, até 250 palavras para artigos e capítulos de livros, e até 300 palavras para livros e teses. V. Deve-se usar o verbo na voz ativa e na terceira pessoa do singular, como em: A resolução de conflitos no trabalho que comprometem a produtividade exige uma reorganização estrutural para reduzir a instabilidade social e/ou um programa de treinamento para reduzir conflitos de ponto de vista.","a":"Está correto o que consta APENAS em I, IV e V.","b":"II, III e V.","c":"I, III e IV.","d":"II, IV e V.","e":"I, II e III.","gabarito":"B","materia":"Biblioteconomia","tema":"Resumo","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629908","enunciado":"Após preparar um ensaio sobre aspectos éticos do direito na atualidade, a ser publicado em uma revista da área, um juiz pede a uma bibliotecária do Tribunal Regional Federal da 3ª Região para resumir o documento. Seguindo as normas e práticas pertinentes em vigor, a profissional deverá elaborar um resumo","a":"indicativo-informativo, recomendado para documentos que combinam elementos e abordagens de ambos os tipos de resumo.","b":"informativo, recomendado para documentos que são frutos de pesquisas que apresentam objetivo, metodologia, resultados e conclusões.","c":"crítico, recomendado para documentos que apresentam uma discussão ou proponham uma reflexão sobre teorias, princípios e teses.","d":"indicativo, recomendado para documentos menos estruturados que não contêm informações relativas a metodologias e resultados.","e":"estruturado, recomendado para documentos que descrevem fundamentos, abordagens e outros argumentos utilizados no texto.","gabarito":"D","materia":"Biblioteconomia","tema":"Resumo","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629907","enunciado":"As normas fixadas pelo Comitê Brasileiro de Informação e Documentação da Associação Brasileira de Normas Técnicas: I. Abrangem atividades referentes, entre outros, a serviços de indexação, incluindo a área de publicação. II. Podem ser propostas por qualquer interessado. III. São de uso obrigatório.","a":"Observa-se que os itens I, II e III estão corretos; as normas visam a consistência, intercâmbio e supressão de diferenças técnicas.","b":"o item II está incorreto; as normas devem ser propostas por instituições.","c":"o item I está incorreto; o CBID fixa normas para bibliotecas e centros de documentação e informação.","d":"os itens I, II e III estão incorretos; as normas não incluem a área de publicação, são propostas por profissionais e são","e":"elegíveis. o item III está incorreto; por princípio, as normas são de uso voluntário. Biblioteconomia>Informação jurídica ,Fontes de Informação jurídica ,Internet na Biblioteconomia","gabarito":"E","materia":"Biblioteconomia","tema":"Normas e Legislações da Biblioteconomia ,Normas Internacionais e de Padronização","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1501","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia Ao avaliar a qualidade de uma fonte de informação jurídica na internet, uma bibliotecária do Tribunal Regional Federal da 3ª Região observa, entre outros, os seguintes aspectos: I. A informação oferecida é preponderantemente opinativa. II. O mantenedor não goza de reconhecimento na área. III. A recuperação da informação original se dá por meio de links. IV. Seus objetivos e o público a que se destina não são claros. V. A cobertura é seletiva. VI. A linguagem utilizada é coerente com a estrutura da fonte.","a":"Considerando os critérios de avaliação consagrados pela literatura, verifica-se que os aspectos constantes em I, III e V indicam que a consistência das informações da fonte é inadequada.","b":"II, IV e VI indicam que a confiabilidade das informações da fonte é inadequada.","c":"I, II e V indicam que a coerência das informações da fonte é inadequada.","d":"III, IV e VI indicam que a identificação das informações da fonte é parcialmente adequada.","e":"I, III e IV indicam que a facilidade de uso das informações da fonte é parcialmente adequada. Biblioteconomia>Informação jurídica ,Fontes de Informação jurídica ,Internet na Biblioteconomia","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1502","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia Interessada em informação jurídica descritiva sobre direitos indígenas, uma desembargadora do Tribunal Regional Federal","a":"da 3ª Região solicita ajuda a uma bibliotecária que realizará uma busca no Portal da Legislação do Governo Federal.","b":"na Infolegis: Pesquisa Jurídica no Brasil.","c":"na Rede Virtual de Bibliotecas do Congresso Nacional.","d":"no Repositório Institucional do Superior Tribunal de Justiça.","e":"na Base de Jurisprudência Unificada do Conselho da Justiça Federal.","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629904","enunciado":"O formato MARC compreende informações de dados bibliográficos e os dados bibliográficos propriamente ditos. Os campos que contêm estes últimos são todos de tamanho fixo. Existem dois tipos de campos fixos: campos de controle, que","a":"são os campos 00X, e campos de dados, que são agrupados em blocos de acordo com o primeiro caractere da etiqueta. afirmativa está incorreta; os campos fixos denominam-se líder e diretório, sendo definidos por padrões como ISBD, AACR2, CDD e A lista de cabeçalhos da LC.","b":"incorreta; os dados do registro estão organizados em campos variáveis, cada um identificado por uma etiqueta de três caracteres numéricos.","c":"incorreta; os campos de controle possibilitam o processamento do registro e os campos de dados possuem doze posições e três partes.","d":"correta; os campos fixos de dados têm uma estrutura mnemônica, pois obedecem à mesma sequência do registro catalográfico.","e":"correta; os campos contêm também dois indicadores, que são algarismos de um dígito exclusivos do campo ao qual são atribuídos.","gabarito":"B","materia":"Biblioteconomia","tema":"Processos Técnicos ,Catalogação ,Automação em BibliotecasMARC21","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629903","enunciado":"Na avaliação da utilidade de uma base de dados, é muito atraente como critério de eficácia, sendo relativamente fácil de","a":"medir e incontestável quando medida, porque não depende de juízos subjetivos. Trata-se da cobertura.","b":"atualidade.","c":"previsibilidade.","d":"recuperabilidade.","e":"precisão.","gabarito":"B","materia":"Biblioteconomia","tema":"Avaliação de Serviços de Informação ,Base de dados","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629902","enunciado":"Entre as formas de buscar e localizar registros em bases de dados textuais, encontram-se: I. Listas enlaçadas unidirecionais: os registros são organizados de acordo com um campo-chave (autor, título etc.) ou de maneira independente, empregando-se um sistema de apontadores para representar a organização dos registros na base. II. Arquivos invertidos: trabalha com dois ou três arquivos separados, sendo que um contém os registros propriamente ditos e o outro, um índice que proporciona o acesso a esses registros. Observa-se que","a":"as afirmações I e II estão corretas; as listas não suportam buscas em campos diferentes do campo-chave, enquanto os arquivos têm melhor desempenho em buscas complexas.","b":"as afirmações I e II estão incorretas; as listas são um índice de palavras-chave conectadas com os registros que as","c":"contêm, enquanto os arquivos contêm um registro de cada termo indexado. a afirmação I está incorreta; as listas são organizadas por campo-chave, e não de maneira independente","d":"a afirmação II está incorreta; cada termo do índice deve ser acompanhado de informações sobre a sua frequência de","e":"ocorrência na base. a afirmação II está incorreta; os arquivos invertidos trabalham com dois arquivos: texto e índice, não com três.","gabarito":"A","materia":"Biblioteconomia","tema":"Processos Técnicos ,Busca e Recuperação da Informação","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629901","enunciado":"","a":"biblioteca do Tribunal Regional Federal da 3ª Região disponibiliza na internet uma base de dados A de referências; ademais, por conter o texto integral de certos documentos, é também uma base de dados de fontes.","b":"de referências; porque inclui citações ou referências bibliográficas que apresentam uma síntese do conteúdo do documento original.","c":"catalográficos; pois relaciona livros, títulos de periódicos e outros itens que a biblioteca possui, mas sem indicar informações sobre o seu conteúdo.","d":"de fontes; uma vez que constitui um acervo completo em formato digital, o que inclui atos normativos, acórdãos e súmulas.","e":"multimídia; além de documentos impressos, armazena uma série de diferentes tipos de meios, como som, vídeo e fotografia.","gabarito":"A","materia":"Biblioteconomia","tema":"Fontes de Informação jurídica ,Base de dados ,Conceitos FundamentaisFontes de Informação","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629900","enunciado":"Adotado pela biblioteca do Tribunal Regional Federal da 3ª Região, o sistema integrado Pergamum utiliza bancos de dados SQL Server e Oracle, oferece pesquisa por tipo de material e possibilita entrada e atualização de dados online, entre outras","a":"características. afirmativa está correta; o conteúdo completo das coleções de livros, artigos, teses e relatórios da biblioteca do TRF-3R encontra-se A disponível em formato digital e acesso direto.","b":"correta; o sistema Pergamum oferece controle de aquisição interligado ao processo de catalogação, acesso à base de dados via internet e busca por palavras do resumo e texto completo.","c":"correta; o sistema Pergamum usa o AACR2 para catalogação, o formato MARC 21 para intercâmbio de registros e a norma ISO-2709 para comunicação entre sistemas.","d":"incorreta; o sistema Pergamum utiliza os bancos de dados Access e Sybase, sendo que e a atualização dos dados é realizada offline.","e":"incorreta; a biblioteca do TRF-3R utiliza o sistema para a migração de sua base de dados já existente, oferecendo pesquisa por autor, título e assunto.","gabarito":"C","materia":"Biblioteconomia","tema":"Automação em Bibliotecas ,Serviços Automatizados para Bibliotecas","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629899","enunciado":"","a":"diretora da biblioteca do Tribunal Regional Federal da 3ª Região solicitou à equipe um inventário dos periféricos disponíveis, classificando-os de acordo com os dois agrupamentos abaixo: I. Dispositivos de entrada. II. Dispositivos de saída. III. Dispositivos de entrada e saída. a. Impressoras b. Teclados c. Caixas de som d. Mouses e. Modems f. Escâneres g. Pendrives h. Canetas óticas i. Quiosques multimídia A correlação correta entre os agrupamentos é","b":"A I: d, e, f, g; II: a, c, h; III: b, i. I: a, b, d, f; II: c, g, h; III: e, i.","c":"I: b, c, e, h; II: a, f, i; III: d, g.","d":"I: b, d, f, h; II: a, c, i; III: e, g.","e":"I: d, f, h, i; II: a, c, g; III: b, e.","gabarito":"D","materia":"Biblioteconomia","tema":"Gestão de Bibliotecas e Unidades de Informação","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629898","enunciado":"Usando um computador para inserir novos itens na base bibliográfica do Tribunal Regional Federal da 3ª Região, uma","a":"bibliotecária acessa a memória PROM, que permite a leitura e armazena os dados de modo permanente.","b":"a memória RAM, que permite a leitura, a gravação e a regravação de dados.","c":"uma fita magnética, que grava os dados de maneira aleatória ou randômica.","d":"a unidade de controle, que gerencia os dados e os convertem para o formato de saída desejado.","e":"o monitor de vídeo, que mostra todas as informações digitadas no teclado.","gabarito":"B","materia":"Biblioteconomia","tema":"Gestão de Bibliotecas e Unidades de Informação","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629897","enunciado":"Ao construir a estratégia de busca, após a negociação da questão, o bibliotecário de referência I. analisa o tema da questão, identificando seus conceitos e relações. II. seleciona os termos do enunciado de busca adequados à linguagem usada pelo sistema da biblioteca. III. identifica as fontes adequadas que possam conter informações relevantes para a questão do usuário. Neste caso,","a":"as afirmações I, II e III estão incorretas; tratam-se de ações que se situam na esfera do processo de busca propriamente dito.","b":"as afirmações I, II e III estão corretas; as buscas mais eficazes são aquelas em que a estratégia é flexível para comportar uma mudança de rumo.","c":"a afirmação I está incorreta; a análise do tema é feita durante a negociação da questão, etapa dedicada ao esclarecimento da necessidade de informação do usuário.","d":"a afirmação II está incorreta; nessa etapa, o bibliotecário formula a estratégia de busca usando operadores booleanos, de truncamento, de proximidade etc.","e":"a afirmação III está incorreta; um bibliotecário bem preparado e eficiente realiza a busca em todas as fontes disponíveis na biblioteca.","gabarito":"B","materia":"Biblioteconomia","tema":"Gestão de Bibliotecas e Unidades de Informação ,Serviço de Referência","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629896","enunciado":"Um magistrado dirige-se ao serviço de referência da biblioteca do Tribunal Regional Federal da 3ª Região com a seguinte consulta: – Estou procurando algo sobre a atuação do Ministério Público no controle das políticas públicas.","a":"– De que maneira o senhor gostaria que essa informação o ajudasse? − pergunta o bibliotecário. pergunta feita pelo bibliotecário ao magistrado","b":"A implica a suposição do bibliotecário sobre o que o usuário deseja. limita a resposta do usuário a um conjunto concreto de possibilidades.","c":"procura compreender a questão a partir do ponto de vista do usuário.","d":"é inadequada pois o uso que o magistrado fará da informação é irrelevante.","e":"não é recomendada considerando que pode colocar o usuário na defensiva.","gabarito":"C","materia":"Biblioteconomia","tema":"Gestão de Bibliotecas e Unidades de Informação ,Serviço de Referência","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629895","enunciado":"","a":"Durante a entrevista de referência, bibliotecário e magistrado encontram-se na etapa inicial da entrevista, denominada problema.","b":"o bibliotecário utilizou uma pergunta fechada, que leva o usuário a especificar o interesse da consulta.","c":"o magistrado fez uma consulta de localização de fatos, cuja resposta será o fornecimento de material específico.","d":"o magistrado fez uma consulta de referência rápida, cuja resposta demanda a assistência limitada do bibliotecário.","e":"o bibliotecário utilizou uma pergunta neutra, que leva ao contexto no qual a necessidade de informação se insere. Biblioteconomia>Gestão de Bibliotecas e Unidades de Informação ,Usuários / Disseminação Seletiva ,","gabarito":"E","materia":"Biblioteconomia","tema":"Gestão de Bibliotecas e Unidades de Informação ,Serviço de Referência","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1513","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia Para operacionalizar o serviço de disseminação seletiva de informações, a equipe de referência da biblioteca do Tribunal Regional Federal da 3ª Região deu início à identificação dos perfis dos usuários a serem atendidos, tomando como base a área de atuação desses usuários, o seu histórico de consultas às bases de dados da instituição e as suas publicações mais recentes.","a":"Neste caso, a identificação dos perfis é individual, quando o usuário atua sozinho no processo de sua elaboração.","b":"explícita, quando o usuário participa do processo de sua elaboração.","c":"interativa, quando usuário e bibliotecário atuam juntos na sua elaboração.","d":"implícita, quando o usuário não participa do processo de sua elaboração.","e":"autônoma, quando o bibliotecário atua sozinho no processo de sua elaboração. Biblioteconomia>Gestão de Bibliotecas e Unidades de Informação ,Usuários / Disseminação Seletiva ,","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1514","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia Como responsável pelo planejamento de um serviço de disseminação seletiva de informações, a equipe de referência da biblioteca do Tribunal Regional Federal da 3ª Região definiu, em uma etapa denominada diagnóstico, o objetivo, o público- alvo, a periodicidade do serviço e as suas características. Neste caso, o procedimento da equipe está","a":"incorreto; objetivo e características são definidos durante a estruturação do serviço, juntamente com a divisão de tarefas da equipe.","b":"incorreto; no diagnóstico, avalia-se o contexto da instituição, identificando os usuários potenciais e os recursos informacionais existentes.","c":"correto; ainda durante o diagnóstico, são definidos os materiais a serem monitorados, a natureza do conteúdo e a forma de acesso à informação.","d":"correto; a implementação do serviço terá sucesso se as etapas do planejamento forem realizadas em conformidade com a política institucional","e":"correto; as características do serviço dependem das necessidades dos usuários, dos recursos humanos disponíveis, da tecnologia e do custo.","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629892","enunciado":"Em uma biblioteca, estabeleceu-se o seguinte diálogo: Estagiário: Necessito de informações sobre direito autorais. Bibliotecária: Claro. O que você busca sobre esse tema? Estagiário: Necessito da legislação específica. Bibliotecária: Você se refere à legislação no Brasil ou em algum outro país? Estagiário: No Brasil. Bibliotecária: Certo. Se você me disser que abordagem deseja seguir, eu poderei entender melhor o que precisa. Estagiário: Bem. Eu pretendo... Ocorreu, no caso, uma tradicional entrevista de referência. Para compreender a questão do usuário, a bibliotecária utilizou","a":"3 tipos de perguntas. Tais perguntas são classificadas, respectivamente, como aberta, fechada e neutra.","b":"encorajadora, aberta e fechada.","c":"fechada, neutra e aberta.","d":"neutra, aberta e fechada.","e":"aberta, encorajadora e neutra.","gabarito":"A","materia":"Biblioteconomia","tema":"Gestão de Bibliotecas e Unidades de Informação ,Serviço de Referência","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629891","enunciado":"Conhecer as situações e o contexto em que surge uma necessidade de informação, as barreiras físicas e psicológicas que podem existir, as estratégias seguidas no momento de buscar informação e o uso que se faz da informação obtida são","a":"atividades compreendidas pelo estudo de usuários.","b":"pela educação de usuários.","c":"pelo serviço de alerta.","d":"pelo estudo de comportamento informacional.","e":"pelo treinamento de usuários.","gabarito":"A","materia":"Biblioteconomia","tema":"Gestão de Bibliotecas e Unidades de Informação ,Estudos de Usuários","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629890","enunciado":"Após avaliar uma coleção, o bibliotecário identificou a necessidade de seu desbastamento. Assim, juntamente com sua equipe, separou aqueles materiais do acervo que poderiam ser objeto dessa atividade. Vários volumes foram encaminhados para um edifício distante da biblioteca, sendo armazenados de maneira compacta e dispostos de forma a poderem ser novamente utilizados, caso solicitados. Neste caso, a biblioteca optou pela modalidade de desbastamento","a":"conhecida como armazenamento compartilhado.","b":"descarte.","c":"remanejamento.","d":"seleção negativa.","e":"preservação. Biblioteconomia>Desenvolvimento de coleções de bibliotecas e unidades de informação ,Processos Técnicos ,","gabarito":"C","materia":"Biblioteconomia","tema":"Processos Técnicos ,Formação e Desenvolvimento de Acervos e Coleções","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1518","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia Considere as afirmações abaixo. I. As bibliotecas que participam do desenvolvimento coordenado de coleções reduzem a duplicação a fim de prover uma coleção coletiva mais forte e atingir maior satisfação do usuário. II. Apesar de algumas poucas e isoladas iniciativas de desenvolvimento coordenado de coleções, as bibliotecas não possuem uma história notável de alterar o comportamento que tradicionalmente adotam no desenvolvimento de coleções. Em relação ao desenvolvimento coordenado de coleções,","a":"as afirmações I e II estão incompletas, pois desconsideram o papel do elemento humano nas atividades do","b":"desenvolvimento coordenado de coleções. as afirmações I e II estão incorretas.","c":"apenas a afirmação I está correta e a II minimiza a adesão das bibliotecas a esforços cooperativos.","d":"apenas a afirmação II está correta e a I extrapola o objetivo do desenvolvimento coordenado de coleções.","e":"as afirmações I e II estão corretas. Biblioteconomia>Normas e Legislações da Biblioteconomia ,Lei nº 9.610/98 - Direito Autoral ,","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1519","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia Considere as afirmações abaixo. I. No Brasil, a proteção aos direitos autorais depende do registro da obra na Biblioteca Nacional. II. É assegurada a proteção dos direitos autorais às participações individuais em obras coletivas. Com relação aos direitos autorais,","a":"a afirmação I está correta e a II se equivoca, pois apenas o direito autoral do organizador da obra coletiva é protegido","b":"pela legislação relacionada aos direitos autorais. a afirmação II está correta e a I desconsidera que a proteção dos direitos autorais independe de registro.","c":"as afirmações I e II estão incompletas; I não esclarece em quais órgãos o registro deve ser feito e II não esclarece o que","d":"vem a ser uma obra coletiva. as afirmações I e II estão corretas.","e":"as afirmações I e II estão incorretas.","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1520","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia Após a avaliação da coleção, a comissão de biblioteca identificou a necessidade de preencher alguns claros e incluir na política de desenvolvimento de coleções algumas áreas que não eram incluídas no acervo. Para atender a essas determinações, o bibliotecário deu início a um processo pela identificação e obtenção de materiais antigos e, muitas vezes,","a":"esgotado ou fora do mercado tradicional. Neste caso, ele está realizando a atividade conhecida como aquisição cooperativa.","b":"aquisição planificada.","c":"avaliação setorial.","d":"seleção retrospectiva.","e":"planejamento “às avessas”. Biblioteconomia>Desenvolvimento de coleções de bibliotecas e unidades de informação ,Processos Técnicos ,","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1521","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia Uma política de desenvolvimento de coleções descreve a coleção (local e de acesso remoto) como ela está e estabelece um plano de como será desenvolvida, definindo também as diretrizes que nortearão tal desenvolvimento. Essas diretrizes são","a":"dinâmicas, na medida em que sua preparação, reavaliação e revisão são processos contínuos, que respondem a mudanças nos materiais armazenados, no mercado de trabalho e na clientela de usuários.","b":"na tecnologia, nos fornecedores de materiais informacionais e nos processos de trabalho.","c":"na comunidade servida, nos recursos financeiros e nos recursos informacionais.","d":"no ambiente informacional, na disponibilidade de títulos e na conjuntura econômica.","e":"nas modalidades de pesquisa bibliográfica, na demanda por informação e nos provedores de recursos. Administração Geral>Abordagem Neoclássica da Administração ,","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1522","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia Considere os dois agrupamentos abaixo, referentes a termos correntemente utilizados em planejamento e suas definições. I. Plano. II. Mensuração. III. Procedimento. a. Processo de atribuir números para descrever ou representar algum objeto ou fenômeno de modo padronizado, podendo levar à avaliação. b. Linha de ação preestabelecida que, em determinado período de tempo, orienta a ação na direção da missão e dos objetivos institucionais ou da solução de determinados problemas, e fornece parâmetros de controle e acompanhamento das ações. c. Instrumento que estabelece um método rotineiro de execução de atividades e detalha a maneira exata pela qual uma","a":"atividade deve ser realizada e a sequência em que a rotina é realizada. correlação correta dos dois agrupamentos é:","b":"A Ic; IIa; IIIb. Ic; IIb; IIIa.","c":"Ia; IIc; IIIb.","d":"Ib; IIc; IIIa.","e":"Ib; IIa; IIIc. Administração Geral>Abordagem Neoclássica da Administração ,","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1523","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia O planejamento I. eficaz depende da qualidade e quantidade de dados disponíveis e confiáveis. II. operacional decide “o que fazer” e “como fazer”. III. é um acontecimento. IV. é o sinônimo da improvisação.","a":"Está correto o que consta APENAS em I e II.","b":"I e III.","c":"II e IV.","d":"II e III.","e":"III e IV. Biblioteconomia>Gestão de Bibliotecas e Unidades de Informação ,Planejamento de Bibliotecas ,","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1524","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia Ao realizar o diagnóstico do serviço de informação, a bibliotecária enfocou todos os componentes da unidade de informação por igual − estrutura, atividades, recursos, processos, produtos e usuários −, sem aprofundar-se em qualquer","a":"deles. Nesse caso, ela adotou um foco sistêmico.","b":"específico.","c":"global.","d":"exploratório.","e":"heurístico.","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629881","enunciado":"Na biblioteca especializada, a bibliotecária decidiu elaborar um serviço de alerta para os usuários. Assim, mensalmente, passou a escanear os sumários das revistas científicas, organizá-los em ordem alfabética, em um arquivo único, e enviá-los aos usuários por e-mail. Depois de alguns meses realizando essa atividade, perguntou aos usuários o que achavam do serviço. Surpreendeu-se quando as respostas evidenciaram que este não despertava qualquer interesse dos usuários e que","a":"o achavam totalmente dispensável. Neste caso, a bibliotecária incorreu em uma falha de custo efetividade: gastou demasiado em algo que devia ser feito.","b":"eficiência: fez algo que não havia sido solicitado.","c":"efetividade: não fez bem alguma coisa.","d":"custo benefício: gastou mais do que devia.","e":"eficácia: fez algo que não devia ser feito. Gerência de Projetos>Áreas de conhecimento ,Gerenciamento das partes interessadas ,","gabarito":"E","materia":"Biblioteconomia","tema":"Gestão de Bibliotecas e Unidades de Informação ,Usuários / Disseminação Seletiva","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1526","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia Com o objetivo de ampliar os serviços da biblioteca, a equipe responsável, elaborou um projeto referente à colocação de caixas estantes em locais determinados da cidade, com um número específico de livros recentes. No entanto, ao ser encaminhado à administração superior para aprovação, descobriu que esta não estava disposta a investir recursos em favor de medidas futuras, argumentando que já tinha gastos demasiados. Neste caso, na busca de execução do projeto, o","a":"tipo de obstáculo ou problema encontrado é conhecido/classificado como circunstancial.","b":"organizacional.","c":"de perda de prestígio.","d":"cultural.","e":"de credibilidade.","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629879","enunciado":"","a":"Quanto a seus atributos, os projetos carregam, em geral, pouco risco e incerteza.","b":"são não repetitivos e tendem a ter características únicas.","c":"independem de compromissos com resultados e/ou com custos predefinidos.","d":"são geralmente responsabilidade de equipes permanentes de trabalho.","e":"são, quando de longa duração, imunes a interferências externas. Administração Geral>Abordagem Comportamental da Administração ,","gabarito":"B","materia":"Gerência de Projetos","tema":"Gerenciamento de Projetos, Programas e Portfólio","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1528","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia Considere as afirmações abaixo, relacionadas aos critérios para escolha de indicadores de desempenho. I. Caráter operacional: o indicador deve ser fácil de estabelecer, fácil de utilizar, vendável ou aceitável. II. Caráter consolidável: deve ser calculável monetariamente e ser útil à prevenção.","a":"Em relação aos critérios para escolha de indicadores de desempenho, a afirmação I está correta e a II confunde a descrição do critério com a do caráter econômico.","b":"a afirmação II está correta e a I confunde a descrição do critério com a do critério de pertinência.","c":"as afirmações I e II estão incompletas, pois não abordam os critérios em sua plenitude, enfocando apenas seu aspecto","d":"mais saliente. as afirmações I e II estão corretas.","e":"as afirmações I e II estão incorretas.","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629877","enunciado":"","a":"Na avaliação de serviços de informação, os indicadores qualitativos indiretos são aqueles que envolvem a satisfação do usuário.","b":"dizem respeito ao valor agregado pelo trabalho do profissional da informação.","c":"representam a medida da notoriedade dos serviços.","d":"estão ligados à qualidade e ao número de fontes de informação escolhidas.","e":"implicam a definição de uma unidade de contagem. Administração Geral>Abordagem Comportamental da Administração ,","gabarito":"C","materia":"Administração Geral","tema":"Gestão de processos","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1530","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia Na administração contemporânea, a gestão de pessoas deixou de ser vista como a definição de recompensas adequadas e/ou punições merecidas. Cada vez mais, ela envolve processos de aconselhamento que buscam levar o trabalhador, especialmente jovens administradores, a desenvolver seu potencial de trabalho e suas capacidades. Uma prática que atende a essas preocupações e está sendo cada vez mais adotada nos últimos tempos, inclusive na área de serviços de","a":"informação, é o advising.","b":"o coaching.","c":"a aprendizagem organizacional.","d":"o treinamento criativo.","e":"o endomarketing. Administração Geral>Gestão Estratégica ,","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629875","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia Considere os dois agrupamentos abaixo, referentes às Teorias da Administração e os resultados esperados da aplicação de suas teorias. I. Administração Científica. II. Neoclássica. III. Relações Humanas. a. Satisfação do operário. b. Eficiência e eficácia.","a":"c. Máxima eficiência. correlação correta dos dois agrupamentos é:","b":"A Ic; IIa; IIIb. Ib; IIa; IIIc.","c":"Ia; IIc; IIIb.","d":"Ib; IIc; IIIa.","e":"Ic; IIb; IIIa.","gabarito":"E","materia":"Abordagem Humanística da Administração - Teoria das Relações Humanas","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629874","enunciado":"É um dos recursos mais eficazes de qualidade organizacional, baseando-se, em processos de controle das experiências dos","a":"outros, na busca de ideias, modelos, soluções com as quais comparar-se e nas quais eventualmente se inspirar. Trata-se do benchlearning.","b":"partnership.","c":"consórcio.","d":"benchmarking.","e":"downsizing.","gabarito":"D","materia":"Administração Geral","tema":"Gestão da Qualidade ,Novas Abordagens da Administração ,Benchmarking","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629873","enunciado":"Considere os dois agrupamentos abaixo, que se referem a vários instrumentos da qualidade e seus objetivos. I. Diagrama espinha-de-peixe. II. Análise de estratificação. III. Gráfico de controle. a. Representar graficamente as mudanças sofridas no tempo por um determinado processo. b. Enquadrar um problema ou um fenômeno de maneira mais analítica.","a":"c. Constatar um efeito e buscar suas causas. correlação correta dos dois agrupamentos é:","b":"A Ia; IIb; IIIc. Ib; IIc; IIIa.","c":"Ic; IIb; IIIa.","d":"Ia; IIc; IIIb.","e":"Ib; IIa; IIIc. Marketing>Fundamentos Teóricos do Marketing ,Conceitos de Marketing ,","gabarito":"C","materia":"Administração Geral","tema":"Gestão da Qualidade ,Ferramentas da qualidade","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1534","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia Considere os dois agrupamentos abaixo, referentes a elementos do marketing e suas definições. I. Estratégia de marketing. II. Tática de marketing. III. Instrumento promocional. a. Conjunto de relações e atitudes, tendo como princípio fundamental captar e manter clientes dos produtos e/ou serviços, quando aplicadas técnicas mercadológicas. b. Todo meio, forma ou recurso capaz de levar ao conhecimento do grupo consumidor a mensagem publicitária.","a":"c. Ação no nível operacional de execução para efetivar ou colocar em prática as atividades de promoção. correlação correta dos dois agrupamentos é:","b":"A Ic; IIa; IIIb. Ic; IIb; IIIa.","c":"Ib; IIa; IIIc.","d":"Ib; IIc; IIIa.","e":"Ia; IIc; IIIb. Marketing>Marketing Organizacional ,Comunicação Organizacional em Marketing ,","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1535","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia Considere as afirmações abaixo. I. Um grande mal-entendido na aplicação do marketing em organizações de serviço, especialmente bibliotecas, é confundir uma orientação para o marketing com uma orientação para vendas. II. É necessário, tanto na Biblioteconomia como em todos os setores de atividade, um aprofundamento da dinâmica associada à percepção do marketing.","a":"Em relação ao uso do marketing em unidades de informação, as afirmações I e II estão corretas.","b":"as afirmações I e II estão incorretas.","c":"a afirmação I está correta e a II não leva em consideração que as proposições do marketing sempre tiveram caráter geral e abrangente, visando sua aplicação em todas as áreas do mercado.","d":"a afirmação II está correta e a I desconsidera que atualmente os bibliotecários avançaram muito no entendimento das proposições do marketing.","e":"a afirmação I está correta e a II está incompleta, por não considerar o desenvolvimento científico do marketing nos últimos anos, que o tornou muito mais permeável ao setor de serviços.","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629870","enunciado":"Considere o organograma abaixo.","a":"Ele se refere a uma estrutura de tipo funcional: ênfase na especialização.","b":"linear: possui linhas diretas e únicas de responsabilidade entre superior e subordinado.","c":"mista: presença de órgãos de apoio junto aos gerentes de linha.","d":"colegiada: caracteriza-se pela pluralidade de membros, que dividem a responsabilidade.","e":"com base em projetos: cada unidade da organização está voltada para o desenvolvimento de um único projeto e chefiada por um único gerente.","gabarito":"A","materia":"Administração Geral","tema":"Organizações, Sistemas e Métodos ,Organograma","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629869","enunciado":"Segundo alguns autores, a motivação individual aumenta e os resultados melhoram quando são dadas às pessoas oportunidades de participar com maior envolvimento e poder decisório no seu trabalho e nas metas a elas pertinentes. Este","a":"raciocínio é a base da prática administrativa conhecida como gatekeeping.","b":"empowerment.","c":"descentralização.","d":"reengenharia.","e":"contingenciamento.","gabarito":"B","materia":"Administração Geral","tema":"Gestão Estratégica ,Liderança e Motivação","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629868","enunciado":"","a":"biblioteca estava em crise, com um crescente número de reclamações dos usuários quanto ao atendimento recebido, às falhas no acervo e ao tempo que a biblioteca levava para catalogar as novas aquisições. Ciente desses problemas, a diretora decidiu convocar a equipe e definir novos padrões que colaborassem para um melhor desempenho, bem como um esquema para monitorar a sua aplicação e responder rapidamente quando desvios fossem constatados, tomando-se as medidas corretivas necessárias. Neste caso, o conjunto dessas atividades constitui um exemplo da função de","b":"A avaliação. controle.","c":"planificação.","d":"organização.","e":"previsão.","gabarito":"B","materia":"Biblioteconomia","tema":"Gestão de Bibliotecas e Unidades de Informação ,Administração de Bibliotecas","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629867","enunciado":"","a":"bibliotecária sentia há tempos que a unidade de informação estava passando por um mau momento. Os funcionários pareciam mais preocupados com sua vida pessoal e as atividades não eram desenvolvidas da forma como devia. Notava, inclusive, que o próprio ambiente sofria revezes, com frequentes extravios de materiais de trabalho e de volumes devolvidos pelos usuários. Para sanar essas falhas, ela realizou uma série de atividades: promoveu uma palestra sobre as obrigações de cada funcionário em relação ao serviço, nomeou uma equipe de trabalho para definir uma melhor ocupação do espaço e promoveu uma reestruturação de cargos e salários, obtendo, junto à Administração Superior, pequenas vantagens salariais para os funcionários. Após a aplicação dessas medidas, sentiu que a situação na biblioteca melhorou substancialmente. Neste caso, as providências da bibliotecária refletem os princípios de administração conhecidos como","b":"A autoridade e responsabilidade, disciplina e espírito de equipe. unidade de direção, centralização e cadeia escalar.","c":"equidade, estabilidade do pessoal e iniciativa.","d":"subordinação do interesse pessoal ao coletivo, ordem e remuneração do pessoal.","e":"unidade de comando, divisão do trabalho e liderança.","gabarito":"D","materia":"Biblioteconomia","tema":"Gestão de Bibliotecas e Unidades de Informação ,Administração de Bibliotecas","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1540","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia No primeiro número do volume 16, referente ao período de janeiro a junho de 2011, a Revista ACB: Biblioteconomia em Santa Catarina, publicada na capital do Estado, dedicou as páginas 289 a 307 ao artigo “O perfil do profissional da informação demandado por uma empresa do ramo jornalístico: um estudo de caso”, elaborado por Edileuda Soares Diniz, André Pena e Leandro Damaceno Gonçalves. Segundo a NBR 6023, a referência bibliográfica desse artigo é","a":"DINIZ, E. S.; PENA, A.; GONÇALVES, L. D. O perfil do profissional da informação demandado por uma empresa do ramo jornalístico: um estudo de caso. Revista ACB: Biblioteconomia em Santa Catarina, Florianópolis, 16(1): 289-307, jan./jun. 2011.","b":"DINIZ, E. S. et al. O perfil do profissional da informação demandado por uma empresa do ramo jornalístico: um estudo de caso. Revista ACB: Biblioteconomia em Santa Catarina, Florianópolis, v. 16, n. 1, p. 289-307, jan./jun. 2011.","c":"DINIZ, E. S.; PENA, A.; GONÇALVES, L. D. O perfil do profissional da informação demandado por uma empresa do ramo jornalístico: um estudo de caso. Revista ACB: Biblioteconomia em Santa Catarina, Florianópolis, v. 16, n. 1, p. 289- 307, jan a jun. 2011.","d":"DINIZ, E. S.; PENA, A.; GONÇALVES, L. D. “O perfil do profissional da informação demandado por uma empresa do ramo jornalístico: um estudo de caso”. Revista ACB: Biblioteconomia em Santa Catarina, Florianópolis, v. 16, n. 1, p. 289 a 307, jan./jun. 2011.","e":"DINIZ, E. S.; PENA, A.; GONÇALVES, L. D. O perfil do profissional da informação demandado por uma empresa do ramo jornalístico: um estudo de caso. Revista ACB: Biblioteconomia em Santa Catarina, Florianópolis, v. 16, n. 1, p. 289-307, jan./jun. 2011. Biblioteconomia>Referência bibliográfica ,Normas e Legislações da Biblioteconomia ,","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1541","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia Considere as referências abaixo. I. SÃO PAULO MEDICAL JOURNAL. São Paulo: Associação Paulista de Medicina, 1941- . Bimensal. ISSN 0035-0362. II. NAVES, P. Lagos andinos dão banho de beleza. Folha de S. Paulo, São Paulo, 28 jun. 1999. Folha Turismo, Caderno 8, p. 13. III. COSTA, S.; SILVA, A. Jura secreta. Intérprete: Simone. In: SIMONE. Face a face. [S.l.]: Emi-Odeon Brasil, p1977. 1 CD. Faixa 7. IV. KOBAYASHI, K. Doença dos xavantes. 1980. 1 fotografia, color., 16 cm × 56 cm.","a":"Segundo a NBR 6023, está correto o que consta APENAS em I e IV.","b":"I, II e III.","c":"I, II e IV.","d":"II e III.","e":"III e IV. Biblioteconomia>Referência bibliográfica ,Normas e Legislações da Biblioteconomia ,","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1542","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia BRASIL. Tribunal Regional Federal (5. Região). Administrativo. Escola Técnica Federal. Pagamento de diferenças referente a enquadramento de servidor decorrente da implantação de Plano Único de Classificação e Distribuição de Cargos e Empregos, instituído pela Lei n° 8.270/91. Predominância da lei sobre a portaria. Apelação cível n° 42.441-PE (94.05.01629- 6). Apelante: Edilemos Mamede dos Santos e outros. Apelada: Escola Técnica Federal de Pernambuco. Relator: Juiz Nereu Santos. Recife, 4 de março de 1997. Lex: jurisprudência do STJ e Tribunais Regionais Federais, São Paulo, v. 10, n° 103, p. 558-562, mar. 1998. É considerado elemento complementar:","a":"Pagamento de diferenças referente a enquadramento de servidor decorrente da implantação de Plano Único de","b":"Classificação e Distribuição de Cargos e Empregos, instituído pela Lei n° 8.270/91. Apelante: Edilemos Mamede dos Santos e outros. Apelada: Escola Técnica Federal de Pernambuco.","c":"Relator: Juiz Nereu Santos.","d":"(5. Região).","e":"Lex: jurisprudência do STJ e Tribunais Regionais Federais, São Paulo, v. 10, n° 103, p. 558-562, mar. 1998. Biblioteconomia>Referência bibliográfica ,Normas e Legislações da Biblioteconomia ,","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1543","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia Considere os dois agrupamentos abaixo, nos quais se arrolam exemplos de referências e os tipos de documentos a que eles se referem: I. EMBRAPA. Unidade de Apoio, Pesquisa e Desenvolvimento de Instrumentação Agropecuária (São Carlos, SP). Paulo Estevão Cruvinel. Medidor digital multissensor de temperatura para solos. BR n. PI 8903105-9, 26 jun. 1989, 30 maio 1995. II. BARROS, Raimundo Gomes de. Ministério Público: sua legitimação frente ao Código do Consumidor. Revista Trimestral de Jurisprudência dos Estados, São Paulo, v. 19, n. 139, p. 53-72, ago. 1995. III. BLADE Runner. Direção: Ridley Scott. Produção: Michael Deeley.Los Angeles: Warner Brothers, c1991. 1 DVD (117 min). a. Imagem em movimento. b. Patente.","a":"c. Doutrina. correlação correta dos dois agrupamentos é:","b":"A Ic; IIa; IIIb. Ia; IIc; IIIb.","c":"Ib; IIc; IIIa.","d":"Ia; IIb; IIIc.","e":"Ic; IIb; IIIa. Direito Constitucional>Supremo Tribunal Federal ,Superior Tribunal de Justiça ,","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1544","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia ...","a":"Quanto à composição de Tribunais é correto afirmar: participação de membros do Ministério Público e da Advocacia nos Tribunais Regionais Federais, nos Tribunais de A Justiça e no Superior Tribunal de Justiça é obrigatória por conta da regra do quinto constitucional.","b":"O Superior Tribunal de Justiça é integrado, em parte de seus quadros, por Desembargadores Federais, que a ele são alçados por meio de promoção, que alterna os critérios de antiguidade e de merecimento.","c":"A regra de participação paritária de advogados e membros do Ministério Público é aplicável a todos os Tribunais, à exceção do Supremo Tribunal Federal.","d":"O Superior Tribunal de Justiça é integrado, obrigatoriamente, por 33 Ministros, sendo um terço por cidadãos com mais de 35 e menos de 65 anos de idade, de reputação ilibada e de notório saber jurídico, indicados pelo Presidente da República após aprovação pelo Senado Federal.","e":"O Superior Tribunal de Justiça poderá ter a sua composição ampliada para além de 33 Ministros, devendo, no entanto, observar sempre a proporcionalidade entre seus integrantes prevista pela Constituição Federal.","gabarito":"","materia":"Geral","tema":"","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia ...","concurso":"TRF3"},{"id":"Q629860","enunciado":"O Congresso Nacional aprovou projeto de lei após regular trâmite, remetendo-o, em seguida, ao Presidente da República. Entendendo-o contrário ao interesse público, o Presidente resolveu vetá-lo integralmente, restituindo-o, então, ao Congresso. As Casas Legislativas Federais, apreciando o veto, deliberaram pela sua rejeição. Citada rejeição dependerá do voto","a":"de dois terços dos integrantes do Congresso, sendo certo que, alcançado o quórum, o Presidente do Congresso o promulgará.","b":"da maioria simples dos integrantes do Congresso, sendo certo que, com a obtenção do quórum, o projeto será remetido ao Presidente da República, para promulgação.","c":"da maioria absoluta dos integrantes de cada Casa Legislativa Federal, sendo certo que, obtido o quórum, o Presidente da Casa pela qual tramitou por último a análise do veto deverá promulgá-lo.","d":"da maioria absoluta dos integrantes do Congresso, sendo certo que, obtido o quórum, o projeto será remetido ao Presidente da República, para promulgação.","e":"da maioria simples dos integrantes do Congresso, sendo certo que, com a obtenção do quórum, o Presidente do Congresso deverá promulgá-lo.","gabarito":"D","materia":"Direito Constitucional","tema":"Processo Legislativo ,Deliberação Parlamentar ,Fase Complementar","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia ...","concurso":"TRF3"},{"id":"Q629859","enunciado":"","a":"incorporação e a fusão de Municípios deverão ser feitas por intermédio de lei federal, em qualquer oportunidade, após consulta prévia, mediante referendo, às populações dos Municípios A envolvidos e autorização da Assembleia Legislativa do Estado em que se encontrem as mencionadas unidades Federativas.","b":"estadual, dentro do período determinado por lei complementar editada pelo Estado, após consulta prévia, mediante plebiscito, às populações dos Municípios envolvidos e aprovação das respectivas Câmaras Legislativas.","c":"federal, dentro do período determinado por lei complementar federal, após consulta prévia, mediante referendo, às populações dos Municípios envolvidos.","d":"estadual, dentro do período determinado por lei complementar federal, após consulta prévia, mediante plebiscito, às populações dos Municípios envolvidos.","e":"estadual, em qualquer oportunidade, após consulta prévia, mediante plebiscito, às populações dos Municípios envolvidos.","gabarito":"D","materia":"Direito Constitucional","tema":"Organização do Estado – Municípios ,Organização Político-Administrativa do Estado","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia ...","concurso":"TRF3"},{"id":"Q629858","enunciado":"","a":"Acerca dos direitos sociais assegurados pela Constituição Federal, é correto afirmar: A remuneração do serviço extraordinário será sempre superior em cinquenta por cento à do normal.","b":"O salário-família é direito apenas do trabalhador considerado de baixa renda, nos termos definidos em lei.","c":"É assegurada ao empregado a participação nos lucros ou resultados, vinculada à remuneração e à participação na","d":"gestão da empresa. Para o trabalho realizado em turnos ininterruptos de revezamento, a jornada será sempre de seis horas.","e":"É assegurada a eleição, em todas as empresas, de um representante dos empregados com a finalidade exclusiva de promover o entendimento direto com os empregadores. Direito Administrativo>Lei nº 8.112-1990 - Regime jurídico dos servidores públicos federais ,","gabarito":"B","materia":"Direito Constitucional","tema":"Direitos Sociais","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia ...","concurso":"TRF3"},{"id":"TRF3_1548","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia ... Débora, servidora pública do Tribunal Regional Federal da 3ª Região, solicitou remoção para outra localidade, para acompanhar seu cônjuge, também servidor público federal, que foi deslocado no interesse da Administração. Nos termos","a":"da Lei n° 8.112/1990, a remoção de Débora ocorre sempre de ofício, isto é, não se dá a pedido do servidor.","b":"pode se dar no âmbito do mesmo quadro de servidores ou em quadro diverso.","c":"independe do interesse da Administração.","d":"ocorre a critério da Administração.","e":"ocorre, obrigatoriamente, sem mudança de sede.","gabarito":"","materia":"Geral","tema":"","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia ...","concurso":"TRF3"},{"id":"Q629855","enunciado":"O processo disciplinar será conduzido por comissão composta de servidores estáveis, designados pela autoridade competente. A propósito do tema, considere: I. O processo disciplinar será conduzido por comissão composta de cinco servidores estáveis. II. A comissão terá como secretário servidor designado pelo seu presidente, não podendo a indicação recair em um de seus membros. III. Poderá participar de comissão de sindicância ou de inquérito, parente do acusado, em linha colateral, de terceiro grau. IV. As audiências das comissões terão caráter reservado.","a":"Nos termos da Lei n° 8.112/1990, está correto o que consta APENAS em I, II e III.","b":"IV.","c":"I e II.","d":"II.","e":"I, III e IV. Direito Administrativo>Lei nº 8.112-1990 - Regime jurídico dos servidores públicos federais ,","gabarito":"B","materia":"Direito Administrativo","tema":"Agentes públicos e Lei 8.112 de 1990 ,Responsabilidades do servidor","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia ...","concurso":"TRF3"},{"id":"TRF3_1550","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia ... Ricardo, servidor público do Tribunal Regional Federal da 3ª Região, foi condenado administrativamente à penalidade de demissão. Já seu colega Bernardo, também servidor público do Tribunal Regional Federal da 3ª Região e ocupante de cargo em comissão, foi condenado administrativamente à penalidade de destituição do cargo em comissão. Nos termos da Lei n° 8.112/1990, as mencionadas penalidades disciplinares foram aplicadas","a":"pelo Presidente do Tribunal Regional Federal da 3ª Região e pela autoridade que nomeou Bernardo para o cargo em comissão, respectivamente.","b":"pelo Presidente do Tribunal Regional Federal da 3ª Região em ambos os casos, não importando, na segunda hipótese, qual autoridade nomeou Bernardo para o cargo em comissão.","c":"pela autoridade administrativa de hierarquia imediatamente inferior à do Presidente do Tribunal Regional Federal da 3ª Região em ambos os casos, não importando, na segunda hipótese, qual autoridade nomeou Bernardo para o cargo em comissão.","d":"pela autoridade administrativa de hierarquia imediatamente inferior à do Presidente do Tribunal Regional Federal da 3ª Região e pela autoridade que nomeou Bernardo para o cargo em comissão, respectivamente.","e":"pela autoridade administrativa de hierarquia imediatamente inferior à do Presidente do Tribunal Regional Federal da 3ª Região e pelo Presidente do Tribunal Regional Federal da 3ª Região, respectivamente.","gabarito":"","materia":"Geral","tema":"","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia ...","concurso":"TRF3"},{"id":"Q629853","enunciado":"Carlos, servidor público do Tribunal Regional Federal da 3ª Região, foi designado para exercer função de confiança no mencionado Tribunal. Cumpre salientar, todavia, que quando houve a publicação do ato de designação para a função de confiança, Carlos estava em licença. Nessa hipótese, conforme preceitua a Lei n° 8.112/1990, o início do exercício da função","a":"de confiança recairá no primeiro dia útil após o término da licença, que não poderá exceder a noventa dias da publicação.","b":"quinto dia útil após o término da licença, que não poderá exceder a sessenta dias da publicação.","c":"décimo quinto dia útil após o término da licença, que não poderá exceder a sessenta dias da publicação.","d":"quinto dia útil após o término da licença, que não poderá exceder a trinta dias da publicação.","e":"primeiro dia útil após o término da licença, que não poderá exceder a trinta dias da publicação.","gabarito":"E","materia":"Direito Administrativo","tema":"Agentes públicos e Lei 8.112 de 1990 ,Cargo, emprego, função","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia ...","concurso":"TRF3"},{"id":"Q629852","enunciado":"","a":"respeito dos Crimes Contra a Administração pública, considere: I. Comete o crime de condescendência criminosa o funcionário público que, por indulgência, sabendo da prática de infração administrativa por parte de subordinado, deixa, quando lhe faltar competência para responsabilizar o subordinado, de levar o fato ao conhecimento da autoridade competente. II. Equipara-se a funcionário público a pessoa que trabalha para empresa prestadora de serviço contratada ou conveniada para a execução de atividade típica da Administração. III. Não configura desacato a ofensa dirigida a funcionário público em razão de suas funções se não estiver no exercício dessas funções no momento da ofensa. Está correto o que consta APENAS em","b":"A I e II. I e III.","c":"II e III.","d":"III.","e":"II. Direito Penal>Crimes contra a administração pública ,Concussão e Excesso de Exação ,Corrupção passiva","gabarito":"A","materia":"Direito Penal","tema":"Crimes contra a administração pública ,Condescendência criminosa ,Desacato","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia ...","concurso":"TRF3"},{"id":"TRF3_1553","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia ... Cicerus, funcionário público, exercia suas funções na Circunscrição de Trânsito e recebeu quantia em dinheiro de uma autoescola para aprovação e fornecimento de carteira de habilitação aos candidatos nela matriculados, sem os necessários","a":"exames. Cicerus cometeu crime de concussão.","b":"corrupção ativa.","c":"prevaricação.","d":"corrupção passiva.","e":"peculato.","gabarito":"","materia":"Geral","tema":"","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia ...","concurso":"TRF3"},{"id":"Q629850","enunciado":"Penélope, funcionária pública, recebeu doações de roupas feitas para a Secretaria de Assistência Social, local em que exercia as suas funções, destinadas a campanha de solidariedade, para serem distribuídas a pessoas pobres. De posse","a":"dessas mercadorias, apropriou-se de várias peças. Nesse caso, Penélope cometeu crime de apropriação indébita simples.","b":"cometeu crime de peculato doloso.","c":"cometeu crime de apropriação indébita qualificada pelo recebimento da coisa em razão de ofício, emprego ou","d":"profissão. cometeu crime de peculato culposo.","e":"não cometeu delito por tratar-se de bens recebidos em doação.","gabarito":"B","materia":"Direito Penal","tema":"Crimes contra a administração pública ,Peculato","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia ...","concurso":"TRF3"},{"id":"Q629849","enunciado":"Brutus, no interior de uma loja, a pretexto de adquirir roupas, solicitou ao vendedor vários modelos para experimentar, mas, no interior do provador, escondeu uma das peças dentro de suas vestes, devolveu as demais e deixou o local. Brutus","a":"cometeu crime de furto qualificado pela fraude.","b":"apropriação indébita.","c":"furto simples.","d":"estelionato.","e":"furto de coisa comum.","gabarito":"A","materia":"Direito Penal","tema":"Crimes contra o patrimônio ,Furto ,Apropriação indébitaEstelionato","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia ...","concurso":"TRF3"},{"id":"Q629848","enunciado":"Placídio achou na rua um cartão de crédito e o utilizou para efetuar compras de roupas finas em um estabelecimento","a":"comercial. Essa conduta caracterizou o crime de apropriação indébita.","b":"furto qualificado pela fraude.","c":"estelionato.","d":"extorsão simples.","e":"receptação.","gabarito":"C","materia":"Direito Penal","tema":"Crimes contra o patrimônio ,Furto ,ExtorsãoApropriação indébita ,Estelionato ,Receptação","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia ...","concurso":"TRF3"},{"id":"Q629847","enunciado":"","a":"Cinco amigos possuem idades de 17, 18, 19, 20 e 21 anos. respeito de suas idades, eles dizem: Antônio: Tenho 17 anos. Beto: Nasci antes do que Ernesto. César: Tenho 18 anos. Dario: Sou mais novo do que César. Ernesto: Tenho 20 anos. Sabendo-se que apenas um dos cinco mentiu, a soma das idades de Beto e Ernesto, em anos, é igual a","b":"A 40. 38.","c":"41.","d":"37.","e":"39.","gabarito":"C","materia":"Raciocínio Lógico","tema":"Verdades e Mentiras","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia ...","concurso":"TRF3"},{"id":"Q629846","enunciado":"Um exame é constituído de cinco perguntas, sendo que cada uma deve ser respondida com verdadeiro (V) ou falso (F). A tabela abaixo mostra as respostas assinaladas por quatro alunos. Sabendo-se que um dos quatro alunos acertou todas as respostas, outro acertou somente duas das respostas, e outro","a":"errou todas as respostas, o número de respostas certas do aluno restante foi 3.","b":"4.","c":"1.","d":"2.","e":"5.","gabarito":"D","materia":"Raciocínio Lógico","tema":"Verdades e Mentiras","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia ...","concurso":"TRF3"},{"id":"Q629845","enunciado":"Determinada mercadoria é classificada em dois tipos de categorias de acordo com o seu índice de impureza: médio (M) e baixo (B). A mercadoria do tipo M é vendida ao preço de “três por R$ 99,00”, e a do tipo B ao preço de “duas por R$ 99,00”. Em determinada época do ano o fabricante da mercadoria vendeu um lote, contendo a mesma quantidade de mercadorias","a":"dos tipos M e B, ao preço de “cinco por R$ 198,00”. Na venda desse lote o fabricante perdeu 4%.","b":"perdeu 8%.","c":"ganhou 4%.","d":"ganhou 5%.","e":"ganhou 8%.","gabarito":"A","materia":"Raciocínio Lógico","tema":"Raciocínio Matemático","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia ...","concurso":"TRF3"},{"id":"Q629844","enunciado":"","a":"locomotiva de um trem leva 8 segundos para ultrapassar uma árvore de espessura desprezível, e leva 38 segundos para atravessar totalmente um túnel de 120 metros. Considerando-se que durante todo o tempo a locomotiva tenha permanecido com a mesma velocidade, o comprimento da locomotiva, em metros, é igual a","b":"A 28. 45.","c":"30.","d":"32.","e":"60.","gabarito":"D","materia":"Raciocínio Lógico","tema":"Raciocínio Matemático","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia ...","concurso":"TRF3"},{"id":"Q629843","enunciado":"Uma peça de precisão é fabricada em diversas especificações. Observe na tabela abaixo o catálogo das 12 primeiras dessas peças e seus respectivos códigos, abaixo.","a":"Mantendo o mesmo padrão, o código da 55ª peça desse catálogo é 23*AB","b":"17**AA","c":"18*AA","d":"24**AB","e":"14**AA","gabarito":"E","materia":"Raciocínio Lógico","tema":"Sequências Lógicas de Números, Letras, Palavras e Figuras","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia ...","concurso":"TRF3"},{"id":"Q629842","enunciado":"","a":"bula de um suplemento alimentar indica que a dosagem correta não deve exceder semanalmente 2 onças de suplemento por cada 11 libras de massa do usuário. Adotando nos cálculos que 1 onça equivale a 28 g, e que 2,2 libras equivalem a 1 kg, se uma pessoa de 60 kg consumir a dosagem máxima semanal, distribuída em doses diárias iguais, ela irá ingerir diariamente uma quantidade de suplemento, em gramas, igual a","b":"A 84. 96.","c":"102.","d":"92.","e":"86.","gabarito":"B","materia":"Raciocínio Lógico","tema":"Raciocínio Matemático","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia ...","concurso":"TRF3"},{"id":"Q629841","enunciado":"O chão de uma sala tem a forma de um quadrado de centro C. Dois segmentos retos serão traçados no chão, um horizontal (paralelo a dois lados opostos do quadrado), e outro vertical (paralelo aos outros dois lados opostos do quadrado), dividindo o chão em quatro figuras (P, Q, R e S), como representa, abaixo, a imagem em uma situação particular. Para que o traçado dos segmentos seja feito de forma a garantir que a soma das áreas de figuras P e R seja igual a soma","a":"das áreas das figuras Q e S, é necessário que, ao menos, duas das quatro figuras sejam quadrados.","b":"necessário que os dois segmentos sejam divididos na proporção 2:1.","c":"necessário que os dois segmentos passem por C.","d":"suficiente que um dos segmentos passe por C.","e":"suficiente que um dos segmentos seja dividido na proporção 2:1.","gabarito":"D","materia":"Raciocínio Lógico","tema":"Geometria Básica","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia ...","concurso":"TRF3"},{"id":"Q629840","enunciado":"O setor de compras de uma empresa vai adquirir certas quantidades de dois tipos de artigos, sendo um deles de valor unitário R$ 15,00, e o outro no valor unitário R$ 24,00. Gastando exatamente R$ 537,00 nessa compra, o maior número de","a":"maneiras distintas em que ela poderá ser realizada é igual a 4.","b":"5.","c":"3.","d":"6.","e":"9.","gabarito":"A","materia":"Raciocínio Lógico","tema":"Raciocínio Matemático","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia ...","concurso":"TRF3"},{"id":"Q629839","enunciado":"Um bibliotecário irá guardar certo número de livros em três prateleiras vazias (A, B e C). Na prateleira A ele começa guardando 28 livros e, em seguida, a quinta parte dos livros restantes. Depois, na prateleira B, ele guarda 30 livros e, logo","a":"em seguida, a metade dos livros restantes. Finalmente, ele guarda na prateleira C os livros que sobraram. Se as prateleiras e B ficaram com a mesma quantidade de livros ao final da tarefa, então a prateleira C ficou com um total de livros igual a","b":"A 10. 9.","c":"13.","d":"11.","e":"12.","gabarito":"D","materia":"Raciocínio Lógico","tema":"Raciocínio Matemático","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia ...","concurso":"TRF3"},{"id":"Q629838","enunciado":"No caminho reto entre as cidades A e B encontram-se 15 postes da companhia elétrica e 15 postes da companhia telefônica, todos eles alinhados no caminho, mas não se sabe a ordem de alinhamento dos 30 postes. Uma equipe de","a":"manutenção que trabalha para as duas empresas checou, um a um, o funcionamento de cada poste no caminho da cidade para a B. Esse trabalho parou após a checagem do 10° poste da companhia elétrica, sendo que no resto do caminho de A para B ainda ficaram 10 postes para serem checados. No dia seguinte, uma equipe que cuida da pintura dos postes das duas companhias iniciou o trabalho de pintura dos postes, um a um, no caminho da cidade B para a cidade A. O trabalho dessa equipe parou depois de pintar o 6° poste de energia elétrica. Após a realização das tarefas dessas duas equipes, o total de postes do caminho entre as cidades que foi checado mas NÃO foi pintado é igual a","b":"A 11. 9.","c":"19.","d":"21.","e":"18. Português>Interpretação de Textos ,Redação - Reescritura de texto ,","gabarito":"C","materia":"Raciocínio Lógico","tema":"Raciocínio Matemático","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia ...","concurso":"TRF3"},{"id":"Q629836","enunciado":"O pior no meu entender está na poesia brasileira, tanto quanto a nossa literatura não imediatamente comercial, ter sido convertida, no empenho de fazê-la alcançar um público mais amplo do que o cada vez mais arredio público frequentador de livrarias, em remédio chato de tomar. Indicados pelos professores como leitura obrigatória a alunos sem maior curiosidade intelectual, esses livros, essas antologias ministradas sob receita pedagógica traem a finalidade precípua da literatura, que é a de deleitar. Dou a este verbo uma etimologia poética, pouco me importando saber se é falsa, possível ou verdadeira. Vejo-o nucleado na palavra “leite”, o alimento primeiro e essencial que reconcilia o nascituro com o mundo no qual se vê repentinamente atirado, sem consulta prévia, e que o faz imaginá-lo, como nos poemas de William Blake, antes o paraíso dos prazeres da idade da inocência que o prosaico reino de deveres da idade da experiência. (Adaptado de: PAES, José Paulo. Apud. SILVA, Marcia Cristina. José Paulo Paes: entre o crítico literário e o poeta para crianças. Revista FronteiraZ, São Paulo, n. 8, julho de 2012.) fazê-la alcançar − Vejo-o nucleado − faz imaginá-lo","a":"Os pronomes dos segmentos acima se referem, respectivamente, a: literatura não imediatamente comercial – este verbo – o paraíso","b":"literatura não imediatamente comercial − leite − o alimento primeiro","c":"leitura obrigatória − o alimento primeiro − o mundo","d":"poesia brasileira − o nascituro − o paraíso","e":"poesia brasileira − este verbo − o mundo","gabarito":"E","materia":"Português","tema":"Interpretação de Textos ,Coesão e coerência","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia ...","concurso":"TRF3"},{"id":"Q629835","enunciado":"","a":"No texto, o autor exalta as qualidades da poesia não imediatamente comercial, como a produzida pelo poeta inglês William Blake.","b":"repudia a literatura comercial, cujo objetivo precípuo é o de alcançar o grande público.","c":"critica métodos educativos que não levam em consideração a etimologia da palavra poética.","d":"assinala a importância do contato com a poesia se dar como uma fonte de prazer gratuito.","e":"expõe a necessidade de que a noção de dever da idade da experiência seja incutida, por meio da literatura, ainda na infância. Português>Morfologia ,Advérbios ,Sintaxe","gabarito":"D","materia":"Português","tema":"Interpretação de Textos ,Noções Gerais de Compreensão e Interpretação de Texto","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia ...","concurso":"TRF3"},{"id":"TRF3_1569","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia ... Os Beatles eram um mecanismo de criação. A força propulsora desse mecanismo era a interação dialética de John Lennon e Paul McCartney. Dialética é diálogo, embate, discussão. Mas também jogo permanente. Adição e contradição. Movimento e síntese. Dois compositores igualmente geniais, mas com inclinações distintas. Dois líderes cheios de ideias e talento. Um levando o outro a permanentemente se superar. As narrativas mais comuns da trajetória dos Beatles levam a crer que a parceria Lennon e McCartney aconteceu apenas na fase inicial do conjunto. Trata-se de um engano. Mesmo quando escreviam separados, John e Paul o faziam um para o outro. Pensavam, sentiam e criavam obcecados com a presença (ou ausência) do parceiro e rival. Lennon era um purista musical, apegado a suas raízes. Quem embarcou na vanguarda musical dos anos 60 foi Paul McCartney, um perfeccionista dado a experimentos e delírios orquestrais. Em contrapartida, sem o olhar crítico de Lennon, sem sua verve, os mais conhecidos padrões de McCartney teriam sofrido perdas poéticas. Lennon sabia reprimir o banal e fomentar o sublime. Como a dialética é uma via de mão dupla, também o lado suave de Lennon se nutria da presença benfazeja de Paul. Gemas preciosas como Julia têm as impressões digitais do parceiro, embora escritas na mais monástica solidão. Nietzsche atribui caráter dionisíaco aos impulsos rebeldes, subjetivos, irracionais; forças do transe, que questionam e subvertem a ordem vigente. Em contrapartida, designa como apolíneas as tendências ordenadoras, objetivas, racionais, solares; forças do sonho e da profecia, que promovem e aprimoram o ordenamento do mundo. Ao se unirem, tais forças teriam criado, a seu ver, a mais nobre forma de arte que jamais existiu. Como criadores, tanto o metódico Paul McCartney como o irrequieto John Lennon expressavam à perfeição a dualidade proposta por Nietzsche. Lennon punha o mundo abaixo; McCartney construía novos monumentos. Lennon abria mentes; McCartney aquecia corações. Lennon trazia vigor e energia; McCartney impunha senso estético e coesão. Quando os Beatles se separaram, essa magia se rompeu. John e Paul se tornaram compositores com altos e baixos. Fizeram coisas boas. Mas raramente se aproximaram da perfeição alcançada pelo quarteto. Sem a presença instigante de Lennon, Paul começou a patinar em letras anódinas. Não se tornou um compositor ruim. Mas os Beatles faziam melhor. Ironicamente, o grande disco dos ex-Beatles acabou sendo o álbum triplo em que George Harrison deglutiu os antigos companheiros de banda, abrindo as comportas de sua produção represada durante uma década à sombra de John e Paul. E foi assim, por estranhos caminhos antropofágicos, que a dialética de Lennon e McCartney brilhou pela última vez. (Adaptado de: DANTAS, Marcelo O. Revista Piauí. Disponível em: http://revistapiaui.estadao.com.br/materia/beatles. Acesso em: 20/02/16) Quando os Beatles se separaram, essa magia se rompeu. (7° parágrafo)","a":"Considerado o contexto, a oração subordinada da frase acima estabelece noção de conformidade.","b":"tempo.","c":"comparação.","d":"proporcionalidade.","e":"consequência.","gabarito":"","materia":"Geral","tema":"","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia ...","concurso":"TRF3"},{"id":"Q629833","enunciado":"","a":"O elemento que justifica a flexão verbal da frase está sublinhado em: Gemas preciosas como Julia têm as impressões digitais do parceiro... (4°parágrafo)","b":"... também o lado suave de Lennon se nutria da presença benfazeja de Paul. (4° parágrafo)","c":"Em contrapartida, sem o olhar crítico de Lennon, sem sua verve, os mais conhecidos padrões de McCartney teriam sofrido","d":"perdas poéticas. (3°parágrafo) A força propulsora desse mecanismo era a interação dialética de John Lennon e Paul McCartney. (1° parágrafo)","e":"... tais forças teriam criado, a seu ver, a mais nobre forma de arte... (5°parágrafo) Português>Sintaxe ,","gabarito":"E","materia":"Português","tema":"Sintaxe ,Concordância verbal, Concordância nominal","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia ...","concurso":"TRF3"},{"id":"TRF3_1571","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia ... ... tanto o metódico Paul McCartney como o irrequieto John Lennon expressavam à perfeição a dualidade... (6° parágrafo)","a":"O verbo que possui, no contexto, o mesmo tipo de complemento que o da frase acima está empregado em: Os Beatles eram um mecanismo de criação.","b":"Fizeram coisas boas.","c":"... a mais nobre forma de arte que jamais existiu.","d":"... criavam obcecados com a presença (ou ausência)...","e":"... que a dialética de Lennon e McCartney brilhou pela última vez.","gabarito":"","materia":"Geral","tema":"","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia ...","concurso":"TRF3"},{"id":"Q629831","enunciado":"Considerado o contexto, afirma-se corretamente:","a":"Nos segmentos Mesmo quando escreviam separados, John e Paul o faziam um para o outro (2° parágrafo) e E foi assim (...) que a dialética de Lennon e McCartney (último parágrafo), ambos os elementos sublinhados são pronomes que exercem a mesma função.","b":"Substituindo-se “um engano” por “equívocos”, o verbo da frase Trata-se de um engano (2° parágrafo) deverá ser flexionado no plural.","c":"Sem prejuízo da correção, o segmento sublinhado em As narrativas mais comuns da trajetória dos Beatles levam a crer que... (2° parágrafo) pode ser substituído por “levam à crença de que”.","d":"Mantendo-se o sentido original, os elementos sublinhados em sem o olhar crítico de Lennon, sem sua verve(3° parágrafo) e Paul começou a patinar em letras anódinas (7° parágrafo) podem ser substituídos, respectivamente, por “irreverência” e “perniciosas”.","e":"Expandindo-se a oração embora escritas na mais monástica solidão (4°parágrafo), o resultado será: “embora cada um deles as tenham escrito na mais monástica solidão”.","gabarito":"C","materia":"Português","tema":"Interpretação de Textos ,Redação - Reescritura de texto","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia ...","concurso":"TRF3"},{"id":"Q629830","enunciado":"É correto depreender do texto: I. O autor apresenta o contraste entre Apolo e Dionísio, estabelecido por Nietzsche, com o propósito de classificar os processos de criação de John Lennon e Paul McCartney à luz de tal teoria, processos que seriam, respectivamente, dionisíaco e apolíneo. II. Ao lançar mão do termo “dialética” no último parágrafo, o autor assinala a incongruência da atitude dos Beatles ao se separarem, uma vez que tal separação ocasionou a derrocada da criação musical dos membros da banda. III. O uso do adjetivo “antropofágicos” (último parágrafo) para caracterizar os caminhos seguidos por George Harrison está relacionado à afirmativa anterior de que o músico teria “deglutido” os antigos companheiros de banda.","a":"Atende ao enunciado o que consta APENAS em I.","b":"II e III.","c":"I e II.","d":"II.","e":"I e III.","gabarito":"E","materia":"Português","tema":"Interpretação de Textos ,Noções Gerais de Compreensão e Interpretação de Texto","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia ...","concurso":"TRF3"},{"id":"Q629829","enunciado":"As normas de concordância estão plenamente respeitadas na redação da seguinte frase:","a":"Ainda que se admita que o aprendizado e a cultura alteram a expressão de uma emoção e conferem-lhe novos significados, constata-se que as emoções dependem de mecanismos cerebrais estabelecidos de modo inato.","b":"O impacto integral e duradouro dos sentimentos requer a consciência, pois somente com o advento de um sentido do “eu” tornam-se conhecidos os sentimentos pelo indivíduo que os possuem.","c":"As emoções são adaptações singulares que integram o mecanismo, especialmente das espécies mais desenvolvidas, com os quais os organismos regulam sua sobrevivência.","d":"Emoções de todas as gradações, como consequência de um poderoso mecanismo de aprendizado de importância vital para a sobrevivência, torna-se inseparável de nossa ideia de bem e de mal.","e":"Não se pode observar o sentimento que um outro vivencia, mas alguns aspectos da emoção que o originou é perfeitamente observável por outra pessoa.","gabarito":"A","materia":"Português","tema":"Sintaxe ,Concordância verbal, Concordância nominal","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia ...","concurso":"TRF3"},{"id":"Q629828","enunciado":"Sem exceção, homens e mulheres de todas as idades, culturas e níveis de instrução têm emoções, cultivam passatempos que manipulam as emoções, atentam para as emoções dos outros, e em grande medida governam suas vidas buscando uma emoção, a felicidade, e procurando evitar emoções desagradáveis. À primeira vista, não existe nada caracteristicamente humano nas emoções, pois numerosas criaturas não humanas têm emoções em abundância; entretanto, existe algo acentuadamente característico no modo como as emoções vincularam-se a ideias, valores, princípios e juízos complexos que só os seres humanos podem ter. De fato, a emoção humana é desencadeada até mesmo por uma música e por filmes banais cujo poder não devemos subestimar. Embora a composição e a dinâmica precisas das reações emocionais sejam moldadas em cada indivíduo pelo meio e por um desenvolvimento único, há indícios de que a maioria das reações emocionais, se não todas, resulta de longos ajustes evolutivos. As emoções são parte dos mecanismos biorreguladores com os quais nascemos, visando à sobrevivência. Foi por isso que Darwin conseguiu catalogar as expressões emocionais de tantas espécies e encontrar consistência nessas expressões, e é por isso que em diferentes culturas as emoções são tão facilmente reconhecidas. É bem verdade que as expressões variam, assim como varia a configuração exata dos estímulos que podem induzir uma emoção. Mas o que causa admiração quando se observa o mundo do alto é a semelhança, e não a diferença. Aliás, é essa semelhança que permite que a arte cruze fronteiras. As emoções podem ser induzidas indiretamente, e o indutor pode bloquear o progresso de uma emoção que já estava presente. O efeito purificador (catártico) que toda boa tragédia deve produzir, segundo Aristóteles, tem por base a suspensão de um estado sistematicamente induzido de medo e compaixão. Não precisamos ter consciência de uma emoção, com frequência não temos e somos incapazes de controlar intencionalmente as emoções. Você pode perceber-se num estado de tristeza ou de felicidade e ainda assim não ter ideia dos motivos responsáveis por esse estado específico. Uma investigação cuidadosa pode revelar causas possíveis, porém frequentemente não se consegue ter certeza. O acionamento inconsciente de emoções também explica por que não é fácil imitá-las voluntariamente. O sorriso nascido de um prazer genuíno é produto de estruturas cerebrais localizadas em uma região profunda do tronco cerebral. A imitação voluntária feita por quem não é um ator exímio é facilmente detectada como fingimento – alguma coisa sempre falha, quer na configuração dos músculos faciais, quer no tom de voz. (Adaptado de: DAMÁSIO, Antonio. O mistério da consciência. Trad. Laura Teixeira Motta. São Paulo, Cia das letras, 2015, 2.ed, p. 39-49) ... há indícios de que a maioria das reações emocionais, se não todas... (2° parágrafo) Mantendo-se o mesmo tipo de relação que estabelece na frase acima, o segmento sublinhado preenche corretamente a","a":"lacuna desta frase: Todos, ...... você, riram-se do acidente.","b":"O palestrante não obteve outra coisa ...... escárnio.","c":"Fala três línguas, ...... quatro.","d":"Não expressou ...... emoções negativas.","e":"Havia um ...... em seu exame.","gabarito":"C","materia":"Português","tema":"Sintaxe ,Uso dos conectivos","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia ...","concurso":"TRF3"},{"id":"Q629827","enunciado":"","a":"Ao se reescrever um segmento do texto, o sinal indicativo de crase foi empregado de modo correto em: Frequentemente não temos consciência de uma emoção, pois somos incapazes de à controlar propositadamente.","b":"Essa é, à propósito, a semelhança que permite que a arte cruze fronteiras.","c":"Por sinal, à essa semelhança imputa-se a causa da arte ser capaz de cruzar fronteiras.","d":"A partir dessa semelhança, permite-se à arte cruzar fronteiras.","e":"À uma região profunda do tronco cerebral atribui-se o ponto de partida de reações como um sorriso nascido de um prazer genuíno. Português>Interpretação de Textos ,Significação Contextual de Palavras e Expressões. Sinônimos e Antônimos. ,","gabarito":"D","materia":"Português","tema":"Crase","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia ...","concurso":"TRF3"},{"id":"TRF3_1577","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia ...","a":"Considerando-se o segundo parágrafo do texto, é correto afirmar: O segmento assim como pode ser substituído por \"conquanto\", sem prejuízo da correção e do sentido.","b":"Sem prejuízo da correção, a expressão do alto pode ser substituída por “a distância”.","c":"A supressão da crase no segmento visando à sobrevivência, embora correta gramaticalmente, acarreta mudança ao sentido original.","d":"Caso o verbo “resultar”, originalmente flexionado no singular, seja flexionado no plural, haverá prejuízo para a","e":"correção. Admite transposição para a voz passiva a frase que as expressões variam.","gabarito":"","materia":"Geral","tema":"","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia ...","concurso":"TRF3"},{"id":"Q629825","enunciado":"O segmento grifado adquire sentido de alternância em:","a":"Uma investigação cuidadosa pode revelar causas possíveis, porém frequentemente não se consegue ter certeza. (4°","b":"parágrafo). Mas o que causa admiração quando se observa o mundo do alto é asemelhança, e não a diferença. (2° parágrafo).","c":"O acionamento inconsciente de emoções também explica por que não é fácil imitá-las... (4° parágrafo).","d":"... alguma coisa sempre falha, quer na configuração dos músculos faciais, quer no tom de voz. (4° parágrafo).","e":"... a emoção humana é desencadeada até mesmo por uma música e por filmes banais... (1° parágrafo).","gabarito":"D","materia":"Português","tema":"Interpretação de Textos ,Noções Gerais de Compreensão e Interpretação de Texto","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia ...","concurso":"TRF3"},{"id":"Q629824","enunciado":"Sem exceção, homens e mulheres de todas as idades, culturas e níveis de instrução têm emoções, cultivam passatempos que manipulam as emoções, atentam para as emoções dos outros, e em grande medida governam suas vidas buscando uma emoção, a felicidade, e procurando evitar emoções desagradáveis. À primeira vista, não existe nada caracteristicamente humano nas emoções, pois numerosas criaturas não humanas têm emoções em abundância; entretanto, existe algo acentuadamente característico no modo como as emoções vincularam-se a ideias, valores, princípios e juízos complexos que só os seres humanos podem ter. De fato, a emoção humana é desencadeada até mesmo por uma música e por filmes banais cujo poder não devemos subestimar. Embora a composição e a dinâmica precisas das reações emocionais sejam moldadas em cada indivíduo pelo meio e por um desenvolvimento único, há indícios de que a maioria das reações emocionais, se não todas, resulta de longos ajustes evolutivos. As emoções são parte dos mecanismos biorreguladores com os quais nascemos, visando à sobrevivência. Foi por isso que Darwin conseguiu catalogar as expressões emocionais de tantas espécies e encontrar consistência nessas expressões, e é por isso que em diferentes culturas as emoções são tão facilmente reconhecidas. É bem verdade que as expressões variam, assim como varia a configuração exata dos estímulos que podem induzir uma emoção. Mas o que causa admiração quando se observa o mundo do alto é a semelhança, e não a diferença. Aliás, é essa semelhança que permite que a arte cruze fronteiras. As emoções podem ser induzidas indiretamente, e o indutor pode bloquear o progresso de uma emoção que já estava presente. O efeito purificador (catártico) que toda boa tragédia deve produzir, segundo Aristóteles, tem por base a suspensão de um estado sistematicamente induzido de medo e compaixão. Não precisamos ter consciência de uma emoção, com frequência não temos e somos incapazes de controlar intencionalmente as emoções. Você pode perceber-se num estado de tristeza ou de felicidade e ainda assim não ter ideia dos motivos responsáveis por esse estado específico. Uma investigação cuidadosa pode revelar causas possíveis, porém frequentemente não se consegue ter certeza. O acionamento inconsciente de emoções também explica por que não é fácil imitá-las voluntariamente. O sorriso nascido de um prazer genuíno é produto de estruturas cerebrais localizadas em uma região profunda do tronco cerebral. A imitação voluntária feita por quem não é um ator exímio é facilmente detectada como fingimento – alguma coisa sempre falha, quer na configuração dos músculos faciais, quer no tom de voz. (Adaptado de: DAMÁSIO, Antonio. O mistério da consciência. Trad. Laura Teixeira Motta. São Paulo, Cia das letras, 2015, 2.ed, p. 39-49) O acréscimo de uma ou mais vírgulas no segmento original resultou em alteração de sentido em: I. ... e, em grande medida, governam suas vidas... (1° parágrafo) II. ... cultivam passatempos, que manipulam as emoções... (1° parágrafo) III. ... porém, frequentemente, não se consegue ter certeza. (último parágrafo)","a":"Atende ao enunciado APENAS o que consta em II e III.","b":"I e II.","c":"II.","d":"I e III.","e":"III.","gabarito":"C","materia":"Português","tema":"Pontuação ,Uso da Vírgula","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia ...","concurso":"TRF3"},{"id":"Q629823","enunciado":"","a":"No texto, identifica-se relação de causa e consequência, respectivamente, entre: processos evolutivos de adaptação que remontam a épocas distantes e grande parte das reações emocionais.","b":"a suscitação de uma emoção imprevista e a estratégia por trás de uma obra de arte vulgar feita para agradar o público em geral.","c":"o fato de Darwin ter sido bem-sucedido ao catalogar as expressões emocionais de diversas espécies e a existência de emoções inerentes à regulação dos organismos.","d":"nossa incapacidade de dissimular as emoções e o fato de que não precisamos ter consciência de uma emoção para que ela aconteça.","e":"a capacidade da arte de cruzar fronteiras culturais e o fato das reações emocionais serem moldadas por uma composição complexa única e exclusiva a cada indivíduo.","gabarito":"A","materia":"Português","tema":"Interpretação de Textos ,Noções Gerais de Compreensão e Interpretação de Texto","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Biblioteconomia ...","concurso":"TRF3"},{"id":"Q629527","enunciado":"","a":"O TRF3 quer implantar uma Central de Serviço conforme estabelecido na ITIL v3 Edição 2011, cujo principal objetivo é gerenciar terceiros especializados em gestão de mudanças.","b":"gerenciar as mudanças.","c":"executar as requisições de mudança.","d":"contratar terceiros especializados em atendimento a clientes.","e":"prover um ponto único de contato entre o provedor de serviço e os usuários.","gabarito":"E","materia":"Governança de TI","tema":"ITIL ,ITIL v. 3","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629526","enunciado":"Um Técnico Judiciário de TI de um Tribunal necessitou saber quais ações de recuperação haviam sido tomadas após uma determinada mudança que falhou. Observou que uma dessas ações havia sido o retorno a um estado conhecido para permitir que o processo de negócio continuasse.","a":"No contexto do Gerenciamento de Mudança, na ITIL v3 Edição 2011, tal conjunto de ações é tratado como Plano Estratégico de Negócio.","b":"Remediação.","c":"Manual de Continuidade do Serviço.","d":"Disaster Recovery.","e":"Changing Plan.","gabarito":"B","materia":"Governança de TI","tema":"ITIL ,ITIL v. 3","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629525","enunciado":"Os Técnicos Judiciários de TI do TRF3, a fim de tomarem medidas preventivas, devem estar atentos a um tipo de ataque à rede que explora uma falha de segurança no protocolo que mapeia endereços IP para endereços físicos Media Access Control − MAC. Isto porque existe uma lista de conversão que é elaborada e mantida para agilizar a pesquisa dos endereços mapeados. Esse ataque adultera essa lista enviando uma série de falsas respostas ao alvo para que a comunicação passe para o atacante de modo a alterar a comunicação do computador de destino, modificando o mapeamento de endereço IP e MAC, assim se passando pelo alvo e ficando no meio da comunicação. Trata-se do ataque do tipo Man in The Middle − MITM","a":"categorizado como IP Tamper Listing.","b":"DNS spoofing.","c":"MAC Cache Breaking.","d":"DNS Corrupt Caching","e":"ARP Cache Poisoning.","gabarito":"E","materia":"Segurança da Informação","tema":"Ataques e ameaças","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629524","enunciado":"Um usuário que se conecta em uma rede wifi em um local público, por exemplo, está exposto a vários tipos de ataques Man in The Middle − MITM. Nesse sentido, para tomarem alguma ação preventiva, os Técnicos Judiciários de TI do TRF3 devem","a":"estar atentos a um desses tipos de ataque, o Session Hijacking, que é utilizado para o sequestro de sessão por meio de modificação do channel Cain & Abe","b":"roubo de cookie que utiliza HTTP.","c":"envenenamento do cache HTTP.","d":"interceptação do tráfego da rede para capturar uma consulta DNS.","e":"sequestro do ettercap, via sniffer","gabarito":"B","materia":"Segurança da Informação","tema":"Ataques e ameaças","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629523","enunciado":"Para responder a questão considere as informações abaixo. Os Técnicos Judiciário de TI de um Tribunal têm ciência sobre ataques da internet e por isso adotam medidas de defesa contra (I) falsificação de e-mail porque esta técnica consiste em alterar (II) elementos do e-mail de forma a aparentar que ele foi enviado de uma determinada origem quando, na verdade, foi enviado de outra. O que possibilita esta técnica de falsificação é a característica de um (III) protocolo de Internet que permite que campos do From, do Reply to e do Return-Path sejam adulterados. Isto é bastante usado por alguns hackers para propagação de códigos maliciosos, envio de spam e (IV) tipos de ataques que atuam informando, falsamente, que a não execução dos procedimentos descritos pode acarretar sérias consequências, como, por exemplo, a inscrição em serviços de proteção de crédito e coisas semelhantes. O protocolo referido em III, cuja característica possibilita o tipo de falsificação descrito, e, a característica de ataque referida","a":"em IV correspondem, correta e respectivamente, a SNMP e sniffing.","b":"HTTP e DDoS","c":"HTML e briefing.","d":"SMTP e phishing.","e":"DNS e DoS","gabarito":"D","materia":"Redes de Computadores","tema":"Protocolo","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629522","enunciado":"Para responder a questão considere as informações abaixo. Os Técnicos Judiciário de TI de um Tribunal têm ciência sobre ataques da internet e por isso adotam medidas de defesa contra (I) falsificação de e-mail porque esta técnica consiste em alterar (II) elementos do e-mail de forma a aparentar que ele foi enviado de uma determinada origem quando, na verdade, foi enviado de outra. O que possibilita esta técnica de falsificação é a característica de um (III) protocolo de Internet que permite que campos do From, do Reply to e do Return-Path sejam adulterados. Isto é bastante usado por alguns hackers para propagação de códigos maliciosos, envio de spam e (IV) tipos de ataques que atuam informando, falsamente, que a não execução dos procedimentos descritos pode acarretar sérias consequências, como, por exemplo, a inscrição em serviços de proteção de crédito e coisas semelhantes. O nome pelo qual a falsificação referida em I é conhecido e os elementos do e-mail alterados referidos em II correspondem,","a":"correta e respectivamente, a e-mail pharming e texto da mensagem.","b":"splashing e dados do remetente.","c":"spoofing e campos do cabeçalho.","d":"brut force e dados do destinatário.","e":"defacement e campos do cabeçalho.","gabarito":"C","materia":"Segurança da Informação","tema":"Ataques e ameaças","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629521","enunciado":"","a":"diretoria do TRF3 solicitou ao departamento técnico de TI que preparasse uma tabela demonstrando as diferenças de conceitos entre internet e intranet, comparando as duas tecnologias. Na tabela preparada foram assinalados com “sim” os itens que correspondem aos conceitos internet e/ou intranet e com “não” aos que não correspondem. Considerando os seguintes itens: I. Comunicação instantânea. II. Comunicação externa. III. Compartilhamento de impressoras. IV. Compartilhamento de dados. V. Rede local. A tabela está correta em","b":"A Itens - I Internet- sim Intranet - sim Itens - IV Internet - não Intranet - sim","c":"Itens - III Internet -não Intranet - não","d":"Itens - V Internet- sim Intranet - não","e":"Itens - II Internet- sim Intranet - sim","gabarito":"A","materia":"Noções de Informática","tema":"Internet ,Intranet e Extranet","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629520","enunciado":"Ao consultar as funções das camadas e protocolos do modelo TCP/IP, um Técnico Judiciário de TI do TRF3 obteve as seguintes informações: I. Conectar dois programas trabalhando em um mesmo computador como, por exemplo, um browser web e um leitor de e- mail. Seus protocolos atribuem a cada programa um número de porta que é anexado a cada pacote de modo que o TCP/IP saiba a quem entregar cada mensagem recebida pela rede. II. Fazer com que a informações sejam transmitidas de um computador para outro em uma mesma mídia de acesso compartilhado ou em uma ligação ponto a ponto. Sua preocupação é permitir o uso do meio físico que conecta os computadores na rede e fazer com que os bytes enviados de um computador cheguem a outro quando há uma conexão direta entre eles. III. Fazer com que as informações enviadas por um computador cheguem a outros computadores pelo protocolo de rede, ainda que estejam em redes fisicamente distintas, ou seja, não existe conexão direta entre eles. Ele traz a capacidade da rede TCP/IP se “reconfigurar” quando uma parte da rede está fora do ar, procurando uma rota alternativa para a comunicação.","a":"Acerca das funções de camadas, os itens I, II e III correspondem, correta e respectivamente, a transporte; acesso a rede; internet.","b":"aplicação; acesso a rede; internet.","c":"aplicação; acesso a rede; transporte.","d":"transporte; internet; aplicação.","e":"acesso a rede; internet; transporte.","gabarito":"A","materia":"Redes de Computadores","tema":"Arquitetura TCP/IP","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629519","enunciado":"Considere os elementos do sistema e da arquitetura Bluetooth abaixo. I. Unidade básica do sistema. II. Coleção interconectada de duas ou mais dessa unidade básica. III. Nós da rede (além dos oito nós – um mestre e mais sete escravos) que o mestre comuta para um estado de baixa energia a fim de reduzir o consumo de baterias. IV. Dois estados de energia intermediários.","a":"Os itens I, II, III e IV correspondem, correta e respectivamente, a I- piconet / II - scatternet / III - nós estacionados (inativos) em número de até 255 / IV - hold e sniff","b":"I- piconet/ II - vippernet / III - nós estacionados (inativos) em número de até 225 / IV - hold e kraft","c":"I- scatternet II - piconet III - nós paralelos (ativos) em número de até 255 IV - bridge e sniff","d":"I- vippernet II - piconet III - nós paralelos (ativos) em número de até 225 IV - bridge e kraft","e":"I- piconet II -scatternet III - nós estacionados (inativos) em número de até 225 IV - bridge e sniff Redes de Computadores>Arquiteturas de Rede ,Arquitetura TCP/IP ,LAN (Local Area Network)","gabarito":"A","materia":"Redes de Computadores","tema":"Redes sem Fio","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629517","enunciado":"Um Tribunal pretende divulgar publicamente notícias radiofônicas pela internet (voz sobre IP, por exemplo) a respeito de sua esfera de atuação e dos serviços oferecidos. Todavia, o protocolo RTP (com multidifusão) utilizado para transmissão de sinais de rádio encontra determinados obstáculos como, por exemplo, o fato de que a maioria dos administradores de sistemas configuram seu firewall para proteger sua LAN de visitantes indesejáveis. Em geral, eles permitem conexões TCP pela porta remota 25, pacotes UDP pela porta remota 53 e conexões TCP pela porta remota 80. Quase todas as outras conexões são bloqueadas, inclusive o RTP. Então, uma alternativa é usar a unidifusão de alguma forma em vez da multidifusão por RTP. Nesse sentido, um meio de fazer o sinal de rádio passar pelo firewall, é o website fingir ser, pelo","a":"menos para o firewall, um protocolo SSL e usar switches over TCP que se comuniquem usando o DNS.","b":"roteador DHCP e usar switches over TCP que se comuniquem usando o UDP.","c":"servidor HTTPS e usar servidores SMTP de banda larga com função de broadcasting para dispersão do sinal e","d":"penetração no firewall. servidor HTTP e usar servidores HTTP que se comuniquem usando o TCP.","e":"protocolo UDP e usar servidores HTML que se comuniquem usando o TCP.","gabarito":"D","materia":"Redes de Computadores","tema":"Firewall","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629516","enunciado":"Em uma consulta a respeito de elementos de interconexão de redes e meios de transmissão, um Técnico Judiciário de TI do TRF3 explicou que o Fast Ethernet, quando criado, visou manter os antigos formatos de quadros, interfaces e regras de procedimentos e apenas reduzir o tempo de bit de 100 ns para 10 ns. Tecnicamente teria sido possível copiar o 10Base-5 ou o 10Base-2 e continuar a detectar colisões a tempo, pela simples redução do comprimento máximo do cabo a um décimo do comprimento original. Entretanto, com a evolução do cabeamento, surgiu o","a":"100Base-T cujas vantagens eram tão grandes que o Fast Ethernet se baseou inteiramente nesse projeto. Por isso, todos os sistemas Fast Ethernet usam bridges e routers. Cabos ponto a ponto com conectores de pressão ou conectores BNC não são permitidos.","b":"100Base-T cujas vantagens eram tão grandes que o Fast Ethernet se baseou inteiramente nesse projeto. Por isso, todos os sistemas Fast Ethernet usam bridges e switches. Cabos multiponto com conectores de pressão ou conectores BNC são permitidos.","c":"10Base-T cujas vantagens eram tão grandes que o Fast Ethernet se baseou inteiramente nesse projeto. Por isso, todos os sistemas Fast Ethernet usam hubs e switches. Cabos multiponto com conectores de pressão ou conectores BNC não são permitidos.","d":"10Base100 cujas vantagens eram tão grandes que o Fast Ethernet se baseou inteiramente nesse projeto. Por isso, todos os sistemas Fast Ethernet usam hubs e smart switches. Cabos fiberglass com conectores de grampo ou conectores BNC-T são os mais utilizados.","e":"10Base-M cujas vantagens eram tão grandes que o Fast Ethernet se baseou inteiramente nesse projeto. Por isso, todos os sistemas Fast Ethernet usam hubs, bridges e routers. Cabos thin com conectores de pressão ou conectores BNC-T são os mais utilizados.","gabarito":"C","materia":"Redes de Computadores","tema":"Arquiteturas de Rede ,Cabeamento ,Ethernet","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629515","enunciado":"Ao ser consultado a respeito de comunicação de dados, um Técnico Judiciário de TI de um Tribunal prestou a informação INCORRETA que","a":"as ondas de rádio são fáceis de gerar, podem percorrer longas distâncias e penetrar facilmente nos prédios, portanto, são amplamente utilizadas para comunicação, seja em ambientes fechados ou abertos.","b":"um sistema de transmissão óptica tem três componentes fundamentais: a fonte de luz, o meio de transmissão e o detector. Por convenção, um pulso de luz indica um bit 1, e a ausência de luz representa um bit zero.","c":"os pulsos de luz enviados através de uma fibra se contraem à medida que se propagam. Essa contração é chamada colapso cromático. O volume da contração depende do comprimento de onda.","d":"a comunicação óptica utiliza três bandas de comprimentos de onda. Elas são centralizadas em 0,85, 1,30 e 1,55 micra, respectivamente. As duas últimas têm boas propriedades de atenuação (uma perda inferior a 5% por quilômetro) um par trançado consiste em dois fios de cobre encapados, que em geral têm cerca de 1 mm de espessura. Os fios","e":"são enrolados de forma helicoidal, assim como uma molécula de DNA. O trançado dos fios é feito porque dois fios paralelos formam uma antena simples. Quando os fios são trançados, as ondas de diferentes partes dos fios se cancelam, o que significa menor interferência.","gabarito":"C","materia":"Redes de Computadores","tema":"Meios físicos de transmissão","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629514","enunciado":"Um Tribunal pretende instalar uma nova rede de comunicação de dados e solicitou aos seus Técnicos Judiciários de TI para especificarem alguns componentes para essa rede. Tais componentes foram especificados em suas respectivas categorias, sendo: I. Escala (Abrangência). II. Meio físico. III. Topologia de cabos.","a":"Correspondem, respectivamente, a essas categorias: Unicasting; fio metálico; anel.","b":"WAN; raio laser; em espinha.","c":"PAN; Multicasting; em rede.","d":"Broadband; onda; barramento.","e":"Árvore; fita magnética; blindado.","gabarito":"B","materia":"Redes de Computadores","tema":"Topologias ,Meios físicos de transmissão","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629513","enunciado":"Um Técnico Judiciário de TI se deparou com a necessidade de entendimento de determinados serviços do Active Directory para poder configurá-lo no Windows Server 2008 R2. Para tanto, ele analisou as seguintes funcionalidades: I. Oferece solução para emissão e administração de certificados usados em sistemas de segurança que utilizam a tecnologia de chaves públicas e privadas. II. Permite estabelecer confiança entre diferentes entidades organizacionais dando aos usuários finais um logon único (SSO) entre empresas. III. Permite um gerenciamento centralizado e seguro de toda uma rede. Armazena as informações sobre objetos na rede e gerencia a comunicação entre os usuários e os domínios, incluindo processos de logon do usuário, autenticação e pesquisas de diretório. Correspondem, respectivamente, às funcionalidades I, II e III analisadas pelo Técnico, os seguintes serviços:","a":"Active Directory Federation Services − ADFS; Active Directory Domain Services – ADDS; Active Directory Sites and Services − ADSS.","b":"Active Directory Federation Services − ADFS; Active Directory Sites and Services − ADSS; Active Directory Lightweight Directory Services − ADLDS.","c":"Active Directory Service Interfaces Editor − ADSIE; Active Directory Sites and Services − ADSS; Active Directory Lightweight Directory Services − ADLDS.","d":"Active Directory Certificate Services − ADCS; Active Directory Federation Services − ADFS; Active Directory Domain Services − ADDS.","e":"Active Directory Certificate Services − ADCS; Active Directory Federation Services − ADFS; Active Directory Sites and Services − ADSS.","gabarito":"D","materia":"Sistemas Operacionais","tema":"Windows ,Administração de usuários (AD - Active Directory) ,Windows 2008 Server","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629512","enunciado":"O Windows Server 2008 possui funcionalidades nos Serviços de Terminal para fazer a conexão com aplicações e computadores remotos. O ...I... para Serviços de Terminal integra completamente as aplicações executadas em um servidor de terminal com as estações de trabalho dos usuários, de modo que as aplicações se comportam como se elas estivessem sendo executadas em um computador local do usuário; os usuários podem executar programas a partir de um local remoto, juntamente com seus programas locais. O Acesso à web nos Serviços de Terminal permite essa mesma flexibilidade do acesso remoto de aplicação através de navegador da web, concedendo muitas maneiras para o usuário acessar e usar os programas executados em um servidor de terminal. Estes recursos, em conjunto com o ...II... de Serviços de Terminal, permitem que os usuários acessem remotamente as estações de trabalho e as aplicações via ....III... de uma maneira amigável com o firewall.","a":"As lacunas I, II e III devem ser preenchidas, correta e respectivamente, por: RemoteApp − Gateway − HTTPS","b":"Gateway − VDesktop − SSL","c":"RemoteApp − VDesktop − HTTP","d":"VDesktop − Gateway − HTTPS","e":"Gateway − RemoteApp − SSL","gabarito":"A","materia":"Sistemas Operacionais","tema":"Terminal Services","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629511","enunciado":"Ao estudar a preparação da infraestrutura de virtualização a ser utilizada no ambiente Windows Server 2008 R2, um Técnico Judiciário de TI do Tribunal observou que o Hyper-V é usado para a virtualização do computador cliente quando usado em","a":"conjunto com a tecnologia Virtual DNS Infrastructure − DNSSEC.","b":"Basic Desktop Node − BDN.","c":"Client Desktop Infrastructure − CDI.","d":"Virtual Basic Client System − VBCS.","e":"Virtual Desktop Infrastructure − VDI.","gabarito":"E","materia":"Sistemas Operacionais","tema":"Windows ,Virtualização ,Windows 2008 Server","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629510","enunciado":"No ambiente Windows 7 um usuário pode escolher as mensagens que deseja ver porque as notificações de múltiplos","a":"recursos, incluindo o Windows Defender, estão consolidadas em Lista de Saltos","b":"Barra de Tarefas.","c":"Windows Touch.","d":"Central de Ações.","e":"Device Stage.","gabarito":"D","materia":"Sistemas Operacionais","tema":"Windows ,Windows 7","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629509","enunciado":"Ao colaborar com a elaboração de um Termo de Referência para contratação de produtos e serviços de informática, um","a":"Técnico Judiciário de TI do TRF3 observou os seguintes requisitos gerais: solução integrada e informatizada para gestão administrativa deverá ser adaptável à estrutura específica do Tribunal, estar em conformidade com a legislação pública, possibilitando a Execução Orçamentária e Financeira, Licitações e Contratos, Gestão de Frota, Gestão de Obras e Manutenção Predial, Gestão de Imóveis, Gestão de Compras, Gestão de Patrimônio, Gestão de Almoxarifado, Recursos Humanos, Relatórios Gerenciais, Gestão de Processos Administrativos, Extrajudiciais e Judiciais, com instalação centralizada na estrutura física do Tribunal e disponibilização de acesso via web, para uso por quantidade ilimitada de usuários por tempo indeterminado, devendo proporcionar as funcionalidades requeridas e definidas em capítulo próprio. Pelas características de tais requisitos, o Técnico entendeu que se tratava","b":"A Customer Relationship Management. Enterprise Resource Planning.","c":"Sistema de Apoio a Decisão.","d":"Computer Numeric Control.","e":"Sistema de Controle de Processos.","gabarito":"B","materia":"Arquitetura de Software","tema":"ERP (Enterprise Resource Planning)","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629508","enunciado":"Um Técnico Judiciário de TI do TRF3, ao estudar os princípios dos sistemas operacionais, teve sua atenção voltada ao processo que perfaz a interface do usuário com o sistema operacional. Observou que este processo lê o teclado a espera de comandos, interpreta-os e passa seus parâmetros ao sistema operacional. Entendeu, com isto, que serviços como login/logout, manipulação de arquivos e execução de programas são, portanto, solicitados por meio do interpretador de","a":"comandos ou Kernel.","b":"System Calls.","c":"Shell.","d":"Cache.","e":"Host.","gabarito":"C","materia":"Sistemas Operacionais","tema":"Linux","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629507","enunciado":"Uma das classes do ASP.NET MVC 5 responsáveis por converter os dados provenientes de requisições HTTP em objetos .Net","a":"requeridos como parâmetros de Actions Methods é a classe HttpRequestAttribute.","b":"HttpRequest.","c":"ModelGetConverter.","d":"DefaultModelBinder.","e":"HttpRequestValue.","gabarito":"D","materia":"Programação","tema":"ASP","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629506","enunciado":"Em um site que utiliza HTML5 Application Cache há um arquivo chamado dados.appcache que define que uma página poderá ter o conteúdo acessado mesmo estando offline. Nessa página, para apontar para esse arquivo deve-se utilizar a","a":"instrução < html manifest=\"dados.appcache\">","b":"< cache manifest=\"dados.appcache\">","c":"< html src=\"dados.inf\" cached>","d":"< cache src=\"dados.inf\">","e":"< !MANIFEST cache=\"demo.appcache\">","gabarito":"A","materia":"Programação","tema":"HTML (HyperText Markup Language) ,Linguagens de marcação","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629505","enunciado":"Considere o método abaixo, de uma aplicação Java:","a":"Ao chamar esse método a partir de outra classe, passando como parâmetro o valor \"R$ 1.000\", será retornado o valor no formato double, para quem chamou o método.","b":"o método será executado normalmente, porém, a conversão não será realizada e aparecerá para o usuário uma","c":"mensagem padrão indicando que o formato do número não é válido. ocorrerá uma exceção do tipo NumberFormatException que deverá ser tratada na chamada do método","d":"ocorrerá uma exceção do tipo NumberFormatException, porém, o método será executado normalmente e o valor 1000 será retornado como double.","e":"ocorrerá uma exceção do tipo NumberFormatException que deverá ser tratada dentro do próprio método, utilizando try...catch.","gabarito":"C","materia":"Programação","tema":"Java ,Linguagens de programação","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629504","enunciado":"Cookie é um arquivo texto que pode ser armazenado no computador do usuário, normalmente com informações de sua navegação no site, para ser recuperado posteriormente pelo servidor. Em PHP, um cookie criado pela instrução","a":"setcookie(\"ck\", \"abcde\", time() + 3600); poderá ser recuperado utilizando a instrução $_ISSET[\"ck\"]","b":"load_cookie (\"ck\")","c":"get_cookie(\"ck\")","d":"$_GETCOOKIE[\"ck\"]","e":"$_COOKIE[\"ck\"]","gabarito":"E","materia":"Programação","tema":"PHP ,Linguagens de programação","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629503","enunciado":"Os pacotes e bibliotecas de classes Java possuem métodos que podem ser chamados diretamente a partir do nome da classe, sem a necessidade de instanciar um objeto da classe explicitamente. Para chamar esses métodos a partir de outra classe basta digitar o nome da classe, o ponto final e o nome do método, passando, se necessário, os parâmetros. Esses","a":"métodos podem ser acessados desta forma porque eles são públicos e abstratos.","b":"sobrecarregados.","c":"sobrescritos.","d":"estáticos.","e":"dinâmicos.","gabarito":"D","materia":"Programação","tema":"Java ,Linguagens de programação","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629502","enunciado":"Um Técnico Judiciário de TI está criando o formulário de um site para submeter imagens utilizando JSF 2.2. Nesse formulário, para criar o campo para upload da imagem e para criar um botão para submeter a imagem utilizam-se,","a":"respectivamente, as tags < file:inputFile> e <html:submitButton>","b":"< h:uploadImage> e <h:uploadButton>","c":"< f:uploadFile> e <h:submitButton>","d":"< jsf:inputFile> e <jsf:uploadButton>","e":"< h:inputFile> e <h:commandButton>","gabarito":"E","materia":"Programação","tema":"JSF (Java Server Faces) ,Frameworks Java","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629501","enunciado":"Considere o documento XML abaixo. Para que, ao carregar o documento XML no navegador, seja aplicada a formatação de exibição contida no arquivo","a":"Configurar.css a lacuna I deverá ser preenchida com < @import src=\"Configurar.css\">","b":"< ?link xml-stylesheet=\"xml/css\" src=\"Configurar.css\"?>","c":"< ?xml-stylesheet type=\"text/css\" href=\"Configurar.css\"?>","d":"< ?xml import=\"Configurar.css\"?>","e":"< ?xml xmlns:css=\"stylesheet\" xmlns:type=\"text/css\" xmlns:source=\"Configurar.css\"?>","gabarito":"C","materia":"Programação","tema":"XML (Extensible Markup Language) ,CSS (Cascading Style Sheets) ,Linguagens de marcação","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629500","enunciado":"Considere o fragmento, abaixo, de um documento XML Schema Definition, que define regras de validação para um documento XML.","a":"No documento XML o elemento de nome d deverá conter até 6 números do intervalo de 0 a 9.","b":"a poderá aparecer vazio ou somente com o elemento b ou somente com o elemento c.","c":"a deverá ter em seu interior os elementos b e c, não importando a ordem.","d":"d deverá conter exatamente 6 números do intervalo de 0 a 9.","e":"d deverá conter até 9 números, sendo obrigatório que um deles seja o número 6.","gabarito":"D","materia":"Programação","tema":"XML (Extensible Markup Language) ,Linguagens de marcação","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629499","enunciado":"Um Técnico Judiciário de TI está criando um site e observou que existe uma parte de código que se repete em várias páginas JSP. Para evitar essa repetição explícita, criou um segmento de código JSP em um arquivo chamado cab.jspf na pasta WEB- INF/jspf do projeto e colocou nesse segmento a parte que se repete nas várias páginas. Para inserir esse segmento de","a":"código nas páginas JSP, o Técnico deverá utilizar, no local desejado, a instrução <%@page import=\"WEB-INF/jspf/cab.jspf\"%>","b":"<%@include file=\"WEB-INF/jspf/cab.jspf\"%>","c":"<%@page file=\"cab.jspf\" import=\"true\"%>","d":"<%@import src=\"cab.jspf\"%>","e":"<%@import file=\"WEB-INF/jspf/cab.jspf\"%>","gabarito":"B","materia":"Programação","tema":"JSP (JavaServer Pages)","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629498","enunciado":"Considere o código da página web abaixo. Ao inserir um comando na linha 16 e carregar a página no navegador, foram exibidos os valores exatamente como consta abaixo: Processo No: 36535-45.2000.03.3400 Em andamento Considere os seguintes comandos: I. document.write(legenda.concat(numeroSeqProcesso, \"-\", digitoProcesso, \".\", anoAjuizamentoProcesso, \".\", regiaoProcesso, \".\", origemPrimeiroGrauProcesso, \"<br>\", status)); II. document.write(legenda + numeroSeqProcesso + \"-\" + digitoProcesso + \".\" + anoAjuizamentoProcesso + \".\" + regiaoProcesso + \".\" + origemPrimeiroGrauProcesso + \"<br>\" + status); III. document.write(legenda,numeroSeqProcesso, \"-\", digitoProcesso, \".\", anoAjuizamentoProcesso, \".\", regiaoProcesso, \".\", origemPrimeiroGrauProcesso, \"\\n\", status);","a":"Serve corretamente ao propósito da linha 16 os comandos apresentados APENAS em I.","b":"I e II.","c":"II.","d":"II e III.","e":"III.","gabarito":"B","materia":"Programação","tema":"Web","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629497","enunciado":"Considere o método abaixo, retirado de uma classe de acesso a dados de uma aplicação Java. Neste método entity é um objeto da interface EntityManager , conectar é um método que realiza uma conexão válida com um banco de dados que possui a tabela Funcionario, onde se encontra o campo nome, e desconectar é um método que finaliza a conexão com o banco. Nesse trecho de código, para que o parâmetro nome da instrução SELECT da linha 3 receba o conteúdo da variável n da linha 1, de forma que sejam selecionados todos os funcionários que tenham em qualquer parte do nome o que contém a","a":"variável n, a linha 4 deverá ser substituída por em.setNome(\"nome\", \"%\" + n + \"%\") ;","b":"q.setString(\"nome\", \"*\" + n + \"*\") ;","c":"q.setParameter(\"nome\", \"%\" + n + \"%\") ;","d":"em.setNome(\"nome\", \" + n + \") ;","e":"q.setValue(\"nome\", \"*\" + n + \"*\") ;","gabarito":"C","materia":"Programação","tema":"Java ,Linguagens de programação","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629496","enunciado":"O fragmento de código abaixo está presente em um método de uma aplicação que utiliza recursos do framework ORM NHibernate.","a":"As lacunas I, II e III devem ser preenchidas, correta e respectivamente, por: CriteriaBuilder − CriteriaQuery − List","b":"Session − Criteria − ResultList","c":"ISession − ICriteria − IList","d":"SessionFactory − CriteriaBuilder − List","e":"SessionBuilder − Criteria − ArrayList","gabarito":"C","materia":"Programação","tema":"Hibernate ,Frameworks Java","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629495","enunciado":"Um Técnico Judiciário de TI gerou uma aplicação CRUD JavaServer Faces 2.x no Netbeans 7.3 utilizando os assistentes disponíveis. Após fazer a conexão com um banco de dados que contém um conjunto de tabelas relacionadas na janela Serviços,","a":"para abrir o assistente de Classes de Entidade do Banco de Dados, o Técnico clicou com o botão direito do mouse sobre o nome do projeto, selecionou a opção Novo e a opção Classes de Entidade do Banco de Dados.","b":"o Técnico selecionou o servidor de aplicação Tomcat para ter suporte a JNDI, JPA, EJB e realizar a criação de Classes de Entidade do Banco de Dados.","c":"para abrir o assistente de criação de Páginas JSF, o Técnico clicou com o botão direito do mouse sobre o nome do","d":"projeto, selecionou a opção XHTML e a opção Gerar Páginas JSF a partir de Classes de Entidade. foram selecionadas as tecnologias Java Persistence API (JPA), Enterprise JavaBeans (EJB) e NHibernate","e":"para abrir o assistente de criação de classes de negócio EJB, o Técnico clicou com o botão direito do mouse sobre o nome do projeto, selecionou a opção Novo e a opção Classes de Negócio EJB.","gabarito":"A","materia":"Programação","tema":"JSF (Java Server Faces) ,Frameworks Java","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629494","enunciado":"Uma entidade Departamento é composta pelos atributos abaixo. Código do Departamento Matrícula do Funcionário Nome do Departamento Nome do Funcionário Telefone do Departamento Telefone do Funcionário Número da CTPS Considerando-se que só poderá ser cadastrado um único número de telefone, tanto para os departamentos quanto para os funcionários, para que a entidade seja normalizada adequadamente, deve-se","a":"aplicar a segunda forma normal (2FN), de forma que todos os demais atributos sejam dependentes da chave primária, que deverá ser composta pelos atributos Código do Departamento e Matrícula do Funcionário.","b":"aplicar a primeira forma normal (1FN), colocando os atributos Matrícula do Funcionário, Nome do Funcionário, Telefone do Funcionário e Número da CTPS em uma entidade Funcionário relacionada adequadamente à entidade Departamento.","c":"criar mais duas entidades, Funcionário e Telefone, relacionando todas elas com cardinalidade 1:n, com o lado n na entidade Departamento.","d":"eliminar os campos Matrícula do Funcionário, Nome do Funcionário e Telefone do Funcionário, já que estes campos são os únicos que não contém dados do departamento, mas sim do funcionário.","e":"aplicar a segunda forma normal (2FN), que requer que todos os valores de atributos em uma entidade sejam atômicos, eliminando grupos repetidos e colocando-os cada um em uma entidade separada.","gabarito":"B","materia":"Banco de Dados","tema":"Formas normais","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629493","enunciado":"Para responder a questão, considere as informações abaixo. Se a tabela Processo for ligada a uma outra tabela em um relacionamento 1:n, sendo 1 processo para n da outra tabela,","a":"as colunas NumeroSeqProcesso, DigitoProcesso e AnoAjuizamentoProcesso terão que aparecer obrigatoriamente na outra tabela como parte da chave primária.","b":"será obrigatório que na outra tabela seja cadastrado, pelo menos, um registro para cada valor da chave primária da tabela Processo.","c":"a chave primária da outra tabela precisa, necessariamente, aparecer na tabela Processo, para que seja garantida a integridade referencial.","d":"as colunas NumeroSeqProcesso, DigitoProcesso e AnoAjuizamentoProcesso terão que aparecer na outra tabela, para haver integridade referencial.","e":"nem todos os registros cadastrados na outra tabela precisarão estar relacionados a algum processo existente na tabela Processo","gabarito":"D","materia":"Banco de Dados","tema":"Banco de Dados Relacionais","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629492","enunciado":"Após receber permissão para alterar os dados dos registros contidos na tabela Processo, o usuário Paulo inseriu diversos registros utilizando a instrução INSERT e em seguida constatou, por meio da instrução SELECT, que estes dados foram inseridos adequadamente. Porém, outros usuários que acessam a tabela não visualizarão os dados inseridos por Paulo até","a":"que ele execute o comando refresh","b":"end transaction","c":"endpoint","d":"close section","e":"commit","gabarito":"E","materia":"Banco de Dados","tema":"Conceitos Básicos em Banco de Dados","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629491","enunciado":"O super-usuário root do banco de dados deseja conceder permissão para que o usuário Paulo possa alterar os dados dos","a":"registros contidos na tabela Processo. Para isso ele deve digitar a instrução ADD PERMISSION TO Paulo FOR update ON Processo;","b":"GRANT update ON Processo TO Paulo;","c":"CREATE ROLE update ON Processo TO Paulo WITH GRANT OPTION;","d":"GRANT OPTION update FROM Processo TO Paulo;","e":"CREATE ROLE ON Processo FOR update TO Paulo;","gabarito":"B","materia":"Banco de Dados","tema":"Segurança","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629490","enunciado":"Ao executar um comando SQL, foram exibidos os dados abaixo. Anos 2014 2012 2007 2002 2000 1999 1997","a":"O comando digitado foi: SELECT DISTINCT AnoAjuizamentoProcesso AS Anos FROM Processo ORDER BY AnoAjuizamentoProcesso DESC;","b":"SELECT AnoAjuizamentoProcesso AS Anos FROM Processo ORDER BY AnoAjuizamentoProcesso DESC;","c":"SELECT AnoAjuizamentoProcesso AS 'Anos' FROM Processo WITH DISTINCT OPTION;","d":"SELECT DISTINCT AnoAjuizamentoProcesso AS 'Anos' FROM Processo ORDER BY AnoAjuizamentoProcesso;","e":"SELECT DISTINCT AnoAjuizamentoProcesso AS Anos FROM Processo ORDER BY DEC;","gabarito":"A","materia":"Banco de Dados","tema":"SQL","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629489","enunciado":"Para responder a questão, considere as informações abaixo. Um Técnico Judiciário de TI executou um comando SQL e foram exibidas as informações abaixo. Ano < 2000 2","a":"O comando digitado pelo Técnico foi: SELECT COUNT(*) AS 'Ano < 2000' FROM Processo WHERE AnoAjuizamentoProcesso<2000;","b":"SELECTCOUNT(AnoAjuizamentoProcesso)AS Ano < 2000 FROM Processo WHERE AnoAjuizamentoProcesso<2000;","c":"SELECTCOUNT(AnoAjuizamentoProcesso)AS'Ano < 2000'FROMProcesso WHERE AnoAjuizamentoProcesso>2010;","d":"SELECT AVG(AnoAjuizamentoProcesso)AS'Ano < 2000' FROM Processo WHERE AnoAjuizamentoProcesso<2000;","e":"SELECT COUNT(AnoAjuizamentoProcesso) LABEL 'Ano < 2000' FROM Processo WHERE AnoAjuizamentoProcesso<2000;","gabarito":"A","materia":"Banco de Dados","tema":"SQL","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629488","enunciado":"Considere que a tabela Processo foi criada sem chave primária. Nesse caso, para definir a chave primária, antes de serem","a":"inseridos registros, deve-se utilizar a instrução SQL ADD TO Processo PRIMARY KEY(NumeroSeqProcesso, DigitoProcesso, AnoAjuizamentoProcesso);","b":"INSERT INTO Processo PRIMARY KEY(NumeroSeqProcesso, DigitoProcesso, AnoAjuizamentoProcesso);","c":"ALTER TABLE Processo ADD PRIMARY KEY(NumeroSeqProcesso, DigitoProcesso, AnoAjuizamentoProcesso);","d":"ADD CONTRAINT PRIMARY KEY(NumeroSeqProcesso, DigitoProcesso, AnoAjuizamentoProcesso) from Processo;","e":"UPDATE TABLE Processo ADD PRIMARY KEY(NumeroSeqProcesso, DigitoProcesso, AnoAjuizamentoProcesso);","gabarito":"C","materia":"Banco de Dados","tema":"SQL","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629487","enunciado":"Em uma linguagem de programação, os tipos primitivos de dados","a":"são sempre verificados pelo compilador. Caso se extrapole a capacidade do tipo, um erro ocorre e o programa é","b":"abortado. mais comuns e mais utilizados são as matrizes e os registros.","c":"são associados a um descritor. Um descritor é uma estrutura de dados, que não ocupa espaço na memória, que","d":"armazena os atributos do tipo de dados. na forma de caracteres geralmente são armazenados como codificações numéricas, como o padrão UTF.","e":"inteiros são sempre representados como uma cadeia de caracteres. O caracter mais à esquerda representa o sinal positivo ou negativo.","gabarito":"D","materia":"Programação","tema":"Conceitos básicos de programação","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629486","enunciado":"Considere o trecho de programa, abaixo.","a":"Em um programa com condições e ambiente ideais, este trecho de código vai apresentar todos os números pares entre 0 e 1000.","b":"vai apresentar todos os números ímpares entre 0 e 1000.","c":"vai dar erro de compilação. Para corrigir o trecho, o comando for deve ser substituído por: for (i=0; i<=1000; i+=2) ShowMessage(IntToStr(i));","d":"não vai dar erro de compilação e é equivalente ao trecho em que o comando for é substituído por: for i:=0 to 1000 step 2 ShowMessage(IntToStr(i));","e":"vai dar erro de compilação. O erro informa que não é possível atribuir valor a uma variável de controle dentro do comando for.","gabarito":"E","materia":"Programação","tema":"Conceitos básicos de programação","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629485","enunciado":"","a":"Um Técnico Judiciário de TI, ao desenvolver um aplicativo em C#, utilizou o operador & para obter o endereço de memória de uma variável numérica.","b":"~ para fazer uma negação lógica.","c":"% para obter o quociente de uma divisão entre dois valores numéricos inteiros.","d":"<< para deslocar bits para a direita e preencher o número com zeros à esquerda.","e":"^= para realizar a operação lógica NOR (negative OR) entre 2 valores inteiros.","gabarito":"A","materia":"Programação","tema":"Linguagens de programação ,C Sharp","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629484","enunciado":"","a":"maneira correta de se utilizar uma string na linguagem de programação indicada é:","b":"A","c":"","d":"","e":"","gabarito":"C","materia":"Programação","tema":"Linguagens de programação","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629483","enunciado":"","a":"Uma associação correta entre a linguagem de programação e suas palavras-chave, é: Visual Basic: abstracts, assert, extends, implements, package, native.","b":"C#: implicit, sbyte, params, sealed, foreach, namespace.","c":"Delphi: enddeclare, include_once, requires, final, global.","d":"Java: unit, implementation, uses, comp, extended, single.","e":"PHP: AddressOf, ByRef, Delegates, NotOverridable, WithEvents.","gabarito":"B","materia":"Programação","tema":"Conceitos básicos de programação","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629482","enunciado":"Um compilador","a":"baseado em um sistema de compilação pura não realiza traduções; os programas são interpretados por um software interpretador.","b":"do tipo JIT- Just in Time tem sido utilizado em linguagens como Java e C#. Na prática, JIT transforma um sistema híbrido em um sistema de compilação adiada.","c":"que utiliza implementação híbrida traduz o programa para um código de formato intermediário e este código é compilado.","d":"separa a tarefa de analisar a semântica do código em 2 partes: análise léxica e análise sintática. Este processo é","e":"realizado por uma máquina virtual. de uma linguagem de programação traduz código de baixo nível para linguagem de máquina.","gabarito":"B","materia":"Arquitetura de Computadores","tema":"Compilador","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629481","enunciado":"Para responder a questão considere os trechos de códigos abaixo, escritos em 2 diferentes linguagens de programação. Em relação à compilação e execução dos trechos de programa, considerando condições e ambientes ideais a cada linguagem,","a":"os compiladores das linguagens dos trechos 1 e 2 permitem a geração de arquivos executáveis (.EXE). No Visual Studio é possível depurar um executável, com limitações.","b":"no Visual Basic, a utilização do procedimento readln para ler as linhas do arquivo, deverá ser implementada no evento onClick de um botão contido em um formulário.","c":"no trecho 2, para proteger a execução do código evitando um eventual erro de abertura, a diretiva de compilação foi ligada pela instrução {$I-}, para que o resultado da operação de abertura do arquivo seja retornado pela função IOResult. O retorno do valor 1 indica que o arquivo foi aberto com sucesso.","d":"no Delphi, cada arquivo criado deve ter um nome e um número para sua identificação. Para que não haja erros de compilação, o nome do arquivo deve estar acompanhado do caminho (path) onde o arquivo está armazenado.","e":"na execução do trecho 1, todas as linhas do arquivo processos.txt serão apresentadas até que o fim do arquivo seja atingido. É necessário que o arquivo tenha, pelo menos, 2 linhas de dados para não ocorrer um run time error","gabarito":"A","materia":"Arquitetura de Computadores","tema":"Compilador","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629480","enunciado":"","a":"Em relação à sintaxe, estrutura e semântica dos trechos de programa, ambos os trechos manipulam um mesmo arquivo texto denominado processos.txt.","b":"a sintaxe para utilização de eventos onClick em ambas as linguagens é muito semelhante, embora no trecho em C# seja necessário o uso de uma procedure.","c":"o trecho de código em Visual Basic apresenta erro de sintaxe, pois não foi verificado se o arquivo existia antes de ser aberto para leitura.","d":"tanto no Visual Basic quanto no Delphi um arquivo texto é aberto, lido e exposto. Ambos utilizam um componente text ou para ler o nome ou para mostrar o arquivo","e":"em ambos os trechos a variavel1 é utilizada para receber os dados do arquivo que são expostos, no Visual Basic, em um Memo Dialog Box.","gabarito":"D","materia":"Programação","tema":"Visual Basic ,Delphi ,Linguagens de programação","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629479","enunciado":"Em um modelo de arquitetura","a":"cliente-servidor de 2 camadas, apresentação, processamento de aplicações e gerenciamento de dados são processos logicamente separados. Portanto, é um modelo inerentemente mais escalável.","b":"cliente-servidor, a estrutura lógica da aplicação que está sendo desenvolvida é modelada, mas cada aplicação deve ser estruturada apenas em 2 camadas.","c":"distribuído, em que um hardware gerencie as diversas partes e garanta que elas se comuniquem e troquem dados, o middleware não pode ser executado em processadores diferentes, pois utiliza um único protocolo de comunicação.","d":"distribuído, a estrutura é menos complexa do que os sistemas centralizados, mais fácil de gerenciar e suas respostas são mais previsíveis.","e":"de objetos distribuídos, os componentes do sistema são objetos que oferecem uma interface para um conjunto de serviços que eles fornecem. Nesse caso, pode-se pensar na camada de middleware como um barramento de software.","gabarito":"E","materia":"Arquitetura de Software","tema":"Arquitetura Cliente-Servidor ,Sistemas Distribuídos","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629478","enunciado":"Uma aplicação desenvolvida no modelo de arquitetura multicamadas apresenta várias vantagens sobre a técnica de 2 camadas, dentre as quais destaca-se a","a":"separação da lógica do negócio e regras de acesso ao banco de dados da camada de apresentação. No modelo de 2 camadas as regras ficam centralizadas em um único local, ao contrário de em uma aplicação desenvolvida em várias camadas","b":"economia de conexões no servidor, pois se existirem, por exemplo, 500 estações clientes conectadas simultaneamente no servidor, a mesma quantidade de conexões no banco de dados será realizada, uma para cada cliente.","c":"facilidade de redistribuição, pois como as estações clientes acessam uma mesma camada em comum, qualquer alteração realizada nas regras de negócios será vista por todas as aplicações clientes.","d":"divisão das regras de negócios entre o cliente e o servidor, pois como não existe a camada intermediária, a camada de apresentação faz todo o processamento das solicitações de dados e exibe os dados resultantes.","e":"utilização de uma única linguagem de programação, pois como são utilizadas interfaces na construção da arquitetura, a camada de regras de negócios é acessada por aplicações clientes desenvolvidas em uma mesma linguagem.","gabarito":"C","materia":"Arquitetura de Software","tema":"Arquitetura em camadas","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629477","enunciado":"Para responder a questão, considere a figura abaixo. Considerando os conceitos de arquitetura orientada a serviços e o modelo apresentado na figura, o modelo SOA","a":"busca a transformação de recursos de TI em serviços de software centralizados que podem se comunicar entre si, aumentando a flexibilidade dos aplicativos de negócio.","b":"centralizado preconiza que cada aplicativo gerencia sua própria segurança e conta com canais de proteção para os dados que fazem intercâmbio com aplicativos do cliente","c":"em múltiplas camadas de negócios permite que haja mecanismos de segurança aplicados de forma independente do negócio, aumentando a flexibilidade do projeto sem grande impacto na segurança da informação.","d":"incorpora características técnicas e organizacionais que objetivam o compartilhamento de serviços para os processos de negócio que devem ser controlados por um único dono da informação.","e":"usa o protocolo de transferência SOAP com o recurso de extensão no modelo SS-Security. Enviar o nome do usuário na requisição é a única forma de confirmação de identidade.","gabarito":"C","materia":"Arquitetura de Software","tema":"SOA (Service-oriented architecture)","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629476","enunciado":"O modelo arquitetural, apresentado na figura, poderia ser adotado pelo TRF da 3a Região, pois","a":"por ser um modelo baseado em SOA, pode-se trabalhar com as funcionalidades de um aplicativo e facilmente combiná-los com funcionalidades de outros aplicativos criando recursos compostos.","b":"as aplicações compostas não podem combinar funcionalidades de negócios com serviços de outras empresas ou parceiros, aumentando a segurança das informações","c":"por ser um modelo centralizado, o servidor de aplicação é 100% confiável e suficiente para que um requisitante tenha acesso a todas as informações do servidor, incluindo quaisquer dados sensíveis que o cliente esteja enviando.","d":"por ser um modelo baseado em SOA, um determinado recurso não pode ser invocado diretamente pelo cliente, aumentando a segurança das informações.","e":"por ser um modelo centralizado, o servidor de aplicação não é 100% confiável, impedindo que um requisitante tenha acesso às informações do servidor, exceto dados que o cliente esteja enviando.","gabarito":"A","materia":"Arquitetura de Software","tema":"SOA (Service-oriented architecture) ,Arquitetura de Software","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629475","enunciado":"Um Técnico Judiciário de TI utiliza herança ao desenvolver programas orientados a objetos e diagramas de classe da UML para representar as relações entre as classes, pois ele sabe que","a":"em UML, uma relação de dependência entre duas classes coloca-as em uma hierarquia representando o conceito de herança de uma classe base a partir de uma classe derivada.","b":"associações são representadas em UML como linhas conectando as classes e devem mostrar a multiplicidade de cada uma. A multiplicidade é exibida como um intervalo [min..máx] de valores não nulos, com um losango representando infinito.","c":"o diagrama mostra a estrutura dinâmica das classes, representadas por um retângulo dividido em 3 compartimentos, nos quais constam as regras de associação, de especialização e de pacotes.","d":"um sistema normalmente possui alguns diagramas de classes, embora uma certa classe não possa participar de mais de um destes diagramas.","e":"na herança uma classe herda todos os atributos e operações da classe da qual deriva e pode sobrescrever ou modificar alguns deles, bem como adicionar mais atributos e operações próprios.","gabarito":"E","materia":"Engenharia de Software","tema":"Orientação a Objetos ,UML ,Diagrama de Classes","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629474","enunciado":"Considere o programa em C#, abaixo.","a":"O programa em C# imprime 4 e 0.4 caso sejam fornecidos 2 e 0.2 como entrada, respectivamente.","b":"utiliza sobrecarga ao utilizar os métodos Quad() diferenciados pelos tipos de parâmetros de entrada.","c":"tem erro, pois não é possível que haja métodos com o mesmo nome dentro de uma mesma classe.","d":"utiliza sobrescrita ao utilizar as classes Quad() diferenciadas pelos tipos de parâmetros de entrada e de retorno.","e":"devidamente ajustado, compilaria sem erro se os métodos Quad() tivessem parâmetros de entrada do mesmo tipo, já que eles têm tipo de retorno diferentes.","gabarito":"B","materia":"Programação","tema":"Linguagens de programação ,C Sharp","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629473","enunciado":"Considere o diagrama, abaixo, elaborado por um Técnico Judiciário de TI","a":"Com base neste diagrama a classe Pessoa possui os métodos Nome, NumeroCpf, NumeroCnpj e Tipo (Fisica ou Juridica ou Estrangeira).","b":"todas as classes que precisem obter o documento da pessoa devem implementar um comando condicional do tipo if com base no atributo Tipo, considerando o NumeroCpf ou NumeroCnpj, por exemplo, como o documento.","c":"há uma interface Pessoa com o método Nome e com o objeto ObterDocumento e três classes que encapsulam três métodos: PessoaFisica (NumeroCpf), PessoaJuridica (NumeroCnpj) e PessoaEstrangeira (NumeroPassaporte).","d":"cada classe ligada à Pessoa fará sua própria implementação da operação ObterDocumento, de forma que não haja preocupação com a regra para obtenção do documento com base no tipo da pessoa.","e":"caso seja necessário adicionar um quarto tipo de pessoa (PessoaAsilada), o impacto seria grande para as classes dependentes, já que o objeto ObterDocumento teria que ser reescrito em todas elas.","gabarito":"D","materia":"Engenharia de Software","tema":"UML ,Diagrama de Classes","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629472","enunciado":"Para responder a questão considere as informações abaixo. O caso de uso “Validar usuário” é descrito pelo seguinte cenário: − Fluxo de eventos principal: O caso de uso inicia quando o sistema do Tribunal solicita ao usuário a sua senha, formada por números. O usuário fornece os números através do teclado e confirma a senha pressionando a tecla Enter. O sistema checa este número e verifica se ele é válido. − Fluxo de evento excepcional: O usuário pode cancelar seu acesso a qualquer momento pressionando o botão Cancelar, reiniciando o caso de uso. Não é feita nenhuma mudança no processo do usuário. − Fluxo de evento excepcional: O usuário pode corrigir a senha a qualquer momento, utilizando a tecla Backspace, antes de confirmar com a tecla enter. − Fluxo de evento excepcional: Se o usuário fornece um número de senha inválido o caso de uso é reiniciado. Ainda com base no caso de uso, considere os diagramas UML 3 e 4, abaixo.","a":"O diagrama 3 e o diagrama 4 são equivalentes. Ambos são diagramas de estado para o caso de uso “Validar usuário”.","b":"3 e o diagrama 4 são alternativos. Ambos são diagramas de atividades para o caso de uso “Validar usuário”.","c":"de sequência 3 mostra o sequenciamento para ler e verificar a senha e o diagrama de sequência 4 apresenta o caso de uso “Validar usuário”.","d":"de estados 3 mostra os estados de ler e de verificar a senha e o diagrama de estados 4 apresenta os subestados do","e":"estado lendo senha do diagrama 3. de atividades 3 está correto e o diagrama 4 está errado, pois não pode haver atividades em paralelo.","gabarito":"B","materia":"Engenharia de Software","tema":"UML ,Diagrama de Casos de Uso","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629471","enunciado":"Para responder a questão considere as informações abaixo. O caso de uso “Validar usuário” é descrito pelo seguinte cenário: − Fluxo de eventos principal: O caso de uso inicia quando o sistema do Tribunal solicita ao usuário a sua senha, formada por números. O usuário fornece os números através do teclado e confirma a senha pressionando a tecla Enter. O sistema checa este número e verifica se ele é válido. − Fluxo de evento excepcional: O usuário pode cancelar seu acesso a qualquer momento pressionando o botão Cancelar, reiniciando o caso de uso. Não é feita nenhuma mudança no processo do usuário. − Fluxo de evento excepcional: O usuário pode corrigir a senha a qualquer momento, utilizando a tecla Backspace, antes de confirmar com a tecla enter. − Fluxo de evento excepcional: Se o usuário fornece um número de senha inválido o caso de uso é reiniciado. Com base no caso de uso, considere, abaixo, os diagramas UML 1 e 2:","a":"O diagrama 1 e o diagrama 2 são equivalentes. Ambos são diagramas de sequência.","b":"1 é uma agregação do diagrama 2. A agregação relaciona um conceito mais genérico a um conceito que seja mais específico. O diagrama 1 é chamado de superclasse, enquanto 2, mais específico, é a subclasse.","c":"2 é uma generalização do diagrama 1. A generalização relaciona um conceito mais específico a um conceito que seja mais genérico. O diagrama 1 é chamado de superclasse, enquanto 2, mais específico, é a subclasse","d":"de atividades 1 mostra as atividades de ler e de verificar a senha e o diagrama de atividades 2 apresenta o detalhamento da atividade lendo senha do diagrama 1.","e":"de estados 1 mostra os estados de ler e de verificar a senha e o diagrama de estados 2 apresenta os subestados do estado lendo senha do diagrama 1.","gabarito":"E","materia":"Engenharia de Software","tema":"UML ,Diagrama de Casos de Uso","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629470","enunciado":"","a":"análise e o projeto orientados a objeto modelam um sistema em termos de objetos, que têm propriedades e comportamentos, e de eventos, que disparam operações que mudam o estado dos objetos. Considere, abaixo, os fundamentos da Orientação a Objetos − OO: I. Ato de empacotar ao mesmo tempo dados e objetos. O objeto esconde seus dados de outros objetos e permite que os dados sejam acessados por intermédio de seus próprios métodos. Protege os dados do objeto do uso arbitrário e não- intencional. Separa a maneira como um objeto se comporta da maneira como ele é implementado. II. Refere-se à implementação de um tipo de objeto. Especifica uma estrutura de dados e as operações permissíveis que se aplicam a cada um de seus objetos. III. Pode ser real ou abstrato. Possui informações (dados) e desempenha ações (funcionalidades). É qualquer coisa, real ou abstrata, a respeito da qual são armazenados dados e operações. Os conceitos da OO indicados em I, II e III, são, correta e respectivamente,","b":"A Herança, Classe, Atributo. Encapsulamento, Método, Objeto.","c":"Polimorfismo, Superclasse, Método.","d":"Encapsulamento, Classe, Objeto.","e":"Herança, Método, Atributo.","gabarito":"D","materia":"Engenharia de Software","tema":"Orientação a Objetos","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629469","enunciado":"Ao participar de uma reunião técnica em que se discutia a implantação do CMMI versão 1.3, um Técnico Judiciário de TI afirmou, corretamente, que","a":"equivalent staging permite que uma organização que use a representação contínua converta um perfil de nível de capacidade para um rating de nível de maturidade associado.","b":"um perfil de nível de capacidade é uma lista de áreas de processo e o correspondente nível de capacidade atingido em cada uma. Este perfil permite que a organização acompanhe seu nível de maturidade por área de processo.","c":"o perfil que representa a situação atual da organização é chamado de target profile e o perfil que representa os objetivos de melhoria é chamado de achievement profile.","d":"níveis de capacidade são usados para caracterizar melhoria organizacional relativa a um conjunto de áreas de processos, enquanto que níveis de maturidade caracterizam melhoria organizacional relativa a uma única área de processo.","e":"depois que a organização atingiu o último nível de capacidade, ou nível 5 − Em Otimização, ela pode continuar sua jornada de melhoria endereçando high capacity process areas.","gabarito":"A","materia":"Governança de TI","tema":"CMMI (Capability Maturity Model Integration)","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629468","enunciado":"Na implantação do MPS.BR para a melhoria de processos de software e serviços, um Tribunal apresentou as seguintes características: − Atingiu o nível de maturidade composto pelos processos Gerência de Projetos e Gerência de Requisitos. − Está finalizando os processos do nível de maturidade seguinte, composto pelos processos do nível de maturidade anterior, acrescidos dos processos Aquisição, Garantia da Qualidade, Gerência de Configuração, Gerência de Portfólio de Projetos e Medição. Este Tribunal atingiu o nível de maturidade","a":"F − Parcialmente Gerenciado, está finalizando os processos do nível de maturidade E − Gerenciado e passará ao nível","b":"F − Gerenciado, está finalizando os processos do nível de maturidade E − Parcialmente Definido e passará ao nível D − Largamente Definido.","c":"G − Parcialmente Gerenciado, está finalizando os processos do nível de maturidade F − Gerenciado e passará ao nível","d":"− Parcialmente Definido.","e":"− Parcialmente Definido. G − Gerenciado, está finalizando os processos do nível de maturidade F − Parcialmente Definido e passará ao nível E − D Definido. E − Gerenciado, está finalizando os processos do nível de maturidade D − Definido e passará ao nível C − Largamente E Definido. Direito Constitucional>Processo Legislativo ,","gabarito":"C","materia":"Governança de TI","tema":"MPS.BR","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1640","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática ... Rivanildo, Ministro de Estado das Relações Exteriores, cometeu, no exercício de suas funções, crime de responsabilidade.","a":"Em tal hipótese, o julgamento respectivo competirá ao Supremo Tribunal Federal.","b":"Superior Tribunal de Justiça.","c":"Congresso Nacional.","d":"Senado Federal.","e":"Conselho Nacional de Justiça.","gabarito":"","materia":"Geral","tema":"","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática ...","concurso":"TRF3"},{"id":"Q629465","enunciado":"Sobre o disposto nos incisos do art. 5º da Constituição Federal, é INCORRETO afirmar que é","a":"livre o exercício de qualquer trabalho, ofício ou profissão, desde que atendidas as qualificações profissionais que a lei estabelecer.","b":"permitido se reunir pacificamente, sem armas, em locais abertos ao público, independentemente de autorização ou prévio aviso, desde que a iniciativa não frustre outra reunião anteriormente convocada para o mesmo local.","c":"livre a expressão da atividade intelectual, artística, científica e de comunicação, independentemente de censura ou","d":"licença. assegurada, nos termos da lei, a prestação de assistência religiosa nos estabelecimentos penitenciários.","e":"livre a criação de associações e, na forma da lei, a de cooperativas, independentemente de autorização, sendo vedada a interferência estatal em seu funcionamento.","gabarito":"B","materia":"Direito Constitucional","tema":"Direitos Individuais ,Direito à Liberdade","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática ...","concurso":"TRF3"},{"id":"Q629464","enunciado":"As emendas constitucionais,","a":"podem ser propostas desde que por iniciativa de um terço dos integrantes da Câmara dos Deputados e do Senado Federal.","b":"serão sempre promulgadas pelo Presidente do Congresso Nacional, dependendo a sua aprovação do voto de dois terços dos integrantes de ambas as Casas Legislativas.","c":"podem ser propostas, aprovadas e promulgadas sem a participação do Presidente da República, em nenhuma fase do","d":"processo legislativo. podem ser propostas por qualquer Assembleia Legislativa Estadual, pelo voto da maioria simples de seus integrantes.","e":"não poderão ser promulgadas na vigência de intervenção federal, estado de sítio, de defesa ou em situação de calamidade pública. Direito Constitucional>Organização Político-Administrativa do Estado ,","gabarito":"C","materia":"Direito Constitucional","tema":"Processo Legislativo","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática ...","concurso":"TRF3"},{"id":"TRF3_1643","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática ... Considere três situações: (I) Claudio, servidor público federal, afastou-se da sua sede de trabalho, em caráter eventual e transitório, para outro ponto do território nacional, entretanto, o mencionado deslocamento não exige pernoite fora da sede. (II) Já Manoela, também servidora pública federal, afastou-se da sua sede de trabalho, em caráter eventual e transitório, para o exterior. (III) Por fim, Rômulo, também servidor público federal, afastou-se da sua sede de trabalho, em caráter eventual e transitório, sendo o mencionado deslocamento dentro da mesma região metropolitana e não exigindo","a":"pernoite fora da sede. Nos termos da Lei no 8.112/1990, as diárias são devidas em nenhum dos casos narrados.","b":"apenas nos itens II e III, sendo em ambos os casos devidas integralmente.","c":"nos itens I, II e III, sendo em todos os casos devidas integralmente.","d":"apenas nos itens I e III, sendo no item III, devidas pela metade.","e":"apenas nos itens I e II, sendo no item I, devidas pela metade. Direito Administrativo>Lei nº 8.112-1990 - Regime jurídico dos servidores públicos federais ,","gabarito":"","materia":"Geral","tema":"","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática ...","concurso":"TRF3"},{"id":"TRF3_1644","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática ... João, servidor público federal, foi convocado para o serviço militar, razão pela qual lhe foi concedida licença, na forma e","a":"condições previstas na legislação específica. Nos termos da Lei nº 8.112/1990, concluído o serviço militar, João terá quinze dias com remuneração para reassumir o exercício do cargo.","b":"deverá imediatamente reassumir o exercício do cargo.","c":"terá somente quinze dias sem remuneração para reassumir o exercício do cargo.","d":"terá quarenta e cinco dias sem remuneração para reassumir o exercício do cargo.","e":"terá até trinta dias sem remuneração para reassumir o exercício do cargo. Direito Administrativo>Lei nº 8.112-1990 - Regime jurídico dos servidores públicos federais ,","gabarito":"","materia":"Geral","tema":"","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática ...","concurso":"TRF3"},{"id":"TRF3_1645","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática ... Francisco é servidor público do Tribunal Regional Federal da 3ª Região, tendo sido processado administrativamente em razão da prática de conduta sujeita à penalidade de suspensão. No curso do processo disciplinar, Francisco preencheu os requisitos legais para sua aposentadoria. Em razão disso, pleiteou à autoridade competente a extinção do processo disciplinar e a concessão da aposentadoria. Nos termos da Lei no 8.112/1990,","a":"Francisco somente poderá ser aposentado voluntariamente após a conclusão do processo e o cumprimento da penalidade, acaso aplicada.","b":"deve ser imediatamente concedida a aposentadoria voluntária de Francisco; no entanto, o processo deverá prosseguir","c":"até seu desfecho final e, se concluída pela falta, a sanção será convertida em multa pecuniária. o processo deverá ser extinto, em razão do preenchimento dos requisitos para a aposentadoria voluntária.","d":"Francisco somente poderá ser aposentado voluntariamente após a conclusão do processo, não sendo necessário que se aguarde o cumprimento da penalidade, pois poderá cumpri-la de outra forma, ou seja, mediante o pagamento de multa.","e":"a instauração do processo disciplinar suspende os requisitos para a aposentadoria voluntária, isto é, Francisco somente preencherá os requisitos para aposentar-se após o trânsito em julgado do processo disciplinar. Direito Administrativo>Lei nº 8.112-1990 - Regime jurídico dos servidores públicos federais ,","gabarito":"","materia":"Geral","tema":"","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática ...","concurso":"TRF3"},{"id":"TRF3_1646","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática ... Joaquina, servidora pública do Tribunal Regional Federal da 3ª Região, ausentou-se do serviço durante o expediente, sem prévia autorização do seu chefe imediato. Já Josefa, também servidora pública do Tribunal Regional Federal da 3ª Região, retirou sem prévia autorização da autoridade competente, determinado documento da repartição pública. Cumpre salientar que ambas as servidoras tinham histórico exemplar, sem nunca terem sofrido qualquer penalidade administrativa. Nos termos da Lei no 8.112/1990,","a":"apenas Joaquina está sujeita a determinada penalidade administrativa, sendo que a ação disciplinar para a penalidade cabível prescreverá em dois anos.","b":"ambas servidoras estão sujeitas a determinada penalidade administrativa, sendo que a ação disciplinar para a penalidade cabível prescreverá em 180 dias.","c":"nenhuma das servidoras está sujeita a qualquer penalidade, sendo apenas avisadas para que tais condutas não se repitam mais.","d":"apenas Josefa está sujeita a determinada penalidade administrativa, sendo que a ação disciplinar para a penalidade cabível prescreverá em dois anos.","e":"ambas servidoras estão sujeitas a determinada penalidade administrativa, sendo que a ação disciplinar para a penalidade cabível prescreverá em dois anos.","gabarito":"","materia":"Geral","tema":"","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática ...","concurso":"TRF3"},{"id":"Q629457","enunciado":"","a":"respeito dos Crimes contra a Administração pública, o crime de resistência não se configura se a oposição do agente, mediante violência ou grave ameaça, não obstar a A","b":"execução do ato legal do funcionário público. o não atendimento a ordem ilegal de funcionário público caracteriza o crime de desobediência.","c":"no crime de denunciação caluniosa, o uso do anonimato agrava a pena a ser aplicada.","d":"quem esconde em sua residência autor de crime de roubo para evitar a sua prisão em flagrante comete o crime de favorecimento real.","e":"o empréstimo de sacola para permitir o transporte e ocultação de objetos furtados por outrem configura o crime de favorecimento pessoal.","gabarito":"C","materia":"Direito Penal","tema":"Crimes contra a administração pública ,Resistência ,DesobediênciaFavorecimento real","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática ...","concurso":"TRF3"},{"id":"Q629456","enunciado":"","a":"respeito dos crimes de corrupção ativa e passiva, considere: I. O delito de corrupção ativa não se caracteriza quando, apesar da solicitação de vantagem indevida, o resultado pretendido pelo agente não ocorreu. II. O crime de corrupção passiva só se configura com a ocorrência simultânea do crime de corrupção ativa. III. É indispensável para a caracterização do delito de corrupção ativa que a solicitação de recebimento de vantagem indevida tenha relação com a função pública exercida pelo agente. Está correto o que consta APENAS em","b":"A I e III. I e II.","c":"II e III.","d":"III.","e":"II.","gabarito":"D","materia":"Direito Penal","tema":"Crimes contra a administração pública ,Corrupção ativa","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática ...","concurso":"TRF3"},{"id":"Q629455","enunciado":"","a":"É punível na forma culposa o delito de abandono de função.","b":"peculato.","c":"violação de sigilo funcional.","d":"prevaricação.","e":"concussão.","gabarito":"B","materia":"Direito Penal","tema":"Crimes contra a administração pública ,Peculato ,PrevaricaçãoViolação de sigilo funcional","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática ...","concurso":"TRF3"},{"id":"Q629454","enunciado":"","a":"NÃO pode ser objeto de furto: bem imóvel.","b":"energia elétrica.","c":"aeronave.","d":"cavalo de raça.","e":"caixa de refrigerantes.","gabarito":"A","materia":"Direito Penal","tema":"Crimes contra o patrimônio ,Furto","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática ...","concurso":"TRF3"},{"id":"Q629453","enunciado":"","a":"respeito do crime de furto, considere: I. Peter cavou um túnel e, com grande esforço, conseguiu entrar no interior de uma loja, dali subtraindo produtos eletrônicos. II. Paulus, com o auxílio de uma corda, entrou pela janela em uma residência, de onde subtraiu objetos. III. Plinius escalou uma árvore, galgou o telhado de um supermercado e removeu várias telhas, entrando no local, de onde subtraiu diversos objetos. Ficou caracterizada a qualificadora da escalada","b":"A nos furtos cometidos por Peter e Paulus, apenas. nos furtos cometidos por Peter, Paulus e Plinius.","c":"nos furtos cometidos por Peter e Plinius, apenas.","d":"nos furtos cometidos por Paulus e Plinius, apenas.","e":"no furto cometido por Plinius, apenas.","gabarito":"B","materia":"Direito Penal","tema":"Crimes contra o patrimônio ,Furto","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática ...","concurso":"TRF3"},{"id":"Q629452","enunciado":"","a":"diferença entre o menor número natural ímpar com cinco divisores positivos distintos e o menor número natural par, também com cinco divisores positivos distintos, é igual a","b":"A 39. 27.","c":"83.","d":"65.","e":"41.","gabarito":"D","materia":"Matemática","tema":"Aritmética e Problemas ,Números Primos e Divisibilidade","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática ...","concurso":"TRF3"},{"id":"Q629451","enunciado":"Uma empresa pavimentadora de ruas utiliza uma máquina que retira o asfalto antigo na razão de 3 metros lineares de rua a cada 8 minutos. O tempo que essa máquina gastará para retirar o asfalto de 3,75 km lineares de rua, de forma","a":"ininterrupta, equivale a 6 dias, 22 horas e 40 minutos.","b":"6 dias, 6 horas e 16 minutos.","c":"6 dias, 16 horas e 16 minutos.","d":"6 dias, 1 hora e 20 minutos.","e":"6 dias, 8 horas e 30 minutos.","gabarito":"A","materia":"Matemática","tema":"Aritmética e Problemas ,Regra de Três","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática ...","concurso":"TRF3"},{"id":"Q629450","enunciado":"Uma empresa investiu 3,42 bilhões de reais na construção de uma rodovia. Perto do final da construção a empresa solicitou uma verba adicional de 7% do valor investido para terminar a obra. Sabe-se que três oitavos desse valor adicional estavam","a":"destinados ao pagamento de fornecedores e equivalem, em reais, a 89.775,00.","b":"897.750.000,00.","c":"8.977.500,00.","d":"897.750,00.","e":"89.775.000,00.","gabarito":"E","materia":"Matemática","tema":"Aritmética e Problemas ,Porcentagem","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática ...","concurso":"TRF3"},{"id":"Q629449","enunciado":"","a":"O valor da expressão numérica 0,00003 . 200 . 0,0014 ÷ (0,05 . 12000 . 0,8) é igual a","b":"","c":"","d":"","e":"","gabarito":"B","materia":"Matemática","tema":"Aritmética e Problemas ,Frações e Números Decimais","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática ...","concurso":"TRF3"},{"id":"Q629448","enunciado":"Cristiano e Rodolfo resolveram fazer investimentos ao mesmo tempo. Cristiano investiu um determinado valor em reais e Rodolfo investiu 40% a mais do que Cristiano havia investido. Após algum tempo verificou-se que o investimento de Cristiano havia valorizado 75% e que o investimento de Rodolfo havia valorizado 60%. Desta forma, e neste momento, o","a":"montante total desse investimento de Rodolfo é maior que o montante total desse investimento de Cristiano em 45%.","b":"35%.","c":"21%.","d":"28%.","e":"14%.","gabarito":"D","materia":"Matemática","tema":"Aritmética e Problemas ,Porcentagem","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática ...","concurso":"TRF3"},{"id":"Q629447","enunciado":"","a":"tabela a seguir indica o(s) dia(s) de plantão de cada um dos cinco funcionários de um departamento. Por problemas na impressão da tabela, apenas o preenchimento de plantões da última linha e da última lacuna não saíram visíveis. A respeito dos plantões dos cinco funcionários nessa semana, sabe-se que: I. apenas dois funcionários fizeram plantão na 4ª feira. II. Ricardo e Camilo fizeram o mesmo número de plantões na semana. III. 3ª feira foi o dia da semana com mais funcionários de plantão. IV. todos os funcionários fizeram, ao menos, um plantão na semana, e todos os dias da semana contaram com, ao menos, um funcionário de plantão. V. três funcionários fizeram apenas um plantão na semana. De acordo com os dados, Camilo NÃO fez plantão apenas","b":"A 2ª feira e 6ª feira. 3ª feira e 6ª feira.","c":"3ª feira e 4ª feira.","d":"3ª feira, 5ª feira e 6ª feira.","e":"2ª feira, 3ª feira e 6ª feira.","gabarito":"A","materia":"Raciocínio Lógico","tema":"Fundamentos de Lógica ,Proposições Simples e Compostas e Operadores Lógicos","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática ...","concurso":"TRF3"},{"id":"Q629446","enunciado":"Helena acha que seu relógio está 3 minutos atrasado, quando na verdade ele está 12 minutos adiantado. Ontem Helena","a":"compareceu ao trabalho julgando que estava 8 minutos atrasada, porém, na realidade ela estava 3 minutos atrasada.","b":"7 minutos adiantada.","c":"5 minutos atrasada.","d":"5 minutos adiantada.","e":"3 minutos adiantada.","gabarito":"B","materia":"Raciocínio Lógico","tema":"Raciocínio Matemático","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática ...","concurso":"TRF3"},{"id":"Q629445","enunciado":"Amanda, Brenda e Carmen são médica, engenheira e biblioteconomista, não necessariamente nessa ordem. Comparando a altura das três, a biblioteconomista, que é a melhor amiga de Brenda, é a mais baixa. Sabendo-se também que a engenheira","a":"é mais baixa do que Carmen, é necessariamente correto afirmar que Brenda é médica.","b":"Carmen é mais baixa que a médica.","c":"Amanda é biblioteconomista.","d":"Carmen é engenheira.","e":"Brenda é biblioteconomista.","gabarito":"C","materia":"Raciocínio Lógico","tema":"Proposições Categóricas","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática ...","concurso":"TRF3"},{"id":"Q629444","enunciado":"Em uma sala estão presentes apenas técnicos em edificações e técnicos em informática. O número de técnicos em edificações presentes na sala excede o de técnicos em informática em 4, e cada técnico exerce apenas uma especialidade (edificações ou informática). Sabe-se que seria necessário sortear ao acaso 20 pessoas da sala, no máximo, para garantir a formação de 4 duplas de técnicos, cada uma com um técnico de cada especialidade. Sendo assim, o número de técnicos em","a":"edificações que estão presentes na sala é igual a 26.","b":"18.","c":"24.","d":"16.","e":"28.","gabarito":"D","materia":"Raciocínio Lógico","tema":"Raciocínio Matemático","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática ...","concurso":"TRF3"},{"id":"Q629443","enunciado":"","a":"Se “todo engenheiro é bom em matemática” e “algum engenheiro é físico”, conclui-se corretamente que todo físico é bom em matemática.","b":"certos bons em matemática não são físicos.","c":"existem bons em matemática que são físicos.","d":"certos físicos não são bons em matemática.","e":"não há engenheiros que sejam físicos.","gabarito":"C","materia":"Raciocínio Lógico","tema":"Lógica de Argumentação - Diagramas e Operadores Lógicos","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática ...","concurso":"TRF3"},{"id":"Q629442","enunciado":"Para responder a questão considere o texto abaixo. Bem no fundo no fundo, no fundo, bem lá no fundo, a gente gostaria de ver nossos problemas resolvidos por decreto a partir desta data, aquela mágoa sem remédio é considerada nula e sobre ela − silêncio perpétuo extinto por lei todo o remorso, maldito seja quem olhar pra trás, lá pra trás não há nada, e nada mais mas problemas não se resolvem, problemas têm família grande, e aos domingos saem todos passear o problema, sua senhora e outros pequenos probleminhas. (LEMINSKI, Paulo. Poesia contemporânea. Instituto Cultural Itaú. São Paulo: ICI, 1997, p. 61. [Cadernos Poesia Brasileira; v. 4])","a":"Preservando a relação de sentido, o segundo verso da última estrofe pode ser introduzido por: todavia","b":"contudo","c":"que","d":"conquanto","e":"não obstante","gabarito":"C","materia":"Português","tema":"Sintaxe ,Uso dos conectivos","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática ...","concurso":"TRF3"},{"id":"Q629441","enunciado":"","a":"Para o poeta, problemas coletivos só vão se resolver com a cooperação dos indivíduos.","b":"problemas familiares tornam-se insolúveis se destituídos da mediação das leis.","c":"problemas pessoais se agravam quando sua resolução não é imediata.","d":"problemas estruturais não se resolvem por meio de regulamentações.","e":"problemas sociais não podem ser resolvidos senão com a intervenção do governo.","gabarito":"D","materia":"Português","tema":"Interpretação de Textos ,Noções Gerais de Compreensão e Interpretação de Texto","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática ...","concurso":"TRF3"},{"id":"Q629440","enunciado":"Está correta a redação da seguinte frase.","a":"No futuro, quando todos os que hoje circulam por São Paulo, já não estiverem mais aqui a paineira continuará a presenciar, as transformações em que o progresso sujeita a cidade.","b":"Há pessoas que se reúnem em parques com o simples propósito de abraçar árvores, alegando de que essa é uma prática terapeutica, que combate o estress e a depressão.","c":"Os trabalhadores de São Paulo frequentemente, passam pela paineira da Biblioteca Mario de Andrade e não reparam de que se trata de uma árvore centenária, que está ali antes deles.","d":"Ao se deparar com seu editor, Antonio teve a ideia de convencer-lhe de que a árvore estava sendo estudada por que faria parte de seu livro e, para tanto era necessário medir o seu perímetro.","e":"Por abrigar esculturas de insignes artistas brasileiros, o Cemitério da Consolação tornou-se um importante ponto turístico da cidade de São Paulo, do qual os paulistanos se orgulham.","gabarito":"E","materia":"Português","tema":"Sintaxe ,Regência","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática ...","concurso":"TRF3"},{"id":"Q629439","enunciado":"","a":"O sinal indicativo de crase está empregado corretamente em: Não era uma felicidade eufórica, semelhava-se mais à uma brisa de contentamento.","b":"O vinho certamente me induziu àquela súbita vontade de abraçar uma árvore gigante.","c":"Antes do fim da manhã, dediquei-me à escrever tudo o que me propusera para o dia.","d":"A paineira sobreviverá a todas às 18 milhões de pessoas que hoje vivem em São Paulo.","e":"Acho importante esclarecer que não sou afeito à essa tradição de se abraçar árvore.","gabarito":"B","materia":"Português","tema":"Crase","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática ...","concurso":"TRF3"},{"id":"Q629438","enunciado":"Para responder a questão considere o texto abaixo. Abraçando árvore Não era uma felicidade eufórica, estava mais pra uma brisa de contentamento, como se eu bebesse vinho branco à beira-mar. Eu tinha acordado cedo naquela sexta − e acordar cedo sempre me predispõe à felicidade. O trabalho havia rendido bem e, antes do fim da manhã, já tinha acabado de escrever tudo o que me propusera para o dia. À uma, fui almoçar com o meu editor. Ele estava com alguns capítulos do meu livro novo desde dezembro e eu temia que não tivesse gostado. Gostou. Comemos um peixe na brasa − peixe e brasa também costumam me predispor à felicidade − e como era sexta-feira, e como somos amigos, e como comemorávamos essa pequena alegria que é uma parceria funcionar, brindamos com vinho branco − não à beira-mar, mas à beira do Cemitério da Consolação, que pode não ter a grandeza de um Atlântico, mas também tem lá os seus pacíficos encantos. Saí andando meio emocionado, meio sem rumo pela tarde ensolarada e quando vi estava em frente à paineira da Biblioteca Mario de Andrade. É uma árvore gigante, que provavelmente já estava ali antes do Mario de Andrade nascer, continuou ali depois de ele morrer e continuará ali depois que todos os 18 milhões de habitantes que hoje perambulam pela cidade de São Paulo estiverem abaixo de suas raízes. Talvez tenha sido o assombro com essa longevidade, talvez acordar cedo, talvez os elogios ao livro, e o vinho certamente colaborou: fato é que senti uma súbita vontade de abraçar aquela árvore. Acho importante deixar claro, inclemente leitor, que não sou do tipo que abraça árvore. Na verdade, sou do tipo que faz piada com quem abraça árvore. Se me contassem, até a última sexta, que algum amigo meu foi visto abraçando uma paineira na rua da Consolação eu diria, sem pestanejar: enlouqueceu. Mas... Olhei prum lado. Olhei pro outro. Tomei coragem e foi só sentir o rosto tocar o tronco para ouvir: “Antonio?!”. Era meu editor. Foram dois segundos de desespero durante os quais contemplei o distrato do livro, a infâmia pública, o alcoolismo e a mendicância, mas só dois segundos, pois meu inconsciente, consciente do perigo, me lançou a ideia salvadora. “Uma braçada”, disse eu, girando pra esquerda e envolvendo a árvore novamente, “duas braçadas e... três”. Então encarei, seguro, meu possível verdugo: “Três braçadas dá o quê? Uns cinco metros de perímetro? Tava medindo pra descrever, no livro. Tem uma parte mais no fim em que essa paineira é importante”. Colou. Nos despedimos. Ele foi embora prum lado, a minha felicidade pro outro e agora estou aqui, já noite alta desta sexta-feira, tentando enfiar a todo custo um tronco de quase dois metros de diâmetro num livro em que, até então, não havia nem uma samambaia. (Adaptado de: PRATA, Antonio. Disponível em: www.folha.uol.com.br/colunas/antonioprata/2016/01/1730364-abracando- arvore.shtml. Acesso em: 18.01.2016.) Foram dois segundos de desespero durante os quais contemplei o distrato do livro, a infâmia pública, o alcoolismo e a mendicância...","a":"Transpondo-se para a voz passiva o verbo sublinhado, a forma resultante será: contemplavam-se.","b":"foram contemplados.","c":"contemplam-se.","d":"eram contemplados.","e":"tinham sido contemplados.","gabarito":"B","materia":"Português","tema":"Morfologia - Verbos ,Flexão de voz (ativa, passiva, reflexiva)","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática ...","concurso":"TRF3"},{"id":"Q629437","enunciado":"","a":"Um fragmento do texto está adequadamente traduzido em: ... acordar cedo sempre me predispõe à felicidade. / ... madrugar sempre me protela a alegria. (2º parágrafo)","b":"Talvez tenha sido o assombro com essa longevidade... / Provavelmente tenha sido o susto com essa magnanimidade...","c":"(3º parágrafo) Então encarei, seguro, meu possível verdugo... / Então enfrentei, firme, meu possível carrasco... (5º parágrafo)","d":"... eu temia que não tivesse gostado. / ... eu presumia que não tivesse vislumbrado. (2° parágrafo)","e":"Acho importante deixar claro, inclemente leitor... / Considero relevante elucidar, transigente leitor... (4º parágrafo)","gabarito":"C","materia":"Português","tema":"Interpretação de Textos ,Redação - Reescritura de texto","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática ...","concurso":"TRF3"},{"id":"Q629436","enunciado":"Considere as frases abaixo. I. O início do terceiro parágrafo expõe uma consequência para o que se conta no segundo. II. O quarto parágrafo apresenta uma ressalva para o que se relata no quinto. III. O sexto parágrafo enuncia uma consequência do que se revela no quinto.","a":"Está correto o que se afirma em I, II e III.","b":"I e II, apenas.","c":"II e III, apenas.","d":"I, apenas.","e":"III, apenas.","gabarito":"A","materia":"Português","tema":"Interpretação de Textos ,Noções Gerais de Compreensão e Interpretação de Texto","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática ...","concurso":"TRF3"},{"id":"Q629435","enunciado":"Para o autor, o ato de abraçar a paineira representou","a":"a possibilidade de acelerar a conclusão de seu novo livro, já que a árvore era o elemento que faltava para enriquecer sua história.","b":"o transbordamento de um estado de exaltação em face da beleza natural que contrastava com o aspecto deprimente da cidade de São Paulo.","c":"a expressão de um sentimento aprazível, que dá lugar à frustração e ao constrangimento após ser flagrado por seu editor.","d":"o desfecho infeliz de uma manhã de projetos bem-sucedidos, em razão do qual seu trabalho se viu malogrado de modo irreversível.","e":"a demonstração de seu amor pela cidade de São Paulo, a qual, por ser cosmopolita, serve de ambientação a seu novo livro.","gabarito":"C","materia":"Português","tema":"Interpretação de Textos ,Noções Gerais de Compreensão e Interpretação de Texto","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática ...","concurso":"TRF3"},{"id":"Q629434","enunciado":"","a":"frase cuja redação está inteiramente correta é: Obtido pela identificação por radiofrequência, os dados das placas de veículos são passíveis em oferecer informações A valiosas acerca dos motoristas.","b":"Na cidade inteligente, a automatização da gestão de setores urbanos são facilitadores de serviços imprecindíveis, como saúde, educação e segurança.","c":"Londres e Barcelona estão entre as cidades que mais destaca-se em termos de inteligência, com avançados centros de operação de dados.","d":"São necessários viabilizar projetos de cidades inteligentes, amparados em políticas públicas que salvaguardam os dados abertos dos cidadãos.","e":"O aprimoramento de técnicas de informatização de dados permitiu que surgisse um novo conceito de cidade, concebido como espaço de fluxos.","gabarito":"E","materia":"Português","tema":"Sintaxe ,Concordância verbal, Concordância nominal","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática ...","concurso":"TRF3"},{"id":"Q629433","enunciado":"Para responder a questão considere o texto abaixo. Cidades inteligentes, até demais O conceito de “cidade inteligente” se popularizou como estratégia de solução e gerenciamento de problemas urbanos. Diz respeito à confluência de informação que circula em grandes cidades e ao uso da tecnologia para automatizar a gestão de setores urbanos, desde bases de dados de saúde e educação públicas, por exemplo, até os dados pessoais que circulam em redes sociais e aplicativos móveis. O advogado Cristiano Therrien, pesquisador em Direito da Tecnologia na Universidade de Montreal, no Canadá, conversou com o Observatório da Privacidade e Vigilância sobre o tema. Observatório da Privacidade e Vigilância: O que é uma cidade inteligente? Cristiano Therrien: Cidades inteligentes, cidades conectadas, cibercidades, cidades responsivas, são muitas as nomenclaturas usadas para destacar a dimensão informativa da cidade. Quando usamos essa terminologia, falamos da cidade enquanto um espaço de fluxos. A maioria das tecnologias necessárias para as cidades inteligentes já são viáveis economicamente em todo o mundo − fácil acessibilidade da computação em nuvem, dispositivos baratos de internet, sistemas de TI cada vez mais flexíveis. As duas cidades mais destacadas nos estudos de cidades inteligentes são Londres e Barcelona. Há experiências importantes em cidades brasileiras também. OPV: A ideia de cidade inteligente sempre aparece relacionada à abertura de bases de dados por parte dos órgãos públicos. Você pode falar sobre isso? CT: Encontramos muitas experiências diferentes em andamento nas cidades: uma parte prioriza a transparência como meio de prestação de contas e responsabilidade política frente à sociedade civil, como a ideia de governo aberto; outra parte prioriza a participação popular através da interatividade, bem como a cooperação técnica para o reuso de dados abertos por entidades e empresas. Mas, se pensarmos na alternativa de projetos de cidades inteligentes que não envolvam políticas públicas de dados abertos, que não prestem conta detalhada de suas atividades, ao mesmo tempo em que disponham dos sofisticados sistemas para o gerenciamento de dados de cidadãos em larga escala, encontraremos condições para o surgimento de um estado de vigilância e controle, pondo em risco as liberdades individuais. Em nome da eficiência administrativa, podem-se armazenar, por exemplo, enormes massas de dados de mobilidade urbana (placas e identificação por radiofrequência em veículos, passes e GPS em ônibus), cujos bancos de dados podem ou não intencionalmente identificar seus usuários. Dados de mobilidade são de grande utilidade pública e podem ser “anonimizados” (ter os seus identificadores pessoais eliminados) e abertos. Contudo, existem estudos que apontam que bastariam meros quatro pontos de dados para identificar os movimentos de uma pessoa na cidade. (Adaptado de: “Observatório da Privacidade e Vigilância”. Disponível em: www.cartacapital.com.br/sociedade/cidades-","a":"inteligentes-atedemais. Acesso em: 18.01.2016.) alternativa em que a expressão sublinhada pode ser substituída pelo que se apresenta entre colchetes, respeitando-se a concordância, e sem quaisquer outras alterações no enunciado, é: A maioria das tecnologias necessárias para as cidades inteligentes já são viáveis economicamente em todo o mundo... A [viável]","b":"A ideia de cidade inteligente sempre aparece relacionada à abertura de bases de dados por parte dos órgãos públicos. [relacionado]","c":"Em nome da eficiência administrativa, podem-se armazenar, por exemplo, enormes massas de dados de mobilidade","d":"urbana... [são possíveis] ..desde bases de dados de saúde e educação públicas, por exemplo, até os dados pessoais... [pública]","e":"Contudo, existem estudos que apontam que bastariam meros quatro pontos de dados... [bastaria]","gabarito":"D","materia":"Português","tema":"Sintaxe ,Concordância verbal, Concordância nominal","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática ...","concurso":"TRF3"},{"id":"Q629432","enunciado":"Mas, se pensarmos na alternativa de projetos de cidades inteligentes que não envolvam políticas públicas de dados abertos, que não prestem conta detalhada de suas atividades, ao mesmo tempo em que disponham dos sofisticados sistemas para o gerenciamento de dados de cidadãos em larga escala, encontraremos condições para o surgimento de um estado de vigilância e controle... Preservando-se a correlação entre as formas verbais, os elementos destacados podem ser substituídos, respectivamente,","a":"por: pensaremos − envolviam − prestavam − disponham − encontremos","b":"pensamos − envolvem − prestam − dispunham − encontrávamos","c":"pensemos − envolveriam − prestariam − disporiam − encontrássemos","d":"pensássemos − envolvessem − prestassem − dispusessem − encontraríamos","e":"pensávamos − envolveram − prestaram − disporam − encontramos","gabarito":"D","materia":"Português","tema":"Morfologia - Verbos ,Flexão verbal de tempo (presente, pretérito, futuro)","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática ...","concurso":"TRF3"},{"id":"Q629431","enunciado":"","a":"O acréscimo de uma vírgula após o termo sublinhado não altera o sentido nem a correção do trecho: ideia de cidade inteligente sempre aparece relacionada à abertura de bases de dados por parte dos órgãos públicos. (4º A","b":"parágrafo) Há experiências importantes em cidades brasileiras também.(3º parágrafo)","c":"... uma parte prioriza a transparência como meio de prestação de contas e responsabilidade política frente à sociedade civil, como a ideia de governo aberto... (5º parágrafo)","d":"...outra parte prioriza a participação popular através da interatividade, bem como a cooperação técnica para o reuso de dados abertos por entidades e empresas. (5º parágrafo)","e":"Contudo, existem estudos que apontam que bastariam meros quatro pontos de dados para identificar os movimentos de uma pessoa na cidade. (7ºparágrafo)","gabarito":"B","materia":"Português","tema":"Pontuação ,Uso da Vírgula","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática ...","concurso":"TRF3"},{"id":"Q629430","enunciado":"No contexto da frase, o segmento sublinhado tem seu sentido expresso entre colchetes em:","a":"Diz respeito à confluência de informação que circula em grandes cidades e ao uso da tecnologia para automatizar a gestão","b":"de setores urbanos... [finalidade] Quando usamos essa terminologia, falamos da cidade enquanto um espaço de fluxos. [proporção]","c":"... fácil acessibilidade da computação em nuvem, dispositivos baratos de internet, sistemas de TI cada vez mais flexíveis.","d":"[partição] ... outra parte prioriza a participação popular através da interatividade, bem como a cooperação técnica... [afirmação]","e":"... podem-se armazenar, por exemplo, enormes massas de dados de mobilidade urbana [...], cujos bancos de dados podem ou não intencionalmente identificar seus usuários. [condição]","gabarito":"A","materia":"Português","tema":"Sintaxe ,Uso dos conectivos","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática ...","concurso":"TRF3"},{"id":"Q629429","enunciado":"Segundo Cristiano Therrien, o uso da tecnologia para controlar o fluxo de informação em setores urbanos pode","a":"fragilizar o arquivamento da documentação dos indivíduos, pois grandes massas de dados podem ser facilmente eliminadas.","b":"favorecer o transporte público, na medida em que o deslocamento dos cidadãos fique circunscrito a quatro pontos de dados.","c":"criar condições que favoreçam a participação popular no governo, contanto que exista um estado de vigilância e controle dos cidadãos.","d":"resultar no tratamento dos cidadãos de modo pouco humanizado, devido à maneira anônima como seus dados são partilhados.","e":"incorrer no cerceamento da autonomia dos cidadãos, caso não haja políticas públicas que regulem o gerenciamento de dados.","gabarito":"E","materia":"Português","tema":"Interpretação de Textos ,Noções Gerais de Compreensão e Interpretação de Texto","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática ...","concurso":"TRF3"},{"id":"Q629428","enunciado":"Para responder a questão considere o texto abaixo. Cidades inteligentes, até demais O conceito de “cidade inteligente” se popularizou como estratégia de solução e gerenciamento de problemas urbanos. Diz respeito à confluência de informação que circula em grandes cidades e ao uso da tecnologia para automatizar a gestão de setores urbanos, desde bases de dados de saúde e educação públicas, por exemplo, até os dados pessoais que circulam em redes sociais e aplicativos móveis. O advogado Cristiano Therrien, pesquisador em Direito da Tecnologia na Universidade de Montreal, no Canadá, conversou com o Observatório da Privacidade e Vigilância sobre o tema. Observatório da Privacidade e Vigilância: O que é uma cidade inteligente? Cristiano Therrien: Cidades inteligentes, cidades conectadas, cibercidades, cidades responsivas, são muitas as nomenclaturas usadas para destacar a dimensão informativa da cidade. Quando usamos essa terminologia, falamos da cidade enquanto um espaço de fluxos. A maioria das tecnologias necessárias para as cidades inteligentes já são viáveis economicamente em todo o mundo − fácil acessibilidade da computação em nuvem, dispositivos baratos de internet, sistemas de TI cada vez mais flexíveis. As duas cidades mais destacadas nos estudos de cidades inteligentes são Londres e Barcelona. Há experiências importantes em cidades brasileiras também. OPV: A ideia de cidade inteligente sempre aparece relacionada à abertura de bases de dados por parte dos órgãos públicos. Você pode falar sobre isso? CT: Encontramos muitas experiências diferentes em andamento nas cidades: uma parte prioriza a transparência como meio de prestação de contas e responsabilidade política frente à sociedade civil, como a ideia de governo aberto; outra parte prioriza a participação popular através da interatividade, bem como a cooperação técnica para o reuso de dados abertos por entidades e empresas. Mas, se pensarmos na alternativa de projetos de cidades inteligentes que não envolvam políticas públicas de dados abertos, que não prestem conta detalhada de suas atividades, ao mesmo tempo em que disponham dos sofisticados sistemas para o gerenciamento de dados de cidadãos em larga escala, encontraremos condições para o surgimento de um estado de vigilância e controle, pondo em risco as liberdades individuais. Em nome da eficiência administrativa, podem-se armazenar, por exemplo, enormes massas de dados de mobilidade urbana (placas e identificação por radiofrequência em veículos, passes e GPS em ônibus), cujos bancos de dados podem ou não intencionalmente identificar seus usuários. Dados de mobilidade são de grande utilidade pública e podem ser “anonimizados” (ter os seus identificadores pessoais eliminados) e abertos. Contudo, existem estudos que apontam que bastariam meros quatro pontos de dados para identificar os movimentos de uma pessoa na cidade. (Adaptado de: “Observatório da Privacidade e Vigilância”. Disponível em: www.cartacapital.com.br/sociedade/cidades- inteligentes-atedemais. Acesso em: 18.01.2016.)","a":"O conceito de “cidade inteligente” envolve, entre outros, a ideia de governança transparente, que equivale ao tratamento consensual dado a questões de ordem pública.","b":"a solução de problemas públicos, por meio da contratação de consórcios privados ofertados em ambiente virtual.","c":"o registro e a circulação de dados informatizados, visando ao atendimento de demandas da administração pública.","d":"o rastreamento de indivíduos, promovido por empresas especializadas em prevenir a violência em meios digitalizados.","e":"a eficiência administrativa, obtida pela criação de aplicativos móveis que priorizem a troca de dados pessoais. Matemática Financeira>Conceitos fundamentais de Matemática Financeira ,","gabarito":"C","materia":"Português","tema":"Interpretação de Textos ,Noções Gerais de Compreensão e Interpretação de Texto","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Técnico Judiciário - Informática ...","concurso":"TRF3"},{"id":"TRF3_1677","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria Um título de valor nominal igual a R$ 18.522,00 vencerá daqui a 3 trimestres. Sabe-se que ele será resgatado antes do vencimento, segundo o critério do desconto racional composto, a uma taxa de juros de 5% ao trimestre. Supondo-se que a primeira opção será resgatar o título 2 trimestres antes do vencimento e a segunda opção será resgatar o título 1 trimestre antes do vencimento, o valor de resgate do título referente à segunda opção supera o valor de resgate do título referente à primeira opção, em R$, em 2 3","a":"Dados: 1,05 = 1,102500 e 1,05 = 1,157625 926,10.","b":"882,00.","c":"900,00.","d":"800,00.","e":"840,00.","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629426","enunciado":"","a":"tabela abaixo fornece os valores recebidos por uma empresa, na data de hoje, correspondentes aos descontos de 3 títulos em um banco. A taxa de desconto utilizada pelo banco é de 18% ao ano para qualquer operação. Se a soma dos valores nominais dos 3 títulos é igual a R$ 50.000,00, então X é, em R$, igual a","b":"A 9.960,65. 10.056,15.","c":"9.769,65.","d":"10.247,15.","e":"9.865,15.","gabarito":"A","materia":"Matemática Financeira","tema":"Conceitos fundamentais de Matemática Financeira ,Desconto Racional Simples","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629425","enunciado":"Uma instituição financeira divulga que a taxa de juros nominal para seus tomadores de empréstimos é de 24% ao ano com","a":"capitalização mensal. Isto significa que a taxa efetiva bimestral correspondente é de","b":"","c":"","d":"","e":"Matemática Financeira>Conceitos fundamentais de Matemática Financeira ,","gabarito":"D","materia":"Matemática Financeira","tema":"Conceitos fundamentais de Matemática Financeira ,Taxa efetiva e Taxa Nominal","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1680","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria Em um país, a taxa de inflação em um determinado período foi de 10,5%. Um investidor, neste país, realizou uma aplicação no valor de R$ 20.000,00 no início do determinado período e resgatou todo o montante no final. Sabendo-se que ele obteve","a":"uma taxa real de juros no período correspondente de 2%, tem-se que o valor do montante resgatado foi, em R$, de 22.521,00.","b":"22.500,00.","c":"21.700,00.","d":"22.542,00.","e":"22.066,00.","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629423","enunciado":"Dois capitais são aplicados sob o regime de capitalização composta a uma taxa de 10% ao ano. O primeiro capital foi aplicado durante 2 anos e o segundo durante 3 anos, apresentando um total de juros no valor de R$ 1.680,00 e R$ 1.986,00, respectivamente. A porcentagem que o segundo capital representa do primeiro é, em %, igual a 2 3","a":"Dados: 1,10 = 1,210 e 1,10 = 1,331 80.","b":"75.","c":"60.","d":"100.","e":"90.","gabarito":"B","materia":"Matemática Financeira","tema":"Conceitos fundamentais de Matemática Financeira ,Juros compostos ,Fluxo de Caixa","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629422","enunciado":"Em um contrato é estabelecido que uma pessoa deverá pagar o valor de R$ 5.000,00 daqui a 3 meses e o valor de R$ 10.665,50 daqui a 6 meses. Esta pessoa decide então aplicar em um banco, na data de hoje, um capital no valor de R$ 15.000,00, durante 3 meses, sob o regime de capitalização simples a uma taxa de 10% ao ano. No final de 3 meses, ela resgatará todo o montante correspondente, pagará o primeiro valor de R$ 5.000,00 e aplicará o restante sob o regime de capitalização simples, também durante 3 meses, em outro banco. Se o valor do montante desta última aplicação no final do período é exatamente igual ao segundo valor de R$ 10.665,50, então a taxa anual fornecida por este outro banco é, em %,","a":"de 10,8.","b":"9,6.","c":"11,2.","d":"12,0.","e":"11,7.","gabarito":"C","materia":"Matemática Financeira","tema":"Conceitos fundamentais de Matemática Financeira ,Juros simples","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629421","enunciado":"Nos termos da NBC TA 240, considere: I. Erro que resulta em distorção nas demonstrações contábeis. II. Distorção decorrente de informações fraudulentas. III. Distorção decorrente de apropriação indébita de ativos.","a":"É distorção intencional pertinente para o auditor o que consta em I e III, apenas.","b":"II, apenas.","c":"I, II e III.","d":"I e II, apenas.","e":"II e III, apenas.","gabarito":"E","materia":"Auditoria","tema":"Auditoria Independente (Externa) ,Fraude e Erro","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629420","enunciado":"Nos termos da NBC TA 230, considere: I. Identificação de quem revisou o trabalho de auditoria executado. II. Discussões de assuntos significativos com a administração. III. Informações referentes a um assunto significativo que são inconsistentes com sua conclusão final. IV. Não atendimento pelo auditor de um requisito relevante de uma norma. V. Circunstâncias identificadas após a data do relatório do auditor.","a":"Deve ser objeto de documentação pelo auditor o que consta em I, III e IV, apenas.","b":"II, III e V, apenas.","c":"I, II, III e IV, apenas.","d":"I, II, III, IV e V.","e":"II, IV e V, apenas.","gabarito":"D","materia":"Auditoria","tema":"Normas de Auditoria ,Normas de Auditoria - NBC TA's","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629419","enunciado":"Nos termos da NBC TA 200, na condução de auditoria de demonstrações contábeis, são exigidos integridade, objetividade, competência e zelo profissional, confidencialidade e comportamento profissional. Esses aspectos são expressamente","a":"denominados regras de conduta profissional.","b":"normas de auditoria relacionadas ao auditor.","c":"princípios fundamentais de ética profissional.","d":"princípios de conduta profissional do auditor.","e":"regras de conduta e comportamento do auditor. Auditoria>Documentos e Relatórios ,Relatório de auditoria (Parecer de auditoria) ,Normas de Auditoria","gabarito":"C","materia":"Auditoria","tema":"Normas de Auditoria ,Código de Ética e Normas de Auditoria","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629417","enunciado":"Um auditor independente verificou que o valor de uma demonstração contábil, antes da auditoria, era diferente daquele exigido de acordo com a estrutura de relatório financeiro aplicável. Nos termos da NBC TA 200, a possibilidade dessa","a":"diferença ser relevante é considerada um risco de auditoria.","b":"distorção relevante.","c":"asseguração razoável.","d":"derivado do julgamento profissional.","e":"derivado do ceticismo profissional.","gabarito":"B","materia":"Auditoria","tema":"Auditoria Independente (Externa) ,Risco de auditoria","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629416","enunciado":"Um auditor interno precisou determinar a extensão de um teste de auditoria para proporcionar evidência suficiente e apropriada. Nos termos regulados pela Resolução CFC nº 986/2003 (NBC TI 01), essa determinação pode ser alcançada por","a":"meio do uso da técnica de amostragem.","b":"normatização.","c":"dimensionamento.","d":"ajustamento.","e":"projeção.","gabarito":"A","materia":"Auditoria","tema":"Testes, Procedimentos e Técnicas de Auditoria ,Amostragem em Auditoria","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629415","enunciado":"Um auditor interno, em um primeiro momento, verificou a necessidade de fazer testes para verificação de registros, documentos e ativos tangíveis. Depois, também constatou a necessidade de acompanhar a execução de procedimentos específicos. Nos termos regulados pela Resolução CFC nº 986/2003 (NBC TI 01), para a consecução desses dois objetivos","a":"deverá realizar, respectivamente, testes de observância, na modalidade inspeção e testes substantivos, na modalidade inspeção.","b":"testes substantivos, na modalidade confirmação e testes de observância, na modalidade investigação.","c":"testes substantivos, na modalidade confirmação e testes de observância, na modalidade inspeção.","d":"testes de observância, na modalidade investigação e testes de observância, na modalidade inspeção.","e":"testes de observância, na modalidade inspeção e testes de observância, na modalidade observação.","gabarito":"E","materia":"Auditoria","tema":"Testes, Procedimentos e Técnicas de Auditoria ,Procedimentos e Técnicas de Auditoria","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629414","enunciado":"Acerca dos termos regulados pela Resolução CFC nº 986/2003 (NBC TI 01), considere: I. A análise deve ser executada no curso da auditoria. II. Estão relacionados à possibilidade de não se atingir, de forma satisfatória, o objetivo dos trabalhos. III. Deve ser levado em conta a extensão da responsabilidade do auditor interno no uso dos trabalhos de especialistas. IV. Deve ser considerada a verificação e a comunicação de eventuais limitações ao alcance dos procedimentos de auditoria interna.","a":"É regra atinente aos riscos de auditoria o que consta em I, II, III e IV.","b":"I, III e IV, apenas.","c":"II e III, apenas.","d":"II, III e IV, apenas.","e":"I, II e IV, apenas","gabarito":"D","materia":"Auditoria","tema":"Auditoria Interna Contábil ,Conceitos, abrangencia, estrutura e objeto","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629413","enunciado":"","a":"Resolução CFC nº 986/2003 (NBC TI 01), no que se refere aos papéis de trabalho, estabelece que são ferramentas destinadas apenas ao registro em meio físico, que devem ser organizadas e arquivadas de forma A sistemática e racional.","b":"são documentos e registros dos fatos, informações e provas obtidos no curso da auditoria para dar suporte à opinião","c":"do auditor. devem ter abrangência superficial, uma vez que se trata de ferramenta de suporte.","d":"não é ferramenta adequada para proporcionar a compreensão da extensão dos procedimentos de auditoria","e":"aplicados. a boa prática dos trabalhos não recomenda que sejam anexados a outros tipos de documentos. Direito Constitucional>Poder Legislativo ,Câmara dos Deputados ,Senado Federal","gabarito":"B","materia":"Auditoria","tema":"Documentos e Relatórios ,Documentação de Auditoria (Papéis de Trabalho)","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1691","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria Nos termos definidos pela Constituição Federal de 1988, o Poder Judiciário Federal, que inclui o TRF da 3ª Região, está submetido a uma fiscalização contábil, financeira e orçamentária. Se, nesse contexto, um determinado ato de despesa for","a":"impugnado pelo controle externo, sua execução poderá ser sustada pela Câmara dos Deputados, que comunicará a decisão ao Senado.","b":"pela Câmara dos Deputados, que comunicará a decisão ao Presidente da República.","c":"pelo Tribunal de Contas da União, que comunicará a decisão ao Presidente da República.","d":"pelo Tribunal de Contas da União, que comunicará a decisão à Câmara dos Deputados e ao Senado.","e":"pelo Senado, que comunicará a decisão ao Presidente da República. Administração Financeira e Orçamentária>LC nº 101 de 2000 - Lei de Responsabilidade Fiscal ,","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1692","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria","a":"Quanto ao Relatório de Gestão Fiscal, a Lei Complementar nº101/2000, estabelece que a versão simplificada desse relatório também é um instrumento de transparência da gestão fiscal.","b":"será publicado trinta dias após o encerramento de cada bimestre","c":"o referente ao último bimestre do exercício será acompanhado de demonstrativo de variação patrimonial.","d":"conterá demonstrativos relativos aos resultados nominal e primário.","e":"deve apresentar as justificativas da limitação de empenho, se for o caso. Administração Financeira e Orçamentária>LC nº 101 de 2000 - Lei de Responsabilidade Fiscal ,","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1693","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria Nos termos da Lei Complementar nº 101/2000, a chamada Lei de Responsabilidade Fiscal, os limites da despesa total com pessoal da União e do Poder Judiciário Federal, respectivamente e em percentual da receita corrente líquida em cada","a":"período de apuração, são, em %, 60 e 6.","b":"60 e 60.","c":"50 e 50.","d":"50 e 6.","e":"60 e 50.","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629405","enunciado":"Sobre as regras para a realização da despesa, considere: I. Imputação de dotação global. II. Imputação de dotação descentralizada por unidade administrativa. III. Atribuição de fornecimento ou prestação de serviços cujo custo excede os limites previamente fixados em lei. IV. Empenhamento contemporâneo à realização da despesa em razão de urgência caracterizada na legislação em vigor. Nos termos do Decreto nº 93.872/1986, constitui vedação para a realização da despesa se ocorrido o que consta APENAS","a":"em I e IV.","b":"III.","c":"II, III e IV.","d":"II e III.","e":"I e II.","gabarito":"B","materia":"Administração Financeira e Orçamentária","tema":"Legislação Complementar de AFO ,Decreto 93.872-86","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629404","enunciado":"Sobre as formas de ingresso de receita, considere: I. Originário ou derivado. II. Ordinário ou extraordinário. III. De natureza orçamentária ou extraorçamentária. IV. Geral ou vinculado. Nos termos do Decreto nº 93.872/1986, considera-se receita da União todo e qualquer ingresso que tenha sido decorrente,","a":"produzido ou realizado direta ou indiretamente pelos órgãos competentes, desde que na forma que consta em I, II e III, apenas.","b":"II, III e IV, apenas.","c":"I, II, III e IV.","d":"I e IV, apenas.","e":"II e III, apenas. Administração Financeira e Orçamentária>Legislação Complementar de AFO ,","gabarito":"C","materia":"Administração Financeira e Orçamentária","tema":"Legislação Complementar de AFO ,Decreto 93.872-86","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629403","enunciado":"","a":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria Lei nº 4.320/1964, estabelece que a dívida ativa é um A crédito da Fazenda Pública classificado como processado e não processado.","b":"crédito da Fazenda Pública e essa receita abrange créditos tributários e não tributários, cujo recebimento não está","c":"sujeito à atualização monetária. débito da Fazenda Pública que deve ser pago por meio de precatórios.","d":"débito da Fazenda Pública escriturado como despesa do exercício em que for paga.","e":"crédito da Fazenda Pública e sobre o recebimento dessa receita inclui multa e juros de mora incidentes sobre o encargo de que trata. Administração Financeira e Orçamentária>Despesa Pública ,Classificação da Despesa Orçamentária em AFO ,","gabarito":"E","materia":"Programação Orçamentária e Financeira","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629402","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria O orçamento anual do TRF da 3ª Região para 2016 previu despesas com material de consumo, equipamentos e instalações, serviços de terceiros, salário-família e material permanente. Nos termos dispostos na Lei n° 4.320/1964, essas despesas são","a":"classificadas, respectivamente, como despesas de custeio, investimentos, despesas de custeio, transferências correntes e investimentos.","b":"despesas de custeio, inversões financeiras, transferências correntes, transferências correntes e transferências de","c":"capital. transferências correntes, investimentos, despesas de custeio, despesas de custeio e investimentos.","d":"transferências correntes, transferências de capital, transferências correntes, despesas de custeio e inversões","e":"financeiras. despesas de custeio, investimentos, transferências correntes, despesas de custeio e despesas de custeio. Administração Financeira e Orçamentária>Legislação Complementar de AFO ,","gabarito":"A","materia":"Legislação Complementar de AFOProgramação Orçamentária e Financeira","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629401","enunciado":"","a":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria Lei nº 4.320/1964, que estabelece normas gerais de Direito Financeiro, quanto a aspectos pertinentes à despesa pública, prevê que transferências correntes são dotações para as despesas que correspondem a contraprestação direta de bens e A serviços.","b":"unidade orçamentária é o agrupamento de serviços subordinados ao mesmo órgão a que serão consignadas dotações","c":"próprias. é vedada consignação de dotações a unidades administrativas subordinadas ao mesmo órgão.","d":"na lei do orçamento a discriminação da despesa será feita, no mínimo, por unidade orçamentária.","e":"material permanente é o de duração superior a 12 meses. Administração Financeira e Orçamentária>Orçamento Público em AFO ,Instrumentos de Planejamento ,","gabarito":"B","materia":"Programação Orçamentária e Financeira","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1699","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria De acordo com a Constituição Federal de 1988, em relação às emendas ao projeto de lei do orçamento anual que indiquem recursos provenientes de anulação de despesa, considere: I. Dotação para pessoal e seus encargos. II. Transferências tributárias constitucionais para Estados, Municípios ou Distrito Federal. III. Dotação para construção de fóruns. IV. Dotação para aquisição de computadores pelo Poder Judiciário. Entre outros requisitos, as emendas somente podem ser aprovadas se a anulação da despesa incidir sobre o que consta","a":"APENAS em III e IV.","b":"I e II.","c":"I e III.","d":"II, III e IV.","e":"I, II e IV. Administração Financeira e Orçamentária>Orçamento Público em AFO ,","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629398","enunciado":"Um Analista Judiciário − Especialidade Contadoria verificou a peça orçamentária do Poder Judiciário Federal e constatou que","a":"foi incluída a concessão de isenção para determinadas taxas judiciais. Esse aspecto feriu o princípio orçamentário da especificação.","b":"programação.","c":"universalidade.","d":"exclusividade.","e":"clareza.","gabarito":"D","materia":"Administração Financeira e Orçamentária","tema":"Orçamento Público em AFO ,Princípios Orçamentários","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629397","enunciado":"O Contador de determinada entidade do setor público para elaboração do Balanço Financeiro do Exercício de 2015 obteve as seguintes informações contábeis: (em R$) − Saldo em Espécie do Exercício Anterior ........................................................................................... 25.500 − Pagamentos Extraorçamentários − Valores Restituíveis .................................................................. 5.000 − Receita Orçamentária − Vinculada ................................................................................................... 75.000 − Despesa Orçamentária Ordinária ..................................................................................................... 168.500 − Recebimentos Extraorçamentários − Inscrição em Restos a Pagar ................................................. 48.500 − Receita Orçamentária Ordinária ....................................................................................................... 185.000 − Despesa Orçamentária Vinculada .................................................................................................... 72.500 − Recebimentos Extraorçamentários − Valores Restituíveis ............................................................... 7.500 − Pagamentos Extraorçamentários − Restos a Pagar ......................................................................... 73.500 Considerando a estrutura do Balanço Financeiro, conforme Manual de Contabilidade Aplicada ao Setor Público","a":"(Demonstrações Contábeis), o “Saldo em Espécie para o Exercício Seguinte” soma, em R$, − 9.000.","b":"− 44.500.","c":"− 22.000.","d":"− 47.000.","e":"− 19.000.","gabarito":"C","materia":"Contabilidade Pública","tema":"Demonstrações Contábeis ,Balanço Financeiro - BF","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629396","enunciado":"No Balanço Patrimonial do exercício de 2015, da Autarquia Hospitalar Federal do Sudeste, o valor total do ativo é de R$ 880.760.000. Desse montante, 25% referem-se ao Ativo Circulante. Segundo o Plano de Contas Aplicado ao Setor Público,","a":"NÃO se classifica no Ativo Circulante, a conta identificada pelo código: 1.1.2.6.0.00.00 − Dívida Ativa não Tributária.","b":"1.1.3.1.1.01.00 − Adiantamentos Concedidos a Pessoal.","c":"1.2.1.1.1.01.00 − Créditos Tributários a Receber.","d":"1.1.1.1.0.00.00 − Caixa e Equivalentes de Caixa em Moeda Nacional.","e":"1.1.2.4.0.00.00 − Empréstimos e Financiamentos Concedidos. Contabilidade Pública>Ingressos e Dispêndios Públicos ,","gabarito":"C","materia":"Contabilidade Pública","tema":"Demonstrações Contábeis ,Balanço Patrimonial - BP","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1703","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria O Departamento de Contabilidade da Prefeitura do município Costa do Pacífico, durante o mês de janeiro de 2016, procedeu, entre outras, a contabilização dos seguintes valores: (em R$) − Operação de Crédito de Longo Prazo ..................................................................................................... 250− Obras de pavimentação de ruas e avenidas ............................................................................................ 200− Alienação de bens imóveis ...................................................................................................................... 470− Cancelamento de Dívida Passiva ............................................................................................................ 100− Recebimento, em doação, de bens imóveis ............................................................................................ 150− Contribuição de Melhoria decorrentes de obras públicas ........................................................................ 110− Amortização de Empréstimos concedidos ............................................................................................... 160− Concessões e permissões de uso de bens públicos ............................................................................... 170− Ganhos com alienação de imobilizado .................................................................................................... 90− Transferência financeira do Estado ao município para construção de duas creches .............................. 220 No que tange à classificação das receitas orçamentárias, segundo a Lei Federal nº 4.320/1964, as receitas de capital","a":"contabilizadas somam, em R$, 1.100.","b":"1.210.","c":"1.250.","d":"1.270.","e":"1.190. Contabilidade Pública>Ingressos e Dispêndios Públicos ,","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1704","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria No início de janeiro de 2016, o Departamento de Contabilidade de determinada unidade da justiça federal procedeu o registro contábil dos empenhos emitidos destinados às despesas: (em R$) − aquisição de pneus para os veículos da frota .......................................................................................... 850− tarifas de energia elétrica, gás, água e esgoto ........................................................................................ 170− aquisição de pen-drive ............................................................................................................................. 190− prestação de serviços de vigilância ostensiva ......................................................................................... 220− aquisição de produtos de higienização .................................................................................................... 430− vale-refeição ............................................................................................................................................ 150− aquisição de lâmpadas e luminárias para reposição ............................................................................... 110− serviços com adaptação de bens imóveis................................................................................................ 440− aquisição de passagens áreas ................................................................................................................. 80− auxílio transporte pago em forma de pecúnia .......................................................................................... 40 Segundo a Lei Federal nº 4.320/1964, as despesas empenhadas nos elementos de despesas − “30 − Material de Consumo” e","a":"“37 − Outros Serviços de Terceiros − Pessoa Jurídica” somam, em R$, respectivamente, 730 e 680.","b":"1.660 e 640.","c":"1.750 e 390.","d":"1.580 e 980.","e":"1.730 e 680. Contabilidade Pública>Procedimentos Contábeis Patrimoniais ,","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1705","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria O resultado patrimonial apurado na Demonstração das Variações Patrimoniais no exercício de 2015 de determinado Estado","a":"da região Sudeste do Brasil foi de R$ 998.750.000,00. São consideradas Variações Patrimoniais Qualitativas: Arrecadação de impostos concomitante ao fato gerador e depreciação de veículos.","b":"Amortização da dívida e Antecipação de receita orçamentária − ARO.","c":"Bens imóveis recebidos em doação e consumo de material.","d":"Remuneração de depósitos bancários e juros sobre a dívida por contrato.","e":"Descontos financeiros obtidos e locação de equipamentos e materiais permanentes.","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629391","enunciado":"Para responder à questão, considere as informações relativamente às receitas arrecadadas e despesas orçamentárias utilizadas na elaboração da Demonstração dos Fluxos de Caixa, referente ao exercício de 2015, por determinado ente público. (em R$) − receitas de impostos ....................................................................................................................... 950− aquisição de computadores ............................................................................................................ 120− recebimento em doação de bens imóveis ....................................................................................... 100− receitas de transferências correntes ............................................................................................... 370− despesas com amortização da dívida.............................................................................................. 670− alienação de bens imóveis .............................................................................................................. 650− despesas com aluguel ..................................................................................................................... 130− despesas com juros e encargos da dívida ...................................................................................... 330− receitas de concessões de serviços públicos ................................................................................. 390− cancelamento de restos a pagar de exercício anterior de despesas com energia elétrica .............. 50− operações de crédito de longo prazo .............................................................................................. 350− despesas com pessoal .................................................................................................................... 550− receitas de transferências de capital ............................................................................................... 200− aquisição de veículos ...................................................................................................................... 280− receitas de dívida ativa .................................................................................................................... 140− despesas com serviços de manutenção de bens imóveis .............................................................. 160− anulação total da dotação “Construções e Reformas de Escolas Públicas” .................................... 40 Nota: todas as despesas foram liquidadas e pagas no próprio exercício","a":"O fluxo de caixa líquido das atividades de investimentos soma, em R$, 350.","b":"370.","c":"90.","d":"250.","e":"290. Contabilidade Pública>Ingressos e Dispêndios Públicos ,","gabarito":"D","materia":"Contabilidade Pública","tema":"Demonstrações Contábeis ,Demonstração de Fluxo de Caixa - DFC","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629390","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria No exercício de 2015, determinado ente da federação pagou R$ 38.000,00 à autarquia hospitalar, entidade integrante do orçamento fiscal e da seguridade social do ente, referentes a serviços de exames laboratoriais nos candidatos aprovados em concurso público. O valor recebido e o pagamento efetuado pelos serviços realizados são classificados,","a":"respectivamente, como receita e despesa corrente orçamentária.","b":"variações patrimoniais aumentativas e permutativas.","c":"ativo e passivo compensado.","d":"receita e despesa corrente intraorçamentária.","e":"variações patrimoniais diminutivas e aumentativas.","gabarito":"D","materia":"Classificação da Receita Orçamentária na Contabilidade Pública","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629389","enunciado":"Do total das receitas correntes arrecadadas pela União em determinado exercício financeiro, 15% referem-se a receita classificada no código 1113.01.00 − Imposto sobre Produtos Industrializados. Quanto aos níveis de classificação da receita orçamentária, o primeiro e segundo dígito (11) representam, respectivamente, a seguinte classificação da receita","a":"orçamentária: corrente e rubrica.","b":"corrente e imposto sobre o patrimônio e a renda.","c":"tributária e rubrica.","d":"categoria econômica e espécie.","e":"categoria econômica e origem.","gabarito":"E","materia":"Administração Financeira e Orçamentária","tema":"Receita Pública ,Codificação da Receita Pública","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629388","enunciado":"Para responder à questão, considere as seguintes informações relativamente ao Balancete do Subsistema de Informações Orçamentárias do mês de novembro de 2015 de determinada entidade do setor público e os registros contábeis das transações realizadas no mês de dezembro de 2015. Transações realizadas no mês de dezembro de 2015 (em R$) − arrecadação de receitas de concessões e permissões .................................................................... 75.000 − empenho de despesa para execução de obras ................................................................................ 90.000 − arrecadação de receitas tributárias .................................................................................................. 275.000 − empenho de despesa para aquisição de material de escritório ........................................................ 45.000 − pagamento de despesa liquidada até o mês de novembro .............................................................. 350.000 − arrecadação de receita de aluguel de bens imóveis ......................................................................... 80.000 − empenho de despesa com serviços de manutenção de elevadores ................................................ 20.000 − recebimento de caução para garantia de execução de contrato de obras ........................................ 8.000 − liquidação de despesas empenhadas no mês de dezembro ............................................................ 75.000 − doação de equipamentos de informática a um hospital público ........................................................ 5.000 − liquidação de despesas empenhadas no mês de novembro ............................................................ 110.000 − pagamento de despesa liquidada no mês de dezembro .................................................................. 45.000 − arrecadação de receitas de multas e juros sobre tributos ................................................................ 25.000 − cancelamento de dívida ativa tributária inscrita indevidamente ........................................................ 10.000 Considerando os saldos das contas do subsistema de informações orçamentárias, ao final de dezembro de 2015, o resultado da execução orçamentária apurado conforme Balanço Orçamentário foi","a":"superavitário, em R$, 35.000.","b":"105.000.","c":"390.000.","d":"130.000.","e":"140.000.","gabarito":"E","materia":"Contabilidade Pública","tema":"Demonstrações Contábeis ,Balanço Orçamentário - BO","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629387","enunciado":"Transações realizadas no mês de dezembro de 2015 (em R$) − arrecadação de receitas de concessões e permissões .................................................................... 75.000 − empenho de despesa para execução de obras ................................................................................ 90.000 − arrecadação de receitas tributárias .................................................................................................. 275.000 − empenho de despesa para aquisição de material de escritório ........................................................ 45.000 − pagamento de despesa liquidada até o mês de novembro .............................................................. 350.000 − arrecadação de receita de aluguel de bens imóveis ......................................................................... 80.000 − empenho de despesa com serviços de manutenção de elevadores ................................................ 20.000 − recebimento de caução para garantia de execução de contrato de obras ........................................ 8.000 − liquidação de despesas empenhadas no mês de dezembro ............................................................ 75.000 − doação de equipamentos de informática a um hospital público ........................................................ 5.000 − liquidação de despesas empenhadas no mês de novembro ............................................................ 110.000 − pagamento de despesa liquidada no mês de dezembro .................................................................. 45.000 − arrecadação de receitas de multas e juros sobre tributos ................................................................ 25.000 − cancelamento de dívida ativa tributária inscrita indevidamente ........................................................ 10.000 O saldo da conta “6.2.2.1.3.03.00 − Crédito Empenhado Liquidado a Pagar”, ao final","a":"de dezembro de 2015, soma, em R$, 170.000.","b":"340.000.","c":"215.000.","d":"165.000.","e":"350.000.","gabarito":"A","materia":"Contabilidade Pública","tema":"Sistema Contábil ,Plano de Contas Aplicado ao Setor Público - PCASP","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629386","enunciado":"Transações realizadas no mês de dezembro de 2015 (em R$) − arrecadação de receitas de concessões e permissões ..................................................................... 75.000 − empenho de despesa para execução de obras ................................................................................. 90.000 − arrecadação de receitas tributárias .................................................................................................. 275.000 − empenho de despesa para aquisição de material de escritório ........................................................ 45.000 − pagamento de despesa liquidada até o mês de novembro ............................................................ 350.000 − arrecadação de receita de aluguel de bens imóveis ......................................................................... 80.000 − empenho de despesa com serviços de manutenção de elevadores ................................................ 20.000 − recebimento de caução para garantia de execução de contrato de obras ........................................ 8.000 − liquidação de despesas empenhadas no mês de dezembro ............................................................ 75.000 − doação de equipamentos de informática a um hospital público ........................................................ 5.000 − liquidação de despesas empenhadas no mês de novembro ...........................................................110.000 − pagamento de despesa liquidada no mês de dezembro .................................................................. 45.000 − arrecadação de receitas de multas e juros sobre tributos ................................................................ 25.000 − cancelamento de dívida ativa tributária inscrita indevidamente ....................................................... 10.000 O saldo da conta “6.2.2.1.3.01.00 − Crédito Empenhado a Liquidar”, ao final de","a":"dezembro de 2015, soma, em R$, 155.000.","b":"80.000.","c":"185.000.","d":"75.000.","e":"85.000. Contabilidade Pública>Ingressos e Dispêndios Públicos ,","gabarito":"B","materia":"Contabilidade Pública","tema":"Sistema Contábil ,Plano de Contas Aplicado ao Setor Público - PCASP","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1712","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria O presidente de determinado órgão do Poder Judiciário Federal autorizou a aquisição de um terreno pelo valor de R$ 1.350.000,00 para a construção de sua sede na região sudeste do Brasil. Sob o aspecto orçamentário, segundo a Lei Federal","a":"nº4.320/1964 a aquisição do imóvel será classificada, no grupo de natureza de despesa ativo permanente.","b":"bens de capital.","c":"investimentos.","d":"inversões financeiras.","e":"variações patrimoniais permutativas.","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629384","enunciado":"No âmbito do Governo Federal, o SIAFI é o principal instrumento utilizado para registro, acompanhamento e controle da execução orçamentária, financeira e patrimonial. Dentre os principais objetivos do SIAFI, considere: I. Fornecer meios para agilizar a programação financeira, otimizando a utilização dos recursos do Tesouro Nacional, através da unificação dos recursos de caixa do Governo Federal. II. Permitir que a contabilidade pública seja fonte segura e tempestiva de informações gerenciais destinadas a todos os níveis da Administração Pública Federal. III. Permitir o acompanhamento específico das despesas com pessoal e encargos sociais e da quantidade física de servidores. IV. Fornecer meios para agilizar a contratação de empresas para o fornecimento de bens e serviços à Administração Pública Federal, através de licitações. V. Permitir o controle da dívida interna e externa, bem como o das transferências negociadas.","a":"Está correto o que consta APENAS em I, II e IV.","b":"III e V.","c":"II e V.","d":"I, III e IV.","e":"I, II e V.","gabarito":"E","materia":"Contabilidade Pública","tema":"Sistema Contábil ,SIAFI","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629383","enunciado":"Na Lei Orçamentária Anual, para o exercício de 2016, do município de Terra dos Anjos do Sudeste foi aprovada a previsão de arrecadação de receitas de IPTU no valor de R$ 16.457.500,00. Considerando o fato gerador do IPTU no início de janeiro de 2016 o município contabilizou a variação patrimonial antes de sua arrecadação. O reconhecimento da variação patrimonial obedece ao princípio de contabilidade e seu registro será realizado no subsistema de informação contábil,","a":"respectivamente, competência e patrimonial.","b":"anualidade e patrimonial.","c":"competência e orçamentário.","d":"misto e patrimonial.","e":"competência e receitas tributárias.","gabarito":"A","materia":"Contabilidade Pública","tema":"Sistema Contábil ,Subsistemas de Contas","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629382","enunciado":"","a":"tabela abaixo apresenta informações obtidas das demonstrações contábeis da Empresa Original S.A. e da Empresa Copiada S.A. publicadas em 31/12/2014. Com base nessas informações, a Empresa","b":"A Copiada S.A. apresenta menor lucro líquido no período. Original S.A. apresenta maior passivo circulante.","c":"Original S.A. apresenta maior ativo circulante","d":"Copiada S.A. apresenta maior patrimônio líquido.","e":"Original S.A. possui um montante maior de recursos de terceiros.","gabarito":"A","materia":"Análise de Balanços","tema":"Análise por Índices ,Índices de Liquidez","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629381","enunciado":"O custo de aquisição de um equipamento foi R$ 6.000.000,00 e o pagamento foi realizado à vista. A aquisição ocorreu em 30/06/2014, a empresa definiu sua vida útil em 7 anos e o valor líquido de venda do equipamento no final do 7º ano foi estimado em R$ 3.060.000,00. Sabe-se que, para fins fiscais, a vida útil é definida em 10 anos. A empresa adota o método das quotas constantes para o cálculo da despesa mensal de depreciação e, no final de 2015, realizou o teste de redução ao valor recuperável para o equipamento (teste de impairment). Os valores obtidos em 31/12/2015 para a realização do teste para o equipamento foram os seguintes: − Valor justo líquido das despesas de venda = R$ 5.200.000,00. − Valor em uso = R$ 5.300.000,00.","a":"O valor contábil do equipamento evidenciado no Balanço Patrimonial de 31/12/2015 foi, em reais, 5.559.000,00.","b":"5.200.000,00.","c":"5.370.000,00.","d":"5.300.000,00.","e":"5.100.000,00.","gabarito":"D","materia":"Contabilidade Geral","tema":"Balanço Patrimonial ,Teste de Recuperabilidade (impairment)","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629380","enunciado":"","a":"Demonstração do Resultado do ano de 2014 e os Balanços Patrimoniais em 31/12/2013 e 31/12/2014 da empresa Produtos de Segurança Porta Aberta S.A. são apresentados nos dois quadros abaixo. Sabe-se que no ano de 2014 a empresa não vendeu participações societárias nem equipamentos, não liquidou qualquer empréstimo e não pagou as despesas financeiras do ano. Os valores em reais no ano de 2014, correspondentes ao Caixa das Atividades Operacionais e ao Caixa das Atividades de Financiamento foram, respectivamente, em reais,","b":"A 69.200 (negativo) e 208.000 (positivo). 21.200 (negativo) e 208.000 (positivo).","c":"21.200 (negativo) e 288.000 (positivo).","d":"49.200 (negativo) e 208.000 (positivo).","e":"49.200 (negativo) e 288.000 (positivo).","gabarito":"E","materia":"Contabilidade Geral","tema":"Demonstração dos Fluxos de Caixa -DFC","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629379","enunciado":"Uma empresa industrial é proprietária de três imóveis evidenciados em seu Balanço Patrimonial, sendo que os objetivos definidos pela empresa para cada um são: − Imóvel 1 − está sendo utilizado pela empresa para suas atividades administrativas. − Imóvel 2 − é mantido pela empresa, mas não está sendo utilizado em suas atividades. Atualmente está alugado para terceiros em um contrato com prazo de 5 anos. − Imóvel 3 − ainda é mantido pela empresa, mas está destinado para venda. Corresponde ao prédio onde a empresa concentrava anteriormente suas atividades administrativas. No entanto, a empresa ainda não iniciou um programa firme para localizar um comprador e concluir o plano de venda. Na divulgação do seu Balanço Patrimonial, a empresa deve evidenciar o Imóvel 1, o Imóvel 2 e o Imóvel 3, respectivamente,","a":"no grupo do ativo imobilizado, imobilizado e imobilizado.","b":"investimentos, imobilizado e realizável no longo prazo.","c":"imobilizado, investimentos e realizável no longo prazo.","d":"realizável a longo prazo, investimentos e investimentos.","e":"imobilizado, investimentos e circulante.","gabarito":"C","materia":"Contabilidade Geral","tema":"Balanço Patrimonial ,Noções Gerais de Balanço Patrimonial","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629378","enunciado":"Os seguintes valores do ativo e do patrimônio líquido de uma empresa foram obtidos a partir do seu Balanço Patrimonial publicado em 31/12/2014: − Total do Ativo = R$ 5.000.000,00. − Patrimônio Líquido = R$ 2.000.000,00. Sabendo-se que o Índice de Liquidez Corrente da empresa, obtido a partir do mesmo balanço, era 1,6 e que o grau de concentração do passivo no curto prazo era 40%, o valor total do Ativo Não Circulante da empresa, em 31/12/2014, era, em","a":"reais, 3.000.000,00.","b":"3.080.000,00.","c":"2.120.000,00.","d":"4.250.000,00.","e":"1.920.000,00.","gabarito":"B","materia":"Análise de Balanços","tema":"Análise por Índices ,Índices de Liquidez","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629377","enunciado":"Uma empresa aplicou parte de seus recursos, no valor total de R$ 360.000,00, em diversos ativos financeiros. As aplicações foram realizadas no dia 01/12/2015 e as características de cada instrumento financeiro adquirido, bem como a classificação feita pela empresa quanto ao objetivo em relação a cada ativo, são apresentadas na tabela abaixo. O valor total que afetou o resultado da empresa em 2015, decorrente das três aplicações apresentadas na tabela anterior","a":"foi, em reais, 8.240,00.","b":"7.320,00.","c":"9.200,00.","d":"5.520,00.","e":"1.200,00.","gabarito":"A","materia":"Contabilidade Geral","tema":"Balanço Patrimonial ,Investimentos ,Instrumentos Financeiros","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629376","enunciado":"","a":"empresa Alimentação para Todos S.A. adquiriu 80% das ações com direito a voto da Cia. Bom Sabor S.A. O preço pago pela aquisição foi R$ 40.000.000,00 e a Alimentação para Todos S.A. passou a deter o controle da Cia. Bom Sabor S.A. Sabe- se que o valor registrado no Patrimônio Líquido da Cia. Bom Sabor S.A. era, na data da aquisição, R$ 40.000.000,00 e que o valor justo líquido dos seus ativos e passivos identificáveis era, nesta data, R$ 45.000.000,00. Os valores totais reconhecidos no grupo Investimentos do balanço individual da empresa Alimentação para Todos S.A. e no grupo Intangíveis no seu balanço consolidado, na data da aquisição, foram, respectivamente, em reais,","b":"A 32.000.000,00 e 8.000.000,00. 40.000.000,00 e 0,00 (zero).","c":"32.000.000,00 e 0,00 (zero).","d":"32.000.000,00 e 4.000.000,00.","e":"40.000.000,00 e 4.000.000,00.","gabarito":"E","materia":"Contabilidade Geral","tema":"Investimentos","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629375","enunciado":"","a":"empresa Produtos Gerais S.A. apresentou, no Balanço Patrimonial de 31/12/2014, a seguinte composição para o Patrimônio líquido (valores em reais): Capital ............................................................................ 8.000.000,00 Reserva Legal ................................................................ 1.400.000,00 Reserva Estatutária ........................................................... 500.000,00 Reserva para Contingências ............................................. 300.000,00 Total do Patrimônio Líquido .......................................... 10.200.000,00 No ano de 2015 a empresa apurou um lucro líquido de R$ 4.800.000,00 e constituiu as seguintes reservas: − Reserva Legal, de acordo com o estabelecido na Lei das Sociedades por Ações. − Reserva Estatutária no valor correspondente a 10% do Lucro Líquido sem qualquer dedução. O fundamento econômico para a Reserva para Contingências contabilizada em 31/12/2014 não mais existia no final de 2015. Sabendo-se que o estatuto da empresa não define o critério para cálculo do dividendo mínimo obrigatório, o valor dos dividendos que deveria ser evidenciado no passivo, no Balanço Patrimonial de 31/12/2015, era, em reais,","b":"A 1.140.000,00. 1.200.000,00.","c":"2.300.000,00.","d":"2.450.000,00.","e":"1.225.000,00.","gabarito":"D","materia":"Contabilidade Geral","tema":"Balanço Patrimonial ,Reservas de Capital e Reservas de Lucros","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629374","enunciado":"","a":"empresa Problemas Gerais S.A. apresentou no Balanço Patrimonial publicado em 31/12/2013 o saldo de R$ 560.000,00 na conta de Provisões, cuja composição era a seguinte: Com base nestas informações, o efeito líquido causado no Resultado de 2014 da empresa Problemas Gerais S.A., relacionado às provisões necessárias foi,","b":"A redução de R$ 540.000,00. aumento de R$ 320.000,00.","c":"redução de R$ 240.000,00.","d":"nulo.","e":"aumento de R$ 400.000,00.","gabarito":"B","materia":"Contabilidade Geral","tema":"Balanço Patrimonial ,Provisões, Passivos Contingentes e Ativos Contingentes","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629373","enunciado":"No dia 01/12/2014 uma empresa contratou um empréstimo no valor de R$ 30.000.000,00. A taxa de juros contratada foi 1,5% ao mês e o pagamento do empréstimo será feito da seguinte forma: − O principal será pago integralmente em uma única parcela que vencerá em 01/12/2020. − Os juros serão pagos trimestralmente, com a primeira parcela vencendo em 01/03/2015. O valor das parcelas de juros a serem pagas trimestralmente é R$ 1.370.351,25 e a empresa pagou, adicionalmente, na data da obtenção do empréstimo, despesas relacionadas com o contrato no valor de R$ 1.000.000,00. Sabendo-se que a taxa de custo efetivo da operação foi 1,577% ao mês, o valor do saldo líquido apresentado no balanço","a":"patrimonial de 31/12/2014 para o passivo relativo ao empréstimo obtido foi, em reais, 30.450.000,00.","b":"30.473.100,00.","c":"29.457.330,00.","d":"31.488.870,00.","e":"29.435.000,00.","gabarito":"C","materia":"Contabilidade Geral","tema":"Balanço Patrimonial ,Noções Gerais de Balanço Patrimonial","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629372","enunciado":"Uma empresa adquiriu uma patente que poderá ser explorada pelo prazo de 20 anos, após o que a patente passa a ser de domínio público. O preço pago foi R$ 20.000.000,00 e a aquisição ocorreu em 31/12/2012. No final do ano de 2013, antes do fechamento das Demonstrações Contábeis, a empresa realizou o teste de redução ao valor recuperável (teste de impairment) e obteve as seguintes informações sobre a patente: − Valor em uso da patente: R$ 17.000.000,00. − Valor justo líquido das despesas de venda da patente: R$ 16.000.000,00. Na apuração do resultado do ano de 2013 a empresa deveria","a":"ter reconhecido uma despesa de amortização no valor de R$ 1.000.000,00 e uma perda por desvalorização no valor de R$ 3.000.000,00.","b":"ter reconhecido uma despesa de amortização no valor de R$ 1.000.000,00 e uma perda por desvalorização no valor de","c":"R$ 2.000.000,00. não ter reconhecido nenhuma despesa por se tratar de ativo intangível que não deve ser amortizado.","d":"ter reconhecido uma despesa de amortização no valor de R$ 1.000.000,00, apenas.","e":"ter reconhecido uma perda por desvalorização no valor de R$ 3.000.000,00, apenas.","gabarito":"B","materia":"Contabilidade Geral","tema":"Balanço Patrimonial ,Teste de Recuperabilidade (impairment)","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629371","enunciado":"O saldo em estoque de um determinado produto em 30/11/2014 era R$ 600.000,00 e correspondia a 400 unidades disponíveis. A empresa comercializa somente este produto e durante o mês de dezembro de 2014 realizou, em ordem cronológica, as seguintes transações relacionadas com a compra e a venda do produto: Sabendo-se que não há incidência de qualquer tributo na compra e na venda deste produto, que a empresa utiliza o critério","a":"da média ponderada móvel, o saldo da conta de estoque evidenciado no Balanço Patrimonial de 31/12/2014 foi, em reais, 548.000,00.","b":"539.000,00.","c":"543.000,00.","d":"552.000,00.","e":"457.000,00.","gabarito":"A","materia":"Contabilidade Geral","tema":"Balanço Patrimonial ,Operações com Mercadorias","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629370","enunciado":"Uma empresa adquiriu um equipamento de produção pelo valor de R$ 12.000.000,00 que foi pago à vista. A aquisição ocorreu em 30/06/2010, a empresa definiu a vida útil do equipamento em 10 anos de utilização e calcula sua despesa de depreciação em função do tempo decorrido (método das quotas constantes), tendo em vista que o mesmo funciona sem qualquer interrupção. No início do prazo de utilização do equipamento o valor residual estimado para sua venda no final da vida útil era R$ 1.500.000,00. No final de 2013, a empresa identificou que o valor residual no final da vida útil foi reduzido para R$ 1.175.000,00, em decorrência do aparecimento de novos equipamentos com tecnologia mais atual, o que fez com que o valor de mercado dos equipamentos utilizados pela empresa diminuísse. A análise feita pela empresa neste momento (final de 2013) identificou que não havia necessidade de redução do valor contábil do equipamento (o valor recuperável era maior que o valor contábil). Se a vida útil do equipamento para fins fiscais é definida em 8 anos, o valor","a":"contábil que deveria ter sido evidenciado no Balanço Patrimonial de 31/12/2014 para este equipamento era, em reais, 5.250.000,00.","b":"6.600.000,00.","c":"5.775.000,00.","d":"7.225.000,00.","e":"7.275.000,00.","gabarito":"D","materia":"Contabilidade Geral","tema":"Balanço Patrimonial ,Amortização, Depreciação e Exaustão","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629369","enunciado":"Um lote de mercadorias foi adquirido do exterior para comercialização no Brasil. A compra ocorreu em 15/10/2015 e o preço pago ao fornecedor no exterior foi R$ 6.000.000,00, sendo que a empresa pagou, adicionalmente, os seguintes encargos para dispor das mercadorias em condições de venda: − R$ 600.000,00 de transporte aéreo para trazer a mercadoria do país de origem até o Brasil. − R$ 240.000,00 de taxas e tarifas alfandegárias para ingresso das mercadorias no Brasil. − R$ 100.000,00 para transporte da mercadoria do aeroporto até a sede da empresa. − R$ 150.000,00 correspondente aos seguintes impostos: − R$ 60.000,00 a título de imposto de importação não recuperável. − R$ 90.000,00 a título de outros impostos locais que podem ser compensados com os impostos incidentes no momento da venda das mercadorias. Sabe-se que não havia saldo de estoque antes desta compra e que, em dezembro de 2015, a empresa vendeu noventa por cento das mercadorias que foram importadas. O valor bruto das vendas foi R$ 8.500.000,00 e os impostos incidentes sobre estas vendas totalizaram R$ 1.275.000,00. O Resultado Bruto com Mercadorias apurado pela empresa no ano de 2015,","a":"exclusivamente em relação às mercadorias importadas e vendidas, foi, em reais, 3.100.000,00.","b":"844.000,00.","c":"925.000,00.","d":"979.000,00.","e":"1.015.000,00.","gabarito":"C","materia":"Contabilidade Geral","tema":"Balanço Patrimonial ,Operações com Mercadorias","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629368","enunciado":"","a":"empresa Tiro Certo S.A. realizou, no dia 01/12/2013, vendas de mercadorias no valor total de R$ 2.331.000,00, sendo que R$ 1.000.000,00 foram recebidos à vista e o restante para ser recebido integralmente em 01/12/2015. Na data da venda a empresa estava praticando, para as suas vendas a prazo, a taxa de juros de 0,797% ao mês que corresponde a 10% ao ano e a 21% em 2 (dois) anos. Na Demonstração do Resultado do ano de 2013 a empresa reconheceu, exclusivamente em relação às vendas efetuadas em 01/12/2013:","b":"A Receita de Vendas no valor de R$ 2.331.000,00, apenas. Receita de Vendas no valor de R$ 2.100.000,00, apenas.","c":"Receita de Vendas no valor de R$ 2.100.000,00 e Receita Financeira no valor de R$ 16.737,00.","d":"Receita de Vendas no valor de R$ 2.331.000,00 e Receita Financeira no valor de R$ 18.578,00.","e":"Receita de Vendas no valor de R$ 2.100.000,00 e Receita Financeira no valor de R$ 8.767,00.","gabarito":"E","materia":"Contabilidade Geral","tema":"Balanço Patrimonial ,Legislação de Contabilidade ,Normas CFC - CPC","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629367","enunciado":"Geremoabo, dirigente de sociedade de economia mista da qual participa o Estado de São Paulo, pratica ato que causa dano ao patrimônio da empresa. Inconformado com tal ato, Trasíbulo resolve questioná-lo judicialmente.","a":"Para tanto, poderá fazer uso de mandado de segurança, desde que comprove possuir domicílio no Estado de São Paulo.","b":"mandado de segurança, pouco importando o local de seu domicílio.","c":"ação popular, desde que demonstre a sua qualidade de cidadão, pouco importando o local de seu domicílio.","d":"ação popular, bastando para tanto a prova de que reside no país e que possui domicílio no Estado de São Paulo.","e":"ação popular, desde que demonstre a sua qualidade de cidadão e que possui domicílio no Estado de São Paulo.","gabarito":"C","materia":"Direito Constitucional","tema":"Direitos Individuais - Remédios Constitucionais e Garantias Processuais ,Ação Popular","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629366","enunciado":"Entre os direitos sociais, a Constituição Federal garante os direitos dos trabalhadores, EXCETO:","a":"Relação de emprego protegida contra despedida arbitrária ou sem justa causa, nos termos de lei complementar, que","b":"preverá indenização compensatória, dentre outros direitos. Salário-família pago em razão do dependente do trabalhador de baixa renda, nos termos da lei.","c":"Seguro contra acidentes do trabalho, a cargo do empregador, sem excluir a indenização a que este está obrigado","d":"quando incorrer em dolo ou culpa. Participação nos lucros ou resultados da empresa, vinculada à remuneração, nos termos da lei.","e":"Duração do trabalho normal não superior a oito horas diárias e quarenta e quatro semanais, facultadas a compensação de horários e a redução da jornada, mediante acordo ou convenção coletiva de trabalho","gabarito":"D","materia":"Direito Constitucional","tema":"Direitos Sociais","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629365","enunciado":"","a":"Compete ao Superior Tribunal de Justiça o julgamento de recursos ordinários contra decisões lançadas pelo Tribunal Regional Federal, em última instância, que concedam ou deneguem a ordem de habeas corpus.","b":"Regional Federal, em instância única, que concedam ou deneguem a ordem em mandado de segurança.","c":"de Justiça do Estado, que neguem vigência ao texto de lei Federal.","d":"de Justiça do Estado, que derem à lei Federal interpretação divergente daquela que lhe foi conferida pelo Tribunal Regional Federal.","e":"Regional Federal ou Tribunal de Justiça do Estado, em instância única, quando denegarem a ordem em habeas corpus ou mandado de segurança.","gabarito":"E","materia":"Direito Constitucional","tema":"Superior Tribunal de Justiça ,Organização do Poder Judiciário","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629364","enunciado":"","a":"Súmula Vinculante somente pode ser editada pelo Supremo Tribunal Federal através do voto da maioria simples de seus integrantes, sendo certo que a seu conteúdo encontram-se vinculados apenas os órgãos A jurisdicionais.","b":"de dois terços de seus integrantes, passando seu conteúdo a obrigar, inclusive, à Administração pública direta e","c":"indireta. de três quintos de seus integrantes, passando seu conteúdo a vincular apenas aos órgãos jurisdicionais.","d":"de dois terços de seus integrantes, passando seu conteúdo a vincular apenas aos órgãos jurisdicionais.","e":"da maioria simples de seus integrantes, sendo certo que seu conteúdo vincula, inclusive, à Administração direta e indireta. Direito Administrativo>Lei nº 8.112-1990 - Regime jurídico dos servidores públicos federais ,","gabarito":"B","materia":"Direito Constitucional","tema":"Controle de Constitucionalidade ,Súmula Vinculante","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1734","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria Aristides, Analista do Tribunal Regional Federal da 3ª Região, foi cedido ao Tribunal de Justiça do Estado de São Paulo, para o exercício de cargo em comissão. No caso narrado, nos termos da Lei n°8.112/1990, o ônus da remuneração será","a":"compartilhado por ambos os Tribunais; no entanto, o Tribunal de Justiça arcará com um terço da remuneração e o","b":"Tribunal Regional Federal com o restante. do Tribunal Regional Federal da 3a Região.","c":"compartilhado por ambos os Tribunais, arcando cada um com metade da remuneração.","d":"compartilhado por ambos os Tribunais; no entanto, o Tribunal de Justiça arcará com dois terços da remuneração e o","e":"Tribunal Regional Federal com o restante. do Tribunal de Justiça do Estado de São Paulo.","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629360","enunciado":"Ana, Analista do Tribunal Regional Federal da 3ªRegião, assumirá, na condição de substituta, sem prejuízo do cargo que ocupa, o exercício de cargo de chefia, no afastamento do titular do referido cargo. Cumpre salientar que assumirá tal","a":"condição pelo período máximo de trinta dias. No caso narrado, conforme preceitua a Lei nº 8.112/1990, Ana receberá, obrigatoriamente, a remuneração do cargo de Analista.","b":"receberá, obrigatoriamente, a remuneração do cargo de chefia.","c":"deverá optar pela remuneração de um dos cargos durante o respectivo período.","d":"acumulará ambas as remunerações, por se tratar do instituto da substituição.","e":"acumulará ambas as remunerações nos primeiros quinze dias, e, a partir do décimo quinto dia, receberá tão somente a remuneração do cargo de chefia. Direito Administrativo>Lei nº 8.112-1990 - Regime jurídico dos servidores públicos federais ,","gabarito":"C","materia":"Direito Administrativo","tema":"Agentes públicos e Lei 8.112 de 1990 ,Acumulação de cargos e funções","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1736","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria Mario é Analista do Tribunal Regional Federal da 3ª Região, ainda em estágio probatório, e pretende licenciar-se para tratar de interesses particulares. Já Alessandra, também Analista do Tribunal Regional Federal da 3ª Região, obteve licença para tratar de interesses particulares há um ano e pretende que sua licença perdure por mais três anos. Nos termos da Lei no","a":"8.112/1990, Mario não tem direito à mencionada licença e Alessandra poderá licenciar-se pelo prazo máximo de três anos consecutivos","b":"faz jus à mencionada licença, desde que preenchidos os demais requisitos legais, e Alessandra poderá licenciar-se pelo prazo máximo de dois anos consecutivos.","c":"não tem direito à mencionada licença e Alessandra poderá licenciar-se pelo prazo máximo de cinco anos, consecutivos ou não.","d":"faz jus à mencionada licença, desde que preenchidos os demais requisitos legais e Alessandra poderá licenciar-se pelo","e":"prazo máximo de cinco anos consecutivos. não faz jus à mencionada licença e Alessandra poderá licenciar-se pelo prazo máximo de dois anos consecutivos.","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q629358","enunciado":"José, Analista de Contadoria do Tribunal Regional Federal da 3ª Região, no exercício de suas atribuições, possibilitou a liquidação de julgado, bem como a atualização de valor de determinada guia, ambos relacionados à empresa WZ Construções S.A. Em razão disso, a citada empresa presenteou José com valioso bem, aceito pelo servidor. Nos termos da","a":"Lei no 8.112/1990, a ação disciplinar atinente à infração praticada por José prescreverá em dois anos.","b":"cinco anos.","c":"três anos.","d":"um ano.","e":"cento e oitenta dias. Direito Penal>Crimes contra a administração pública ,Noções Gerais de Crimes Contra a Administração Pública ,","gabarito":"B","materia":"Direito Administrativo","tema":"Agentes públicos e Lei 8.112 de 1990 ,Responsabilidades do servidor","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Contadoria","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1738","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","a":"... respeito dos Crimes contra a Administração pública, é INCORRETO afirmar que","b":"A o particular pode ser coautor do crime de concussão. comete o crime de excesso de exação o funcionário que emprega meio vexatório na cobrança de tributo.","c":"o crime de prevaricação exige o intuito do agente de satisfazer interesse ou sentimento pessoal.","d":"comete crime de corrupção passiva quem oferece dinheiro a funcionário público para determiná-lo a retardar ato de ofício.","e":"o ato de desferir um tapa no rosto de funcionário público, em razão da sua função, sem causar lesão, pode caracterizar o crime de desacato.","gabarito":"","materia":"Geral","tema":"","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","concurso":"TRF3"},{"id":"Q629355","enunciado":"... Lucius, funcionário público, escrevente de cartório de secretaria de Vara Criminal, apropriou-se de um relógio valioso que foi remetido ao Fórum juntamente com os autos do inquérito policial no qual foi objeto de apreensão. Lucius cometeu","a":"crime de apropriação de coisa achada.","b":"apropriação indébita simples.","c":"apropriação indébita qualificada pelo recebimento da coisa em razão de ofício, emprego ou profissão.","d":"apropriação de coisa havida por erro.","e":"peculato.","gabarito":"E","materia":"Direito Penal","tema":"Crimes contra a administração pública ,Peculato","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","concurso":"TRF3"},{"id":"Q629354","enunciado":"... Peter, pessoa de grande porte físico, agarrou Paulus pelas costas e o imobilizou com uma “gravata”. Com a vítima imobilizada, subtraiu-lhe a carteira, o celular e o relógio. Em seguida, deixou o local e soltou a vítima que não sofreu","a":"nenhum ferimento. Peter cometeu crime de extorsão simples.","b":"furto qualificado pela destreza.","c":"roubo qualificado.","d":"roubo simples.","e":"extorsão qualificada.","gabarito":"D","materia":"Direito Penal","tema":"Crimes contra o patrimônio ,Furto ,RouboExtorsão","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","concurso":"TRF3"},{"id":"Q629352","enunciado":"... Em uma empresa, um funcionário deve cumprir exatas 8 horas de trabalho em um dia. Certo dia, um funcionário trabalhou 2 horas e 14 minutos; em seguida trabalhou outras 3 horas e 38 minutos. A fração da carga diária de tempo de trabalho que","a":"esse funcionário ainda deve cumprir nesse dia é igual a 4/15","b":"1/4","c":"3/5","d":"3/8","e":"7/20","gabarito":"A","materia":"Matemática","tema":"Aritmética e Problemas ,Frações e Números Decimais ,Regra de Três","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","concurso":"TRF3"},{"id":"Q629351","enunciado":"... Considere, abaixo, as afirmações e o valor lógico atribuído a cada uma delas entre parênteses. − Ou Júlio é pintor, ou Bruno não é cozinheiro (afirmação FALSA). − Se Carlos é marceneiro, então Júlio não é pintor (afirmação FALSA).","a":"− Bruno é cozinheiro ou Antônio não é pedreiro (afirmação VERDADEIRA). partir dessas afirmações,","b":"A Júlio não é pintor e Bruno não é cozinheiro. Antônio é pedreiro ou Bruno é cozinheiro.","c":"Carlos é marceneiro e Antônio não é pedreiro.","d":"Júlio é pintor e Carlos não é marceneiro.","e":"Antônio é pedreiro ou Júlio não é pintor.","gabarito":"C","materia":"Raciocínio Lógico","tema":"Lógica de Argumentação - Diagramas e Operadores Lógicos","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","concurso":"TRF3"},{"id":"Q629350","enunciado":"... As letras da expressão x − (w − y) − (z − h), representam números diferentes e serão substituídas, uma a uma e para efeito de cálculo, pelos números naturais 9; 12; 13; 15 e 17, não necessariamente nessa ordem. Opere apenas no conjunto dos","a":"números naturais. Para que o resultado da expressão seja 8, as letras w e h devem ser substituídas, respectivamente, por 15 e 13.","b":"17 e 12.","c":"13 e 9.","d":"15 e 12.","e":"17 e 9.","gabarito":"E","materia":"Raciocínio Lógico","tema":"Raciocínio Matemático","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","concurso":"TRF3"},{"id":"Q629349","enunciado":"... Uma indústria produz um tipo de máquina que demanda a ação de grupos de funcionários no preparo para o despacho ao cliente. Um grupo de 20 funcionários prepara o despacho de 150 máquinas em 45 dias. Para preparar o despacho de 275 máquinas, essa indústria designou 30 funcionários. O número de dias gastos por esses 30 funcionários para preparem","a":"essas 275 máquinas é igual a 55.","b":"36.","c":"60.","d":"72.","e":"48.","gabarito":"A","materia":"Matemática","tema":"Aritmética e Problemas ,Regra de Três","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","concurso":"TRF3"},{"id":"Q629345","enunciado":"... O senhor A investiu a quantia de x em um produto financeiro que apresentou queda constante e sucessiva de 10% ao ano por, pelo menos, 10 anos. Simultaneamente, o senhor B investiu a quantia de 27x (27 vezes a quantia x) em um produto financeiro que apresentou queda constante e sucessiva de 70% ao ano por, pelo menos, 10 anos. A partir do início desses dois investimentos, o número de anos completos necessários para que o montante investido pelo senhor A se tornasse","a":"maior que o montante investido pelo senhor B é igual a 2","b":"4","c":"6","d":"3","e":"5","gabarito":"B","materia":"Matemática","tema":"Matemática Financeira","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","concurso":"TRF3"},{"id":"Q629342","enunciado":"... Estava mal chegando a São Paulo, quando um repórter me provocou: \"Mas como, Chico, mais um samba? Você não acha que isso já está superado?\" Não tive tempo de me defender ou de atacar os outros, coisa que anda muito em voga. Já era hora de enfrentar o dragão, como diz o Tom, enfrentar as luzes, os cartazes, e a plateia, onde distingui um caro colega regendo um coro pra frente, de franca oposição. Fiquei um pouco desconcertado pela atitude do meu amigo, um homem sabidamente isento de preconceitos. Foi-se o tempo em que ele me censurava amargamente, numa roda revolucionária, pelo meu desinteresse em participar de uma passeata cívica contra a guitarra elétrica. Nunca tive nada contra esse instrumento, como nada tenho contra o tamborim. O importante é Mutantes e Martinho da Vila no mesmo palco. Mas, como eu ia dizendo, estava voltando da Europa e de sua música estereotipada, onde samba, toada etc. são ritmos virgens para seus melhores músicos, indecifráveis para seus cérebros eletrônicos. \"Só tenho uma opção, confessou-me um italiano − sangue novo ou a antimúsica. Veja, os Beatles, foram à Índia...\" Donde se conclui como precipitada a opinião, entre nós, de que estaria morto o nosso ritmo, o lirismo e a malícia, a malemolência. É certo que se deve romper com as estruturas. Mas a música brasileira, ao contrário de outras artes, já traz dentro de si os elementos de renovação. Não se trata de defender a tradição, família ou propriedade de ninguém. Mas foi com o samba que João Gilberto rompeu as estruturas da nossa canção. E se o rompimento não foi universal, culpa é do brasileiro, que não tem vocação pra exportar coisa alguma. Quanto a festival, acho justo que estejam todos ansiosos por um primeiro prêmio. Mas não é bom usar de qualquer recurso, nem se deve correr com estrondo atrás do sucesso, senão ele se assusta e foge logo. E não precisa dar muito tempo para se perceber \"que nem toda loucura é genial, como nem toda lucidez é velha\". (Adaptado de: HOLANDA, Chico Buarque de, apud Adélia B. de Menezes, Desenho Mágico: Poesia e Política em Chico Buarque, São Paulo, Ateliê, 2002, p. 28-29)","a":"Sem que se altere o sentido da frase, todas as vírgulas podem ser substituídas por travessão, EXCETO em: Não se trata de defender a tradição, família ou propriedade... (2º parágrafo)","b":"Fiquei um pouco desconcertado pela atitude do meu amigo, um homem... (1º parágrafo)","c":"Mas, como eu ia dizendo, estava voltando da Europa... (2º parágrafo)","d":"... como precipitada, entre nós, de que estaria morto... (2º parágrafo)","e":"Mas a música brasileira, ao contrário de outras artes, já traz... (2º parágrafo)","gabarito":"A","materia":"Português","tema":"Pontuação ,Uso da Vírgula ,Travessão","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","concurso":"TRF3"},{"id":"Q628956","enunciado":"Um Analista em Tecnologia da Informação está participando de uma reunião de planejamento de um projeto do TRF3 que utiliza o PMBOK 5ª edição. Esta reunião, que envolve toda a equipe, objetiva definir e decompor as atividades do projeto e calcular o esforço necessário em cada uma delas. Inicialmente, está sendo realizada a subdivisão das entregas e do trabalho","a":"do projeto em componentes menores e mais facilmente gerenciáveis, no processo de Sequenciamento das Atividades do Projeto.","b":"Definição do Escopo do Projeto.","c":"Criação da Estrutura Analítica do Projeto.","d":"Classificação das Atividades do Projeto.","e":"Controle do Trabalho do Projeto.","gabarito":"C","materia":"Engenharia de Software","tema":"Gestão de Projetos em Engenharia de Software","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q628955","enunciado":"Para gerenciar os serviços de Tecnologia da Informação − TI um Analista do TRF3 deve adotar um modelo baseado nas melhores práticas de gerenciamento de serviços utilizadas com sucesso nas organizações. Já para a governança e gestão de","a":"TI deverá adotar um framework que traz boas práticas para a governança e gestão da TI. escolha do Analista deverá ser, respectivamente,","b":"A ITIL − COBIT. CMMI − MPS.BR.","c":"BSC − PRINCE2.","d":"ITIL − CMMI.","e":"SPICE − COBIT.","gabarito":"A","materia":"Governança de TI","tema":"ITIL ,COBIT","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q628954","enunciado":"Todos os computadores conectados na Internet recebem um número de endereço IP, formado por quatro séries de","a":"números separados por pontos. Assim, um endereço possível para o site do TRF3 é 344.241.0.122","b":"324.255.0.128","c":"512.256.128.64","d":"257.266.13.1","e":"177.43.200.30","gabarito":"E","materia":"Redes de Computadores","tema":"Arquitetura TCP/IP","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q628953","enunciado":"Dada a urgência no desenvolvimento de um software, a equipe de Tecnologia da Informação − TI do TRF3 resolveu utilizar uma das metodologias ágeis de desenvolvimento de sistemas. Um dos princípios destas metodologias é dar maior","a":"prioridade aos procedimentos e ferramentas do que às pessoas e suas interações.","b":"ao desenvolvimento de uma documentação abrangente do que às funcionalidades.","c":"à negociação de contratos do que à colaboração com clientes.","d":"a responder a mudanças do que a seguir um plano pré-estabelecido.","e":"ao desenvolvimento completo do software do que a fazer entregas parciais.","gabarito":"D","materia":"Engenharia de Software","tema":"Processos de Software - Desenvolvimento Ágil","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q628952","enunciado":"Um Analista Judiciário da Área Administrativa do TRF3 deseja solicitar ao departamento de Tecnologia da Informação − TI o desenvolvimento de um sistema de informação para fazer com que cada vez que uma resma de 500 folhas de papel sulfite seja retirada do estoque, um registro apareça, automaticamente, nos computadores da empresa fabricante e fornecedora de papel sulfite, de forma que ela possa fabricar a quantidade necessária e enviar diretamente ao TRF3, eliminando distribuidores e reduzindo custos de armazenamento. Neste caso, o sistema de informação que o Analista deseja solicitar é","a":"um Customer Relationship Management − CRM.","b":"Supply Chain Management − SCM.","c":"Enterprise Resource Planning − ERP.","d":"Knowledge Management System − KMS.","e":"Transaction Support System − TSS.","gabarito":"B","materia":"Sistemas de Informação","tema":"Sistemas de Informação","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q628951","enunciado":"Adonis trabalha como soldado da Polícia Militar, em escala 12x36, das 6h00 às 18h00. Em todas as suas folgas, prestava serviços de forma pessoal e subordinada para uma empresa de segurança, fazendo a escolta de caminhões de carga, mediante o pagamento de salário mensal, sem registro em sua CTPS. Após dois anos de trabalho para a empresa de segurança, Adonis foi dispensado sem o recebimento das verbas rescisórias. Por esta razão, pleiteou o reconhecimento do vínculo empregatício e o pagamento das verbas salariais e rescisórias devidas durante a prestação de serviços. Segundo o entendimento sumulado pelo TST, o reconhecimento do vínculo empregatício entre o policial militar e a empresa","a":"de segurança não é devido, porque o policial militar está proibido de trabalhar para empresas privadas, em suas horas vagas.","b":"não é devido, porque o policial militar trabalhava apenas em dias alternados, não havendo habitualidade.","c":"não é devido, pois Adonis, por ser policial militar, não estava sujeito às ordens da empresa de segurança, nem poderia ser punido com advertência ou suspensão.","d":"é devido, tendo em vista que preenchidas as características da relação de emprego, independentemente do eventual cabimento de penalidade disciplinar prevista no Estatuto do Policial Militar.","e":"é devido, pois a prestação de serviços foi pessoal, habitual, subordinada e onerosa, porém, é vedada a aplicação de qualquer tipo de penalidade disciplinar pela corporação ao policial militar, bem como o registro em sua CTPS.","gabarito":"D","materia":"Direito do Trabalho","tema":"Relação de trabalho e de emprego ,Das relações laborais","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1753","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa Maria Dolores, analista de sistemas da empresa Digital S/A, ficou afastada de suas atividades durante quatro períodos: 14 dias, em razão de um pequeno acidente doméstico; 03 dias, em virtude de casamento; 10 dias, em razão de uma cirurgia de retirada de varizes e 03 dias, em razão de suspensão disciplinar. Analisando-se a situação acima, o contrato de trabalho de Maria Dolores, durante os afastamentos esteve,","a":"respectivamente, suspenso, suspenso, interrompido e interrompido.","b":"interrompido, interrompido, suspenso e suspenso.","c":"suspenso, interrompido, interrompido e interrompido.","d":"interrompido, suspenso, suspenso e interrompido.","e":"interrompido, interrompido, interrompido e suspenso.","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q628949","enunciado":"João Fita é Operador de Máquina na Gráfica Imprima Bem Ltda. Desde a sua contratação, João Fita opera a máquina CPTD4 que, em funcionamento, emite ruídos acima dos limites de tolerância fixados pelo Ministério do Trabalho e Previdência Social e recebe adicional compatível com o grau de insalubridade apurado. Após a modernização do pátio gráfico, João Fita passou a operar a máquina CPTD5, que não emite qualquer tipo de ruído. Em virtude disso, a Gráfica Imprima Bem Ltda. parou de pagar o adicional de insalubridade. Diante dos fatos, a atitude da empresa","a":"está correta, eis que, eliminados os riscos à saúde de João Fita, cessará a obrigação do pagamento do adicional de","b":"insalubridade. não está correta, pois a Constituição Federal garante a irredutibilidade salarial.","c":"está correta, porém João Fita terá direito à indenização correspondente a um mês do adicional de insalubridade suprimido por ano de trabalho nestas condições.","d":"não está correta, pois o adicional de insalubridade integrou o contrato de trabalho de João Fita, não podendo ser suprimido.","e":"não está correta, pois como se trata de alteração do contrato de trabalho, o consentimento João Fita é obrigatório e só terá validade se a condição for mais benéfica ao empregado.","gabarito":"A","materia":"Direito do Trabalho","tema":"Remuneração e salário ,Adicionais","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q628948","enunciado":"Judith Cristina, assistente administrativo na empresa Sem Rumo Representação Comercial, foi dispensada sem justa causa em 14/10/2015, sendo quitadas todas as verbas rescisórias inerentes ao contrato de trabalho. No dia 30/10/2015, após um mal estar, Judith Cristina passou por uma consulta médica quando, então, foi constatado que estava grávida, com 6 semanas de gestação. Após seis meses do nascimento da criança, Judith Cristina procurou a empresa Sem Rumo Representação Comercial e informou que, no momento da rescisão do contrato de trabalho, estava grávida.","a":"Diante dos fatos e de acordo com o entendimento sumulado pelo TST, Judith Cristina deve ser reintegrada, com o pagamento dos salários e demais verbas relativas ao período posterior à reintegração.","b":"deve ser reintegrada, com pagamento de todos os salários e demais direitos correspondentes ao período de estabilidade.","c":"tem direito apenas aos salários e demais verbas correspondentes ao período de estabilidade, tendo em vista o término do período relativo à garantia de emprego.","d":"não tem direito aos salários e demais verbas correspondentes ao período de estabilidade, uma vez que não","e":"comunicou a empresa antes do nascimento da criança. não tem direito à reintegração e aos salários, em razão do término da garantia de emprego. Direito do Trabalho>Extinção do contrato de emprego: modalidades e obrigações legais ,","gabarito":"C","materia":"Direito do Trabalho","tema":"Das relações laborais ,Trabalho da mulher","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1756","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa Rosa Maria trabalhou como Gerente de Produtos na empresa Limpe Bem Ltda., que aluga equipamentos de limpeza residencial e industrial. A empregada trabalhou para a referida empresa de 01 de agosto de 2012 até 10 de novembro de 2015, quando foi dispensada sem justa causa, com a concessão de aviso prévio indenizado. Uma semana após a comunicação da dispensa, Rosa Maria voltou à empresa para devolver dois equipamentos de limpeza que havia levado para sua residência, indevidamente e sem o conhecimento da empresa, com o objetivo de limpar um cômodo de sua casa. Diante da situação fática apresentada e de acordo com o entendimento sumulado pelo TST, Rosa Maria","a":"poderá ter sua dispensa imotivada convertida em dispensa por justa causa, perdendo o direito ao restante do respectivo período de aviso prévio.","b":"poderá ter sua dispensa imotivada convertida em dispensa por justa causa, mas terá direito de receber todos os valores relativos à rescisão sem justa causa, com a compensação da quantia referente ao aluguel do equipamento utilizado indevidamente.","c":"perderá o período restante do aviso prévio, mas terá direito a receber os valores relativos às férias vencidas e proporcionais acrescidas de 1/3 constitucional, décimo terceiro salário e saque do FGTS.","d":"não poderá ter sua dispensa imotivada convertida em dispensa por justa causa, porque o ato faltoso foi cometido antes da concessão do aviso prévio, não sendo mais possível alterar o motivo determinante da ruptura do contrato de trabalho.","e":"poderá sofrer a aplicação de uma penalidade como a advertência ou suspensão, mas não poderá ter sua dispensa imotivada convertida em dispensa por justa causa.","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q628943","enunciado":"O gráfico abaixo demonstra a evolução de um item de material de escritório do almoxarifado de determinada instituição. Considerando a importância desse item para o andamento dos processos internos, ao avaliá-lo utilizando o indicador de","a":"rotatividade dos estoques, conclui-se que, no ano de 2015, este item teve um giro de 36 vezes.","b":"24 vezes.","c":"12 vezes.","d":"6 vezes.","e":"18 vezes.","gabarito":"C","materia":"Administração de Recursos Materiais","tema":"Armazenagem ,Administração dos Almoxarifados","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q628942","enunciado":"Decidir por estocar um item requer avaliar sua importância no que tange a representatividade econômica para a instituição e a demanda do usuário final. Esta avaliação pode ser efetuada utilizando-se a técnica do lote econômico de compra. Em uma situação hipotética, certa SKU tem utilização anual de 8.000 unidades, a um custo unitário de R$ 20,00. Sabendo-se que o custo do pedido é de R$ 50,00 e o custo de ocupação de estoque compreende a 30%, o lote econômico de compra para","a":"esta SKU corresponde a 250 unidades.","b":"365 unidades.","c":"65 unidades.","d":"120 unidades.","e":"435 unidades.","gabarito":"B","materia":"Administração de Recursos Materiais","tema":"Administração de Compras ,Lote Econômico de Compras – LEC","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q628941","enunciado":"Um dos procedimentos mais relevantes do inventário que, quando mal organizado, pode gerar discrepâncias tanto de valor","a":"como de quantidade, entre o estoque físico e o contábil, é o Spin-off.","b":"Start-up.","c":"Break-up.","d":"Cut-off.","e":"Count-down.","gabarito":"D","materia":"Administração de Recursos Materiais","tema":"Armazenagem ,Inventários","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q628940","enunciado":"Os custos de manutenção de estoque são muito importantes, pois refletem uma fração do custo de um serviço prestado por uma organização pública. Sobre custos diretamente relacionados à manutenção de estoque, considere: I. O custo de obsolescência estima a taxa em que o valor de um SKU decresce tanto em relação ao seu valor de mercado, como pela sua própria deterioração. II. O custo do capital expressa, efetivamente, o custo de oportunidade do capital. Podendo ser avaliado pelo custo médio ponderado de capital. III. Os custos marginais associados à emissão, ou ao recebimento de um pedido extra, devem ser considerados como custos de manutenção de estoque. IV. Os custos de recebimentos podem ser contraídos independentemente do tamanho do pedido, contudo os custos de recebimentos baseados no volume não devem ser incluídos para o cálculo da manutenção de estoque. V. O custo de ocupação reflete a alteração marginal no espaço causado por mudanças no estoque cíclico.","a":"Está correto o que consta APENAS em II, III e IV.","b":"I, IV e V.","c":"II, III e V.","d":"I, III e IV.","e":"I, II e V.","gabarito":"E","materia":"Administração de Recursos Materiais","tema":"Administração de Estoques ,Previsão e Custos dos Estoques","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q628939","enunciado":"","a":"política de estoque de um Tribunal Regional Federal adota, como um dos seus princípios, o estoque mínimo (que deve ser de um mês de consumo para cada um dos itens em estoque). Ao rever seu processo interno de compras e negociar com três dos seus fornecedores, os tempos de reposições foram alterados conforme abaixo. − Fornecedor 1 (Forn1): tempo de reposição 30 dias. − Fornecedor 2 (Forn2): tempo de reposição 60 dias. − Fornecedor 3 (Forn3): tempo de reposição 90 dias. Diante destas alterações nos tempos de reposições do estoque, foram identificados dez itens que são abastecidos por estes fornecedores, conforme tabela abaixo. Os itens que se encontram abaixo do seu ponto de pedido de compra são:","b":"A 15 − 17 − 10. 11 − 13 − 16 − 17 − 19.","c":"10 − 15 − 17 − 18.","d":"10 − 12 − 14 − 15 − 18.","e":"11 − 13 − 16 − 19.","gabarito":"D","materia":"Administração de Recursos Materiais","tema":"Administração de Estoques ,Sistemas de Controle de Estoques","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q628938","enunciado":"O almoxarifado de um determinado Tribunal Regional Federal movimenta anualmente R$ 200.000,00 em Stock Keeping Unit − SKU’s. Em função de algumas falhas no atendimento das requisições de materiais, foi solicitada pelo gestor do almoxarifado uma classificação “ABC” seguindo novos parâmetros, conforme abaixo. − Curva A: 70% do valor anual do consumo, em R$. − Curva B: 20% do valor anual do consumo, em R$. − Curva C: 10% do valor anual do consumo, em R$. Cada grupo reclassificado em A, B e C compõe-se por um número de SKU’s, no qual cada um representa uma fração do total movimentado no estoque, conforme tabela abaixo.","a":"Após a reclassificação, os grupos A, B e C podem ser representados, respectivamente, por: 20% − 30% − 50%.","b":"50% − 30% − 20%.","c":"70% − 20% − 10%.","d":"20% − 50% − 30%.","e":"50% − 20% − 30%. Direito Administrativo>Lei nº 8.112-1990 - Regime jurídico dos servidores públicos federais ,","gabarito":"A","materia":"Administração de Recursos Materiais","tema":"Administração de Estoques ,Classificação ABC","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1763","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa Dentre as vantagens expressamente previstas na Lei n° 8.112/1990 para os servidores, além dos vencimentos já previstos para remuneração,","a":"a gratificação natalina é a única vantagem que integra os vencimentos para fins de cálculo de outras vantagens e adicionais.","b":"o fato gerador do adicional de insalubridade, em razão de sua distinção, não elide que o servidor perceba também o adicional de periculosidade, mas somente este último pode integrar a remuneração dos servidores.","c":"tanto o adicional de insalubridade, quando o adicional de periculosidade integram a remuneração dos servidores quando configurada habitualidade por tempo superior ao previsto para o estágio probatório definido para o cargo ocupado.","d":"o adicional por serviço extraordinário é obrigatoriamente remunerado com acréscimo em relação à hora normal de trabalho, não admitindo integração à remuneração, em razão de sua natureza indenizatória.","e":"a gratificação natalina não é considerada para fins de cálculo de outras vantagens pecuniárias, mas não afasta o pagamento do adicional de insalubridade ou de periculosidade, cabendo ao servidor, entretanto, optar por um dentre esses últimos.","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q628933","enunciado":"Sobre o provimento de cargos públicos com base na Lei n° 8.112/1990 considere: I. A subscrição do termo de posse pelo servidor ocupante de cargo em comissão dá início a contagem do prazo para o efetivo exercício, que não pode exceder 30 dias, hipótese em que esse período já pode ser considerado para fins remuneratórios. II. Os cargos de provimento por nomeação ensejam posse por parte do servidor público, que se exerce mediante subscrição do respectivo termo, do qual constam os direitos e as responsabilidades inerentes ao cargo, bem como eventuais alterações nos deveres que sejam unilateralmente impostas pela Administração pública. III. Os cargos públicos que dependem de nomeação sujeitam o servidor ao empossamento, cujo prazo não se confunde com o legalmente fixado para o início do exercício, que se dá com o efetivo desempenho das atribuições daquele cargo.","a":"Está correto o que consta em I, II e III.","b":"II e III, apenas.","c":"I, apenas.","d":"III, apenas.","e":"II, apenas. Direito Administrativo>Lei nº 8.112-1990 - Regime jurídico dos servidores públicos federais ,","gabarito":"D","materia":"Direito Administrativo","tema":"Agentes públicos e Lei 8.112 de 1990 ,Provimento e vacância","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1765","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa O descumprimento de deveres e obrigações pode dar ensejo à aplicação de penalidades, devendo ser respeitada a relação entre a natureza e especificidade da sanção e a competência para sua imposição, tal como prevista na Lei n° 8.112/1990, do que é exemplo a penalidade de","a":"suspensão superior a 30 dias, cuja competência para aplicação é privativa da autoridade máxima do ente ao qual esteja vinculado o servidor, qual seja, por exemplo, o Presidente do Tribunal Federal em questão.","b":"suspensão, seja qual for o prazo, em razão da gravidade, privativa da autoridade de hierarquia imediatamente inferior à autoridade máxima do ente ao qual esteja vinculado o servidor, ou seja, por exemplo, Ministro de Estado.","c":"demissão, privativa da autoridade máxima do órgão do ente ao qual esteja vinculado o servidor, ou seja, por exemplo, Ministro de Estado ou Presidente de Tribunal Federal.","d":"cassação de aposentadoria, a ser aplicada pela autoridade máxima do ente ao qual esteja vinculado o servidor, como, por exemplo, o Presidente da República.","e":"cassação de aposentadoria ou suspensão por prazo superior a 30 dias, cuja aplicação é competência privativa da autoridade máxima do ente ao qual esteja vinculado o servidor, ou seja, por exemplo, Ministro de Estado ou Presidente de Tribunal Federal.","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q628931","enunciado":"Arnaldo é servidor público estatutário há cerca de dez anos, classificado no setor de transportes da secretaria da educação e responsável pela logística das peruas que fazem o deslocamento dos alunos no trajeto casa-escola, escola-casa. No último mês, a diretoria da escola e a delegacia de ensino local começaram a receber diversas criticas sobre falhas no serviço de transporte das crianças, a ponto de terem sido narrados episódios de alunos que não foram incluídos no rol de atendimento, não obstante regularmente inscritos para tanto. Diante da recorrência, foi instaurada sindicância para apuração do ocorrido e identificado que Arnaldo não vinha realizando as programações de itinerário corretamente, comparecendo em repartições diversas para trabalhar, não no local correto. Instaurado processo administrativo disciplinar, a comissão disciplinar, no curso do inquérito administrativo, de acordo com o que dispõe a Lei n° 8.112/1990,","a":"deverá providenciar a realização de perícia judicial, para atestar as condições de sanidade mental do acusado antes do prosseguimento do processo.","b":"poderá denegar pedidos de vista dos autos na fase de instrução, inclusive do acusado, tendo em vista que a oportunidade de defesa e contraditório se exerce na fase de defesa.","c":"poderá, com base nos elementos constantes da sindicância, propor que o acusado seja submetido a exame por junta médica oficial, caso exista dúvida sobre a sanidade mental do acusado.","d":"deverá requerer que a sindicância, excepcionalmente, integre os autos do processo administrativo quando houver indícios de insanidade mental, para evitar a repetição de provas e possibilitar que o perito judicial designado administrativamente possa opinar sobre os fatos lá apurados.","e":"poderá processar nos mesmos autos o incidente de sanidade mental, aproveitando a instrução do inquérito, para decidir pela conversão de sanção administrativa por medida de segurança.","gabarito":"C","materia":"Direito Administrativo","tema":"Agentes públicos e Lei 8.112 de 1990 ,Responsabilidades do servidor","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q628930","enunciado":"Janaina inscreveu-se em concurso público para determinado Tribunal. Os vencimentos iniciais eram bastante significativos, o que atraiu grande número de inscritos, sendo que não havia muitos cargos vagos para provimento. Após a divulgação do resultado da 1ª fase, diversos candidatos iniciaram discussões individualizadas, inclusive judiciais, sobre o gabarito, o que alongou por quase 06 meses a convocação para 2ª fase, para a qual Janaina já estava aprovada desde a primeira lista. Realizou-se a segunda fase e novo ciclo de discussões foi iniciado, dessa vez para questionar também as avaliações impostas após a prova oral. Considerando que o número de candidatos da fase seguinte guardava proporcionalidade com número certo de aprovados da fase anterior, a Administração pública aguardava o tanto quanto possível a definitividade das decisões judiciais que impactassem na continuidade do certame. Passados quase dois anos entre o início do concurso e sua conclusão, Janaina, finalmente aprovada e empossada, ajuizou ação judicial para pleitear indenização em face do Poder público pela excessiva demora na realização do certame, baseando-se no valor dos vencimentos previstos para o cargo. Essa medida","a":"é pertinente com o disposto na Constituição Federal, que prevê a responsabilidade objetiva do Estado pela prática de atos ilícitos, tendo em vista que a não nomeação de Janaina se consubstancia em ato administrativo eivado de vício de legalidade.","b":"não possui perspectiva de procedência, tendo em vista que a submissão do concurso ao edital que o disciplina não impede a possibilidade de questionamentos por parte dos candidatos, inexistindo direito consolidado à aprovação, ainda que não tenha havido qualquer irresignação por parte da candidata em questão.","c":"é improcedente, tendo em vista que somente se poderia cogitar do direito à indenização antes da aprovação e da posse da candidata, após o que fica sanada a ilicitude do ato que motivava a responsabilização.","d":"é procedente, tendo em vista que qualquer ato do Poder público pode gerar direito à indenização em razão de responsabilidade objetiva, seja ele lícito ou ilícito, cabendo ao prejudicado pleitear a indenização que, no caso, deve equivaler ao valor dos vencimentos a que faria jus quando nomeado.","e":"depende de comprovação de culpa por parte do Poder público, tendo em vista que diante da imputação de indenização pela prática de atos lícitos, impera a modalidade subjetiva de responsabilidade civil. Direito Constitucional>Direitos Individuais - Remédios Constitucionais e Garantias Processuais ,","gabarito":"B","materia":"Direito Administrativo","tema":"Agentes públicos e Lei 8.112 de 1990 ,Concurso público","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1768","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa Nos termos do art. 5° , LIII, da Constituição Federal, “ninguém será processado nem sentenciado senão pela autoridade competente”.","a":"O dispositivo constitucional citado consagra o princípio do juiz natural.","b":"do contraditório.","c":"da inafastabilidade da jurisdição.","d":"da ampla defesa.","e":"do devido processo legal.","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q628928","enunciado":"Rivanildo, Juiz Federal, conta com quatro anos de exercício no cargo, sendo que há dois anos e meio é titular de Vara. Com a abertura de vaga junto ao respectivo Tribunal Regional Federal, inscreveu-se no concurso de promoção por merecimento. Neste caso, Rivanildo","a":"poderá ser promovido desde que se encontre na primeira quinta parte da lista de antiguidade, ainda que haja, dentre","b":"os inscritos, juiz com mais de cinco anos de exercício no cargo. poderá ser promovido se não houver, dentre os inscritos, Juiz com mais de cinco anos de exercício no cargo.","c":"não poderá ser promovido por ausência de cumprimento de requisito temporal de exercício do cargo.","d":"não poderá ser promovido por ausência de tempo de estágio como Juiz Titular.","e":"poderá ser promovido por contar com tempo de estágio como Juiz Titular, ainda que não integre a primeira quinta parte da lista de antiguidade e concorra contra candidato que possua tal predicamento.","gabarito":"B","materia":"Direito Constitucional","tema":"Tribunais Regionais Federais e Juízes Federais ,Organização do Poder Judiciário","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q628927","enunciado":"Abenebaldo, originariamente holandês, solicitou e obteve a sua naturalização brasileira no ano de 2014. Após o decurso de um mês do encerramento do processo de naturalização, apurou-se que em 2011, em seu país natal, Abenebaldo esteve","a":"comprovadamente envolvido em tráfico ilícito de entorpecentes. Sendo assim, a naturalização será automaticamente cassada, devendo Abenebaldo ser imediatamente extraditado.","b":"a naturalização será automaticamente cassada, devendo Abenebaldo ser imediatamente deportado.","c":"Abenebaldo poderá ser extraditado, vez que o crime ocorreu antes de sua naturalização, o que não seria possível caso","d":"o delito tivesse sido praticado após tal ato. Abenebaldo não poderá ser extraditado, vez que o crime ocorreu antes de sua naturalização.","e":"Abenebaldo poderá ser extraditado, independentemente de o crime ter sido praticado antes ou após a sua naturalização.","gabarito":"E","materia":"Direito Constitucional","tema":"Direitos da Nacionalidade","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q628926","enunciado":"De acordo com a Constituição Federal, o cargo de Advogado-Geral da União, observados limites etários, o notável saber jurídico e a reputação ilibada, comporta provimento através de nomeação pelo Presidente da República, a qual será","a":"precedida de eleição dentre todos os integrantes da carreira de Advogado da União, que formarão lista tríplice","b":"vinculativa. livre, devendo, no entanto, recair em integrante da carreira de Advogado da União.","c":"livre, devendo, no entanto, ser aprovada pelo Senado Federal.","d":"livre, podendo, inclusive, recair em pessoa que não integre a carreira de Advogado da União.","e":"livre, exercendo o titular do cargo mandato por prazo certo e determinado.","gabarito":"D","materia":"Direito Constitucional","tema":"Funções Essenciais à Justiça ,Advocacia Pública","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q628925","enunciado":"","a":"empresa Branca S/A, sociedade de economia mista controlada pela União, no exercício de sua atividade típica, causou dano ambiental que atingiu o Município de Dracena, no interior do Estado de São Paulo, o qual não é sede de Subseção da Justiça Federal. Em virtude de tal dano, o Ministério Público Federal irá propor ação civil pública em face da referida empresa. De acordo com o entendimento do Supremo Tribunal Federal, a ação deverá ser proposta perante a Justiça","b":"A Federal, em razão da qualidade da Ré, controlada pela União. Estadual, do local do dano.","c":"Federal, em razão da qualidade do Autor.","d":"Federal, tanto em razão da qualidade do Autor quanto da Ré.","e":"Federal, em face do presumível interesse da União.","gabarito":"C","materia":"Legislação Federal","tema":"Lei Nº 7.347 de 1985 - Disciplina a Ação Civil Pública","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1773","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa Em uma situação hipotética, a Câmara dos Deputados, por dois terços de seus integrantes, admitiu a acusação contra o Presidente da República por prática de crime de responsabilidade. Ante tal situação, de acordo com a jurisprudência do Supremo Tribunal Federal, o afastamento do Presidente da República do exercício de seu mandato","a":"será automático em virtude da decisão soberana da Câmara dos Deputados, única com atribuição para deflagrar o","b":"processo de impedimento contra o Presidente da República. dependerá da instauração do processo pelo Senado.","c":"dependerá da instauração do processo pelo Supremo Tribunal Federal.","d":"dependerá do resultado do julgamento do processo pelo Senado Federal, por conta do princípio constitucional da presunção de inocência.","e":"dependerá de decisão específica a esse respeito da presidência da Câmara dos Deputados, ratificada pelo Presidente do Senado Federal, vez que o afastamento não decorre do recebimento da acusação, nem da instauração do processo contra o Presidente da República.","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q628923","enunciado":"Uma das classificações das normas constitucionais quanto a sua aplicabilidade foi proposta por José Afonso da Silva. Segundo a classificação desse autor, entende-se por norma constitucional de eficácia contida aquela que possui aplicabilidade","a":"direta e imediata, produzindo de logo todos os seus efeitos, os quais, no entanto, podem ser limitados por outras","b":"normas jurídicas, constitucionais ou infraconstitucionais. direta, imediata e integral, não estando sujeita a qualquer tipo de limitação infraconstitucional.","c":"indireta e mediata, vez depender a sua plena efetividade de regulamentação infraconstitucional.","d":"direta, imediata e integral, competindo ao Poder Público apenas regrar a forma de seu exercício por meio de normas","e":"administrativas infralegais, vedada qualquer limitação. indireta e mediata, vez depender a sua plena efetividade da aplicação de outras normas constitucionais. Administração Financeira e Orçamentária>LC nº 101 de 2000 - Lei de Responsabilidade Fiscal ,","gabarito":"A","materia":"Direito Constitucional","tema":"Teoria da Constituição ,Classificação das Normas Constitucionais","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1775","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa No que se refere à escrituração e consolidação das contas públicas, a Lei de Responsabilidade Fiscal estabelece que","a":"no caso de demonstrações das variações patrimoniais conjuntas, deverão ser excluídas as operações intragovernamentais.","b":"a despesa, a assunção de compromisso e o resultado do fluxo financeiro devem ser registrados pelo regime de competência.","c":"as demonstrações contábeis compreenderão, isolada e conjuntamente, as transações e operações de cada órgão, fundo ou entidade da Administração direta, autárquica e fundacional, excetuando apenas a empresa estatal","d":"dependente. a obrigatoriedade de registros individualizados de recursos vinculados não se estende aos fundos de despesa.","e":"as operações de crédito e inscrições de restos a pagar devem ser escrituradas de forma a evidenciar, pelo menos, o nome e dados pessoais do credor. Administração Financeira e Orçamentária>LC nº 101 de 2000 - Lei de Responsabilidade Fiscal ,","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q628919","enunciado":"Considere: I. Despesa expressamente definida em lei. II. Empenho prévio. III. Dotação própria. IV. Despesa que pode ser submetida ao processo normal de aplicação.","a":"Nos termos da Lei n° 4.320/1964, é regra atinente ao suprimento de fundos o que consta em I, II, III e IV.","b":"I, II e III apenas.","c":"II e III, apenas.","d":"I e IV, apenas.","e":"II, III e IV, apenas. Administração Financeira e Orçamentária>Despesa Pública ,Estágios da Receita e Despesa ,","gabarito":"B","materia":"Administração Financeira e Orçamentária","tema":"Suprimento de Fundos (Regime de Adiantamento)","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1777","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa O TRF da 3ª Região realizou despesa para a aquisição de microcomputadores, tablets e notebooks. As notas de empenho foram emitidas no mês de setembro. Em outubro do mesmo ano foram entregues os microcomputadores. Após essa primeira entrega, o TRF promoveu o pagamento total da despesa. No mês seguinte os demais itens também foram entregues. Esse relato evidencia que houve descumprimento da Lei n° 4.320/1964, uma vez que foi constatada","a":"irregularidade na fase de planejamento da despesa.","b":"nas fases de empenhamento e liquidação da despesa.","c":"na fase de pagamento da despesa.","d":"nas fases de liquidação e pagamento da despesa.","e":"nas fases de empenhamento, liquidação e pagamento da despesa. Administração Financeira e Orçamentária>Programação e Execução Financeira e Orçamentária , Legislação Complementar de AFO ,Programação Orçamentária e Financeira","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1778","enunciado":"Decreto Sobre a Programação Orçamentária e Financeira - Lei 4.320 de 1964 Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","a":"Nos termos da Lei n° 4.320/1964, o repasse de valores destinados a cobrir despesas de custeio de entidades é limitado a instituições públicas ou privadas de caráter assistencial ou cultural, sem fins lucrativos.","b":"é ato contábil classificado como inversão financeira.","c":"é considerado despesa de capital se for destinado a empresas de caráter industrial ou comercial.","d":"pode ter caráter social ou econômico.","e":"somente podem ter caráter econômico se destinado a empresas públicas. Administração Financeira e Orçamentária>Despesa Pública ,Legislação Complementar de AFO ,","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q628916","enunciado":"","a":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa Lei n° 4.320/1964 determina que os créditos adicionais terão vigência adstrita ao exercício financeiro em que forem abertos. Essa regra é absoluta em relação","b":"A ao crédito adicional especial, apenas. ao crédito adicional suplementar, apenas.","c":"ao crédito adicional extraordinário, apenas.","d":"aos créditos adicionais especial e suplementar.","e":"aos créditos adicionais especial e extraordinário. Administração Financeira e Orçamentária>Receita Pública ,Classificação da Receita Orçamentária em AFO ,","gabarito":"B","materia":"Créditos AdicionaisProgramação Orçamentária e Financeira","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q628915","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","a":"No que se refere às receitas públicas, a Lei n° 4.320/1964 estabelece que receita tributária e receita não tributária são espécies de categorias econômicas.","b":"receitas tributária e patrimonial são espécies de receitas de capital.","c":"o superávit do orçamento corrente resultante do balanceamento dos totais das receitas e despesas correntes não constitui item de receita orçamentária.","d":"a receita proveniente da realização de recursos financeiros oriundos de constituição de dívidas é classificada como","e":"receita corrente. a receita advinda de tributo tem seu produto destinado a custear apenas atividades gerais.","gabarito":"C","materia":"Legislação Complementar de AFOProgramação Orçamentária e Financeira","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q628914","enunciado":"Sobre a Lei de Diretrizes Orçamentárias, considere: I. Condições e exigências para transferências de recursos a entidades públicas e privadas. II. Metas anuais, em valores correntes e constantes, relativas a receitas, despesas, resultados nominal e primário e montante da dívida pública, para o exercício a que se referirem e para os dois seguintes. III. Demonstrativo da estimativa e compensação da renúncia de receita. IV. Demonstrativo da margem de expansão das despesas obrigatórias de caráter continuado. V. Passivos contingentes e outros riscos capazes de afetar as contas públicas.","a":"É conteúdo obrigatório da citada lei o que consta em II, IV e V, apenas.","b":"I, II e III, apenas.","c":"II, III, IV e V, apenas.","d":"I, II, III, IV e V.","e":"I, III, IV e V, apenas. Administração Financeira e Orçamentária>Orçamento Público em AFO ,","gabarito":"D","materia":"Administração Financeira e Orçamentária","tema":"Orçamento Público em AFO ,Instrumentos de Planejamento","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q628913","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa No que se refere à matéria orçamentária, considere: I. Concessão ou utilização de créditos ilimitados. II. Realização de despesas ou a assunção de obrigações diretas que excedam os créditos orçamentários ou adicionais. III. Realização de operações de créditos que excedam o montante das despesas correntes. IV. Transferência voluntária de recursos e a concessão de empréstimos, inclusive por antecipação de receita, pelos Governos Federal e Estaduais e suas instituições financeiras, para pagamento de despesas com pessoal ativo, inativo e","a":"pensionista, dos Estados, do Distrito Federal e dos Municípios. Constituição Federal VEDA expressamente o que consta em","b":"A I, II, III e IV. II e IV, apenas.","c":"I, III e IV, apenas.","d":"I, II e III, apenas.","e":"I, II e IV, apenas. Administração Financeira e Orçamentária>Ciclo Orçamentário ,","gabarito":"E","materia":"Finanças Públicas e Orçamento de acordo com a CF/88","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1783","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa Quanto ao processo de elaboração, discussão, votação e aprovação da proposta orçamentária, a Constituição Federal estabelece que","a":"o projeto de lei relativo ao orçamento anual será apreciado pela Câmara dos Deputados, cabendo ao Senado apenas o acompanhamento do atendimento aos limites constitucionais.","b":"uma das fontes de recursos admitida para emendas ao projeto de lei do orçamento anual é a anulação de despesa que incida sobre dotações de pessoal e encargos.","c":"no caso de emendas ao projeto da lei do orçamento anual, somente são admitidas as indicações de recursos advindos de anulação de despesa.","d":"as emendas ao projeto da lei do orçamento anual serão apresentadas ao Presidente da República, responsável por sua apreciação.","e":"em qualquer momento o Presidente da República pode enviar mensagem ao Congresso Nacional para propor modificações no projeto da lei orçamentária anual.","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q628911","enunciado":"Nos termos da Constituição Federal é conteúdo da Lei Orçamentária Anual: I. Orçamento fiscal referente aos fundos da União. II. O orçamento de investimento das empresas em que a União, direta ou indiretamente, detenha a maioria do capital social com direito a voto. III. Autorização para abertura de créditos suplementares. IV. Autorização para contratação de operação de crédito por antecipação de receita. V. Critérios e formas para limitação de empenho.","a":"Está correto o que consta APENAS em I, II, III e IV.","b":"II, III, IV e V.","c":"I, III, IV e V.","d":"I, II, IV e V.","e":"I, II, III e V.","gabarito":"A","materia":"Administração Financeira e Orçamentária","tema":"Orçamento Público em AFO ,Instrumentos de Planejamento","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q628910","enunciado":"Um analista judiciário examinou o orçamento previsto para o Poder Judiciário referente ao exercício de 2015 e verificou que a peça orçamentária abordou aspecto relacionado ao cumprimento do princípio orçamentário da exclusividade. Ele chegou","a":"a essa conclusão porque a peça orçamentária foi elaborada para um período determinado.","b":"autorizou a contratação de operação de crédito.","c":"conteve dotações específicas para despesas com pessoal.","d":"foi autorizada pelo Poder Legislativo.","e":"incluiu todas as receitas e todas as despesas.","gabarito":"B","materia":"Administração Financeira e Orçamentária","tema":"Orçamento Público em AFO ,Princípios Orçamentários","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q628909","enunciado":"Considere que determinada organização tenha optado por agrupar suas atividades concentrando em um mesmo órgão aquelas da mesma natureza ou especialidade, contemplando, por exemplo, departamento de contabilidade, de vendas e de","a":"pessoal. O critério de departamentalização adotado pela referida organização é: o funcional.","b":"por produtos.","c":"por clientela.","d":"o estrutural.","e":"o finalístico.","gabarito":"A","materia":"Administração Geral","tema":"Organizações, Sistemas e Métodos ,Departamentalização","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q628908","enunciado":"Entre as metodologias comumente aplicadas para avaliação de desempenho existe a Avaliação Participativa por Objetivos − APPO e a Avaliação 360° ou circular, que consideram, respectivamente,","a":"processo participativo de escolha de indicadores e metas que serão utilizados na mensuração do resultado; registro","b":"dos aspectos excepcionalmente positivos e negativos do avaliado. escolha binária entre objetivos (metas) estabelecidas pelo avaliador; autoavaliação, avaliação da equipe e da chefia.","c":"estabelecimento consensual de objetivos entre gerentes e subordinados; recebimento de feedbacks (retornos) das pessoas com quem o avaliado se relaciona.","d":"fixação de objetivos, indicadores e metas pela própria equipe avaliada; escolha forçada de respostas constantes de formulário que indica soluções para problemas potenciais.","e":"procedimentos intuitivos para a escolha dos objetivos da organização; entrevistas com os gerentes, visando identificar os fatores que afetam o desempenho dos subordinados.","gabarito":"C","materia":"Gestão de Pessoas","tema":"Aplicando Pessoas ,Avaliação 360 graus","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q628907","enunciado":"Considere que determinada entidade integrante da Administração Indireta pretenda aprimorar seus processos de trabalho, redesenhando e otimizando os processos já padronizados, utilizando os conceitos de BPM − Business Process Management. Nesse contexto, uma das ferramentas disponíveis e consagradas no mercado, que pode ser utilizada para a automação dos","a":"processos de negócios da referida entidade é Diagrama de Pareto.","b":"ERP − Enterprise Resource Planning.","c":"EAP − Estrutura Analítica do Processo.","d":"CPM − Critical Path Method.","e":"PERT − Program Evaluation and Review Technique.","gabarito":"B","materia":"Administração Geral","tema":"Gestão de processos","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q628905","enunciado":"Considere que determinada organização esteja promovendo uma ampla revisão de sua estrutura funcional, redefinindo a configuração, a distribuição e inter-relação dos cargos existentes. No âmbito de tal processo, deve ter-se em mente que: I. A análise de cargos diz respeito aos seus aspectos intrínsecos e consiste em enumerar as tarefas, atribuições e responsabilidades que compõem o cargo. II. A descrição de cargos leva em conta seus aspectos extrínsecos, definindo os requisitos que o cargo impõe a seu ocupante. III. O desenho de cargos, quando adotado o modelo contingencial, leva em conta as variáveis: pessoas, tarefa e estrutura da organização.","a":"Está correto o que consta APENAS em I e II.","b":"III.","c":"I.","d":"II.","e":"II e III. Administração Pública>Plano Diretor de Reforma do Aparelho do Estado – PDRAE ,","gabarito":"B","materia":"Gestão de Pessoas","tema":"Cargos e Salários ,Desenho de Cargos","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1790","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa Sobre os objetivos e características do Plano Diretor da Reforma do Aparelho do Estado, implementado nos anos 1990, no âmbito federal, considere: I. Publicização, que corresponde à assunção, pelo Estado, dos serviços próprios do denominado Núcleo Estratégico. II. Flexibilização, oferecendo aos gestores maior autonomia e estabelecendo o controle e cobrança de resultados a posteriori. III. Desestatização, que compreende a privatização, a terceirização e a desregulamentação.","a":"Está correto o que consta APENAS em I.","b":"I e II.","c":"II.","d":"II e III.","e":"III.","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q628903","enunciado":"As teorias situacionais sobre liderança, diversamente das teorias comportamentais, preconizam que o líder deve agir de acordo com as contingências e situações apresentadas pelo ambiente. Exemplo desta corrente é o denominado Modelo de","a":"Fiedler, que isola três critérios situacionais, entre os quais: poder de posição: poder formal disponível para o líder.","b":"resiliência: resistência a situações adversas.","c":"persuasão: capacidade de convencimento em relação ao grupo.","d":"poder de coesão: fundamental para a condução da equipe.","e":"plasticidade: capacidade de adaptação a diferentes cenários.","gabarito":"A","materia":"Administração Geral","tema":"Gestão Estratégica ,Liderança e Motivação","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q628902","enunciado":"","a":"maturidade no gerenciamento de projetos é aplicável em se tratando de projetos repetitivos ou reiterados, onde o aprendizado oriundo de projetos anteriores e a implantação de inovações sugerem a melhoria das práticas e a sua padronização. Nesse sentido, um dos conceitos aplicados para identificar o grau de maturidade no gerenciamento de projetos é o benchmarking, que corresponde à concentração da supervisão dos projetos no âmbito da gerência da organização, objetivando maior controle e A eficácia.","b":"à adoção de modelos padronizados e testados no mercado para o gerenciamento de projetos comuns, não aplicável,","c":"contudo, em projetos complexos. ao ciclo de melhoria contínua praticado pela organização e representado por etapas de aquisição de conhecimento.","d":"à disseminação dos conceitos de excelência na gestão de projetos no âmbito da organização, através de treinamentos contínuos e avaliações de resultados.","e":"à comparação das práticas e resultados do gerenciamento de projetos verificadas na organização com as existentes em outras organizações de sucesso.","gabarito":"E","materia":"Gerência de Projetos","tema":"Maturidade e Escritório de Gerenciamento de Projetos (EGP)","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q628901","enunciado":"O Balanced Scorecard − BSC corresponde a um modelo de gestão estratégica que alinha missão, visão e estratégia da","a":"organização a um conjunto de indicadores classificados como forças, fraquezas, ameaças e desafios.","b":"divididos entre individuais e corporativos.","c":"que levam em conta, entre outras, a perspectiva dos clientes.","d":"entre os quais predominam os de natureza procedimental.","e":"dos quais se excluem os de natureza estritamente financeira.","gabarito":"C","materia":"Administração Geral","tema":"Gestão Estratégica","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q628900","enunciado":"","a":"aplicação das diferentes metodologias de avaliação de desempenho pode apresentar falhas, na maioria das vezes decorrentes de erros e distorções cometidos pelo avaliador. Uma dessas falhas é conhecida como efeito Halo, que corresponde a A generalização, nivelando o julgamento de uma pessoa a partir de um aspecto (quesito) do desempenho avaliado.","b":"pré-julgamento, partindo de premissas como formação acadêmica e experiências anteriores para a formação do julgamento sobre determinada pessoa.","c":"horizontalização da avaliação, sem levar em conta as sinergias que os diversos aspectos avaliados devem representar","d":"no resultado final. formalismo exacerbado, decorrente da aplicação de conceitos técnicos, dissociados da realidade da organização.","e":"mimetismo, decorrente da não padronização da avaliação e excesso de “customização” em função das peculiaridades de cada organização.","gabarito":"A","materia":"Gestão de Pessoas","tema":"Aplicando Pessoas ,Controle e Avaliação","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q628899","enunciado":"Considere que, em uma abordagem acerca da motivação verificada em determinado ambiente de trabalho, um dos","a":"aspectos considerados sejam os denominados fatores de higiene. Referida abordagem diz respeito à Teoria Bifatorial, preconizada por Herzberg, na qual tais fatores são insatisfacentes, ou seja, previnem a insatisfação.","b":"X e Y, de Macgregor, que sustenta a concepção negativa da natureza humana, segundo a qual o homem precisa ser","c":"forçado a trabalhar. da Hierarquia das Necessidades Humanas, criada por Maslow, que aloca tais fatores no topo da pirâmide.","d":"ERC, defendida por Clayton Alderfer, fundada no reforço positivo e negativo dos comportamentos padrão.","e":"das Necessidades Adquiridas, defendida por Mcclelland, na qual o principal fator a ser considerado é a recompensa envolvida em determinada ação. Administração Geral>Abordagem Comportamental da Administração ,","gabarito":"A","materia":"Administração Geral","tema":"Gestão Estratégica ,Liderança e Motivação","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1796","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa Cultura e clima organizacional são conceitos fortemente imbricados entre si, o que não impede, contudo, a identificação de","a":"elementos e aspectos próprios de cada um deles. Nesse sentido, a literatura enfatiza que uma das funções do clima organizacional é gerar senso de identidade aos membros da organização.","b":"a cultura organizacional retrata o grau de identificação e satisfação do indivíduo com os valores perseguidos pela organização.","c":"o clima organizacional é verificado no âmbito psicológico de cada colaborador, enquanto a cultura organizacional corresponde à percepção coletiva de aspectos materiais e emocionais.","d":"a cultura organizacional diz respeito, exclusivamente, a aspectos tangíveis da instituição e, portanto, claramente identificados e praticados.","e":"o clima organizacional está relacionado diretamente com o grau de satisfação dos membros da organização e influencia a produtividade.","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q628897","enunciado":"Atualmente, o processo de gestão estratégica de pessoas tem como um dos principais objetivos sustentar o caminho das organizações na direção da visão, missão, objetivos estratégicos e valores organizacionais. Verifica-se, portanto, uma significativa mudança (na gestão de pessoas), passando de uma abordagem tradicional e operacional para uma abordagem","a":"moderna e estratégica. É exemplo desse movimento: Aversão à instabilidade, com a adoção de normas pré-estabelecidas de promoção e desligamento.","b":"Ênfase na eficiência, abandonando o conceito de eficácia, este que é próprio do modelo operacional.","c":"Concentração, na área responsável pela gestão de RH, das atividades de recrutamento e administração de pessoal.","d":"Responsabilidade de linha, sendo cada gestor responsável pelos recursos humanos alocados em seu departamento.","e":"Função de staff, consistente no suporte que todos os gestores devem proporcionar à área de RH, no processo de alinhamento organizacional.","gabarito":"D","materia":"Gestão de Pessoas","tema":"Estratégias de Recursos Humanos ,Visão Geral da área de RH na organização","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q628895","enunciado":"","a":"... respeito do crime de advocacia administrativa, considere: I. Caracteriza-se mesmo que o interesse privado patrocinado seja legítimo. II. Não se caracteriza se o patrocínio for feito por terceira pessoa que apareça como procurador. III. Só pode ser cometido por advogado. Está correto o que consta APENAS em","b":"A I e II. I.","c":"I e III.","d":"II e III.","e":"III.","gabarito":"B","materia":"Direito Penal","tema":"Crimes contra a administração pública ,Advocacia administrativa","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","concurso":"TRF3"},{"id":"Q628887","enunciado":"... Seja A o quociente da divisão de 8 por 3. Seja B o quociente da divisão de 15 por 7. Seja C o quociente da divisão de 14 por 22.","a":"O produto A . B . C é igual a 3,072072072 . . .","b":"3,636363 . . .","c":"3,121212 . . .","d":"3,252525 . . .","e":"3,111 . . .","gabarito":"B","materia":"Matemática","tema":"Aritmética e Problemas ,Números Primos e Divisibilidade","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","concurso":"TRF3"},{"id":"Q628886","enunciado":"","a":"... diferença entre o 12° e o 13°, nessa ordem, termos da sequência lógica matemática (20; 20; 15; 30; 20; 60; 40; 160; 120; 600; 520; ...) é igual a","b":"A 220. −80.","c":"160.","d":"−120.","e":"1200.","gabarito":"C","materia":"Raciocínio Lógico","tema":"Sequências Lógicas de Números, Letras, Palavras e Figuras","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","concurso":"TRF3"},{"id":"Q628885","enunciado":"... Uma herança de R$ 82.000,00 será repartida de modo inversamente proporcional às idades, em anos completos, dos três herdeiros. As idades dos herdeiros são: 2, 3 e x anos. Sabe-se que os números que correspondem às idades dos herdeiros são números primos entre si (o maior divisor comum dos três números é o número 1) e que foi R$ 42.000,00 a parte da","a":"herança que o herdeiro com 2 anos recebeu. A partir dessas informações o valor de x é igual a 7.","b":"5.","c":"11.","d":"1.","e":"13.","gabarito":"A","materia":"Matemática","tema":"Aritmética e Problemas ,Razão e Proporção; e Números Proporcionais","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","concurso":"TRF3"},{"id":"Q628883","enunciado":"... Considere verdadeiras as afirmações abaixo. I. Todos os analistas que são advogados, são contadores também. II. Nem todos os contadores que são advogados, são analistas também. III. Há advogados que são apenas advogados e isso também acontece com alguns analistas, mas não acontece com","a":"qualquer um dos contadores. partir dessas afirmações, é possível concluir corretamente que","b":"A todo analista é advogado e é também contador. qualquer contador que seja analista é advogado também.","c":"existe analista que é advogado e não é contador.","d":"todo contador que é advogado é também analista.","e":"existe analista que não é advogado e existe contador que é analista.","gabarito":"E","materia":"Raciocínio Lógico","tema":"Diagramas de Venn (Conjuntos)","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","concurso":"TRF3"},{"id":"Q628882","enunciado":"... Considere verdadeiras as afirmações abaixo. I. Ou Bruno é médico, ou Carlos não é engenheiro. II. Se Durval é administrador, então Eliane não é secretária. III. Se Bruno é médico, então Eliane é secretária.","a":"IV. Carlos é engenheiro. partir dessas afirmações, pode-se concluir corretamente que","b":"A Eliane não é secretária e Durval não é administrador. Bruno não é médico ou Durval é administrador.","c":"se Eliane não é secretária, então Bruno não é médico.","d":"Carlos é engenheiro e Eliane não é secretária.","e":"se Carlos é engenheiro, então Eliane não é secretária.","gabarito":"C","materia":"Raciocínio Lógico","tema":"Lógica de Argumentação - Diagramas e Operadores Lógicos","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","concurso":"TRF3"},{"id":"Q628881","enunciado":"","a":"respeito da concordância verbal, é correto afirmar: Em \"A aquisição de novas obras devem trazer benefícios a todos os frequentadores\", a concordância está correta por A se tratar de expressão partitiva.","b":"Em \"Existe atualmente, no Brasil, cerca de 60 museus\", a concordância está correta, uma vez que o núcleo do sujeito é \"cerca\".","c":"Na frase \"Hão de se garantir as condições necessárias à conservação das obras de arte\", o verbo \"haver\" deveria estar no singular, uma vez que é impessoal.","d":"Em \"Acredita-se que 25% da população frequentem ambientes culturais\", a concordância está correta, uma vez que a porcentagem é o núcleo do segmento nominal.","e":"Na frase \"A maioria das pessoas não frequentam o museu\", o verbo encontra-se no plural por concordar com \"pessoas\", ainda que pudesse, no singular, concordar com \"maioria\".","gabarito":"E","materia":"Português","tema":"Sintaxe ,Concordância verbal, Concordância nominal","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q628880","enunciado":"O museu é considerado um instrumento de neutralização – e talvez o seja de fato. Os objetos que nele se encontram reunidos trazem o testemunho de disputas sociais, de conflitos políticos e religiosos. Muitas obras antigas celebram vitórias militares e conquistas: a maior parte presta homenagem às potências dominantes, suas financiadoras. As obras modernas são, mais genericamente, animadas pelo espírito crítico: elas protestam contra os fatos da realidade, os poderes, o estado das coisas. O museu reúne todas essas manifestações de sentido oposto. Expõe tudo junto em nome de um valor que se presume partilhado por elas: a qualidade artística. Suas diferenças funcionais, suas divergências políticas são apagadas. A violência de que participavam, ou que combatiam, é esquecida. O museu parece assim desempenhar um papel de pacificação social. A guerra das imagens extingue-se na pacificação dos museus. Todos os objetos reunidos ali têm como princípio o fato de terem sido retirados de seu contexto. Desde então, dois pontos de vista concorrentes são possíveis. De acordo com o primeiro, o museu é por excelência o lugar de advento da Arte enquanto tal, separada de seus pretextos, libertada de suas sujeições. Para o segundo, e pela mesma razão, é um \"depósito de despojos\". Por um lado, o museu facilita o acesso das obras a um status estético que as exalta. Por outro, as reduz a um destino igualmente","a":"estético, mas, desta vez, concebido como um estado letárgico. colocação em museu foi descrita e denunciada frequentemente como uma desvitalização do simbólico, e a musealização progressiva dos objetos de uso como outros tantos escândalos sucessivos. Ainda seria preciso perguntar sobre a razão do \"escândalo\". Para que haja escândalo, é necessário que tenha havido atentado ao sagrado. Diante de cada crítica escandalizada dirigida ao museu, seria interessante desvendar que valor foi previamente sacralizado. A Religião? A Arte? A singularidade absoluta da obra? A Revolta? A Vida autêntica? A integridade do Contexto original? Estranha inversão de perspectiva. Porque, simultaneamente, a crítica mais comum contra o museu apresenta-o como sendo, ele próprio, um órgão de sacralização. O museu, por retirar as obras de sua origem, é realmente \"o lugar simbólico onde o trabalho de abstração assume seu caráter mais violento e mais ultrajante\". Porém, esse trabalho de abstração e esse efeito de alienação operam em toda parte. É a ação do tempo, conjugada com nossa ilusão da presença mantida e da arte conservada. (Adaptado de: GALARD, Jean. Beleza Exorbitante. São Paulo, Fap.-Unifesp, 2012, p. 68-71) Na frase Diante de cada crítica escandalizada dirigida ao museu, seria interessante desvendar que valor foi previamente sacralizado (3°parágrafo), a oração sublinhada complementa o sentido de","b":"A um substantivo, e pode ser considerada como interrogativa indireta. um verbo, e pode ser considerada como interrogativa direta.","c":"um verbo, e pode ser considerada como interrogativa indireta.","d":"um substantivo, e pode ser considerada como interrogativa direta.","e":"um advérbio, e pode ser considerada como interrogativa indireta.","gabarito":"C","materia":"Português","tema":"Sintaxe ,Análise sintática","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q628879","enunciado":"","a":"frase que NÃO admite transposição para a voz passiva encontra-se em:","b":"A ... o acesso das obras a um status estético que as exalta. (2° parágrafo) ... elas protestam contra os fatos da realidade, os poderes... (1°parágrafo)","c":"Muitas obras antigas celebram vitórias militares e conquistas... (1°parágrafo)","d":"O museu, por retirar as obras de sua origem... (3° parágrafo)","e":"... a crítica mais comum contra o museu apresenta-o... (3° parágrafo)","gabarito":"B","materia":"Português","tema":"Morfologia - Verbos ,Flexão de voz (ativa, passiva, reflexiva)","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q628878","enunciado":"... suas financiadoras (1° parágrafo) Suas diferenças funcionais... (1°parágrafo) ... seu caráter mais violento... (3° parágrafo)","a":"Os pronomes dos trechos acima referem-se, respectivamente, a: vitórias militares − manifestações − museu","b":"vitórias militares − obras modernas − museu","c":"potências dominantes − obras modernas − trabalho de abstração","d":"potências dominantes − manifestações − trabalho de abstração","e":"potências dominantes − obras modernas − museu","gabarito":"D","materia":"Português","tema":"Morfologia - Pronomes ,Pronomes possessivos","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q628877","enunciado":"Atente para as afirmativas abaixo. I. Em ... presta homenagem às potências dominantes... (1° parágrafo), o sinal indicativo de crase pode ser suprimido excluindo- se também o artigo definido, sem prejuízo para a correção. II. O acento em \"têm\" (2° parágrafo) é de caráter diferencial, em razão da semelhança com a forma singular \"tem\", diferentemente do acento aplicado a \"porém\" (3° parágrafo), devido à tonicidade da última sílaba, terminada em \"em\". III. Os acentos nos termos \"excelência\" (2° parágrafo) e \"necessário\" (3° parágrafo) devem-se à mesma razão.","a":"Está correto o que consta em I, II e III.","b":"I, apenas.","c":"I e III, apenas.","d":"II, apenas.","e":"II e III, apenas. Português>Interpretação de Textos ,Redação - Reescritura de texto ,Sintaxe","gabarito":"A","materia":"Português","tema":"Ortografia ,Crase ,Acentuação Gráfica: Proparoxítonas, Paroxítonas, Oxítonas e Hiatos","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q628875","enunciado":"De acordo com o texto,","a":"o museu, enquanto depósito de despojos, confere destaque às características estéticas das obras, uma vez que apaga seu contexto social de produção.","b":"o caráter antagônico dos museus pode ser expresso por dois pontos de vista: o da neutralização das obras modernas e o da evidenciação das lutas políticas nas obras antigas.","c":"a crítica ao museu como um lugar que desmistifica a arte traz em seu bojo uma contradição, pois as acusações mais comuns lhe imputavam o mais das vezes a sacralização das obras.","d":"o contexto original das obras, restaurado pelos museus, não oblitera as razões sociopolíticas que as engendraram, o que costuma ser motivo de crítica a essas instituições.","e":"a junção das mais diversas obras de arte evidencia os conflitos políticos que as motivaram e que opõem diferentes matrizes estéticas, de modo que a função pacificadora dos museus pode ser questionada.","gabarito":"C","materia":"Português","tema":"Interpretação de Textos ,Noções Gerais de Compreensão e Interpretação de Texto","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q628873","enunciado":"Estava mal chegando a São Paulo, quando um repórter me provocou: \"Mas como, Chico, mais um samba? Você não acha que isso já está superado?\" Não tive tempo de me defender ou de atacar os outros, coisa que anda muito em voga. Já era hora de enfrentar o dragão, como diz o Tom, enfrentar as luzes, os cartazes, e a plateia, onde distingui um caro colega regendo um coro pra frente, de franca oposição. Fiquei um pouco desconcertado pela atitude do meu amigo, um homem sabidamente isento de preconceitos. Foi-se o tempo em que ele me censurava amargamente, numa roda revolucionária, pelo meu desinteresse em participar de uma passeata cívica contra a guitarra elétrica. Nunca tive nada contra esse instrumento, como nada tenho contra o tamborim. O importante é Mutantes e Martinho da Vila no mesmo palco. Mas, como eu ia dizendo, estava voltando da Europa e de sua música estereotipada, onde samba, toada etc. são ritmos virgens para seus melhores músicos, indecifráveis para seus cérebros eletrônicos. \"Só tenho uma opção, confessou-me um italiano − sangue novo ou a antimúsica. Veja, os Beatles, foram à Índia...\" Donde se conclui como precipitada a opinião, entre nós, de que estaria morto o nosso ritmo, o lirismo e a malícia, a malemolência. É certo que se deve romper com as estruturas. Mas a música brasileira, ao contrário de outras artes, já traz dentro de si os elementos de renovação. Não se trata de defender a tradição, família ou propriedade de ninguém. Mas foi com o samba que João Gilberto rompeu as estruturas da nossa canção. E se o rompimento não foi universal, culpa é do brasileiro, que não tem vocação pra exportar coisa alguma. Quanto a festival, acho justo que estejam todos ansiosos por um primeiro prêmio. Mas não é bom usar de qualquer recurso, nem se deve correr com estrondo atrás do sucesso, senão ele se assusta e foge logo. E não precisa dar muito tempo para se perceber \"que nem toda loucura é genial, como nem toda lucidez é velha\". (Adaptado de: HOLANDA, Chico Buarque de, apud Adélia B. de Menezes, Desenho Mágico: Poesia e Política em Chico Buarque, São Paulo, Ateliê, 2002, p. 28-29)","a":"O verbo que pode ser indiferentemente flexionado no singular ou no plural encontra-se em: ... enfrentar as luzes, os cartazes, e a plateia... (1° parágrafo)","b":"Mas a música brasileira, ao contrário de outras artes, já traz dentro de si os elementos de renovação. (2° parágrafo)","c":"Veja, os Beatles, foram à Índia... (2° parágrafo)","d":"O importante é Mutantes e Martinho da Vila no mesmo palco. (1°parágrafo)","e":"... onde samba, toada etc. são ritmos virgens para seus melhores músicos... (2° parágrafo)","gabarito":"D","materia":"Português","tema":"Morfologia - Verbos ,Flexão verbal de número (singular, plural)","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q628872","enunciado":"Estava mal chegando a São Paulo, quando um repórter me provocou: \"Mas como, Chico, mais um samba? Você não acha que isso já está superado?\" Não tive tempo de me defender ou de atacar os outros, coisa que anda muito em voga. Já era hora de enfrentar o dragão, como diz o Tom, enfrentar as luzes, os cartazes, e a plateia, onde distingui um caro colega regendo um coro pra frente, de franca oposição. Fiquei um pouco desconcertado pela atitude do meu amigo, um homem sabidamente isento de preconceitos. Foi-se o tempo em que ele me censurava amargamente, numa roda revolucionária, pelo meu desinteresse em participar de uma passeata cívica contra a guitarra elétrica. Nunca tive nada contra esse instrumento, como nada tenho contra o tamborim. O importante é Mutantes e Martinho da Vila no mesmo palco. Mas, como eu ia dizendo, estava voltando da Europa e de sua música estereotipada, onde samba, toada etc. são ritmos virgens para seus melhores músicos, indecifráveis para seus cérebros eletrônicos. \"Só tenho uma opção, confessou-me um italiano − sangue novo ou a antimúsica. Veja, os Beatles, foram à Índia...\" Donde se conclui como precipitada a opinião, entre nós, de que estaria morto o nosso ritmo, o lirismo e a malícia, a malemolência. É certo que se deve romper com as estruturas. Mas a música brasileira, ao contrário de outras artes, já traz dentro de si os elementos de renovação. Não se trata de defender a tradição, família ou propriedade de ninguém. Mas foi com o samba que João Gilberto rompeu as estruturas da nossa canção. E se o rompimento não foi universal, culpa é do brasileiro, que não tem vocação pra exportar coisa alguma. Quanto a festival, acho justo que estejam todos ansiosos por um primeiro prêmio. Mas não é bom usar de qualquer recurso, nem se deve correr com estrondo atrás do sucesso, senão ele se assusta e foge logo. E não precisa dar muito tempo para se perceber \"que nem toda loucura é genial, como nem toda lucidez é velha\". (Adaptado de: HOLANDA, Chico Buarque de, apud Adélia B. de Menezes, Desenho Mágico: Poesia e Política em Chico Buarque, São Paulo, Ateliê, 2002, p. 28-29) Estava mal chegando a São Paulo, quando um repórter me provocou: \"Mas como, Chico, mais um samba? Você não acha que isso já está superado?\" (1° parágrafo) Mantendo-se, em linhas gerais, o sentido original, o trecho acima está corretamente reescrito, em um único período, em:","a":"Cheguei a São Paulo quando um repórter, questionando-me por que mais um samba – se eu não achava que isso já estava superado –, provocou-me.","b":"Quando um repórter, recém-chegando a São Paulo, provocou-me questionando porque mais um samba e se eu não acharia que isso já estaria superado.","c":"Quando um repórter me provocou e me questionou: por que mais um samba e se eu não acho que isso já está superado?","d":"Chegando a São Paulo, um repórter me provocou ao questionar-me por que eu iria escrever mais um samba e se eu não achava que isso já estivesse superado.","e":"Recém-chegado a São Paulo, fui provocado por um repórter, que me questionava por que mais um samba e se eu não achava que isso já estava superado.","gabarito":"E","materia":"Português","tema":"Interpretação de Textos ,Redação - Reescritura de texto","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q628871","enunciado":"... Considere as afirmativas abaixo. I. O termo \"coisa\" (1° parágrafo) pode ser substituído por \"o\" com função de pronome, uma vez que, no período, retoma o segmento que o antecede. II. As orações \"de atacar os outros\" (1° parágrafo) e \"de defender a tradição\" (2° parágrafo) servem de complemento ao sentido do verbo a que se referem. III. Na frase Mas foi com o samba que João Gilberto rompeu... (2°parágrafo), o pronome \"que\" retoma \"samba\", além de ser elemento subordinante a introduzir uma nova oração.","a":"Está correto o que consta de II e III, apenas.","b":"I, II e III.","c":"I e II, apenas.","d":"I, apenas.","e":"III, apenas. Português>Interpretação de Textos ,Significação Contextual de Palavras e Expressões. Sinônimos e Antônimos. ,","gabarito":"D","materia":"Português","tema":"Morfologia - Pronomes ,Pronomes relativos","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","concurso":"TRF3"},{"id":"TRF3_1813","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Prova: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa No segmento ... nem se deve correr com estrondo atrás do sucesso, senão ele se assusta e foge logo (3° parágrafo), o termo","a":"sublinhado pode ser substituído, mantendo-se a lógica e o sentido original, por: exceto se","b":"salvo","c":"do contrário","d":"não obstante","e":"por mais que","gabarito":"","materia":"Geral","tema":"","origem":"FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q628869","enunciado":"...","a":"Sem prejuízo para a correção e o sentido, pode-se acrescentar uma vírgula imediatamente após o termo \"E\", em E se o rompimento não foi universal... (2° parágrafo)","b":"\"Mas\", em Mas não é bom usar de qualquer recurso... (3° parágrafo)","c":"\"e\", em ... se assusta e foge logo (3° parágrafo)","d":"\"Mas\", em Mas foi com o samba que João Gilberto... (2° parágrafo)","e":"\"Mas\", em Mas como, Chico, mais um samba? (1° parágrafo)","gabarito":"A","materia":"Português","tema":"Pontuação ,Uso da Vírgula","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","concurso":"TRF3"},{"id":"Q628868","enunciado":"... Depreende-se da frase ... nem toda loucura é genial, como nem toda lucidez é velha que","a":"a loucura, o mais das vezes, é vista como uma característica que marca a singularidade, enquanto a lucidez é um atributo costumeiro da velhice.","b":"essas duas características, lucidez e loucura, devem ser vistas com reserva, uma vez que a fronteira entre ambas nem sempre é clara.","c":"as inovações, por mais lúcidas que sejam, devem algo à loucura, pois é mediante o abandono da causalidade natural","d":"que se obtém algo inusitado. ambas as características podem conviver em obras de arte de vanguarda, uma vez que não são conflitantes.","e":"a genialidade pode ter algo de lucidez, embora, para que isso ocorra, tenha de negar a loucura, podendo ocorrer o inverso, o que caracteriza essencialmente a inovação.","gabarito":"A","materia":"Português","tema":"Interpretação de Textos ,Noções Gerais de Compreensão e Interpretação de Texto","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","concurso":"TRF3"},{"id":"Q628867","enunciado":"... De acordo com o texto,","a":"o convívio harmônico entre as mais variadas tendências é característica encontrada não apenas em nossa música, mas também em artistas europeus.","b":"muito embora o samba seja parte da nova música, o que caracteriza essencialmente sua originalidade se deve à influência externa.","c":"se os elementos novos na música não devem ser descartados peremptoriamente, tampouco a grande inovação menospreza o que a precede.","d":"foi a partir do exemplo estrangeiro que João Gilberto soube revolucionar a música brasileira, ainda que os elementos para tanto sejam essencialmente locais.","e":"há uma nítida diferença entre a música brasileira e a europeia, já que aquela se caracteriza, ao contrário desta, por uma ausência de diálogo com a tradição.","gabarito":"C","materia":"Português","tema":"Interpretação de Textos ,Noções Gerais de Compreensão e Interpretação de Texto","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","concurso":"TRF3"},{"id":"Q628866","enunciado":"... Depois que se tinha fartado de ouro, o mundo teve fome de açúcar, mas o açúcar consumia escravos. O esgotamento das minas − que de resto foi precedido pelo das florestas que forneciam o combustível para os fornos −, a abolição da escravatura e, finalmente, uma procura mundial crescente, orientam São Paulo e o seu porto de Santos para o café. De amarelo, passando pelo branco, o ouro tornou-se negro. Mas, apesar de terem ocorrido essas transformações que tornaram Santos num dos centros do comércio internacional, o local conserva uma beleza secreta; à medida que o barco penetra lentamente por entre as ilhas, experimento aqui o primeiro sobressalto dos trópicos. Estamos encerrados num canal verdejante. Quase podíamos, só com estender a mão, agarrar essas plantas que o Rio ainda mantinha à distância nas suas estufas empoleiradas lá no alto. Aqui se estabelece, num palco mais modesto, o contato com a paisagem. O arrabalde de Santos, uma planície inundada, crivada de lagoas e pântanos, entrecortada por riachos estreitos e canais, cujos contornos são perpetuamente esbatidos por uma bruma nacarada, assemelha-se à própria Terra, emergindo no começo da criação. As plantações de bananeiras que a cobrem são do verde mais jovem e terno que se possa imaginar: mais agudo que o ouro verde dos campos de juta no delta do Bramaputra, com o qual gosto de o associar na minha recordação; mas é que a própria fragilidade do matiz, a sua gracilidade inquieta, comparada com a suntuosidade tranquila da outra, contribuem para criar uma atmosfera primordial. Durante cerca de meia hora, rolamos por entre bananeiras, mais plantas mastodontes do que árvores anãs, com troncos plenos de seiva que terminam numa girândola de folhas elásticas por sobre uma mão de 100 dedos que sai de um enorme lótus castanho e rosado. A seguir, a estrada eleva-se até os 800 metros de altitude, o cume da serra. Como acontece em toda parte nessa costa, escarpas abruptas protegeram dos ataques do homem essa floresta virgem tão rica que para encontrarmos igual a ela teríamos de percorrer vários milhares de quilômetros para norte, junto da bacia amazônica. Enquanto o carro geme em curvas que já nem poderíamos qualificar como “cabeças de alfinete”, de tal modo se sucedem em espiral, por entre um nevoeiro que imita a alta montanha de outros climas, posso examinar à vontade as árvores e as plantas estendendo-se perante o meu olhar como espécimes de museu. (Adaptado de: LÉVI-STRAUSS, Claude. Tristes Trópicos. Coimbra, Edições 70, 1979, p. 82-3) As orações reduzidas ... para encontrarmos igual a ela... (4° parágrafo) e ... estendendo-se perante o meu olhar... (último","a":"parágrafo), no contexto em que ocorrem, podem ser distendidas da seguinte forma: para que tivéssemos encontrado igual a ela / de modo que se estendem perante o meu olhar.","b":"para que encontremos igual a ela / as quais se estendem perante o meu olhar","c":"para que encontrássemos igual a ela / que se estendem perante o meu olhar","d":"para que encontrássemos igual a ela / quando se estendem perante o meu olhar","e":"para que encontremos igual a ela / desde que se estendam perante o meu olhar","gabarito":"C","materia":"Português","tema":"Sintaxe ,Orações subordinadas reduzidas","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","concurso":"TRF3"},{"id":"Q628865","enunciado":"... Uma redação alternativa para o segmento ... mas é que a própria fragilidade do matiz, a sua gracilidade inquieta, comparada com a suntuosidade tranquila da outra, contribuem para criar uma atmosfera primordial (3° parágrafo), sem prejuízo da correção e do sentido, está em:","a":"conquanto seja a fragilidade mesma do colorido, aliada à graciosidade fugaz, em contraposição à riqueza consolidada da outra, que contribui para a formação de um clima primaz.","b":"não obstante a própria instabilidade da coloração, à sua gratuidade pode-se comparar o fausto despreocupado da outra, que contribui para instaurar um ambiente primevo.","c":"todavia, é devido à própria fragilidade do tom − à sua graciosidade irrequieta − posta em paralelo com o fausto inabalável da outra, que contribui para inventar um ambiente primordial.","d":"mas é, no entanto, a própria delicadeza do matiz, sua gratuidade inconstante, que, comparada ao luxo estável da outra, contribui para a conformação de um meio ambiente ancestral.","e":"é, todavia, porque a própria fragilidade da coloração e a sua graciosidade instável, comparada ao fausto tranquilo da outra, contribuem para conformar uma ambientação primitiva.","gabarito":"E","materia":"Português","tema":"Interpretação de Textos ,Redação - Reescritura de texto","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","concurso":"TRF3"},{"id":"Q628864","enunciado":"... As plantações de bananeiras que a cobrem... (3° parágrafo) ... com troncos plenos de seiva que terminam numa girândola de folhas... (4° parágrafo) ... que sai de um enorme lótus castanho e rosado... (4° parágrafo)","a":"Os pronomes sublinhados referem-se respectivamente a: bruma − seiva − mão","b":"planície − troncos − mão","c":"planície − troncos − dedos","d":"Terra − seiva − mão","e":"bruma − troncos − dedos Português>Sintaxe ,","gabarito":"B","materia":"Português","tema":"Morfologia - Pronomes ,Pronomes relativos ,Pronomes pessoais oblíquos","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","concurso":"TRF3"},{"id":"TRF3_1820","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","a":"... oração ... de tal modo se sucedem em espiral... (último parágrafo):","b":"A expressa a consequência da oração precedente, além de introduzir matiz de intensidade. além de introduzir a causa da oração anterior, expressa certo grau de intensidade.","c":"além de introduzir complemento de modo ou instrumento, expressa uma consequência.","d":"expressa condição, aliada a certo grau de proporcionalidade.","e":"expressa concessão, resultante de uma relação de proporcionalidade. Português>Sintaxe ,Concordância verbal, Concordância nominal ,Morfologia - Verbos","gabarito":"","materia":"Geral","tema":"","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","concurso":"TRF3"},{"id":"Q628862","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa ... Mantendo-se a correlação verbal na primeira frase do texto, a substituição de Depois que por “Caso”, acarretará as seguintes","a":"mudanças nas formas verbais: fartasse − terá − iria consumir","b":"fartara − tivera − consumira","c":"teria fartado − teria tido − teria consumido","d":"tenha fartado − terá − consumirá","e":"tivesse fartado − teria − consumiria Português>Sintaxe ,Concordância verbal, Concordância nominal ,Morfologia - Verbos","gabarito":"E","materia":"Flexão verbal de tempo (presente, pretérito, futuro)","tema":"","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","concurso":"TRF3"},{"id":"TRF3_1822","enunciado":"Ano: 2016 Banca: FCC Órgão: TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","a":"... alteração da voz do verbo poder, nas duas vezes em que ocorre no último parágrafo, deverá resultar nas seguintes formas, respectivamente:","b":"A se poderia − se pode poder-se-ia − podem-se","c":"poderiam-se − pode-se","d":"se poderiam − podem-se","e":"se poderiam − se pode","gabarito":"","materia":"Geral","tema":"","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","concurso":"TRF3"},{"id":"Q628860","enunciado":"... Considere as frases abaixo. I. O segmento que se estende de uma planície inundada até uma bruma nacarada (3° parágrafo) constitui explicação do termo antecedente, de maneira que poderia ser iniciado por “que é”, sem prejuízo para o sentido. II. Neste mesmo segmento, as vírgulas poderiam ser substituídas por ponto-e-vírgulas, uma vez que se trata de uma sequência de características atribuídas a um mesmo termo. III. No mesmo período, a oração iniciada por emergindo pode tanto subordinar-se a assemelha-se como a Terra.","a":"Está correto o que consta em III, apenas.","b":"I, II e III.","c":"I e II, apenas.","d":"I e III, apenas.","e":"II, apenas.","gabarito":"D","materia":"Português","tema":"Pontuação ,Uso da Vírgula ,Uso do ponto e vírgulaSintaxe ,Análise sintática","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","concurso":"TRF3"},{"id":"Q628859","enunciado":"... No primeiro período do segundo parágrafo, as duas orações que não se subordinam a nenhuma outra contêm os seguintes","a":"verbos: conserva − experimento","b":"terem ocorrido − conserva","c":"tornaram − penetra","d":"tornaram − experimento","e":"conserva − penetra","gabarito":"A","materia":"Português","tema":"Sintaxe ,Análise sintática","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","concurso":"TRF3"},{"id":"Q628858","enunciado":"... Em relação à primeira parte da frase, o segmento ... orientam São Paulo e o seu porto de Santos para o café (1° parágrafo)","a":"expressa: finalidade.","b":"causa.","c":"decorrência.","d":"conformidade.","e":"proporcionalidade.","gabarito":"C","materia":"Português","tema":"Sintaxe ,Análise sintática","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","concurso":"TRF3"},{"id":"Q628857","enunciado":"... O excerto, que narra a passagem de Lévi-Strauss por Santos, rumo a São Paulo,","a":"representa com minúcia uma natureza que foi preservada graças ao desenvolvimento de Santos, impulsionado pelo cultivo do café.","b":"descreve a natureza pujante da região, a despeito de seu desenvolvimento econômico, a ponto de recorrer a imagens de cunho religioso para melhor ilustrar seu ponto de vista.","c":"tece juízo de valor a respeito do desenvolvimento econômico do Brasil, tendo como pano de fundo sua riqueza natural inexplorada.","d":"compara a natureza litorânea de Santos à encontradiça junto ao leito do rio Bramaputra, com vistas a mostrar, paralelamente, o quão luxuriante é a natureza brasileira.","e":"lamenta o comércio que teria destruído praticamente toda a beleza natural, reduzindo-a a pequenos e secretos lugares, observáveis apenas em expedições como a que conduzia.","gabarito":"B","materia":"Português","tema":"Interpretação de Textos ,Noções Gerais de Compreensão e Interpretação de Texto","origem":"","ano":"2016","banca":"FCC Ó","orgao":"TRF - 3ª REGIÃO Provas: FCC - 2016 - TRF - 3ª REGIÃO - Analista Judiciário - Área Administrativa","concurso":"TRF3"},{"id":"Q625142","enunciado":"Substituto Assinale a alternativa incorreta:","a":"Realizando-se o casamento no exterior, pela autoridade estrangeira, será aplicada a lei do local da celebração com relação aos impedimentos dirimentes e às formalidades.","b":"O casamento de um brasileiro, domiciliado ou não no exterior, celebrado perante a autoridade consular brasileira, submete-se ao direito brasileiro, constituindo-se exceção à regra da “lex loci celebrationis”.","c":"Somente se os nubentes forem estrangeiros poderão celebrar o casamento no Brasil perante o cônsul do país de ambos, segundo a lei do Estado da autoridade celebrante, configurando-se exceção à regra da “lex loci celebrationis”.","d":"O casamento celebrado no exterior, observadas todas as regras do direito local estrangeiro, será sempre válido no Brasil. Direitos Humanos>Sistema Global de Proteção dos Direitos Humanos: Instituições e Mecanismos , Sistema Interamericano de Proteção aos Direitos Humanos: Instituições , Corte Interamericana de Direitos HumanosDireitos Humanos no Ordenamento Nacional ,","e":"","gabarito":"D","materia":"Direito Civil","tema":"Lei de Introdução às Normas do Direito Brasileiro (LINDB)","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1828","enunciado":"Incidente de Deslocamento de Competência - Federalização dos Crimes Graves contra os Direitos Humanos , Estatuto de Roma e o Tribunal Penal Internacional Ano: 2016 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal Substituto Consideradas as assertivas que se seguem, assinale a alternativa correta: I. A Corte Interamericana de Direitos Humanos, órgão da Convenção Americana de Direitos Humanos, tem a finalidade de julgar casos de violação dos direitos humanos ocorridos em países que integram a Organização dos Estados Americanos (OEA) e reconheçam a sua competência, como o Brasil, que a reconheceu por meio do Decreto Legislativo nº 89, de 1998, do Senado Federal. II. O instituto do deslocamento de competência para a Justiça Federal poderá ocorrer, em qualquer fase processual, com relação a inquéritos e processos em trâmite na Justiça Estadual, com a finalidade de assegurar o cumprimento de obrigações decorrentes de tratado internacional de direitos humanos do qual o Brasil seja parte, mediante requerimento do Procurador-Geral da República perante o Supremo Tribunal Federal, nas hipóteses de grave violação de direitos humanos. III. Compete ao Superior Tribunal de Justiça julgar, em recurso especial, as causas decididas, em única ou última instância, pelos Tribunais Regionais Federais ou pelos Tribunais dos Estados, do Distrito Federal e Territórios, quando a decisão recorrida contrariar tratado ou negar-lhe vigência. IV. O Tribunal Penal Internacional, criado pelo Estatuto de Roma de 1998 promulgado pelo Decreto nº 4.388, de 25.9.2002, tem competência para julgar crime de genocídio; crimes contra a humanidade; crimes de guerra e crime de agressão, todos","a":"imprescritíveis, em relação às violações praticadas depois da entrada em vigor do Estatuto de Roma. As assertivas I e II estão incorretas.","b":"Somente a assertiva II está incorreta.","c":"Somente a assertiva IV está incorreta.","d":"Todas as assertivas estão corretas. Direito Internacional Público>","e":"","gabarito":"","materia":"Geral","tema":"","origem":"","ano":"","banca":"","orgao":"","concurso":"TRF3"},{"id":"Q625140","enunciado":"Ano: 2016 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal Substituto Sobre as assertivas que se seguem, assinale a alternativa correta: I. A sentença eclesiástica de anulação de matrimônio, confirmada pelo Supremo Tribunal da Assinatura Apostólica, no Vaticano, será submetida à homologação do Superior Tribunal de Justiça, observado o acordo firmado entre o Brasil e a Santa Sé, relativo ao Estatuto Jurídico da Igreja Católica no Brasil (Decreto 7.107/2010). II. A Procuradoria-Geral da República tem legitimidade ativa para deduzir pedido de homologação de sentença estrangeira de alimentos, perante o Superior Tribunal de Justiça, na qualidade de Instituição Intermediária indicada nos termos da Convenção de Nova York sobre Prestação de Alimentos no Estrangeiro, promulgada pelo Decreto 56.826, de 2.9.1965, combinado com a Lei nº 5.478, de 25.7.1968. III. As sentenças estrangeiras terão os seus efeitos reconhecidos no ordenamento jurídico brasileiro somente depois de homologadas pelo Superior Tribunal de Justiça. IV. O Acordo de Cooperação e Assistência Jurisdicional, denominado Protocolo de Las Lenãs, promulgado pelo Decreto nº 6.891, de 2.7.2009, busca facilitar o sistema de reconhecimento de sentenças estrangeiras proferidas por tribunais domésticos dos Estados do MERCOSUL, porém não modifica em nada a competência do Superior Tribunal de Justiça para","a":"homologá- las. Todas as assertivas estão corretas.","b":"Todas as assertivas estão incorretas.","c":"Somente a assertivas III está incorreta.","d":"Somente a assertiva IV está incorreta. Direito Internacional Público>Sujeitos de Direito Internacional Público: Estados ,","e":"","gabarito":"A","materia":"Os litígios internacionais e os meios de solução. Meios diplomáticos. Meios políticos. Meios jurisdicionais","tema":"","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1830","enunciado":"Ano: 2016 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal Substituto Dadas as assertivas abaixo, assinale a alternativa correta: Em 10/10/2001, W.W.W., americano, casa-se com A.A.A., brasileira. Dessa união nasceu, no Brasil, a menina A.W, em 10/10/2005. A partir de então, outubro de 2005, os pais fixaram residência nos Estados Unidos da América. Em julho de 2015, a mãe, AAA, veio a São Paulo, trazendo a filha, com a autorização do pai. Na data do agendamento da passagem aérea de regresso ao EUA, em 30/07/2015, AAA comunicou o esposo que decidiu não regressar e permanecer no Brasil com a menor. Em face da transferência, em 30/08/2015, o pai noticiou o fato à Autoridade Central americana, e, paralelamente, na mesma data, ingressou com ação de busca, apreensão e restituição da menor na Justiça Federal de São Paulo. A mãe respondeu, em sede de contestação da ação, que obteve a guarda da filha perante a Justiça Estadual de São Paulo, até porque a menina, A.W., é brasileira. A Advocacia da União pleiteou o seu ingresso na ação em trâmite na Justiça Federal. Quais das medidas abaixo poderiam ser ordenadas pelo Juiz Federal, com fundamento nas normas expressas e implícitas da Convenção da Haia sobre Sequestro Internacional de Crianças, promulgada pelo Decreto nº 3.413, de 14.4.2000: I. Determinar as providências necessárias à responsabilização da mãe na esfera criminal, pela prática de sequestro internacional, encaminhando peças ao Ministério Público Federal. II. Comunicar o MM. Juiz de Direito prolator da decisão que deferiu a guarda na Justiça Estadual, alertando sobre a existência da ação para a discussão de eventual ocorrência de retenção ilícita dos menores, nos termos da Convenção da Haia. Acolher o pedido da União para ingressar no polo ativo do feito como litisconsorte do pai, na qualidade Autoridade Central. III. Julgar extinto o processo sem julgamento de mérito em razão de a menina, A.W, ser brasileira, aplicando na espécie a interpretação sistemática com a regra da Constituição da República (art. 5º, XLVII, “d”) a qual proíbe a pena de banimento, que veda a determinação de saída compulsória do território nacional de cidadão brasileiro. IV. Considerar que o pedido foi deduzido em período de menos de um ano da data da transferência ou retenção, eventualmente, indevida, razão por que deverá deliberar acerca do retorno da menor AW aos Estados Unidos da América,","a":"onde se localizava a sua residência habitual. Todas as assertivas estão corretas.","b":"A assertiva IV está incorreta.","c":"Somente as assertivas II e IV estão corretas.","d":"Somente a assertivas III está incorreta.","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q625134","enunciado":"Substituto Dadas as assertivas abaixo, assinale a alternativa incorreta. Com base no disposto na Lei nº 12.651/2012 e suas alterações posteriores, é possível afirmar sobre a Reserva Legal: Todo imóvel rural deve manter área com cobertura de vegetação nativa, a título de Reserva Legal, sem prejuízo da aplicação das normas sobre as Áreas de Preservação Permanente, observados os seguintes percentuais mínimos em","a":"relação à área do imóvel caso os imóveis estejam situados na Amazônia Legal, excetuados os casos previstos no art. 68 da referida Lei: 80% (oitenta por cento), no imóvel situado em área de florestas; 35% (trinta e cinco por cento), no imóvel situado em área de cerrado; 20% (vinte por cento), no imóvel situado em área de campos gerais. Para os imóveis situados nas demais regiões do país, o percentual é de 20% (vinte por cento).","b":"Em caso de fracionamento do imóvel rural, a qualquer título, inclusive para assentamentos pelo Programa de Reforma Agrária, será considerada, para fins do disposto do caput, a área do imóvel antes do fracionamento. Nos casos de imóvel situado em área de florestas na Amazônia Legal, o poder público poderá reduzir a Reserva Legal para até 50% (cinquenta por cento), para fins de recomposição, quando o Município tiver mais de 80% (oitenta por","c":"cento) da área ocupada por unidades de conservação da natureza de domínio público e por terras indígenas homologadas. Nas mesmas hipóteses o poder público estadual, ouvido o Conselho Estadual de Meio Ambiente, poderá reduzir a Reserva Legal para até 50% (cinquenta por cento), quando o Estado tiver Zoneamento Ecológico- Econômico aprovado e mais de 75% (setenta e cinco por cento) do seu território ocupado por unidades de conservação da natureza de domínio público, devidamente regularizadas, e por terras indígenas homologadas. Os empreendimentos de abastecimento público de água e tratamento de esgoto não estão sujeitos à constituição de Reserva Legal. Também não será exigido Reserva Legal relativa às áreas adquiridas ou desapropriadas por detentor de","d":"concessão, permissão ou autorização para exploração de potencial de energia hidráulica, nas quais funcionem empreendimentos de geração de energia elétrica, subestações ou sejam instaladas linhas de transmissão e de distribuição de energia elétrica. Também não será exigido Reserva Legal relativa às áreas adquiridas ou desapropriadas com o objetivo de implantação e ampliação de capacidade de rodovias e ferrovias. Direito Ambiental>Proteção do Meio Ambiente em Normas Infraconstitucionais ,","e":"","gabarito":"C","materia":"Direito Ambiental","tema":"Código Florestal – Lei nº 12.651 de 2012 ,Reserva legal","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1832","enunciado":"Ano: 2016 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal Substituto Dadas as assertivas abaixo, assinale a alternativa correta. Sobre a gestão de recursos hídricos nacionais, é possível afirmar que: I – A jurisprudência do STJ firmou entendimento no sentido de que, como regra, tendo em vista a legislação vigente, há necessidade de outorga para a extração de água do subterrâneo por meio de poço artesiano. II – Na forma dos arts. 20, III, e 26, I, da Constituição Federal, não mais existe propriedade privada de lagos, rios, águas superficiais ou subterrâneas, fluentes, emergentes ou em depósito, e quaisquer correntes de água. Nesses termos, a interpretação a ser conferida ao art. 11, caput, do Código de Águas (\"São públicos dominicais, se não estiverem destinados ao uso comum, ou por algum título legítimo não pertencerem ao domínio particular\"), que, teoricamente, coaduna-se com o sistema constitucional vigente e com a Lei das Águas (Lei 9.433/1997), é a de que, no que concerne a rios federais e estaduais, o título legítimo em favor do particular que afastaria o domínio pleno da União seria somente o decorrente de enfiteuse ou concessão, este último de natureza real. III – Segundo a Lei nº 9433/1997, estão sujeitos a outorga pelo Poder Público os direitos dos usos de recursos hídricos, dentre outros, de derivação ou captação de parcela da água existente em um corpo de água para consumo final, inclusive abastecimento público, ou insumo de processo produtivo e de lançamento em corpo de água de esgotos e demais resíduos líquidos ou gasosos, tratados ou não, com o fim de sua diluição, transporte ou disposição final.","a":"Estão corretas as assertivas: I e III.","b":"I, II e III.","c":"II e III.","d":"III. Direito Ambiental>Código Florestal – Lei nº 12.651 de 2012 ,Áreas de preservação permanente – APP ,","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1833","enunciado":"Ano: 2016 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal Substituto Dadas as assertivas abaixo, assinale a alternativa correta. Com base no disposto na Lei nº 12.651/2012 e suas alterações posteriores, é possível afirmar sobre os institutos conceituados em seu art. 3º: I – Área de Preservação Permanente: área protegida coberta por vegetação nativa, com a função ambiental de preservar os recursos hídricos, a paisagem, a estabilidade geológica e a biodiversidade, facilitar o fluxo gênico de fauna e flora, proteger o solo e assegurar o bem-estar das populações humanas. II – Reserva Legal: área localizada no interior de uma propriedade ou posse rural, delimitada nos termos do art. 12 da mesma lei, com a função de assegurar o uso econômico de modo sustentável dos recursos naturais do imóvel rural, auxiliar a conservação e a reabilitação dos processos ecológicos e promover a conservação da biodiversidade, bem como o abrigo e a proteção de fauna silvestre e da flora nativa. III – Manejo sustentável: administração da vegetação natural para a obtenção de benefícios econômicos, sociais e ambientais, respeitando-se os mecanismos de sustentação do ecossistema objeto do manejo e considerando-se, cumulativa ou alternativamente, a utilização de única espécie madeireira, de múltiplos produtos e subprodutos da flora, bem como a utilização de outros bens e serviços.","a":"Estão corretas as assertivas: I e II.","b":"I, II e III.","c":"Apenas a II.","d":"Apenas a III.","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q625131","enunciado":"Substituto Dadas as assertivas abaixo, assinale a alternativa correta. Acerca do Conselho de Gestão do Patrimônio Genético - CGen, órgão colegiado criado no âmbito do Ministério do Meio Ambiente, de caráter deliberativo, normativo, consultivo e recursal, responsável por coordenar a elaboração e a implementação de políticas para a gestão do acesso ao patrimônio genético e ao conhecimento tradicional associado e da repartição de benefícios, formado por representação de órgãos e entidades da administração pública federal que detêm competência sobre as diversas ações de que trata a Lei nº 13.123/2015, com participação máxima de 60% (sessenta por cento) e a representação da sociedade civil em no mínimo 40% (quarenta por cento) dos membros, é possível afirmar que: I – No que toca à representação da sociedade civil, deve ser garantida a paridade entre o setor empresarial, o setor acadêmico e as populações indígenas, comunidades tradicionais e agricultores tradicionais. II – Compete ao CGen estabelecer normas técnicas, diretrizes e critérios para elaboração e cumprimento do acordo de repartição de benefícios e critérios para a criação de banco de dados para o registro de informação sobre patrimônio genético e conhecimento tradicional associado. III – Compete ao CGen criar e manter base de dados relativos às coleções ex situ, entendidas como aquelas que são mantidas fora das sedes administrativas do CGen, das instituições credenciadas que contenham amostras de patrimônio","a":"genético. Estão corretas as assertivas: I e II","b":"I, II e III","c":"I e III","d":"II e III Direito Ambiental>Princípios do direito ambiental ,Princípio da prevenção/precaução ,","e":"","gabarito":"A","materia":"Legislação Federal","tema":"Lei nº 13.123 de 2015 - Dispõe sobre o Acesso ao Patrimônio Genético","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q625128","enunciado":"Ano: 2016 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal Substituto Dadas as assertivas abaixo, assinale a alternativa correta. I – O princípio da prevenção está intimamente relacionado ao brocardo jurídico “in dubio contra projectum” e, segundo jurisprudência das Cortes Superiores, impõe o reconhecimento da inversão do ônus da prova. II – A respeito das sanções penais e administrativas derivadas de condutas e atividades lesivas ao meio ambiente, é possível afirmar que configuram circunstâncias atenuantes o baixo grau de instrução ou escolaridade do agente, o arrependimento do infrator, manifestado pela espontânea reparação do dano, ou limitação significativa da degradação ambiental causada, a comunicação prévia pelo agente do perigo iminente de degradação ambiental, a ausência de intuito de obtenção de vantagem pecuniária e a colaboração com os agentes encarregados da vigilância e do controle ambiental. III – Tratando-se de direito difuso, a reparação civil de danos ambientais assume grande amplitude, com profundas implicações na espécie de responsabilidade do degradador, que é objetiva e fundada no simples risco ou no simples fato da atividade danosa, independentemente da culpa do agente causador do dano.","a":"Estão corretas as assertivas: I e II.","b":"I, II e III.","c":"II e III.","d":"III.","e":"","gabarito":"D","materia":"Responsabilidade ambientalResponsabilidade civil por danos ao meio ambiente","tema":"","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q625126","enunciado":"Substituto Dadas as assertivas abaixo, assinale a alternativa correta no que concerne à contratação de parceria público-privada no âmbito da administração pública. I – Concessão patrocinada é o contrato de prestação de serviços de que a Administração Pública seja a usuária direta ou indireta, ainda que envolva execução de obra ou fornecimento e instalação de bens. II – Concessão administrativa é a concessão de serviços públicos ou de obras públicas de que trata a Lei nº 8.987, de 13 de fevereiro de 1995, quando envolver, adicionalmente à tarifa cobrada dos usuários contraprestação pecuniária do parceiro público ao parceiro privado. III – As cláusulas dos contratos de parceria público-privada deverão prever, dentre outros, o prazo de vigência do contrato, compatível com a amortização dos investimentos realizados, não inferior a 5 (cinco), nem superior a 35 (trinta e cinco) anos, incluindo eventual prorrogação.","a":"Estão corretas: I, II e III.","b":"Apenas I.","c":"Apenas II.","d":"Apenas III.","e":"","gabarito":"D","materia":"Direito Administrativo","tema":"Parcerias público-privadas ,Serviços Públicos","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q625125","enunciado":"Substituto Sobre o poder de polícia, assinale a alternativa incorreta. Segundo o STF, o art. 144, §8º, da CF (“Os Municípios poderão constituir guardas municipais destinadas à proteção de","a":"seus bens, serviços e instalações, conforme dispuser a lei”), não impede que a guarda municipal exerça funções adicionais à de proteção dos bens, serviços e instalações do Município, incluindo o exercício do poder de polícia para fiscalização do trânsito, que não é prerrogativa exclusiva das entidades policiais.","b":"Segundo o STF, a taxa de renovação de licença de funcionamento é constitucional, desde que haja o efetivo exercício do poder de polícia, não bastando para sua demonstração a mera existência de órgão administrativo que possua estrutura e competência para a realização da atividade de fiscalização.","c":"A edição de atos normativos pode caracterizar a atuação de polícia administrativa, por exemplo, quando impõe limitações administrativas ao exercício dos direitos e de atividades individuais.","d":"Atos de polícia administrativa podem ser expedidos no exercício de competência discricionária ou vinculada, conforme o caso.","e":"","gabarito":"B","materia":"Direito Administrativo","tema":"Poderes da Administração ,Poder de polícia","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q625124","enunciado":"Substituto Dadas as assertivas abaixo a respeito das OSCIPs, assinale a alternativa correta. I – Podem qualificar-se como Organizações da Sociedade Civil de Interesse Público as pessoas jurídicas de direito privado sem fins lucrativos que tenham sido constituídas e se encontrem em funcionamento regular há, no mínimo, 1 (um) ano, desde que os respectivos objetivos sociais e normas estatutárias atendam aos requisitos instituídos pela Lei nº 9.790/1999. II – Não são passíveis de qualificação como Organizações da Sociedade Civil de Interesse Público, as sociedades comerciais, os sindicatos, as associações de classe ou de representação de categoria profissional, nem as instituições religiosas ou voltadas para a disseminação de credos, cultos, práticas e visões devocionais e confessionais. III – Dentre os objetos sociais possíveis para a qualificação instituída pela Lei nº 9.790/1999 está o de realização de estudos e pesquisas para o desenvolvimento, a disponibilização e a implementação de tecnologias voltadas à mobilidade de pessoas, por qualquer meio de transporte.","a":"Estão corretas: Apenas I e II.","b":"I, II e III.","c":"Apenas II.","d":"Apenas II e III.","e":"","gabarito":"D","materia":"Direito Administrativo","tema":"Entidades Paraestatais ou Terceiro Setor ,Organização da Administração Pública","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q625121","enunciado":"Substituto Dadas as assertivas abaixo, assinale a alternativa correta, nos termos do Decreto-lei nº 25/37. I- O tombamento provisório possui caráter preventivo e assemelha-se ao definitivo quanto às limitações incidentes sobre a utilização do bem tutelado. II- Sem prévia autorização do Serviço do Patrimônio Histórico e Artístico Nacional, não se poderá, na vizinhança da coisa tombada, fazer construção que lhe impeça ou reduza a visibilidade, nem nela colocar anúncios ou cartazes, sob pena de destruição da coisa, com imposição de multa. III – Com prévia autorização especial do Serviço do Patrimônio Histórico e Artístico Nacional, as coisas tombadas poderão ser mutiladas, vedado em todos os casos sua demolição ou destruição.","a":"Estão corretas: apenas I e II.","b":"I, II e III.","c":"apenas I.","d":"apenas II e III.","e":"","gabarito":"C","materia":"Direito Administrativo","tema":"Intervenção do estado na propriedade","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q625119","enunciado":"Substituto Dadas as assertivas abaixo, assinale a alternativa correta. São bens da União: I – O mar territorial, entendido como uma faixa de doze milhas marítimas de largura, medidas a partir da linha de baixa-mar do litoral continental e insular, tal como indicada nas cartas náuticas de grande escala, reconhecidas oficialmente no Brasil. II – Os recursos naturais da plataforma continental, entendida como o subsolo das áreas submarinas que se estendem além do seu mar territorial, em toda a extensão do prolongamento natural de seu território terrestre, até o bordo exterior da margem continental, ou até uma distância de cento e cinquenta milhas marítimas das linhas de base, a partir das quais se mede a largura do mar territorial, nos casos em que o bordo exterior da margem continental não atinja essa distância. III – Os recursos naturais da zona econômica exclusiva, entendida como uma faixa que se estende das doze às duzentas milhas marítimas, contadas a partir das linhas de base que servem para medir a largura do mar territorial.","a":"Estão corretas: I, II e III.","b":"I e III.","c":"II e III.","d":"Apenas III.","e":"","gabarito":"B","materia":"Direito Administrativo","tema":"Bens Públicos na Administração Pública ,Conceito, classificação, afetação e desafetação","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q625117","enunciado":"Substituto O cancro cítrico é doença altamente contagiosa que atinge as diversas variedades de citros, afetando a produtividade e a qualidade da lavoura, levando, inclusive, à morte do vegetal contaminado. A patologia é incurável e demanda, como medida profilática, a erradicação dos vegetais contaminados. Nesses termos, criou-se Campanha Nacional de Erradicação do Cancro Cítrico - CANECC, instaurada por meio da Portaria nº 291/1997 e promovida pelo Ministério da Agricultura, em consonância com o Decreto nº 24.114/34, que prevê a possibilidade de destruição parcial ou tal das lavouras contaminadas ou passíveis de contaminação em condições como essa. Imaginando-se que determinado proprietário, atingido pelas medidas sanitárias acima indicadas, reivindica indenização, é possível afirmar, com alicerce nesses elementos, que: Em tese é cabível indenização, tendo em vista que o art. 37, § 6º, da CF/88 consagra a responsabilidade objetiva do","a":"Estado, cujo reconhecimento condiciona-se à comprovação dos seguintes requisitos: conduta lesiva imputável a um de seus agentes, dano indenizável e nexo de causalidade entre a conduta impugnada, restando dispensada a configuração de culpa, de excesso ou de abuso do Poder Público.","b":"Em tese não é cabível indenização, tendo em vista que, conforme entendimento jurisprudencial pacífico, em casos como esse, a indenização somente seria devida se comprovado excesso ou abuso do Poder Público.","c":"Embora em tese não seja necessária a comprovação de excesso ou abuso do Poder Público para que seja reconhecido o direito à indenização em casos como esse, a indenização não é cabível porquanto o ato praticado buscou resguardar o interesse público.","d":"Em tese não é cabível indenização, porquanto em nenhuma hipótese o Estado deve reparar danos causados a terceiros quando decorrentes de seu comportamento lícito.","e":"","gabarito":"B","materia":"Direito Administrativo","tema":"Responsabilidade civil do estado","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q625115","enunciado":"Substituto Dadas as assertivas abaixo, assinale a alternativa correta.","a":"Os vencimentos dos cargos do Poder Executivo e do Poder Judiciário não poderão ser superiores aos pagos pelo Poder Legislativo.","b":"As funções de confiança, exercidas exclusivamente por servidores ocupantes de cargo efetivo, e os cargos em comissão, a serem preenchidos por servidores de carreira nos casos, condições e percentuais mínimos previstos em lei, destinam-se apenas às atribuições de direção, chefia e assessoramento.","c":"O regime de emprego público regulamentado pela Lei nº 9.962/2000 incide apenas sobre os servidores da administração pública federal.","d":"Embora afaste-se o reconhecimento de direito adquirido a regime jurídico, o servidor público tem direito à aplicação irrestrita da norma que prevê a irredutibilidade de seus vencimentos.","e":"","gabarito":"B","materia":"Direito Administrativo","tema":"Agentes públicos e Lei 8.112 de 1990 ,Cargo, emprego, função","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q625113","enunciado":"Substituto Dadas as assertivas abaixo, assinale a alternativa correta.","a":"As empresas públicas, pessoas jurídicas de direito privado, são submetidas à responsabilidade civil objetiva, independentemente de seu objeto.","b":"A pessoa jurídica prestadora de serviços públicos se sujeita à responsabilidade civil objetiva, ainda que estes sejam","c":"prestados por concessionárias e permissionárias e ainda que o dano seja causado a usuário ou terceiro. A responsabilidade civil por danos nucleares é integral, podendo ser afastada em casos extremos de força maior.","d":"Segundo precedentes do STJ, o roubo em face do Estado, mediante uso de arma de fogo, é fato de terceiro que, em regra, não é equiparável à força maior, razão pela qual não afasta a responsabilidade objetiva do Estado, caso verificados danos a terceiros. Direito Tributário>Limitações Constitucionais ao Poder de Tributar - Princípios Tributários , Princípio da Anterioridade ,Obrigação TributáriaSolidariedade e Responsabilidade Tributária ,","e":"","gabarito":"B","materia":"Direito Administrativo","tema":"Responsabilidade civil do estado","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1844","enunciado":"Execução Fiscal Ano: 2016 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal Substituto Com relação a jurisprudência dominante, assinale a alternativa correta:","a":"STF: isenções tributárias, como favor fiscal que são, podem ser livremente suprimidas mesmo se concedidas sob condição onerosa.","b":"STJ: na execução fiscal é necessária a instrução da petição inicial com o demonstrativo do cálculo do débito, para assegurar a ampla defesa do contribuinte.","c":"STJ: no caso de sucessão empresarial, a responsabilidade da sucessora abrange os tributos e as multas moratórias devidas pela sucedida referentes aos fatos geradores ocorridos até a sucessão, mas não as multas punitivas dado o caráter pessoal delas.","d":"STF: a norma legal que altera o prazo de recolhimento da obrigação tributária não se sujeita ao princípio da anterioridade. Direito Tributário>Obrigação Tributária ,Fato Gerador ,Lançamento Tributário","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1845","enunciado":"Ano: 2016 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal Substituto O lançamento tributário:","a":"reporta-se à data da ocorrência do fato gerador da obrigação e é regido pela lei vigente, mesmo que venha a ser","b":"revogada ou modificada. constitui a obrigação tributária e torna-se imutável após a notificação válida do sujeito passivo.","c":"é inibido por decisão judicial que suspende a exigibilidade do crédito tributário.","d":"identifica o sujeito passivo, verifica a ocorrência do fato gerador, calcula o montante do tributo devido e estabelece os critérios para a revisão “de ofício”do crédito decorrente. Direito Tributário>Limitações Constitucionais ao Poder de Tributar - Imunidades ,","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q625110","enunciado":"Ano: 2016 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal Substituto Considere as seguintes afirmações e assinale a alternativa correta: I. As multas fiscais também são alcançadas pelo princípio da não-confiscatoriedade. II. As medidas provisórias podem instituir ou majorar tributos para os quais não é exigida lei complementar. III. O IPI (imposto sobre produtos industrializados) não incide sobre produtos industrializados destinados à exportação. IV. A imunidade recíproca prevista para as pessoas políticas alcança empresas públicas e sociedades de economia mista","a":"delegatárias de serviços públicos que atuam em regime de monopólio. Todas as afirmações são erradas.","b":"As afirmações II e III são erradas.","c":"Todas as afirmações são verdadeiras.","d":"A afirmação IV é a única verdadeira. Direito Tributário>Conceito de Tributo e Espécies Tributárias ,Taxa e Tarifas ,Contribuições Especiais","e":"","gabarito":"C","materia":"Legislação do Direito Tributário","tema":"","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1847","enunciado":"Ano: 2016 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal Substituto","a":"Assinale a alternativa incorreta: Tratando-se de serviço indivisível e inespecífico, a iluminação pública não pode ser remunerada mediante taxa.","b":"Cabe ao Poder Judiciário, em prestígio da isonomia, estender tratamento tributário benéfico já previsto em lei, para contribuinte não contemplado no texto legal.","c":"As contribuições sociais e as contribuições de intervenção no domínio econômico não incidirão sobre receitas decorrentes de exportação.","d":"É possível a adoção, no cálculo do valor de uma taxa, de um ou mais elementos da base de cálculo de um imposto, desde que não ocorra integral identidade entre uma base e outra. Direito Tributário>Conceito de Tributo e Espécies Tributárias ,Taxa e Tarifas ,Contribuição de Melhoria","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1848","enunciado":"Ano: 2016 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal Substituto Aponte a alternativa correta:","a":"Contribuições de melhoria são tributos vinculados à prestação ou à disposição de serviços públicos fruíveis pelo","b":"contribuinte. Pagando um imposto o contribuinte pode exigir do Poder Público uma contraprestação individual e específica.","c":"Em caso de relevante interesse público os Estados e o DF podem instituir contribuições de intervenção no domínio","d":"econômico. A tarifa pública e o preço público não se submetem ao regime jurídico tributário porque sua natureza é contratual.","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q625107","enunciado":"Substituto","a":"Só podem ser instituídos por meio de lei complementar: o empréstimo compulsório e o imposto extraordinário.","b":"a contribuição de intervenção no domínio econômico e o empréstimo compulsório.","c":"o imposto sobre grandes fortunas e as contribuições de interesse de categorias profissionais ou econômicas.","d":"o empréstimo compulsório e o imposto residual.","e":"","gabarito":"D","materia":"Direito Tributário","tema":"Legislação do Direito Tributário ,Função da Lei Complementar em Direito Tributário","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q625106","enunciado":"Substituto O IOF (imposto sobre operações de crédito, câmbio e seguro, ou relativas a títulos ou valores mobiliários):","a":"tem predominante função extrafiscal e não se submete à anterioridade tributaria; o Poder Executivo pode manejar as suas alíquotas para ajustá-lo a objetivos de política monetária indicando o que almeja alcançar com a mudança de alíquota.","b":"incide na operação financeira de levantamento de depósitos judiciais destinados a suspender a exigibilidade do crédito tributário ou a garantir a instância executiva.","c":"pode ser exigido nas operações financeiras dos Estados, DF e Municípios, porque essa tributação não é limitada pela imunidade constitucional recíproca.","d":"pode incidir sobre qualquer operação financeira, desde que seja observado o princípio da estrita legalidade, porque as operações enumeradas no CTN são exemplificativas.","e":"","gabarito":"A","materia":"Direito Tributário","tema":"Tributos Federais ,IOF","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q625105","enunciado":"Substituto","a":"São causas da exclusão do crédito tributário: isenção e anistia.","b":"imunidade e remissão.","c":"transação e compensação.","d":"decadência e novação.","e":"","gabarito":"A","materia":"Direito Tributário","tema":"Exclusão do Crédito Tributário ,Exclusão do Credito Tributário - Disposições Gerais","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q625104","enunciado":"Substituto Considere a denúncia espontânea (art. 138 do CTN) e assinale a alternativa incorreta:","a":"Não se aplica aos tributos sujeitos a lançamento por homologação regularmente declarados, mas que são pagos a destempo.","b":"Só se considera espontânea a denúncia apresentada antes de qualquer medida de fiscalização relacionada com a","c":"infração fiscal. Aplica-se ao caso em que o contribuinte devedor confessa a dívida e obtém o parcelamento do débito tributário.","d":"Exclui a exigência da multa, mas não evita a incidência dos juros moratórios e da correção monetária do débito confessado. Direito Tributário>Limitações Constitucionais ao Poder de Tributar - Princípios Tributários ,","e":"","gabarito":"C","materia":"Direito Tributário","tema":"Obrigação Tributária ,Denúncia Espontânea","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1853","enunciado":"Ano: 2016 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal Substituto O princípio da anterioridade genérica significa que:","a":"as pessoas políticas não podem cobrar tributos levando em conta fatos geradores ocorridos antes do início da vigência da lei que os instituiu ou aumentou.","b":"as pessoas políticas não podem exigir tributos no mesmo exercício financeiro em que foi publicada a lei que os instituiu ou aumentou.","c":"as pessoas políticas não podem exigir ou majorar tributos antes de decorridos três meses da entrada em vigor da lei que os instituiu ou aumentou.","d":"as pessoas políticas não podem exigir tributos sem que haja prévia autorização orçamentária para a cobrança deles em cada exercício financeiro.","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q625101","enunciado":"Substituto Relativamente ao registro do empresário, assinale a alternativa incorreta:","a":"O requerimento deve conter a firma, com a respectiva assinatura autógrafa que poderá ser substituída pela assinatura autenticada com certificação digital ou meio equivalente que comprove a sua autenticidade.","b":"No caso de abertura de microempresa e empresa de pequeno porte, poderá ser dispensado o uso da firma, com a respectiva assinatura autógrafa.","c":"O empresário que instituir sucursal, filial ou agência, em lugar sujeito à jurisdição de outro Registro Público de Empresas Mercantis, neste poderá, se o desejar, também inscrevê-la, com a prova da inscrição originária.","d":"O empresário, cuja atividade rural constitua sua principal profissão, pode requerer inscrição no Registro Público de Empresas Mercantis da respectiva sede, caso em que, depois de inscrito, ficará equiparado, para todos os efeitos, ao empresário sujeito a registro.","e":"","gabarito":"C","materia":"Direito Empresarial (Comercial)","tema":"Teoria Geral do Direito Empresarial ,Registro e escrituração","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q625100","enunciado":"Substituto Marque a alternativa correta:","a":"O art. 6º, e, da Lei n. 4.380/1964 estabelece limitação aos juros remuneratórios nos contratos vinculados ao Sistema Financeiro da Habitação - SFH.","b":"Nas sociedades anônimas, apenas os administradores da companhia e seu acionista controlador podem ser responsabilizados pelos atos de gestão e pela utilização abusiva do poder.","c":"Nos contratos de financiamento celebrados no âmbito do SFH, sem cláusula de garantia de cobertura do FCVS, o saldo devedor residual deverá ser suportado pelo mutuante.","d":"Nos contratos vinculados ao SFH, a atualização do saldo devedor não antecede sua amortização pelo pagamento da prestação.","e":"","gabarito":"B","materia":"Direito Empresarial (Comercial)","tema":"Contratos Empresariais","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q625099","enunciado":"Substituto","a":"Assinale a alternativa incorreta: fusão determina a manutenção das sociedades que se unem, para formar sociedade nova, que a elas sucederá nos A direitos e obrigações.","b":"A cláusula constitutiva de mandato, lançada no endosso, confere ao endossatário o exercício dos direitos inerentes ao título, salvo restrição expressamente estatuída.","c":"Na sociedade em comandita simples, a morte de sócio comanditário, salvo disposição do contrato, não impede sua continuidade com seus sucessores, que designarão quem os represente.","d":"A invenção e o modelo de utilidade são considerados suscetíveis de aplicação industrial quando possam ser utilizados ou produzidos em qualquer tipo de indústria.","e":"","gabarito":"A","materia":"Direito Empresarial (Comercial)","tema":"Direito Societário ,Operações societárias","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q625098","enunciado":"Substituto","a":"Marque a alternativa incorreta, observando-se a legislação e a jurisprudência dominante do Superior Tribunal de Justiça: Nos contratos bancários, é vedado ao julgador conhecer, de ofício, da abusividade das cláusulas.","b":"A nota promissória vinculada a contrato de abertura de crédito não goza de autonomia em razão da iliquidez do título que a originou.","c":"O avalista do título de credito vinculado a contrato de mutuo também responde pelas obrigações pactuadas, quando","d":"no contrato figurar como devedor solidário. A companhia dissolvida perde automaticamente sua personalidade jurídica.","e":"","gabarito":"D","materia":"Direito Empresarial (Comercial)","tema":"Títulos de Crédito ,Títulos em espécie ,Direito SocietárioSociedade Anônima","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q625097","enunciado":"Substituto Dadas as assertivas abaixo, assinale a alternativa incorreta. Segundo o STJ, o prazo prescricional para a cobrança da taxa de ocupação de terrenos de marinha é de cinco ou dez","a":"anos, a depender do período considerado, uma vez que os débitos posteriores a 1998 são submetidos ao prazo decenal, à luz do que dispõe a Lei nº 9.636/98, e os anteriores à citada lei, em face da ausência de previsão normativa específica, se subsomem ao prazo encartado no art. 1º do Decreto-Lei 20.910/1932. A Lei Complementar 118, de 9 de fevereiro de 2005 alterou o art. 174 do CTN para atribuir ao despacho do juiz que","b":"ordenar a citação o efeito interruptivo da prescrição nas ações para cobrança de crédito tributário. Nesses termos, consubstanciando norma processual, a referida Lei Complementar é aplicada imediatamente aos processos em curso anteriormente à sua vigência, desde que o despacho que ordenar a citação seja anterior à sua entrada em vigor, sob pena de retroação da novel legislação. O Codex Processual, no § 1º, do artigo 219, estabelece que a interrupção da prescrição, pela citação, retroage à data","c":"da propositura da ação, o que, na seara tributária, após as alterações promovidas pela Lei Complementar nº 118/2005, conduz ao entendimento de que o marco interruptivo atinente à prolação do despacho que ordena a citação do executado retroage à data do ajuizamento do feito executivo, a qual deve ser empreendida no prazo prescricional. Com relação ao prazo prescricional aplicável à execução fiscal para a cobrança de dívida ativa não tributária relativa à operação de crédito rural transferida à União por força da Medida Provisória nº 2.196- 3/2001, o STJ fixou o entendimento de que ao crédito rural cujo contrato tenha sido celebrado sob a égide do Código Civil de 1916, aplica- se o prazo prescricional de 20 (vinte) anos (prescrição das ações pessoais - direito pessoal de crédito), a contar da data","d":"do vencimento, para que dentro dele (observado o disposto no art. 2º, §3º da LEF) sejam feitos a inscrição e o ajuizamento da respectiva execução fiscal, sem embargo da norma de transição prevista no art. 2.028 do CC/2002, sendo que para o crédito rural cujo contrato tenha sido celebrado sob a égide do Código Civil de 2002, aplica-se o prazo prescricional de 5 (cinco) anos (prescrição da pretensão para a cobrança de dívidas líquidas constantes de instrumento público ou particular), a contar da data do vencimento, consoante o disposto no art. 206, §5º, I, do CC/2002, para que dentro dele (observado o disposto no art. 2º, §3º da LEF) sejam feitos a inscrição em dívida ativa e o ajuizamento da respectiva execução fiscal. Direito Processual Civil - CPC 1973>Procedimentos Especiais ,Processo de execução ,Da execução em geral","e":"","gabarito":"A","materia":"Direito Tributário","tema":"Execução Fiscal e Processo Tributário ,Visão Geral das Ações Fiscais ,Execução Fiscal","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1859","enunciado":"Ano: 2016 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal Substituto Assinale a alternativa incorreta.","a":"Segundo entendimento consolidado pelo STJ admite-se a possibilidade de ajuizamento de ação de prestação de contas relativa a contrato de conta-corrente bancária, contrato de financiamento e contrato de mútuo.","b":"A penhora pode ser substituída por fiança bancária ou seguro garantia judicial, em valor não inferior ao débito constante da inicial mais 30% (trinta por cento). Nos termos do CPC, os embargos de terceiro podem ser opostos a qualquer tempo no processo de conhecimento","c":"enquanto não transitada em julgado a sentença, e, no processo de execução, até 5 (cinco) dias depois da arrematação, adjudicação ou remição, mas sempre antes da assinatura da respectiva carta. Contudo, caso o terceiro não tenha conhecimento da execução, o prazo somente tem início a partir da efetiva turbação da posse que se dá com a imissão do arrematante na posse do bem.","d":"Em ação monitória fundada em cheque prescrito, ajuizada em face do emitente, é dispensável menção ao negócio jurídico subjacente à emissão da cártula. Nesse caso, o prazo para ajuizamento da ação é quinquenal, tendo por termo “a quo” o dia seguinte à data de emissão estampada na cártula, sendo cabível, nesse caso, a reconvenção.","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q625093","enunciado":"Substituto Assinale a alternativa correta, acerca dos Juizados Especiais Federais.","a":"Podem ser partes no Juizado Especial Federal Cível, como autores, as pessoas físicas, as microempresas e as empresas","b":"de pequeno e médio porte e, como rés, a União, autarquias e fundações públicas, exclusivamente. Não haverá prazo diferenciado para a prática de qualquer ato processual pelas pessoas jurídicas de direito público.","c":"Tendo em vista a indisponibilidade do interesse público, inviável que representantes judiciais da União, autarquias e fundações públicas desistam nos processos da competência dos Juizados Especiais Federais.","d":"Há previsão legal expressa prevendo o reexame necessário em certas hipóteses, em causas submetidas ao Juizado Especial Federal.","e":"","gabarito":"B","materia":"Direito Processual Civil - CPC 1973","tema":"Juizado Especial no CPC 1973 ,Juizado Especial - Federal","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q625092","enunciado":"Substituto O STJ firmou o entendimento de que, em atenção ao princípio da especialidade da Lei de Execuções Fiscais a nova redação do art. 736 do CPC dada pela Lei n. 11.382/2006 - artigo que dispensa a garantia como condicionante dos embargos - não se aplica às execuções fiscais diante da presença de dispositivo específico, qual seja o art. 16 §1º da Lei nº 6.830/80, que exige expressamente a garantia para a apresentação dos embargos à execução fiscal. A respeito desse tema, é correto afirmar","a":"que: É inviável o recebimento dos embargos de devedor caso a garantia existente não seja integral. É viável o recebimento dos embargos do devedor ainda que não haja garantia integral do débito, mas a atribuição de","b":"efeito suspensivo a eles depende da existência de requerimento expresso, da verificação pelo juiz da relevância da fundamentação e de perigo de dano irreparável ou de difícil reparação, além da garantia integral do débito mediante depósito em dinheiro.","c":"É viável o recebimento dos embargos do devedor ainda que não haja garantia integral do débito, mas a atribuição de efeito suspensivo a eles depende da existência de requerimento expresso, da verificação pelo juiz da relevância da fundamentação e de perigo de dano irreparável ou de difícil reparação, além da garantia integral do débito.","d":"tanto o recebimento dos embargos do devedor, como a atribuição de efeito suspensivo a eles, independe da garantia integral do débito, bastando a garantia parcial, a existência de requerimento expresso, além da verificação pelo juiz da relevância da fundamentação e de perigo de dano irreparável ou de difícil reparação.","e":"","gabarito":"C","materia":"Direito Processual Civil - CPC 1973","tema":"Processo de execução ,Execução fiscal","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q625088","enunciado":"Substituto Dadas as assertivas abaixo, assinale a alternativa correta. Com base no disposto na Lei nº 9.307/96 e suas alterações posteriores, é possível afirmar que: I – Do compromisso arbitral deverá constar, obrigatoriamente, o nome, profissão, estado civil e domicílio das partes; o nome, profissão e domicílio do árbitro, ou dos árbitros, ou, se for o caso, a identificação da entidade à qual as partes delegaram a indicação de árbitros; a matéria que será objeto da arbitragem; o local, ou locais, onde se desenvolverá a arbitragem e onde será proferida a sentença arbitral. II – Extingue-se o compromisso arbitral escusando-se qualquer dos árbitros, antes de aceitar a nomeação, a menos que as partes tenham declarado, expressamente, aceitar substituto. III – São requisitos obrigatórios da sentença arbitral: o relatório, que conterá os nomes das partes e um resumo do litígio; os fundamentos da decisão, onde serão analisadas as questões de fato e de direito, mencionando-se, expressamente, se os árbitros julgaram por equidade; o dispositivo, em que os árbitros resolverão as questões que lhes forem submetidas e estabelecerão o prazo para o cumprimento da decisão, se for o caso; a data e o lugar em que foi proferida. IV – Para que haja a homologação da sentença arbitral estrangeira, deverá haver requerimento da parte interessada, devendo a petição inicial conter as indicações da lei processual, conforme o art. 282 do Código de Processo Civil, sendo dispensável a apresentação do original da sentença arbitral, desde que substituído por cópia devidamente certificada, autenticada pelo consulado brasileiro e acompanhada de tradução oficial e sendo dispensável a apresentação do original da convenção de arbitragem, desde que substituído por cópia devidamente certificada, acompanhada de tradução oficial.","a":"Estão corretas: I, III e IV.","b":"I e II.","c":"II e III.","d":"III e IV. Direito Civil>Direito das Obrigações ,Direito das Sucessões ,","e":"","gabarito":"D","materia":"Direito Processual Civil - Novo Código de Processo Civil - CPC 2015","tema":"Arbitragem","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q625087","enunciado":"Ano: 2016 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal Substituto","a":"Assinale a alternativa incorreta: expromissão é uma forma de novação subjetiva ativa, que implica a extinção da obrigação em favor do devedor A","b":"secundário. São susceptíveis de cessão, por meio de escritura pública o direito à sucessão aberta e o quinhão do herdeiro.","c":"São irrevogáveis os atos de aceitação ou de renúncia da herança.","d":"Quando a obrigação for divisível, só incorre na pena o devedor ou o herdeiro do devedor que a infringir, e proporcionalmente à sua parte na obrigação.","e":"","gabarito":"A","materia":"Adimplemento","tema":"","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q625086","enunciado":"Substituto","a":"Sobre os defeitos do negócio jurídico, assinale a alternativa incorreta: O erro de cálculo não invalida o negócio jurídico; ele apenas autoriza a retificação da declaração de vontade.","b":"O erro não invalida o negócio jurídico quando a pessoa, a quem a manifestação de vontade se dirige, se oferecer para executá- la na conformidade da vontade real do manifestante.","c":"A lesão não invalida o negócio jurídico se for oferecido suplemento suficiente, ou se a parte favorecida concordar com a redução do proveito.","d":"O estado de perigo não invalida o negócio jurídico se a parte beneficiada oferecer justa reparação pelo fato de ter se aproveitado da premente necessidade de a outra parte salvar-se.","e":"","gabarito":"D","materia":"Direito Civil","tema":"Defeitos do Negócio Jurídico ,Parte Geral","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q625085","enunciado":"Substituto","a":"Assinale a alternativa incorreta: Perde a qualidade de indivisível a obrigação que se resolver em perdas e danos.","b":"Convertendo-se a prestação em perdas e danos, subsiste, para todos os efeitos, a solidariedade.","c":"A remissão da dívida feita por um dos credores em obrigação indivisível extingue esta para com os demais credores.","d":"A remissão da dívida feita por um dos credores solidários extingue a obrigação com relação ao devedor, devendo aquele credor responder aos outros pela parte que lhes caiba.","e":"","gabarito":"C","materia":"Direito Civil","tema":"Direito das Obrigações ,Modalidades de Obrigações","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q625083","enunciado":"Substituto","a":"Marque a alternativa correta, observando a jurisprudência dominante do Superior Tribunal de Justiça: A simples propositura da ação de revisão de contrato inibe a caracterização da mora do autor.","b":"Nas indenizações por ato ilícito, os juros compostos não são devidos por aquele que praticou o crime.","c":"A evicção consiste na perda parcial ou integral da posse ou da propriedade do bem, via de regra, em virtude de decisão judicial que atribui o uso, a posse ou a propriedade a outrem, em decorrência de motivo jurídico anterior ao contrato de aquisição.","d":"Os conceitos de onerosidade excessiva e de imprevisão são sinônimos, tendo o legislador civil deles feito uso de modo indistinto. Direito Civil>Direito de Família ,Direito das Sucessões ,ParentescoCasamento no Direito de Família ,","e":"","gabarito":"C","materia":"Direito Civil","tema":"Direito das Coisas / Direitos Reais ,Propriedade ,Efeitos, Tutela, Transmissão e Perda da Posse","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1867","enunciado":"Ano: 2016 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal Substituto","a":"Sobre o Direito de Família e das Sucessões, marque a alternativa incorreta: São susceptíveis de cessão, por meio de escritura pública o direito à sucessão aberta e o quinhão do herdeiro.","b":"São irrevogáveis os atos de aceitação ou de renúncia da herança.","c":"A pensão alimentícia incide sobre a gratificação natalina e a gratificação de férias.","d":"O casamento é nulo quando contraído por enfermo mental sem o necessário discernimento para a vida civil. Direito Civil>Contratos em Espécie ,Compra e Venda ,Locação de Coisas","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1868","enunciado":"Ano: 2016 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal Substituto Sobre os contratos em espécie, assinale a alternativa correta:","a":"O contrato de seguro por danos pessoais não compreende os danos morais, devendo haver cláusula expressa com tal previsão de cobertura.","b":"A cláusula especial de venda sobre documentos transforma o negócio de compra, de modo que a transferência","c":"documentária faz as vezes da tradição real. São elementos essenciais categoriais da compra e venda o preço, a coisa e a tradição.","d":"A locação por tempo determinado cessa de pleno direito findo o prazo estipulado, mediante notificação ou aviso prévio obrigatório.","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q625080","enunciado":"Substituto Relativamente às pessoas jurídicas, marque a alternativa correta:","a":"Se a pessoa jurídica tiver administração coletiva, as decisões se tomarão, em qualquer caso, pela maioria de votos dos presentes.","b":"Compete privativamente às assembleias gerais das associações a destituição e a eleição dos administradores, bem como a alteração dos estatutos.","c":"Quando insuficientes para constituir a fundação, os bens a ela destinados serão incorporados em outra fundação que se proponha a fim igual ou semelhante, independentemente do que dispuser o instituidor.","d":"É obrigatória a inclusão de norma estatutária nas associações que preveja o direito de recorrer dos associados na hipótese de sua exclusão.","e":"","gabarito":"D","materia":"Direito Civil","tema":"Pessoa Jurídica ,Parte Geral","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q625079","enunciado":"Substituto","a":"Considerando a jurisprudência dominante no Superior Tribunal de Justiça, assinale a alternativa incorreta: A correção monetária do valor da indenização do dano material incide desde a data do arbitramento.","b":"São cumuláveis as pretensões ao dano moral, ao dano estético e ao dano material decorrentes do mesmo fato.","c":"A simples devolução indevida de cheque caracteriza dano moral.","d":"São civilmente responsáveis pelo ressarcimento de dano, decorrente de publicação pela imprensa, tanto o autor do escrito quanto o proprietário do veículo de divulgação.","e":"","gabarito":"A","materia":"Direito Civil","tema":"Responsabilidade civil ,Indenização - Liquidação do Dano","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1871","enunciado":"Ano: 2016 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal Substituto","a":"Sobre a posse, assinale a alternativa incorreta: A acessão possessória pode-se dar de modo facultativo ou por continuidade do direito recebido do antecessor.","b":"Admite-se o convalescimento da posse violenta e da posse clandestina.","c":"A posse de boa-fé só perde este caráter no caso e desde o momento em que as circunstâncias façam presumir que o","d":"possuidor não ignora que possui indevidamente. O reivindicante, quando obrigado, indenizará as benfeitorias ao possuidor de má-fé pelo valor atual. Direito Econômico>O Sistema Brasileiro de Defesa da Concorrência e a Lei nº 12.529 de 2011 ,","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1872","enunciado":"Ano: 2016 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","a":"Substituto Lei nº 12.529, de 30.11.2011, Lei de Defesa da Concorrência – LDC, estrutura o Sistema Brasileiro de Defesa da Concorrência – SBDC, integrado pelo Conselho Administrativo de Defesa Econômica – CADE. Assim, sobre as assertivas que se seguem, assinale a alternativa correta: I. A prática usualmente denominada “gun jumping” (expressão em inglês que significa “queimar a largada”), conhecida na literatura e jurisprudência estrangeiras, consiste na consumação de atos de concentração econômica, antes da decisão final da autoridade antitruste. A LDC prevê que o controle dos atos de concentração, quando cabíveis, será realizado previamente pelo CADE em 240 (duzentos e quarenta) dias, prorrogáveis, a fim de preservar a livre iniciativa e a concorrência. II. O critério de submissão dos atos de concentração ao CADE decorre da aferição, cumulativamente, do faturamento bruto anual e do volume de negócios total no País dos grupos envolvidos, apurados no ano anterior à operação. III. São considerados atos de concentração econômica, pela LDC, as operações nas quais: i) duas ou mais empresas anteriormente independentes se fundem; ii) uma ou mais empresas adquirem, direta ou indiretamente, por compra ou permuta de ações, quotas, títulos ou valores mobiliários conversíveis em ações, ou ativos, tangíveis ou intangíveis, por via contratual ou por qualquer outro meio ou forma, o controle ou partes de uma ou outras empresas; iii) uma ou mais empresas incorporam outra ou outras empresas; ou iv) duas ou mais empresas celebram contrato associativo, consórcio ou joint venture, exceto quando destinados às licitações promovidas pela Administração Pública direta e indireta. IV. Para fins de evitar o risco de aplicação de multa pecuniária de até R$60.000.000,00 (sessenta milhões de reais), dentre outras consequências, as partes envolvidas em um ato de concentração deverão manter as suas estruturas físicas e as condições competitivas inalteradas até a avaliação final do CADE.","b":"A Estão corretas apenas as assertivas I e IV. Estão corretas apenas as assertivas II e IV.","c":"Estão corretas apenas as assertivas I e III.","d":"Todas as assertivas estão corretas. Direito do Consumidor>Defesa do Consumidor Em Juízo ,Ações Coletivas na Defesa do Consumidor ,","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q625076","enunciado":"Ano: 2016 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal Substituto Dadas as assertivas abaixo, assinale a alternativa correta, considerando os termos preconizados pelo Código de Defesa do Consumidor - CDC, introduzido pela Lei nº 8.078, 11.9.1990. I. Os bancos são considerados, à luz do CDC, como fornecedores de serviços e de produtos, neste caso - o dinheiro. II. A jurisprudência do Superior Tribunal de Justiça pacificou entendimento no sentido de que o ajuizamento da execução individual, derivada de decisão proferida no julgamento de ação coletiva, tem como foro o domicílio do exequente, em conformidade com os artigos 98, § 2º, I, e 101, I, do CDC, afastada a ocorrência de prevenção do juízo que examinou o mérito da ação coletiva. III. É considerada irregular a informação em cadastro de proteção ao crédito, referente a período superior a cinco anos, podendo o consumidor valer-se do habeas data (artigo 5º, inciso LXXII, da Constituição da República) como meio de conhecimento, retificação e supressão de dados inexatos. IV. Aplica-se a multa de mora de, no máximo, dois por cento, decorrente do inadimplemento de obrigações condominiais,","a":"na forma do artigo 52 do CDC. Estão corretas apenas as assertivas I e IV.","b":"Estão incorretas apenas as assertivas II e IV.","c":"Está incorreta apenas a assertiva IV.","d":"Estão corretas todas as assertivas.","e":"","gabarito":"C","materia":"Coisa Julgada na Defesa do ConsumidorDisposições Gerais do Código de Defesa do Consumidor","tema":"","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q625074","enunciado":"Substituto","a":"Se o defensor de um condenado preso entender que ele faz jus ao livramento condicional, deverá: Solicitar ao Tribunal, mediante a impetração de habeas corpus;","b":"Solicitar ao Tribunal, mediante a propositura de Revisão Criminal;","c":"Solicitar ao Juiz da Execução, mediante Agravo em Execução;","d":"Solicitar ao Juiz da Execução, mediante petição. Direito Processual Penal>Da Prisão e da Liberdade Provisória ,Da Prisão em Flagrante ,","e":"","gabarito":"D","materia":"Direito Processual Penal","tema":"Recursos Criminais ,Agravo em execução","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1875","enunciado":"Ano: 2016 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal Substituto","a":"Assinale a alternativa correta: Pode ser considerado em flagrante delito quem integra organização criminosa;","b":"Crimes inafiançáveis não comportam liberdade provisória, sem fiança;","c":"A autoridade policial só pode decretar fiança, em caso de crimes apenados com detenção;","d":"A autoridade policial pode aplicar medidas cautelares diversas da prisão.","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q625072","enunciado":"Substituto","a":"Se, no curso da ação penal, o magistrado notar que a prescrição está prestes a ocorrer, poderá: Sentenciar, independentemente da apresentação dos memoriais defensivos;","b":"Concentrar a oitiva das testemunhas de acusação e defesa em um único ato;","c":"Determinar à defesa que apresente declarações escritas, no lugar de ouvir as testemunhas arroladas;","d":"Declarar, desde logo, a extinção da punibilidade, pela prescrição em perspectiva. Direito Processual Penal>Competência no Processo Penal ,Competência criminal da Justiça Federal ,","e":"","gabarito":"B","materia":"Direito Processual Penal","tema":"Procedimento Penal ,Processo e procedimento","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1877","enunciado":"Ano: 2016 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal Substituto","a":"Segundo o Supremo Tribunal Federal, o julgamento dos crimes relacionados à pornografia na internet compete: À Vara da Criança e Adolescente, uma vez que o crime está previsto no ECA;","b":"À Justiça Federal, pois, dentre outros motivos, presente a internacionalidade;","c":"À Justiça Estadual, sempre que as imagens tiverem sido postadas no Brasil;","d":"À Justiça Estadual, desde que as imagens tenham sido acessadas no Brasil.","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q625070","enunciado":"Substituto Pensando na hipótese de, após a apresentação de resposta à acusação, o magistrado se convencer da falta de justa causa","a":"para a ação penal, assinale qual hipótese é verdadeira: O magistrado terá que deixar a ação correr, pois não lhe compete conceder habeas corpus contra si próprio;","b":"O magistrado deverá absolver sumariamente o acusado, sem especificar nenhum inciso do artigo 397 do Código de Processo Penal;","c":"O magistrado poderá rejeitar a denúncia, dado que o primeiro recebimento, conforme parte da doutrina, ocorre a","d":"título precário; O magistrado deverá enviar os autos ao titular da ação, para que diga se concorda em retirar a denúncia. Direito Processual Penal>Competência no Processo Penal ,Habeas Corpus no Processo Penal ,","e":"","gabarito":"C","materia":"Direito Processual Penal","tema":"Procedimento Penal ,Procedimento comum ordinário","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1879","enunciado":"Ano: 2016 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal Substituto Em virtude de um ofício encaminhado pelo COAF, noticiando movimentações bancárias suspeitas, um Procurador da República requisitou a instauração de Inquérito Policial, para apurar a suposta prática de lavagem de dinheiro e de crimes financeiros. A Polícia Federal instaurou o inquérito, tendo o Delegado determinado, de plano, o indiciamento do investigado. Desejando questionar a ordem de indiciamento e a própria instauração do inquérito policial, a defesa decide impetrar habeas corpus, tendo o advogado dúvidas acerca de quem seja a autoridade competente para apreciar a ação","a":"constitucional. Diante desse cenário, assinale a opção correta: A decisão de impetrar habeas corpus é incorreta, pois não há coação ilegal, sequer em tese;","b":"A autoridade competente é o juiz de primeira instância;","c":"A autoridade competente é o Tribunal Regional Federal;","d":"A análise da ordem de indiciamento compete ao juiz de primeira instância e a da instauração do inquérito policial ao Tribunal Regional Federal.","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q625068","enunciado":"Substituto Pensando nas pessoas que se dispõem a transportar drogas, no próprio corpo, durante viagens internacionais, é possível dizer:","a":"Se forem primárias, ostentarem bons antecedentes e não integrarem organização criminosa, terão a pena reduzida de um sexto a dois terços;","b":"Mesmo se forem primárias, ostentarem bons antecedentes e não integrarem organização criminosa, não farão jus à redução de pena, haja vista tratar-se de tráfico internacional;","c":"São isentas de pena, haja vista o fato de estarem submetidas a organizações criminosas que as obrigam a cometer o crime;","d":"Mesmo quando obrigadas a proceder dessa forma, devem ser punidas, pois, em Direito Penal, o que importa é o resultado. Direito Penal>Concurso de crimes ,Concurso material ,Concurso formalCrimes contra a administração pública ,","e":"","gabarito":"A","materia":"Direito Penal","tema":"Legislação Penal Especial ,Lei de Tóxicos – Lei nº 11.343 de 2006","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q625067","enunciado":"Ano: 2016 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal Substituto","a":"Relativamente ao concurso de crimes, pode-se afirmar: Não pode haver concurso material, ou formal, entre os crimes de cartel e corrupção ativa;","b":"Entre o crime tributário a falsidade documental intentada para sua prática, há concurso material;","c":"Entre o crime tributário a falsidade documental intentada para sua prática, há concurso formal;","d":"Em regra, o cartel afasta a corrupção.","e":"","gabarito":"D","materia":"Corrupção ativa","tema":"","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q625066","enunciado":"Substituto","a":"Para fins penais, é considerado funcionário público: O médico não concursado, que presta serviços pelo SUS;","b":"Os funcionários das empresas de ônibus, haja vista que o transporte público é serviço fundamental;","c":"Os funcionários das empresas de telecomunicações, haja vista que se trata de serviço essencial;","d":"Apenas quem tenha prestado concurso público.","e":"","gabarito":"A","materia":"Direito Penal","tema":"Crimes contra a administração pública ,Noções Gerais de Crimes Contra a Administração Pública","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q625065","enunciado":"Substituto","a":"Relativamente à responsabilidade penal da pessoa jurídica, é possível afirmar que: É cabível quando praticados crimes ambientais e contrários à administração pública;","b":"É inconstitucional, haja vista o princípio da responsabilidade penal objetiva;","c":"Independe da responsabilização das pessoas físicas envolvidas, conforme decidiu o Supremo Tribunal Federal, ao julgar o RE 548181/PR, de relatoria da Ministra Rosa Weber;","d":"Depende da responsabilização das pessoas físicas envolvidas, conforme decidiu o Supremo Tribunal Federal, ao julgar o RE 548181/PR.","e":"","gabarito":"C","materia":"Direito Penal","tema":"Tipicidade ,Crime praticado por pessoa jurídica","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q625063","enunciado":"Substituto Um dos crimes mais graves do ordenamento pátrio é o de redução à condição análoga à de escravo, capitulado no artigo","a":"149 do Código Penal. Acerca de tal delito, é possível afirmar que: Restará verificado, sempre que os direitos trabalhistas não forem observados em sua integralidade;","b":"Restará verificado, apenas quando o trabalho a que as vítimas forem submetidas não for remunerado;","c":"Haja vista as alterações realizadas pela lei 10.803/03, revogou o artigo 203 do Código Penal;","d":"Convive em harmonia com o artigo 203 do Código Penal; Direito Penal>Legislação Penal Especial ,","e":"","gabarito":"D","materia":"Direito Penal","tema":"Crimes contra a liberdade pessoal ,Redução à condição análoga à de escravo","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1885","enunciado":"Ano: 2016 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal Substituto Sabendo-se que os presidentes de empresas, que dominam o mercado em um determinado setor, se unem para fixar preços e dividir territórios de atuação, é possível afirmar que tais presidentes:","a":"Devem ser responsabilizados por crimes contra as relações de consumo, especialmente o previsto no artigo 7º., inciso","b":"IV, da Lei 8.137/90; Devem responder por crime contra a ordem econômica em sentido estrito;","c":"Não podem sofrer qualquer tipo de procedimento penal, haja vista o princípio da responsabilidade penal subjetiva;","d":"Não podem sofrer qualquer punição, como pessoas físicas; as empresas, entretanto, poderão ser punidas nos termos da Lei 12.529/11; Direito Penal>Lei do Colarinho Branco - Lei nº 7.492 de 1986 - Crimes contra o Sistema Financeiro Nacional ,","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q625060","enunciado":"Ano: 2016 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal Substituto Se um indivíduo é flagrado entrando com R$ 100.000,00 (cem mil reais) em dinheiro no território nacional, pode-se dizer","a":"que: A situação constitui um irrelevante penal, pois evadir dinheiro é crime, porém, internar não;","b":"Está-se diante do crime capitulado no artigo 22, “caput”, da Lei 7.492/86;","c":"A depender da origem do dinheiro, pode-se estar diante de vários crimes, inclusive lavagem de dinheiro;","d":"A depender da origem do dinheiro, pode-se estar diante de crime contra a ordem tributária; Direito Previdenciário>Seguridade Social ,Princípios da Seguridade Social ,","e":"","gabarito":"C","materia":"Legislação Penal Especial","tema":"","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q625059","enunciado":"Ano: 2016 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal Substituto Assinale a alternativa correta:","a":"O abono anual corresponde ao valor integral da prestação mensal e é devido a todos os beneficiários de prestação continuada do Sistema de Seguridade Social, sendo, apenas, proporcional ao número de meses da percepção do benefício, caso tenha percebido menos de 12 parcelas no ano.","b":"O valor dos benefícios em manutenção será reajustado, anualmente, na mesma data do reajuste do salário mínimo, pro rata, de acordo com suas respectivas datas de início ou do último reajustamento, e pelos mesmos índices.","c":"Não há ofensa aos princípios constitucionais da irredutibilidade e da preservação do valor real dos benefícios, a aplicação de reajustes com base nos critérios estabelecidos em lei.","d":"O primeiro pagamento do benefício será efetuado até trinta dias após a data da apresentação, pelo segurado, da documentação necessária à sua concessão.","e":"","gabarito":"C","materia":"Planos de Benefício da Previdência Social - Lei nº 8.213, de 24 de Julho de 1991","tema":"","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q625057","enunciado":"Substituto Sobre o benefício de auxílio-doença, é correto afirmar que:","a":"É devido ao segurado empregado que ficar incapacitado, temporariamente, para o seu trabalho, desde que cumprido o período de carência, devendo ser pago o seu salário integral pela empresa, durante os 30 (trinta) primeiros dias consecutivos ao do afastamento da atividade por motivo de doença.","b":"Para o segurado empregado, o benefício de auxílio-doença tem início no 16º dia da incapacidade, se requerido até 30 (trinta) dias do afastamento do trabalho.","c":"A progressão ou o agravamento da doença ou da lesão invocada como causa para a incapacidade devem ser anteriores à filiação do segurado ao Regime Geral de Previdência Social, para que seja devido o benefício de auxílio- doença.","d":"Cumpridos os requisitos legais, a concessão do auxílio-doença é devido a todos os segurados a partir da data do início da incapacidade. Direito Previdenciário>Beneficiários do Regime Geral de Previdência Social - RGPS ,","e":"","gabarito":"B","materia":"Direito Previdenciário","tema":"Benefícios em Espécie ,Auxílio-Doença","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1889","enunciado":"Ano: 2016 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal Substituto Assinale a alternativa incorreta:","a":"Os segurados facultativos são aqueles que não exercem atividade remunerada, enquadrada por lei como obrigatória, tenham idade mínima de 16 (dezesseis) anos, não se enquadrem em regime próprio e decidam contribuir para o Regime Geral da Previdência Social.","b":"São segurados obrigatórios da Previdência Social aqueles que exercem atividade remunerada, os quais são divididos nas seguintes classes: empregado, empregado doméstico, trabalhador avulso, contribuinte individual, segurado especial, bolsista e estagiário prestadores de serviços à empresa, nos termos da Lei 11.788/2008.","c":"O período de graça é o prazo em que a pessoa mantém a qualidade de segurado, embora não esteja vertendo contribuições, podendo ou não ter limite, nos termos da lei, e conservando todos os seus direitos perante a previdência social.","d":"É beneficiário do Regime Geral da Previdência Social, na condição de dependente do segurado, o irmão não emancipado, de qualquer condição, menor de 21 (vinte e um) anos ou inválido ou que tenha deficiência intelectual ou mental ou deficiência grave.","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q625054","enunciado":"Substituto Considerando as assertivas abaixo, assinale a alternativa correta: I. São diretrizes para a organização das ações governamentais na área da assistência social: a descentralização político- administrativa e a participação da população, por meio de organizações representativas. II. A assistência social será prestada a quem dela necessitar, independentemente de contribuição, para subsistência da pessoa necessitada, portadora de deficiência e do idoso, cabendo à família do beneficiário contribuir com valor mensal correspondente a ¼ do salário mínimo per capita, nos termos da lei. III. A renda mensal vitalícia, o benefício de prestação continuada, o auxílio-natalidade e os benefícios eventuais, previstos no artigo 22 da Lei Orgânica da Assistência Social - LOAS, são benefícios concedidos independentemente de requerimento e contribuição da pessoa necessitada e prestados com recursos do orçamento da seguridade social, como encargo de toda a sociedade, de forma direta ou indireta. IV. O benefício de prestação continuada não pode ser acumulado pelo beneficiário com qualquer outro no âmbito da seguridade social ou de outro regime, excepcionados apenas o de assistência médica e da pensão especial de natureza indenizatória, não sendo também computados os rendimentos decorrentes de estágio supervisionado e de aprendizagem,","a":"para os fins de cumprimento do requisito da renda familiar mínima. As assertivas I e IV estão corretas.","b":"As assertivas I e III estão corretas.","c":"Apenas a assertiva III está incorreta.","d":"Apenas a assertiva I está correta.","e":"","gabarito":"A","materia":"Direito Previdenciário","tema":"Seguridade Social ,Definição","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q625053","enunciado":"Substituto Quanto à assistência à saúde, é correto afirmar:","a":"É um direito de acesso universal e igualitário às ações e aos serviços de saúde e de atendimento integral, com preferência para as atividades preventivas, sendo devido pelo Estado complementarmente aos serviços privados, podendo ser executado diretamente pelo Poder Público ou por intermédio de terceiros, pessoas físicas ou jurídicas.","b":"As ações e os serviços públicos de saúde integram uma rede regionalizada e hierarquizada, constituída na forma de um sistema único de saúde, financiado com recursos do orçamento da seguridade social e da União, não podendo, no caso da União, a receita líquida do respectivo exercício financeiro ser inferior a 15% (quinze por cento).","c":"A Agência Nacional de Saúde Suplementar – ANS é autarquia especial, vinculada ao Ministério da Saúde, com funções de regular, normatizar, controlar e fiscalizar as medidas sanitárias, cabendo aos Estados e Municípios e à rede privada a prestação dos serviços de saúde e vigilância sanitária em todo o território nacional.","d":"Entende-se por vigilância sanitária um conjunto de ações capaz de eliminar, diminuir ou prevenir riscos à saúde e de intervir nos problemas sanitários decorrentes do meio ambiente, da produção e circulação de bens e da prestação de serviços de interesse da saúde.","e":"","gabarito":"","materia":"Direito Previdenciário","tema":"Seguridade Social ,Definição","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q625052","enunciado":"Substituto Estabelece o artigo 194 da Constituição Federal que “A seguridade social compreende um conjunto integrado de ações de iniciativa dos Poderes Públicos e da sociedade, destinadas a assegurar os direitos relativos à saúde, à previdência e à assistência social”. Assinale a alternativa correta sobre os princípios constitucionais específicos que regem a Seguridade Social:","a":"Universalidade da cobertura e do atendimento pode ser destacada como subjetiva e objetiva e refere-se ao direito dos contribuintes à cobertura das necessidades nas situações socialmente danosas.","b":"Uniformidade e equivalência dos benefícios e serviços às populações urbanas e rurais impõe que, diante de idênticas situações de necessidade, haja diversidade de proteção, em forma de benefícios e serviços.","c":"Seletividade e distributividade na prestação dos benefícios e serviços indica que o sistema de proteção social deve oferecer todas as prestações, sem exceções, a quem delas necessite, para a consecução da igualdade e da justiça social.","d":"Diversidade da base de financiamento refere-se à busca da seguridade social pela pluralidade de recursos, com participação individual e social e decorre do solidarismo social, pelo qual devem ser adotadas técnicas de proteção social e conjugados esforços de todos para a cobertura das contingências sociais. Direito Constitucional>Poder Executivo ,","e":"","gabarito":"","materia":"Direito Previdenciário","tema":"Seguridade Social ,Princípios da Seguridade Social","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1893","enunciado":"Ano: 2016 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal Substituto Em relação ao Presidente da República é incorreto afirmar:","a":"O processo por crime de responsabilidade é levado a efeito pelo Senado Federal , mas sob a presidência do Presidente do Supremo Tribunal Federal/STF.","b":"Os crimes de responsabilidade que lhe forem imputados serão objeto de acusação e processo nos termos da lei que trata da improbidade administrativa.","c":"Ficará suspenso de suas funções se for recebida denúncia criminal ou queixa-crime contra ele pelo Supremo Tribunal","d":"Federal/STF. Após a instauração do processo por crime de responsabilidade, ficará suspenso de suas funções. Direito Constitucional>Processo Legislativo ,Poder Legislativo , Presidente da República, Vice-Presidente da República e Ministros de Estado.Poder Executivo ,","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1894","enunciado":"Espécies Normativas: Lei Complementar e Lei Ordinária ,Vedações, Garantias e Imunidades Parlamentares Ano: 2016 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal Substituto Examine as seguintes proposições e indique a alternativa correta: I. As Comissões Parlamentares de Inquérito/CPIs são temporárias e destinadas a apurar fatos determinados; possuem poderes próprios das autoridades judiciárias o que legitima que, apuradas por elas responsabilidades civil ou penal, apliquem sanções aos infratores. II. A Constituição Federal não estabelece hierarquia entre lei complementar e lei ordinária, nem entre lei federal e lei estadual, tampouco prevê iniciativa popular para emendar a Carta Magna. III. A inviolabilidade parlamentar por opiniões e palavras acompanha o Deputado Federal ou Senador quando ele é candidato a outro cargo eletivo, imunizando-o de responder por ofensas dirigidas a outras pessoas durante a campanha. IV. Vagando os cargos de Presidente e de Vice-Presidente da República nos dois primeiros anos do mandato presidencial,","a":"será feita eleição direta noventa dias depois de aberta a última vaga. São corretas as proposições II e IV.","b":"São corretas as proposições I e III.","c":"São corretas as proposições III e IV.","d":"Todas as proposições são incorretas.","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q625049","enunciado":"Substituto Ao explorarem diretamente atividade econômica, as empresas públicas e as sociedades de economia mista:","a":"não se sujeitam à exigência de licitação para contratar obras, serviços, compras e alienações, diante da supremacia do interesse público .","b":"sujeitam-se ao regime jurídico das empresas privadas quanto aos direitos e obrigações civis, comerciais, tributários e","c":"trabalhistas. estão impedidas de atuar nas atividades econômicas que são de livre exploração pelo setor privado.","d":"não podem desfrutar de tratamento fiscal mais favorecido que não é estendido ao setor privado, mas em compensação não se sujeitam aos princípios constitucionais que animam a Administração Pública.","e":"","gabarito":"","materia":"Direito Constitucional","tema":"Ordem Econômica e Financeira ,Princípios Gerais da Atividade Econômica","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q625048","enunciado":"Substituto Com relação a classificação das Constituições é correto dizer que:","a":"a Constituição formal é aquela promulgada em sessão solene do Poder Constituinte que a elaborou, com a presença do chefe do Poder Executivo.","b":"a Constituição rígida é aquela que não prevê mecanismo ou processo que permita a alteração de suas normas, só","c":"podendo ser mudada por outro Poder Constituinte originário. a Constituição dirigente confere atenção especial à implementação de programas pelo Estado.","d":"a Constituição ortodoxa é aquela que se pauta por valores e tradições há muito já estabelecidos e conservados pela sociedade.","e":"","gabarito":"","materia":"Direito Constitucional","tema":"Classificação das Constituições ,Teoria da Constituição","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q625047","enunciado":"Substituto","a":"Incluem-se entre os bens dos Estados: os potenciais de energia elétrica.","b":"os rios e lagos em terrenos de seu domínio, ainda que sejam limítrofes de outros países.","c":"as cavidades naturais subterrâneas e os sítios arqueológicos e pré-históricos.","d":"as áreas nas ilhas oceânicas e costeiras que estiverem sob seu domínio, excluídas as que forem da União, dos Municípios ou que pertençam a particulares. Direito Constitucional>Disposições Gerais no Poder Judiciário ,Superior Tribunal de Justiça ,","e":"","gabarito":"","materia":"Direito Constitucional","tema":"Organização do Estado – Estados ,Organização Político-Administrativa do Estado","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1898","enunciado":"Ano: 2016 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal Substituto Em relação ao Poder Judiciário a afirmativa incorreta é: Aos juízes federais compete processar e julgar todas as causas em que a União, entidade autárquica ou empresa","a":"pública federal forem interessadas na condição de autoras, rés, assistentes ou oponentes, bem como a disputa sobre direitos indígenas, e ainda as causas em que Estado estrangeiro ou organismo internacional litiga com Município ou pessoa domiciliada ou residente no Brasil.","b":"O Conselho da Justiça Federal/CJF funciona junta ao Superior Tribunal de Justiça/STJ, exercendo na forma da lei a supervisão administrativa e orçamentária da Justiça Federal e possui poderes correcionais, cujas decisões terão caráter vinculante.","c":"A cláusula constitucional de reserva de plenário não impede que os órgãos fracionários dos Tribunais, ou os seus membros quando decidem monocraticamente, rejeitem a arguição de invalidade dos atos normativos.","d":"Compete ao Superior Tribunal de Justiça/STJ a homologação das sentenças estrangeiras e a concessão do “exequatur” para as cartas rogatórias.","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q625045","enunciado":"Substituto","a":"Só o brasileiro nato pode ser: Deputado Federal ou Senador da República.","b":"Ministro de Tribunal Superior.","c":"Chefe do Estado Maior das Forças Armadas.","d":"Presidente do Banco Central da República. Direito Constitucional> Poder Constituinte Originário, Derivado e Decorrente - Reforma (Emendas e Revisão) e Mutação da Constituição ,","e":"","gabarito":"","materia":"Direito Constitucional","tema":"Direitos da Nacionalidade","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1900","enunciado":"Direito de Propriedade e Função Social da Propriedade ,Teoria dos Direitos Fundamentais Ano: 2016 Banca: TRF - 3ª REGIÃO Órgão: TRF - 3ª REGIÃO Prova: TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal Substituto Analise as proposições abaixo e assinale a alternativa certa: I. Sob o aspecto democrático, a titularidade do Poder Constituinte é do Estado, mas é o povo que o exerce. II. A Constituição nova, ainda que seja silente a respeito, revoga inteiramente a Constituição anterior, fenômeno que decorre da normatização geral. III. Os direitos e deveres individuais e coletivos estendem-se aos estrangeiros que apenas estão em trânsito pelo Brasil. IV. Para fins da proteção referida no art. 5º, XI, da Constituição atual, o conceito normativo de “casa” deve ser abrangente, de modo a se estender, em regra, a qualquer compartimento privado onde alguém exerce uma atividade ou profissão.","a":"V. As associações de caráter paramilitar só podem funcionar depois de autorizadas pelo Ministério da Defesa. Todas as proposições estão corretas.","b":"Apenas a proposição I é incorreta.","c":"As proposições III e IV são incorretas.","d":"As proposições II, III e IV são as corretas.","e":"","gabarito":"","materia":"Geral","tema":"","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"Q625043","enunciado":"Substituto Considere a história constitucional do Brasil e assinale a alternativa correta:","a":"Os direitos fundamentais foram expressamente previstos pela primeira vez na Constituição de 1946, a qual sobreveio após a queda do Estado Novo.","b":"A forma federativa de Estado foi prevista na Constituição de 1891, mas ainda assim não foi assegurada autonomia aos Municípios na condição de entes federados.","c":"Na Constituição de 1946 foi concedida ao Presidente da República autorização para expedir decretos-lei e foi prevista a eleição para as Casas Legislativas por meio de voto direto e secreto.","d":"O presidencialismo sempre acompanhou a forma republicana de governo desde que esta foi implantada com a queda do Império.","e":"","gabarito":"","materia":"Direito Constitucional","tema":"Teoria da Constituição ,História Constitucional Brasileira","origem":"TRF - 3ª REGIÃO - 2016 - TRF - 3ª REGIÃO - Juiz Federal","ano":"2016","banca":"TRF - 3ª REGIÃO Ó","orgao":"TRF - 3ª REGIÃO","concurso":"TRF3"},{"id":"TRF3_1902","enunciado":"www.qconcursos.com","a":"","b":"","c":"","d":"","e":"","gabarito":"","materia":"Geral","tema":"","origem":"","ano":"","banca":"","orgao":"","concurso":"TRF3"},{"id":"TRF3_1903","enunciado":"www.qconcursos.com","a":"","b":"","c":"","d":"","e":"","gabarito":"","materia":"Geral","tema":"","origem":"","ano":"","banca":"","orgao":"","concurso":"TRF3"},{"id":"TRF3_1904","enunciado":"www.qconcursos.com","a":"","b":"","c":"","d":"","e":"","gabarito":"","materia":"Geral","tema":"","origem":"","ano":"","banca":"","orgao":"","concurso":"TRF3"}];
